#!/bin/bash
#
# oci_cli_ops.sh - OCI CLI Operations Management Tool
#
# Description:
#   Interactive management tool for Oracle Cloud Infrastructure covering compute,
#   GPU infrastructure, Kubernetes (OKE), networking, storage, identity, and operations.
#   Provides menu-driven access to instances, GPU memory fabrics/clusters, DRG connectivity,
#   maintenance events, service limits, and diagnostic tools.
#
# Dependencies on the node it is run from:
#   - oci CLI (configured)
#   - kubectl (configured with cluster access)
#   - jq (JSON processor)
#   - base64, gunzip, xxd (for user-data decoding)
#   - helm (optional, for GPU stack inspection)
#
# Usage:
#   ./oci_cli_ops.sh [OPTIONS] [resource-ocid] [OPTIONS]
#   Run with --help for full usage information.
#
# Configuration:
#   If you have a variables.sh file already precreated will use the value in it, else will prompt to create one.
#   It'll query for the resources to populate the file accordingly.
#   It assumes that you are running the components for the AI stack in the same compartment, compute, network, storage.
#   Optional: OKE_CLUSTER_ID to specify which OKE cluster to manage
#
# Author: Tim Cowen
# Version: 3.25.50 (2026-03-02)
# Please use at your own risk.
#
#===============================================================================
# CODING STANDARDS (for AI-assisted development — read before modifying)
#===============================================================================
#
# NAVIGATION (category-based):
#   Main menu → c)Compute k)Kubernetes n)Network s)Storage i)Identity o)Operations
#   Shortcuts: c1=Instances, c2=Configs, c8=Instance Pools, c9=Cluster Networks, k1=OKE, k2=GPU Stack, etc.
#   CLI: --manage c1 jumps directly to Compute Instances
#   Every menu supports: b=back, show=redraw, r=refresh cache
#   Every menu supports: env (full menu), env c, env r, env oke, env vcn (quick-switch)
#
# OVERVIEW FLOW (no-args and --manage r):
#   Pattern: BANNER → FOCUS → CACHE → COMMANDS → DISCOVERING → DISPLAY
#   _display_overview → _ui_banner + _focus_display + _display_cache_info + _ui_oci_cmd
#                     → SINGLE discovery bar (4 phases via _step_phase_end):
#                       Phase 1: OKE env → Phase 2: network → Phase 3: GPU → Phase 4: instances
#                     → display_oke_environment_header (from cache, inline cache suppressed)
#                     → list_all_instances(_OVERVIEW_PREFETCHED=1) (display only, no discovery)
#   _OVERVIEW_SKIP_CACHE=1 suppresses inline cache in display_*() called from overview.
#
# DATA ARCHITECTURE — CACHE → FOCUS → DISPLAY
#   All data flows through a three-phase pipeline. Never fetch inline with display.
#
#   ┌─────────────────────────────────────────────────────────────────────────────┐
#   │  PHASE 1: CACHE (fetch + write)                                           │
#   │                                                                            │
#   │  fetch_*() functions make OCI API calls and write results to *_CACHE files. │
#   │  Every fetch checks TTL first via is_cache_fresh() — skips if fresh.       │
#   │  Caches are flat text files (pipe-delimited) or JSON, one per resource.    │
#   │                                                                            │
#   │  Pattern:                                                                  │
#   │    fetch_oke_environment()      → OKE_ENV_CACHE (cluster, ADs, VCN, addons)│
#   │    fetch_network_resources()    → NETWORK_RESOURCES_CACHE (subnets, NSGs)  │
#   │    fetch_all_network_gateways() → IGW/SGW/NAT/DRG/RT/NSG/SL/PE caches    │
#   │    fetch_gpu_fabrics()          → FABRIC_CACHE                             │
#   │    fetch_gpu_clusters()         → CLUSTER_CACHE + INSTANCE_CLUSTER_MAP     │
#   │    fetch_capacity_topology()    → CAPACITY_TOPOLOGY_CACHE (c5 only)        │
#   │    fetch_compute_hosts()        → COMPUTE_HOST_CACHE (health/topology)    │
#   │                                                                            │
#   │  Rules:                                                                    │
#   │    • Always check is_cache_fresh() before calling OCI                      │
#   │    • TTLs defined in CACHE_TTL_MAP (20s real-time → 300s/5m default)       │
#   │    • Avoid duplicate fetches — fetch_oke_environment populates             │
#   │      NETWORK_RESOURCES_CACHE from its own subnet/NSG data                  │
#   │    • Write caches atomically: _cache_write or direct > "$CACHE_FILE"       │
#   │    • fetch_* functions own the discovery bar (_step_init/finish)            │
#   │    • Use _STEP_OUTER=1 to merge nested bars into a parent bar              │
#   ├─────────────────────────────────────────────────────────────────────────────┤
#   │  PHASE 2: FOCUS (scope + invalidation)                                    │
#   │                                                                            │
#   │  FOCUS_* variables scope ALL queries and display to a specific context.    │
#   │  Changing focus invalidates relevant caches so next fetch gets fresh data. │
#   │                                                                            │
#   │  Variables (always set):                                                   │
#   │    FOCUS_REGION             FOCUS_REGION_SOURCE                            │
#   │    FOCUS_COMPARTMENT_ID     FOCUS_COMPARTMENT_SOURCE                      │
#   │  Variables (optional):                                                     │
#   │    FOCUS_OKE_CLUSTER_ID     FOCUS_OKE_SOURCE                              │
#   │    FOCUS_VCN_OCID           FOCUS_VCN_SOURCE                              │
#   │    FOCUS_AD                 FOCUS_AD_SOURCE                               │
#   │                                                                            │
#   │  Mutation functions (never set FOCUS_* directly):                          │
#   │    _focus_set_region()       → invalidates ALL caches, clears OKE/AD      │
#   │    _focus_set_compartment()  → invalidates ALL caches, clears OKE         │
#   │    _focus_set_oke_cluster()  → invalidates OKE caches, derives VCN        │
#   │    _focus_set_vcn()          → invalidates network caches                 │
#   │    _focus_set_ad()           → no cache impact (AD is a filter, not scope)│
#   │                                                                            │
#   │  Cascade rules:                                                            │
#   │    Region change    → clears OKE cluster + AD (region-specific)           │
#   │    Compartment change → clears OKE cluster (compartment-specific)         │
#   │    OKE cluster change → derives VCN (unless VCN manually selected)        │
#   │    OKE cluster clear  → clears derived VCN                                │
#   │                                                                            │
#   │  Source tracking (_SOURCE suffix):                                         │
#   │    "config"    → from variables.sh       → displayed GREEN                │
#   │    "selected"  → manual pick at runtime  → displayed YELLOW               │
#   │    "derived"   → auto-resolved (e.g., VCN from OKE) → displayed CYAN     │
#   │                                                                            │
#   │  Access from any menu:                                                     │
#   │    env         → full environment menu                                    │
#   │    env c       → quick compartment change (_env_select_compartment)       │
#   │    env r       → quick region change      (_env_select_region)            │
#   │    env oke     → quick OKE cluster change  (_env_select_oke)              │
#   │    env vcn     → quick VCN change          (_env_select_vcn)              │
#   │    Dispatcher: _env_dispatch "$input" — routes all env* patterns          │
#   ├─────────────────────────────────────────────────────────────────────────────┤
#   │  PHASE 3: DISPLAY (read cache + render)                                   │
#   │                                                                            │
#   │  display_*() functions read from cache files and render formatted output.  │
#   │  They call fetch_*() for freshness but rely on cache — no inline API calls.│
#   │                                                                            │
#   │  Pattern:                                                                  │
#   │    display_oke_environment_header() reads OKE_ENV_CACHE → box format      │
#   │    display_network_resources() reads NETWORK_RESOURCES_CACHE → tree format│
#   │    list_all_instances() fetches instances live + reads GPU/topology caches │
#   │                                                                            │
#   │  Rules:                                                                    │
#   │    • display_*() may call fetch_*() but MUST NOT make OCI calls directly  │
#   │    • If fetch_*() finds cache fresh, display_*() renders with zero latency│
#   │    • Discovery bars belong in fetch_*() — display_*() should be silent    │
#   │    • Use _skip_header pattern when a parent already rendered the header    │
#   │    • Use _OVERVIEW_SKIP_CACHE=1 to suppress inline cache in display_*()  │
#   │    • Use _ui_* helpers for all visual output (never raw printf for menus) │
#   └─────────────────────────────────────────────────────────────────────────────┘
#
#   Canonical example — _display_overview (no-args and --manage r):
#
#     _display_overview()
#       │
#       ├── _ui_banner "FULL ENVIRONMENT OVERVIEW"     ← BANNER
#       │
#       ├── _focus_display()                            ← FOCUS (tenancy, region, comp, OKE, tools)
#       │
#       ├── _display_cache_info(...)                    ← CACHE (all caches with counts + ages)
#       │   ├── OKE Env, Fabrics, GPU Clusters, Instance Map, Compute Clusters
#       │   ├── Subnets, NSGs, Routes, IGW, NAT, SGW, DRG, DRG Att, OS PEs
#       │   └── Topology, Node States, Announcements
#       │
#       ├── _ui_oci_cmd(...)                            ← COMMANDS (OCI + kubectl commands used)
#       │
#       ├── SINGLE CONSOLIDATED DISCOVERY BAR           ← DISCOVERING (one bar, multi-line phases)
#       │   _step_init
#       │   ├── Phase 1: OKE environment                  ✓ OKE(name) ✓ ADs(3) ✓ subnets(8) ✓ NSGs(3)
#       │   │   └── _STEP_OUTER=1 fetch_oke_environment   (populates NETWORK_RESOURCES_CACHE)
#       │   │   _step_phase_end                            → prints line 1, start fresh line
#       │   ├── Phase 2: network gateways                  ✓ IGW(1) ✓ SGW(1) ... ✓ PEs(2)
#       │   │   └── _STEP_OUTER=1 fetch_all_net_gateways  (or cached summary)
#       │   │   _step_phase_end                            → prints line 2
#       │   ├── Phase 3: GPU infrastructure                ✓ fabrics(7) ✓ GPU clusters(7) ✓ configs(4)
#       │   │   _step_phase_end                            → prints line 3
#       │   ├── Phase 4: instances & K8s                   ✓ instances(121) ✓ K8s nodes ✓ topology
#       │   │   └── pre-fetches into _OV_INST_TEMP/_OV_K8S_TEMP for list_all_instances
#       │   _step_finish                                   → prints line 4 + bottom separator
#       │
#       ├── display_oke_environment_header()            ← DISPLAY (from cache, no bars)
#       │   ├── _OVERVIEW_SKIP_CACHE=1                    (inline cache suppressed)
#       │   ├── fetch_oke_environment → cache fresh → no-op
#       │   └── renders OKE box + network tree from cache
#       │
#       └── list_all_instances(skip_header=true)        ← DISPLAY (no discovery bar)
#           ├── _OVERVIEW_PREFETCHED=1                    (uses pre-fetched _OV_INST_TEMP/_OV_K8S_TEMP)
#           └── renders instance table from temp files + caches
#
#   Pattern: BANNER → FOCUS → CACHE → COMMANDS → DISCOVERING → DISPLAY
#   This is the standard flow for any top-level view. display_*() functions
#   support _OVERVIEW_SKIP_CACHE=1 to suppress their inline cache lines
#   when a parent has already shown the comprehensive cache summary.
#   Discovery uses separate short bars (OKE env, gateways, GPU) — never merge
#   bars beyond ~180 chars to avoid terminal line-wrap ghost corruption.
#
#   Adding a new resource view:
#     1. Create fetch_my_resource() → writes MY_CACHE, uses _step_* for discovery
#     2. Create display_my_resource() → reads MY_CACHE, renders with _ui_* helpers
#     3. Focus scoping: pass FOCUS_COMPARTMENT_ID/FOCUS_REGION to fetch_*()
#     4. Cache invalidation: add MY_CACHE to rm -f in relevant _focus_set_*()
#     5. Wire into menu: call fetch then display, or just display (it calls fetch)
#
# UI HELPERS (mandatory for all --manage menus):
#   _ui_menu_header, _ui_banner, _ui_breadcrumb, _ui_section, _ui_subheader, _ui_env_info,
#   _ui_oci_cmd, _ui_summary, _ui_legend, _ui_actions, _ui_action_group, _ui_prompt, _ui_pause,
#   _ui_detail_banner, _ui_table_header, _ui_confirm, _ui_compare_field,
#   _ui_content_border.
#
# STANDARD MENU LAYOUT (enforced by _ui_menu_header):
#   ┌──────────────────────────────────────────────────────────┐
#   │  ═══════════════ BANNER TITLE ═══════════════            │  _ui_banner
#   │  Main > Compute > Instances                              │  _ui_breadcrumb
#   │  Cache: Items (8, 3m)  Other (12, 3m) │ TTL: 5m        │  _display_cache_info
#   │  Focus: (variables.sh configured │ manually selected │ derived)  │  _ui_env_info
#   │    Tenancy: name [ocid]                                  │
#   │    Region │ AD │ Compartment │ OKE │ VCN                 │
#   │    OCI CLI │ kubectl │ helm                              │
#   │  Commands executed during fetch:                       │  _ui_oci_cmd (gray)
#   │  oci network subnet list --compartment-id $COMP_ID      │
#   ├──────────────────────────────────────────────────────────┤
#   │  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━  │  Discovery (_step_*)
#   │    Discovering:                                          │  _step_init
#   │    ✓ items(11)  ✓ details(11)  ⠋ [████░░░░] 40% BV(4/10)│  _step_active/_step_progress_start
#   │  ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━  │  _step_finish
#   │  Main > Compute > Instances                              │  _ui_breadcrumb
#   │  ─── Section Title ───                                   │  _ui_section (top-level)
#   │    ── Subheader ──                                       │  _ui_subheader (indented)
#   │  ═══ Detail: resource_name ═══                           │  _ui_detail_banner (sub-view)
#   │  BOLD %-4s %-30s %-10s + separator                       │  _ui_table_header (auto-width)
#   │  ... display area (tables, details, content) ...         │
#   │  ─── Summary ───                                         │  _ui_summary
#   │  ─── Legend ───                                          │  _ui_legend
#   │  ─── Actions ──────────────────────────────────────────  │  _ui_actions (yellow line)
#   │    » View / » Search / » Create ...                    │  _ui_action_group (cyan » + bold white)
#   │  Type 'CONFIRM' to ...:                                  │  _ui_confirm (returns 0/1)
#   │  [Context] Selection (options):                          │  _ui_prompt
#   └──────────────────────────────────────────────────────────┘
#
# NEW MENU / SUBMENU CHECKLIST:
#   Every navigable interactive view (top-level menu OR drill-in detail view)
#   MUST follow this pattern. Action/confirmation dialogs (delete, rename, etc.)
#   and one-shot read-only displays (JSON dump, diff output) are exempt.
#
#   1. HEADER — call _ui_menu_header with ALL applicable flags:
#        _ui_menu_header "TITLE" \
#            --breadcrumb "Category" "Submenu" \  # ← REQUIRED for all views
#            --cmd "oci <service> <verb> --compartment-id \$COMPARTMENT_ID" \
#            --env \                          # ← REQUIRED for all views
#            --cache \                        # ← if view uses cached data
#            "file|Label" "file2|Label2"
#      • --breadcrumb displays "Main > Category > Submenu" navigation path.
#        Use the parent category name from the main menu (Compute, Kubernetes,
#        Network, Storage, Identity, Operations) as the first segment.
#      • --env displays the standard Focus block (Tenancy, Region, AD,
#        Compartment, OKE, VCN, Tools) with source coloring.
#      • --cmd shows the OCI CLI commands used (gray text).
#      • --cache shows cache freshness for each data source.
#      • Do NOT add env extras for values already in Focus (Tenancy, Region,
#        Compartment, OKE, VCN). Only use extras for view-specific context
#        (e.g., "Net Comp" when different from main compartment).
#
#   2. DISCOVERY — use _step_* functions for ALL API fetches:
#        _step_init                                    # separator + "Discovering:"
#        _step_active "items"                          # spinner: ⠋ items...
#        items_json=$(oci ... 2>/dev/null)
#        _step_complete "items(${count})"              # checkmark: ✓ items(11)
#        _step_progress_start "BV" "$dir" "*.json" $n  # progress bar for parallel
#        <parallel work creating files>
#        _step_complete "BV(${n})"                     # checkmark when done
#        _step_finish                                  # closing separator
#      • Show count in parentheses: ✓ items(11), ✓ BV cached
#      • Use _step_progress_start for parallel fetches with file-based progress
#      • Use _step_active for single sequential API calls
#      • _STEP_OUTER=1: makes _step_init/_step_finish no-ops so nested functions
#        contribute their _step_active/_step_complete to a parent discovery bar.
#      • _step_phase_end: prints the current progress line and resets for a new
#        line within the same discovery bar. Use between _step_init and _step_finish
#        to break long bars into multiple lines, keeping each phase's spinner
#        under ~180 chars. Example:
#            _step_init
#            _step_complete "foo(3)"; _step_phase_end   # line 1: ✓ foo(3)
#            _step_complete "bar(5)"; _step_phase_end   # line 2: ✓ bar(5)
#            _step_complete "baz(7)"                     # line 3 (via _step_finish)
#            _step_finish
#      • TERMINAL LINE-WRAP BUG: The spinner reprints the entire accumulated
#        _STEP_COMPLETED_TEXT every ~100ms. CLEAR_LINE (\033[2K\r) only clears
#        the current physical terminal line. If accumulated text wraps past terminal
#        width, wrapped lines above freeze as ghost content that repeats on every
#        spinner tick. FIX: Use _step_phase_end to keep each line under ~180 chars.
#      • NEVER use bare _show_spinner in a menu view; reserve it for
#        action dialogs or one-off fetches outside the discovery flow
#      • NEVER use bare `wait` (waits on spinner subshell too → hang);
#        always track PIDs and `wait "${pids[@]}"`
#
#   3. DATA DISPLAY — use centralized UI helpers:
#      • _ui_subheader "Title" 0 for top-level sections
#      • _ui_table_header "%-4s %-30s" "#" "Name" for table columns
#      • printf with color constants for data rows
#
#   4. ACTIONS — use centralized prompt helpers:
#      • _ui_actions for "─── Actions ───" separator
#      • _ui_action_group for bold white sub-category labels within actions
#      • _ui_prompt "Context" "options" for input prompt
#      • _ui_pause "return" for press-enter-to-continue
#
#   5. FOCUS COLORING — source colors are automatic in _ui_env_info:
#      • GREEN  = variables.sh configured
#      • YELLOW = manually selected at runtime
#      • CYAN   = derived (e.g., VCN derived from OKE cluster)
#      Do NOT hand-roll Focus blocks; _ui_menu_header --env handles it.
#
# SPINNERS & PROGRESS (see NEW MENU CHECKLIST above for when to use each):
#   - Multi-step discovery: _step_init / _step_active / _step_progress_start / _step_complete / _step_finish
#     ← PREFERRED for all menu/submenu views. Shows inline checkmarks on one line.
#   - File-based progress bar: _step_progress_start "label" "$dir" "*.json" $total
#     ← For parallel fetches within step discovery. Monitors files and shows [████░░░░].
#   - Single API call (action dialogs only): _show_spinner "msg" & / _kill_spinner $_sp
#   - Parallel N+1 fetch (legacy): _progress_start / _progress_done (wraps show_parallel_progress)
#   - Long-running ops: run_with_elapsed_timer "cmd" "$log_file"
#   - Shared constant: _SPINNER_CHARS (braille pattern, used by all spinner functions)
#   - EVERY OCI API call must have a spinner or progress bar
#   - Show commands BEFORE fetch, include (×N) count for parallel calls
#   - Progress bar files: use numeric index (item_${i}.json), NOT resource IDs
#   - CRITICAL: Never use bare `wait` when a _step_active spinner is running;
#     track PIDs in an array and `wait "${pids[@]}"` to avoid infinite hang.
#   - CRITICAL: Never run a spinner inside a function called via $() capture.
#     Spinner writes to stdout; $() captures it, corrupting the return value.
#     Instead: function writes to cache file + returns 0/1; caller reads file.
#
# CACHING:
#   - Define: readonly MY_CACHE="${CACHE_DIR}/name.json"
#   - Inline cache check: if file fresh → read; else → OCI call → save to file
#   - Write caches atomically: echo "$json" | _cache_write "$CACHE_FILE"
#     (writes to tmp then mv; prevents partial-read on crash)
#   - Invalidate: rm -f "$CACHE" on create/update/delete and refresh (r|R)
#   - Share caches across menus when data is the same (e.g., COMPARTMENTS_CACHE)
#   - Show _display_cache_info in menu header
#
# Safety:
#   - rm -rf: always use ${var:?} guard: rm -rf "${dir:?}" (prevents rm -rf "" on empty var)
#   - OCI_MAX_PARALLEL: use this constant for xargs -P / parallel job limits (env-configurable)
#
# OCI CLI:
#   - Boolean flags: --compartment-id-in-subtree true (key-value, NOT presence)
#   - Identity-domains SCIM: normalize .data envelope after every call
#   - Identity-domains: do NOT use --attribute-sets or --attributes on list calls
#   - Identity-domains group get: MUST use --attribute-sets all (members is null without it)
#   - Always --output json + 2>/dev/null for machine parsing
#   - Prefer _oci_call wrapper for new code (auto-detects auth failures,
#     rate limits, transient errors; retries automatically):
#       json=$(_oci_call "label" oci compute instance list --compartment-id "$CID" --all --output json)
#   - SC2155: split local declaration from assignment for OCI/jq calls:
#       local json           # declaration
#       json=$(oci ...)      # assignment (exit code visible)
#       NOT: local json=$(oci ...)  # exit code masked by local
#
# JQ HEREDOC:
#   - Always: jq '...' <<< "$var" 2>/dev/null
#   - Never:  jq '...' 2>/dev/null <<< "$var"  (heredoc after redirect breaks)
#
# LOGGING (create/update/delete):
#   - Show exact command on screen before execution
#   - Log to ${LOGS_DIR}/<action>_actions.log with timestamp
#
# COLORS: GREEN=success/active, YELLOW=selection/OCID/warning, RED=error,
#   CYAN=labels/prompts, MAGENTA=groups/principals, BLUE=compartments,
#   GRAY=metadata/timestamps, WHITE=primary content, DARK_GREEN=policy names
#   Lifecycle color helpers: color_oci_state, color_cluster_state, color_resource_state,
#   color_cap_topo_state, color_fabric_state, color_node_state (use instead of inline case)
#
# TERMINAL CONTROL (use variables, never raw ANSI codes):
#   CLEAR_LINE (\033[2K\r)  - Clear entire line + carriage return (spinners/progress)
#   CLEAR_EOL  (\033[K)     - Clear from cursor to end of line (timer/spinner cleanup)
#   DIM        (\033[2m)    - Dim/faint text (cache info, metadata)
#   NC         (\033[0m)    - Reset all attributes
#   All spinner/progress code must use these + color variables. No raw \033 sequences.
#
# TRAPS (consolidated EXIT handler):
#   EXIT  → _cleanup_all: kills bg jobs + spinner + progress, resets terminal, cleans temp
#   INT/TERM/HUP/QUIT → exit with conventional code → triggers EXIT cleanup
#   This covers: Ctrl+C, kill, SSH disconnect, Ctrl+\, and normal exit.
#

# Source guard: when sourced (. ./script), re-execute as a child process so that
# exit/Ctrl+C/traps/readonly don't pollute the parent shell (e.g. PuTTY session).
# MUST be the first executable statement — before set, readonly, or trap.
# trap ':' INT prevents bash's "wait and cooperative exit" from killing the parent
# when the child dies from SIGINT (Ctrl+C sends SIGINT to the entire process group).
if [[ "${BASH_SOURCE[0]}" != "${0}" ]]; then
    trap : INT
    bash "${BASH_SOURCE[0]}" "$@"
    __src_guard_rc=$?
    trap - INT
    return $__src_guard_rc 2>/dev/null || exit $__src_guard_rc
fi

set -o pipefail

#===============================================================================
# CONFIGURATION
#===============================================================================

# Color codes (readonly to prevent accidental modification)
readonly RED='\033[0;31m'
readonly GREEN='\033[0;32m'
readonly LIGHT_GREEN='\033[92m'
readonly YELLOW='\033[1;33m'
readonly BLUE='\033[0;34m'
readonly MAGENTA='\033[0;35m'
readonly CYAN='\033[0;36m'
readonly WHITE='\033[1;37m'
readonly GRAY='\033[0;90m'
readonly LIGHT_RED='\033[1;31m'
readonly ORANGE='\033[38;5;208m'
readonly BOLD='\033[1m'
