readonly GPU_NVLINK_ERROR_WARN="${GPU_NVLINK_ERROR_WARN:-100}" # NVLink replay errors

# Parallelism: max concurrent OCI API calls (override via environment variable)
# Lower for rate-limited tenancies, raise for high-limit tenancies
readonly OCI_MAX_PARALLEL=${OCI_MAX_PARALLEL:-10}

# Global throttle: limit concurrent background jobs to OCI_MAX_PARALLEL
# Use before launching background OCI API calls to prevent rate-limiting
_oci_throttle() {
    while [[ $(jobs -rp | wc -l) -ge ${OCI_MAX_PARALLEL} ]]; do sleep 0.15; done
}

