readonly TEMP_DIR="${CACHE_DIR}/tmp/${SESSION_ID}"
( umask 077 && mkdir -p "$TEMP_DIR" 2>/dev/null )
# All cleanup in EXIT trap — fires on normal exit AND after signal handlers call exit
readonly _MAIN_PID=$$
_cleanup_all() {
    # Only run cleanup in the main process — subshells must NOT delete shared state
    [[ "${BASHPID:-$$}" != "$_MAIN_PID" ]] && return 0
    # Kill spinner if running
    [[ -n "${_STEP_ANIM_PID:-}" ]] && kill "$_STEP_ANIM_PID" 2>/dev/null
    # Kill progress bar if running
    [[ -n "${_PROGRESS_PID:-}" ]] && kill "$_PROGRESS_PID" 2>/dev/null
    # Kill any background jobs (parallel OCI fetches)
    local _bg_pids
    _bg_pids=$(jobs -p 2>/dev/null)
    [[ -n "$_bg_pids" ]] && echo "$_bg_pids" | xargs -r kill 2>/dev/null
    # Reset terminal colors (harmless on clean exit)
    printf '%b' "${NC:-\033[0m}" 2>/dev/null
    # Clean temp files — remove this session's isolated dir entirely
    rm -rf "${TEMP_DIR:?}" 2>/dev/null
}
trap _cleanup_all EXIT

# Stale session cleanup — remove tmp dirs whose owning PID is dead
_cleanup_stale_sessions() {
    local _tmp_base="${CACHE_DIR}/tmp"
    [[ -d "$_tmp_base" ]] || return 0
    local _dir _pid
    for _dir in "${_tmp_base}"/*/; do
        [[ -d "$_dir" ]] || continue
        _pid="${_dir##*/}"          # e.g. ubuntu_12345
        _pid="${_pid##*_}"          # extract PID portion
        [[ "$_pid" =~ ^[0-9]+$ ]] || continue
        [[ "$_pid" == "$$" ]] && continue   # skip own session
        # If PID is dead AND dir is older than 1 hour (guards against PID recycling)
        if ! kill -0 "$_pid" 2>/dev/null; then
            local _dir_age=$(( $(date +%s) - $(stat -c %Y "$_dir" 2>/dev/null || echo 0) ))
            if [[ $_dir_age -gt 3600 ]]; then
                rm -rf "${_dir:?}" 2>/dev/null
            fi
        fi
    done
}
_cleanup_stale_sessions

# Signal handlers: reset terminal line, then exit with conventional code
# EXIT trap fires automatically after exit, handling all cleanup
trap 'printf "\n" 2>/dev/null; exit 130' INT       # Ctrl+C
trap 'exit 143' TERM                                 # kill $PID
trap 'exit 129' HUP                                  # SSH disconnect, terminal close
trap 'printf "\n" 2>/dev/null; exit 131' QUIT       # Ctrl+\

