# Centralized cache TTL registry — single source of truth for every cache file's TTL
# Default: CACHE_MAX_AGE (300s/5m). Only exceptions below (shorter than default).
# Used by _display_cache_info for validity checks and by fetch functions for freshness.
declare -gA CACHE_TTL_MAP=(
    # Cross-region DRG: 3m
    ["$XR_CACHE_DIR"]=180
    # Capacity reports: 20s (real-time availability)
    ["$CAPACITY_REPORT_CACHE_PREFIX"]=20
    # Audit events: 2m (frequent changes)
    ["$AUDIT_EVENTS_CACHE"]=120
    # Limits search index: 24h (service limit definitions rarely change)
    ["$LIMITS_SEARCH_INDEX"]=86400
    # Everything else: default CACHE_MAX_AGE (300s/5m)
)
# Lookup helper — returns TTL for a cache file, defaults to CACHE_MAX_AGE
_cache_ttl() {
    # Exact match first
    [[ -n "${CACHE_TTL_MAP[$1]:-}" ]] && { echo "${CACHE_TTL_MAP[$1]}"; return; }
    # Prefix match (e.g., capacity_report_AD-1.json → capacity_report prefix)
    local _k
    for _k in "${!CACHE_TTL_MAP[@]}"; do
        [[ "$1" == "${_k}"* ]] && { echo "${CACHE_TTL_MAP[$_k]}"; return; }
    done
    echo "$CACHE_MAX_AGE"
}

