# Print error message to stderr
log_error() {
    [[ "${_LOG_QUIET:-0}" == "1" ]] && return 0
    echo -e "${RED}[ERROR]${NC} $1" >&2
}

# Print warning message to stderr
log_warn() {
    [[ "${_LOG_QUIET:-0}" == "1" ]] && return 0
    echo -e "${YELLOW}[WARNING]${NC} $1" >&2
}

# Print info message to stderr (no color for cleaner output)
log_info() {
    [[ "${_LOG_QUIET:-0}" == "1" ]] && return 0
    echo "$1" >&2
}

# Logs directory setup - restrict to owner only (contains OCIDs and command details)
LOGS_DIR="${LOGS_DIR:-${CACHE_DIR}/logs}"
( umask 077 && mkdir -p "$LOGS_DIR" 2>/dev/null )

# Per-user log identification — isolates log files by OS username
readonly _LOG_USER="${USER:-$(id -un 2>/dev/null || echo unknown)}"

# Action log file for tracking changes (create, update, delete operations)
ACTION_LOG_FILE="${ACTION_LOG_FILE:-${LOGS_DIR}/oci_ops_actions_${_LOG_USER}_$(date +%Y%m%d).log}"

# Maintenance log file for maintenance operations
MAINTENANCE_LOG_FILE="${MAINTENANCE_LOG_FILE:-${LOGS_DIR}/oci_ops_maintenance_${_LOG_USER}_$(date +%Y%m%d).log}"

# Enforce restrictive permissions on log files (owner-only read/write)
( umask 077 && touch "$ACTION_LOG_FILE" "$MAINTENANCE_LOG_FILE" ) 2>/dev/null
chmod 600 "$ACTION_LOG_FILE" "$MAINTENANCE_LOG_FILE" 2>/dev/null

# Mask OCIDs in a string for secure logging (ocid1.xxx.oc1..aaaa...xyz → ocid1.xxx..****xyz)
# Preserves resource type and last 8 chars for identification while hiding the full ID
_mask_ocids() {
    local _s="$1"
    # Match ocid1.<type>.oc1..<region>.<hash> patterns — keep type + last 8 chars
    echo "$_s" | sed -E 's/(ocid1\.[a-z]+)\.[a-z0-9.]+([a-z0-9]{8})\b/\1..****\2/g'
}

# Log action to file and display command on screen
# Args: $1 = action type (e.g., REBOOT, TERMINATE), $2 = command being executed
log_action() {
    local action_type="$1"
    local command="$2"
    local quiet=0
    local context=""
    shift 2
    while [[ $# -gt 0 ]]; do
        case "$1" in
            --quiet) quiet=1 ;;
            --context) shift; context="$1" ;;
        esac
        shift
    done
    local timestamp
    timestamp=$(date '+%Y-%m-%d %H:%M:%S')
    
    # Display command on screen (unless --quiet)
    if [[ $quiet -eq 0 ]]; then
        echo ""
        echo -e "${YELLOW}Executing:${NC}"
        echo -e "${GRAY}$command${NC}"
        echo ""
    fi
    
    # Log to file (mask OCIDs for security — full IDs shown on screen above)
    local _masked_cmd; _masked_cmd=$(_mask_ocids "$command")
    {
        echo "========================================"
        echo "Timestamp: $timestamp"
        echo "Action: $action_type"
        [[ -n "$context" ]] && echo "Context: $(_mask_ocids "$context")"
        echo "Command: $_masked_cmd"
        echo "========================================"
        echo ""
    } >> "$ACTION_LOG_FILE" 2>/dev/null
}

# Log action result to file
# Args: $1 = result (SUCCESS/FAILED), $2 = optional details
log_action_result() {
    local result="$1"
    local details="${2:-}"
    local timestamp
    timestamp=$(date '+%Y-%m-%d %H:%M:%S')

    {
        echo "Result: $result"
        [[ -n "$details" ]] && echo "Details: $(_mask_ocids "$details")"
        echo "Completed: $timestamp"
        echo ""
    } >> "$ACTION_LOG_FILE" 2>/dev/null
}

# Check if a value is a valid OCID (not empty, not N/A, not null)
# Args: $1 = value to check
# Returns: 0 if valid, 1 if invalid
is_valid_ocid() {
    local val="$1"
    [[ -n "$val" && "$val" != "N/A" && "$val" != "null" ]]
}

# Wrapper for OCI CLI calls with error classification
# Captures stderr, detects common failure modes (auth, rate-limit, service outage),
# and optionally retries on transient errors.
# Args: $1 = label (for error messages), $@ = full OCI command
# Stdout: command output (JSON)
# Returns: command exit code
# Usage:
#   local json
#   json=$(_oci_call "instance list" oci compute instance list --compartment-id "$CID" --all --output json)
_oci_call() {
    local label="$1"
    shift

    local _oc_errfile="${TEMP_DIR}/oci_last_error_${BASHPID}_${RANDOM}.txt"
    local _oc_output
    local _oc_rc
    _oc_output=$("$@" 2>"$_oc_errfile")
    _oc_rc=$?

    if [[ $_oc_rc -ne 0 ]]; then
        local _oc_err=""
        [[ -f "$_oc_errfile" ]] && _oc_err=$(cat "$_oc_errfile" 2>/dev/null)

        case "$_oc_err" in
            *"NotAuthenticated"*|*"NotAuthorized"*|*"SignatureNotFound"*)
                log_error "$label: Authentication failed — check OCI CLI config or token expiry"
                ;;
            *"TooManyRequests"*)
                log_warn "$label: Rate limited — retrying in 5s..."
                sleep 5
                _oc_output=$("$@" 2>/dev/null)
                _oc_rc=$?
                [[ $_oc_rc -ne 0 ]] && log_error "$label: Rate limit retry failed"
                ;;
            *"ServiceUnavailable"*|*"InternalServerError"*)
                log_warn "$label: OCI service error (transient) — retrying in 3s..."
                sleep 3
                _oc_output=$("$@" 2>/dev/null)
                _oc_rc=$?
                [[ $_oc_rc -ne 0 ]] && log_error "$label: Service retry failed"
                ;;
            *"NotFound"*)
                # Resource not found — not an error to log loudly
                [[ "$DEBUG_MODE" == "true" ]] && log_warn "$label: Resource not found"
                ;;
            *"InvalidParameter"*|*"MissingParameter"*)
                log_error "$label: Invalid/missing parameter in OCI call"
                [[ "$DEBUG_MODE" == "true" ]] && log_error "  Detail: $_oc_err"
                ;;
            *)
                [[ "$DEBUG_MODE" == "true" ]] && log_warn "$label: OCI call failed (rc=$_oc_rc): ${_oc_err:0:200}"
                ;;
        esac
    fi

    rm -f "$_oc_errfile" 2>/dev/null
    echo "$_oc_output"
    return $_oc_rc
}

# Check if cache file is fresh (less than CACHE_MAX_AGE seconds old)
# Args: $1 = cache file path
# Returns: 0 if fresh, 1 if stale or missing
is_cache_fresh() {
    local cache_file="$1"
    local custom_ttl="${2:-}"
    
    [[ ! -f "$cache_file" ]] && return 1
    
    local file_mtime
    file_mtime=$(stat -c %Y "$cache_file" 2>/dev/null) || return 1
    
    local current_time
    current_time=$(date +%s)
    
    # Priority: explicit arg > CACHE_TTL_MAP > CACHE_MAX_AGE
    local ttl="${custom_ttl:-${CACHE_TTL_MAP[$cache_file]:-$CACHE_MAX_AGE}}"
    
    local cache_age=$((current_time - file_mtime))
    [[ $cache_age -lt $ttl ]]
}

# Atomic cache write: write to temp file then rename (mv is atomic on same filesystem)
# Prevents readers from seeing partial data if script is killed mid-write.
# Args: $1 = cache file path, stdin = data to write
# Usage: echo "$json_data" | _cache_write "$INSTANCE_LIST_CACHE"
#    or: _cache_write "$CACHE_FILE" <<< "$data"
_cache_write() {
    local cache_file="$1"
    local tmp_file="${cache_file}.tmp.$$"
    if cat > "$tmp_file" && [[ -s "$tmp_file" ]]; then
        mv -f "$tmp_file" "$cache_file"
    else
        rm -f "$tmp_file" 2>/dev/null
        return 1
    fi
}

# Invalidate a JSON cache if any resource has a transitional lifecycle state.
# Ensures next loop iteration fetches fresh data for in-progress operations.
# Args: $1 = cache file path
#       $2 = JSON data (or empty to read from file)
#       $3 = jq filter to extract lifecycle states (default: .data[]."lifecycle-state")
# Returns: 0 if cache was invalidated, 1 if no transitional states found
# Transitional states: UPDATING, CREATING, DELETING, PROVISIONING, SCALING,
#   TERMINATING, STARTING, STOPPING, MOVING, IMPORTING, EXPORTING, RESTORING,
#   CONFIGURING, IN_PROGRESS, PENDING, ACCEPTED, CANCELING
_cache_invalidate_if_transitional() {
    local _cache_file="$1"
    local _json_data="${2:-}"
    local _jq_filter="${3:-.data[].\"lifecycle-state\"}"
    
    [[ ! -f "$_cache_file" ]] && return 1
    
    local _source="$_json_data"
    [[ -z "$_source" ]] && _source=$(cat "$_cache_file" 2>/dev/null)
    [[ -z "$_source" ]] && return 1
    
    local _count
    _count=$(jq -r "$_jq_filter // empty" <<< "$_source" 2>/dev/null | \
        grep -ciE 'UPDATING|CREATING|DELETING|PROVISIONING|SCALING|TERMINATING|STARTING|STOPPING|MOVING|IMPORTING|EXPORTING|RESTORING|CONFIGURING|IN_PROGRESS|PENDING|ACCEPTED|CANCELING' 2>/dev/null)
    
    if [[ "${_count:-0}" -gt 0 ]]; then
        rm -f "$_cache_file"
        return 0
    fi
    return 1
}

# Invalidate a text-based cache if any line contains a transitional state.
# Args: $1 = cache file path
# Returns: 0 if invalidated, 1 if no transitional states
_cache_invalidate_text_if_transitional() {
    local _cache_file="$1"
    [[ ! -f "$_cache_file" ]] && return 1
    
    local _count
    _count=$(grep -ciE 'UPDATING|CREATING|DELETING|PROVISIONING|SCALING|TERMINATING|STARTING|STOPPING|MOVING|IMPORTING|EXPORTING|RESTORING|CONFIGURING|IN_PROGRESS|PENDING|ACCEPTED|CANCELING' "$_cache_file" 2>/dev/null)
    
    if [[ "${_count:-0}" -gt 0 ]]; then
        rm -f "$_cache_file"
        return 0
    fi
    return 1
}

# Display a compact one-liner showing which caches are in use on the current page
# Args: pairs of "cache_file|label|type_filter" where type_filter is optional
#   - Text caches: lines counted (excluding #comments and blank lines)
#   - Text caches with type_filter: only count lines starting with that prefix
#   - JSON caches (*.json): count via jq .data (array) or .data.items (object) length
#   - If cache missing: shows ✗ NOT CACHED in red
# Output: single dim line with item counts and ages, TTL at end:
#   Cache: Subnets (8, 3m)  NSGs (12, 3m)  Routes (5, 67m)  │ TTL: 1h
_display_cache_info() {
    local parts=()
    local -A seen_ttls=()
    
    for spec in "$@"; do
        local cache_file label type_filter
        IFS='|' read -r cache_file label type_filter <<< "$spec"
        
        [[ -z "$cache_file" || -z "$label" ]] && continue
        
        # Lookup TTL from centralized registry
        local ttl
        ttl=$(_cache_ttl "$cache_file")
        seen_ttls["$ttl"]=1
        
        if [[ ! -f "$cache_file" || ! -s "$cache_file" ]]; then
            parts+=("${label} (0, --)")
            continue
        fi
        
        # Count items
        local count=0
        local ext="${cache_file##*.}"
        if [[ "$ext" == "json" ]]; then
            count=$(jq -r 'if (.data | type) == "array" then (.data | length) elif (.data.items // null | type) == "array" then (.data.items | length) else 0 end' "$cache_file" 2>/dev/null || echo 0)
        elif [[ -n "$type_filter" ]]; then
            count=$(grep -c "^${type_filter}|" "$cache_file" 2>/dev/null || true)
        else
            count=$(grep -cvE '^#|^$' "$cache_file" 2>/dev/null || true)
        fi
        count=${count:-0}
        count=$(echo "$count" | tr -d '[:space:]')
        
        # Age calculation
        local mtime age_secs age_str
        mtime=$(stat -c %Y "$cache_file" 2>/dev/null || echo 0)
        age_secs=$(( $(date +%s) - mtime ))
        if [[ $age_secs -lt 60 ]]; then
            age_str="<1m"
        elif [[ $age_secs -ge 3600 ]]; then
            age_str="$((age_secs / 3600))h$((age_secs % 3600 / 60))m"
        else
            age_str="$((age_secs / 60))m"
        fi
        
        parts+=("${label} (${count}, ${age_str})")
    done
    
    [[ ${#parts[@]} -eq 0 ]] && return
    
    # Build TTL display
    local ttl_display=""
    local ttl_keys=("${!seen_ttls[@]}")
    if [[ ${#ttl_keys[@]} -eq 1 ]]; then
        local t="${ttl_keys[0]}"
        if [[ $t -ge 3600 ]]; then
            ttl_display="$((t / 3600))h"
        else
            ttl_display="$((t / 60))m"
        fi
    elif [[ ${#ttl_keys[@]} -gt 1 ]]; then
        local min_t=999999 max_t=0
        for t in "${ttl_keys[@]}"; do
            [[ $t -lt $min_t ]] && min_t=$t
            [[ $t -gt $max_t ]] && max_t=$t
        done
        local min_s max_s
        [[ $min_t -ge 3600 ]] && min_s="$((min_t / 3600))h" || min_s="$((min_t / 60))m"
        [[ $max_t -ge 3600 ]] && max_s="$((max_t / 3600))h" || max_s="$((max_t / 60))m"
        ttl_display="${min_s}–${max_s}"
    fi
    
    # Build lines with wrapping at UI_WIDTH
    # Caller sets _CACHE_PREFIX_WIDTH if prefix differs from default "  Cache: " (10 chars)
    local prefix_width=${_CACHE_PREFIX_WIDTH:-10}
    local max_width=${UI_WIDTH:-120}
    local current_len=$prefix_width
    local current_line=""
    local all_lines=()
    
    for ((i=0; i<${#parts[@]}; i++)); do
        local part="${parts[$i]}"
        local sep=""
        [[ -n "$current_line" ]] && sep="  "
        local add_len=$(( ${#sep} + ${#part} ))
        
        if [[ -n "$current_line" ]] && [[ $((current_len + add_len)) -gt $max_width ]]; then
            # Wrap: save current line, start new one with indent
            all_lines+=("$current_line")
            current_line="$part"
            current_len=$(( prefix_width + ${#part} ))
        else
            current_line+="${sep}${part}"
            current_len=$((current_len + add_len))
        fi
    done
    
    # Append TTL to last line or wrap if needed
    # NOTE: Use visible width, not ${#}, because │ (U+2502, 3 bytes) and – (U+2013, 3 bytes)
    # are single-column but multi-byte. ${#} counts bytes, inflating length by 2 per char.
    if [[ -n "$ttl_display" ]]; then
        local ttl_part="  │ TTL: ${ttl_display}"
        # "  │ TTL: " = 9 visible cols; strip unicode for accurate display length
        local _ttl_ascii="${ttl_display//–/-}"
        local ttl_visible_len=$(( 9 + ${#_ttl_ascii} ))
        if [[ $((current_len + ttl_visible_len)) -gt $max_width ]]; then
            all_lines+=("$current_line")
            current_line="│ TTL: ${ttl_display}"
        else
            current_line+="$ttl_part"
        fi
    fi
    [[ -n "$current_line" ]] && all_lines+=("$current_line")
    
    # Output: first line inline, subsequent lines indented to align after "Cache: "
    local pad
    pad=$(printf '%*s' $prefix_width '')
    for ((i=0; i<${#all_lines[@]}; i++)); do
        if [[ $i -eq 0 ]]; then
            echo -e "${DIM}${GRAY}${all_lines[$i]}${NC}"
        else
            echo -e "${pad}${DIM}${GRAY}${all_lines[$i]}${NC}"
        fi
    done
}
# Uses trap to ensure cleanup on script exit
create_temp_file() {
    local tmp
    # Ensure temp directory exists
    [[ ! -d "$TEMP_DIR" ]] && mkdir -p "$TEMP_DIR"
    tmp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX") || { log_error "Failed to create temp file"; return 1; }
    echo "$tmp"
}

#--------------------------------------------------------------------------------
# Safe command execution - validates command prefix before executing
# Validates command starts with known-safe prefix, then executes directly
# Uses word-splitting to convert the command string into an array (no eval).
# Args: $1 = command string to execute
# Returns: command exit code; stdout/stderr passed through
#--------------------------------------------------------------------------------
_safe_exec() {
    local cmd="$1"
    case "$cmd" in
        oci\ *|kubectl\ *|python3\ *|diff\ *|jq\ *) ;;
        *) log_error "_safe_exec blocked unknown command prefix: ${cmd%% *}"; return 1 ;;
    esac
    # Convert string to array via word-splitting (safe: values are OCIDs/flags, not user input)
    local -a _cmd_arr
    read -r -a _cmd_arr <<< "$cmd"
    # Disable OCI CLI interactive mode to prevent TUI prompts in non-interactive contexts
    OCI_CLI_INTERACTIVE=0 "${_cmd_arr[@]}" 2>&1
}

# Show progress bar for parallel operations
# Args: $1 = output_dir, $2 = file_pattern, $3 = total_count, $4 = description
# Runs in background, call with & and capture PID, then kill when done
# Prefer using _progress_start / _progress_done wrappers instead of calling directly.
readonly _SPINNER_CHARS='⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏'

show_parallel_progress() {
    local output_dir="$1"
    local file_pattern="$2"
    local total="$3"
    local desc="${4:-Processing}"
    
    local spin_idx=0
    
    while true; do
        local completed
        completed=$(find "$output_dir" -name "$file_pattern" 2>/dev/null | wc -l)
        local pct=0
        [[ "$total" -gt 0 ]] && pct=$((completed * 100 / total))
        
        # Build progress bar (20 chars wide)
        local filled=$((pct / 5))
        local empty=$((20 - filled))
        local bar=""
        for ((i=0; i<filled; i++)); do bar+="█"; done
        for ((i=0; i<empty; i++)); do bar+="░"; done
        
        # Get spinner character
        local spin_char="${_SPINNER_CHARS:$spin_idx:1}"
        spin_idx=$(( (spin_idx + 1) % ${#_SPINNER_CHARS} ))
        
        # Print progress (clear line + carriage return to overwrite)
        printf "${CLEAR_LINE}  ${CYAN}%s${NC} [${GREEN}%s${NC}] %3d%% (%d/%d) %s " "$spin_char" "$bar" "$pct" "$completed" "$total" "$desc"
        
        # Exit if complete
        [[ "$completed" -ge "$total" ]] && break
        
        sleep 0.2
    done
    printf "${CLEAR_LINE}  ${GREEN}✓${NC} [████████████████████] 100%% (%d/%d) %s " "$total" "$total" "$desc"
}

#--------------------------------------------------------------------------------
# Parallel progress lifecycle helpers
# Wrap show_parallel_progress start/stop boilerplate into two calls.
# Handles _QUIET_SPINNERS suppression, PID management, and 100% completion line.
#
# Usage:
#   _progress_start "$temp_dir" "item_*.json" "$total" "Fetching items"
#   <parallel work that creates files matching the pattern>
#   _progress_done "$total" "Fetching items"
#
# For cases where completed count differs from total (e.g., partial success):
#   _progress_done "$success_count" "items fetched" "$total"
#--------------------------------------------------------------------------------
_PROGRESS_PID=""

_progress_start() {
    local output_dir="$1"
    local file_pattern="$2"
    local total="$3"
    local desc="${4:-Processing}"
    
    _PROGRESS_PID=""
    if [[ "${_QUIET_SPINNERS:-0}" != "1" ]]; then
        show_parallel_progress "$output_dir" "$file_pattern" "$total" "$desc" &
        _PROGRESS_PID=$!
    fi
}

_progress_done() {
    local completed="$1"
    local desc="${2:-Processing}"
    local total="${3:-$completed}"  # Optional: if completed != total (e.g., NSG success/fetch)
    
    if [[ -n "$_PROGRESS_PID" ]]; then
        kill "$_PROGRESS_PID" 2>/dev/null
        wait "$_PROGRESS_PID" 2>/dev/null
        printf "${CLEAR_LINE}  ${GREEN}✓${NC} [████████████████████] 100%% (%d/%d) %s \n" "$completed" "$total" "$desc"
        _PROGRESS_PID=""
    fi
}

# Run a command with a live elapsed timer display
# Streams command output in real-time while showing an updating elapsed counter
# Args: $1 = command string to execute, $2 = log file to append output, $3 = timeout seconds (optional, shown in timer)
# Returns: exit code of the executed command
# Usage: run_with_elapsed_timer "my_long_command --args" "/path/to/logfile" 1200
#        local exit_code=$?
run_with_elapsed_timer() {
    local cmd_to_run="$1"
    local timer_log_file="${2:-}"
    local timer_timeout_secs="${3:-0}"
    local timer_timeout_label=""
    if [[ "$timer_timeout_secs" -gt 0 ]]; then
        timer_timeout_label=" / timeout $(( timer_timeout_secs / 60 ))m"
    fi
    local timer_start=$(date +%s)
    local timer_output_tmp
    timer_output_tmp=$(mktemp "${TEMP_DIR}/timer_output.XXXXXXXXXX")
    
    # Show timer header
    echo -e "  ${CYAN}⏱ Timer started - tracking elapsed time${NC}"
    echo ""
    
    # Run command in background, capture all output to temp file
    # Uses word-splitting array conversion instead of eval for safety
    # $cmd_to_run is constructed internally by calling functions, not from user input
    local -a _timer_cmd_arr
    read -r -a _timer_cmd_arr <<< "$cmd_to_run"
    "${_timer_cmd_arr[@]}" > "$timer_output_tmp" 2>&1 &
    local cmd_pid=$!
    
    # Monitor loop: show timer + new output lines
    local last_line_count=0
    local spin_idx=0
    
    while kill -0 "$cmd_pid" 2>/dev/null; do
        # Check for new output lines
        local current_lines
        current_lines=$(wc -l < "$timer_output_tmp" 2>/dev/null || echo "0")
        
        if [[ $current_lines -gt $last_line_count ]]; then
            # Clear the timer line before showing output
            printf "\r${CLEAR_EOL}"
            # Display new lines
            sed -n "$((last_line_count + 1)),${current_lines}p" "$timer_output_tmp"
            last_line_count=$current_lines
        fi
        
        # Update elapsed timer (overwrites itself on same line via \r)
        local elapsed=$(($(date +%s) - timer_start))
        local t_hrs=$((elapsed / 3600))
        local t_mins=$(( (elapsed % 3600) / 60 ))
        local t_secs=$((elapsed % 60))
        local spin_char="${_SPINNER_CHARS:$spin_idx:1}"
        spin_idx=$(( (spin_idx + 1) % ${#_SPINNER_CHARS} ))
        
        if [[ $t_hrs -gt 0 ]]; then
            printf "\r  ${CYAN}%s ⏱ Elapsed: %dh %02dm %02ds%b${NC}" "$spin_char" "$t_hrs" "$t_mins" "$t_secs" "${GRAY}${timer_timeout_label}"
        elif [[ $t_mins -gt 0 ]]; then
            printf "\r  ${CYAN}%s ⏱ Elapsed: %dm %02ds%b${NC}" "$spin_char" "$t_mins" "$t_secs" "${GRAY}${timer_timeout_label}"
        else
            printf "\r  ${CYAN}%s ⏱ Elapsed: %ds%b${NC}" "$spin_char" "$t_secs" "${GRAY}${timer_timeout_label}"
        fi
        
        sleep 1
    done
    
    # Wait for process to fully exit and capture exit code
    wait "$cmd_pid"
    local cmd_exit_code=$?
    
    # Show any remaining output that arrived after last check
    local final_lines
    final_lines=$(wc -l < "$timer_output_tmp" 2>/dev/null || echo "0")
    if [[ $final_lines -gt $last_line_count ]]; then
        printf "\r${CLEAR_EOL}"
        sed -n "$((last_line_count + 1)),${final_lines}p" "$timer_output_tmp"
    fi
    
    # Also check for any trailing partial line (no newline at end)
    local file_last_char
    file_last_char=$(tail -c 1 "$timer_output_tmp" 2>/dev/null | xxd -p 2>/dev/null)
    if [[ -n "$file_last_char" && "$file_last_char" != "0a" ]]; then
        # There's a partial line at the end without a newline
        printf "\r${CLEAR_EOL}"
        local partial_line
        partial_line=$(tail -n 1 "$timer_output_tmp" 2>/dev/null)
        # Only show if it's different from what we already showed
        if [[ $final_lines -eq $last_line_count ]]; then
            echo "$partial_line"
        fi
    fi
    
    # Append all output to the log file
    if [[ -n "$timer_log_file" ]]; then
        cat "$timer_output_tmp" >> "$timer_log_file" 2>/dev/null
    fi
    
    # Clean up temp file
    rm -f "$timer_output_tmp"
    
    # Calculate and display final elapsed time
    local total_elapsed=$(($(date +%s) - timer_start))
    local final_hrs=$((total_elapsed / 3600))
    local final_mins=$(( (total_elapsed % 3600) / 60 ))
    local final_secs=$((total_elapsed % 60))
    
    printf "\r${CLEAR_EOL}"
    echo ""
    if [[ $final_hrs -gt 0 ]]; then
        echo -e "  ${BOLD}${CYAN}⏱ Total elapsed: ${WHITE}${final_hrs}h ${final_mins}m ${final_secs}s${NC}"
    elif [[ $final_mins -gt 0 ]]; then
        echo -e "  ${BOLD}${CYAN}⏱ Total elapsed: ${WHITE}${final_mins}m ${final_secs}s${NC}"
    else
        echo -e "  ${BOLD}${CYAN}⏱ Total elapsed: ${WHITE}${final_secs}s${NC}"
    fi
    
    return $cmd_exit_code
}

# Simple animated spinner for background use (matches capacity topology visual style)
# Usage: _show_spinner "Fetching data..." &
#        local _sp=$!; <work>; _kill_spinner $_sp "Done message"
_show_spinner() {
    local desc="${1:-Working...}"
    # When called inside step-progress context, exit immediately as a no-op.
    # The PID remains valid for _kill_spinner to target (kill/wait of dead PID is harmless).
    if [[ "${_QUIET_SPINNERS:-0}" == "1" ]]; then
        return 0
    fi
    local i=0
    trap 'return 0' TERM INT
    while true; do
        printf "${CLEAR_LINE}  ${CYAN}%s${NC} %s " "${_SPINNER_CHARS:$((i % ${#_SPINNER_CHARS})):1}" "$desc"
        ((i++))
        sleep 0.15
    done
}

# Kill a spinner process and optionally print a completion message
_kill_spinner() {
    local pid="$1"
    local done_msg="${2:-}"
    kill "$pid" 2>/dev/null
    wait "$pid" 2>/dev/null
    # Skip display updates when quiet (step-progress owns the line)
    [[ "${_QUIET_SPINNERS:-0}" == "1" ]] && return
    if [[ -n "$done_msg" ]]; then
        printf "${CLEAR_LINE}  ${GREEN}✓${NC} %s \n" "$done_msg"
    else
        printf "${CLEAR_LINE}"
    fi
}

#--------------------------------------------------------------------------------
# Multi-step single-line progress display
# Shows completed steps with ✓ and active step with animated spinner on ONE line
# Each _step_active forks a subshell that animates; _step_complete kills it + adds ✓
#
# Usage:
#   _step_init                    # Reset state
#   _step_active "instances"      # ⠋ instances...
#   <do work>
#   _step_complete "instances"    # ✓ instances
#   _step_active "nodes"          # ✓ instances  ⠋ nodes...
#   <do work>
#   _step_complete "nodes"        # ✓ instances  ✓ nodes
#   _step_progress_start "BV" "$dir" "*.json" 10  # ✓ instances  ✓ nodes  ⠋ [████░░░░] 40% BV(4/10)...
#   <parallel work creating files>
#   _step_complete "BV(10)"       # ✓ instances  ✓ nodes  ✓ BV(10)
#   _step_finish                  # Final newline
#--------------------------------------------------------------------------------
_STEP_ANIM_PID=""
_STEP_COMPLETED_TEXT=""

_step_init() {
    # When _STEP_OUTER is set, a parent function controls the bar — skip init
    [[ "${_STEP_OUTER:-0}" -eq 1 ]] && return 0
    _STEP_ANIM_PID=""
    _STEP_COMPLETED_TEXT=""
    _STEP_ACTIVE_T0=""
    _LOG_QUIET=1
    _QUIET_SPINNERS=1
    print_separator $UI_WIDTH "$GRAY"
    echo -e "  ${GRAY}Discovering:${NC}"
}

_step_active() {
    local label="$1"
    # Record start time for elapsed timer (bash 5.0+ EPOCHREALTIME, fallback to date)
    if [[ -n "${EPOCHREALTIME:-}" ]]; then
        _STEP_ACTIVE_T0="$EPOCHREALTIME"
    else
        _STEP_ACTIVE_T0=$(date +%s.%N 2>/dev/null || date +%s)
    fi
    # Safety: kill any stale animation before starting new one
    if [[ -n "$_STEP_ANIM_PID" ]]; then
        kill "$_STEP_ANIM_PID" 2>/dev/null
        wait "$_STEP_ANIM_PID" 2>/dev/null
        _STEP_ANIM_PID=""
    fi
    local completed="$_STEP_COMPLETED_TEXT"
    (
        local i=0
        trap 'return 0' TERM INT
        while true; do
            printf "${CLEAR_LINE}  %b${CYAN}%s${NC} %s... " "$completed" "${_SPINNER_CHARS:$((i % ${#_SPINNER_CHARS})):1}" "$label"
            ((i++))
            sleep 0.15
        done
    ) &
    _STEP_ANIM_PID=$!
}

_step_complete() {
    local label="$1"
    if [[ -n "$_STEP_ANIM_PID" ]]; then
        kill "$_STEP_ANIM_PID" 2>/dev/null
        wait "$_STEP_ANIM_PID" 2>/dev/null
        _STEP_ANIM_PID=""
    fi
    # Append elapsed time since _step_active
    if [[ -n "${_STEP_ACTIVE_T0:-}" ]]; then
        local _t1
        if [[ -n "${EPOCHREALTIME:-}" ]]; then
            _t1="$EPOCHREALTIME"
        else
            _t1=$(date +%s.%N 2>/dev/null || date +%s)
        fi
        local _dt
        _dt=$(awk "BEGIN{printf \"%.1f\", ${_t1} - ${_STEP_ACTIVE_T0}}" 2>/dev/null)
        if [[ -n "$_dt" ]]; then
            label+="${GRAY}, ${_dt}s${NC}"
        fi
    fi
    _STEP_COMPLETED_TEXT+="${GREEN}✓${NC} ${label}  "
    printf "${CLEAR_LINE}  %b" "$_STEP_COMPLETED_TEXT"
}

_step_finish() {
    # When _STEP_OUTER is set, a parent function controls the bar — skip finish
    [[ "${_STEP_OUTER:-0}" -eq 1 ]] && return 0
    if [[ -n "$_STEP_ANIM_PID" ]]; then
        kill "$_STEP_ANIM_PID" 2>/dev/null
        wait "$_STEP_ANIM_PID" 2>/dev/null
        _STEP_ANIM_PID=""
    fi
    printf "${CLEAR_LINE}  %b\n" "$_STEP_COMPLETED_TEXT"
    _STEP_COMPLETED_TEXT=""
    _LOG_QUIET=0
    _QUIET_SPINNERS=0
    print_separator $UI_WIDTH "$GRAY"
}

# End the current phase within a discovery bar.
# Prints the accumulated progress line and resets for a new line.
# Use between _step_init and _step_finish to keep each spinner phase on its
# own terminal line (~180 chars max), avoiding ghost text from line wrapping.
# Only works when called from the parent bar (not suppressed by _STEP_OUTER).
_step_phase_end() {
    [[ "${_STEP_OUTER:-0}" -eq 1 ]] && return 0
    if [[ -n "$_STEP_ANIM_PID" ]]; then
        kill "$_STEP_ANIM_PID" 2>/dev/null
        wait "$_STEP_ANIM_PID" 2>/dev/null
        _STEP_ANIM_PID=""
    fi
    [[ -n "$_STEP_COMPLETED_TEXT" ]] && printf "${CLEAR_LINE}  %b\n" "$_STEP_COMPLETED_TEXT"
    _STEP_COMPLETED_TEXT=""
}

# File-based progress bar variant of _step_active
# Monitors a directory for completed files and shows inline progress bar
# Usage: _step_progress_start "label" "/path/to/dir" "*.json" 10
#        <parallel work creating files>
#        _step_complete "label(10)"
_step_progress_start() {
    local label="$1"
    local output_dir="$2"
    local file_pattern="$3"
    local total="$4"
    # Record start time for elapsed timer
    if [[ -n "${EPOCHREALTIME:-}" ]]; then
        _STEP_ACTIVE_T0="$EPOCHREALTIME"
    else
        _STEP_ACTIVE_T0=$(date +%s.%N 2>/dev/null || date +%s)
    fi
    # Safety: kill any stale animation before starting new one
    if [[ -n "$_STEP_ANIM_PID" ]]; then
        kill "$_STEP_ANIM_PID" 2>/dev/null
        wait "$_STEP_ANIM_PID" 2>/dev/null
        _STEP_ANIM_PID=""
    fi
    local completed="$_STEP_COMPLETED_TEXT"
    (
        local i=0
        trap 'return 0' TERM INT
        while true; do
            local done_count
            done_count=$(find "$output_dir" -maxdepth 1 -type f -name "$file_pattern" 2>/dev/null | wc -l)
            local pct=0
            [[ "$total" -gt 0 ]] && pct=$((done_count * 100 / total))
            local filled=$((pct / 5))
            local empty=$((20 - filled))
            local bar=""
            for ((j=0; j<filled; j++)); do bar+="█"; done
            for ((j=0; j<empty; j++)); do bar+="░"; done
            printf "${CLEAR_LINE}  %b${CYAN}%s${NC} [${GREEN}%s${NC}] %3d%% %s(%d/%d)... " \
                "$completed" "${_SPINNER_CHARS:$((i % ${#_SPINNER_CHARS})):1}" "$bar" "$pct" "$label" "$done_count" "$total"
            ((i++))
            sleep 0.2
        done
    ) &
    _STEP_ANIM_PID=$!
}

# Cache line count — count non-comment, non-empty lines in a cache file
# Usage: _clc "$CACHE_FILE"  →  "12" or "0"
_clc() { local _n; _n=$(grep -v '^#' "$1" 2>/dev/null | grep -c . 2>/dev/null); echo "${_n:-0}"; }

# Wait for an array of background PIDs with optional debug logging on failure
# Usage: _wait_pids <label> pid1 pid2 ...
# Logs per-pid failures when DEBUG_MODE=true; always returns count of failures
_wait_pids() {
    local _label="$1"; shift
    local _fail_count=0
    local _p
    for _p in "$@"; do
        if ! wait "$_p" 2>/dev/null; then
            ((_fail_count++))
            [[ "$DEBUG_MODE" == "true" ]] && echo -e "  ${GRAY}[${_label}] Background job $_p exited non-zero${NC}" >&2
        fi
    done
    return "$_fail_count"
}

# Args: $1 = cache file, $2 = key, $3 = field number (1-indexed)
# Returns: field value or "N/A" if not found
lookup_cache() {
    local cache_file="$1"
    local key="$2"
    local field="$3"
    
    [[ ! -f "$cache_file" ]] && { echo "N/A"; return 1; }
    
    local line
    line=$(grep -F "${key}|" "$cache_file" 2>/dev/null | head -n1)
    
    if [[ -n "$line" ]]; then
        local value
        value=$(echo "$line" | cut -d'|' -f"$field")
        echo "${value:-N/A}"
    else
        echo "N/A"
        return 1
    fi
}

# Get full pipe-delimited line from cache by key (first field match)
# Args: $1 = cache file, $2 = key (matched against first pipe-delimited field)
# Returns: full line or empty string; return code 1 if not found
_cache_line() {
    [[ ! -f "$1" ]] && return 1
    grep -F "${2}|" "$1" 2>/dev/null | head -1
}

# Refresh all cache files
refresh_all_caches() {
    echo -e "${BOLD}${CYAN}Refreshing all caches...${NC}"
    
    # List of all cache files
    local cache_files=(
        "$FABRIC_CACHE"
        "$FABRIC_JSON_CACHE"
        "$CLUSTER_CACHE"
        "$CLUSTER_JSON_CACHE"
        "$INSTANCE_CLUSTER_MAP_CACHE"
        "$INSTANCE_CONFIG_CACHE"
        "$NODE_STATE_CACHE"
        "$CAPACITY_TOPOLOGY_CACHE"
        "$CAPACITY_TOPOLOGY_JSON_CACHE"
        "$ANNOUNCEMENTS_LIST_CACHE"
        "$OKE_ENV_CACHE"
        "$OKE_CLUSTER_JSON_CACHE"
        "$OKE_CLUSTER_OPTIONS_CACHE"
        "$OKE_ADDON_OPTIONS_CACHE"
        "$OKE_NODEPOOL_CACHE"
        "$OKE_SUBNET_LIST_CACHE"
        "$COMPUTE_CLUSTER_CACHE"
        "$COMPUTE_CLUSTER_JSON_CACHE"
        "$NETWORK_RESOURCES_CACHE"
        "$VCN_LIST_CACHE"
        "$IGW_CACHE"
        "$SGW_CACHE"
        "$NAT_CACHE"
        "$DRG_CACHE"
        "$DRG_LIST_CACHE"
        "$LPG_CACHE"
        "$RPC_CACHE"
        "$RT_CACHE"
        "$NSG_RULES_CACHE"
        "$NSG_SUBNET_MAP_CACHE"
        "$SL_CACHE"
        "$MAINT_EVENTS_CACHE"
        "$FAULT_DETAILS_CACHE"
        "$OS_PE_CACHE"
        "$INSTANCE_LIST_CACHE"
        "$CUSTOM_IMAGE_CACHE"
        "$FSS_FS_CACHE"
        "$FSS_MT_CACHE"
        "$FSS_EXPORT_CACHE"
        "$FSS_MT_IP_CACHE"
        "$LUSTRE_FS_CACHE"
        "$POLICIES_ALL_CACHE"
        "$COMPARTMENTS_CACHE"
        "$AD_LIST_CACHE"
        "$COMPUTE_SHAPES_CACHE"
        "$COMPUTE_LIMITS_CACHE"
        "$COMPUTE_LIMITS_REGION_CACHE"
        "$INSTANCE_POOL_CACHE"
        "$CLUSTER_NETWORK_CACHE"
        "$COMPUTE_HOST_CACHE"
        "$COMPUTE_HOST_JSON_CACHE"
        "$BOOT_VOLUME_CACHE"
        "$IMAGE_CACHE"
        "$VAULTS_CACHE"
        "$LIMITS_SERVICE_CACHE"
        "$LIMITS_QUOTA_CACHE"
        "$LIMITS_SEARCH_INDEX"
        "$AUDIT_EVENTS_CACHE"
        "${CACHE_DIR}/auth_detection.cache"
    )
    
    local removed_count=0
    for cache_file in "${cache_files[@]}"; do
        if [[ -f "$cache_file" ]]; then
            rm -f "$cache_file"
            ((removed_count++))
        fi
    done
    
    # Also clear prefix-based capacity report caches
    local _cap_removed=0
    for _cf in "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json; do
        [[ -f "$_cf" ]] && rm -f "$_cf" && ((_cap_removed++))
    done
    ((removed_count += _cap_removed))
    _CAPACITY_ALL_SHAPES=()
    
    echo -e "${GREEN}✓${NC} Removed ${removed_count} cache file(s) from ${CACHE_DIR}"
    echo ""
    echo -e "${WHITE}Cache will be refreshed on next command execution.${NC}"
    echo -e "${GRAY}Tip: Run without arguments to refresh and list all instances${NC}"
}

# Check if required commands are available
check_dependencies() {
    local missing=()
    
    command -v oci &>/dev/null || missing+=("oci")
    command -v kubectl &>/dev/null || missing+=("kubectl")
    command -v jq &>/dev/null || missing+=("jq")
    
    if [[ ${#missing[@]} -gt 0 ]]; then
        log_error "Missing required commands: ${missing[*]}"
        log_error "Please install the missing dependencies and try again."
        return 1
    fi
    return 0
}

#--------------------------------------------------------------------------------
# Detect tool versions and OCI auth method — called once at startup
# Sets: _TOOL_OCI_VER, _TOOL_OCI_AUTH, _TOOL_OCI_AUTH_SOURCE, _TOOL_OCI_USER, _TOOL_TENANCY_NAME, _TOOL_KUBECTL_VER, _TOOL_HELM_VER
#--------------------------------------------------------------------------------
_detect_tool_versions() {
    # ── OCI CLI version (always live — package can be upgraded) ──
    _TOOL_OCI_VER=$(oci --version 2>/dev/null | grep -oP '[\d.]+' | head -1)
    [[ -z "$_TOOL_OCI_VER" ]] && _TOOL_OCI_VER="n/a"

    # ── OCI auth + tenancy name (cached — stable on a given host) ──
    # Cache file stores: AUTH|AUTH_SOURCE|USER|TENANCY_NAME
    # TTL: 24h.  Invalidated by: env change, --refresh, or manual delete.
    local _auth_cache="${CACHE_DIR}/auth_detection.cache"
    local _auth_cache_ttl=86400  # 24 hours
    local _auth_cache_hit=false

    if [[ -f "$_auth_cache" ]]; then
        local _cache_age=$(( $(date +%s) - $(stat -c %Y "$_auth_cache" 2>/dev/null || echo 0) ))
        if [[ $_cache_age -lt $_auth_cache_ttl ]]; then
            local _cached_line
            _cached_line=$(head -1 "$_auth_cache" 2>/dev/null)
            if [[ -n "$_cached_line" ]]; then
                IFS='|' read -r _TOOL_OCI_AUTH _TOOL_OCI_AUTH_SOURCE _TOOL_OCI_USER _TOOL_TENANCY_NAME <<< "$_cached_line"
                _auth_cache_hit=true
            fi
        fi
    fi

    if [[ "$_auth_cache_hit" == "false" ]]; then
        # ── OCI auth method (requires curl/oci API calls) ──
        _TOOL_OCI_AUTH="api_key"
        _TOOL_OCI_AUTH_SOURCE="config"   # "config" = from env/file, "derived" = auto-detected
        _TOOL_OCI_USER=""

        # Check for OCI Cloud Shell (security_token via delegation token)
        if [[ -n "${OCI_CS_TERMINAL_OCID:-}" ]]; then
            _TOOL_OCI_AUTH="security_token"
            _TOOL_OCI_AUTH_SOURCE="cloud_shell"
        # Check OCI_CLI_AUTH env var first
        elif [[ "${OCI_CLI_AUTH:-}" == "instance_principal" ]]; then
            _TOOL_OCI_AUTH="instance_principal"
            _TOOL_OCI_AUTH_SOURCE="config"   # Explicitly set via env var
        # Check if running on OCI instance with instance principal working
        elif curl -sS -m 2 -H "Authorization: Bearer Oracle" --max-redirs 0 http://169.254.169.254/opc/v2/instance/ -o /dev/null 2>/dev/null; then
            # IMDS available — test if instance principal auth works
            if oci iam region list --auth instance_principal --output json &>/dev/null 2>&1; then
                _TOOL_OCI_AUTH="instance_principal"
                _TOOL_OCI_AUTH_SOURCE="derived"  # Auto-detected via IMDS probe
            fi
        fi

        # For API key / security_token auth, extract username from OCI config → API
        if [[ "$_TOOL_OCI_AUTH" == "api_key" ]]; then
            local _oci_profile="${OCI_CLI_PROFILE:-DEFAULT}"
            local _oci_config="${OCI_CLI_CONFIG_FILE:-$HOME/.oci/config}"
            if [[ -f "$_oci_config" ]]; then
                # Extract user OCID from the active profile
                local _user_ocid=""
                _user_ocid=$(awk -v prof="[$_oci_profile]" '
                    $0 == prof { found=1; next }
                    found && /^\[/ { exit }
                    found && /^user\s*=/ { sub(/^user\s*=\s*/, ""); print; exit }
                ' "$_oci_config" 2>/dev/null)

                if [[ -n "$_user_ocid" ]]; then
                    # Resolve: api_key → user OCID → user display name via OCI API
                    local _uname=""
                    _uname=$(oci iam user get --user-id "$_user_ocid" \
                        --query 'data.name' --raw-output 2>/dev/null) || true
                    if [[ -n "$_uname" && "$_uname" != "null" ]]; then
                        _TOOL_OCI_USER="$_uname"
                    else
                        # Fall back to showing short OCID
                        _TOOL_OCI_USER=$(_short_ocid "$_user_ocid")
                    fi
                fi

                # Check for security_token auth override in profile
                local _auth_type=""
                _auth_type=$(awk -v prof="[$_oci_profile]" '
                    $0 == prof { found=1; next }
                    found && /^\[/ { exit }
                    found && /^security_token_file\s*=/ { print "security_token"; exit }
                ' "$_oci_config" 2>/dev/null)
                [[ "$_auth_type" == "security_token" ]] && _TOOL_OCI_AUTH="security_token"
            fi
        fi

        # ── Tenancy name (resolve OCID → display name) ──
        _TOOL_TENANCY_NAME=""
        if [[ -n "${TENANCY_ID:-}" ]]; then
            _TOOL_TENANCY_NAME=$(oci iam tenancy get --tenancy-id "$TENANCY_ID" \
                --query 'data.name' --raw-output 2>/dev/null) || true
            [[ "$_TOOL_TENANCY_NAME" == "null" ]] && _TOOL_TENANCY_NAME=""
        fi

        # Write cache (pipe-delimited, single line)
        printf '%s\n' "${_TOOL_OCI_AUTH}|${_TOOL_OCI_AUTH_SOURCE}|${_TOOL_OCI_USER}|${_TOOL_TENANCY_NAME}" \
            > "$_auth_cache" 2>/dev/null
    fi

    # ── kubectl version (always live — package can be upgraded) ──
    _TOOL_KUBECTL_VER=""
    if command -v kubectl &>/dev/null; then
        _TOOL_KUBECTL_VER=$(kubectl version --client -o json 2>/dev/null | jq -r '.clientVersion.gitVersion // empty' 2>/dev/null)
        [[ -z "$_TOOL_KUBECTL_VER" ]] && _TOOL_KUBECTL_VER=$(kubectl version --client --short 2>/dev/null | grep -oP 'v[\d.]+' | head -1)
        [[ -z "$_TOOL_KUBECTL_VER" ]] && _TOOL_KUBECTL_VER="installed"
    fi

    # ── helm version (always live — package can be upgraded) ──
    _TOOL_HELM_VER=""
    if command -v helm &>/dev/null; then
        _TOOL_HELM_VER=$(helm version --short 2>/dev/null | grep -oP 'v[\d.]+' | head -1)
        [[ -z "$_TOOL_HELM_VER" ]] && _TOOL_HELM_VER="installed"
    fi
}

# Build formatted tools/auth line for environment display headers
# Usage: local line; line=$(_build_tools_line)
_build_tools_line() {
    local tl="${CYAN}OCI CLI:${NC} ${GREEN}${_TOOL_OCI_VER:-n/a}${NC}"
    # Auth color follows Focus convention: GREEN=config (env var/file), CYAN=derived (auto-detected)
    local _auth_color="$GREEN"
    [[ "${_TOOL_OCI_AUTH_SOURCE:-config}" == "derived" ]] && _auth_color="$CYAN"
    [[ "${_TOOL_OCI_AUTH_SOURCE:-config}" == "cloud_shell" ]] && _auth_color="$CYAN"
    if [[ "${_TOOL_OCI_AUTH_SOURCE:-}" == "cloud_shell" ]]; then
        tl+=" ${GRAY}(${NC}${_auth_color}cloud_shell${NC}${GRAY})${NC}"
    elif [[ "${_TOOL_OCI_AUTH:-}" == "instance_principal" ]]; then
        tl+=" ${GRAY}(${NC}${_auth_color}instance_principal${NC}${GRAY})${NC}"
    elif [[ "${_TOOL_OCI_AUTH:-}" == "security_token" ]]; then
        tl+=" ${GRAY}(${NC}${_auth_color}security_token${NC}"
        [[ -n "${_TOOL_OCI_USER:-}" ]] && tl+=": ${WHITE}${_TOOL_OCI_USER}${NC}"
        tl+="${GRAY})${NC}"
    else
        tl+=" ${GRAY}(${NC}${_auth_color}api_key${NC}"
        [[ -n "${_TOOL_OCI_USER:-}" ]] && tl+=": ${WHITE}${_TOOL_OCI_USER}${NC}"
        tl+="${GRAY})${NC}"
    fi
    if [[ -n "${_TOOL_KUBECTL_VER:-}" ]]; then
        tl+="  ${GRAY}│${NC}  ${CYAN}kubectl:${NC} ${GREEN}${_TOOL_KUBECTL_VER}${NC}"
    else
        tl+="  ${GRAY}│${NC}  ${CYAN}kubectl:${NC} ${RED}Not Installed${NC}"
    fi
    if [[ -n "${_TOOL_HELM_VER:-}" ]]; then
        tl+="  ${GRAY}│${NC}  ${CYAN}helm:${NC} ${GREEN}${_TOOL_HELM_VER}${NC}"
    else
        tl+="  ${GRAY}│${NC}  ${CYAN}helm:${NC} ${RED}Not Installed${NC}"
    fi
    echo "$tl"
}

#===============================================================================
# CACHE FETCH FUNCTIONS
#===============================================================================

# Fetch and cache GPU memory fabrics from OCI
fetch_gpu_fabrics() {
    [[ -z "$TENANCY_ID" ]] && { log_warn "TENANCY_ID not set. GPU fabric details unavailable."; return 1; }
    local region="${FOCUS_REGION:-$REGION}"

    # Check cache freshness; invalidate if any fabric is in a transitional state
    if is_cache_fresh "$FABRIC_CACHE"; then
        _cache_invalidate_text_if_transitional "$FABRIC_CACHE" || return 0
    fi

    local raw_json
    raw_json=$(create_temp_file) || return 1

    if ! oci compute compute-gpu-memory-fabric list \
            --compartment-id "$TENANCY_ID" \
            --region "$region" \
            --all \
            --output json > "$raw_json" 2>/dev/null; then
        rm -f "$raw_json"
        log_warn "Failed to fetch GPU memory fabrics"
        _ui_policy_hint "read compute-gpu-memory-fabrics in compartment"
        return 1
    fi
    
    # Write cache header and data - filter out DELETED/TERMINATED, deduplicate
    {
        echo "# GPU Memory Fabrics"
        echo "# Format: DisplayName|Last5Chars|FabricOCID|State|HealthyHosts|AvailableHosts|TotalHosts|CurrentFirmware|TargetFirmware|FirmwareUpdateState"
        jq -r '.data.items[] | select(.["lifecycle-state"] != "DELETED" and .["lifecycle-state"] != "TERMINATED") | "\(.["display-name"])|\(.id[-5:] | ascii_downcase)|\(.id)|\(.["lifecycle-state"])|\(.["healthy-host-count"] // 0)|\(.["available-host-count"] // 0)|\(.["total-host-count"] // 0)|\(.["current-firmware-bundle-id"] // "N/A")|\(.["target-firmware-bundle-id"] // "N/A")|\(.["firmware-update-state"] // "N/A")"' "$raw_json" 2>/dev/null | sort -u
    } | _cache_write "$FABRIC_CACHE"

    # Save raw JSON for JSON viewer
    cat "$raw_json" | _cache_write "$FABRIC_JSON_CACHE"

    rm -f "$raw_json"
    return 0
}

# Fetch and cache GPU memory clusters from OCI
fetch_gpu_clusters() {
    local compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$compartment" ]] && { log_warn "COMPARTMENT_ID not set. GPU cluster details unavailable."; return 1; }
    
    # Check if cache exists and is fresh
    if is_cache_fresh "$CLUSTER_CACHE" && is_cache_fresh "$INSTANCE_CLUSTER_MAP_CACHE"; then
        # Even if cache is fresh, invalidate if any cluster is in a transitional state
        # This ensures we pick up new instances when clusters are scaling
        if [[ -f "$CLUSTER_CACHE" ]]; then
            local transitional_states
            transitional_states=$(grep -E "\|UPDATING\||\|SCALING\||\|CREATING\|" "$CLUSTER_CACHE" 2>/dev/null | wc -l)
            if [[ "$transitional_states" -gt 0 ]]; then
                log_info "Detected $transitional_states cluster(s) in transitional state - refreshing cache..."
            else
                return 0
            fi
        else
            return 0
        fi
    fi
    
    local raw_json
    raw_json=$(create_temp_file) || return 1
    
    if ! oci compute compute-gpu-memory-cluster list \
            --compartment-id "$compartment" \
            --region "$region" \
            --all \
            --output json > "$raw_json" 2>/dev/null; then
        rm -f "$raw_json"
        log_warn "Failed to fetch GPU memory clusters"
        _ui_policy_hint "read compute-gpu-memory-clusters in compartment"
        return 1
    fi
    
    # Write cache headers
    {
        echo "# GPU Memory Clusters"
        echo "# Format: ClusterOCID|DisplayName|State|FabricSuffix|InstanceConfigurationId|ComputeClusterId|Size"
    } | _cache_write "$CLUSTER_CACHE"

    {
        echo "# Instance to GPU Memory Cluster Mapping"
        echo "# Format: InstanceOCID|ClusterOCID|ClusterDisplayName"
    } | _cache_write "$INSTANCE_CLUSTER_MAP_CACHE"
    
    # Get cluster IDs - filter out DELETED/TERMINATED states, deduplicate
    local cluster_ids
    cluster_ids=$(jq -r '.data.items[] | select(.["lifecycle-state"] != "DELETED" and .["lifecycle-state"] != "TERMINATED") | .id // empty' "$raw_json" 2>/dev/null | sort -u)
    
    local cluster_count
    cluster_count=$(echo "$cluster_ids" | grep -c . 2>/dev/null | tr -d '[:space:]')
    [[ -z "$cluster_count" ]] && cluster_count=0
    
    # Log if there were deleted clusters filtered out
    local total_in_api
    total_in_api=$(jq -r '.data.items | length // 0' "$raw_json" 2>/dev/null)
    if [[ "$total_in_api" -gt "$cluster_count" ]]; then
        local filtered_count=$((total_in_api - cluster_count))
        log_info "Filtered out $filtered_count DELETED/TERMINATED cluster(s)"
    fi
    
    if [[ "$cluster_count" -eq 0 ]]; then
        rm -f "$raw_json"
        return 0
    fi
    
    # Create temp directory for parallel outputs
    local parallel_temp="${TEMP_DIR}/gpu_cluster_parallel_$$"
    mkdir -p "$parallel_temp"
    
    # Parallel fetch using standard () & + wait pattern (max 8 concurrent)
    local _pids=() _batch=0
    local cluster_id
    while IFS= read -r cluster_id; do
        [[ -z "$cluster_id" ]] && continue
        
        local _suffix="${cluster_id##*.}"
        (
            local _err_file="${parallel_temp}/err_${_suffix}.log"
            # Fetch cluster details
            local cluster_json
            cluster_json=$(oci compute compute-gpu-memory-cluster get \
                --compute-gpu-memory-cluster-id "$cluster_id" \
                --region "$region" \
                --output json 2>"$_err_file")

            if [[ -z "$cluster_json" ]] || ! jq -e '.data' <<< "$cluster_json" >/dev/null 2>&1; then
                echo "FAIL|cluster-get|$cluster_id|$(cat "$_err_file" 2>/dev/null)" >> "${parallel_temp}/errors.log" 2>/dev/null
            fi

            if [[ -n "$cluster_json" ]] && jq -e '.data' <<< "$cluster_json" >/dev/null 2>&1; then
                # Save raw JSON for JSON viewer merge
                echo "$cluster_json" > "${parallel_temp}/cluster_${_suffix}.json" 2>/dev/null

                # Single-pass jq: extract cache line + display name together
                local _jq_out
                _jq_out=$(jq -r '
                    .data["display-name"] as $name |
                    (.data["gpu-memory-fabric-id"] // "") as $fabric_id |
                    (if $fabric_id != "" and $fabric_id != null then
                        ($fabric_id[-5:] | ascii_downcase)
                     else
                        (($name | capture("fabric-(?<suffix>[a-z0-9]{5})") // {suffix: ""}).suffix)
                     end) as $fabric_suffix |
                    "\(.data.id)|\($name)|\(.data["lifecycle-state"])|\($fabric_suffix)|\(.data["instance-configuration-id"] // "N/A")|\(.data["compute-cluster-id"] // "N/A")|\(.data["size"] // 0)",
                    ($name // "N/A")
                ' <<< "$cluster_json" 2>/dev/null)
                # First line is cache record, second is display name
                local cluster_display_name
                cluster_display_name=$(sed -n '2p' <<< "$_jq_out")
                sed -n '1p' <<< "$_jq_out" > "${parallel_temp}/cluster_${_suffix}.txt"
                
                # Fetch instances for this cluster
                local instances_json
                instances_json=$(oci compute compute-gpu-memory-cluster-instance-summary list-compute-gpu-memory-cluster-instances \
                    --compute-gpu-memory-cluster-id "$cluster_id" \
                    --region "$region" \
                    --all \
                    --output json 2>>"$_err_file")
                if [[ -z "$instances_json" ]]; then
                    echo "FAIL|instance-list|$cluster_id|$(tail -1 "$_err_file" 2>/dev/null)" >> "${parallel_temp}/errors.log" 2>/dev/null
                fi
                
                if [[ -n "$instances_json" ]]; then
                    jq -r --arg cluster_id "$cluster_id" --arg cluster_name "$cluster_display_name" ' 
                        (.data.items // .data // [])[] | 
                        "\(.["instance-id"] // .id)|\($cluster_id)|\($cluster_name)"
                    ' <<< "$instances_json" > "${parallel_temp}/instances_${_suffix}.txt" 2>/dev/null
                fi
            fi
        ) >/dev/null 2>&1 &
        _pids+=($!)
        ((_batch++))
        
        # Throttle: wait after every 8 jobs
        if [[ $_batch -ge 8 ]]; then
            _wait_pids "GPU-CLU" "${_pids[@]}" || true
            _pids=()
            _batch=0
        fi
    done <<< "$cluster_ids"

    # Wait for remaining jobs
    [[ ${#_pids[@]} -gt 0 ]] && { _wait_pids "GPU-CLU" "${_pids[@]}" || true; }

    # Aggregate results from parallel outputs (check files exist)
    local _agg_clusters=0 _agg_instances=0
    if ls "$parallel_temp"/cluster_*.txt >/dev/null 2>&1; then
        cat "$parallel_temp"/cluster_*.txt >> "$CLUSTER_CACHE" 2>/dev/null
        _agg_clusters=$(wc -l < "$CLUSTER_CACHE" 2>/dev/null || echo 0)
    fi
    if ls "$parallel_temp"/instances_*.txt >/dev/null 2>&1; then
        cat "$parallel_temp"/instances_*.txt >> "$INSTANCE_CLUSTER_MAP_CACHE" 2>/dev/null
        _agg_instances=$(wc -l < "$INSTANCE_CLUSTER_MAP_CACHE" 2>/dev/null || echo 0)
    fi
    # Merge per-cluster JSON files for JSON viewer
    if ls "$parallel_temp"/cluster_*.json >/dev/null 2>&1; then
        jq -s '{ data: { items: [ .[].data ] } }' \
            "$parallel_temp"/cluster_*.json 2>/dev/null | _cache_write "$CLUSTER_JSON_CACHE"
    else
        rm -f "$CLUSTER_JSON_CACHE"
    fi
    [[ "$DEBUG_MODE" == "true" ]] && echo -e "  ${GRAY}[GPU-DBG] Aggregated: ${_agg_clusters} cluster lines, ${_agg_instances} instance lines${NC}" >&2
    # Report parallel fetch errors in debug mode
    if [[ "$DEBUG_MODE" == "true" && -s "${parallel_temp}/errors.log" ]]; then
        echo -e "  ${YELLOW}[GPU-DBG] Parallel fetch errors:${NC}" >&2
        while IFS= read -r _errline; do echo -e "    ${GRAY}${_errline}${NC}" >&2; done < "${parallel_temp}/errors.log"
    fi

    # Cleanup
    rm -rf "${parallel_temp:?}"
    rm -f "$raw_json"
    
    return 0
}

# Lookup GPU memory cluster OCID for an instance
get_instance_gpu_cluster() {
    local instance_ocid="$1"
    [[ -z "$instance_ocid" || ! -f "$INSTANCE_CLUSTER_MAP_CACHE" ]] && { echo "N/A"; return 1; }
    
    local result
    result=$(lookup_cache "$INSTANCE_CLUSTER_MAP_CACHE" "$instance_ocid" 2)
    echo "$result"
}

#--------------------------------------------------------------------------------
# List instance configurations from cache with numbered selection
# Populates global _IC_LIST_MAP[$idx]="ocid|name" and _IC_LIST_COUNT
# Args: $1 = optional OCID to exclude from listing (for "compare with another" flows)
#--------------------------------------------------------------------------------
declare -A _IC_LIST_MAP=()
_IC_LIST_COUNT=0

_list_ics_numbered() {
    local exclude_ocid="${1:-}"
    _IC_LIST_MAP=()
    _IC_LIST_COUNT=0
    local idx=0

    _ui_table_header "%-4s %-60s" "#" "Instance Configuration Name"

    while IFS='|' read -r ic_ocid ic_name _; do
        [[ "$ic_ocid" =~ ^#.*$ || -z "$ic_ocid" ]] && continue
        [[ -n "$exclude_ocid" && "$ic_ocid" == "$exclude_ocid" ]] && continue
        ((idx++))
        _IC_LIST_MAP[$idx]="$ic_ocid|$ic_name"
        printf "${YELLOW}%-4s${NC} ${WHITE}%-60s${NC}\n" "$idx" "$ic_name"
    done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)

    _IC_LIST_COUNT=$idx
}

# Fetch and cache all instance configurations from OCI
fetch_instance_configurations() {
    local compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$compartment" ]] && { log_warn "COMPARTMENT_ID not set. Instance configurations unavailable."; return 1; }

    is_cache_fresh "$INSTANCE_CONFIG_CACHE" && return 0

    log_info "Fetching instance configurations from OCI..."

    local raw_json
    raw_json=$(create_temp_file) || return 1

    if ! oci compute-management instance-configuration list \
            --compartment-id "$compartment" \
            --region "$region" \
            --all \
            --output json > "$raw_json" 2>/dev/null; then
        rm -f "$raw_json"
        log_warn "Failed to fetch instance configurations"
        _ui_policy_hint "read instance-configurations in compartment"
        return 1
    fi
    
    # Write cache header and data (now includes time-created)
    {
        echo "# Instance Configurations"
        echo "# Format: InstanceConfigOCID|DisplayName|TimeCreated"
        jq -r '.data[]? | "\(.id)|\(.["display-name"] // "N/A")|\(.["time-created"] // "N/A")"' "$raw_json" 2>/dev/null
    } | _cache_write "$INSTANCE_CONFIG_CACHE"
    
    rm -f "$raw_json"
    return 0
}

# Get instance configuration name from cache
# Args: $1 = instance configuration OCID
get_instance_config_name() {
    local config_id="$1"
    
    [[ -z "$config_id" || "$config_id" == "N/A" || "$config_id" == "null" ]] && { echo "N/A"; return 1; }
    
    # Ensure cache is populated
    fetch_instance_configurations
    
    # Lookup from cache
    lookup_cache "$INSTANCE_CONFIG_CACHE" "$config_id" 2
}

# Extract and display user-data (cloud-init) from an instance configuration
# Args: $1 = instance configuration OCID
get_instance_config_user_data() {
    local ic_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"

    if [[ -z "$ic_ocid" ]]; then
        log_error "Instance configuration OCID required"
        return 1
    fi

    # Validate OCID format
    if [[ ! "$ic_ocid" =~ ^ocid1\.instanceconfiguration\. ]]; then
        log_error "Invalid instance configuration OCID format: $ic_ocid"
        echo "Expected format: ocid1.instanceconfiguration.oc1.<region>.<unique-id>" >&2
        return 1
    fi

    log_info "Fetching instance configuration..." >&2

    local ic_json
    ic_json=$(oci compute-management instance-configuration get \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --output json 2>/dev/null)
    
    if [[ -z "$ic_json" ]] || ! jq -e '.data' <<< "$ic_json" > /dev/null 2>&1; then
        log_error "Failed to fetch instance configuration: $ic_ocid"
        return 1
    fi
    
    local ic_name
    ic_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$ic_json")
    
    # Extract user_data (base64 encoded)
    local user_data_b64
    user_data_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic_json" 2>/dev/null)
    
    if [[ -z "$user_data_b64" ]]; then
        echo "# No user-data found in instance configuration: $ic_name" >&2
        echo "# OCID: $ic_ocid" >&2
        return 0
    fi
    
    # Output header as comments (to stderr so stdout is just the yaml)
    echo "# Instance Configuration: $ic_name" >&2
    echo "# OCID: $ic_ocid" >&2
    echo "# Decoded cloud-init user-data:" >&2
    echo "#" >&2
    
    # Decode and output to stdout (handles gzip compressed data)
    decode_user_data "$user_data_b64"
    
    return 0
}

#--------------------------------------------------------------------------------
# Decode base64 user_data, handling gzip compression
# Args: $1 = base64 encoded user_data
# Output: decoded (and decompressed if gzip) data to stdout
#--------------------------------------------------------------------------------
decode_user_data() {
    local user_data_b64="$1"
    
    [[ -z "$user_data_b64" ]] && return 1
    
    # Decode to temp file
    local tmp_decoded
    tmp_decoded=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    echo "$user_data_b64" | base64 -d > "$tmp_decoded" 2>/dev/null
    
    # Check if gzip compressed (magic bytes: 1f 8b)
    local magic_bytes
    magic_bytes=$(xxd -l 2 -p "$tmp_decoded" 2>/dev/null)
    
    if [[ "$magic_bytes" == "1f8b" ]]; then
        # Gzip compressed - decompress
        gunzip -c "$tmp_decoded" 2>/dev/null
    else
        # Plain text
        cat "$tmp_decoded"
    fi
    
    rm -f "$tmp_decoded"
    return 0
}

#--------------------------------------------------------------------------------
# Decode base64 user_data to file, handling gzip compression
# Args: $1 = base64 encoded user_data, $2 = output filename
# Returns: 0 on success, 1 on failure
#--------------------------------------------------------------------------------
decode_user_data_to_file() {
    local user_data_b64="$1"
    local output_file="$2"
    
    [[ -z "$user_data_b64" || -z "$output_file" ]] && return 1
    
    # Decode to temp file
    local tmp_decoded
    tmp_decoded=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    echo "$user_data_b64" | base64 -d > "$tmp_decoded" 2>/dev/null
    
    # Check if gzip compressed (magic bytes: 1f 8b)
    local magic_bytes
    magic_bytes=$(xxd -l 2 -p "$tmp_decoded" 2>/dev/null)
    
    local result=0
    if [[ "$magic_bytes" == "1f8b" ]]; then
        # Gzip compressed - decompress
        if gunzip -c "$tmp_decoded" > "$output_file" 2>/dev/null; then
            result=0
        else
            result=1
        fi
    else
        # Plain text
        if cp "$tmp_decoded" "$output_file" 2>/dev/null; then
            result=0
        else
            result=1
        fi
    fi
    
    rm -f "$tmp_decoded"
    return $result
}

#--------------------------------------------------------------------------------
# Check if user_data is gzip compressed
# Args: $1 = base64 encoded user_data
# Returns: 0 if gzip compressed, 1 if not
#--------------------------------------------------------------------------------
is_user_data_gzip() {
    local user_data_b64="$1"
    
    [[ -z "$user_data_b64" ]] && return 1
    
    # Decode to temp file and check magic bytes
    local tmp_decoded
    tmp_decoded=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    echo "$user_data_b64" | base64 -d > "$tmp_decoded" 2>/dev/null
    
    local magic_bytes
    magic_bytes=$(xxd -l 2 -p "$tmp_decoded" 2>/dev/null)
    
    rm -f "$tmp_decoded"
    
    [[ "$magic_bytes" == "1f8b" ]]
}

#--------------------------------------------------------------------------------
# Interactive instance termination with details and confirmation
# Args: $1 = instance OCID
# Shows: instance details, running pods, termination command, confirmation
#--------------------------------------------------------------------------------
terminate_instance_interactive() {
    local instance_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"

    if [[ -z "$instance_ocid" ]]; then
        log_error "Instance OCID required"
        return 1
    fi
    
    echo ""
    _ui_menu_header "INSTANCE TERMINATION"
    echo ""
    
    # Fetch instance details
    log_info "Fetching instance details..."
    local instance_json
    local instance_json
    instance_json=$(oci compute instance get --instance-id "$instance_ocid" --region "$region" --output json 2>/dev/null)

    if [[ -z "$instance_json" || "$instance_json" == "null" ]]; then
        log_error "Failed to fetch instance details. Instance may not exist or you don't have access."
        return 1
    fi
    
    # Parse instance details
    local display_name lifecycle_state shape ad fault_domain
    local compartment_id time_created
    IFS=$'\t' read -r display_name lifecycle_state shape ad fault_domain \
        compartment_id time_created < <(jq -r '.data | [
            .["display-name"] // "N/A",
            .["lifecycle-state"] // "N/A",
            .shape // "N/A",
            .["availability-domain"] // "N/A",
            .["fault-domain"] // "N/A",
            .["compartment-id"] // "N/A",
            .["time-created"] // "N/A"
        ] | @tsv' <<< "$instance_json")
    
    # Color for state
    local state_color
    state_color=$(color_oci_state "$lifecycle_state")
    
    # Display instance details
    _ui_subheader "Instance Details" 0
    echo -e "  ${CYAN}Display Name:${NC}    $display_name"
    echo -e "  ${CYAN}OCID:${NC}            ${YELLOW}$instance_ocid${NC}"
    echo -e "  ${CYAN}State:${NC}           ${state_color}$lifecycle_state${NC}"
    echo -e "  ${CYAN}Shape:${NC}           $shape"
    echo -e "  ${CYAN}AD:${NC}              $ad"
    echo -e "  ${CYAN}Fault Domain:${NC}    $fault_domain"
    echo -e "  ${CYAN}Compartment:${NC}     ${WHITE}$(resolve_compartment_name "$compartment_id")${NC} ${GRAY}($compartment_id)${NC}"
    echo -e "  ${CYAN}Created:${NC}         ${time_created:0:19}"
    echo ""
    
    # Check if already terminated
    if [[ "$lifecycle_state" == "TERMINATED" ]]; then
        echo -e "${YELLOW}Instance is already terminated.${NC}"
        return 0
    fi
    
    # Check if instance is in K8s and show pods
    local k8s_node_name=""
    log_info "Checking K8s node status..."
    
    # Find K8s node by provider ID
    local k8s_nodes_json
    k8s_nodes_json=$(kubectl get nodes -o json 2>/dev/null)
    
    if [[ -n "$k8s_nodes_json" ]]; then
        k8s_node_name=$(resolve_k8s_node_name "$instance_ocid" "$k8s_nodes_json")
    fi
    
    if [[ -n "$k8s_node_name" && "$k8s_node_name" != "null" ]]; then
        _ui_subheader "Kubernetes Node" 0
        echo -e "  ${CYAN}Node Name:${NC}       $k8s_node_name"
        
        # Get node status
        local node_ready node_schedulable
        node_ready=$(kubectl get node "$k8s_node_name" -o jsonpath='{.status.conditions[?(@.type=="Ready")].status}' 2>/dev/null)
        node_schedulable=$(kubectl get node "$k8s_node_name" -o jsonpath='{.spec.unschedulable}' 2>/dev/null)
        
        local ready_color="$GREEN"
        [[ "$node_ready" != "True" ]] && ready_color="$RED"
        echo -e "  ${CYAN}Ready:${NC}           ${ready_color}$node_ready${NC}"
        
        if [[ "$node_schedulable" == "true" ]]; then
            echo -e "  ${CYAN}Cordoned:${NC}        ${YELLOW}Yes${NC}"
        else
            echo -e "  ${CYAN}Cordoned:${NC}        No"
        fi
        echo ""
        
        # Get pods on this node
        _ui_subheader "Pods Running on Node" 0
        echo ""
        
        local node_pods
        node_pods=$(kubectl get pods --all-namespaces --field-selector "spec.nodeName=$k8s_node_name" -o wide 2>/dev/null)
        
        if [[ -n "$node_pods" ]]; then
            local pod_count
            pod_count=$(echo "$node_pods" | tail -n +2 | wc -l)
            echo -e "  ${CYAN}Total Pods:${NC} ${WHITE}$pod_count${NC}"
            echo ""
            
            # Print header
            echo "$node_pods" | head -1 | while IFS= read -r line; do
                echo -e "  ${BOLD}${WHITE}$line${NC}"
            done
            
            # Print pods with color coding
            echo "$node_pods" | tail -n +2 | while IFS= read -r line; do
                if echo "$line" | grep -q "Running"; then
                    echo -e "  ${GREEN}$line${NC}"
                elif echo "$line" | grep -q "Completed"; then
                    echo -e "  ${GRAY}$line${NC}"
                elif echo "$line" | grep -qE "Error|Failed|CrashLoopBackOff|ImagePullBackOff"; then
                    echo -e "  ${RED}$line${NC}"
                elif echo "$line" | grep -qE "Pending|ContainerCreating|Init"; then
                    echo -e "  ${YELLOW}$line${NC}"
                else
                    echo "  $line"
                fi
            done
            
            if [[ $pod_count -gt 0 ]]; then
                echo ""
                echo -e "  ${RED}⚠️  WARNING: $pod_count pod(s) are running on this node!${NC}"
                echo -e "  ${YELLOW}Consider draining the node first: kubectl drain $k8s_node_name --ignore-daemonsets --delete-emptydir-data --force${NC}"
            fi
        else
            echo -e "  ${GRAY}No pods found on this node${NC}"
        fi
        echo ""
    else
        echo -e "${GRAY}Instance is not registered as a Kubernetes node${NC}"
        echo ""
    fi
    
    # Show the command that will be executed
    local terminate_cmd="oci compute instance terminate --instance-id $instance_ocid --region $region --preserve-boot-volume false --force"
    
    _ui_subheader "Command to Execute" 0
    echo -e "  ${WHITE}$terminate_cmd${NC}"
    echo ""
    
    print_separator 90
    echo ""
    echo -e "${RED}⚠️  WARNING: This will PERMANENTLY TERMINATE the instance!${NC}"
    echo -e "${RED}    This action cannot be undone!${NC}"
    echo ""
    echo -e "${RED}    Instance: ${WHITE}$display_name${NC}"
    echo -e "${RED}    OCID:     ${WHITE}$instance_ocid${NC}"
    echo ""
    
    if _ui_confirm "TERMINATE" "confirm"; then
        log_action "TERMINATE" "$terminate_cmd" --context "Instance: $display_name ($instance_ocid), K8s Node: ${k8s_node_name:-N/A}"
        
        if oci compute instance terminate --instance-id "$instance_ocid" --region "$region" --preserve-boot-volume false --force 2>&1; then
            echo ""
            echo -e "${GREEN}✓ Instance termination initiated${NC}"
            echo -e "${GRAY}  Instance will transition to TERMINATING state${NC}"
            log_action_result "SUCCESS" "Terminated instance $display_name ($instance_ocid)"
        else
            echo ""
            echo -e "${RED}✗ Failed to terminate instance${NC}"
            log_action_result "FAILED" "Terminate instance $display_name ($instance_ocid)"
        fi
        
        echo ""
        echo -e "${GRAY}Log: $ACTION_LOG_FILE${NC}"
    else
        echo -e "${YELLOW}Cancelled (must type 'TERMINATE' exactly)${NC}"
    fi
    
    echo ""
}

#--------------------------------------------------------------------------------
# Get user-data from an instance OCID
# Args: $1 = instance OCID
# Output: decoded user-data to stdout
#--------------------------------------------------------------------------------
get_instance_user_data() {
    local instance_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"

    if [[ -z "$instance_ocid" ]]; then
        log_error "Instance OCID required"
        return 1
    fi
    
    # Validate OCID format
    if [[ ! "$instance_ocid" =~ ^ocid1\.instance\. ]]; then
        log_error "Invalid instance OCID format: $instance_ocid"
        echo "Expected format: ocid1.instance.oc1.<region>.<unique-id>" >&2
        return 1
    fi
    
    log_info "Fetching instance metadata..." >&2
    
    local instance_json
    instance_json=$(oci compute instance get \
        --instance-id "$instance_ocid" \
        --region "$region" \
        --output json 2>/dev/null)

    if [[ -z "$instance_json" ]] || ! jq -e '.data' <<< "$instance_json" > /dev/null 2>&1; then
        log_error "Failed to fetch instance: $instance_ocid"
        return 1
    fi
    
    local instance_name
    instance_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$instance_json")
    
    # Extract user_data (base64 encoded)
    local user_data_b64
    user_data_b64=$(jq -r '.data.metadata.user_data // empty' <<< "$instance_json" 2>/dev/null)
    
    if [[ -z "$user_data_b64" ]]; then
        echo "# No user-data found in instance metadata: $instance_name" >&2
        echo "# OCID: $instance_ocid" >&2
        echo "" >&2
        echo "# Note: user_data is typically only available if the instance was launched with" >&2
        echo "# cloud-init user-data specified in the metadata." >&2
        return 0
    fi
    
    # Output header as comments (to stderr so stdout is just the yaml)
    echo "# Instance: $instance_name" >&2
    echo "# OCID: $instance_ocid" >&2
    echo "# Decoded cloud-init user-data:" >&2
    echo "#" >&2
    
    # Decode and output to stdout (handles gzip compressed data)
    decode_user_data "$user_data_b64"
    
    return 0
}

# Fetch and cache compute clusters from OCI
fetch_compute_clusters() {
    local compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$compartment" ]] && { log_warn "COMPARTMENT_ID not set. Compute clusters unavailable."; return 1; }
    
    if is_cache_fresh "$COMPUTE_CLUSTER_CACHE"; then
        _cache_invalidate_text_if_transitional "$COMPUTE_CLUSTER_CACHE" || return 0
    fi
    
    # Write cache header
    {
        echo "# Compute Clusters"
        echo "# Format: ComputeClusterOCID|DisplayName|AvailabilityDomain|LifecycleState"
    } | _cache_write "$COMPUTE_CLUSTER_CACHE"
    
    # Get availability domains
    local ad_list
    ad_list=$(oci iam availability-domain list --compartment-id "$compartment" --region "$region" --query 'data[].name' --raw-output 2>/dev/null | jq -r '.[]' 2>/dev/null)
    
    # Fetch compute clusters from each AD
    local ad
    local _cc_json_parts=()
    for ad in $ad_list; do
        [[ -z "$ad" ]] && continue

        local raw_json
        raw_json=$(create_temp_file) || continue

        if oci compute compute-cluster list \
                --compartment-id "$compartment" \
                --availability-domain "$ad" \
                --region "$region" \
                --all \
                --output json > "$raw_json" 2>/dev/null; then

            # OCI returns .data.items[] for paginated results
            jq -r '(.data.items // .data // [])[] | "\(.id)|\(.["display-name"] // "N/A")|\(.["availability-domain"] // "N/A")|\(.["lifecycle-state"] // "UNKNOWN")"' "$raw_json" >> "$COMPUTE_CLUSTER_CACHE" 2>/dev/null
            # Collect JSON files for merge
            _cc_json_parts+=("$raw_json")
        else
            rm -f "$raw_json"
        fi
    done

    # Merge raw JSON from all ADs into a single combined cache
    if [[ ${#_cc_json_parts[@]} -gt 0 ]]; then
        jq -s '{ data: { items: [ .[] | (.data.items // .data // [])[] ] } }' \
            "${_cc_json_parts[@]}" 2>/dev/null | _cache_write "$COMPUTE_CLUSTER_JSON_CACHE"
        rm -f "${_cc_json_parts[@]}"
    else
        rm -f "$COMPUTE_CLUSTER_JSON_CACHE"
    fi

    return 0
}

# Get compute cluster name from cache
# Args: $1 = compute cluster OCID
get_compute_cluster_name() {
    local cluster_id="$1"
    
    [[ -z "$cluster_id" || "$cluster_id" == "N/A" || "$cluster_id" == "null" ]] && { echo "N/A"; return 1; }
    
    # Ensure cache is populated
    fetch_compute_clusters
    
    # Lookup from cache
    lookup_cache "$COMPUTE_CLUSTER_CACHE" "$cluster_id" 2
}

#--------------------------------------------------------------------------------
# Fetch and cache VCN list from OCI
# Cache format: ocid|name|cidr|state|compartment_id
# Tries FOCUS_COMPARTMENT_ID first, falls back to NETWORK_COMPARTMENT_ID
#--------------------------------------------------------------------------------
fetch_vcn_list() {
    if is_cache_fresh "$VCN_LIST_CACHE"; then
        return 0
    fi

    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local vcn_json

    {
        echo "# VCN List"
        echo "# Format: ocid|name|cidr|state|compartment_id"
    } | _cache_write "$VCN_LIST_CACHE"

    vcn_json=$(oci network vcn list --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)

    # Fallback to network compartment if primary returned nothing
    if { [[ -z "$vcn_json" ]] || ! jq -e '.data[0]' <<< "$vcn_json" > /dev/null 2>&1; } && \
       [[ -n "${NETWORK_COMPARTMENT_ID:-}" && "${NETWORK_COMPARTMENT_ID:-}" != "$compartment_id" ]]; then
        compartment_id="$NETWORK_COMPARTMENT_ID"
        vcn_json=$(oci network vcn list --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
    fi
    
    if [[ -n "$vcn_json" ]] && jq -e '.data[0]' <<< "$vcn_json" > /dev/null 2>&1; then
        jq -r '(.data // [])[] | "\(.id)|\(.["display-name"])|\(.["cidr-block"] // .["cidr-blocks"][0] // "N/A")|\(.["lifecycle-state"])|\(.["compartment-id"])"' \
            <<< "$vcn_json" >> "$VCN_LIST_CACHE" 2>/dev/null
    fi
}

# Get VCN count from cache
get_vcn_count() {
    [[ -f "$VCN_LIST_CACHE" ]] || { echo 0; return; }
    local _c
    _c=$(grep -cv '^#\|^$' "$VCN_LIST_CACHE" 2>/dev/null) || _c=0
    echo "$_c"
}

# Fetch and cache Kubernetes node states
fetch_node_states() {
    {
        echo "# Node States"
        echo "# Format: ProviderID|NodeState"
        kubectl get nodes -o json 2>/dev/null | jq -r '
            .items[] | 
            "\(.spec.providerID)|\(
                .status.conditions[] | 
                select(.type=="Ready") | 
                if .status=="True" then "Ready" 
                elif .status=="False" then "NotReady" 
                else "Unknown" end
            )"' 2>/dev/null
    } | _cache_write "$NODE_STATE_CACHE"
}

# Fetch and cache capacity topology bare metal hosts
fetch_capacity_topology() {
    [[ -z "$TENANCY_ID" ]] && { log_warn "TENANCY_ID not set. Capacity topology unavailable."; return 1; }
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$CAPACITY_TOPOLOGY_CACHE" && return 0

    local topologies_json
    topologies_json=$(create_temp_file) || return 1

    if ! oci compute capacity-topology list \
            --compartment-id "$TENANCY_ID" \
            --region "$region" \
            --all \
            --output json > "$topologies_json" 2>/dev/null; then
        rm -f "$topologies_json"
        log_warn "Failed to fetch capacity topologies"
        _ui_policy_hint "read capacity-topologies in compartment"
        return 1
    fi
    
    # Write cache header
    {
        echo "# Capacity Topology Hosts"
        echo "# Format: InstanceOCID|HostLifecycleState|HostLifecycleDetails|TopologyOCID|InstanceShape|HPCIslandID|NetworkBlockID|LocalBlockID|TimeCreated|TimeUpdated|BareMetalHostOCID"
    } | _cache_write "$CAPACITY_TOPOLOGY_CACHE"
    
    # Get topology IDs - filter out DELETED/TERMINATED states, deduplicate
    local topology_ids
    topology_ids=$(jq -r '.data.items[] | select(.["lifecycle-state"] != "DELETED" and .["lifecycle-state"] != "TERMINATED") | .id // empty' "$topologies_json" 2>/dev/null | sort -u)
    
    local topo_count
    topo_count=$(echo "$topology_ids" | grep -c . 2>/dev/null | tr -d '[:space:]')
    [[ -z "$topo_count" ]] && topo_count=0
    
    # Log if there were deleted topologies filtered out
    local total_in_api
    total_in_api=$(jq -r '.data.items | length // 0' "$topologies_json" 2>/dev/null)
    if [[ "$total_in_api" -gt "$topo_count" ]]; then
        local filtered_count=$((total_in_api - topo_count))
        log_info "Filtered out $filtered_count DELETED/TERMINATED topology(ies)"
    fi
    
    if [[ "$topo_count" -eq 0 ]]; then
        rm -f "$topologies_json"
        # API succeeded but 0 active topologies — keep header-only cache so caller
        # can distinguish "no topologies" from "API failure" (missing cache file)
        return 0
    fi
    
    # Create temp directory for parallel outputs
    local parallel_temp="${TEMP_DIR}/capacity_topo_parallel_$$"
    mkdir -p "$parallel_temp"    
    # Determine parallelism (OCI_MAX_PARALLEL, configurable via env var)
    local parallel_jobs=$OCI_MAX_PARALLEL
    [[ "$topo_count" -lt "$parallel_jobs" ]] && parallel_jobs="$topo_count"

    # Run parallel fetch using () & + wait pattern (avoids export -f portability issues)
    local _topo_pids=()
    local _topo_batch=0
    while IFS= read -r topo_id; do
        [[ -z "$topo_id" ]] && continue
        (
            local output_file="${parallel_temp}/topo_${topo_id##*.}.txt"
            local json_file="${parallel_temp}/topo_${topo_id##*.}.json"
            local _err_file="${parallel_temp}/err_topo_${topo_id##*.}.log"
            local hosts_json
            hosts_json=$(oci compute capacity-topology bare-metal-host list \
                --capacity-topology-id "$topo_id" \
                --region "$region" \
                --all \
                --output json 2>"$_err_file")
            if [[ -z "$hosts_json" ]]; then
                echo "FAIL|topo-hosts|$topo_id|$(cat "$_err_file" 2>/dev/null)" >> "${parallel_temp}/errors.log" 2>/dev/null
            elif [[ -n "$hosts_json" ]]; then
                # Save raw JSON for json viewer (j)
                echo "$hosts_json" > "$json_file" 2>/dev/null
                jq -r --arg topo "$topo_id" '
                    .data.items[]? |
                    "\(.["instance-id"] // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.["lifecycle-details"] // "N/A")|\($topo)|\(.["instance-shape"] // "N/A")|\(.["compute-hpc-island-id"] // "N/A")|\(.["compute-network-block-id"] // "N/A")|\(.["compute-local-block-id"] // "N/A")|\(.["time-created"] // "N/A")|\(.["time-updated"] // "N/A")|\(.id // "N/A")"
                ' <<< "$hosts_json" > "$output_file" 2>/dev/null
            fi
        ) &
        _topo_pids+=($!)
        ((_topo_batch++))
        if [[ $_topo_batch -ge $parallel_jobs ]]; then
            _wait_pids "TOPO" "${_topo_pids[@]}" || true
            _topo_pids=()
            _topo_batch=0
        fi
    done <<< "$topology_ids"
    [[ ${#_topo_pids[@]} -gt 0 ]] && { _wait_pids "TOPO" "${_topo_pids[@]}" || true; }

    # Aggregate results from parallel outputs
    if ls "$parallel_temp"/topo_*.txt >/dev/null 2>&1; then
        cat "$parallel_temp"/topo_*.txt >> "$CAPACITY_TOPOLOGY_CACHE" 2>/dev/null
    fi
    # Merge raw JSON from parallel fetches into a single combined cache
    if ls "$parallel_temp"/topo_*.json >/dev/null 2>&1; then
        jq -s '{ data: { items: [ .[].data.items[]? ] } }' \
            "$parallel_temp"/topo_*.json 2>/dev/null | _cache_write "$CAPACITY_TOPOLOGY_JSON_CACHE"
    else
        rm -f "$CAPACITY_TOPOLOGY_JSON_CACHE"
    fi
    # Report parallel fetch errors in debug mode
    if [[ "$DEBUG_MODE" == "true" && -s "${parallel_temp}/errors.log" ]]; then
        echo -e "  ${YELLOW}[TOPO-DBG] Parallel fetch errors:${NC}" >&2
        while IFS= read -r _errline; do echo -e "    ${GRAY}${_errline}${NC}" >&2; done < "${parallel_temp}/errors.log"
    fi

    # Cache the most recent time-updated from the topology list (UTC)
    # Used by both c5 (Capacity Topology) and c10 (Compute Hosts) to show API refresh status
    local _topo_time_updated
    _topo_time_updated=$(jq -r '[.data.items[]? | .["time-updated"] // empty] | sort | last // empty' "$topologies_json" 2>/dev/null)
    if [[ -n "$_topo_time_updated" ]]; then
        echo "$_topo_time_updated" > "$CAPACITY_TOPO_TIME_CACHE"
    fi

    # Cleanup
    rm -rf "${parallel_temp:?}"
    rm -f "$topologies_json"

    return 0
}

# Fetch and cache compute hosts (oci compute compute-host list)
fetch_compute_hosts() {
    [[ -z "$TENANCY_ID" ]] && { log_warn "TENANCY_ID not set. Compute hosts unavailable."; return 1; }
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$COMPUTE_HOST_CACHE" && return 0

    local _json _rc=0
    _json=$(oci compute compute-host list \
        --compartment-id "$TENANCY_ID" \
        --region "$region" \
        --all --output json 2>/dev/null) || _rc=$?

    if [[ $_rc -ne 0 || -z "$_json" ]]; then
        # API call failed — do NOT create cache so caller sees "failed to fetch"
        rm -f "$COMPUTE_HOST_CACHE" "$COMPUTE_HOST_JSON_CACHE"
        log_warn "Failed to fetch compute hosts (rc=$_rc)"
        return 1
    fi

    # Write cache header + pipe-delimited rows
    {
        echo "# Compute Hosts"
        echo "# Format: DisplayName|State|Health|Shape|Platform|AD|FD|InstanceID|HostOCID|HPCIslandID|NetworkBlockID|LocalBlockID|HostGroupID|CapResID|GPUFabricID|HasImpacted|TimeCreated|TimeUpdated|CompartmentID"
    } | _cache_write "$COMPUTE_HOST_CACHE"

    # Save raw JSON for json viewer (j)
    echo "$_json" | _cache_write "$COMPUTE_HOST_JSON_CACHE"

    jq -r '.data.items[]? |
        "\(.["display-name"] // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.health // "N/A")|\(.shape // "N/A")|\(.platform // "N/A")|\(.["availability-domain"] // "N/A")|\(.["fault-domain"] // "N/A")|\(.["instance-id"] // "N/A")|\(.id // "N/A")|\(.["hpc-island-id"] // "N/A")|\(.["network-block-id"] // "N/A")|\(.["local-block-id"] // "N/A")|\(.["compute-host-group-id"] // "N/A")|\(.["capacity-reservation-id"] // "N/A")|\(.["gpu-memory-fabric-id"] // "N/A")|\(.["has-impacted-components"] // false)|\(.["time-created"] // "N/A")|\(.["time-updated"] // "N/A")|\(.["compartment-id"] // "N/A")"
    ' <<< "$_json" >> "$COMPUTE_HOST_CACHE" 2>/dev/null

    return 0
}

# Fetch and cache OKE environment information
fetch_oke_environment() {
    local compartment_id="$1"
    local region="$2"
    
    # Check if OKE_CLUSTER_ID from variables.sh differs from cached value
    # If so, we need to refresh the cache
    local configured_cluster_id="${OKE_CLUSTER_ID:-}"
    local cached_cluster_id=""
    
    if [[ -f "$OKE_ENV_CACHE" ]]; then
        cached_cluster_id=$(grep "^OKE_CLUSTER_ID|" "$OKE_ENV_CACHE" 2>/dev/null | cut -d'|' -f2)
    fi
    
    # Invalidate cache if configured cluster differs from cached
    if [[ -n "$configured_cluster_id" && "$configured_cluster_id" != "N/A" && "$configured_cluster_id" != "$cached_cluster_id" ]]; then
        log_info "OKE_CLUSTER_ID changed, refreshing cache..."
        rm -f "$OKE_ENV_CACHE" "$OKE_CLUSTER_JSON_CACHE" "$OKE_NODEPOOL_CACHE" "$OKE_SUBNET_LIST_CACHE"
    fi
    
    if is_cache_fresh "$OKE_ENV_CACHE"; then
        _cache_invalidate_text_if_transitional "$OKE_ENV_CACHE" || return 0
    fi
    
    _step_init
    
    # Temp dir for parallel results
    local _ptmp="${TEMP_DIR}/oke_fetch_$$"
    mkdir -p "$_ptmp"
    
    # Get tenancy OCID (fast, from variable or metadata)
    local tenancy_ocid="${TENANCY_ID:-}"
    if [[ -z "$tenancy_ocid" ]]; then
        tenancy_ocid=$(curl -sH "Authorization: Bearer Oracle" --max-redirs 0 http://169.254.169.254/opc/v2/instance/ 2>/dev/null | jq -r '.tenantId // empty')
    fi
    
    #---------------------------------------------------------------------------
    # PARALLEL GROUP 1: compartment name + AD list + cluster discovery
    # Commands: oci iam compartment get, oci iam availability-domain list, oci ce cluster get/list
    #---------------------------------------------------------------------------
    _step_active "OKE cluster"
    local _pids=()
    (oci iam compartment get --compartment-id "$compartment_id" --region "$region" --query 'data.name' --raw-output > "$_ptmp/comp_name" 2>/dev/null) &
    _pids+=($!)
    (oci iam availability-domain list --compartment-id "$compartment_id" --region "$region" --output json > "$_ptmp/ad_json" 2>/dev/null) &
    _pids+=($!)
    
    # Cluster discovery — list all active clusters (picker after wait if multiple)
    if [[ -n "$configured_cluster_id" && "$configured_cluster_id" != "N/A" ]]; then
        # Configured via variables.sh — direct get (parallel)
        (oci ce cluster get --cluster-id "$configured_cluster_id" --region "$region" --output json > "$_ptmp/cluster" 2>/dev/null) &
        _pids+=($!)
        echo "configured" > "$_ptmp/cluster_mode"
    else
        # Discovery — list ALL active clusters (parallel), pick after wait
        (oci ce cluster list --compartment-id "$compartment_id" --region "$region" \
            --lifecycle-state ACTIVE --all --output json > "$_ptmp/cluster_list" 2>/dev/null) &
        _pids+=($!)
        echo "discovered" > "$_ptmp/cluster_mode"
    fi
    wait "${_pids[@]}"
    
    # Read Group 1 results
    local compartment_name="N/A"
    [[ -s "$_ptmp/comp_name" ]] && compartment_name=$(cat "$_ptmp/comp_name")
    [[ -z "$compartment_name" ]] && compartment_name="N/A"
    
    local ads="N/A"
    local _ad_ct=0
    if [[ -s "$_ptmp/ad_json" ]]; then
        ads=$(jq -r '[.data[].name] | join(", ")' "$_ptmp/ad_json" 2>/dev/null) || ads="N/A"
        _ad_ct=$(jq '.data | length // 0' "$_ptmp/ad_json" 2>/dev/null) || _ad_ct=0
    fi
    
    # ── Cluster selection ──
    local cluster_json="" _cluster_mode
    _cluster_mode=$(cat "$_ptmp/cluster_mode" 2>/dev/null)
    
    if [[ "$_cluster_mode" == "configured" ]]; then
        # Configured cluster — use directly, fall back to list if failed
        if [[ -s "$_ptmp/cluster" ]] && jq -e '.data' "$_ptmp/cluster" >/dev/null 2>&1; then
            cluster_json=$(cat "$_ptmp/cluster")
        else
            # Configured OCID failed — fall back to listing
            _step_active "OKE cluster(fallback list)"
            local _fb_list
            _fb_list=$(oci ce cluster list --compartment-id "$compartment_id" --region "$region" \
                --lifecycle-state ACTIVE --all --output json 2>/dev/null)
            if [[ -n "$_fb_list" ]]; then
                echo "$_fb_list" > "$_ptmp/cluster_list"
                _cluster_mode="discovered"
            fi
        fi
    fi
    
    if [[ "$_cluster_mode" == "discovered" && -z "$cluster_json" ]]; then
        local _cl_count=0
        [[ -s "$_ptmp/cluster_list" ]] && _cl_count=$(jq '(.data // []) | length' "$_ptmp/cluster_list" 2>/dev/null || echo "0")
        
        if [[ "$_cl_count" -eq 1 ]]; then
            # Single cluster — auto-select
            local _auto_cid
            _auto_cid=$(jq -r '.data[0].id // empty' "$_ptmp/cluster_list" 2>/dev/null)
            if [[ -n "$_auto_cid" ]]; then
                _step_active "OKE cluster(fetching)"
                oci ce cluster get --cluster-id "$_auto_cid" --region "$region" --output json > "$_ptmp/cluster" 2>/dev/null
                [[ -s "$_ptmp/cluster" ]] && cluster_json=$(cat "$_ptmp/cluster")
            fi
        elif [[ "$_cl_count" -gt 1 ]]; then
            # Multiple clusters — show picker
            # Temporarily allow step bar to finish so picker renders cleanly
            local _saved_outer="${_STEP_OUTER:-0}"
            _STEP_OUTER=0
            _step_complete "OKE clusters(${_cl_count} found)"
            _step_finish
            
            echo ""
            _ui_subheader "Multiple OKE Clusters Found" 0
            echo -e "  ${GRAY}${_cl_count} active clusters in this compartment/region${NC}"
            echo ""
            printf "  ${BOLD}%-4s %-40s %-14s %-14s %-10s${NC}\n" "#" "Cluster Name" "K8s Version" "State" "Created"
            print_separator 90
            
            local _ci=0
            declare -A _CL_PICK_MAP=()
            while IFS=$'\t' read -r _cid _cname _cver _cstate _ccreated; do
                [[ -z "$_cid" ]] && continue
                ((_ci++))
                _CL_PICK_MAP[$_ci]="$_cid"
                local _cdate="${_ccreated:0:10}"
                local _sc="${GREEN}"
                [[ "$_cstate" != "ACTIVE" ]] && _sc="${YELLOW}"
                printf "  ${YELLOW}%-4s${NC} %-40s %-14s ${_sc}%-14s${NC} %-10s\n" \
                    "${_ci})" "${_cname:0:40}" "$_cver" "$_cstate" "$_cdate"
            done < <(jq -r '.data[] | [.id, .name, .["kubernetes-version"], .["lifecycle-state"], .["time-created"]] | @tsv' "$_ptmp/cluster_list" 2>/dev/null)
            
            echo ""
            echo -n -e "  ${CYAN}Select cluster [1]: ${NC}"
            local _cl_choice
            read -r _cl_choice
            [[ -z "$_cl_choice" ]] && _cl_choice=1
            
            local _sel_cid="${_CL_PICK_MAP[$_cl_choice]}"
            if [[ -z "$_sel_cid" ]]; then
                echo -e "  ${RED}Invalid selection — defaulting to cluster 1${NC}"
                _sel_cid="${_CL_PICK_MAP[1]}"
            fi
            
            if [[ -n "$_sel_cid" ]]; then
                # Re-open the step bar for remaining discovery
                _step_init
                _step_active "OKE cluster(fetching)"
                oci ce cluster get --cluster-id "$_sel_cid" --region "$region" --output json > "$_ptmp/cluster" 2>/dev/null
                [[ -s "$_ptmp/cluster" ]] && cluster_json=$(cat "$_ptmp/cluster")
            fi
            # Restore outer mode
            _STEP_OUTER="$_saved_outer"
        fi
    fi
    
    # Parse cluster JSON (file written by configured get, auto-select get, or picker get above)
    [[ -z "$cluster_json" && -s "$_ptmp/cluster" ]] && cluster_json=$(cat "$_ptmp/cluster")
    
    local cluster_name="N/A" cluster_ocid="N/A" cluster_state="N/A"
    local cluster_version="N/A" pod_network="N/A" vcn_ocid="N/A"
    
    if [[ -n "$cluster_json" ]] && jq -e '.data' <<< "$cluster_json" >/dev/null 2>&1; then
        IFS=$'\t' read -r cluster_name cluster_ocid cluster_state cluster_version pod_network vcn_ocid < <(jq -r '.data | [
            (.name // "N/A"),
            (.id // "N/A"),
            (.["lifecycle-state"] // "N/A"),
            (.["kubernetes-version"] // "N/A"),
            ((.["cluster-pod-network-options"] // []) | map(.["cni-type"] // empty) | join(", ") | if . == "" then "N/A" else . end),
            (.["vcn-id"] // "N/A")
        ] | @tsv' <<< "$cluster_json")
        
        # Save cluster JSON to cache for reuse by manage_oke_cluster
        echo "$cluster_json" | _cache_write "$OKE_CLUSTER_JSON_CACHE"
    fi
    
    # Complete Group 1 with descriptive info
    if [[ "$cluster_name" != "N/A" ]]; then
        _step_complete "OKE cluster(${cluster_name})"
    else
        _step_complete "OKE cluster(none)"
    fi
    _step_complete "ADs(${_ad_ct})"
    
    #---------------------------------------------------------------------------
    # PARALLEL GROUP 2: addons + VCN + subnets + NSGs (all need cluster/VCN)
    #---------------------------------------------------------------------------
    local cluster_addons="N/A"
    local vcn_name="N/A"
    local worker_subnet_name="N/A" worker_subnet_ocid="N/A"
    local worker_nsg_name="N/A" worker_nsg_ocid="N/A"
    local pod_subnet_name="N/A" pod_subnet_ocid="N/A"
    local pod_nsg_name="N/A" pod_nsg_ocid="N/A"
    
    if is_valid_ocid "$cluster_ocid"; then
        # Launch parallel: addons + VCN + subnets + NSGs
        # Commands: oci ce cluster list-addons, oci network vcn get, oci network subnet list, oci network nsg list
        _step_active "VCN, subnets, NSGs"
        _pids=()
        (oci ce cluster list-addons --cluster-id "$cluster_ocid" --region "$region" --all --output json > "$_ptmp/addons" 2>/dev/null) &
        _pids+=($!)
        
        if is_valid_ocid "$vcn_ocid"; then
            (oci network vcn get --vcn-id "$vcn_ocid" --region "$region" --query 'data."display-name"' --raw-output > "$_ptmp/vcn_name" 2>/dev/null) &
            _pids+=($!)
            (oci network subnet list --vcn-id "$vcn_ocid" --compartment-id "$compartment_id" --region "$region" --output json > "$_ptmp/subnets" 2>/dev/null) &
            _pids+=($!)
            (oci network nsg list --compartment-id "$compartment_id" --vcn-id "$vcn_ocid" --region "$region" --output json > "$_ptmp/nsgs" 2>/dev/null) &
            _pids+=($!)
        fi
        wait "${_pids[@]}"
        
        # Count results for discovery labels
        local _sub_ct=0 _nsg_ct=0 _addon_ct=0 _vcn_label="N/A"
        [[ -s "$_ptmp/vcn_name" ]] && _vcn_label=$(cat "$_ptmp/vcn_name")
        [[ -z "$_vcn_label" ]] && _vcn_label="N/A"
        [[ -s "$_ptmp/subnets" ]] && _sub_ct=$(jq '.data | length // 0' "$_ptmp/subnets" 2>/dev/null)
        [[ -s "$_ptmp/nsgs" ]] && _nsg_ct=$(jq '.data | length // 0' "$_ptmp/nsgs" 2>/dev/null)
        [[ -s "$_ptmp/addons" ]] && _addon_ct=$(jq '[.data[] | select(.["lifecycle-state"] == "ACTIVE")] | length // 0' "$_ptmp/addons" 2>/dev/null)
        _sub_ct="${_sub_ct:-0}"; _nsg_ct="${_nsg_ct:-0}"; _addon_ct="${_addon_ct:-0}"
        
        _step_complete "VCN(${_vcn_label})"
        _step_complete "subnets(${_sub_ct})"
        _step_complete "NSGs(${_nsg_ct})"
        _step_complete "addons(${_addon_ct})"
        
        # Parse addons
        if [[ -s "$_ptmp/addons" ]]; then
            local addon_lines
            addon_lines=$(jq -r '.data[] | select(.["lifecycle-state"] == "ACTIVE") | .name + " (" + (.["current-installed-version"] // "N/A") + ")"' "$_ptmp/addons" 2>/dev/null)
            if [[ -n "$addon_lines" ]]; then
                cluster_addons=$(echo "$addon_lines" | tr '\n' ',' | sed 's/,$//' | sed 's/,/, /g')
            else
                cluster_addons="None installed"
            fi
        else
            cluster_addons="Unable to retrieve"
        fi
        
        # Parse VCN name
        [[ -s "$_ptmp/vcn_name" ]] && vcn_name=$(cat "$_ptmp/vcn_name")
        [[ -z "$vcn_name" ]] && vcn_name="N/A"
        
        # Parse subnets and NSGs
        if [[ -s "$_ptmp/subnets" ]]; then
            local subnet_json
            subnet_json=$(cat "$_ptmp/subnets")
            # Save to subnet cache for nodepool subnet resolution
            cp "$_ptmp/subnets" "$OKE_SUBNET_LIST_CACHE" 2>/dev/null
            
            worker_subnet_name=$(jq -r '.data[] | select(."display-name" | test("worker"; "i")) | ."display-name"' <<< "$subnet_json" 2>/dev/null | head -n1 )
            worker_subnet_ocid=$(jq -r '.data[] | select(."display-name" | test("worker"; "i")) | .id' <<< "$subnet_json" 2>/dev/null | head -n1 )
            pod_subnet_name=$(jq -r '.data[] | select(."display-name" | test("pod"; "i")) | ."display-name"' <<< "$subnet_json" 2>/dev/null | head -n1 )
            pod_subnet_ocid=$(jq -r '.data[] | select(."display-name" | test("pod"; "i")) | .id' <<< "$subnet_json" 2>/dev/null | head -n1 )
        fi
        worker_subnet_name="${worker_subnet_name:-N/A}"; worker_subnet_ocid="${worker_subnet_ocid:-N/A}"
        pod_subnet_name="${pod_subnet_name:-N/A}"; pod_subnet_ocid="${pod_subnet_ocid:-N/A}"
        
        if [[ -s "$_ptmp/nsgs" ]]; then
            local nsg_json
            nsg_json=$(cat "$_ptmp/nsgs")
            worker_nsg_name=$(jq -r '.data[] | select(."display-name" | test("worker"; "i")) | ."display-name"' <<< "$nsg_json" 2>/dev/null | head -n1 )
            worker_nsg_ocid=$(jq -r '.data[] | select(."display-name" | test("worker"; "i")) | .id' <<< "$nsg_json" 2>/dev/null | head -n1 )
            pod_nsg_name=$(jq -r '.data[] | select(."display-name" | test("pod"; "i")) | ."display-name"' <<< "$nsg_json" 2>/dev/null | head -n1 )
            pod_nsg_ocid=$(jq -r '.data[] | select(."display-name" | test("pod"; "i")) | .id' <<< "$nsg_json" 2>/dev/null | head -n1 )
        fi
        worker_nsg_name="${worker_nsg_name:-N/A}"; worker_nsg_ocid="${worker_nsg_ocid:-N/A}"
        pod_nsg_name="${pod_nsg_name:-N/A}"; pod_nsg_ocid="${pod_nsg_ocid:-N/A}"
        
        # Populate NETWORK_RESOURCES_CACHE from the same data to avoid duplicate fetch
        # (display_network_resources → fetch_network_resources would make the same API calls)
        if [[ -s "$_ptmp/subnets" ]] || [[ -s "$_ptmp/nsgs" ]]; then
            {
                echo "# Network Resources Cache (populated by fetch_oke_environment)"
                echo "# Format: SUBNET|NAME|CIDR|ACCESS|STATE|OCID|RT_OCID|SL_IDS|DNS_LABEL|COMPARTMENT_ID"
                echo "# Format: NSG|NAME||STATE|OCID|COMPARTMENT_ID"
                [[ -s "$_ptmp/subnets" ]] && jq -r '.data[] | "SUBNET|\(."display-name" // "N/A")|\(."cidr-block" // "N/A")|\(if ."prohibit-public-ip-on-vnic" then "Private" else "Public" end)|\(."lifecycle-state" // "N/A")|\(.id // "N/A")|\(."route-table-id" // "N/A")|\((."security-list-ids" // []) | join(","))|\(."dns-label" // "")|\(."compartment-id" // "N/A")"' "$_ptmp/subnets" 2>/dev/null
                [[ -s "$_ptmp/nsgs" ]] && jq -r '.data[] | "NSG|\(."display-name" // "N/A")||\(."lifecycle-state" // "N/A")|\(.id // "N/A")|\(."compartment-id" // "N/A")"' "$_ptmp/nsgs" 2>/dev/null
            } | _cache_write "$NETWORK_RESOURCES_CACHE"
        fi
    fi
    
    _step_finish
    
    # Cleanup temp files
    rm -rf "${_ptmp:?}"
    
    # Write cache
    {
        echo "TENANCY_OCID|${tenancy_ocid:-N/A}"
        echo "COMPARTMENT_NAME|${compartment_name}"
        echo "COMPARTMENT_OCID|${compartment_id}"
        echo "REGION|${region}"
        echo "ADS|${ads}"
        echo "CLUSTER_NAME|${cluster_name}"
        echo "OKE_CLUSTER_ID|${cluster_ocid}"
        echo "CLUSTER_STATE|${cluster_state}"
        echo "CLUSTER_VERSION|${cluster_version}"
        echo "CLUSTER_ADDONS|${cluster_addons}"
        echo "POD_NETWORK|${pod_network}"
        echo "VCN_NAME|${vcn_name}"
        echo "VCN_OCID|${vcn_ocid}"
        echo "WORKER_SUBNET_NAME|${worker_subnet_name}"
        echo "WORKER_SUBNET_OCID|${worker_subnet_ocid}"
        echo "WORKER_NSG_NAME|${worker_nsg_name}"
        echo "WORKER_NSG_OCID|${worker_nsg_ocid}"
        echo "POD_SUBNET_NAME|${pod_subnet_name}"
        echo "POD_SUBNET_OCID|${pod_subnet_ocid}"
        echo "POD_NSG_NAME|${pod_nsg_name}"
        echo "POD_NSG_OCID|${pod_nsg_ocid}"
    } | _cache_write "$OKE_ENV_CACHE"
}

# Get value from OKE environment cache
get_oke_env_value() {
    local key="$1"
    grep "^${key}|" "$OKE_ENV_CACHE" 2>/dev/null | cut -d'|' -f2
}

# Resolve subnet display name from cache, fallback to API
# Cache format: SUBNET|NAME|CIDR|ACCESS|STATE|OCID|...
# Args: $1 = subnet OCID
# Output: subnet name to stdout
resolve_subnet_name_cached() {
    local subnet_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$subnet_ocid" || "$subnet_ocid" == "N/A" ]] && echo "N/A" && return

    # Try network resources cache first (SUBNET|NAME|...|OCID is field 6)
    if [[ -f "$NETWORK_RESOURCES_CACHE" ]]; then
        local cached_name
        cached_name=$(awk -F'|' -v ocid="$subnet_ocid" '$1=="SUBNET" && $6==ocid {print $2; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
        if [[ -n "$cached_name" ]]; then
            echo "$cached_name"
            return
        fi
    fi

    # Fallback to API
    local api_name
    api_name=$(oci network subnet get --subnet-id "$subnet_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null) || api_name="N/A"
    echo "${api_name:-N/A}"
}

#--------------------------------------------------------------------------------
# Cached image name resolution - avoids redundant OCI API calls
# Uses IMAGE_CACHE file first, then in-memory cache, then API fallback
# Args: $1 = image OCID
# Returns: image display name or "N/A"
#--------------------------------------------------------------------------------
declare -gA _IMAGE_NAME_CACHE=()

resolve_image_name_cached() {
    local image_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$image_ocid" || "$image_ocid" == "N/A" ]] && echo "N/A" && return

    # Try in-memory cache first
    if [[ -n "${_IMAGE_NAME_CACHE[$image_ocid]:-}" ]]; then
        echo "${_IMAGE_NAME_CACHE[$image_ocid]}"
        return
    fi
    
    # Try CUSTOM_IMAGE_CACHE (JSON)
    if [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
        local _name
        _name=$(jq -r --arg id "$image_ocid" '.data[] | select(.id == $id) | .["display-name"] // empty' "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
        if [[ -n "$_name" ]]; then
            _IMAGE_NAME_CACHE["$image_ocid"]="$_name"
            echo "$_name"
            return
        fi
    fi
    
    # Try IMAGE_CACHE (text format: ocid|name|...)
    if [[ -s "$IMAGE_CACHE" ]]; then
        local _name
        _name=$(grep "^${image_ocid}|" "$IMAGE_CACHE" 2>/dev/null | head -1 | cut -d'|' -f2)
        if [[ -n "$_name" ]]; then
            _IMAGE_NAME_CACHE["$image_ocid"]="$_name"
            echo "$_name"
            return
        fi
    fi
    
    # Fallback to API
    local api_name
    api_name=$(oci compute image get --image-id "$image_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null) || api_name="N/A"
    _IMAGE_NAME_CACHE["$image_ocid"]="${api_name:-N/A}"
    echo "${api_name:-N/A}"
}

resolve_nsg_name_cached() {
    local nsg_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"
    [[ -z "$nsg_ocid" || "$nsg_ocid" == "N/A" ]] && echo "N/A" && return

    # Try NETWORK_RESOURCES_CACHE first (NSG|NAME||STATE|OCID|COMPARTMENT_ID)
    if [[ -f "$NETWORK_RESOURCES_CACHE" ]]; then
        local cached_name
        cached_name=$(awk -F'|' -v ocid="$nsg_ocid" '$1=="NSG" && $5==ocid {print $2; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
        if [[ -n "$cached_name" ]]; then
            echo "$cached_name"
            return
        fi
    fi
    
    # Fallback to API
    local api_name
    api_name=$(oci network nsg get --nsg-id "$nsg_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null) || api_name="N/A"
    echo "${api_name:-N/A}"
}

# Cached subnet list JSON — returns JSON from cache or fetches live
# Usage: local json; json=$(_get_subnet_list_cached "$compartment_id" "$vcn_ocid")
_get_subnet_list_cached() {
    local _comp_id="$1" _vcn_id="${2:-}"
    local region="${FOCUS_REGION:-$REGION}"

    # Try OKE_SUBNET_LIST_CACHE (JSON, VCN-scoped from OKE discovery)
    if is_cache_fresh "$OKE_SUBNET_LIST_CACHE" 2>/dev/null && [[ -s "$OKE_SUBNET_LIST_CACHE" ]]; then
        local _cached
        _cached=$(cat "$OKE_SUBNET_LIST_CACHE" 2>/dev/null)
        if [[ -n "$_cached" ]] && jq -e '.data[0]' <<< "$_cached" >/dev/null 2>&1; then
            echo "cached"  # signal to caller
            echo "$_cached"
            return
        fi
    fi
    
    # Live fetch
    local _json
    if [[ -n "$_vcn_id" ]]; then
        _json=$(oci network subnet list --vcn-id "$_vcn_id" --compartment-id "$_comp_id" --region "$region" --all --output json 2>/dev/null)
    else
        _json=$(oci network subnet list --compartment-id "$_comp_id" --region "$region" --all --output json 2>/dev/null)
    fi
    echo "live"
    echo "$_json"
}

# Cached NSG list JSON — returns JSON from NETWORK_RESOURCES_CACHE or fetches live
_get_nsg_list_cached() {
    local _comp_id="$1" _vcn_id="${2:-}"
    local region="${FOCUS_REGION:-$REGION}"

    # Try NETWORK_RESOURCES_CACHE (text → JSON)
    if is_cache_fresh "$NETWORK_RESOURCES_CACHE" 2>/dev/null; then
        local _nsg_lines
        _nsg_lines=$(grep '^NSG|' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
        if [[ -n "$_nsg_lines" ]]; then
            local _json
            _json=$(echo "$_nsg_lines" | awk -F'|' '{printf "{\"id\":\"%s\",\"display-name\":\"%s\",\"lifecycle-state\":\"%s\"}\n", $5, $2, $4}' | jq -s '{data: .}' 2>/dev/null)
            if [[ -n "$_json" ]] && jq -e '.data[0]' <<< "$_json" >/dev/null 2>&1; then
                echo "cached"
                echo "$_json"
                return
            fi
        fi
    fi
    
    # Live fetch
    local _json
    if [[ -n "$_vcn_id" ]]; then
        _json=$(oci network nsg list --compartment-id "$_comp_id" --vcn-id "$_vcn_id" --region "$region" --all --output json 2>/dev/null)
    else
        _json=$(oci network nsg list --compartment-id "$_comp_id" --region "$region" --all --output json 2>/dev/null)
    fi
    echo "live"
    echo "$_json"
}

# Cached custom images list — returns JSON from CUSTOM_IMAGE_CACHE or fetches live
_get_custom_images_cached() {
    local _comp_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    if is_cache_fresh "$CUSTOM_IMAGE_CACHE" 2>/dev/null && [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
        local _cached
        _cached=$(cat "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
        if [[ -n "$_cached" ]] && jq -e '.data' <<< "$_cached" >/dev/null 2>&1; then
            echo "cached"
            echo "$_cached"
            return
        fi
    fi
    
    # Live fetch — filter to compartment-owned images only
    local _all
    _all=$(oci compute image list --compartment-id "$_comp_id" --region "$region" --lifecycle-state AVAILABLE \
        --sort-by TIMECREATED --sort-order DESC --all --output json 2>/dev/null)
    local _custom
    _custom=$(jq --arg cid "$_comp_id" '{ data: [.data[] | select(.["compartment-id"] == $cid)] }' <<< "$_all" 2>/dev/null)
    
    # Update cache
    if [[ -n "$_custom" ]] && jq -e '.data' <<< "$_custom" >/dev/null 2>&1; then
        echo "$_custom" > "${CUSTOM_IMAGE_CACHE}.tmp" && mv "${CUSTOM_IMAGE_CACHE}.tmp" "$CUSTOM_IMAGE_CACHE" 2>/dev/null
    fi
    
    echo "live"
    echo "$_custom"
}
fetch_network_resources() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$NETWORK_RESOURCES_CACHE" && return 0
    
    [[ "$vcn_ocid" == "N/A" || -z "$vcn_ocid" ]] && return 1
    
    log_info "Fetching network resources..."
    
    _step_init
    _step_active "subnets, NSGs(2 parallel)"
    
    # Fetch subnets and NSGs in parallel
    local _nr_tmp="${TEMP_DIR}/nr_fetch_$$"
    mkdir -p "$_nr_tmp"
    
    (oci network subnet list --vcn-id "$vcn_ocid" --compartment-id "$compartment_id" --region "$region" --output json > "$_nr_tmp/subnets.json" 2>/dev/null) &
    local _nr_p1=$!
    (oci network nsg list --compartment-id "$compartment_id" --vcn-id "$vcn_ocid" --region "$region" --output json > "$_nr_tmp/nsgs.json" 2>/dev/null) &
    local _nr_p2=$!
    wait "$_nr_p1" "$_nr_p2" 2>/dev/null
    
    local subnet_json="" nsg_json=""
    [[ -s "$_nr_tmp/subnets.json" ]] && subnet_json=$(cat "$_nr_tmp/subnets.json")
    [[ -s "$_nr_tmp/nsgs.json" ]] && nsg_json=$(cat "$_nr_tmp/nsgs.json")
    rm -rf "${_nr_tmp:?}"
    
    local _sub_ct=0 _nsg_ct=0
    [[ -n "$subnet_json" ]] && _sub_ct=$(jq '.data | length // 0' <<< "$subnet_json" 2>/dev/null)
    [[ -n "$nsg_json" ]] && _nsg_ct=$(jq '.data | length // 0' <<< "$nsg_json" 2>/dev/null)
    _sub_ct="${_sub_ct:-0}"; _nsg_ct="${_nsg_ct:-0}"
    
    _step_complete "subnets(${_sub_ct})"
    _step_complete "NSGs(${_nsg_ct})"
    _step_finish
    
    # Write cache
    {
        echo "# Network Resources Cache"
        echo "# Format: SUBNET|NAME|CIDR|ACCESS|STATE|OCID|RT_OCID|SL_IDS|DNS_LABEL|COMPARTMENT_ID"
        echo "# Format: NSG|NAME||STATE|OCID|COMPARTMENT_ID"
        
        # Process subnets (include route-table-id, security-list-ids, dns-label, compartment-id)
        jq -r '.data[] | "SUBNET|\(."display-name" // "N/A")|\(."cidr-block" // "N/A")|\(if ."prohibit-public-ip-on-vnic" then "Private" else "Public" end)|\(."lifecycle-state" // "N/A")|\(.id // "N/A")|\(."route-table-id" // "N/A")|\((."security-list-ids" // []) | join(","))|\(."dns-label" // "")|\(."compartment-id" // "N/A")"' <<< "$subnet_json" 2>/dev/null
        
        # Process NSGs
        jq -r '.data[] | "NSG|\(."display-name" // "N/A")||\(."lifecycle-state" // "N/A")|\(.id // "N/A")|\(."compartment-id" // "N/A")"' <<< "$nsg_json" 2>/dev/null
    } | _cache_write "$NETWORK_RESOURCES_CACHE"
}

#===============================================================================
# NETWORK GATEWAY FUNCTIONS
#===============================================================================

# Fetch and cache Internet Gateways
fetch_internet_gateways() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$IGW_CACHE" && return 0

    log_info "Fetching Internet Gateways..."
    
    # Cache format: VCN_ID|IGW_ID|STATE|DISPLAY_NAME|COMPARTMENT_ID
    local _tmp_cache="${IGW_CACHE}.tmp.$$"
    > "$_tmp_cache"
    local -A _seen_ids=()

    # Build compartment list to search
    local -a _comps=("$compartment_id")
    [[ -n "$NETWORK_COMPARTMENT_ID" && "$NETWORK_COMPARTMENT_ID" != "$compartment_id" ]] && _comps+=("$NETWORK_COMPARTMENT_ID")

    for _c in "${_comps[@]}"; do
        local result
        result=$(oci network internet-gateway list \
            --compartment-id "$_c" \
            --vcn-id "$vcn_ocid" \
            --region "$region" \
            --all \
            --output json 2>/dev/null) || continue

        while IFS='|' read -r _vcn _id _state _name _comp; do
            [[ -z "$_id" || -n "${_seen_ids[$_id]+x}" ]] && continue
            _seen_ids[$_id]=1
            echo "${_vcn}|${_id}|${_state}|${_name}|${_comp}" >> "$_tmp_cache"
        done < <(jq -r '.data[] | "\(.["vcn-id"])|\(.id)|\(.["lifecycle-state"])|\(.["display-name"] // "N/A")|\(.["compartment-id"])"' <<< "$result" 2>/dev/null)
    done

    [[ -s "$_tmp_cache" ]] && mv -f "$_tmp_cache" "$IGW_CACHE" || { rm -f "$_tmp_cache"; touch "$IGW_CACHE"; }
}

