# Fetch and cache DRG list (the DRGs themselves, not attachments)
# Cache format: DRG_ID|DISPLAY_NAME|STATE|COMPARTMENT_ID
fetch_drgs() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$DRG_LIST_CACHE" && return 0

    log_info "Fetching DRGs..."
    
    local _tmp_cache="${DRG_LIST_CACHE}.tmp.$$"
    > "$_tmp_cache"
    local -A _seen_ids=()

    local -a _comps=("$compartment_id")
    [[ -n "$NETWORK_COMPARTMENT_ID" && "$NETWORK_COMPARTMENT_ID" != "$compartment_id" ]] && _comps+=("$NETWORK_COMPARTMENT_ID")

    for _c in "${_comps[@]}"; do
        [[ -z "$_c" ]] && continue
        local result
        result=$(oci network drg list \
            --compartment-id "$_c" \
            --region "$region" \
            --all \
            --output json 2>/dev/null) || continue

        while IFS='|' read -r _id _name _state _comp; do
            [[ -z "$_id" || -n "${_seen_ids[$_id]+x}" ]] && continue
            _seen_ids[$_id]=1
            echo "${_id}|${_name}|${_state}|${_comp}" >> "$_tmp_cache"
        done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "N/A")|\(.["lifecycle-state"])|\(.["compartment-id"])"' <<< "$result" 2>/dev/null)
    done

    [[ -s "$_tmp_cache" ]] && mv -f "$_tmp_cache" "$DRG_LIST_CACHE" || { rm -f "$_tmp_cache"; touch "$DRG_LIST_CACHE"; }
}

# Fetch and cache DRG Attachments
fetch_drg_attachments() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$DRG_CACHE" && return 0

    log_info "Fetching DRG Attachments..."
    
    # Cache format: VCN_ID|DRG_ID|STATE|DISPLAY_NAME|COMPARTMENT_ID|ATTACHMENT_OCID
    local _tmp_cache="${DRG_CACHE}.tmp.$$"
    > "$_tmp_cache"
    local -A _seen_ids=()

    local -a _comps=("$compartment_id")
    [[ -n "$NETWORK_COMPARTMENT_ID" && "$NETWORK_COMPARTMENT_ID" != "$compartment_id" ]] && _comps+=("$NETWORK_COMPARTMENT_ID")

    for _c in "${_comps[@]}"; do
        local result
        result=$(oci network drg-attachment list \
            --compartment-id "$_c" \
            --region "$region" \
            --all \
            --output json 2>/dev/null) || continue

        # Handle both DRGv1 and DRGv2 formats
        while IFS='|' read -r _vcn _drg _state _name _id _comp; do
            [[ -z "$_id" || -n "${_seen_ids[$_id]+x}" ]] && continue
            [[ -z "$_vcn" || "$_vcn" == "null" ]] && continue
            _seen_ids[$_id]=1
            echo "${_vcn}|${_drg}|${_state}|${_name}|${_comp}|${_id}" >> "$_tmp_cache"
        done < <(jq -r '.data[] |
            (if .["vcn-id"] != null then .["vcn-id"]
             elif .["network-details"] != null and .["network-details"]["id"] != null then .["network-details"]["id"]
             else "null" end) as $vcn |
            "\($vcn)|\(.["drg-id"])|\(.["lifecycle-state"])|\(.["display-name"] // "N/A")|\(.id)|\(.["compartment-id"])"' <<< "$result" 2>/dev/null)
    done

    [[ -s "$_tmp_cache" ]] && mv -f "$_tmp_cache" "$DRG_CACHE" || { rm -f "$_tmp_cache"; touch "$DRG_CACHE"; }
}

