# Fetch and cache NSG rules for all NSGs
fetch_nsg_rules() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$NSG_RULES_CACHE" && return 0

    log_info "Fetching NSG rules..."
    
    # Cache format: NSG_ID|INGRESS_COUNT|EGRESS_COUNT
    > "$NSG_RULES_CACHE"
    
    local -a _comps=("$compartment_id")
    [[ -n "$NETWORK_COMPARTMENT_ID" && "$NETWORK_COMPARTMENT_ID" != "$compartment_id" ]] && _comps+=("$NETWORK_COMPARTMENT_ID")
    
    for _c in "${_comps[@]}"; do
        # Get all NSGs in this compartment
        local nsgs_json
        nsgs_json=$(oci network nsg list \
            --compartment-id "$_c" \
            --vcn-id "$vcn_ocid" \
            --region "$region" \
            --all \
            --output json 2>/dev/null) || continue
        
        jq -r '.data[].id' <<< "$nsgs_json" 2>/dev/null | while read -r nsg_id; do
            [[ -z "$nsg_id" ]] && continue
            # Dedup across compartments (subshell, so use file-based dedup)
            grep -q "^${nsg_id}|" "$NSG_RULES_CACHE" 2>/dev/null && continue
            
            local result ingress_count egress_count
            result=$(oci network nsg rules list \
                --nsg-id "$nsg_id" \
                --region "$region" \
                --all \
                --output json 2>/dev/null)
            
            if [[ -n "$result" ]]; then
                ingress_count=$(jq '[.data[] | select(.direction=="INGRESS")] | length' <<< "$result" 2>/dev/null) || ingress_count=0
                egress_count=$(jq '[.data[] | select(.direction=="EGRESS")] | length' <<< "$result" 2>/dev/null) || egress_count=0
            else
                ingress_count=0
                egress_count=0
            fi
            
            echo "${nsg_id}|${ingress_count:-0}|${egress_count:-0}" >> "$NSG_RULES_CACHE"
        done
    done
    
    [[ ! -s "$NSG_RULES_CACHE" ]] && touch "$NSG_RULES_CACHE"
}

#--------------------------------------------------------------------------------
# Fetch NSG → Subnet mapping via VNIC lookup (two-phase):
#   Phase 1: oci network nsg vnics list → get vnic-ids per NSG (parallel)
#   Phase 2: oci network vnic get → get subnet-id per VNIC (batched parallel)
# Cache format: NSG_OCID|SUBNET_OCID1,SUBNET_OCID2,...
#
# Globals set by phase1 for phase2:
#   _NSM_PHASE1_DONE, _NSM_TOTAL_VNICS, _NSM_DIR, _NSM_NSG_IDS[], _NSM_NSG_VNICS[],
#   _NSM_ALL_VNIC_LIST[], _NSM_ALL_VNIC_SEEN[]
#--------------------------------------------------------------------------------
fetch_nsg_subnet_map_phase1() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local region="${FOCUS_REGION:-$REGION}"

    _NSM_PHASE1_DONE=0
    _NSM_TOTAL_VNICS=0
    
    is_cache_fresh "$NSG_SUBNET_MAP_CACHE" && return 0
    
    [[ ! -f "$NETWORK_RESOURCES_CACHE" ]] && return 1
    
    > "$NSG_SUBNET_MAP_CACHE"
    
    # Get list of NSG OCIDs from cache
    _NSM_NSG_IDS=()
    while IFS='|' read -r type name _ state ocid _; do
        [[ "$type" != "NSG" || -z "$ocid" ]] && continue
        _NSM_NSG_IDS+=("$ocid")
    done < "$NETWORK_RESOURCES_CACHE"
    
    local nsg_count=${#_NSM_NSG_IDS[@]}
    [[ $nsg_count -eq 0 ]] && { touch "$NSG_SUBNET_MAP_CACHE"; return 0; }
    
    _NSM_DIR=$(mktemp -d "${TEMP_DIR}/nsm.XXXXXX" 2>/dev/null)
    
    # Parallel nsg vnics list (track PIDs — don't use bare 'wait')
    local -a _nsg_pids=()
    for i in "${!_NSM_NSG_IDS[@]}"; do
        oci network nsg vnics list --nsg-id "${_NSM_NSG_IDS[$i]}" --region "$region" --all --output json \
            > "$_NSM_DIR/nsg_${i}.json" 2>/dev/null &
        _nsg_pids+=($!)
    done
    for _p in "${_nsg_pids[@]}"; do wait "$_p" 2>/dev/null; done
    
    # Parse: build per-NSG VNIC list + collect all unique VNICs
    declare -gA _NSM_NSG_VNICS=()
    _NSM_ALL_VNIC_LIST=()
    declare -gA _NSM_ALL_VNIC_SEEN=()
    
    for i in "${!_NSM_NSG_IDS[@]}"; do
        local _nf="$_NSM_DIR/nsg_${i}.json"
        local _vnic_ids=""
        if [[ -f "$_nf" && -s "$_nf" ]]; then
            _vnic_ids=$(jq -r '.data[]? | .["vnic-id"] // empty' "$_nf" 2>/dev/null | sort -u)
        fi
        _NSM_NSG_VNICS[$i]="$_vnic_ids"
        while IFS= read -r _vid; do
            [[ -z "$_vid" ]] && continue
            if [[ -z "${_NSM_ALL_VNIC_SEEN[$_vid]+x}" ]]; then
                _NSM_ALL_VNIC_SEEN["$_vid"]=1
                _NSM_ALL_VNIC_LIST+=("$_vid")
            fi
        done <<< "$_vnic_ids"
    done
    
    _NSM_TOTAL_VNICS=${#_NSM_ALL_VNIC_LIST[@]}
    _NSM_PHASE1_DONE=1
    
    # If no VNICs found at all, write empty mappings now
    if [[ $_NSM_TOTAL_VNICS -eq 0 ]]; then
        for nsg_id in "${_NSM_NSG_IDS[@]}"; do
            echo "${nsg_id}|" >> "$NSG_SUBNET_MAP_CACHE"
        done
        rm -rf "${_NSM_DIR:?}" 2>/dev/null
        _NSM_PHASE1_DONE=0  # skip phase2
    fi
}

fetch_nsg_subnet_map_phase2() {
    local total_vnics=${#_NSM_ALL_VNIC_LIST[@]}
    local region="${FOCUS_REGION:-$REGION}"
    [[ $total_vnics -eq 0 ]] && return 0
    
    # Batched parallel vnic get (max 10 concurrent, track PIDs)
    declare -A _vnic_subnet=()
    local _batch_size=10
    
    for (( _bi=0; _bi<total_vnics; _bi+=_batch_size )); do
        local -a _batch_pids=()
        local -a _batch_vids=()
        
        for (( _bj=_bi; _bj<_bi+_batch_size && _bj<total_vnics; _bj++ )); do
            local _vid="${_NSM_ALL_VNIC_LIST[$_bj]}"
            _batch_vids+=("$_vid")
            oci network vnic get --vnic-id "$_vid" --region "$region" --query 'data."subnet-id"' --raw-output \
                > "$_NSM_DIR/vnic_${_bj}.txt" 2>/dev/null &
            _batch_pids+=($!)
        done
        
        for _p in "${_batch_pids[@]}"; do wait "$_p" 2>/dev/null; done
        
        for _idx in "${!_batch_vids[@]}"; do
            local _vid="${_batch_vids[$_idx]}"
            local _fi=$(( _bi + _idx ))
            local _sf="$_NSM_DIR/vnic_${_fi}.txt"
            if [[ -f "$_sf" && -s "$_sf" ]]; then
                local _sid
                _sid=$(cat "$_sf" 2>/dev/null)
                [[ -n "$_sid" && "$_sid" != "null" && "$_sid" != "None" ]] && _vnic_subnet["$_vid"]="$_sid"
            fi
        done
    done
    
    # Build NSG → unique subnet list and write cache
    for i in "${!_NSM_NSG_IDS[@]}"; do
        local nsg_id="${_NSM_NSG_IDS[$i]}"
        local _vnics="${_NSM_NSG_VNICS[$i]:-}"
        declare -A _seen_subs=()
        local _sub_list=""
        
        while IFS= read -r _vid; do
            [[ -z "$_vid" ]] && continue
            local _sid="${_vnic_subnet[$_vid]:-}"
            if [[ -n "$_sid" && -z "${_seen_subs[$_sid]+x}" ]]; then
                _seen_subs["$_sid"]=1
                [[ -n "$_sub_list" ]] && _sub_list="${_sub_list},"
                _sub_list="${_sub_list}${_sid}"
            fi
        done <<< "$_vnics"
        
        unset _seen_subs
        echo "${nsg_id}|${_sub_list}" >> "$NSG_SUBNET_MAP_CACHE"
    done
    
    rm -rf "${_NSM_DIR:?}" 2>/dev/null
}

#--------------------------------------------------------------------------------
# Fetch NSG rules detail with parallel processing and caching
# Args: $1 = array of NSG IDs (space-separated or newline-separated)
# Caches full rules JSON in NSG_RULES_DETAIL_DIR/{nsg_short_id}.json
#--------------------------------------------------------------------------------
fetch_nsg_rules_detail_parallel() {
    local nsg_ids="$1"
    local region="${FOCUS_REGION:-$REGION}"

    [[ -z "$nsg_ids" ]] && return 0
    
    # Create cache directory if needed
    mkdir -p "$NSG_RULES_DETAIL_DIR"
    
    # Count NSGs to fetch (skip already cached)
    local nsg_list=()
    local cached_count=0
    local to_fetch=()
    
    while read -r nsg_id; do
        [[ -z "$nsg_id" ]] && continue
        nsg_list+=("$nsg_id")
        
        local nsg_short="${nsg_id##*.}"
        local cache_file="${NSG_RULES_DETAIL_DIR}/${nsg_short}.json"
        
        # Check if cache is fresh (TTL from CACHE_MAX_AGE)
        if [[ -f "$cache_file" ]]; then
            local file_age=$(($(date +%s) - $(stat -c %Y "$cache_file" 2>/dev/null || echo 0)))
            if [[ $file_age -lt $CACHE_MAX_AGE ]]; then
                ((cached_count++))
                continue
            fi
        fi
        to_fetch+=("$nsg_id")
    done <<< "$nsg_ids"
    
    local total_count=${#nsg_list[@]}
    local fetch_count=${#to_fetch[@]}
    
    if [[ $fetch_count -eq 0 ]]; then
        return 0
    fi
    
    # Create temp directory for parallel outputs
    local parallel_temp="${TEMP_DIR}/nsg_rules_parallel_$$"
    mkdir -p "$parallel_temp"
    
    # Determine parallelism (OCI_MAX_PARALLEL, configurable via env var)
    local parallel_jobs=$OCI_MAX_PARALLEL
    [[ "$fetch_count" -lt "$parallel_jobs" ]] && parallel_jobs="$fetch_count"

    # Run parallel fetch using () & + wait pattern (avoids export -f portability issues)
    local _nsg_pids=()
    local _nsg_batch=0
    for nsg_id in "${to_fetch[@]}"; do
        [[ -z "$nsg_id" ]] && continue
        (
            local nsg_short="${nsg_id##*.}"
            local status_file="${parallel_temp}/status_${nsg_short}.txt"
            local cache_file="${NSG_RULES_DETAIL_DIR}/${nsg_short}.json"

            local nsg_json rules_json
            nsg_json=$(oci network nsg get --nsg-id "$nsg_id" --region "$region" --output json 2>/dev/null)
            rules_json=$(oci network nsg rules list --nsg-id "$nsg_id" --region "$region" --all --output json 2>/dev/null)

            if [[ -n "$rules_json" ]]; then
                local nsg_name
                nsg_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$nsg_json" 2>/dev/null)
                jq -n \
                    --arg nsg_id "$nsg_id" \
                    --arg nsg_name "$nsg_name" \
                    --argjson rules "$(jq '.data // []' <<< "$rules_json")" \
                    '{nsg_id: $nsg_id, nsg_name: $nsg_name, rules: $rules}' > "$cache_file" 2>/dev/null
                echo "OK" > "$status_file"
            else
                echo "FAIL" > "$status_file"
            fi
        ) &
        _nsg_pids+=($!)
        ((_nsg_batch++))
        if [[ $_nsg_batch -ge $parallel_jobs ]]; then
            wait "${_nsg_pids[@]}" 2>/dev/null
            _nsg_pids=()
            _nsg_batch=0
        fi
    done
    [[ ${#_nsg_pids[@]} -gt 0 ]] && wait "${_nsg_pids[@]}" 2>/dev/null
    
    # Cleanup
    rm -rf "${parallel_temp:?}"
    
    return 0
}

#--------------------------------------------------------------------------------
# Get cached NSG rules for a specific NSG
# Args: $1 = NSG ID
# Returns: JSON with rules or empty if not cached
#--------------------------------------------------------------------------------
get_cached_nsg_rules() {
    local nsg_id="$1"
    [[ -z "$nsg_id" ]] && return 1
    
    local nsg_short="${nsg_id##*.}"
    local cache_file="${NSG_RULES_DETAIL_DIR}/${nsg_short}.json"
    
    if [[ -f "$cache_file" ]]; then
        cat "$cache_file"
        return 0
    fi
    
    return 1
}

#--------------------------------------------------------------------------------
# Display NSG rules in table format (shared function)
# Args: $1 = rules_json (from oci network nsg rules list)
#       $2 = (optional) use_cache_lookup - if "true", use NETWORK_RESOURCES_CACHE for NSG name lookup
#--------------------------------------------------------------------------------
display_nsg_rules_table() {
    local rules_json="$1"
    local use_cache_lookup="${2:-false}"
    
    if [[ -z "$rules_json" ]] || ! jq -e '.data' <<< "$rules_json" > /dev/null 2>&1; then
        echo -e "${RED}Failed to fetch NSG rules${NC}"
        _ui_policy_hint "read network-security-groups in compartment"
        return 1
    fi
    
    local rule_count
    rule_count=$(jq '(.data // []) | length' <<< "$rules_json")
    echo -e "Found ${GREEN}$rule_count${NC} security rule(s)"
    echo ""
    
    if [[ "$rule_count" -eq 0 ]]; then
        echo -e "${YELLOW}No rules configured${NC}"
        return 0
    fi
    
    # Build NSG name lookup if using cache
    declare -A NSG_NAME_LOOKUP
    if [[ "$use_cache_lookup" == "true" && -f "$NETWORK_RESOURCES_CACHE" ]]; then
        while IFS='|' read -r type name _ state ocid _; do
            [[ "$type" == "NSG" && -n "$ocid" ]] && NSG_NAME_LOOKUP["$ocid"]="$name"
        done < "$NETWORK_RESOURCES_CACHE"
    fi
    
    # Count ingress and egress
    local ingress_count egress_count
    ingress_count=$(jq '[(.data // [])[] | select(.direction == "INGRESS")] | length' <<< "$rules_json")
    egress_count=$(jq '[(.data // [])[] | select(.direction == "EGRESS")] | length' <<< "$rules_json")
    
    # Display ingress rules
    if [[ "$ingress_count" -gt 0 ]]; then
        echo -e "${BOLD}${GREEN}▼▼▼ INGRESS RULES (${ingress_count}) ▼▼▼${NC}"
        echo ""
        printf "${BOLD}%-6s | %-9s | %-8s | %-43s | %-9s | %-9s | %s${NC}\n" \
            "Rule #" "Direction" "Protocol" "Source" "Src Ports" "Dst Ports" "Description"
        printf "${WHITE}%-6s-+-%-9s-+-%-8s-+-%-43s-+-%-9s-+-%-9s-+-%s${NC}\n" \
            "------" "---------" "--------" "-------------------------------------------" "---------" "---------" "---------------------------------------------"
        
        local ingress_rules
        ingress_rules=$(jq -r '
            (.data // [])[] | select(.direction == "INGRESS") |
            [
                .direction,
                (if .protocol == "6" then "TCP"
                 elif .protocol == "17" then "UDP"
                 elif .protocol == "1" then "ICMP"
                 elif .protocol == "all" then "ALL"
                 else .protocol end),
                (.source // .["source-type"] // "N/A"),
                (if .["tcp-options"]["source-port-range"] then
                    "\(.["tcp-options"]["source-port-range"]["min"])-\(.["tcp-options"]["source-port-range"]["max"])"
                 elif .["udp-options"]["source-port-range"] then
                    "\(.["udp-options"]["source-port-range"]["min"])-\(.["udp-options"]["source-port-range"]["max"])"
                 else "ALL" end),
                (if .["tcp-options"]["destination-port-range"] then
                    (if .["tcp-options"]["destination-port-range"]["min"] == .["tcp-options"]["destination-port-range"]["max"] then
                        "\(.["tcp-options"]["destination-port-range"]["min"])"
                    else
                        "\(.["tcp-options"]["destination-port-range"]["min"])-\(.["tcp-options"]["destination-port-range"]["max"])"
                    end)
                 elif .["udp-options"]["destination-port-range"] then
                    (if .["udp-options"]["destination-port-range"]["min"] == .["udp-options"]["destination-port-range"]["max"] then
                        "\(.["udp-options"]["destination-port-range"]["min"])"
                    else
                        "\(.["udp-options"]["destination-port-range"]["min"])-\(.["udp-options"]["destination-port-range"]["max"])"
                    end)
                 elif .["icmp-options"] then "ALL"
                 else "ALL" end),
                (.description // "-")
            ] | @tsv
        ' <<< "$rules_json" 2>/dev/null)
        
        local rule_num=0
        if [[ -n "$ingress_rules" ]]; then
            while IFS=$'\t' read -r direction proto source src_ports dst_ports desc; do
                ((rule_num++))
                # Resolve NSG OCID to name if applicable
                if [[ "$source" == ocid1.networksecuritygroup.* ]]; then
                    local resolved_name="${NSG_NAME_LOOKUP[$source]:-}"
                    if [[ -z "$resolved_name" ]]; then
                        resolved_name=$(resolve_nsg_name_cached "$source")
                    fi
                    [[ -n "$resolved_name" && "$resolved_name" != "null" ]] && source="NSG: $resolved_name"
                fi
                printf "${YELLOW}%-6s${NC} | ${CYAN}%-9s${NC} | ${WHITE}%-8s${NC} | ${GREEN}%-43s${NC} | %-9s | %-9s | ${WHITE}%s${NC}\n" \
                    "$rule_num" "$direction" "$proto" "${source:0:43}" "$src_ports" "$dst_ports" "${desc:0:45}"
            done <<< "$ingress_rules"
        fi
        echo ""
    fi
    
    # Display egress rules
    if [[ "$egress_count" -gt 0 ]]; then
        echo -e "${BOLD}${RED}▲▲▲ EGRESS RULES (${egress_count}) ▲▲▲${NC}"
        echo ""
        printf "${BOLD}%-6s | %-9s | %-8s | %-43s | %-9s | %-9s | %s${NC}\n" \
            "Rule #" "Direction" "Protocol" "Destination" "Src Ports" "Dst Ports" "Description"
        printf "${WHITE}%-6s-+-%-9s-+-%-8s-+-%-43s-+-%-9s-+-%-9s-+-%s${NC}\n" \
            "------" "---------" "--------" "-------------------------------------------" "---------" "---------" "---------------------------------------------"
        
        local egress_rules
        egress_rules=$(jq -r '
            (.data // [])[] | select(.direction == "EGRESS") |
            [
                .direction,
                (if .protocol == "6" then "TCP"
                 elif .protocol == "17" then "UDP"
                 elif .protocol == "1" then "ICMP"
                 elif .protocol == "all" then "ALL"
                 else .protocol end),
                (.destination // .["destination-type"] // "N/A"),
                (if .["tcp-options"]["source-port-range"] then
                    "\(.["tcp-options"]["source-port-range"]["min"])-\(.["tcp-options"]["source-port-range"]["max"])"
                 elif .["udp-options"]["source-port-range"] then
                    "\(.["udp-options"]["source-port-range"]["min"])-\(.["udp-options"]["source-port-range"]["max"])"
                 else "ALL" end),
                (if .["tcp-options"]["destination-port-range"] then
                    (if .["tcp-options"]["destination-port-range"]["min"] == .["tcp-options"]["destination-port-range"]["max"] then
                        "\(.["tcp-options"]["destination-port-range"]["min"])"
                    else
                        "\(.["tcp-options"]["destination-port-range"]["min"])-\(.["tcp-options"]["destination-port-range"]["max"])"
                    end)
                 elif .["udp-options"]["destination-port-range"] then
                    (if .["udp-options"]["destination-port-range"]["min"] == .["udp-options"]["destination-port-range"]["max"] then
                        "\(.["udp-options"]["destination-port-range"]["min"])"
                    else
                        "\(.["udp-options"]["destination-port-range"]["min"])-\(.["udp-options"]["destination-port-range"]["max"])"
                    end)
                 elif .["icmp-options"] then "ALL"
                 else "ALL" end),
                (.description // "-")
            ] | @tsv
        ' <<< "$rules_json" 2>/dev/null)
        
        local rule_num=0
        if [[ -n "$egress_rules" ]]; then
            while IFS=$'\t' read -r direction proto dest src_ports dst_ports desc; do
                ((rule_num++))
                # Resolve NSG OCID to name if applicable
                if [[ "$dest" == ocid1.networksecuritygroup.* ]]; then
                    local resolved_name="${NSG_NAME_LOOKUP[$dest]:-}"
                    if [[ -z "$resolved_name" ]]; then
                        resolved_name=$(resolve_nsg_name_cached "$dest")
                    fi
                    [[ -n "$resolved_name" && "$resolved_name" != "null" ]] && dest="NSG: $resolved_name"
                fi
                printf "${YELLOW}%-6s${NC} | ${MAGENTA}%-9s${NC} | ${WHITE}%-8s${NC} | ${GREEN}%-43s${NC} | %-9s | %-9s | ${WHITE}%s${NC}\n" \
                    "$rule_num" "$direction" "$proto" "${dest:0:43}" "$src_ports" "$dst_ports" "${desc:0:45}"
            done <<< "$egress_rules"
        fi
        echo ""
    fi
    
    if [[ "$ingress_count" -eq 0 && "$egress_count" -eq 0 ]]; then
        echo -e "${YELLOW}No ingress or egress rules configured${NC}"
    fi
}

# Fetch and cache Security Lists
fetch_security_lists() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local region="${FOCUS_REGION:-$REGION}"

    is_cache_fresh "$SL_CACHE" && return 0

    log_info "Fetching Security Lists..."
    
    # Cache format: SL_ID|VCN_ID|DISPLAY_NAME|STATE|INGRESS_COUNT|EGRESS_COUNT|COMPARTMENT_ID
    local _tmp_cache="${SL_CACHE}.tmp.$$"
    > "$_tmp_cache"
    local -A _seen_ids=()

    local -a _comps=("$compartment_id")
    [[ -n "$NETWORK_COMPARTMENT_ID" && "$NETWORK_COMPARTMENT_ID" != "$compartment_id" ]] && _comps+=("$NETWORK_COMPARTMENT_ID")

    for _c in "${_comps[@]}"; do
        local result
        result=$(oci network security-list list \
            --compartment-id "$_c" \
            --vcn-id "$vcn_ocid" \
            --region "$region" \
            --all \
            --output json 2>/dev/null) || continue

        while IFS='|' read -r _id _vcn _name _state _in _eg _comp; do
            [[ -z "$_id" || -n "${_seen_ids[$_id]+x}" ]] && continue
            _seen_ids[$_id]=1
            echo "${_id}|${_vcn}|${_name}|${_state}|${_in}|${_eg}|${_comp}" >> "$_tmp_cache"
        done < <(jq -r '.data[] | "\(.id)|\(.["vcn-id"])|\(.["display-name"])|\(.["lifecycle-state"])|\(.["ingress-security-rules"] | length)|\(.["egress-security-rules"] | length)|\(.["compartment-id"])"' <<< "$result" 2>/dev/null)
    done

    [[ -s "$_tmp_cache" ]] && mv -f "$_tmp_cache" "$SL_CACHE" || { rm -f "$_tmp_cache"; touch "$SL_CACHE"; }
}

# Fetch all network gateway caches
fetch_all_network_gateways() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local network_compartment_id="${3:-}"
    
    [[ "$vcn_ocid" == "N/A" || -z "$vcn_ocid" ]] && return 1
    
    # Skip entirely if all network caches are fresh (avoids empty discovery bar on re-runs)
    local _all_net_fresh=true
    for _nc in "$IGW_CACHE" "$SGW_CACHE" "$NAT_CACHE" "$DRG_LIST_CACHE" "$DRG_CACHE" \
               "$LPG_CACHE" "$RPC_CACHE" "$RT_CACHE" "$NSG_RULES_CACHE" \
               "$NSG_SUBNET_MAP_CACHE" "$SL_CACHE" "$OS_PE_CACHE"; do
        is_cache_fresh "$_nc" || { _all_net_fresh=false; break; }
    done
    [[ "$_all_net_fresh" == "true" ]] && return 0
    
    _step_init
    
    # ── Wave 1: Parallel independent fetches (each writes to its own cache file) ──
    local _gw_pids=() _gw_stale=0
    local _c="$compartment_id" _v="$vcn_ocid" _nc="$network_compartment_id"
    
    if ! is_cache_fresh "$IGW_CACHE"; then
        ( fetch_internet_gateways "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$SGW_CACHE"; then
        ( fetch_service_gateways "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$NAT_CACHE"; then
        ( fetch_nat_gateways "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$DRG_LIST_CACHE"; then
        ( fetch_drgs "$_c" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$DRG_CACHE"; then
        ( fetch_drg_attachments "$_c" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$LPG_CACHE"; then
        ( fetch_local_peering_gateways "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$RPC_CACHE"; then
        ( fetch_remote_peering_connections "$_c" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$RT_CACHE"; then
        ( fetch_route_tables "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$NSG_RULES_CACHE"; then
        ( fetch_nsg_rules "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$SL_CACHE"; then
        ( fetch_security_lists "$_c" "$_v" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    if ! is_cache_fresh "$OS_PE_CACHE"; then
        ( fetch_os_private_endpoints "$_c" "$_nc" ) &
        _gw_pids+=($!); ((_gw_stale++))
    fi
    
    if [[ ${#_gw_pids[@]} -gt 0 ]]; then
        _step_active "network(${_gw_stale} parallel)"
        wait "${_gw_pids[@]}" 2>/dev/null
    fi
    
    # Report results
    _step_complete "IGW($(_clc "$IGW_CACHE")) SGW($(_clc "$SGW_CACHE")) NAT($(_clc "$NAT_CACHE"))"
    _step_complete "DRG($(_clc "$DRG_LIST_CACHE")) DRG-Att($(_clc "$DRG_CACHE")) LPG($(_clc "$LPG_CACHE")) RPC($(_clc "$RPC_CACHE"))"
    _step_complete "RT($(_clc "$RT_CACHE")) NSG($(_clc "$NSG_RULES_CACHE")) SL($(_clc "$SL_CACHE")) PE($(_clc "$OS_PE_CACHE"))"
    
    # ── Wave 2: NSG↔Subnet mapping (uses shell variables between phases — must be serial) ──
    if is_cache_fresh "$NSG_SUBNET_MAP_CACHE"; then
        _step_complete "NSG↔Sub($(_clc "$NSG_SUBNET_MAP_CACHE") cached)"
    else
        _step_active "NSG↔Sub"
        fetch_nsg_subnet_map_phase1 "$compartment_id" "$vcn_ocid"
        
        if [[ "${_NSM_PHASE1_DONE:-0}" -eq 1 && "${_NSM_TOTAL_VNICS:-0}" -gt 0 ]]; then
            fetch_nsg_subnet_map_phase2
        fi
        _step_complete "NSG↔Sub($(_clc "$NSG_SUBNET_MAP_CACHE"))"
    fi
    
    _step_finish
}

#--------------------------------------------------------------------------------
# Fetch Object Storage Private Endpoints and cache them
# Accepts one or two compartment IDs (main + optional network compartment)
# Cache format: name|namespace|state|prefix|subnet-id|private-ip|pe-ocid|nsg-ids|compartment-id|time-created
#--------------------------------------------------------------------------------
fetch_os_private_endpoints() {
    local comp1="$1"
    local comp2="${2:-}"
    local region="${FOCUS_REGION:-$REGION}"

    [[ -z "$comp1" ]] && return 1
    
    # Check cache TTL (reuse CACHE_MAX_AGE)
    if [[ -f "$OS_PE_CACHE" ]]; then
        local cache_mtime cache_age
        cache_mtime=$(stat -c %Y "$OS_PE_CACHE" 2>/dev/null || echo 0)
        cache_age=$(( $(date +%s) - cache_mtime ))
        if [[ $cache_age -lt ${CACHE_MAX_AGE:-300} ]]; then
            return 0
        fi
    fi
    
    # Build unique compartment list
    local -a comp_list=("$comp1")
    [[ -n "$comp2" && "$comp2" != "$comp1" ]] && comp_list+=("$comp2")
    
    # Write cache header
    echo "# OS Private Endpoints - $(date)" > "$OS_PE_CACHE"
    
    local total_found=0
    
    for cid in "${comp_list[@]}"; do
        [[ -z "$cid" ]] && continue
        
        # List all private endpoints in this compartment
        local pe_list_json
        pe_list_json=$(oci os private-endpoint list --compartment-id "$cid" --region "$region" --output json 2>/dev/null)
        
        if [[ -z "$pe_list_json" ]] || ! jq -e '.data[0]' <<< "$pe_list_json" > /dev/null 2>&1; then
            continue
        fi
        
        # The list endpoint returns name, namespace, state, prefix, compartment-id
        # but NOT private-endpoint-ip or subnet-id - we need 'get' for those
        while IFS='|' read -r pe_name pe_namespace pe_state pe_prefix pe_comp; do
            [[ -z "$pe_name" ]] && continue
            
            # Fetch full details for each PE (typically 1-2 per compartment)
            local pe_detail
            pe_detail=$(oci os private-endpoint get \
                --pe-name "$pe_name" \
                --namespace-name "$pe_namespace" \
                --region "$region" \
                --output json 2>/dev/null)
            
            local subnet_id="N/A" private_ip="N/A" pe_ocid="N/A" nsg_ids="" time_created="N/A"
            
            if [[ -n "$pe_detail" ]] && jq -e '.data' <<< "$pe_detail" > /dev/null 2>&1; then
                subnet_id=$(jq -r '.data["subnet-id"] // "N/A"' <<< "$pe_detail")
                private_ip=$(jq -r '.data["private-endpoint-ip"] // "N/A"' <<< "$pe_detail")
                pe_ocid=$(jq -r '.data.id // "N/A"' <<< "$pe_detail")
                time_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$pe_detail")
                # Comma-separated NSG IDs
                nsg_ids=$(jq -r '.data["nsg-ids"] // [] | join(",")' <<< "$pe_detail" 2>/dev/null)
            fi
            
            echo "${pe_name}|${pe_namespace}|${pe_state}|${pe_prefix}|${subnet_id}|${private_ip}|${pe_ocid}|${nsg_ids}|${pe_comp}|${time_created}" >> "$OS_PE_CACHE"
            ((total_found++))
            
        done < <(jq -r '.data[] | "\(.name)|\(.namespace)|\(.["lifecycle-state"] // "N/A")|\(.prefix // "N/A")|\(.["compartment-id"] // "N/A")"' <<< "$pe_list_json" 2>/dev/null)
    done
    
    # Update header with count
    # Update header line (total_found is always an integer — safe for sed)
    local _pe_header="# OS Private Endpoints - $(date) - ${total_found} found"
    sed -i "1s|.*|${_pe_header}|" "$OS_PE_CACHE"
    
    return 0
}

# Check if VCN has an Internet Gateway
has_internet_gateway() {
    local vcn_id="$1"
    [[ ! -f "$IGW_CACHE" ]] && { echo "false"; return; }
    grep -q "^${vcn_id}|" "$IGW_CACHE" 2>/dev/null && echo "true" || echo "false"
}

# Check if VCN has a Service Gateway
has_service_gateway() {
    local vcn_id="$1"
    [[ ! -f "$SGW_CACHE" ]] && { echo "false"; return; }
    grep -q "^${vcn_id}|" "$SGW_CACHE" 2>/dev/null && echo "true" || echo "false"
}

# Check if VCN has a NAT Gateway
has_nat_gateway() {
    local vcn_id="$1"
    [[ ! -f "$NAT_CACHE" ]] && { echo "false"; return; }
    grep -q "^${vcn_id}|" "$NAT_CACHE" 2>/dev/null && echo "true" || echo "false"
}

# Check if VCN has a DRG Attachment
has_drg_attachment() {
    local vcn_id="$1"
    [[ ! -f "$DRG_CACHE" ]] && { echo "false"; return; }
    grep -q "^${vcn_id}|" "$DRG_CACHE" 2>/dev/null && echo "true" || echo "false"
}

# Check if VCN has a Local Peering Gateway
has_local_peering_gateway() {
    local vcn_id="$1"
    [[ ! -f "$LPG_CACHE" ]] && { echo "false"; return; }
    grep -q "^${vcn_id}|" "$LPG_CACHE" 2>/dev/null && echo "true" || echo "false"
}

# Check if VCN has a Remote Peering Connection (via DRG)
has_remote_peering_connection() {
    local vcn_id="$1"
    
    [[ ! -f "$DRG_CACHE" || ! -f "$RPC_CACHE" ]] && { echo "false"; return; }
    
    # Get DRG ID for this VCN
    local drg_id
    drg_id=$(lookup_cache "$DRG_CACHE" "$vcn_id" 2)
    [[ -z "$drg_id" || "$drg_id" == "N/A" ]] && { echo "false"; return; }
    
    # Check if this DRG has an RPC
    if grep "^${drg_id}|" "$RPC_CACHE" 2>/dev/null | grep -qv "|TERMINATED|"; then
        echo "true"
    else
        echo "false"
    fi
}

# Check if VCN has Route Tables with rules
has_route_table() {
    local vcn_id="$1"
    
    [[ ! -f "$RT_CACHE" ]] && { echo "false"; return; }
    
    # Check for route tables with at least one rule
    local found="false"
    while IFS='|' read -r _ vid _ state count _; do
        if [[ "$vid" == "$vcn_id" && "$state" == "AVAILABLE" && "$count" -gt 0 ]]; then
            found="true"
            break
        fi
    done < "$RT_CACHE"
    echo "$found"
}

# Get route table name by ID
get_route_table_name() {
    local rt_id="$1"
    
    [[ ! -f "$RT_CACHE" ]] && { echo "N/A"; return; }
    [[ -z "$rt_id" || "$rt_id" == "N/A" ]] && { echo "N/A"; return; }
    
    local name
    name=$(lookup_cache "$RT_CACHE" "$rt_id" 3)
    echo "${name:-N/A}"
}

# Get route table rule count by ID
get_route_table_rule_count() {
    local rt_id="$1"
    
    [[ ! -f "$RT_CACHE" ]] && { echo "0"; return; }
    [[ -z "$rt_id" || "$rt_id" == "N/A" ]] && { echo "0"; return; }
    
    local count
    count=$(lookup_cache "$RT_CACHE" "$rt_id" 5)
    [[ "$count" == "N/A" ]] && count="0"
    echo "${count:-0}"
}

# Get security list name by ID (SL_CACHE format: SL_ID|VCN_ID|DISPLAY_NAME|STATE|INGRESS_COUNT|EGRESS_COUNT)
get_security_list_name() {
    local sl_id="$1"
    
    [[ ! -f "$SL_CACHE" ]] && { echo ""; return; }
    [[ -z "$sl_id" || "$sl_id" == "N/A" ]] && { echo ""; return; }
    
    local name
    name=$(lookup_cache "$SL_CACHE" "$sl_id" 3)
    [[ "$name" == "N/A" ]] && name=""
    echo "${name:-}"
}

# Get NSG ingress/egress counts
get_nsg_rule_counts() {
    local nsg_id="$1"
    
    [[ -z "$nsg_id" ]] && { echo "0|0"; return; }
    [[ ! -f "$NSG_RULES_CACHE" ]] && { echo "0|0"; return; }
    
    local line
    line=$(_cache_line "$NSG_RULES_CACHE" "$nsg_id")
    
    if [[ -n "$line" ]]; then
        local ingress egress
        ingress=$(echo "$line" | cut -d'|' -f2)
        egress=$(echo "$line" | cut -d'|' -f3)
        echo "${ingress:-0}|${egress:-0}"
    else
        echo "0|0"
    fi
}

# Find matching shortname for a resource name
get_shortname_match() {
    local name="$1"
    local name_lower
    name_lower=$(echo "$name" | tr '[:upper:]' '[:lower:]')
    
    local shortname
    for shortname in "${NETWORK_SHORTNAMES[@]}"; do
        if [[ "$name_lower" == *"$shortname"* ]]; then
            echo "$shortname"
            return 0
        fi
    done
    echo ""
}

# Display network resources grouped by shortname
display_network_resources() {
    local compartment_id="$1"
    local vcn_ocid="$2"
    local vcn_name="${3:-N/A}"
    
    [[ "$vcn_ocid" == "N/A" || -z "$vcn_ocid" ]] && return 1
    
    # Fetch/refresh caches
    fetch_network_resources "$compartment_id" "$vcn_ocid"
    fetch_all_network_gateways "$compartment_id" "$vcn_ocid" "${NETWORK_COMPARTMENT_ID:-}"
    
    # Build subnet OCID → PE name lookup from OS PE cache
    declare -A PE_SUBNET_MAP
    if [[ -f "$OS_PE_CACHE" ]]; then
        while IFS='|' read -r _pe_name _pe_ns _pe_state _pe_prefix _pe_subnet _pe_ip _pe_ocid _pe_nsgs _pe_comp _pe_ts; do
            [[ "$_pe_name" =~ ^#.*$ ]] && continue
            [[ -z "$_pe_name" || -z "$_pe_subnet" || "$_pe_subnet" == "N/A" ]] && continue
            PE_SUBNET_MAP["$_pe_subnet"]="$_pe_name"
        done < "$OS_PE_CACHE"
    fi
    
    [[ ! -f "$NETWORK_RESOURCES_CACHE" ]] && return 1
    
    if [[ "${_OVERVIEW_SKIP_CACHE:-0}" -ne 1 ]]; then
        echo -n -e "${GRAY}Network Resources: ${NC}"
        _CACHE_PREFIX_WIDTH=20 _display_cache_info \
            "${NETWORK_RESOURCES_CACHE}|Subnets|SUBNET" \
            "${NETWORK_RESOURCES_CACHE}|NSGs|NSG" \
            "${RT_CACHE}|Routes" \
            "${IGW_CACHE}|IGW" \
            "${NAT_CACHE}|NAT" \
            "${SGW_CACHE}|SGW" \
            "${DRG_LIST_CACHE}|DRG" \
            "${DRG_CACHE}|DRG Att" \
            "${OS_PE_CACHE}|OS PEs"
    fi
    
    # Build gateway indicators for VCN
    local has_igw has_sgw has_nat has_drg has_lpg has_rpc has_rt
    has_igw=$(has_internet_gateway "$vcn_ocid" 2>/dev/null) || has_igw="false"
    has_sgw=$(has_service_gateway "$vcn_ocid" 2>/dev/null) || has_sgw="false"
    has_nat=$(has_nat_gateway "$vcn_ocid" 2>/dev/null) || has_nat="false"
    has_drg=$(has_drg_attachment "$vcn_ocid" 2>/dev/null) || has_drg="false"
    has_lpg=$(has_local_peering_gateway "$vcn_ocid" 2>/dev/null) || has_lpg="false"
    has_rpc=$(has_remote_peering_connection "$vcn_ocid" 2>/dev/null) || has_rpc="false"
    has_rt=$(has_route_table "$vcn_ocid" 2>/dev/null) || has_rt="false"
    
    local igw_box sgw_box nat_box drg_box lpg_box rpc_box rt_box
    [[ "$has_igw" == "true" ]] && igw_box="${GREEN}[X]${NC}" || igw_box="${WHITE}[ ]${NC}"
    [[ "$has_sgw" == "true" ]] && sgw_box="${GREEN}[X]${NC}" || sgw_box="${WHITE}[ ]${NC}"
    [[ "$has_nat" == "true" ]] && nat_box="${GREEN}[X]${NC}" || nat_box="${WHITE}[ ]${NC}"
    [[ "$has_drg" == "true" ]] && drg_box="${GREEN}[X]${NC}" || drg_box="${WHITE}[ ]${NC}"
    [[ "$has_lpg" == "true" ]] && lpg_box="${GREEN}[X]${NC}" || lpg_box="${WHITE}[ ]${NC}"
    [[ "$has_rpc" == "true" ]] && rpc_box="${GREEN}[X]${NC}" || rpc_box="${WHITE}[ ]${NC}"
    [[ "$has_rt" == "true" ]] && rt_box="${GREEN}[X]${NC}" || rt_box="${WHITE}[ ]${NC}"
    
    local gateway_indicators="IGW:${igw_box} SGW:${sgw_box} NAT:${nat_box} DRG:${drg_box} LPG:${lpg_box} RPC:${rpc_box} RT:${rt_box}"
    
    # Display VCN line with gateway indicators
    echo -e "${BOLD}${MAGENTA}VCN:${NC} ${GREEN}${vcn_name}${NC} ${WHITE}[${NC}${gateway_indicators}${WHITE}]${NC} ${WHITE}(${YELLOW}${vcn_ocid}${WHITE})${NC}"
    echo ""
    
    # Build arrays of subnets and NSGs
    declare -A subnets_by_shortname
    declare -A nsgs_by_shortname
    declare -a unmatched_subnets
    declare -a unmatched_nsgs
    declare -a subnet_shortnames
    
    # Read subnets (now with route-table-id, security-list-ids, and dns-label)
    while IFS='|' read -r type name cidr access state ocid rt_ocid sl_ids dns_label _; do
        [[ "$type" != "SUBNET" ]] && continue
        local shortname
        shortname=$(get_shortname_match "$name")
        if [[ -n "$shortname" ]]; then
            subnets_by_shortname[$shortname]="${name}|${cidr}|${access}|${ocid}|${rt_ocid}|${sl_ids}|${dns_label}"
            subnet_shortnames+=("$shortname")
        else
            unmatched_subnets+=("${name}|${cidr}|${access}|${ocid}|${rt_ocid}|${sl_ids}|${dns_label}")
        fi
    done < <(grep "^SUBNET|" "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
    
    # Read NSGs
    while IFS='|' read -r type name _ state ocid _; do
        [[ "$type" != "NSG" ]] && continue
        local shortname
        shortname=$(get_shortname_match "$name")
        if [[ -n "$shortname" ]]; then
            if [[ -n "${nsgs_by_shortname[$shortname]:-}" ]]; then
                nsgs_by_shortname[$shortname]="${nsgs_by_shortname[$shortname]}#${name}|${ocid}"
            else
                nsgs_by_shortname[$shortname]="${name}|${ocid}"
            fi
        else
            unmatched_nsgs+=("${name}|${ocid}")
        fi
    done < <(grep "^NSG|" "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
    
    # Display subnets with their matching NSGs
    local shortname
    for shortname in "${subnet_shortnames[@]}"; do
        local subnet_info="${subnets_by_shortname[$shortname]}"
        [[ -z "$subnet_info" ]] && continue
        
        local name cidr access ocid rt_ocid sl_ids dns_label
        IFS='|' read -r name cidr access ocid rt_ocid sl_ids dns_label _ <<< "$subnet_info"
        
        local access_color
        [[ "$access" == "Private" ]] && access_color="$RED" || access_color="$LIGHT_GREEN"
        
        # Get route table info
        local rt_name rt_rules rt_display
        rt_name=$(get_route_table_name "$rt_ocid")
        rt_rules=$(get_route_table_rule_count "$rt_ocid")
        rt_display="${rt_name} (${rt_rules})"
        
        # DNS label display with fixed width (one space after colon)
        local dns_display
        if [[ -n "$dns_label" ]]; then
            dns_display=$(printf "DNS: %-12s" "$dns_label")
        else
            dns_display=$(printf "%-17s" "")
        fi
        
        # Get security list names
        local sl_display=""
        if [[ -n "$sl_ids" ]]; then
            local sl_names=""
            IFS=',' read -ra sl_array <<< "$sl_ids"
            for sl_id in "${sl_array[@]}"; do
                [[ -z "$sl_id" ]] && continue
                local sl_name
                sl_name=$(get_security_list_name "$sl_id")
                if [[ -n "$sl_name" ]]; then
                    [[ -n "$sl_names" ]] && sl_names+=", "
                    sl_names+="$sl_name"
                fi
            done
            [[ -n "$sl_names" ]] && sl_display="${sl_names}"
        fi
        
        # Subnet line with route table and DNS label
        # OS PE indicator - check if this subnet has a private endpoint
        local pe_indicator=""
        if [[ -n "${PE_SUBNET_MAP[$ocid]:-}" ]]; then
            pe_indicator="OS PE ${GREEN}[X]${NC} "
        fi
        
        printf "  ${BOLD}${WHITE}Subnet:${NC} ${GREEN}%-30s${NC} ${WHITE}[${CYAN}%-15s${WHITE}]${NC} ${WHITE}[${access_color}%-7s${WHITE}]${NC} ${MAGENTA}%-17s${NC} %b${WHITE}RT:${NC} ${CYAN}%-25s${NC} ${WHITE}(${YELLOW}%s${WHITE})${NC}\n" \
            "$name" "$cidr" "$access" "$dns_display" "$pe_indicator" "$rt_display" "$ocid"
        
        # Count total items for tree display (SL + NSGs)
        local nsg_list="${nsgs_by_shortname[$shortname]:-}"
        local has_sl=false
        local has_nsg=false
        [[ -n "$sl_display" ]] && has_sl=true
        [[ -n "$nsg_list" ]] && has_nsg=true
        
        # Display security lists if any
        if [[ "$has_sl" == "true" ]]; then
            local sl_prefix="└─"
            [[ "$has_nsg" == "true" ]] && sl_prefix="├─"
            printf "          ${MAGENTA}${sl_prefix} SL:${NC}  ${WHITE}%s${NC}\n" "$sl_display"
        fi
        
        # Display matching NSGs
        if [[ "$has_nsg" == "true" ]]; then
            local nsg_entries
            IFS='#' read -ra nsg_entries <<< "$nsg_list"
            local nsg_count=${#nsg_entries[@]}
            local i=0
            for nsg_entry in "${nsg_entries[@]}"; do
                ((i++))
                local nsg_name nsg_ocid
                IFS='|' read -r nsg_name nsg_ocid <<< "$nsg_entry"
                
                # Get NSG rule counts
                local rule_counts ingress egress rules_display
                rule_counts=$(get_nsg_rule_counts "$nsg_ocid")
                ingress=$(echo "$rule_counts" | cut -d'|' -f1)
                egress=$(echo "$rule_counts" | cut -d'|' -f2)
                rules_display="In:${ingress} Out:${egress}"
                
                local prefix="├─"
                [[ $i -eq $nsg_count ]] && prefix="└─"
                
                # NSG line with rule counts - aligned with subnet OCID
                printf "          ${BLUE}${prefix} NSG:${NC} ${WHITE}%-30s${NC} ${CYAN}%-15s${NC} %-51s ${WHITE}(${YELLOW}%s${WHITE})${NC}\n" \
                    "$nsg_name" "$rules_display" "" "$nsg_ocid"
            done
        fi
        echo ""
    done
    
    # Display unmatched subnets
    if [[ ${#unmatched_subnets[@]} -gt 0 ]]; then
        for subnet_entry in "${unmatched_subnets[@]}"; do
            local name cidr access ocid rt_ocid sl_ids dns_label
            IFS='|' read -r name cidr access ocid rt_ocid sl_ids dns_label _ <<< "$subnet_entry"
            
            local access_color
            [[ "$access" == "Private" ]] && access_color="$RED" || access_color="$LIGHT_GREEN"
            
            # Get route table info
            local rt_name rt_rules rt_display
            rt_name=$(get_route_table_name "$rt_ocid")
            rt_rules=$(get_route_table_rule_count "$rt_ocid")
            rt_display="${rt_name} (${rt_rules})"
            
            # DNS label display with fixed width (one space after colon)
            local dns_display
            if [[ -n "$dns_label" ]]; then
                dns_display=$(printf "DNS: %-12s" "$dns_label")
            else
                dns_display=$(printf "%-17s" "")
            fi
            
            # Get security list names
            local sl_display=""
            if [[ -n "$sl_ids" ]]; then
                local sl_names=""
                IFS=',' read -ra sl_array <<< "$sl_ids"
                for sl_id in "${sl_array[@]}"; do
                    [[ -z "$sl_id" ]] && continue
                    local sl_name
                    sl_name=$(get_security_list_name "$sl_id")
                    if [[ -n "$sl_name" ]]; then
                        [[ -n "$sl_names" ]] && sl_names+=", "
                        sl_names+="$sl_name"
                    fi
                done
                [[ -n "$sl_names" ]] && sl_display="${sl_names}"
            fi
            
            # OS PE indicator - check if this subnet has a private endpoint
            local pe_indicator=""
            if [[ -n "${PE_SUBNET_MAP[$ocid]:-}" ]]; then
                pe_indicator="OS PE ${GREEN}[X]${NC} "
            fi
            
            printf "  ${BOLD}${WHITE}Subnet:${NC} ${GREEN}%-30s${NC} ${WHITE}[${CYAN}%-15s${WHITE}]${NC} ${WHITE}[${access_color}%-7s${WHITE}]${NC} ${MAGENTA}%-17s${NC} %b${WHITE}RT:${NC} ${CYAN}%-25s${NC} ${WHITE}(${YELLOW}%s${WHITE})${NC}\n" \
                "$name" "$cidr" "$access" "$dns_display" "$pe_indicator" "$rt_display" "$ocid"
            
            # Display security lists if any
            if [[ -n "$sl_display" ]]; then
                printf "          ${MAGENTA}└─ SL:${NC}  ${WHITE}%s${NC}\n" "$sl_display"
            fi
            echo ""
        done
    fi
    
    # Display unmatched NSGs if any
    if [[ ${#unmatched_nsgs[@]} -gt 0 ]]; then
        _ui_subheader "Unmatched NSGs"
        local i=0
        local total=${#unmatched_nsgs[@]}
        for nsg_entry in "${unmatched_nsgs[@]}"; do
            ((i++))
            local nsg_name nsg_ocid
            IFS='|' read -r nsg_name nsg_ocid <<< "$nsg_entry"
            
            # Get NSG rule counts
            local rule_counts ingress egress rules_display
            rule_counts=$(get_nsg_rule_counts "$nsg_ocid")
            ingress=$(echo "$rule_counts" | cut -d'|' -f1)
            egress=$(echo "$rule_counts" | cut -d'|' -f2)
            rules_display="In:${ingress} Out:${egress}"
            
            local prefix="├─"
            [[ $i -eq $total ]] && prefix="└─"
            
            # NSG line with rule counts - aligned with subnet OCID
            printf "          ${BLUE}${prefix} NSG:${NC} ${WHITE}%-30s${NC} ${CYAN}%-15s${NC} %-51s ${WHITE}(${YELLOW}%s${WHITE})${NC}\n" \
                "$nsg_name" "$rules_display" "" "$nsg_ocid"
        done
        echo ""
    fi
}

# Build announcement lookup tables from cached data
build_announcement_lookup() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    # Reset arrays
    INSTANCE_ANNOUNCEMENTS=()
    GPU_MEM_CLUSTER_ANNOUNCEMENTS=()
    
    # Refresh cache if needed
    if ! is_cache_fresh "$ANNOUNCEMENTS_LIST_CACHE"; then
        log_info "Fetching announcements from OCI..."
        
        if ! timeout 60 oci announce announcements list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --lifecycle-state ACTIVE \
                --output json \
                --all > "$ANNOUNCEMENTS_LIST_CACHE" 2>/dev/null; then
            log_warn "Failed to fetch announcements (timeout or error)"
            _ui_policy_hint "read announcements in tenancy"
            rm -f "$ANNOUNCEMENTS_LIST_CACHE"
            return 1
        fi
        
        # Fetch details for each announcement in parallel
        local announcement_ids
        announcement_ids=$(jq -r '.data.items[].id' "$ANNOUNCEMENTS_LIST_CACHE" 2>/dev/null)
        
        local ann_id
        local _ann_pids=()
        local _ann_batch=0
        while IFS= read -r ann_id; do
            [[ -z "$ann_id" ]] && continue
            local detail_file="${CACHE_DIR}/ann_${ann_id##*.}.json"
            if [[ ! -f "$detail_file" || ! -s "$detail_file" ]]; then
                oci announce announcements get --announcement-id "$ann_id" --region "$region" --output json > "$detail_file" 2>/dev/null &
                _ann_pids+=($!)
                ((_ann_batch++))
                if [[ $_ann_batch -ge $OCI_MAX_PARALLEL ]]; then
                    wait "${_ann_pids[@]}" 2>/dev/null
                    _ann_pids=()
                    _ann_batch=0
                fi
            fi
        done <<< "$announcement_ids"
        [[ ${#_ann_pids[@]} -gt 0 ]] && wait "${_ann_pids[@]}"
    fi
    
    # Process cached announcement details (only ann_*.json files)
    local detail_file
    for detail_file in "$CACHE_DIR"/ann_*.json; do
        [[ ! -f "$detail_file" ]] && continue
        
        # Validate JSON has announcement data
        if ! jq -e '.data.id' "$detail_file" > /dev/null 2>&1; then
            continue
        fi
        
        # Only process ACTIVE announcements
        local lifecycle_state
        lifecycle_state=$(jq -r '.data."lifecycle-state" // "N/A"' "$detail_file")
        [[ "$lifecycle_state" != "ACTIVE" ]] && continue
        
        local reference_ticket
        reference_ticket=$(jq -r '.data."reference-ticket-number" // "N/A"' "$detail_file")
        local short_ticket="${reference_ticket:0:8}"
        
        # Extract affected resources count
        local resource_count
        resource_count=$(jq '.data."affected-resources" | length' "$detail_file" 2>/dev/null) || resource_count=0
        
        local i
        for ((i=0; i<resource_count; i++)); do
            # Get instance/resource ID
            local resource_id
            resource_id=$(jq -r ".data.\"affected-resources\"[$i] | 
                if .properties then
                    (.properties[] | select(.name == \"resourceId\" or .name == \"instanceId\") | .value) // null
                else
                    (.\"resource-id\" // .\"instance-id\" // null)
                end" "$detail_file" 2>/dev/null)
            
            # Get GPU memory cluster
            local gpu_mem_cluster
            gpu_mem_cluster=$(jq -r ".data.\"affected-resources\"[$i] |
                if .properties then
                    (.properties[] | select(.name == \"gpuMemoryCluster\") | .value) // null
                else
                    null
                end" "$detail_file" 2>/dev/null)
            
            # Add to instance lookup (avoid duplicates)
            if [[ -n "$resource_id" && "$resource_id" != "null" ]]; then
                if [[ -z "${INSTANCE_ANNOUNCEMENTS[$resource_id]:-}" ]]; then
                    INSTANCE_ANNOUNCEMENTS[$resource_id]="$short_ticket"
                elif [[ ! "${INSTANCE_ANNOUNCEMENTS[$resource_id]}" =~ $short_ticket ]]; then
                    INSTANCE_ANNOUNCEMENTS[$resource_id]="${INSTANCE_ANNOUNCEMENTS[$resource_id]},$short_ticket"
                fi
            fi
            
            # Add to GPU memory cluster lookup (avoid duplicates)
            if [[ -n "$gpu_mem_cluster" && "$gpu_mem_cluster" != "null" ]]; then
                if [[ -z "${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]:-}" ]]; then
                    GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]="$short_ticket"
                elif [[ ! "${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]}" =~ $short_ticket ]]; then
                    GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]="${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]},$short_ticket"
                fi
            fi
        done
    done
}

#===============================================================================
# LOOKUP FUNCTIONS
#===============================================================================

# Get cluster state from cache
# Args: $1 = cluster OCID
get_cluster_state() {
    lookup_cache "$CLUSTER_CACHE" "$1" 3
}

# Get instance configuration ID from cluster OCID
# Args: $1 = cluster OCID
get_instance_config_from_cluster() {
    lookup_cache "$CLUSTER_CACHE" "$1" 5
}

# Get node state from cache
# Args: $1 = instance OCID (provider ID)
get_node_state_cached() {
    lookup_cache "$NODE_STATE_CACHE" "$1" 2
}

# Get capacity topology state for an instance (kept for c5 backward compat)
# Args: $1 = instance OCID
get_capacity_topology_state() {
    lookup_cache "$CAPACITY_TOPOLOGY_CACHE" "$1" 3
}

# Get compute host health for an instance from COMPUTE_HOST_CACHE
# Instance OCID is field 8, health is field 3 — cannot use lookup_cache (field 1 mismatch)
# Args: $1 = instance OCID
get_compute_host_health() {
    [[ ! -f "$COMPUTE_HOST_CACHE" ]] && { echo "N/A"; return 1; }
    local _line
    _line=$(grep -F "$1" "$COMPUTE_HOST_CACHE" 2>/dev/null | head -1)
    if [[ -n "$_line" ]]; then
        echo "$_line" | cut -d'|' -f3
    else
        echo "N/A"; return 1
    fi
}

# Get full compute host record for an instance from COMPUTE_HOST_CACHE
# Args: $1 = instance OCID
# Returns: full pipe-delimited line (all 19 fields), or empty string if not found
get_compute_host_record() {
    [[ ! -f "$COMPUTE_HOST_CACHE" ]] && return 1
    grep -F "$1" "$COMPUTE_HOST_CACHE" 2>/dev/null | head -1
}

# Get fabric details from cluster OCID
# Args: $1 = cluster OCID
# Returns: DisplayName|Last5Chars|FabricOCID|State|AvailableHosts|TotalHosts
get_fabric_from_cluster() {
    local cluster_ocid="$1"
    local default="N/A|N/A|N/A|N/A|0|0"
    
    [[ ! -f "$FABRIC_CACHE" || ! -f "$CLUSTER_CACHE" ]] && { echo "$default"; return 1; }
    
    local fabric_suffix
    fabric_suffix=$(lookup_cache "$CLUSTER_CACHE" "$cluster_ocid" 4)
    [[ -z "$fabric_suffix" || "$fabric_suffix" == "N/A" ]] && { echo "$default"; return 1; }
    
    local fabric_line
    fabric_line=$(grep -v '^#' "$FABRIC_CACHE" | grep "|${fabric_suffix}|" | head -n1)
    echo "${fabric_line:-$default}"
}

# Get announcements for a resource (instance and/or GPU memory cluster)
# Args: $1 = instance OCID, $2 = GPU memory cluster OCID
# Returns: comma-separated ticket numbers or "-" if none
get_resource_announcements() {
    local instance_ocid="$1"
    local gpu_mem_cluster="$2"
    local result=""
    
    # Check instance-level announcements
    if [[ -n "$instance_ocid" && -n "${INSTANCE_ANNOUNCEMENTS[$instance_ocid]:-}" ]]; then
        result="${INSTANCE_ANNOUNCEMENTS[$instance_ocid]}"
    fi
    
    # Check GPU memory cluster level announcements
    if [[ -n "$gpu_mem_cluster" && "$gpu_mem_cluster" != "N/A" && -n "${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]:-}" ]]; then
        if [[ -z "$result" ]]; then
            result="${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]}"
        else
            # Append unique tickets only
            local ticket
            for ticket in ${GPU_MEM_CLUSTER_ANNOUNCEMENTS[$gpu_mem_cluster]//,/ }; do
                [[ ! "$result" =~ $ticket ]] && result="${result},${ticket}"
            done
        fi
    fi
    
    echo "${result:--}"
}

#===============================================================================
# API REFRESH STATUS DISPLAY
#===============================================================================

# Display API data refresh status from capacity topology time-updated cache
# Converts UTC to server local time, shows last refresh + next expected refresh
# Used by c5 (Capacity Topology) and c10 (Compute Hosts)
_display_api_refresh_status() {
    local _label="${1:-API data}"
    local _refresh_interval=15   # minutes

    # Resolve the most recent time-updated (UTC) from available sources:
    #   1. Dedicated time cache (topology-level, written during fetch)
    #   2. Capacity topology text cache field 10 (per-host TimeUpdated)
    #   3. Compute host text cache field 18 (per-host TimeUpdated)
    local _utc_time=""
    if [[ -f "$CAPACITY_TOPO_TIME_CACHE" ]]; then
        _utc_time=$(cat "$CAPACITY_TOPO_TIME_CACHE" 2>/dev/null)
    fi
    if [[ -z "$_utc_time" && -f "$CAPACITY_TOPOLOGY_CACHE" ]]; then
        _utc_time=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" 2>/dev/null | cut -d'|' -f10 | sort -r | head -1)
        # Persist for future use
        [[ -n "$_utc_time" && "$_utc_time" != "N/A" ]] && echo "$_utc_time" > "$CAPACITY_TOPO_TIME_CACHE"
    fi
    if [[ -z "$_utc_time" && -f "$COMPUTE_HOST_CACHE" ]]; then
        _utc_time=$(grep -v "^#" "$COMPUTE_HOST_CACHE" 2>/dev/null | cut -d'|' -f18 | sort -r | head -1)
        [[ -n "$_utc_time" && "$_utc_time" != "N/A" ]] && echo "$_utc_time" > "$CAPACITY_TOPO_TIME_CACHE"
    fi

    if [[ -z "$_utc_time" || "$_utc_time" == "N/A" ]]; then
        echo -e "  ${GRAY}${_label} refreshes every ${_refresh_interval} minutes.${NC}"
        return
    fi

    # Convert UTC time-updated to epoch seconds
    local _utc_epoch _now_epoch _local_time _next_epoch _next_local
    _utc_epoch=$(date -d "$_utc_time" +%s 2>/dev/null)
    if [[ -z "$_utc_epoch" ]]; then
        echo -e "  ${GRAY}${_label} refreshes every ${_refresh_interval} minutes.${NC}"
        return
    fi

    _now_epoch=$(date +%s)
    _local_time=$(date -d "$_utc_time" '+%Y-%m-%d %H:%M:%S %Z' 2>/dev/null)
    _next_epoch=$((_utc_epoch + _refresh_interval * 60))
    _next_local=$(date -d "@$_next_epoch" '+%Y-%m-%d %H:%M:%S %Z' 2>/dev/null)

    # Time since last refresh
    local _diff_sec=$((_now_epoch - _utc_epoch))
    local _diff_min=$((_diff_sec / 60))

    # Time until next refresh
    local _remain_sec=$((_next_epoch - _now_epoch))
    local _remain_min=$((_remain_sec / 60))

    # Color-code: green=just refreshed (<5m), yellow=approaching (5-14m), cyan=overdue/imminent
    local _last_color="$GREEN" _next_color="$GREEN"
    if [[ $_diff_min -ge 15 ]]; then
        _last_color="$YELLOW"
        _next_color="$CYAN"
    elif [[ $_diff_min -ge 10 ]]; then
        _last_color="$YELLOW"
        _next_color="$YELLOW"
    fi

    if [[ $_remain_sec -le 0 ]]; then
        echo -e "  ${GRAY}${_label} │ Last: ${_last_color}${_local_time}${GRAY} (${_diff_min}m ago) │ Next: ${CYAN}expected any moment${GRAY} │ Refreshes every ${_refresh_interval}m${NC}"
    else
        echo -e "  ${GRAY}${_label} │ Last: ${_last_color}${_local_time}${GRAY} (${_diff_min}m ago) │ Next: ${_next_color}${_next_local}${GRAY} (~${_remain_min}m) │ Refreshes every ${_refresh_interval}m${NC}"
    fi
}

#===============================================================================
# COLOR HELPER FUNCTIONS
#===============================================================================

# Get color for Kubernetes node state
color_node_state() {
    case "$1" in
        Ready)    echo "$GREEN" ;;
        NotReady) echo "$RED" ;;
        -)        echo "$GRAY" ;;
        *)        echo "$YELLOW" ;;
    esac
}

# Get color for OCI instance lifecycle state (comprehensive)
color_oci_state() {
    case "$1" in
        RUNNING|AVAILABLE)              echo "$GREEN" ;;
        STOPPED|TERMINATED|FAILED)      echo "$RED" ;;
        STARTING|STOPPING|MOVING)       echo "$YELLOW" ;;
        PROVISIONING|CREATING_IMAGE)    echo "$CYAN" ;;
        *)                              echo "$YELLOW" ;;
    esac
}

# Get color for capacity topology state (kept for c5 backward compat)
color_cap_topo_state() {
    case "$1" in
        AVAILABLE) echo "$GREEN" ;;
        DEGRADED)  echo "$RED" ;;
        N/A|-)     echo "$GRAY" ;;
        *)         echo "$YELLOW" ;;
    esac
}

# Get color for compute host health state
color_host_health() {
    case "$1" in
        HEALTHY)                     echo "$GREEN" ;;
        DEGRADED|IMPAIRED)           echo "$YELLOW" ;;
        UNHEALTHY|FAILED)            echo "$RED" ;;
        N/A|-|"")                    echo "$GRAY" ;;
        *)                           echo "$YELLOW" ;;
    esac
}

# Get color for cluster state
color_cluster_state() {
    case "$1" in
        ACTIVE) echo "$GREEN" ;;
        CREATING) echo "$CYAN" ;;
        UPDATING|SCALING) echo "$YELLOW" ;;
        INACTIVE|FAILED|DELETED|DELETING) echo "$RED" ;;
        *)      echo "$WHITE" ;;
    esac
}

# Get color for generic OCI resource lifecycle state (FSS, PE, RM, WR, images, etc.)
color_resource_state() {
    case "$1" in
        ACTIVE|AVAILABLE|SUCCEEDED|COMPLETED|RUNNING)                          echo "$GREEN" ;;
        CREATING|UPDATING|ACCEPTED|IN_PROGRESS|PROVISIONING|IMPORTING|EXPORTING|STARTING|MOVING) echo "$YELLOW" ;;
        DELETING|DELETED|FAILED|INACTIVE|DISABLED|TERMINATED|TERMINATING|STOPPED|STOPPING) echo "$RED" ;;
        *)                                                                   echo "$GRAY" ;;
    esac
}

# Get color for fabric state
color_fabric_state() {
    case "$1" in
        AVAILABLE) echo "$GREEN" ;;
        *)         echo "$RED" ;;
    esac
}

# Get color for announcement status
color_announcement() {
    [[ "$1" == "-" ]] && echo "$GREEN" || echo "$RED"
}

# Get color for firmware update state
color_firmware_state() {
    case "$1" in
        UP_TO_DATE|COMPLETED) echo "$GREEN" ;;
        IN_PROGRESS|UPDATING) echo "$YELLOW" ;;
        FAILED|ERROR) echo "$RED" ;;
        *) echo "$WHITE" ;;
    esac
}

#===============================================================================
# TABLE FORMATTING HELPERS
#===============================================================================

# Print a horizontal separator line
# Header/table separator line — reusable across every menu and submenu
# Usage: print_separator 80            → blue ━ line, width 80
#        print_separator 120 "$GRAY"   → gray ━ line, width 120
#        print_separator 80 "${BOLD}${YELLOW}"  → bold yellow ━ line
print_separator() {
    local width="${1:-255}"
    local color="${2:-$BLUE}"
    echo -e "${color}$(printf '━%.0s' $(seq 1 "$width"))${NC}"
}

#================================================================================
# UI CONSISTENCY HELPERS - Shared rendering for all --manage submenus
# Provides uniform banner, environment info, section headers, prompts, and pauses
#================================================================================
readonly UI_WIDTH=177

# Menu banner - centered title with consistent width and color (internal: use _ui_menu_header)
# Usage: _ui_menu_header "TITLE" --cmd "..." --env --cache "file|label"
#        _ui_menu_header "GPU MANAGEMENT" --color "$MAGENTA" --env
_ui_banner() {
    local title="$1"
    local color="${2:-$CYAN}"
    local line
    line=$(printf '═%.0s' $(seq 1 $UI_WIDTH))
    local pad=$(( (UI_WIDTH - ${#title}) / 2 ))
    [[ $pad -lt 0 ]] && pad=0
    echo ""
    echo -e "${BOLD}${color}${line}${NC}"
    printf "${BOLD}${color}%*s%s${NC}\n" "$pad" "" "$title"
    echo -e "${BOLD}${color}${line}${NC}"
}

# Detail banner — sub-view banner with dynamic resource name
# Lighter than _ui_banner, used for drill-down detail views
# Usage: _ui_detail_banner "Stack State" "$stack_name"
#        _ui_detail_banner "Pod Details for Node" "$node_name" "$CYAN"
_ui_detail_banner() {
    local label="$1"
    local resource_name="${2:-}"
    local color="${3:-${BOLD}${WHITE}}"
    if [[ -n "$resource_name" ]]; then
        echo -e "${color}═══ ${label}: ${CYAN}${resource_name}${NC} ${color}═══${NC}"
    else
        echo -e "${color}═══ ${label} ═══${NC}"
    fi
}

# Field comparison row — compare two values and display same/different
# Returns 0 if same, 1 if different (allows: _ui_compare_field ... || has_diff=true)
# Usage: _ui_compare_field "Shape" "$val1" "Config A" "$val2" "Config B"
#        _ui_compare_field "Image" "$img1" "New" "$img2" "Existing" --detail "$id1" "$id2"
_ui_compare_field() {
    local field_name="$1"
    local val1="$2"
    local name1="$3"
    local val2="$4"
    local name2="$5"
    shift 5
    local show_detail=false
    local detail1="" detail2=""
    if [[ "${1:-}" == "--detail" ]]; then
        show_detail=true
        detail1="${2:-}"
        detail2="${3:-}"
    fi
    
    echo ""
    _ui_subheader "$field_name" 0
    if [[ "$val1" == "$val2" ]]; then
        if [[ "$show_detail" == "true" && -n "$detail1" ]]; then
            echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}$val1${NC} (${YELLOW}$detail1${NC})"
        else
            echo -e "  ${GREEN}✓ Same:${NC} $val1"
        fi
        return 0
    else
        echo -e "  ${RED}✗ Different:${NC}"
        if [[ "$show_detail" == "true" ]]; then
            echo -e "    ${GREEN}$name1:${NC} ${WHITE}$val1${NC}"
            [[ -n "$detail1" ]] && echo -e "      ${YELLOW}$detail1${NC}"
            echo -e "    ${BLUE}$name2:${NC} ${WHITE}$val2${NC}"
            [[ -n "$detail2" ]] && echo -e "      ${YELLOW}$detail2${NC}"
        else
            echo -e "    ${GREEN}$name1:${NC} $val1"
            echo -e "    ${BLUE}$name2:${NC} $val2"
        fi
        return 1
    fi
}
# Enforces consistent layout across every --manage menu.
# See "NEW MENU / SUBMENU CHECKLIST" in script header for full requirements.
#
#   ┌─────────────────────────────────────────────────────┐
#   │  ═══════════ BANNER TITLE ═══════════               │  _ui_banner
#   │  Main > Compute > Instances                         │  _ui_breadcrumb
#   │  Cache: Items (8, 3m)  Other (5, 67m) │ TTL: 5m    │  _display_cache_info
#   │  Focus: (variables.sh configured │ manually selected │ derived)
#   │    Tenancy: name [ocid]                             │  _ui_env_info
#   │    Region │ AD │ Compartment │ OKE │ VCN            │
#   │    OCI CLI │ kubectl │ helm                         │
#   │  Commands executed during fetch:                    │  _ui_oci_cmd
#   │  oci network subnet list --compartment-id $COMP_ID  │
#   └─────────────────────────────────────────────────────┘
#   ... discovery (_step_*) / display / actions            │  caller renders
#
# Usage:
#   _ui_menu_header "TITLE" [OPTIONS] [--cache SPEC...]
#
# Options:
#   --color  COLOR    Banner color (default: $CYAN)
#   --cmd    STRING   OCI CLI command reference (gray)
#   --breadcrumb SEG...  Breadcrumb path segments (e.g., --breadcrumb "Compute" "Instances")
#   --env            Show standard Focus block (Tenancy, Region, AD, Comp, OKE, VCN, Tools)
#   --env    K1 V1 K2 V2 ...  Extra key/value pairs (for view-specific context ONLY;
#                              do NOT duplicate values already in Focus like Tenancy/VCN)
#   --cache  SPEC...  Cache info specs (all remaining args), format: "file|label" or "file|label|filter"
#
# Layout order: Banner → Breadcrumb → Cache → Environment → Commands
#
# Examples:
#   # Full header (navigable menu with data)
#   _ui_menu_header "NETWORK RESOURCES" \
#       --breadcrumb "Network" "Network Resources" \
#       --cmd "oci network subnet list --compartment-id \$COMPARTMENT_ID" \
#       --env \
#       --cache "${RT_CACHE}|Routes" "${SL_CACHE}|SLs"
#
#   # Drill-in detail view (always include --env and --breadcrumb)
#   _ui_menu_header "INSTANCE DETAILS" \
#       --breadcrumb "Compute" "Instances" "Details" \
#       --cmd "oci compute instance get --instance-id \$INSTANCE_OCID" \
#       --env
#
#   # Title only (action/confirmation dialogs — exempt from --env/--breadcrumb)
#   _ui_menu_header "INSTANCE TERMINATION"
#
#   # Custom color with env
#   _ui_menu_header "GPU MANAGEMENT" --color "$MAGENTA" \
#       --breadcrumb "Kubernetes" "GPU Memory Fabric" \
#       --env
#--------------------------------------------------------------------------------
_ui_menu_header() {
    local title="$1"
    shift
    
    local color="$CYAN"
    local cmd=""
    local show_env=0
    local -a env_extras=()
    local -a cache_specs=()
    local -a breadcrumb_segments=()
    local parsing_cache=0
    local parsing_env_extras=0
    local parsing_breadcrumb=0
    
    while [[ $# -gt 0 ]]; do
        if [[ $parsing_cache -eq 1 ]]; then
            cache_specs+=("$1")
            shift
            continue
        fi
        if [[ $parsing_breadcrumb -eq 1 ]]; then
            if [[ "$1" == --* ]]; then
                parsing_breadcrumb=0
            else
                breadcrumb_segments+=("$1")
                shift
                continue
            fi
        fi
        if [[ $parsing_env_extras -eq 1 ]]; then
            if [[ "$1" == --* ]]; then
                local parsing_env_extras=0
            else
                env_extras+=("$1")
                shift
                continue
            fi
        fi
        case "$1" in
            --color)
                shift
                local color="$1"
                ;;
            --cmd)
                shift
                local cmd="$1"
                ;;
            --env)
                local show_env=1
                if [[ $# -gt 1 && "${2:0:2}" != "--" ]]; then
                    parsing_env_extras=1
                fi
                ;;
            --breadcrumb)
                parsing_breadcrumb=1
                ;;
            --cache)
                parsing_cache=1
                ;;
            *)
                if [[ "$1" == *"|"* ]]; then
                    cache_specs+=("$1")
                fi
                ;;
        esac
        shift
    done
    
    # 1. Banner
    _ui_banner "$title" "$color"
    
    # 2. Breadcrumb (if segments provided)
    if [[ ${#breadcrumb_segments[@]} -gt 0 ]]; then
        _ui_breadcrumb "${breadcrumb_segments[@]}"
    fi

    # 3. Cache details (if specs provided) — single line, dim text
    if [[ ${#cache_specs[@]} -gt 0 ]]; then
        echo -n -e "  ${GRAY}Cache: ${NC}"
        _display_cache_info "${cache_specs[@]}"
    fi
    
    # 4. Environment info
    if [[ $show_env -eq 1 ]]; then
        _ui_env_info "${env_extras[@]}"
    fi
    
    # 5. Command reference (always last in header)
    if [[ -n "$cmd" ]]; then
        _ui_oci_cmd "$cmd"
    fi
}

# Truncate an OCID for display: ocid1.subnet.oc1.iad.aaa...abcd → ...abcd
# Usage: _short_ocid "ocid1.subnet.oc1.iad.aaabbbcccddd" → "...cddd"
_short_ocid() {
    local ocid="$1"
    local tail="${2:-6}"
    [[ -z "$ocid" || "$ocid" == "null" || "$ocid" == "N/A" ]] && return
    if [[ ${#ocid} -gt $((tail + 3)) ]]; then
        echo "...${ocid: -$tail}"
    else
        echo "$ocid"
    fi
}

# Quick cache-only name lookup — never makes API calls, returns "" on miss
# Usage: _quick_name "cache_file" "ocid" [field_num]
#   field_num: which pipe-delimited field holds the name (default: 2)
_quick_name() {
    local cache="$1" ocid="$2" field="${3:-2}"
    [[ -z "$ocid" || ! -f "$cache" ]] && return
    awk -F'|' -v id="$ocid" -v f="$field" '$1==id {print $f; exit}' "$cache" 2>/dev/null
}

# Resolve an OCID to "name (short-id)" or just "short-id" if no name found
# Tries cache lookup first, falls back to short OCID. Never calls API.
# Usage: _name_or_id "cache_file" "ocid" [field_num]
_name_or_id() {
    local cache="$1" ocid="$2" field="${3:-2}"
    local name
    name=$(_quick_name "$cache" "$ocid" "$field")
    if [[ -n "$name" ]]; then
        echo "$name"
    else
        _short_ocid "$ocid"
    fi
}

# Environment info block — compact display of current focus configuration
# GREEN = populated from variables.sh, YELLOW = selected at runtime, CYAN = derived
# Line 1 (always):  Tenancy Name [OCID]
# Line 2 (always):  Region │ AD (if set) │ Compartment │ OKE (if set) │ VCN (if set)
# Line 3 (always):  OCI CLI │ kubectl │ helm
# Extra key/value pairs appended: _ui_env_info "Label1" "Value1"
_ui_env_info() {
    local region="${FOCUS_REGION:-$REGION}"
    local comp_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local comp_display
    comp_display=$(_resolve_compartment_path "$comp_id" 2>/dev/null || resolve_compartment_name "$comp_id" 2>/dev/null || echo "$comp_id")

    # Determine source color using FOCUS_*_SOURCE tracking
    # GREEN = variables.sh configured, YELLOW = manually selected at runtime, CYAN = derived
    local region_color="$GREEN"
    [[ "$FOCUS_REGION_SOURCE" == "selected" ]] && region_color="$YELLOW"
    local comp_color="$GREEN"
    [[ "$FOCUS_COMPARTMENT_SOURCE" == "selected" ]] && comp_color="$YELLOW"

    echo -e "  ${BOLD}${WHITE}Focus:${NC} ${GRAY}(${GREEN}variables.sh configured${NC} ${GRAY}│${NC} ${YELLOW}manually selected${NC} ${GRAY}│${NC} ${CYAN}derived${NC}${GRAY})${NC}"

    # ── Line 1: Tenancy (always) ──
    if [[ -n "${TENANCY_ID:-}" ]]; then
        local _tenancy_display="${TENANCY_ID}"
        [[ -n "${_TOOL_TENANCY_NAME:-}" ]] && _tenancy_display="${_TOOL_TENANCY_NAME} ${GRAY}[${NC}${GREEN}${TENANCY_ID}${NC}${GRAY}]${NC}"
        echo -e "    ${CYAN}Tenancy:${NC} ${GREEN}${_tenancy_display}${NC}"
    fi

    # ── Line 2: Region │ AD │ Compartment │ OKE │ VCN ──
    local line2="${CYAN}Region:${NC} ${region_color}${region}${NC}"
    local _ad="${FOCUS_AD:-${AD:-}}"
    if [[ -n "$_ad" ]]; then
        local _ad_color="$GREEN"
        [[ "${FOCUS_AD_SOURCE:-}" == "selected" ]] && _ad_color="$YELLOW"
        local _ad_display
        if [[ "$_ad" == *","* ]]; then
            local _ad_ct=$(echo "$_ad" | tr ',' '\n' | wc -l)
            _ad_display="all (${_ad_ct})"
        else
            _ad_display="${_ad##*:}"
        fi
        line2+="  ${GRAY}│${NC}  ${CYAN}AD:${NC} ${_ad_color}${_ad_display}${NC}"
    fi
    line2+="  ${GRAY}│${NC}  ${CYAN}Compartment:${NC} ${comp_color}${comp_display}${NC}"
    if [[ -n "${FOCUS_OKE_CLUSTER_ID:-}${OKE_CLUSTER_ID:-}" ]]; then
        local _oke_id="${FOCUS_OKE_CLUSTER_ID:-$OKE_CLUSTER_ID}"
        local _oke="${FOCUS_OKE_CLUSTER_NAME:-${CLUSTER_NAME:-$(_short_ocid "$_oke_id")}}"
        local _oke_color="$GREEN"
        [[ "$FOCUS_OKE_SOURCE" == "selected" ]] && _oke_color="$YELLOW"
        [[ "$FOCUS_OKE_SOURCE" == "derived" ]] && _oke_color="$CYAN"
        line2+="  ${GRAY}│${NC}  ${CYAN}OKE:${NC} ${_oke_color}${_oke}${NC}"
    fi
    if [[ -n "${FOCUS_VCN_OCID:-}" ]]; then
        local _vcn_color="$GREEN"
        [[ "$FOCUS_VCN_SOURCE" == "selected" ]] && _vcn_color="$YELLOW"
        [[ "$FOCUS_VCN_SOURCE" == "derived" ]] && _vcn_color="$CYAN"
        line2+="  ${GRAY}│${NC}  ${CYAN}VCN:${NC} ${_vcn_color}${FOCUS_VCN_NAME:-$(_short_ocid "$FOCUS_VCN_OCID")}${NC}"
    fi
    echo -e "    ${line2}"
    
    # ── Extra fields from caller (always runtime-selected = yellow) ──
    if [[ $# -ge 2 ]]; then
        local line_extra=""
        while [[ $# -ge 2 ]]; do
            [[ -n "$line_extra" ]] && line_extra+="  ${GRAY}│${NC}  "
            line_extra+="${CYAN}${1}:${NC} ${YELLOW}${2}${NC}"
            shift 2
        done
        echo -e "    ${line_extra}"
    fi
    # ── Tools line (always last) ──
    echo -e "    $(_build_tools_line)"
    
    echo ""
}

# Command display - shows what commands power the current view
# Usage: _ui_oci_cmd "oci compute instance list --compartment-id \$COMPARTMENT_ID --all"
_ui_oci_cmd() {
    local full_cmd="$1"
    local max_width=${UI_WIDTH:-177}
    local prefix="  "
    
    echo -e "  ${GRAY}Commands executed during fetch:${NC}"
    
    # If short enough, single line
    if [[ ${#full_cmd} -le $max_width ]]; then
        echo -e "${prefix}${GRAY}${full_cmd}${NC}"
        return
    fi
    
    # Split on " | " and rebuild lines within max_width
    local line="" first=1
    local IFS_OLD="$IFS"
    
    # Use pipe as delimiter
    local -a parts=()
    local tmp="$full_cmd"
    while [[ "$tmp" == *" | "* ]]; do
        parts+=("${tmp%%" | "*}")
        tmp="${tmp#*" | "}"
    done
    parts+=("$tmp")
    
    local current_line=""
    for part in "${parts[@]}"; do
        if [[ -z "$current_line" ]]; then
            current_line="$part"
        elif [[ $(( ${#current_line} + 3 + ${#part} )) -le $max_width ]]; then
            current_line+=" | ${part}"
        else
            echo -e "${prefix}${GRAY}${current_line}${NC}"
            current_line="${part}"
        fi
    done
    [[ -n "$current_line" ]] && echo -e "${prefix}${GRAY}${current_line}${NC}"
}

# Indented subheader within display areas — lighter weight than _ui_banner
# Usage: _ui_subheader "Subnets"                        → "  ◆ Subnets"
#        _ui_subheader "Remote DRG" 4                   → "    ◆ Remote DRG"
#        _ui_subheader "Custom Images (5)" 2 "$MAGENTA" → "  ◆ Custom Images (5)"
_ui_subheader() {
    local title="$1"
    local indent="${2:-2}"
    local color="${3:-${BOLD}${WHITE}}"
    local pad
    pad=$(printf '%*s' "$indent" '')
    echo -e "${pad}${color}◆ ${title}${NC}"
}

# Summary section header — frames totals/counts after a display area
# Usage: _ui_summary   → prints "◆ Summary"
#        _ui_summary "Network Summary"   → prints "◆ Network Summary"
_ui_summary() {
    _ui_subheader "${1:-Summary}" 0
}

# Legend section header — frames color codes and abbreviation keys
# Usage: _ui_legend   → prints "◆ Legend"
_ui_legend() {
    _ui_subheader "${1:-Legend}" 0
}

# Actions section header — distinct visual separator for menu action keys
# Usage: _ui_actions   → prints "─── Actions ───────────"
#        _ui_actions "Options"  → prints "─── Options ───────────"
_ui_actions() {
    local title="${1:-Actions}"
    local line_len=60
    local label="─── ${title} "
    local remaining=$((line_len - ${#label}))
    [[ $remaining -lt 3 ]] && remaining=3
    local trail
    trail=$(printf '─%.0s' $(seq 1 "$remaining"))
    echo -e "  ${BOLD}${YELLOW}${label}${trail}${NC}"
}

# Action group sub-label — bold white category header inside an _ui_actions block
# Usage: _ui_action_group "View"     → prints "  » View" in cyan+bold white
#        _ui_action_group "Search"   → prints "  » Search" in cyan+bold white
_ui_action_group() {
    echo -e "  ${CYAN}»${NC} ${BOLD}${WHITE}${1}${NC}"
}

# Menu prompt - breadcrumb-style with context
# Usage: _ui_prompt "Instance Configs" "i#, comp, create, r, b"
_ui_prompt() {
    local context="$1"
    local options="$2"
    echo -n -e "${BOLD}${CYAN}[${context}] Selection (${options}): ${NC}"
}

# Pause - two standardized variants
# Usage: _ui_pause           → "Press Enter to continue..."
#        _ui_pause "return"  → "Press Enter to return..."
_ui_pause() {
    local mode="${1:-continue}"
    echo -e "Press Enter to ${mode}..."
    read -r
}

# Print a policy hint after a permissions failure.
# Usage: _ui_policy_hint "read domains in tenancy"
#        _ui_policy_hint "read policies in tenancy" "read compartments in tenancy"
_ui_policy_hint() {
    echo -e "  ${YELLOW}Possible missing IAM policy:${NC}"
    local stmt
    for stmt in "$@"; do
        echo -e "    ${GRAY}allow group <your-group> to ${stmt}${NC}"
    done
}

#--------------------------------------------------------------------------------
# Interactive JSON Viewer
# Displays JSON with colorized output and supports key/value searching.
#   j             — show full JSON
#   j <keyword>   — search for keys/values matching keyword (case-insensitive)
#
# Args: $1 = title (e.g., "Cluster JSON")
#       $2 = JSON string or "-f" for file mode
#       $3 = file path (when $2 == "-f") or jq root (default ".data")
#       $4 = jq root when $2 == "-f" (default ".data")
#       $5 = search term (optional, from "j <keyword>" dispatch)
# Usage from menu:
#   j|J|json|JSON)  _ui_json_viewer "Instance JSON" "$instance_json" ".data" ;;
#   j\ *|J\ *)      _ui_json_viewer "Instance JSON" "$instance_json" ".data" "${input#* }" ;;
#--------------------------------------------------------------------------------
_ui_json_viewer() {
    local title="$1"
    local json_src="$2"
    local jq_root="${3:-.data}"
    local search="${4:-}"

    # File mode: json_src="-f", jq_root=$3=filepath, actual root=$4
    local json_data=""
    if [[ "$json_src" == "-f" ]]; then
        local filepath="$jq_root"
        jq_root="${4:-.data}"
        search="${5:-}"
        if [[ ! -s "$filepath" ]]; then
            echo -e "${RED}${title} not available${NC}"
            return 1
        fi
        json_data=$(cat "$filepath")
    else
        json_data="$json_src"
    fi

    if [[ -z "$json_data" ]]; then
        echo -e "${RED}${title} not available${NC}"
        return 1
    fi

    echo ""
    if [[ -z "$search" ]]; then
        # Full JSON display
        echo -e "${BOLD}${CYAN}━━━ ${title} ━━━${NC}"
        jq -C "$jq_root" <<< "$json_data" 2>/dev/null
    else
        # Search mode — unified deep search across all depths:
        #   1. Key name matches at any depth in the JSON tree
        #   2. Scalar value matches at any depth (returns parent object)
        #   Child paths are collapsed when a parent path is already listed.
        echo -e "${BOLD}${CYAN}━━━ ${title} — search: '${search}' ━━━${NC}"
        local search_lower
        search_lower=$(echo "$search" | tr '[:upper:]' '[:lower:]')

        local _jv_root_json
        _jv_root_json=$(jq "$jq_root" <<< "$json_data" 2>/dev/null)

        # Find all key names matching at any depth (tab-separated path segments)
        local _jv_key_paths
        _jv_key_paths=$(jq -r --arg s "$search_lower" '
            [paths | select(length > 0 and (.[-1] | type == "string") and (.[-1] | ascii_downcase | test($s)))] |
            unique | .[] | map(tostring) | join("\t")
        ' <<< "$_jv_root_json" 2>/dev/null | head -30)

        # Find scalar values matching at any depth — return parent object path
        local _jv_val_paths
        _jv_val_paths=$(jq -r --arg s "$search_lower" '
            [paths(scalars) as $p | select(getpath($p) | tostring | ascii_downcase | test($s)) |
             $p | .[:-1] | select(length > 0)] |
            unique | .[] | map(tostring) | join("\t")
        ' <<< "$_jv_root_json" 2>/dev/null | head -30)

        # Combine and dedup
        local _jv_all
        _jv_all=$(printf "%s\n%s" "$_jv_key_paths" "$_jv_val_paths" | grep -v '^$' | sort -u)

        # Collapse child paths when a parent is already in the set
        if [[ -n "$_jv_all" ]]; then
            local _jv_filtered="" _jv_is_child
            while IFS= read -r _jv_line; do
                [[ -z "$_jv_line" ]] && continue
                _jv_is_child=false
                while IFS= read -r _jv_other; do
                    [[ -z "$_jv_other" || "$_jv_other" == "$_jv_line" ]] && continue
                    if [[ "$_jv_line" == "$_jv_other"$'\t'* ]]; then
                        _jv_is_child=true
                        break
                    fi
                done <<< "$_jv_all"
                if [[ "$_jv_is_child" == "false" ]]; then
                    [[ -n "$_jv_filtered" ]] && _jv_filtered+=$'\n'
                    _jv_filtered+="$_jv_line"
                fi
            done <<< "$_jv_all"
            _jv_all="$_jv_filtered"
        fi

        if [[ -n "$_jv_all" ]]; then
            local match_count
            match_count=$(echo "$_jv_all" | wc -l)
            echo -e "${WHITE}${match_count} match(es):${NC}"
            echo ""

            while IFS= read -r _jv_entry; do
                [[ -z "$_jv_entry" ]] && continue
                local jq_path="" display_path=""
                IFS=$'\t' read -ra parts <<< "$_jv_entry"
                for part in "${parts[@]}"; do
                    if [[ "$part" =~ ^[0-9]+$ ]]; then
                        jq_path+="[${part}]"
                        display_path+="[${part}]"
                    else
                        jq_path+=".\"${part}\""
                        [[ -n "$display_path" ]] && display_path+="."
                        display_path+="${part}"
                    fi
                done

                echo -e "  ${CYAN}${display_path}${NC}:"
                jq -C "${jq_path}" <<< "$_jv_root_json" 2>/dev/null | sed 's/^/    /'
                echo ""
            done <<< "$_jv_all"
        else
            echo -e "${YELLOW}No matches found for '${search}'${NC}"
            echo ""
            echo -e "${GRAY}Tip: search matches key names and values (case-insensitive)${NC}"
        fi
    fi
    echo ""
}

# ─── Global Navigation Jump ─────────────────────────────────────────────────
# Enables :c, :k1, :n2, :env, :r, :q shortcuts from ANY --manage submenu.
# Sets _NAV_JUMP global so callers can unwind and re-dispatch at main menu.
#
# Usage: in case blocks:   :*) _nav_try_jump "$var" && return ;;
#        in if/elif blocks: [[ "${var:-}" == :* ]] && _nav_try_jump "$var" && return
#        after sub-calls:   [[ -n "${_NAV_JUMP:-}" ]] && return
#
# Supported shortcuts:
#   :c, :c1-:c9   → Compute category / item
#   :k, :k1-:k4   → Kubernetes category / item
#   :n, :n1-:n2   → Network category / item
#   :s, :s1-:s3   → Storage category / item
#   :i, :i1-:i4   → Identity category / item
#   :o, :o1-:o9   → Operations category / item
#   :env           → Change Focus
#   :r             → Overview
#   :cache         → Cache Stats
#   :q             → Quit
declare -g _NAV_JUMP=""

_nav_try_jump() {
    local _input="${1:-}"
    [[ "$_input" != :* ]] && return 1
    
    local _cmd="${_input#:}"  # Strip leading colon
    _cmd="${_cmd,,}"          # Lowercase
    
    case "$_cmd" in
        # Category + optional item: c, c1, k, k2, etc.
        [cknsiom]|[cknsiom][0-9]|[cknsiom][0-9][0-9])
            _NAV_JUMP="$_cmd"
            echo -e "  ${CYAN}↪ Jumping to ${WHITE}${_cmd}${NC}"
            return 0
            ;;
        env|env\ *|r|cache|q)
            _NAV_JUMP="$_cmd"
            echo -e "  ${CYAN}↪ Jumping to ${WHITE}${_cmd}${NC}"
            return 0
            ;;
        *)
            echo -e "  ${RED}Unknown nav shortcut ':${_cmd}'. Use :c, :k, :n, :s, :i, :o (+ optional number), :env, :r, :cache, :q${NC}"
            return 1
            ;;
    esac
}
# Usage: _ui_content_border          → MAGENTA border at UI_WIDTH
#        _ui_content_border "$GREEN"  → GREEN border at UI_WIDTH
_ui_content_border() {
    local color="${1:-$MAGENTA}"
    echo -e "${BOLD}${color}$(printf '═%.0s' $(seq 1 $UI_WIDTH))${NC}"
}

# Table header - prints BOLD column header row + auto-width separator
# Extracts %-Ns field widths from format string to calculate separator width
# Usage: _ui_table_header "%-4s %-30s %-10s" "#" "Name" "State"
#        _ui_table_header "  %-4s %-30s %-10s" "#" "Name" "State"   (indented)
_ui_table_header() {
    local fmt="$1"
    shift
    printf "${BOLD}${fmt}${NC}\n" "$@"
    # Calculate width from format: sum of %-Ns field widths + literal chars
    local width
    width=$(printf "$fmt" "$@" | sed "s/$(printf '\033')[^m]*m//g" | wc -c)
    # Detect leading indent
    local stripped="${fmt#"${fmt%%[! ]*}"}"
    local indent_len=$(( ${#fmt} - ${#stripped} ))
    if [[ $indent_len -gt 0 ]]; then
        printf '%*s' "$indent_len" ''
        print_separator $((width - indent_len))
    else
        print_separator "$width"
    fi
}

# Confirmation prompt - standardized dangerous/standard/info confirmations
# Returns 0 if confirmed, 1 if cancelled
# Usage: _ui_confirm "TERMINATE"                     → RED "Type 'TERMINATE' to confirm: "
#        _ui_confirm "yes" "drain 5 nodes"            → RED "Type 'yes' to drain 5 nodes: "
#        _ui_confirm "RENAME" "" "$CYAN"              → CYAN "Type 'RENAME' to confirm: "
#        _ui_confirm "y" "create compartment" "$YELLOW" → YELLOW "Type 'y' to create compartment: "
_ui_confirm() {
    local confirm_word="$1"
    local action_desc="${2:-confirm}"
    local color="${3:-$RED}"
    
    echo -n -e "${color}Type '${confirm_word}' to ${action_desc}: ${NC}"
    local response
    read -r response
    [[ "$response" == "$confirm_word" ]]
}

#================================================================================
# Centralized Work Request Helpers
#   _wr_annotate       — Annotate OCIDs in text with name + color
#   _wr_display_logs   — Render log entries from JSON file
#   _wr_display_errors — Render error entries from JSON file
#   _wr_generic_detail — Full generic WR detail view (fetch, display, action loop)
#
# Requirements:
#   declare -A _WR_OCID_NAMES=()   (caller populates OCID→name map)
#   compartment_id                  (global, for state enrichment)
#================================================================================

# Annotate OCIDs in text with WHITE display names and YELLOW OCIDs
# Uses: _WR_OCID_NAMES (associative array), _BASE_COLOR (line base color)
_wr_annotate() {
    local _text="$1"
    local _bc="${_BASE_COLOR:-$GRAY}"
    local _ocid _name
    for _ocid in "${!_WR_OCID_NAMES[@]}"; do
        if [[ "$_text" == *"$_ocid"* ]]; then
            _name="${_WR_OCID_NAMES[$_ocid]}"
            _text="${_text//$_ocid/${WHITE}${_name}${_bc} (${YELLOW}${_ocid}${_bc})}"
        fi
    done
    echo "$_text"
}

# Display log entries from a JSON file with color-coding and OCID annotation
# Color: RED=error/fail, YELLOW=warn/timeout, GREEN=success/completed, default=normal
# Usage: _wr_display_logs "/path/to/logs.json" [debug_hint_file]
_wr_display_logs() {
    local _file="$1"
    local _hint_file="${2:-}"
    local _ct=0
    [[ -s "$_file" ]] && _ct=$(jq '(.data // .items // []) | length' "$_file" 2>/dev/null || echo "0")
    echo ""
    if [[ "$_ct" -gt 0 ]]; then
        echo -e "  ${BOLD}${CYAN}━━━ Log Entries (${_ct}) ━━━${NC}"
        echo ""
        jq -r '(.data // .items // [])[] | "\(.timestamp // .["time-created"] // "N/A") | \(.message // "N/A")"' "$_file" 2>/dev/null | while IFS= read -r _line; do
            if echo "$_line" | grep -qi "error\|fail\|denied"; then
                _BASE_COLOR="$RED"
                _line=$(_wr_annotate "$_line")
                echo -e "    ${RED}${_line}${NC}"
            elif echo "$_line" | grep -qi "warn\|timeout\|retry"; then
                _BASE_COLOR="$YELLOW"
                _line=$(_wr_annotate "$_line")
                echo -e "    ${YELLOW}${_line}${NC}"
            elif echo "$_line" | grep -qi "success\|completed\|succeeded"; then
                _BASE_COLOR="$GREEN"
                _line=$(_wr_annotate "$_line")
                echo -e "    ${GREEN}${_line}${NC}"
            else
                _BASE_COLOR="$NC"
                _line=$(_wr_annotate "$_line")
                echo -e "    ${_line}"
            fi
        done
    else
        echo -e "  ${GRAY}No log entries${NC}"
        if [[ -n "$_hint_file" && -s "$_hint_file" ]]; then
            local _he; _he=$(head -c 200 "$_hint_file")
            [[ -n "$_he" ]] && echo -e "  ${GRAY}(${_he:0:120})${NC}"
        fi
    fi
}

# Display error entries from a JSON file with OCID annotation
# Usage: _wr_display_errors "/path/to/errors.json" [debug_hint_file]
_wr_display_errors() {
    local _file="$1"
    local _hint_file="${2:-}"
    local _ct=0
    [[ -s "$_file" ]] && _ct=$(jq '(.data // .items // []) | length' "$_file" 2>/dev/null || echo "0")
    echo ""
    if [[ "$_ct" -gt 0 ]]; then
        echo -e "  ${BOLD}${RED}━━━ Errors (${_ct}) ━━━${NC}"
        echo ""
        jq -r '(.data // .items // [])[] | "  [\(.code // "N/A")] \(.message // "N/A")"' "$_file" 2>/dev/null | while IFS= read -r _eline; do
            _BASE_COLOR="$RED"
            _eline=$(_wr_annotate "$_eline")
            echo -e "  ${RED}${_eline}${NC}"
        done
    else
        echo -e "  ${GREEN}No errors${NC}"
        if [[ -n "$_hint_file" && -s "$_hint_file" ]]; then
            local _he; _he=$(head -c 200 "$_hint_file")
            [[ -n "$_he" ]] && echo -e "  ${GRAY}(${_he:0:120})${NC}"
        fi
    fi
}

# Full generic work request detail view with progress bar, display, and action loop
# Uses generic work-requests API (not CE-specific)
# Usage: _wr_generic_detail "wr_ocid" "/tmp/dir" "Title" ["subtitle_line"] ["enrich"] ["breadcrumb_csv"]
#   wr_ocid        — work request OCID
#   tmp_dir        — temp directory for JSON files (will mkdir -p)
#   title          — section title (e.g. "Instance WR Detail: node-name")
#   subtitle       — optional subtitle line (e.g. "${WHITE}Instance:${NC} ${YELLOW}ocid...${NC}")
#   enrich         — pass "enrich" to enable resource state enrichment
#   breadcrumb_csv — pipe-separated breadcrumb (e.g. "Compute|Instances|Work Requests|Detail")
#                    When provided, shows full _ui_menu_header with Focus + commands
#                    When empty, shows simple inline title (for nested sub-WR drill-downs)
# Requires: _WR_OCID_NAMES populated by caller
_wr_generic_detail() {
    local _wrid="$1"
    local _tmpdir="$2"
    local _title="${3:-Work Request Detail}"
    local _subtitle="${4:-}"
    local _enrich="${5:-}"
    local _breadcrumb="${6:-}"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    if [[ -n "$_breadcrumb" ]]; then
        # Full header with Focus + commands
        local _bc_args=()
        IFS='|' read -ra _bc_args <<< "$_breadcrumb"
        _ui_menu_header "WORK REQUEST DETAIL" \
            --breadcrumb "${_bc_args[@]}" \
            --cmd "oci work-requests work-request get --work-request-id \$WR_OCID | oci work-requests work-request-log-entry list --work-request-id \$WR_OCID --all | oci work-requests work-request-error list --work-request-id \$WR_OCID --all" \
            --env
    else
        # Simple inline title (sub-WR drill-downs)
        echo -e "  ${BOLD}${CYAN}━━━ ${_title} ━━━${NC}"
    fi
    [[ -n "$_subtitle" ]] && echo -e "  $_subtitle"
    
    # Progress bar
    _step_init
    _step_active "work request"
    
    mkdir -p "$_tmpdir"
    local _pids=()
    (oci work-requests work-request get --work-request-id "$_wrid" --region "$region" --output json > "$_tmpdir/wr.json" 2>/dev/null) &
    _pids+=($!)
    (oci work-requests work-request-log-entry list --work-request-id "$_wrid" --region "$region" --all --output json > "$_tmpdir/logs.json" 2>/dev/null) &
    _pids+=($!)
    (oci work-requests work-request-error list --work-request-id "$_wrid" --region "$region" --all --output json > "$_tmpdir/errors.json" 2>/dev/null) &
    _pids+=($!)
    wait "${_pids[@]}"
    
    local _log_ct=0 _err_ct=0
    [[ -s "$_tmpdir/logs.json" ]] && _log_ct=$(jq '(.data // .items // []) | length' "$_tmpdir/logs.json" 2>/dev/null || echo "0")
    [[ -s "$_tmpdir/errors.json" ]] && _err_ct=$(jq '(.data // .items // []) | length' "$_tmpdir/errors.json" 2>/dev/null || echo "0")
    _step_complete "detail"
    _step_complete "logs(${_log_ct})"
    _step_complete "errors(${_err_ct})"
    _step_finish
    
    # ── Header ──
    if [[ -s "$_tmpdir/wr.json" ]] && jq -e '.data' "$_tmpdir/wr.json" >/dev/null 2>&1; then
        local _wd_status _wd_op _wd_pct _wd_accepted _wd_started _wd_finished
        _wd_status=$(jq -r '.data.status // "UNKNOWN"' "$_tmpdir/wr.json")
        _wd_op=$(jq -r '.data["operation-type"] // .data.operationType // "N/A"' "$_tmpdir/wr.json")
        _wd_pct=$(jq -r '(.data["percent-complete"] // .data.percentComplete // null) | if . == null then "N/A" elif . == 0 then "0" else (. * 100 | round / 100 | tostring) end' "$_tmpdir/wr.json" 2>/dev/null)
        [[ -z "$_wd_pct" || "$_wd_pct" == "null" ]] && _wd_pct="N/A"
        _wd_accepted=$(jq -r '.data["time-accepted"] // .data.timeAccepted // "N/A"' "$_tmpdir/wr.json")
        _wd_started=$(jq -r '.data["time-started"] // .data.timeStarted // "N/A"' "$_tmpdir/wr.json")
        _wd_finished=$(jq -r '.data["time-finished"] // .data.timeFinished // "N/A"' "$_tmpdir/wr.json")
        
        local _sc="${WHITE}"
        [[ "$_wd_status" == "SUCCEEDED" ]] && _sc="${GREEN}"
        [[ "$_wd_status" == "FAILED" || "$_wd_status" == "CANCELED" ]] && _sc="${RED}"
        [[ "$_wd_status" == "IN_PROGRESS" || "$_wd_status" == "ACCEPTED" ]] && _sc="${YELLOW}"
        
        local _duration=""
        if [[ "$_wd_started" != "N/A" && "$_wd_finished" != "N/A" ]]; then
            local _ts1 _ts2
            _ts1=$(date -d "$_wd_started" +%s 2>/dev/null) || true
            _ts2=$(date -d "$_wd_finished" +%s 2>/dev/null) || true
            if [[ -n "$_ts1" && -n "$_ts2" ]]; then
                local _ds=$(( _ts2 - _ts1 ))
                if [[ "$_ds" -ge 3600 ]]; then _duration="$((_ds/3600))h $(( (_ds%3600)/60 ))m $((_ds%60))s"
                elif [[ "$_ds" -ge 60 ]]; then _duration="$((_ds/60))m $((_ds%60))s"
                else _duration="${_ds}s"; fi
            fi
        fi
        
        echo ""
        echo -e "  ${CYAN}Work Request:${NC}  ${YELLOW}${_wrid}${NC}"
        echo -e "  ${CYAN}Operation:${NC}     ${_wd_op}"
        echo -e "  ${CYAN}Status:${NC}        ${_sc}${_wd_status}${NC}"
        [[ "$_wd_pct" != "N/A" ]] && echo -e "  ${CYAN}Progress:${NC}      ${_wd_pct}%"
        echo -e "  ${CYAN}Accepted:${NC}      ${_wd_accepted}"
        echo -e "  ${CYAN}Started:${NC}       ${_wd_started}"
        echo -e "  ${CYAN}Finished:${NC}      ${_wd_finished}${_duration:+  (${_duration})}"
        
        # ── Resources ──
        local _res_ct
        _res_ct=$(jq '(.data.resources // []) | length' "$_tmpdir/wr.json" 2>/dev/null || echo "0")
        if [[ "$_res_ct" -gt 0 ]]; then
            if [[ "$_enrich" == "enrich" ]]; then
                # State enrichment: parallel fetch lifecycle state per resource
                declare -A _RES_STATE=()
                local _rs_pids=()
                mkdir -p "$_tmpdir/rs"
                while IFS= read -r _rid; do
                    [[ -z "$_rid" ]] && continue
                    local _rk="${_rid##*.}"
                    case "$_rid" in
                        ocid1.instance.*)    (oci compute instance get --instance-id "$_rid" --region "$region" --query 'data."lifecycle-state"' --raw-output > "$_tmpdir/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                        ocid1.bootvolume.*)  (oci bv boot-volume get --boot-volume-id "$_rid" --region "$region" --query 'data."lifecycle-state"' --raw-output > "$_tmpdir/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                        ocid1.volume.*)      (oci bv volume get --volume-id "$_rid" --region "$region" --query 'data."lifecycle-state"' --raw-output > "$_tmpdir/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                        ocid1.vnic.*)        (oci network vnic get --vnic-id "$_rid" --region "$region" --query 'data."lifecycle-state"' --raw-output > "$_tmpdir/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                        ocid1.subnet.*)      (oci network subnet get --subnet-id "$_rid" --region "$region" --query 'data."lifecycle-state"' --raw-output > "$_tmpdir/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                    esac
                done < <(jq -r '(.data.resources // [])[] | .identifier // empty' "$_tmpdir/wr.json" 2>/dev/null)
                [[ ${#_rs_pids[@]} -gt 0 ]] && wait "${_rs_pids[@]}"
                while IFS= read -r _rid; do
                    [[ -z "$_rid" ]] && continue
                    local _rk="${_rid##*.}"
                    [[ -s "$_tmpdir/rs/${_rk}" ]] && _RES_STATE["$_rid"]=$(cat "$_tmpdir/rs/${_rk}")
                done < <(jq -r '(.data.resources // [])[] | .identifier // empty' "$_tmpdir/wr.json" 2>/dev/null)
                
                echo ""
                echo -e "  ${BOLD}Resources (${_res_ct}):${NC}"
                printf "    ${BOLD}%-14s %-14s %-12s %-50s %s${NC}\n" "Type" "Action" "State" "Display Name" "OCID"
                while IFS=$'\t' read -r _rt _ra _ri; do
                    [[ -z "$_ri" ]] && continue
                    local _rn="${_WR_OCID_NAMES[$_ri]:-—}"
                    local _rs="${_RES_STATE[$_ri]:-—}"
                    local _rsc; _rsc=$(color_resource_state "$_rs")
                    printf "    ${WHITE}%-14s${NC} %-14s ${_rsc}%-12s${NC} ${WHITE}%-50s${NC} ${YELLOW}%s${NC}\n" \
                        "$_rt" "$_ra" "$_rs" "$_rn" "$_ri"
                done < <(jq -r '(.data.resources // [])[] | [(.["entity-type"] // .entityType // "N/A"), (.["action-type"] // .actionType // "N/A"), (.identifier // "N/A")] | @tsv' "$_tmpdir/wr.json" 2>/dev/null)
            else
                echo ""
                echo -e "  ${BOLD}Resources (${_res_ct}):${NC}"
                printf "    ${BOLD}%-14s %-14s %-50s %s${NC}\n" "Type" "Action" "Display Name" "OCID"
                while IFS=$'\t' read -r _rt _ra _ri; do
                    [[ -z "$_ri" ]] && continue
                    local _rn="${_WR_OCID_NAMES[$_ri]:-—}"
                    printf "    ${WHITE}%-14s${NC} %-14s ${WHITE}%-50s${NC} ${YELLOW}%s${NC}\n" \
                        "$_rt" "$_ra" "$_rn" "$_ri"
                done < <(jq -r '(.data.resources // [])[] | [(.["entity-type"] // .entityType // "N/A"), (.["action-type"] // .actionType // "N/A"), (.identifier // "N/A")] | @tsv' "$_tmpdir/wr.json" 2>/dev/null)
            fi
        fi
    else
        echo -e "  ${RED}Failed to fetch work request detail${NC}"
        _ui_policy_hint "read work-requests in compartment"
    fi

    # ── Logs & Errors ──
    _wr_display_logs "$_tmpdir/logs.json"
    _wr_display_errors "$_tmpdir/errors.json"
    echo ""
    
    # ── Actions ──
    _ui_actions
    echo -e "  ${YELLOW}r${NC})      Refresh (re-fetch work request)"
    echo -e "  ${YELLOW}j${NC})      View JSON (j <keyword> to search)"
    echo -e "  ${YELLOW}d${NC})      Detail JSON    ${YELLOW}l${NC}) Logs JSON    ${YELLOW}e${NC}) Errors JSON"
    echo -e "  ${CYAN}Enter${NC})  Back"
    echo ""

    # ── Action loop ──
    while true; do
        _ui_prompt "${_title}" "r, j, d, l, e, Enter=back"
        local _rj; read -r _rj
        [[ "${_rj:-}" == :* ]] && _nav_try_jump "$_rj" && return
        case "$_rj" in
            r|R) _wr_generic_detail "$_wrid" "$_tmpdir" "$_title" "$_subtitle" "$_enrich" "$_breadcrumb"; return ;;
            j|J|json|JSON) [[ -s "$_tmpdir/wr.json" ]] && _ui_json_viewer "Work Request" "-f" "$_tmpdir/wr.json" ".data" ;;
            j\ *|J\ *|json\ *|JSON\ *) [[ -s "$_tmpdir/wr.json" ]] && _ui_json_viewer "Work Request" "-f" "$_tmpdir/wr.json" ".data" "${_rj#* }" ;;
            d|D) jq -C '.' "$_tmpdir/wr.json" 2>/dev/null ;;
            l|L) jq -C '.' "$_tmpdir/logs.json" 2>/dev/null ;;
            e|E) jq -C '.' "$_tmpdir/errors.json" 2>/dev/null ;;
            *)   break ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Categorize a compute shape or limit name into: vm | bm_hpc | vm_gpu | bm_gpu
#   vm      → VM non-GPU (standard-*, dense-*, optimized-*, vm-standard-*, etc.)
#   bm_hpc  → BM / HPC (bm-*, *hpc*)
#   vm_gpu  → VM GPU (vm-gpu*, vm.gpu*)
#   bm_gpu  → BM GPU (gpu* without bm- or vm- prefix)
#--------------------------------------------------------------------------------
_shape_category() {
    local lname="${1,,}"
    [[ "$lname" == *hpc* ]] && { echo "bm_hpc"; return; }
    [[ "$lname" == vm-gpu* || "$lname" == vm.gpu* ]] && { echo "vm_gpu"; return; }
    [[ "$lname" == bm-gpu* || "$lname" == bm.gpu* ]] && { echo "bm_gpu"; return; }
    [[ "$lname" == bm-* || "$lname" == bm.* ]] && { echo "bm_hpc"; return; }
    [[ "$lname" == gpu* ]] && { echo "bm_gpu"; return; }
    [[ "$lname" == dense-io* || "$lname" == dense.io* ]] && { echo "bm_hpc"; return; }
    [[ "$lname" == optimized* ]] && { echo "bm_hpc"; return; }
    echo "vm"
}

#--------------------------------------------------------------------------------
# 4-column shape/limit display  (VM non-GPU | BM / HPC | VM GPU | BM GPU)
#
# Renders 4 arrays side-by-side with AUTO-CALCULATED column widths.
# Colors: VM=CYAN, BM/HPC=MAGENTA, VM GPU=GREEN, BM GPU=YELLOW
#
# Usage:
#   _ui_4col_render <mode> <arr1_varname> <arr2_varname> <arr3_varname> <arr4_varname>
#
# Modes:
#   plain    - entries are shape names; displayed as-is in white
#   numbered - entries are "idx|name"; displayed as "idx) name"
#   valued   - entries are "idx|name|value"; displayed as "idx) name [value]"
#--------------------------------------------------------------------------------
_ui_4col_render() {
    local _mode="$1"
    local -n _a1="$2" _a2="$3" _a3="$4" _a4="$5"
    local n1=${#_a1[@]} n2=${#_a2[@]} n3=${#_a3[@]} n4=${#_a4[@]}
    
    # ── Auto-calculate max display width per column ──
    local w1=12 w2=12 w3=12 w4=12 _w _e
    local _idx _rest _name _val _fval
    
    _4col_calc_widths() {
        local -n _arr_ref="$1"
        local _maxw=12
        for _e in "${_arr_ref[@]}"; do
            case "$_mode" in
                plain)  _w=${#_e} ;;
                numbered)
                    _idx="${_e%%|*}"; _name="${_e#*|}"
                    _w=$(( ${#_idx} + 2 + ${#_name} )) ;;
                valued)
                    _idx="${_e%%|*}"; _rest="${_e#*|}"
                    _name="${_rest%%|*}"; _val="${_rest##*|}"
                    printf -v _fval "%'d" "$_val" 2>/dev/null || _fval="$_val"
                    _w=$(( ${#_idx} + 2 + ${#_name} + 2 + ${#_fval} + 1 )) ;;
            esac
            [[ $_w -gt $_maxw ]] && _maxw=$_w
        done
        echo "$_maxw"
    }
    
    w1=$(_4col_calc_widths "$2"); w2=$(_4col_calc_widths "$3")
    w3=$(_4col_calc_widths "$4"); w4=$(_4col_calc_widths "$5")
    
    # Add 2 chars padding per column
    ((w1+=2)); ((w2+=2)); ((w3+=2)); ((w4+=2))
    
    # ── Headers with counts and category colors ──
    printf "  ${BOLD}${CYAN}%-${w1}s${NC} ${BOLD}${MAGENTA}%-${w2}s${NC} ${BOLD}${GREEN}%-${w3}s${NC} ${BOLD}${YELLOW}%-${w4}s${NC}\n" \
        "VM non-GPU (${n1})" "BM / HPC (${n2})" "VM GPU (${n3})" "BM GPU (${n4})"
    printf "  ${GRAY}%-${w1}s %-${w2}s %-${w3}s %-${w4}s${NC}\n" \
        "$(printf '%*s' $((w1-2)) '' | tr ' ' '─')" \
        "$(printf '%*s' $((w2-2)) '' | tr ' ' '─')" \
        "$(printf '%*s' $((w3-2)) '' | tr ' ' '─')" \
        "$(printf '%*s' $((w4-2)) '' | tr ' ' '─')"

    # Sub-header for valued mode: show LIMIT column label
    if [[ "$_mode" == "valued" ]]; then
        echo -ne "  ${GRAY}"
        local _cwi=0
        for _cw in "$w1" "$w2" "$w3" "$w4"; do
            [[ $_cwi -gt 0 ]] && echo -n " "
            local _hlbl="  #  NAME" _hrtxt="LIMIT"
            local _hgap=$((_cw - ${#_hlbl} - ${#_hrtxt}))
            [[ $_hgap -lt 1 ]] && _hgap=1
            printf "%s%*s%s" "$_hlbl" "$_hgap" "" "$_hrtxt"
            ((_cwi++))
        done
        echo -e "${NC}"
    fi

    # ── Row-by-row rendering ──
    local _max=$n1
    [[ $n2 -gt $_max ]] && _max=$n2
    [[ $n3 -gt $_max ]] && _max=$n3
    [[ $n4 -gt $_max ]] && _max=$n4
    
    local _ri=0
    while [[ $_ri -lt $_max ]]; do
        echo -ne "  "
        _4col_print_entry "${_a1[$_ri]:-}" "$_mode" "$w1"
        echo -n " "
        _4col_print_entry "${_a2[$_ri]:-}" "$_mode" "$w2"
        echo -n " "
        _4col_print_entry "${_a3[$_ri]:-}" "$_mode" "$w3"
        echo -n " "
        _4col_print_entry "${_a4[$_ri]:-}" "$_mode" "$w4"
        echo ""
        ((_ri++))
    done
}

# Helper: format + print one entry in a column
_4col_print_entry() {
    local _e="$1" _m="$2" _w="$3"
    if [[ -z "$_e" ]]; then
        printf "%-${_w}s" ""
        return
    fi
    local _idx _rest _name _val _fval _name_w _tag
    case "$_m" in
        plain)
            printf "${WHITE}%-${_w}s${NC}" "$_e"
            ;;
        numbered)
            _idx="${_e%%|*}"; _name="${_e#*|}"
            _name_w=$((_w - ${#_idx} - 2))
            printf "${YELLOW}%${#_idx}s${WHITE})${NC} ${WHITE}%-${_name_w}s${NC}" "$_idx" "$_name"
            ;;
        valued)
            _idx="${_e%%|*}"; _rest="${_e#*|}"
            _name="${_rest%%|*}"; _val="${_rest##*|}"
            printf -v _fval "%'d" "$_val" 2>/dev/null || _fval="$_val"
            if [[ "$_val" == "0" ]]; then
                _name_w=$((_w - 4))
                printf "${GRAY}%3s) %-${_name_w}s${NC}" "$_idx" "$_name"
            else
                _tag=" [${_fval}]"
                _name_w=$((_w - ${#_idx} - 2 - ${#_tag}))
                [[ $_name_w -lt 10 ]] && _name_w=10
                printf "${YELLOW}%${#_idx}s${WHITE})${NC} ${WHITE}%-${_name_w}s${NC}${GRAY}%s${NC}" "$_idx" "$_name" "$_tag"
            fi
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Centralized shape categorization with modern/older split
#
# Populates 6 caller-provided arrays via nameref:
#   _sc_vm, _sc_vm_old, _sc_bm, _sc_bm_old, _sc_bm_gpu, _sc_vm_gpu
#
# Also populates caller's _SC_MAP associative array (idx → shape name)
# and sets _sc_total (total count).
#
# Entry format: "idx|shape_name|compat_mark" where compat_mark is ✓/✗
#
# Args: $1 = shapes JSON (from oci compute shape list)
#       $2 = name of associative array with compatible shapes (keys=shape names)
#            Pass "" to skip compat marks (all get ✓)
#       $3-$8 = nameref array names: vm, vm_old, bm, bm_old, bm_gpu, vm_gpu
#       $9 = nameref for index map (associative array)
#       $10 = nameref for total count variable
#--------------------------------------------------------------------------------
_shapes_categorize() {
    local _json="$1" _compat_map_name="$2"
    local -n _scv="$3" _scvo="$4" _scb="$5" _scbo="$6" _scbg="$7" _scvg="$8"
    local -n _sc_total_ref="${9}"
    
    _scv=(); _scvo=(); _scb=(); _scbo=(); _scbg=(); _scvg=()
    _sc_total_ref=0
    
    local _has_compat=false
    if [[ -n "$_compat_map_name" ]]; then
        local -n _compat_ref="$_compat_map_name"
        _has_compat=true
    fi
    
    if [[ -z "$_json" ]] || ! jq -e '.data[0]' <<< "$_json" >/dev/null 2>&1; then
        return 1
    fi
    
    # Entry format: "shapename|compat_mark" (no index — assigned at render time)
    local _count=0
    while IFS='|' read -r _sname _socpu _smem; do
        [[ -z "$_sname" ]] && continue
        ((_count++))
        
        local _mark="${GREEN}✓${NC}"
        if [[ "$_has_compat" == "true" ]]; then
            [[ -z "${_compat_ref[$_sname]+x}" ]] && _mark="${RED}✗${NC}"
        fi
        local _entry="${_sname}|${_mark}"
        
        if [[ "$_sname" == BM.GPU* ]]; then
            _scbg+=("$_entry")
        elif [[ "$_sname" == VM.GPU* ]]; then
            _scvg+=("$_entry")
        elif [[ "$_sname" == BM.HPC* ]]; then
            _scb+=("$_entry")
        elif [[ "$_sname" == BM.* ]]; then
            if [[ "$_sname" =~ \.(E[3-6]|DenseIO\.E[45]|Optimized3|Standard\.A[0-9]|Standard\.B[0-9])\. ]]; then
                _scb+=("$_entry")
            else
                _scbo+=("$_entry")
            fi
        else
            if [[ "$_sname" =~ \.(E[3-6]|DenseIO\.E[45]|Optimized3|Standard\.A[0-9]|Standard\.B[0-9])\. ]]; then
                _scv+=("$_entry")
            else
                _scvo+=("$_entry")
            fi
        fi
    done < <(jq -r '[.data[] | {shape, ocpus: (.ocpus // "N/A"), mem: (.["memory-in-gbs"] // "N/A")}] | unique_by(.shape) | sort_by(.shape)[] | "\(.shape)|\(.ocpus)|\(.mem)"' <<< "$_json" 2>/dev/null)
    
    _sc_total_ref=$_count
}

#--------------------------------------------------------------------------------
# Render categorized shapes in 4-column layout with modern/older toggle
#
# Reads from 6 arrays built by _shapes_categorize.
# Entry format from _shapes_categorize: "shapename|compat_mark" (no index)
# Shows modern shapes by default, 'o' toggle shows older.
# Returns immediately if mode="display" (no selection).
# For mode="select", returns shape name in _SC_SELECTED.
# Indices are assigned at render time to only VISIBLE shapes, flowing
# left-to-right: VM 1..N, BM N+1..M, BM GPU M+1..P, VM GPU P+1..Q.
#
# Args: $1 = mode: "display" (view only) or "select" (interactive picker)
#       $2-$7 = nameref array names: vm, vm_old, bm, bm_old, bm_gpu, vm_gpu
#       $8 = total shape count (informational)
#       $9 = default shape name (for select mode, optional)
#--------------------------------------------------------------------------------
_shapes_render_compat() {
    local _mode="$1"
    local -n _rv="$2" _rvo="$3" _rb="$4" _rbo="$5" _rbg="$6" _rvg="$7"
    local _total="${8}" _default="${9:-}"
    
    local _show_older="${_SHAPE_SHOW_OLDER:-false}"
    local _old_vm_ct=${#_rvo[@]} _old_bm_ct=${#_rbo[@]}
    local _old_total=$((_old_vm_ct + _old_bm_ct))
    
    while true; do
        # Build display arrays (append older if toggled)
        # Entry format: "shapename|compat_mark"
        local -a _d_vm=("${_rv[@]}") _d_bm=("${_rb[@]}")
        if [[ "$_show_older" == "true" ]]; then
            [[ ${#_rvo[@]} -gt 0 ]] && _d_vm+=("${_rvo[@]}")
            [[ ${#_rbo[@]} -gt 0 ]] && _d_bm+=("${_rbo[@]}")
        fi
        local -a _d_bg=("${_rbg[@]}") _d_vg=("${_rvg[@]}")
        
        local _d_vm_ct=${#_d_vm[@]} _d_bm_ct=${#_d_bm[@]}
        local _d_bg_ct=${#_d_bg[@]} _d_vg_ct=${#_d_vg[@]}
        
        # Assign sequential indices across columns (select mode only)
        # Order: VM → BM → BM GPU → VM GPU (left to right)
        declare -A _SC_SEL_MAP=()
        local -a _n_vm=() _n_bm=() _n_bg=() _n_vg=()
        if [[ "$_mode" != "display" ]]; then
            local _si=0
            local _e _ename
            for _e in "${_d_vm[@]}"; do ((_si++)); _ename="${_e%%|*}"; _SC_SEL_MAP[$_si]="$_ename"; _n_vm+=("$_si"); done
            for _e in "${_d_bm[@]}"; do ((_si++)); _ename="${_e%%|*}"; _SC_SEL_MAP[$_si]="$_ename"; _n_bm+=("$_si"); done
            for _e in "${_d_bg[@]}"; do ((_si++)); _ename="${_e%%|*}"; _SC_SEL_MAP[$_si]="$_ename"; _n_bg+=("$_si"); done
            for _e in "${_d_vg[@]}"; do ((_si++)); _ename="${_e%%|*}"; _SC_SEL_MAP[$_si]="$_ename"; _n_vg+=("$_si"); done
        fi
        
        echo -e "  ${GREEN}✓${NC} = image compatible    ${RED}✗${NC} = missing compatibility"
        echo ""
        
        # 4-column display: VM | BM | BM GPU | VM GPU
        local _cw=34
        # Generate separator: _cw Unicode dashes via loop (avoids printf %-Ns multibyte issues)
        local _sep="" _si
        for ((_si=0; _si<_cw; _si++)); do _sep+="─"; done
        
        local _vm_hdr="VM (${_d_vm_ct})"
        local _bm_hdr="BM (${_d_bm_ct})"
        [[ "$_show_older" != "true" && $_old_total -gt 0 ]] && {
            _vm_hdr="VM (${_d_vm_ct}${_old_vm_ct:+, +${_old_vm_ct} older})"
            _bm_hdr="BM (${_d_bm_ct}${_old_bm_ct:+, +${_old_bm_ct} older})"
        }
        
        printf "  ${BOLD}${CYAN}%-${_cw}s${NC} ${BOLD}${MAGENTA}%-${_cw}s${NC} ${BOLD}${GREEN}%-${_cw}s${NC} ${BOLD}${YELLOW}%-${_cw}s${NC}\n" \
            "$_vm_hdr" "$_bm_hdr" "BM GPU (${_d_bg_ct})" "VM GPU (${_d_vg_ct})"
        # Print separator without %-Ns (multibyte ─ breaks byte-counting printf padding)
        printf "  ${GRAY}%s %s %s %s${NC}\n" "$_sep" "$_sep" "$_sep" "$_sep"
        
        # Find max column height
        local _s_max=$_d_vm_ct
        [[ $_d_bm_ct -gt $_s_max ]] && _s_max=$_d_bm_ct
        [[ $_d_bg_ct -gt $_s_max ]] && _s_max=$_d_bg_ct
        [[ $_d_vg_ct -gt $_s_max ]] && _s_max=$_d_vg_ct
        
        # label width: display = cw - 4 ("✓ "), select = cw - 8 ("idx) ✓ ")
        local _lw
        [[ "$_mode" == "display" ]] && _lw=$((_cw - 2)) || _lw=$((_cw - 7))
        
        local _ri=0
        while [[ $_ri -lt $_s_max ]]; do
            echo -ne "  "
            # VM column
            if [[ $_ri -lt $_d_vm_ct ]]; then
                local _vs="${_d_vm[$_ri]%%|*}" _vc="${_d_vm[$_ri]##*|}"
                if [[ "$_mode" == "display" ]]; then
                    printf "${_vc} %-${_lw}s " "${_vs:0:${_lw}}"
                else
                    printf "${YELLOW}%-4s${NC} ${_vc} %-${_lw}s " "${_n_vm[$_ri]})" "${_vs:0:${_lw}}"
                fi
            else
                printf "%-${_cw}s " ""
            fi
            # BM column
            if [[ $_ri -lt $_d_bm_ct ]]; then
                local _bs="${_d_bm[$_ri]%%|*}" _bc="${_d_bm[$_ri]##*|}"
                if [[ "$_mode" == "display" ]]; then
                    printf "${_bc} %-${_lw}s " "${_bs:0:${_lw}}"
                else
                    printf "${YELLOW}%-4s${NC} ${_bc} %-${_lw}s " "${_n_bm[$_ri]})" "${_bs:0:${_lw}}"
                fi
            else
                printf "%-${_cw}s " ""
            fi
            # BM GPU column
            if [[ $_ri -lt $_d_bg_ct ]]; then
                local _gs="${_d_bg[$_ri]%%|*}" _gc="${_d_bg[$_ri]##*|}"
                if [[ "$_mode" == "display" ]]; then
                    printf "${_gc} %-${_lw}s " "${_gs:0:${_lw}}"
                else
                    printf "${YELLOW}%-4s${NC} ${_gc} %-${_lw}s " "${_n_bg[$_ri]})" "${_gs:0:${_lw}}"
                fi
            else
                printf "%-${_cw}s " ""
            fi
            # VM GPU column (last — no trailing space)
            if [[ $_ri -lt $_d_vg_ct ]]; then
                local _gs="${_d_vg[$_ri]%%|*}" _gc="${_d_vg[$_ri]##*|}"
                if [[ "$_mode" == "display" ]]; then
                    printf "${_gc} %-${_lw}s" "${_gs:0:${_lw}}"
                else
                    printf "${YELLOW}%-4s${NC} ${_gc} %-${_lw}s" "${_n_vg[$_ri]})" "${_gs:0:${_lw}}"
                fi
            fi
            printf "\n"
            ((_ri++))
        done
        
        echo ""
        if [[ "$_show_older" != "true" && $_old_total -gt 0 ]]; then
            echo -e "  ${GRAY}o${NC}) Show older shapes (+${_old_vm_ct} VM, +${_old_bm_ct} BM: Standard1/2/3, DenseIO2, E2)"
        elif [[ "$_show_older" == "true" && $_old_total -gt 0 ]]; then
            echo -e "  ${GRAY}o${NC}) Hide older shapes"
        fi
        
        # Display mode — show once and return
        if [[ "$_mode" == "display" ]]; then
            return 0
        fi
        
        # Select mode — prompt for shape
        echo -e "  ${GRAY}c${NC}) Custom (enter shape name manually)"
        echo ""
        echo -n -e "${CYAN}Select shape # or 'c' for custom [${_default}]: ${NC}"
        local _shape_choice
        read -r _shape_choice
        
        case "$_shape_choice" in
            o|O)
                if [[ "$_show_older" == "true" ]]; then
                    _show_older=false; _SHAPE_SHOW_OLDER=false
                else
                    _show_older=true; _SHAPE_SHOW_OLDER=true
                fi
                continue
                ;;
            c|C)
                echo -n -e "  ${CYAN}Enter shape name: ${NC}"
                local _custom_shape
                read -r _custom_shape
                if [[ -n "$_custom_shape" ]]; then
                    _SC_SELECTED="$_custom_shape"
                else
                    _SC_SELECTED="$_default"
                fi
                return 0
                ;;
            "")
                _SC_SELECTED="$_default"
                return 0
                ;;
            [0-9]*)
                if [[ -n "${_SC_SEL_MAP[$_shape_choice]:-}" ]]; then
                    _SC_SELECTED="${_SC_SEL_MAP[$_shape_choice]}"
                else
                    _SC_SELECTED="$_default"
                fi
                return 0
                ;;
            *)
                _SC_SELECTED="$_default"
                return 0
                ;;
        esac
    done
}

# Truncate string to max length with ellipsis
truncate_string() {
    local str="$1"
    local max_len="$2"
    
    if [[ ${#str} -gt $max_len ]]; then
        echo "${str:0:$((max_len-3))}..."
    else
        echo "$str"
    fi
}

# Breadcrumb navigation — shows hierarchical path
# Usage: _ui_breadcrumb "Compute"
#        _ui_breadcrumb "Compute" "Instance Configurations"
#        _ui_breadcrumb "Network" "Network Resources" "DRG Connectivity"
_ui_breadcrumb() {
    local path="Main"
    for segment in "$@"; do
        path+=" ${GRAY}>${NC} ${WHITE}${segment}"
    done
    echo -e "  ${GRAY}${path}${NC}"
}

#===============================================================================
# ENVIRONMENT FOCUS SYSTEM
# Single source of truth for compartment, region, OKE cluster, and VCN scope.
# All resource managers read from FOCUS_* variables.
#===============================================================================

# Initialize focus from variables.sh values and CLI overrides
# Called once at startup from the entry point.
_focus_init() {
    local custom_compartment="${1:-}"
    local custom_region="${2:-}"
    
    # Region
    FOCUS_REGION="${custom_region:-$REGION}"
    if [[ -n "$custom_region" ]]; then
        FOCUS_REGION_SOURCE="selected"
    else
        FOCUS_REGION_SOURCE="config"
    fi
    
    # Compartment
    FOCUS_COMPARTMENT_ID="${custom_compartment:-$COMPARTMENT_ID}"
    if [[ -n "$custom_compartment" ]]; then
        FOCUS_COMPARTMENT_SOURCE="selected"
    else
        FOCUS_COMPARTMENT_SOURCE="config"
    fi
    
    # OKE Cluster (from variables.sh if set)
    if [[ -n "${OKE_CLUSTER_ID:-}" ]]; then
        FOCUS_OKE_CLUSTER_ID="$OKE_CLUSTER_ID"
        FOCUS_OKE_CLUSTER_NAME="${CLUSTER_NAME:-}"
        FOCUS_OKE_SOURCE="config"
    fi
    
    # AD — auto-resolve first AD when --region overrides the configured region
    if [[ -n "$custom_region" && "$custom_region" != "${REGION:-}" ]]; then
        # Custom region differs from variables.sh — fetch ADs for the new region
        local _init_ads_json
        _init_ads_json=$(oci iam availability-domain list \
            --compartment-id "${FOCUS_COMPARTMENT_ID:-${TENANCY_ID:-}}" \
            --region "$custom_region" --output json 2>/dev/null)
        local _init_first_ad
        _init_first_ad=$(jq -r '.data[0].name // empty' <<< "$_init_ads_json" 2>/dev/null)
        if [[ -n "$_init_first_ad" ]]; then
            FOCUS_AD="$_init_first_ad"
            FOCUS_AD_SOURCE="derived"
        else
            # Could not resolve — clear stale AD from a different region
            FOCUS_AD=""
            FOCUS_AD_SOURCE=""
        fi
    elif [[ -n "${AD:-}" ]]; then
        # No custom region — use AD from variables.sh
        FOCUS_AD="$AD"
        FOCUS_AD_SOURCE="config"
    fi

}

# Change compartment focus — invalidates all caches, cascades to OKE/VCN
_focus_set_compartment() {
    local new_id="$1"
    local new_name="${2:-}"
    
    if [[ "$new_id" == "$FOCUS_COMPARTMENT_ID" ]]; then
        return 0  # No change
    fi
    
    local old_id="$FOCUS_COMPARTMENT_ID"
    FOCUS_COMPARTMENT_ID="$new_id"
    FOCUS_COMPARTMENT_SOURCE="selected"
    
    # Invalidate all caches — data is compartment-scoped
    echo -e "${YELLOW}Compartment changed — invalidating caches...${NC}"
    refresh_all_caches
    
    # Cascade: clear OKE if cluster not in new compartment
    if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
        echo -e "${GRAY}Clearing OKE cluster focus (compartment changed)${NC}"
        _focus_clear_oke
    fi
    
    log_action "FOCUS_CHANGE" "Compartment: $old_id → $new_id" --quiet
}

# Change region focus — invalidates all caches, clears OKE/VCN
_focus_set_region() {
    local new_region="$1"
    
    if [[ "$new_region" == "$FOCUS_REGION" ]]; then
        return 0
    fi
    
    local old_region="$FOCUS_REGION"
    FOCUS_REGION="$new_region"
    FOCUS_REGION_SOURCE="selected"
    
    echo -e "${YELLOW}Region changed — invalidating caches...${NC}"
    refresh_all_caches
    
    # Cascade: clusters and VCNs are region-specific
    if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
        echo -e "${GRAY}Clearing OKE cluster focus (region changed)${NC}"
        _focus_clear_oke
    fi
    
    # Cascade: ADs are region-specific
    if [[ -n "$FOCUS_AD" ]]; then
        echo -e "${GRAY}Clearing AD focus (region changed)${NC}"
        FOCUS_AD=""
        FOCUS_AD_SOURCE=""
    fi
    
    log_action "FOCUS_CHANGE" "Region: $old_region → $new_region" --quiet
}

# Change AD focus
_focus_set_ad() {
    local new_ad="$1"
    FOCUS_AD="$new_ad"
    FOCUS_AD_SOURCE="selected"
    log_action "FOCUS_CHANGE" "AD: → $new_ad" --quiet
}

# Set OKE cluster focus — derives VCN
_focus_set_oke_cluster() {
    local cluster_id="$1"
    local cluster_name="${2:-}"
    local source="${3:-selected}"
    
    FOCUS_OKE_CLUSTER_ID="$cluster_id"
    FOCUS_OKE_CLUSTER_NAME="$cluster_name"
    FOCUS_OKE_SOURCE="$source"
    
    # Derive VCN from cluster (unless VCN was manually set)
    if [[ "$FOCUS_VCN_SOURCE" != "selected" ]]; then
        # Will be populated when OKE env is fetched
        FOCUS_VCN_OCID=""
        FOCUS_VCN_NAME=""
        FOCUS_VCN_SOURCE="derived"
    fi
    
    # Invalidate OKE caches
    rm -f "$OKE_ENV_CACHE" "$OKE_CLUSTER_JSON_CACHE" "$OKE_NODEPOOL_CACHE" "$OKE_SUBNET_LIST_CACHE"
    
}

# Set VCN focus directly (manual selection)
_focus_set_vcn() {
    local vcn_id="$1"
    local vcn_name="${2:-}"
    local source="${3:-selected}"
    
    FOCUS_VCN_OCID="$vcn_id"
    FOCUS_VCN_NAME="$vcn_name"
    FOCUS_VCN_SOURCE="$source"
    
    # Invalidate network caches
    rm -f "$NETWORK_RESOURCES_CACHE" "$VCN_LIST_CACHE" "$RT_CACHE" "$IGW_CACHE" "$NAT_CACHE" "$SGW_CACHE" \
          "$DRG_LIST_CACHE" "$DRG_CACHE" "$LPG_CACHE" "$NSG_RULES_CACHE" "$NSG_SUBNET_MAP_CACHE" "$SL_CACHE"
    
}

# Clear OKE cluster focus — also clears derived VCN
_focus_clear_oke() {
    FOCUS_OKE_CLUSTER_ID=""
    FOCUS_OKE_CLUSTER_NAME=""
    FOCUS_OKE_SOURCE=""
    
    # Clear VCN if it was derived from the cluster
    if [[ "$FOCUS_VCN_SOURCE" == "derived" ]]; then
        _focus_clear_vcn
    fi
    
    rm -f "$OKE_ENV_CACHE" "$OKE_CLUSTER_JSON_CACHE" "$OKE_NODEPOOL_CACHE" "$OKE_SUBNET_LIST_CACHE"
}

# Clear VCN focus
_focus_clear_vcn() {
    FOCUS_VCN_OCID=""
    FOCUS_VCN_NAME=""
    FOCUS_VCN_SOURCE=""
    
    rm -f "$NETWORK_RESOURCES_CACHE" "$VCN_LIST_CACHE" "$RT_CACHE" "$IGW_CACHE" "$NAT_CACHE" "$SGW_CACHE" \
          "$DRG_LIST_CACHE" "$DRG_CACHE" "$LPG_CACHE" "$NSG_RULES_CACHE" "$NSG_SUBNET_MAP_CACHE" "$SL_CACHE"
}

# Derive VCN from focused OKE cluster (lazy — only when needed)
# Fetches OKE environment cache, extracts VCN_OCID/VCN_NAME, sets FOCUS_VCN
# No-op if OKE not focused, VCN already set, or VCN manually selected
_focus_derive_vcn_from_oke() {
    # Skip if no OKE cluster focused
    [[ -z "$FOCUS_OKE_CLUSTER_ID" ]] && return 1
    # Skip if VCN already resolved (either manually selected or previously derived)
    [[ -n "$FOCUS_VCN_OCID" ]] && return 0
    # Skip if VCN was manually selected (don't override)
    [[ "$FOCUS_VCN_SOURCE" == "selected" ]] && return 0
    
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    # Populate OKE env cache if needed (fast if already cached, skip compute clusters)
    fetch_oke_environment "$compartment_id" "$region" 2>/dev/null
    
    local vcn_ocid vcn_name
    vcn_ocid=$(get_oke_env_value "VCN_OCID" 2>/dev/null)
    vcn_name=$(get_oke_env_value "VCN_NAME" 2>/dev/null)
    
    if [[ -n "$vcn_ocid" && "$vcn_ocid" != "N/A" ]]; then
        FOCUS_VCN_OCID="$vcn_ocid"
        FOCUS_VCN_NAME="${vcn_name:-}"
        FOCUS_VCN_SOURCE="derived"
        return 0
    fi
    
    # Fallback: try cluster JSON directly
    if [[ -f "$OKE_CLUSTER_JSON_CACHE" ]]; then
        vcn_ocid=$(jq -r '.data["vcn-id"] // empty' "$OKE_CLUSTER_JSON_CACHE" 2>/dev/null)
        if [[ -n "$vcn_ocid" ]]; then
            vcn_name=$(oci network vcn get --vcn-id "$vcn_ocid" \
                --region "$region" \
                --query 'data."display-name"' --raw-output 2>/dev/null) || vcn_name=""
            FOCUS_VCN_OCID="$vcn_ocid"
            FOCUS_VCN_NAME="${vcn_name:-}"
            FOCUS_VCN_SOURCE="derived"
            return 0
        fi
    fi
    
    return 1
}

# Save current focus to variables.sh
_focus_save_to_variables() {
    local variables_file="${VARIABLES_FILE:-./variables.sh}"
    
    if [[ ! -f "$variables_file" ]]; then
        echo -e "${RED}No variables.sh found at: $variables_file${NC}"
        return 1
    fi
    
    local changes=0
    
    # Helper: update or add a variable in the file
    # Uses line-by-line replacement to avoid sed regex injection
    _focus_save_var() {
        local var_name="$1"
        local var_value="$2"
        local var_comment="${3:-}"

        if [[ -z "$var_value" ]]; then
            return 0
        fi

        # Use bash pattern match to check if var exists (avoids regex injection in grep)
        local _var_exists=0
        while IFS= read -r _chk; do
            [[ "$_chk" == "${var_name}="* ]] && { _var_exists=1; break; }
        done < "$variables_file" 2>/dev/null
        if [[ $_var_exists -eq 1 ]]; then
            # Safe replacement: read file, replace matching line, write back
            local _tmp_vars
            _tmp_vars=$(mktemp "${TEMP_DIR}/vars.XXXXXX") || return 1
            while IFS= read -r _line; do
                if [[ "$_line" == "${var_name}="* ]]; then
                    echo "${var_name}=\"${var_value}\""
                else
                    echo "$_line"
                fi
            done < "$variables_file" > "$_tmp_vars"
            mv -f "$_tmp_vars" "$variables_file"
        else
            echo "" >> "$variables_file"
            [[ -n "$var_comment" ]] && echo "# $var_comment" >> "$variables_file"
            echo "${var_name}=\"${var_value}\"" >> "$variables_file"
        fi
        ((changes++))
    }
    
    _focus_save_var "REGION" "$FOCUS_REGION" "OCI region"
    _focus_save_var "COMPARTMENT_ID" "$FOCUS_COMPARTMENT_ID" "Target compartment"
    
    if [[ -n "$FOCUS_AD" ]]; then
        _focus_save_var "AD" "$FOCUS_AD" "Availability domain"
    fi
    
    if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
        _focus_save_var "OKE_CLUSTER_ID" "$FOCUS_OKE_CLUSTER_ID" "OKE cluster"
        [[ -n "$FOCUS_OKE_CLUSTER_NAME" ]] && _focus_save_var "CLUSTER_NAME" "$FOCUS_OKE_CLUSTER_NAME"
    fi
    
    if [[ -n "$FOCUS_VCN_OCID" && "$FOCUS_VCN_SOURCE" == "selected" ]]; then
        _focus_save_var "NETWORK_COMPARTMENT_ID" "$FOCUS_COMPARTMENT_ID" "Network compartment"
    fi
    
    unset -f _focus_save_var
    
    echo -e "${GREEN}✓ Saved $changes value(s) to $variables_file${NC}"
    log_action "FOCUS_SAVE" "Saved focus to $variables_file: Region=$FOCUS_REGION, Compartment=$FOCUS_COMPARTMENT_ID" --quiet
}

# Display current focus status (used in env menu and headers)
_focus_display() {
    local region_color="$GREEN"
    [[ "$FOCUS_REGION_SOURCE" == "selected" ]] && region_color="$YELLOW"
    
    local comp_color="$GREEN"
    [[ "$FOCUS_COMPARTMENT_SOURCE" == "selected" ]] && comp_color="$YELLOW"
    
    local comp_display
    comp_display=$(_resolve_compartment_path "$FOCUS_COMPARTMENT_ID" 2>/dev/null || echo "$FOCUS_COMPARTMENT_ID")

    echo -e "  ${BOLD}${WHITE}Focus:${NC} ${GRAY}(${GREEN}variables.sh configured${NC} ${GRAY}│${NC} ${YELLOW}manually selected${NC} ${GRAY}│${NC} ${CYAN}derived${NC}${GRAY})${NC}"
    
    # ── Tenancy ──
    if [[ -n "${TENANCY_ID:-}" ]]; then
        local _tenancy_display="${TENANCY_ID}"
        [[ -n "${_TOOL_TENANCY_NAME:-}" ]] && _tenancy_display="${_TOOL_TENANCY_NAME} ${GRAY}[${NC}${GREEN}${TENANCY_ID}${NC}${GRAY}]${NC}"
        echo -e "    ${CYAN}Tenancy:${NC} ${GREEN}${_tenancy_display}${NC}"
    fi
    
    # ── Region │ AD │ Compartment │ OKE │ VCN ──
    local _fd_line="${CYAN}Region:${NC} ${region_color}${FOCUS_REGION}${NC}"
    local _fd_ad="${FOCUS_AD:-${AD:-}}"
    if [[ -n "$_fd_ad" ]]; then
        local _fd_ad_color="$GREEN"
        [[ "${FOCUS_AD_SOURCE:-}" == "selected" ]] && _fd_ad_color="$YELLOW"
        local _fd_ad_display
        if [[ "$_fd_ad" == *","* ]]; then
            local _fd_ad_ct=$(echo "$_fd_ad" | tr ',' '\n' | wc -l)
            _fd_ad_display="all (${_fd_ad_ct})"
        else
            _fd_ad_display="${_fd_ad##*:}"
        fi
        _fd_line+="  ${GRAY}│${NC}  ${CYAN}AD:${NC} ${_fd_ad_color}${_fd_ad_display}${NC}"
    fi
    _fd_line+="  ${GRAY}│${NC}  ${CYAN}Compartment:${NC} ${comp_color}${comp_display}${NC}"
    
    if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
        local oke_color="$GREEN"
        [[ "$FOCUS_OKE_SOURCE" == "selected" ]] && oke_color="$YELLOW"
        _fd_line+="  ${GRAY}│${NC}  ${CYAN}OKE:${NC} ${oke_color}${FOCUS_OKE_CLUSTER_NAME:-$(_short_ocid "$FOCUS_OKE_CLUSTER_ID")}${NC}"
    fi
    
    if [[ -n "$FOCUS_VCN_OCID" ]]; then
        local vcn_color="$GREEN"
        [[ "$FOCUS_VCN_SOURCE" == "selected" ]] && vcn_color="$YELLOW"
        [[ "$FOCUS_VCN_SOURCE" == "derived" ]] && vcn_color="$CYAN"
        _fd_line+="  ${GRAY}│${NC}  ${CYAN}VCN:${NC} ${vcn_color}${FOCUS_VCN_NAME:-$(_short_ocid "$FOCUS_VCN_OCID")}${NC}"
    fi
    echo -e "    ${_fd_line}"
    
    # ── Tools (always last) ──
    echo -e "    $(_build_tools_line)"
}

#--------------------------------------------------------------------------------
# Environment Focus Menu — interactive focus management
#--------------------------------------------------------------------------------
#--------------------------------------------------------------------------------
# Environment Focus Quick Actions
# Standalone functions for each focus change — called by manage_environment_focus
# and by _env_dispatch for inline shortcuts (env c, env r, etc.) from any menu.
#--------------------------------------------------------------------------------

# Change region — lists subscribed regions, lets user pick
_env_select_region() {
    echo ""
    _step_init
    _step_active "regions"
    local regions_json
    regions_json=$(oci iam region-subscription list --tenancy-id "${TENANCY_ID:-}" --all --output json 2>/dev/null)
    local _erc
    _erc=$(jq '.data | length' <<< "$regions_json" 2>/dev/null || echo "0")
    _step_complete "regions(${_erc})"
    _step_finish
    
    if [[ -z "$regions_json" ]] || ! jq -e '.data[0]' <<< "$regions_json" >/dev/null 2>&1; then
        echo -e "${YELLOW}Could not fetch regions. Enter manually:${NC}"
        echo -n -e "${CYAN}Region (e.g., us-ashburn-1): ${NC}"
        local new_region
        read -r new_region
        if [[ -n "$new_region" ]]; then
            _focus_set_region "$new_region"
            echo -e "${GREEN}✓ Region set to: $new_region${NC}"
            # Prompt for AD in the new region
            echo -e "${GRAY}ADs are region-specific — select AD for the new region:${NC}"
            _env_select_ad
        fi
    else
        echo ""
        _ui_subheader "Subscribed Regions" 0
        local ridx=0 _current_idx=""
        declare -A _REGION_MAP=()
        while IFS='|' read -r rname rstatus rhome; do
            ((ridx++))
            _REGION_MAP[$ridx]="$rname"
            local _rc="$GREEN" _home=""
            [[ "$rstatus" != "READY" ]] && _rc="$YELLOW"
            [[ "$rhome" == "true" ]] && _home=" ${CYAN}(home)${NC}"
            local _current=""
            if [[ "$rname" == "$FOCUS_REGION" ]]; then
                _current=" ${YELLOW}← current${NC}"
                _current_idx="$ridx"
            fi
            printf "  ${YELLOW}%2d${NC}) ${_rc}%-20s${NC}${_home}${_current}\n" "$ridx" "$rname"
        done < <(jq -r '.data[] | "\(.["region-name"])|\(.status)|\(.["is-home-region"])"' <<< "$regions_json" 2>/dev/null | sort)

        echo ""
        local _def_hint="Enter to cancel"
        [[ -n "$_current_idx" ]] && _def_hint="${_current_idx}"
        echo -n -e "${CYAN}Select region number [${_def_hint}]: ${NC}"
        local r_choice
        read -r r_choice
        # Apply default when user presses Enter with no input
        [[ -z "$r_choice" && -n "$_current_idx" ]] && r_choice="$_current_idx"

        if [[ -n "$r_choice" && -n "${_REGION_MAP[$r_choice]:-}" ]]; then
            _focus_set_region "${_REGION_MAP[$r_choice]}"
            echo -e "${GREEN}✓ Region set to: ${_REGION_MAP[$r_choice]}${NC}"
            # Prompt for AD in the new region
            echo -e "${GRAY}ADs are region-specific — select AD for the new region:${NC}"
            _env_select_ad
        fi
    fi
}

# Change availability domain — lists ADs, supports single/multi/all selection
_env_select_ad() {
    echo ""
    _step_init
    _step_active "availability domains"
    local ads_json
    ads_json=$(_get_ads_json "${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}")
    local _eadc
    _eadc=$(jq '.data | length' <<< "$ads_json" 2>/dev/null || echo "0")
    _step_complete "availability domains(${_eadc})"
    _step_finish
    
    if [[ -z "$ads_json" ]] || ! jq -e '.data[0]' <<< "$ads_json" >/dev/null 2>&1; then
        echo -e "${YELLOW}No availability domains found${NC}"
    else
        echo ""
        _ui_subheader "Availability Domains" 0
        local aidx=0 _current_idx="" _current_idx_list=""
        declare -A _AD_MAP=()
        local _focus_ad="${FOCUS_AD:-${AD:-}}"
        while IFS= read -r adname; do
            ((aidx++))
            _AD_MAP[$aidx]="$adname"
            local _current=""
            if [[ "$_focus_ad" == *","* ]]; then
                if [[ "$_focus_ad" == *"$adname"* ]]; then
                    _current=" ${YELLOW}← current${NC}"
                    [[ -n "$_current_idx_list" ]] && _current_idx_list+=","
                    _current_idx_list+="$aidx"
                fi
            else
                if [[ "$adname" == "$_focus_ad" ]]; then
                    _current=" ${YELLOW}← current${NC}"
                    _current_idx="$aidx"
                fi
            fi
            printf "  ${YELLOW}%2d${NC}) ${WHITE}%-40s${NC}${_current}\n" "$aidx" "$adname"
        done < <(jq -r '.data[].name' <<< "$ads_json" 2>/dev/null | sort)

        # Auto-select if only one AD available
        if [[ "$aidx" -eq 1 ]]; then
            _focus_set_ad "${_AD_MAP[1]}"
            echo -e "${GREEN}✓ AD auto-selected: ${_AD_MAP[1]} (only 1 available)${NC}"
            return
        fi

        # Determine default hint — single AD index, multi-AD index list, or "all"
        # Default to AD1 if no current selection
        local _def_hint="1" _def_value="1"
        if [[ -n "$_current_idx" ]]; then
            _def_hint="${_current_idx}"
            _def_value="$_current_idx"
        elif [[ -n "$_current_idx_list" ]]; then
            # Check if all ADs are selected
            local _sel_count _total_count="$aidx"
            _sel_count=$(echo "$_current_idx_list" | tr ',' '\n' | wc -l)
            if [[ "$_sel_count" -eq "$_total_count" ]]; then
                _def_hint="all"
                _def_value="all"
            else
                _def_hint="${_current_idx_list}"
                _def_value="$_current_idx_list"
            fi
        fi

        echo ""
        echo -e "  ${GRAY}Select one AD, or multiple (e.g., 1,2,3 or all)${NC}"
        echo -n -e "${CYAN}Select AD [${_def_hint}]: ${NC}"
        local ad_choice
        read -r ad_choice
        # Apply default when user presses Enter with no input
        [[ -z "$ad_choice" && -n "$_def_value" ]] && ad_choice="$_def_value"

        if [[ "$ad_choice" == "all" || "$ad_choice" == "ALL" ]]; then
            local all_ads=""
            for ((i=1; i<=aidx; i++)); do
                [[ -n "$all_ads" ]] && all_ads+=","
                all_ads+="${_AD_MAP[$i]}"
            done
            _focus_set_ad "$all_ads"
            echo -e "${GREEN}✓ AD set to: all (${aidx} domains)${NC}"
        elif [[ "$ad_choice" == *","* ]]; then
            local multi_ads=""
            local sel
            while IFS= read -r sel; do
                sel="${sel// /}"
                if [[ -n "$sel" && -n "${_AD_MAP[$sel]:-}" ]]; then
                    [[ -n "$multi_ads" ]] && multi_ads+=","
                    multi_ads+="${_AD_MAP[$sel]}"
                fi
            done < <(tr ',' '\n' <<< "$ad_choice")
            if [[ -n "$multi_ads" ]]; then
                _focus_set_ad "$multi_ads"
                local _ad_ct
                _ad_ct=$(tr ',' '\n' <<< "$multi_ads" | wc -l)
                echo -e "${GREEN}✓ AD set to: ${_ad_ct} domain(s)${NC}"
            fi
        elif [[ -n "$ad_choice" && -n "${_AD_MAP[$ad_choice]:-}" ]]; then
            _focus_set_ad "${_AD_MAP[$ad_choice]}"
            echo -e "${GREEN}✓ AD set to: ${_AD_MAP[$ad_choice]}${NC}"
        fi
    fi
}

# Change compartment — lists compartment tree, lets user pick
_env_select_compartment() {
    echo ""
    local tenancy_id="${TENANCY_ID:-}"
    [[ -z "$tenancy_id" ]] && tenancy_id=$(get_tenancy_id_from_compartment "$FOCUS_COMPARTMENT_ID")
    
    if display_compartment_selector "$tenancy_id" "$FOCUS_COMPARTMENT_ID"; then
        local _default_idx="${COMP_IDX_REV[$FOCUS_COMPARTMENT_ID]:-}"
        local _default_hint=""
        [[ -n "$_default_idx" ]] && _default_hint="${_default_idx}"
        echo -n -e "${CYAN}Select compartment number [${_default_hint:-Enter to cancel}]: ${NC}"
        local comp_choice
        read -r comp_choice
        [[ -z "$comp_choice" && -n "$_default_hint" ]] && comp_choice="$_default_hint"
        
        if [[ -n "$comp_choice" && -n "${COMP_IDX[$comp_choice]:-}" ]]; then
            local selected_id="${COMP_IDX[$comp_choice]}"
            local selected_data="${COMP_MAP[$selected_id]}"
            local selected_name="${selected_data%%|*}"
            _focus_set_compartment "$selected_id" "$selected_name"
            echo -e "${GREEN}✓ Compartment set to: $selected_name${NC}"
        fi
    fi
}

# Select/change OKE cluster — lists clusters in current compartment
_env_select_oke() {
    echo ""
    _step_init
    _step_active "OKE clusters"
    local clusters_json
    clusters_json=$(oci ce cluster list \
        --compartment-id "$FOCUS_COMPARTMENT_ID" \
        --region "${FOCUS_REGION:-$REGION}" \
        --all --output json 2>/dev/null)
    local _ekc
    _ekc=$(jq '.data | length' <<< "$clusters_json" 2>/dev/null || echo "0")
    _step_complete "OKE clusters(${_ekc})"
    _step_finish
    
    if [[ -z "$clusters_json" ]] || ! jq -e '.data[0]' <<< "$clusters_json" >/dev/null 2>&1; then
        echo -e "${YELLOW}No OKE clusters found in this compartment/region${NC}"
    else
        local cluster_count
        cluster_count=$(jq '.data | length' <<< "$clusters_json")
        echo ""
        _ui_subheader "OKE Clusters ($cluster_count)" 0
        local cidx=0
        declare -A _CLUSTER_MAP=()
        while IFS='|' read -r cname cid cstate; do
            ((cidx++))
            _CLUSTER_MAP[$cidx]="$cid|$cname"
            local _cc="$GREEN"
            [[ "$cstate" != "ACTIVE" ]] && _cc="$YELLOW"
            printf "  ${YELLOW}%2d${NC}) ${_cc}%-12s${NC} ${WHITE}%-40s${NC} ${GRAY}%s${NC}\n" "$cidx" "$cstate" "$cname" "$(_short_ocid "$cid")"
        done < <(jq -r '.data[] | "\(.name)|\(.id)|\(.["lifecycle-state"])"' <<< "$clusters_json" 2>/dev/null)
        
        echo ""
        echo -n -e "${CYAN}Select cluster number [Enter to cancel]: ${NC}"
        local cl_choice
        read -r cl_choice
        
        if [[ -n "$cl_choice" && -n "${_CLUSTER_MAP[$cl_choice]:-}" ]]; then
            local cl_id="${_CLUSTER_MAP[$cl_choice]%%|*}"
            local cl_name="${_CLUSTER_MAP[$cl_choice]#*|}"
            _focus_set_oke_cluster "$cl_id" "$cl_name" "selected"
            echo -e "${GREEN}✓ OKE Cluster set to: $cl_name${NC}"
        fi
    fi
}

# Select/change VCN — lists VCNs in current compartment
_env_select_vcn() {
    echo ""
    _step_init
    _step_active "VCNs"
    rm -f "$VCN_LIST_CACHE"
    fetch_vcn_list
    local _evc
    _evc=$(get_vcn_count)
    _step_complete "VCNs(${_evc})"
    _step_finish
    
    if [[ "${_evc:-0}" -eq 0 ]]; then
        echo -e "${YELLOW}No VCNs found in this compartment${NC}"
    else
        echo ""
        _ui_subheader "VCNs (${_evc})" 0
        local vidx=0
        declare -A _VCN_MAP=()
        while IFS='|' read -r vid vname vcidr vstate _; do
            [[ "$vid" =~ ^#.*$ ]] && continue
            [[ -z "$vid" ]] && continue
            ((vidx++))
            _VCN_MAP[$vidx]="$vid|$vname"
            printf "  ${YELLOW}%2d${NC}) ${WHITE}%-35s${NC} ${CYAN}%-18s${NC} ${GREEN}%s${NC}\n" "$vidx" "$vname" "$vcidr" "$vstate"
        done < "$VCN_LIST_CACHE"
        
        echo ""
        echo -n -e "${CYAN}Select VCN number [Enter to cancel]: ${NC}"
        local vcn_choice
        read -r vcn_choice
        
        if [[ -n "$vcn_choice" && -n "${_VCN_MAP[$vcn_choice]:-}" ]]; then
            local v_id="${_VCN_MAP[$vcn_choice]%%|*}"
            local v_name="${_VCN_MAP[$vcn_choice]#*|}"
            _focus_set_vcn "$v_id" "$v_name" "selected"
            echo -e "${GREEN}✓ VCN set to: $v_name${NC}"
        fi
    fi
}

#--------------------------------------------------------------------------------
# Environment Focus Dispatcher
# Routes env shortcuts to the appropriate action from any menu.
# Usage (in case statements):
#   env*|ENV*) _env_dispatch "$choice" ;;
#
# Shortcuts:
#   env           → Full environment focus menu
#   env c|comp    → Change compartment
#   env r|region  → Change region
#   env ad        → Change availability domain
#   env oke       → Select OKE cluster
#   env vcn       → Select VCN
#   env s|save    → Save focus to variables.sh
#--------------------------------------------------------------------------------
_env_dispatch() {
    local input="$1"
    # Strip "env" prefix and normalize
    local sub="${input#[eE][nN][vV]}"
    sub="${sub#[[:space:]]}"    # trim leading space
    sub="${sub,,}"              # lowercase
    
    case "$sub" in
        "")
            # Plain "env" → full menu
            manage_environment_focus
            ;;
        c|comp|compartment|3)
            _env_select_compartment
            ;;
        r|region|1)
            _env_select_region
            ;;
        ad|2)
            _env_select_ad
            ;;
        oke|cluster|4)
            _env_select_oke
            ;;
        vcn|5)
            _env_select_vcn
            ;;
        s|save)
            _focus_save_to_variables
            ;;
        *)
            echo -e "${YELLOW}Unknown env shortcut: ${WHITE}env ${sub}${NC}"
            echo -e "${GRAY}Available: env c (compartment), env r (region), env ad, env oke, env vcn, env s (save)${NC}"
            ;;
    esac
}

manage_environment_focus() {
    while true; do
        echo ""
        _ui_banner "ENVIRONMENT FOCUS" "$CYAN"
        _ui_breadcrumb "Environment Focus"
        echo ""
        _focus_display
        echo ""
        
        _ui_actions
        echo -e "  ${YELLOW}1${NC}|${YELLOW}r${NC})   Change Region"
        echo -e "  ${YELLOW}2${NC}|${YELLOW}ad${NC})  Change Availability Domain"
        echo -e "  ${YELLOW}3${NC}|${YELLOW}c${NC})   Change Compartment"
        if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
            echo -e "  ${YELLOW}4${NC}|${YELLOW}oke${NC}) Change OKE Cluster"
            echo -e "  ${RED}4c${NC})    Clear OKE Cluster"
        else
            echo -e "  ${YELLOW}4${NC}|${YELLOW}oke${NC}) Select OKE Cluster"
        fi
        if [[ -n "$FOCUS_VCN_OCID" ]]; then
            echo -e "  ${YELLOW}5${NC}|${YELLOW}vcn${NC}) Change VCN"
            echo -e "  ${RED}5c${NC})    Clear VCN"
        else
            echo -e "  ${YELLOW}5${NC}|${YELLOW}vcn${NC}) Select VCN"
        fi
        echo ""
        echo -e "  ${GREEN}s${NC}) Save focus to variables.sh"
        echo -e "  ${CYAN}b${NC}) Back"
        echo ""
        echo -e "  ${GRAY}Tip: Use ${WHITE}env c${GRAY}, ${WHITE}env r${GRAY}, ${WHITE}env oke${GRAY}, ${WHITE}env vcn${GRAY} from any menu to quick-switch${NC}"
        echo ""
        _ui_prompt "Focus" "1-5, r, c, ad, oke, vcn, s, b"
        local input
        read -r input
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        
        case "$input" in
            1|r|region)
                _env_select_region
                ;;
            2|ad)
                _env_select_ad
                ;;
            3|c|comp|compartment)
                _env_select_compartment
                ;;
            4|oke|cluster)
                _env_select_oke
                ;;
            4c|4C)
                if [[ -n "$FOCUS_OKE_CLUSTER_ID" ]]; then
                    _focus_clear_oke
                    echo -e "${GREEN}✓ OKE Cluster focus cleared${NC}"
                fi
                ;;
            5|vcn)
                _env_select_vcn
                ;;
            5c|5C)
                if [[ -n "$FOCUS_VCN_OCID" ]]; then
                    _focus_clear_vcn
                    echo -e "${GREEN}✓ VCN focus cleared${NC}"
                fi
                ;;
            s|S)
                _focus_save_to_variables
                ;;
            b|B|"")
                return
                ;;
            show|SHOW)
                continue
                ;;
        esac
    done
}

