_menu_network() {
    local direct_choice="${1:-}"
    while true; do
        local choice
        if [[ -n "$direct_choice" ]]; then
            choice="$direct_choice"
            direct_choice=""
        else
            # Derive VCN from OKE cluster if focused (lazy, cached)
            if [[ -n "$FOCUS_OKE_CLUSTER_ID" && -z "$FOCUS_VCN_OCID" ]]; then
                _focus_derive_vcn_from_oke
            fi
            
            # Auto-enter if OKE or VCN is focused
            if [[ -n "$FOCUS_VCN_OCID" ]]; then
                manage_network_resources
                [[ -n "${_NAV_JUMP:-}" ]] && return
                return
            fi
            
            # No VCN focused — show VCN picker (ignore any direct_choice from :n#)
            direct_choice=""
            
            echo ""
            _ui_banner "NETWORK" "$MAGENTA"
            _ui_breadcrumb "Network"
            echo ""
            _focus_display
            echo ""
            
            local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
            
            _step_init
            _step_active "VCNs"
            fetch_vcn_list
            local _vcn_ct
            _vcn_ct=$(get_vcn_count)
            _step_complete "${_vcn_ct} VCNs"
            _step_finish
            
            if [[ "${_vcn_ct:-0}" -eq 0 ]]; then
                echo -e "  ${YELLOW}No VCNs found in compartment${NC}"
                echo ""
                _ui_prompt "Network" "env [c|r|oke|vcn], b"
                read -r choice
                case "$choice" in
                    env*|ENV*) _env_dispatch "$choice"; continue ;;
                    :*) _nav_try_jump "$choice" && return ;;
                    *) return ;;
                esac
                continue
            fi
            
            # Display VCN table
            echo ""
            printf "  ${BOLD}%-5s %-40s %-20s %-12s %s${NC}\n" \
                "ID" "VCN Name" "CIDR Block" "State" "VCN OCID"
            print_separator 130
            
            declare -A _VCN_MAP=()
            local _vidx=0
            while IFS='|' read -r _vid _vname _vcidr _vstate _; do
                [[ "$_vid" =~ ^#.*$ ]] && continue
                [[ -z "$_vid" ]] && continue
                ((_vidx++))
                _VCN_MAP["i${_vidx}"]="${_vid}|${_vname}"
                local _sc; _sc=$(color_resource_state "$_vstate")
                printf "  ${YELLOW}%-5s${NC} %-40s %-20s ${_sc}%-12s${NC} ${GRAY}%s${NC}\n" \
                    "i${_vidx}" "${_vname:0:40}" "$_vcidr" "$_vstate" "$_vid"
            done < "$VCN_LIST_CACHE"
            
            echo ""
            echo -e "  ${GRAY}${_vidx} VCNs │ Select a VCN to view network resources${NC}"
            echo ""
            _ui_actions
            echo ""
            echo -e "  ${YELLOW}i#${NC} or ${YELLOW}#${NC}${WHITE})${NC}  Select VCN (e.g., ${YELLOW}i1${NC} or ${YELLOW}1${NC})"
            echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh VCN list"
            echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
            echo ""
            _ui_prompt "Network" "i# or #, r, env [c|r|oke|vcn], b"
            read -r choice
        fi
        
        case "$choice" in
            b|B|"") return ;;
            r|R) rm -f "$VCN_LIST_CACHE"; continue ;;
            show|SHOW) continue ;;
            env*|ENV*) _env_dispatch "$choice" ;;
            :*) _nav_try_jump "$choice" && return ;;
            i[0-9]*)
                local _vsel="${choice#i}"
                if [[ -n "${_VCN_MAP[i${_vsel}]:-}" ]]; then
                    local _sel_vid="${_VCN_MAP[i${_vsel}]%%|*}"
                    local _sel_vname="${_VCN_MAP[i${_vsel}]#*|}"
                    _focus_set_vcn "$_sel_vid" "$_sel_vname" "selected"
                    manage_network_resources
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    # After returning, clear VCN focus so picker shows again
                    FOCUS_VCN_OCID=""
                    FOCUS_VCN_NAME=""
                    FOCUS_VCN_SOURCE=""
                    continue
                else
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                ;;
            [0-9]*)
                # Allow bare numbers too
                if [[ -n "${_VCN_MAP[i${choice}]:-}" ]]; then
                    local _sel_vid="${_VCN_MAP[i${choice}]%%|*}"
                    local _sel_vname="${_VCN_MAP[i${choice}]#*|}"
                    _focus_set_vcn "$_sel_vid" "$_sel_vname" "selected"
                    manage_network_resources
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    FOCUS_VCN_OCID=""
                    FOCUS_VCN_NAME=""
                    FOCUS_VCN_SOURCE=""
                    continue
                else
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                ;;
            *) echo -e "${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

