#--------------------------------------------------------------------------------
# Shape picker: enable/disable shapes for capacity report
# Shows categorized shapes with ✓/✗, supports multi-select toggle
#--------------------------------------------------------------------------------
_cap_shape_picker() {
    _cap_load_shapes
    
    # Build enabled set
    declare -A _enabled=()
    for _sh in "${_REPORT_SHAPES[@]}"; do
        _enabled["$_sh"]=1
    done
    
    # Categorize into 4 columns: VM | BM | BM GPU | VM GPU
    local -a _col_vm=() _col_bm=() _col_bg=() _col_vg=()
    for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
        case "$_sh" in
            VM.GPU*)       _col_vg+=("$_sh") ;;
            BM.GPU*)       _col_bg+=("$_sh") ;;
            VM.*)          _col_vm+=("$_sh") ;;
            BM.*)          _col_bm+=("$_sh") ;;
        esac
    done
    
    local _cw=30  # Column width
    
    while true; do
        echo ""
        echo -e "  ${BOLD}${WHITE}Capacity Report — Shape Selection${NC}"
        echo -e "  ${GRAY}Toggle shapes to include in capacity checks. Enabled shapes are queried per AD.${NC}"
        echo ""
        echo -e "  ${GREEN}✓${NC} = enabled (will be checked)    ${RED}✗${NC} = disabled (skipped)"
        echo ""
        
        # Assign sequential indices: VM → BM → BM GPU → VM GPU
        declare -A _IDX_MAP=()
        local -a _n_vm=() _n_bm=() _n_bg=() _n_vg=()
        local _si=0
        for _sh in "${_col_vm[@]}"; do ((_si++)); _IDX_MAP[$_si]="$_sh"; _n_vm+=("$_si"); done
        for _sh in "${_col_bm[@]}"; do ((_si++)); _IDX_MAP[$_si]="$_sh"; _n_bm+=("$_si"); done
        for _sh in "${_col_bg[@]}"; do ((_si++)); _IDX_MAP[$_si]="$_sh"; _n_bg+=("$_si"); done
        for _sh in "${_col_vg[@]}"; do ((_si++)); _IDX_MAP[$_si]="$_sh"; _n_vg+=("$_si"); done
        local _max_idx=$_si
        
        # Header
        printf "  ${BOLD}${CYAN}%-${_cw}s${NC} ${BOLD}${MAGENTA}%-${_cw}s${NC} ${BOLD}${GREEN}%-${_cw}s${NC} ${BOLD}${YELLOW}%-${_cw}s${NC}\n" \
            "VM (${#_col_vm[@]})" "BM (${#_col_bm[@]})" "BM GPU (${#_col_bg[@]})" "VM GPU (${#_col_vg[@]})"
        # Separator
        local _sep="" _si2
        for ((_si2=0; _si2<_cw; _si2++)); do _sep+="─"; done
        printf "  ${GRAY}%s %s %s %s${NC}\n" "$_sep" "$_sep" "$_sep" "$_sep"
        
        # Max column height
        local _max=${#_col_vm[@]}
        [[ ${#_col_bm[@]} -gt $_max ]] && _max=${#_col_bm[@]}
        [[ ${#_col_bg[@]} -gt $_max ]] && _max=${#_col_bg[@]}
        [[ ${#_col_vg[@]} -gt $_max ]] && _max=${#_col_vg[@]}
        
        local _lw=$((_cw - 7))  # label width: cw - "idx) ✓ "
        local _ri=0
        while [[ $_ri -lt $_max ]]; do
            echo -ne "  "
            # VM column
            if [[ $_ri -lt ${#_col_vm[@]} ]]; then
                local _sh="${_col_vm[$_ri]}"
                local _mark="${RED}✗${NC}"
                [[ -n "${_enabled[$_sh]:-}" ]] && _mark="${GREEN}✓${NC}"
                printf "${YELLOW}%-4s${NC} ${_mark} %-${_lw}s " "${_n_vm[$_ri]})" "${_sh:0:${_lw}}"
            else
                printf "%-${_cw}s " ""
            fi
            # BM column
            if [[ $_ri -lt ${#_col_bm[@]} ]]; then
                local _sh="${_col_bm[$_ri]}"
                local _mark="${RED}✗${NC}"
                [[ -n "${_enabled[$_sh]:-}" ]] && _mark="${GREEN}✓${NC}"
                printf "${YELLOW}%-4s${NC} ${_mark} %-${_lw}s " "${_n_bm[$_ri]})" "${_sh:0:${_lw}}"
            else
                printf "%-${_cw}s " ""
            fi
            # BM GPU column
            if [[ $_ri -lt ${#_col_bg[@]} ]]; then
                local _sh="${_col_bg[$_ri]}"
                local _mark="${RED}✗${NC}"
                [[ -n "${_enabled[$_sh]:-}" ]] && _mark="${GREEN}✓${NC}"
                printf "${YELLOW}%-4s${NC} ${_mark} %-${_lw}s " "${_n_bg[$_ri]})" "${_sh:0:${_lw}}"
            else
                printf "%-${_cw}s " ""
            fi
            # VM GPU column
            if [[ $_ri -lt ${#_col_vg[@]} ]]; then
                local _sh="${_col_vg[$_ri]}"
                local _mark="${RED}✗${NC}"
                [[ -n "${_enabled[$_sh]:-}" ]] && _mark="${GREEN}✓${NC}"
                printf "${YELLOW}%-4s${NC} ${_mark} %-${_lw}s" "${_n_vg[$_ri]})" "${_sh:0:${_lw}}"
            fi
            echo ""
            ((_ri++))
        done
        
        local _en_count=0
        for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
            [[ -n "${_enabled[$_sh]:-}" ]] && ((_en_count++))
        done
        
        echo ""
        echo -e "  ${WHITE}${_en_count}/${#_CAPACITY_ALL_SHAPES[@]} shapes enabled${NC}"
        echo ""
        echo -e "  ${GRAY}Toggle: ${WHITE}1${GRAY}, ${WHITE}1,3,5${GRAY}, ${WHITE}1-5${GRAY}  │  ${WHITE}gpu${GRAY} = GPU only  ${WHITE}all${GRAY} = enable all  ${WHITE}none${GRAY} = disable all${NC}"
        echo -e "  ${GRAY}${WHITE}o${GRAY}) Add shape by name  │  ${WHITE}d${GRAY}) Re-discover shapes from API  │  ${WHITE}Enter${GRAY} = save & back${NC}"
        echo ""
        _ui_prompt "Shape Selection" "1-${_max_idx}, gpu, all, none, o, d, Enter"
        
        local _input
        read -r _input
        
        case "${_input:-}" in
            "")
                # Save and return
                _REPORT_SHAPES=()
                for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                    [[ -n "${_enabled[$_sh]:-}" ]] && _REPORT_SHAPES+=("$_sh")
                done
                _cap_save_shapes
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                local _saved=${#_REPORT_SHAPES[@]}
                echo -e "  ${GREEN}✓ Saved ${_saved} shapes${NC}"
                sleep 0.5
                return
                ;;
            gpu|GPU)
                # Legacy shapes excluded from gpu preset — users can toggle individually
                local -a _gpu_excludes=("BM.GPU2.2" "BM.GPU3.8")
                _enabled=()
                for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                    [[ "$_sh" == *GPU* || "$_sh" == *gpu* ]] || continue
                    local _skip=false
                    for _ex in "${_gpu_excludes[@]}"; do
                        [[ "$_sh" == "$_ex" ]] && _skip=true && break
                    done
                    [[ "$_skip" == "false" ]] && _enabled["$_sh"]=1
                done
                ;;
            all|ALL)
                for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                    _enabled["$_sh"]=1
                done
                ;;
            none|NONE)
                _enabled=()
                ;;
            d|D)
                echo ""
                echo -e "  ${YELLOW}Re-discovering shapes from oci compute shape list...${NC}"
                rm -f "$COMPUTE_SHAPES_CACHE"
                _CAPACITY_ALL_SHAPES=()
                if _discover_shapes; then
                    # Preserve currently enabled shapes, re-categorize
                    _col_vm=(); _col_bm=(); _col_bg=(); _col_vg=()
                    for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                        case "$_sh" in
                            VM.GPU*)       _col_vg+=("$_sh") ;;
                            BM.GPU*)       _col_bg+=("$_sh") ;;
                            VM.*)          _col_vm+=("$_sh") ;;
                            BM.*)          _col_bm+=("$_sh") ;;
                        esac
                    done
                    echo -e "  ${GREEN}✓ Discovered ${#_CAPACITY_ALL_SHAPES[@]} shapes${NC}"
                else
                    echo -e "  ${RED}✗ Discovery failed — check permissions${NC}"
                fi
                sleep 0.5
                ;;
            o|O)
                echo ""
                echo -ne "  ${CYAN}Shape name to add: ${NC}"
                local _new_shape
                read -r _new_shape
                _new_shape=$(echo "$_new_shape" | tr -d ' ')
                if [[ -z "$_new_shape" ]]; then
                    continue
                fi
                # Check if already in list
                local _found=false
                for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                    [[ "$_sh" == "$_new_shape" ]] && _found=true
                done
                if [[ "$_found" == "true" ]]; then
                    echo -e "  ${YELLOW}$_new_shape already in shape list${NC}"
                    sleep 0.5
                else
                    _CAPACITY_ALL_SHAPES+=("$_new_shape")
                    _enabled["$_new_shape"]=1
                    # Re-categorize
                    _col_vm=(); _col_bm=(); _col_bg=(); _col_vg=()
                    for _sh in "${_CAPACITY_ALL_SHAPES[@]}"; do
                        case "$_sh" in
                            VM.GPU*)       _col_vg+=("$_sh") ;;
                            BM.GPU*)       _col_bg+=("$_sh") ;;
                            VM.*)          _col_vm+=("$_sh") ;;
                            BM.*)          _col_bm+=("$_sh") ;;
                        esac
                    done
                    echo -e "  ${GREEN}✓ Added $_new_shape${NC}"
                    sleep 0.5
                fi
                ;;
            *)
                # Parse targets using comma/range notation
                local _targets=()
                IFS=',' read -ra _parts <<< "$_input"
                for _p in "${_parts[@]}"; do
                    _p=$(echo "$_p" | tr -d ' ')
                    if [[ "$_p" == *-* ]]; then
                        local _start="${_p%-*}" _end="${_p#*-}"
                        if [[ "$_start" =~ ^[0-9]+$ && "$_end" =~ ^[0-9]+$ ]]; then
                            for ((_ti=_start; _ti<=_end; _ti++)); do
                                _targets+=("$_ti")
                            done
                        fi
                    elif [[ "$_p" =~ ^[0-9]+$ ]]; then
                        _targets+=("$_p")
                    fi
                done
                # Toggle each target
                for _t in "${_targets[@]}"; do
                    local _tsh="${_IDX_MAP[$_t]:-}"
                    [[ -z "$_tsh" ]] && continue
                    if [[ -n "${_enabled[$_tsh]:-}" ]]; then
                        unset '_enabled[$_tsh]'
                    else
                        _enabled["$_tsh"]=1
                    fi
                done
                ;;
        esac
    done
}


# Shapes initialized on demand by _cap_load_shapes() → _discover_shapes()

#================================================================================

parse_instance_targets() {
    local targets="$1"
    _PARSED_IDS=()
    _PARSED_OCIDS=()
    
    if ! _parse_targets "i" "$targets" "INSTANCE_INDEX_MAP"; then
        return 1
    fi
    
    # Map keys to OCIDs
    for _k in "${_SEL_KEYS[@]}"; do
        _PARSED_IDS+=("$_k")
        _PARSED_OCIDS+=("${INSTANCE_INDEX_MAP[$_k]}")
    done
    return 0
}

#--------------------------------------------------------------------------------
# Helper: Resolve K8s node name from OCI instance OCID
# Args: $1 = instance OCID, $2 = k8s_nodes_json
# Prints: k8s node name or empty string
#--------------------------------------------------------------------------------
resolve_k8s_node_name() {
    local ocid="$1" k8s_json="$2"
    [[ -z "$k8s_json" ]] && return
    jq -r --arg ocid "$ocid" \
        '.items[] | select(.spec.providerID | contains($ocid)) | .metadata.name' <<< "$k8s_json" 2>/dev/null | head -1
}

#--------------------------------------------------------------------------------
# Lookup instance attribute from instance list cache by OCID
# Args: $1 = OCID, $2 = cache file path (JSON), $3 = field name (e.g., "display-name")
#       $4 = fallback value (default: "N/A")
# Prints: field value or fallback
# NOTE: Reads from file (not variable) to avoid bash function parameter size limits
#       that silently fail with large OCI instance JSON responses (>100KB)
#--------------------------------------------------------------------------------
_inst_attr() {
    local _ocid="$1" _file="$2" _field="$3" _fallback="${4:-N/A}"
    [[ ! -f "$_file" ]] && { echo "$_fallback"; return 1; }
    jq -r --arg id "$_ocid" --arg field "$_field" --arg fb "$_fallback" \
        '.data[] | select(.id == $id) | .[$field] // $fb' "$_file" 2>/dev/null | head -1
}

#--------------------------------------------------------------------------------
# Log to a custom file in standard format: [timestamp] TYPE: message
# Args: $1 = log file, $2 = type (EXECUTE/SUCCESS/FAILED/WARNING/SKIPPED), $3 = message
# Also writes to ACTION_LOG_FILE as a secondary record
#--------------------------------------------------------------------------------
_log_to() {
    local _lf="$1" _type="$2" _msg="$3"
    local _ts; _ts=$(date '+%Y-%m-%d %H:%M:%S')
    echo "[${_ts}] ${_type}: ${_msg}" >> "$_lf" 2>/dev/null
}

#--------------------------------------------------------------------------------
# Execute K8s node operation with logging and result display
# Args: $1 = action (cordon|uncordon|drain|taint|untaint)
#       $2 = node name
#       $3 = log file path
#       $4 = extra args (for taint: "key=value:effect", for drain: custom flags)
# Returns: 0 on success, 1 on failure
# Sets: _K8S_RESULT (stdout of command for caller inspection)
#--------------------------------------------------------------------------------
_k8s_node_op() {
    local _action="$1" _node="$2" _logfile="$3" _extra="${4:-}"
    local _result _rc
    local -a _cmd_arr
    local _cmd_display

    case "$_action" in
        cordon)   _cmd_arr=(kubectl cordon "$_node"); _cmd_display="kubectl cordon ${_node}" ;;
        uncordon) _cmd_arr=(kubectl uncordon "$_node"); _cmd_display="kubectl uncordon ${_node}" ;;
        drain)
            _cmd_arr=(kubectl drain "$_node" --ignore-daemonsets --delete-emptydir-data)
            _cmd_display="kubectl drain ${_node} --ignore-daemonsets --delete-emptydir-data"
            if [[ -n "$_extra" ]]; then
                read -r -a _extra_arr <<< "$_extra"
                _cmd_arr+=("${_extra_arr[@]}")
                _cmd_display+=" $_extra"
            fi
            ;;
        taint)    _cmd_arr=(kubectl taint node "$_node" "$_extra"); _cmd_display="kubectl taint node ${_node} ${_extra}" ;;
        untaint)  _cmd_arr=(kubectl taint node "$_node" "${_extra}-"); _cmd_display="kubectl taint node ${_node} ${_extra}-" ;;
        *)        echo -e "${RED}Unknown K8s action: ${_action}${NC}"; return 1 ;;
    esac

    # Display + log the command
    echo -e "${GRAY}$ ${_cmd_display}${NC}"
    _log_to "$_logfile" "EXECUTE" "$_cmd_display"
    log_action "${_action^^}" "$_cmd_display" --quiet

    # Execute
    _K8S_RESULT=$("${_cmd_arr[@]}" 2>&1)
    _rc=$?
    
    if [[ $_rc -eq 0 ]]; then
        echo -e "  ${GREEN}✓ ${_action^} succeeded${NC}"
        _log_to "$_logfile" "SUCCESS" "${_action^} ${_node}"
        log_action_result "SUCCESS" "${_action^} ${_node}"
    else
        echo -e "  ${RED}✗ ${_action^} failed${NC}"
        _log_to "$_logfile" "FAILED" "${_action^} ${_node}: ${_K8S_RESULT}"
        log_action_result "FAILED" "${_action^} ${_node}"
    fi
    
    return $_rc
}

# Inspect a K8s node: labels, describe, logs, pods
# Args: $1 = action (labels|describe|logs|pods), $2 = k8s node name, $3 = search term (optional)
# Reusable from both --manage c 1 → i1 and --manage k 1 → np1
_k8s_node_inspect() {
    local _action="$1" _node="$2" _search="${3:-}"
    [[ -z "$_node" ]] && { echo -e "${RED}No K8s node name available${NC}"; return 1; }

    echo ""
    case "$_action" in
        labels)
            _ui_subheader "Labels: ${_node}" 0
            _ui_oci_cmd "kubectl get node ${_node} -o jsonpath='{.metadata.labels}' | jq ."
            _step_init; _step_active "labels"
            local _lbl_json
            _lbl_json=$(kubectl get node "$_node" -o jsonpath='{.metadata.labels}' 2>/dev/null)
            if [[ -z "$_lbl_json" ]]; then
                _step_complete "labels(failed)"; _step_finish
                echo -e "${RED}Failed to fetch labels${NC}"; return 1
            fi
            local _lc; _lc=$(jq 'keys | length' <<< "$_lbl_json" 2>/dev/null)
            _step_complete "labels(${_lc:-0})"; _step_finish
            echo ""
            if [[ -n "$_search" ]]; then
                echo -e "${WHITE}Filter:${NC} ${YELLOW}${_search}${NC}"
                jq -C '.' <<< "$_lbl_json" 2>/dev/null | grep -i --color=always "$_search"
                local _mc; _mc=$(jq -r 'to_entries[] | "\(.key)=\(.value)"' <<< "$_lbl_json" 2>/dev/null | grep -ic "$_search" || echo "0")
                echo -e "\n${GRAY}${_mc} matching label(s)${NC}"
            else
                jq -C '.' <<< "$_lbl_json" 2>/dev/null
            fi
            ;;
        describe)
            _ui_subheader "Describe: ${_node}" 0
            _ui_oci_cmd "kubectl describe node ${_node}"
            _step_init; _step_active "describe"
            local _desc_out
            _desc_out=$(kubectl describe node "$_node" 2>/dev/null)
            if [[ -z "$_desc_out" ]]; then
                _step_complete "describe(failed)"; _step_finish
                echo -e "${RED}Failed to describe node${NC}"; return 1
            fi
            _step_complete "describe"; _step_finish
            echo ""
            if [[ -n "$_search" ]]; then
                echo -e "${WHITE}Filter:${NC} ${YELLOW}${_search}${NC}"
                echo "$_desc_out" | grep -i --color=always -C 2 "$_search"
                local _mc; _mc=$(echo "$_desc_out" | grep -ic "$_search" || echo "0")
                echo -e "\n${GRAY}${_mc} matching line(s)${NC}"
            else
                echo "$_desc_out" | less -R 2>/dev/null || echo "$_desc_out"
            fi
            ;;
        logs)
            _ui_subheader "Logs: ${_node}" 0
            _ui_oci_cmd "kubectl get events --field-selector involvedObject.name=${_node}"
            _step_init; _step_active "events"
            local _events_out
            _events_out=$(kubectl get events --all-namespaces --field-selector "involvedObject.name=${_node}" --sort-by='.lastTimestamp' 2>/dev/null)
            if [[ -z "$_events_out" ]]; then
                _step_complete "events(0)"; _step_finish
                echo -e "${GRAY}No events found for this node${NC}"; return 0
            fi
            local _ec; _ec=$(echo "$_events_out" | tail -n +2 | wc -l)
            _step_complete "events(${_ec})"; _step_finish
            echo ""
            if [[ -n "$_search" ]]; then
                echo -e "${WHITE}Filter:${NC} ${YELLOW}${_search}${NC}"
                echo "$_events_out" | head -1
                echo "$_events_out" | tail -n +2 | grep -i --color=always "$_search"
                local _mc; _mc=$(echo "$_events_out" | grep -ic "$_search" || echo "0")
                echo -e "\n${GRAY}${_mc} matching event(s)${NC}"
            else
                echo "$_events_out"
            fi
            ;;
        pods)
            _ui_subheader "Running Pods on ${_node}" 0
            _ui_oci_cmd "kubectl get pods --all-namespaces --field-selector=spec.nodeName=${_node},status.phase=Running -o json"
            _step_init; _step_active "pods"
            local _pods_json
            _pods_json=$(kubectl get pods --all-namespaces --field-selector=spec.nodeName="$_node",status.phase=Running -o json 2>/dev/null)
            local _pc=0
            [[ -n "$_pods_json" ]] && _pc=$(jq '.items | length' <<< "$_pods_json" 2>/dev/null)
            [[ -z "$_pc" || "$_pc" == "null" ]] && _pc=0
            _step_complete "pods(${_pc})"; _step_finish
            echo ""
            if [[ "$_pc" -eq 0 ]]; then
                echo -e "  ${GRAY}No running pods found on this node${NC}"
            else
                local _ds_count
                _ds_count=$(jq '[.items[] | select(.metadata.ownerReferences[]?.kind == "DaemonSet")] | length' <<< "$_pods_json" 2>/dev/null)
                [[ -z "$_ds_count" ]] && _ds_count=0
                echo -e "  ${CYAN}${_pc}${NC} running pods (${_ds_count} DaemonSet)"
                echo ""
                printf "${BOLD}  %-30s %-20s %-12s %-10s %s${NC}\n" "NAME" "NAMESPACE" "STATUS" "RESTARTS" "TYPE"
                print_separator 90
                jq -r '.items[] |
                    (.metadata.ownerReferences[0].kind // "standalone") as $kind |
                    "\(.metadata.name)\t\(.metadata.namespace)\t\(.status.phase)\t\(.status.containerStatuses[0].restartCount // 0)\t\($kind)"
                ' <<< "$_pods_json" 2>/dev/null | sort -t$'\t' -k5,5 -k2,2 -k1,1 | while IFS=$'\t' read -r _pn _pns _ps _pr _pk; do
                    local _pkc="${GRAY}"
                    [[ "$_pk" == "DaemonSet" ]] && _pkc="${GRAY}" || _pkc="${CYAN}"
                    printf "  %-30s %-20s ${GREEN}%-12s${NC} %-10s ${_pkc}%s${NC}\n" "${_pn:0:30}" "${_pns:0:20}" "$_ps" "$_pr" "$_pk"
                done
            fi
            ;;
    esac
    echo ""
    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# _k8s_bulk_node_action — Cordon / Uncordon / Drain / Cordon-Drain K8s node(s)
# Centralized handler that both --manage c 1 and --manage o 3 call.
# Handles: preview table, pod counts (drain), command preview, confirmation,
#          execution via _k8s_node_op(), logging, and summary display.
# Args: $1 = action ("cordon"|"uncordon"|"drain"|"cordon-drain")
#       $2…N = pre-validated entries in "id|ocid|name|k8s_node" format
# Returns: 0 on action completed (success or partial), 1 on cancel/no entries
#--------------------------------------------------------------------------------
_k8s_bulk_node_action() {
    local action="$1"; shift
    local -a entries=("$@")

    [[ ${#entries[@]} -eq 0 ]] && {
        echo -e "${RED}No valid entries provided to _k8s_bulk_node_action${NC}"
        return 1
    }

    # Determine log file, labels, confirmation style
    local log_file action_label action_upper confirm_style drain_warning=""
    action_upper="${action^^}"
    action_upper="${action_upper//-/_}"
    case "$action" in
        cordon)
            action_label="Cordon K8s Nodes"
            log_file="${LOGS_DIR}/instance_cordon_actions.log"
            confirm_style="yN"
            ;;
        uncordon)
            action_label="Uncordon K8s Nodes"
            log_file="${LOGS_DIR}/instance_cordon_actions.log"
            confirm_style="yN"
            ;;
        drain)
            action_label="Drain K8s Nodes"
            log_file="${LOGS_DIR}/instance_drain_actions.log"
            confirm_style="yN"
            drain_warning="yes"
            ;;
        cordon-drain)
            action_label="Cordon & Drain K8s Nodes"
            log_file="${LOGS_DIR}/instance_cordon_drain_actions.log"
            confirm_style="yes"
            drain_warning="yes"
            ;;
        *)
            echo -e "${RED}Unknown bulk action: ${action}${NC}"
            return 1
            ;;
    esac
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    echo ""
    _ui_subheader "$action_label" 0
    echo ""

    # Preview table — show pod counts for drain/cordon-drain
    if [[ "$action" == "drain" || "$action" == "cordon-drain" ]]; then
        printf "  ${BOLD}%-5s %-45s %-40s %-8s %-10s${NC}\n" "ID" "Display Name" "K8s Node Name" "Status" "Pods"
        print_separator 115
    else
        printf "  ${BOLD}%-5s %-45s %-40s %-8s${NC}\n" "ID" "Display Name" "K8s Node Name" "Status"
        print_separator 105
    fi

    for entry in "${entries[@]}"; do
        local e_id e_ocid e_name e_node
        IFS='|' read -r e_id e_ocid e_name e_node <<< "$entry"
        if [[ "$action" == "drain" || "$action" == "cordon-drain" ]]; then
            local _pc="-"
            _pc=$(kubectl get pods --all-namespaces --field-selector "spec.nodeName=${e_node}" --no-headers 2>/dev/null | wc -l)
            [[ -z "$_pc" || "$_pc" == "0" ]] && _pc="0"
            printf "  ${YELLOW}%-5s${NC} %-45s ${CYAN}%-40s${NC} ${GREEN}%-8s${NC} ${WHITE}%-10s${NC}\n" "$e_id" "${e_name:0:45}" "$e_node" "Ready" "$_pc"
        else
            printf "  ${YELLOW}%-5s${NC} %-45s ${CYAN}%-40s${NC} ${GREEN}%-8s${NC}\n" "$e_id" "${e_name:0:45}" "$e_node" "Ready"
        fi
    done

    echo ""

    # Drain warning
    if [[ -n "$drain_warning" ]]; then
        echo -e "${YELLOW}⚠ Drain will evict all pods from the selected node(s).${NC}"
        echo -e "${GRAY}  Flags: --ignore-daemonsets --delete-emptydir-data --force --timeout=300s${NC}"
        echo -e "${GRAY}  PodDisruptionBudgets will be respected. Drain blocks until pods are evicted or timeout.${NC}"
        echo ""
    fi

    # Commands to execute
    _ui_subheader "Commands to Execute" 0
    for entry in "${entries[@]}"; do
        local e_node
        e_node=$(echo "$entry" | cut -d'|' -f4)
        case "$action" in
            cordon)       echo -e "  ${GRAY}kubectl cordon ${e_node}${NC}" ;;
            uncordon)     echo -e "  ${GRAY}kubectl uncordon ${e_node}${NC}" ;;
            drain)        echo -e "  ${GRAY}kubectl drain ${e_node} --ignore-daemonsets --delete-emptydir-data --force --timeout=300s${NC}" ;;
            cordon-drain) echo -e "  ${GRAY}kubectl cordon ${e_node} && kubectl drain ${e_node} --ignore-daemonsets --delete-emptydir-data --force --timeout=300s${NC}" ;;
        esac
    done
    echo ""

    # Confirm
    if [[ "$confirm_style" == "yes" ]]; then
        if ! _ui_confirm "yes" "${action} ${#entries[@]} node(s)"; then
            echo -e "${YELLOW}Cancelled${NC}"
            _ui_pause
            return 1
        fi
    else
        local _prompt_color="$CYAN"
        [[ "$action" == "drain" ]] && _prompt_color="$RED"
        echo -n -e "${_prompt_color}${action^} ${#entries[@]} node(s)? [y/N]: ${NC}"
        local _confirm
        read -r _confirm
        if [[ ! "$_confirm" =~ ^[Yy] ]]; then
            echo -e "${YELLOW}Cancelled${NC}"
            _ui_pause
            return 1
        fi
    fi

    echo ""
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== ${action_upper}: ${#entries[@]} node(s) =====" >> "$log_file"
    local ok=0 fail=0

    for entry in "${entries[@]}"; do
        local e_id e_ocid e_name e_node
        IFS='|' read -r e_id e_ocid e_name e_node <<< "$entry"

        echo -e "${WHITE}[${e_id}] ${e_name} → ${e_node}${NC}"

        if [[ "$action" == "cordon-drain" ]]; then
            # Step 1: Cordon
            if ! _k8s_node_op "cordon" "$e_node" "$log_file"; then
                echo -e "  ${RED}Cordon failed — skipping drain${NC}"
                ((fail++))
                echo ""
                continue
            fi
            # Step 2: Drain
            if _k8s_node_op "drain" "$e_node" "$log_file" "--force --timeout=300s"; then
                ((ok++))
            else
                echo -e "  ${YELLOW}Node remains cordoned${NC}"
                ((fail++))
            fi
        else
            local _extra=""
            [[ "$action" == "drain" ]] && _extra="--force --timeout=300s"
            if _k8s_node_op "$action" "$e_node" "$log_file" "$_extra"; then
                ((ok++))
            else
                ((fail++))
            fi
        fi
        echo ""
    done

    _ui_subheader "${action_label} Summary" 0
    echo -e "  ${GREEN}Succeeded:${NC} ${ok}  ${RED}Failed:${NC} ${fail}  ${WHITE}Total:${NC} ${#entries[@]}"
    echo -e "  ${GRAY}Log: ${log_file}${NC}"
    echo ""
    _ui_pause "refresh"
    return 0
}

#--------------------------------------------------------------------------------
# _k8s_taint_action — Apply or remove a taint on K8s node(s)
# Centralized handler for taint/untaint with type support (newNode / Maintenance).
# Handles: target parsing, node resolution, command preview, confirmation,
#          execution, logging, and summary display.
# Args: $1 = mode ("apply" or "remove")
#       $2 = taint string ("newNode=true:NoSchedule" or "Maintenance=true:NoSchedule")
#       $3 = taint label ("newNode" or "Maintenance")
#       $4 = target string ("i1", "i1,i3", "i1-i5", "all")
#       $5 = k8s nodes JSON variable
# Returns: 0 on action completed (success or partial), 1 on cancel/no targets
#--------------------------------------------------------------------------------
_k8s_taint_action() {
    local mode="$1" taint_str="$2" taint_label="$3" targets="$4" k8s_json="$5"
    local log_file="${LOGS_DIR}/instance_taint_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    if ! parse_instance_targets "$targets"; then
        echo -e "${RED}No valid instances selected. Use: taint [n|m] i1, taint [n|m] i1,i3, taint [n|m] all${NC}"
        sleep 2
        return 1
    fi

    local action_label suffix
    if [[ "$mode" == "apply" ]]; then
        action_label="Apply Taint"
        suffix=""
    else
        action_label="Remove Taint"
        suffix="-"
    fi

    echo ""
    _ui_subheader "${action_label}: ${taint_str}" 0
    echo ""

    # Resolve K8s node names and display
    declare -a _TAINT_VALID=()
    printf "  ${BOLD}%-5s %-45s %-40s %-8s${NC}\n" "ID" "Display Name" "K8s Node Name" "Status"
    print_separator 105

    for ti in "${!_PARSED_IDS[@]}"; do
        local t_iid="${_PARSED_IDS[$ti]}"
        local t_ocid="${_PARSED_OCIDS[$ti]}"
        local t_name
        t_name=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "display-name")
        local t_k8s_node
        t_k8s_node=$(resolve_k8s_node_name "$t_ocid" "$k8s_json")

        if [[ -z "$t_k8s_node" ]]; then
            printf "  ${YELLOW}%-5s${NC} %-45s ${RED}%-40s${NC} ${RED}%-8s${NC}\n" "$t_iid" "$t_name" "(not a node in current kubeconfig)" "Skip"
        else
            printf "  ${YELLOW}%-5s${NC} %-45s ${CYAN}%-40s${NC} ${GREEN}%-8s${NC}\n" "$t_iid" "$t_name" "$t_k8s_node" "Ready"
            _TAINT_VALID+=("$t_iid|$t_ocid|$t_name|$t_k8s_node")
        fi
    done

    if [[ ${#_TAINT_VALID[@]} -eq 0 ]]; then
        echo ""
        echo -e "${RED}No selected instances are K8s nodes in the current kubeconfig context${NC}"
        local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
        echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
        _ui_pause
        return 1
    fi

    echo ""
    _ui_subheader "Commands to Execute" 0
    for tv in "${_TAINT_VALID[@]}"; do
        local tv_node
        tv_node=$(echo "$tv" | cut -d'|' -f4)
        echo -e "  ${GRAY}kubectl taint node ${tv_node} ${taint_str}${suffix}${NC}"
    done
    echo ""
    echo -n -e "${CYAN}${action_label} on ${#_TAINT_VALID[@]} node(s)? [y/N]: ${NC}"
    local confirm
    read -r confirm

    if [[ ! "$confirm" =~ ^[Yy] ]]; then
        echo -e "${YELLOW}Cancelled${NC}"
        _ui_pause
        return 1
    fi

    echo ""
    local _mode_upper
    _mode_upper=$(echo "$mode" | tr '[:lower:]' '[:upper:]')
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== ${_mode_upper} TAINT: ${taint_str} on ${#_TAINT_VALID[@]} node(s) =====" >> "$log_file"
    local ok=0 fail=0

    for tv in "${_TAINT_VALID[@]}"; do
        IFS='|' read -r tv_iid tv_ocid tv_name tv_node <<< "$tv"
        local cmd="kubectl taint node ${tv_node} ${taint_str}${suffix}"

        echo -e "${WHITE}[${tv_iid}] ${tv_name} → ${tv_node}${NC}"
        echo -e "${GRAY}$ ${cmd}${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd}" >> "$log_file"

        local result
        result=$(_safe_exec "$cmd")
        if [[ $? -eq 0 ]]; then
            if [[ "$mode" == "apply" ]]; then
                echo -e "  ${GREEN}✓ Taint applied (${taint_label})${NC}"
            else
                echo -e "  ${GREEN}✓ Taint removed (${taint_label})${NC}"
            fi
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: ${mode^} ${taint_label} on ${tv_node} (${tv_name})" >> "$log_file"
            ((ok++))
        else
            if [[ "$mode" == "apply" && ("$result" == *"already has"* || "$result" == *"already exists"*) ]]; then
                echo -e "  ${YELLOW}⚠ Already tainted (${taint_label})${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SKIPPED: ${tv_node} already has ${taint_label} taint" >> "$log_file"
                ((ok++))
            elif [[ "$mode" == "remove" && "$result" == *"not found"* ]]; then
                echo -e "  ${YELLOW}⚠ Taint not present (${taint_label})${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SKIPPED: ${tv_node} ${taint_label} taint not found" >> "$log_file"
                ((ok++))
            else
                echo -e "  ${RED}✗ Failed: ${result}${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${mode^} ${taint_label} on ${tv_node}: ${result}" >> "$log_file"
                ((fail++))
            fi
        fi
    done

    echo ""
    _ui_subheader "${action_label} Summary" 0
    echo -e "  ${GREEN}Succeeded:${NC} ${ok}  ${RED}Failed:${NC} ${fail}"
    echo -e "  ${GRAY}Log: ${log_file}${NC}"
    echo ""
    _ui_pause "refresh"
    return 0
}

#--------------------------------------------------------------------------------
# Search instances in Compute Instances view (--manage c1)
# Searches across: name, state, shape, AD, OCID, K8s node name
# Supports: keyword search with BG_YELLOW highlighting, OCID paste for details
#--------------------------------------------------------------------------------
_compute_search_instances() {
    local k8s_lookup="$1"
    local pods_per_node="$2"
    
    # Pre-build searchable data: iid|name|state|shape|ad|ocid|k8s_node|cordon|taint|pods|time_created
    local search_data
    search_data=$(jq -r '
        .data[] |
        select(.["lifecycle-state"] != "TERMINATED") |
        "\(.["time-created"] // "N/A")|\(.["display-name"])|\(.["lifecycle-state"])|\(.shape)|\(.["availability-domain"])|\(.["fault-domain"] // "N/A")|\(.id)"
    ' "$INSTANCE_LIST_CACHE" 2>/dev/null | sort -t'|' -k1,1 | while IFS='|' read -r time_created name state shape ad fd ocid; do
        ((idx++))
        local iid="i${idx}"
        
        # K8s info
        local k8s_node="" k8s_status="No" cordon_status="-" taint_status="-" pod_count="-"
        local host_id="-" rack_id="-" serial_num="-"
        local k8s_match
        k8s_match=$(echo "$k8s_lookup" | grep -F "$ocid" 2>/dev/null)
        if [[ -n "$k8s_match" ]]; then
            k8s_node=$(echo "$k8s_match" | cut -d'|' -f2)
            local k8s_ready=$(echo "$k8s_match" | cut -d'|' -f3)
            local new_node_taint=$(echo "$k8s_match" | cut -d'|' -f4)
            local unschedulable=$(echo "$k8s_match" | cut -d'|' -f5)
            host_id=$(echo "$k8s_match" | cut -d'|' -f7)
            rack_id=$(echo "$k8s_match" | cut -d'|' -f8)
            serial_num=$(echo "$k8s_match" | cut -d'|' -f9)

            [[ "$k8s_ready" == "True" ]] && k8s_status="Ready" || k8s_status="NotRdy"
            [[ "$unschedulable" == "true" ]] && cordon_status="Yes"
            [[ "$new_node_taint" != "N/A" && -n "$new_node_taint" ]] && taint_status="newNode"

            local node_pods
            node_pods=$(echo "$pods_per_node" | grep "^${k8s_node}|" | cut -d'|' -f2)
            [[ -n "$node_pods" ]] && pod_count="$node_pods" || pod_count="0"
        fi

        local time_display="$time_created"
        if [[ "$time_display" != "N/A" && -n "$time_display" ]]; then
            time_display="${time_display:0:16}"
            time_display="${time_display/T/ }"
        fi

        # Shorten AD: e.g. "xxxx:US-ASHBURN-AD-1" → "AD1"
        local ad_short="-"
        if [[ "$ad" == *-AD-* ]]; then
            ad_short="AD${ad##*-AD-}"
        elif [[ "$ad" != "N/A" && -n "$ad" ]]; then
            ad_short="${ad##*:}"
        fi

        # Shorten FD values: FAULT-DOMAIN-1→FD1, FAULT-DOMAIN-2→FD2, FAULT-DOMAIN-3→FD3
        local fd_short="${fd}"
        fd_short="${fd_short/FAULT-DOMAIN-1/FD1}"
        fd_short="${fd_short/FAULT-DOMAIN-2/FD2}"
        fd_short="${fd_short/FAULT-DOMAIN-3/FD3}"

        local shape_trunc="${shape:0:20}"

        # Check compute host impact status
        local imp_indicator=" "
        if [[ -f "$COMPUTE_HOST_CACHE" ]]; then
            local _s_host_rec
            _s_host_rec=$(grep -F "$ocid" "$COMPUTE_HOST_CACHE" 2>/dev/null | head -1)
            if [[ -n "$_s_host_rec" ]]; then
                local _s_has_imp
                _s_has_imp=$(echo "$_s_host_rec" | cut -d'|' -f16)
                [[ "$_s_has_imp" == "true" ]] && imp_indicator="I"
            fi
        fi

        # Output: searchable_text|display fields
        echo "${iid}|${imp_indicator}|${name}|${state}|${k8s_status}|${cordon_status}|${taint_status}|${pod_count}|${shape_trunc}|${ad_short}|${fd_short}|${time_display}|${host_id}|${rack_id}|${serial_num}|${ocid}|${k8s_node}"
    done)
    
    while true; do
        echo ""
        local search_term="${3:-}"
        if [[ -z "$search_term" ]]; then
            _ui_prompt "Search Instances" "term, Enter=back"
            read -r search_term
            [[ "${search_term:-}" == :* ]] && _nav_try_jump "$search_term" && return
        fi
        # Clear inline term after first use so loop prompts
        set -- "$1" "$2" ""
        
        [[ -z "$search_term" ]] && return
        
        # If user pasted an instance OCID, show instance details
        if [[ "$search_term" == ocid1.instance.* ]]; then
            while true; do
                display_instance_details "$search_term"
                local ret=$?
                [[ -n "${_NAV_JUMP:-}" ]] && break
                [[ $ret -ne 2 ]] && break
            done
            [[ -n "${_NAV_JUMP:-}" ]] && return
            continue
        fi
        
        # Escape regex special characters
        local search_escaped
        search_escaped=$(printf '%s' "$search_term" | sed 's/[.[\*^$()+?{|\\]/\\&/g')
        
        # Filter matching lines (case-insensitive across all fields)
        local matched_lines
        matched_lines=$(echo "$search_data" | grep -i "$search_escaped" 2>/dev/null)
        
        local match_count=0
        [[ -n "$matched_lines" ]] && match_count=$(echo "$matched_lines" | grep -c . 2>/dev/null)
        
        echo ""
        _ui_subheader "Search Results: '${YELLOW}${search_term}${WHITE}' ($match_count matches)" 0
        echo ""
        
        if [[ "$match_count" -eq 0 ]]; then
            echo -e "  ${GRAY}No matches found for '${search_term}'${NC}"
            continue
        fi
        
        printf "${BOLD}${_INST_HDR_FMT}${NC}\n" "${_INST_HDR_ARGS[@]}"
        print_separator $_INST_SEP_WIDTH

        echo "$matched_lines" | while IFS='|' read -r iid imp_indicator name state k8s_status cordon_status taint_status pod_count shape_trunc ad_short fd_short time_display host_id rack_id serial_num ocid k8s_node; do
            [[ -z "$iid" ]] && continue

            # Build plain-text row (dynamic columns)
            local row
            row=$(_col_print_row_plain "INST" "$iid" "$imp_indicator" "${name:0:${_INST_COL_WIDTHS[2]}}" "${state:0:${_INST_COL_WIDTHS[3]}}" "$k8s_status" "$cordon_status" "$taint_status" "$pod_count" "$shape_trunc" "$ad_short" "$fd_short" "$time_display" "$host_id" "$rack_id" "$serial_num" "$ocid")
            
            # Apply BG_YELLOW highlight to matching text (case-insensitive)
            local highlighted
            highlighted=$(echo "$row" | sed -E "s/(${search_escaped})/\x1b[43m\1\x1b[0m/gI" 2>/dev/null)
            [[ -z "$highlighted" ]] && highlighted="$row"
            
            echo -e "$highlighted"
        done
        
        echo ""
        echo -e "  ${GRAY}Search again, paste an instance OCID for details, or press Enter to go back${NC}"
    done
}

#--------------------------------------------------------------------------------
# Search instances in Properties View (--manage c1, p)
# Searches across: name, state, shape, image, created by, cloud-init FP
#--------------------------------------------------------------------------------
_compute_search_properties() {
    local tmp_data="$1"
    local instances_json="$2"
    local _inline_term="${3:-}"
    
    if [[ ! -f "$tmp_data" ]]; then
        echo -e "${RED}No instance data to search${NC}"
        return
    fi
    
    # Uses CREATED_BY_NAME_CACHE from parent scope (display_instances_properties_view)
    
    while true; do
        echo ""
        local search_term="$_inline_term"
        if [[ -z "$search_term" ]]; then
            _ui_prompt "Search Properties" "term, Enter=back"
            read -r search_term
            [[ "${search_term:-}" == :* ]] && _nav_try_jump "$search_term" && return
        fi
        _inline_term=""  # Clear after first use
        
        [[ -z "$search_term" ]] && return
        
        # Escape regex special characters
        local search_escaped
        search_escaped=$(printf '%s' "$search_term" | sed 's/[.[\*^$()+?{|\\]/\\&/g')
        
        # For CreatedBy columns, we need to also search the resolved names
        # Build an augmented version: original line + resolved created_by appended
        local augmented_data=""
        augmented_data=$(while IFS='|' read -r name state shape ocpus memory gpus net_bw max_vnics bv_size bv_vpus image_name created_by created_on ci_fp _inst_ocid; do
            local resolved_by="$created_by"
            if [[ "$created_by" == ocid1.* && -n "${CREATED_BY_NAME_CACHE[$created_by]+x}" ]]; then
                resolved_by="${CREATED_BY_NAME_CACHE[$created_by]}"
            fi
            echo "${name}|${state}|${shape}|${ocpus}|${memory}|${gpus}|${net_bw}|${max_vnics}|${bv_size}|${bv_vpus}|${image_name}|${created_by}|${created_on}|${ci_fp}|${_inst_ocid}|${resolved_by}"
        done < <(sort -t'|' -k1,1 "$tmp_data"))
        
        # Filter matching lines (search against augmented data including resolved names)
        local matched_lines
        matched_lines=$(echo "$augmented_data" | grep -i "$search_escaped" 2>/dev/null)
        
        local match_count=0
        [[ -n "$matched_lines" ]] && match_count=$(echo "$matched_lines" | grep -c . 2>/dev/null)
        
        echo ""
        _ui_subheader "Search Results: '${YELLOW}${search_term}${WHITE}' ($match_count matches)" 0
        echo ""
        
        if [[ "$match_count" -eq 0 ]]; then
            echo -e "  ${GRAY}No matches found for '${search_term}'${NC}"
            continue
        fi
        
        printf "${BOLD}${_PROP_SEARCH_HDR_FMT}${NC}\n" "${_PROP_SEARCH_HDR_ARGS[@]}"
        print_separator $_PROP_SEARCH_SEP_WIDTH
        
        echo "$matched_lines" | while IFS='|' read -r name state shape ocpus memory gpus net_bw max_vnics bv_size bv_vpus image_name created_by created_on ci_fp _inst_ocid resolved_by; do
            [[ -z "$name" ]] && continue
            
            local gpu_disp="$gpus"
            [[ "$gpus" == "0" ]] && gpu_disp="-"
            
            local name_t="${name:0:${_PROP_COL_WIDTHS[1]}}"
            local state_t="${state:0:${_PROP_COL_WIDTHS[2]}}"
            local shape_t="${shape:0:${_PROP_COL_WIDTHS[3]}}"
            local created_by_display="${resolved_by:-$created_by}"
            # Truncate long CreatedBy — "..." prefix + last (width-3) chars
            local _cb_w=${_PROP_COL_WIDTHS[12]}
            local _cb_trunc=$((_cb_w - 3))
            if [[ $_cb_trunc -gt 0 && ${#created_by_display} -gt $_cb_trunc ]]; then
                created_by_display="...${created_by_display: -${_cb_trunc}}"
            fi

            # Build plain-text row (dynamic columns)
            local row
            row=$(_col_print_row_plain "PROP" "" "$name_t" "$state_t" "$shape_t" "$ocpus" "$memory" "$gpu_disp" "$net_bw" "$max_vnics" "$bv_size" "$bv_vpus" "$image_name" "$created_by_display" "$created_on" "$ci_fp")
            
            # Apply BG_YELLOW highlight to matching text (case-insensitive)
            local highlighted
            highlighted=$(echo "$row" | sed -E "s/(${search_escaped})/\x1b[43m\1\x1b[0m/gI" 2>/dev/null)
            [[ -z "$highlighted" ]] && highlighted="$row"
            
            echo -e "$highlighted"
        done
        
        echo ""
        echo -e "  ${GRAY}Search again or press Enter to go back${NC}"
    done
}

manage_compute_instances() {
    local filter_label="${1:-}"       # Optional: e.g., "GPU Cluster: fabric-tpqrq"
    local filter_ocids="${2:-}"       # Optional: pipe-separated instance OCIDs to filter to
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"

    # Migrate: add new columns to existing inst_columns.conf
    if [[ -f "$INST_COLUMNS_CONF" ]]; then
        if ! grep -q "^imp" "$INST_COLUMNS_CONF" 2>/dev/null; then
            sed -i '/^id$/a imp' "$INST_COLUMNS_CONF" 2>/dev/null
        fi
        if ! grep -q "^fd" "$INST_COLUMNS_CONF" 2>/dev/null; then
            sed -i '/^ad/a fd' "$INST_COLUMNS_CONF" 2>/dev/null
        fi
    fi

    while true; do
        echo ""
        if [[ -n "$filter_label" ]]; then
            _ui_menu_header "COMPUTE INSTANCE MANAGEMENT (${filter_label})" \
                --color "$YELLOW" \
                --breadcrumb "Compute" "Instances" \
                --cmd "oci compute instance list --compartment-id \$COMPARTMENT_ID --all (+ kubectl if instances found)" \
                --env \
                --cache \
                "${INSTANCE_LIST_CACHE}|Instances"
        else
            _ui_menu_header "COMPUTE INSTANCE MANAGEMENT" \
                --color "$YELLOW" \
                --breadcrumb "Compute" "Instances" \
                --cmd "oci compute instance list --compartment-id \$COMPARTMENT_ID --all (+ kubectl if instances found)" \
                --env \
                --cache \
                "${INSTANCE_LIST_CACHE}|Instances"
        fi
        [[ -n "$filter_label" ]] && echo -e "  ${CYAN}Filter:${NC}      ${YELLOW}${filter_label}${NC}"
        echo ""
        
        # ── Discovery ──
        _step_init

        # Fetch instances (with caching - TTL from CACHE_TTL_MAP)
        _step_active "instances"
        local instances_json _inst_cached=""
        if is_cache_fresh "$INSTANCE_LIST_CACHE"; then
            # Invalidate if any instance is in a transitional state
            if _cache_invalidate_if_transitional "$INSTANCE_LIST_CACHE" "" '.data[]."lifecycle-state"'; then
                : # fall through to fetch
            else
                local _cached_data
                _cached_data=$(cat "$INSTANCE_LIST_CACHE")
                # Skip cache if 0 instances — always revalidate to detect new instances
                local _cached_ct
                _cached_ct=$(jq '.data | length' <<< "$_cached_data" 2>/dev/null || echo "0")
                if [[ "${_cached_ct:-0}" -gt 0 ]]; then
                    instances_json="$_cached_data"
                    _inst_cached=" cached"
                fi
            fi
        fi
        local _inst_err="" _inst_err_file="" _inst_rc=0
        if [[ -z "$_inst_cached" ]]; then
            _inst_err_file=$(mktemp "${TEMP_DIR}/inst_err.XXXXXX") 2>/dev/null
            instances_json=$(oci compute instance list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --all \
                --output json 2>"$_inst_err_file") || _inst_rc=$?
            # OCI CLI returns empty stdout (no JSON) when compartment has 0 instances
            if [[ -z "$instances_json" && $_inst_rc -eq 0 ]]; then
                instances_json='{"data":[]}'
            fi
            if [[ -n "$instances_json" ]] && jq -e '.data' <<< "$instances_json" > /dev/null 2>&1; then
                echo "$instances_json" | _cache_write "$INSTANCE_LIST_CACHE"
            fi
        fi

        if [[ -z "$instances_json" ]] || ! jq -e '.data' <<< "$instances_json" > /dev/null 2>&1; then
            _step_complete "instances(failed)"
            _step_finish
            echo -e "${RED}Failed to fetch instances${NC}"
            _ui_policy_hint "read instances in compartment"
            echo -e "  ${WHITE}Command:${NC} ${GRAY}oci compute instance list --compartment-id \"${compartment_id}\" --region \"${region}\" --all --output json${NC}"
            # Try to extract error from: 1) stderr capture, 2) stdout JSON error, 3) stdout raw text
            local _err_msg=""
            if [[ -f "${_inst_err_file:-}" && -s "$_inst_err_file" ]]; then
                _err_msg=$(grep -oP '(?<=message: ).*' "$_inst_err_file" | head -1)
                [[ -z "$_err_msg" ]] && _err_msg=$(tail -3 "$_inst_err_file")
            fi
            if [[ -z "$_err_msg" && -n "$instances_json" ]]; then
                # OCI CLI may return error JSON on stdout: {"code":"...","message":"..."}
                _err_msg=$(jq -r '.message // .code // empty' <<< "$instances_json" 2>/dev/null)
                [[ -z "$_err_msg" ]] && _err_msg=$(echo "$instances_json" | head -5)
            fi
            [[ -n "$_err_msg" ]] && echo -e "  ${WHITE}Error:${NC}   ${GRAY}${_err_msg}${NC}"
            rm -f "${_inst_err_file:-}"
            echo ""
            _ui_pause "return"
            return
        fi
        rm -f "${_inst_err_file:-}"
        local _ic
        _ic=$(jq '.data | length' <<< "$instances_json" 2>/dev/null)
        _step_complete "instances(${_ic}${_inst_cached})"

        # No instances — skip k8s calls and show empty result
        if [[ "${_ic:-0}" -eq 0 ]]; then
            _step_finish
            echo ""
            echo -e "  ${YELLOW}No instances found in this compartment.${NC}"
            echo ""
            _ui_pause "return"
            return
        fi

        # Apply filter if provided (filter_ocids is pipe-separated list of instance OCIDs)
        if [[ -n "$filter_ocids" ]]; then
            instances_json=$(jq --arg ids "$filter_ocids" '
                .data |= [.[] | select(.id as $id | ($ids | split("|")) | index($id))]
            ' <<< "$instances_json" )
        fi

        # Build instance index map
        declare -A INSTANCE_INDEX_MAP=()
        local instance_idx=0

        # Fetch compute hosts (parallel, best-effort for impact indicator)
        _step_active "compute hosts"
        local _ch_cached=""
        if is_cache_fresh "$COMPUTE_HOST_CACHE"; then
            _ch_cached=" cached"
        else
            fetch_compute_hosts 2>/dev/null || true
            [[ -f "$COMPUTE_HOST_CACHE" ]] && _ch_cached="" || _ch_cached=" n/a"
        fi
        _step_complete "compute hosts($(_clc "$COMPUTE_HOST_CACHE" 2>/dev/null || echo "0")${_ch_cached})"

        # Fetch K8s data (only when instances exist)
        local _k8s_tmp="${TEMP_DIR}/k8s_nodes_$$" _pods_tmp="${TEMP_DIR}/k8s_pods_$$"
        _step_active "k8s nodes"
        (kubectl get nodes -o json > "$_k8s_tmp" 2>/dev/null) &
        local _k8s_pid=$!
        (kubectl get pods --all-namespaces --field-selector=status.phase=Running \
            -o custom-columns=NODE:.spec.nodeName --no-headers > "$_pods_tmp" 2>/dev/null) &
        local _pods_pid=$!
        wait "$_k8s_pid" 2>/dev/null
        wait "$_pods_pid" 2>/dev/null

        local k8s_nodes_json
        k8s_nodes_json=$(cat "$_k8s_tmp" 2>/dev/null)
        rm -f "$_k8s_tmp"

        # Process pods per node from background result (custom-columns = node names only, no JSON)
        local pods_per_node
        pods_per_node=$(sort "$_pods_tmp" 2>/dev/null | uniq -c | awk '{print $2"|"$1}')
        rm -f "$_pods_tmp"

        # Build lookup: providerID|nodeName|readyStatus|newNodeTaint|unschedulable|maintenanceTaint|hostId|rackId|serialNumber
        local k8s_lookup
        k8s_lookup=$(jq -r '
            .items[] |
            (.spec.taints // [] | map(select(.key == "newNode")) | if length > 0 then .[0].effect else "N/A" end) as $newNodeTaint |
            (.spec.taints // [] | map(select(.key == "Maintenance")) | if length > 0 then .[0].effect else "N/A" end) as $maintenanceTaint |
            (.spec.unschedulable // false) as $unschedulable |
            "\(.spec.providerID)|\(.metadata.name)|\(.status.conditions[] | select(.type=="Ready") | .status)|\($newNodeTaint)|\($unschedulable)|\($maintenanceTaint)|\(.metadata.labels["oci.oraclecloud.com/host.id"] // "-")|\(.metadata.labels["oci.oraclecloud.com/host.rack_id"] // "-")|\(.metadata.labels["oci.oraclecloud.com/host.serial_number"] // "-")"
        ' <<< "$k8s_nodes_json" 2>/dev/null)
        local _nc=$(echo "$k8s_lookup" | grep -c . 2>/dev/null || true)
        _step_complete "k8s nodes(${_nc})"
        _step_finish

        # ── Pre-build associative arrays for O(1) lookups (eliminates per-row subprocesses) ──
        # K8s lookup: key=instance OCID, value=full pipe-delimited k8s line
        declare -A _k8s_map=()
        while IFS='|' read -r _kpid _krest; do
            [[ -z "$_kpid" ]] && continue
            local _kocid="${_kpid##*/}"  # strip oci:// prefix if present
            [[ -n "$_kocid" ]] && _k8s_map["$_kocid"]="${_kpid}|${_krest}"
        done <<< "$k8s_lookup"

        # Pods per node: key=node name, value=pod count
        declare -A _pods_map=()
        while IFS='|' read -r _pn _pc; do
            [[ -n "$_pn" ]] && _pods_map["$_pn"]="$_pc"
        done <<< "$pods_per_node"

        # Compute host impact: key=instance OCID, value="true" if impacted
        declare -A _ch_imp_map=()
        if [[ -f "$COMPUTE_HOST_CACHE" ]]; then
            while IFS='|' read -r _ _ _ _ _ _ _ _chi_inst _ _ _ _ _ _ _ _chi_imp _ _ _; do
                [[ -n "$_chi_inst" && "$_chi_inst" != "N/A" && "$_chi_imp" == "true" ]] && _ch_imp_map["$_chi_inst"]="true"
            done < <(grep -v '^#' "$COMPUTE_HOST_CACHE" 2>/dev/null)
        fi

        # Display instances table
        _ui_subheader "Instances" 0
        echo ""
        _col_build_fmt "INST"
        printf "${BOLD}${_INST_HDR_FMT}${NC}\n" "${_INST_HDR_ARGS[@]}"
        print_separator $_INST_SEP_WIDTH

        # Sort by time-created (ascending - oldest first, newest last)
        # Uses process substitution (not pipeline) so the while loop runs in the main
        # shell — this lets us populate INSTANCE_INDEX_MAP directly and avoids the
        # subshell overhead of a pipeline. All per-row lookups use pre-built associative
        # arrays (_k8s_map, _pods_map, _ch_imp_map) instead of spawning grep/cut per row.
        while IFS='|' read -r time_created name state shape ad fd ocid; do
            ((instance_idx++))
            local iid="i${instance_idx}"

            # Store in map directly (no temp file needed — we're in the main shell)
            INSTANCE_INDEX_MAP[$iid]="$ocid"

            # Color state
            local state_color
            state_color=$(color_oci_state "$state")

            # Check if in K8s and get taint/cordon info
            local k8s_status="No"
            local k8s_color="$YELLOW"
            local cordon_status="-"
            local cordon_color="$GRAY"
            local taint_status="-"
            local taint_color="$GRAY"
            local pod_count="-"
            local pod_color="$GRAY"
            local k8s_node_name=""
            local host_id="-" rack_id="-" serial_num="-"

            # O(1) associative array lookup instead of grep per row
            local k8s_match="${_k8s_map[$ocid]:-}"

            if [[ -n "$k8s_match" ]]; then
                local k8s_ready unschedulable new_node_taint maintenance_taint _discard_pid
                IFS='|' read -r _discard_pid k8s_node_name k8s_ready new_node_taint unschedulable maintenance_taint host_id rack_id serial_num <<< "$k8s_match"

                if [[ "$k8s_ready" == "True" ]]; then
                    k8s_status="Ready"
                    k8s_color="$GREEN"
                else
                    k8s_status="NotRdy"
                    k8s_color="$RED"
                fi

                # Check cordon status
                if [[ "$unschedulable" == "true" ]]; then
                    cordon_status="Yes"
                    cordon_color="$YELLOW"
                else
                    cordon_status="-"
                    cordon_color="$GRAY"
                fi

                # Check taints: newNode (n) and Maintenance (m)
                local _has_n="false" _has_m="false"
                [[ "$new_node_taint" != "N/A" && -n "$new_node_taint" ]] && _has_n="true"
                [[ "$maintenance_taint" != "N/A" && -n "$maintenance_taint" ]] && _has_m="true"
                if [[ "$_has_n" == "true" && "$_has_m" == "true" ]]; then
                    taint_status="n,m"
                    taint_color="$CYAN"
                elif [[ "$_has_n" == "true" ]]; then
                    taint_status="newNode"
                    taint_color="$CYAN"
                elif [[ "$_has_m" == "true" ]]; then
                    taint_status="maint"
                    taint_color="$MAGENTA"
                fi

                # O(1) pod count lookup instead of grep per row
                local node_pods="${_pods_map[$k8s_node_name]:-}"
                if [[ -n "$node_pods" ]]; then
                    pod_count="$node_pods"
                    pod_color="$CYAN"
                else
                    pod_count="0"
                    pod_color="$GRAY"
                fi
            fi

            # Show full name, truncate shape if needed
            local shape_trunc="${shape:0:20}"
            # Shorten AD: e.g. "xxxx:US-ASHBURN-AD-1" → "AD1"
            local ad_short="-"
            if [[ "$ad" == *-AD-* ]]; then
                ad_short="AD${ad##*-AD-}"
            elif [[ "$ad" != "N/A" && -n "$ad" ]]; then
                ad_short="${ad##*:}"
            fi

            # Shorten FD values: FAULT-DOMAIN-1→FD1, FAULT-DOMAIN-2→FD2, FAULT-DOMAIN-3→FD3
            local fd_short="${fd}"
            fd_short="${fd_short/FAULT-DOMAIN-1/FD1}"
            fd_short="${fd_short/FAULT-DOMAIN-2/FD2}"
            fd_short="${fd_short/FAULT-DOMAIN-3/FD3}"

            # Format time_created - show date and time portion
            local time_display="$time_created"
            if [[ "$time_display" != "N/A" && -n "$time_display" ]]; then
                # Format: 2026-01-27T03:29:11.123Z -> 2026-01-27 03:29
                time_display="${time_display:0:16}"
                time_display="${time_display/T/ }"
            fi

            # O(1) compute host impact lookup instead of grep per row
            local imp_indicator=" " imp_color="$NC"
            if [[ "${_ch_imp_map[$ocid]:-}" == "true" ]]; then
                imp_indicator="I"
                imp_color="$LIGHT_RED"
            fi

            _col_print_row "INST" "$iid" "$imp_indicator" "${name:0:${_INST_COL_WIDTHS[2]}}" "${state:0:${_INST_COL_WIDTHS[3]}}" "$k8s_status" "$cordon_status" "$taint_status" "$pod_count" "$shape_trunc" "$ad_short" "$fd_short" "$time_display" "$host_id" "$rack_id" "$serial_num" "$ocid" "$state_color" "$k8s_color" "$cordon_color" "$taint_color" "$pod_color" "$imp_color"
        done < <(jq -r '
            .data[] |
            select(.["lifecycle-state"] != "TERMINATED") |
            "\(.["time-created"] // "N/A")|\(.["display-name"])|\(.["lifecycle-state"])|\(.shape)|\(.["availability-domain"])|\(.["fault-domain"] // "N/A")|\(.id)"
        ' <<< "$instances_json" 2>/dev/null | sort -t'|' -k1,1)
        
        local total_instances=${#INSTANCE_INDEX_MAP[@]}
        echo ""
        echo -e "${GRAY}Total: ${total_instances} instances (excluding TERMINATED)${NC}"
        # Show hidden columns hint
        local _hidden_cols=()
        declare -A _en_check=()
        for _ek in "${_INST_ENABLED_COLS[@]}"; do _en_check["$_ek"]=1; done
        for _ak in "${_INST_COL_KEYS[@]}"; do
            [[ -z "${_en_check[$_ak]:-}" ]] && _hidden_cols+=("$_ak")
        done
        if [[ ${#_hidden_cols[@]} -gt 0 ]]; then
            echo -e "${GRAY}Hidden columns: ${_hidden_cols[*]} — use 'col' to toggle${NC}"
        fi
        echo ""
        
        _ui_actions
        echo -e "  ${YELLOW}i#${NC} or ${YELLOW}ocid1...${NC} - View instance details (e.g., 'i1', 'i5', or paste OCID)"
        echo -e "  ${YELLOW}p${NC}          - View all instances with OCI properties (shape, mem, boot vol, cloud-init)"
        echo -e "  ${ORANGE}taint${NC}      - Apply taint: ${CYAN}taint n i1${NC} (newNode) ${CYAN}taint m i1${NC} (Maintenance) — supports i1,i3 / i1-i5 / all"
        echo -e "  ${ORANGE}untaint${NC}    - Remove taint: ${CYAN}untaint n i1${NC} (newNode) ${CYAN}untaint m i1${NC} (Maintenance) — same targets"
        echo -e "  ${ORANGE}cordon${NC}     - Cordon K8s node(s) (e.g., 'cordon i1', 'cordon i1,i3')"
        echo -e "  ${ORANGE}uncordon${NC}   - Uncordon K8s node(s) (e.g., 'uncordon i1', 'uncordon all')"
        echo -e "  ${ORANGE}drain${NC}      - Drain K8s node(s) — evict pods (e.g., 'drain i1', 'drain i1,i3', 'drain all')"
        echo -e "  ${RED}reboot${NC}     - Reboot instances (e.g., 'reboot i1', 'reboot i1,i3', 'reboot i1-i5', 'reboot all')"
        echo -e "  ${RED}cdt${NC}        - Cordon → Drain → Tag → Terminate (e.g., 'cdt i1', 'cdt i1-i5', 'cdt all')"
        echo -e "  ${RED}terminate${NC}  - Terminate instances (e.g., 'terminate i1,i3' or 'terminate i1-i5' or 'terminate all')"
        echo -e "  ${GREEN}bvr${NC}        - Boot Volume Replacement (upgrade OKE nodes without reboot)"
        echo -e "  ${GREEN}brc${NC}        - Bulk RunCommand — execute commands across multiple instances with presets"
        echo -e "  ${MAGENTA}r${NC}          - Refresh instance list"
        echo -e "  ${CYAN}/${NC}          - Search instances (name, state, shape, OCID, K8s node)"
        echo -e "  ${CYAN}col${NC}        - Toggle column visibility"
        echo -e "  ${CYAN}back${NC}       - Return to main menu"
        echo ""
        _ui_prompt "Compute Instances" "i#, /, taint, untaint, cordon, uncordon, drain, reboot, cdt, terminate, p, col, bvr, brc, r, back, show"
        
        local input
        read -r input
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        
        # Empty input goes back
        if [[ -z "$input" ]]; then
            return
        fi

        # Show menu again
        [[ "$input" == "show" || "$input" == "SHOW" ]] && continue
        
        #----------------------------------------------------------------------
        # Taint: Apply newNode or Maintenance taint
        # Usage: taint i1 / taint n i1 / taint m i1,i3 / taint m all
        #   n = newNode=true:NoSchedule (default when no type given)
        #   m = Maintenance=true:NoSchedule
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^taint[[:space:]]+(.+)$ ]]; then
            local _taint_rest="${BASH_REMATCH[1]}"
            local _taint_type="n" _taint_targets="$_taint_rest"
            # Check for type prefix: first word is a single letter
            if [[ "$_taint_rest" =~ ^([a-zA-Z])[[:space:]]+(.+)$ ]]; then
                local _taint_letter="${BASH_REMATCH[1],,}"
                if [[ "$_taint_letter" == "n" || "$_taint_letter" == "m" ]]; then
                    _taint_type="$_taint_letter"
                    _taint_targets="${BASH_REMATCH[2]}"
                else
                    echo -e "${RED}Invalid taint type '${BASH_REMATCH[1]}'. Use ${WHITE}n${RED} (newNode) or ${WHITE}m${RED} (Maintenance)${NC}"
                    echo -e "  ${GRAY}Example: taint n i1, taint m i1,i3, taint m all${NC}"
                    sleep 2
                    continue
                fi
            fi
            local _taint_str _taint_label
            if [[ "$_taint_type" == "m" ]]; then
                _taint_str="Maintenance=true:NoSchedule"
                _taint_label="Maintenance"
            else
                _taint_str="newNode=true:NoSchedule"
                _taint_label="newNode"
            fi
            _k8s_taint_action "apply" "$_taint_str" "$_taint_label" "$_taint_targets" "$k8s_nodes_json"
            continue
        fi
        
        #----------------------------------------------------------------------
        # Untaint: Remove newNode or Maintenance taint
        # Usage: untaint i1 / untaint n i1 / untaint m i1,i3 / untaint m all
        #   n = newNode=true:NoSchedule (default when no type given)
        #   m = Maintenance=true:NoSchedule
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^untaint[[:space:]]+(.+)$ ]]; then
            local _utaint_rest="${BASH_REMATCH[1]}"
            local _utaint_type="n" _utaint_targets="$_utaint_rest"
            # Check for type prefix: first word is a single letter
            if [[ "$_utaint_rest" =~ ^([a-zA-Z])[[:space:]]+(.+)$ ]]; then
                local _utaint_letter="${BASH_REMATCH[1],,}"
                if [[ "$_utaint_letter" == "n" || "$_utaint_letter" == "m" ]]; then
                    _utaint_type="$_utaint_letter"
                    _utaint_targets="${BASH_REMATCH[2]}"
                else
                    echo -e "${RED}Invalid taint type '${BASH_REMATCH[1]}'. Use ${WHITE}n${RED} (newNode) or ${WHITE}m${RED} (Maintenance)${NC}"
                    echo -e "  ${GRAY}Example: untaint n i1, untaint m i1,i3, untaint m all${NC}"
                    sleep 2
                    continue
                fi
            fi
            local _utaint_str _utaint_label
            if [[ "$_utaint_type" == "m" ]]; then
                _utaint_str="Maintenance=true:NoSchedule"
                _utaint_label="Maintenance"
            else
                _utaint_str="newNode=true:NoSchedule"
                _utaint_label="newNode"
            fi
            _k8s_taint_action "remove" "$_utaint_str" "$_utaint_label" "$_utaint_targets" "$k8s_nodes_json"
            continue
        fi
        
        #----------------------------------------------------------------------
        # Cordon: kubectl cordon node(s)
        # Usage: cordon i1 / cordon i1,i3 / cordon i1-i5 / cordon all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^cordon[[:space:]]+(.+)$ ]]; then
            local cordon_targets="${BASH_REMATCH[1]}"
            if ! parse_instance_targets "$cordon_targets"; then
                echo -e "${RED}No valid instances selected. Use: cordon i1, cordon i1,i3, cordon i1-i5, cordon all${NC}"
                sleep 2
                continue
            fi
            # Build validated entries and delegate to shared function
            local -a _cordon_entries=()
            for ti in "${!_PARSED_IDS[@]}"; do
                local t_iid="${_PARSED_IDS[$ti]}" t_ocid="${_PARSED_OCIDS[$ti]}"
                local t_name; t_name=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "display-name")
                local t_k8s_node; t_k8s_node=$(resolve_k8s_node_name "$t_ocid" "$k8s_nodes_json")
                if [[ -z "$t_k8s_node" ]]; then
                    printf "  ${YELLOW}%-5s${NC} %-45s ${RED}%-40s${NC} ${RED}%-8s${NC}\n" "$t_iid" "$t_name" "(not a node in current kubeconfig)" "Skip"
                else
                    _cordon_entries+=("$t_iid|$t_ocid|$t_name|$t_k8s_node")
                fi
            done
            if [[ ${#_cordon_entries[@]} -eq 0 ]]; then
                echo -e "${RED}No selected instances are K8s nodes in the current kubeconfig context${NC}"
                _ui_pause; continue
            fi
            _k8s_bulk_node_action "cordon" "${_cordon_entries[@]}"
            continue
        fi
        
        #----------------------------------------------------------------------
        # Uncordon: kubectl uncordon node(s)
        # Usage: uncordon i1 / uncordon i1,i3 / uncordon i1-i5 / uncordon all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^uncordon[[:space:]]+(.+)$ ]]; then
            local uncordon_targets="${BASH_REMATCH[1]}"
            if ! parse_instance_targets "$uncordon_targets"; then
                echo -e "${RED}No valid instances selected. Use: uncordon i1, uncordon i1,i3, uncordon i1-i5, uncordon all${NC}"
                sleep 2
                continue
            fi
            # Build validated entries and delegate to shared function
            local -a _uncordon_entries=()
            for ti in "${!_PARSED_IDS[@]}"; do
                local t_iid="${_PARSED_IDS[$ti]}" t_ocid="${_PARSED_OCIDS[$ti]}"
                local t_name; t_name=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "display-name")
                local t_k8s_node; t_k8s_node=$(resolve_k8s_node_name "$t_ocid" "$k8s_nodes_json")
                if [[ -z "$t_k8s_node" ]]; then
                    printf "  ${YELLOW}%-5s${NC} %-45s ${RED}%-40s${NC} ${RED}%-8s${NC}\n" "$t_iid" "$t_name" "(not a node in current kubeconfig)" "Skip"
                else
                    _uncordon_entries+=("$t_iid|$t_ocid|$t_name|$t_k8s_node")
                fi
            done
            if [[ ${#_uncordon_entries[@]} -eq 0 ]]; then
                echo -e "${RED}No selected instances are K8s nodes in the current kubeconfig context${NC}"
                _ui_pause; continue
            fi
            _k8s_bulk_node_action "uncordon" "${_uncordon_entries[@]}"
            continue
        fi
        
        #----------------------------------------------------------------------
        # Drain: kubectl drain node(s) (evict pods, respect PDBs)
        # Usage: drain i1 / drain i1,i3 / drain i1-i5 / drain all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^drain[[:space:]]+(.+)$ ]]; then
            local drain_targets="${BASH_REMATCH[1]}"
            if ! parse_instance_targets "$drain_targets"; then
                echo -e "${RED}No valid instances selected. Use: drain i1, drain i1,i3, drain i1-i5, drain all${NC}"
                sleep 2
                continue
            fi
            # Build validated entries and delegate to shared function
            local -a _drain_entries=()
            for ti in "${!_PARSED_IDS[@]}"; do
                local t_iid="${_PARSED_IDS[$ti]}" t_ocid="${_PARSED_OCIDS[$ti]}"
                local t_name; t_name=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "display-name")
                local t_k8s_node; t_k8s_node=$(resolve_k8s_node_name "$t_ocid" "$k8s_nodes_json")
                if [[ -z "$t_k8s_node" ]]; then
                    printf "  ${YELLOW}%-5s${NC} %-45s ${RED}%-40s${NC} ${RED}%-8s${NC}\n" "$t_iid" "$t_name" "(not a node in current kubeconfig)" "Skip"
                else
                    _drain_entries+=("$t_iid|$t_ocid|$t_name|$t_k8s_node")
                fi
            done
            if [[ ${#_drain_entries[@]} -eq 0 ]]; then
                echo -e "${RED}No selected instances are K8s nodes in the current kubeconfig context${NC}"
                _ui_pause; continue
            fi
            _k8s_bulk_node_action "drain" "${_drain_entries[@]}"
            continue
        fi
        
        #----------------------------------------------------------------------
        # CDT: Cordon → Drain → Tag → Terminate workflow
        # Usage: cdt i1 / cdt i1,i3 / cdt i1-i5 / cdt all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^cdt[[:space:]]+(.+)$ ]]; then
            local cdt_targets="${BASH_REMATCH[1]}"
            local cdt_log_file="${LOGS_DIR}/instance_cdt_actions.log"
            mkdir -p "$(dirname "$cdt_log_file")" 2>/dev/null
            
            if ! parse_instance_targets "$cdt_targets"; then
                echo -e "${RED}No valid instances selected. Use: cdt i1, cdt i1,i3, cdt i1-i5, cdt all${NC}"
                sleep 2
                continue
            fi
            
            echo ""
            echo -e "${RED}╔═══════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
            echo -e "${RED}║                            ⚠️  CORDON → DRAIN → TAG → TERMINATE  ⚠️                                        ║${NC}"
            echo -e "${RED}╚═══════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
            echo ""
            echo -e "${WHITE}This workflow will execute the following steps for each instance:${NC}"
            echo -e "  ${YELLOW}1.${NC} ${CYAN}Cordon${NC}    - Mark K8s node as unschedulable"
            echo -e "  ${YELLOW}2.${NC} ${CYAN}Drain${NC}     - Evict all pods (--ignore-daemonsets --delete-emptydir-data --force --timeout=300s)"
            echo -e "  ${YELLOW}3.${NC} ${CYAN}Tag${NC}       - Apply defined-tag ${MAGENTA}ComputeInstanceHostActions.CustomerReportedHostStatus=unhealthy${NC}"
            echo -e "  ${YELLOW}4.${NC} ${RED}Terminate${NC} - Terminate OCI instance (boot volume deleted)"
            echo ""
            
            # Build validated list
            declare -a CDT_VALID=()
            printf "  ${BOLD}%-5s %-45s %-40s %-9s %-8s %-10s${NC}\n" "ID" "Display Name" "K8s Node Name" "State" "Cordon" "Taint"
            print_separator 125
            
            for ti in "${!_PARSED_IDS[@]}"; do
                local t_iid="${_PARSED_IDS[$ti]}"
                local t_ocid="${_PARSED_OCIDS[$ti]}"
                local t_name t_state
                t_name=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "display-name")
                t_state=$(_inst_attr "$t_ocid" "$INSTANCE_LIST_CACHE" "lifecycle-state")
                
                local t_k8s_node=""
                local t_cordon_status="-"
                local t_taint_status="-"
                
                t_k8s_node=$(resolve_k8s_node_name "$t_ocid" "$k8s_nodes_json")
                
                if [[ -n "$t_k8s_node" ]]; then
                    # Get cordon and taint status
                    local k8s_match
                    k8s_match=$(echo "$k8s_lookup" | grep -F "$t_ocid" 2>/dev/null)
                    if [[ -n "$k8s_match" ]]; then
                        local unschedulable new_node_taint
                        new_node_taint=$(echo "$k8s_match" | cut -d'|' -f4)
                        unschedulable=$(echo "$k8s_match" | cut -d'|' -f5)
                        [[ "$unschedulable" == "true" ]] && t_cordon_status="Yes"
                        [[ "$new_node_taint" != "N/A" && -n "$new_node_taint" ]] && t_taint_status="newNode"
                    fi
                fi
                
                # Color state
                local state_color; state_color=$(color_oci_state "$t_state")
                local cordon_color="$GRAY"
                [[ "$t_cordon_status" == "Yes" ]] && cordon_color="$YELLOW"
                local taint_color="$GRAY"
                [[ "$t_taint_status" == "newNode" ]] && taint_color="$CYAN"
                
                local k8s_display="${t_k8s_node:-(not in K8s)}"
                local k8s_col="$CYAN"
                [[ -z "$t_k8s_node" ]] && k8s_col="$RED"
                
                printf "  ${YELLOW}%-5s${NC} %-45s ${k8s_col}%-40s${NC} ${state_color}%-9s${NC} ${cordon_color}%-8s${NC} ${taint_color}%-10s${NC}\n" \
                    "$t_iid" "$t_name" "$k8s_display" "${t_state:0:9}" "$t_cordon_status" "$t_taint_status"
                
                CDT_VALID+=("$t_iid|$t_ocid|$t_name|$t_state|$t_k8s_node")
            done
            
            if [[ ${#CDT_VALID[@]} -eq 0 ]]; then
                echo ""
                echo -e "${RED}No valid instances selected${NC}"
                _ui_pause
                continue
            fi
            
            # K8s warnings
            local cdt_no_k8s=0
            for tv in "${CDT_VALID[@]}"; do
                local tv_node
                tv_node=$(echo "$tv" | cut -d'|' -f5)
                [[ -z "$tv_node" ]] && ((cdt_no_k8s++))
            done
            if [[ $cdt_no_k8s -gt 0 ]]; then
                echo ""
                echo -e "${YELLOW}⚠ ${cdt_no_k8s} instance(s) not in K8s - cordon/drain steps will be skipped for those${NC}"
            fi
            
            echo ""
            echo -e "${RED}⚠️  WARNING: This will PERMANENTLY TERMINATE ${#CDT_VALID[@]} instance(s)!${NC}"
            echo -e "${RED}   Boot volumes will be deleted. This action cannot be undone!${NC}"
            echo ""
            if ! _ui_confirm "CDT" "confirm cordon-drain-tag-terminate of ${#CDT_VALID[@]} instance(s)"; then
                echo -e "${YELLOW}Cancelled${NC}"
                _ui_pause
                continue
            fi
            
            echo ""
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== CDT WORKFLOW: ${#CDT_VALID[@]} instance(s) =====" >> "$cdt_log_file"
            
            local cdt_success=0 cdt_fail=0
            
            for tv in "${CDT_VALID[@]}"; do
                IFS='|' read -r tv_iid tv_ocid tv_name tv_state tv_node <<< "$tv"
                
                _ui_subheader "[${tv_iid}] ${tv_name}" 0
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] --- CDT START: ${tv_name} (${tv_ocid}) ---" >> "$cdt_log_file"
                
                local cdt_abort=false
                
                # ── Step 1: Cordon ──
                if [[ -n "$tv_node" ]]; then
                    local cmd="kubectl cordon ${tv_node}"
                    echo -e "  ${CYAN}Step 1: Cordon${NC}"
                    echo -e "  ${GRAY}$ ${cmd}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd}" >> "$cdt_log_file"
                    
                    local result
                    result=$(_safe_exec "$cmd")
                    if [[ $? -eq 0 || "$result" == *"already cordoned"* ]]; then
                        echo -e "  ${GREEN}✓ Cordoned${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Cordoned ${tv_node}" >> "$cdt_log_file"
                    else
                        echo -e "  ${RED}✗ Cordon failed: ${result}${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Cordon ${tv_node}: ${result}" >> "$cdt_log_file"
                        echo -n -e "  ${YELLOW}Continue anyway? [y/N]: ${NC}"
                        local cordon_cont
                        read -r cordon_cont
                        if [[ ! "$cordon_cont" =~ ^[Yy] ]]; then
                            echo -e "  ${RED}Skipping this instance${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ABORTED: CDT for ${tv_name} (cordon failed)" >> "$cdt_log_file"
                            cdt_abort=true
                        fi
                    fi
                else
                    echo -e "  ${YELLOW}Step 1: Cordon - Skipped (not in K8s)${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SKIPPED: Cordon - ${tv_name} not in K8s" >> "$cdt_log_file"
                fi
                
                # ── Step 2: Drain ──
                if [[ "$cdt_abort" != "true" && -n "$tv_node" ]]; then
                    local cmd="kubectl drain ${tv_node} --ignore-daemonsets --delete-emptydir-data --force --timeout=300s"
                    echo -e "  ${CYAN}Step 2: Drain${NC}"
                    echo -e "  ${GRAY}$ ${cmd}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd}" >> "$cdt_log_file"
                    
                    echo -e "  ${YELLOW}Draining pods (timeout 300s)...${NC}"
                    local result
                    result=$(_safe_exec "$cmd")
                    local drain_exit=$?
                    
                    if [[ $drain_exit -eq 0 ]]; then
                        echo -e "  ${GREEN}✓ Drained${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Drained ${tv_node}" >> "$cdt_log_file"
                    else
                        echo -e "  ${RED}✗ Drain failed (exit code: ${drain_exit})${NC}"
                        echo -e "  ${GRAY}${result}${NC}" | tail -5
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Drain ${tv_node}: exit=${drain_exit}" >> "$cdt_log_file"
                        echo -n -e "  ${YELLOW}Continue to terminate anyway? [y/N]: ${NC}"
                        local drain_cont
                        read -r drain_cont
                        if [[ ! "$drain_cont" =~ ^[Yy] ]]; then
                            echo -e "  ${RED}Skipping this instance${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ABORTED: CDT for ${tv_name} (drain failed)" >> "$cdt_log_file"
                            cdt_abort=true
                        fi
                    fi
                elif [[ "$cdt_abort" != "true" ]]; then
                    echo -e "  ${YELLOW}Step 2: Drain - Skipped (not in K8s)${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SKIPPED: Drain - ${tv_name} not in K8s" >> "$cdt_log_file"
                fi
                
                # ── Step 3: Tag (ComputeInstanceHostActions.CustomerReportedHostStatus=unhealthy) ──
                if [[ "$cdt_abort" != "true" ]]; then
                    local tag_namespace="ComputeInstanceHostActions"
                    local tag_key="CustomerReportedHostStatus"
                    local tag_value="unhealthy"
                    
                    echo -e "  ${CYAN}Step 3: Tag${NC} ${MAGENTA}${tag_namespace}.${tag_key}=${tag_value}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] Step 3: Tag ${tag_namespace}.${tag_key}=${tag_value}" >> "$cdt_log_file"
                    
                    # Fetch current defined tags (preserve existing)
                    local inst_json
                    inst_json=$(oci compute instance get \
                        --instance-id "$tv_ocid" \
                        --region "${FOCUS_REGION:-$REGION}" \
                        --output json 2>/dev/null)
                    
                    if [[ -n "$inst_json" ]]; then
                        local current_defined_tags
                        current_defined_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$inst_json")
                        
                        # Merge new tag preserving all existing
                        local updated_defined_tags
                        updated_defined_tags=$(jq --arg ns "$tag_namespace" --arg key "$tag_key" --arg val "$tag_value" '
                            .[$ns] = ((.[$ns] // {}) + {($key): $val})
                        ' <<< "$current_defined_tags")
                        
                        local updated_tags_compact
                        updated_tags_compact=$(jq -c '.' <<< "$updated_defined_tags")
                        
                        local cmd="oci compute instance update --instance-id ${tv_ocid} --region ${FOCUS_REGION:-$REGION} --defined-tags '${updated_tags_compact}' --force"
                        echo -e "  ${GRAY}$ oci compute instance update --instance-id ${tv_ocid} \\${NC}"
                        echo -e "  ${GRAY}    --region ${FOCUS_REGION:-$REGION} --defined-tags '<merged-tags>' --force${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd}" >> "$cdt_log_file"
                        
                        local tag_result
                        log_action "UPDATE" "$cmd"
                        tag_result=$(oci compute instance update \
                            --instance-id "$tv_ocid" \
                            --region "${FOCUS_REGION:-$REGION}" \
                            --defined-tags "$updated_defined_tags" \
                            --force \
                            --output json 2>&1)
                        
                        if [[ $? -eq 0 ]]; then
                            # Verify the tag was applied
                            local applied_tag
                            applied_tag=$(jq -r --arg ns "$tag_namespace" --arg key "$tag_key" '.data["defined-tags"][$ns][$key] // "NOT_SET"' <<< "$tag_result" 2>/dev/null)
                            echo -e "  ${GREEN}✓ Tagged: ${MAGENTA}${tag_namespace}.${tag_key}${NC} = ${RED}${applied_tag}${NC}"
                            log_action_result "SUCCESS" "UPDATE operation"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Tagged ${tv_name} ${tag_namespace}.${tag_key}=${applied_tag}" >> "$cdt_log_file"
                        else
                            echo -e "  ${YELLOW}⚠ Tag failed (non-fatal): ${tag_result}${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] WARNING: Tag failed for ${tv_name}: ${tag_result}" >> "$cdt_log_file"
                            # Check if namespace doesn't exist
                            if echo "$tag_result" | grep -qi "TagDefinition\|TagNamespace\|does not exist"; then
                                echo -e "  ${YELLOW}  ↳ Tag namespace '${tag_namespace}' may not exist in this tenancy${NC}"
                            fi
                        fi
                    else
                        echo -e "  ${YELLOW}⚠ Could not fetch instance tags (non-fatal)${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] WARNING: Could not fetch tags for ${tv_name}" >> "$cdt_log_file"
                    fi
                fi
                
                # ── Step 4: Terminate ──
                if [[ "$cdt_abort" != "true" ]]; then
                    local _cdt_region
                    _cdt_region=$(_ocid_region "$tv_ocid" "${FOCUS_REGION:-$REGION}")
                    local cmd="oci compute instance terminate --instance-id ${tv_ocid} --region ${_cdt_region} --preserve-boot-volume false --force"
                    echo -e "  ${RED}Step 4: Terminate${NC}"
                    echo -e "  ${GRAY}$ ${cmd}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd}" >> "$cdt_log_file"

                    local result
                    log_action "TERMINATE" "$cmd"
                    result=$(oci compute instance terminate \
                        --instance-id "$tv_ocid" \
                        --region "$_cdt_region" \
                        --preserve-boot-volume false \
                        --force 2>&1)
                    if [[ $? -eq 0 ]]; then
                        echo -e "  ${GREEN}✓ Terminate initiated${NC}"
                        log_action_result "SUCCESS" "TERMINATE operation"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Terminated ${tv_name} (${tv_ocid})" >> "$cdt_log_file"
                        ((cdt_success++))
                    else
                        echo -e "  ${RED}✗ Terminate failed: ${result}${NC}"
                        log_action_result "FAILED" "TERMINATE operation"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Terminate ${tv_name}: ${result}" >> "$cdt_log_file"
                        ((cdt_fail++))
                    fi
                else
                    ((cdt_fail++))
                fi
                
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] --- CDT END: ${tv_name} ---" >> "$cdt_log_file"
                echo ""
            done
            
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== CDT COMPLETE: Success=${cdt_success} Failed=${cdt_fail} Total=${#CDT_VALID[@]} =====" >> "$cdt_log_file"
            _ui_subheader "CDT Workflow Complete" 0
            echo -e "  ${GREEN}Success:${NC} ${cdt_success}  ${RED}Failed/Skipped:${NC} ${cdt_fail}  ${WHITE}Total:${NC} ${#CDT_VALID[@]}"
            echo -e "  ${GRAY}Log: ${cdt_log_file}${NC}"
            echo ""
            rm -f "$INSTANCE_LIST_CACHE"
            _ui_pause "refresh"

            continue
        fi
        
        #----------------------------------------------------------------------
        # Reboot instances: reboot i1 / reboot i1,i3 / reboot i1-i5 / reboot all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^reboot[[:space:]]+(.+)$ ]]; then
            local reboot_targets="${BASH_REMATCH[1]}"
            local reboot_log_file="${LOGS_DIR}/instance_reboot_actions.log"
            mkdir -p "$(dirname "$reboot_log_file")" 2>/dev/null
            
            if ! parse_instance_targets "$reboot_targets"; then
                echo -e "${RED}No valid instances selected. Use: reboot i1, reboot i1,i3, reboot i1-i5, reboot all${NC}"
                sleep 2
                continue
            fi
            
            echo ""
            echo -e "${YELLOW}╔════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
            echo -e "${YELLOW}║                                       REBOOT INSTANCES                                       ║${NC}"
            echo -e "${YELLOW}╚════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
            echo ""
            
            declare -a reboot_valid=()
            
            printf "  ${BOLD}%-5s %-45s %-9s %-8s %-55s${NC}\n" "ID" "Display Name" "State" "K8s" "Instance OCID"
            print_separator 130
            
            for ri in "${!_PARSED_IDS[@]}"; do
                local r_iid="${_PARSED_IDS[$ri]}"
                local r_ocid="${_PARSED_OCIDS[$ri]}"
                local r_name r_state
                r_name=$(_inst_attr "$r_ocid" "$INSTANCE_LIST_CACHE" "display-name")
                r_state=$(_inst_attr "$r_ocid" "$INSTANCE_LIST_CACHE" "lifecycle-state")
                
                local r_k8s_status="No"
                if [[ -n "$k8s_nodes_json" ]]; then
                    local r_k8s_node
                    r_k8s_node=$(resolve_k8s_node_name "$r_ocid" "$k8s_nodes_json")
                    [[ -n "$r_k8s_node" ]] && r_k8s_status="Yes"
                fi
                
                local r_state_color; r_state_color=$(color_oci_state "$r_state")
                local r_k8s_color="$GRAY"; [[ "$r_k8s_status" == "Yes" ]] && r_k8s_color="$YELLOW"
                
                if [[ "$r_state" == "RUNNING" ]]; then
                    printf "  ${YELLOW}%-5s${NC} %-45s ${r_state_color}%-9s${NC} ${r_k8s_color}%-8s${NC} ${GRAY}%-55s${NC}\n" \
                        "$r_iid" "${r_name:0:45}" "${r_state:0:9}" "$r_k8s_status" "$r_ocid"
                    reboot_valid+=("${r_iid}|${r_ocid}|${r_name}|${r_state}|${r_k8s_status}")
                else
                    printf "  ${GRAY}%-5s %-45s %-9s %-8s %-55s${NC}  ${RED}(not RUNNING — skip)${NC}\n" \
                        "$r_iid" "${r_name:0:45}" "${r_state:0:9}" "$r_k8s_status" "$r_ocid"
                fi
            done
            
            if [[ ${#reboot_valid[@]} -eq 0 ]]; then
                echo ""
                echo -e "${RED}No instances in RUNNING state to reboot${NC}"
                echo ""
                _ui_pause
                continue
            fi
            
            # K8s node warning
            local r_k8s_count=0
            for rv in "${reboot_valid[@]}"; do
                [[ "$(echo "$rv" | cut -d'|' -f5)" == "Yes" ]] && ((r_k8s_count++))
            done
            if [[ $r_k8s_count -gt 0 ]]; then
                echo ""
                echo -e "${YELLOW}   ⚠️  ${r_k8s_count} instance(s) are Kubernetes nodes — pods will be disrupted!${NC}"
            fi
            
            # Choose reboot type
            echo ""
            echo -e "  ${CYAN}Reboot Type:${NC}"
            echo -e "    ${YELLOW}1${NC}) ${WHITE}RESET${NC}      - Hard reboot (immediate power cycle, like pressing the reset button)"
            echo -e "    ${YELLOW}2${NC}) ${WHITE}SOFTRESET${NC}  - Graceful reboot (ACPI shutdown → power on, gives OS time to clean up)"
            echo ""
            echo -n -e "  ${WHITE}Select reboot type [1=RESET, 2=SOFTRESET] (default: 2): ${NC}"
            local reboot_type_choice
            read -r reboot_type_choice
            local reboot_action="SOFTRESET"
            [[ "$reboot_type_choice" == "1" ]] && reboot_action="RESET"
            
            echo ""
            _ui_subheader "Commands to Execute (${reboot_action})" 0
            for rv in "${reboot_valid[@]}"; do
                local rv_idx rv_ocid rv_name
                IFS='|' read -r rv_idx rv_ocid rv_name _ _ <<< "$rv"
                local _rv_pre_region
                _rv_pre_region=$(_ocid_region "$rv_ocid" "${FOCUS_REGION:-$REGION}")
                echo -e "  ${GRAY}[${rv_idx}] oci compute instance action --action ${reboot_action} --instance-id ${rv_ocid} --region ${_rv_pre_region}${NC}"
            done
            echo ""
            if ! _ui_confirm "REBOOT" "confirm ${reboot_action} of ${#reboot_valid[@]} instance(s)"; then
                echo -e "${YELLOW}Reboot cancelled${NC}"
                echo ""
                _ui_pause
                continue
            fi

            # Execute reboots
            echo ""
            _ui_subheader "Executing Reboots (${reboot_action})" 0
            echo ""
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK REBOOT (${reboot_action}): ${#reboot_valid[@]} instance(s) =====" >> "$reboot_log_file"

            local reboot_success=0 reboot_fail=0
            for rv in "${reboot_valid[@]}"; do
                local rv_idx rv_ocid rv_name rv_state rv_k8s
                IFS='|' read -r rv_idx rv_ocid rv_name rv_state rv_k8s <<< "$rv"

                local _rv_region
                _rv_region=$(_ocid_region "$rv_ocid" "${FOCUS_REGION:-$REGION}")
                local reboot_cmd="oci compute instance action --action ${reboot_action} --instance-id ${rv_ocid} --region ${_rv_region}"

                echo -e "${WHITE}[${rv_idx}] ${rv_name}${NC}"
                echo -e "${GRAY}$ ${reboot_cmd}${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${reboot_cmd}" >> "$reboot_log_file"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')]   Instance: ${rv_name} (${rv_state}) K8s=${rv_k8s}" >> "$reboot_log_file"

                local reboot_result
                reboot_result=$(oci compute instance action \
                    --action "$reboot_action" \
                    --instance-id "$rv_ocid" \
                    --region "$_rv_region" \
                    --output json 2>&1)
                
                if [[ $? -eq 0 ]]; then
                    echo -e "  ${GREEN}✓ ${reboot_action} initiated: ${rv_name}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: ${reboot_action} ${rv_name} (${rv_ocid})" >> "$reboot_log_file"
                    ((reboot_success++))
                else
                    echo -e "  ${RED}✗ Failed to ${reboot_action}: ${rv_name}${NC}"
                    echo -e "  ${GRAY}${reboot_result}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${reboot_action} ${rv_name} (${rv_ocid}) - ${reboot_result}" >> "$reboot_log_file"
                    ((reboot_fail++))
                fi
                echo ""
            done
            
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK REBOOT COMPLETE: Success=${reboot_success} Failed=${reboot_fail} Total=${#reboot_valid[@]} =====" >> "$reboot_log_file"
            echo ""
            _ui_subheader "Reboot Complete" 0
            echo -e "  ${GREEN}Success:${NC} $reboot_success  ${RED}Failed:${NC} $reboot_fail  ${WHITE}Total:${NC} ${#reboot_valid[@]}"
            echo -e "  ${GRAY}Log:${NC} $reboot_log_file"
            echo ""
            rm -f "$INSTANCE_LIST_CACHE"
            _ui_pause "refresh"

            continue
        fi
        
        #----------------------------------------------------------------------
        # Terminate instances: terminate i1,i3 / terminate i1-i5 / terminate all
        #----------------------------------------------------------------------
        if [[ "$input" =~ ^terminate[[:space:]]+(.+)$ ]]; then
            local term_targets="${BASH_REMATCH[1]}"
            local term_log_file="${LOGS_DIR}/instance_terminate_actions.log"
            mkdir -p "$(dirname "$term_log_file")" 2>/dev/null
            
            # Parse targets using shared helper
            if ! _parse_targets "i" "$term_targets" "INSTANCE_INDEX_MAP"; then
                echo -e "${RED}No valid instances selected. Use: terminate i1,i3 or terminate i1-i5 or terminate all${NC}"
                sleep 2
                continue
            fi
            local -a term_indices=("${_SEL_KEYS[@]}")
            
            # Look up instance details for display
            echo ""
            echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
            echo -e "${RED}║                                   ⚠️  TERMINATE INSTANCES  ⚠️                                    ║${NC}"
            echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
            echo ""
            
            declare -a term_valid=()
            declare -a term_invalid=()
            
            printf "  ${BOLD}%-5s %-45s %-9s %-8s %-55s${NC}\n" "ID" "Display Name" "State" "K8s" "Instance OCID"
            print_separator 130
            
            for tidx in "${term_indices[@]}"; do
                local tocid="${INSTANCE_INDEX_MAP[$tidx]:-}"
                if [[ -z "$tocid" ]]; then
                    term_invalid+=("$tidx")
                    continue
                fi
                
                # Get instance name and state
                local tname tstate
                tname=$(_inst_attr "$tocid" "$INSTANCE_LIST_CACHE" "display-name")
                tstate=$(_inst_attr "$tocid" "$INSTANCE_LIST_CACHE" "lifecycle-state")
                
                # Check K8s membership
                local tk8s_status="No"
                if [[ -n "$k8s_nodes_json" ]]; then
                    local tk8s_node
                    tk8s_node=$(resolve_k8s_node_name "$tocid" "$k8s_nodes_json")
                    [[ -n "$tk8s_node" ]] && tk8s_status="Yes"
                fi
                
                # Color state
                local tstate_color
                tstate_color=$(color_oci_state "$tstate")
                local tk8s_color="$GRAY"
                [[ "$tk8s_status" == "Yes" ]] && tk8s_color="$YELLOW"
                
                printf "  ${YELLOW}%-5s${NC} %-45s ${tstate_color}%-9s${NC} ${tk8s_color}%-8s${NC} ${GRAY}%-55s${NC}\n" \
                    "$tidx" "${tname:0:45}" "${tstate:0:9}" "$tk8s_status" "$tocid"
                
                term_valid+=("$tidx|$tocid|$tname|$tstate|$tk8s_status")
            done
            
            [[ ${#term_invalid[@]} -gt 0 ]] && echo -e "${RED}Invalid IDs skipped: ${term_invalid[*]}${NC}"
            
            if [[ ${#term_valid[@]} -eq 0 ]]; then
                echo -e "${RED}No valid instances to terminate${NC}"
                echo ""
                _ui_pause
                continue
            fi
            
            # Show warnings
            echo ""
            echo -e "${RED}⚠️  WARNING: This will PERMANENTLY TERMINATE ${#term_valid[@]} instance(s)!${NC}"
            echo -e "${RED}   Boot volumes will also be deleted. This action cannot be undone!${NC}"
            
            # Check if any are K8s nodes
            local k8s_count=0
            for tv in "${term_valid[@]}"; do
                local tv_k8s
                tv_k8s=$(echo "$tv" | cut -d'|' -f5)
                [[ "$tv_k8s" == "Yes" ]] && ((k8s_count++))
            done
            if [[ $k8s_count -gt 0 ]]; then
                echo -e "${YELLOW}   ⚠️  ${k8s_count} instance(s) are Kubernetes nodes - consider draining first!${NC}"
            fi
            
            echo ""
            _ui_subheader "Commands to Execute" 0
            for tv in "${term_valid[@]}"; do
                local tv_idx tv_ocid tv_name
                IFS='|' read -r tv_idx tv_ocid tv_name _ _ <<< "$tv"
                local _tv_pre_region
                _tv_pre_region=$(_ocid_region "$tv_ocid" "${FOCUS_REGION:-$REGION}")
                echo -e "  ${GRAY}[${tv_idx}] oci compute instance terminate --instance-id ${tv_ocid} --region ${_tv_pre_region} --preserve-boot-volume false --force${NC}"
            done
            echo ""
            if ! _ui_confirm "TERMINATE" "confirm deletion of ${#term_valid[@]} instance(s)"; then
                echo -e "${YELLOW}Termination cancelled${NC}"
                echo ""
                _ui_pause
                continue
            fi
            
            # Execute terminations
            echo ""
            _ui_subheader "Executing Terminations" 0
            echo ""
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK TERMINATE: ${#term_valid[@]} instance(s) =====" >> "$term_log_file"
            
            local term_success=0 term_fail=0
            for tv in "${term_valid[@]}"; do
                local tv_idx tv_ocid tv_name tv_state tv_k8s
                IFS='|' read -r tv_idx tv_ocid tv_name tv_state tv_k8s <<< "$tv"
                
                local _tv_region
                _tv_region=$(_ocid_region "$tv_ocid" "${FOCUS_REGION:-$REGION}")
                local term_cmd="oci compute instance terminate --instance-id ${tv_ocid} --region ${_tv_region} --preserve-boot-volume false --force"

                echo -e "${WHITE}[${tv_idx}] ${tv_name}${NC}"
                echo -e "${GRAY}$ ${term_cmd}${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${term_cmd}" >> "$term_log_file"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')]   Instance: ${tv_name} (${tv_state}) K8s=${tv_k8s}" >> "$term_log_file"
                
                if _safe_exec "$term_cmd"; then
                    echo -e "  ${GREEN}✓ Terminate initiated: ${tv_name}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Terminated ${tv_name} (${tv_ocid})" >> "$term_log_file"
                    ((term_success++))
                else
                    echo -e "  ${RED}✗ Failed to terminate: ${tv_name}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Terminate ${tv_name} (${tv_ocid})" >> "$term_log_file"
                    ((term_fail++))
                fi
                echo ""
            done
            
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK TERMINATE COMPLETE: Success=${term_success} Failed=${term_fail} Total=${#term_valid[@]} =====" >> "$term_log_file"
            echo ""
            _ui_subheader "Terminate Complete" 0
            echo -e "  ${GREEN}Success:${NC} $term_success  ${RED}Failed:${NC} $term_fail  ${WHITE}Total:${NC} ${#term_valid[@]}"
            echo -e "  ${GRAY}Log:${NC} $term_log_file"
            echo ""
            rm -f "$INSTANCE_LIST_CACHE"
            _ui_pause "refresh"

            continue
        fi
        
        case "$input" in
            /*)
                _compute_search_instances "$k8s_lookup" "$pods_per_node" "${input#/}"
                ;;
            properties|PROPERTIES|props|p)
                display_instances_properties_view
                ;;
            col|COL|columns|COLUMNS)
                _col_picker "INST" "Compute Instances"
                continue
                ;;
            bvr|BVR)
                compute_boot_volume_replacement
                ;;
            brc|BRC)
                bulk_runcommand
                ;;
            r|R|refresh|REFRESH)
                rm -f "$INSTANCE_LIST_CACHE"
                echo -e "${YELLOW}Cache cleared, refreshing...${NC}"
                ;;
            quit|QUIT|q|Q|exit|EXIT|back|BACK|b|B)
                return
                ;;
            i[0-9]*)
                local instance_ocid="${INSTANCE_INDEX_MAP[$input]:-}"
                if [[ -z "$instance_ocid" ]]; then
                    echo -e "${RED}Invalid instance ID: $input${NC}"
                    sleep 1
                else
                    # Loop to handle refresh requests
                    while true; do
                        display_instance_details "$instance_ocid"
                        local ret=$?
                        [[ -n "${_NAV_JUMP:-}" ]] && break
                        [[ $ret -ne 2 ]] && break  # Exit loop unless refresh requested
                    done
                fi
                ;;
            ocid1.instance.*)
                # Direct OCID input - loop to handle refresh requests
                while true; do
                    display_instance_details "$input"
                    local ret=$?
                    [[ -n "${_NAV_JUMP:-}" ]] && break
                    [[ $ret -ne 2 ]] && break  # Exit loop unless refresh requested
                done
                ;;
            taint|untaint|cordon|uncordon|drain|reboot|cdt|terminate)
                echo -e "${YELLOW}Usage: ${input} i1, ${input} i1,i3, ${input} i1-i5, ${input} all${NC}"
                sleep 1
                ;;
            env*|ENV*)
                _env_dispatch "$input"
                ;;
            *)
                echo -e "${RED}Unknown command: $input${NC}"
                sleep 1
                ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

#--------------------------------------------------------------------------------
# Boot Volume Replacement (BVR) - Upgrade OKE nodes without reboot
# Uses: https://github.com/oracle-quickstart/oci-hpc-oke/blob/main/docs/files/bvr-script.py
#--------------------------------------------------------------------------------
compute_boot_volume_replacement() {
    local pre_selected_instance="${1:-}"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/bvr_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    echo ""
    _ui_menu_header "BOOT VOLUME REPLACEMENT (BVR)"
    echo ""
    echo -e "${GRAY}Replaces boot volumes on OKE worker nodes to change images or upgrade K8s without rebooting.${NC}"
    echo -e "${GRAY}Source: https://github.com/oracle-quickstart/oci-hpc-oke/blob/main/docs/files/bvr-script.py${NC}"
    echo ""
    
    #==========================================================================
    # Step 0: Ensure uv is installed
    #==========================================================================
    _ui_subheader "Checking Prerequisites" 0
    if ! command -v uv &>/dev/null; then
        # Check if uv is in $HOME/.local/bin (common install path) but not in PATH
        if [[ -f "$HOME/.local/bin/uv" ]]; then
            export PATH="$HOME/.local/bin:$PATH"
            echo -e "  ${GREEN}✓${NC} uv found at $HOME/.local/bin/uv (added to PATH)"
        else
            echo -e "  ${YELLOW}⚠ uv not found - installing...${NC}"
            curl -LsSf https://astral.sh/uv/install.sh | sh 2>/dev/null
            export PATH="$HOME/.local/bin:$PATH"
            if ! command -v uv &>/dev/null; then
                echo -e "  ${RED}✗ Failed to install uv${NC}"
                echo -e "  ${GRAY}Install manually: curl -LsSf https://astral.sh/uv/install.sh | sh${NC}"
                _ui_pause
                return
            fi
            echo -e "  ${GREEN}✓${NC} uv installed successfully"
        fi
    else
        echo -e "  ${GREEN}✓${NC} uv $(uv --version 2>/dev/null || echo 'installed')"
    fi
    
    #==========================================================================
    # Step 0b: Ensure bvr-script.py is available
    # NOTE: Downloads from Oracle's public quickstart repo (main branch)
    # Verify integrity after download if running in sensitive environments
    #==========================================================================
    local bvr_script="${HOME}/bvr-script.py"
    if [[ ! -f "$bvr_script" ]]; then
        echo -e "  ${YELLOW}⚠ bvr-script.py not found - downloading...${NC}"
        curl -sSL "https://raw.githubusercontent.com/oracle-quickstart/oci-hpc-oke/main/docs/files/bvr-script.py" -o "$bvr_script" 2>/dev/null
        if [[ ! -f "$bvr_script" || ! -s "$bvr_script" ]]; then
            echo -e "  ${RED}✗ Failed to download bvr-script.py${NC}"
            echo -e "  ${GRAY}Download manually from: https://github.com/oracle-quickstart/oci-hpc-oke/blob/main/docs/files/bvr-script.py${NC}"
            _ui_pause
            return
        fi
        echo -e "  ${GREEN}✓${NC} bvr-script.py downloaded to ${bvr_script}"
    else
        echo -e "  ${GREEN}✓${NC} bvr-script.py found at ${bvr_script}"
    fi
    echo ""
    
    #==========================================================================
    # Common arrays used downstream
    #==========================================================================
    declare -a BVR_NODE_NAMES=()
    declare -a BVR_NODE_OCIDS=()
    declare -a BVR_NODE_IMAGE_IDS=()
    declare -a BVR_NODE_BV_SIZES=()
    declare -a BVR_NODE_VERSIONS=()
    declare -a selected_indices=()
    local K8S_NODE_NAME=""
    local first_image_id=""
    local first_bv_size=""
    
    if [[ -n "$pre_selected_instance" ]]; then
        #======================================================================
        # Pre-selected instance path (called from instance details view)
        #======================================================================
        _ui_subheader "Pre-selected Instance" 0
        echo ""
        echo -e "${GRAY}Looking up K8s node for instance...${NC}"
        
        # Look up K8s node name from provider ID
        local ps_k8s_node_name=""
        ps_k8s_node_name=$(kubectl get nodes -o json 2>/dev/null | jq -r --arg ocid "$pre_selected_instance" \
            '.items[] | select(.spec.providerID | contains($ocid)) | .metadata.name' 2>/dev/null)
        
        if [[ -z "$ps_k8s_node_name" ]]; then
            echo -e "${RED}Cannot perform BVR — this instance is not registered as a node in the current kubeconfig context${NC}"
            local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
            echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
            _ui_pause
            return
        fi
        
        # Fetch instance details from OCI
        local ps_inst_json
        ps_inst_json=$(oci compute instance get --instance-id "$pre_selected_instance" --region "$region" --output json 2>/dev/null)
        
        if [[ -z "$ps_inst_json" ]] || ! jq -e '.data' <<< "$ps_inst_json" >/dev/null; then
            echo -e "${RED}Failed to fetch instance details${NC}"
            _ui_pause
            return
        fi
        
        local ps_inst_name ps_inst_shape ps_inst_ad ps_inst_image_id ps_kubelet_version
        ps_inst_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$ps_inst_json")
        ps_inst_shape=$(jq -r '.data.shape // "N/A"' <<< "$ps_inst_json")
        ps_inst_ad=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$ps_inst_json")
        ps_inst_image_id=$(jq -r '.data["image-id"] // ""' <<< "$ps_inst_json")
        
        # Get K8s version
        ps_kubelet_version=$(kubectl get node "$ps_k8s_node_name" -o jsonpath='{.status.nodeInfo.kubeletVersion}' 2>/dev/null || echo "N/A")
        
        # Get boot volume size
        local ps_bv_size="N/A"
        local ps_bv_attach_json ps_bv_id
        ps_bv_attach_json=$(oci compute boot-volume-attachment list \
            --compartment-id "$compartment_id" \
            --availability-domain "$ps_inst_ad" \
            --instance-id "$pre_selected_instance" \
            --region "$region" \
            --output json 2>/dev/null)
        ps_bv_id=$(jq -r '.data[0]["boot-volume-id"] // empty' <<< "$ps_bv_attach_json" 2>/dev/null)
        if [[ -n "$ps_bv_id" && "$ps_bv_id" != "null" ]]; then
            ps_bv_size=$(oci bv boot-volume get --boot-volume-id "$ps_bv_id" \
                --region "$region" \
                --query 'data."size-in-gbs"' --raw-output 2>/dev/null || echo "N/A")
        fi
        
        # Populate arrays with single entry
        BVR_NODE_NAMES=("$ps_k8s_node_name")
        BVR_NODE_OCIDS=("$pre_selected_instance")
        BVR_NODE_IMAGE_IDS=("${ps_inst_image_id:-}")
        BVR_NODE_BV_SIZES=("${ps_bv_size:-N/A}")
        BVR_NODE_VERSIONS=("$ps_kubelet_version")
        selected_indices=(1)
        
        K8S_NODE_NAME="$ps_k8s_node_name"
        first_image_id="${ps_inst_image_id:-}"
        first_bv_size="${ps_bv_size:-N/A}"
        
        echo -e "${CYAN}Instance:${NC}    ${WHITE}$ps_inst_name${NC}"
        echo -e "${CYAN}OCID:${NC}        ${YELLOW}$pre_selected_instance${NC}"
        echo -e "${CYAN}K8s Node:${NC}    ${WHITE}$ps_k8s_node_name${NC}"
        echo -e "${CYAN}Shape:${NC}       ${WHITE}$ps_inst_shape${NC}"
        echo -e "${CYAN}Boot Vol:${NC}    ${WHITE}${ps_bv_size} GB${NC}"
        echo -e "${CYAN}K8s Version:${NC} ${WHITE}$ps_kubelet_version${NC}"
        echo -e "${CYAN}AD:${NC}          ${WHITE}${ps_inst_ad##*:}${NC}"
        echo ""
        
    else
        #======================================================================
        # Full listing path (instance-first, matching --manage c4 pattern)
        #======================================================================
        _ui_subheader "K8s Worker Nodes" 0
        echo ""
        
        # Fetch all instances from OCI
        _step_init
        _step_active "instances and K8s node data"
        local _bvr_err_file _bvr_rc=0
        _bvr_err_file=$(mktemp "${TEMP_DIR}/bvr_err.XXXXXX") 2>/dev/null
        local bvr_instances_json
        bvr_instances_json=$(oci compute instance list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all \
            --output json 2>"$_bvr_err_file") || _bvr_rc=$?
        # OCI CLI returns empty stdout when compartment has 0 instances
        if [[ -z "$bvr_instances_json" && $_bvr_rc -eq 0 ]]; then
            bvr_instances_json='{"data":[]}'
        fi

        if [[ -z "$bvr_instances_json" ]] || ! jq -e '.data' <<< "$bvr_instances_json" >/dev/null 2>&1; then
            _step_complete "instances and K8s node data(failed)"
            _step_finish
            echo -e "${RED}Failed to fetch instances from OCI${NC}"
            _ui_policy_hint "read instances in compartment"
            echo -e "  ${WHITE}Command:${NC} ${GRAY}oci compute instance list --compartment-id \"${compartment_id}\" --region \"${region}\" --all --output json${NC}"
            local _err_msg=""
            if [[ -s "$_bvr_err_file" ]]; then
                _err_msg=$(grep -oP '(?<=message: ).*' "$_bvr_err_file" | head -1)
                [[ -z "$_err_msg" ]] && _err_msg=$(tail -3 "$_bvr_err_file")
            fi
            if [[ -z "$_err_msg" && -n "$bvr_instances_json" ]]; then
                _err_msg=$(jq -r '.message // .code // empty' <<< "$bvr_instances_json" 2>/dev/null)
                [[ -z "$_err_msg" ]] && _err_msg=$(echo "$bvr_instances_json" | head -5)
            fi
            [[ -n "$_err_msg" ]] && echo -e "  ${WHITE}Error:${NC}   ${GRAY}${_err_msg}${NC}"
            rm -f "$_bvr_err_file"
            _ui_pause
            return
        fi
        rm -f "$_bvr_err_file"
        
        # Fetch K8s nodes
        local bvr_k8s_nodes_json
        bvr_k8s_nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        _step_complete "instances and K8s node data"
        _step_finish
        
        if [[ -z "$bvr_k8s_nodes_json" ]] || ! jq -e '.items[0]' <<< "$bvr_k8s_nodes_json" >/dev/null; then
            echo -e "${RED}Failed to fetch K8s nodes - ensure kubectl is configured${NC}"
            _ui_pause
            return
        fi
        
        # Build K8s lookup: providerID → node_name|ready_status|kubelet_version|unschedulable|newNodeTaint
        local bvr_k8s_lookup
        bvr_k8s_lookup=$(jq -r '
            .items[] |
            (.spec.taints // [] | map(select(.key == "newNode")) | if length > 0 then .[0].effect else "N/A" end) as $newNodeTaint |
            (.spec.unschedulable // false) as $unschedulable |
            "\(.spec.providerID // "")|\(.metadata.name)|\(.status.conditions[] | select(.type=="Ready") | .status)|\(.status.nodeInfo.kubeletVersion // "N/A")|\($unschedulable)|\($newNodeTaint)"
        ' <<< "$bvr_k8s_nodes_json" 2>/dev/null)
        
        # Fetch pods per node for pod count
        local bvr_pods_per_node
        bvr_pods_per_node=$(kubectl get pods --all-namespaces --field-selector=status.phase=Running \
            -o custom-columns=NODE:.spec.nodeName --no-headers 2>/dev/null | sort | uniq -c | awk '{print $2"|"$1}')
        
        local bvr_idx=0
        
        echo ""
        printf "  ${BOLD}%-4s %-50s %-10s %-8s %-8s %-22s %-14s %-12s %-5s %-10s${NC}\n" \
            "#" "Display Name" "State" "K8s" "Cordon" "Shape" "Boot Vol (GB)" "K8s Version" "Pods" "AD"
        print_separator 155
        
        # Loop through OCI instances, only show those in K8s
        while IFS='|' read -r bvr_inst_id bvr_inst_name bvr_inst_state bvr_inst_shape bvr_inst_ad bvr_inst_image_id; do
            [[ -z "$bvr_inst_id" ]] && continue
            [[ "$bvr_inst_state" == "TERMINATED" ]] && continue
            
            # Check if this instance is a K8s node
            local bvr_k8s_match
            bvr_k8s_match=$(echo "$bvr_k8s_lookup" | grep -F "$bvr_inst_id" 2>/dev/null)
            [[ -z "$bvr_k8s_match" ]] && continue
            
            # Extract K8s data
            local bvr_k8s_node_name bvr_k8s_ready bvr_kubelet_version bvr_k8s_unschedulable bvr_k8s_taint
            bvr_k8s_node_name=$(echo "$bvr_k8s_match" | cut -d'|' -f2)
            bvr_k8s_ready=$(echo "$bvr_k8s_match" | cut -d'|' -f3)
            bvr_kubelet_version=$(echo "$bvr_k8s_match" | cut -d'|' -f4)
            bvr_k8s_unschedulable=$(echo "$bvr_k8s_match" | cut -d'|' -f5)
            bvr_k8s_taint=$(echo "$bvr_k8s_match" | cut -d'|' -f6)
            
            ((bvr_idx++))
            BVR_NODE_NAMES+=("$bvr_k8s_node_name")
            BVR_NODE_OCIDS+=("$bvr_inst_id")
            BVR_NODE_IMAGE_IDS+=("${bvr_inst_image_id:-}")
            BVR_NODE_VERSIONS+=("$bvr_kubelet_version")
            
            # Get boot volume size
            local bvr_inst_bv_size="N/A"
            local bvr_bv_attach_json=""
            bvr_bv_attach_json=$(oci compute boot-volume-attachment list \
                --compartment-id "$compartment_id" \
                --availability-domain "$bvr_inst_ad" \
                --instance-id "$bvr_inst_id" \
                --region "$region" \
                --output json 2>/dev/null)
            local bvr_bv_id=""
            bvr_bv_id=$(jq -r '.data[0]["boot-volume-id"] // empty' <<< "$bvr_bv_attach_json" 2>/dev/null)
            if [[ -n "$bvr_bv_id" && "$bvr_bv_id" != "null" ]]; then
                bvr_inst_bv_size=$(oci bv boot-volume get --boot-volume-id "$bvr_bv_id" \
                    --region "$region" \
                    --query 'data."size-in-gbs"' --raw-output 2>/dev/null || echo "N/A")
            fi
            BVR_NODE_BV_SIZES+=("${bvr_inst_bv_size:-N/A}")
            
            # Color state
            local bvr_state_color
            bvr_state_color=$(color_oci_state "$bvr_inst_state")
            
            # K8s ready color
            local bvr_ready_color="$GREEN"
            local bvr_ready_display="Ready"
            if [[ "$bvr_k8s_ready" != "True" ]]; then
                bvr_ready_color="$RED"
                bvr_ready_display="NotRdy"
            fi
            
            # Cordon status
            local bvr_cordon_status="-"
            local bvr_cordon_color="$GRAY"
            if [[ "$bvr_k8s_unschedulable" == "true" ]]; then
                bvr_cordon_status="Yes"
                bvr_cordon_color="$YELLOW"
            fi
            
            # Pod count
            local bvr_pod_count="-"
            local bvr_pod_color="$GRAY"
            local bvr_node_pods
            bvr_node_pods=$(echo "$bvr_pods_per_node" | grep "^${bvr_k8s_node_name}|" | cut -d'|' -f2)
            if [[ -n "$bvr_node_pods" ]]; then
                bvr_pod_count="$bvr_node_pods"
                bvr_pod_color="$CYAN"
            fi
            
            local bvr_ad_short="${bvr_inst_ad##*:}"
            
            printf "  ${YELLOW}%-4s${NC} %-50s ${bvr_state_color}%-10s${NC} ${bvr_ready_color}%-8s${NC} ${bvr_cordon_color}%-8s${NC} %-22s %-14s %-12s ${bvr_pod_color}%-5s${NC} %-10s\n" \
                "$bvr_idx" "$bvr_inst_name" "$bvr_inst_state" "$bvr_ready_display" "$bvr_cordon_status" \
                "${bvr_inst_shape:0:22}" "$bvr_inst_bv_size" "$bvr_kubelet_version" "$bvr_pod_count" "$bvr_ad_short"
                
        done < <(jq -r ' 
            .data[] |
            "\(.id)|\(.["display-name"] // "Unnamed")|\(.["lifecycle-state"])|\(.shape // "N/A")|\(.["availability-domain"] // "N/A")|\(.["image-id"] // "")"
        ' <<< "$bvr_instances_json" 2>/dev/null | sort -t'|' -k2,2)
        
        echo ""
        
        if [[ $bvr_idx -eq 0 ]]; then
            echo -e "${RED}No K8s nodes found with valid instance OCIDs in this compartment${NC}"
            _ui_pause
            return
        fi
        
        #======================================================================
        # Step 2: Select nodes
        #======================================================================
        _ui_subheader "Select Nodes" 0
        echo -e "${GRAY}Enter node numbers: 1,3,5  or  1-5  or  all${NC}"
        echo ""
        echo -n -e "${CYAN}Select nodes: ${NC}"
        read -r node_selection
        
        if [[ -z "$node_selection" ]]; then
            echo -e "${YELLOW}No nodes selected - cancelled${NC}"
            _ui_pause
            return
        fi
        
        # Parse selection into indices using shared helper
        if ! _parse_targets "" "$node_selection" "$bvr_idx"; then
            echo -e "${RED}No valid nodes selected${NC}"
            _ui_pause
            return
        fi
        local -a selected_indices=("${_SEL_INDICES[@]}")
        
        # Build the K8S_NODE_NAME string
        echo ""
        _ui_subheader "Selected Nodes" 0
        for si in "${selected_indices[@]}"; do
            local idx=$((si - 1))
            local nname="${BVR_NODE_NAMES[$idx]}"
            echo -e "  ${GREEN}•${NC} ${WHITE}$nname${NC}"
            if [[ -n "$K8S_NODE_NAME" ]]; then
                K8S_NODE_NAME+=" $nname"
            else
                K8S_NODE_NAME="$nname"
                first_image_id="${BVR_NODE_IMAGE_IDS[$idx]}"
                first_bv_size="${BVR_NODE_BV_SIZES[$idx]}"
            fi
        done
        echo ""
    fi
    
    #==========================================================================
    # Step 3: Compartment
    #==========================================================================
    local comp_name
    comp_name=$(resolve_compartment_name "$compartment_id")
    echo -e "${CYAN}Compartment:${NC} ${WHITE}$comp_name${NC} ${GRAY}($compartment_id)${NC}"
    echo -n -e "${CYAN}Use this compartment? (Y/n): ${NC}"
    read -r comp_confirm
    if [[ "$comp_confirm" == "n" || "$comp_confirm" == "N" ]]; then
        echo -n -e "${CYAN}Enter compartment OCID: ${NC}"
        read -r compartment_id
        if [[ -z "$compartment_id" ]]; then
            echo -e "${RED}No compartment provided - cancelled${NC}"
            _ui_pause
            return
        fi
    fi
    echo ""
    
    #==========================================================================
    # Step 4: Region
    #==========================================================================
    echo -e "${CYAN}Region:${NC} ${WHITE}$region${NC}"
    echo -n -e "${CYAN}Use this region? (Y/n): ${NC}"
    read -r region_confirm
    if [[ "$region_confirm" == "n" || "$region_confirm" == "N" ]]; then
        echo -n -e "${CYAN}Enter region (e.g., us-ashburn-1): ${NC}"
        read -r region
        if [[ -z "$region" ]]; then
            echo -e "${RED}No region provided - cancelled${NC}"
            _ui_pause
            return
        fi
    fi
    echo ""
    
    #==========================================================================
    # Step 5: Select custom image
    #==========================================================================
    _ui_subheader "Select Image" 0
    _step_init
    _step_active "custom images(2 parallel)"
    
    # Run current image name lookup + full image list in parallel
    local _bvr_tmp="${TEMP_DIR}/bvr_img_$$"
    mkdir -p "$_bvr_tmp"
    
    if [[ -n "$first_image_id" && "$first_image_id" != "null" ]]; then
        (oci compute image get --image-id "$first_image_id" --region "$region" \
            --query 'data."display-name"' --raw-output > "$_bvr_tmp/current_name" 2>/dev/null) &
        local _bvr_p1=$!
    fi
    (oci compute image list --compartment-id "$compartment_id" --region "$region" --all --output json > "$_bvr_tmp/images.json" 2>/dev/null) &
    local _bvr_p2=$!
    wait ${_bvr_p1:-} "$_bvr_p2" 2>/dev/null
    
    local current_image_name="N/A"
    [[ -s "$_bvr_tmp/current_name" ]] && current_image_name=$(cat "$_bvr_tmp/current_name")
    [[ -z "$current_image_name" ]] && current_image_name="N/A"
    
    local images_json=""
    [[ -s "$_bvr_tmp/images.json" ]] && images_json=$(cat "$_bvr_tmp/images.json")
    rm -rf "${_bvr_tmp:?}"
    
    local custom_images_json='{"data":[]}'
    if [[ -n "$images_json" ]] && jq -e '.data' <<< "$images_json" >/dev/null; then
        custom_images_json=$(jq --arg comp "$compartment_id" \
            '{data: [.data[] | select(.["compartment-id"] == $comp and .["lifecycle-state"] == "AVAILABLE")]}' <<< "$images_json" 2>/dev/null)
    fi
    _step_complete "custom images"
    _step_finish
    
    local img_count=0
    img_count=$(jq '.data | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
    
    declare -A BVR_IMAGE_MAP=()
    local img_idx=0
    
    echo ""
    if [[ "$img_count" -gt 0 ]]; then
        printf "  ${BOLD}%-4s %-105s %-20s${NC}\n" "#" "Image Name" "OS"
        print_separator 140

        while IFS='|' read -r img_id img_name img_os; do
            [[ -z "$img_id" ]] && continue
            ((img_idx++))
            BVR_IMAGE_MAP[$img_idx]="$img_id"

            # Mark the current image
            local marker=""
            if [[ "$img_id" == "$first_image_id" ]]; then
                marker=" ${YELLOW}← current${NC}"
            fi

            printf "  ${YELLOW}%-4s${NC} %-105s %-20s%b\n" \
                "$img_idx" "$img_name" "$img_os" "$marker"
        done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "Unnamed")|\(.["operating-system"] // "N/A")"' <<< "$custom_images_json" 2>/dev/null)
    fi
    
    echo ""
    if [[ -n "$first_image_id" && "$first_image_id" != "null" ]]; then
        echo -e "${GRAY}Current image: ${WHITE}$current_image_name${NC} ${YELLOW}($first_image_id)${NC}"
    fi
    echo -e "${GRAY}Press Enter to keep current image, or enter a number or paste an image OCID${NC}"
    echo -n -e "${CYAN}Select image [keep current]: ${NC}"
    read -r img_choice
    
    local selected_image_id="$first_image_id"
    local selected_image_name="$current_image_name"
    if [[ -n "$img_choice" ]]; then
        if [[ "$img_choice" =~ ^[0-9]+$ && -n "${BVR_IMAGE_MAP[$img_choice]}" ]]; then
            selected_image_id="${BVR_IMAGE_MAP[$img_choice]}"
            selected_image_name=$(jq -r --arg id "$selected_image_id" \
                '.data[] | select(.id == $id) | .["display-name"] // "N/A"' <<< "$custom_images_json" 2>/dev/null)
        elif [[ "$img_choice" =~ ^ocid1\.image\. ]]; then
            selected_image_id="$img_choice"
            selected_image_name=$(oci compute image get --image-id "$selected_image_id" --region "$region" \
                --query 'data."display-name"' --raw-output 2>/dev/null || echo "Custom OCID")
        else
            echo -e "${RED}Invalid selection - using current image${NC}"
        fi
    fi
    
    if [[ -z "$selected_image_id" || "$selected_image_id" == "null" ]]; then
        echo -e "${RED}No image selected and no current image found - cannot proceed${NC}"
        _ui_pause
        return
    fi
    echo ""
    
    #==========================================================================
    # Step 6: Boot volume size
    #==========================================================================
    _ui_subheader "Boot Volume Size" 0
    echo -e "${CYAN}Current boot volume size:${NC} ${WHITE}${first_bv_size:-N/A} GB${NC}"
    echo -n -e "${CYAN}Change boot volume size? (y/N): ${NC}"
    read -r change_bv
    
    local bv_size_param=""
    if [[ "$change_bv" == "y" || "$change_bv" == "Y" ]]; then
        echo -n -e "${CYAN}Enter new boot volume size in GB: ${NC}"
        read -r new_bv_size
        if [[ -n "$new_bv_size" && "$new_bv_size" =~ ^[0-9]+$ ]]; then
            bv_size_param="--bv-size $new_bv_size"
        else
            echo -e "${YELLOW}Invalid size - keeping current boot volume size${NC}"
        fi
    fi
    echo ""
    
    #==========================================================================
    # Step 7: Desired K8s version
    #==========================================================================
    _ui_subheader "K8s Version" 0
    
    # Get current cluster version and available versions
    local cluster_ocid=""
    cluster_ocid=$(get_oke_env_value "OKE_CLUSTER_ID" 2>/dev/null)
    local current_k8s_version=""
    
    declare -a available_versions=()
    if [[ -n "$cluster_ocid" && "$cluster_ocid" != "N/A" ]]; then
        current_k8s_version=$(oci ce cluster get --cluster-id "$cluster_ocid" --region "$region" \
            --query 'data."kubernetes-version"' --raw-output 2>/dev/null || echo "")
        
        # Get available versions from cluster-options
        local options_json
        options_json=$(oci ce cluster-options get --cluster-option-id all --output json 2>/dev/null)
        if [[ -n "$options_json" ]]; then
            while read -r ver; do
                [[ -n "$ver" ]] && available_versions+=("$ver")
            done < <(jq -r '(.data["kubernetes-versions"] // [])[]' <<< "$options_json" 2>/dev/null | sort -V)
        fi
    fi
    
    echo -e "${CYAN}Current cluster version:${NC} ${WHITE}${current_k8s_version:-N/A}${NC}"
    echo -e "${CYAN}Node kubelet versions:${NC}  ${WHITE}${BVR_NODE_VERSIONS[0]:-N/A}${NC}"
    
    local k8s_version_param=""
    if [[ ${#available_versions[@]} -gt 0 ]]; then
        echo ""
        echo -e "${GRAY}Available K8s versions:${NC}"
        local ver_idx=0
        declare -A BVR_VER_MAP=()
        for ver in "${available_versions[@]}"; do
            ((ver_idx++))
            BVR_VER_MAP[$ver_idx]="$ver"
            local ver_marker=""
            [[ "$ver" == "$current_k8s_version" ]] && ver_marker=" ${YELLOW}← cluster${NC}"
            printf "  ${YELLOW}%-3s${NC}) ${WHITE}%-15s${NC}%b\n" "$ver_idx" "$ver" "$ver_marker"
        done
        echo ""
        echo -e "${GRAY}Press Enter to skip (no version change), or select a version number${NC}"
        echo -n -e "${CYAN}Desired K8s version [skip]: ${NC}"
        read -r ver_choice
        
        if [[ -n "$ver_choice" ]]; then
            local chosen_ver=""
            if [[ "$ver_choice" =~ ^[0-9]+$ && -n "${BVR_VER_MAP[$ver_choice]}" ]]; then
                chosen_ver="${BVR_VER_MAP[$ver_choice]}"
            elif [[ "$ver_choice" =~ ^v?[0-9]+\.[0-9]+ ]]; then
                chosen_ver="$ver_choice"
            fi
            if [[ -n "$chosen_ver" ]]; then
                # Ensure it starts with v
                [[ "$chosen_ver" != v* ]] && chosen_ver="v$chosen_ver"
                k8s_version_param="--desired-k8s-version $chosen_ver"
                echo -e "  ${GREEN}✓${NC} Will upgrade nodes to ${WHITE}$chosen_ver${NC}"
            fi
        fi
    else
        echo -e "${GRAY}Could not fetch available versions - you can enter manually${NC}"
        echo -n -e "${CYAN}Desired K8s version (e.g., v1.33.1) [skip]: ${NC}"
        read -r manual_ver
        if [[ -n "$manual_ver" ]]; then
            [[ "$manual_ver" != v* ]] && manual_ver="v$manual_ver"
            k8s_version_param="--desired-k8s-version $manual_ver"
        fi
    fi
    echo ""
    
    #==========================================================================
    # Step 8: Previous boot volume removal preference
    #==========================================================================
    _ui_subheader "Post-Replacement Cleanup" 0
    echo -n -e "${CYAN}Remove previous boot volume after replacement? (y/N): ${NC}"
    read -r remove_bv_pref
    local remove_old_bv=false
    [[ "$remove_bv_pref" == "y" || "$remove_bv_pref" == "Y" ]] && remove_old_bv=true
    echo ""
    
    #==========================================================================
    # Step 9: Build and confirm command
    #==========================================================================
    local cmd="uv run ${bvr_script}"
    cmd+=" -c $compartment_id"
    cmd+=" --auth instance_principal"
    cmd+=" --image-ocid $selected_image_id"
    cmd+=" --region $region"
    [[ -n "$bv_size_param" ]] && cmd+=" $bv_size_param"
    [[ -n "$k8s_version_param" ]] && cmd+=" $k8s_version_param"
    cmd+=" --timeout-seconds 1200"
    cmd+=" $K8S_NODE_NAME"
    
    _ui_menu_header "CONFIRM BOOT VOLUME REPLACEMENT"
    echo ""
    echo -e "  ${CYAN}Nodes:${NC}          ${WHITE}$K8S_NODE_NAME${NC}"
    echo -e "  ${CYAN}Compartment:${NC}    ${WHITE}$(resolve_compartment_name "$compartment_id")${NC}"
    echo -e "  ${CYAN}Region:${NC}         ${WHITE}$region${NC}"
    if [[ "$selected_image_id" == "$first_image_id" ]]; then
        echo -e "  ${CYAN}Image:${NC}          ${WHITE}$selected_image_name${NC} ${GRAY}(no change)${NC}"
    else
        echo -e "  ${CYAN}Image:${NC}          ${WHITE}$selected_image_name${NC} ${YELLOW}(changed)${NC}"
    fi
    echo -e "                  ${GRAY}[$selected_image_id]${NC}"
    if [[ -n "$bv_size_param" ]]; then
        echo -e "  ${CYAN}Boot Vol Size:${NC}  ${WHITE}${bv_size_param##* } GB${NC} ${YELLOW}(changed)${NC}"
    else
        echo -e "  ${CYAN}Boot Vol Size:${NC}  ${WHITE}${first_bv_size:-N/A} GB${NC} ${GRAY}(unchanged)${NC}"
    fi
    if [[ -n "$k8s_version_param" ]]; then
        echo -e "  ${CYAN}K8s Version:${NC}    ${WHITE}${k8s_version_param##* }${NC} ${YELLOW}(upgrade)${NC}"
    else
        echo -e "  ${CYAN}K8s Version:${NC}    ${GRAY}(no change)${NC}"
    fi
    echo -e "  ${CYAN}Remove Old BV:${NC}  ${WHITE}$remove_old_bv${NC}"
    echo ""
    _ui_subheader "Command to Execute" 0
    echo -e "${GRAY}$cmd${NC}"
    echo ""
    echo -n -e "${BOLD}${YELLOW}⚠ This will replace boot volumes on ${#selected_indices[@]} node(s). Proceed? (y/N): ${NC}"
    read -r final_confirm
    
    if [[ "$final_confirm" != "y" && "$final_confirm" != "Y" ]]; then
        echo -e "${YELLOW}BVR cancelled${NC}"
        _ui_pause
        return
    fi
    
    #==========================================================================
    # Step 10: Execute BVR
    #==========================================================================
    echo ""
    _ui_subheader "Executing Boot Volume Replacement" 0
    echo ""
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"
    echo -e "${WHITE}$ ${cmd}${NC}"
    echo ""
    
    # Run BVR with live elapsed timer (1200s timeout)
    run_with_elapsed_timer "$cmd" "$log_file" 1200
    local bvr_exit_code=$?
    
    echo ""
    if [[ $bvr_exit_code -eq 0 ]]; then
        echo -e "${GREEN}Boot Volume Replacement Completed Successfully${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: BVR completed for nodes: $K8S_NODE_NAME" >> "$log_file"
        
        #==================================================================
        # Post-execution: Handle old boot volumes
        #==================================================================
        echo ""
        echo -e "${BOLD}${YELLOW}⚠ NOTE: The previous boot volume(s) from the replaced node(s) still exist.${NC}"
        echo -e "${GRAY}These boot volumes are detached but not deleted. They will continue to incur storage costs.${NC}"
        echo ""
        
        if [[ "$remove_old_bv" == "true" ]]; then
            echo -e "${YELLOW}You opted to remove old boot volumes.${NC}"
            echo -e "${GRAY}Searching for detached boot volumes...${NC}"
            echo ""
            
            # For each selected node, find any AVAILABLE (detached) boot volumes
            for si in "${selected_indices[@]}"; do
                local nidx=$((si - 1))
                local nname="${BVR_NODE_NAMES[$nidx]}"
                local nocid="${BVR_NODE_OCIDS[$nidx]}"
                
                # List boot volumes that might be from this instance (AVAILABLE = detached)
                local old_bvs
                old_bvs=$(oci bv boot-volume list --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null | \
                    jq -r --arg name "$nname" '.data[] | select(.["lifecycle-state"] == "AVAILABLE") | select(.["display-name"] | contains($name)) | "\(.id)|\(.["display-name"])|\(.["size-in-gbs"])"' 2>/dev/null)
                
                if [[ -n "$old_bvs" ]]; then
                    echo -e "${WHITE}Node: ${NC}${CYAN}$nname${NC}"
                    while IFS='|' read -r old_bv_id old_bv_name old_bv_gb; do
                        [[ -z "$old_bv_id" ]] && continue
                        echo -e "  ${GRAY}Found: ${WHITE}$old_bv_name${NC} (${old_bv_gb} GB) ${YELLOW}$old_bv_id${NC}"
                        echo -n -e "  ${RED}Delete this boot volume? (y/N): ${NC}"
                        read -r del_confirm
                        if [[ "$del_confirm" == "y" || "$del_confirm" == "Y" ]]; then
                            local del_cmd="oci bv boot-volume delete --boot-volume-id $old_bv_id --region $region --force"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $del_cmd" >> "$log_file"
                            echo -e "  ${WHITE}$ ${del_cmd}${NC}"
                            _safe_exec "$del_cmd"
                            if [[ $? -eq 0 ]]; then
                                echo -e "  ${GREEN}✓ Boot volume deleted${NC}"
                                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted old boot volume $old_bv_id" >> "$log_file"
                            else
                                echo -e "  ${RED}✗ Failed to delete boot volume${NC}"
                                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete boot volume $old_bv_id" >> "$log_file"
                            fi
                        else
                            echo -e "  ${GRAY}Skipped${NC}"
                        fi
                    done <<< "$old_bvs"
                    echo ""
                fi
            done
        else
            echo -e "${GRAY}To clean up old boot volumes later, use:${NC}"
            echo -e "${GRAY}  oci bv boot-volume list --compartment-id $compartment_id --region $region --lifecycle-state AVAILABLE${NC}"
            echo -e "${GRAY}  oci bv boot-volume delete --boot-volume-id <ocid> --region $region --force${NC}"
        fi
    else
        echo -e "${RED}Boot Volume Replacement Failed (exit code: $bvr_exit_code)${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: BVR exit code $bvr_exit_code for nodes: $K8S_NODE_NAME" >> "$log_file"
    fi
    
    echo ""
    echo -e "${GRAY}Log: $log_file${NC}"
    _ui_pause
}

#--------------------------------------------------------------------------------
# Display all instances with OCI properties in consolidated view
# Shows: Name, State, Shape config, Boot Vol, Image, Oracle-Tags, Cloud-Init
# Uses parallel fetching and caching for boot volumes and images
#--------------------------------------------------------------------------------
display_instances_properties_view() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local max_parallel=$OCI_MAX_PARALLEL
    
    while true; do
        echo ""
        _ui_menu_header "INSTANCE PROPERTIES VIEW" \
            --breadcrumb "Compute" "Instances" "Properties" \
            --cmd "oci compute instance list | oci compute instance get | oci compute boot-volume-attachment list | oci bv boot-volume get | oci compute image get | oci iam user get | oci iam group get | oci iam dynamic-group get | oci iam compartment get | oci iam identity-provider get | oci ce cluster get | oci ce node-pool get | oci compute-management instance-pool get" \
            --env \
            --cache \
            "${INSTANCE_LIST_CACHE}|Instances" \
            "${BOOT_VOLUME_CACHE}|Boot Volumes" \
            "${IMAGE_CACHE}|Images"
        echo ""
        
        # ── Discovery ──
        _step_init
        
        # Step: instances
        local instances_json
        if is_cache_fresh "$INSTANCE_LIST_CACHE"; then
            instances_json=$(cat "$INSTANCE_LIST_CACHE")
            local total_count
            total_count=$(jq '[.data[] | select(.["lifecycle-state"] != "TERMINATED")] | length' <<< "$instances_json")
            _step_complete "instances(${total_count} cached)"
        else
            _step_active "instances"
            instances_json=$(oci compute instance list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --all \
                --output json 2>/dev/null)
            if [[ -n "$instances_json" ]] && jq -e '.data' <<< "$instances_json" > /dev/null 2>&1; then
                echo "$instances_json" | _cache_write "$INSTANCE_LIST_CACHE"
            fi
            local total_count
            total_count=$(jq '[.data[] | select(.["lifecycle-state"] != "TERMINATED")] | length' <<< "$instances_json" 2>/dev/null)
            _step_complete "instances(${total_count:-0})"
        fi
        
        if [[ -z "$instances_json" ]] || ! jq -e '.data[]' <<< "$instances_json" > /dev/null 2>&1; then
            _step_finish
            echo -e "  ${RED}No instances found${NC}"
            _ui_pause "return"
            return
        fi
        
        # Extract unique image IDs and instance OCIDs
        local unique_images unique_instances
        unique_images=$(jq -r '.data[] | select(.["lifecycle-state"] != "TERMINATED") | .["image-id"] // empty' <<< "$instances_json" | sort -u | grep -v '^$' )
        unique_instances=$(jq -r '.data[] | select(.["lifecycle-state"] != "TERMINATED") | "\(.id)|\(.["availability-domain"])"' <<< "$instances_json")
        
        # Step: boot volumes
        if is_cache_fresh "$BOOT_VOLUME_CACHE"; then
            _step_complete "BV cached"
        else
            local tmp_bv_dir="${TEMP_DIR}/bv_fetch_$$"
            mkdir -p "$tmp_bv_dir"
            
            local bv_total
            bv_total=$(echo "$unique_instances" | grep -c . 2>/dev/null) || bv_total=0
            [[ ! "$bv_total" =~ ^[0-9]+$ ]] && bv_total=0
            
            local unique_ads
            unique_ads=$(echo "$unique_instances" | cut -d'|' -f2 | sort -u)
            local ad_count=0
            local ad_total
            ad_total=$(echo "$unique_ads" | grep -c . 2>/dev/null) || ad_total=0
            
            _step_progress_start "BV att" "$tmp_bv_dir" "ad_*.json" "$ad_total"
            local _bv_att_pids=()
            while IFS= read -r ad; do
                [[ -z "$ad" ]] && continue
                oci compute boot-volume-attachment list \
                    --compartment-id "$compartment_id" \
                    --availability-domain "$ad" \
                    --region "$region" \
                    --all --output json > "${tmp_bv_dir}/ad_${ad_count}.json" 2>/dev/null &
                _bv_att_pids+=($!)
                ((ad_count++))
            done <<< "$unique_ads"
            [[ ${#_bv_att_pids[@]} -gt 0 ]] && wait "${_bv_att_pids[@]}" 2>/dev/null
            
            # Build instance → boot-volume-id map
            declare -A _inst_bv_map=()
            declare -A _unique_bv_ids=()
            local _ad_i=0
            while IFS= read -r ad; do
                [[ -z "$ad" ]] && continue
                local _ad_file="${tmp_bv_dir}/ad_${_ad_i}.json"
                if [[ -f "$_ad_file" && -s "$_ad_file" ]]; then
                    while IFS='|' read -r _att_inst _att_bv _att_state; do
                        [[ -z "$_att_inst" || -z "$_att_bv" ]] && continue
                        [[ "$_att_state" == "DETACHED" || "$_att_state" == "DETACHING" ]] && continue
                        _inst_bv_map[$_att_inst]="$_att_bv"
                        _unique_bv_ids[$_att_bv]=1
                    done < <(jq -r '.data[]? | "\(.["instance-id"] // "")|\(.["boot-volume-id"] // "")|\(.["lifecycle-state"] // "")"' "$_ad_file" 2>/dev/null)
                fi
                ((_ad_i++))
            done <<< "$unique_ads"
            _step_complete "BV att(${#_inst_bv_map[@]})"
            
            local bv_unique=${#_unique_bv_ids[@]}
            if [[ $bv_unique -gt 0 ]]; then
                local _bv_detail_dir="${tmp_bv_dir}/details"
                mkdir -p "$_bv_detail_dir"
                
                _step_progress_start "BV details" "$_bv_detail_dir" "*" "$bv_unique"
                local _bv_pids=()
                local _bv_batch=0
                for bv_id in "${!_unique_bv_ids[@]}"; do
                    [[ -z "$bv_id" ]] && continue
                    (
                        local bv_json
                        bv_json=$(oci bv boot-volume get --boot-volume-id "$bv_id" --output json 2>/dev/null)
                        if [[ -n "$bv_json" ]]; then
                            local bv_size bv_vpus
                            bv_size=$(jq -r '.data["size-in-gbs"] // empty' <<< "$bv_json" 2>/dev/null)
                            bv_vpus=$(jq -r '.data["vpus-per-gb"] // empty' <<< "$bv_json" 2>/dev/null)
                            if [[ -n "$bv_size" && "$bv_size" != "null" ]]; then
                                [[ -z "$bv_vpus" || "$bv_vpus" == "null" ]] && bv_vpus="-"
                                echo "${bv_id}|${bv_size}|${bv_vpus}" > "${_bv_detail_dir}/${bv_id##*.}"
                            fi
                        fi
                    ) >/dev/null 2>&1 &
                    _bv_pids+=($!)
                    ((_bv_batch++))
                    if (( _bv_batch % max_parallel == 0 )); then
                        wait "${_bv_pids[@]}" 2>/dev/null
                        _bv_pids=()
                    fi
                done
                [[ ${#_bv_pids[@]} -gt 0 ]] && wait "${_bv_pids[@]}" 2>/dev/null
                _step_complete "BV details(${bv_unique})"
                
                # Build BV detail map and write cache
                declare -A _bv_detail_map=()
                if ls "${_bv_detail_dir}"/* >/dev/null 2>&1; then
                    while IFS='|' read -r _bvd_id _bvd_size _bvd_vpus; do
                        [[ -n "$_bvd_id" ]] && _bv_detail_map[$_bvd_id]="${_bvd_size}|${_bvd_vpus}"
                    done < <(cat "${_bv_detail_dir}"/* 2>/dev/null)
                fi
                
                local _bv_cache_tmp="${tmp_bv_dir}/cache_out"
                for inst_id in "${!_inst_bv_map[@]}"; do
                    local _bv_id="${_inst_bv_map[$inst_id]}"
                    if [[ -n "${_bv_detail_map[$_bv_id]+x}" ]]; then
                        echo "${inst_id}|${_bv_detail_map[$_bv_id]}" >> "$_bv_cache_tmp"
                    fi
                done
                [[ -f "$_bv_cache_tmp" && -s "$_bv_cache_tmp" ]] && mv "$_bv_cache_tmp" "$BOOT_VOLUME_CACHE"
            fi
            rm -rf "${tmp_bv_dir:?}"
        fi
        
        # Step: images
        if is_cache_fresh "$IMAGE_CACHE"; then
            _step_complete "images cached"
        else
            local tmp_img_dir="${TEMP_DIR}/img_fetch_$$"
            mkdir -p "$tmp_img_dir"
            
            local img_total
            img_total=$(echo "$unique_images" | wc -l)
            
            # First pass: find which images need fetching vs already cached
            local _imgs_to_fetch=()
            while read -r image_id; do
                [[ -z "$image_id" ]] && continue
                if grep -q "^${image_id}|" "$IMAGE_CACHE" 2>/dev/null; then
                    continue
                fi
                _imgs_to_fetch+=("$image_id")
            done <<< "$unique_images"
            
            local _fetch_total=${#_imgs_to_fetch[@]}
            if [[ $_fetch_total -eq 0 ]]; then
                _step_complete "images(${img_total} cached)"
            else
                _step_progress_start "images" "$tmp_img_dir" "*" "$_fetch_total"
                local _img_pids=()
                local _img_batch=0
                for image_id in "${_imgs_to_fetch[@]}"; do
                    (
                        local img_name
                        img_name=$(oci compute image get --image-id "$image_id" \
                            --query 'data."display-name"' --raw-output 2>/dev/null) || img_name="-"
                        echo "${image_id}|${img_name}" > "${tmp_img_dir}/${image_id##*.}"
                    ) >/dev/null 2>&1 &
                    _img_pids+=($!)
                    ((_img_batch++))
                    if (( _img_batch % max_parallel == 0 )); then
                        wait "${_img_pids[@]}" 2>/dev/null
                        _img_pids=()
                    fi
                done
                [[ ${#_img_pids[@]} -gt 0 ]] && wait "${_img_pids[@]}" 2>/dev/null
                _step_complete "images(${img_total})"
            fi
            
            if [[ -d "$tmp_img_dir" ]]; then
                cat "${tmp_img_dir}"/* >> "$IMAGE_CACHE" 2>/dev/null
                rm -rf "${tmp_img_dir:?}"
            fi
        fi
        
        # Step: build display data
        _step_active "display"
        local tmp_data="${TEMP_DIR}/instance_props_$$"
        rm -f "$tmp_data"
        
        declare -A BV_CACHE_MAP=()
        declare -A IMG_CACHE_MAP=()
        
        if [[ -f "$BOOT_VOLUME_CACHE" && -s "$BOOT_VOLUME_CACHE" ]]; then
            while IFS='|' read -r inst_id bv_sz bv_vp; do
                [[ -n "$inst_id" && -n "$bv_sz" ]] && BV_CACHE_MAP["$inst_id"]="${bv_sz}|${bv_vp}"
            done < "$BOOT_VOLUME_CACHE"
        fi
        
        if [[ -f "$IMAGE_CACHE" && -s "$IMAGE_CACHE" ]]; then
            while IFS='|' read -r img_id img_nm; do
                [[ -n "$img_id" ]] && IMG_CACHE_MAP["$img_id"]="$img_nm"
            done < "$IMAGE_CACHE"
        fi
        
        while IFS='|' read -r ocid name state shape ocpus memory gpus net_bw max_vnics ad image_id user_data created_by created_on; do
            [[ -z "$ocid" ]] && continue
            
            local bv_size="-" bv_vpus="-"
            if [[ -n "${BV_CACHE_MAP[$ocid]:-}" ]]; then
                IFS='|' read -r bv_size bv_vpus <<< "${BV_CACHE_MAP[$ocid]}"
                [[ -z "$bv_size" || "$bv_size" == "null" ]] && bv_size="-"
                [[ -z "$bv_vpus" || "$bv_vpus" == "null" ]] && bv_vpus="-"
            fi
            
            local image_name="-"
            if [[ -n "$image_id" && "$image_id" != "null" && -n "${IMG_CACHE_MAP[$image_id]:-}" ]]; then
                image_name="${IMG_CACHE_MAP[$image_id]}"
            fi
            
            local ci_fp="-"
            if [[ -n "$user_data" && "$user_data" != "null" && "$user_data" != "" ]]; then
                ci_fp="${user_data: -7}"
            fi
            
            [[ "$gpus" == "null" || -z "$gpus" ]] && gpus="0"
            [[ "$net_bw" == "null" || -z "$net_bw" ]] && net_bw="-"
            [[ "$max_vnics" == "null" || -z "$max_vnics" ]] && max_vnics="-"
            [[ "$created_by" == "null" || -z "$created_by" ]] && created_by="-"
            [[ "$created_on" == "null" || -z "$created_on" ]] && created_on="-"
            [[ "$created_on" != "-" ]] && created_on="${created_on:0:10}"
            
            echo "${name}|${state}|${shape}|${ocpus}|${memory}|${gpus}|${net_bw}|${max_vnics}|${bv_size}|${bv_vpus}|${image_name}|${created_by}|${created_on}|${ci_fp}|${ocid}" >> "$tmp_data"
            
        done < <(jq -r ' 
            .data[] | 
            select(.["lifecycle-state"] != "TERMINATED") |
            "\(.id)|\(.["display-name"])|\(.["lifecycle-state"])|\(.shape)|\(.["shape-config"]["ocpus"] // "")|\(.["shape-config"]["memory-in-gbs"] // "")|\(.["shape-config"]["gpus"] // "0")|\(.["shape-config"]["networking-bandwidth-in-gbps"] // "")|\(.["shape-config"]["max-vnic-attachments"] // "")|\(.["availability-domain"])|\(.["image-id"] // "")|\(.metadata.user_data // "")|\(.["defined-tags"]["Oracle-Tags"]["CreatedBy"] // "")|\(.["defined-tags"]["Oracle-Tags"]["CreatedOn"] // "")"
        ' <<< "$instances_json" 2>/dev/null)
        _step_complete "display"
        
        if [[ ! -f "$tmp_data" ]]; then
            _step_finish
            echo -e "  ${RED}No instance data collected${NC}"
            _ui_pause "return"
            return
        fi
        
        # Step: resolve CreatedBy OCIDs
        declare -A CREATED_BY_NAME_CACHE=()
        local _all_ocids
        _all_ocids=$(awk -F'|' '$12 ~ /^ocid1\./' "$tmp_data" | cut -d'|' -f12 | sort -u)
        if [[ -n "$_all_ocids" ]]; then
            local _ocid_count
            _ocid_count=$(echo "$_all_ocids" | wc -l)
            
            _step_active "CreatedBy"
            
            # Pre-resolve ocid1.instance from instances_json (no API calls needed)
            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                if [[ "$_oid" == ocid1.instance.* ]]; then
                    local _iname
                    _iname=$(_inst_attr "$_oid" "$INSTANCE_LIST_CACHE" "display-name" "")
                    [[ -n "$_iname" ]] && CREATED_BY_NAME_CACHE["$_oid"]="$_iname"
                fi
            done <<< "$_all_ocids"
            
            # Parallel resolve remaining OCIDs by type
            local _resolve_dir="${TEMP_DIR}/createdby_resolve_$$"
            mkdir -p "$_resolve_dir"
            local _resolve_pids=()
            local _resolve_batch=0
            local _resolve_max=15
            
            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                [[ -n "${CREATED_BY_NAME_CACHE[$_oid]+x}" ]] && continue
                
                (
                    local _rname=""
                    case "$_oid" in
                        ocid1.user.*)
                            _rname=$(oci iam user get --user-id "$_oid" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.instance.*)
                            _rname=$(oci compute instance get --instance-id "$_oid" --query 'data."display-name"' --raw-output 2>/dev/null)
                            ;;
                        ocid1.nodepool.*)
                            _rname=$(oci ce node-pool get --node-pool-id "$_oid" --region "$region" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.instancepool.*)
                            _rname=$(oci compute-management instance-pool get --instance-pool-id "$_oid" --query 'data."display-name"' --raw-output 2>/dev/null)
                            ;;
                        ocid1.cluster.*)
                            _rname=$(oci ce cluster get --cluster-id "$_oid" --region "$region" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.saml2idp.*)
                            _rname=$(oci iam identity-provider get --identity-provider-id "$_oid" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.group.*)
                            _rname=$(oci iam group get --group-id "$_oid" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.dynamicgroup.*)
                            _rname=$(oci iam dynamic-group get --dynamic-group-id "$_oid" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                        ocid1.compartment.*)
                            _rname=$(oci iam compartment get --compartment-id "$_oid" --query 'data.name' --raw-output 2>/dev/null)
                            ;;
                    esac
                    if [[ -n "$_rname" && "$_rname" != "null" && "$_rname" != "None" ]]; then
                        echo "$_rname" > "${_resolve_dir}/${_oid##*.}"
                    fi
                ) >/dev/null 2>&1 &
                _resolve_pids+=($!)
                ((_resolve_batch++))
                if (( _resolve_batch % _resolve_max == 0 )); then
                    wait "${_resolve_pids[@]}" 2>/dev/null
                    _resolve_pids=()
                fi
            done <<< "$_all_ocids"
            [[ ${#_resolve_pids[@]} -gt 0 ]] && wait "${_resolve_pids[@]}" 2>/dev/null
            
            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                [[ -n "${CREATED_BY_NAME_CACHE[$_oid]+x}" ]] && continue
                local _rf="${_resolve_dir}/${_oid##*.}"
                if [[ -f "$_rf" && -s "$_rf" ]]; then
                    CREATED_BY_NAME_CACHE["$_oid"]=$(cat "$_rf")
                fi
            done <<< "$_all_ocids"
            rm -rf "${_resolve_dir:?}" 2>/dev/null
            
            local _resolved_ct=${#CREATED_BY_NAME_CACHE[@]}
            _step_complete "CreatedBy(${_resolved_ct})"
        fi
        
        _step_finish
        
        # ── Display table ──
        _ui_subheader "Instance Properties (${total_count})" 0
        echo ""
        _col_build_fmt "PROP"
        _col_build_fmt "PROP" "id"
        printf "${BOLD}${_PROP_HDR_FMT}${NC}\n" "${_PROP_HDR_ARGS[@]}"
        print_separator $_PROP_SEP_WIDTH
        
        declare -A PROP_INDEX_MAP=()
        local _prop_idx=0
        
        while IFS='|' read -r name state shape ocpus memory gpus net_bw max_vnics bv_size bv_vpus image_name created_by created_on ci_fp inst_ocid; do
            local state_color
            state_color=$(color_oci_state "$state")
            
            local gpu_disp="$gpus"
            [[ "$gpus" == "0" ]] && gpu_disp="-"
            
            local name_t="${name:0:${_PROP_COL_WIDTHS[1]}}"
            local state_t="${state:0:${_PROP_COL_WIDTHS[2]}}"
            local shape_t="${shape:0:${_PROP_COL_WIDTHS[3]}}"

            # Build index map
            ((_prop_idx++))
            local _piid="i${_prop_idx}"
            PROP_INDEX_MAP[$_piid]="$inst_ocid"

            # Resolve CreatedBy: use unified OCID name cache
            local created_by_display="$created_by"
            if [[ "$created_by" == ocid1.* && -n "${CREATED_BY_NAME_CACHE[$created_by]+x}" ]]; then
                created_by_display="${CREATED_BY_NAME_CACHE[$created_by]}"
            fi
            # Truncate long CreatedBy — "..." prefix + last (width-3) chars
            local _cb_w=${_PROP_COL_WIDTHS[12]}
            local _cb_trunc=$((_cb_w - 3))
            if [[ $_cb_trunc -gt 0 && ${#created_by_display} -gt $_cb_trunc ]]; then
                created_by_display="...${created_by_display: -${_cb_trunc}}"
            fi
            
            _col_print_row "PROP" "$_piid" "$name_t" "$state_t" "$shape_t" "$ocpus" "$memory" "$gpu_disp" "$net_bw" "$max_vnics" "$bv_size" "$bv_vpus" "$image_name" "$created_by_display" "$created_on" "$ci_fp" "$state_color"
        done < <(sort -t'|' -k1,1 "$tmp_data")

        echo ""
        print_separator $_PROP_SEP_WIDTH
        echo ""

        # Show hidden columns notice when not all visible
        if [[ $_PROP_COL_COUNT -lt ${#_PROP_COL_KEYS[@]} ]]; then
            local _hidden_labels=""
            declare -A _en_lookup=()
            for _ek in "${_PROP_ENABLED_COLS[@]}"; do _en_lookup["$_ek"]=1; done
            for _hi in "${!_PROP_COL_KEYS[@]}"; do
                local _hk="${_PROP_COL_KEYS[$_hi]}"
                if [[ -z "${_en_lookup[$_hk]:-}" ]]; then
                    [[ -n "$_hidden_labels" ]] && _hidden_labels+=", "
                    _hidden_labels+="${_PROP_COL_LABELS[$_hi]}"
                fi
            done
            echo -e "  ${GRAY}Hidden (${#_PROP_COL_KEYS[@]}-${_PROP_COL_COUNT}): ${_hidden_labels}  │  type ${WHITE}col${GRAY} to configure${NC}"
            echo ""
        fi

        _ui_actions
        echo -e "  ${YELLOW}i#${NC}         - View instance details (e.g. i1, i3)"
        echo -e "  ${CYAN}/${NC}          - Search instances (name, shape, image, created by, etc.)"
        echo -e "  ${CYAN}legend${NC}     - Show column legend"
        echo -e "  ${CYAN}col${NC}        - Toggle column visibility"
        echo -e "  ${MAGENTA}r${NC}          - Clear cache and re-fetch all data"
        echo -e "  ${CYAN}back${NC}       - Return to instances menu"
        echo ""
        _ui_prompt "Instance Properties" "i#, /, legend, col, r, back"
        
        local action
        read -r action
        [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return
        
        case "$action" in
            /*)
                _compute_search_properties "$tmp_data" "$instances_json" "${action#/}"
                ;;
            i[0-9]*)
                local _prop_ocid="${PROP_INDEX_MAP[$action]:-}"
                if [[ -z "$_prop_ocid" ]]; then
                    echo -e "${RED}Invalid instance ID: $action${NC}"
                    sleep 1
                else
                    while true; do
                        display_instance_details "$_prop_ocid"
                        local ret=$?
                        [[ $ret -ne 2 ]] && break
                    done
                fi
                ;;
            ocid1.instance.*)
                while true; do
                    display_instance_details "$action"
                    local ret=$?
                    [[ $ret -ne 2 ]] && break
                done
                ;;
            col|COL|columns|COLUMNS)
                _col_picker "PROP" "Instance Properties"
                rm -f "$tmp_data"
                continue
                ;;
            legend|LEGEND|l|L)
                echo ""
                _ui_legend
                echo -e "  ${WHITE}OCPUs${NC}      - Number of OCPUs (shape-config.ocpus)"
                echo -e "  ${WHITE}Mem${NC}        - Memory in GB (shape-config.memory-in-gbs)"
                echo -e "  ${WHITE}GPU${NC}        - Number of GPUs (shape-config.gpus)"
                echo -e "  ${WHITE}NetBW${NC}      - Network bandwidth in Gbps (shape-config.networking-bandwidth-in-gbps)"
                echo -e "  ${WHITE}VNIC${NC}       - Max VNIC attachments (shape-config.max-vnic-attachments)"
                echo -e "  ${WHITE}BV GB${NC}      - Boot Volume size in GB (boot-volume.size-in-gbs)"
                echo -e "  ${WHITE}VPUs${NC}       - Boot Volume VPUs/GB (boot-volume.vpus-per-gb) [10=Balanced, 20=Higher, 30+=Ultra]"
                echo -e "  ${BLUE}CreatedBy${NC}  - Oracle-Tags CreatedBy (defined-tags.Oracle-Tags.CreatedBy)"
                echo -e "  ${GRAY}CreatedOn${NC}  - Oracle-Tags CreatedOn date (defined-tags.Oracle-Tags.CreatedOn)"
                echo -e "  ${WHITE}CI${NC}         - Cloud-Init fingerprint (last 7 chars of metadata.user_data)"
                echo ""
                echo -e "  ${GRAY}Instances with matching CI fingerprints have identical cloud-init configurations${NC}"
                echo ""
                _ui_pause "return"
                ;;
            refresh|REFRESH|r|R)
                rm -f "$BOOT_VOLUME_CACHE" "$IMAGE_CACHE" "$INSTANCE_LIST_CACHE"
                echo -e "  ${GREEN}✓${NC} Cache cleared, refreshing..."
                rm -f "$tmp_data"
                sleep 1
                continue
                ;;
            show|SHOW)
                rm -f "$tmp_data"
                continue
                ;;
            *)
                rm -f "$tmp_data"
                return
                ;;
        esac
        
        rm -f "$tmp_data"
    done
}

#--------------------------------------------------------------------------------
# Display detailed instance information
#--------------------------------------------------------------------------------
display_instance_details() {
    local instance_ocid="$1"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_menu_header "INSTANCE DETAILS" \
        --breadcrumb "Compute" "Instances" "Details" \
        --cmd "oci compute instance get --instance-id \$INSTANCE_OCID | oci compute vnic-attachment list | oci compute boot-volume-attachment list | oci compute volume-attachment list | oci compute image get | kubectl get nodes -o json | oci network vnic get | oci bv boot-volume get | oci bv volume get | kubectl get pods --field-selector=spec.nodeName | oci network subnet get | oci network nsg get | oci bv volume-backup-policy-assignment get-volume-backup-policy-asset-assignment | oci network route-table get | oci bv volume-backup-policy get" \
        --env
    
    # ========== DISCOVERY ==========
    _step_init
    _step_active "instance"
    
    # Fetch instance details
    local instance_json
    instance_json=$(oci compute instance get --instance-id "$instance_ocid" --region "$region" --output json 2>/dev/null)

    if [[ -z "$instance_json" ]] || ! jq -e '.data' <<< "$instance_json" > /dev/null 2>&1; then
        _step_complete "instance(failed)"
        _step_finish
        echo -e "${RED}Failed to fetch instance details${NC}"
        return 1
    fi
    _step_complete "instance"
    
    # ========== PARALLEL WAVE PREFETCH (all instance data) ==========
    _step_active "attachments"
    
    local _dtmp="${TEMP_DIR}/detail_$$"
    mkdir -p "$_dtmp"
    local _pids=()
    
    # Get availability domain and image-id from instance JSON (local jq, instant)
    local ad_for_query
    ad_for_query=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$instance_json")
    local image_id
    image_id=$(jq -r '.data["image-id"] // empty' <<< "$instance_json")
    
    # Early-parse OKE tags (needed to add OKE fetches to wave 1)
    local oke_cluster_id oke_nodepool_id
    oke_cluster_id=$(jq -r '.data["defined-tags"]["oke-apisystem"]["ClusterId"] // empty' <<< "$instance_json")
    oke_nodepool_id=$(jq -r '.data["defined-tags"]["oke-apisystem"]["NodePoolId"] // empty' <<< "$instance_json")
    [[ -z "$oke_cluster_id" ]] && oke_cluster_id=$(jq -r '.data["freeform-tags"]["oke-clusterId"] // empty' <<< "$instance_json")
    [[ -z "$oke_nodepool_id" ]] && oke_nodepool_id=$(jq -r '.data["freeform-tags"]["oke-nodePoolId"] // empty' <<< "$instance_json")
    
    #--- WAVE 1: All independent fetches (only need instance_ocid/compartment_id) ---
    _pids=()
    (oci compute vnic-attachment list --compartment-id "$compartment_id" --instance-id "$instance_ocid" --region "$region" --output json > "$_dtmp/vnic_attach.json" 2>/dev/null) &
    _pids+=($!)
    (oci compute boot-volume-attachment list --compartment-id "$compartment_id" --availability-domain "$ad_for_query" --instance-id "$instance_ocid" --region "$region" --output json > "$_dtmp/bv_attach.json" 2>/dev/null) &
    _pids+=($!)
    (oci compute volume-attachment list --compartment-id "$compartment_id" --instance-id "$instance_ocid" --region "$region" --output json > "$_dtmp/vol_attach.json" 2>/dev/null) &
    _pids+=($!)
    if [[ -n "$image_id" ]]; then
        (oci compute image get --image-id "$image_id" --region "$region" --output json > "$_dtmp/image.json" 2>/dev/null) &
        _pids+=($!)
    fi
    if command -v kubectl &>/dev/null; then
        (kubectl get nodes -o json > "$_dtmp/k8s_nodes.json" 2>/dev/null) &
        _pids+=($!)
    fi
    # OKE cluster + node pool detail (if this instance is an OKE node)
    # Use k1's caches first (OKE_CLUSTER_JSON_CACHE, OKE_NODEPOOL_CACHE) to avoid extra API calls
    if [[ -n "$oke_cluster_id" ]]; then
        if [[ -s "$OKE_CLUSTER_JSON_CACHE" ]] && \
           jq -e --arg cid "$oke_cluster_id" '.data.id == $cid' "$OKE_CLUSTER_JSON_CACHE" >/dev/null 2>&1; then
            cp "$OKE_CLUSTER_JSON_CACHE" "$_dtmp/oke_cluster.json" 2>/dev/null
        else
            (oci ce cluster get --cluster-id "$oke_cluster_id" --region "$region" --output json > "$_dtmp/oke_cluster.json" 2>/dev/null) &
            _pids+=($!)
        fi
    fi
    if [[ -n "$oke_nodepool_id" ]]; then
        # Try extracting from k1's nodepool list cache (wraps single item into {data:...} format)
        if [[ -s "$OKE_NODEPOOL_CACHE" ]] && \
           jq -e --arg npid "$oke_nodepool_id" '[.data[] | select(.id == $npid)] | length > 0' "$OKE_NODEPOOL_CACHE" >/dev/null 2>&1; then
            jq --arg npid "$oke_nodepool_id" '{ data: (.data[] | select(.id == $npid)) }' "$OKE_NODEPOOL_CACHE" > "$_dtmp/oke_nodepool.json" 2>/dev/null
        else
            (oci ce node-pool get --node-pool-id "$oke_nodepool_id" --region "$region" --output json > "$_dtmp/oke_nodepool.json" 2>/dev/null) &
            _pids+=($!)
        fi
    fi
    # Instance work requests (generic work-requests API)
    (oci work-requests work-request list --compartment-id "$compartment_id" --resource-id "$instance_ocid" --region "$region" --output json > "$_dtmp/inst_wr.json" 2>/dev/null) &
    _pids+=($!)
    # Run commands (instance agent command executions)
    (oci instance-agent command-execution list --compartment-id "$compartment_id" --instance-id "$instance_ocid" --region "$region" --sort-by TIMECREATED --sort-order DESC --limit 20 --output json > "$_dtmp/inst_rc.json" 2>/dev/null) &
    _pids+=($!)
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    
    # Read wave 1 results
    local cached_vnic_attachments="" cached_boot_vol_attachments="" cached_block_vol_attachments=""
    [[ -s "$_dtmp/vnic_attach.json" ]] && cached_vnic_attachments=$(cat "$_dtmp/vnic_attach.json")
    [[ -s "$_dtmp/bv_attach.json" ]] && cached_boot_vol_attachments=$(cat "$_dtmp/bv_attach.json")
    [[ -s "$_dtmp/vol_attach.json" ]] && cached_block_vol_attachments=$(cat "$_dtmp/vol_attach.json")
    
    local _vnic_count
    _vnic_count=$(jq -r '.data | length' <<< "${cached_vnic_attachments:-{}}" 2>/dev/null)
    local _bv_count
    _bv_count=$(jq -r '.data | length' <<< "${cached_boot_vol_attachments:-{}}" 2>/dev/null)
    local _blk_count
    _blk_count=$(jq -r '.data | length' <<< "${cached_block_vol_attachments:-{}}" 2>/dev/null)
    [[ -z "$_vnic_count" || "$_vnic_count" == "null" ]] && _vnic_count=0
    [[ -z "$_bv_count" || "$_bv_count" == "null" ]] && _bv_count=0
    [[ -z "$_blk_count" || "$_blk_count" == "null" ]] && _blk_count=0
    local _attach_total=$(( _vnic_count + _bv_count + _blk_count ))
    _step_complete "attachments(${_attach_total})"
    _step_active "details"
    
    # Cache K8s nodes JSON for reuse (serial number, K8s status, actions menu)
    local cached_k8s_nodes_json=""
    [[ -s "$_dtmp/k8s_nodes.json" ]] && cached_k8s_nodes_json=$(cat "$_dtmp/k8s_nodes.json")
    
    # Extract host labels from cached K8s nodes (serial_number, host.id, rack_id)
    local k8s_serial_number="N/A" k8s_host_id="N/A" k8s_rack_id="N/A"
    if [[ -n "$cached_k8s_nodes_json" ]]; then
        k8s_serial_number=$(jq -r --arg ocid "$instance_ocid" '
            .items[] | select(.spec.providerID | contains($ocid)) |
            .metadata.labels["oci.oraclecloud.com/host.serial_number"] // "N/A"
        ' <<< "$cached_k8s_nodes_json" 2>/dev/null)
        [[ -z "$k8s_serial_number" ]] && k8s_serial_number="N/A"
        k8s_host_id=$(jq -r --arg ocid "$instance_ocid" '
            .items[] | select(.spec.providerID | contains($ocid)) |
            .metadata.labels["oci.oraclecloud.com/host.id"] // "N/A"
        ' <<< "$cached_k8s_nodes_json" 2>/dev/null)
        [[ -z "$k8s_host_id" ]] && k8s_host_id="N/A"
        k8s_rack_id=$(jq -r --arg ocid "$instance_ocid" '
            .items[] | select(.spec.providerID | contains($ocid)) |
            .metadata.labels["oci.oraclecloud.com/host.rack_id"] // "N/A"
        ' <<< "$cached_k8s_nodes_json" 2>/dev/null)
        [[ -z "$k8s_rack_id" ]] && k8s_rack_id="N/A"
    fi
    
    #--- WAVE 2: Depends on wave 1 (VNIC IDs, boot vol IDs, block vol IDs, K8s node name) ---
    _pids=()
    
    # Extract VNIC IDs and fetch each in parallel
    local vnic_ids_list=""
    if [[ -n "$cached_vnic_attachments" ]]; then
        vnic_ids_list=$(jq -r '.data[]?["vnic-id"] // empty' <<< "$cached_vnic_attachments" 2>/dev/null)
        for vnic_id in $vnic_ids_list; do
            [[ -z "$vnic_id" ]] && continue
            (oci network vnic get --vnic-id "$vnic_id" --region "$region" --output json > "$_dtmp/vnic_${vnic_id##*.}.json" 2>/dev/null) &
            _pids+=($!)
        done
    fi
    
    # Fetch boot volume details in parallel
    local bv_ids_list=""
    if [[ -n "$cached_boot_vol_attachments" ]] && jq -e '.data[]' <<< "$cached_boot_vol_attachments" > /dev/null 2>&1; then
        bv_ids_list=$(jq -r '.data[]?["boot-volume-id"] // empty' <<< "$cached_boot_vol_attachments" 2>/dev/null)
        for bv_id in $bv_ids_list; do
            [[ -z "$bv_id" ]] && continue
            (oci bv boot-volume get --boot-volume-id "$bv_id" --region "$region" --output json > "$_dtmp/bv_${bv_id##*.}.json" 2>/dev/null) &
            _pids+=($!)
        done
    fi
    
    # Fetch block volume details in parallel
    local vol_ids_list=""
    if [[ -n "$cached_block_vol_attachments" ]] && jq -e '.data[]' <<< "$cached_block_vol_attachments" > /dev/null 2>&1; then
        vol_ids_list=$(jq -r '.data[]?["volume-id"] // empty' <<< "$cached_block_vol_attachments" 2>/dev/null)
        for vol_id in $vol_ids_list; do
            [[ -z "$vol_id" ]] && continue
            (oci bv volume get --volume-id "$vol_id" --region "$region" --output json > "$_dtmp/blkvol_${vol_id##*.}.json" 2>/dev/null) &
            _pids+=($!)
        done
    fi
    
    # Fetch K8s pods (single call, reuse for both total and daemonset counts)
    local cached_k8s_node_name=""
    if [[ -n "$cached_k8s_nodes_json" ]]; then
        cached_k8s_node_name=$(resolve_k8s_node_name "$instance_ocid" "$cached_k8s_nodes_json")
    fi
    if [[ -n "$cached_k8s_node_name" ]]; then
        (kubectl get pods --all-namespaces --field-selector=spec.nodeName="$cached_k8s_node_name",status.phase=Running -o json > "$_dtmp/k8s_pods.json" 2>/dev/null) &
        _pids+=($!)
    fi
    
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    _step_complete "details"
    _step_active "networking"
    
    #--- WAVE 3: Depends on wave 2 (subnet IDs, NSG IDs from VNIC details; backup policies from BV details) ---
    _pids=()
    
    # Build VNIC details cache and collect subnet/NSG IDs
    local cached_vnic_details="{}"
    local all_subnet_ids="" all_nsg_ids=""
    for vnic_id in $vnic_ids_list; do
        [[ -z "$vnic_id" ]] && continue
        local vnic_file="$_dtmp/vnic_${vnic_id##*.}.json"
        if [[ -s "$vnic_file" ]]; then
            local vnic_data
            vnic_data=$(cat "$vnic_file")
            cached_vnic_details=$(jq --arg id "$vnic_id" --argjson data "$vnic_data" '. + {($id): $data}' <<< "$cached_vnic_details" 2>/dev/null)
            local subnet_id nsg_list
            subnet_id=$(jq -r '.data["subnet-id"] // empty' <<< "$vnic_data" 2>/dev/null)
            [[ -n "$subnet_id" ]] && all_subnet_ids="$all_subnet_ids $subnet_id"
            nsg_list=$(jq -r '.data["nsg-ids"] // [] | .[]' <<< "$vnic_data" 2>/dev/null)
            [[ -n "$nsg_list" ]] && all_nsg_ids="$all_nsg_ids $nsg_list"
        fi
    done
    
    # Fetch subnets in parallel (each writes name + rt_id to temp file)
    for subnet_id in $(echo "$all_subnet_ids" | tr ' ' '\n' | sort -u); do
        [[ -z "$subnet_id" ]] && continue
        (oci network subnet get --subnet-id "$subnet_id" --region "$region" --output json > "$_dtmp/subnet_${subnet_id##*.}.json" 2>/dev/null) &
        _pids+=($!)
    done
    
    # Fetch NSGs in parallel
    for nsg_id in $(echo "$all_nsg_ids" | tr ' ' '\n' | sort -u); do
        [[ -z "$nsg_id" ]] && continue
        (oci network nsg get --nsg-id "$nsg_id" --region "$region" --query 'data."display-name"' --raw-output > "$_dtmp/nsg_${nsg_id##*.}.txt" 2>/dev/null) &
        _pids+=($!)
    done
    
    # Fetch backup policy assignments for boot volumes and block volumes in parallel
    for bv_id in $bv_ids_list; do
        [[ -z "$bv_id" ]] && continue
        (oci bv volume-backup-policy-assignment get-volume-backup-policy-asset-assignment \
            --asset-id "$bv_id" --region "$region" --query 'data[0]."policy-id"' --raw-output > "$_dtmp/bkup_assign_${bv_id##*.}.txt" 2>/dev/null) &
        _pids+=($!)
    done
    for vol_id in $vol_ids_list; do
        [[ -z "$vol_id" ]] && continue
        (oci bv volume-backup-policy-assignment get-volume-backup-policy-asset-assignment \
            --asset-id "$vol_id" --region "$region" --query 'data[0]."policy-id"' --raw-output > "$_dtmp/bkup_assign_${vol_id##*.}.txt" 2>/dev/null) &
        _pids+=($!)
    done
    
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    
    #--- WAVE 4: Depends on wave 3 (route table IDs from subnets; backup policy names from assignments) ---
    _pids=()
    
    # Build subnet names cache and fetch route tables in parallel
    local cached_subnet_names="{}"
    local rt_ids_to_fetch=""
    for subnet_id in $(echo "$all_subnet_ids" | tr ' ' '\n' | sort -u); do
        [[ -z "$subnet_id" ]] && continue
        local subnet_file="$_dtmp/subnet_${subnet_id##*.}.json"
        if [[ -s "$subnet_file" ]]; then
            local subnet_name rt_id
            subnet_name=$(jq -r '.data["display-name"] // "-"' "$subnet_file" 2>/dev/null)
            rt_id=$(jq -r '.data["route-table-id"] // empty' "$subnet_file" 2>/dev/null)
            # Store subnet name now, route table will be filled after wave 4
            cached_subnet_names=$(jq --arg id "$subnet_id" --arg name "$subnet_name" --arg rt "-" --arg rtid "${rt_id:-}" \
                '. + {($id): {"name": $name, "rt": $rt, "rtid": $rtid}}' <<< "$cached_subnet_names" 2>/dev/null)
            if [[ -n "$rt_id" ]]; then
                (oci network route-table get --rt-id "$rt_id" --region "$region" --query 'data."display-name"' --raw-output > "$_dtmp/rt_${rt_id##*.}.txt" 2>/dev/null) &
                _pids+=($!)
                rt_ids_to_fetch="$rt_ids_to_fetch ${subnet_id}:${rt_id}"
            fi
        fi
    done
    
    # Build NSG names cache
    local cached_nsg_names="{}"
    for nsg_id in $(echo "$all_nsg_ids" | tr ' ' '\n' | sort -u); do
        [[ -z "$nsg_id" ]] && continue
        local nsg_file="$_dtmp/nsg_${nsg_id##*.}.txt"
        local nsg_name="N/A"
        [[ -s "$nsg_file" ]] && nsg_name=$(cat "$nsg_file")
        [[ -z "$nsg_name" ]] && nsg_name="N/A"
        cached_nsg_names=$(jq --arg id "$nsg_id" --arg name "$nsg_name" '. + {($id): $name}' <<< "$cached_nsg_names" 2>/dev/null)
    done
    
    # Build boot volume details + backup policies cache
    local cached_boot_vol_details="{}"
    local cached_backup_policies="{}"
    for bv_id in $bv_ids_list; do
        [[ -z "$bv_id" ]] && continue
        local bv_file="$_dtmp/bv_${bv_id##*.}.json"
        [[ -s "$bv_file" ]] && cached_boot_vol_details=$(jq --arg id "$bv_id" --argjson data "$(cat "$bv_file")" '. + {($id): $data}' <<< "$cached_boot_vol_details" 2>/dev/null)
        # Read backup policy assignment
        local backup_assign_file="$_dtmp/bkup_assign_${bv_id##*.}.txt"
        local backup_policy="None"
        local backup_assign=""
        [[ -s "$backup_assign_file" ]] && backup_assign=$(cat "$backup_assign_file")
        if [[ -n "$backup_assign" && "$backup_assign" != "null" && "$backup_assign" != "None" ]]; then
            (oci bv volume-backup-policy get --policy-id "$backup_assign" --region "$region" --query 'data."display-name"' --raw-output > "$_dtmp/bkup_name_${bv_id##*.}.txt" 2>/dev/null) &
            _pids+=($!)
        else
            echo "None" > "$_dtmp/bkup_name_${bv_id##*.}.txt"
        fi
    done
    
    # Build block volume details + backup policies cache
    local cached_block_vol_details="{}"
    for vol_id in $vol_ids_list; do
        [[ -z "$vol_id" ]] && continue
        local vol_file="$_dtmp/blkvol_${vol_id##*.}.json"
        [[ -s "$vol_file" ]] && cached_block_vol_details=$(jq --arg id "$vol_id" --argjson data "$(cat "$vol_file")" '. + {($id): $data}' <<< "$cached_block_vol_details" 2>/dev/null)
        local backup_assign_file="$_dtmp/bkup_assign_${vol_id##*.}.txt"
        local backup_policy="None"
        local backup_assign=""
        [[ -s "$backup_assign_file" ]] && backup_assign=$(cat "$backup_assign_file")
        if [[ -n "$backup_assign" && "$backup_assign" != "null" && "$backup_assign" != "None" ]]; then
            (oci bv volume-backup-policy get --policy-id "$backup_assign" --region "$region" --query 'data."display-name"' --raw-output > "$_dtmp/bkup_name_${vol_id##*.}.txt" 2>/dev/null) &
            _pids+=($!)
        else
            echo "None" > "$_dtmp/bkup_name_${vol_id##*.}.txt"
        fi
    done
    
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    
    #--- POST-WAVE: Assemble final route table names and backup policy names ---
    # Update cached_subnet_names with route table names
    for pair in $rt_ids_to_fetch; do
        local s_id="${pair%%:*}" r_id="${pair##*:}"
        local rt_file="$_dtmp/rt_${r_id##*.}.txt"
        local rt_name="-"
        [[ -s "$rt_file" ]] && rt_name=$(cat "$rt_file")
        [[ -z "$rt_name" ]] && rt_name="-"
        cached_subnet_names=$(jq --arg id "$s_id" --arg rt "$rt_name" '.[$id].rt = $rt' <<< "$cached_subnet_names" 2>/dev/null)
    done
    
    # Assemble backup policy names
    for bv_id in $bv_ids_list; do
        [[ -z "$bv_id" ]] && continue
        local policy_name_file="$_dtmp/bkup_name_${bv_id##*.}.txt"
        local backup_policy="None"
        [[ -s "$policy_name_file" ]] && backup_policy=$(cat "$policy_name_file")
        [[ -z "$backup_policy" || "$backup_policy" == "null" ]] && backup_policy="None"
        cached_backup_policies=$(jq --arg id "$bv_id" --arg policy "$backup_policy" '. + {($id): $policy}' <<< "$cached_backup_policies" 2>/dev/null)
    done
    for vol_id in $vol_ids_list; do
        [[ -z "$vol_id" ]] && continue
        local policy_name_file="$_dtmp/bkup_name_${vol_id##*.}.txt"
        local backup_policy="None"
        [[ -s "$policy_name_file" ]] && backup_policy=$(cat "$policy_name_file")
        [[ -z "$backup_policy" || "$backup_policy" == "null" ]] && backup_policy="None"
        cached_backup_policies=$(jq --arg id "$vol_id" --arg policy "$backup_policy" '. + {($id): $policy}' <<< "$cached_backup_policies" 2>/dev/null)
    done
    
    # Cache image JSON for display phase (fetched in wave 1)
    local cached_image_json=""
    [[ -s "$_dtmp/image.json" ]] && cached_image_json=$(cat "$_dtmp/image.json")
    
    # Cache K8s pods JSON for display phase (fetched in wave 2)
    local cached_k8s_pods_json=""
    [[ -s "$_dtmp/k8s_pods.json" ]] && cached_k8s_pods_json=$(cat "$_dtmp/k8s_pods.json")
    
    # Persist instance WR data (survives _dtmp cleanup for menu loop)
    local _inst_wr_dir="${TEMP_DIR}/inst_wr_$$"
    mkdir -p "$_inst_wr_dir"
    [[ -s "$_dtmp/inst_wr.json" ]] && cp "$_dtmp/inst_wr.json" "$_inst_wr_dir/wr.json"
    local _inst_wr_ct=0
    [[ -s "$_inst_wr_dir/wr.json" ]] && _inst_wr_ct=$(jq '(.data // []) | length' "$_inst_wr_dir/wr.json" 2>/dev/null || echo "0")
    
    # Persist run command data (survives _dtmp cleanup for menu loop)
    local _inst_rc_dir="${TEMP_DIR}/inst_rc_$$"
    mkdir -p "$_inst_rc_dir"
    [[ -s "$_dtmp/inst_rc.json" ]] && cp "$_dtmp/inst_rc.json" "$_inst_rc_dir/rc.json"
    local _inst_rc_ct=0
    [[ -s "$_inst_rc_dir/rc.json" ]] && _inst_rc_ct=$(jq '(.data // []) | length' "$_inst_rc_dir/rc.json" 2>/dev/null || echo "0")

    # Persist OKE data (survives _dtmp cleanup for associations display)
    local _inst_oke_dir="${TEMP_DIR}/inst_oke_$$"
    mkdir -p "$_inst_oke_dir"
    [[ -s "$_dtmp/oke_cluster.json" ]] && cp "$_dtmp/oke_cluster.json" "$_inst_oke_dir/oke_cluster.json"
    [[ -s "$_dtmp/oke_nodepool.json" ]] && cp "$_dtmp/oke_nodepool.json" "$_inst_oke_dir/oke_nodepool.json"

    # Cleanup temp files
    rm -rf "${_dtmp:?}"
    
    # Complete discovery
    _step_complete "networking"
    [[ "$_inst_wr_ct" -gt 0 ]] && _step_complete "work requests(${_inst_wr_ct})"
    [[ "$_inst_rc_ct" -gt 0 ]] && _step_complete "run commands(${_inst_rc_ct})"
    _step_finish
    
    # Extract basic info
    local display_name state shape ad fd time_created launch_mode image_id
    IFS=$'\t' read -r display_name state shape ad fd time_created launch_mode image_id < <(jq -r '.data | [
        .["display-name"] // "N/A",
        .["lifecycle-state"] // "N/A",
        .shape // "N/A",
        .["availability-domain"] // "N/A",
        .["fault-domain"] // "N/A",
        .["time-created"] // "N/A",
        .["launch-mode"] // "N/A",
        .["image-id"] // empty
    ] | @tsv' <<< "$instance_json")
    
    # Extract shape config
    local shape_ocpus shape_memory_gb shape_gpus shape_gpu_desc shape_nvmes shape_network_bw shape_max_nics
    IFS=$'\t' read -r shape_ocpus shape_memory_gb shape_gpus shape_gpu_desc \
        shape_nvmes shape_network_bw shape_max_nics < <(jq -r '.data["shape-config"] | [
            .ocpus // "N/A",
            .["memory-in-gbs"] // "N/A",
            .gpus // "0",
            .["gpu-description"] // empty,
            .["local-disks"] // "0",
            .["networking-bandwidth-in-gbps"] // "N/A",
            .["max-vnic-attachments"] // "N/A"
        ] | @tsv' <<< "$instance_json")
    
    # Extract GPU memory cluster tag
    local gpu_mem_cluster
    gpu_mem_cluster=$(jq -r '.data["freeform-tags"]["oci:compute:gpumemorycluster"] // empty' <<< "$instance_json")
    
    # Extract compute cluster ID
    local compute_cluster_id
    compute_cluster_id=$(jq -r '.data["compute-cluster-id"] // empty' <<< "$instance_json")

    # Look up dedicated compute host (if instance runs on one)
    local _ch_record="" _ch_name="" _ch_state="" _ch_health="" _ch_host_ocid=""
    local _ch_ad="" _ch_fd="" _ch_hpc="" _ch_netblock="" _ch_localblock="" _ch_gpu_fabric=""
    _ch_record=$(get_compute_host_record "$instance_ocid" 2>/dev/null)
    if [[ -n "$_ch_record" ]]; then
        IFS='|' read -r _ch_name _ch_state _ch_health _ _ _ch_ad _ch_fd _ _ch_host_ocid \
            _ch_hpc _ch_netblock _ch_localblock _ _ _ch_gpu_fabric _ _ _ _ <<< "$_ch_record"
    fi

    # OKE tags already parsed early (before wave 1 for parallel fetch)
    
    # Check for instance pool / instance configuration
    local instance_pool_id instance_config_id
    instance_pool_id=$(jq -r '.data["metadata"]["oci:compute:instancepool:id"] // empty' <<< "$instance_json")
    instance_config_id=$(jq -r '.data["metadata"]["oci:compute:instanceconfiguration:id"] // empty' <<< "$instance_json")
    
    # Extract Oracle-Tags
    local oracle_created_by oracle_created_on
    oracle_created_by=$(jq -r '.data["defined-tags"]["Oracle-Tags"]["CreatedBy"] // empty' <<< "$instance_json")
    oracle_created_on=$(jq -r '.data["defined-tags"]["Oracle-Tags"]["CreatedOn"] // empty' <<< "$instance_json")
    
    # Color state
    local state_color
    state_color=$(color_oci_state "$state")
    
    # ========== BASIC INFO (Compact) ==========
    echo ""
    _ui_subheader "Basic Info" 0
    printf "${WHITE}%-10s${NC}${GREEN}%s${NC}\n" "Name:" "$display_name"
    printf "${WHITE}%-10s${NC}${GRAY}%s${NC}\n" "OCID:" "$instance_ocid"
    printf "${WHITE}%-10s${NC}${state_color}%-12s${NC}  ${WHITE}%-10s${NC}%-22s  ${WHITE}%-8s${NC}%s\n" "State:" "$state" "Created:" "${time_created:0:19}" "Launch:" "$launch_mode"
    printf "${WHITE}%-10s${NC}%-12s  ${WHITE}%-10s${NC}%s\n" "AD:" "${ad##*:}" "FD:" "${fd##*-}"
    
    # ========== SHAPE & COMPUTE (Compact) ==========
    echo ""
    _ui_subheader "Shape & Resources" 0
    printf "${WHITE}%-10s${NC}${CYAN}%-20s${NC}  ${WHITE}%-8s${NC}%-8s  ${WHITE}%-8s${NC}%-10s\n" "Shape:" "${shape:0:20}" "OCPUs:" "$shape_ocpus" "Memory:" "${shape_memory_gb} GB"

    local gpu_info="N/A"
    if [[ "$shape_gpus" != "0" && "$shape_gpus" != "N/A" ]]; then
        gpu_info="${shape_gpus}x ${shape_gpu_desc:-GPU}"
    fi
    printf "${WHITE}%-10s${NC}${GREEN}%-20s${NC}  ${WHITE}%-8s${NC}%-8s  ${WHITE}%-8s${NC}%-10s\n" "GPUs:" "$gpu_info" "NetBW:" "${shape_network_bw}Gb" "VNICs:" "$shape_max_nics"
    # K8s host labels: Host ID, Rack ID, Serial Number (single line)
    local _k8s_host_parts=()
    [[ "$k8s_host_id" != "N/A" && -n "$k8s_host_id" ]]         && _k8s_host_parts+=("Host ID:$k8s_host_id")
    [[ "$k8s_rack_id" != "N/A" && -n "$k8s_rack_id" ]]         && _k8s_host_parts+=("Rack ID:$k8s_rack_id")
    [[ "$k8s_serial_number" != "N/A" && -n "$k8s_serial_number" ]] && _k8s_host_parts+=("SN:$k8s_serial_number")
    if [[ ${#_k8s_host_parts[@]} -gt 0 ]]; then
        local _k8s_line=""
        for _part in "${_k8s_host_parts[@]}"; do
            local _lbl="${_part%%:*}:" _val="${_part#*:}"
            _k8s_line+="$(printf "${WHITE}%-9s${NC}${CYAN}%-18s${NC}" "$_lbl" "$_val")"
        done
        printf "${WHITE}%-10s${NC}%b\n" "Host:" "$_k8s_line"
    fi
    
    # ========== IMAGE (Full Details - from prefetch cache) ==========
    echo ""
    _ui_subheader "Image" 0
    if [[ -n "$image_id" && -n "$cached_image_json" ]]; then
        local image_name image_os image_os_version
        image_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$cached_image_json")
        image_os=$(jq -r '.data["operating-system"] // "N/A"' <<< "$cached_image_json")
        image_os_version=$(jq -r '.data["operating-system-version"] // "N/A"' <<< "$cached_image_json")
        echo -e "${WHITE}Name:${NC} ${GREEN}$image_name${NC}  ${GRAY}[${YELLOW}$image_id${GRAY}]${NC}"
        echo -e "${WHITE}OS:${NC}   $image_os $image_os_version"
    elif [[ -n "$image_id" ]]; then
        echo -e "${WHITE}Name:${NC} ${GRAY}(not available)${NC}  ${GRAY}[${YELLOW}$image_id${GRAY}]${NC}"
    else
        echo -e "${GRAY}Image information not available${NC}"
    fi
    
    # ========== CLUSTER/OKE ASSOCIATIONS (Compact) ==========
    if [[ -n "$_ch_record" || -n "$gpu_mem_cluster" || -n "$compute_cluster_id" || -n "$oke_cluster_id" || -n "$instance_config_id" ]]; then
        echo ""
        _ui_subheader "Associations" 0

        if [[ -n "$_ch_record" ]]; then
            local _ch_sc; _ch_sc=$(color_resource_state "$_ch_state")
            local _ch_hc="$GREEN"
            case "$_ch_health" in
                DEGRADED|IMPAIRED) _ch_hc="$YELLOW" ;;
                UNHEALTHY|FAILED)  _ch_hc="$RED" ;;
            esac
            printf "${WHITE}%-18s${NC}${GREEN}%s${NC} ${GRAY}[${YELLOW}%s${GRAY}]${NC} ${GRAY}[${NC}${_ch_sc}%s${NC}${GRAY}]${NC} ${GRAY}[${NC}${_ch_hc}%s${NC}${GRAY}]${NC}\n" \
                "Compute Host:" "$_ch_name" "$_ch_host_ocid" "$_ch_state" "$_ch_health"
            # Topology details (AD, FD, HPC Island, Network Block, Local Block, GPU Fabric)
            local _ch_ad_short="${_ch_ad##*:}"
            local _ch_fd_short="${_ch_fd##*FAULT-DOMAIN-}"
            [[ "$_ch_fd_short" == "$_ch_fd" ]] && _ch_fd_short="${_ch_fd##*-}"
            printf "${WHITE}%-18s${NC}${WHITE}AD:${NC} %-14s ${WHITE}FD:${NC} %s\n" "" "$_ch_ad_short" "FD-${_ch_fd_short}"
            # RDMA topology line (only if any topology IDs exist)
            local _ch_topo_parts=()
            [[ -n "$_ch_hpc" && "$_ch_hpc" != "N/A" ]]           && _ch_topo_parts+=("${WHITE}HPC:${GRAY}..${_ch_hpc: -5}${NC}")
            [[ -n "$_ch_netblock" && "$_ch_netblock" != "N/A" ]]   && _ch_topo_parts+=("${WHITE}NetBlk:${GRAY}..${_ch_netblock: -5}${NC}")
            [[ -n "$_ch_localblock" && "$_ch_localblock" != "N/A" ]] && _ch_topo_parts+=("${WHITE}LocBlk:${GRAY}..${_ch_localblock: -5}${NC}")
            [[ -n "$_ch_gpu_fabric" && "$_ch_gpu_fabric" != "N/A" ]] && _ch_topo_parts+=("${WHITE}GPUFab:${GRAY}..${_ch_gpu_fabric: -5}${NC}")
            if [[ ${#_ch_topo_parts[@]} -gt 0 ]]; then
                local _ch_topo_str="${_ch_topo_parts[*]}"
                printf "${WHITE}%-18s${NC}%b\n" "  RDMA Topology:" "$_ch_topo_str"
            fi
        fi
        if [[ -n "$gpu_mem_cluster" ]]; then
            # Look up cluster display name and state from cache
            local _gmc_name="" _gmc_state=""
            if [[ -f "$CLUSTER_CACHE" ]]; then
                _gmc_name=$(lookup_cache "$CLUSTER_CACHE" "$gpu_mem_cluster" 2 2>/dev/null)
                _gmc_state=$(lookup_cache "$CLUSTER_CACHE" "$gpu_mem_cluster" 3 2>/dev/null)
            fi
            [[ -z "$_gmc_name" || "$_gmc_name" == "N/A" || "$_gmc_name" == "null" ]] && _gmc_name=""
            [[ -z "$_gmc_state" || "$_gmc_state" == "N/A" || "$_gmc_state" == "null" ]] && _gmc_state=""

            # Look up parent GPU memory fabric from cluster
            local _gmf_name="" _gmf_ocid="" _gmf_state=""
            if [[ -f "$FABRIC_CACHE" && -f "$CLUSTER_CACHE" ]]; then
                local _fab_line
                _fab_line=$(get_fabric_from_cluster "$gpu_mem_cluster" 2>/dev/null)
                if [[ -n "$_fab_line" && "$_fab_line" != "N/A|"* ]]; then
                    _gmf_name=$(echo "$_fab_line" | cut -d'|' -f1)
                    _gmf_ocid=$(echo "$_fab_line" | cut -d'|' -f3)
                    _gmf_state=$(echo "$_fab_line" | cut -d'|' -f4)
                fi
            fi

            # Display fabric (parent) first, then cluster
            if [[ -n "$_gmf_name" ]]; then
                local _gmf_sc; _gmf_sc=$(color_resource_state "$_gmf_state")
                printf "${WHITE}%-18s${NC}${GREEN}%s${NC} ${GRAY}[${YELLOW}%s${GRAY}]${NC} ${_gmf_sc}[%s]${NC}\n" "GPU Mem Fabric:" "$_gmf_name" "$_gmf_ocid" "$_gmf_state"
            fi
            if [[ -n "$_gmc_name" ]]; then
                local _gmc_sc; _gmc_sc=$(color_resource_state "$_gmc_state")
                printf "${WHITE}%-18s${NC}${GREEN}%s${NC} ${GRAY}[${YELLOW}%s${GRAY}]${NC} ${_gmc_sc}[%s]${NC}\n" "GPU Mem Cluster:" "$_gmc_name" "$gpu_mem_cluster" "$_gmc_state"
            else
                printf "${WHITE}%-18s${NC}${GRAY}[${YELLOW}%s${GRAY}]${NC}\n" "GPU Mem Cluster:" "$gpu_mem_cluster"
            fi
        fi
        if [[ -n "$compute_cluster_id" ]]; then
            local cc_name
            cc_name=$(get_compute_cluster_name "$compute_cluster_id")
            printf "${WHITE}%-18s${NC}${GREEN}%s${NC}\n" "Compute Cluster:" "$cc_name"
            printf "${WHITE}%-18s${NC}${YELLOW}%s${NC}\n" "" "$compute_cluster_id"
        fi
        if [[ -n "$oke_cluster_id" ]]; then
            # Rich OKE cluster details from prefetched data
            local _oke_c_name="" _oke_c_state="" _oke_c_k8s="" _oke_c_endpoint="" _oke_c_type=""
            if [[ -s "$_inst_oke_dir/oke_cluster.json" ]] && jq -e '.data' "$_inst_oke_dir/oke_cluster.json" >/dev/null 2>&1; then
                _oke_c_name=$(jq -r '.data.name // "N/A"' "$_inst_oke_dir/oke_cluster.json")
                _oke_c_state=$(jq -r '.data["lifecycle-state"] // "UNKNOWN"' "$_inst_oke_dir/oke_cluster.json")
                _oke_c_k8s=$(jq -r '.data["kubernetes-version"] // "N/A"' "$_inst_oke_dir/oke_cluster.json")
                _oke_c_endpoint=$(jq -r '.data.endpoints["public-endpoint"] // .data.endpoints["private-endpoint"] // "N/A"' "$_inst_oke_dir/oke_cluster.json")
                _oke_c_type=$(jq -r '.data.type // "N/A"' "$_inst_oke_dir/oke_cluster.json")
                local _oke_sc; _oke_sc=$(color_resource_state "$_oke_c_state")
                printf "${WHITE}%-18s${NC}${GREEN}%-40s${NC} ${_oke_sc}%-12s${NC} ${WHITE}K8s:${NC} %-12s ${WHITE}Type:${NC} %-12s\n" \
                    "OKE Cluster:" "$_oke_c_name" "$_oke_c_state" "$_oke_c_k8s" "$_oke_c_type"
                printf "${WHITE}%-18s${NC}${GRAY}%s${NC}\n" "" "$oke_cluster_id"
                [[ "$_oke_c_endpoint" != "N/A" ]] && printf "${WHITE}%-18s${NC}${CYAN}%s${NC}\n" "  Endpoint:" "$_oke_c_endpoint"
            else
                printf "${WHITE}%-18s${NC}${YELLOW}%s${NC}\n" "OKE Cluster:" "$oke_cluster_id"
            fi
        fi
        if [[ -n "$oke_nodepool_id" ]]; then
            # Rich node pool details from prefetched data
            local _oke_np_name="" _oke_np_state="" _oke_np_shape="" _oke_np_size="" _oke_np_k8s="" _oke_np_img=""
            if [[ -s "$_inst_oke_dir/oke_nodepool.json" ]] && jq -e '.data' "$_inst_oke_dir/oke_nodepool.json" >/dev/null 2>&1; then
                _oke_np_name=$(jq -r '.data.name // "N/A"' "$_inst_oke_dir/oke_nodepool.json")
                _oke_np_state=$(jq -r '.data["lifecycle-state"] // "UNKNOWN"' "$_inst_oke_dir/oke_nodepool.json")
                _oke_np_shape=$(jq -r '.data["node-shape"] // "N/A"' "$_inst_oke_dir/oke_nodepool.json")
                _oke_np_size=$(jq -r '.data["node-config-details"]["size"] // .data["node-pool-size"] // "N/A"' "$_inst_oke_dir/oke_nodepool.json")
                _oke_np_k8s=$(jq -r '.data["kubernetes-version"] // "N/A"' "$_inst_oke_dir/oke_nodepool.json")
                _oke_np_img=$(jq -r '.data["node-source"]["image-id"] // .data["node-source-details"]["image-id"] // "N/A"' "$_inst_oke_dir/oke_nodepool.json")
                local _oke_np_img_name; _oke_np_img_name=$(resolve_image_name_cached "$_oke_np_img" 2>/dev/null)
                [[ -z "$_oke_np_img_name" || "$_oke_np_img_name" == "N/A" ]] && _oke_np_img_name="(unknown)"
                local _oke_nsc; _oke_nsc=$(color_resource_state "$_oke_np_state")
                # nodes array only present from 'get', not from list cache
                local _node_ct_display
                if jq -e '.data.nodes' "$_inst_oke_dir/oke_nodepool.json" >/dev/null 2>&1; then
                    local _node_ct; _node_ct=$(jq '(.data.nodes // []) | length' "$_inst_oke_dir/oke_nodepool.json" 2>/dev/null || echo "0")
                    _node_ct_display="${_node_ct}/${_oke_np_size}"
                else
                    _node_ct_display="${_oke_np_size} target"
                fi
                printf "${WHITE}%-18s${NC}${GREEN}%-40s${NC} ${_oke_nsc}%-12s${NC} ${WHITE}Nodes:${NC} %-12s ${WHITE}Shape:${NC} %-20s\n" \
                    "OKE Node Pool:" "$_oke_np_name" "$_oke_np_state" "$_node_ct_display" "$_oke_np_shape"
                printf "${WHITE}%-18s${NC}${GRAY}%s${NC}\n" "" "$oke_nodepool_id"
                printf "${WHITE}%-18s${NC}${WHITE}%s${NC}  ${GRAY}[%s]${NC}\n" "  NP Image:" "$_oke_np_img_name" "$_oke_np_img"
                printf "${WHITE}%-18s${NC}${WHITE}%s${NC}\n" "  NP K8s:" "$_oke_np_k8s"
                echo -e "${GRAY}  ⚠ BVR/cycling for OKE nodes should be done via node pool (--manage, k, 1, np#)${NC}"
            else
                printf "${WHITE}%-18s${NC}${YELLOW}%s${NC}\n" "OKE Node Pool:" "$oke_nodepool_id"
            fi
        fi
        if [[ -n "$instance_config_id" ]]; then
            local ic_name
            ic_name=$(get_instance_config_name "$instance_config_id")
            printf "${WHITE}%-18s${NC}${GREEN}%s${NC}\n" "Instance Config:" "$ic_name"
            printf "${WHITE}%-18s${NC}${YELLOW}%s${NC}\n" "" "$instance_config_id"
        fi
    fi
    
    # ========== KUBERNETES STATUS (Compact - from prefetch cache) ==========
    echo ""
    _ui_subheader "Kubernetes" 0
    
    local k8s_node_info=""
    if [[ -n "$cached_k8s_nodes_json" ]]; then
        k8s_node_info=$(jq -r --arg ocid "$instance_ocid" '
            .items[] | select(.spec.providerID | contains($ocid)) | 
            "\(.metadata.name)|\(.status.conditions[] | select(.type=="Ready") | .status)|\(.metadata.labels["nvidia.com/gpu.clique"] // "N/A")|\(.metadata.labels["nvidia.com/gpu.present"] // "false")|\(.spec.unschedulable // false)|\((.spec.taints // []) | map(select(.key == "newNode")) | if length > 0 then .[0].effect else "N/A" end)|\(.metadata.labels["oci.oraclecloud.com/host.serial_number"] // "N/A")"
        ' <<< "$cached_k8s_nodes_json" 2>/dev/null)
    fi
    
    if [[ -n "$k8s_node_info" ]]; then
        local k8s_node_name k8s_ready k8s_clique k8s_gpu_present k8s_unschedulable k8s_new_node_taint k8s_serial
        IFS='|' read -r k8s_node_name k8s_ready k8s_clique k8s_gpu_present k8s_unschedulable k8s_new_node_taint k8s_serial <<< "$k8s_node_info"
        
        local ready_color="$GREEN"
        [[ "$k8s_ready" != "True" ]] && ready_color="$RED"
        
        # Get pod count on this node
        local k8s_pod_count k8s_ds_pod_count
        if [[ -n "$cached_k8s_pods_json" ]]; then
            k8s_pod_count=$(jq '.items | length' <<< "$cached_k8s_pods_json" 2>/dev/null)
            k8s_ds_pod_count=$(jq '[.items[] | select(.metadata.ownerReferences[]?.kind == "DaemonSet")] | length' <<< "$cached_k8s_pods_json" 2>/dev/null)
        fi
        [[ -z "$k8s_pod_count" ]] && k8s_pod_count="0"
        [[ -z "$k8s_ds_pod_count" ]] && k8s_ds_pod_count="0"
        
        # Determine scheduling status
        local sched_status="Schedulable"
        local sched_color="$GREEN"
        if [[ "$k8s_unschedulable" == "true" ]]; then
            local non_ds_pods=$((k8s_pod_count - k8s_ds_pod_count))
            if [[ $non_ds_pods -le 0 ]]; then
                sched_status="Drained"
                sched_color="$RED"
            else
                sched_status="Cordoned"
                sched_color="$YELLOW"
            fi
        fi
        
        # Check for newNode taint
        local taint_info=""
        local taint_color="$GRAY"
        if [[ "$k8s_new_node_taint" != "N/A" && -n "$k8s_new_node_taint" ]]; then
            taint_info="newNode:${k8s_new_node_taint}"
            taint_color="$YELLOW"
        fi
        
        printf "${WHITE}%-10s${NC}${GREEN}%-14s${NC}  ${WHITE}%-8s${NC}${GREEN}%-22s${NC}  ${WHITE}%-8s${NC}${ready_color}%-8s${NC}  ${WHITE}%-10s${NC}${sched_color}%-12s${NC}  ${WHITE}%-6s${NC}${CYAN}%-5s${NC}\n" \
            "Status:" "In Cluster" "Node:" "$k8s_node_name" "Ready:" "$k8s_ready" "Schedule:" "$sched_status" "Pods:" "$k8s_pod_count"
        
        # Second line with GPU and taint info
        if [[ "$k8s_gpu_present" == "true" ]]; then
            local clique_info="N/A"
            [[ "$k8s_clique" != "N/A" ]] && clique_info="$k8s_clique"
            if [[ -n "$taint_info" ]]; then
                printf "${WHITE}%-10s${NC}${GREEN}%-14s${NC}  ${WHITE}%-8s${NC}${CYAN}%-22s${NC}  ${WHITE}%-8s${NC}${taint_color}%-20s${NC}\n" "GPU:" "Present" "Clique:" "$clique_info" "Taint:" "$taint_info"
            else
                printf "${WHITE}%-10s${NC}${GREEN}%-14s${NC}  ${WHITE}%-8s${NC}${CYAN}%-22s${NC}\n" "GPU:" "Present" "Clique:" "$clique_info"
            fi
        elif [[ -n "$taint_info" ]]; then
            printf "${WHITE}%-10s${NC}${taint_color}%-30s${NC}\n" "Taint:" "$taint_info"
        fi
    else
        printf "${WHITE}%-10s${NC}${YELLOW}%-50s${NC}\n" "Status:" "Not in cluster (not joined or not found)"
    fi
    
    # ========== NETWORK / VNIC INFORMATION (Single Line per VNIC) ==========
    echo ""
    _ui_subheader "Network (VNICs)" 0
    
    if [[ -n "$cached_vnic_attachments" ]] && jq -e '.data[]' <<< "$cached_vnic_attachments" > /dev/null 2>&1; then
        # Print header
        printf "${GRAY}%-3s %-30s %-15s %-15s %-22s %-22s %-6s %-55s %s${NC}\n" "NIC" "Name" "Private IP" "Public IP" "Subnet" "Route Table" "VLAN" "NSG" "OCID"
        
        jq -r '.data[] | "\(.["vnic-id"])|\(.["display-name"] // "N/A")|\(.["nic-index"] // 0)|\(.["vlan-tag"] // "")"' <<< "$cached_vnic_attachments" 2>/dev/null | \
        while IFS='|' read -r vnic_id vnic_attach_name nic_index vlan_tag; do
            [[ -z "$vnic_id" ]] && continue
            
            # Get VNIC details from cache
            local vnic_json
            vnic_json=$(jq --arg id "$vnic_id" '.[$id]' <<< "$cached_vnic_details" 2>/dev/null)
            
            if [[ -n "$vnic_json" && "$vnic_json" != "null" ]] && jq -e '.data' <<< "$vnic_json" > /dev/null 2>&1; then
                local vnic_name private_ip public_ip subnet_id mac_addr is_primary
                IFS=$'\t' read -r vnic_name private_ip public_ip subnet_id mac_addr is_primary < <(jq -r '.data | [
                    .["display-name"] // "N/A",
                    .["private-ip"] // "N/A",
                    .["public-ip"] // "N/A",
                    .["subnet-id"] // "N/A",
                    .["mac-address"] // "N/A",
                    .["is-primary"] // false
                ] | @tsv' <<< "$vnic_json")
                
                # Get NSG names from cache
                local nsg_ids nsg_names=""
                nsg_ids=$(jq -r '.data["nsg-ids"] // [] | .[]' <<< "$vnic_json" 2>/dev/null)
                if [[ -n "$nsg_ids" ]]; then
                    while read -r nsg_id; do
                        [[ -z "$nsg_id" ]] && continue
                        local nsg_name
                        nsg_name=$(jq -r --arg id "$nsg_id" '.[$id] // "N/A"' <<< "$cached_nsg_names" 2>/dev/null)
                        [[ "$nsg_name" == "null" ]] && nsg_name="N/A"
                        if [[ -n "$nsg_names" ]]; then
                            nsg_names="${nsg_names}, ${nsg_name}"
                        else
                            nsg_names="$nsg_name"
                        fi
                    done <<< "$nsg_ids"
                fi
                [[ -z "$nsg_names" ]] && nsg_names="-"
                
                # Get subnet name from cache
                local subnet_name="-"
                local route_table_name="-"
                if [[ "$subnet_id" != "N/A" && -n "$subnet_id" ]]; then
                    subnet_name=$(jq -r --arg id "$subnet_id" '.[$id].name // "-"' <<< "$cached_subnet_names" 2>/dev/null)
                    route_table_name=$(jq -r --arg id "$subnet_id" '.[$id].rt // "-"' <<< "$cached_subnet_names" 2>/dev/null)
                    [[ "$subnet_name" == "null" ]] && subnet_name="-"
                    [[ "$route_table_name" == "null" ]] && route_table_name="-"
                    # Truncate to fit column width
                    [[ ${#subnet_name} -gt 22 ]] && subnet_name="${subnet_name:0:20}.."
                    [[ ${#route_table_name} -gt 22 ]] && route_table_name="${route_table_name:0:20}.."
                fi
                
                local nic_display="$nic_index"
                [[ "$is_primary" == "true" ]] && nic_display="${nic_index}*"
                
                # Format public IP and VLAN display
                local pub_ip_display="N/A"
                [[ -n "$public_ip" && "$public_ip" != "null" && "$public_ip" != "N/A" ]] && pub_ip_display="$public_ip"
                local vlan_display="-"
                [[ -n "$vlan_tag" ]] && vlan_display="$vlan_tag"
                
                # Truncate name to fit column width
                local vnic_name_t="$vnic_name"
                [[ ${#vnic_name_t} -gt 30 ]] && vnic_name_t="${vnic_name_t:0:28}.."
                
                # Single line with all info - NSG fully expanded near end
                printf "%-3s ${GREEN}%-30s${NC} ${CYAN}%-15s${NC} ${CYAN}%-15s${NC} %-22s %-22s %-6s %-55s ${YELLOW}%s${NC}\n" \
                    "$nic_display" "$vnic_name_t" "$private_ip" "$pub_ip_display" "$subnet_name" "$route_table_name" "$vlan_display" "$nsg_names" "$vnic_id"
            fi
        done
    else
        echo -e "${YELLOW}No VNICs found${NC}"
    fi
    
    # ========== BOOT VOLUME (with extended details) ==========
    echo ""
    _ui_subheader "Boot Volume" 0
    
    if [[ -n "$cached_boot_vol_attachments" ]] && jq -e '.data[]' <<< "$cached_boot_vol_attachments" > /dev/null 2>&1; then
        # Print header (aligned with block volumes)
        printf "${GRAY}%-40s %-9s %-5s %-3s %-5s %-6s %-8s %-4s %-4s %-4s %-6s %s${NC}\n" "Name" "State" "Size" "VPU" "Type" "Backup" "BkupMgd" "Repl" "VGrp" "Hydr" "EncKey" "OCID"
        
        jq -r '.data[] | "\(.["boot-volume-id"])|\(.["lifecycle-state"])"' <<< "$cached_boot_vol_attachments" 2>/dev/null | \
        while IFS='|' read -r bv_id bv_attach_state; do
            [[ -z "$bv_id" ]] && continue
            
            # Get boot volume details from cache
            local bv_json
            bv_json=$(jq --arg id "$bv_id" '.[$id]' <<< "$cached_boot_vol_details" 2>/dev/null)
            
            if [[ -n "$bv_json" && "$bv_json" != "null" ]] && jq -e '.data' <<< "$bv_json" > /dev/null 2>&1; then
                local bv_name bv_state bv_size_gb bv_vpus
                bv_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$bv_json")
                bv_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$bv_json")
                bv_size_gb=$(jq -r '.data["size-in-gbs"] // "N/A"' <<< "$bv_json")
                bv_vpus=$(jq -r '.data["vpus-per-gb"] // "N/A"' <<< "$bv_json")
                
                # Get additional fields
                local kms_key_id volume_group_id is_hydrated
                kms_key_id=$(jq -r '.data["kms-key-id"] // empty' <<< "$bv_json")
                volume_group_id=$(jq -r '.data["volume-group-id"] // empty' <<< "$bv_json")
                is_hydrated=$(jq -r '.data["is-hydrated"] // "N/A"' <<< "$bv_json")
                
                # Get backup policy from cache
                local backup_policy="None"
                local cached_policy
                cached_policy=$(jq -r --arg id "$bv_id" '.[$id] // "None"' <<< "$cached_backup_policies" 2>/dev/null)
                [[ -n "$cached_policy" && "$cached_policy" != "null" ]] && backup_policy="$cached_policy"
                
                # Backup managed by: Volume (direct) or VolGroup (if in volume group)
                local backup_managed="Volume"
                [[ -n "$volume_group_id" ]] && backup_managed="VolGroup"
                
                # Check cross-region replication
                local repl_status="-"
                local replicas
                replicas=$(jq -r '.data["boot-volume-replicas"] // [] | length' <<< "$bv_json" 2>/dev/null)
                [[ "$replicas" -gt 0 ]] && repl_status="Yes"
                
                # Format displays
                local bv_state_color="$GREEN"
                [[ "$bv_state" != "AVAILABLE" ]] && bv_state_color="$YELLOW"
                
                # Encryption: Oracle managed (no kms-key-id) or Customer (has kms-key-id/Vault)
                local enc_display="Oracle"
                [[ -n "$kms_key_id" ]] && enc_display="Cust"
                
                local vg_display="-"
                [[ -n "$volume_group_id" ]] && vg_display="Yes"
                
                local hydr_display="-"
                [[ "$is_hydrated" == "true" ]] && hydr_display="Yes"
                [[ "$is_hydrated" == "false" ]] && hydr_display="No"
                
                # Truncate name to fit column width
                local bv_name_t="$bv_name"
                [[ ${#bv_name_t} -gt 40 ]] && bv_name_t="${bv_name_t:0:38}.."
                
                printf "${GREEN}%-40s${NC} ${bv_state_color}%-9s${NC} %-5s %-3s %-5s %-6s %-8s %-4s %-4s %-4s %-6s ${YELLOW}%s${NC}\n" \
                    "$bv_name_t" "$bv_state" "${bv_size_gb}GB" "$bv_vpus" "boot" "${backup_policy:0:6}" "$backup_managed" "$repl_status" "$vg_display" "$hydr_display" "$enc_display" "$bv_id"
            fi
        done
    else
        echo -e "${YELLOW}No boot volume found${NC}"
    fi
    
    # ========== BLOCK VOLUMES (with extended details) ==========
    echo ""
    _ui_subheader "Block Volumes" 0
    
    local vol_count=0
    if [[ -n "$cached_block_vol_attachments" ]] && jq -e '.data[]' <<< "$cached_block_vol_attachments" > /dev/null 2>&1; then
        # Print header (aligned with boot volume)
        printf "${GRAY}%-40s %-9s %-5s %-3s %-5s %-6s %-8s %-4s %-4s %-4s %-6s %s${NC}\n" "Name" "State" "Size" "VPU" "Type" "Backup" "BkupMgd" "Repl" "VGrp" "Hydr" "EncKey" "OCID"
        
        while IFS='|' read -r vol_id attach_state attach_type device is_readonly; do
            [[ -z "$vol_id" ]] && continue
            ((vol_count++))
            
            # Get block volume details from cache
            local vol_json
            vol_json=$(jq --arg id "$vol_id" '.[$id]' <<< "$cached_block_vol_details" 2>/dev/null)
            
            if [[ -n "$vol_json" && "$vol_json" != "null" ]] && jq -e '.data' <<< "$vol_json" > /dev/null 2>&1; then
                local vol_name vol_state vol_size_gb vol_vpus is_hydrated
                vol_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$vol_json")
                vol_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$vol_json")
                vol_size_gb=$(jq -r '.data["size-in-gbs"] // "N/A"' <<< "$vol_json")
                vol_vpus=$(jq -r '.data["vpus-per-gb"] // "N/A"' <<< "$vol_json")
                is_hydrated=$(jq -r '.data["is-hydrated"] // "N/A"' <<< "$vol_json")
                
                # Get additional fields
                local kms_key_id volume_group_id
                kms_key_id=$(jq -r '.data["kms-key-id"] // empty' <<< "$vol_json")
                volume_group_id=$(jq -r '.data["volume-group-id"] // empty' <<< "$vol_json")
                
                # Get backup policy from cache
                local backup_policy="None"
                local cached_policy
                cached_policy=$(jq -r --arg id "$vol_id" '.[$id] // "None"' <<< "$cached_backup_policies" 2>/dev/null)
                [[ -n "$cached_policy" && "$cached_policy" != "null" ]] && backup_policy="$cached_policy"
                
                # Backup managed by: Volume (direct) or VolGroup (if in volume group)
                local backup_managed="Volume"
                [[ -n "$volume_group_id" ]] && backup_managed="VolGroup"
                
                # Check cross-region replication
                local repl_status="-"
                local replicas
                replicas=$(jq -r '.data["block-volume-replicas"] // [] | length' <<< "$vol_json" 2>/dev/null)
                [[ "$replicas" -gt 0 ]] && repl_status="Yes"
                
                # Format displays
                local vol_state_color="$GREEN"
                [[ "$vol_state" != "AVAILABLE" ]] && vol_state_color="$YELLOW"
                
                local name_display="$vol_name"
                [[ "$is_readonly" == "true" ]] && name_display="${vol_name}*RO"
                
                # Encryption: Oracle managed (no kms-key-id) or Customer (has kms-key-id/Vault)
                local enc_display="Oracle"
                [[ -n "$kms_key_id" ]] && enc_display="Cust"
                
                local vg_display="-"
                [[ -n "$volume_group_id" ]] && vg_display="Yes"
                
                local hydr_display="-"
                [[ "$is_hydrated" == "true" ]] && hydr_display="Yes"
                [[ "$is_hydrated" == "false" ]] && hydr_display="No"
                
                # Truncate name to fit column width
                [[ ${#name_display} -gt 40 ]] && name_display="${name_display:0:38}.."
                
                printf "${GREEN}%-40s${NC} ${vol_state_color}%-9s${NC} %-5s %-3s %-5s %-6s %-8s %-4s %-4s %-4s %-6s ${YELLOW}%s${NC}\n" \
                    "$name_display" "$vol_state" "${vol_size_gb}GB" "$vol_vpus" "$attach_type" "${backup_policy:0:6}" "$backup_managed" "$repl_status" "$vg_display" "$hydr_display" "$enc_display" "$vol_id"
            fi
        done < <(jq -r '.data[] | "\(.["volume-id"])|\(.["lifecycle-state"])|\(.["attachment-type"])|\(.device // "N/A")|\(.["is-read-only"] // false)"' <<< "$cached_block_vol_attachments" 2>/dev/null)
    fi
    
    [[ $vol_count -eq 0 ]] && echo -e "${GRAY}No block volumes attached${NC}"
    
    # ========== TAGS ==========
    echo ""
    _ui_subheader "Tags" 0
    
    # Defined Tags
    local defined_tags
    defined_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$instance_json")
    
    local has_defined_tags="false"
    if [[ -n "$defined_tags" && "$defined_tags" != "{}" ]]; then
        has_defined_tags="true"
        echo -e "${CYAN}Defined Tags:${NC}"
        jq -r 'to_entries[] | .key as $ns | .value | to_entries[] | "\($ns).\(.key) = \(.value)"' <<< "$defined_tags" 2>/dev/null | while read -r tag_line; do
            # Split into namespace.key and value
            local tag_key="${tag_line%% = *}"
            local tag_val="${tag_line#* = }"
            # Highlight unhealthy tags
            if [[ "$tag_line" == *"ComputeInstanceHostActions"* ]]; then
                echo -e "  ${RED}★ ${WHITE}${tag_key}${NC} = ${RED}${tag_val}${NC}"
            else
                echo -e "  ${WHITE}${tag_key}${NC} = ${GRAY}${tag_val}${NC}"
            fi
        done
    fi
    
    # Freeform Tags
    local freeform_tags
    freeform_tags=$(jq -r '.data["freeform-tags"] // {}' <<< "$instance_json")
    
    local has_freeform_tags="false"
    if [[ -n "$freeform_tags" && "$freeform_tags" != "{}" ]]; then
        has_freeform_tags="true"
        [[ "$has_defined_tags" == "true" ]] && echo ""
        echo -e "${CYAN}Freeform Tags:${NC}"
        jq -r 'to_entries[] | "\(.key) = \(.value)"' <<< "$freeform_tags" 2>/dev/null | while read -r tag_line; do
            local tag_key="${tag_line%% = *}"
            local tag_val="${tag_line#* = }"
            # Highlight GPU/cluster related tags
            if [[ "$tag_line" == *"gpumemorycluster"* || "$tag_line" == *"oke-"* ]]; then
                echo -e "  ${WHITE}${tag_key}${NC} = ${GREEN}${tag_val}${NC}"
            else
                echo -e "  ${WHITE}${tag_key}${NC} = ${GRAY}${tag_val}${NC}"
            fi
        done
    fi
    
    [[ "$has_defined_tags" == "false" && "$has_freeform_tags" == "false" ]] && echo -e "${GRAY}No tags${NC}"
    
    # Check for user_data (cloud-init)
    local user_data_b64
    user_data_b64=$(jq -r '.data.metadata.user_data // empty' <<< "$instance_json")
    
    local has_cloud_init="false"
    if [[ -n "$user_data_b64" ]]; then
        has_cloud_init="true"
        local ud_decoded_size
        ud_decoded_size=$(echo "$user_data_b64" | base64 -d 2>/dev/null | wc -c)
        echo ""
        _ui_subheader "Cloud-Init" 0
        local gzip_indicator=""
        is_user_data_gzip "$user_data_b64" && gzip_indicator=" (gzip)"
        printf "${WHITE}%-10s${NC}${GREEN}%-15s${NC}  ${WHITE}%-8s${NC}%-15s\n" "Status:" "Present${gzip_indicator}" "Size:" "~${ud_decoded_size} bytes"
    fi
    
    # Check if in K8s (reuse prefetch cache)
    local k8s_node_name="${cached_k8s_node_name:-}"
    
    # ── Instance WR display helper ──
    declare -A _INST_WR_MAP=()
    local _INST_WR_IDX=0
    _inst_display_wr() {
        local _wr_file="${1:-$_inst_wr_dir/wr.json}"
        _INST_WR_MAP=()
        _INST_WR_IDX=0
        if [[ ! -s "$_wr_file" ]] || ! jq -e '.data[0]' "$_wr_file" >/dev/null 2>&1; then
            echo -e "  ${GRAY}No work requests found${NC}"
            return
        fi
        printf "  ${BOLD}%-5s %-14s %-28s %-20s %-20s %s${NC}\n" "#" "Status" "Operation" "Started" "Finished" "Work Request ID"
        print_separator 130
        while IFS=$'\t' read -r _ws _wop _wt _wf _wid; do
            ((_INST_WR_IDX++))
            _INST_WR_MAP[$_INST_WR_IDX]="$_wid"
            local _wc="${WHITE}"
            [[ "$_ws" == "SUCCEEDED" ]] && _wc="${GREEN}"
            [[ "$_ws" == "FAILED" || "$_ws" == "CANCELED" ]] && _wc="${RED}"
            [[ "$_ws" == "IN_PROGRESS" || "$_ws" == "ACCEPTED" ]] && _wc="${YELLOW}"
            local _wf_disp="${_wf:0:19}"
            [[ "$_wf" == "null" || "$_wf" == "N/A" || -z "$_wf" ]] && _wf_disp="-"
            printf "  ${YELLOW}%-5s${NC} ${_wc}%-14s${NC} %-28s %-20s %-20s ${YELLOW}%s${NC}\n" \
                "wr${_INST_WR_IDX}" "$_ws" "${_wop:0:28}" "${_wt:0:19}" "$_wf_disp" "${_wid}"
        done < <(jq -r '(.data // [])[] | [
            (.status // "UNKNOWN"),
            (.["operation-type"] // .operationType // "N/A"),
            (.["time-accepted"] // .timeAccepted // "N/A"),
            (.["time-finished"] // .timeFinished // "null"),
            (.id // "N/A")
        ] | @tsv' "$_wr_file" 2>/dev/null)
        echo ""
    }
    
    # ── Instance WR detail (delegates to centralized _wr_generic_detail) ──
    _inst_wr_detail() {
        local _wrid="$1"
        [[ -z "$_wrid" ]] && return 1
        
        # Build OCID→name map from instance context
        declare -A _WR_OCID_NAMES=()
        [[ -n "$instance_ocid" && -n "$display_name" ]] && _WR_OCID_NAMES["$instance_ocid"]="$display_name"
        if [[ -s "$INSTANCE_LIST_CACHE" ]]; then
            while IFS=$'\t' read -r _oid _oname; do
                [[ -n "$_oid" && -z "${_WR_OCID_NAMES[$_oid]:-}" ]] && _WR_OCID_NAMES["$_oid"]="$_oname"
            done < <(jq -r '.data[] | [.id, .["display-name"]] | @tsv' "$INSTANCE_LIST_CACHE" 2>/dev/null)
        fi
        # OKE context if available
        [[ -n "${oke_cluster_id:-}" ]] && {
            local _cname=""
            [[ -s "$OKE_CLUSTER_JSON_CACHE" ]] && _cname=$(jq -r '.data.name // empty' "$OKE_CLUSTER_JSON_CACHE" 2>/dev/null)
            [[ -n "$_cname" ]] && _WR_OCID_NAMES["$oke_cluster_id"]="$_cname"
        }
        [[ -n "${oke_nodepool_id:-}" ]] && {
            local _npname=""
            [[ -s "$OKE_NODEPOOL_CACHE" ]] && _npname=$(jq -r --arg id "$oke_nodepool_id" '.data[] | select(.id == $id) | .name // empty' "$OKE_NODEPOOL_CACHE" 2>/dev/null)
            [[ -n "$_npname" ]] && _WR_OCID_NAMES["$oke_nodepool_id"]="$_npname"
        }
        
        _wr_generic_detail "$_wrid" "$_inst_wr_dir/detail" \
            "Instance WR - ${display_name}" "" "enrich" "Compute|Instances|Work Requests|Detail"
    }
    
    # ── Run Command helpers ──
    declare -A _INST_RC_MAP=()
    local _INST_RC_IDX=0
    
    _inst_display_rc() {
        local _rc_file="${1:-$_inst_rc_dir/rc.json}"
        _INST_RC_MAP=()
        _INST_RC_IDX=0
        if [[ ! -s "$_rc_file" ]] || ! jq -e '.data[0]' "$_rc_file" >/dev/null 2>&1; then
            echo -e "  ${GRAY}No run commands found${NC}"
            return
        fi
        printf "  ${BOLD}%-5s %-14s %-50s %-20s %-20s %s${NC}\n" "#" "Status" "Display Name" "Created" "Updated" "Command OCID"
        print_separator 165
        while IFS=$'|' read -r _rcmdid _rstate _rdisp _rcreated _rupdated; do
            [[ -z "$_rcmdid" ]] && continue
            ((_INST_RC_IDX++))
            _INST_RC_MAP[$_INST_RC_IDX]="${_rcmdid}|${_rstate}|${_rdisp}"
            local _rc="${WHITE}"
            [[ "$_rstate" == "SUCCEEDED" ]] && _rc="${GREEN}"
            [[ "$_rstate" == "FAILED" || "$_rstate" == "CANCELED" || "$_rstate" == "TIMED_OUT" ]] && _rc="${RED}"
            [[ "$_rstate" == "IN_PROGRESS" || "$_rstate" == "QUEUED" || "$_rstate" == "PENDING" || "$_rstate" == "ACCEPTED" ]] && _rc="${YELLOW}"
            local _updated_disp="${_rupdated:0:19}"
            [[ -z "$_rupdated" || "$_rupdated" == "null" ]] && _updated_disp="-"
            printf "  ${YELLOW}%-5s${NC} ${_rc}%-14s${NC} %-50s %-20s %-20s ${YELLOW}%s${NC}\n" \
                "rc${_INST_RC_IDX}" "$_rstate" "${_rdisp:0:50}" "${_rcreated:0:19}" "$_updated_disp" "${_rcmdid}"
        done < <(jq -r '(.data // [])[] | [
            (."instance-agent-command-id" // .id // "N/A"),
            (."lifecycle-state" // ."delivery-state" // ."delivery-status" // "UNKNOWN"),
            (."display-name" // "-"),
            (."time-created" // "N/A"),
            (."time-updated" // "null")
        ] | join("|")' "$_rc_file" 2>/dev/null)
        echo ""
    }
    
    _inst_rc_detail() {
        local _entry="${1:-}"
        [[ -z "$_entry" ]] && return 1
        local _cmd_id="${_entry%%|*}"
        [[ -z "$_cmd_id" ]] && return 1
        
        echo ""
        _step_init
        _step_active "command detail"
        
        mkdir -p "$_inst_rc_dir/detail"
        
        # Parallel fetch: command get + command-execution get
        local _rc_pids=()
        (oci instance-agent command get --command-id "$_cmd_id" --region "$region" --output json > "$_inst_rc_dir/detail/cmd.json" 2>/dev/null) &
        _rc_pids+=($!)
        (oci instance-agent command-execution get --command-id "$_cmd_id" --instance-id "$instance_ocid" --region "$region" --output json > "$_inst_rc_dir/detail/exec.json" 2>/dev/null) &
        _rc_pids+=($!)
        wait "${_rc_pids[@]}" 2>/dev/null
        _step_complete "command detail"
        _step_finish
        
        # Parse command info
        local _cmd_json="$_inst_rc_dir/detail/cmd.json"
        local _exec_json="$_inst_rc_dir/detail/exec.json"
        
        local _c_id _c_comp _c_timeout _c_created _c_updated
        if [[ -s "$_cmd_json" ]] && jq -e '.data' "$_cmd_json" >/dev/null 2>&1; then
            IFS=$'|' read -r _c_id _c_comp _c_timeout _c_created _c_updated < <(jq -r '.data | [
                (.id // "N/A"),
                (."compartment-id" // .compartmentId // "N/A"),
                (."timeout-in-seconds" // .timeoutInSeconds // "60"),
                (."time-created" // .timeCreated // "N/A"),
                (."time-updated" // .timeUpdated // "N/A")
            ] | join("|")' "$_cmd_json" 2>/dev/null)
        fi
        
        # Parse script content from command
        local _script_text="" _source_type=""
        if [[ -s "$_cmd_json" ]] && jq -e '.data' "$_cmd_json" >/dev/null 2>&1; then
            _source_type=$(jq -r '.data.content.source."source-type" // .data.content.source.sourceType // "UNKNOWN"' "$_cmd_json" 2>/dev/null)
            if [[ "$_source_type" == "TEXT" ]]; then
                _script_text=$(jq -r '.data.content.source.text // "N/A"' "$_cmd_json" 2>/dev/null)
            else
                _script_text=$(jq -r '.data.content.source."source-uri" // .data.content.source.sourceUri // "N/A"' "$_cmd_json" 2>/dev/null)
            fi
        fi
        
        # Parse execution results
        local _e_state _e_exit _e_msg _e_stdout
        if [[ -s "$_exec_json" ]] && jq -e '.data' "$_exec_json" >/dev/null 2>&1; then
            _e_state=$(jq -r '.data."lifecycle-state" // .data."delivery-state" // .data."delivery-status" // "UNKNOWN"' "$_exec_json" 2>/dev/null)
            _e_exit=$(jq -r '.data.content.output."exit-code" // .data.content.output.exitCode // "N/A"' "$_exec_json" 2>/dev/null)
            _e_msg=$(jq -r '.data.content.output.message // empty' "$_exec_json" 2>/dev/null)
            _e_stdout=$(jq -r '.data.content.output.text // empty' "$_exec_json" 2>/dev/null)
        else
            _e_state="NO DATA"
        fi
        
        # Display
        local _state_color="${WHITE}"
        [[ "$_e_state" == "SUCCEEDED" ]] && _state_color="${GREEN}"
        [[ "$_e_state" == "FAILED" || "$_e_state" == "TIMED_OUT" ]] && _state_color="${RED}"
        [[ "$_e_state" == "IN_PROGRESS" || "$_e_state" == "PENDING" || "$_e_state" == "ACCEPTED" ]] && _state_color="${YELLOW}"
        
        echo ""
        _ui_subheader "Run Command Detail" 0
        echo ""
        echo -e "  ${CYAN}Command:${NC}  ${YELLOW}${_c_id:-$_cmd_id}${NC}"
        echo -e "  ${CYAN}Status:${NC}   ${_state_color}${_e_state}${NC}"
        echo -e "  ${CYAN}Timeout:${NC}  ${_c_timeout:-60}s"
        echo -e "  ${CYAN}Created:${NC}  ${_c_created:-N/A}"
        echo -e "  ${CYAN}Updated:${NC}  ${_c_updated:-N/A}"
        
        local _exit_color="${GREEN}"
        [[ "${_e_exit:-N/A}" != "0" && "${_e_exit:-N/A}" != "N/A" ]] && _exit_color="${RED}"
        echo -e "  ${CYAN}Exit:${NC}     ${_exit_color}${_e_exit:-N/A}${NC}"
        
        if [[ -n "$_e_msg" ]]; then
            echo -e "  ${CYAN}Message:${NC}  ${_e_msg}"
        fi
        
        echo ""
        _ui_subheader "Script Content" 0
        echo ""
        if [[ -n "$_script_text" && "$_script_text" != "N/A" && "$_script_text" != "null" ]]; then
            if [[ "$_source_type" != "TEXT" ]]; then
                echo -e "    ${GRAY}Source (${_source_type}): ${_script_text}${NC}"
            else
                while IFS= read -r _line; do
                    echo -e "    ${GRAY}${_line}${NC}"
                done <<< "$_script_text"
            fi
        else
            echo -e "    ${GRAY}(script content not available - may be file-based or expired)${NC}"
        fi
        
        echo ""
        _ui_subheader "Execution Output" 0
        echo ""
        if [[ -n "$_e_stdout" ]]; then
            echo -e "  ${WHITE}stdout:${NC}"
            while IFS= read -r _line; do
                echo -e "    ${_line}"
            done <<< "$_e_stdout"
        else
            echo -e "  ${WHITE}stdout:${NC} ${GRAY}(empty or unavailable)${NC}"
        fi
        
        echo ""
        
        # Action loop
        while true; do
            _ui_prompt "Run Command - ${display_name}" "r, j, j <key>, Enter=back"
            local _rc_act; read -r _rc_act
            [[ "${_rc_act:-}" == :* ]] && _nav_try_jump "$_rc_act" && return
            case "$_rc_act" in
                r|R) _inst_rc_detail "$_entry"; return ;;
                j|J)
                    if [[ -s "$_cmd_json" ]]; then
                        _ui_json_viewer "Command JSON" "-f" "$_cmd_json" ".data"
                    else
                        echo -e "\n  ${CYAN}Command JSON:${NC} ${GRAY}(unavailable)${NC}"
                    fi
                    if [[ -s "$_exec_json" ]]; then
                        _ui_json_viewer "Execution JSON" "-f" "$_exec_json" ".data"
                    else
                        echo -e "\n  ${CYAN}Execution JSON:${NC} ${GRAY}(unavailable)${NC}"
                    fi
                    ;;
                j\ *|J\ *)
                    local _rc_search="${_rc_act#* }"
                    if [[ -s "$_cmd_json" ]]; then
                        _ui_json_viewer "Command JSON" "-f" "$_cmd_json" ".data" "$_rc_search"
                    fi
                    if [[ -s "$_exec_json" ]]; then
                        _ui_json_viewer "Execution JSON" "-f" "$_exec_json" ".data" "$_rc_search"
                    fi
                    [[ ! -s "$_cmd_json" && ! -s "$_exec_json" ]] && echo -e "  ${GRAY}(no JSON available)${NC}"
                    ;;
                *) break ;;
            esac
        done
    }
    
    _inst_rc_create() {
        local _rc_log="${LOGS_DIR}/runcommand_actions.log"
        mkdir -p "$(dirname "$_rc_log")" 2>/dev/null
        
        echo ""
        _ui_subheader "Run Command on ${display_name}" 0
        echo ""
        echo -e "  ${CYAN}1${NC}) Type/paste inline script"
        echo -e "  ${CYAN}2${NC}) Select file from current directory"
        echo -e "  ${CYAN}3${NC}) Enter absolute file path"
        echo ""
        echo -n -e "  ${CYAN}Select source (1-3, Enter=cancel): ${NC}"
        local _src_choice; read -r _src_choice
        
        local _script_content=""
        
        case "$_src_choice" in
            1)
                echo ""
                echo -e "  ${WHITE}Enter script (finish with a line containing only 'EOF' or press Ctrl-D):${NC}"
                echo -e "  ${GRAY}──────────────────────────────────────────────────${NC}"
                local _lines=""
                while IFS= read -r _line; do
                    [[ "$_line" == "EOF" || "$_line" == "eof" ]] && break
                    _lines+="${_line}"$'\n'
                done
                _script_content="$_lines"
                ;;
            2)
                echo ""
                echo -e "  ${WHITE}Files in current directory ($(pwd)):${NC}"
                local -a _files=()
                local _fi=0
                while IFS= read -r _f; do
                    [[ -z "$_f" ]] && continue
                    ((_fi++))
                    _files[$_fi]="$_f"
                    printf "    ${YELLOW}%-4s${NC} %s\n" "$_fi)" "$_f"
                done < <(find . -maxdepth 1 -type f -name '*.sh' -o -name '*.py' -o -name '*.bash' -o -name '*.txt' 2>/dev/null | sort)
                if [[ $_fi -eq 0 ]]; then
                    echo -e "    ${GRAY}No script files found (.sh, .py, .bash, .txt)${NC}"
                    echo -e "    ${GRAY}Showing all files:${NC}"
                    while IFS= read -r _f; do
                        [[ -z "$_f" ]] && continue
                        ((_fi++))
                        _files[$_fi]="$_f"
                        printf "    ${YELLOW}%-4s${NC} %s\n" "$_fi)" "$_f"
                    done < <(find . -maxdepth 1 -type f 2>/dev/null | sort | head -20)
                fi
                echo ""
                echo -n -e "  ${CYAN}Select file #: ${NC}"
                local _fc; read -r _fc
                if [[ -n "${_files[$_fc]:-}" && -f "${_files[$_fc]}" ]]; then
                    _script_content=$(cat "${_files[$_fc]}")
                    echo -e "  ${GREEN}✓ Loaded: ${_files[$_fc]}${NC}"
                else
                    echo -e "  ${RED}Invalid selection${NC}"
                    _ui_pause "return"
                    return
                fi
                ;;
            3)
                echo ""
                echo -n -e "  ${CYAN}Enter absolute file path: ${NC}"
                local _fp; read -r _fp
                if [[ -f "$_fp" ]]; then
                    _script_content=$(cat "$_fp")
                    echo -e "  ${GREEN}✓ Loaded: ${_fp}${NC}"
                else
                    echo -e "  ${RED}File not found: ${_fp}${NC}"
                    _ui_pause "return"
                    return
                fi
                ;;
            *)
                echo -e "  ${YELLOW}Cancelled${NC}"
                return
                ;;
        esac
        
        if [[ -z "$_script_content" ]]; then
            echo -e "  ${RED}No script content provided${NC}"
            _ui_pause "return"
            return
        fi
        
        # Ask for timeout
        echo ""
        echo -n -e "  ${CYAN}Timeout in seconds (default=3600): ${NC}"
        local _timeout; read -r _timeout
        [[ -z "$_timeout" ]] && _timeout=3600
        
        # Ask for display name
        echo -n -e "  ${CYAN}Command label (optional, Enter=skip): ${NC}"
        local _rc_label; read -r _rc_label
        [[ -z "$_rc_label" ]] && _rc_label="rc-$(date +%H%M%S)"
        
        # Preview
        echo ""
        local _preview; _preview=$(head -3 <<< "$_script_content")
        local _total_lines; _total_lines=$(wc -l <<< "$_script_content")
        echo -e "  ${WHITE}Preview (${_total_lines} lines):${NC}"
        echo -e "  ${GRAY}──────────────────────────────────────────────────${NC}"
        while IFS= read -r _line; do
            echo -e "    ${GRAY}${_line}${NC}"
        done <<< "$_preview"
        [[ "$_total_lines" -gt 3 ]] && echo -e "    ${GRAY}...${NC}"
        echo -e "  ${GRAY}──────────────────────────────────────────────────${NC}"
        
        echo ""
        echo -e "  ${YELLOW}⚠ Execute on:${NC} ${GREEN}${display_name}${NC} ${GRAY}[${YELLOW}${instance_ocid}${GRAY}]${NC}"
        
        # Build JSON payload files
        local _content_file="$_inst_rc_dir/content.json"
        local _target_file="$_inst_rc_dir/target.json"
        
        jq -n --arg text "$_script_content" '{
            "source": {
                "sourceType": "TEXT",
                "text": $text
            }
        }' > "$_content_file"
        
        jq -n --arg iid "$instance_ocid" '{
            "instanceId": $iid
        }' > "$_target_file"
        
        # Build command (show before confirmation)
        local _cmd_display="oci instance-agent command create"
        _cmd_display+=" --compartment-id ${compartment_id}"
        _cmd_display+=" --region ${region}"
        _cmd_display+=" --timeout-in-seconds ${_timeout}"
        _cmd_display+=" --display-name \"${_rc_label}\""
        _cmd_display+=" --content file://${_content_file}"
        _cmd_display+=" --target file://${_target_file}"
        _cmd_display+=" --output json"

        echo ""
        echo -e "  ${WHITE}Command:${NC}"
        echo -e "  ${GRAY}${_cmd_display}${NC}"
        echo ""
        echo -n -e "  ${CYAN}Proceed? (y/n): ${NC}"
        local _confirm; read -r _confirm
        [[ "${_confirm,,}" != "y" ]] && { echo -e "  ${YELLOW}Cancelled${NC}"; return; }

        echo ""
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${_cmd_display}" >> "$_rc_log"
        log_action "RUN_COMMAND" "$_cmd_display" --quiet

        local _result
        _result=$(oci instance-agent command create \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --timeout-in-seconds "$_timeout" \
            --display-name "$_rc_label" \
            --content "file://${_content_file}" \
            --target "file://${_target_file}" \
            --output json 2>"$_inst_rc_dir/create_err.txt")
        local _rc=$?

        if [[ $_rc -eq 0 ]] && [[ -n "$_result" ]]; then
            local _new_id
            _new_id=$(jq -r '.data.id // "unknown"' <<< "$_result" 2>/dev/null)
            echo -e "  ${GREEN}✓ Command submitted: ${YELLOW}${_new_id}${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Command created ${_new_id}" >> "$_rc_log"
            log_action_result "SUCCESS" "Command created ${_new_id}"
        else
            echo -e "  ${RED}✗ Failed to create command${NC}"
            [[ -s "$_inst_rc_dir/create_err.txt" ]] && {
                local _err; _err=$(cat "$_inst_rc_dir/create_err.txt")
                echo -e "  ${RED}${_err}${NC}"
            }
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${_cmd}" >> "$_rc_log"
            log_action_result "FAILED" "Run command creation failed"
            _ui_pause "return"
            return
        fi

        echo ""
        echo -e "  ${YELLOW}Refreshing run commands...${NC}"
        # Retry with delay — agent needs time to register execution
        local _rc_retry _rc_found=0
        for _rc_retry in 2 3 5; do
            sleep "$_rc_retry"
            oci instance-agent command-execution list --compartment-id "$compartment_id" --instance-id "$instance_ocid" --region "$region" --sort-by TIMECREATED --sort-order DESC --limit 20 --output json > "$_inst_rc_dir/rc.json" 2>/dev/null
            _inst_rc_ct=$(jq '(.data // []) | length' "$_inst_rc_dir/rc.json" 2>/dev/null || echo "0")
            if [[ "$_inst_rc_ct" -gt 0 ]]; then
                _rc_found=1
                break
            fi
        done
        echo ""
        if [[ "$_rc_found" -eq 1 ]]; then
            _inst_display_rc "$_inst_rc_dir/rc.json"
        else
            echo -e "  ${GRAY}Command submitted but agent hasn't registered it yet. Use ${CYAN}r${GRAY} to refresh.${NC}"
        fi
    }
    
    _inst_rc_cancel() {
        local _entry="${1:-}"
        local _idx="${2:-}"
        [[ -z "$_entry" ]] && return 1
        local _cmd_id="${_entry%%|*}"
        local _rest="${_entry#*|}"
        local _rstate="${_rest%%|*}"
        local _rdisp="${_rest#*|}"
        local _rc_log="${LOGS_DIR}/runcommand_actions.log"
        
        local _cmd="oci instance-agent command cancel --command-id \"${_cmd_id}\" --region \"${region}\" --force"
        echo ""
        echo -e "  ${YELLOW}⚠ Cancel run command rc${_idx} on ${display_name}?${NC}"
        echo -e "  ${WHITE}Status:${NC} ${_rstate}  ${WHITE}Command:${NC} ${_rdisp:0:60}"
        echo ""
        echo -e "  ${WHITE}Command to execute:${NC}"
        echo -e "  ${GRAY}${_cmd}${NC}"
        echo ""
        echo -n -e "  ${CYAN}(y/n): ${NC}"
        local _confirm; read -r _confirm
        [[ "${_confirm,,}" != "y" ]] && { echo -e "  ${YELLOW}Cancelled${NC}"; return; }

        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${_cmd}" >> "$_rc_log"

        oci instance-agent command cancel --command-id "$_cmd_id" --region "$region" --force 2>/dev/null
        local _rc=$?
        
        if [[ $_rc -eq 0 ]]; then
            echo -e "  ${GREEN}✓ Cancel request sent (best-effort)${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Cancelled ${_cmd_id}" >> "$_rc_log"
        else
            echo -e "  ${RED}✗ Cancel failed${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Cancel ${_cmd_id}" >> "$_rc_log"
        fi
    }
    
    # ── Display instance work requests ──
    if [[ "$_inst_wr_ct" -gt 0 ]]; then
        echo ""
        _ui_subheader "Recent Work Requests" 0
        echo ""
        _inst_display_wr "$_inst_wr_dir/wr.json"
    fi
    
    # ── Display run commands ──
    echo ""
    _ui_subheader "Run Commands" 0
    echo ""
    if [[ "$_inst_rc_ct" -gt 0 ]]; then
        _inst_display_rc "$_inst_rc_dir/rc.json"
    else
        echo -e "  ${GRAY}No run commands found. Use ${CYAN}rc${GRAY} to submit one.${NC}"
        echo ""
    fi
    
    # ========== ACTIONS LOOP ==========
    while true; do
        # Show actions menu
        echo ""
        _ui_actions
        
        # Columns aligned at visible positions 2, 24, 50, 76
        if [[ "$has_cloud_init" == "true" ]]; then
            echo -e "  ${CYAN}1${NC}) View cloud-init    ${CYAN}2${NC}) Save cloud-init        ${CYAN}3${NC}) Compare cloud-init     ${CYAN}4${NC}) Console history"
        else
            echo -e "  ${GRAY}1) View cloud-init    2) Save cloud-init        3) Compare cloud-init${NC}     ${CYAN}4${NC}) Console history"
        fi
        
        if [[ -n "$k8s_node_name" ]]; then
            echo -e "  ${ORANGE}p${NC}) Show running pods  ${ORANGE}d${NC}) Drain K8s node         ${ORANGE}c${NC}) Cordon node            ${ORANGE}u${NC}) Uncordon node        ${ORANGE}cd${NC}) Cordon & Drain"
            echo -e "  ${CYAN}l${NC}) K8s labels         ${CYAN}desc${NC}) Describe node       ${CYAN}logs${NC}) Node events          ${GRAY}(add search: l <term>, desc <term>, logs <term>)${NC}"
        fi
        
        echo -e "  ${RED}re${NC}) Reboot            ${RED}fre${NC}) Force reboot         ${RED}stop${NC}) Stop instance       ${GREEN}start${NC}) Start instance"
        echo -e "  ${RED}T${NC}) TERMINATE          ${RED}x${NC}) Tag unhealthy + TERMINATE"
        echo -e "  ${YELLOW}t${NC}) Tag unhealthy      ${GREEN}rt${NC}) Remove unhealthy tag"
        echo -e "  ${CYAN}j${NC}) View instance JSON  |  ${CYAN}j <key>${NC}) Search JSON (e.g., 'j user_data')"
        echo -e "  ${CYAN}wr${NC}) Work requests     ${CYAN}wr#${NC}) Work request detail"
        echo -e "  ${CYAN}rc${NC}) Run command       ${CYAN}rc#${NC}) Run command detail   ${RED}rcc#${NC}) Cancel run command"
        echo -e "  ${CYAN}icc${NC}) Console connections (list, create, get, plink, delete)"

        if [[ -n "$k8s_node_name" && -z "$oke_nodepool_id" ]]; then
            echo -e "  ${GREEN}bvr${NC}) Boot Volume Replacement"
        elif [[ -n "$k8s_node_name" && -n "$oke_nodepool_id" ]]; then
            echo -e "  ${GRAY}bvr) Boot Volume Replacement — use node pool instead (--manage, k, 1, np#, bvr)${NC}"
        fi
        
        echo ""
        echo -e "  ${MAGENTA}r${NC}) Refresh instance details"
        echo -e "  ${CYAN}Enter${NC}) Return to list"
        echo ""
        if [[ -n "$k8s_node_name" ]]; then
            _ui_prompt "Instance - ${display_name}" "r, 1-4, p, l, desc, logs, icc, re, fre, stop, 8, t, rt, T, x, j, wr, wr#, rc, rc#, rcc#, d, c, u, cd, bvr, Enter, show"
        else
            _ui_prompt "Instance - ${display_name}" "r, 1-4, icc, re, fre, stop, 8, t, rt, T, x, j, wr, wr#, rc, rc#, rcc#, Enter, show"
        fi
        
        local action
        read -r action
        [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return
        
        case "$action" in
        r|R|refresh|REFRESH|details|DETAILS)
            # Re-display instance details by calling self recursively (but without re-fetching)
            # Actually, just break and let the caller loop handle it by re-calling display_instance_details
            echo ""
            echo -e "${YELLOW}Refreshing instance details...${NC}"
            # Return special code to indicate refresh
            return 2
            ;;
        1|cloud-init|cloudinit|ci|view|VIEW)
            if [[ "$has_cloud_init" == "true" ]]; then
                echo ""
                _ui_menu_header "CLOUD-INIT USER-DATA" \
                    --breadcrumb "Compute" "Instances" "Cloud-Init" \
                    --cmd "oci compute instance get --instance-id \$INSTANCE_OCID (metadata.user_data)" \
                    --env
                echo -e "  ${GRAY}Instance: ${WHITE}$display_name${NC}"
                echo -e "  ${GRAY}OCID:     ${YELLOW}$instance_ocid${NC}"
                _ui_content_border
                echo ""
                
                # Check if gzip compressed and show message
                if is_user_data_gzip "$user_data_b64"; then
                    echo -e "${GRAY}(gzip compressed - decompressing)${NC}"
                    echo ""
                fi
                
                # Decode and display (handles gzip)
                decode_user_data "$user_data_b64"
                
                echo ""
                _ui_content_border
                echo ""
                _ui_pause
            else
                echo -e "${YELLOW}No cloud-init user-data found for this instance${NC}"
                sleep 1
            fi
            ;;
        2|save|SAVE|s|S)
            if [[ "$has_cloud_init" == "true" ]]; then
                local safe_name
                safe_name=$(echo "$display_name" | tr ' ' '_' | tr -cd '[:alnum:]_-')
                local filename="${safe_name}_cloud-init.yml"
                
                echo ""
                echo -n -e "${CYAN}Save as [${filename}]: ${NC}"
                local custom_filename
                read -r custom_filename
                [[ -n "$custom_filename" ]] && filename="$custom_filename"
                
                local gzip_msg=""
                if is_user_data_gzip "$user_data_b64"; then
                    gzip_msg=" ${GRAY}(decompressed from gzip)${NC}"
                fi
                
                if decode_user_data_to_file "$user_data_b64" "$filename"; then
                    echo -e "${GREEN}✓ Cloud-init saved to: ${WHITE}$(pwd)/${filename}${NC}${gzip_msg}"
                else
                    echo -e "${RED}Failed to save cloud-init${NC}"
                fi
                echo ""
                _ui_pause
            else
                echo -e "${YELLOW}No cloud-init user-data found for this instance${NC}"
                sleep 1
            fi
            ;;
        3|compare|COMPARE)
            if [[ "$has_cloud_init" == "true" ]]; then
                compare_instance_cloud_init "$instance_ocid" "$display_name" "$user_data_b64"
            else
                echo -e "${YELLOW}No cloud-init user-data found for this instance${NC}"
                sleep 1
            fi
            ;;
        4|console|CONSOLE|con|CON|history|HISTORY)
            capture_console_history "$instance_ocid" "$display_name"
            ;;
        re|reboot|REBOOT)
            echo ""
            echo -e "${YELLOW}Rebooting instance ${GREEN}$display_name${NC}${YELLOW}...${NC}"
            echo ""
            echo -e "  ${GRAY}\$ oci compute instance action --instance-id ${instance_ocid} --region ${region} --action SOFTRESET${NC}"
            echo ""
            echo -n -e "${CYAN}Confirm reboot? (yes/no): ${NC}"
            local confirm
            read -r confirm
            if [[ "$confirm" == "yes" ]]; then
                log_action "REBOOT" "oci compute instance action --instance-id $instance_ocid --region $region --action SOFTRESET"
                if oci compute instance action --instance-id "$instance_ocid" --region "$region" --action SOFTRESET 2>/dev/null; then
                    echo -e "${GREEN}✓ Reboot initiated successfully${NC}"
                    log_action_result "SUCCESS" "Instance $display_name reboot initiated"
                else
                    echo -e "${RED}✗ Failed to reboot instance${NC}"
                    log_action_result "FAILED" "Instance $display_name reboot failed"
                fi
            else
                echo -e "${YELLOW}Reboot cancelled${NC}"
            fi
            echo ""
            _ui_pause
            ;;
        fre|force|FORCE)
            echo ""
            echo -e "${YELLOW}Force rebooting instance ${GREEN}$display_name${NC}${YELLOW}...${NC}"
            echo -e "${RED}WARNING: This is a hard reset and may cause data loss!${NC}"
            echo ""
            echo -e "  ${GRAY}\$ oci compute instance action --instance-id ${instance_ocid} --region ${region} --action RESET${NC}"
            echo ""
            echo -n -e "${CYAN}Confirm force reboot? (yes/no): ${NC}"
            local confirm
            read -r confirm
            if [[ "$confirm" == "yes" ]]; then
                log_action "FORCE_REBOOT" "oci compute instance action --instance-id $instance_ocid --region $region --action RESET"
                if oci compute instance action --instance-id "$instance_ocid" --region "$region" --action RESET 2>/dev/null; then
                    echo -e "${GREEN}✓ Force reboot initiated successfully${NC}"
                    log_action_result "SUCCESS" "Instance $display_name force reboot initiated"
                else
                    echo -e "${RED}✗ Failed to force reboot instance${NC}"
                    log_action_result "FAILED" "Instance $display_name force reboot failed"
                fi
            else
                echo -e "${YELLOW}Force reboot cancelled${NC}"
            fi
            echo ""
            _ui_pause
            ;;
        stop|STOP)
            echo ""
            echo -e "${YELLOW}Stopping instance ${GREEN}$display_name${NC}${YELLOW}...${NC}"
            echo ""
            echo -e "  ${GRAY}\$ oci compute instance action --instance-id ${instance_ocid} --region ${region} --action SOFTSTOP${NC}"
            echo ""
            echo -n -e "${CYAN}Confirm stop? (yes/no): ${NC}"
            local confirm
            read -r confirm
            if [[ "$confirm" == "yes" ]]; then
                log_action "STOP" "oci compute instance action --instance-id $instance_ocid --region $region --action SOFTSTOP"
                if oci compute instance action --instance-id "$instance_ocid" --region "$region" --action SOFTSTOP 2>/dev/null; then
                    echo -e "${GREEN}✓ Stop initiated successfully${NC}"
                    log_action_result "SUCCESS" "Instance $display_name stop initiated"
                else
                    echo -e "${RED}✗ Failed to stop instance${NC}"
                    log_action_result "FAILED" "Instance $display_name stop failed"
                fi
            else
                echo -e "${YELLOW}Stop cancelled${NC}"
            fi
            echo ""
            _ui_pause
            ;;
        8|start|START)
            echo ""
            echo -e "${YELLOW}Starting instance ${GREEN}$display_name${NC}${YELLOW}...${NC}"
            echo ""
            echo -e "  ${GRAY}\$ oci compute instance action --instance-id ${instance_ocid} --region ${region} --action START${NC}"
            echo ""
            echo -n -e "${CYAN}Confirm start? (yes/no): ${NC}"
            local confirm
            read -r confirm
            if [[ "$confirm" == "yes" ]]; then
                log_action "START" "oci compute instance action --instance-id $instance_ocid --region $region --action START"
                if oci compute instance action --instance-id "$instance_ocid" --region "$region" --action START 2>/dev/null; then
                    echo -e "${GREEN}✓ Start initiated successfully${NC}"
                    log_action_result "SUCCESS" "Instance $display_name start initiated"
                else
                    echo -e "${RED}✗ Failed to start instance${NC}"
                    log_action_result "FAILED" "Instance $display_name start failed"
                fi
            else
                echo -e "${YELLOW}Start cancelled${NC}"
            fi
            echo ""
            _ui_pause
            ;;
        T|terminate|TERMINATE)
            echo ""
            echo -e "${RED}╔════════════════════════════════════════════════════════════════╗${NC}"
            echo -e "${RED}║                    ⚠️  WARNING: TERMINATE  ⚠️                   ║${NC}"
            echo -e "${RED}╚════════════════════════════════════════════════════════════════╝${NC}"
            echo ""
            echo -e "${RED}This will PERMANENTLY DELETE the instance:${NC}"
            echo -e "  Name: ${GREEN}$display_name${NC}"
            echo -e "  OCID: ${YELLOW}$instance_ocid${NC}"
            echo ""
            echo -e "${RED}This action cannot be undone!${NC}"
            echo ""
            
            echo -e "  ${GRAY}\$ oci compute instance terminate --instance-id ${instance_ocid} --region ${region} --preserve-boot-volume false --force${NC}"
            echo ""

            if [[ -n "$k8s_node_name" ]]; then
                echo -e "${YELLOW}⚠️  This instance is a Kubernetes node: ${CYAN}$k8s_node_name${NC}"
                echo -e "${YELLOW}   Consider draining the node first (option d)${NC}"
                echo ""
            fi

            if _ui_confirm "TERMINATE" "confirm deletion"; then
                echo ""
                echo -e "${YELLOW}Terminating instance...${NC}"
                log_action "TERMINATE" "oci compute instance terminate --instance-id $instance_ocid --region $region --preserve-boot-volume false --force"
                if oci compute instance terminate --instance-id "$instance_ocid" --region "$region" --preserve-boot-volume false --force 2>/dev/null; then
                    echo -e "${GREEN}✓ Terminate initiated successfully${NC}"
                    echo -e "${YELLOW}Instance will be deleted. Boot volume will also be deleted.${NC}"
                    log_action_result "SUCCESS" "Instance $display_name terminate initiated"
                else
                    echo -e "${RED}✗ Failed to terminate instance${NC}"
                    log_action_result "FAILED" "Instance $display_name terminate failed"
                fi
            else
                echo -e "${YELLOW}Termination cancelled${NC}"
            fi
            echo ""
            _ui_pause
            ;;
        d|D|drain|DRAIN)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform K8s action — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                echo ""
                echo -e "${YELLOW}Draining Kubernetes node ${GREEN}$k8s_node_name${NC}${YELLOW}...${NC}"
                echo -e "${WHITE}This will evict all pods (except DaemonSets) from the node.${NC}"
                echo ""
                echo -e "  ${GRAY}\$ kubectl drain ${k8s_node_name} --ignore-daemonsets --delete-emptydir-data${NC}"
                echo ""
                echo -n -e "${CYAN}Confirm drain? (yes/no): ${NC}"
                local confirm
                read -r confirm
                if [[ "$confirm" == "yes" ]]; then
                    echo ""
                    log_action "K8S_DRAIN" "kubectl drain $k8s_node_name --ignore-daemonsets --delete-emptydir-data"
                    if kubectl drain "$k8s_node_name" --ignore-daemonsets --delete-emptydir-data 2>&1; then
                        echo -e "${GREEN}✓ Node drained successfully${NC}"
                        log_action_result "SUCCESS" "Node $k8s_node_name drained"
                    else
                        echo -e "${RED}✗ Failed to drain node (some pods may not be evictable)${NC}"
                        log_action_result "FAILED" "Node $k8s_node_name drain failed"
                    fi
                else
                    echo -e "${YELLOW}Drain cancelled${NC}"
                fi
                echo ""
                _ui_pause
            fi
            ;;
        cd|CD|cordon-drain|CORDON-DRAIN)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform K8s action — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                echo ""
                echo -e "${YELLOW}Cordon & Drain Kubernetes node ${GREEN}$k8s_node_name${NC}${YELLOW}...${NC}"
                echo -e "${WHITE}Step 1: Cordon (mark unschedulable)${NC}"
                echo -e "${WHITE}Step 2: Drain (evict all pods except DaemonSets)${NC}"
                echo ""
                echo -e "${RED}⚠️  This will evict all pods from the node!${NC}"
                echo ""
                echo -n -e "${CYAN}Confirm cordon & drain? (yes/no): ${NC}"
                local confirm
                read -r confirm
                if [[ "$confirm" == "yes" ]]; then
                    echo ""
                    echo -e "${YELLOW}Step 1: Cordoning...${NC}"
                    echo -e "${GRAY}$ kubectl cordon $k8s_node_name${NC}"
                    log_action "K8S_CORDON" "kubectl cordon $k8s_node_name"
                    if kubectl cordon "$k8s_node_name" 2>&1; then
                        echo -e "${GREEN}✓ Node cordoned${NC}"
                        log_action_result "SUCCESS" "Node $k8s_node_name cordoned"
                        echo ""
                        echo -e "${YELLOW}Step 2: Draining...${NC}"
                        echo -e "${GRAY}$ kubectl drain $k8s_node_name --ignore-daemonsets --delete-emptydir-data${NC}"
                        log_action "K8S_DRAIN" "kubectl drain $k8s_node_name --ignore-daemonsets --delete-emptydir-data"
                        if kubectl drain "$k8s_node_name" --ignore-daemonsets --delete-emptydir-data 2>&1; then
                            echo -e "${GREEN}✓ Node drained successfully${NC}"
                            log_action_result "SUCCESS" "Node $k8s_node_name drained"
                        else
                            echo -e "${RED}✗ Failed to drain node (node remains cordoned)${NC}"
                            log_action_result "FAILED" "Node $k8s_node_name drain failed (remains cordoned)"
                        fi
                    else
                        echo -e "${RED}✗ Failed to cordon node - skipping drain${NC}"
                        log_action_result "FAILED" "Node $k8s_node_name cordon failed - skipping drain"
                    fi
                else
                    echo -e "${YELLOW}Cordon & drain cancelled${NC}"
                fi
                echo ""
                _ui_pause
            fi
            ;;
        c|C|cordon|CORDON)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform K8s action — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                echo ""
                echo -e "${YELLOW}Cordoning Kubernetes node ${GREEN}$k8s_node_name${NC}${YELLOW}...${NC}"
                echo -e "${WHITE}This marks the node as unschedulable (existing pods continue running).${NC}"
                echo ""
                echo -n -e "${CYAN}Confirm cordon? (yes/no): ${NC}"
                local confirm
                read -r confirm
                if [[ "$confirm" == "yes" ]]; then
                    log_action "K8S_CORDON" "kubectl cordon $k8s_node_name"
                    if kubectl cordon "$k8s_node_name" 2>&1; then
                        echo -e "${GREEN}✓ Node cordoned successfully${NC}"
                        log_action_result "SUCCESS" "Node $k8s_node_name cordoned"
                    else
                        echo -e "${RED}✗ Failed to cordon node${NC}"
                        log_action_result "FAILED" "Node $k8s_node_name cordon failed"
                    fi
                else
                    echo -e "${YELLOW}Cordon cancelled${NC}"
                fi
                echo ""
                _ui_pause
            fi
            ;;
        u|U|uncordon|UNCORDON)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform K8s action — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                echo ""
                echo -e "${YELLOW}Uncordoning Kubernetes node ${GREEN}$k8s_node_name${NC}${YELLOW}...${NC}"
                echo -e "${WHITE}This marks the node as schedulable again.${NC}"
                echo ""
                echo -n -e "${CYAN}Confirm uncordon? (yes/no): ${NC}"
                local confirm
                read -r confirm
                if [[ "$confirm" == "yes" ]]; then
                    log_action "K8S_UNCORDON" "kubectl uncordon $k8s_node_name"
                    if kubectl uncordon "$k8s_node_name" 2>&1; then
                        echo -e "${GREEN}✓ Node uncordoned successfully${NC}"
                        log_action_result "SUCCESS" "Node $k8s_node_name uncordoned"
                    else
                        echo -e "${RED}✗ Failed to uncordon node${NC}"
                        log_action_result "FAILED" "Node $k8s_node_name uncordon failed"
                    fi
                else
                    echo -e "${YELLOW}Uncordon cancelled${NC}"
                fi
                echo ""
                _ui_pause
            fi
            ;;
        bvr|BVR)
            if [[ -n "$oke_nodepool_id" ]]; then
                echo ""
                echo -e "${YELLOW}This instance is managed by OKE node pool.${NC}"
                echo -e "${YELLOW}BVR should be performed at the node pool level to ensure OKE manages cordon/drain properly.${NC}"
                echo -e "${WHITE}Navigate to:${NC} ${CYAN}--manage, k, 1, np#, bvr${NC}"
                echo ""
                sleep 1
            elif [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform BVR — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                compute_boot_volume_replacement "$instance_ocid"
            fi
            ;;
        p|P|pods|PODS)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Cannot perform K8s action — this instance is not registered as a node in the current kubeconfig context${NC}"
                local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
                echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
                sleep 2
            else
                echo ""
                _ui_subheader "Running Pods on ${k8s_node_name}" 0
                _ui_oci_cmd "kubectl get pods --all-namespaces --field-selector=spec.nodeName=${k8s_node_name},status.phase=Running -o json"
                
                # Fetch live pod data (don't rely on cached - user may have drained/changed)
                _step_init
                _step_active "pods"
                local pods_json
                pods_json=$(kubectl get pods --all-namespaces --field-selector=spec.nodeName="$k8s_node_name",status.phase=Running -o json 2>/dev/null)
                local _pc=0
                [[ -n "$pods_json" ]] && _pc=$(jq '.items | length' <<< "$pods_json" 2>/dev/null)
                [[ -z "$_pc" || "$_pc" == "null" ]] && _pc=0
                _step_complete "pods(${_pc})"
                _step_finish
                
                if [[ "$_pc" -eq 0 ]]; then
                    echo -e "  ${GRAY}No running pods found on this node${NC}"
                else
                    echo ""
                    # Count DaemonSet pods
                    local _ds_count
                    _ds_count=$(jq '[.items[] | select(.metadata.ownerReferences[]?.kind == "DaemonSet")] | length' <<< "$pods_json" 2>/dev/null)
                    [[ -z "$_ds_count" ]] && _ds_count=0
                    local _workload_count=$(( _pc - _ds_count ))
                    echo -e "  ${WHITE}Total:${NC} ${_pc}  ${WHITE}Workload:${NC} ${CYAN}${_workload_count}${NC}  ${WHITE}DaemonSet:${NC} ${GRAY}${_ds_count}${NC}"
                    echo ""
                    
                    # Table header
                    printf "  ${BOLD}%-30s %-14s %-10s %-8s %-12s %-8s %s${NC}\n" \
                        "Pod Name" "Namespace" "Owner" "Status" "Restarts" "Age" "IP"
                    print_separator 120
                    
                    # Sort: workloads first, then daemonsets; alphabetical within each group
                    jq -r '
                        [.items[] |
                            (.metadata.ownerReferences // [{}])[0] as $owner |
                            {
                                name: .metadata.name,
                                ns: .metadata.namespace,
                                owner_kind: ($owner.kind // "None"),
                                status: .status.phase,
                                restarts: ([.status.containerStatuses[]?.restartCount // 0] | add // 0),
                                created: .metadata.creationTimestamp,
                                ip: (.status.podIP // "-"),
                                is_ds: (if $owner.kind == "DaemonSet" then 1 else 0 end)
                            }
                        ] | sort_by(.is_ds, .ns, .name)[] |
                        "\(.is_ds)|\(.name)|\(.ns)|\(.owner_kind)|\(.status)|\(.restarts)|\(.created)|\(.ip)"
                    ' <<< "$pods_json" 2>/dev/null | while IFS='|' read -r is_ds pname pns powner pstatus prestarts pcreated pip; do
                        [[ -z "$pname" ]] && continue
                        
                        # Truncate long pod names
                        local pname_t="$pname"
                        [[ ${#pname_t} -gt 29 ]] && pname_t="${pname_t:0:27}.."
                        
                        # Calculate age
                        local age_str="-"
                        if [[ -n "$pcreated" && "$pcreated" != "null" ]]; then
                            local created_epoch now_epoch age_secs
                            created_epoch=$(date -d "$pcreated" +%s 2>/dev/null)
                            now_epoch=$(date +%s)
                            if [[ -n "$created_epoch" ]]; then
                                age_secs=$(( now_epoch - created_epoch ))
                                if (( age_secs < 3600 )); then
                                    age_str="$(( age_secs / 60 ))m"
                                elif (( age_secs < 86400 )); then
                                    age_str="$(( age_secs / 3600 ))h$(( (age_secs % 3600) / 60 ))m"
                                else
                                    age_str="$(( age_secs / 86400 ))d$(( (age_secs % 86400) / 3600 ))h"
                                fi
                            fi
                        fi
                        
                        # Color by owner type
                        local owner_color="$WHITE"
                        case "$powner" in
                            DaemonSet)   owner_color="$GRAY" ;;
                            ReplicaSet)  owner_color="$CYAN" ;;
                            StatefulSet) owner_color="$GREEN" ;;
                            Job)         owner_color="$YELLOW" ;;
                        esac
                        
                        # Restart color
                        local restart_color="$GREEN"
                        [[ "$prestarts" -gt 0 ]] && restart_color="$YELLOW"
                        [[ "$prestarts" -gt 5 ]] && restart_color="$RED"
                        
                        printf "  ${owner_color}%-30s${NC} %-14s ${owner_color}%-10s${NC} %-8s ${restart_color}%-12s${NC} %-8s %s\n" \
                            "$pname_t" "$pns" "$powner" "$pstatus" "$prestarts" "$age_str" "$pip"
                    done
                fi
                echo ""
                _ui_pause
            fi
            ;;
        l|l\ *)
            # K8s node labels (l or l <search term>)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Not a K8s node — labels not available${NC}"; sleep 1
            else
                local _lsearch=""
                [[ "$action" =~ ^l\ +(.+)$ ]] && _lsearch="${BASH_REMATCH[1]}"
                _k8s_node_inspect "labels" "$k8s_node_name" "$_lsearch"
            fi
            ;;
        desc|desc\ *)
            # K8s describe node (desc or desc <search term>)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Not a K8s node — describe not available${NC}"; sleep 1
            else
                local _dsearch=""
                [[ "$action" =~ ^desc\ +(.+)$ ]] && _dsearch="${BASH_REMATCH[1]}"
                _k8s_node_inspect "describe" "$k8s_node_name" "$_dsearch"
            fi
            ;;
        logs|logs\ *)
            # K8s node events/logs (logs or logs <search term>)
            if [[ -z "$k8s_node_name" ]]; then
                echo -e "${RED}Not a K8s node — logs not available${NC}"; sleep 1
            else
                local _lgsearch=""
                [[ "$action" =~ ^logs\ +(.+)$ ]] && _lgsearch="${BASH_REMATCH[1]}"
                _k8s_node_inspect "logs" "$k8s_node_name" "$_lgsearch"
            fi
            ;;
        icc|ICC)
            # ── Instance Console Connection sub-menu ──
            local _icc_cache="${CACHE_DIR}/icc_${instance_ocid##*.}"
            mkdir -p "$_icc_cache"
            local _icc_list_file="${_icc_cache}/list.json"
            local _icc_log="${LOGS_DIR}/icc_actions_$(date +%Y%m%d).log"

            while true; do
                echo ""
                _ui_menu_header "CONSOLE CONNECTIONS" \
                    --breadcrumb "Compute" "Instances" "${display_name:0:15}" "Console Connections" \
                    --cmd "oci compute instance-console-connection list --compartment-id \$COMPARTMENT_ID --instance-id \$INSTANCE_OCID --region \$REGION" \
                    --env \
                    --cache "${_icc_list_file}|Console Connections"

                # ── Discovery ──
                _step_init
                _step_active "console connections"
                local _icc_json
                _icc_json=$(oci compute instance-console-connection list \
                    --compartment-id "$compartment_id" \
                    --instance-id "$instance_ocid" \
                    --region "$region" \
                    --all --output json 2>/dev/null)
                if [[ -n "$_icc_json" ]] && jq -e '.data' <<< "$_icc_json" > /dev/null 2>&1; then
                    echo "$_icc_json" > "$_icc_list_file"
                fi
                local _icc_ct=0
                [[ -s "$_icc_list_file" ]] && _icc_ct=$(jq '[.data[] | select(.["lifecycle-state"] != "DELETED")] | length' "$_icc_list_file" 2>/dev/null || echo "0")
                _step_complete "console connections(${_icc_ct})"
                _step_finish

                # ── Display list ──
                echo ""
                if [[ "$_icc_ct" -eq 0 ]]; then
                    echo -e "  ${YELLOW}No active console connections for this instance${NC}"
                else
                    declare -A _ICC_MAP=()
                    local _icc_idx=0
                    printf "  ${BOLD}%-4s %-10s %-20s %-60s %s${NC}\n" "#" "State" "Created" "Connection ID" "Fingerprint"
                    print_separator 120
                    jq -r '.data[] | select(.["lifecycle-state"] != "DELETED") |
                        "\(.["lifecycle-state"])|\(.["time-created"] // "N/A")|\(.id)|\(.fingerprint // "N/A")"
                    ' "$_icc_list_file" 2>/dev/null | while IFS='|' read -r _ic_state _ic_time _ic_id _ic_fp; do
                        ((_icc_idx++))
                        echo "${_icc_idx}|${_ic_id}" >> "${_icc_cache}/map_$$"
                        local _ic_sc; _ic_sc=$(color_resource_state "$_ic_state")
                        local _ic_time_short="${_ic_time:0:19}"; _ic_time_short="${_ic_time_short/T/ }"
                        printf "  ${YELLOW}%-4s${NC} ${_ic_sc}%-10s${NC} %-20s ${GRAY}%-60s${NC} ${CYAN}%s${NC}\n" \
                            "$_icc_idx" "$_ic_state" "$_ic_time_short" "${_ic_id}" "${_ic_fp:0:20}"
                    done
                    # Read map from subshell
                    if [[ -f "${_icc_cache}/map_$$" ]]; then
                        while IFS='|' read -r _midx _mid; do
                            _ICC_MAP[$_midx]="$_mid"
                        done < "${_icc_cache}/map_$$"
                        rm -f "${_icc_cache}/map_$$"
                    fi
                fi

                # ── Actions ──
                echo ""
                _ui_actions
                echo -e "  ${GREEN}create${NC}   - Create new console connection"
                echo -e "  ${CYAN}get #${NC}    - Get connection details (e.g., 'get 1')"
                echo -e "  ${CYAN}plink #${NC}  - Get plink connection string (e.g., 'plink 1')"
                echo -e "  ${RED}del #${NC}    - Delete console connection (e.g., 'del 1')"
                echo -e "  ${MAGENTA}r${NC}        - Refresh"
                echo -e "  ${CYAN}Enter${NC}    - Back"
                echo ""
                _ui_prompt "Console Connections - ${display_name:0:15}" "create, get#, plink#, del#, r, Enter"

                local _icc_input
                read -r _icc_input
                [[ -z "$_icc_input" ]] && break

                case "$_icc_input" in
                r|R)
                    continue
                    ;;
                create|CREATE)
                    echo ""
                    echo -e "  ${WHITE}Creating console connection for:${NC} ${GREEN}${display_name}${NC}"
                    echo ""
                    # Detect RSA public keys (OCI console connections require RSA)
                    local -a _pk_choices=()
                    local _pki=0
                    for _pkf in ~/.ssh/id_rsa.pub ~/.ssh/*.pub; do
                        [[ -f "$_pkf" ]] || continue
                        # Only include RSA keys
                        grep -q '^ssh-rsa ' "$_pkf" 2>/dev/null || continue
                        # Avoid duplicates
                        local _dup=0; for _pc in "${_pk_choices[@]:-}"; do [[ "$_pc" == "$_pkf" ]] && _dup=1; done
                        [[ $_dup -eq 1 ]] && continue
                        _pk_choices+=("$_pkf"); ((_pki++))
                    done
                    echo -e "  ${WHITE}SSH Public Key — choose an option:${NC} ${GRAY}(RSA keys only)${NC}"
                    if [[ ${#_pk_choices[@]} -gt 0 ]]; then
                        local _pi=0
                        for _pkf in "${_pk_choices[@]}"; do
                            ((_pi++))
                            local _pk_fp; _pk_fp=$(ssh-keygen -lf "$_pkf" 2>/dev/null | awk '{print $2}') || _pk_fp=""
                            echo -e "    ${YELLOW}${_pi}${NC}) ${_pkf}  ${GRAY}${_pk_fp}${NC}"
                        done
                    fi
                    echo -e "    ${YELLOW}f${NC}) Enter file path"
                    echo -e "    ${YELLOW}p${NC}) Paste public key"
                    echo ""
                    _ui_prompt "Selection" "#, f, p"
                    local _pub_key_input
                    read -r _pub_key_input

                    local _pub_key_file="" _pub_key_tmp=""
                    if [[ "$_pub_key_input" =~ ^[0-9]+$ ]] && [[ -n "${_pk_choices[$((_pub_key_input-1))]:-}" ]]; then
                        # Numbered selection from detected keys
                        _pub_key_file="${_pk_choices[$((_pub_key_input-1))]}"
                    elif [[ "$_pub_key_input" =~ ^[fF]$ ]]; then
                        # Prompt for file path
                        _ui_prompt "SSH public key file path" "e.g. ~/.ssh/id_rsa.pub"
                        local _fpath
                        read -r _fpath
                        _pub_key_file="${_fpath/#\~/$HOME}"
                    elif [[ "$_pub_key_input" =~ ^[pP]$ ]]; then
                        # Paste public key (RSA only)
                        echo -e "  ${WHITE}Paste your SSH public key (ssh-rsa ...):${NC}"
                        local _pasted_key
                        read -r _pasted_key
                        if [[ -n "$_pasted_key" ]]; then
                            _pub_key_tmp=$(mktemp "${TEMP_DIR}/icc_pubkey.XXXXXX")
                            echo "$_pasted_key" > "$_pub_key_tmp"
                            _pub_key_file="$_pub_key_tmp"
                        fi
                    else
                        echo -e "  ${YELLOW}Cancelled${NC}"
                        _ui_pause
                        continue
                    fi

                    if [[ -z "$_pub_key_file" ]]; then
                        echo -e "  ${YELLOW}Cancelled — SSH public key required${NC}"
                        _ui_pause
                        continue
                    fi
                    if [[ ! -f "$_pub_key_file" ]]; then
                        echo -e "  ${RED}File not found: ${_pub_key_file}${NC}"
                        _ui_pause
                        continue
                    fi
                    # Validate RSA key type
                    if ! grep -q '^ssh-rsa ' "$_pub_key_file" 2>/dev/null; then
                        echo -e "  ${RED}✗ OCI console connections require RSA keys (ssh-rsa)${NC}"
                        echo -e "  ${GRAY}Generate one with: ssh-keygen -t rsa -b 2048 -f ~/.ssh/id_rsa_console${NC}"
                        [[ -n "$_pub_key_tmp" && -f "$_pub_key_tmp" ]] && rm -f "$_pub_key_tmp"
                        _ui_pause
                        continue
                    fi
                    echo -e "  ${WHITE}Using key:${NC} ${_pub_key_file}"

                    local _icc_create_cmd="oci compute instance-console-connection create --instance-id ${instance_ocid} --ssh-public-key-file ${_pub_key_file} --region ${region}"
                    echo -e "  ${GRAY}\$ ${_icc_create_cmd}${NC}"
                    log_action "ICC_CREATE" "$_icc_create_cmd" --quiet

                    _step_init; _step_active "creating"
                    local _icc_create_json _icc_create_rc=0
                    _icc_create_json=$(oci compute instance-console-connection create \
                        --instance-id "$instance_ocid" \
                        --ssh-public-key-file "$_pub_key_file" \
                        --region "$region" \
                        --output json 2>/dev/null) || _icc_create_rc=$?

                    if [[ $_icc_create_rc -eq 0 && -n "$_icc_create_json" ]] && jq -e '.data' <<< "$_icc_create_json" > /dev/null 2>&1; then
                        local _new_id; _new_id=$(jq -r '.data.id // "N/A"' <<< "$_icc_create_json")
                        local _new_state; _new_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$_icc_create_json")
                        _step_complete "created(${_new_state})"; _step_finish
                        echo -e "  ${GREEN}✓ Console connection created${NC}"
                        echo -e "  ${WHITE}ID:${NC}    ${YELLOW}${_new_id}${NC}"
                        echo -e "  ${WHITE}State:${NC} ${_new_state}"
                        # Show SSH connection string if available
                        local _ssh_str; _ssh_str=$(jq -r '.data["connection-string"] // empty' <<< "$_icc_create_json")
                        [[ -n "$_ssh_str" ]] && echo -e "\n  ${WHITE}SSH Connection String:${NC}\n  ${CYAN}${_ssh_str}${NC}"
                        local _vnc_str; _vnc_str=$(jq -r '.data["vnc-connection-string"] // empty' <<< "$_icc_create_json")
                        [[ -n "$_vnc_str" ]] && echo -e "\n  ${WHITE}VNC Connection String:${NC}\n  ${CYAN}${_vnc_str}${NC}"
                        log_action_result "SUCCESS" "Created ICC: ${_new_id}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] CREATE: ${_icc_create_cmd} → ${_new_id} (${_new_state})" >> "$_icc_log"
                    else
                        _step_complete "create(failed)"; _step_finish
                        echo -e "  ${RED}✗ Failed to create console connection${NC}"
                        [[ -n "$_icc_create_json" ]] && echo -e "  ${GRAY}$(jq -r '.message // .' <<< "$_icc_create_json" 2>/dev/null | head -3)${NC}"
                        log_action_result "FAILED" "ICC create for ${instance_ocid}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED CREATE: ${_icc_create_cmd}" >> "$_icc_log"
                    fi
                    # Clean up temp key file if we created one
                    [[ -n "$_pub_key_tmp" && -f "$_pub_key_tmp" ]] && rm -f "$_pub_key_tmp"
                    echo ""
                    _ui_pause
                    ;;
                get\ [0-9]*)
                    local _g_num="${_icc_input#get }"
                    _g_num="${_g_num%% *}"
                    local _g_id="${_ICC_MAP[$_g_num]:-}"
                    if [[ -z "$_g_id" ]]; then
                        echo -e "${RED}Invalid connection #${_g_num}${NC}"
                    else
                        echo ""
                        local _get_cmd="oci compute instance-console-connection get --instance-console-connection-id ${_g_id} --region ${region}"
                        echo -e "  ${GRAY}\$ ${_get_cmd}${NC}"
                        _step_init; _step_active "fetching"
                        local _g_json
                        _g_json=$(oci compute instance-console-connection get \
                            --instance-console-connection-id "$_g_id" \
                            --region "$region" \
                            --output json 2>/dev/null)
                        _step_complete "done"; _step_finish
                        if [[ -n "$_g_json" ]] && jq -e '.data' <<< "$_g_json" > /dev/null 2>&1; then
                            echo ""
                            echo -e "  ${WHITE}State:${NC}       $(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$_g_json")"
                            echo -e "  ${WHITE}ID:${NC}          ${YELLOW}$(jq -r '.data.id // "N/A"' <<< "$_g_json")${NC}"
                            echo -e "  ${WHITE}Instance:${NC}    $(jq -r '.data["instance-id"] // "N/A"' <<< "$_g_json")"
                            echo -e "  ${WHITE}Compartment:${NC} $(jq -r '.data["compartment-id"] // "N/A"' <<< "$_g_json")"
                            echo -e "  ${WHITE}Fingerprint:${NC} ${CYAN}$(jq -r '.data.fingerprint // "N/A"' <<< "$_g_json")${NC}"
                            echo -e "  ${WHITE}Created:${NC}     $(jq -r '.data["time-created"] // "N/A"' <<< "$_g_json" | sed 's/T/ /;s/\..*//')"
                            echo ""
                            local _ssh_str; _ssh_str=$(jq -r '.data["connection-string"] // empty' <<< "$_g_json")
                            if [[ -n "$_ssh_str" ]]; then
                                echo -e "  ${WHITE}SSH Connection String:${NC}"
                                echo -e "  ${CYAN}${_ssh_str}${NC}"
                                echo ""
                            fi
                            local _vnc_str; _vnc_str=$(jq -r '.data["vnc-connection-string"] // empty' <<< "$_g_json")
                            if [[ -n "$_vnc_str" ]]; then
                                echo -e "  ${WHITE}VNC Connection String:${NC}"
                                echo -e "  ${CYAN}${_vnc_str}${NC}"
                                echo ""
                            fi
                        else
                            echo -e "  ${RED}Failed to get connection details${NC}"
                        fi
                        _ui_pause
                    fi
                    ;;
                plink\ [0-9]*)
                    local _p_num="${_icc_input#plink }"
                    _p_num="${_p_num%% *}"
                    local _p_id="${_ICC_MAP[$_p_num]:-}"
                    if [[ -z "$_p_id" ]]; then
                        echo -e "${RED}Invalid connection #${_p_num}${NC}"
                    else
                        echo ""
                        echo -e "  ${WHITE}Plink connection string for connection #${_p_num}${NC}"
                        echo -e "  ${GRAY}Provide the path to the private key file:${NC}"
                        _ui_prompt "Private key path" "e.g. ~/.ssh/id_rsa"
                        local _pk_path
                        read -r _pk_path
                        if [[ -z "$_pk_path" ]]; then
                            echo -e "  ${YELLOW}Cancelled — private key path required${NC}"
                        else
                            local _plink_cmd="oci compute instance-console-connection get-plink-connection-string --instance-console-connection-id ${_p_id} --private-key-file ${_pk_path} --region ${region}"
                            echo -e "  ${GRAY}\$ ${_plink_cmd}${NC}"
                            _step_init; _step_active "fetching"
                            local _p_json
                            _p_json=$(oci compute instance-console-connection get-plink-connection-string \
                                --instance-console-connection-id "$_p_id" \
                                --private-key-file "$_pk_path" \
                                --region "$region" \
                                --output json 2>/dev/null)
                            _step_complete "done"; _step_finish
                            if [[ -n "$_p_json" ]] && jq -e '.data' <<< "$_p_json" > /dev/null 2>&1; then
                                echo ""
                                echo -e "  ${WHITE}Plink Connection String:${NC}"
                                echo -e "  ${CYAN}$(jq -r '.data["connection-string"] // "N/A"' <<< "$_p_json")${NC}"
                                echo ""
                            else
                                echo -e "  ${RED}Failed to get plink connection string${NC}"
                                [[ -n "$_p_json" ]] && echo -e "  ${GRAY}$(jq -r '.message // .' <<< "$_p_json" 2>/dev/null | head -3)${NC}"
                            fi
                        fi
                        echo ""
                        _ui_pause
                    fi
                    ;;
                del\ [0-9]*)
                    local _d_num="${_icc_input#del }"
                    _d_num="${_d_num%% *}"
                    local _d_id="${_ICC_MAP[$_d_num]:-}"
                    if [[ -z "$_d_id" ]]; then
                        echo -e "${RED}Invalid connection #${_d_num}${NC}"
                    else
                        echo ""
                        echo -e "  ${RED}Delete console connection #${_d_num}?${NC}"
                        echo -e "  ${WHITE}ID:${NC} ${YELLOW}${_d_id}${NC}"
                        local _del_cmd="oci compute instance-console-connection delete --instance-console-connection-id ${_d_id} --region ${region} --force"
                        echo -e "  ${GRAY}\$ ${_del_cmd}${NC}"
                        echo ""
                        _ui_prompt "Confirm delete" "y/N"
                        local _del_confirm
                        read -r _del_confirm
                        if [[ "$_del_confirm" =~ ^[yY]$ ]]; then
                            log_action "ICC_DELETE" "$_del_cmd" --quiet
                            _step_init; _step_active "deleting"
                            local _del_rc=0
                            oci compute instance-console-connection delete \
                                --instance-console-connection-id "$_d_id" \
                                --region "$region" \
                                --force 2>/dev/null || _del_rc=$?
                            if [[ $_del_rc -eq 0 ]]; then
                                _step_complete "deleted"; _step_finish
                                echo -e "  ${GREEN}✓ Console connection deleted${NC}"
                                log_action_result "SUCCESS" "Deleted ICC: ${_d_id}"
                                echo "[$(date '+%Y-%m-%d %H:%M:%S')] DELETE: ${_del_cmd}" >> "$_icc_log"
                            else
                                _step_complete "delete(failed)"; _step_finish
                                echo -e "  ${RED}✗ Failed to delete console connection${NC}"
                                log_action_result "FAILED" "ICC delete: ${_d_id}"
                                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED DELETE: ${_del_cmd}" >> "$_icc_log"
                            fi
                        else
                            echo -e "  ${GRAY}Cancelled${NC}"
                        fi
                        echo ""
                        _ui_pause
                    fi
                    ;;
                *)
                    echo -e "${RED}Invalid: ${_icc_input} (valid: create, get #, plink #, del #, r, Enter)${NC}"
                    ;;
                esac
            done
            ;;
        t|tag|TAG)
            # Tag instance as unhealthy (no terminate)
            tag_instance_unhealthy "$instance_ocid" "$display_name" "false"
            ;;
        rt|RT|removetag|REMOVETAG)
            # Remove unhealthy tag from instance
            remove_instance_unhealthy_tag "$instance_ocid" "$display_name"
            ;;
        j|J|json|JSON)
            echo ""
            echo -e "  ${GRAY}$ oci compute instance get --instance-id ${instance_ocid} --region ${region}${NC}"
            _ui_json_viewer "Instance JSON" "$instance_json" ".data"
            _ui_pause
            ;;
        j\ *|J\ *|json\ *|JSON\ *)
            echo ""
            echo -e "  ${GRAY}$ oci compute instance get --instance-id ${instance_ocid} --region ${region}${NC}"
            _ui_json_viewer "Instance JSON" "$instance_json" ".data" "${action#* }"
            _ui_pause
            ;;
        wr[0-9]*|WR[0-9]*)
            local _wr_num="${action//[^0-9]/}"
            if [[ -n "${_INST_WR_MAP[$_wr_num]:-}" ]]; then
                _inst_wr_detail "${_INST_WR_MAP[$_wr_num]}"
            else
                echo -e "${RED}Invalid work request wr${_wr_num}. Run 'wr' first to list.${NC}"
            fi
            ;;
        wr|WR)
            echo ""
            _ui_subheader "Work Requests for ${display_name}" 0
            echo ""
            echo -e "  ${GRAY}Fetching work requests...${NC}"
            oci work-requests work-request list --compartment-id "$compartment_id" --resource-id "$instance_ocid" --region "$region" --output json > "$_inst_wr_dir/wr.json" 2>/dev/null
            _inst_wr_ct=$(jq '(.data // []) | length' "$_inst_wr_dir/wr.json" 2>/dev/null || echo "0")
            _inst_display_wr "$_inst_wr_dir/wr.json"
            if [[ "$_INST_WR_IDX" -gt 0 ]]; then
                echo -e "  ${GRAY}Use wr# for detail (e.g. wr1, wr2)${NC}"
            fi
            ;;
        rcc[0-9]*|RCC[0-9]*)
            local _rcc_num="${action//[^0-9]/}"
            if [[ -n "${_INST_RC_MAP[$_rcc_num]:-}" ]]; then
                _inst_rc_cancel "${_INST_RC_MAP[$_rcc_num]}" "$_rcc_num"
            else
                echo -e "${RED}Invalid run command rc${_rcc_num}. Run 'rc' first to list.${NC}"
            fi
            ;;
        rc[0-9]*|RC[0-9]*)
            local _rc_num="${action//[^0-9]/}"
            if [[ -n "${_INST_RC_MAP[$_rc_num]:-}" ]]; then
                _inst_rc_detail "${_INST_RC_MAP[$_rc_num]}"
            else
                echo -e "${RED}Invalid run command rc${_rc_num}. Run 'rc' first to list.${NC}"
            fi
            ;;
        rc|RC)
            _inst_rc_create
            ;;
        rcl|RCL)
            echo ""
            _ui_subheader "Run Commands for ${display_name}" 0
            echo ""
            echo -e "  ${GRAY}Fetching run commands...${NC}"
            oci instance-agent command-execution list --compartment-id "$compartment_id" --instance-id "$instance_ocid" --region "$region" --sort-by TIMECREATED --sort-order DESC --limit 20 --output json > "$_inst_rc_dir/rc.json" 2>/dev/null
            _inst_rc_ct=$(jq '(.data // []) | length' "$_inst_rc_dir/rc.json" 2>/dev/null || echo "0")
            _inst_display_rc "$_inst_rc_dir/rc.json"
            if [[ "$_INST_RC_IDX" -gt 0 ]]; then
                echo -e "  ${GRAY}Use rc# for detail (e.g. rc1, rc2), rcc# to cancel${NC}"
            fi
            ;;
        x|X)
            # Tag instance as unhealthy AND terminate
            tag_instance_unhealthy "$instance_ocid" "$display_name" "true"
            ;;
        show|SHOW)
            # Re-display full instance details (same as refresh but silent)
            return 2
            ;;
        *)
            # Return to instance list (exit the actions loop)
            break
            ;;
    esac
    done  # End of actions loop
    rm -rf "${_inst_wr_dir:?}" 2>/dev/null
    rm -rf "${_inst_rc_dir:?}" 2>/dev/null
}

#--------------------------------------------------------------------------------
# Tag instance as unhealthy with optional terminate
# Args: $1 = instance OCID, $2 = display name, $3 = terminate (true/false)
#--------------------------------------------------------------------------------
tag_instance_unhealthy() {
    local instance_ocid="$1"
    local display_name="$2"
    local do_terminate="${3:-false}"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    # Oracle defined tag namespace and key for host actions
    local tag_namespace="ComputeInstanceHostActions"
    local tag_key="CustomerReportedHostStatus"
    local tag_value="unhealthy"
    
    echo ""
    if [[ "$do_terminate" == "true" ]]; then
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║              ⚠️  TAG UNHEALTHY + TERMINATE INSTANCE  ⚠️                         ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    else
        echo -e "${YELLOW}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${YELLOW}║                         TAG INSTANCE AS UNHEALTHY                              ║${NC}"
        echo -e "${YELLOW}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    fi
    echo ""
    echo -e "${WHITE}Instance:${NC}  ${GREEN}$display_name${NC}"
    echo -e "${WHITE}OCID:${NC}      ${YELLOW}$instance_ocid${NC}"
    echo ""
    echo -e "${WHITE}Defined tag to apply:${NC}"
    echo -e "  ${CYAN}Namespace:${NC} ${MAGENTA}$tag_namespace${NC}"
    echo -e "  ${CYAN}Key:${NC}       ${MAGENTA}$tag_key${NC}"
    echo -e "  ${CYAN}Value:${NC}     ${MAGENTA}$tag_value${NC}"
    echo ""
    
    if [[ "$do_terminate" == "true" ]]; then
        echo -e "${RED}⚠️  This will TAG the instance as unhealthy AND TERMINATE it!${NC}"
        echo ""
        echo -n -e "${RED}Type 'yes' to confirm TAG + TERMINATE: ${NC}"
    else
        echo -e "${YELLOW}This will TAG the instance as unhealthy (instance will continue running).${NC}"
        echo ""
        echo -n -e "${CYAN}Confirm tag? (yes/no): ${NC}"
    fi
    
    local confirm
    read -r confirm
    
    if [[ "$confirm" != "yes" ]]; then
        echo -e "${YELLOW}Operation cancelled${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    # Get current defined tags
    echo ""
    _step_init
    _step_active "current instance tags"
    
    local instance_json
    instance_json=$(oci compute instance get \
        --instance-id "$instance_ocid" \
        --region "$region" \
        --output json 2>&1)
    local _oci_rc=$?
    _step_complete "current instance tags"
    _step_finish

    if [[ $_oci_rc -ne 0 ]]; then
        echo -e "${RED}Failed to fetch instance details:${NC}"
        echo "$instance_json"
        echo ""
        _ui_pause
        return 1
    fi
    
    # Extract current defined-tags
    local current_defined_tags
    current_defined_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$instance_json")
    
    # Show current tags
    echo ""
    echo -e "${WHITE}Current defined tags:${NC}"
    if [[ -n "$current_defined_tags" && "$current_defined_tags" != "{}" ]]; then
        jq -r 'to_entries[] | .key as $ns | .value | to_entries[] | "  \($ns).\(.key) = \(.value)"' <<< "$current_defined_tags" 2>/dev/null
    else
        echo -e "  ${GRAY}(none)${NC}"
    fi
    echo ""
    
    # Merge in our new tag (preserving all existing tags)
    local updated_defined_tags
    updated_defined_tags=$(jq --arg ns "$tag_namespace" --arg key "$tag_key" --arg val "$tag_value" '
        .[$ns] = ((.[$ns] // {}) + {($key): $val})
    ' <<< "$current_defined_tags")
    
    # Format the JSON for display (compact for command, pretty for log)
    local updated_tags_compact
    updated_tags_compact=$(jq -c '.' <<< "$updated_defined_tags")
    
    # Build the update command for display
    local update_cmd="oci compute instance update --instance-id \"$instance_ocid\" --region \"$region\" --defined-tags '${updated_tags_compact}' --force"
    
    echo -e "${WHITE}Command to execute:${NC}"
    _ui_oci_cmd "oci compute instance update \\"
    echo -e "${GRAY}  --instance-id \"$instance_ocid\" \\${NC}"
    echo -e "${GRAY}  --region \"$region\" \\${NC}"
    echo -e "${GRAY}  --defined-tags '${NC}"
    jq '.' <<< "$updated_defined_tags" | while IFS= read -r line; do
        echo -e "${GRAY}$line${NC}"
    done
    echo -e "${GRAY}' --force${NC}"
    echo ""
    
    # Log the action
    log_action "TAG_UNHEALTHY" "$update_cmd"
    
    # Apply the tag
    echo -e "${YELLOW}Applying defined tag...${NC}"
    
    local tag_result
    tag_result=$(oci compute instance update \
        --instance-id "$instance_ocid" \
        --region "$region" \
        --defined-tags "$updated_defined_tags" \
        --force \
        --output json 2>&1)
    
    local tag_exit_code=$?
    
    if [[ $tag_exit_code -eq 0 ]]; then
        echo -e "${GREEN}✓ Instance tagged as unhealthy successfully${NC}"
        log_action_result "SUCCESS" "Instance $display_name tagged with $tag_namespace.$tag_key=$tag_value"
        
        # Verify the tag was applied
        local applied_tag
        applied_tag=$(jq -r --arg ns "$tag_namespace" --arg key "$tag_key" '.data["defined-tags"][$ns][$key] // "NOT_SET"' <<< "$tag_result")
        echo -e "  ${CYAN}Verified:${NC} ${MAGENTA}$tag_namespace.$tag_key${NC} = ${GREEN}$applied_tag${NC}"
        
        # If terminate requested, show instance details with the tag first
        if [[ "$do_terminate" == "true" ]]; then
            echo ""
            _ui_content_border "$YELLOW"
            echo -e "${YELLOW}                           INSTANCE DETAILS WITH APPLIED TAG                                                    ${NC}"
            _ui_content_border "$YELLOW"
            echo ""
            
            # Re-fetch instance to show updated tags
            local updated_instance_json
            updated_instance_json=$(oci compute instance get \
                --instance-id "$instance_ocid" \
                --region "$region" \
                --output json 2>/dev/null)
            
            if [[ -n "$updated_instance_json" ]]; then
                # Display key instance info
                local inst_state inst_shape inst_ad inst_created
                inst_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$updated_instance_json")
                inst_shape=$(jq -r '.data.shape // "N/A"' <<< "$updated_instance_json")
                inst_ad=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$updated_instance_json")
                inst_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$updated_instance_json")
                
                echo -e "${WHITE}Instance:${NC}       ${GREEN}$display_name${NC}"
                echo -e "${WHITE}OCID:${NC}           ${YELLOW}$instance_ocid${NC}"
                echo -e "${WHITE}State:${NC}          ${CYAN}$inst_state${NC}"
                echo -e "${WHITE}Shape:${NC}          ${CYAN}$inst_shape${NC}"
                echo -e "${WHITE}AD:${NC}             ${CYAN}${inst_ad##*:}${NC}"
                echo -e "${WHITE}Created:${NC}        ${GRAY}${inst_created:0:19}${NC}"
                echo ""
                
                # Display defined tags (highlighting the unhealthy tag)
                _ui_subheader "Defined Tags" 0
                local defined_tags
                defined_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$updated_instance_json")
                
                if [[ -n "$defined_tags" && "$defined_tags" != "{}" ]]; then
                    jq -r 'to_entries[] | .key as $ns | .value | to_entries[] | "\($ns).\(.key)=\(.value)"' <<< "$defined_tags" 2>/dev/null | while read -r tag_line; do
                        if [[ "$tag_line" == *"$tag_namespace.$tag_key"* ]]; then
                            # Highlight the unhealthy tag
                            echo -e "  ${RED}★ $tag_line${NC}  ${RED}← UNHEALTHY TAG APPLIED${NC}"
                        else
                            echo -e "  ${GRAY}$tag_line${NC}"
                        fi
                    done
                else
                    echo -e "  ${GRAY}(none)${NC}"
                fi
                
                # Display freeform tags if any
                local freeform_tags
                freeform_tags=$(jq -r '.data["freeform-tags"] // {}' <<< "$updated_instance_json")
                if [[ -n "$freeform_tags" && "$freeform_tags" != "{}" ]]; then
                    echo ""
                    _ui_subheader "Freeform Tags" 0
                    jq -r 'to_entries[] | "  \(.key)=\(.value)"' <<< "$freeform_tags" 2>/dev/null
                fi
            fi
            
            echo ""
            _ui_content_border "$YELLOW"
        fi
    else
        echo -e "${RED}✗ Failed to tag instance:${NC}"
        echo "$tag_result"
        log_action_result "FAILED" "Failed to tag instance $display_name"
        
        # Check if it's a tag namespace issue
        if echo "$tag_result" | grep -qi "TagDefinition\|TagNamespace\|does not exist"; then
            echo ""
            _ui_content_border "$YELLOW"
            echo -e "${YELLOW}NOTE: The tag namespace '$tag_namespace' or key '$tag_key' may not exist in your tenancy.${NC}"
            echo -e "${YELLOW}You may need to create it first or use a different tag.${NC}"
            echo ""
            echo -e "${WHITE}To create the tag namespace and key, use:${NC}"
            echo -e "${GRAY}  oci iam tag-namespace create --compartment-id <root-compartment> --name \"$tag_namespace\" --description \"Host action tags\"${NC}"
            echo -e "${GRAY}  oci iam tag create --tag-namespace-id <namespace-ocid> --name \"$tag_key\" --description \"Customer reported host status\"${NC}"
            _ui_content_border "$YELLOW"
        fi
        
        echo ""
        _ui_pause
        return 1
    fi
    
    # If terminate requested, do it now
    if [[ "$do_terminate" == "true" ]]; then
        echo ""
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                    ⚠️  FINAL CONFIRMATION TO TERMINATE  ⚠️                       ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${WHITE}Instance ${GREEN}$display_name${NC}${WHITE} has been tagged as unhealthy.${NC}"
        echo -e "${RED}Are you sure you want to TERMINATE this instance?${NC}"
        echo ""
        
        if ! _ui_confirm "TERMINATE" "proceed (or anything else to cancel)"; then
            echo -e "${YELLOW}Termination cancelled. Instance remains tagged as unhealthy.${NC}"
            echo ""
            _ui_pause
            return 0
        fi
        
        echo ""
        echo -e "${RED}Proceeding with instance termination...${NC}"
        
        local terminate_cmd="oci compute instance terminate --instance-id \"$instance_ocid\" --region \"$region\" --preserve-boot-volume false --force"
        
        echo ""
        echo -e "${WHITE}Command to execute:${NC}"
        echo -e "${GRAY}$terminate_cmd${NC}"
        echo ""
        
        log_action "TERMINATE" "$terminate_cmd"
        
        local terminate_result
        terminate_result=$(oci compute instance terminate \
            --instance-id "$instance_ocid" \
            --region "$region" \
            --preserve-boot-volume false \
            --force 2>&1)
        
        if [[ $? -eq 0 ]]; then
            echo -e "${GREEN}✓ Instance termination initiated${NC}"
            log_action_result "SUCCESS" "Instance $display_name termination initiated"
        else
            echo -e "${RED}✗ Failed to terminate instance:${NC}"
            echo "$terminate_result"
            log_action_result "FAILED" "Failed to terminate instance $display_name"
        fi
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Remove unhealthy tag from instance
# Args: $1 = instance OCID, $2 = display name
#--------------------------------------------------------------------------------
remove_instance_unhealthy_tag() {
    local instance_ocid="$1"
    local display_name="$2"
    local region="${FOCUS_REGION:-$REGION}"
    
    # Oracle defined tag namespace and key for host actions
    local tag_namespace="ComputeInstanceHostActions"
    local tag_key="CustomerReportedHostStatus"
    
    echo ""
    echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║                       REMOVE UNHEALTHY TAG FROM INSTANCE                       ║${NC}"
    echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}Instance:${NC}  ${GREEN}$display_name${NC}"
    echo -e "${WHITE}OCID:${NC}      ${YELLOW}$instance_ocid${NC}"
    echo ""
    
    # Get current defined tags
    _step_init
    _step_active "current instance tags"
    
    local instance_json
    instance_json=$(oci compute instance get \
        --instance-id "$instance_ocid" \
        --region "$region" \
        --output json 2>&1)
    local _oci_rc=$?
    _step_complete "current instance tags"
    _step_finish

    if [[ $_oci_rc -ne 0 ]]; then
        echo -e "${RED}Failed to fetch instance details:${NC}"
        echo "$instance_json"
        echo ""
        _ui_pause
        return 1
    fi
    
    # Extract current defined-tags
    local current_defined_tags
    current_defined_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$instance_json")
    
    # Check if the tag exists
    local current_tag_value
    current_tag_value=$(jq -r --arg ns "$tag_namespace" --arg key "$tag_key" '.[$ns][$key] // empty' <<< "$current_defined_tags")
    
    if [[ -z "$current_tag_value" ]]; then
        echo ""
        echo -e "${YELLOW}The unhealthy tag is not set on this instance.${NC}"
        echo -e "  ${CYAN}$tag_namespace.$tag_key${NC} = ${GRAY}(not set)${NC}"
        echo ""
        _ui_pause
        return 0
    fi
    
    echo ""
    echo -e "${WHITE}Current tag to remove:${NC}"
    echo -e "  ${CYAN}Namespace:${NC} ${MAGENTA}$tag_namespace${NC}"
    echo -e "  ${CYAN}Key:${NC}       ${MAGENTA}$tag_key${NC}"
    echo -e "  ${CYAN}Value:${NC}     ${RED}$current_tag_value${NC}"
    echo ""
    
    # Show all current tags
    echo -e "${WHITE}All current defined tags:${NC}"
    if [[ -n "$current_defined_tags" && "$current_defined_tags" != "{}" ]]; then
        jq -r 'to_entries[] | .key as $ns | .value | to_entries[] | "\($ns).\(.key) = \(.value)"' <<< "$current_defined_tags" 2>/dev/null | while read -r tag_line; do
            if [[ "$tag_line" == *"$tag_namespace.$tag_key"* ]]; then
                echo -e "  ${RED}★ $tag_line${NC}  ${RED}← TO BE REMOVED${NC}"
            else
                echo -e "  ${GRAY}$tag_line${NC}"
            fi
        done
    fi
    echo ""
    
    echo -e "${GREEN}This will REMOVE the unhealthy tag from the instance.${NC}"
    echo ""
    echo -n -e "${CYAN}Confirm removal? (yes/no): ${NC}"
    
    local confirm
    read -r confirm
    
    if [[ "$confirm" != "yes" ]]; then
        echo -e "${YELLOW}Operation cancelled${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    # Remove the tag by deleting the key from the namespace
    local updated_defined_tags
    updated_defined_tags=$(jq --arg ns "$tag_namespace" --arg key "$tag_key" '
        if .[$ns] then
            .[$ns] |= del(.[$key]) |
            if .[$ns] == {} then del(.[$ns]) else . end
        else
            .
        end
    ' <<< "$current_defined_tags" )
    
    # Format the JSON for display
    local updated_tags_compact
    updated_tags_compact=$(jq -c '.' <<< "$updated_defined_tags")
    
    # Build the update command for display
    local update_cmd="oci compute instance update --instance-id \"$instance_ocid\" --region \"$region\" --defined-tags '${updated_tags_compact}' --force"
    
    echo ""
    echo -e "${WHITE}Command to execute:${NC}"
    _ui_oci_cmd "oci compute instance update \\"
    echo -e "${GRAY}  --instance-id \"$instance_ocid\" \\${NC}"
    echo -e "${GRAY}  --region \"$region\" \\${NC}"
    echo -e "${GRAY}  --defined-tags '${NC}"
    jq '.' <<< "$updated_defined_tags" | while IFS= read -r line; do
        echo -e "${GRAY}$line${NC}"
    done
    echo -e "${GRAY}' --force${NC}"
    echo ""
    
    # Log the action
    log_action "REMOVE_UNHEALTHY_TAG" "$update_cmd"
    
    # Apply the update
    echo -e "${YELLOW}Removing unhealthy tag...${NC}"
    
    local tag_result
    tag_result=$(oci compute instance update \
        --instance-id "$instance_ocid" \
        --region "$region" \
        --defined-tags "$updated_defined_tags" \
        --force \
        --output json 2>&1)
    
    local tag_exit_code=$?
    
    if [[ $tag_exit_code -eq 0 ]]; then
        echo -e "${GREEN}✓ Unhealthy tag removed successfully${NC}"
        log_action_result "SUCCESS" "Instance $display_name - removed $tag_namespace.$tag_key tag"
        
        # Verify the tag was removed
        local verified_tag
        verified_tag=$(jq -r --arg ns "$tag_namespace" --arg key "$tag_key" '.data["defined-tags"][$ns][$key] // "REMOVED"' <<< "$tag_result")
        if [[ "$verified_tag" == "REMOVED" || -z "$verified_tag" ]]; then
            echo -e "  ${CYAN}Verified:${NC} ${MAGENTA}$tag_namespace.$tag_key${NC} = ${GREEN}(removed)${NC}"
        else
            echo -e "  ${YELLOW}Warning:${NC} Tag may still exist: ${MAGENTA}$tag_namespace.$tag_key${NC} = ${RED}$verified_tag${NC}"
        fi
        
        # Show updated tags
        echo ""
        _ui_subheader "Updated Defined Tags" 0
        local final_tags
        final_tags=$(jq -r '.data["defined-tags"] // {}' <<< "$tag_result")
        if [[ -n "$final_tags" && "$final_tags" != "{}" ]]; then
            jq -r 'to_entries[] | .key as $ns | .value | to_entries[] | "  \($ns).\(.key) = \(.value)"' <<< "$final_tags" 2>/dev/null
        else
            echo -e "  ${GRAY}(no defined tags)${NC}"
        fi
    else
        echo -e "${RED}✗ Failed to remove tag:${NC}"
        echo "$tag_result"
        log_action_result "FAILED" "Failed to remove unhealthy tag from instance $display_name"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Interactive console history - entry point from instance details menu
# Args: $1 = instance OCID, $2 = instance display name
#--------------------------------------------------------------------------------
capture_console_history() {
    local instance_ocid="$1"
    local instance_name="$2"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_menu_header "CONSOLE HISTORY" \
        --breadcrumb "Compute" "Instances" "Console History" \
        --cmd "oci compute console-history list --compartment-id \$COMPARTMENT_ID --instance-id \$INSTANCE_OCID | oci compute instance list | oci compute instance get" \
        --env
    echo ""
    echo -e "  ${WHITE}Instance:${NC} ${GREEN}$instance_name${NC}"
    echo -e "  ${WHITE}OCID:${NC}     ${YELLOW}$instance_ocid${NC}"
    echo ""
    
    # Check for existing console history captures
    _step_init
    _step_active "console history"
    
    local existing_history
    existing_history=$(oci --region "$region" compute console-history list \
        --compartment-id "$compartment_id" \
        --instance-id "$instance_ocid" \
        --lifecycle-state "SUCCEEDED" \
        --sort-by "TIMECREATED" \
        --sort-order "DESC" \
        --limit 5 \
        --output json 2>/dev/null)
    
    local history_count=0
    [[ -n "$existing_history" ]] && history_count=$(jq -r '.data | length' <<< "$existing_history" 2>/dev/null) || history_count=0
    [[ ! "$history_count" =~ ^[0-9]+$ ]] && history_count=0
    _step_complete "console history(${history_count})"
    _step_finish
    
    if [[ $history_count -gt 0 ]]; then
        echo ""
        echo -e "${WHITE}Recent console history captures:${NC}"
        echo ""
        
        declare -a HISTORY_LIST=()
        local idx=0
        
        printf "  ${GRAY}%-4s %-25s %-20s${NC}\n" "#" "Time Created" "State"
        echo -e "  ${GRAY}────────────────────────────────────────────────────────────${NC}"
        
        while IFS='|' read -r hist_id hist_time hist_state; do
            [[ -z "$hist_id" ]] && continue
            ((idx++))
            HISTORY_LIST+=("$hist_id")
            printf "  ${YELLOW}%-4s${NC} ${WHITE}%-25s${NC} ${GREEN}%-20s${NC}\n" "${idx})" "${hist_time:0:19}" "$hist_state"
        done < <(jq -r '.data[] | "\(.id)|\(.["time-created"])|\(.["lifecycle-state"])"' <<< "$existing_history" 2>/dev/null)
        
        echo ""
        echo -e "  ${CYAN}n${NC}) Capture new console history"
        echo -e "  ${CYAN}b${NC}) Back"
        echo ""
        echo -n -e "${CYAN}Select existing capture [1-${idx}] or 'n' for new: ${NC}"
        local choice
        read -r choice
        
        if [[ "$choice" == "n" || "$choice" == "N" ]]; then
            # Capture new using unified function (auto_cleanup=true, interactive=true)
            fetch_and_display_console_history "$instance_ocid" "$region" "$instance_name" "true" "true"
            echo ""
            _ui_pause
        elif [[ "$choice" == "b" || "$choice" == "B" || -z "$choice" ]]; then
            return
        elif [[ "$choice" =~ ^[0-9]+$ ]] && [[ $choice -ge 1 ]] && [[ $choice -le ${#HISTORY_LIST[@]} ]]; then
            local selected_id="${HISTORY_LIST[$((choice-1))]}"
            # Display existing history content
            _display_existing_console_history "$selected_id" "$instance_name" "$region"
            echo ""
            _ui_pause
        else
            echo -e "${RED}Invalid selection${NC}"
            sleep 1
        fi
    else
        echo ""
        echo -e "${GRAY}No existing console history captures found.${NC}"
        echo ""
        # Automatically capture new console history using unified function
        fetch_and_display_console_history "$instance_ocid" "$region" "$instance_name" "true" "true"
        echo ""
        _ui_pause
    fi
}

#--------------------------------------------------------------------------------
# Display existing console history content (for viewing previously captured history)
# Args: $1 = console history OCID, $2 = instance display name, $3 = region
#--------------------------------------------------------------------------------
_display_existing_console_history() {
    local history_id="$1"
    local instance_name="$2"
    local region="${3:-${FOCUS_REGION:-$REGION}}"
    
    echo ""
    
    # Build the command (for display)
    local cmd="oci --region \"$region\" compute console-history get-content --instance-console-history-id \"$history_id\" --length 10000000 --file -"
    echo -e "${GRAY}Command: ${cmd}${NC}"
    echo ""
    
    # Use temp file for reliability
    local temp_output temp_error
    temp_output=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    temp_error=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    _step_init
    _step_active "console output"
    # Capture raw output for display if empty
    local raw_output
    raw_output=$(oci --region "$region" compute console-history get-content \
        --instance-console-history-id "$history_id" \
        --length 10000000 \
        --file "$temp_output" 2>&1)
    local exit_code=$?
    _step_complete "console output"
    _step_finish
    
    _ui_subheader "Console Output" 0
    echo ""
    
    if [[ $exit_code -eq 0 ]]; then
        if [[ -s "$temp_output" ]]; then
            cat "$temp_output"
            echo ""
            _ui_subheader "End of Console Output" 0
            echo ""
            
            # Option to save
            echo -n -e "${CYAN}Save to file? [y/N]: ${NC}"
            local save_choice
            read -r save_choice
            
            if [[ "$save_choice" =~ ^[Yy] ]]; then
                local safe_name
                safe_name=$(echo "$instance_name" | tr ' ' '_' | tr -cd '[:alnum:]_-')
                local filename="${safe_name}_console_$(date +%Y%m%d_%H%M%S).log"
                
                echo -n -e "${CYAN}Filename [${filename}]: ${NC}"
                local custom_filename
                read -r custom_filename
                [[ -n "$custom_filename" ]] && filename="$custom_filename"
                
                if cp "$temp_output" "$filename" 2>/dev/null; then
                    echo -e "${GREEN}✓ Console output saved to: ${WHITE}$(pwd)/${filename}${NC}"
                else
                    echo -e "${RED}Failed to save console output${NC}"
                fi
            fi
        else
            echo -e "${YELLOW}(Console history is empty - no serial console output captured)${NC}"
            echo ""
            echo -e "${WHITE}OCI CLI raw output:${NC}"
            if [[ -n "$raw_output" ]]; then
                echo -e "${GRAY}${raw_output}${NC}"
            else
                echo -e "${GRAY}(no output returned)${NC}"
            fi
            echo ""
            echo -e "${WHITE}Note: This can happen if:${NC}"
            echo -e "${GRAY}  - The instance has not produced any serial console output${NC}"
            echo -e "${GRAY}  - Serial console logging is not enabled on the instance${NC}"
            echo -e "${GRAY}  - The instance was recently created/rebooted${NC}"
            echo ""
            _ui_subheader "End of Console Output" 0
        fi
    else
        echo -e "${RED}Failed to fetch console history content${NC}"
        _ui_policy_hint "read console-histories in compartment"
        echo -e "${GRAY}Exit code: ${exit_code}${NC}"
        echo -e "${WHITE}OCI CLI output:${NC}"
        echo -e "${GRAY}${raw_output}${NC}"
        if [[ -s "$temp_error" ]]; then
            echo -e "${WHITE}Stderr:${NC}"
            cat "$temp_error"
        fi
        echo ""
        _ui_subheader "End of Console Output" 0
    fi
    
    # Cleanup temp files
    rm -f "$temp_output" "$temp_error"
}

#--------------------------------------------------------------------------------
# Compare instance cloud-init - offers choice of another instance or instance config
# Args: $1 = instance OCID, $2 = instance display name, $3 = instance user_data base64
#--------------------------------------------------------------------------------
compare_instance_cloud_init() {
    local instance_ocid="$1"
    local instance_name="$2"
    local instance_ud_b64="$3"
    
    echo ""
    _ui_subheader "Compare Cloud-Init" 0
    echo ""
    echo -e "${WHITE}Current Instance:${NC} ${GREEN}$instance_name${NC}"
    echo ""
    _ui_subheader "Compare Against" 0
    echo -e "  ${YELLOW}1${NC}) Another Compute Instance"
    echo -e "  ${YELLOW}2${NC}) An Instance Configuration"
    echo -e "  ${YELLOW}3${NC}) A Local File"
    echo -e "  ${CYAN}q${NC}) Cancel"
    echo ""
    echo -n -e "${CYAN}Select option [1/2/3/q]: ${NC}"
    
    local choice
    read -r choice
    
    case "$choice" in
        1)
            compare_instance_to_instance "$instance_ocid" "$instance_name" "$instance_ud_b64"
            ;;
        2)
            compare_instance_to_config "$instance_ocid" "$instance_name" "$instance_ud_b64"
            ;;
        3)
            compare_instance_to_file "$instance_ocid" "$instance_name" "$instance_ud_b64"
            ;;
        *)
            return
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Compare instance cloud-init to another instance
# Args: $1 = instance OCID, $2 = instance display name, $3 = instance user_data base64
#--------------------------------------------------------------------------------
compare_instance_to_instance() {
    local instance_ocid="$1"
    local instance_name="$2"
    local instance_ud_b64="$3"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Compare to Another Instance" 0
    echo ""
    _step_init
    _step_active "compute instances"

    # Get list of instances
    local instances_json
    instances_json=$(oci compute instance list \
        --compartment-id "$compartment_id" \
        --region "$region" \
        --lifecycle-state RUNNING \
        --output json 2>/dev/null)
    _step_complete "compute instances"
    _step_finish
    
    if [[ -z "$instances_json" ]] || ! jq -e '.data[]' <<< "$instances_json" > /dev/null 2>&1; then
        echo -e "${RED}No running instances found${NC}"
        _ui_pause "return"
        return
    fi
    
    # List instances (excluding current one)
    local inst_idx=0
    declare -A COMPARE_INST_MAP=()
    
    _ui_table_header "%-4s %-50s %-25s" "#" "Instance Name" "Shape"
    
    while IFS='|' read -r inst_ocid inst_name inst_shape; do
        [[ -z "$inst_ocid" ]] && continue
        [[ "$inst_ocid" == "$instance_ocid" ]] && continue  # Skip current instance
        
        ((inst_idx++))
        COMPARE_INST_MAP[$inst_idx]="$inst_ocid|$inst_name"
        printf "${YELLOW}%-4s${NC} ${WHITE}%-50s${NC} ${CYAN}%-25s${NC}\n" "$inst_idx" "${inst_name:0:50}" "$inst_shape"
    done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])|\(.shape)"' <<< "$instances_json" 2>/dev/null)
    
    if [[ $inst_idx -eq 0 ]]; then
        echo -e "${GRAY}No other instances found to compare${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    echo -n -e "${CYAN}Select instance to compare against (1-${inst_idx}): ${NC}"
    local select_choice
    read -r select_choice
    
    if [[ -z "${COMPARE_INST_MAP[$select_choice]:-}" ]]; then
        echo -e "${RED}Invalid selection${NC}"
        _ui_pause "return"
        return
    fi
    
    local other_ocid other_name
    IFS='|' read -r other_ocid other_name <<< "${COMPARE_INST_MAP[$select_choice]}"
    
    echo ""
    _step_init
    _step_active "instance details"

    # Get the other instance's user_data (fetch full JSON, extract with jq)
    local other_json other_ud_b64
    other_json=$(oci compute instance get \
        --instance-id "$other_ocid" \
        --region "$region" \
        --output json 2>/dev/null)
    _step_complete "instance details"
    _step_finish
    
    if [[ -n "$other_json" ]] && jq -e '.data' <<< "$other_json" > /dev/null 2>&1; then
        other_ud_b64=$(jq -r '.data.metadata.user_data // empty' <<< "$other_json" 2>/dev/null)
    fi
    
    if [[ -z "$other_ud_b64" || "$other_ud_b64" == "null" ]]; then
        echo -e "${YELLOW}The selected instance has no cloud-init user_data${NC}"
        _ui_pause "return"
        return
    fi
    
    # Create temp files for diff
    local tmp1 tmp2
    tmp1=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    tmp2=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    # Decode user_data (handles gzip compression)
    decode_user_data_to_file "$instance_ud_b64" "$tmp1"
    decode_user_data_to_file "$other_ud_b64" "$tmp2"
    
    echo ""
    _ui_menu_header "INSTANCE CLOUD-INIT COMPARISON"
    echo ""
    echo -e "${WHITE}Comparing:${NC}"
    echo -e "  ${RED}- Instance A:${NC} ${GREEN}$instance_name${NC}"
    echo -e "  ${GREEN}+ Instance B:${NC} ${BLUE}$other_name${NC}"
    echo ""
    
    if diff -q "$tmp1" "$tmp2" > /dev/null 2>&1; then
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                                                 ✓ CLOUD-INIT IS IDENTICAL                                                                              ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
    else
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                                                 ✗ CLOUD-INIT DIFFERS                                                                                    ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        _ui_subheader "Differences" 0
        echo ""
        
        local diff_output
        diff_output=$(diff -u "$tmp1" "$tmp2" 2>/dev/null | tail -n +4)
        
        while IFS= read -r line; do
            if [[ "$line" =~ ^@@ ]]; then
                printf '%b%s%b\n' "${YELLOW}" "$line" "${NC}"
            elif [[ "$line" =~ ^- ]]; then
                printf '%b%s%b\n' "${RED}" "$line" "${NC}"
            elif [[ "$line" =~ ^\+ ]]; then
                printf '%b%s%b\n' "${GREEN}" "$line" "${NC}"
            elif [[ "$line" =~ ^[[:space:]] ]]; then
                printf '%b%s%b\n' "${GRAY}" "$line" "${NC}"
            fi
        done <<< "$diff_output"
    fi

    rm -f "$tmp1" "$tmp2"
    
    echo ""
    _ui_content_border
    echo ""
    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Compare instance cloud-init against an instance configuration
# Args: $1 = instance OCID, $2 = instance display name, $3 = instance user_data base64
#--------------------------------------------------------------------------------
compare_instance_to_config() {
    local instance_ocid="$1"
    local instance_name="$2"
    local instance_ud_b64="$3"
    
    echo ""
    _ui_subheader "Compare Instance Cloud-Init to Instance Configuration" 0
    echo ""
    echo -e "${WHITE}Instance:${NC} ${GREEN}$instance_name${NC}"
    echo ""
    
    # Refresh instance config cache
    fetch_instance_configurations > /dev/null 2>&1
    
    if [[ ! -f "$INSTANCE_CONFIG_CACHE" ]]; then
        echo -e "${RED}No instance configurations found${NC}"
        _ui_pause "return"
        return
    fi
    
    # List configs
    _list_ics_numbered
    
    if [[ $_IC_LIST_COUNT -eq 0 ]]; then
        echo -e "${GRAY}No instance configurations found${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    echo -n -e "${CYAN}Select instance configuration to compare against (1-${_IC_LIST_COUNT}): ${NC}"
    local choice
    read -r choice
    
    if [[ -z "${_IC_LIST_MAP[$choice]:-}" ]]; then
        echo -e "${RED}Invalid selection${NC}"
        _ui_pause "return"
        return
    fi
    
    local ic_ocid ic_name
    IFS='|' read -r ic_ocid ic_name <<< "${_IC_LIST_MAP[$choice]}"
    
    echo ""
    _step_init
    _step_active "instance configuration"

    # Get instance config user_data (fetch full JSON, extract with jq - same as detail view)
    local ic_json ic_ud_b64
    ic_json=$(oci compute-management instance-configuration get \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --output json 2>/dev/null)
    _step_complete "instance configuration"
    _step_finish
    
    if [[ -n "$ic_json" ]] && jq -e '.data' <<< "$ic_json" > /dev/null 2>&1; then
        ic_ud_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic_json" 2>/dev/null)
    fi
    
    if [[ -z "$ic_ud_b64" || "$ic_ud_b64" == "null" ]]; then
        echo -e "${YELLOW}Instance configuration has no user_data${NC}"
        _ui_pause "return"
        return
    fi
    
    # Create temp files for diff
    local tmp_instance tmp_ic
    tmp_instance=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    tmp_ic=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    # Decode user_data (handles gzip compression)
    decode_user_data_to_file "$instance_ud_b64" "$tmp_instance"
    decode_user_data_to_file "$ic_ud_b64" "$tmp_ic"
    
    echo ""
    _ui_menu_header "CLOUD-INIT COMPARISON"
    echo ""
    echo -e "${WHITE}Comparing:${NC}"
    echo -e "  ${RED}- (Instance):${NC}        ${GREEN}$instance_name${NC}"
    echo -e "  ${GREEN}+ (Instance Config):${NC} ${BLUE}$ic_name${NC}"
    echo ""
    
    if diff -q "$tmp_instance" "$tmp_ic" > /dev/null 2>&1; then
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                                           ✓ CLOUD-INIT IS IDENTICAL - NO DRIFT DETECTED                                                               ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
    else
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                                           ✗ DRIFT DETECTED - CLOUD-INIT DIFFERS                                                                        ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        _ui_subheader "Differences" 0
        echo ""
        
        # Show annotated diff
        local diff_output
        diff_output=$(diff -u "$tmp_instance" "$tmp_ic" 2>/dev/null | tail -n +4)
        
        while IFS= read -r line; do
            if [[ "$line" =~ ^@@ ]]; then
                echo -e "${YELLOW}${line}${NC}"
            elif [[ "$line" =~ ^- ]]; then
                echo -e "${RED}${line}${NC}  ${GRAY}← Instance (current)${NC}"
            elif [[ "$line" =~ ^\+ ]]; then
                echo -e "${GREEN}${line}${NC}  ${GRAY}← Instance Config (expected)${NC}"
            elif [[ "$line" =~ ^[[:space:]] ]]; then
                echo -e "${GRAY}${line}${NC}"
            fi
        done <<< "$diff_output"
    fi
    
    # Cleanup
    rm -f "$tmp_instance" "$tmp_ic"
    
    echo ""
    _ui_content_border
    echo ""
    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Compare instance cloud-init to a local file
# Args: $1 = instance OCID, $2 = instance display name, $3 = instance user_data base64
#--------------------------------------------------------------------------------
compare_instance_to_file() {
    local instance_ocid="$1"
    local instance_name="$2"
    local instance_ud_b64="$3"
    
    echo ""
    _ui_subheader "Compare Instance Cloud-Init to Local File" 0
    echo ""
    echo -e "${WHITE}Instance:${NC} ${GREEN}$instance_name${NC}"
    echo ""
    
    # Search for cloud-init files in current directory
    local ci_files=()
    local ci_idx=0
    while IFS= read -r -d '' ci_file; do
        ((ci_idx++))
        ci_files[$ci_idx]="$ci_file"
    done < <(find . -maxdepth 1 \( -name 'cloud-init*.yml' -o -name 'cloud-init*.yaml' -o -name 'cloud-init*.txt' -o -name '*.cloud-init' \) -print0 2>/dev/null | sort -z)
    
    local local_file=""
    if [[ $ci_idx -gt 0 ]]; then
        _ui_subheader "Cloud-init Files in Current Directory" 0
        for ((fi=1; fi<=ci_idx; fi++)); do
            printf "  ${YELLOW}%-3s${NC} %s\n" "$fi" "${ci_files[$fi]}"
        done
        echo ""
        echo -n -e "${CYAN}Select file # or enter path manually (Enter=cancel): ${NC}"
        local file_choice
        read -r file_choice
        
        [[ -z "$file_choice" ]] && return
        
        if [[ "$file_choice" =~ ^[0-9]+$ ]] && [[ -n "${ci_files[$file_choice]:-}" ]]; then
            local_file="${ci_files[$file_choice]}"
        else
            local_file="$file_choice"
        fi
    else
        echo -e "${GRAY}No cloud-init*.yml / cloud-init*.yaml files found in current directory${NC}"
        echo ""
        echo -n -e "${CYAN}Enter path to local file (Enter=cancel): ${NC}"
        read -r local_file
        [[ -z "$local_file" ]] && return
    fi
    
    # Expand ~ to home directory
    local_file="${local_file/#\~/$HOME}"
    
    if [[ ! -f "$local_file" ]]; then
        echo -e "${RED}File not found: ${local_file}${NC}"
        _ui_pause "return"
        return
    fi
    
    local local_basename
    local_basename=$(basename "$local_file")
    
    # Decode instance cloud-init to temp file
    local tmp_instance
    tmp_instance=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    if [[ -n "$instance_ud_b64" && "$instance_ud_b64" != "null" ]]; then
        decode_user_data_to_file "$instance_ud_b64" "$tmp_instance" || echo "# Failed to decode" > "$tmp_instance"
    else
        echo "# No user_data" > "$tmp_instance"
    fi
    
    echo ""
    _ui_menu_header "CLOUD-INIT COMPARISON (Instance vs File)"
    echo ""
    echo -e "${WHITE}Comparing:${NC}"
    echo -e "  ${RED}- Instance:${NC}   ${GREEN}$instance_name${NC} ${GRAY}($instance_ocid)${NC}"
    echo -e "  ${GREEN}+ Local File:${NC} ${BLUE}$local_basename${NC} ${GRAY}($local_file)${NC}"
    echo ""
    
    if diff -q "$tmp_instance" "$local_file" > /dev/null 2>&1; then
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                                                 ✓ CLOUD-INIT IS IDENTICAL                                                                              ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
    else
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                                                 ✗ CLOUD-INIT DIFFERS                                                                                    ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        _ui_subheader "Differences" 0
        echo ""
        
        local diff_output
        diff_output=$(diff -u "$tmp_instance" "$local_file" 2>/dev/null | tail -n +4)
        
        while IFS= read -r line; do
            if [[ "$line" =~ ^@@ ]]; then
                printf '%b%s%b\n' "${YELLOW}" "$line" "${NC}"
            elif [[ "$line" =~ ^- ]]; then
                printf '%b%s%b\n' "${RED}" "$line" "${NC}"
            elif [[ "$line" =~ ^\+ ]]; then
                printf '%b%s%b\n' "${GREEN}" "$line" "${NC}"
            elif [[ "$line" =~ ^[[:space:]] ]]; then
                printf '%b%s%b\n' "${GRAY}" "$line" "${NC}"
            fi
        done <<< "$diff_output"
    fi
    
    # Cleanup
    rm -f "$tmp_instance"
    
    echo ""
    _ui_pause "return"
}

#===============================================================================
# INSTANCE CONFIGURATION MANAGEMENT
#===============================================================================

manage_instance_configurations() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    # Build instance config index map
    declare -A LOCAL_IC_INDEX_MAP=()
    
    while true; do
        _ui_menu_header "INSTANCE CONFIGURATION MANAGEMENT" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Instance Configs" \
            --cmd "oci compute-management instance-configuration list --compartment-id \$COMPARTMENT_ID --all" \
            --env \
            --cache \
            "${INSTANCE_CONFIG_CACHE}|Instance Configs"
        
        # ── Discovery ──
        _step_init
        if is_cache_fresh "$INSTANCE_CONFIG_CACHE"; then
            _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE") cached)"
        else
            _step_active "instance configs"
            fetch_instance_configurations > /dev/null 2>&1
            _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
        fi
        _step_finish
        
        _ui_subheader "Instance Configurations" 0
        echo ""
        _ui_table_header "%-5s %-90s %-20s %s" "ID" "Name" "Created" "OCID"
        
        local ic_idx=0
        LOCAL_IC_INDEX_MAP=()
        
        if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
            # Read from cache (now includes time-created)
            while IFS='|' read -r ic_ocid ic_name ic_time_created; do
                [[ "$ic_ocid" =~ ^#.*$ ]] && continue
                [[ -z "$ic_ocid" ]] && continue
                
                ((ic_idx++))
                local cid="c${ic_idx}"
                LOCAL_IC_INDEX_MAP[$cid]="$ic_ocid"
                IC_INDEX_MAP[$cid]="$ic_ocid"
                # Keep i# alias for delete function compatibility
                IC_INDEX_MAP["i${ic_idx}"]="$ic_ocid"
                
                # Format time_created from cache
                local time_display="N/A"
                if [[ -n "$ic_time_created" && "$ic_time_created" != "N/A" ]]; then
                    time_display="${ic_time_created:0:16}"
                    time_display="${time_display/T/ }"
                fi
                
                printf "${YELLOW}%-5s${NC} ${WHITE}%-90s${NC} ${GRAY}%-20s${NC} ${YELLOW}%s${NC}\n" \
                    "$cid" "$ic_name" "$time_display" "$ic_ocid"
            done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
        fi
        
        if [[ $ic_idx -eq 0 ]]; then
            echo -e "  ${GRAY}No instance configurations found${NC}"
        fi
        
        echo ""
        echo -e "${GRAY}Total: ${ic_idx} instance configurations${NC}"
        echo ""
        
        _ui_actions
        echo -e "  ${CYAN}c#${NC}          - View instance configuration details and user-data (e.g., 'c1', 'c2')"
        echo -e "  ${GREEN}c${NC}           - Create a new Instance Configuration"
        echo -e "  ${YELLOW}re${NC}          - Rename an Instance Configuration (e.g., ${YELLOW}re c1${NC})"
        echo -e "  ${RED}d #${NC}         - Delete Instance Configuration (d 1, d 1,2,3, d 1-3, d all)"
        echo -e "  ${CYAN}comp${NC}        - Compare configs (e.g., ${CYAN}comp c1 c2${NC}) (alias: ${CYAN}diff${NC})"
        echo -e "  ${MAGENTA}ua${NC}          - Update GPU memory cluster instance configuration"
        echo -e "  ${MAGENTA}r${NC}           - Refresh data from OCI"
        echo -e "  ${CYAN}back${NC}        - Return to main menu"
        echo ""
        _ui_prompt "Instance Configs" "c#, c, re, re c#, d #, comp c# c#, ua, r, back, show"
        
        local input
        read -r input
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        
        # Empty input goes back
        if [[ -z "$input" ]]; then
            return
        fi
        
        case "$input" in
            c|C|create|CREATE)
                create_instance_configuration_interactive
                ;;
            re|RE|rename|RENAME)
                rename_instance_configuration_interactive
                ;;
            re\ *|RE\ *)
                local _re_id="${input#* }"
                _re_id="${_re_id,,}"  # lowercase
                [[ "$_re_id" != c* ]] && _re_id="c${_re_id}"
                local _re_ocid="${IC_INDEX_MAP[$_re_id]:-}"
                if [[ -n "$_re_ocid" ]]; then
                    local _re_name=""
                    _re_name=$(grep "^${_re_ocid}|" "$INSTANCE_CONFIG_CACHE" 2>/dev/null | cut -d'|' -f2)
                    rename_single_instance_configuration "$_re_ocid" "${_re_name:-Unknown}"
                else
                    echo -e "${RED}Invalid config ID: $_re_id${NC}"
                fi
                ;;
            d|D|delete|DELETE)
                delete_instance_configuration_interactive
                ;;
            d\ *|D\ *|delete\ *|DELETE\ *)
                local delete_args="${input#* }"
                delete_instance_configuration_interactive "$delete_args"
                ;;
            ua|UA|update-all|UPDATE-ALL)
                update_all_clusters_instance_config
                ;;
            comp|COMP|compare|COMPARE|diff|DIFF)
                compare_instance_configurations
                ;;
            comp\ *|COMP\ *)
                local _comp_args="${input#* }"
                # Parse c# c# format (e.g., "comp c1 c2" or "comp 1 2")
                local _comp_a _comp_b
                read -r _comp_a _comp_b <<< "$_comp_args"
                [[ "$_comp_a" != c* ]] && _comp_a="c${_comp_a}"
                [[ -n "$_comp_b" && "$_comp_b" != c* ]] && _comp_b="c${_comp_b}"
                local _comp_ocid_a="${IC_INDEX_MAP[${_comp_a}]:-}"
                local _comp_ocid_b="${IC_INDEX_MAP[${_comp_b:-}]:-}"
                if [[ -z "$_comp_ocid_a" ]]; then
                    echo -e "${RED}Invalid config ID: $_comp_a${NC}"
                elif [[ -n "$_comp_b" && -z "$_comp_ocid_b" ]]; then
                    echo -e "${RED}Invalid config ID: $_comp_b${NC}"
                elif [[ -n "$_comp_ocid_b" ]]; then
                    # Direct comparison of two configs
                    local _comp_name_a _comp_name_b
                    _comp_name_a=$(grep "^${_comp_ocid_a}|" "$INSTANCE_CONFIG_CACHE" 2>/dev/null | cut -d'|' -f2)
                    _comp_name_b=$(grep "^${_comp_ocid_b}|" "$INSTANCE_CONFIG_CACHE" 2>/dev/null | cut -d'|' -f2)
                    echo ""
                    _step_init
                    _step_active "configurations (2 parallel)"
                    local _comp_json_a="" _comp_json_b="" _comp_tmp_dir
                    _comp_tmp_dir=$(mktemp -d "${TEMP_DIR}/comp.XXXXXXXXXX")
                    oci compute-management instance-configuration get \
                        --instance-configuration-id "$_comp_ocid_a" --output json > "$_comp_tmp_dir/a.json" 2>/dev/null &
                    local _cp1=$!
                    oci compute-management instance-configuration get \
                        --instance-configuration-id "$_comp_ocid_b" --output json > "$_comp_tmp_dir/b.json" 2>/dev/null &
                    local _cp2=$!
                    wait "$_cp1" "$_cp2" 2>/dev/null
                    [[ -s "$_comp_tmp_dir/a.json" ]] && _comp_json_a=$(<"$_comp_tmp_dir/a.json")
                    [[ -s "$_comp_tmp_dir/b.json" ]] && _comp_json_b=$(<"$_comp_tmp_dir/b.json")
                    rm -rf "${_comp_tmp_dir:?}"
                    _step_complete "configurations"
                    _step_finish
                    if [[ -n "$_comp_json_a" && -n "$_comp_json_b" ]]; then
                        local _comp_launch_a _comp_launch_b
                        _comp_launch_a=$(jq '.data["instance-details"]["launch-details"]' <<< "$_comp_json_a")
                        _comp_launch_b=$(jq '.data["instance-details"]["launch-details"]' <<< "$_comp_json_b")
                        _do_field_comparison "$_comp_launch_a" "${_comp_name_a:-$_comp_a}" "$_comp_launch_b" "${_comp_name_b:-$_comp_b}"
                    else
                        echo -e "${RED}Failed to fetch one or both configurations${NC}"
                        _ui_policy_hint "read instance-configurations in compartment"
                    fi
                else
                    # Single config specified — open its detail view for comparison
                    view_instance_configuration_detail "$_comp_a"
                fi
                ;;
            r|R|refresh|REFRESH)
                echo -e "${YELLOW}Refreshing cache...${NC}"
                rm -f "$INSTANCE_CONFIG_CACHE"
                ;;
            quit|QUIT|q|Q|exit|EXIT|back|BACK|b|B)
                return
                ;;
            c[0-9]*)
                view_instance_configuration_detail "$input"
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Unknown command: $input${NC}"
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# View Instance Configuration Detail with user-data decoding
#--------------------------------------------------------------------------------
view_instance_configuration_detail() {
    local ic_id="$1"
    local ic_ocid="${IC_INDEX_MAP[$ic_id]:-}"
    local region="${FOCUS_REGION:-$REGION}"

    if [[ -z "$ic_ocid" ]]; then
        echo -e "${RED}Invalid instance config ID: $ic_id${NC}"
        return 1
    fi
    
    echo ""
    _ui_menu_header "INSTANCE CONFIGURATION DETAILS" \
        --color "$YELLOW" \
        --breadcrumb "Compute" "Instance Configs" "Details" \
        --cmd "oci compute-management instance-configuration get --instance-configuration-id ${ic_ocid} | oci compute image get | oci network subnet get" \
        --env
    
    # ── Cache setup ──
    mkdir -p "$IC_DETAIL_CACHE_DIR" 2>/dev/null
    local _ic_cache_key="${ic_ocid##*.}"
    local _ic_cache_json="${IC_DETAIL_CACHE_DIR}/${_ic_cache_key}.json"
    local _ic_cache_resolved="${IC_DETAIL_CACHE_DIR}/${_ic_cache_key}.resolved"

    # ── Discovery ──
    _step_init

    local ic_json="" img_name="" img_os="" subnet_name=""
    local pod_subnet_name="" worker_nsg_display="" pod_nsg_display=""
    local _ic_from_cache=false

    # Check if both cache files are fresh (within TTL)
    if is_cache_fresh "$_ic_cache_json" && [[ -s "$_ic_cache_resolved" ]]; then
        _ic_from_cache=true
        ic_json=$(<"$_ic_cache_json")
        # Read resolved names: img_name|img_os|subnet_name|pod_subnet_name|worker_nsg_display|pod_nsg_display
        IFS='|' read -r img_name img_os subnet_name pod_subnet_name worker_nsg_display pod_nsg_display < "$_ic_cache_resolved"
        _step_complete "configuration(cached)"
        _step_complete "names(cached)"
        _step_finish
    fi

    if [[ "$_ic_from_cache" == "false" ]]; then
        _step_active "configuration"
        ic_json=$(oci compute-management instance-configuration get \
            --instance-configuration-id "$ic_ocid" \
            --region "$region" \
            --output json 2>/dev/null)

        if [[ -z "$ic_json" ]]; then
            _step_complete "configuration(failed)"
            _step_finish
            echo -e "${RED}Failed to fetch instance configuration details${NC}"
            _ui_policy_hint "read instance-configurations in compartment"
            echo ""
            _ui_pause "return"
            return 1
        fi
        _step_complete "configuration"

        # Cache the raw config JSON
        echo "$ic_json" > "$_ic_cache_json"
    fi

    local ic_name ic_time_created ic_compartment
    ic_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$ic_json")
    ic_time_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$ic_json")
    ic_compartment=$(jq -r '.data["compartment-id"] // "N/A"' <<< "$ic_json")

    local shape ad boot_size boot_vpus image_id subnet_id
    shape=$(jq -r '.data["instance-details"]["launch-details"]["shape"] // "N/A"' <<< "$ic_json")
    ad=$(jq -r '.data["instance-details"]["launch-details"]["availability-domain"] // "N/A"' <<< "$ic_json")
    boot_size=$(jq -r '.data["instance-details"]["launch-details"]["source-details"] | (.["boot-volume-size-in-gbs"] // .bootVolumeSizeInGBs // .["bootVolumeSizeInGBs"] // "N/A")' <<< "$ic_json")
    boot_vpus=$(jq -r '.data["instance-details"]["launch-details"]["source-details"] | (.["boot-volume-vpus-per-gb"] // .bootVolumeVpusPerGB // .["bootVolumeVpusPerGB"] // "N/A")' <<< "$ic_json")
    image_id=$(jq -r '.data["instance-details"]["launch-details"]["source-details"]["image-id"] // .data["instance-details"]["launch-details"]["source-details"]["imageId"] // "N/A"' <<< "$ic_json")
    subnet_id=$(jq -r '.data["instance-details"]["launch-details"]["create-vnic-details"]["subnet-id"] // "N/A"' <<< "$ic_json")
    local max_pods
    max_pods=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["oke-max-pods"] // "N/A"' <<< "$ic_json")

    # Extract pod subnet, worker NSGs, pod NSGs from metadata + create-vnic-details
    local pod_subnet_id="" worker_nsg_ids="" pod_nsg_ids=""
    # Pod subnet: metadata first (OKE native), fallback to create-vnic-details
    pod_subnet_id=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["pod-subnets"] // empty' <<< "$ic_json" 2>/dev/null)
    [[ -z "$pod_subnet_id" ]] && pod_subnet_id=$(jq -r '.data["instance-details"]["launch-details"]["create-vnic-details"]["pod-subnet-id"] // empty' <<< "$ic_json" 2>/dev/null)
    # Worker NSGs: from create-vnic-details.nsg-ids array
    worker_nsg_ids=$(jq -r '(.data["instance-details"]["launch-details"]["create-vnic-details"]["nsg-ids"] // []) | join(",")' <<< "$ic_json" 2>/dev/null)
    # Pod NSGs: metadata first (OKE native), fallback to create-vnic-details
    pod_nsg_ids=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["pod-nsgids"] // empty' <<< "$ic_json" 2>/dev/null)
    [[ -z "$pod_nsg_ids" ]] && pod_nsg_ids=$(jq -r '(.data["instance-details"]["launch-details"]["create-vnic-details"]["pod-nsg-ids"] // []) | join(",")' <<< "$ic_json" 2>/dev/null)

    # Resolve image, subnet, pod subnet, worker NSGs, pod NSGs in parallel (skip if cached)
    if [[ "$_ic_from_cache" == "false" ]]; then
        local _tmp_img _tmp_sub _tmp_psub _tmp_wnsg _tmp_pnsg
        _tmp_img=$(create_temp_file); _tmp_sub=$(create_temp_file)
        _tmp_psub=$(create_temp_file); _tmp_wnsg=$(create_temp_file); _tmp_pnsg=$(create_temp_file)

        local _resolve_pids=() _resolve_count=0

        if [[ -n "$image_id" && "$image_id" != "N/A" ]]; then
            (
                local _j; _j=$(oci compute image get --image-id "$image_id" --region "$region" --output json 2>/dev/null)
                if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" > /dev/null 2>&1; then
                    jq -r '(.data["display-name"] // "") + "|" + (.data["operating-system"] // "")' <<< "$_j"
                fi
            ) > "$_tmp_img" &
            _resolve_pids+=($!); ((_resolve_count++))
        fi

        if [[ -n "$subnet_id" && "$subnet_id" != "N/A" ]]; then
            (
                local _j; _j=$(oci network subnet get --subnet-id "$subnet_id" --region "$region" --output json 2>/dev/null)
                if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" > /dev/null 2>&1; then
                    jq -r '.data["display-name"] // ""' <<< "$_j"
                fi
            ) > "$_tmp_sub" &
            _resolve_pids+=($!); ((_resolve_count++))
        fi

        if [[ -n "$pod_subnet_id" ]]; then
            (
                local _j; _j=$(oci network subnet get --subnet-id "$pod_subnet_id" --region "$region" --output json 2>/dev/null)
                if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" > /dev/null 2>&1; then
                    jq -r '.data["display-name"] // ""' <<< "$_j"
                fi
            ) > "$_tmp_psub" &
            _resolve_pids+=($!); ((_resolve_count++))
        fi

        if [[ -n "$worker_nsg_ids" ]]; then
            (
                local _result=""
                IFS=',' read -ra _nsg_arr <<< "$worker_nsg_ids"
                for _nid in "${_nsg_arr[@]}"; do
                    _nid="${_nid// /}"
                    [[ -z "$_nid" ]] && continue
                    local _j; _j=$(oci network nsg get --nsg-id "$_nid" --region "$region" --output json 2>/dev/null)
                    local _name=""
                    if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" > /dev/null 2>&1; then
                        _name=$(jq -r '.data["display-name"] // ""' <<< "$_j")
                    fi
                    [[ -n "$_result" ]] && _result+="|"
                    _result+="${_name}:${_nid}"
                done
                echo "$_result"
            ) > "$_tmp_wnsg" &
            _resolve_pids+=($!); ((_resolve_count++))
        fi

        if [[ -n "$pod_nsg_ids" ]]; then
            (
                local _result=""
                IFS=',' read -ra _nsg_arr <<< "$pod_nsg_ids"
                for _nid in "${_nsg_arr[@]}"; do
                    _nid="${_nid// /}"
                    [[ -z "$_nid" ]] && continue
                    local _j; _j=$(oci network nsg get --nsg-id "$_nid" --region "$region" --output json 2>/dev/null)
                    local _name=""
                    if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" > /dev/null 2>&1; then
                        _name=$(jq -r '.data["display-name"] // ""' <<< "$_j")
                    fi
                    [[ -n "$_result" ]] && _result+="|"
                    _result+="${_name}:${_nid}"
                done
                echo "$_result"
            ) > "$_tmp_pnsg" &
            _resolve_pids+=($!); ((_resolve_count++))
        fi

        _step_active "image+subnets+NSGs(${_resolve_count})"
        [[ ${#_resolve_pids[@]} -gt 0 ]] && wait "${_resolve_pids[@]}" 2>/dev/null

        # Collect results
        if [[ -s "$_tmp_img" ]]; then
            local _img_line; _img_line=$(<"$_tmp_img")
            img_name="${_img_line%%|*}"
            img_os="${_img_line#*|}"
        fi
        [[ -s "$_tmp_sub" ]] && subnet_name=$(<"$_tmp_sub")
        [[ -s "$_tmp_psub" ]] && pod_subnet_name=$(<"$_tmp_psub")
        [[ -s "$_tmp_wnsg" ]] && worker_nsg_display=$(<"$_tmp_wnsg")
        [[ -s "$_tmp_pnsg" ]] && pod_nsg_display=$(<"$_tmp_pnsg")

        rm -f "$_tmp_img" "$_tmp_sub" "$_tmp_psub" "$_tmp_wnsg" "$_tmp_pnsg"
        _step_complete "image+subnets+NSGs(${_resolve_count})"
        _step_finish

        # Cache resolved names (pipe-delimited, single line)
        echo "${img_name}|${img_os}|${subnet_name}|${pod_subnet_name}|${worker_nsg_display}|${pod_nsg_display}" > "$_ic_cache_resolved"
    fi
    
    echo ""
    echo -e "${WHITE}Name:${NC}         ${GREEN}$ic_name${NC}"
    echo -e "${WHITE}OCID:${NC}         ${YELLOW}$ic_ocid${NC}"
    echo -e "${WHITE}Time Created:${NC} $ic_time_created"
    echo -e "${WHITE}Compartment:${NC}  ${WHITE}$(resolve_compartment_name "$ic_compartment")${NC} ${GRAY}($ic_compartment)${NC}"
    
    # Show instance details from the configuration
    echo ""
    echo -e "${BOLD}${CYAN}Instance Details:${NC}"
    echo -e "  ${WHITE}Shape:${NC}              $shape"
    echo -e "  ${WHITE}Availability Domain:${NC} $ad"
    echo -e "  ${WHITE}Boot Volume Size:${NC}   ${boot_size} GB"
    echo -e "  ${WHITE}Boot Volume VPUs:${NC}   ${boot_vpus} VPUs/GB"
    echo -e "  ${WHITE}Max Pods:${NC}           $max_pods"
    
    if [[ -n "$image_id" && "$image_id" != "N/A" ]]; then
        if [[ -n "$img_name" ]]; then
            echo -e "  ${WHITE}Image Name:${NC}         ${WHITE}$img_name${NC}  ${YELLOW}[$image_id]${NC}"
        else
            echo -e "  ${WHITE}Image Name:${NC}         ${GRAY}N/A${NC}  ${YELLOW}[$image_id]${NC}"
        fi
        [[ -n "$img_os" && "$img_os" != "null" ]] && echo -e "  ${WHITE}Image OS:${NC}           ${WHITE}$img_os${NC}"
    else
        echo -e "  ${WHITE}Image:${NC}              ${GRAY}N/A${NC}"
    fi

    if [[ -n "$subnet_id" && "$subnet_id" != "N/A" ]]; then
        if [[ -n "$subnet_name" ]]; then
            echo -e "  ${WHITE}Subnet Name:${NC}        ${WHITE}$subnet_name${NC}  ${YELLOW}[$subnet_id]${NC}"
        else
            echo -e "  ${WHITE}Subnet Name:${NC}        ${GRAY}N/A${NC}  ${YELLOW}[$subnet_id]${NC}"
        fi
    else
        echo -e "  ${WHITE}Subnet:${NC}             ${GRAY}N/A${NC}"
    fi

    # Pod subnet display (resolved in parallel above)
    if [[ -n "$pod_subnet_id" ]]; then
        if [[ -n "$pod_subnet_name" ]]; then
            echo -e "  ${WHITE}Pod Subnet:${NC}         ${WHITE}$pod_subnet_name${NC}  ${YELLOW}[$pod_subnet_id]${NC}"
        else
            echo -e "  ${WHITE}Pod Subnet:${NC}         ${YELLOW}[$pod_subnet_id]${NC}"
        fi
    else
        echo -e "  ${WHITE}Pod Subnet:${NC}         ${GRAY}Not configured${NC}"
    fi

    # Worker NSGs display (resolved in parallel above)
    if [[ -n "$worker_nsg_display" ]]; then
        IFS='|' read -ra _wnsg_entries <<< "$worker_nsg_display"
        for _entry in "${_wnsg_entries[@]}"; do
            local _wname="${_entry%%:*}" _wid="${_entry#*:}"
            if [[ -n "$_wname" ]]; then
                echo -e "  ${WHITE}Worker NSGs:${NC}        ${WHITE}${_wname}${NC}  ${YELLOW}[${_wid}]${NC}"
            else
                echo -e "  ${WHITE}Worker NSGs:${NC}        ${YELLOW}[${_wid}]${NC}"
            fi
        done
    else
        echo -e "  ${WHITE}Worker NSGs:${NC}        ${GRAY}Not configured${NC}"
    fi

    # Pod NSGs display (resolved in parallel above)
    if [[ -n "$pod_nsg_display" ]]; then
        IFS='|' read -ra _pnsg_entries <<< "$pod_nsg_display"
        for _entry in "${_pnsg_entries[@]}"; do
            local _pname="${_entry%%:*}" _pid="${_entry#*:}"
            if [[ -n "$_pname" ]]; then
                echo -e "  ${WHITE}Pod NSGs:${NC}           ${WHITE}${_pname}${NC}  ${YELLOW}[${_pid}]${NC}"
            else
                echo -e "  ${WHITE}Pod NSGs:${NC}           ${YELLOW}[${_pid}]${NC}"
            fi
        done
    else
        echo -e "  ${WHITE}Pod NSGs:${NC}           ${GRAY}Not configured${NC}"
    fi
    
    # Check for user_data
    local user_data_b64
    user_data_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic_json" 2>/dev/null)
    
    local has_user_data="false"
    [[ -n "$user_data_b64" ]] && has_user_data="true"
    
    # Check for SSH keys
    local ssh_keys
    ssh_keys=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["ssh_authorized_keys"] // empty' <<< "$ic_json" 2>/dev/null)
    
    if [[ -n "$ssh_keys" ]]; then
        echo ""
        echo -e "${BOLD}${CYAN}SSH Keys:${NC}"
        echo -e "  ${GREEN}✓ SSH authorized keys are configured${NC}"
    fi
    
    if [[ "$has_user_data" == "true" ]]; then
        echo ""
        echo -e "${BOLD}${CYAN}User Data:${NC}"
        echo -e "  ${GREEN}✓ Cloud-init user-data is configured ($(echo "$user_data_b64" | wc -c) bytes encoded)${NC}"
    fi
    
    # Show actions
    echo ""
    _ui_actions
    if [[ "$has_user_data" == "true" ]]; then
        echo -e "  ${MAGENTA}v${NC}           - View decoded cloud-init user-data"
        echo -e "  ${MAGENTA}s${NC}           - Save user-data to file"
        echo -e "  ${CYAN}comp${NC}        - Compare vs another config, instance, or local file"
    fi
    echo -e "  ${GREEN}j${NC}           - View JSON ${GRAY}| j <key> Search JSON${NC}"
    echo -e "  ${YELLOW}re${NC}          - Rename this instance configuration"
    echo -e "  ${RED}d${NC}           - Delete this instance configuration"
    echo -e "  ${MAGENTA}r${NC}           - Refresh (clear cache)"
    echo -e "  ${CYAN}Enter${NC}       - Return to list"
    echo ""
    _ui_prompt "IC - ${ic_name}" "v, s, comp, j, j <key>, re, d, r, Enter"
    
    local action
    read -r action
    [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return
    
    case "$action" in
        view|VIEW|v|V)
            if [[ "$has_user_data" == "true" ]]; then
                echo ""
                _ui_menu_header "DECODED CLOUD-INIT USER-DATA"
                echo ""

                # Check if gzip compressed and decompress
                if is_user_data_gzip "$user_data_b64"; then
                    echo -e "${GRAY}(gzip compressed - decompressing)${NC}"
                    echo ""
                fi
                decode_user_data "$user_data_b64"

                echo ""
                _ui_content_border
                echo ""
                _ui_pause
            else
                echo -e "${YELLOW}No user-data found${NC}"
            fi
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        save|SAVE|s|S)
            if [[ "$has_user_data" == "true" ]]; then
                local safe_name
                safe_name=$(echo "$ic_name" | tr ' ' '_' | tr -cd '[:alnum:]_-')
                local filename="${safe_name}_cloud-init.yml"

                echo ""
                echo -n -e "${CYAN}Save as [${filename}]: ${NC}"
                local custom_filename
                read -r custom_filename
                [[ -n "$custom_filename" ]] && filename="$custom_filename"

                local gzip_msg=""
                if is_user_data_gzip "$user_data_b64"; then
                    gzip_msg=" ${GRAY}(decompressed from gzip)${NC}"
                fi

                if decode_user_data_to_file "$user_data_b64" "$filename"; then
                    echo -e "${GREEN}✓ User-data saved to: ${WHITE}$(pwd)/${filename}${NC}${gzip_msg}"
                else
                    echo -e "${RED}Failed to save user-data${NC}"
                fi
                echo ""
                _ui_pause
            else
                echo -e "${YELLOW}No user-data found${NC}"
            fi
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        re|RE|rename|RENAME)
            rename_single_instance_configuration "$ic_ocid" "$ic_name" "$ic_json"
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        json|JSON|j|J)
            _ui_json_viewer "Instance Configuration JSON" "$ic_json" ".data"
            # Offer to save
            local safe_json_name
            safe_json_name=$(echo "$ic_name" | tr ' ' '_' | tr -cd '[:alnum:]_-')
            local json_filename="${safe_json_name}.json"
            echo -n -e "${CYAN}Save to file? [y/N]: ${NC}"
            local save_json
            read -r save_json
            if [[ "$save_json" == "y" || "$save_json" == "Y" ]]; then
                echo -n -e "${CYAN}Save as [${json_filename}]: ${NC}"
                local custom_json_name
                read -r custom_json_name
                [[ -n "$custom_json_name" ]] && json_filename="$custom_json_name"
                if jq '.' <<< "$ic_json" > "$json_filename" 2>/dev/null; then
                    echo -e "${GREEN}✓ JSON saved to: ${WHITE}$(pwd)/${json_filename}${NC}"
                else
                    echo -e "${RED}Failed to save JSON${NC}"
                fi
            fi
            echo ""
            _ui_pause
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        json\ *|JSON\ *|j\ *|J\ *)
            _ui_json_viewer "Instance Configuration JSON" "$ic_json" ".data" "${action#* }"
            echo ""
            _ui_pause
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        delete|DELETE|d|D)
            delete_single_instance_configuration "$ic_ocid" "$ic_name"
            ;;
        comp|COMP|compare|COMPARE|diff|DIFF)
            _ui_menu_header "COMPARE: ${ic_name}" --color "$MAGENTA"
            echo ""
            echo -e "${WHITE}Compare this config against:${NC}"
            echo -e "  ${YELLOW}1${NC}) Another Instance Configuration  ${GRAY}(full field + cloud-init comparison)${NC}"
            echo -e "  ${YELLOW}2${NC}) A Running Instance               ${GRAY}(full field + cloud-init comparison)${NC}"
            if [[ "$has_user_data" == "true" ]]; then
                echo -e "  ${YELLOW}3${NC}) A Local File                     ${GRAY}(cloud-init diff only)${NC}"
            fi
            echo -e "  ${CYAN}q${NC}) Cancel"
            echo ""
            echo -n -e "${CYAN}Select mode [1/2/3/q]: ${NC}"
            local comp_mode
            read -r comp_mode
            
            case "$comp_mode" in
                1)
                    # vs another IC - use full comparison
                    fetch_instance_configurations > /dev/null 2>&1
                    
                    if [[ ! -f "$INSTANCE_CONFIG_CACHE" ]]; then
                        echo -e "${RED}No instance configurations found${NC}"
                    else
                        local cmp_idx=0
                        declare -A CMP_IC_MAP=()
                        
                        echo ""
                        _ui_table_header "%-4s %-60s" "#" "Name"
                        
                        while IFS='|' read -r cmp_ocid cmp_name _; do
                            [[ "$cmp_ocid" =~ ^#.*$ ]] && continue
                            [[ -z "$cmp_ocid" ]] && continue
                            [[ "$cmp_ocid" == "$ic_ocid" ]] && continue  # Skip current
                            
                            ((cmp_idx++))
                            CMP_IC_MAP[$cmp_idx]="$cmp_ocid|$cmp_name"
                            printf "${YELLOW}%-4s${NC} ${WHITE}%-60s${NC}\n" "$cmp_idx" "$cmp_name"
                        done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
                        
                        if [[ $cmp_idx -eq 0 ]]; then
                            echo -e "${GRAY}No other instance configurations to compare against${NC}"
                        else
                            echo ""
                            echo -n -e "${CYAN}Select configuration (1-${cmp_idx}): ${NC}"
                            local cmp_choice
                            read -r cmp_choice
                            
                            if [[ -n "${CMP_IC_MAP[$cmp_choice]:-}" ]]; then
                                local cmp_ocid2 cmp_name2
                                IFS='|' read -r cmp_ocid2 cmp_name2 <<< "${CMP_IC_MAP[$cmp_choice]}"
                                
                                echo ""
                                _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${cmp_ocid2}"
                                _step_init
                                _step_active "configuration"
                                
                                local cmp_json2
                                cmp_json2=$(oci compute-management instance-configuration get \
                                    --instance-configuration-id "$cmp_ocid2" \
                                    --output json 2>/dev/null)
                                _step_complete "configuration"
                                _step_finish
                                
                                if [[ -n "$cmp_json2" ]] && jq -e '.data' <<< "$cmp_json2" > /dev/null 2>&1; then
                                    local cmp_launch1 cmp_launch2
                                    cmp_launch1=$(jq '.data["instance-details"]["launch-details"]' <<< "$ic_json")
                                    cmp_launch2=$(jq '.data["instance-details"]["launch-details"]' <<< "$cmp_json2")
                                    _do_field_comparison "$cmp_launch1" "$ic_name" "$cmp_launch2" "$cmp_name2"
                                else
                                    echo -e "${RED}Failed to fetch configuration${NC}"
                                    _ui_policy_hint "read instance-configurations in compartment"
                                fi
                            else
                                echo -e "${RED}Invalid selection${NC}"
                            fi
                        fi
                    fi
                    ;;
                2)
                    # vs Running Instance
                    _compare_ic_vs_instance "$ic_json" "$ic_name"
                    ;;
                3)
                    if [[ "$has_user_data" != "true" ]]; then
                        echo -e "${YELLOW}No user-data in this configuration${NC}"
                    else
                        # vs Local File - cloud-init diff only
                        echo ""
                        local cmp_ci_files=()
                        local cmp_ci_idx=0
                        while IFS= read -r -d '' cmp_ci_file; do
                            ((cmp_ci_idx++))
                            cmp_ci_files[$cmp_ci_idx]="$cmp_ci_file"
                        done < <(find . -maxdepth 1 \( -name 'cloud-init*.yml' -o -name 'cloud-init*.yaml' \) -print0 2>/dev/null | sort -z)
                        
                        local cmp_local_file=""
                        if [[ $cmp_ci_idx -gt 0 ]]; then
                            _ui_subheader "Cloud-init Files in Current Directory" 0
                            for ((cfi=1; cfi<=cmp_ci_idx; cfi++)); do
                                printf "  ${YELLOW}%-3s${NC} %s\n" "$cfi" "${cmp_ci_files[$cfi]}"
                            done
                            echo ""
                            echo -n -e "${CYAN}Select file # or enter path manually: ${NC}"
                            local cmp_file_choice
                            read -r cmp_file_choice
                            
                            if [[ "$cmp_file_choice" =~ ^[0-9]+$ ]] && [[ -n "${cmp_ci_files[$cmp_file_choice]:-}" ]]; then
                                cmp_local_file="${cmp_ci_files[$cmp_file_choice]}"
                            else
                                cmp_local_file="$cmp_file_choice"
                            fi
                        else
                            echo -n -e "${CYAN}Enter path to local cloud-init file: ${NC}"
                            read -r cmp_local_file
                        fi
                        
                        # Expand ~ to home directory
                        cmp_local_file="${cmp_local_file/#\~/$HOME}"
                        
                        if [[ -z "$cmp_local_file" ]]; then
                            echo -e "${YELLOW}No file specified${NC}"
                        elif [[ ! -f "$cmp_local_file" ]]; then
                            echo -e "${RED}File not found: $cmp_local_file${NC}"
                        else
                            local cmp_tmp_cfg
                            cmp_tmp_cfg=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
                            decode_user_data_to_file "$user_data_b64" "$cmp_tmp_cfg" || echo "# Failed to decode" > "$cmp_tmp_cfg"
                            _display_cloudinit_diff "$cmp_tmp_cfg" "$ic_name" "$cmp_local_file" "$(basename "$cmp_local_file")"
                            rm -f "$cmp_tmp_cfg"
                        fi
                    fi
                    ;;
                *)
                    ;;
            esac
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        r|R|refresh|REFRESH)
            # Clear this config's cache and re-display
            rm -f "$_ic_cache_json" "$_ic_cache_resolved" 2>/dev/null
            echo -e "${YELLOW}Cache cleared, refreshing...${NC}"
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        show|SHOW)
            view_instance_configuration_detail "$ic_id"
            return
            ;;
        *)
            # Return to menu
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Build a launch-details-like JSON from a running instance
# This normalizes instance data so _do_field_comparison can work on it
# Args: $1=instance_ocid
# Returns: JSON on stdout matching IC launch-details structure
#--------------------------------------------------------------------------------
_build_launch_json_from_instance() {
    local inst_ocid="$1"
    local output_file="$2"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    # ── Discovery ──
    _step_init
    
    # Fetch instance details
    _step_active "instance"
    local inst_json
    inst_json=$(oci compute instance get \
        --instance-id "$inst_ocid" \
        --region "$region" \
        --output json 2>/dev/null)

    if [[ -z "$inst_json" ]] || ! jq -e '.data' <<< "$inst_json" > /dev/null 2>&1; then
        _step_complete "instance(failed)"
        _step_finish
        echo "{}" > "$output_file"
        return 1
    fi
    _step_complete "instance"
    
    # Extract base fields
    local shape ad image_id metadata agent_config shape_config
    shape=$(jq -r '.data.shape // "N/A"' <<< "$inst_json")
    ad=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$inst_json")
    image_id=$(jq -r '.data["image-id"] // "N/A"' <<< "$inst_json")
    metadata=$(jq '.data.metadata // {}' <<< "$inst_json")
    agent_config=$(jq '.data["agent-config"] // {}' <<< "$inst_json")
    shape_config=$(jq '.data["shape-config"] // {}' <<< "$inst_json")
    
    # Fetch boot volume attachment → boot volume details
    _step_active "boot volume"
    local bv_att_json bv_id bv_size bv_vpus
    bv_att_json=$(oci compute boot-volume-attachment list \
        --compartment-id "$compartment_id" \
        --instance-id "$inst_ocid" \
        --availability-domain "$ad" \
        --region "$region" \
        --output json 2>/dev/null)
    
    bv_id=$(jq -r '.data[0]["boot-volume-id"] // empty' <<< "$bv_att_json" 2>/dev/null)
    bv_size="N/A"
    bv_vpus="N/A"
    
    if [[ -n "$bv_id" ]]; then
        local bv_json
        bv_json=$(oci bv boot-volume get \
            --boot-volume-id "$bv_id" \
            --region "$region" \
            --output json 2>/dev/null)
        bv_size=$(jq -r '.data["size-in-gbs"] // "N/A"' <<< "$bv_json" 2>/dev/null)
        bv_vpus=$(jq -r '.data["vpus-per-gb"] // "N/A"' <<< "$bv_json" 2>/dev/null)
    fi
    _step_complete "boot volume"
    
    # Fetch primary VNIC → subnet, NSGs
    _step_active "networking"
    local vnic_att_json vnic_id subnet_id nsg_ids
    vnic_att_json=$(oci compute vnic-attachment list \
        --compartment-id "$compartment_id" \
        --instance-id "$inst_ocid" \
        --region "$region" \
        --output json 2>/dev/null)
    
    vnic_id=$(jq -r '.data[0]["vnic-id"] // empty' <<< "$vnic_att_json" 2>/dev/null)
    subnet_id="N/A"
    nsg_ids="[]"
    
    if [[ -n "$vnic_id" ]]; then
        local vnic_json
        vnic_json=$(oci network vnic get \
            --vnic-id "$vnic_id" \
            --region "$region" \
            --output json 2>/dev/null)
        subnet_id=$(jq -r '.data["subnet-id"] // "N/A"' <<< "$vnic_json" 2>/dev/null)
        nsg_ids=$(jq '.data["nsg-ids"] // []' <<< "$vnic_json" 2>/dev/null)
    fi
    _step_complete "networking"
    _step_finish
    
    # Build launch-details-compatible JSON
    jq -n \
        --arg shape "$shape" \
        --arg ad "$ad" \
        --arg image_id "$image_id" \
        --arg bv_size "$bv_size" \
        --arg bv_vpus "$bv_vpus" \
        --arg subnet_id "$subnet_id" \
        --argjson nsg_ids "$nsg_ids" \
        --argjson metadata "$metadata" \
        --argjson agent_config "$agent_config" \
        --argjson shape_config "$shape_config" \
        '{
            "shape": $shape,
            "shape-config": $shape_config,
            "availability-domain": $ad,
            "source-details": {
                "image-id": $image_id,
                "boot-volume-size-in-gbs": $bv_size,
                "boot-volume-vpus-per-gb": $bv_vpus
            },
            "create-vnic-details": {
                "subnet-id": $subnet_id,
                "nsg-ids": $nsg_ids
            },
            "metadata": $metadata,
            "agent-config": $agent_config
        }' > "$output_file"
}

#--------------------------------------------------------------------------------
# Field-by-field comparison of two launch-details-like JSON objects
# Args: $1=json_a, $2=name_a, $3=json_b, $4=name_b
# Works for IC vs IC, IC vs Instance, etc.
#--------------------------------------------------------------------------------
_do_field_comparison() {
    local launch1="$1"
    local name1="$2"
    local launch2="$3"
    local name2="$4"
    
    echo ""
    _ui_menu_header "CONFIGURATION COMPARISON"
    echo ""
    echo -e "${BOLD}Comparing:${NC}"
    echo -e "  ${GREEN}A:${NC} $name1"
    echo -e "  ${BLUE}B:${NC} $name2"
    
    local has_diff=false
    
    # Shape
    local shape1 shape2
    shape1=$(jq -r '.shape // "N/A"' <<< "$launch1")
    shape2=$(jq -r '.shape // "N/A"' <<< "$launch2")
    _ui_compare_field "Shape" "$shape1" "$name1" "$shape2" "$name2" || has_diff=true
    
    # Shape Config (OCPUs + Memory)
    local sc1_ocpus sc1_mem sc2_ocpus sc2_mem
    sc1_ocpus=$(jq -r '.["shape-config"].ocpus // empty' <<< "$launch1")
    sc1_mem=$(jq -r '.["shape-config"]["memory-in-gbs"] // empty' <<< "$launch1")
    sc2_ocpus=$(jq -r '.["shape-config"].ocpus // empty' <<< "$launch2")
    sc2_mem=$(jq -r '.["shape-config"]["memory-in-gbs"] // empty' <<< "$launch2")
    
    if [[ -n "$sc1_ocpus" || -n "$sc2_ocpus" ]]; then
        _ui_compare_field "Shape Config (OCPUs)" "${sc1_ocpus:-N/A}" "$name1" "${sc2_ocpus:-N/A}" "$name2" || has_diff=true
        _ui_compare_field "Shape Config (Memory GB)" "${sc1_mem:-N/A}" "$name1" "${sc2_mem:-N/A}" "$name2" || has_diff=true
    fi
    
    # Availability Domain
    local ad1 ad2
    ad1=$(jq -r '.["availability-domain"] // "N/A"' <<< "$launch1")
    ad2=$(jq -r '.["availability-domain"] // "N/A"' <<< "$launch2")
    _ui_compare_field "Availability Domain" "$ad1" "$name1" "$ad2" "$name2" || has_diff=true
    
    # Boot Volume Size
    local bvsize1 bvsize2
    bvsize1=$(jq -r '.["source-details"]["boot-volume-size-in-gbs"] // .["source-details"].bootVolumeSizeInGBs // "N/A"' <<< "$launch1")
    bvsize2=$(jq -r '.["source-details"]["boot-volume-size-in-gbs"] // .["source-details"].bootVolumeSizeInGBs // "N/A"' <<< "$launch2")
    _ui_compare_field "Boot Volume Size (GB)" "$bvsize1" "$name1" "$bvsize2" "$name2" || has_diff=true
    
    # Boot Volume VPUs
    local bvvpus1 bvvpus2
    bvvpus1=$(jq -r '.["source-details"]["boot-volume-vpus-per-gb"] // .["source-details"].bootVolumeVpusPerGB // "N/A"' <<< "$launch1")
    bvvpus2=$(jq -r '.["source-details"]["boot-volume-vpus-per-gb"] // .["source-details"].bootVolumeVpusPerGB // "N/A"' <<< "$launch2")
    _ui_compare_field "Boot Volume VPUs/GB" "$bvvpus1" "$name1" "$bvvpus2" "$name2" || has_diff=true
    
    # Image ID - show full OCID with name
    local img1 img2
    img1=$(jq -r '.["source-details"]["image-id"] // .["source-details"].imageId // "N/A"' <<< "$launch1")
    img2=$(jq -r '.["source-details"]["image-id"] // .["source-details"].imageId // "N/A"' <<< "$launch2")
    
    # Fetch image names (using cache)
    local img1_name="(fetching...)" img2_name="(fetching...)"
    if [[ -n "$img1" && "$img1" != "N/A" ]]; then
        img1_name=$(resolve_image_name_cached "$img1")
    fi
    if [[ -n "$img2" && "$img2" != "N/A" ]]; then
        img2_name=$(resolve_image_name_cached "$img2")
    fi
    echo ""
    _ui_subheader "Image" 0
    if [[ "$img1" == "$img2" ]]; then
        echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}$img1_name${NC} (${YELLOW}$img1${NC})"
    else
        echo -e "  ${RED}✗ Different:${NC}"
        echo -e "    ${GREEN}$name1:${NC} ${WHITE}$img1_name${NC}"
        echo -e "      ${YELLOW}$img1${NC}"
        echo -e "    ${BLUE}$name2:${NC} ${WHITE}$img2_name${NC}"
        echo -e "      ${YELLOW}$img2${NC}"
        has_diff=true
    fi
    
    # Subnet ID - show full OCID with name
    local subnet1 subnet2 subnet1_name subnet2_name
    subnet1=$(jq -r '.["create-vnic-details"]["subnet-id"] // "N/A"' <<< "$launch1")
    subnet2=$(jq -r '.["create-vnic-details"]["subnet-id"] // "N/A"' <<< "$launch2")
    subnet1_name=""
    subnet2_name=""
    [[ -n "$subnet1" && "$subnet1" != "N/A" ]] && subnet1_name=$(resolve_subnet_name_cached "$subnet1")
    [[ -n "$subnet2" && "$subnet2" != "N/A" ]] && subnet2_name=$(resolve_subnet_name_cached "$subnet2")
    echo ""
    _ui_subheader "Subnet" 0
    if [[ "$subnet1" == "$subnet2" ]]; then
        echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}${subnet1_name:-N/A}${NC} (${YELLOW}$subnet1${NC})"
    else
        echo -e "  ${RED}✗ Different:${NC}"
        echo -e "    ${GREEN}$name1:${NC} ${WHITE}${subnet1_name:-N/A}${NC} (${YELLOW}$subnet1${NC})"
        echo -e "    ${BLUE}$name2:${NC} ${WHITE}${subnet2_name:-N/A}${NC} (${YELLOW}$subnet2${NC})"
        has_diff=true
    fi
    
    # NSG IDs
    local nsg1 nsg2
    nsg1=$(jq -r '.["create-vnic-details"]["nsg-ids"] // []' <<< "$launch1" | jq -r '.[]' 2>/dev/null | sort )
    nsg2=$(jq -r '.["create-vnic-details"]["nsg-ids"] // []' <<< "$launch2" | jq -r '.[]' 2>/dev/null | sort )
    echo ""
    _ui_subheader "NSG IDs" 0
    if [[ "$nsg1" == "$nsg2" ]]; then
        if [[ -n "$nsg1" ]]; then
            echo -e "  ${GREEN}✓ Same:${NC}"
            echo "$nsg1" | while read -r nsg; do echo -e "    $nsg"; done
        else
            echo -e "  ${GREEN}✓ Same:${NC} (none)"
        fi
    else
        echo -e "  ${RED}✗ Different:${NC}"
        echo -e "    ${GREEN}$name1:${NC}"
        if [[ -n "$nsg1" ]]; then
            echo "$nsg1" | while read -r nsg; do echo -e "      $nsg"; done
        else
            echo -e "      (none)"
        fi
        echo -e "    ${BLUE}$name2:${NC}"
        if [[ -n "$nsg2" ]]; then
            echo "$nsg2" | while read -r nsg; do echo -e "      $nsg"; done
        else
            echo -e "      (none)"
        fi
        has_diff=true
    fi
    
    # Agent Config comparison
    echo ""
    _ui_subheader "Agent Config" 0
    local agent1 agent2
    agent1=$(jq -c '.["agent-config"]["plugins-config"] // []' <<< "$launch1" 2>/dev/null | jq -c 'sort_by(.name)' 2>/dev/null )
    agent2=$(jq -c '.["agent-config"]["plugins-config"] // []' <<< "$launch2" 2>/dev/null | jq -c 'sort_by(.name)' 2>/dev/null )
    
    if [[ "$agent1" == "$agent2" ]]; then
        echo -e "  ${GREEN}✓ Same agent plugin configuration${NC}"
    else
        echo -e "  ${RED}✗ Different agent plugin configuration:${NC}"
        local all_plugins
        all_plugins=$(echo -e "${agent1}\n${agent2}" | jq -r '.[].name' 2>/dev/null | sort -u)
        while read -r plugin; do
            [[ -z "$plugin" ]] && continue
            local state1 state2
            state1=$(jq -r --arg p "$plugin" '.[] | select(.name == $p) | .["desired-state"] // "(not set)"' <<< "$agent1" 2>/dev/null)
            state2=$(jq -r --arg p "$plugin" '.[] | select(.name == $p) | .["desired-state"] // "(not set)"' <<< "$agent2" 2>/dev/null)
            [[ -z "$state1" ]] && state1="(not set)"
            [[ -z "$state2" ]] && state2="(not set)"
            if [[ "$state1" == "$state2" ]]; then
                echo -e "    ${GREEN}✓${NC} ${WHITE}$plugin:${NC} $state1"
            else
                echo -e "    ${RED}✗${NC} ${WHITE}$plugin:${NC}"
                echo -e "        ${GREEN}$name1:${NC} $state1"
                echo -e "        ${BLUE}$name2:${NC} $state2"
            fi
        done <<< "$all_plugins"
        has_diff=true
    fi
    
    # Metadata fields (excluding user_data)
    echo ""
    _ui_subheader "Metadata Fields" 0
    local meta1_keys meta2_keys
    meta1_keys=$(jq -r '.metadata // {} | keys[]' <<< "$launch1" 2>/dev/null | grep -v '^user_data$' | sort )
    meta2_keys=$(jq -r '.metadata // {} | keys[]' <<< "$launch2" 2>/dev/null | grep -v '^user_data$' | sort )
    
    local all_meta_keys
    all_meta_keys=$(echo -e "${meta1_keys}\n${meta2_keys}" | sort -u | grep -v '^$')
    
    if [[ -z "$all_meta_keys" ]]; then
        echo -e "  ${GRAY}(no metadata fields other than user_data)${NC}"
    else
        while read -r key; do
            [[ -z "$key" ]] && continue
            local val1 val2
            val1=$(jq -r ".metadata[\"$key\"] // \"(not set)\"" <<< "$launch1")
            val2=$(jq -r ".metadata[\"$key\"] // \"(not set)\"" <<< "$launch2")
            
            if [[ "$val1" == "$val2" ]]; then
                echo -e "  ${GREEN}✓${NC} ${WHITE}$key:${NC} $val1"
            else
                echo -e "  ${RED}✗${NC} ${WHITE}$key:${NC}"
                echo -e "      ${GREEN}$name1:${NC} $val1"
                echo -e "      ${BLUE}$name2:${NC} $val2"
                has_diff=true
            fi
        done <<< "$all_meta_keys"
    fi
    
    # Cloud-init user-data comparison
    echo ""
    _ui_menu_header "CLOUD-INIT USER-DATA COMPARISON"
    echo ""
    _ui_legend
    echo -e "  ${RED}- Lines only in:${NC} ${GREEN}$name1${NC}"
    echo -e "  ${GREEN}+ Lines only in:${NC} ${BLUE}$name2${NC}"
    echo ""
    
    local ud1 ud2
    ud1=$(jq -r '.metadata.user_data // empty' <<< "$launch1")
    ud2=$(jq -r '.metadata.user_data // empty' <<< "$launch2")
    
    # Create temp files for diff
    local tmp1 tmp2
    tmp1=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    tmp2=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    if [[ -n "$ud1" ]]; then
        decode_user_data_to_file "$ud1" "$tmp1" || echo "# Failed to decode user_data" > "$tmp1"
    else
        echo "# No user_data" > "$tmp1"
    fi
    
    if [[ -n "$ud2" ]]; then
        decode_user_data_to_file "$ud2" "$tmp2" || echo "# Failed to decode user_data" > "$tmp2"
    else
        echo "# No user_data" > "$tmp2"
    fi
    
    local lines1 lines2
    lines1=$(wc -l < "$tmp1" 2>/dev/null || echo "0")
    lines2=$(wc -l < "$tmp2" 2>/dev/null || echo "0")
    echo -e "${GRAY}  A: ${lines1} lines  |  B: ${lines2} lines${NC}"
    echo ""
    
    if diff -q "$tmp1" "$tmp2" > /dev/null 2>&1; then
        echo -e "${GREEN}✓ Cloud-init user-data is identical${NC}"
    else
        echo -e "${RED}✗ Cloud-init user-data is DIFFERENT${NC}"
        echo ""
        
        local added removed
        added=$(diff -u "$tmp1" "$tmp2" 2>/dev/null | grep -c '^+[^+]' || true)
        removed=$(diff -u "$tmp1" "$tmp2" 2>/dev/null | grep -c '^-[^-]' || true)
        echo -e "${GRAY}  Changes: ${RED}-${removed} lines removed${NC}  ${GREEN}+${added} lines added${NC}"
        echo ""
        
        _ui_subheader "Differences Found" 0
        echo ""
        
        local diff_output
        diff_output=$(diff -u "$tmp1" "$tmp2" 2>/dev/null | tail -n +4)
        
        local in_change=false
        while IFS= read -r line; do
            if [[ "$line" =~ ^@@ ]]; then
                echo ""
                printf '%b%s%b\n' "${YELLOW}" "$line" "${NC}"
                in_change=true
            elif [[ "$line" =~ ^- ]]; then
                printf '%b%s%b\n' "${RED}" "$line" "${NC}"
            elif [[ "$line" =~ ^\+ ]]; then
                printf '%b%s%b\n' "${GREEN}" "$line" "${NC}"
            elif [[ "$line" =~ ^[[:space:]] ]] && [[ "$in_change" == "true" ]]; then
                printf '%b%s%b\n' "${GRAY}" "$line" "${NC}"
            fi
        done <<< "$diff_output"
        
        has_diff=true
    fi
    
    # Summary
    echo ""
    _ui_content_border
    if [[ "$has_diff" == "true" ]]; then
        echo -e "${RED}✗ Configurations have differences${NC}"
    else
        echo -e "${GREEN}✓ Configurations are identical${NC}"
    fi
    _ui_content_border
    
    # Post-compare actions menu
    echo ""
    _ui_subheader "Post-Compare Actions" 0
    echo -e "  ${YELLOW}view-a${NC}   - View full cloud-init for: ${GREEN}$name1${NC}"
    echo -e "  ${YELLOW}view-b${NC}   - View full cloud-init for: ${BLUE}$name2${NC}"
    echo -e "  ${GREEN}save-a${NC}   - Save cloud-init A to file"
    echo -e "  ${GREEN}save-b${NC}   - Save cloud-init B to file"
    echo -e "  ${CYAN}save${NC}     - Save both cloud-init files"
    echo -e "  ${WHITE}Enter${NC}    - Return"
    echo ""
    
    while true; do
        echo -n -e "${CYAN}Action [Enter to return]: ${NC}"
        local post_action
        read -r post_action
        
        case "$post_action" in
            view-a|VIEW-A)
                echo ""
                _ui_subheader "Cloud-Init: $name1 (${lines1} lines)" 0
                print_separator 120 "$GRAY"
                nl -ba "$tmp1"
                print_separator 120 "$GRAY"
                echo ""
                ;;
            view-b|VIEW-B)
                echo ""
                _ui_subheader "Cloud-Init: $name2 (${lines2} lines)" 0
                print_separator 120 "$GRAY"
                nl -ba "$tmp2"
                print_separator 120 "$GRAY"
                echo ""
                ;;
            save-a|SAVE-A)
                local safe_name1
                safe_name1=$(echo "$name1" | tr ' /()' '_---')
                local save_file1="cloud-init-${safe_name1}-$(date +%Y%m%d_%H%M%S).yml"
                cp "$tmp1" "$save_file1"
                echo -e "${GREEN}✓ Saved: ${WHITE}${save_file1}${NC}"
                ;;
            save-b|SAVE-B)
                local safe_name2
                safe_name2=$(echo "$name2" | tr ' /()' '_---')
                local save_file2="cloud-init-${safe_name2}-$(date +%Y%m%d_%H%M%S).yml"
                cp "$tmp2" "$save_file2"
                echo -e "${GREEN}✓ Saved: ${WHITE}${save_file2}${NC}"
                ;;
            save|SAVE)
                local timestamp_save
                timestamp_save=$(date +%Y%m%d_%H%M%S)
                local safe_n1 safe_n2
                safe_n1=$(echo "$name1" | tr ' /()' '_---')
                safe_n2=$(echo "$name2" | tr ' /()' '_---')
                local sf1="cloud-init-${safe_n1}-${timestamp_save}.yml"
                local sf2="cloud-init-${safe_n2}-${timestamp_save}.yml"
                cp "$tmp1" "$sf1"
                cp "$tmp2" "$sf2"
                echo -e "${GREEN}✓ Saved: ${WHITE}${sf1}${NC}"
                echo -e "${GREEN}✓ Saved: ${WHITE}${sf2}${NC}"
                ;;
            "")
                break
                ;;
            *)
                echo -e "${GRAY}Unknown action. Press Enter to return.${NC}"
                ;;
        esac
    done
    
    # Cleanup
    rm -f "$tmp1" "$tmp2"
}

#--------------------------------------------------------------------------------
# Compare IC vs Running Instance
# Args: $1=ic_json (full IC JSON), $2=ic_name
#--------------------------------------------------------------------------------
_compare_ic_vs_instance() {
    local ic_json="$1"
    local ic_name="$2"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Select Instance to Compare" 0
    echo ""
    
    # Fetch instances
    _ui_oci_cmd "oci compute instance list --compartment-id \$COMPARTMENT_ID --all"
    _step_init
    _step_active "instances"
    
    local instances_json
    instances_json=$(oci compute instance list \
        --compartment-id "$compartment_id" \
        --region "$region" \
        --all \
        --output json 2>/dev/null)
    _step_complete "instances"
    _step_finish
    
    if [[ -z "$instances_json" ]] || ! jq -e '.data[0]' <<< "$instances_json" > /dev/null 2>&1; then
        echo -e "${RED}No instances found${NC}"
        _ui_pause "return"
        return
    fi
    
    # List non-terminated instances
    local cinst_idx=0
    declare -A CINST_MAP=()
    
    echo ""
    _ui_table_header "%-4s %-55s %-12s %-24s %s" "#" "Display Name" "State" "Shape" "Instance OCID"
    
    jq -r ' 
        .data[] |
        select(.["lifecycle-state"] != "TERMINATED") |
        "\(.["display-name"])|\(.["lifecycle-state"])|\(.shape)|\(.id)"
    ' <<< "$instances_json" 2>/dev/null | sort -t'|' -k1,1 | while IFS='|' read -r inst_name inst_state inst_shape inst_ocid; do
        [[ -z "$inst_ocid" ]] && continue
        ((cinst_idx++))
        echo "${cinst_idx}|${inst_ocid}|${inst_name}" >> "${TEMP_DIR}/cinst_map_$$"
        
        local state_color
        state_color=$(color_oci_state "$inst_state")
        
        printf "${YELLOW}%-4s${NC} %-55s ${state_color}%-12s${NC} %-24s ${YELLOW}%s${NC}\n" \
            "$cinst_idx" "$inst_name" "$inst_state" "$inst_shape" "$inst_ocid"
    done
    
    # Read map from subshell temp file
    if [[ -f "${TEMP_DIR}/cinst_map_$$" ]]; then
        while IFS='|' read -r idx ocid name; do
            CINST_MAP[$idx]="$ocid|$name"
        done < "${TEMP_DIR}/cinst_map_$$"
        rm -f "${TEMP_DIR}/cinst_map_$$"
    fi
    
    local cinst_total=${#CINST_MAP[@]}
    if [[ $cinst_total -eq 0 ]]; then
        echo -e "${GRAY}No instances available${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    echo -e "${GRAY}Total: ${cinst_total} instances${NC}"
    echo ""
    echo -n -e "${CYAN}Select instance (1-${cinst_total}) or paste OCID: ${NC}"
    local cinst_choice
    read -r cinst_choice
    
    local cinst_ocid="" cinst_name=""
    
    if [[ "$cinst_choice" == ocid1.instance.* ]]; then
        cinst_ocid="$cinst_choice"
        cinst_name=$(_inst_attr "$cinst_ocid" "$INSTANCE_LIST_CACHE" "display-name")
        [[ -z "$cinst_name" || "$cinst_name" == "null" ]] && cinst_name="Instance ..${cinst_ocid: -20}"
    elif [[ -n "${CINST_MAP[$cinst_choice]:-}" ]]; then
        IFS='|' read -r cinst_ocid cinst_name <<< "${CINST_MAP[$cinst_choice]}"
    else
        echo -e "${RED}Invalid selection${NC}"
        return
    fi
    
    echo ""
    local _build_tmp
    _build_tmp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    _build_launch_json_from_instance "$cinst_ocid" "$_build_tmp"
    
    local inst_launch_json
    inst_launch_json=$(cat "$_build_tmp" 2>/dev/null)
    rm -f "$_build_tmp"
    
    if [[ -z "$inst_launch_json" || "$inst_launch_json" == "{}" ]]; then
        echo -e "${RED}Failed to fetch instance details${NC}"
        _ui_pause "return"
        return
    fi
    
    # Extract IC launch details
    local ic_launch_json
    ic_launch_json=$(jq '.data["instance-details"]["launch-details"]' <<< "$ic_json")
    
    # Run comparison
    _do_field_comparison "$ic_launch_json" "$ic_name (Config)" "$inst_launch_json" "$cinst_name (Instance)"
}

#--------------------------------------------------------------------------------
# Unified Compare: IC vs IC, IC vs Instance, IC vs Local File
# Replaces old compare_instance_configurations + diff_instance_config_cloudinit
#--------------------------------------------------------------------------------
compare_instance_configurations() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_menu_header "COMPARE INSTANCE CONFIGURATIONS" \
        --breadcrumb "Compute" "Instance Configs" "Compare" \
        --cmd "oci compute-management instance-configuration list | oci compute-management instance-configuration get | oci compute instance list" \
        --env
    echo ""
    
    # ── Discovery ──
    _step_init
    if is_cache_fresh "$INSTANCE_CONFIG_CACHE"; then
        _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE") cached)"
    else
        _step_active "instance configs"
        fetch_instance_configurations > /dev/null 2>&1
        _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    fi
    _step_finish
    
    local _ic_cnt=0
    [[ -f "$INSTANCE_CONFIG_CACHE" ]] && _ic_cnt=$(_clc "$INSTANCE_CONFIG_CACHE")
    
    if [[ ! -f "$INSTANCE_CONFIG_CACHE" ]] || [[ $_ic_cnt -eq 0 ]]; then
        echo -e "${RED}No instance configurations found${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    echo -e "${WHITE}Compare mode:${NC}"
    echo -e "  ${YELLOW}1${NC}) Instance Config vs Instance Config   ${GRAY}(full field + cloud-init comparison)${NC}"
    echo -e "  ${YELLOW}2${NC}) Instance Config vs Running Instance   ${GRAY}(full field + cloud-init comparison)${NC}"
    echo -e "  ${YELLOW}3${NC}) Instance Config vs Local File         ${GRAY}(cloud-init diff only)${NC}"
    echo -e "  ${CYAN}q${NC}) Cancel"
    echo ""
    echo -n -e "${CYAN}Select mode [1/2/3/q]: ${NC}"
    local mode_choice
    read -r mode_choice
    
    case "$mode_choice" in
        1)
            # IC vs IC - full comparison
            # List configs
            echo ""
            _list_ics_numbered
            
            if [[ $_IC_LIST_COUNT -lt 2 ]]; then
                echo ""
                echo -e "${YELLOW}Need at least 2 instance configurations to compare${NC}"
                _ui_pause "return"
                return
            fi
            
            echo ""
            echo -n -e "${CYAN}Select first configuration (1-${_IC_LIST_COUNT}): ${NC}"
            local choice1
            read -r choice1
            
            if [[ -z "${_IC_LIST_MAP[$choice1]:-}" ]]; then
                echo -e "${RED}Invalid selection${NC}"
                return
            fi
            
            echo -n -e "${CYAN}Select second configuration (1-${_IC_LIST_COUNT}): ${NC}"
            local choice2
            read -r choice2
            
            if [[ -z "${_IC_LIST_MAP[$choice2]:-}" ]]; then
                echo -e "${RED}Invalid selection${NC}"
                return
            fi
            
            local ocid1 name1 ocid2 name2
            IFS='|' read -r ocid1 name1 <<< "${_IC_LIST_MAP[$choice1]}"
            IFS='|' read -r ocid2 name2 <<< "${_IC_LIST_MAP[$choice2]}"
            
            echo ""
            echo -e "${BOLD}Comparing:${NC}"
            echo -e "  ${GREEN}A:${NC} $name1"
            echo -e "  ${BLUE}B:${NC} $name2"
            echo ""
            _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${ocid1}"
            _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${ocid2}"
            echo ""
            _step_init
            _step_active "full configuration details"
            
            local json1 json2
            json1=$(oci compute-management instance-configuration get \
                --instance-configuration-id "$ocid1" \
                --region "$region" \
                --output json 2>/dev/null)
            json2=$(oci compute-management instance-configuration get \
                --instance-configuration-id "$ocid2" \
                --region "$region" \
                --output json 2>/dev/null)
            _step_complete "full configuration details"
            _step_finish
            
            if [[ -z "$json1" || -z "$json2" ]]; then
                echo -e "${RED}Failed to fetch configuration details${NC}"
                _ui_policy_hint "read instance-configurations in compartment"
                _ui_pause "return"
                return
            fi
            
            local launch1 launch2
            launch1=$(jq '.data["instance-details"]["launch-details"]' <<< "$json1")
            launch2=$(jq '.data["instance-details"]["launch-details"]' <<< "$json2")
            
            _do_field_comparison "$launch1" "$name1" "$launch2" "$name2"
            ;;
        2)
            # IC vs Instance
            # Select IC
            echo ""
            _list_ics_numbered
            
            if [[ $_IC_LIST_COUNT -eq 0 ]]; then
                echo -e "${GRAY}No instance configurations found${NC}"
                _ui_pause "return"
                return
            fi
            
            echo ""
            echo -n -e "${CYAN}Select instance configuration (1-${_IC_LIST_COUNT}): ${NC}"
            local ic2_choice
            read -r ic2_choice
            
            if [[ -z "${_IC_LIST_MAP[$ic2_choice]:-}" ]]; then
                echo -e "${RED}Invalid selection${NC}"
                return
            fi
            
            local ic2_ocid ic2_name
            IFS='|' read -r ic2_ocid ic2_name <<< "${_IC_LIST_MAP[$ic2_choice]}"
            
            echo ""
            _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${ic2_ocid}"
            _step_init
            _step_active "configuration"
            
            local ic2_json
            ic2_json=$(oci compute-management instance-configuration get \
                --instance-configuration-id "$ic2_ocid" \
                --region "$region" \
                --output json 2>/dev/null)
            _step_complete "configuration"
            _step_finish

            if [[ -z "$ic2_json" ]] || ! jq -e '.data' <<< "$ic2_json" > /dev/null 2>&1; then
                echo -e "${RED}Failed to fetch configuration${NC}"
                _ui_policy_hint "read instance-configurations in compartment"
                _ui_pause "return"
                return
            fi
            
            _compare_ic_vs_instance "$ic2_json" "$ic2_name"
            ;;
        3)
            # IC vs Local File - cloud-init diff only
            # Select IC
            echo ""
            _list_ics_numbered
            
            if [[ $_IC_LIST_COUNT -eq 0 ]]; then
                echo -e "${GRAY}No instance configurations found${NC}"
                _ui_pause "return"
                return
            fi
            
            echo ""
            echo -n -e "${CYAN}Select instance configuration (1-${_IC_LIST_COUNT}): ${NC}"
            local ic3_choice
            read -r ic3_choice
            
            if [[ -z "${_IC_LIST_MAP[$ic3_choice]:-}" ]]; then
                echo -e "${RED}Invalid selection${NC}"
                return
            fi
            
            local ic3_ocid ic3_name
            IFS='|' read -r ic3_ocid ic3_name <<< "${_IC_LIST_MAP[$ic3_choice]}"
            
            # Select local file
            echo ""
            local ci_files=()
            local ci_idx=0
            while IFS= read -r -d '' ci_file; do
                ((ci_idx++))
                ci_files[$ci_idx]="$ci_file"
            done < <(find . -maxdepth 1 \( -name 'cloud-init*.yml' -o -name 'cloud-init*.yaml' \) -print0 2>/dev/null | sort -z)
            
            local local_file=""
            if [[ $ci_idx -gt 0 ]]; then
                _ui_subheader "Cloud-init Files in Current Directory" 0
                for ((fi=1; fi<=ci_idx; fi++)); do
                    printf "  ${YELLOW}%-3s${NC} %s\n" "$fi" "${ci_files[$fi]}"
                done
                echo ""
                echo -n -e "${CYAN}Select file # or enter path manually: ${NC}"
                local file_choice
                read -r file_choice
                
                if [[ "$file_choice" =~ ^[0-9]+$ ]] && [[ -n "${ci_files[$file_choice]:-}" ]]; then
                    local_file="${ci_files[$file_choice]}"
                else
                    local_file="$file_choice"
                fi
            else
                echo -n -e "${CYAN}Enter path to local cloud-init file: ${NC}"
                read -r local_file
            fi
            
            # Expand ~ to home directory
            local_file="${local_file/#\~/$HOME}"
            
            if [[ ! -f "$local_file" ]]; then
                echo -e "${RED}File not found: ${local_file}${NC}"
                _ui_pause "return"
                return
            fi
            
            echo ""
            _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${ic3_ocid}"
            _step_init
            _step_active "cloud-init from instance configuration"
            
            local ic3_json
            ic3_json=$(oci compute-management instance-configuration get \
                --instance-configuration-id "$ic3_ocid" \
                --region "$region" \
                --output json 2>/dev/null)
            _step_complete "cloud-init from instance configuration"
            _step_finish
            
            local ud_b64=""
            if [[ -n "$ic3_json" ]] && jq -e '.data' <<< "$ic3_json" > /dev/null 2>&1; then
                ud_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic3_json" 2>/dev/null)
            fi
            
            local tmp_config
            tmp_config=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
            
            if [[ -n "$ud_b64" && "$ud_b64" != "null" ]]; then
                decode_user_data_to_file "$ud_b64" "$tmp_config" || echo "# Failed to decode" > "$tmp_config"
            else
                echo "# No user_data" > "$tmp_config"
            fi
            
            _display_cloudinit_diff "$tmp_config" "$ic3_name" "$local_file" "$(basename "$local_file") (local)"
            
            rm -f "$tmp_config"
            ;;
        *)
            return
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Internal: Display cloud-init diff with interactive actions
# Args: $1=file_a, $2=name_a, $3=file_b, $4=name_b
#--------------------------------------------------------------------------------
_display_cloudinit_diff() {
    local file_a="$1"
    local name_a="$2"
    local file_b="$3"
    local name_b="$4"
    
    local lines_a lines_b
    lines_a=$(wc -l < "$file_a" 2>/dev/null || echo "0")
    lines_b=$(wc -l < "$file_b" 2>/dev/null || echo "0")
    
    echo ""
    _ui_menu_header "CLOUD-INIT DIFF"
    echo ""
    echo -e "${WHITE}Comparing:${NC}"
    echo -e "  ${RED}- A:${NC} ${GREEN}$name_a${NC} ${GRAY}(${lines_a} lines)${NC}"
    echo -e "  ${GREEN}+ B:${NC} ${BLUE}$name_b${NC} ${GRAY}(${lines_b} lines)${NC}"
    echo ""
    
    if diff -q "$file_a" "$file_b" > /dev/null 2>&1; then
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                                                 ✓ CLOUD-INIT IS IDENTICAL                                                                              ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
    else
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                                                 ✗ CLOUD-INIT DIFFERS                                                                                    ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        
        # Count changed lines
        local added removed
        added=$(diff -u "$file_a" "$file_b" 2>/dev/null | grep -c '^+[^+]' || true)
        removed=$(diff -u "$file_a" "$file_b" 2>/dev/null | grep -c '^-[^-]' || true)
        echo -e "${GRAY}  Changes: ${RED}-${removed} lines removed${NC}  ${GREEN}+${added} lines added${NC}"
        echo ""
        
        _ui_subheader "Unified Diff" 0
        echo ""
        
        local diff_output
        diff_output=$(diff -u "$file_a" "$file_b" 2>/dev/null | tail -n +4)
        
        while IFS= read -r line; do
            if [[ "$line" =~ ^@@ ]]; then
                echo ""
                printf '%b%s%b\n' "${YELLOW}" "$line" "${NC}"
            elif [[ "$line" =~ ^- ]]; then
                printf '%b%s%b\n' "${RED}" "$line" "${NC}"
            elif [[ "$line" =~ ^\+ ]]; then
                printf '%b%s%b\n' "${GREEN}" "$line" "${NC}"
            elif [[ "$line" =~ ^[[:space:]] ]]; then
                printf '%b%s%b\n' "${GRAY}" "$line" "${NC}"
            fi
        done <<< "$diff_output"
    fi

    echo ""
    _ui_content_border
    echo ""
    
    # Interactive post-diff actions
    _ui_actions
    echo -e "  ${CYAN}view-a${NC}   - View full cloud-init: ${GREEN}$name_a${NC}"
    echo -e "  ${CYAN}view-b${NC}   - View full cloud-init: ${BLUE}$name_b${NC}"
    echo -e "  ${CYAN}save-a${NC}   - Save cloud-init A to file"
    echo -e "  ${CYAN}save-b${NC}   - Save cloud-init B to file"
    echo -e "  ${CYAN}save${NC}     - Save both cloud-init files"
    echo -e "  ${CYAN}Enter${NC}    - Return"
    echo ""
    
    while true; do
        echo -n -e "${CYAN}Action [Enter to return]: ${NC}"
        local action
        read -r action
        
        case "$action" in
            view-a|VIEW-A)
                echo ""
                _ui_subheader "Cloud-Init: $name_a (${lines_a} lines)" 0
                print_separator 120 "$GRAY"
                nl -ba "$file_a"
                print_separator 120 "$GRAY"
                echo ""
                ;;
            view-b|VIEW-B)
                echo ""
                _ui_subheader "Cloud-Init: $name_b (${lines_b} lines)" 0
                print_separator 120 "$GRAY"
                nl -ba "$file_b"
                print_separator 120 "$GRAY"
                echo ""
                ;;
            save-a|SAVE-A)
                local safe_a
                safe_a=$(echo "$name_a" | tr ' /()' '_---')
                local out_a="cloud-init-${safe_a}-$(date +%Y%m%d_%H%M%S).yml"
                cp "$file_a" "$out_a"
                echo -e "${GREEN}✓ Saved: ${WHITE}${out_a}${NC}"
                ;;
            save-b|SAVE-B)
                local safe_b
                safe_b=$(echo "$name_b" | tr ' /()' '_---')
                local out_b="cloud-init-${safe_b}-$(date +%Y%m%d_%H%M%S).yml"
                cp "$file_b" "$out_b"
                echo -e "${GREEN}✓ Saved: ${WHITE}${out_b}${NC}"
                ;;
            save|SAVE)
                local ts_save
                ts_save=$(date +%Y%m%d_%H%M%S)
                local sa sb
                sa=$(echo "$name_a" | tr ' /()' '_---')
                sb=$(echo "$name_b" | tr ' /()' '_---')
                local oa="cloud-init-${sa}-${ts_save}.yml"
                local ob="cloud-init-${sb}-${ts_save}.yml"
                cp "$file_a" "$oa"
                cp "$file_b" "$ob"
                echo -e "${GREEN}✓ Saved: ${WHITE}${oa}${NC}"
                echo -e "${GREEN}✓ Saved: ${WHITE}${ob}${NC}"
                ;;
            "")
                break
                ;;
            *)
                echo -e "${GRAY}Unknown action. Press Enter to return.${NC}"
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Rename Instance Configuration interactively
#--------------------------------------------------------------------------------
rename_instance_configuration_interactive() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_menu_header "RENAME INSTANCE CONFIGURATION" \
        --breadcrumb "Compute" "Instance Configs" "Rename" \
        --cmd "oci compute-management instance-configuration get --instance-configuration-id \$IC_OCID | oci compute-management instance-configuration update --instance-configuration-id \$IC_OCID --display-name \$NEW_NAME" \
        --env
    
    # ── Discovery ──
    _step_init
    if is_cache_fresh "$INSTANCE_CONFIG_CACHE"; then
        _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE") cached)"
    else
        _step_active "instance configs"
        fetch_instance_configurations > /dev/null 2>&1
        _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    fi
    _step_finish
    
    if [[ ! -f "$INSTANCE_CONFIG_CACHE" ]]; then
        echo -e "${RED}No instance configurations found${NC}"
        _ui_pause "return"
        return
    fi
    
    # List configs
    _list_ics_numbered
    
    if [[ $_IC_LIST_COUNT -eq 0 ]]; then
        echo -e "${GRAY}No instance configurations found${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    echo -n -e "${CYAN}Select instance configuration to rename (1-${_IC_LIST_COUNT}): ${NC}"
    local choice
    read -r choice
    
    if [[ -z "${_IC_LIST_MAP[$choice]:-}" ]]; then
        echo -e "${RED}Invalid selection${NC}"
        _ui_pause "return"
        return
    fi
    
    local ic_ocid ic_current_name
    IFS='|' read -r ic_ocid ic_current_name <<< "${_IC_LIST_MAP[$choice]}"
    
    echo ""
    echo -e "${BOLD}${WHITE}Selected:${NC} ${CYAN}$ic_current_name${NC}"
    echo -e "${GRAY}OCID: $ic_ocid${NC}"
    echo ""
    
    # Fetch full details to generate recommended name
    _ui_oci_cmd "oci compute-management instance-configuration get --instance-configuration-id ${ic_ocid}"
    _step_init
    _step_active "configuration details"
    local ic_json
    ic_json=$(oci compute-management instance-configuration get \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --output json 2>/dev/null)
    _step_complete "configuration details"
    _step_finish
    
    if [[ -z "$ic_json" ]]; then
        echo -e "${RED}Failed to fetch instance configuration details${NC}"
        _ui_policy_hint "read instance-configurations in compartment"
        _ui_pause "return"
        return
    fi
    
    # Extract details for recommended name
    local shape network_type oke_version
    shape=$(jq -r '.data["instance-details"]["launch-details"]["shape"] // "unknown"' <<< "$ic_json")
    
    # Determine network type from metadata
    local native_networking
    native_networking=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["oke-native-pod-networking"] // "false"' <<< "$ic_json")
    if [[ "$native_networking" == "true" ]]; then
        network_type="native"
    else
        network_type="flannel"
    fi
    
    # Try to extract kubernetes version from user_data
    local user_data_b64
    user_data_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic_json")
    oke_version="unknown"
    if [[ -n "$user_data_b64" ]]; then
        local decoded_ud
        decoded_ud=$(echo "$user_data_b64" | base64 -d 2>/dev/null)
        # Look for kubernetes version in the apt source or package name
        # e.g., kubernetes-1.33 or oci-oke-node-all-1.33.1
        local extracted_version
        extracted_version=$(echo "$decoded_ud" | grep -oP 'kubernetes-\K[0-9]+\.[0-9]+' | head -1)
        if [[ -z "$extracted_version" ]]; then
            extracted_version=$(echo "$decoded_ud" | grep -oP 'oci-oke-node-all-\K[0-9]+\.[0-9]+' | head -1)
        fi
        if [[ -n "$extracted_version" ]]; then
            oke_version="$extracted_version"
        fi
    fi
    
    # Count existing configs with similar pattern to determine next number
    local base_pattern="${shape}-ic-oke-${oke_version}-${network_type}"
    local existing_count=0
    if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
        existing_count=$(grep -c "${base_pattern}" "$INSTANCE_CONFIG_CACHE" 2>/dev/null) || existing_count=0
        [[ ! "$existing_count" =~ ^[0-9]+$ ]] && existing_count=0
    fi
    local next_num=$((existing_count + 1))
    
    # Generate recommended name
    local recommended_name="${shape}-ic-oke-${oke_version}-${network_type}-${next_num}"
    
    echo ""
    _ui_subheader "Detected Configuration" 0
    echo -e "  ${CYAN}Shape:${NC}        $shape"
    echo -e "  ${CYAN}Network Type:${NC} $network_type"
    echo -e "  ${CYAN}OKE Version:${NC}  $oke_version"
    echo ""
    
    _ui_subheader "Naming Convention" 0
    echo -e "  ${GRAY}<shape>-ic-oke-<version>-<network_type>-<#>${NC}"
    echo ""
    echo -e "${BOLD}${GREEN}Recommended Name:${NC} ${WHITE}$recommended_name${NC}"
    echo ""
    
    echo -n -e "${CYAN}Enter new name [${recommended_name}]: ${NC}"
    local new_name
    read -r new_name
    
    # Use recommended name if empty
    [[ -z "$new_name" ]] && new_name="$recommended_name"
    
    # Don't rename if same name
    if [[ "$new_name" == "$ic_current_name" ]]; then
        echo -e "${YELLOW}New name is the same as current name. No changes made.${NC}"
        _ui_pause "return"
        return
    fi
    
    echo ""
    _ui_subheader "Rename Summary" 0
    echo -e "  ${RED}Current:${NC} $ic_current_name"
    echo -e "  ${GREEN}New:${NC}     $new_name"
    echo ""
    
    # Show command to be executed
    _ui_subheader "Command to Execute" 0
    echo ""
    printf "%s\n" "oci compute-management instance-configuration update \\"
    printf "%s\n" "  --instance-configuration-id \"$ic_ocid\" \\"
    printf "%s\n" "  --region \"$region\" \\"
    printf "%s\n" "  --display-name \"$new_name\""
    echo ""
    
    # Log file for the action
    local log_file="${LOGS_DIR}/instance_config_rename_$(date +%Y%m%d_%H%M%S).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    _ui_subheader "CONFIRM RENAME" 0
    echo ""
    echo -e "${WHITE}Log file: ${CYAN}${log_file}${NC}"
    echo ""
    if ! _ui_confirm "RENAME" "confirm" "$CYAN"; then
        echo -e "${YELLOW}Cancelled.${NC}"
        _ui_pause "return"
        return
    fi
    
    # Log the command
    {
        echo "=========================================="
        echo "Instance Configuration Rename"
        echo "Timestamp: $(date)"
        echo "=========================================="
        echo ""
        echo "OCID: $ic_ocid"
        echo "Current Name: $ic_current_name"
        echo "New Name: $new_name"
        echo ""
        echo "Command:"
        echo "oci compute-management instance-configuration update \\"
        echo "  --instance-configuration-id \"$ic_ocid\" \\"
        echo "  --region \"$region\" \\"
        echo "  --display-name \"$new_name\""
        echo ""
        echo "=========================================="
        echo "Execution Output:"
        echo "=========================================="
    } > "$log_file"

    # Execute the rename
    echo ""
    echo -e "${YELLOW}Renaming instance configuration...${NC}"

    local _rename_cmd="oci compute-management instance-configuration update --instance-configuration-id \"$ic_ocid\" --region \"$region\" --display-name \"$new_name\""
    local result
    log_action "UPDATE" "$_rename_cmd"
    result=$(oci compute-management instance-configuration update \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --display-name "$new_name" 2>&1)
    local exit_code=$?

    # Log the result
    echo "$result" >> "$log_file"
    
    if [[ $exit_code -eq 0 ]]; then
        echo ""
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                 INSTANCE CONFIGURATION RENAMED SUCCESSFULLY                ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${WHITE}Old Name:${NC} ${RED}$ic_current_name${NC}"
        echo -e "${WHITE}New Name:${NC} ${GREEN}$new_name${NC}"
        echo -e "${WHITE}Log:${NC}      ${WHITE}$log_file${NC}"
        echo ""
        
        # Invalidate cache
        rm -f "$INSTANCE_CONFIG_CACHE"
        
        echo -e "${GREEN}✓ Rename complete!${NC}"
        log_action_result "SUCCESS" "UPDATE operation"
    else
        echo ""
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                    FAILED TO RENAME INSTANCE CONFIGURATION                 ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${RED}Error:${NC}"
        log_action_result "FAILED" "UPDATE operation"
        echo "$result"
        echo ""
        echo -e "${WHITE}Log file: ${CYAN}$log_file${NC}"
    fi
    
    echo ""
    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Rename a single Instance Configuration (called from detail view)
# Args: $1 = OCID, $2 = current name, $3 = JSON (optional, will fetch if not provided)
#--------------------------------------------------------------------------------
rename_single_instance_configuration() {
    local ic_ocid="$1"
    local ic_current_name="$2"
    local ic_json="${3:-}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Rename Instance Configuration" 0
    echo ""
    
    # Fetch JSON if not provided
    if [[ -z "$ic_json" ]]; then
        _step_init
        _step_active "configuration details"
        ic_json=$(oci compute-management instance-configuration get \
            --instance-configuration-id "$ic_ocid" \
            --region "$region" \
            --output json 2>/dev/null)
        _step_complete "configuration details"
        _step_finish

        if [[ -z "$ic_json" ]]; then
            echo -e "${RED}Failed to fetch instance configuration details${NC}"
            _ui_policy_hint "read instance-configurations in compartment"
            _ui_pause
            return
        fi
    fi
    
    # Extract details for recommended name
    local shape network_type oke_version
    shape=$(jq -r '.data["instance-details"]["launch-details"]["shape"] // "unknown"' <<< "$ic_json")
    
    # Determine network type from metadata
    local native_networking
    native_networking=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["oke-native-pod-networking"] // "false"' <<< "$ic_json")
    if [[ "$native_networking" == "true" ]]; then
        network_type="native"
    else
        network_type="flannel"
    fi
    
    # Try to extract kubernetes version from user_data
    local user_data_b64
    user_data_b64=$(jq -r '.data["instance-details"]["launch-details"]["metadata"]["user_data"] // empty' <<< "$ic_json")
    oke_version="unknown"
    if [[ -n "$user_data_b64" ]]; then
        local decoded_ud
        decoded_ud=$(echo "$user_data_b64" | base64 -d 2>/dev/null)
        local extracted_version
        extracted_version=$(echo "$decoded_ud" | grep -oP 'kubernetes-\K[0-9]+\.[0-9]+' | head -1)
        if [[ -z "$extracted_version" ]]; then
            extracted_version=$(echo "$decoded_ud" | grep -oP 'oci-oke-node-all-\K[0-9]+\.[0-9]+' | head -1)
        fi
        if [[ -n "$extracted_version" ]]; then
            oke_version="$extracted_version"
        fi
    fi
    
    # Count existing configs with similar pattern
    local base_pattern="${shape}-ic-oke-${oke_version}-${network_type}"
    local existing_count=0
    if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
        existing_count=$(grep -c "${base_pattern}" "$INSTANCE_CONFIG_CACHE" 2>/dev/null) || existing_count=0
        [[ ! "$existing_count" =~ ^[0-9]+$ ]] && existing_count=0
    fi
    local next_num=$((existing_count + 1))
    
    # Generate recommended name
    local recommended_name="${shape}-ic-oke-${oke_version}-${network_type}-${next_num}"
    
    echo -e "${WHITE}Current Name:${NC}     ${CYAN}$ic_current_name${NC}"
    echo -e "${WHITE}Shape:${NC}            $shape"
    echo -e "${WHITE}Network Type:${NC}     $network_type"
    echo -e "${WHITE}OKE Version:${NC}      $oke_version"
    echo ""
    echo -e "${BOLD}${GREEN}Recommended:${NC}      ${WHITE}$recommended_name${NC}"
    echo ""
    
    echo -n -e "${CYAN}Enter new name [${recommended_name}]: ${NC}"
    local new_name
    read -r new_name
    
    [[ -z "$new_name" ]] && new_name="$recommended_name"
    
    if [[ "$new_name" == "$ic_current_name" ]]; then
        echo -e "${YELLOW}New name is the same as current name. No changes made.${NC}"
        _ui_pause
        return
    fi
    
    # Show command
    echo ""
    echo -e "${BOLD}${YELLOW}Command:${NC}"
    echo -e "oci compute-management instance-configuration update \\"
    echo -e "  --instance-configuration-id \"$ic_ocid\" \\"
    echo -e "  --region \"$region\" \\"
    echo -e "  --display-name \"$new_name\""
    echo ""

    if ! _ui_confirm "RENAME" "confirm" "$CYAN"; then
        echo -e "${YELLOW}Cancelled.${NC}"
        _ui_pause
        return
    fi
    
    # Log file
    local log_file="${LOGS_DIR}/instance_config_rename_$(date +%Y%m%d_%H%M%S).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    {
        echo "=========================================="
        echo "Instance Configuration Rename"
        echo "Timestamp: $(date)"
        echo "=========================================="
        echo "OCID: $ic_ocid"
        echo "Current Name: $ic_current_name"
        echo "New Name: $new_name"
        echo ""
        echo "Command:"
        echo "oci compute-management instance-configuration update \\"
        echo "  --instance-configuration-id \"$ic_ocid\" \\"
        echo "  --region \"$region\" \\"
        echo "  --display-name \"$new_name\""
        echo ""
        echo "=========================================="
        echo "Execution Output:"
        echo "=========================================="
    } > "$log_file"

    echo ""
    echo -e "${YELLOW}Renaming...${NC}"

    local _rename_cmd="oci compute-management instance-configuration update --instance-configuration-id \"$ic_ocid\" --region \"$region\" --display-name \"$new_name\""
    local result
    log_action "UPDATE" "$_rename_cmd"
    result=$(oci compute-management instance-configuration update \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --display-name "$new_name" 2>&1)
    local exit_code=$?

    echo "$result" >> "$log_file"

    if [[ $exit_code -eq 0 ]]; then
        echo -e "${GREEN}✓ Renamed successfully!${NC}"
        log_action_result "SUCCESS" "UPDATE operation"
        echo -e "  ${RED}Old:${NC} $ic_current_name"
        echo -e "  ${GREEN}New:${NC} $new_name"
        rm -f "$INSTANCE_CONFIG_CACHE"
    else
        echo -e "${RED}✗ Failed to rename${NC}"
        log_action_result "FAILED" "UPDATE operation"
        echo "$result"
    fi
    
    echo -e "${WHITE}Log: $log_file${NC}"
    echo ""
    _ui_pause
}

#===============================================================================
# GPU MEMORY FABRIC & CLUSTER MANAGEMENT
#===============================================================================

interactive_gpu_management() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    while true; do
        display_gpu_management_menu
        
        _ui_actions
        echo -e "  ${YELLOW}f#/g#/i#/c#${NC} - View resource details (e.g., 'f1', 'g2', 'i3', 'c1')"
        echo -e "  ${GREEN}create${NC}      - Create a new GPU Memory Cluster on a Fabric"
        echo -e "  ${GREEN}update${NC}      - Update an existing GPU Memory Cluster (size/instance config)"
        echo -e "  ${RED}d${NC}           - Delete GPU Memory Cluster(s) (e.g., 'd g1', 'd g1,g2', 'd g1-g3')"
        echo -e "  ${CYAN}fw${NC}          - Firmware Bundles (list available firmware by platform)"
        echo -e "  ${YELLOW}j${NC}           - View raw JSON (j <keyword> to search)"
        echo -e "  ${MAGENTA}r${NC}           - Refresh data from OCI"
        echo -e "  ${CYAN}back${NC}        - Return to main menu"
        echo ""

        # Inner loop: stay at prompt without redrawing after view actions
        while true; do
            _ui_prompt "GPU Fabrics" "f#, g#, i#, c#, create, update, d g#, fw, j, r, back, show"
            
            local input
            read -r input
            [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
            
            # Empty input goes back
            if [[ -z "$input" ]]; then
                return
            fi
            
            # ── Delete GPU Memory Clusters: d g1 / d g1,g2 / d g1-g3 / delete g1 ──
            if [[ "$input" =~ ^(d|delete)[[:space:]]+(.+)$ ]]; then
                local del_targets="${BASH_REMATCH[2]}"
                local del_log_file="${LOGS_DIR}/gpu_cluster_delete_actions.log"
                mkdir -p "$(dirname "$del_log_file")" 2>/dev/null
                
                # Parse g# targets using shared helper
                if ! _parse_targets "g" "$del_targets" "CLUSTER_INDEX_MAP"; then
                    echo -e "${RED}No valid GPU clusters selected. Use: d g1, d g1,g2, d g1-g3${NC}"
                    continue
                fi
                local -a del_indices=("${_SEL_KEYS[@]}")
                
                echo ""
                echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
                echo -e "${RED}║                              ⚠️  DELETE GPU MEMORY CLUSTER(S)  ⚠️                                ║${NC}"
                echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
                echo ""
                
                declare -a del_valid=()
                
                printf "  ${BOLD}%-5s %-40s %-15s %-6s %-70s${NC}\n" "ID" "Display Name" "State" "Size" "Cluster OCID"
                print_separator 140
                
                for didx in "${del_indices[@]}"; do
                    local d_ocid="${CLUSTER_INDEX_MAP[$didx]:-}"
                    if [[ -z "$d_ocid" ]]; then
                        echo -e "  ${GRAY}${didx}  — (invalid)${NC}"
                        continue
                    fi
                    
                    # Fetch cluster details
                    local d_json; d_json=$(oci compute compute-gpu-memory-cluster get \
                        --compute-gpu-memory-cluster-id "$d_ocid" \
                        --region "$region" \
                        --output json 2>/dev/null)
                    
                    local d_name="Unknown" d_state="Unknown" d_size="?"
                    if [[ -n "$d_json" ]]; then
                        d_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$d_json")
                        d_state=$(jq -r '.data["lifecycle-state"] // "Unknown"' <<< "$d_json")
                        d_size=$(jq -r '.data["size"] // "?"' <<< "$d_json")
                    fi
                    
                    local d_state_color; d_state_color=$(color_oci_state "$d_state")
                    
                    printf "  ${YELLOW}%-5s${NC} %-40s ${d_state_color}%-15s${NC} %-6s ${GRAY}%-70s${NC}\n" \
                        "$didx" "${d_name:0:40}" "$d_state" "$d_size" "$d_ocid"
                    
                    del_valid+=("${didx}|${d_ocid}|${d_name}|${d_state}|${d_size}")
                done
                
                if [[ ${#del_valid[@]} -eq 0 ]]; then
                    echo ""
                    echo -e "${RED}No valid GPU clusters to delete${NC}"
                    echo ""
                    _ui_pause
                    break  # Refresh display
                fi
                
                # Show warnings
                echo ""
                echo -e "${RED}⚠️  WARNING: This will DELETE ${#del_valid[@]} GPU Memory Cluster(s)!${NC}"
                echo -e "${RED}   Associated instances will be terminated. This action cannot be undone!${NC}"
                
                echo ""
                _ui_subheader "Commands to Execute" 0
                for dv in "${del_valid[@]}"; do
                    local dv_idx dv_ocid dv_name
                    IFS='|' read -r dv_idx dv_ocid dv_name _ _ <<< "$dv"
                    echo -e "  ${WHITE}$ oci compute compute-gpu-memory-cluster delete --compute-gpu-memory-cluster-id \"${dv_ocid}\" --region \"${region}\" --force${NC}"
                done
                echo ""
                if ! _ui_confirm "DELETE" "confirm deletion of ${#del_valid[@]} GPU Memory Cluster(s)"; then
                    echo -e "${YELLOW}Deletion cancelled${NC}"
                    echo ""
                    _ui_pause
                    break  # Refresh display
                fi
                
                # Execute deletions
                echo ""
                _ui_subheader "Executing GPU Memory Cluster Deletions" 0
                echo ""
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK DELETE GPU MEMORY CLUSTERS: ${#del_valid[@]} cluster(s) =====" >> "$del_log_file"
                
                local del_success=0 del_fail=0
                for dv in "${del_valid[@]}"; do
                    local dv_idx dv_ocid dv_name dv_state dv_size
                    IFS='|' read -r dv_idx dv_ocid dv_name dv_state dv_size <<< "$dv"
                    
                    local del_cmd="oci compute compute-gpu-memory-cluster delete --compute-gpu-memory-cluster-id ${dv_ocid} --region ${region} --force"
                    
                    echo -e "${WHITE}[${dv_idx}] ${dv_name}${NC} ${GRAY}(${dv_state}, size=${dv_size})${NC}"
                    echo -e "${GRAY}$ ${del_cmd}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${del_cmd}" >> "$del_log_file"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')]   Cluster: ${dv_name} (${dv_state}, size=${dv_size})" >> "$del_log_file"
                    
                    if _safe_exec "$del_cmd" >/dev/null 2>&1; then
                        echo -e "  ${GREEN}✓ Delete initiated: ${dv_name}${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted ${dv_name} (${dv_ocid})" >> "$del_log_file"
                        ((del_success++))
                    else
                        echo -e "  ${RED}✗ Failed to delete: ${dv_name}${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete ${dv_name} (${dv_ocid})" >> "$del_log_file"
                        ((del_fail++))
                    fi
                    echo ""
                done
                
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] ===== BULK DELETE COMPLETE: Success=${del_success} Failed=${del_fail} Total=${#del_valid[@]} =====" >> "$del_log_file"
                echo ""
                _ui_subheader "Delete Complete" 0
                echo -e "  ${GREEN}Success:${NC} $del_success  ${RED}Failed:${NC} $del_fail  ${WHITE}Total:${NC} ${#del_valid[@]}"
                echo -e "  ${GRAY}Log:${NC} $del_log_file"
                echo ""
                rm -f "$FABRIC_CACHE" "$CLUSTER_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE"
                _ui_pause "refresh"
                break  # Refresh display
            fi
            
            case "$input" in
                d|D|delete|DELETE)
                    echo -e "${YELLOW}Usage: d g1, d g1,g2, d g1-g3${NC}"
                    echo -e "${GRAY}Specify GPU Memory Cluster(s) to delete by g# index${NC}"
                    ;;
                create|CREATE)
                    create_gpu_memory_cluster_interactive
                    break  # Refresh display after create
                    ;;
                update|UPDATE)
                    update_gpu_memory_cluster_interactive
                    break  # Refresh display after update
                    ;;
                fw|FW|firmware|FIRMWARE)
                    manage_firmware_bundles
                    ;;
                j|J|json|JSON)
                    if [[ -s "$FABRIC_JSON_CACHE" ]]; then
                        _ui_json_viewer "GPU Fabrics" "-f" "$FABRIC_JSON_CACHE" ".data"
                    elif [[ -s "$CLUSTER_JSON_CACHE" ]]; then
                        _ui_json_viewer "GPU Clusters" "-f" "$CLUSTER_JSON_CACHE" ".data"
                    else
                        echo -e "  ${GRAY}No JSON cache available — press r to refresh${NC}"
                    fi
                    ;;
                j\ *|J\ *|json\ *|JSON\ *)
                    if [[ -s "$FABRIC_JSON_CACHE" ]]; then
                        _ui_json_viewer "GPU Fabrics" "-f" "$FABRIC_JSON_CACHE" ".data" "${input#* }"
                    elif [[ -s "$CLUSTER_JSON_CACHE" ]]; then
                        _ui_json_viewer "GPU Clusters" "-f" "$CLUSTER_JSON_CACHE" ".data" "${input#* }"
                    else
                        echo -e "  ${GRAY}No JSON cache available — press r to refresh${NC}"
                    fi
                    ;;
                jf|JF)
                    [[ -s "$FABRIC_JSON_CACHE" ]] && _ui_json_viewer "GPU Fabrics" "-f" "$FABRIC_JSON_CACHE" ".data" || echo -e "  ${GRAY}No fabric JSON cache${NC}"
                    ;;
                jg|JG)
                    [[ -s "$CLUSTER_JSON_CACHE" ]] && _ui_json_viewer "GPU Clusters" "-f" "$CLUSTER_JSON_CACHE" ".data" || echo -e "  ${GRAY}No cluster JSON cache${NC}"
                    ;;
                r|R|refresh|REFRESH)
                    echo -e "${YELLOW}Refreshing cache...${NC}"
                    rm -f "$FABRIC_CACHE" "$FABRIC_JSON_CACHE" "$CLUSTER_CACHE" "$CLUSTER_JSON_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE" "$INSTANCE_CONFIG_CACHE" "$COMPUTE_CLUSTER_CACHE"
                    break  # Refresh display
                    ;;
                quit|QUIT|q|Q|exit|EXIT|back|BACK|b|B)
                    return
                    ;;
                f[0-9]*|g[0-9]*|i[0-9]*|c[0-9]*)
                    view_gpu_resource "$input"
                    # Stay in inner loop - no refresh needed for view actions
                    echo ""
                    ;;
                show|SHOW)
                    break
                    ;;
                *)
                    echo -e "${RED}Unknown command: $input${NC}"
                    ;;
            esac
        done
    done
}

# View details of a fabric or cluster
view_gpu_resource() {
    local resource_id="$1"
    
    case "$resource_id" in
        f[0-9]*)
            local fabric_ocid="${FABRIC_INDEX_MAP[$resource_id]:-}"
            if [[ -z "$fabric_ocid" ]]; then
                echo -e "${RED}Invalid fabric ID: $resource_id${NC}"
                return 1
            fi

            local _f_region="${FOCUS_REGION:-$REGION}"
            while true; do
                echo ""
                _ui_menu_header "GPU MEMORY FABRIC DETAILS" \
                    --color "$YELLOW" \
                    --breadcrumb "Compute" "GPU Memory Fabric" "Details: ${resource_id}" \
                    --cmd "oci compute compute-gpu-memory-fabric get --compute-gpu-memory-fabric-id ${fabric_ocid}" \
                    --env

                _step_init
                _step_active "fabric ${resource_id}"

                local fabric_json
                fabric_json=$(oci compute compute-gpu-memory-fabric get \
                    --compute-gpu-memory-fabric-id "$fabric_ocid" \
                    --region "$_f_region" \
                    --output json 2>/dev/null)
                _step_complete "fabric ${resource_id}"
                _step_finish

                if [[ -z "$fabric_json" ]]; then
                    echo -e "${WHITE}OCID:${NC} ${YELLOW}$fabric_ocid${NC}"
                    echo ""
                    echo -e "${RED}Failed to fetch fabric details${NC}"
                    _ui_policy_hint "read compute-gpu-memory-fabrics in compartment"
                    echo ""
                    _ui_pause "return"
                    return
                fi

                local fabric_name
                fabric_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$fabric_json")

                echo ""
                _ui_subheader "Fabric Properties" 0
                echo -e "${WHITE}Name:${NC} ${ORANGE}$fabric_name${NC}"
                echo -e "${WHITE}OCID:${NC} ${YELLOW}$fabric_ocid${NC}"
                echo ""
                jq -r '
                    .data |
                    "State:             \(.["lifecycle-state"] // "N/A")",
                    "Healthy Hosts:     \(.["healthy-host-count"] // 0)",
                    "Available Hosts:   \(.["available-host-count"] // 0)",
                    "Total Hosts:       \(.["total-host-count"] // 0)",
                    "Current Firmware:  \(.["current-firmware-bundle-id"] // "N/A")",
                    "Target Firmware:   \(.["target-firmware-bundle-id"] // "N/A")",
                    "Firmware State:    \(.["firmware-update-state"] // "N/A")",
                    "Time Created:      \(.["time-created"] // "N/A")"
                ' <<< "$fabric_json"

                echo ""
                _ui_actions
                echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
                echo -e "  ${MAGENTA}r${NC}) Refresh"
                echo -e "  ${CYAN}Enter${NC}) Return"
                echo ""
                _ui_prompt "Fabric Details" "j, r, Enter, show"
                local _f_choice
                read -r _f_choice
                [[ "${_f_choice:-}" == :* ]] && _nav_try_jump "$_f_choice" && return

                case "$_f_choice" in
                    j|J|json|JSON)
                        _ui_json_viewer "GPU Fabric: ${fabric_name}" "$fabric_json" ".data"
                        ;;
                    j\ *|J\ *|json\ *|JSON\ *)
                        _ui_json_viewer "GPU Fabric: ${fabric_name}" "$fabric_json" ".data" "${_f_choice#* }"
                        ;;
                    r|R) continue ;;
                    show|SHOW) continue ;;
                    *) return ;;
                esac
            done
            ;;
            
        g[0-9]*)
            local cluster_ocid="${CLUSTER_INDEX_MAP[$resource_id]:-}"
            if [[ -z "$cluster_ocid" ]]; then
                echo -e "${RED}Invalid cluster ID: $resource_id${NC}"
                return 1
            fi

            local _g_region="${FOCUS_REGION:-$REGION}"
            while true; do
                echo ""
                _ui_menu_header "GPU MEMORY CLUSTER DETAILS" \
                    --color "$MAGENTA" \
                    --breadcrumb "Compute" "GPU Memory Cluster" "Details: ${resource_id}" \
                    --cmd "oci compute compute-gpu-memory-cluster get --compute-gpu-memory-cluster-id ${cluster_ocid}" \
                    --env

                _step_init
                _step_active "cluster ${resource_id}"

                local cluster_json
                cluster_json=$(oci compute compute-gpu-memory-cluster get \
                    --compute-gpu-memory-cluster-id "$cluster_ocid" \
                    --region "$_g_region" \
                    --output json 2>/dev/null)
                _step_complete "cluster ${resource_id}"
                _step_finish

                if [[ -z "$cluster_json" ]]; then
                    echo -e "${WHITE}OCID:${NC} ${YELLOW}$cluster_ocid${NC}"
                    echo ""
                    echo -e "${RED}Failed to fetch cluster details${NC}"
                    _ui_policy_hint "read compute-gpu-memory-clusters in compartment"
                    echo ""
                    _ui_pause "return"
                    return
                fi

                local cluster_name
                cluster_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$cluster_json")

                echo ""
                _ui_subheader "Cluster Properties" 0
                echo -e "${WHITE}Name:${NC} ${MAGENTA}$cluster_name${NC}"
                echo -e "${WHITE}OCID:${NC} ${YELLOW}$cluster_ocid${NC}"
                echo ""

                local ic_id cc_id fabric_id
                ic_id=$(jq -r '.data["instance-configuration-id"] // "N/A"' <<< "$cluster_json")
                cc_id=$(jq -r '.data["compute-cluster-id"] // "N/A"' <<< "$cluster_json")
                fabric_id=$(jq -r '.data["gpu-memory-fabric-id"] // "N/A"' <<< "$cluster_json")

                local ic_name cc_name
                ic_name=$(get_instance_config_name "$ic_id")
                cc_name=$(get_compute_cluster_name "$cc_id")

                jq -r '
                    .data |
                    "State:                  \(.["lifecycle-state"] // "N/A")",
                    "Size:                   \(.["size"] // 0)",
                    "Availability Domain:    \(.["availability-domain"] // "N/A")",
                    "Time Created:           \(.["time-created"] // "N/A")"
                ' <<< "$cluster_json"
                echo -e "Instance Configuration: ${GREEN}$ic_name${NC} ${YELLOW}($ic_id)${NC}"
                echo -e "Compute Cluster:        ${GREEN}$cc_name${NC} ${YELLOW}($cc_id)${NC}"

                # Resolve fabric name
                local fabric_name="N/A"
                if [[ "$fabric_id" != "N/A" && -n "$fabric_id" ]]; then
                    fabric_name=$(oci compute compute-gpu-memory-fabric get --compute-gpu-memory-fabric-id "$fabric_id" --query 'data."display-name"' --raw-output 2>/dev/null) || fabric_name="N/A"
                fi
                echo -e "GPU Memory Fabric:      ${GREEN}$fabric_name${NC} ${YELLOW}($fabric_id)${NC}"

                # Check for instances in cache
                local inst_lines=""
                if [[ -f "$INSTANCE_CLUSTER_MAP_CACHE" ]]; then
                    inst_lines=$(grep "|${cluster_ocid}|" "$INSTANCE_CLUSTER_MAP_CACHE" 2>/dev/null)
                fi
                local _has_instances=0
                if [[ -n "$inst_lines" ]]; then
                    _has_instances=1
                    echo ""
                    echo -e "  ${GRAY}(instances available — use 'i' to drill into filtered instance view)${NC}"
                else
                    echo ""
                    echo -e "  ${GRAY}(no instances found in cache for this cluster)${NC}"
                fi

                echo ""
                _ui_actions
                echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
                [[ "$_has_instances" -eq 1 ]] && echo -e "  ${CYAN}i${NC}) View cluster instances"
                echo -e "  ${MAGENTA}r${NC}) Refresh"
                echo -e "  ${CYAN}Enter${NC}) Return"
                echo ""
                _ui_prompt "Cluster Details" "j, ${_has_instances:+i, }r, Enter, show"
                local _g_choice
                read -r _g_choice
                [[ "${_g_choice:-}" == :* ]] && _nav_try_jump "$_g_choice" && return

                case "$_g_choice" in
                    j|J|json|JSON)
                        _ui_json_viewer "GPU Cluster: ${cluster_name}" "$cluster_json" ".data"
                        ;;
                    j\ *|J\ *|json\ *|JSON\ *)
                        _ui_json_viewer "GPU Cluster: ${cluster_name}" "$cluster_json" ".data" "${_g_choice#* }"
                        ;;
                    i|I)
                        if [[ "$_has_instances" -eq 1 ]]; then
                            local filter_ocids=""
                            while IFS='|' read -r _gocid _gcl _gcn; do
                                [[ -z "$_gocid" || "$_gocid" == "#"* ]] && continue
                                [[ -n "$filter_ocids" ]] && filter_ocids="${filter_ocids}|"
                                filter_ocids="${filter_ocids}${_gocid}"
                            done <<< "$inst_lines"
                            manage_compute_instances "GPU Cluster: ${cluster_name}" "$filter_ocids"
                        else
                            echo -e "  ${GRAY}No instances in cache for this cluster${NC}"
                        fi
                        ;;
                    r|R) continue ;;
                    show|SHOW) continue ;;
                    *) return ;;
                esac
            done
            ;;

        i[0-9]*)
            local ic_ocid="${IC_INDEX_MAP[$resource_id]:-}"
            if [[ -z "$ic_ocid" ]]; then
                echo -e "${RED}Invalid instance config ID: $resource_id${NC}"
                return 1
            fi
            
            # Delegate to the same detail view used by --manage c2
            view_instance_configuration_detail "$resource_id"
            ;;
            
        c[0-9]*)
            local cc_ocid="${CC_INDEX_MAP[$resource_id]:-}"
            if [[ -z "$cc_ocid" ]]; then
                echo -e "${RED}Invalid compute cluster ID: $resource_id${NC}"
                return 1
            fi
            
            # Lookup name from cache
            local cc_name
            cc_name=$(get_compute_cluster_name "$cc_ocid")
            
            # Delegate to the same detail view used by --manage c3
            view_compute_cluster_details "$cc_ocid" "$cc_name"
            ;;
            
        *)
            echo -e "${RED}Invalid resource ID format. Use f#, g#, i#, or c#${NC}"
            return 1
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Firmware Bundles — list and inspect firmware bundles by platform
# Sources platform values from:
#   1. Compute Hosts cache (field 5 = platform)
#   2. Manual entry
# Uses: oci compute firmware-bundle list --platform <platform> --all
#       oci compute firmware-bundle get  --firmware-bundle-id <id>
#--------------------------------------------------------------------------------
manage_firmware_bundles() {
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "FIRMWARE BUNDLES" \
        --color "$YELLOW" \
        --breadcrumb "Compute" "GPU Fabrics" "Firmware Bundles" \
        --cmd "oci compute firmware-bundle list --platform \$PLATFORM --compartment-id \$TENANCY_ID --all | oci compute firmware-bundle get --firmware-bundle-id \$BUNDLE_ID" \
        --env \
        --cache \
        "${COMPUTE_HOST_CACHE}|Compute Hosts"

    # ── Gather unique platforms from Compute Host cache (auto-fetch if needed) ──
    if [[ ! -f "$COMPUTE_HOST_CACHE" ]] || [[ $(_clc "$COMPUTE_HOST_CACHE") -eq 0 ]]; then
        _step_init
        _step_active "compute hosts"
        fetch_compute_hosts
        local _ch_ct
        _ch_ct=$(_clc "$COMPUTE_HOST_CACHE")
        _step_complete "compute hosts(${_ch_ct})"
        _step_finish
    fi

    local -a _platforms=()
    if [[ -f "$COMPUTE_HOST_CACHE" ]]; then
        while IFS= read -r _p; do
            [[ -n "$_p" && "$_p" != "N/A" ]] && _platforms+=("$_p")
        done < <(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f5 | sort -u)
    fi

    local selected_platform=""
    if [[ ${#_platforms[@]} -eq 0 ]]; then
        echo -e "  ${YELLOW}No platforms found. Enter a platform manually.${NC}"
        echo ""
        echo -n -e "  ${CYAN}Platform: ${NC}"
        read -r selected_platform
        [[ -z "$selected_platform" ]] && return
    elif [[ ${#_platforms[@]} -eq 1 ]]; then
        selected_platform="${_platforms[0]}"
        echo -e "  ${WHITE}Platform:${NC} ${CYAN}${selected_platform}${NC} (from Compute Hosts)"
    else
        echo -e "  ${WHITE}Select platform:${NC}"
        local _pidx=0
        for _p in "${_platforms[@]}"; do
            ((_pidx++))
            echo -e "    ${GREEN}${_pidx}${NC}) ${_p}"
        done
        echo ""
        echo -n -e "  ${CYAN}Select #: ${NC}"
        local _psel
        read -r _psel
        if [[ "$_psel" =~ ^[0-9]+$ && -n "${_platforms[$((_psel-1))]:-}" ]]; then
            selected_platform="${_platforms[$((_psel-1))]}"
        else
            [[ -z "$_psel" ]] && return
            selected_platform="$_psel"  # Treat as manual entry
        fi
    fi

    [[ -z "$selected_platform" ]] && return

    # ── Collect current/target firmware bundle IDs from fabric cache ──
    local _current_fw="" _target_fw="" _fw_state=""
    if [[ -f "$FABRIC_CACHE" ]]; then
        # Fields: 1=Name|2=Last5|3=OCID|4=State|5=Healthy|6=Avail|7=Total|8=CurrentFW|9=TargetFW|10=FWState
        _current_fw=$(grep -v "^#" "$FABRIC_CACHE" | head -1 | cut -d'|' -f8)
        _target_fw=$(grep -v "^#" "$FABRIC_CACHE" | head -1 | cut -d'|' -f9)
        _fw_state=$(grep -v "^#" "$FABRIC_CACHE" | head -1 | cut -d'|' -f10)
    fi

    # ── Fetch firmware bundles ──
    echo ""
    _step_init
    _step_active "firmware bundles"
    local _fw_json
    _fw_json=$(oci compute firmware-bundle list \
        --platform "$selected_platform" \
        --compartment-id "$TENANCY_ID" \
        --region "$region" \
        --all --output json 2>/dev/null)

    if [[ -z "$_fw_json" ]]; then
        _step_complete "firmware bundles(0)"
        _step_finish
        echo -e "  ${RED}Failed to fetch firmware bundles for platform '${selected_platform}'${NC}"
        _ui_policy_hint "read firmware-bundles"
        echo ""
        _ui_pause "return"
        return
    fi

    local _fw_count
    _fw_count=$(jq -r '.data.items | length // 0' <<< "$_fw_json" 2>/dev/null)
    _step_complete "firmware bundles(${_fw_count})"
    _step_finish

    if [[ "$_fw_count" -eq 0 ]]; then
        echo -e "  ${YELLOW}No firmware bundles found for platform '${selected_platform}'${NC}"
        echo ""
        _ui_pause "return"
        return
    fi

    # ── Seed default column config if needed ──
    if [[ ! -f "$FWB_COLUMNS_CONF" ]]; then
        mkdir -p "$(dirname "$FWB_COLUMNS_CONF")"
        printf "# Column config (auto-generated, format: key[:width])\n" > "$FWB_COLUMNS_CONF"
        for _dk in "${_FWB_COL_DEFAULT_ENABLED[@]}"; do
            echo "$_dk" >> "$FWB_COLUMNS_CONF"
        done
    fi
    _col_load "FWB"

    # ── Display firmware bundles ──
    echo ""
    echo -e "  ${BOLD}${WHITE}Platform:${NC} ${CYAN}${selected_platform}${NC}"

    # Show current fabric firmware context if available
    if [[ -n "$_current_fw" && "$_current_fw" != "N/A" ]]; then
        echo -e "  ${BOLD}${WHITE}Current Firmware (fabric):${NC} ${GREEN}${_current_fw}${NC}"
    fi
    if [[ -n "$_target_fw" && "$_target_fw" != "N/A" && "$_target_fw" != "$_current_fw" ]]; then
        echo -e "  ${BOLD}${WHITE}Target Firmware (fabric):${NC}  ${YELLOW}${_target_fw}${NC}"
    fi
    if [[ -n "$_fw_state" && "$_fw_state" != "N/A" ]]; then
        local _fws_color
        _fws_color=$(color_firmware_state "$_fw_state")
        echo -e "  ${BOLD}${WHITE}Firmware Update State:${NC}     ${_fws_color}${_fw_state}${NC}"
    fi
    echo ""

    # Pre-parse bundles into temp file for two-pass rendering
    local _fw_parsed="${TEMP_DIR}/fw_parsed_$$.txt"
    jq -r '.data.items[] | "\(.id // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.["display-name"] // "N/A")|\(.description // "N/A")|\(.["time-created"] // "N/A")|\(.["time-updated"] // "N/A")"' <<< "$_fw_json" 2>/dev/null | sort -t'|' -k3,3 > "$_fw_parsed"

    # Check if any bundle has updated != created — hide column if all same
    local _has_updated=false
    while IFS='|' read -r _ _ _ _ _tc _tu; do
        [[ "${_tc:0:16}" != "${_tu:0:16}" ]] && _has_updated=true && break
    done < "$_fw_parsed"

    # Build column format — then dynamically remove "updated" if not needed
    _col_build_fmt "FWB"
    local _updated_was_enabled=false
    if [[ "$_has_updated" == "false" ]]; then
        for _ek in "${_FWB_ENABLED_COLS[@]}"; do
            [[ "$_ek" == "updated" ]] && _updated_was_enabled=true && break
        done
        if [[ "$_updated_was_enabled" == "true" ]]; then
            local -a _tmp_cols=()
            for _ek in "${_FWB_ENABLED_COLS[@]}"; do
                [[ "$_ek" != "updated" ]] && _tmp_cols+=("$_ek")
            done
            _FWB_ENABLED_COLS=("${_tmp_cols[@]}")
            _FWB_COL_COUNT=${#_FWB_ENABLED_COLS[@]}
            _FWB_ENABLED_INDICES=()
            for _ek in "${_FWB_ENABLED_COLS[@]}"; do
                for _ki in "${!_FWB_COL_KEYS[@]}"; do
                    [[ "${_FWB_COL_KEYS[$_ki]}" == "$_ek" ]] && _FWB_ENABLED_INDICES+=("$_ki") && break
                done
            done
            # Rebuild header format without updated column
            local _hdr_fmt="" _sep_w=0
            local -a _hdr_args=()
            local _first=true
            for _idx in "${_FWB_ENABLED_INDICES[@]}"; do
                [[ "$_first" == "true" ]] && _first=false || { _hdr_fmt+=" "; ((_sep_w++)); }
                _hdr_fmt+="${_FWB_COL_FMTS[$_idx]}"
                _hdr_args+=("${_FWB_COL_LABELS[$_idx]}")
                ((_sep_w += ${_FWB_COL_WIDTHS[$_idx]}))
            done
            _FWB_HDR_FMT="$_hdr_fmt"
            _FWB_HDR_ARGS=("${_hdr_args[@]}")
            _FWB_SEP_WIDTH=$_sep_w
        fi
    fi

    # Table header
    printf "${BOLD}${_FWB_HDR_FMT}${NC}\n" "${_FWB_HDR_ARGS[@]}"
    print_separator $_FWB_SEP_WIDTH

    # Display bundles
    local _fw_idx=0
    declare -A FW_BUNDLE_MAP=()
    rm -f "${TEMP_DIR}/fw_bundle_map_$$" 2>/dev/null

    while IFS='|' read -r _fwid _fwstate _fwname _fwdesc _fwcreated _fwupdated; do
        [[ -z "$_fwid" ]] && continue
        ((_fw_idx++))

        # Write to temp file for map (subshell can't set parent vars)
        echo "${_fw_idx}|${_fwid}" >> "${TEMP_DIR}/fw_bundle_map_$$"

        local _state_color="$WHITE"
        case "$_fwstate" in
            ACTIVE) _state_color="$GREEN" ;;
            DEPRECATED) _state_color="$YELLOW" ;;
            DELETED|FAILED) _state_color="$RED" ;;
        esac

        # Indicator: current / target from fabric — append to OCID
        local _indicator=""
        [[ "$_fwid" == "$_current_fw" ]] && _indicator="  ← current"
        [[ "$_fwid" == "$_target_fw" && "$_target_fw" != "$_current_fw" ]] && _indicator="  ← target"
        local _ocid_display="${_fwid}${_indicator}"

        # Truncate timestamps to date portion (YYYY-MM-DD HH:MM)
        local _created_short="${_fwcreated:0:16}"
        [[ "$_fwcreated" == "N/A" ]] && _created_short="N/A"
        local _updated_short="${_fwupdated:0:16}"
        [[ "$_fwupdated" == "N/A" ]] && _updated_short="N/A"

        _col_print_row "FWB" "$_fw_idx" "$_fwstate" "${_fwname:0:35}" "$_created_short" "$_updated_short" "$_fwdesc" "$_ocid_display" "$_state_color"
    done < "$_fw_parsed"
    rm -f "$_fw_parsed" 2>/dev/null

    # Restore updated column if it was temporarily hidden
    if [[ "$_updated_was_enabled" == "true" && "$_has_updated" == "false" ]]; then
        _col_load "FWB"
    fi

    # Read map from temp file
    if [[ -f "${TEMP_DIR}/fw_bundle_map_$$" ]]; then
        while IFS='|' read -r _mi _mocid; do
            FW_BUNDLE_MAP[$_mi]="$_mocid"
        done < "${TEMP_DIR}/fw_bundle_map_$$"
        rm -f "${TEMP_DIR}/fw_bundle_map_$$"
    fi

    # Hidden columns notice
    if [[ $_FWB_COL_COUNT -lt ${#_FWB_COL_KEYS[@]} ]]; then
        local _hid=() _htotal=${#_FWB_COL_KEYS[@]}
        for _hk in "${_FWB_COL_KEYS[@]}"; do
            local _found=false
            for _ek in "${_FWB_ENABLED_COLS[@]}"; do [[ "$_hk" == "$_ek" ]] && _found=true && break; done
            [[ "$_found" == "false" ]] && _hid+=("$_hk")
        done
        echo -e "  ${GRAY}Hidden columns (${#_hid[@]}/${_htotal}): ${_hid[*]}  — use ${NC}col${GRAY} to configure${NC}"
    fi
    echo ""

    # ── Action loop ──
    while true; do
        echo -e "  ${YELLOW}#${NC}) View bundle    ${GREEN}all${NC}) Expand all    ${GREEN}overview${NC}) Firmware overview    ${GREEN}update${NC}) Update    ${GREEN}col${NC}) Columns    ${CYAN}Enter${NC}) Return"
        _ui_prompt "Firmware" "#, all, overview, update, col, Enter"
        local _fwsel
        read -r _fwsel

        [[ -z "$_fwsel" ]] && return
        [[ "${_fwsel:-}" == :* ]] && _nav_try_jump "$_fwsel" && return

        case "$_fwsel" in
            update|UPDATE)
                _fw_update_fabric_firmware "$selected_platform" "$_fw_json"
                return  # Return to GPU menu to refresh display
                ;;
            overview|OVERVIEW|ov|OV)
                _fw_overview "$_fw_json"
                continue
                ;;
            all|ALL)
                _fw_view_all_expanded "$_fw_json" "$_current_fw" "$_target_fw"
                continue
                ;;
            col|COL|columns|COLUMNS)
                _col_picker "FWB" "Firmware Bundles"
                return  # Return to re-render with new columns
                ;;
            show|SHOW) continue ;;
            *)
                if [[ "$_fwsel" =~ ^[0-9]+$ && -n "${FW_BUNDLE_MAP[$_fwsel]:-}" ]]; then
                    _fw_view_bundle_detail "${FW_BUNDLE_MAP[$_fwsel]}"
                    continue
                elif [[ "$_fwsel" == ocid1.firmwarebundle.* || "$_fwsel" == ocid1.* ]]; then
                    _fw_view_bundle_detail "$_fwsel"
                    continue
                fi
                echo -e "  ${RED}Invalid selection${NC}"
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Firmware Overview — Fabric → Cluster → Current/Target FW → Available Upgrades
# Args: $1 = firmware list JSON (for available bundles)
# Uses: FABRIC_CACHE, CLUSTER_CACHE
#--------------------------------------------------------------------------------
_fw_overview() {
    local _fw_json="$1"

    echo ""
    _ui_subheader "Firmware Overview" 0
    echo ""

    if [[ ! -f "$FABRIC_CACHE" ]]; then
        echo -e "  ${RED}No GPU Memory Fabrics cached. Return to GPU menu and refresh first.${NC}"
        _ui_pause "return"
        return
    fi

    # ── Build available bundles lookup: OCID → display-name ──
    declare -A _bname_map=()
    if [[ -n "$_fw_json" ]]; then
        while IFS='|' read -r _bid _bname; do
            [[ -n "$_bid" && "$_bid" != "N/A" ]] && _bname_map["$_bid"]="$_bname"
        done < <(jq -r '.data.items[] | "\(.id // "N/A")|\(.["display-name"] // "N/A")"' <<< "$_fw_json" 2>/dev/null)
    fi

    # ── Build cluster lookup: fabric_suffix → cluster lines ──
    declare -A _cluster_by_fabric=()
    if [[ -f "$CLUSTER_CACHE" ]]; then
        while IFS='|' read -r _cocid _cname _cstate _cfabsuf _cinstconf _ccompclust _csize; do
            [[ -z "$_cocid" || "$_cocid" == \#* ]] && continue
            _cluster_by_fabric["$_cfabsuf"]+="${_cname}|${_cstate}|${_csize}|${_cocid}"$'\n'
        done < <(grep -v "^#" "$CLUSTER_CACHE")
    fi

    # ── Available upgrade bundles (ACTIVE only, sorted by display-name) ──
    local -a _avail_ids=() _avail_names=()
    if [[ -n "$_fw_json" ]]; then
        while IFS='|' read -r _aid _aname; do
            [[ -n "$_aid" && "$_aid" != "N/A" ]] && _avail_ids+=("$_aid") && _avail_names+=("$_aname")
        done < <(jq -r '.data.items[] | select(.["lifecycle-state"] == "ACTIVE") | "\(.id)|\(.["display-name"] // "N/A")"' <<< "$_fw_json" 2>/dev/null | sort -t'|' -k2,2)
    fi

    # ── Iterate fabrics ──
    local _fidx=0
    while IFS='|' read -r _fname _flast5 _focid _fstate _fhealthy _favail _ftotal _fcurfw _ftarfw _ffwstate; do
        [[ -z "$_fname" ]] && continue
        ((_fidx++))

        local _fsc="$WHITE"
        case "$_fstate" in
            ACTIVE|AVAILABLE) _fsc="$GREEN" ;;
            PROVISIONING|UPDATING) _fsc="$YELLOW" ;;
            *) _fsc="$RED" ;;
        esac

        # Fabric header
        echo -e "  ${BOLD}${ORANGE}Fabric ${_fidx}:${NC} ${WHITE}${_fname}${NC}  ${_fsc}[${_fstate}]${NC}  ${GRAY}Hosts: ${_fhealthy}/${_ftotal} healthy${NC}"
        echo -e "  ${GRAY}OCID: ${_focid}${NC}"

        # Firmware state
        local _fwsc
        _fwsc=$(color_firmware_state "$_ffwstate")
        echo -e "  ${WHITE}Firmware State:${NC}   ${_fwsc}${_ffwstate}${NC}"

        # Current firmware
        if [[ "$_fcurfw" != "N/A" && -n "$_fcurfw" ]]; then
            local _cur_name="${_bname_map[$_fcurfw]:-}"
            if [[ -n "$_cur_name" ]]; then
                echo -e "  ${WHITE}Current Bundle:${NC}   ${GREEN}${_cur_name}${NC}"
                echo -e "  ${GRAY}                  ${_fcurfw}${NC}"
            else
                echo -e "  ${WHITE}Current Bundle:${NC}   ${GREEN}${_fcurfw}${NC}"
            fi
        else
            echo -e "  ${WHITE}Current Bundle:${NC}   ${GRAY}N/A${NC}"
        fi

        # Target firmware (only if different from current)
        if [[ "$_ftarfw" != "N/A" && -n "$_ftarfw" && "$_ftarfw" != "$_fcurfw" ]]; then
            local _tar_name="${_bname_map[$_ftarfw]:-}"
            if [[ -n "$_tar_name" ]]; then
                echo -e "  ${WHITE}Target Bundle:${NC}    ${YELLOW}${_tar_name}${NC}"
                echo -e "  ${GRAY}                  ${_ftarfw}${NC}"
            else
                echo -e "  ${WHITE}Target Bundle:${NC}    ${YELLOW}${_ftarfw}${NC}"
            fi
        fi

        # GPU Memory Clusters under this fabric
        local _clusters="${_cluster_by_fabric[$_flast5]:-}"
        if [[ -n "$_clusters" ]]; then
            echo ""
            echo -e "  ${WHITE}GPU Memory Clusters:${NC}"
            while IFS='|' read -r _cname _cstate _csize _cocid; do
                [[ -z "$_cname" ]] && continue
                local _csc="$WHITE"
                case "$_cstate" in
                    ACTIVE) _csc="$GREEN" ;;
                    UPDATING|SCALING|CREATING) _csc="$YELLOW" ;;
                    *) _csc="$RED" ;;
                esac
                echo -e "    ${GRAY}├──${NC} ${WHITE}${_cname}${NC}  ${_csc}[${_cstate}]${NC}  ${GRAY}Size: ${_csize}${NC}"
                echo -e "    ${GRAY}│   ${_cocid}${NC}"
            done <<< "$_clusters"
        fi

        # Available upgrade bundles for this fabric
        if [[ ${#_avail_ids[@]} -gt 0 ]]; then
            echo ""
            echo -e "  ${WHITE}Available Bundles:${NC}"
            for _ai in "${!_avail_ids[@]}"; do
                local _badge=""
                if [[ "${_avail_ids[$_ai]}" == "$_fcurfw" ]]; then
                    _badge=" ${GREEN}← current${NC}"
                elif [[ "${_avail_ids[$_ai]}" == "$_ftarfw" && "$_ftarfw" != "$_fcurfw" ]]; then
                    _badge=" ${YELLOW}← target${NC}"
                fi
                echo -e "    ${GRAY}•${NC} ${_avail_names[$_ai]}${_badge}"
            done
        fi

        echo ""
        print_separator 100
        echo ""
    done < <(grep -v "^#" "$FABRIC_CACHE")

    if [[ $_fidx -eq 0 ]]; then
        echo -e "  ${YELLOW}No GPU Memory Fabrics found in cache.${NC}"
    fi

    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Firmware Bundle — Expand all bundles showing firmware components
# Args: $1 = firmware list JSON, $2 = current_fw OCID, $3 = target_fw OCID
#--------------------------------------------------------------------------------
_fw_view_all_expanded() {
    local _fw_json="$1" _current_fw="${2:-}" _target_fw="${3:-}"

    echo ""
    _ui_subheader "All Firmware Bundles — Expanded" 0
    echo ""

    local _bcount
    _bcount=$(jq -r '.data.items | length // 0' <<< "$_fw_json" 2>/dev/null)

    local _bi=0
    jq -r '.data.items | sort_by(.["display-name"])[] | @base64' <<< "$_fw_json" 2>/dev/null | while IFS= read -r _b64; do
        local _bdata
        _bdata=$(echo "$_b64" | base64 -d 2>/dev/null)
        [[ -z "$_bdata" ]] && continue
        ((_bi++))

        local _bid _bstate _bname _bdesc _bcreated
        _bid=$(jq -r '.id // "N/A"' <<< "$_bdata")
        _bstate=$(jq -r '.["lifecycle-state"] // "N/A"' <<< "$_bdata")
        _bname=$(jq -r '.["display-name"] // "N/A"' <<< "$_bdata")
        _bdesc=$(jq -r '.description // "N/A"' <<< "$_bdata")
        _bcreated=$(jq -r '.["time-created"] // "N/A"' <<< "$_bdata")

        local _state_color="$WHITE"
        case "$_bstate" in
            ACTIVE) _state_color="$GREEN" ;;
            DEPRECATED) _state_color="$YELLOW" ;;
            DELETED|FAILED) _state_color="$RED" ;;
        esac

        local _indicator=""
        [[ "$_bid" == "$_current_fw" ]] && _indicator="  ${GREEN}← current${NC}"
        [[ "$_bid" == "$_target_fw" && "$_target_fw" != "$_current_fw" ]] && _indicator="  ${YELLOW}← target${NC}"

        echo -e "  ${YELLOW}${_bi}${NC}) ${_state_color}[${_bstate}]${NC} ${WHITE}${_bname}${NC}${_indicator}"
        echo -e "     ${GRAY}${_bdesc}${NC}"
        echo -e "     ${GRAY}Created: ${_bcreated:0:16}  OCID: ${_bid}${NC}"

        # Platforms → versions tree
        local _plat_count
        _plat_count=$(jq -r '.platforms | length // 0' <<< "$_bdata" 2>/dev/null)
        if [[ "$_plat_count" -gt 0 ]]; then
            local _pi=0
            while [[ $_pi -lt $_plat_count ]]; do
                local _pname
                _pname=$(jq -r ".platforms[$_pi].platform // \"N/A\"" <<< "$_bdata")
                echo -e "     ${CYAN}${_pname}${NC}"

                local _ver_count
                _ver_count=$(jq -r ".platforms[$_pi].versions | length // 0" <<< "$_bdata" 2>/dev/null)
                local _vi=0
                while [[ $_vi -lt $_ver_count ]]; do
                    local _ctype _vers
                    _ctype=$(jq -r ".platforms[$_pi].versions[$_vi][\"component-type\"] // \"N/A\"" <<< "$_bdata")
                    _vers=$(jq -r ".platforms[$_pi].versions[$_vi].version // [] | join(\", \")" <<< "$_bdata")
                    local _branch="├──"
                    [[ $((_vi+1)) -eq $_ver_count ]] && _branch="└──"
                    echo -e "       ${GRAY}${_branch}${NC} ${WHITE}${_ctype}${NC}: ${GREEN}${_vers}${NC}"
                    ((_vi++))
                done
                ((_pi++))
            done
        fi
        echo ""
    done

    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Firmware Bundle — View detailed info for a single bundle
#--------------------------------------------------------------------------------
_fw_view_bundle_detail() {
    local bundle_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Firmware Bundle Details" 0

    _step_init
    _step_active "firmware bundle"
    local _detail_json
    _detail_json=$(oci compute firmware-bundle get \
        --firmware-bundle-id "$bundle_id" \
        --output json 2>/dev/null)
    _step_complete "firmware bundle"
    _step_finish

    if [[ -z "$_detail_json" ]]; then
        echo -e "  ${RED}Failed to fetch firmware bundle details${NC}"
        echo -e "  ${WHITE}OCID:${NC} ${YELLOW}${bundle_id}${NC}"
        _ui_policy_hint "read firmware-bundles"
        return
    fi

    echo ""
    echo -e "  ${WHITE}OCID:${NC}            ${YELLOW}$(jq -r '.data.id // "N/A"' <<< "$_detail_json")${NC}"

    # Display fields matching real API structure
    local _state _dname _desc _created _updated
    _state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$_detail_json")
    _dname=$(jq -r '.data["display-name"] // "N/A"' <<< "$_detail_json")
    _desc=$(jq -r '.data.description // "N/A"' <<< "$_detail_json")
    _created=$(jq -r '.data["time-created"] // "N/A"' <<< "$_detail_json")
    _updated=$(jq -r '.data["time-updated"] // "N/A"' <<< "$_detail_json")

    local _state_color="$WHITE"
    case "$_state" in
        ACTIVE) _state_color="$GREEN" ;;
        DEPRECATED) _state_color="$YELLOW" ;;
        DELETED|FAILED) _state_color="$RED" ;;
    esac

    echo -e "  ${WHITE}State:${NC}           ${_state_color}${_state}${NC}"
    echo -e "  ${WHITE}Display Name:${NC}    ${CYAN}${_dname}${NC}"
    echo -e "  ${WHITE}Description:${NC}     ${_desc}"
    echo -e "  ${WHITE}Time Created:${NC}    ${_created}"
    echo -e "  ${WHITE}Time Updated:${NC}    ${_updated}"

    # Show platforms → versions component tree
    local _plat_count
    _plat_count=$(jq -r '.data.platforms | length // 0' <<< "$_detail_json" 2>/dev/null)
    if [[ "$_plat_count" -gt 0 ]]; then
        echo ""
        echo -e "  ${BOLD}${WHITE}Platforms & Firmware Components:${NC}"
        local _pi=0
        while [[ $_pi -lt $_plat_count ]]; do
            local _pname
            _pname=$(jq -r ".data.platforms[$_pi].platform // \"N/A\"" <<< "$_detail_json")
            echo -e "    ${CYAN}${_pname}${NC}"

            local _ver_count
            _ver_count=$(jq -r ".data.platforms[$_pi].versions | length // 0" <<< "$_detail_json" 2>/dev/null)
            local _vi=0
            while [[ $_vi -lt $_ver_count ]]; do
                local _ctype _vers
                _ctype=$(jq -r ".data.platforms[$_pi].versions[$_vi][\"component-type\"] // \"N/A\"" <<< "$_detail_json")
                _vers=$(jq -r ".data.platforms[$_pi].versions[$_vi].version // [] | join(\", \")" <<< "$_detail_json")
                local _branch="├──"
                [[ $((_vi+1)) -eq $_ver_count ]] && _branch="└──"
                echo -e "      ${GRAY}${_branch}${NC} ${WHITE}${_ctype}${NC}: ${GREEN}${_vers}${NC}"
                ((_vi++))
            done
            ((_pi++))
        done
    fi

    # Show release notes if present
    local _notes
    _notes=$(jq -r '.data["release-notes"] // empty' <<< "$_detail_json" 2>/dev/null)
    if [[ -n "$_notes" && "$_notes" != "null" ]]; then
        echo ""
        echo -e "  ${BOLD}${WHITE}Release Notes:${NC}"
        echo -e "  ${GRAY}${_notes}${NC}"
    fi

    echo ""
    while true; do
        echo -e "  ${YELLOW}j${NC}) Raw JSON    ${CYAN}Enter${NC}) Return"
        _ui_prompt "Bundle Detail" "j, Enter"
        local _dsel
        read -r _dsel
        [[ -z "$_dsel" ]] && return
        case "$_dsel" in
            j|J|json|JSON)
                echo ""
                echo -e "  ${GRAY}─── Raw JSON ───${NC}"
                jq '.data' <<< "$_detail_json" 2>/dev/null | sed 's/^/  /'
                echo ""
                ;;
            show|SHOW) continue ;;
            *) return ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Firmware Bundle — Update fabric firmware (set desired firmware bundle)
# Args: $1 = platform, $2 = firmware list JSON (reuse from parent)
# Uses: FABRIC_INDEX_MAP, FABRIC_CACHE
# Command: oci compute compute-gpu-memory-fabric update
#   --compute-gpu-memory-fabric-id <fabric-ocid>
#   --memory-fabric-preferences '{"customerDesiredFirmwareBundleId":"<bundle>",...}'
#--------------------------------------------------------------------------------
_fw_update_fabric_firmware() {
    local _platform="$1"
    local _fw_json="$2"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/firmware_update_actions_$(date +%Y%m%d).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    echo ""
    _ui_subheader "Update Fabric Firmware" 0
    echo ""

    # ── Step 1: Select GPU Memory Fabric ──
    # Build fabric list from cache
    if [[ ! -f "$FABRIC_CACHE" ]]; then
        echo -e "  ${RED}No GPU Memory Fabrics cached. Return to GPU menu and refresh first.${NC}"
        _ui_pause "return"
        return
    fi

    local -a _fab_names=() _fab_ocids=() _fab_states=() _fab_curfw=() _fab_tarfw=() _fab_fwstates=()
    local _fidx=0
    while IFS='|' read -r _fn _fsuf _focid _fstate _fhealthy _favail _ftotal _fcurfw _ftarfw _ffwstate; do
        [[ -z "$_focid" ]] && continue
        ((_fidx++))
        _fab_names+=("$_fn")
        _fab_ocids+=("$_focid")
        _fab_states+=("$_fstate")
        _fab_curfw+=("$_fcurfw")
        _fab_tarfw+=("$_ftarfw")
        _fab_fwstates+=("$_ffwstate")
    done < <(grep -v "^#" "$FABRIC_CACHE")

    if [[ $_fidx -eq 0 ]]; then
        echo -e "  ${RED}No GPU Memory Fabrics found in cache.${NC}"
        _ui_pause "return"
        return
    fi

    # Find the latest ACTIVE bundle OCID (last by display-name sort) for upgrade comparison
    local _latest_bundle=""
    _latest_bundle=$(jq -r '[.data.items[] | select(.["lifecycle-state"] == "ACTIVE")] | sort_by(.["display-name"]) | last | .id // ""' <<< "$_fw_json" 2>/dev/null)

    echo -e "  ${BOLD}${WHITE}Select GPU Memory Fabric:${NC}"
    echo ""
    for _i in "${!_fab_names[@]}"; do
        local _sc="$WHITE"
        case "${_fab_states[$_i]}" in
            ACTIVE|OCCUPIED) _sc="$GREEN" ;;
            AVAILABLE) _sc="$CYAN" ;;
            PROVISIONING|UPDATING) _sc="$YELLOW" ;;
            *) _sc="$RED" ;;
        esac

        local _fws_badge=""
        if [[ "${_fab_fwstates[$_i]}" != "N/A" && -n "${_fab_fwstates[$_i]}" ]]; then
            local _fwsc
            _fwsc=$(color_firmware_state "${_fab_fwstates[$_i]}")
            _fws_badge="  [${_fwsc}${_fab_fwstates[$_i]}${NC}]"
        fi

        # Upgrade available indicator
        local _upgrade_badge=""
        if [[ -n "$_latest_bundle" && "${_fab_curfw[$_i]}" != "$_latest_bundle" && "${_fab_curfw[$_i]}" != "N/A" ]]; then
            _upgrade_badge="  ${CYAN}↑ upgrade available${NC}"
        fi

        local _fw_inline=""
        if [[ "${_fab_curfw[$_i]}" != "N/A" && -n "${_fab_curfw[$_i]}" ]]; then
            _fw_inline="  ${YELLOW}${_fab_curfw[$_i]}${NC}"
        fi

        printf "    ${GREEN}%2d${NC}) ${WHITE}%-30s${NC} ${_sc}%-12s${NC}${_fws_badge}${_fw_inline}${_upgrade_badge}\n" \
            "$((_i+1))" "${_fab_names[$_i]}" "${_fab_states[$_i]}"
    done

    echo ""
    echo -n -e "  ${CYAN}Select fabric #: ${NC}"
    local _fsel
    read -r _fsel
    [[ -z "$_fsel" ]] && return

    if ! [[ "$_fsel" =~ ^[0-9]+$ ]] || [[ $((_fsel-1)) -ge $_fidx || $((_fsel-1)) -lt 0 ]]; then
        echo -e "  ${RED}Invalid selection${NC}"
        sleep 1
        return
    fi

    local _sel_idx=$((_fsel-1))
    local _sel_fabric_name="${_fab_names[$_sel_idx]}"
    local _sel_fabric_ocid="${_fab_ocids[$_sel_idx]}"
    local _sel_cur_fw="${_fab_curfw[$_sel_idx]}"

    echo ""
    echo -e "  ${WHITE}Fabric:${NC}           ${ORANGE}${_sel_fabric_name}${NC}"
    echo -e "  ${WHITE}OCID:${NC}             ${YELLOW}${_sel_fabric_ocid}${NC}"
    if [[ "$_sel_cur_fw" != "N/A" && -n "$_sel_cur_fw" ]]; then
        echo -e "  ${WHITE}Current Firmware:${NC} ${GREEN}${_sel_cur_fw}${NC}"
    fi

    # ── Step 2: Select Firmware Bundle ──
    echo ""
    echo -e "  ${BOLD}${WHITE}Select target firmware bundle:${NC}"
    echo ""

    # Parse bundles from the JSON (only ACTIVE ones for update)
    local -a _bun_ids=() _bun_names=() _bun_descs=()
    local _bidx=0
    while IFS='|' read -r _bid _bstate _bname _bdesc; do
        [[ -z "$_bid" || "$_bstate" != "ACTIVE" ]] && continue
        ((_bidx++))
        _bun_ids+=("$_bid")
        _bun_names+=("$_bname")
        _bun_descs+=("$_bdesc")
    done < <(jq -r '.data.items[] | "\(.id // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.["display-name"] // "N/A")|\(.description // "N/A")"' <<< "$_fw_json" 2>/dev/null | sort -t'|' -k3,3)

    if [[ $_bidx -eq 0 ]]; then
        echo -e "  ${RED}No ACTIVE firmware bundles available for this platform.${NC}"
        _ui_pause "return"
        return
    fi

    for _i in "${!_bun_ids[@]}"; do
        local _cur_badge=""
        [[ "${_bun_ids[$_i]}" == "$_sel_cur_fw" ]] && _cur_badge=" ${GREEN}← current${NC}"

        printf "    ${GREEN}%2d${NC}) ${WHITE}%s${NC}  ${YELLOW}%s${NC}  ${GRAY}%s${NC}%b\n" \
            "$((_i+1))" "${_bun_names[$_i]}" "${_bun_ids[$_i]}" "${_bun_descs[$_i]}" "$_cur_badge"
    done

    echo ""
    echo -n -e "  ${CYAN}Select bundle #: ${NC}"
    local _bsel
    read -r _bsel
    [[ -z "$_bsel" ]] && return

    if ! [[ "$_bsel" =~ ^[0-9]+$ ]] || [[ $((_bsel-1)) -ge $_bidx || $((_bsel-1)) -lt 0 ]]; then
        echo -e "  ${RED}Invalid selection${NC}"
        sleep 1
        return
    fi

    local _sel_bundle="${_bun_ids[$((_bsel-1))]}"
    local _sel_bundle_name="${_bun_names[$((_bsel-1))]}"

    # Check if same as current
    if [[ "$_sel_bundle" == "$_sel_cur_fw" ]]; then
        echo -e "  ${YELLOW}Selected bundle is already the current firmware on this fabric.${NC}"
        _ui_pause "return"
        return
    fi

    # ── Step 3: Select recycle level ──
    echo ""
    echo -e "  ${BOLD}${WHITE}Select fabric recycle level:${NC}"
    echo ""
    echo -e "    ${GREEN}1${NC}) FULL_RECYCLE     ${GRAY}- Full fabric recycle (recommended)${NC}"
    echo -e "    ${GREEN}2${NC}) NO_RECYCLE        ${GRAY}- No recycle (apply on next maintenance)${NC}"
    echo ""
    echo -n -e "  ${CYAN}Select # [1]: ${NC}"
    local _rsel
    read -r _rsel
    local _recycle_level="FULL_RECYCLE"
    [[ "$_rsel" == "2" ]] && _recycle_level="NO_RECYCLE"

    # ── Step 4: Confirm and execute ──
    echo ""
    echo -e "  ${BOLD}${WHITE}── Update Summary ──${NC}"
    echo -e "  ${WHITE}Fabric:${NC}          ${ORANGE}${_sel_fabric_name}${NC}"
    echo -e "  ${WHITE}Fabric OCID:${NC}     ${YELLOW}${_sel_fabric_ocid}${NC}"
    echo -e "  ${WHITE}Target Bundle:${NC}   ${CYAN}${_sel_bundle_name}${NC}"
    echo -e "  ${WHITE}Bundle OCID:${NC}     ${GRAY}${_sel_bundle}${NC}"
    echo -e "  ${WHITE}Recycle Level:${NC}   ${YELLOW}${_recycle_level}${NC}"
    if [[ "$_sel_cur_fw" != "N/A" && -n "$_sel_cur_fw" ]]; then
        echo -e "  ${WHITE}Current Bundle:${NC}  ${GRAY}${_sel_cur_fw}${NC}"
    fi
    echo ""

    local _prefs_json
    _prefs_json=$(jq -n --arg bid "$_sel_bundle" --arg rl "$_recycle_level" \
        '{"customerDesiredFirmwareBundleId": $bid, "fabricRecycleLevel": $rl}')
    local _cmd="oci compute compute-gpu-memory-fabric update --compute-gpu-memory-fabric-id ${_sel_fabric_ocid} --memory-fabric-preferences '${_prefs_json}' --region ${region} --force"

    echo -e "  ${BOLD}${WHITE}Command:${NC}"
    echo -e "  ${GRAY}${_cmd}${NC}"
    echo ""
    echo -n -e "  ${RED}${BOLD}Proceed? (yes/no): ${NC}"
    local _confirm
    read -r _confirm

    if [[ "$_confirm" != "yes" && "$_confirm" != "YES" && "$_confirm" != "y" ]]; then
        echo -e "  ${YELLOW}Cancelled.${NC}"
        return
    fi

    # Log the action
    log_action "UPDATE_FIRMWARE" "$_cmd" --context "Fabric: ${_sel_fabric_name}, Bundle: ${_sel_bundle}, Recycle: ${_recycle_level}"
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] UPDATE FIRMWARE: $_cmd" >> "$log_file"

    # Execute
    local _result
    _result=$(oci compute compute-gpu-memory-fabric update \
        --compute-gpu-memory-fabric-id "$_sel_fabric_ocid" \
        --memory-fabric-preferences "$_prefs_json" \
        --region "$region" \
        --force \
        --output json 2>&1)
    local _rc=$?

    if [[ $_rc -eq 0 ]] && jq -e '.data' <<< "$_result" > /dev/null 2>&1; then
        echo -e "  ${GREEN}✓ Firmware update initiated successfully${NC}"
        local _new_state
        _new_state=$(jq -r '.data["firmware-update-state"] // "N/A"' <<< "$_result" 2>/dev/null)
        local _new_target
        _new_target=$(jq -r '.data["target-firmware-bundle-id"] // "N/A"' <<< "$_result" 2>/dev/null)
        echo -e "  ${WHITE}Firmware Update State:${NC} $(color_firmware_state "$_new_state")${_new_state}${NC}"
        echo -e "  ${WHITE}Target Firmware:${NC}       ${YELLOW}${_new_target}${NC}"
        log_action_result "SUCCESS" "Firmware update initiated for ${_sel_fabric_name}: target=${_sel_bundle}, recycle=${_recycle_level}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Firmware update initiated for ${_sel_fabric_name}" >> "$log_file"

        # Invalidate fabric cache so it refreshes on next view
        rm -f "$FABRIC_CACHE"
    else
        echo -e "  ${RED}✗ Failed to update fabric firmware${NC}"
        echo -e "  ${GRAY}${_result}${NC}"
        log_action_result "FAILED" "Firmware update failed for ${_sel_fabric_name}: ${_result}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${_result}" >> "$log_file"
    fi

    echo ""
    _ui_pause "return"
}

# Create GPU Memory Cluster interactively
create_gpu_memory_cluster_interactive() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Create GPU Memory Cluster" 0
    echo ""
    
    # ── Refresh data from OCI ──
    rm -f "$FABRIC_CACHE" "$CLUSTER_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE" "$INSTANCE_CONFIG_CACHE" "$COMPUTE_CLUSTER_CACHE"
    _step_init
    _step_active "fabrics"
    fetch_gpu_fabrics
    local _fabric_count
    _fabric_count=$(_clc "$FABRIC_CACHE")
    _step_complete "fabrics(${_fabric_count})"
    
    if [[ "${_fabric_count:-0}" -eq 0 ]]; then
        _step_finish
        echo ""
        echo -e "${RED}No GPU Memory Fabrics found. Cannot create cluster.${NC}"
        _ui_pause
        return 1
    fi
    
    _step_active "GPU clusters"
    fetch_gpu_clusters
    _step_complete "GPU clusters($(_clc "$CLUSTER_CACHE"))"
    _step_active "instance configs"
    fetch_instance_configurations
    _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    _step_active "compute clusters"
    fetch_compute_clusters
    _step_complete "compute clusters($(_clc "$COMPUTE_CLUSTER_CACHE"))"
    _step_finish
    
    # Rebuild index maps
    display_gpu_management_menu > /dev/null 2>&1
    
    echo ""
    echo -e "${WHITE}GPU Memory Fabrics with Available Capacity:${NC}"
    echo ""
    printf "${BOLD}%-6s %-45s %-12s %8s %6s %6s  %-90s${NC}\n" \
        "ID" "Fabric Name" "State" "Healthy" "Avail" "Total" "Fabric OCID"
    print_separator 180
    
    local has_available=false
    local fabric_output_temp
    fabric_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    # Build map of fabric availability for later use
    declare -A FABRIC_AVAIL_MAP
    
    local fid
    for fid in "${!FABRIC_INDEX_MAP[@]}"; do
        local fabric_ocid="${FABRIC_INDEX_MAP[$fid]}"
        [[ -z "$fabric_ocid" ]] && continue
        
        # Get fabric info from cache
        local fabric_line
        fabric_line=$(grep "^[^#].*|${fabric_ocid}|" "$FABRIC_CACHE" 2>/dev/null | head -1)
        [[ -z "$fabric_line" ]] && fabric_line=$(grep -F "${fabric_ocid}" "$FABRIC_CACHE" 2>/dev/null | head -1)
        
        if [[ -n "$fabric_line" ]]; then
            local f_name f_suffix f_ocid f_state f_healthy f_avail f_total
            IFS='|' read -r f_name f_suffix f_ocid f_state f_healthy f_avail f_total _ _ _ <<< "$fabric_line"
            
            # Only include fabrics with available capacity
            if [[ "$f_avail" != "0" && "$f_avail" != "N/A" && -n "$f_avail" && "$f_avail" -gt 0 ]] 2>/dev/null; then
                has_available=true
                FABRIC_AVAIL_MAP[$fid]="$f_avail"
                
                # Store for sorting (numeric key|display data including OCID)
                local fid_num="${fid#f}"
                echo "${fid_num}|${fid}|${f_name}|${f_state}|${f_healthy}|${f_avail}|${f_total}|${fabric_ocid}" >> "$fabric_output_temp"
            fi
        fi
    done
    
    # Sort and display
    sort -t'|' -k1 -n "$fabric_output_temp" | while IFS='|' read -r _ fid f_name f_state f_healthy f_avail f_total f_ocid; do
        # State color
        local state_color="$GREEN"
        [[ "$f_state" != "AVAILABLE" && "$f_state" != "OCCUPIED" ]] && state_color="$RED"
        
        printf "${YELLOW}%-6s${NC} ${CYAN}%-45s${NC} ${state_color}%-12s${NC} %8s ${LIGHT_GREEN}%6s${NC} %6s  ${GRAY}%-90s${NC}\n" \
            "$fid" "$f_name" "$f_state" "$f_healthy" "$f_avail" "$f_total" "$f_ocid"
    done
    
    rm -f "$fabric_output_temp"
    
    echo ""
    
    if [[ "$has_available" != "true" ]]; then
        echo -e "${RED}No GPU Memory Fabrics have available capacity. Cannot create cluster.${NC}"
        return 1
    fi
    
    # Select Fabric
    echo -n -e "${CYAN}Select GPU Memory Fabric (f#): ${NC}"
    local fabric_input
    read -r fabric_input
    
    local fabric_ocid="${FABRIC_INDEX_MAP[$fabric_input]:-}"
    if [[ -z "$fabric_ocid" ]]; then
        echo -e "${RED}Invalid fabric selection: $fabric_input${NC}"
        return 1
    fi
    
    # Check fabric has availability
    local fabric_avail="${FABRIC_AVAIL_MAP[$fabric_input]:-0}"
    if [[ "$fabric_avail" -eq 0 ]] 2>/dev/null; then
        echo -e "${RED}Selected fabric has no available capacity${NC}"
        return 1
    fi
    
    # Get fabric suffix for display name
    local fabric_suffix="${fabric_ocid: -5}"
    local default_display_name="fabric-${fabric_suffix}"
    
    echo -e "${WHITE}Selected Fabric:${NC} ${YELLOW}$fabric_ocid${NC}"
    echo -e "${WHITE}Available Nodes:${NC} ${LIGHT_GREEN}$fabric_avail${NC}"
    echo ""
    
    # Display Compute Clusters
    echo -e "${WHITE}Available Compute Clusters:${NC}"
    echo ""
    printf "${BOLD}%-6s %-40s %-35s %-12s${NC}\n" \
        "ID" "Compute Cluster Name" "Availability Domain" "Status"
    print_separator 95
    
    local cc_output_temp
    cc_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    local cid
    for cid in "${!CC_INDEX_MAP[@]}"; do
        local cc_ocid="${CC_INDEX_MAP[$cid]}"
        [[ -z "$cc_ocid" ]] && continue
        
        # Get compute cluster info from cache
        local cc_line cc_name cc_ad cc_state
        cc_line=$(_cache_line "$COMPUTE_CLUSTER_CACHE" "$cc_ocid")
        if [[ -n "$cc_line" ]]; then
            IFS='|' read -r _ cc_name cc_ad cc_state <<< "$cc_line"
            # Default state if not present (old cache format)
            [[ -z "$cc_state" ]] && cc_state="UNKNOWN"
        else
            cc_name="N/A"
            cc_ad="N/A"
            cc_state="UNKNOWN"
        fi
        
        # Skip deleted clusters
        [[ "$cc_state" == "DELETED" ]] && continue
        
        local cid_num="${cid#c}"
        echo "${cid_num}|${cid}|${cc_name}|${cc_ad}|${cc_state}" >> "$cc_output_temp"
    done
    
    sort -t'|' -k1 -n "$cc_output_temp" | while IFS='|' read -r _ cid cc_name cc_ad cc_state; do
        # Color-code the status
        local state_color
        state_color=$(color_resource_state "$cc_state")
        printf "${YELLOW}%-6s${NC} ${CYAN}%-40s${NC} ${MAGENTA}%-35s${NC} ${state_color}%-12s${NC}\n" \
            "$cid" "$cc_name" "$cc_ad" "$cc_state"
    done
    
    rm -f "$cc_output_temp"
    
    echo ""
    
    # Select Compute Cluster
    echo -n -e "${CYAN}Select Compute Cluster (c#): ${NC}"
    local cc_input
    read -r cc_input
    
    local cc_ocid="${CC_INDEX_MAP[$cc_input]:-}"
    if [[ -z "$cc_ocid" ]]; then
        echo -e "${RED}Invalid compute cluster selection: $cc_input${NC}"
        return 1
    fi
    
    # Get AD from compute cluster
    local cc_ad
    cc_ad=$(oci compute compute-cluster get \
        --compute-cluster-id "$cc_ocid" \
        --region "$region" \
        --query 'data."availability-domain"' \
        --raw-output 2>/dev/null)
    
    echo -e "${WHITE}Selected Compute Cluster:${NC} ${YELLOW}$cc_ocid${NC}"
    echo -e "${WHITE}Availability Domain:${NC} ${MAGENTA}$cc_ad${NC}"
    echo ""
    
    # Display Instance Configurations
    echo -e "${WHITE}Available Instance Configurations:${NC}"
    echo ""
    printf "${BOLD}%-6s %-60s${NC}\n" \
        "ID" "Instance Configuration Name"
    print_separator 70
    
    local ic_output_temp
    ic_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    local iid
    for iid in "${!IC_INDEX_MAP[@]}"; do
        local ic_ocid="${IC_INDEX_MAP[$iid]}"
        [[ -z "$ic_ocid" ]] && continue
        
        # Get instance config name from cache
        local ic_name
        ic_name=$(get_instance_config_name "$ic_ocid")
        
        local iid_num="${iid#i}"
        echo "${iid_num}|${iid}|${ic_name}" >> "$ic_output_temp"
    done
    
    sort -t'|' -k1 -n "$ic_output_temp" | while IFS='|' read -r _ iid ic_name; do
        printf "${YELLOW}%-6s${NC} ${CYAN}%-60s${NC}\n" \
            "$iid" "$ic_name"
    done
    
    rm -f "$ic_output_temp"
    
    echo ""
    
    # Select Instance Configuration
    echo -n -e "${CYAN}Select Instance Configuration (i#): ${NC}"
    local ic_input
    read -r ic_input
    
    local ic_ocid="${IC_INDEX_MAP[$ic_input]:-}"
    if [[ -z "$ic_ocid" ]]; then
        echo -e "${RED}Invalid instance configuration selection: $ic_input${NC}"
        return 1
    fi
    
    echo -e "${WHITE}Selected Instance Config:${NC} ${YELLOW}$ic_ocid${NC}"
    echo ""
    
    # Enter Size (default 1, max = fabric availability)
    echo -n -e "${CYAN}Enter cluster size (1-${fabric_avail}) [1]: ${NC}"
    local cluster_size
    read -r cluster_size
    cluster_size="${cluster_size:-1}"
    
    if ! [[ "$cluster_size" =~ ^[0-9]+$ ]] || [[ "$cluster_size" -lt 1 ]]; then
        echo -e "${RED}Invalid size: must be a positive integer${NC}"
        return 1
    fi
    
    if [[ "$cluster_size" -gt "$fabric_avail" ]]; then
        echo -e "${RED}Invalid size: requested $cluster_size but only $fabric_avail nodes available${NC}"
        return 1
    fi
    
    # Enter Display Name
    echo -n -e "${CYAN}Enter display name [${default_display_name}]: ${NC}"
    local display_name
    read -r display_name
    display_name="${display_name:-$default_display_name}"
    
    echo ""
    _ui_subheader "Confirm Creation" 0
    echo -e "  ${CYAN}Display Name:${NC}         ${WHITE}$display_name${NC}"
    echo -e "  ${CYAN}Availability Domain:${NC}  ${WHITE}$cc_ad${NC}"
    echo -e "  ${CYAN}Size:${NC}                 ${WHITE}$cluster_size${NC}"
    echo ""
    
    # Show compartment with name
    local comp_name_display
    comp_name_display=$(resolve_compartment_name "$compartment_id")
    echo -e "  ${CYAN}Compartment:${NC}"
    echo -e "    Name: ${WHITE}${comp_name_display}${NC}"
    echo -e "    OCID: ${YELLOW}${compartment_id}${NC}"
    
    # Show compute cluster with name
    local cc_name_display
    cc_name_display=$(oci compute compute-cluster get --compute-cluster-id "$cc_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null || echo "Unknown")
    echo -e "  ${CYAN}Compute Cluster:${NC}"
    echo -e "    Name: ${WHITE}${cc_name_display}${NC}"
    echo -e "    OCID: ${YELLOW}${cc_ocid}${NC}"
    
    # Show instance configuration with name
    local ic_name_display
    ic_name_display=$(oci compute-management instance-configuration get --instance-configuration-id "$ic_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null || echo "Unknown")
    echo -e "  ${CYAN}Instance Config:${NC}"
    echo -e "    Name: ${WHITE}${ic_name_display}${NC}"
    echo -e "    OCID: ${YELLOW}${ic_ocid}${NC}"
    
    # Show GPU memory fabric with name
    local fabric_name_display
    fabric_name_display=$(oci compute compute-gpu-memory-fabric get --compute-gpu-memory-fabric-id "$fabric_ocid" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null || echo "Unknown")
    echo -e "  ${CYAN}GPU Memory Fabric:${NC}"
    echo -e "    Name: ${WHITE}${fabric_name_display}${NC}"
    echo -e "    OCID: ${YELLOW}${fabric_ocid}${NC}"
    echo ""
    
    _ui_subheader "Command to Execute" 0
    echo -e "${GRAY}oci compute compute-gpu-memory-cluster create \\
    --availability-domain \"$cc_ad\" \\
    --compartment-id \"$compartment_id\" \\
    --region \"$region\" \\
    --compute-cluster-id \"$cc_ocid\" \\
    --instance-configuration-id \"$ic_ocid\" \\
    --gpu-memory-fabric-id \"$fabric_ocid\" \\
    --size $cluster_size \\
    --display-name \"$display_name\"${NC}"
    echo ""
    
    echo -n -e "${YELLOW}Proceed with creation? (yes/no): ${NC}"
    local confirm
    read -r confirm
    
    if [[ "$confirm" != "yes" ]]; then
        echo -e "${RED}Creation cancelled${NC}"
        return 0
    fi
    
    echo ""
    echo -e "${GREEN}Creating GPU Memory Cluster...${NC}"
    
    # Create the cluster
    local result
    log_action "CREATE" "oci compute compute-gpu-memory-cluster create"
    result=$(oci compute compute-gpu-memory-cluster create \
        --availability-domain "$cc_ad" \
        --compartment-id "$compartment_id" \
        --region "$region" \
        --compute-cluster-id "$cc_ocid" \
        --instance-configuration-id "$ic_ocid" \
        --gpu-memory-fabric-id "$fabric_ocid" \
        --size "$cluster_size" \
        --display-name "$display_name" \
        --output json 2>&1)
    
    if [[ $? -eq 0 ]]; then
        echo -e "${GREEN}GPU Memory Cluster creation initiated successfully!${NC}"
        log_action_result "SUCCESS" "CREATE operation"
        echo ""
        local new_cluster_id
        new_cluster_id=$(jq -r '.data.id // "N/A"' <<< "$result")
        local new_cluster_state
        new_cluster_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$result")
        
        echo -e "${WHITE}New Cluster OCID:${NC}  ${YELLOW}$new_cluster_id${NC}"
        echo -e "${WHITE}Initial State:${NC}     ${CYAN}$new_cluster_state${NC}"
        
        # Invalidate cluster, fabric, and instance-cluster map caches
        rm -f "$CLUSTER_CACHE" "$FABRIC_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE"
    else
        echo -e "${RED}Failed to create GPU Memory Cluster:${NC}"
        log_action_result "FAILED" "CREATE operation"
        echo "$result"
        return 1
    fi
}

# Update GPU Memory Cluster interactively
update_gpu_memory_cluster_interactive() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Update GPU Memory Cluster(s)" 0
    echo ""
    
    # ── Refresh data from OCI ──
    rm -f "$FABRIC_CACHE" "$CLUSTER_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE" "$INSTANCE_CONFIG_CACHE" "$COMPUTE_CLUSTER_CACHE"
    _step_init
    _step_active "fabrics"
    fetch_gpu_fabrics
    local _fabric_count
    _fabric_count=$(_clc "$FABRIC_CACHE")
    _step_complete "fabrics(${_fabric_count})"
    
    if [[ "${_fabric_count:-0}" -eq 0 ]]; then
        _step_finish
        echo ""
        echo -e "${RED}No GPU Memory Fabrics found. Nothing to update.${NC}"
        _ui_pause
        return 1
    fi
    
    _step_active "GPU clusters"
    fetch_gpu_clusters
    local _cluster_count
    _cluster_count=$(_clc "$CLUSTER_CACHE")
    _step_complete "GPU clusters(${_cluster_count})"
    
    if [[ "${_cluster_count:-0}" -eq 0 ]]; then
        _step_finish
        echo ""
        echo -e "${RED}No GPU Memory Clusters found. Nothing to update.${NC}"
        _ui_pause
        return 1
    fi
    
    _step_active "instance configs"
    fetch_instance_configurations
    _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    _step_active "compute clusters"
    fetch_compute_clusters
    _step_complete "compute clusters($(_clc "$COMPUTE_CLUSTER_CACHE"))"
    _step_finish
    
    # Rebuild index maps
    display_gpu_management_menu > /dev/null 2>&1
    
    echo ""
    
    # List available GPU Memory Clusters
    echo -e "${WHITE}Available GPU Memory Clusters:${NC}"
    echo ""
    printf "${BOLD}%-6s %-35s %-10s %6s  %-40s %8s %6s %6s${NC}\n" \
        "ID" "Cluster Name" "State" "Size" "Fabric" "Healthy" "Avail" "Total"
    print_separator 130
    
    # Collect cluster lines for sorting
    local cluster_lines_temp
    cluster_lines_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    local has_clusters=false
    local max_gid_num=0
    
    for gid in "${!CLUSTER_INDEX_MAP[@]}"; do
        local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
        [[ -z "$cluster_ocid" ]] && continue
        
        has_clusters=true
        
        # Track max gid number
        local gid_num="${gid#g}"
        [[ "$gid_num" -gt "$max_gid_num" ]] && max_gid_num="$gid_num"
        
        # Get cluster info from cache
        local cluster_line
        cluster_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
        
        if [[ -n "$cluster_line" ]]; then
            local c_name c_state c_fabric_suffix c_size
            IFS='|' read -r _ c_name c_state c_fabric_suffix _ _ c_size <<< "$cluster_line"
            
            # Get fabric info from suffix
            local fabric_name="N/A" f_healthy="N/A" f_avail="N/A" f_total="N/A"
            if [[ -n "$c_fabric_suffix" ]]; then
                local fabric_line
                fabric_line=$(grep -v '^#' "$FABRIC_CACHE" 2>/dev/null | grep "|${c_fabric_suffix}|" | head -1)
                if [[ -n "$fabric_line" ]]; then
                    IFS='|' read -r fabric_name _ _ _ f_healthy f_avail f_total _ _ _ <<< "$fabric_line"
                fi
            fi
            
            # Store for sorting: gid_num|gid|name|state|size|fabric|healthy|avail|total
            echo "${gid_num}|${gid}|${c_name}|${c_state}|${c_size}|${fabric_name}|${f_healthy}|${f_avail}|${f_total}" >> "$cluster_lines_temp"
        fi
    done
    
    # Sort and display
    sort -t'|' -k1 -n "$cluster_lines_temp" | while IFS='|' read -r _ gid c_name c_state c_size fabric_name f_healthy f_avail f_total; do
        # Color state
        local state_color
        state_color=$(color_resource_state "$c_state")
        
        # Color available - highlight if > 0
        local avail_color="${WHITE}"
        [[ "$f_avail" != "N/A" && "$f_avail" != "0" ]] && avail_color="${LIGHT_GREEN}"
        
        printf "${YELLOW}%-6s${NC} ${MAGENTA}%-35s${NC} ${state_color}%-10s${NC} %6s  ${CYAN}%-40s${NC} %8s ${avail_color}%6s${NC} %6s\n" \
            "$gid" "$c_name" "$c_state" "$c_size" "$fabric_name" "$f_healthy" "$f_avail" "$f_total"
    done
    
    rm -f "$cluster_lines_temp"
    
    if [[ "$has_clusters" != "true" ]]; then
        echo -e "  ${YELLOW}No GPU Memory Clusters available${NC}"
        return 1
    fi
    
    echo ""
    
    # ── Multi-select: g1, g1,g2,g3, g1-5, all ──
    echo -e "${WHITE}Select cluster(s) to update:${NC}"
    echo -e "  ${GRAY}Examples: ${WHITE}g1${GRAY}  |  ${WHITE}g1,g3,g5${GRAY}  |  ${WHITE}g1-5${GRAY}  |  ${WHITE}all${NC}"
    echo ""
    echo -n -e "${CYAN}Select GPU Memory Cluster(s): ${NC}"
    local cluster_input
    read -r cluster_input
    
    if [[ -z "$cluster_input" ]]; then
        echo -e "${RED}No cluster selected${NC}"
        return 1
    fi
    
    # ── Parse selection into array of g# IDs using shared helper ──
    if ! _parse_targets "g" "$cluster_input" "CLUSTER_INDEX_MAP"; then
        echo -e "${RED}No valid clusters selected${NC}"
        return 1
    fi
    local -a valid_gids=("${_SEL_KEYS[@]}")
    
    echo ""
    echo -e "${GREEN}✓ Selected ${WHITE}${#valid_gids[@]}${GREEN} cluster(s): ${YELLOW}${valid_gids[*]}${NC}"
    echo ""
    
    # ── Update type selection ──
    echo -e "${WHITE}What would you like to update?${NC}"
    echo -e "  ${GREEN}1${NC} - Size"
    echo -e "  ${GREEN}2${NC} - Instance Configuration"
    echo -e "  ${GREEN}3${NC} - Both Size and Instance Configuration"
    echo -e "  ${RED}0${NC} - Cancel"
    echo ""
    echo -n -e "${CYAN}Select option: ${NC}"
    local option
    read -r option
    
    [[ "$option" == "0" ]] && { echo -e "${RED}Update cancelled${NC}"; return 0; }
    [[ ! "$option" =~ ^[1-3]$ ]] && { echo -e "${RED}Invalid option${NC}"; return 1; }
    
    # ── Collect per-cluster details ──
    # For sizes, we need per-cluster input; for IC, one IC applies to all
    
    local new_ic=""
    declare -A cluster_new_sizes  # gid -> new_size
    
    # If size update is requested (option 1 or 3)
    if [[ "$option" == "1" || "$option" == "3" ]]; then
        echo ""
        _ui_subheader "Size Update" 0
        echo ""
        
        # Show current sizes for reference
        printf "  ${BOLD}%-6s %-35s %10s  %-40s %6s %6s${NC}\n" \
            "ID" "Cluster Name" "Curr Size" "Fabric" "Avail" "Total"
        printf "  ${WHITE}%-6s %-35s %10s  %-40s %6s %6s${NC}\n" \
            "------" "-----------------------------------" "----------" "----------------------------------------" "------" "------"
        
        for gid in "${valid_gids[@]}"; do
            local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
            local c_line
            c_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
            local c_name="" c_size="" c_fabric_suffix=""
            IFS='|' read -r _ c_name _ c_fabric_suffix _ _ c_size <<< "$c_line"
            
            local f_avail="N/A" f_total="N/A"
            if [[ -n "$c_fabric_suffix" ]]; then
                local f_line
                f_line=$(grep -v '^#' "$FABRIC_CACHE" 2>/dev/null | grep "|${c_fabric_suffix}|" | head -1)
                [[ -n "$f_line" ]] && IFS='|' read -r _ _ _ _ _ f_avail f_total _ <<< "$f_line"
            fi
            
            local fabric_name_short="N/A"
            [[ -n "$f_line" ]] && IFS='|' read -r fabric_name_short _ <<< "$f_line"
            
            printf "  ${YELLOW}%-6s${NC} ${MAGENTA}%-35s${NC} ${CYAN}%10s${NC}  ${GRAY}%-40s${NC} ${YELLOW}%6s${NC} ${WHITE}%6s${NC}\n" \
                "$gid" "${c_name:0:35}" "$c_size" "${fabric_name_short:0:40}" "$f_avail" "$f_total"
        done
        
        echo ""
        
        if [[ ${#valid_gids[@]} -eq 1 ]]; then
            # Single cluster - show context on prompt line
            local _sg="${valid_gids[0]}"
            local _sc_ocid="${CLUSTER_INDEX_MAP[$_sg]}"
            local _sc_line _sc_name="" _sc_size="" _sc_fab_suffix=""
            _sc_line=$(_cache_line "$CLUSTER_CACHE" "$_sc_ocid")
            IFS='|' read -r _ _sc_name _ _sc_fab_suffix _ _ _sc_size <<< "$_sc_line"
            local _sc_avail="N/A" _sc_total="N/A"
            if [[ -n "$_sc_fab_suffix" ]]; then
                local _sc_fline
                _sc_fline=$(grep -v '^#' "$FABRIC_CACHE" 2>/dev/null | grep "|${_sc_fab_suffix}|" | head -1)
                [[ -n "$_sc_fline" ]] && IFS='|' read -r _ _ _ _ _ _sc_avail _sc_total _ <<< "$_sc_fline"
            fi
            echo -e "  ${GRAY}Current: ${WHITE}${_sc_size}${GRAY}  Available: ${YELLOW}${_sc_avail}${GRAY}  Fabric Total: ${WHITE}${_sc_total}${NC}"
            echo -n -e "${CYAN}Enter new size for ${YELLOW}${valid_gids[0]}${CYAN}: ${NC}"
            local sz
            read -r sz
            if ! [[ "$sz" =~ ^[0-9]+$ ]] || [[ "$sz" -lt 1 ]]; then
                echo -e "${RED}Invalid size: must be a positive integer${NC}"
                return 1
            fi
            cluster_new_sizes["${valid_gids[0]}"]="$sz"
        else
            # Multiple clusters - offer same size or per-cluster
            echo -e "${WHITE}Size options:${NC}"
            echo -e "  ${GREEN}a${NC} - Apply ${WHITE}same size${NC} to all selected clusters"
            echo -e "  ${GREEN}p${NC} - Specify size ${WHITE}per cluster${NC} individually"
            echo ""
            echo -n -e "${CYAN}Choose [a/p]: ${NC}"
            local size_mode
            read -r size_mode
            
            if [[ "${size_mode,,}" == "a" ]]; then
                echo -n -e "${CYAN}Enter new size for all ${WHITE}${#valid_gids[@]}${CYAN} clusters: ${NC}"
                local sz
                read -r sz
                if ! [[ "$sz" =~ ^[0-9]+$ ]] || [[ "$sz" -lt 1 ]]; then
                    echo -e "${RED}Invalid size: must be a positive integer${NC}"
                    return 1
                fi
                for gid in "${valid_gids[@]}"; do
                    cluster_new_sizes["$gid"]="$sz"
                done
            else
                # Per-cluster sizing
                for gid in "${valid_gids[@]}"; do
                    local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
                    local c_line
                    c_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
                    local c_name="" c_size="" c_fab_sfx=""
                    IFS='|' read -r _ c_name _ c_fab_sfx _ _ c_size <<< "$c_line"
                    local _pc_avail="N/A" _pc_total="N/A"
                    if [[ -n "$c_fab_sfx" ]]; then
                        local _pc_fline
                        _pc_fline=$(grep -v '^#' "$FABRIC_CACHE" 2>/dev/null | grep "|${c_fab_sfx}|" | head -1)
                        [[ -n "$_pc_fline" ]] && IFS='|' read -r _ _ _ _ _ _pc_avail _pc_total _ <<< "$_pc_fline"
                    fi
                    
                    echo -e "  ${GRAY}${gid}: current=${WHITE}${c_size}${GRAY}  available=${YELLOW}${_pc_avail}${GRAY}  total=${WHITE}${_pc_total}${NC}"
                    echo -n -e "${CYAN}New size for ${YELLOW}${gid}${CYAN} (${MAGENTA}${c_name}${CYAN}): ${NC}"
                    local sz
                    read -r sz
                    if ! [[ "$sz" =~ ^[0-9]+$ ]] || [[ "$sz" -lt 1 ]]; then
                        echo -e "${RED}Invalid size '${sz}' for ${gid} - must be a positive integer. Aborting.${NC}"
                        return 1
                    fi
                    cluster_new_sizes["$gid"]="$sz"
                done
            fi
        fi
    fi
    
    # If instance config update is requested (option 2 or 3)
    if [[ "$option" == "2" || "$option" == "3" ]]; then
        echo ""
        _ui_subheader "Instance Configuration Update" 0
        echo ""
        echo -e "${WHITE}Available Instance Configurations:${NC}"
        echo ""
        printf "${BOLD}%-6s %-60s %-90s${NC}\n" \
            "ID" "Instance Configuration Name" "Instance Configuration OCID"
        print_separator 160
        
        local ic_output_temp
        ic_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
        
        local iid
        for iid in "${!IC_INDEX_MAP[@]}"; do
            local ic_ocid="${IC_INDEX_MAP[$iid]}"
            [[ -z "$ic_ocid" ]] && continue
            
            local ic_name
            ic_name=$(get_instance_config_name "$ic_ocid")
            
            local iid_num="${iid#i}"
            echo "${iid_num}|${iid}|${ic_name}|${ic_ocid}" >> "$ic_output_temp"
        done
        
        sort -t'|' -k1 -n "$ic_output_temp" | while IFS='|' read -r _ iid ic_name ic_ocid; do
            printf "${YELLOW}%-6s${NC} ${CYAN}%-60s${NC} ${GRAY}%-90s${NC}\n" \
                "$iid" "$ic_name" "$ic_ocid"
        done
        
        rm -f "$ic_output_temp"
        echo ""
        
        echo -n -e "${CYAN}Select Instance Configuration for all clusters (i#): ${NC}"
        local ic_input
        read -r ic_input
        new_ic="${IC_INDEX_MAP[$ic_input]:-}"
        if [[ -z "$new_ic" ]]; then
            echo -e "${RED}Invalid instance configuration selection: $ic_input${NC}"
            return 1
        fi
    fi
    
    # ── Confirmation Summary ──
    echo ""
    _ui_menu_header "CONFIRM UPDATE"
    echo ""
    
    local new_ic_name=""
    [[ -n "$new_ic" ]] && new_ic_name=$(get_instance_config_name "$new_ic")
    
    for gid in "${valid_gids[@]}"; do
        local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
        local c_line
        c_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
        local c_name="" c_state="" c_size="" c_ic=""
        IFS='|' read -r _ c_name c_state _ _ _ c_size <<< "$c_line"
        
        # Get current IC
        local cur_ic_ocid=""
        cur_ic_ocid=$(oci compute compute-gpu-memory-cluster get \
            --compute-gpu-memory-cluster-id "$cluster_ocid" \
            --region "$region" \
            --query 'data."instance-configuration-id"' --raw-output 2>/dev/null)
        local cur_ic_name=""
        [[ -n "$cur_ic_ocid" ]] && cur_ic_name=$(get_instance_config_name "$cur_ic_ocid")
        
        echo -e "  ${YELLOW}${gid}${NC} ${MAGENTA}${c_name}${NC}  ${GRAY}(${cluster_ocid})${NC}"
        
        if [[ -n "${cluster_new_sizes[$gid]:-}" ]]; then
            echo -e "      ${CYAN}Size:${NC}     ${WHITE}${c_size}${NC} → ${GREEN}${cluster_new_sizes[$gid]}${NC}"
        fi
        if [[ -n "$new_ic" ]]; then
            echo -e "      ${CYAN}IC:${NC}       ${WHITE}${cur_ic_name:-N/A}${NC} → ${GREEN}${new_ic_name}${NC}"
        fi
        echo ""
    done
    
    # Display commands that will be executed
    _ui_subheader "Commands to Execute" 0
    echo ""
    for gid in "${valid_gids[@]}"; do
        local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
        local cmd_str="oci compute compute-gpu-memory-cluster update --compute-gpu-memory-cluster-id \"${cluster_ocid}\""
        [[ -n "${cluster_new_sizes[$gid]:-}" ]] && cmd_str+=" --size ${cluster_new_sizes[$gid]}"
        [[ -n "$new_ic" ]] && cmd_str+=" --instance-configuration-id \"${new_ic}\""
        echo -e "  ${GRAY}[${gid}] ${cmd_str}${NC}"
    done
    
    echo ""
    echo -n -e "${YELLOW}Proceed with update of ${WHITE}${#valid_gids[@]}${YELLOW} cluster(s)? (yes/no): ${NC}"
    local confirm
    read -r confirm
    
    if [[ "$confirm" != "yes" ]]; then
        echo -e "${RED}Update cancelled${NC}"
        return 0
    fi
    
    # ── Execute updates ──
    echo ""
    echo -e "${GREEN}Executing updates...${NC}"
    echo ""
    
    local success_count=0
    local fail_count=0
    local log_file="${LOGS_DIR}/gpu_cluster_actions.log"
    mkdir -p "$LOGS_DIR"
    
    for gid in "${valid_gids[@]}"; do
        local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
        local c_line
        c_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
        local c_name=""
        IFS='|' read -r _ c_name _ <<< "$c_line"
        
        # Build command args as array for safe execution
        local -a cmd_args=(--compute-gpu-memory-cluster-id "$cluster_ocid" --region "$region")
        local cmd_display="oci compute compute-gpu-memory-cluster update --compute-gpu-memory-cluster-id \"${cluster_ocid}\" --region \"${region}\""

        [[ -n "${cluster_new_sizes[$gid]:-}" ]] && { cmd_args+=(--size "${cluster_new_sizes[$gid]}"); cmd_display+=" --size ${cluster_new_sizes[$gid]}"; }
        [[ -n "$new_ic" ]] && { cmd_args+=(--instance-configuration-id "$new_ic"); cmd_display+=" --instance-configuration-id \"${new_ic}\""; }

        echo -e "  ${YELLOW}${gid}${NC} ${MAGENTA}${c_name}${NC} ..."

        # Log the command
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${cmd_display}" >> "$log_file"

        local result
        log_action "UPDATE" "$cmd_display"
        result=$(oci compute compute-gpu-memory-cluster update "${cmd_args[@]}" --output json 2>&1)
        local exit_code=$?
        
        if [[ $exit_code -eq 0 ]]; then
            local updated_state updated_size
            updated_state=$(jq -r 'if .data then .data["lifecycle-state"] else .["lifecycle-state"] end // "N/A"' <<< "$result" 2>/dev/null)
            updated_size=$(jq -r 'if .data then .data["size"] else .["size"] end // "N/A"' <<< "$result" 2>/dev/null)
            
            [[ -z "$updated_state" || "$updated_state" == "null" ]] && updated_state="N/A"
            [[ -z "$updated_size" || "$updated_size" == "null" ]] && updated_size="N/A"
            
            local state_color="${WHITE}"
            state_color=$(color_resource_state "$updated_state")
            
            echo -e "    ${GREEN}✓${NC} State: ${state_color}${updated_state}${NC}  Size: ${CYAN}${updated_size}${NC}"
            log_action_result "SUCCESS" "UPDATE operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: ${gid} ${c_name} -> state=${updated_state} size=${updated_size}" >> "$log_file"
            ((success_count++))
        else
            echo -e "    ${RED}✗ Failed${NC}"
            log_action_result "FAILED" "UPDATE operation"
            echo "$result" | head -3 | sed 's/^/      /'
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${gid} ${c_name} -> ${result}" >> "$log_file"
            ((fail_count++))
        fi
    done
    
    echo ""
    echo -e "${WHITE}Results: ${GREEN}${success_count} succeeded${NC}, ${RED}${fail_count} failed${NC}"
    echo -e "  ${GRAY}Logged to: ${log_file}${NC}"
    
    # Invalidate caches
    rm -f "$CLUSTER_CACHE" "$FABRIC_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE"
}

#--------------------------------------------------------------------------------
# Update ALL GPU Memory Clusters with a selected Instance Configuration
#--------------------------------------------------------------------------------
update_all_clusters_instance_config() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    
    echo ""
    _ui_subheader "Update All GPU Memory Clusters - Instance Configuration" 0
    echo ""
    
    # ── Refresh data from OCI (parallel — all independent, cache-file based) ──
    rm -f "$FABRIC_CACHE" "$CLUSTER_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE" "$INSTANCE_CONFIG_CACHE" "$COMPUTE_CLUSTER_CACHE"
    _step_init
    _step_active "GPU infra(4 parallel)"
    ( fetch_gpu_fabrics ) &
    local _p1=$!
    ( fetch_gpu_clusters ) &
    local _p2=$!
    ( fetch_instance_configurations ) &
    local _p3=$!
    ( fetch_compute_clusters ) &
    local _p4=$!
    wait $_p1 $_p2 $_p3 $_p4 2>/dev/null
    _step_complete "fabrics($(_clc "$FABRIC_CACHE")) clusters($(_clc "$CLUSTER_CACHE")) configs($(_clc "$INSTANCE_CONFIG_CACHE")) CC($(_clc "$COMPUTE_CLUSTER_CACHE"))"
    _step_finish
    
    # Rebuild index maps
    display_gpu_management_menu > /dev/null 2>&1
    
    echo ""
    
    # Check if any instance configurations exist
    if [[ ${#IC_INDEX_MAP[@]} -eq 0 ]]; then
        echo -e "${YELLOW}No Instance Configurations available${NC}"
        echo ""
        _ui_pause
        return 0
    fi
    
    # Check if any clusters exist
    if [[ ${#CLUSTER_INDEX_MAP[@]} -eq 0 ]]; then
        echo -e "${YELLOW}No GPU Memory Clusters available to update${NC}"
        echo ""
        _ui_pause
        return 0
    fi
    
    # Display Instance Configurations
    echo -e "${WHITE}Available Instance Configurations:${NC}"
    echo ""
    printf "${BOLD}%-6s %-60s %-90s${NC}\n" \
        "ID" "Instance Configuration Name" "OCID"
    print_separator 160
    
    # Sort and display instance configs
    local ic_output_temp
    ic_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    local iid
    for iid in "${!IC_INDEX_MAP[@]}"; do
        local ic_ocid="${IC_INDEX_MAP[$iid]}"
        [[ -z "$ic_ocid" ]] && continue
        
        local ic_name
        ic_name=$(get_instance_config_name "$ic_ocid")
        
        local iid_num="${iid#i}"
        echo "${iid_num}|${iid}|${ic_name}|${ic_ocid}" >> "$ic_output_temp"
    done
    
    sort -t'|' -k1 -n "$ic_output_temp" | while IFS='|' read -r _ iid ic_name ic_ocid; do
        printf "${YELLOW}%-6s${NC} ${GREEN}%-60s${NC} ${GRAY}%-90s${NC}\n" \
            "$iid" "$ic_name" "$ic_ocid"
    done
    
    rm -f "$ic_output_temp"
    echo ""
    
    # Select Instance Configuration
    echo -n -e "${CYAN}Select Instance Configuration to apply to ALL clusters (i#) or 'cancel': ${NC}"
    local ic_input
    read -r ic_input
    
    # Check for cancel
    if [[ "$ic_input" == "cancel" || "$ic_input" == "c" || -z "$ic_input" ]]; then
        echo -e "${YELLOW}Update cancelled${NC}"
        return 0
    fi
    
    local selected_ic_ocid="${IC_INDEX_MAP[$ic_input]:-}"
    if [[ -z "$selected_ic_ocid" ]]; then
        echo -e "${RED}Invalid instance configuration selection: $ic_input${NC}"
        return 1
    fi
    
    # Get selected IC name
    local selected_ic_name
    selected_ic_name=$(get_instance_config_name "$selected_ic_ocid")
    
    echo ""
    _ui_subheader "GPU Memory Clusters to Update" 0
    echo ""
    
    # Collect clusters to update (only ACTIVE, UPDATING, SCALING states that don't already have the selected IC)
    local clusters_to_update=()
    local cluster_names=()
    local cluster_current_ics=()
    local skipped_count=0
    
    for gid in "${!CLUSTER_INDEX_MAP[@]}"; do
        local cluster_ocid="${CLUSTER_INDEX_MAP[$gid]}"
        [[ -z "$cluster_ocid" ]] && continue
        
        # Get cluster info from cache
        local cluster_line
        cluster_line=$(_cache_line "$CLUSTER_CACHE" "$cluster_ocid")
        
        if [[ -n "$cluster_line" ]]; then
            local c_name c_state c_fabric_suffix c_ic_id c_size
            IFS='|' read -r _ c_name c_state c_fabric_suffix c_ic_id _ c_size <<< "$cluster_line"
            
            # Only include active-ish clusters
            if [[ "$c_state" == "ACTIVE" || "$c_state" == "UPDATING" || "$c_state" == "SCALING" ]]; then
                # Skip if already has the selected instance configuration
                if [[ "$c_ic_id" == "$selected_ic_ocid" ]]; then
                    ((skipped_count++))
                    continue
                fi
                
                clusters_to_update+=("$cluster_ocid")
                cluster_names+=("$c_name")
                
                # Get current IC name
                local current_ic_name="N/A"
                if [[ -n "$c_ic_id" && "$c_ic_id" != "N/A" ]]; then
                    current_ic_name=$(get_instance_config_name "$c_ic_id")
                fi
                cluster_current_ics+=("$current_ic_name")
            fi
        fi
    done
    
    # Show skipped count if any
    if [[ $skipped_count -gt 0 ]]; then
        echo -e "${GREEN}Skipped ${skipped_count} cluster(s) already using ${selected_ic_name}${NC}"
        echo ""
    fi
    
    if [[ ${#clusters_to_update[@]} -eq 0 ]]; then
        echo -e "${GREEN}All active GPU Memory Clusters already have the selected Instance Configuration${NC}"
        echo ""
        _ui_pause
        return 0
    fi
    
    # Display clusters that will be updated
    _ui_table_header "%-40s %-50s" "Cluster Name" "Current Instance Config"
    
    for i in "${!clusters_to_update[@]}"; do
        printf "%-40s ${GRAY}%-50s${NC}\n" "${cluster_names[$i]}" "${cluster_current_ics[$i]}"
    done
    
    echo ""
    echo -e "${WHITE}Total clusters to update:${NC} ${CYAN}${#clusters_to_update[@]}${NC}"
    echo -e "${WHITE}New Instance Configuration:${NC} ${GREEN}$selected_ic_name${NC}"
    echo ""
    
    # Show commands that will be executed
    _ui_subheader "Commands to Execute" 0
    echo ""
    for i in "${!clusters_to_update[@]}"; do
        local cluster_ocid="${clusters_to_update[$i]}"
        echo -e "${GRAY}oci compute compute-gpu-memory-cluster update \\
    --compute-gpu-memory-cluster-id \"$cluster_ocid\" \\
    --instance-configuration-id \"$selected_ic_ocid\"${NC}"
        echo ""
    done
    
    # Confirm
    echo -e "${YELLOW}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${YELLOW}║                    ⚠️  BULK UPDATE CONFIRMATION  ⚠️                              ║${NC}"
    echo -e "${YELLOW}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}This will update ${CYAN}${#clusters_to_update[@]}${NC}${WHITE} GPU Memory Cluster(s) to use:${NC}"
    echo -e "  ${GREEN}$selected_ic_name${NC}"
    echo -e "  ${GRAY}$selected_ic_ocid${NC}"
    echo ""
    
    if ! _ui_confirm "UPDATE ALL" "confirm" "$YELLOW"; then
        echo -e "${YELLOW}Update cancelled${NC}"
        return 0
    fi
    
    echo ""
    echo -e "${GREEN}Starting bulk update...${NC}"
    echo ""
    
    # Update each cluster
    local success_count=0
    local fail_count=0
    
    for i in "${!clusters_to_update[@]}"; do
        local cluster_ocid="${clusters_to_update[$i]}"
        local cluster_name="${cluster_names[$i]}"
        
        echo -n -e "  Updating ${CYAN}$cluster_name${NC}... "
        
        local result
        log_action "UPDATE" "oci compute compute-gpu-memory-cluster update"
        result=$(oci compute compute-gpu-memory-cluster update \
            --compute-gpu-memory-cluster-id "$cluster_ocid" \
            --instance-configuration-id "$selected_ic_ocid" \
            --output json 2>&1)
        local exit_code=$?
        
        if [[ $exit_code -eq 0 ]]; then
            echo -e "${GREEN}✓${NC}"
            log_action_result "SUCCESS" "UPDATE operation"
            ((success_count++))
        else
            echo -e "${RED}✗${NC}"
            log_action_result "FAILED" "UPDATE operation"
            echo -e "    ${RED}Error: $(echo "$result" | head -1)${NC}"
            ((fail_count++))
        fi
    done
    
    echo ""
    _ui_subheader "Update Summary" 0
    echo -e "  ${GREEN}Successful:${NC} $success_count"
    echo -e "  ${RED}Failed:${NC}     $fail_count"
    echo ""
    
    # Invalidate caches
    rm -f "$CLUSTER_CACHE" "$FABRIC_CACHE" "$INSTANCE_CLUSTER_MAP_CACHE"
    
    _ui_pause
}

#--------------------------------------------------------------------------------
# Delete a single Instance Configuration by OCID (called from view details)
#--------------------------------------------------------------------------------
delete_single_instance_configuration() {
    local ic_ocid="$1"
    local ic_name="$2"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║                    ⚠️  WARNING: DELETE INSTANCE CONFIGURATION  ⚠️               ║${NC}"
    echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}Instance Configuration:${NC} ${GREEN}$ic_name${NC}"
    echo -e "${WHITE}OCID:${NC}                   ${YELLOW}$ic_ocid${NC}"
    echo ""
    
    # Check if in use
    local clusters_using_ic=""
    if [[ -f "$CLUSTER_CACHE" ]]; then
        while IFS='|' read -r cluster_ocid cluster_name cluster_state _ cluster_ic_id _; do
            [[ "$cluster_ocid" =~ ^#.*$ ]] && continue
            [[ -z "$cluster_ocid" ]] && continue
            [[ "$cluster_state" == "DELETED" ]] && continue
            
            if [[ "$cluster_ic_id" == "$ic_ocid" ]]; then
                clusters_using_ic="${clusters_using_ic}${cluster_name} (${cluster_state})\n"
            fi
        done < "$CLUSTER_CACHE"
    fi
    
    if [[ -n "$clusters_using_ic" ]]; then
        echo -e "${RED}⚠️  WARNING: This instance configuration is used by:${NC}"
        echo -e "${YELLOW}$(echo -e "$clusters_using_ic")${NC}"
        echo ""
    fi
    
    echo -e "${RED}This action cannot be undone!${NC}"
    echo ""
    
    _ui_subheader "Command to Execute" 0
    echo -e "  ${GRAY}\$ oci compute-management instance-configuration delete --instance-configuration-id \"${ic_ocid}\" --region \"${region}\" --force${NC}"
    echo ""
    
    if ! _ui_confirm "DELETE" "confirm"; then
        echo -e "${YELLOW}Delete cancelled${NC}"
        return 0
    fi
    
    echo ""
    echo -e "${YELLOW}Deleting Instance Configuration...${NC}"
    
    local result
    log_action "DELETE" "oci compute-management instance-configuration delete --instance-configuration-id ${ic_ocid} --region ${region} --force"
    result=$(oci compute-management instance-configuration delete \
        --instance-configuration-id "$ic_ocid" \
        --region "$region" \
        --force 2>&1)
    local exit_code=$?

    if [[ $exit_code -eq 0 ]]; then
        echo -e "${GREEN}✓ Instance Configuration deleted successfully${NC}"
        log_action_result "SUCCESS" "DELETE operation"
        rm -f "$INSTANCE_CONFIG_CACHE"
    else
        echo -e "${RED}✗ Failed to delete:${NC}"
        log_action_result "FAILED" "DELETE operation"
        echo "$result"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Manage Compute Clusters - Main menu for compute cluster operations
#--------------------------------------------------------------------------------
manage_compute_clusters() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    while true; do
        echo ""
        _ui_menu_header "COMPUTE CLUSTER MANAGEMENT" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Compute Clusters" \
            --cmd "oci compute compute-cluster list --compartment-id \$COMPARTMENT_ID --all | oci compute compute-cluster get" \
            --env \
            --cache \
            "${COMPUTE_CLUSTER_CACHE}|Compute Clusters"
        
        # ── Discovery ──
        _step_init
        if is_cache_fresh "$COMPUTE_CLUSTER_CACHE"; then
            _step_complete "compute clusters($(_clc "$COMPUTE_CLUSTER_CACHE") cached)"
        else
            _QUIET_SPINNERS=1
            _step_active "compute clusters"
            fetch_compute_clusters "$compartment_id" "$region"
            _step_complete "compute clusters($(_clc "$COMPUTE_CLUSTER_CACHE"))"
            _QUIET_SPINNERS=0
        fi
        _step_finish
        
        # ========== Show Existing Compute Clusters ==========
        _ui_subheader "Existing Compute Clusters" 0
        echo ""
        
        # Build array for selection
        declare -a CC_LIST=()
        local cc_count=0
        
        if [[ -f "$COMPUTE_CLUSTER_CACHE" ]] && [[ -s "$COMPUTE_CLUSTER_CACHE" ]]; then
            printf "  ${GRAY}%-4s %-45s %-35s %-12s${NC}\n" "#" "Display Name" "Availability Domain" "Status"
            echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
            while IFS='|' read -r cc_ocid cc_name cc_ad cc_state; do
                [[ -z "$cc_ocid" || "$cc_ocid" == "#"* ]] && continue
                
                # Default state if not present (old cache format)
                [[ -z "$cc_state" ]] && cc_state="UNKNOWN"
                
                # Skip deleted clusters
                [[ "$cc_state" == "DELETED" ]] && continue
                ((cc_count++))
                CC_LIST+=("$cc_ocid|$cc_name|$cc_ad|$cc_state")
                
                # Color-code the status
                local state_color
                state_color=$(color_resource_state "$cc_state")
                
                printf "  ${YELLOW}%-4s${NC} ${WHITE}%-45s${NC} ${CYAN}%-35s${NC} ${state_color}%-12s${NC}\n" "$cc_count)" "$cc_name" "$cc_ad" "$cc_state"
            done < <(grep -v '^#' "$COMPUTE_CLUSTER_CACHE" 2>/dev/null)
            
            if [[ $cc_count -eq 0 ]]; then
                echo -e "  ${GRAY}(No existing compute clusters found)${NC}"
            else
                echo ""
                echo -e "  ${WHITE}Total: ${GREEN}${cc_count}${WHITE} compute cluster(s)${NC}"
            fi
        else
            echo -e "  ${GRAY}(No existing compute clusters found)${NC}"
        fi
        echo ""
        
        # ========== Menu Options ==========
        _ui_actions
        echo ""
        if [[ $cc_count -gt 0 ]]; then
            echo -e "  ${CYAN}#${NC}) ${WHITE}View${NC}    - View compute cluster details (enter number)"
        fi
        echo -e "  ${GREEN}c${NC}) ${WHITE}Create${NC}  - Create a new compute cluster"
        if [[ $cc_count -gt 0 ]]; then
            echo -e "  ${RED}d${NC}) ${WHITE}Delete${NC}  - Delete compute cluster(s) ${GRAY}(d 1, d 1,2,3, d 1-3, d all)${NC}"
        fi
        echo -e "  ${YELLOW}j${NC}) ${WHITE}JSON${NC}    - View raw JSON (j <keyword> to search)"
        echo -e "  ${MAGENTA}r${NC}) ${WHITE}Refresh${NC} - Refresh compute cluster list"
        echo -e "  ${CYAN}b${NC}) ${WHITE}Back${NC}    - Return to main menu"
        echo ""
        _ui_prompt "Compute Clusters" "#, c, d [#|#,#|#-#|all], j, r, b, show"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            c|C|create|CREATE)
                create_compute_cluster_interactive
                ;;
            d|D|delete|DELETE)
                if [[ $cc_count -eq 0 ]]; then
                    echo -e "${YELLOW}No compute clusters available to delete${NC}"
                    sleep 1
                else
                    delete_compute_cluster_interactive ""
                fi
                ;;
            d\ *|D\ *|delete\ *|DELETE\ *)
                if [[ $cc_count -eq 0 ]]; then
                    echo -e "${YELLOW}No compute clusters available to delete${NC}"
                    sleep 1
                else
                    local delete_args="${choice#* }"
                    delete_compute_cluster_interactive "$delete_args"
                fi
                ;;
            j|J|json|JSON)
                _ui_json_viewer "Compute Clusters JSON" "-f" "$COMPUTE_CLUSTER_JSON_CACHE" ".data"
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "Compute Clusters JSON" "-f" "$COMPUTE_CLUSTER_JSON_CACHE" ".data" "${choice#* }"
                ;;
            r|R|refresh|REFRESH)
                rm -f "$COMPUTE_CLUSTER_CACHE" "$COMPUTE_CLUSTER_JSON_CACHE"
                echo -e "${GREEN}Cache cleared, refreshing...${NC}"
                sleep 1
                ;;
            b|B|back|BACK|"")
                return
                ;;
            [0-9]*)
                # Direct number selection for viewing
                if [[ "$choice" =~ ^[0-9]+$ ]] && [[ $choice -ge 1 ]] && [[ $choice -le $cc_count ]]; then
                    local selected="${CC_LIST[$((choice-1))]}"
                    local sel_ocid sel_name sel_ad sel_state
                    IFS='|' read -r sel_ocid sel_name sel_ad sel_state <<< "$selected"
                    view_compute_cluster_details "$sel_ocid" "$sel_name"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# View Compute Cluster details
#--------------------------------------------------------------------------------
view_compute_cluster_details() {
    local cc_ocid="$1"
    local cc_name="$2"
    local region="${FOCUS_REGION:-$REGION}"

    while true; do
        echo ""
        _ui_menu_header "COMPUTE CLUSTER DETAILS" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Compute Clusters" "Details: ${cc_name}" \
            --cmd "oci compute compute-cluster get --compute-cluster-id ${cc_ocid}" \
            --env

        _step_init
        _step_active "details for: ${cc_name}"

        local cc_json
        cc_json=$(oci compute compute-cluster get --compute-cluster-id "$cc_ocid" --region "$region" 2>/dev/null)
        _step_complete "details for: ${cc_name}"
        _step_finish

        if [[ -z "$cc_json" ]]; then
            echo -e "${RED}Failed to fetch compute cluster details${NC}"
            _ui_policy_hint "read compute-clusters in compartment"
            echo ""
            _ui_pause "return"
            return
        fi

        echo ""
        _ui_subheader "Cluster Properties" 0
        jq -r '
            .data |
            "  Display Name:        \(.["display-name"] // "N/A")",
            "  OCID:                \(.id)",
            "  Availability Domain: \(.["availability-domain"] // "N/A")",
            "  Lifecycle State:     \(.["lifecycle-state"] // "N/A")",
            "  Time Created:        \(.["time-created"] // "N/A")"
        ' <<< "$cc_json"

        echo ""
        _ui_actions
        echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
        echo -e "  ${MAGENTA}r${NC}) Refresh"
        echo -e "  ${CYAN}Enter${NC}) Return"
        echo ""
        _ui_prompt "Cluster Details" "j, r, Enter, show"
        local view_choice
        read -r view_choice
        [[ "${view_choice:-}" == :* ]] && _nav_try_jump "$view_choice" && return

        case "$view_choice" in
            j|J|json|JSON)
                _ui_json_viewer "Compute Cluster: ${cc_name}" "$cc_json" ".data"
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "Compute Cluster: ${cc_name}" "$cc_json" ".data" "${view_choice#* }"
                ;;
            r|R) continue ;;
            show|SHOW) continue ;;
            *) return ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Delete Compute Cluster interactively — supports multi-select
# Usage: delete_compute_cluster_interactive [selection]
#   selection: 1, 1,2,3, 1-3, all (or empty for interactive prompt)
#--------------------------------------------------------------------------------
delete_compute_cluster_interactive() {
    local delete_args="${1:-}"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/compute_cluster_delete_$(date +%Y%m%d_%H%M%S).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    echo ""
    _ui_menu_header "DELETE COMPUTE CLUSTER" \
        --breadcrumb "Compute" "Compute Clusters" "Delete" \
        --cmd "oci compute compute-cluster delete --compute-cluster-id \$CC_OCID --region \$REGION --force" \
        --env

    # Fetch and display compute clusters
    _step_init
    _QUIET_SPINNERS=1
    _step_active "compute clusters"
    fetch_compute_clusters "$compartment_id" "$region"
    _step_complete "compute clusters($(_clc "$COMPUTE_CLUSTER_CACHE"))"
    _QUIET_SPINNERS=0
    _step_finish

    declare -a CC_LIST=()
    local cc_count=0

    if [[ -f "$COMPUTE_CLUSTER_CACHE" ]] && [[ -s "$COMPUTE_CLUSTER_CACHE" ]]; then
        echo ""
        echo -e "${WHITE}Available Compute Clusters:${NC}"
        echo ""
        printf "  ${GRAY}%-4s %-45s %-35s %-12s${NC}\n" "#" "Display Name" "Availability Domain" "Status"
        echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        while IFS='|' read -r cc_ocid cc_name cc_ad cc_state; do
            [[ -z "$cc_ocid" || "$cc_ocid" == "#"* ]] && continue

            # Default state if not present (old cache format)
            [[ -z "$cc_state" ]] && cc_state="UNKNOWN"

            # Skip deleted clusters
            [[ "$cc_state" == "DELETED" ]] && continue
            ((cc_count++))
            CC_LIST+=("$cc_ocid|$cc_name|$cc_ad|$cc_state")

            # Color-code the status
            local state_color
            state_color=$(color_resource_state "$cc_state")

            printf "  ${YELLOW}%-4s${NC} ${WHITE}%-45s${NC} ${CYAN}%-35s${NC} ${state_color}%-12s${NC}\n" "$cc_count)" "$cc_name" "$cc_ad" "$cc_state"
        done < <(grep -v '^#' "$COMPUTE_CLUSTER_CACHE" 2>/dev/null)
    fi

    if [[ $cc_count -eq 0 ]]; then
        echo -e "  ${GRAY}(No compute clusters found to delete)${NC}"
        echo ""
        _ui_pause "return"
        return
    fi
    echo ""

    # If no args provided, prompt interactively with usage
    if [[ -z "$delete_args" ]]; then
        echo -e "${WHITE}Usage: Enter one of the following:${NC}"
        echo -e "  ${YELLOW}#${NC}           - Delete a single cluster (e.g., ${YELLOW}1${NC})"
        echo -e "  ${YELLOW}#,#,#${NC}       - Delete multiple clusters (e.g., ${YELLOW}1,3,5${NC})"
        echo -e "  ${YELLOW}#-#${NC}         - Delete a range of clusters (e.g., ${YELLOW}1-3${NC})"
        echo -e "  ${RED}all${NC}         - Delete ALL compute clusters"
        echo -e "  ${CYAN}cancel${NC}      - Cancel"
        echo ""
        echo -n -e "${CYAN}Select Compute Cluster(s) to delete: ${NC}"
        read -r delete_args
    fi

    # Check for cancel
    if [[ -z "$delete_args" || "${delete_args,,}" == "cancel" || "${delete_args,,}" == "b" ]]; then
        echo -e "${YELLOW}Delete cancelled${NC}"
        return 0
    fi

    # Build list of clusters to delete using shared parser
    # Uses "" prefix (plain numbers) and $cc_count as numeric validator
    if ! _parse_targets "" "$delete_args" "$cc_count"; then
        echo -e "${RED}No valid compute clusters selected for deletion${NC}"
        _ui_pause
        return 1
    fi

    declare -a DELETE_OCIDS=()
    declare -a DELETE_NAMES=()
    declare -a DELETE_ADS=()
    declare -a DELETE_STATES=()
    declare -a DELETE_NUMS=()

    for _idx in "${_SEL_INDICES[@]}"; do
        local _entry="${CC_LIST[$((_idx-1))]}"
        local _ocid _name _ad _state
        IFS='|' read -r _ocid _name _ad _state <<< "$_entry"
        [[ -z "$_ocid" ]] && continue
        DELETE_NUMS+=("$_idx")
        DELETE_OCIDS+=("$_ocid")
        DELETE_NAMES+=("$_name")
        DELETE_ADS+=("$_ad")
        DELETE_STATES+=("$_state")
    done

    # Validate we have something to delete
    if [[ ${#DELETE_OCIDS[@]} -eq 0 ]]; then
        echo -e "${RED}No valid compute clusters selected for deletion${NC}"
        _ui_pause
        return 1
    fi

    # Use global DEBUG_MODE
    local debug_flag=""
    if [[ "$DEBUG_MODE" == "true" ]]; then
        debug_flag="--debug"
    fi

    # Show what will be deleted
    echo ""
    echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║               WARNING: DELETE COMPUTE CLUSTER(S)                             ║${NC}"
    echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}The following ${RED}${#DELETE_OCIDS[@]}${WHITE} compute cluster(s) will be deleted:${NC}"
    echo ""

    printf "  ${GRAY}%-4s %-45s %-35s %-12s${NC}\n" "#" "Display Name" "Availability Domain" "Status"
    echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
    for i in "${!DELETE_OCIDS[@]}"; do
        local state_color
        state_color=$(color_resource_state "${DELETE_STATES[$i]}")
        printf "  ${YELLOW}%-4s${NC} ${WHITE}%-45s${NC} ${CYAN}%-35s${NC} ${state_color}%-12s${NC}\n" \
            "${DELETE_NUMS[$i]})" "${DELETE_NAMES[$i]}" "${DELETE_ADS[$i]}" "${DELETE_STATES[$i]}"
    done
    echo ""

    # Show exact commands that will be executed
    echo -e "${BOLD}Commands to Execute:${NC}"
    for i in "${!DELETE_OCIDS[@]}"; do
        echo -e "  ${WHITE}$ oci compute compute-cluster delete --compute-cluster-id \"${DELETE_OCIDS[$i]}\" --region \"${region}\" --force${debug_flag:+ $debug_flag}${NC}"
    done
    echo ""

    echo -e "${RED}This action cannot be undone!${NC}"
    echo -e "${WHITE}Log file: ${CYAN}${log_file}${NC}"
    echo ""

    # Confirmation
    if [[ ${#DELETE_OCIDS[@]} -gt 1 ]]; then
        if ! _ui_confirm "DELETE ${#DELETE_OCIDS[@]}" "confirm deletion of ${#DELETE_OCIDS[@]} clusters"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    else
        if ! _ui_confirm "DELETE" "confirm deletion"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    fi

    # Execute deletions
    echo ""
    local success_count=0
    local fail_count=0

    for i in "${!DELETE_OCIDS[@]}"; do
        local sel_ocid="${DELETE_OCIDS[$i]}"
        local sel_name="${DELETE_NAMES[$i]}"
        local sel_ad="${DELETE_ADS[$i]}"
        local sel_num="${DELETE_NUMS[$i]}"

        local cmd="oci compute compute-cluster delete --compute-cluster-id ${sel_ocid} --region ${region} --force${debug_flag:+ $debug_flag}"

        echo -e "${GRAY}$ ${cmd}${NC}"

        # Log the command
        {
            echo "=========================================="
            echo "Compute Cluster Deletion [#${sel_num}]"
            echo "Timestamp: $(date)"
            echo "Display Name:        ${sel_name}"
            echo "OCID:                ${sel_ocid}"
            echo "Availability Domain: ${sel_ad}"
            echo "Command: ${cmd}"
            echo "=========================================="
        } >> "$log_file"

        log_action "DELETE" "$cmd"
        local result
        result=$(_safe_exec "$cmd")
        local exit_code=$?

        echo "$result" >> "$log_file"

        if [[ $exit_code -eq 0 ]]; then
            echo -e "${GREEN}✓ Deleted: ${WHITE}${sel_name}${NC} ${GRAY}(#${sel_num})${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted CC '${sel_name}' (${sel_ocid})" >> "$log_file"
            ((success_count++))
        else
            echo -e "${RED}✗ Failed: ${WHITE}${sel_name}${NC} ${GRAY}(#${sel_num})${NC}"
            echo -e "  ${RED}${result}${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete CC '${sel_name}' (${sel_ocid}): ${result}" >> "$log_file"
            ((fail_count++))
        fi
        echo ""
    done

    # Summary
    _ui_subheader "Delete Summary" 0
    echo -e "  ${GREEN}Succeeded:${NC} ${success_count}"
    [[ $fail_count -gt 0 ]] && echo -e "  ${RED}Failed:${NC}    ${fail_count}"
    echo -e "  ${GRAY}Log file:  ${log_file}${NC}"
    echo ""

    # Invalidate compute cluster cache
    rm -f "$COMPUTE_CLUSTER_CACHE"
    echo -e "${GRAY}(Compute cluster cache cleared)${NC}"

    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Create Compute Cluster interactively
#--------------------------------------------------------------------------------
create_compute_cluster_interactive() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local selected_ad="${FOCUS_AD:-$AD}"
    # Compute cluster needs a single AD — use first if multi-AD selected
    [[ "$selected_ad" == *","* ]] && selected_ad="${selected_ad%%,*}"
    local shape_name="${SHAPE_NAME:-GPU}"
    
    echo ""
    _ui_menu_header "CREATE COMPUTE CLUSTER"
    echo ""
    
    # Validate required variables
    local missing_vars=""
    [[ -z "$compartment_id" ]] && missing_vars+="COMPARTMENT_ID "
    [[ -z "$selected_ad" ]] && missing_vars+="AD "
    
    if [[ -n "$missing_vars" ]]; then
        echo -e "${RED}Missing required variables in variables.sh:${NC}"
        echo -e "${YELLOW}  $missing_vars${NC}"
        echo ""
        echo -e "${WHITE}Please run ${CYAN}--setup${WHITE} or manually configure variables.sh${NC}"
        echo ""
        _ui_pause "return"
        return 1
    fi
    
    _ui_env_info
    echo -e "  ${CYAN}Availability Domain:${NC} ${WHITE}${selected_ad}${NC}"
    echo -e "  ${CYAN}Shape:${NC}               ${WHITE}${shape_name}${NC}"
    [[ "$DEBUG_MODE" == "true" ]] && echo -e "  ${CYAN}Debug Mode:${NC}          ${YELLOW}ENABLED${NC}"
    echo ""
    
    # ========== Enter Display Name ==========
    _ui_subheader "Compute Cluster Display Name" 0
    echo ""
    
    # Default name based on shape from variables.sh
    local default_name="${shape_name}-Compute-Cluster"
    echo -e "${WHITE}Common naming patterns:${NC}"
    echo -e "  ${GRAY}- <shape>-Compute-Cluster (e.g., BM.GPU.H100.8-Compute-Cluster)${NC}"
    echo -e "  ${GRAY}- <project>-cc-<ad> (e.g., ml-training-cc-ad1)${NC}"
    echo ""
    
    echo -n -e "${CYAN}Enter display name [${default_name}]: ${NC}"
    local display_name
    read -r display_name
    
    [[ -z "$display_name" ]] && display_name="$default_name"
    
    echo -e "${GREEN}✓ Display Name: ${WHITE}${display_name}${NC}"
    echo ""
    
    # Use global DEBUG_MODE (set via --debug command line flag)
    local debug_flag=""
    if [[ "$DEBUG_MODE" == "true" ]]; then
        debug_flag="--debug"
    fi
    
    # ========== Show Command and Confirm ==========
    _ui_menu_header "COMMAND TO EXECUTE"
    echo ""
    
    local cmd="oci compute compute-cluster create \\
    --availability-domain \"${selected_ad}\" \\
    --compartment-id \"${compartment_id}\" \\
    --region \"${region}\" \\
    --display-name \"${display_name}\""
    
    [[ -n "$debug_flag" ]] && cmd="${cmd} \\
    ${debug_flag}"
    
    echo -e "${WHITE}${cmd}${NC}"
    echo ""
    
    # Log file for the action
    local log_file="${LOGS_DIR}/compute_cluster_create_$(date +%Y%m%d_%H%M%S).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    _ui_subheader "CONFIRM CREATION" 0
    echo ""
    echo -e "${YELLOW}This will create a new Compute Cluster.${NC}"
    echo -e "${WHITE}Log file: ${CYAN}${log_file}${NC}"
    echo ""
    if ! _ui_confirm "CREATE" "confirm, or anything else to cancel" "$CYAN"; then
        echo -e "${YELLOW}Cancelled.${NC}"
        _ui_pause "return"
        return 0
    fi
    
    # ========== Execute the Command ==========
    echo ""
    echo -e "${YELLOW}Creating Compute Cluster...${NC}"
    
    # Log the command
    {
        echo "=========================================="
        echo "Compute Cluster Creation"
        echo "Timestamp: $(date)"
        echo "=========================================="
        echo ""
        echo "Display Name:        ${display_name}"
        echo "Availability Domain: ${selected_ad}"
        echo "Compartment ID:      ${compartment_id}"
        echo "Region:              ${region}"
        echo "Debug Mode:          ${debug_flag:-disabled}"
        echo ""
        echo "Command:"
        echo "oci compute compute-cluster create \\"
        echo "    --availability-domain \"${selected_ad}\" \\"
        echo "    --compartment-id \"${compartment_id}\" \\"
        echo "    --region \"${region}\" \\"
        echo "    --display-name \"${display_name}\" ${debug_flag}"
        echo ""
        echo "=========================================="
        echo "Execution Output:"
        echo "=========================================="
    } > "$log_file"
    
    local result
    if [[ -n "$debug_flag" ]]; then
        log_action "CREATE" "$cmd"
        result=$(oci compute compute-cluster create \
            --availability-domain "${selected_ad}" \
            --compartment-id "${compartment_id}" \
            --region "$region" \
            --display-name "${display_name}" \
            --debug 2>&1)
    else
        log_action "CREATE" "$cmd"
        result=$(oci compute compute-cluster create \
            --availability-domain "${selected_ad}" \
            --compartment-id "${compartment_id}" \
            --region "$region" \
            --display-name "${display_name}" 2>&1)
    fi
    local exit_code=$?
    
    # Log the result
    echo "$result" >> "$log_file"
    
    if [[ $exit_code -eq 0 ]]; then
        local new_ocid
        new_ocid=$(jq -r '.data.id // empty' <<< "$result" 2>/dev/null)
        local new_state
        new_state=$(jq -r '.data["lifecycle-state"] // "UNKNOWN"' <<< "$result" 2>/dev/null)
        
        echo ""
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                                        COMPUTE CLUSTER CREATED                                                  ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "  ${CYAN}Display Name:${NC}        ${WHITE}${display_name}${NC}"
        echo -e "  ${CYAN}OCID:${NC}                ${YELLOW}${new_ocid}${NC}"
        echo -e "  ${CYAN}Availability Domain:${NC} ${WHITE}${selected_ad}${NC}"
        echo -e "  ${CYAN}State:${NC}               ${GREEN}${new_state}${NC}"
        echo ""
        echo -e "  ${WHITE}Log file: ${CYAN}${log_file}${NC}"
        echo ""
        
        # Invalidate compute cluster cache
        rm -f "$COMPUTE_CLUSTER_CACHE"
        echo -e "${GRAY}(Compute cluster cache cleared - will refresh on next access)${NC}"
        
        # Log success
        {
            echo ""
            echo "=========================================="
            echo "Result: SUCCESS"
            echo "New OCID: ${new_ocid}"
            echo "State: ${new_state}"
            echo "=========================================="
        } >> "$log_file"
    else
        echo ""
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                                      COMPUTE CLUSTER CREATION FAILED                                            ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${RED}Error:${NC}"
        echo "$result"
        echo ""
        echo -e "  ${WHITE}Log file: ${CYAN}${log_file}${NC}"
        
        # Log failure
        {
            echo ""
            echo "=========================================="
            echo "Result: FAILED"
            echo "Exit Code: ${exit_code}"
            echo "=========================================="
        } >> "$log_file"
    fi
    
    echo ""
    _ui_pause
}

#===============================================================================
# INSTANCE POOL MANAGEMENT
#===============================================================================

#--------------------------------------------------------------------------------
# Manage Instance Pools - Main menu for instance pool operations
# OCI Commands: oci compute-management instance-pool list/get/create/update/terminate
#--------------------------------------------------------------------------------
manage_instance_pools() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/instance_pool_actions_$(whoami)_$(date +%Y%m%d).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    while true; do
        echo ""
        _ui_menu_header "INSTANCE POOL MANAGEMENT" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Instance Pools" \
            --cmd "oci compute-management instance-pool list --compartment-id \$COMPARTMENT_ID --all | oci compute-management instance-pool get" \
            --env \
            --cache \
            "${INSTANCE_POOL_CACHE}|Instance Pools"

        # ── Discovery ──
        _step_init
        local pools_json=""
        if is_cache_fresh "$INSTANCE_POOL_CACHE"; then
            pools_json=$(cat "$INSTANCE_POOL_CACHE" 2>/dev/null)
            local pool_ct
            pool_ct=$(jq -r '.data | length' <<< "$pools_json" 2>/dev/null || echo "0")
            _step_complete "instance pools(${pool_ct} cached)"
        else
            _step_active "instance pools"
            pools_json=$(oci compute-management instance-pool list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --all --output json 2>/dev/null)
            if [[ -n "$pools_json" ]]; then
                echo "$pools_json" | _cache_write "$INSTANCE_POOL_CACHE"
                local pool_ct
                pool_ct=$(jq -r '.data | length' <<< "$pools_json" 2>/dev/null || echo "0")
                _step_complete "instance pools(${pool_ct})"
            else
                _step_complete "instance pools(0)"
                pools_json='{"data":[]}'
            fi
        fi
        _step_finish

        # ========== Display Instance Pools ==========
        _ui_subheader "Instance Pools" 0
        echo ""

        local pool_count=0
        declare -a POOL_LIST=()

        local pool_data
        pool_data=$(jq -r '.data[] | [
            .id,
            ."display-name",
            ."lifecycle-state",
            (.size // 0),
            ."instance-configuration-id",
            (."time-created" // "N/A")
        ] | @tsv' <<< "$pools_json" 2>/dev/null)

        if [[ -n "$pool_data" ]]; then
            printf "  ${BOLD}%-4s %-40s %-12s %-6s %-20s %s${NC}\n" "#" "Display Name" "State" "Size" "Created" "OCID"
            echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"

            while IFS=$'\t' read -r p_ocid p_name p_state p_size p_ic_id p_created; do
                [[ -z "$p_ocid" ]] && continue
                [[ "$p_state" == "TERMINATED" ]] && continue
                ((pool_count++))
                POOL_LIST+=("${p_ocid}|${p_name}|${p_state}|${p_size}|${p_ic_id}")

                local state_color
                state_color=$(color_resource_state "$p_state")
                local time_display="${p_created:0:16}"
                time_display="${time_display/T/ }"

                printf "  ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${state_color}%-12s${NC} ${CYAN}%-6s${NC} ${GRAY}%-20s${NC} ${YELLOW}%s${NC}\n" \
                    "$pool_count)" "${p_name:0:40}" "$p_state" "$p_size" "$time_display" "$p_ocid"
            done <<< "$pool_data"
        fi

        if [[ $pool_count -eq 0 ]]; then
            echo -e "  ${GRAY}(No instance pools found)${NC}"
        else
            echo ""
            echo -e "  ${WHITE}Total: ${GREEN}${pool_count}${WHITE} instance pool(s)${NC}"
        fi
        echo ""

        # ========== Menu Options ==========
        _ui_actions
        echo ""
        if [[ $pool_count -gt 0 ]]; then
            echo -e "  ${CYAN}#${NC}) ${WHITE}View${NC}      - View instance pool details (enter number)"
        fi
        echo -e "  ${GREEN}c${NC}) ${WHITE}Create${NC}    - Create a new instance pool"
        if [[ $pool_count -gt 0 ]]; then
            echo -e "  ${RED}d${NC}) ${WHITE}Terminate${NC} - Terminate an instance pool"
        fi
        echo -e "  ${MAGENTA}r${NC}) ${WHITE}Refresh${NC}   - Refresh instance pool list"
        echo -e "  ${CYAN}b${NC}) ${WHITE}Back${NC}      - Return to Compute menu"
        echo ""
        _ui_prompt "Instance Pools" "#, c, d, r, b, show"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            c|C|create|CREATE)
                create_instance_pool_interactive "$compartment_id" "$region" "$log_file"
                rm -f "$INSTANCE_POOL_CACHE"
                ;;
            d|D|delete|DELETE|terminate|TERMINATE)
                if [[ $pool_count -eq 0 ]]; then
                    echo -e "${YELLOW}No instance pools available to terminate${NC}"
                    sleep 1
                else
                    terminate_instance_pool_interactive "$compartment_id" "$log_file"
                    rm -f "$INSTANCE_POOL_CACHE"
                fi
                ;;
            r|R|refresh|REFRESH)
                rm -f "$INSTANCE_POOL_CACHE"
                echo -e "${GREEN}Cache cleared, refreshing...${NC}"
                sleep 1
                ;;
            b|B|back|BACK|"")
                return
                ;;
            [0-9]*)
                if [[ "$choice" =~ ^[0-9]+$ ]] && [[ $choice -ge 1 ]] && [[ $choice -le $pool_count ]]; then
                    local selected="${POOL_LIST[$((choice-1))]}"
                    local sel_ocid sel_name sel_state sel_size sel_ic_id
                    IFS='|' read -r sel_ocid sel_name sel_state sel_size sel_ic_id <<< "$selected"
                    view_instance_pool_details "$sel_ocid" "$sel_name" "$compartment_id" "$log_file"
                    rm -f "$INSTANCE_POOL_CACHE"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            show|SHOW)
                continue
                ;;
            env*|ENV*) _env_dispatch "$choice" ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

#--------------------------------------------------------------------------------
# View Instance Pool Details
# OCI Commands: oci compute-management instance-pool get
#               oci compute-management instance-pool list-instances
#--------------------------------------------------------------------------------
view_instance_pool_details() {
    local pool_ocid="$1"
    local pool_name="${2:-}"
    local compartment_id="${3:-${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}}"
    local log_file="${4:-}"
    local region="${FOCUS_REGION:-$REGION}"

    # ── Pool WR detail with related instance work requests ──
    # Follows the same pattern as _k1_wr_detail (cluster) and _np_wr_detail (nodepool)
    # Uses: _WR_OCID_NAMES (populated by caller), _pool_tmpd, compartment_id, region
    _pool_wr_detail() {
        local _wrid="$1"

        echo ""
        _ui_menu_header "WORK REQUEST DETAIL" \
            --breadcrumb "Compute" "Instance Pools" "Work Requests" "Detail" \
            --cmd "oci work-requests work-request get --work-request-id \$WR_OCID | oci work-requests work-request-log-entry list --work-request-id \$WR_OCID --all | oci work-requests work-request-error list --work-request-id \$WR_OCID --all" \
            --env

        # ── Fetch WR detail + logs + errors in parallel ──
        local _wrtmpd="$_pool_tmpd/wr_detail"
        mkdir -p "$_wrtmpd"

        _step_init
        _step_active "work request"
        local _wpids=()
        (oci work-requests work-request get --work-request-id "$_wrid" --output json > "$_wrtmpd/wr.json" 2>/dev/null) &
        _wpids+=($!)
        (oci work-requests work-request-log-entry list --work-request-id "$_wrid" --all --output json > "$_wrtmpd/logs.json" 2>/dev/null) &
        _wpids+=($!)
        (oci work-requests work-request-error list --work-request-id "$_wrid" --all --output json > "$_wrtmpd/errors.json" 2>/dev/null) &
        _wpids+=($!)
        wait "${_wpids[@]}"

        local _log_ct=0 _err_ct=0
        [[ -s "$_wrtmpd/logs.json" ]] && _log_ct=$(jq '(.data // .items // []) | length' "$_wrtmpd/logs.json" 2>/dev/null || echo "0")
        [[ -s "$_wrtmpd/errors.json" ]] && _err_ct=$(jq '(.data // .items // []) | length' "$_wrtmpd/errors.json" 2>/dev/null || echo "0")
        _step_complete "detail"
        _step_complete "logs(${_log_ct})"
        _step_complete "errors(${_err_ct})"
        _step_finish

        # ── Header ──
        local _wd_status="UNKNOWN" _wd_op="N/A" _wd_pct="N/A"
        local _wd_accepted="N/A" _wd_started="N/A" _wd_finished="N/A"
        if [[ -s "$_wrtmpd/wr.json" ]] && jq -e '.data' "$_wrtmpd/wr.json" >/dev/null 2>&1; then
            _wd_status=$(jq -r '.data.status // "UNKNOWN"' "$_wrtmpd/wr.json")
            _wd_op=$(jq -r '.data["operation-type"] // .data.operationType // "N/A"' "$_wrtmpd/wr.json")
            _wd_pct=$(jq -r '(.data["percent-complete"] // .data.percentComplete // null) | if . == null then "N/A" elif . == 0 then "0" else (. * 100 | round / 100 | tostring) end' "$_wrtmpd/wr.json" 2>/dev/null)
            [[ -z "$_wd_pct" || "$_wd_pct" == "null" ]] && _wd_pct="N/A"
            _wd_accepted=$(jq -r '.data["time-accepted"] // .data.timeAccepted // "N/A"' "$_wrtmpd/wr.json")
            _wd_started=$(jq -r '.data["time-started"] // .data.timeStarted // "N/A"' "$_wrtmpd/wr.json")
            _wd_finished=$(jq -r '.data["time-finished"] // .data.timeFinished // "N/A"' "$_wrtmpd/wr.json")
        fi

        local _sc="${WHITE}"
        [[ "$_wd_status" == "SUCCEEDED" ]] && _sc="${GREEN}"
        [[ "$_wd_status" == "FAILED" || "$_wd_status" == "CANCELED" ]] && _sc="${RED}"
        [[ "$_wd_status" == "IN_PROGRESS" || "$_wd_status" == "ACCEPTED" ]] && _sc="${YELLOW}"

        local _duration=""
        if [[ "$_wd_started" != "N/A" && "$_wd_finished" != "N/A" ]]; then
            local _ts1 _ts2
            _ts1=$(date -d "$_wd_started" +%s 2>/dev/null) || true
            _ts2=$(date -d "$_wd_finished" +%s 2>/dev/null) || true
            if [[ -n "$_ts1" && -n "$_ts2" ]]; then
                local _ds=$(( _ts2 - _ts1 ))
                if [[ "$_ds" -ge 3600 ]]; then _duration="$((_ds/3600))h $(( (_ds%3600)/60 ))m $((_ds%60))s"
                elif [[ "$_ds" -ge 60 ]]; then _duration="$((_ds/60))m $((_ds%60))s"
                else _duration="${_ds}s"; fi
            fi
        fi

        echo ""
        echo -e "  ${CYAN}Work Request:${NC}  ${YELLOW}${_wrid}${NC}"
        echo -e "  ${CYAN}Operation:${NC}     ${_wd_op}"
        echo -e "  ${CYAN}Status:${NC}        ${_sc}${_wd_status}${NC}"
        [[ "$_wd_pct" != "N/A" ]] && echo -e "  ${CYAN}Progress:${NC}      ${_wd_pct}%"
        echo -e "  ${CYAN}Accepted:${NC}      ${_wd_accepted}"
        echo -e "  ${CYAN}Started:${NC}       ${_wd_started}"
        echo -e "  ${CYAN}Finished:${NC}      ${_wd_finished}${_duration:+  (${_duration})}"

        # ── Resources ──
        local _res_ct
        _res_ct=$(jq '(.data.resources // []) | length' "$_wrtmpd/wr.json" 2>/dev/null || echo "0")
        if [[ "$_res_ct" -gt 0 ]]; then
            declare -A _RES_STATE=()
            local _rs_pids=()
            mkdir -p "$_wrtmpd/rs"
            while IFS= read -r _rid; do
                [[ -z "$_rid" ]] && continue
                local _rk="${_rid##*.}"
                case "$_rid" in
                    ocid1.instance.*)    (oci compute instance get --instance-id "$_rid" --query 'data."lifecycle-state"' --raw-output > "$_wrtmpd/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                    ocid1.instancepool.*) (oci compute-management instance-pool get --instance-pool-id "$_rid" --query 'data."lifecycle-state"' --raw-output > "$_wrtmpd/rs/${_rk}" 2>/dev/null) & _rs_pids+=($!) ;;
                esac
            done < <(jq -r '(.data.resources // [])[] | .identifier // empty' "$_wrtmpd/wr.json" 2>/dev/null)
            [[ ${#_rs_pids[@]} -gt 0 ]] && wait "${_rs_pids[@]}"
            while IFS= read -r _rid; do
                [[ -z "$_rid" ]] && continue
                local _rk="${_rid##*.}"
                [[ -s "$_wrtmpd/rs/${_rk}" ]] && _RES_STATE["$_rid"]=$(cat "$_wrtmpd/rs/${_rk}")
            done < <(jq -r '(.data.resources // [])[] | .identifier // empty' "$_wrtmpd/wr.json" 2>/dev/null)

            echo ""
            echo -e "  ${BOLD}Resources (${_res_ct}):${NC}"
            printf "    ${BOLD}%-14s %-14s %-12s %-50s %s${NC}\n" "Type" "Action" "State" "Display Name" "OCID"
            while IFS=$'\t' read -r _rt _ra _ri; do
                [[ -z "$_ri" ]] && continue
                local _rn="${_WR_OCID_NAMES[$_ri]:-—}"
                local _rs="${_RES_STATE[$_ri]:-—}"
                local _rsc; _rsc=$(color_resource_state "$_rs")
                printf "    ${WHITE}%-14s${NC} %-14s ${_rsc}%-12s${NC} ${WHITE}%-50s${NC} ${YELLOW}%s${NC}\n" \
                    "$_rt" "$_ra" "$_rs" "$_rn" "$_ri"
            done < <(jq -r '(.data.resources // [])[] | [(.["entity-type"] // .entityType // "N/A"), (.["action-type"] // .actionType // "N/A"), (.identifier // "N/A")] | @tsv' "$_wrtmpd/wr.json" 2>/dev/null)
        fi

        # ── Logs & Errors ──
        _wr_display_logs "$_wrtmpd/logs.json"
        _wr_display_errors "$_wrtmpd/errors.json"

        # ── Related Instance Work Requests ──
        # Scan logs, errors, and resources for instance OCIDs
        declare -A _seen_inst=()
        local _rel_inst_ids=()
        local _all_text=""
        [[ -s "$_wrtmpd/logs.json" ]] && _all_text+=$(jq -r '(.data // [])[] | .message // ""' "$_wrtmpd/logs.json" 2>/dev/null)
        _all_text+=$'\n'
        [[ -s "$_wrtmpd/errors.json" ]] && _all_text+=$(jq -r '(.data // [])[] | .message // ""' "$_wrtmpd/errors.json" 2>/dev/null)
        _all_text+=$'\n'
        [[ -s "$_wrtmpd/wr.json" ]] && _all_text+=$(jq -r '(.data.resources // [])[] | .identifier // ""' "$_wrtmpd/wr.json" 2>/dev/null)

        while IFS= read -r _iid; do
            [[ -n "$_iid" && -z "${_seen_inst[$_iid]:-}" ]] && {
                _seen_inst["$_iid"]=1
                _rel_inst_ids+=("$_iid")
            }
        done < <(grep -oP 'ocid1\.instance\.[a-z0-9.]+' <<< "$_all_text" 2>/dev/null | sort -u)

        declare -A _SUB_WR_MAP=()
        local _SUB_WR_IDX=0

        if [[ ${#_rel_inst_ids[@]} -gt 0 ]]; then
            echo ""
            echo -e "  ${BOLD}${CYAN}━━━ Related Instance Work Requests ━━━${NC}"
            echo -e "  ${GRAY}Fetching work requests for ${#_rel_inst_ids[@]} instance(s)...${NC}"

            mkdir -p "$_wrtmpd/sub_wr"
            local _sw_pids=()
            for _sid in "${_rel_inst_ids[@]}"; do
                local _sk="${_sid##*.}"
                (oci work-requests work-request list --compartment-id "$compartment_id" --resource-id "$_sid" --output json > "$_wrtmpd/sub_wr/${_sk}_list.json" 2>/dev/null) &
                _sw_pids+=($!)
            done
            wait "${_sw_pids[@]}"

            # Time window: parent WR accepted → finished (with 5min buffer each side)
            local _pw_start _pw_end
            _pw_start=$(date -d "${_wd_started:-now} - 5 minutes" +%s 2>/dev/null || echo "0")
            _pw_end=$(date -d "${_wd_finished:-now} + 5 minutes" +%s 2>/dev/null || echo "$(date +%s)")
            [[ "$_pw_start" == "0" ]] && _pw_start=$(( _pw_end - 7200 ))

            echo ""
            printf "  ${BOLD}%-5s %-50s %-14s %-24s %-20s %-20s %s${NC}\n" "#" "Instance" "Status" "Operation" "Started" "Finished" "Work Request ID"
            print_separator 170

            for _sid in "${_rel_inst_ids[@]}"; do
                local _sk="${_sid##*.}"
                local _sname="${_WR_OCID_NAMES[$_sid]:-${_sk:0:20}}"
                local _had_match=0

                if [[ ! -s "$_wrtmpd/sub_wr/${_sk}_list.json" ]] || ! jq -e '.data[0]' "$_wrtmpd/sub_wr/${_sk}_list.json" >/dev/null 2>&1; then
                    printf "  ${GRAY}%-5s${NC} ${WHITE}%-50s${NC} ${GRAY}%-14s${NC}\n" "-" "$_sname" "no WRs found"
                    continue
                fi

                while IFS=$'\t' read -r _sw_id _sw_status _sw_op _sw_accepted _sw_finished; do
                    [[ -z "$_sw_id" || "$_sw_id" == "N/A" ]] && continue
                    local _sw_ts
                    _sw_ts=$(date -d "$_sw_accepted" +%s 2>/dev/null || echo "0")
                    [[ "$_sw_ts" -lt "$_pw_start" || "$_sw_ts" -gt "$_pw_end" ]] && continue
                    _had_match=1

                    ((_SUB_WR_IDX++))
                    _SUB_WR_MAP[$_SUB_WR_IDX]="${_sw_id}|${_sid}|${_sname}"

                    local _swc="${WHITE}"
                    [[ "$_sw_status" == "SUCCEEDED" ]] && _swc="${GREEN}"
                    [[ "$_sw_status" == "FAILED" || "$_sw_status" == "CANCELED" ]] && _swc="${RED}"
                    [[ "$_sw_status" == "IN_PROGRESS" || "$_sw_status" == "ACCEPTED" ]] && _swc="${YELLOW}"
                    local _sf_disp="${_sw_finished:0:19}"
                    [[ "$_sw_finished" == "null" || "$_sw_finished" == "N/A" || -z "$_sw_finished" ]] && _sf_disp="-"

                    printf "  ${YELLOW}%-5s${NC} ${WHITE}%-50s${NC} ${_swc}%-14s${NC} %-24s %-20s %-20s ${YELLOW}%s${NC}\n" \
                        "i${_SUB_WR_IDX}" "$_sname" "$_sw_status" "${_sw_op:0:24}" "${_sw_accepted:0:19}" "$_sf_disp" "$_sw_id"
                done < <(jq -r '(.data // [])[] | [
                    (.id // "N/A"),
                    (.status // "UNKNOWN"),
                    (.["operation-type"] // .operationType // "N/A"),
                    (.["time-accepted"] // .timeAccepted // "N/A"),
                    (.["time-finished"] // .timeFinished // "null")
                ] | @tsv' "$_wrtmpd/sub_wr/${_sk}_list.json" 2>/dev/null)
                [[ "$_had_match" -eq 0 ]] && printf "  ${GRAY}%-5s${NC} ${WHITE}%-50s${NC} ${GRAY}%-14s${NC}\n" "-" "$_sname" "no WRs in window"
            done

            if [[ "$_SUB_WR_IDX" -gt 0 ]]; then
                echo ""
                echo -e "  ${GRAY}Use i# to drill into instance WR detail (e.g. i1, i2)${NC}"
            else
                echo -e "  ${GRAY}No instance work requests found in parent WR time window${NC}"
            fi
        fi
        echo ""

        # ── Sub-WR drill-down helper ──
        _pool_sub_wr_detail() {
            local _sw_id="$1" _sw_inst_id="$2" _sw_inst_name="$3"
            _wr_generic_detail "$_sw_id" "$_wrtmpd/sub_wr/detail" \
                "Instance WR Detail: ${GREEN}${_sw_inst_name}${NC}${BOLD}${CYAN}" \
                "${WHITE}Instance:${NC} ${YELLOW}${_sw_inst_id}${NC}" \
                "enrich"
        }

        # ── Actions ──
        _ui_actions
        if [[ "$_SUB_WR_IDX" -gt 0 ]]; then
            echo -e "  ${YELLOW}i#${NC})     Drill into instance work request (e.g., ${WHITE}i1${NC}, ${WHITE}i2${NC})"
        fi
        echo -e "  ${YELLOW}r${NC})      Refresh (re-fetch work request)"
        echo -e "  ${YELLOW}d${NC})      Detail JSON"
        echo -e "  ${YELLOW}l${NC})      Logs JSON"
        echo -e "  ${YELLOW}e${NC})      Errors JSON"
        echo -e "  ${CYAN}Enter${NC})  Back"
        echo ""

        # ── Action loop ──
        while true; do
            local _i_hint=""
            [[ "$_SUB_WR_IDX" -gt 0 ]] && _i_hint="i#, "
            _ui_prompt "Pool WR - ${pool_name}" "${_i_hint}r, d, l, e, Enter=back"
            local _rj; read -r _rj
            [[ "${_rj:-}" == :* ]] && _nav_try_jump "$_rj" && return
            case "$_rj" in
                r|R)
                    _pool_wr_detail "$_wrid"
                    return
                    ;;
                i[0-9]*|I[0-9]*)
                    local _inum="${_rj//[^0-9]/}"
                    if [[ -n "${_SUB_WR_MAP[$_inum]:-}" ]]; then
                        local _sw_entry="${_SUB_WR_MAP[$_inum]}"
                        local _sw_id="${_sw_entry%%|*}"
                        local _sw_rest="${_sw_entry#*|}"
                        local _sw_inst_id="${_sw_rest%%|*}"
                        local _sw_inst_name="${_sw_rest#*|}"
                        _pool_sub_wr_detail "$_sw_id" "$_sw_inst_id" "$_sw_inst_name"
                    else
                        echo -e "  ${RED}Invalid selection i${_inum}. Valid: i1-i${_SUB_WR_IDX}${NC}"
                    fi
                    ;;
                d|D) jq -C '.' "$_wrtmpd/wr.json" 2>/dev/null ;;
                l|L) jq -C '.' "$_wrtmpd/logs.json" 2>/dev/null ;;
                e|E) jq -C '.' "$_wrtmpd/errors.json" 2>/dev/null ;;
                *)   break ;;
            esac
        done
    }

  while true; do
    echo ""
    _ui_detail_banner "Instance Pool" "$pool_name" "${BOLD}${YELLOW}"
    echo ""

    # Parallel discovery: pool details + instances + work requests
    local _pool_tmpd="${TEMP_DIR}/pool_detail_$$"
    mkdir -p "$_pool_tmpd"

    _step_init
    _step_active "pool details+instances+work requests(3 parallel)"
    (oci compute-management instance-pool get \
        --instance-pool-id "$pool_ocid" --region "$region" \
        --output json > "$_pool_tmpd/pool.json" 2>/dev/null) &
    local _pp1=$!
    (oci compute-management instance-pool list-instances \
        --instance-pool-id "$pool_ocid" --compartment-id "$compartment_id" \
        --region "$region" --all --output json > "$_pool_tmpd/instances.json" 2>/dev/null) &
    local _pp2=$!
    (oci work-requests work-request list \
        --compartment-id "$compartment_id" --resource-id "$pool_ocid" \
        --all --output json > "$_pool_tmpd/wr.json" 2>/dev/null) &
    local _pp3=$!
    wait $_pp1 $_pp2 $_pp3 2>/dev/null
    _step_complete "pool details"
    _step_complete "instances"
    _step_complete "work requests"
    _step_finish

    local pool_json=""
    [[ -s "$_pool_tmpd/pool.json" ]] && pool_json=$(<"$_pool_tmpd/pool.json")

    if [[ -z "$pool_json" ]] || ! jq -e '.data' <<< "$pool_json" > /dev/null 2>&1; then
        echo -e "${RED}Failed to fetch instance pool details${NC}"
        _ui_policy_hint "read instance-pools in compartment"
        rm -rf "$_pool_tmpd"
        _ui_pause "return"
        return 1
    fi

    local instances_json=""
    [[ -s "$_pool_tmpd/instances.json" ]] && instances_json=$(<"$_pool_tmpd/instances.json")
    local inst_ct
    inst_ct=$(jq -r '.data | length' <<< "$instances_json" 2>/dev/null || echo "0")

    local _pool_wr_ct=0
    [[ -s "$_pool_tmpd/wr.json" ]] && _pool_wr_ct=$(jq '(.data // []) | length' "$_pool_tmpd/wr.json" 2>/dev/null || echo "0")

    # Display pool details
    local p_name p_state p_size p_ic_id p_created p_ad
    p_name=$(jq -r '.data["display-name"] // "N/A"' <<< "$pool_json")
    p_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$pool_json")
    p_size=$(jq -r '.data.size // 0' <<< "$pool_json")
    p_ic_id=$(jq -r '.data["instance-configuration-id"] // "N/A"' <<< "$pool_json")
    p_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$pool_json")

    local state_color
    state_color=$(color_resource_state "$p_state")

    # Resolve instance configuration name
    local ic_name=""
    if [[ -n "$p_ic_id" && "$p_ic_id" != "N/A" ]]; then
        ic_name=$(oci compute-management instance-configuration get \
            --instance-configuration-id "$p_ic_id" \
            --region "$region" \
            --query 'data."display-name"' --raw-output 2>/dev/null)
    fi

    echo ""
    echo -e "  ${WHITE}Name:${NC}            ${GREEN}$p_name${NC}  ${GRAY}[${YELLOW}$pool_ocid${GRAY}]${NC}"
    echo -e "  ${WHITE}State:${NC}           ${state_color}$p_state${NC}"
    echo -e "  ${WHITE}Size:${NC}            ${CYAN}$p_size${NC}"
    echo -e "  ${WHITE}Created:${NC}         ${p_created:0:19}"
    echo -e "  ${WHITE}Instance Config:${NC} ${WHITE}${ic_name:-N/A}${NC}  ${GRAY}[${YELLOW}$p_ic_id${GRAY}]${NC}"

    # Placement details
    local placements
    placements=$(jq -r '.data["placement-configurations"][]? | "\(.["availability-domain"] // "N/A")|\(.["primary-subnet-id"] // "N/A")"' <<< "$pool_json" 2>/dev/null)
    if [[ -n "$placements" ]]; then
        echo ""
        echo -e "  ${BOLD}${CYAN}Placement Configurations:${NC}"
        local pidx=0
        while IFS='|' read -r pl_ad pl_subnet; do
            ((pidx++))
            echo -e "    ${WHITE}#${pidx} AD:${NC}     ${CYAN}$pl_ad${NC}"
            if [[ -n "$pl_subnet" && "$pl_subnet" != "N/A" ]]; then
                local pl_sn_name
                pl_sn_name=$(oci network subnet get --subnet-id "$pl_subnet" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null)
                if [[ -n "$pl_sn_name" ]]; then
                    echo -e "    ${WHITE}   Subnet:${NC}  ${WHITE}$pl_sn_name${NC}  ${YELLOW}[$pl_subnet]${NC}"
                else
                    echo -e "    ${WHITE}   Subnet:${NC}  ${YELLOW}[$pl_subnet]${NC}"
                fi
            fi
        done <<< "$placements"
    fi

    # Display pool instances
    declare -A _POOL_INST_MAP=()
    if [[ "$inst_ct" -gt 0 ]]; then
        echo ""
        echo -e "  ${BOLD}${CYAN}Pool Instances (${inst_ct}):${NC}"
        printf "    ${BOLD}%-4s %-40s %-12s %-18s %s${NC}\n" "#" "Display Name" "State" "Shape" "OCID"
        echo -e "    ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"

        local iidx=0
        while IFS=$'\t' read -r i_ocid i_name i_state i_shape; do
            [[ -z "$i_ocid" ]] && continue
            ((iidx++))
            _POOL_INST_MAP[$iidx]="$i_ocid"
            local i_state_upper="${i_state^^}"
            local i_sc
            i_sc=$(color_resource_state "$i_state_upper")
            printf "    ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${i_sc}%-12s${NC} ${CYAN}%-18s${NC} ${GRAY}%s${NC}\n" \
                "$iidx)" "${i_name:0:40}" "$i_state" "$i_shape" "$i_ocid"
        done < <(jq -r '.data[] | [.id, ."display-name", (.state // .["lifecycle-state"] // "N/A"), .shape] | @tsv' <<< "$instances_json" 2>/dev/null)
    fi

    # Display work requests
    declare -A _POOL_WR_MAP=()
    local _pool_wr_idx=0
    if [[ "$_pool_wr_ct" -gt 0 ]]; then
        echo ""
        _ui_subheader "Recent Work Requests (${_pool_wr_ct})" 0
        echo ""
        printf "  ${BOLD}%-5s %-14s %-28s %-20s %-20s %s${NC}\n" "#" "Status" "Operation" "Started" "Finished" "Work Request ID"
        print_separator 130
        while IFS=$'\t' read -r _ws _wop _wt _wf _wid; do
            [[ -z "$_wid" || "$_wid" == "N/A" ]] && continue
            ((_pool_wr_idx++))
            _POOL_WR_MAP[$_pool_wr_idx]="$_wid"
            local _wc="${WHITE}"
            [[ "$_ws" == "SUCCEEDED" ]] && _wc="${GREEN}"
            [[ "$_ws" == "FAILED" || "$_ws" == "CANCELED" ]] && _wc="${RED}"
            [[ "$_ws" == "IN_PROGRESS" || "$_ws" == "ACCEPTED" ]] && _wc="${YELLOW}"
            local _wf_disp="${_wf:0:19}"
            [[ "$_wf" == "null" || "$_wf" == "N/A" || -z "$_wf" ]] && _wf_disp="-"
            printf "  ${YELLOW}%-5s${NC} ${_wc}%-14s${NC} %-28s %-20s %-20s ${YELLOW}%s${NC}\n" \
                "wr${_pool_wr_idx}" "$_ws" "${_wop:0:28}" "${_wt:0:19}" "$_wf_disp" "${_wid}"
        done < <(jq -r '(.data // [])[] | [
            (.status // "UNKNOWN"),
            (.["operation-type"] // .operationType // "N/A"),
            (.["time-accepted"] // .timeAccepted // "N/A"),
            (.["time-finished"] // .timeFinished // "null"),
            (.id // "N/A")
        ] | @tsv' "$_pool_tmpd/wr.json" 2>/dev/null)
        echo ""
    fi

    # Actions
    echo ""
    _ui_actions
    if [[ "$inst_ct" -gt 0 ]]; then
        echo -e "  ${CYAN}#${NC}       - View instance details (e.g., '1', '2')"
    fi
    if [[ "$_pool_wr_idx" -gt 0 ]]; then
        echo -e "  ${CYAN}wr#${NC}     - View work request details (e.g., 'wr1', 'wr2')"
    fi
    echo -e "  ${YELLOW}j${NC}       - View raw JSON (j <keyword> to search)"
    echo -e "  ${CYAN}scale${NC}   - Scale pool (change size)"
    echo -e "  ${YELLOW}start${NC}   - Start all instances in pool"
    echo -e "  ${YELLOW}stop${NC}    - Stop all instances in pool"
    echo -e "  ${YELLOW}reboot${NC}  - Reboot all instances in pool"
    echo -e "  ${RED}term${NC}    - Terminate this instance pool"
    echo -e "  ${CYAN}Enter${NC}   - Return to pool list"
    echo ""
    _ui_prompt "Instance Pool" "#, wr#, j, scale, start, stop, reboot, term, b"

    local action
    read -r action
    [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return

    case "$action" in
        j|J|json|JSON)
            _ui_json_viewer "Instance Pool: ${p_name}" "$pool_json" ".data"
            ;;
        j\ *|J\ *|json\ *|JSON\ *)
            _ui_json_viewer "Instance Pool: ${p_name}" "$pool_json" ".data" "${action#* }"
            ;;
        scale|SCALE)
            echo ""
            echo -e "  ${WHITE}Current size: ${CYAN}$p_size${NC}"
            echo -n -e "  ${CYAN}Enter new size: ${NC}"
            local new_size
            read -r new_size
            if [[ "$new_size" =~ ^[0-9]+$ ]]; then
                local scale_cmd="oci compute-management instance-pool update --instance-pool-id \"${pool_ocid}\" --region \"${region}\" --size ${new_size}"
                echo ""
                echo -e "  ${WHITE}Command:${NC} ${GRAY}${scale_cmd}${NC}"
                echo ""
                if _ui_confirm "SCALE" "scale pool from ${p_size} to ${new_size}"; then
                    log_action "UPDATE" "$scale_cmd"
                    echo -e "  ${YELLOW}Scaling pool...${NC}"
                    local scale_result
                    scale_result=$(oci compute-management instance-pool update \
                        --instance-pool-id "$pool_ocid" \
                        --region "$region" \
                        --size "$new_size" --output json 2>&1)
                    local scale_exit=$?
                    if [[ $scale_exit -eq 0 ]]; then
                        echo -e "  ${GREEN}✓ Pool scaling initiated (${p_size} → ${new_size})${NC}"
                        log_action_result "SUCCESS" "SCALE from $p_size to $new_size"
                    else
                        echo -e "  ${RED}✗ Scale failed:${NC}"
                        echo "$scale_result"
                        log_action_result "FAILED" "SCALE"
                    fi
                else
                    echo -e "  ${YELLOW}Scale cancelled${NC}"
                fi
            else
                echo -e "  ${RED}Invalid size${NC}"
            fi
            echo ""
            _ui_pause "return"
            ;;
        start|START)
            local start_cmd="oci compute-management instance-pool start --instance-pool-id \"${pool_ocid}\" --region \"${region}\""
            echo ""
            echo -e "  ${WHITE}Command:${NC} ${GRAY}${start_cmd}${NC}"
            echo ""
            if _ui_confirm "START" "start all instances in pool '${p_name}'"; then
                log_action "START" "$start_cmd"
                local start_result
                start_result=$(oci compute-management instance-pool start \
                    --instance-pool-id "$pool_ocid" --region "$region" --output json 2>&1)
                if [[ $? -eq 0 ]]; then
                    echo -e "  ${GREEN}✓ Pool start initiated${NC}"
                    log_action_result "SUCCESS" "START pool"
                else
                    echo -e "  ${RED}✗ Start failed:${NC}"
                    echo "$start_result"
                    log_action_result "FAILED" "START pool"
                fi
            else
                echo -e "  ${YELLOW}Start cancelled${NC}"
            fi
            echo ""
            _ui_pause "return"
            ;;
        stop|STOP)
            local stop_cmd="oci compute-management instance-pool softstop --instance-pool-id \"${pool_ocid}\" --region \"${region}\""
            echo ""
            echo -e "  ${WHITE}Command:${NC} ${GRAY}${stop_cmd}${NC}"
            echo ""
            if _ui_confirm "STOP" "stop all instances in pool '${p_name}'"; then
                log_action "STOP" "$stop_cmd"
                local stop_result
                stop_result=$(oci compute-management instance-pool softstop \
                    --instance-pool-id "$pool_ocid" --region "$region" --output json 2>&1)
                if [[ $? -eq 0 ]]; then
                    echo -e "  ${GREEN}✓ Pool stop initiated${NC}"
                    log_action_result "SUCCESS" "STOP pool"
                else
                    echo -e "  ${RED}✗ Stop failed:${NC}"
                    echo "$stop_result"
                    log_action_result "FAILED" "STOP pool"
                fi
            else
                echo -e "  ${YELLOW}Stop cancelled${NC}"
            fi
            echo ""
            _ui_pause "return"
            ;;
        reboot|REBOOT|reset|RESET)
            local reset_cmd="oci compute-management instance-pool reset --instance-pool-id \"${pool_ocid}\" --region \"${region}\""
            echo ""
            echo -e "  ${WHITE}Command:${NC} ${GRAY}${reset_cmd}${NC}"
            echo ""
            if _ui_confirm "RESET" "reset (reboot) all instances in pool '${p_name}'"; then
                log_action "RESET" "$reset_cmd"
                local reset_result
                reset_result=$(oci compute-management instance-pool reset \
                    --instance-pool-id "$pool_ocid" --region "$region" --output json 2>&1)
                if [[ $? -eq 0 ]]; then
                    echo -e "  ${GREEN}✓ Pool reset initiated${NC}"
                    log_action_result "SUCCESS" "RESET pool"
                else
                    echo -e "  ${RED}✗ Reset failed:${NC}"
                    echo "$reset_result"
                    log_action_result "FAILED" "RESET pool"
                fi
            else
                echo -e "  ${YELLOW}Reset cancelled${NC}"
            fi
            echo ""
            _ui_pause "return"
            ;;
        term|TERM|terminate|TERMINATE)
            echo ""
            local term_cmd="oci compute-management instance-pool terminate --instance-pool-id \"${pool_ocid}\" --region \"${region}\" --force"
            echo -e "  ${RED}⚠ This will terminate the instance pool and all its instances!${NC}"
            echo -e "  ${WHITE}Command:${NC} ${GRAY}${term_cmd}${NC}"
            echo ""
            if _ui_confirm "TERMINATE" "terminate pool '${p_name}' (${p_size} instances)"; then
                log_action "TERMINATE" "$term_cmd"
                local term_result
                term_result=$(oci compute-management instance-pool terminate \
                    --instance-pool-id "$pool_ocid" --region "$region" --force 2>&1)
                if [[ $? -eq 0 ]]; then
                    echo -e "  ${GREEN}✓ Pool termination initiated${NC}"
                    log_action_result "SUCCESS" "TERMINATE pool"
                else
                    echo -e "  ${RED}✗ Terminate failed:${NC}"
                    echo "$term_result"
                    log_action_result "FAILED" "TERMINATE pool"
                fi
                echo ""
                _ui_pause "return"
                rm -rf "$_pool_tmpd"
                return
            else
                echo -e "  ${YELLOW}Terminate cancelled${NC}"
            fi
            echo ""
            _ui_pause "return"
            ;;
        wr[0-9]*|WR[0-9]*)
            # Work request detail with related instance WRs
            local _wr_num="${action#[wW][rR]}"
            if [[ -n "${_POOL_WR_MAP[$_wr_num]:-}" ]]; then
                local _pwrid="${_POOL_WR_MAP[$_wr_num]}"
                declare -A _WR_OCID_NAMES=()
                _WR_OCID_NAMES["$pool_ocid"]="$p_name"
                [[ -n "$p_ic_id" && "$p_ic_id" != "N/A" && -n "${ic_name:-}" ]] && _WR_OCID_NAMES["$p_ic_id"]="$ic_name"
                # Also map pool instance OCIDs to names
                if [[ -s "$_pool_tmpd/instances.json" ]]; then
                    while IFS=$'\t' read -r _iid _iname; do
                        [[ -n "$_iid" && -z "${_WR_OCID_NAMES[$_iid]:-}" ]] && _WR_OCID_NAMES["$_iid"]="$_iname"
                    done < <(jq -r '.data[] | [.id, ."display-name"] | @tsv' "$_pool_tmpd/instances.json" 2>/dev/null)
                fi
                _pool_wr_detail "$_pwrid"
            else
                echo -e "${RED}Invalid work request number: $action${NC}"
                sleep 1
            fi
            ;;
        [0-9]*)
            # Instance selection — navigate to instance detail view
            local _pi_ocid="${_POOL_INST_MAP[$action]:-}"
            if [[ -n "$_pi_ocid" ]]; then
                while true; do
                    display_instance_details "$_pi_ocid"
                    local _pi_ret=$?
                    [[ -n "${_NAV_JUMP:-}" ]] && break
                    [[ $_pi_ret -ne 2 ]] && break
                done
            else
                echo -e "${RED}Invalid instance number: $action${NC}"
                sleep 1
            fi
            ;;
        b|B|"")
            rm -rf "$_pool_tmpd"
            return
            ;;
        *)
            echo -e "${RED}Invalid selection${NC}"
            sleep 1
            ;;
    esac
  done  # while true — pool detail loop
  rm -rf "$_pool_tmpd"
}

#--------------------------------------------------------------------------------
# Create Instance Pool - Interactive wizard
# OCI Command: oci compute-management instance-pool create
#--------------------------------------------------------------------------------
create_instance_pool_interactive() {
    local compartment_id="$1"
    local region="$2"
    local log_file="$3"

    echo ""
    _ui_subheader "Create Instance Pool" 0
    echo ""

    # Step 1: Select Instance Configuration
    echo -e "  ${BOLD}${CYAN}Step 1: Select Instance Configuration${NC}"
    echo ""

    _step_init
    _step_active "instance configurations"
    if ! is_cache_fresh "$INSTANCE_CONFIG_CACHE"; then
        fetch_instance_configurations > /dev/null 2>&1
    fi
    _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    _step_finish

    if [[ ! -f "$INSTANCE_CONFIG_CACHE" ]] || [[ ! -s "$INSTANCE_CONFIG_CACHE" ]]; then
        echo -e "  ${RED}No instance configurations found. Create one first (Compute > Instance Configurations).${NC}"
        _ui_pause "return"
        return 1
    fi

    local ic_idx=0
    declare -A IC_SEL_MAP=()
    while IFS='|' read -r ic_ocid ic_name _; do
        [[ "$ic_ocid" =~ ^#.*$ ]] && continue
        [[ -z "$ic_ocid" ]] && continue
        ((ic_idx++))
        IC_SEL_MAP[$ic_idx]="$ic_ocid|$ic_name"
        printf "  ${YELLOW}%-4s${NC} ${WHITE}%s${NC}\n" "$ic_idx)" "$ic_name"
    done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)

    if [[ "$ic_idx" -eq 0 ]]; then
        echo -e "  ${RED}No instance configurations found.${NC}"
        echo -e "  ${YELLOW}Please create an instance configuration before creating an instance pool.${NC}"
        echo -e "  ${GRAY}(Compute > Instance Configurations > Create)${NC}"
        _ui_pause "return"
        return 1
    fi

    echo ""
    echo -n -e "  ${CYAN}Select instance configuration [1-${ic_idx}]: ${NC}"
    local ic_choice
    read -r ic_choice

    if [[ ! "$ic_choice" =~ ^[0-9]+$ ]] || [[ -z "${IC_SEL_MAP[$ic_choice]:-}" ]]; then
        echo -e "  ${RED}Invalid selection${NC}"
        _ui_pause "return"
        return 1
    fi

    local sel_ic_ocid="${IC_SEL_MAP[$ic_choice]%%|*}"
    local sel_ic_name="${IC_SEL_MAP[$ic_choice]#*|}"
    echo -e "  ${GREEN}✓ Selected: ${WHITE}${sel_ic_name}${NC}"
    echo ""

    # Step 2: Display Name
    echo -e "  ${BOLD}${CYAN}Step 2: Display Name${NC}"
    local default_pool_name="${sel_ic_name}-pool"
    echo -n -e "  ${CYAN}Enter display name [${default_pool_name}]: ${NC}"
    local pool_display_name
    read -r pool_display_name
    [[ -z "$pool_display_name" ]] && pool_display_name="$default_pool_name"
    echo -e "  ${GREEN}✓ Name: ${WHITE}${pool_display_name}${NC}"
    echo ""

    # Step 3: Pool Size
    echo -e "  ${BOLD}${CYAN}Step 3: Pool Size${NC}"
    echo -n -e "  ${CYAN}Enter initial pool size [1]: ${NC}"
    local pool_size
    read -r pool_size
    [[ -z "$pool_size" || ! "$pool_size" =~ ^[0-9]+$ ]] && pool_size=1
    echo -e "  ${GREEN}✓ Size: ${WHITE}${pool_size}${NC}"
    echo ""

    # Step 4: Availability Domain
    echo -e "  ${BOLD}${CYAN}Step 4: Availability Domain${NC}"
    local ad_list
    ad_list=$(oci iam availability-domain list --compartment-id "$compartment_id" --region "$region" --output json 2>/dev/null)
    local ad_count=0
    declare -A AD_SEL_MAP=()

    while IFS= read -r ad_name; do
        [[ -z "$ad_name" ]] && continue
        ((ad_count++))
        AD_SEL_MAP[$ad_count]="$ad_name"
        printf "  ${YELLOW}%-4s${NC} ${WHITE}%s${NC}\n" "$ad_count)" "$ad_name"
    done < <(jq -r '.data[].name' <<< "$ad_list" 2>/dev/null)

    echo ""
    echo -n -e "  ${CYAN}Select availability domain [1]: ${NC}"
    local ad_choice
    read -r ad_choice
    [[ -z "$ad_choice" || ! "$ad_choice" =~ ^[0-9]+$ ]] && ad_choice=1
    local selected_ad="${AD_SEL_MAP[$ad_choice]:-${AD_SEL_MAP[1]:-}}"

    if [[ -z "$selected_ad" ]]; then
        echo -e "  ${RED}No availability domains found${NC}"
        _ui_pause "return"
        return 1
    fi
    echo -e "  ${GREEN}✓ AD: ${WHITE}${selected_ad}${NC}"
    echo ""

    # Step 5: Subnet
    echo -e "  ${BOLD}${CYAN}Step 5: Primary Subnet${NC}"
    echo -e "  ${GRAY}Fetching subnets...${NC}"
    local subnets_json

    if [[ -n "${FOCUS_VCN_OCID:-}" ]]; then
        subnets_json=$(oci network subnet list --compartment-id "$compartment_id" --vcn-id "$FOCUS_VCN_OCID" --region "$region" --all --output json 2>/dev/null)
    else
        subnets_json=$(oci network subnet list --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
    fi

    local sn_count=0
    declare -A SN_SEL_MAP=()
    while IFS=$'\t' read -r sn_ocid sn_name sn_cidr; do
        ((sn_count++))
        SN_SEL_MAP[$sn_count]="$sn_ocid"
        printf "  ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${GRAY}%s${NC}\n" "$sn_count)" "$sn_name" "$sn_cidr"
    done < <(jq -r '.data[] | [.id, ."display-name", ."cidr-block"] | @tsv' <<< "$subnets_json" 2>/dev/null)

    if [[ $sn_count -eq 0 ]]; then
        echo -e "  ${RED}No subnets found${NC}"
        _ui_pause "return"
        return 1
    fi

    echo ""
    echo -n -e "  ${CYAN}Select primary subnet [1]: ${NC}"
    local sn_choice
    read -r sn_choice
    [[ -z "$sn_choice" || ! "$sn_choice" =~ ^[0-9]+$ ]] && sn_choice=1
    local selected_subnet="${SN_SEL_MAP[$sn_choice]:-${SN_SEL_MAP[1]:-}}"
    echo -e "  ${GREEN}✓ Subnet selected${NC}"
    echo ""

    # Build placement config JSON
    local placement_json
    placement_json=$(jq -n \
        --arg ad "$selected_ad" \
        --arg subnet "$selected_subnet" \
        '[{"availability-domain": $ad, "primary-subnet-id": $subnet}]')

    # Show command and confirm
    local create_cmd="oci compute-management instance-pool create --compartment-id \"${compartment_id}\" --instance-configuration-id \"${sel_ic_ocid}\" --placement-configurations '...' --size ${pool_size} --display-name \"${pool_display_name}\""
    echo -e "  ${BOLD}${WHITE}Command to Execute:${NC}"
    echo -e "  ${GRAY}\$ ${create_cmd}${NC}"
    echo ""

    if ! _ui_confirm "CREATE" "create instance pool '${pool_display_name}' with ${pool_size} instance(s)"; then
        echo -e "  ${YELLOW}Create cancelled${NC}"
        _ui_pause "return"
        return 0
    fi

    echo ""
    echo -e "  ${YELLOW}Creating instance pool...${NC}"

    # Log the action
    {
        echo ""
        echo "=========================================="
        echo "Action: CREATE Instance Pool"
        echo "Time: $(date '+%Y-%m-%d %H:%M:%S')"
        echo "Display Name: $pool_display_name"
        echo "Instance Config: $sel_ic_name ($sel_ic_ocid)"
        echo "Size: $pool_size"
        echo "AD: $selected_ad"
        echo "Subnet: $selected_subnet"
        echo ""
        echo "Command:"
        echo "oci compute-management instance-pool create \\"
        echo "    --compartment-id \"$compartment_id\" \\"
        echo "    --instance-configuration-id \"$sel_ic_ocid\" \\"
        echo "    --placement-configurations '$placement_json' \\"
        echo "    --size $pool_size \\"
        echo "    --display-name \"$pool_display_name\""
        echo ""
        echo "=========================================="
    } >> "$log_file"

    log_action "CREATE" "$create_cmd"
    local result
    result=$(oci compute-management instance-pool create \
        --compartment-id "$compartment_id" \
        --instance-configuration-id "$sel_ic_ocid" \
        --placement-configurations "$placement_json" \
        --size "$pool_size" \
        --display-name "$pool_display_name" \
        --region "$region" \
        --output json 2>&1)
    local exit_code=$?

    echo "$result" >> "$log_file"

    if [[ $exit_code -eq 0 ]]; then
        local new_ocid new_state
        new_ocid=$(jq -r '.data.id // empty' <<< "$result" 2>/dev/null)
        new_state=$(jq -r '.data["lifecycle-state"] // "UNKNOWN"' <<< "$result" 2>/dev/null)

        echo ""
        echo -e "  ${GREEN}╔═══════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "  ${GREEN}║                          INSTANCE POOL CREATED                              ║${NC}"
        echo -e "  ${GREEN}╚═══════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "  ${CYAN}Display Name:${NC}  ${WHITE}$pool_display_name${NC}"
        echo -e "  ${CYAN}OCID:${NC}          ${YELLOW}$new_ocid${NC}"
        echo -e "  ${CYAN}State:${NC}         ${GREEN}$new_state${NC}"
        echo -e "  ${CYAN}Size:${NC}          ${WHITE}$pool_size${NC}"
        echo ""
        echo -e "  ${WHITE}Log file: ${CYAN}${log_file}${NC}"
        log_action_result "SUCCESS" "CREATE instance pool"

        {
            echo ""
            echo "Result: SUCCESS"
            echo "New OCID: ${new_ocid}"
            echo "State: ${new_state}"
            echo "=========================================="
        } >> "$log_file"
    else
        echo ""
        echo -e "  ${RED}╔═══════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "  ${RED}║                       INSTANCE POOL CREATION FAILED                         ║${NC}"
        echo -e "  ${RED}╚═══════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "  ${RED}Error:${NC}"
        echo "  $result"
        echo ""
        echo -e "  ${WHITE}Log file: ${CYAN}${log_file}${NC}"
        log_action_result "FAILED" "CREATE instance pool"

        {
            echo ""
            echo "Result: FAILED"
            echo "Exit Code: ${exit_code}"
            echo "=========================================="
        } >> "$log_file"
    fi

    echo ""
    _ui_pause "return"
}

#--------------------------------------------------------------------------------
# Terminate Instance Pool - Interactive selection
# OCI Command: oci compute-management instance-pool terminate
#--------------------------------------------------------------------------------
terminate_instance_pool_interactive() {
    local compartment_id="$1"
    local log_file="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    echo -e "  ${RED}Select instance pool to terminate:${NC}"
    echo -n -e "  ${CYAN}Enter pool number: ${NC}"
    local pool_choice
    read -r pool_choice

    if [[ ! "$pool_choice" =~ ^[0-9]+$ ]] || [[ $pool_choice -lt 1 ]] || [[ $pool_choice -gt ${#POOL_LIST[@]} ]]; then
        echo -e "  ${RED}Invalid selection${NC}"
        _ui_pause "return"
        return 1
    fi

    local selected="${POOL_LIST[$((pool_choice-1))]}"
    local sel_ocid sel_name sel_state sel_size sel_ic
    IFS='|' read -r sel_ocid sel_name sel_state sel_size sel_ic <<< "$selected"

    echo ""
    _ui_menu_header "TERMINATE INSTANCE POOL" --color "$RED"
    echo ""
    echo -e "  ${WHITE}Pool:${NC}  ${GREEN}$sel_name${NC}"
    echo -e "  ${WHITE}OCID:${NC}  ${YELLOW}$sel_ocid${NC}"
    echo -e "  ${WHITE}State:${NC} $sel_state"
    echo -e "  ${WHITE}Size:${NC}  $sel_size instance(s)"
    echo ""
    echo -e "  ${RED}⚠ This will terminate the pool and all its instances!${NC}"

    local term_cmd="oci compute-management instance-pool terminate --instance-pool-id \"${sel_ocid}\" --force"
    echo ""
    echo -e "  ${WHITE}Command:${NC} ${GRAY}${term_cmd}${NC}"
    echo ""

    if ! _ui_confirm "TERMINATE" "confirm"; then
        echo -e "  ${YELLOW}Terminate cancelled${NC}"
        _ui_pause "return"
        return 0
    fi

    echo ""
    echo -e "  ${YELLOW}Terminating instance pool...${NC}"

    log_action "TERMINATE" "$term_cmd"
    local result
    result=$(oci compute-management instance-pool terminate \
        --instance-pool-id "$sel_ocid" --region "$region" --force 2>&1)
    local exit_code=$?

    {
        echo ""
        echo "=========================================="
        echo "Action: TERMINATE Instance Pool"
        echo "Time: $(date '+%Y-%m-%d %H:%M:%S')"
        echo "Pool: $sel_name ($sel_ocid)"
        echo "Command: $term_cmd"
        echo "Result: $([ $exit_code -eq 0 ] && echo 'SUCCESS' || echo 'FAILED')"
        echo "=========================================="
    } >> "$log_file"

    if [[ $exit_code -eq 0 ]]; then
        echo -e "  ${GREEN}✓ Instance pool termination initiated${NC}"
        log_action_result "SUCCESS" "TERMINATE pool"
    else
        echo -e "  ${RED}✗ Failed to terminate:${NC}"
        echo "  $result"
        log_action_result "FAILED" "TERMINATE pool"
    fi

    echo ""
    _ui_pause "return"
}

#===============================================================================
# CLUSTER NETWORK MANAGEMENT
#===============================================================================

#--------------------------------------------------------------------------------
# Manage Cluster Networks - View cluster networks and instances
# OCI Commands: oci compute-management cluster-network list/get
#               oci compute-management cluster-network list-instances
#--------------------------------------------------------------------------------
manage_cluster_networks() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"

    while true; do
        echo ""
        _ui_menu_header "CLUSTER NETWORK MANAGEMENT" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Cluster Networks" \
            --cmd "oci compute-management cluster-network list --compartment-id \$COMPARTMENT_ID --all | oci compute-management cluster-network get" \
            --env \
            --cache \
            "${CLUSTER_NETWORK_CACHE}|Cluster Networks"

        # ── Discovery ──
        _step_init
        local cn_json=""
        if is_cache_fresh "$CLUSTER_NETWORK_CACHE"; then
            cn_json=$(cat "$CLUSTER_NETWORK_CACHE" 2>/dev/null)
            local cn_ct
            cn_ct=$(jq -r '.data | length' <<< "$cn_json" 2>/dev/null || echo "0")
            _step_complete "cluster networks(${cn_ct} cached)"
        else
            _step_active "cluster networks"
            cn_json=$(oci compute-management cluster-network list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --all --output json 2>/dev/null)
            if [[ -n "$cn_json" ]]; then
                echo "$cn_json" | _cache_write "$CLUSTER_NETWORK_CACHE"
                local cn_ct
                cn_ct=$(jq -r '.data | length' <<< "$cn_json" 2>/dev/null || echo "0")
                _step_complete "cluster networks(${cn_ct})"
            else
                _step_complete "cluster networks(0)"
                cn_json='{"data":[]}'
            fi
        fi
        _step_finish

        # ========== Display Cluster Networks ==========
        _ui_subheader "Cluster Networks" 0
        echo ""

        local cn_count=0
        declare -a CN_LIST=()

        local cn_data
        cn_data=$(jq -r '.data[] | [
            .id,
            ."display-name",
            ."lifecycle-state",
            ."instance-pools"[0]."id" // "N/A",
            ."instance-pools"[0].size // 0,
            (."time-created" // "N/A")
        ] | @tsv' <<< "$cn_json" 2>/dev/null)

        if [[ -n "$cn_data" ]]; then
            printf "  ${BOLD}%-4s %-40s %-12s %-8s %-20s %s${NC}\n" "#" "Display Name" "State" "Pool Sz" "Created" "OCID"
            echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"

            while IFS=$'\t' read -r cn_ocid cn_name cn_state cn_pool_id cn_pool_size cn_created; do
                [[ -z "$cn_ocid" ]] && continue
                [[ "$cn_state" == "TERMINATED" ]] && continue
                ((cn_count++))
                CN_LIST+=("${cn_ocid}|${cn_name}|${cn_state}|${cn_pool_id}|${cn_pool_size}")

                local state_color
                state_color=$(color_resource_state "$cn_state")
                local time_display="${cn_created:0:16}"
                time_display="${time_display/T/ }"

                printf "  ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${state_color}%-12s${NC} ${CYAN}%-8s${NC} ${GRAY}%-20s${NC} ${YELLOW}%s${NC}\n" \
                    "$cn_count)" "${cn_name:0:40}" "$cn_state" "$cn_pool_size" "$time_display" "$cn_ocid"
            done <<< "$cn_data"
        fi

        if [[ $cn_count -eq 0 ]]; then
            echo -e "  ${GRAY}(No cluster networks found)${NC}"
        else
            echo ""
            echo -e "  ${WHITE}Total: ${GREEN}${cn_count}${WHITE} cluster network(s)${NC}"
        fi
        echo ""

        # ========== Menu Options ==========
        _ui_actions
        echo ""
        if [[ $cn_count -gt 0 ]]; then
            echo -e "  ${CYAN}#${NC}) ${WHITE}View${NC}    - View cluster network details and instances (enter number)"
        fi
        echo -e "  ${MAGENTA}r${NC}) ${WHITE}Refresh${NC} - Refresh cluster network list"
        echo -e "  ${CYAN}b${NC}) ${WHITE}Back${NC}    - Return to Compute menu"
        echo ""
        _ui_prompt "Cluster Networks" "#, r, b, show"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            r|R|refresh|REFRESH)
                rm -f "$CLUSTER_NETWORK_CACHE"
                echo -e "${GREEN}Cache cleared, refreshing...${NC}"
                sleep 1
                ;;
            b|B|back|BACK|"")
                return
                ;;
            [0-9]*)
                if [[ "$choice" =~ ^[0-9]+$ ]] && [[ $choice -ge 1 ]] && [[ $choice -le $cn_count ]]; then
                    local selected="${CN_LIST[$((choice-1))]}"
                    local sel_ocid sel_name sel_state sel_pool_id sel_pool_size
                    IFS='|' read -r sel_ocid sel_name sel_state sel_pool_id sel_pool_size <<< "$selected"
                    view_cluster_network_details "$sel_ocid" "$sel_name" "$compartment_id"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            show|SHOW)
                continue
                ;;
            env*|ENV*) _env_dispatch "$choice" ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

#--------------------------------------------------------------------------------
# View Cluster Network Details
# OCI Commands: oci compute-management cluster-network get
#               oci compute-management cluster-network list-instances
#--------------------------------------------------------------------------------
view_cluster_network_details() {
    local cn_ocid="$1"
    local cn_name="${2:-}"
    local compartment_id="${3:-${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}}"
    local region="${FOCUS_REGION:-$REGION}"

    while true; do
        echo ""
        _ui_menu_header "CLUSTER NETWORK DETAILS" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Cluster Networks" "Details: ${cn_name:-$cn_ocid}" \
            --cmd "oci compute-management cluster-network get --cluster-network-id ${cn_ocid}" \
            --env

        _step_init
        _step_active "cluster network details"
        local cn_json
        cn_json=$(oci compute-management cluster-network get \
            --cluster-network-id "$cn_ocid" \
            --region "$region" \
            --output json 2>/dev/null)
        _step_complete "details"

        if [[ -z "$cn_json" ]] || ! jq -e '.data' <<< "$cn_json" > /dev/null 2>&1; then
            _step_finish
            echo -e "${RED}Failed to fetch cluster network details${NC}"
            _ui_policy_hint "read cluster-networks in compartment"
            _ui_pause "return"
            return 1
        fi

        _step_active "instances"
        local instances_json
        instances_json=$(oci compute-management cluster-network list-instances \
            --cluster-network-id "$cn_ocid" \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all --output json 2>/dev/null)
        local inst_ct
        inst_ct=$(jq -r '.data | length' <<< "$instances_json" 2>/dev/null || echo "0")
        _step_complete "instances(${inst_ct})"
        _step_finish

        # Display details
        local cn_display cn_state cn_created
        cn_display=$(jq -r '.data["display-name"] // "N/A"' <<< "$cn_json")
        cn_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$cn_json")
        cn_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$cn_json")

        local state_color
        state_color=$(color_resource_state "$cn_state")

        echo ""
        echo -e "  ${WHITE}Name:${NC}     ${GREEN}$cn_display${NC}"
        echo -e "  ${WHITE}OCID:${NC}     ${YELLOW}$cn_ocid${NC}"
        echo -e "  ${WHITE}State:${NC}    ${state_color}$cn_state${NC}"
        echo -e "  ${WHITE}Created:${NC}  ${cn_created:0:19}"

        # Instance Pool details within the cluster network
        local pool_data
        pool_data=$(jq -r '.data["instance-pools"][]? | [
            .id,
            ."display-name",
            ."lifecycle-state",
            (.size // 0)
        ] | @tsv' <<< "$cn_json" 2>/dev/null)

        if [[ -n "$pool_data" ]]; then
            echo ""
            echo -e "  ${BOLD}${CYAN}Instance Pools:${NC}"
            while IFS=$'\t' read -r ip_id ip_name ip_state ip_size; do
                local ip_sc
                ip_sc=$(color_resource_state "$ip_state")
                echo -e "    ${WHITE}Pool:${NC}  ${WHITE}$ip_name${NC}  ${ip_sc}$ip_state${NC}  Size: ${CYAN}$ip_size${NC}"
                echo -e "    ${WHITE}OCID:${NC}  ${YELLOW}$ip_id${NC}"
            done <<< "$pool_data"
        fi

        # Placement configuration
        local pc_data
        pc_data=$(jq -r '.data["placement-configuration"] |
            "AD: \(.["availability-domain"] // "N/A")\nSubnet: \(.["primary-subnet-id"] // "N/A")"' <<< "$cn_json" 2>/dev/null)
        if [[ -n "$pc_data" ]]; then
            echo ""
            echo -e "  ${BOLD}${CYAN}Placement:${NC}"
            local pc_ad pc_subnet
            pc_ad=$(jq -r '.data["placement-configuration"]["availability-domain"] // "N/A"' <<< "$cn_json" 2>/dev/null)
            pc_subnet=$(jq -r '.data["placement-configuration"]["primary-subnet-id"] // "N/A"' <<< "$cn_json" 2>/dev/null)
            echo -e "    ${WHITE}AD:${NC}     ${CYAN}$pc_ad${NC}"
            if [[ -n "$pc_subnet" && "$pc_subnet" != "N/A" ]]; then
                local pc_sn_name
                pc_sn_name=$(oci network subnet get --subnet-id "$pc_subnet" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null)
                if [[ -n "$pc_sn_name" ]]; then
                    echo -e "    ${WHITE}Subnet:${NC} ${WHITE}$pc_sn_name${NC}  ${YELLOW}[$pc_subnet]${NC}"
                else
                    echo -e "    ${WHITE}Subnet:${NC} ${YELLOW}[$pc_subnet]${NC}"
                fi
            fi
        fi

        # Display instances
        if [[ "$inst_ct" -gt 0 ]]; then
            echo ""
            echo -e "  ${BOLD}${CYAN}Cluster Network Instances (${inst_ct}):${NC}"
            printf "    ${BOLD}%-4s %-40s %-12s %-18s %-15s %s${NC}\n" "#" "Display Name" "State" "Shape" "AD" "OCID"
            echo -e "    ${GRAY}──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"

            local iidx=0
            jq -r '.data[] | [.id, ."display-name", .state, .shape, ."availability-domain"] | @tsv' <<< "$instances_json" 2>/dev/null | \
            while IFS=$'\t' read -r i_ocid i_name i_state i_shape i_ad; do
                ((iidx++))
                local i_sc
                i_sc=$(color_resource_state "$i_state")
                local short_ad="${i_ad##*:}"
                printf "    ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${i_sc}%-12s${NC} ${CYAN}%-18s${NC} ${WHITE}%-15s${NC} ${GRAY}%s${NC}\n" \
                    "$iidx)" "${i_name:0:40}" "$i_state" "$i_shape" "$short_ad" "$i_ocid"
            done
        fi

        echo ""
        _ui_actions
        echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
        echo -e "  ${MAGENTA}r${NC}) Refresh"
        echo -e "  ${CYAN}Enter${NC}) Return"
        echo ""
        _ui_prompt "Cluster Network" "j, r, Enter"
        local _cn_choice
        read -r _cn_choice
        [[ "${_cn_choice:-}" == :* ]] && _nav_try_jump "$_cn_choice" && return

        case "$_cn_choice" in
            j|J|json|JSON)
                _ui_json_viewer "Cluster Network: ${cn_display}" "$cn_json" ".data"
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "Cluster Network: ${cn_display}" "$cn_json" ".data" "${_cn_choice#* }"
                ;;
            r|R) continue ;;
            show|SHOW) continue ;;
            *) return ;;
        esac
    done
}

#===============================================================================
# GPU INSTANCE TAGGING MANAGEMENT
#===============================================================================

# Default tag namespace and tag settings for GPU instance host actions
GPU_TAG_NAMESPACE="${GPU_TAG_NAMESPACE:-ComputeInstanceHostActions}"
GPU_TAG_NAMESPACE_DESCRIPTION="${GPU_TAG_NAMESPACE_DESCRIPTION:-Compute Instance Actions Tag Namespace}"
GPU_TAG_NAME="${GPU_TAG_NAME:-CustomerReportedHostStatus}"
GPU_TAG_NAME_DESCRIPTION="${GPU_TAG_NAME_DESCRIPTION:-host is unhealthy and needs manual intervention before returning to the previous pool post-recycle}"
GPU_TAG_VALUES="${GPU_TAG_VALUES:-unhealthy}"

#--------------------------------------------------------------------------------
# Get tenancy home region (required for IAM operations)
# OCI Command: oci iam region-subscription list --tenancy-id <TENANCY_ID>
#--------------------------------------------------------------------------------
get_home_region() {
    local tenancy_ocid="${TENANCY_ID:-$TENANCY_OCID}"
    
    if [[ -z "$tenancy_ocid" ]]; then
        echo ""
        return 1
    fi
    
    local home_region
    # Query home region from tenancy's region subscriptions
    # Note: backticks below are JMESPath literal syntax, not bash command substitution
    home_region=$(oci iam region-subscription list \
        --tenancy-id "$tenancy_ocid" \
        --query "data[?\"is-home-region\"==\`true\`].\"region-name\" | [0]" \
        --raw-output 2>/dev/null)
    
    echo "$home_region"
}

#================================================================================
# RESOURCE MANAGER STACKS MANAGEMENT
#================================================================================

#--------------------------------------------------------------------------------
# Manage Resource Manager Stacks - Main menu
#--------------------------------------------------------------------------------
manage_resource_manager_stacks() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    
    # Show stacks with jobs - this function handles all interactions
    # When user presses 'b', it returns and we go back to main menu
    rm_list_stacks_with_jobs "$compartment_id"
}

#--------------------------------------------------------------------------------
# List All Resource Manager Stacks with their Jobs - Interactive
#--------------------------------------------------------------------------------
rm_list_stacks_with_jobs() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "ALL STACKS WITH JOB HISTORY" \
        --color "$RED" \
        --breadcrumb "Operations" "Stacks" \
        --cmd "oci resource-manager stack list --compartment-id \$COMPARTMENT_ID --all | oci resource-manager job list --stack-id \$STACK_ID" \
        --env
    
    local stacks_json
    _step_init
    _step_active "stacks"
    stacks_json=$(oci resource-manager stack list \
        --compartment-id "$compartment_id" \
        --region "$region" \
        --all \
        --output json 2>/dev/null)
    _step_complete "stacks"
    _step_finish
    
    if [[ -z "$stacks_json" || "$stacks_json" == "null" ]]; then
        echo -e "${YELLOW}No stacks found or unable to list stacks${NC}"
        return 1
    fi
    
    local stack_count
    stack_count=$(jq '.data | length' <<< "$stacks_json" 2>/dev/null)
    
    if [[ "$stack_count" -eq 0 ]]; then
        echo -e "${YELLOW}No stacks found in this compartment${NC}"
        return 1
    fi
    
    echo -e "${GREEN}Found $stack_count stack(s)${NC}"
    echo ""
    
    # Clear and populate global maps
    declare -gA RM_STACK_MAP
    declare -gA RM_STACK_NAMES
    declare -gA RM_JOB_MAP  # Maps "stack_idx.job_idx" to job_id
    RM_STACK_MAP=()
    RM_STACK_NAMES=()
    RM_JOB_MAP=()
    
    local stack_idx=0
    
    # Process each stack
    while IFS='|' read -r stack_name state tf_version stack_id time_created; do
        [[ -z "$stack_name" ]] && continue
        ((stack_idx++))
        
        RM_STACK_MAP[$stack_idx]="$stack_id"
        RM_STACK_NAMES[$stack_idx]="$stack_name"
        
        # Color based on state
        local state_color
        state_color=$(color_resource_state "$state")
        
        echo -e "${BOLD}${CYAN}┌──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        echo -e "${BOLD}${CYAN}│ [s${stack_idx}] Stack: ${WHITE}${stack_name}${NC}"
        echo -e "${BOLD}${CYAN}├──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        echo -e "│ ${CYAN}State:${NC}      ${state_color}${state}${NC}"
        echo -e "│ ${CYAN}TF Version:${NC} ${WHITE}${tf_version:-N/A}${NC}"
        echo -e "│ ${CYAN}Created:${NC}    ${WHITE}${time_created:0:19}${NC}"
        echo -e "│ ${CYAN}Stack OCID:${NC} ${YELLOW}${stack_id}${NC}"
        echo -e "${BOLD}${CYAN}│${NC}"
        
        # Fetch jobs for this stack
        local jobs_json
        jobs_json=$(oci resource-manager job list \
            --stack-id "$stack_id" \
            --region "$region" \
            --all \
            --output json 2>/dev/null)
        
        local job_count=0
        if [[ -n "$jobs_json" && "$jobs_json" != "null" ]]; then
            job_count=$(jq '.data | length' <<< "$jobs_json" 2>/dev/null) || job_count=0
        fi
        
        if [[ "$job_count" -eq 0 ]]; then
            echo -e "│ ${GRAY}No jobs found for this stack${NC}"
        else
            echo -e "│ ${BOLD}${WHITE}Jobs (${job_count}):${NC}"
            echo -e "│"
            printf "│   ${BOLD}%-8s %-12s %-12s %-20s %-20s %s${NC}\n" "ID" "Operation" "State" "Created" "Finished" "Job OCID"
            echo -e "│   ────────────────────────────────────────────────────────────────────────────────────────────────────────"
            
            local job_idx=0
            while IFS='|' read -r operation job_state time_created time_finished job_id; do
                [[ -z "$operation" ]] && continue
                ((job_idx++))
                
                # Store job mapping
                RM_JOB_MAP["${stack_idx}.${job_idx}"]="$job_id"
                
                # Color based on state
                local job_state_color
                job_state_color=$(color_resource_state "$job_state")
                
                # Operation color
                local op_color="$WHITE"
                case "$operation" in
                    APPLY) op_color="$GREEN" ;;
                    PLAN) op_color="$CYAN" ;;
                    DESTROY) op_color="$RED" ;;
                    IMPORT_TF_STATE) op_color="$YELLOW" ;;
                esac
                
                # Format times
                local time_created_short="${time_created:0:19}"
                local time_finished_short="${time_finished:0:19}"
                [[ "$time_finished_short" == "null" || -z "$time_finished_short" ]] && time_finished_short="-"
                
                printf "│   ${YELLOW}[j%-5s]${NC} ${op_color}%-12s${NC} ${job_state_color}%-12s${NC} %-20s %-20s ${GRAY}%s${NC}\n" \
                    "${stack_idx}.${job_idx}" "$operation" "$job_state" "$time_created_short" "$time_finished_short" "$job_id"
                    
            done < <(jq -r '.data | sort_by(.["time-created"]) | reverse | .[] | "\(.operation)|\(.["lifecycle-state"])|\(.["time-created"])|\(.["time-finished"] // "null")|\(.id)"' <<< "$jobs_json" 2>/dev/null)
        fi
        
        echo -e "${BOLD}${CYAN}└──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        echo ""
        
    done < <(jq -r '.data | sort_by(.["display-name"]) | .[] | "\(.["display-name"])|\(.["lifecycle-state"])|\(.["terraform-version"] // "N/A")|\(.id)|\(.["time-created"])"' <<< "$stacks_json" 2>/dev/null)
    
    RM_STACK_COUNT=$stack_idx
    
    echo ""
    _ui_summary
    echo -e "  Total Stacks: ${GREEN}$stack_count${NC}"
    echo ""
    
    # Interactive selection loop
    while true; do
        _ui_actions "Selection Options"
        echo -e "  ${YELLOW}s#${NC}       - View stack details (e.g., ${YELLOW}s1${NC})"
        echo -e "  ${YELLOW}s#o${NC}      - View stack outputs (e.g., ${YELLOW}s1o${NC})"
        echo -e "  ${YELLOW}s#r${NC}      - View stack resources (e.g., ${YELLOW}s1r${NC})"
        echo -e "  ${YELLOW}s#t${NC}      - View stack state file (e.g., ${YELLOW}s1t${NC})"
        echo -e "  ${YELLOW}j#.#${NC}     - View job details (e.g., ${YELLOW}j1.2${NC})"
        echo -e "  ${YELLOW}j#.#l${NC}    - View job logs (e.g., ${YELLOW}j1.2l${NC})"
        echo -e "  ${MAGENTA}r${NC}        - Reload stacks and jobs"
        echo -e "  ${CYAN}b${NC}        - Back to Resource Manager menu"
        echo ""
        _ui_prompt "Resource Manager" "s#, s#o, s#r, s#t, j#.#, j#.#l, r, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        [[ -z "$selection" || "$selection" == "b" || "$selection" == "B" ]] && return 0

        # Show menu again
        [[ "$selection" == "show" || "$selection" == "SHOW" ]] && continue
        
        # Refresh
        if [[ "$selection" == "r" || "$selection" == "R" || "$selection" == "refresh" ]]; then
            rm_list_stacks_with_jobs "$compartment_id"
            return $?
        fi
        
        # Stack details: s#
        if [[ "$selection" =~ ^s([0-9]+)$ ]]; then
            local sel_stack="${BASH_REMATCH[1]}"
            if [[ -n "${RM_STACK_MAP[$sel_stack]}" ]]; then
                rm_show_stack_detail "${RM_STACK_MAP[$sel_stack]}"
            else
                echo -e "${RED}Invalid stack number: s${sel_stack}${NC}"
            fi
            continue
        fi
        
        # Stack outputs: s#o
        if [[ "$selection" =~ ^s([0-9]+)o$ ]]; then
            local sel_stack="${BASH_REMATCH[1]}"
            if [[ -n "${RM_STACK_MAP[$sel_stack]}" ]]; then
                rm_show_stack_outputs_direct "${RM_STACK_MAP[$sel_stack]}" "${RM_STACK_NAMES[$sel_stack]}"
            else
                echo -e "${RED}Invalid stack number: s${sel_stack}${NC}"
            fi
            continue
        fi
        
        # Stack resources: s#r
        if [[ "$selection" =~ ^s([0-9]+)r$ ]]; then
            local sel_stack="${BASH_REMATCH[1]}"
            if [[ -n "${RM_STACK_MAP[$sel_stack]}" ]]; then
                rm_show_stack_resources_direct "${RM_STACK_MAP[$sel_stack]}" "${RM_STACK_NAMES[$sel_stack]}"
            else
                echo -e "${RED}Invalid stack number: s${sel_stack}${NC}"
            fi
            continue
        fi
        
        # Stack state: s#t
        if [[ "$selection" =~ ^s([0-9]+)t$ ]]; then
            local sel_stack="${BASH_REMATCH[1]}"
            if [[ -n "${RM_STACK_MAP[$sel_stack]}" ]]; then
                rm_show_stack_state_direct "${RM_STACK_MAP[$sel_stack]}" "${RM_STACK_NAMES[$sel_stack]}"
            else
                echo -e "${RED}Invalid stack number: s${sel_stack}${NC}"
            fi
            continue
        fi
        
        # Job details: j#.#
        if [[ "$selection" =~ ^j([0-9]+)\.([0-9]+)$ ]]; then
            local sel_key="${BASH_REMATCH[1]}.${BASH_REMATCH[2]}"
            if [[ -n "${RM_JOB_MAP[$sel_key]}" ]]; then
                rm_show_job_detail_direct "${RM_JOB_MAP[$sel_key]}"
            else
                echo -e "${RED}Invalid job reference: j${sel_key}${NC}"
            fi
            continue
        fi
        
        # Job logs: j#.#l
        if [[ "$selection" =~ ^j([0-9]+)\.([0-9]+)l$ ]]; then
            local sel_key="${BASH_REMATCH[1]}.${BASH_REMATCH[2]}"
            if [[ -n "${RM_JOB_MAP[$sel_key]}" ]]; then
                rm_show_job_logs_direct "${RM_JOB_MAP[$sel_key]}"
            else
                echo -e "${RED}Invalid job reference: j${sel_key}${NC}"
            fi
            continue
        fi
        
        echo -e "${RED}Invalid selection. Use s# for stacks, j#.# for jobs${NC}"
    done
    
    return 0
}

#--------------------------------------------------------------------------------
# Show stack outputs directly by stack ID
#--------------------------------------------------------------------------------
rm_show_stack_outputs_direct() {
    local stack_id="$1"
    local stack_name="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Stack Outputs: ${stack_name}" 0
    echo ""

    local get_cmd="oci resource-manager stack get --stack-id \"$stack_id\" --region \"$region\" --output json"
    echo -e "${GRAY}$get_cmd${NC}"
    echo ""

    local stack_json
    stack_json=$(oci resource-manager stack get --stack-id "$stack_id" --region "$region" --output json 2>/dev/null)
    
    if [[ -z "$stack_json" || "$stack_json" == "null" ]]; then
        echo -e "${RED}Failed to get stack details${NC}"
        return
    fi
    
    # Check for outputs in stack
    local outputs
    outputs=$(jq '.data.outputs // {}' <<< "$stack_json" 2>/dev/null)
    
    if [[ "$outputs" == "{}" || "$outputs" == "null" || -z "$outputs" ]]; then
        echo -e "${YELLOW}No outputs found for this stack${NC}"
        echo -e "${GRAY}Note: Outputs are populated after a successful apply job${NC}"
    else
        echo -e "${GREEN}Stack Outputs:${NC}"
        echo ""
        jq -r 'to_entries[] | "  \(.key): \(.value)"' <<< "$outputs" 2>/dev/null
    fi
    
    echo ""
}

#--------------------------------------------------------------------------------
# Show stack resources directly by stack ID
#--------------------------------------------------------------------------------
rm_show_stack_resources_direct() {
    local stack_id="$1"
    local stack_name="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Stack Resources: ${stack_name}" 0
    echo ""

    local list_cmd="oci resource-manager stack list-terraform-resources --stack-id \"$stack_id\" --region \"$region\" --output json"
    echo -e "${GRAY}$list_cmd${NC}"
    echo ""

    local resources_json
    resources_json=$(oci resource-manager stack list-terraform-resources \
        --stack-id "$stack_id" \
        --region "$region" \
        --output json 2>/dev/null)
    
    if [[ -z "$resources_json" || "$resources_json" == "null" ]]; then
        echo -e "${YELLOW}No resources found or unable to list resources${NC}"
        return
    fi
    
    local resource_count
    resource_count=$(jq '.data | length' <<< "$resources_json" 2>/dev/null)
    
    if [[ "$resource_count" -eq 0 ]]; then
        echo -e "${YELLOW}No resources found for this stack${NC}"
        return
    fi
    
    echo -e "${GREEN}Found $resource_count resource(s)${NC}"
    echo ""
    
    # Print header
    _ui_table_header "%-50s %-40s %s" "Resource Type" "Resource Name" "Resource OCID"
    
    jq -r '.data[] | "\(.["resource-type"] // "N/A")|\(.["resource-name"] // "N/A")|\(.["resource-id"] // "N/A")"' <<< "$resources_json" 2>/dev/null | while IFS='|' read -r res_type res_name res_id; do
        printf "%-50s %-40s ${GRAY}%s${NC}\n" "${res_type:0:48}" "${res_name:0:38}" "$res_id"
    done
    
    echo ""
}

#--------------------------------------------------------------------------------
# Show stack state directly by stack ID
#--------------------------------------------------------------------------------
rm_show_stack_state_direct() {
    local stack_id="$1"
    local stack_name="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Stack State: ${stack_name}" 0
    echo ""

    local get_cmd="oci resource-manager stack get-stack-tf-state --stack-id \"$stack_id\" --region \"$region\" --file -"
    echo -e "${GRAY}$get_cmd${NC}"
    echo ""

    local state_content
    state_content=$(oci resource-manager stack get-stack-tf-state \
        --stack-id "$stack_id" \
        --region "$region" \
        --file - 2>/dev/null)
    
    if [[ -z "$state_content" ]]; then
        echo -e "${YELLOW}No state found or unable to get state${NC}"
        return
    fi
    
    # Parse and display state summary
    echo -e "${GREEN}Terraform State Summary:${NC}"
    echo ""
    
    local version serial
    version=$(jq -r '.version // "N/A"' <<< "$state_content" 2>/dev/null)
    serial=$(jq -r '.serial // "N/A"' <<< "$state_content" 2>/dev/null)
    
    echo -e "  ${CYAN}Version:${NC} $version"
    echo -e "  ${CYAN}Serial:${NC}  $serial"
    echo ""
    
    # Count resources
    local res_count
    res_count=$(jq '.resources | length' <<< "$state_content" 2>/dev/null) || res_count=0
    echo -e "  ${CYAN}Resources in state:${NC} $res_count"
    echo ""
    
    if [[ "$res_count" -gt 0 ]]; then
        echo -e "${WHITE}Resources:${NC}"
        echo ""
        printf "  ${BOLD}%-40s %-50s %s${NC}\n" "Type" "Name" "Provider"
        echo "  ────────────────────────────────────────────────────────────────────────────────────────────────────────"
        
        jq -r '.resources[] | "\(.type // "N/A")|\(.name // "N/A")|\(.provider // "N/A")"' <<< "$state_content" 2>/dev/null | while IFS='|' read -r res_type res_name res_provider; do
            printf "  %-40s %-50s ${GRAY}%s${NC}\n" "${res_type:0:38}" "${res_name:0:48}" "$res_provider"
        done
    fi
    
    echo ""
}

#--------------------------------------------------------------------------------
# Show job details directly by job ID
#--------------------------------------------------------------------------------
rm_show_job_detail_direct() {
    local job_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Job Details" 0
    echo ""

    local get_cmd="oci resource-manager job get --job-id \"$job_id\" --region \"$region\" --output json"
    echo -e "${GRAY}$get_cmd${NC}"
    echo ""

    local job_json
    job_json=$(oci resource-manager job get --job-id "$job_id" --region "$region" --output json 2>/dev/null)
    
    if [[ -z "$job_json" || "$job_json" == "null" ]]; then
        echo -e "${RED}Failed to get job details${NC}"
        return
    fi
    
    # Extract fields
    local operation state stack_id time_created time_finished
    local resolved_plan_id apply_tf_state failure_details
    operation=$(jq -r '.data.operation // "N/A"' <<< "$job_json")
    state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$job_json")
    stack_id=$(jq -r '.data["stack-id"] // "N/A"' <<< "$job_json")
    time_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$job_json")
    time_finished=$(jq -r '.data["time-finished"] // "N/A"' <<< "$job_json")
    resolved_plan_id=$(jq -r '.data["resolved-plan-job-id"] // "N/A"' <<< "$job_json")
    
    # State color
    local state_color
    state_color=$(color_resource_state "$state")
    
    # Operation color
    local op_color="$WHITE"
    case "$operation" in
        APPLY) op_color="$GREEN" ;;
        PLAN) op_color="$CYAN" ;;
        DESTROY) op_color="$RED" ;;
        IMPORT_TF_STATE) op_color="$YELLOW" ;;
    esac
    
    echo -e "  ${CYAN}Operation:${NC}    ${op_color}$operation${NC}"
    echo -e "  ${CYAN}State:${NC}        ${state_color}$state${NC}"
    echo -e "  ${CYAN}Created:${NC}      ${WHITE}$time_created${NC}"
    echo -e "  ${CYAN}Finished:${NC}     ${WHITE}$time_finished${NC}"
    echo -e "  ${CYAN}Stack OCID:${NC}   ${YELLOW}$stack_id${NC}"
    echo -e "  ${CYAN}Job OCID:${NC}     ${YELLOW}$job_id${NC}"
    
    if [[ "$resolved_plan_id" != "N/A" && "$resolved_plan_id" != "null" && -n "$resolved_plan_id" ]]; then
        echo -e "  ${CYAN}Plan Job:${NC}     ${YELLOW}$resolved_plan_id${NC}"
    fi
    
    # Check for failure details
    if [[ "$state" == "FAILED" ]]; then
        failure_details=$(jq -r '.data["failure-details"] // "N/A"' <<< "$job_json" 2>/dev/null)
        if [[ "$failure_details" != "N/A" && "$failure_details" != "null" && -n "$failure_details" ]]; then
            echo ""
            echo -e "  ${RED}Failure Details:${NC}"
            echo "$failure_details" | fold -s -w 100 | while IFS= read -r line; do
                echo -e "    ${RED}$line${NC}"
            done
        fi
    fi
    
    echo ""
    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Job Detail" "j, Enter"
    local _jd_choice
    read -r _jd_choice
    [[ "${_jd_choice:-}" == :* ]] && _nav_try_jump "$_jd_choice" && return
    case "$_jd_choice" in
        j|J|json|JSON) _ui_json_viewer "Job: $job_id" "$job_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Job: $job_id" "$job_json" ".data" "${_jd_choice#* }" ;;
    esac
}

#--------------------------------------------------------------------------------
# Show job logs directly by job ID
#--------------------------------------------------------------------------------
rm_show_job_logs_direct() {
    local job_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Job Logs" 0
    echo ""

    local logs_cmd="oci resource-manager job get-job-logs --job-id \"$job_id\" --region \"$region\" --all --output json"
    echo -e "${GRAY}$logs_cmd${NC}"
    echo ""

    local logs_json
    logs_json=$(oci resource-manager job get-job-logs \
        --job-id "$job_id" \
        --region "$region" \
        --all \
        --output json 2>/dev/null)
    
    if [[ -z "$logs_json" || "$logs_json" == "null" ]]; then
        echo -e "${YELLOW}No logs found or unable to get logs${NC}"
        return
    fi
    
    local log_count
    log_count=$(jq '.data | length' <<< "$logs_json" 2>/dev/null)
    
    if [[ "$log_count" -eq 0 ]]; then
        echo -e "${YELLOW}No log entries found${NC}"
        return
    fi
    
    echo -e "${GREEN}Found $log_count log entries${NC}"
    echo ""
    
    # Display logs
    jq -r '.data[] | "\(.timestamp // "N/A") [\(.level // "INFO")] \(.message // "")"' <<< "$logs_json" 2>/dev/null | while IFS= read -r log_line; do
        # Color based on log level
        if echo "$log_line" | grep -qE '\[ERROR\]|\[FATAL\]'; then
            echo -e "${RED}$log_line${NC}"
        elif echo "$log_line" | grep -qE '\[WARN\]|\[WARNING\]'; then
            echo -e "${YELLOW}$log_line${NC}"
        elif echo "$log_line" | grep -qE 'Apply complete|Creation complete|Destruction complete'; then
            echo -e "${GREEN}$log_line${NC}"
        else
            echo "$log_line"
        fi
    done
    
    echo ""
    _ui_pause

}
rm_show_stack_detail() {
    local stack_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Stack Details" 0
    echo ""

    local get_cmd="oci resource-manager stack get --stack-id \"$stack_id\" --region \"$region\" --output json"
    echo -e "${GRAY}$get_cmd${NC}"
    echo ""

    local stack_json
    stack_json=$(oci resource-manager stack get \
        --stack-id "$stack_id" \
        --region "$region" \
        --output json 2>/dev/null)
    
    if [[ -z "$stack_json" || "$stack_json" == "null" ]]; then
        echo -e "${RED}Failed to get stack details${NC}"
        return
    fi
    
    # Extract fields
    local name state tf_version description time_created source_type working_dir
    IFS=$'\t' read -r name state tf_version description time_created source_type working_dir < <(jq -r '.data | [
        .["display-name"] // "N/A",
        .["lifecycle-state"] // "N/A",
        .["terraform-version"] // "N/A",
        .description // "N/A",
        .["time-created"] // "N/A",
        .["config-source"]["config-source-type"] // "N/A",
        .["config-source"]["working-directory"] // "N/A"
    ] | @tsv' <<< "$stack_json")
    
    # State color
    local state_color
    state_color=$(color_resource_state "$state")
    
    echo -e "  ${CYAN}Name:${NC}              ${WHITE}$name${NC}"
    echo -e "  ${CYAN}State:${NC}             ${state_color}$state${NC}"
    echo -e "  ${CYAN}Terraform Version:${NC} ${WHITE}$tf_version${NC}"
    echo -e "  ${CYAN}Description:${NC}       ${WHITE}$description${NC}"
    echo -e "  ${CYAN}Created:${NC}           ${WHITE}$time_created${NC}"
    echo -e "  ${CYAN}Source Type:${NC}       ${WHITE}$source_type${NC}"
    echo -e "  ${CYAN}Working Directory:${NC} ${WHITE}$working_dir${NC}"
    echo -e "  ${CYAN}Stack OCID:${NC}        ${YELLOW}$stack_id${NC}"
    echo ""
    
    # Show variables if any
    local variables
    variables=$(jq -r '.data.variables // {}' <<< "$stack_json")
    if [[ "$variables" != "{}" && "$variables" != "null" ]]; then
        _ui_subheader "Variables" 0
        jq -r 'to_entries[] | "  \(.key) = \(.value)"' <<< "$variables" 2>/dev/null | head -20
        local var_count
        var_count=$(jq 'keys | length' <<< "$variables" 2>/dev/null)
        [[ "$var_count" -gt 20 ]] && echo -e "  ${GRAY}... and $((var_count - 20)) more${NC}"
        echo ""
    fi
    
    # Show freeform tags
    local freeform_tags
    freeform_tags=$(jq -r '.data["freeform-tags"] // {}' <<< "$stack_json")
    if [[ "$freeform_tags" != "{}" && "$freeform_tags" != "null" ]]; then
        _ui_subheader "Freeform Tags" 0
        jq -r 'to_entries[] | "  \(.key) = \(.value)"' <<< "$freeform_tags" 2>/dev/null
        echo ""
    fi

    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Stack Detail" "j, Enter"
    local _sd_choice
    read -r _sd_choice
    [[ "${_sd_choice:-}" == :* ]] && _nav_try_jump "$_sd_choice" && return
    case "$_sd_choice" in
        j|J|json|JSON) _ui_json_viewer "Stack: $name" "$stack_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Stack: $name" "$stack_json" ".data" "${_sd_choice#* }" ;;
    esac
}

#================================================================================
# WORK REQUESTS MANAGEMENT
#================================================================================

#--------------------------------------------------------------------------------
# Manage Work Requests - Main menu
#--------------------------------------------------------------------------------
manage_work_requests() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _wr_filter=""
    local _wr_filter_file="${TEMP_DIR}/.wr_next_filter_$$"
    
    # Loop: re-display with current filter until user exits
    while true; do
        # Write current filter to file so the function can update it
        echo "$_wr_filter" > "$_wr_filter_file"
        
        wr_list_work_requests_interactive "$compartment_id" "$_wr_filter" "$_wr_filter_file"
        local _wr_rc=$?
        
        # Check return: 0=back, 2=re-filter (new filter in temp file)
        if [[ $_wr_rc -eq 2 ]]; then
            _wr_filter=$(cat "$_wr_filter_file" 2>/dev/null)
            continue
        else
            rm -f "$_wr_filter_file"
            return 0
        fi
    done
}

#--------------------------------------------------------------------------------
# List Work Requests with Interactive Selection
#--------------------------------------------------------------------------------
wr_list_work_requests_interactive() {
    local compartment_id="$1"
    local status_filter="${2:-}"
    local filter_file="${3:-}"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "WORK REQUESTS" \
        --color "$RED" \
        --breadcrumb "Operations" "Work Requests" \
        --cmd "oci work-requests work-request list --compartment-id \$COMPARTMENT_ID --all | oci work-requests work-request get | oci work-requests work-request-error list | oci work-requests work-request-log-entry list" \
        --env
    
    local query_filter=""
    if [[ -n "$status_filter" ]]; then
        query_filter="--query \"data[?status=='${status_filter}']\""
    fi
    
    _step_init
    local _wr_label="work requests"
    [[ -n "$status_filter" ]] && _wr_label="work requests(${status_filter})"
    _step_active "$_wr_label"
    
    local wr_json
    if [[ -n "$status_filter" ]]; then
        wr_json=$(oci work-requests work-request list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all \
            --query "data[?status=='${status_filter}']" \
            --output json 2>/dev/null)
    else
        wr_json=$(oci work-requests work-request list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all \
            --output json 2>/dev/null)
    fi
    
    local wr_count=0
    if [[ -n "$wr_json" && "$wr_json" != "null" ]]; then
        # Handle both formats - with and without .data wrapper
        if jq -e '.data' <<< "$wr_json" >/dev/null 2>&1; then
            wr_count=$(jq '.data | length' <<< "$wr_json" 2>/dev/null)
        else
            wr_count=$(jq 'length' <<< "$wr_json" 2>/dev/null)
        fi
    fi
    wr_count="${wr_count:-0}"
    _step_complete "work requests(${wr_count})"
    _step_finish
    
    if [[ -z "$wr_json" || "$wr_json" == "null" || "$wr_count" -eq 0 ]]; then
        echo -e "${YELLOW}No work requests found${NC}"
        [[ -n "$status_filter" ]] && echo -e "${CYAN}Filter: ${WHITE}$status_filter${NC}"
        echo ""
        if [[ -n "$status_filter" ]]; then
            echo -e "${GRAY}Press Enter to clear filter, or 'b' to go back...${NC}"
            local _empty_choice
            read -r _empty_choice
            if [[ "$_empty_choice" == "b" || "$_empty_choice" == "B" ]]; then
                return 0
            fi
            [[ -n "$filter_file" ]] && echo "" > "$filter_file"
            return 2
        fi
        _ui_pause "return"
        return 0
    fi
    
    [[ -n "$status_filter" ]] && echo -e "  ${CYAN}Filter: ${WHITE}$status_filter${NC}"
    echo ""
    
    # Print header
    _ui_table_header "%-6s %-40s %-15s %-6s %-20s %-20s %s" "ID" "Operation Type" "Status" "%" "Time Accepted" "Time Finished" "Work Request OCID"
    
    local idx=0
    # Clear and populate global work request map
    declare -gA WR_MAP
    WR_MAP=()
    
    # Handle both formats - with and without .data wrapper
    local jq_path=".data"
    if ! jq -e '.data' <<< "$wr_json" >/dev/null; then
        jq_path="."
    fi
    
    while IFS='|' read -r operation_type status percent_complete time_accepted time_finished wr_id; do
        [[ -z "$operation_type" ]] && continue
        ((idx++))
        
        WR_MAP[$idx]="$wr_id"
        
        # Color based on status
        local status_color
        status_color=$(color_resource_state "$status")
        
        # Truncate operation type if needed
        local op_trunc="${operation_type:0:38}"
        [[ ${#operation_type} -gt 38 ]] && op_trunc="${op_trunc}.."
        
        # Format times
        local accepted_short="${time_accepted:0:19}"
        [[ "$time_accepted" == "null" || -z "$time_accepted" ]] && accepted_short="N/A"
        accepted_short="${accepted_short/T/ }"
        
        local finished_short="${time_finished:0:19}"
        [[ "$time_finished" == "null" || -z "$time_finished" ]] && finished_short="--"
        finished_short="${finished_short/T/ }"
        
        # Format percentage
        local pct_display="${percent_complete:-0}"
        
        printf "${YELLOW}%-6s${NC} %-40s ${status_color}%-15s${NC} %-6s %-20s %-20s ${YELLOW}%s${NC}\n" \
            "w${idx}" "$op_trunc" "$status" "${pct_display}%" "$accepted_short" "$finished_short" "$wr_id"
            
    done < <(jq -r "${jq_path} | sort_by(.[\"time-accepted\"]) | reverse | .[] | \"\(.[\"operation-type\"])|\(.status)|\(.[\"percent-complete\"])|\(.[\"time-accepted\"])|\(.[\"time-finished\"])|\(.id)\"" <<< "$wr_json" 2>/dev/null)
    
    echo ""
    
    # Store count
    WR_COUNT=$idx
    
    # Interactive selection loop
    while true; do
        _ui_actions "Selection Options"
        echo -e "  ${YELLOW}w#${NC}        - View work request details (e.g., ${YELLOW}w1${NC})"
        echo -e "  ${CYAN}filter${NC}    - Filter by status: ${RED}f${NC}=FAILED  ${YELLOW}p${NC}=IN_PROGRESS  ${GREEN}s${NC}=SUCCEEDED  ${WHITE}a${NC}=ALL"
        echo -e "  ${MAGENTA}r${NC}         - Reload work requests"
        echo -e "  ${CYAN}b${NC}         - Back to main menu"
        echo ""
        _ui_prompt "Work Requests" "w#, f, p, s, a, r, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        [[ -z "$selection" || "$selection" == "b" || "$selection" == "B" ]] && return 0

        # Show menu again
        [[ "$selection" == "show" || "$selection" == "SHOW" ]] && continue
        
        # Refresh (with current filter)
        if [[ "$selection" == "r" || "$selection" == "R" || "$selection" == "refresh" ]]; then
            [[ -n "$filter_file" ]] && echo "$status_filter" > "$filter_file"
            return 2
        fi
        
        # Filter commands (abbreviations and full names) - always re-query full list with new filter
        if [[ "$selection" == "f" || "$selection" == "F" || "$selection" == "failed" ]]; then
            [[ -n "$filter_file" ]] && echo "FAILED" > "$filter_file"
            return 2
        fi
        if [[ "$selection" == "p" || "$selection" == "P" || "$selection" == "progress" ]]; then
            [[ -n "$filter_file" ]] && echo "IN_PROGRESS" > "$filter_file"
            return 2
        fi
        if [[ "$selection" == "s" || "$selection" == "S" || "$selection" == "succeeded" ]]; then
            [[ -n "$filter_file" ]] && echo "SUCCEEDED" > "$filter_file"
            return 2
        fi
        if [[ "$selection" == "a" || "$selection" == "A" || "$selection" == "all" ]]; then
            [[ -n "$filter_file" ]] && echo "" > "$filter_file"
            return 2
        fi
        
        # Work request details: w#
        if [[ "$selection" =~ ^w([0-9]+)$ ]]; then
            local sel_wr="${BASH_REMATCH[1]}"
            if [[ -n "${WR_MAP[$sel_wr]}" ]]; then
                wr_show_work_request_detail "${WR_MAP[$sel_wr]}"
            else
                echo -e "${RED}Invalid work request number: w${sel_wr}${NC}"
            fi
            continue
        fi
        
        echo -e "${RED}Invalid selection. Use w# for work requests${NC}"
    done
    
    return 0
}

#--------------------------------------------------------------------------------
# Show Work Request Resources
#--------------------------------------------------------------------------------
wr_show_work_request_detail() {
    local wr_id="$1"
    
    # Build OCID→name map from instance list cache
    declare -A _WR_OCID_NAMES=()
    if [[ -s "$INSTANCE_LIST_CACHE" ]]; then
        while IFS=$'\t' read -r _oid _oname; do
            [[ -n "$_oid" && -n "$_oname" ]] && _WR_OCID_NAMES["$_oid"]="$_oname"
        done < <(jq -r '.data[] | [.id, .["display-name"]] | @tsv' "$INSTANCE_LIST_CACHE" 2>/dev/null)
    fi
    
    _wr_generic_detail "$wr_id" "${TEMP_DIR}/wr_detail_$$" \
        "Work Request Detail" "" "enrich" "Operations|Work Requests|Detail"
}


#================================================================================
# SERVICE LIMITS & QUOTAS MANAGEMENT
#================================================================================

#--------------------------------------------------------------------------------
# Search within a LIMIT_IDX_MAP — prompt, match, auto-drill on single result
# Usage: _limits_search_in_map MAP_NAME "service" "$tenancy_id" "$compartment_id"
#   MAP_NAME must be an associative array with entries: "AD|limit-name" or "REGION|limit-name"
#--------------------------------------------------------------------------------
_limits_search_in_map() {
    local -n _smap="$1"
    local service_name="$2" tenancy_id="$3" compartment_id="$4"
    local _sterm="${5:-}"
    local _multi="${6:-}"   # "multi" = entries are "svc|scope|name"; default = "scope|name"
    
    # Prompt if no pre-populated term
    if [[ -z "$_sterm" ]]; then
        echo ""
        echo -n -e "  ${CYAN}Search ${service_name} limits: ${NC}"
        read -r _sterm
        [[ -z "$_sterm" ]] && return
    fi
    
    # Find matches (case-insensitive) — extract limit name from entry
    local -a _match_keys=()
    local _k _entry _lname
    for _k in $(echo "${!_smap[@]}" | tr ' ' '\n' | sort -n); do
        _entry="${_smap[$_k]}"
        if [[ "$_multi" == "multi" ]]; then
            _lname="${_entry##*|}"   # last field = name
        else
            _lname="${_entry#*|}"    # after first pipe = name
        fi
        [[ "${_lname,,}" == *"${_sterm,,}"* ]] && _match_keys+=("$_k")
    done
    
    if [[ ${#_match_keys[@]} -eq 0 ]]; then
        echo -e "  ${YELLOW}No limits matching '${_sterm}' in ${service_name}${NC}"
        sleep 1
        return
    fi
    
    # Helper to parse entry and drill
    _sim_drill() {
        local __e="$1"
        local __svc __scope __lname
        if [[ "$_multi" == "multi" ]]; then
            __svc="${__e%%|*}"; local __rest="${__e#*|}"; __scope="${__rest%%|*}"; __lname="${__rest#*|}"
        else
            __svc="$service_name"; __scope="${__e%%|*}"; __lname="${__e#*|}"
        fi
        _limits_availability_detail "$__svc" "$__lname" "$tenancy_id" "$compartment_id" "$__scope"
    }
    
    # Single match → auto-drill
    if [[ ${#_match_keys[@]} -eq 1 ]]; then
        _entry="${_smap[${_match_keys[0]}]}"
        if [[ "$_multi" == "multi" ]]; then
            local _dsvc="${_entry%%|*}" _drest="${_entry#*|}" _dlname="${_entry##*|}"
            echo -e "  ${GREEN}→ ${_dsvc}/${_dlname}${NC}"
        else
            echo -e "  ${GREEN}→ ${_entry#*|}${NC}"
        fi
        sleep 0.3
        _sim_drill "$_entry"
        return
    fi
    
    # Multiple matches → numbered list with select
    echo ""
    echo -e "  ${WHITE}${#_match_keys[@]} matches for '${_sterm}':${NC}"
    echo ""
    
    if [[ "$_multi" == "multi" ]]; then
        printf "  ${BOLD}${CYAN}%-4s %-22s %-45s %-8s${NC}\n" "#" "Service" "Limit Name" "Scope"
        echo -e "  ${GRAY}$(printf '─%.0s' {1..80})${NC}"
    fi
    
    declare -A _SMATCH=()
    local _si=0
    for _k in "${_match_keys[@]}"; do
        _entry="${_smap[$_k]}"
        ((_si++))
        _SMATCH[$_si]="$_entry"
        if [[ "$_multi" == "multi" ]]; then
            local _ms="${_entry%%|*}" _mr="${_entry#*|}" _mn="${_entry##*|}"
            local _msc="${_mr%%|*}"
            local _nc="$WHITE"; [[ "${_mn,,}" == *gpu* ]] && _nc="$GREEN"; [[ "${_mn,,}" == *hpc* ]] && _nc="$CYAN"
            printf "  ${YELLOW}%-4s${NC} ${MAGENTA}%-22s${NC} ${_nc}%-45s${NC} ${GRAY}%-8s${NC}\n" "$_si" "$_ms" "$_mn" "$_msc"
        else
            local _scope="${_entry%%|*}" _lname="${_entry#*|}"
            printf "  ${YELLOW}%-4s${NC} ${WHITE}%-55s${NC} ${GRAY}(%s)${NC}\n" "$_si" "$_lname" "$_scope"
        fi
    done
    echo ""
    echo -n -e "  ${CYAN}Select # (Enter to cancel): ${NC}"
    local _ssel
    read -r _ssel
    if [[ "$_ssel" =~ ^[0-9]+$ ]] && [[ -n "${_SMATCH[$_ssel]:-}" ]]; then
        _sim_drill "${_SMATCH[$_ssel]}"
    fi
}

#--------------------------------------------------------------------------------
# Build cross-service limit definition search index (parallel fetch, cached 24h)
# Creates: LIMITS_SEARCH_INDEX (tsv: service|limit_name|scope_type|description)
#--------------------------------------------------------------------------------
_limits_build_search_index() {
    local tenancy_id="$1"
    local region="${FOCUS_REGION:-$REGION}"
    local _idx_tmp
    _idx_tmp=$(mktemp -d "${TEMP_DIR}/lim_idx.XXXXXX")

    # Fetch service list (cache-first)
    local services_json
    if is_cache_fresh "$LIMITS_SERVICE_CACHE" 2>/dev/null && [[ -s "$LIMITS_SERVICE_CACHE" ]]; then
        services_json=$(cat "$LIMITS_SERVICE_CACHE")
    else
        services_json=$(oci limits service list \
            --compartment-id "$tenancy_id" \
            --region "$region" \
            --all --output json 2>/dev/null)
        [[ -z "$services_json" ]] && services_json='{"data":[]}'
        if jq -e '.data' <<< "$services_json" >/dev/null 2>&1; then
            echo "$services_json" | _cache_write "$LIMITS_SERVICE_CACHE"
        fi
    fi
    
    local -a svc_list=()
    while read -r _svc; do
        [[ -n "$_svc" ]] && svc_list+=("$_svc")
    done < <(jq -r '.data[].name // empty' <<< "$services_json" 2>/dev/null | sort)
    
    local _total=${#svc_list[@]}
    if [[ $_total -eq 0 ]]; then
        echo -e "  ${YELLOW}No services found — cannot build index${NC}"
        rm -rf "$_idx_tmp"
        return 1
    fi
    
    _step_init
    _step_progress_start "indexing ${_total} services" "$_idx_tmp" "*.done" "$_total"
    
    # Parallel fetch definitions — batch of 15 concurrent
    local -a _fetch_pids=()
    local _running=0
    for _svc in "${svc_list[@]}"; do
        (
            oci limits definition list \
                --service-name "$_svc" \
                --compartment-id "$tenancy_id" \
                --region "$region" \
                --all --output json 2>/dev/null | \
            jq -r --arg svc "$_svc" \
                '.data[]? | "\($svc)|\(.name)|\(.["scope-type"] // "AD")|\(.description // "")"' \
                > "$_idx_tmp/${_svc}.tsv" 2>/dev/null
            touch "$_idx_tmp/${_svc}.done"
        ) &
        _fetch_pids+=($!); ((_running++))
        if [[ $_running -ge 15 ]]; then
            wait -n 2>/dev/null || wait
            ((_running--))
        fi
    done
    for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
    
    # Merge into index file
    cat "$_idx_tmp"/*.tsv > "$LIMITS_SEARCH_INDEX" 2>/dev/null
    local _line_ct
    _line_ct=$(wc -l < "$LIMITS_SEARCH_INDEX" 2>/dev/null) || _line_ct=0
    
    _step_complete "indexed ${_line_ct} limits across ${_total} services"
    _step_finish
    
    rm -rf "$_idx_tmp"
    return 0
}

#--------------------------------------------------------------------------------
# Global cross-service limit search — builds index if needed, searches, drills
# Usage: _limits_search_global "$tenancy_id" "$compartment_id"
#--------------------------------------------------------------------------------
_limits_search_global() {
    local tenancy_id="$1" compartment_id="$2"
    local _sterm="${3:-}"
    
    # Prompt if no pre-populated term
    if [[ -z "$_sterm" ]]; then
        echo ""
        echo -n -e "  ${CYAN}Search all service limits: ${NC}"
        read -r _sterm
        [[ -z "$_sterm" ]] && return
    fi
    
    # Build index if stale or missing
    if ! is_cache_fresh "$LIMITS_SEARCH_INDEX" 2>/dev/null || [[ ! -s "$LIMITS_SEARCH_INDEX" ]]; then
        echo ""
        echo -e "  ${WHITE}Building limit definitions index (first time / 24h expired)...${NC}"
        echo ""
        if ! _limits_build_search_index "$tenancy_id"; then
            _ui_pause
            return
        fi
        echo ""
    fi
    
    # Search index (case-insensitive)
    local -a _matches=()
    while IFS='|' read -r _svc _lname _scope _desc; do
        [[ -z "$_lname" ]] && continue
        _matches+=("${_svc}|${_lname}|${_scope}|${_desc}")
    done < <(grep -i "$_sterm" "$LIMITS_SEARCH_INDEX" 2>/dev/null)
    
    if [[ ${#_matches[@]} -eq 0 ]]; then
        echo -e "  ${YELLOW}No limits matching '${_sterm}' across all services${NC}"
        sleep 1
        return
    fi
    
    # Single match → auto-drill
    if [[ ${#_matches[@]} -eq 1 ]]; then
        IFS='|' read -r _svc _lname _scope _desc <<< "${_matches[0]}"
        echo -e "  ${GREEN}→ ${_svc}/${_lname}${NC} (${_scope})"
        sleep 0.3
        if [[ "$_svc" == "compute" ]]; then
            local _region="${FOCUS_REGION:-${REGION:-}}"
            _limits_gpu_report "$tenancy_id" "$compartment_id" "$_region" "$_lname"
        else
            _limits_availability_detail "$_svc" "$_lname" "$tenancy_id" "$compartment_id" "$_scope"
        fi
        return
    fi
    
    # Multiple matches — cap display at 50
    local _total_matches=${#_matches[@]}
    local _display_max=50
    echo ""
    if [[ $_total_matches -gt $_display_max ]]; then
        echo -e "  ${WHITE}${_total_matches} matches for '${_sterm}' (showing first ${_display_max}):${NC}"
    else
        echo -e "  ${WHITE}${_total_matches} matches for '${_sterm}':${NC}"
    fi
    echo ""
    
    printf "  ${BOLD}${CYAN}%-4s %-25s %-45s %-8s${NC}\n" "#" "Service" "Limit Name" "Scope"
    echo -e "  ${GRAY}$(printf '─%.0s' {1..84})${NC}"
    
    declare -A _GMATCH=()
    local _gi=0
    for _m in "${_matches[@]}"; do
        ((_gi++))
        [[ $_gi -gt $_display_max ]] && break
        IFS='|' read -r _svc _lname _scope _desc <<< "$_m"
        _GMATCH[$_gi]="${_svc}|${_lname}|${_scope}"
        
        printf "  ${YELLOW}%-4s${NC} ${MAGENTA}%-25s${NC} ${WHITE}%-45s${NC} ${GRAY}%-8s${NC}\n" \
            "$_gi" "${_svc:0:24}" "${_lname:0:44}" "$_scope"
    done
    
    echo ""
    echo -n -e "  ${CYAN}Select # (Enter to cancel): ${NC}"
    local _gsel
    read -r _gsel
    if [[ "$_gsel" =~ ^[0-9]+$ ]] && [[ -n "${_GMATCH[$_gsel]:-}" ]]; then
        IFS='|' read -r _svc _lname _scope <<< "${_GMATCH[$_gsel]}"
        if [[ "$_svc" == "compute" ]]; then
            # Route compute limits through the capacity report with filter
            local _region="${FOCUS_REGION:-${REGION:-}}"
            _limits_gpu_report "$tenancy_id" "$compartment_id" "$_region" "$_lname"
        else
            _limits_availability_detail "$_svc" "$_lname" "$tenancy_id" "$compartment_id" "$_scope"
        fi
    fi
}


#--------------------------------------------------------------------------------
# Render Dedicated Pool summary table from Compute Hosts cache
# Shows per-shape host counts (total / available / in-use) with limit names.
# Args: $1 = header style: "subheader" uses _ui_subheader, "banner" uses ━━━ line
# Requires: COMPUTE_HOST_CACHE, TEMP_DIR
#--------------------------------------------------------------------------------
_render_dedicated_pool() {
    [[ -s "$COMPUTE_HOST_CACHE" ]] && grep -qv "^#" "$COMPUTE_HOST_CACHE" || return 0
    local _style="${1:-subheader}"

    echo ""
    if [[ "$_style" == "banner" ]]; then
        echo -e "  ${BOLD}${WHITE}━━━ Dedicated Pool ━━━${NC}"
    else
        _ui_subheader "Dedicated Pool" 0
    fi

    # Shape → service limit name mapping (BM shapes in capacity topologies)
    declare -A _dp_limit_map=(
        ["BM.GPU2.2"]="bm-gpu2-2-count"
        ["BM.GPU3.8"]="bm-gpu3-8-count"
        ["BM.GPU4.8"]="gpu4-count"
        ["BM.GPU.A10.4"]="gpu-a10-count"
        ["BM.GPU.A100-v2.8"]="gpu-a100-v2-count"
        ["BM.GPU.H100.8"]="gpu-h100-count"
        ["BM.GPU.B4.8"]="gpu-b4-count"
    )

    printf "  ${BOLD}${CYAN}%-48s %6s %10s %8s${NC}\n" "SHAPE" "TOTAL" "AVAILABLE" "IN USE"
    echo -e "  ${GRAY}──────────────────────────────────────────────────────────────────────────────${NC}"

    local _dp_agg="${TEMP_DIR}/ct_dp_agg_$$.txt"
    grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '{
        shape = $4
        if (shape == "" || shape == "N/A") shape = "(unknown)"
        total[shape]++
        if ($8 == "N/A" || $8 == "") avail[shape]++
        else inuse[shape]++
    } END {
        for (s in total) printf "%s|%d|%d|%d\n", s, total[s], avail[s]+0, inuse[s]+0
    }' | sort -t'|' -k1,1 > "$_dp_agg"

    while IFS='|' read -r _dp_shape _dp_total _dp_avail _dp_inuse; do
        [[ -z "$_dp_shape" ]] && continue

        local _dp_avail_color="${NC}"
        [[ "$_dp_avail" -gt 0 ]] && _dp_avail_color="${GREEN}"
        local _dp_inuse_color="${NC}"
        [[ "$_dp_inuse" -gt 0 ]] && _dp_inuse_color="${YELLOW}"

        local _dp_lname="${_dp_limit_map[$_dp_shape]:-}"
        local _dp_lsuffix=""
        [[ -n "$_dp_lname" ]] && _dp_lsuffix=" (${_dp_lname})"
        local _dp_label="${_dp_shape}${_dp_lsuffix}"
        local _dp_pad=$(( 48 - ${#_dp_label} ))
        [[ $_dp_pad -lt 1 ]] && _dp_pad=1

        printf "  ${WHITE}%s${GRAY}%s${NC}%*s %6s ${_dp_avail_color}%10s${NC} ${_dp_inuse_color}%8s${NC}\n" \
            "$_dp_shape" "$_dp_lsuffix" "$_dp_pad" "" "$_dp_total" "$_dp_avail" "$_dp_inuse"
    done < "$_dp_agg"
    rm -f "$_dp_agg" 2>/dev/null

    echo ""
    echo -e "  ${GRAY}Available = no instance running, ready to provision${NC}"
}

# Extended dedicated pool renderer — per-AD columns matching compute standard capacity layout
# Requires: COMPUTE_HOST_CACHE, _ad_list[], _ad_short[], _rpt_ra(), _rpt_fnum() (all from _limits_gpu_report scope)
_render_dedicated_pool_ext() {
    [[ -s "$COMPUTE_HOST_CACHE" ]] && grep -qv "^#" "$COMPUTE_HOST_CACHE" || return 0
    local _style="${1:-subheader}"

    echo ""
    if [[ "$_style" == "banner" ]]; then
        echo -e "  ${BOLD}${WHITE}━━━ Dedicated Pool ━━━${NC}"
    else
        _ui_subheader "Dedicated Pool" 0
    fi

    # Shape → service limit name mapping (BM shapes in capacity topologies)
    declare -A _dp_limit_map=(
        ["BM.GPU2.2"]="bm-gpu2-2-count"
        ["BM.GPU3.8"]="bm-gpu3-8-count"
        ["BM.GPU4.8"]="gpu4-count"
        ["BM.GPU.A10.4"]="gpu-a10-count"
        ["BM.GPU.A100-v2.8"]="gpu-a100-v2-count"
        ["BM.GPU.H100.8"]="gpu-h100-count"
        ["BM.GPU.B4.8"]="gpu-b4-count"
    )

    # ── Aggregate compute hosts per shape per AD ──
    local _dp_agg="${TEMP_DIR}/ct_dp_agg_ext_$$.txt"
    grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '{
        shape = $4; ad = $6
        if (shape == "" || shape == "N/A") shape = "(unknown)"
        if (ad == "" || ad == "N/A") ad = "(unknown-ad)"
        key = shape "|" ad
        total[key]++
        if ($8 == "N/A" || $8 == "") unocc[key]++
    } END {
        for (k in total) printf "%s|%d|%d\n", k, total[k], unocc[k]+0
    }' | sort -t'|' -k1,1 > "$_dp_agg"

    # Build associative arrays: _dp_hosts[shape|ad_short] = total, _dp_unocc[shape|ad_short] = unoccupied
    declare -A _dp_hosts=() _dp_unocc=()
    local -a _dp_shapes_seen=()
    declare -A _dp_shape_set=()
    while IFS='|' read -r _dps _dpa _dpt _dpu; do
        [[ -z "$_dps" ]] && continue
        # Convert full AD name to short form (strip prefix before colon)
        local _dpa_short="${_dpa##*:}"
        _dp_hosts["${_dps}|${_dpa_short}"]="$_dpt"
        _dp_unocc["${_dps}|${_dpa_short}"]="$_dpu"
        if [[ -z "${_dp_shape_set[$_dps]:-}" ]]; then
            _dp_shapes_seen+=("$_dps")
            _dp_shape_set["$_dps"]=1
        fi
    done < "$_dp_agg"
    rm -f "$_dp_agg" 2>/dev/null

    [[ ${#_dp_shapes_seen[@]} -eq 0 ]] && return 0

    # Sort shapes
    IFS=$'\n' read -r -d '' -a _dp_shapes_seen < <(printf '%s\n' "${_dp_shapes_seen[@]}" | sort && printf '\0') || true

    # ── Header (same layout as standard capacity table) ──
    local _col1=46
    printf "  ${BOLD}${CYAN}%-${_col1}s${NC}" "Shape / Limit"
    for _ads in "${_ad_short[@]}"; do
        printf " ${BOLD}${CYAN}%-24s${NC}" "$_ads"
    done
    echo ""
    printf "  ${BOLD}${CYAN}%-${_col1}s${NC}" ""
    for _ads in "${_ad_short[@]}"; do
        printf " ${BOLD}${GRAY}%8s %7s %7s${NC}" "Cap" "Used" "Limit"
    done
    echo ""
    printf "  ${GRAY}%-${_col1}s" "$(printf '─%.0s' $(seq 1 $_col1))"
    for _ads in "${_ad_short[@]}"; do
        printf " %-24s" "$(printf '─%.0s' {1..24})"
    done
    echo -e "${NC}"

    # ── Data rows ──
    for _dps in "${_dp_shapes_seen[@]}"; do
        local _dp_lname="${_dp_limit_map[$_dps]:-}"
        local _dp_lsuffix=""
        [[ -n "$_dp_lname" ]] && _dp_lsuffix=" (${_dp_lname})"
        local _dp_label="${_dps}${_dp_lsuffix}"
        local _dp_pad=$(( _col1 - ${#_dp_label} ))
        [[ $_dp_pad -lt 1 ]] && _dp_pad=1

        printf "  ${WHITE}%s${GRAY}%s${NC}%*s" "$_dps" "$_dp_lsuffix" "$_dp_pad" ""

        for _ads in "${_ad_short[@]}"; do
            local _dp_key="${_dps}|${_ads}"
            local _dp_un="${_dp_unocc[$_dp_key]:-0}"

            # Cap column: ✓(n) if unoccupied hosts exist, ✗ if none
            local _cap_str="✗"
            if [[ "$_dp_un" -gt 0 ]] 2>/dev/null; then
                _cap_str="✓(${_dp_un})"
            fi

            local _cap_display="${RED}${_cap_str}${NC}"
            [[ "$_cap_str" == ✓* ]] && _cap_display="${GREEN}${_cap_str}${NC}"
            local _cw_color=21

            # Used / Limit from resource-availability API
            local _uv="-" _av="-"
            if [[ -n "$_dp_lname" ]]; then
                local _ra_data
                _ra_data=$(_rpt_ra "compute" "$_dp_lname" "$_ads")
                local _lv_raw
                IFS='|' read -r _lv_raw _uv _av <<< "$_ra_data"
            fi
            _uv=$(_rpt_fnum "$_uv"); _av=$(_rpt_fnum "$_av")

            if [[ "$_uv" == "ERR" || "$_uv" == "RATE" || "$_uv" == "DENY" ]]; then
                printf " %${_cw_color}b ${RED}%7s %7s${NC}" "$_cap_display" "$_uv" "$_av"
            else
                printf " %${_cw_color}b %7s %7s" "$_cap_display" "$_uv" "$_av"
            fi
        done
        echo ""
    done

    echo ""
    echo -e "  ${GRAY}Cap: Unoccupied dedicated hosts in this AD — ✓(n)=n available, ✗=none${NC}"
}

#--------------------------------------------------------------------------------
# Compute Standard Capacity — Capacity + Limits + Used/Available unified view
#--------------------------------------------------------------------------------
_limits_gpu_report() {
    local tenancy_id="$1" compartment_id="$2" region="$3"
    local _filter="${4:-}"   # optional: filter shapes/limits by keyword
    
    while true; do
        tenancy_id="${TENANCY_ID:-$tenancy_id}"
        compartment_id="${FOCUS_COMPARTMENT_ID:-${COMPARTMENT_ID:-$compartment_id}}"
        region="${FOCUS_REGION:-${REGION:-$region}}"
        echo ""
        _ui_menu_header "COMPUTE STANDARD CAPACITY" \
            --breadcrumb "Operations" "Service Limits" "Compute Capacity" \
            --cmd "oci limits resource-availability get --service-name <svc> --limit-name <limit> --compartment-id \$TENANCY_ID --availability-domain <AD> | oci compute compute-capacity-report create | oci compute compute-host list" \
            --env \
            --cache "${COMPUTE_LIMITS_CACHE}|Limits Catalog" --cache "${COMPUTE_HOST_CACHE}|Compute Hosts"
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 1: Discover ADs
        # ══════════════════════════════════════════════════════════════════════
        if ! _discover_ads "$tenancy_id"; then
            echo -e "  ${RED}Could not discover availability domains${NC}"
            _ui_pause "return"; return
        fi
        local -a _ad_list=("${_AD_LIST[@]}") _ad_short=("${_AD_SHORT[@]}")
        local _ad_count=${#_ad_list[@]}
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 2: Shape → Limit mapping
        # ══════════════════════════════════════════════════════════════════════
        
        # Shapes for capacity report (loads from config, defaults to GPU)
        _cap_load_shapes
        local -a _GPU_SHAPES=("${_REPORT_SHAPES[@]}")
        local -a _CAP_SHAPES=("${_REPORT_SHAPES[@]}")
        
        # Shape → primary limit name mapping
        # NOTE: vm-gpu* limits excluded — they are VM-specific subdivisions of the gpu* limits
        declare -A _SHAPE_LIMIT_MAP=(
            ["VM.GPU.A10.1"]="gpu-a10-count"
            ["VM.GPU.A10.2"]="gpu-a10-count"
            ["BM.GPU2.2"]="bm-gpu2-2-count"
            ["BM.GPU3.8"]="bm-gpu3-8-count"
            ["BM.GPU4.8"]="gpu4-count"
            ["BM.GPU.A10.4"]="gpu-a10-count"
            ["BM.GPU.A100-v2.8"]="gpu-a100-v2-count"
            ["BM.GPU.H100.8"]="gpu-h100-count"
            ["BM.GPU.H200.8"]="gpu-h200-count"
            ["BM.GPU.B4.8"]="gpu-b4-count"
            ["BM.GPU.B5.8"]="gpu-b5-count"
            ["BM.GPU.GB200-v3.4"]="gpu-gb200-v3-count"
            ["VM.Standard.E5.Flex"]="standard-e5-core-count"
            ["VM.Standard.E4.Flex"]="standard-e4-core-count"
            ["VM.Standard.E6.Flex"]="standard-e6-core-count"
        )

        # Shape → secondary limits (core/memory pairs for VM/Flex shapes)
        # Displayed as indented sub-rows below the primary limit
        declare -A _SHAPE_EXTRA_LIMITS=(
            ["VM.Standard.E4.Flex"]="standard-e4-memory-count"
            ["VM.Standard.E5.Flex"]="standard-e5-memory-count"
            ["VM.Standard.E6.Flex"]="standard-e6-memory-count"
        )

        # NOTE: Related service limits (compute-management, container-engine, block-storage, etc.)
        # removed to reduce API call count. Use o5,1 Quick View for those services.

        # ══════════════════════════════════════════════════════════════════════
        # Filter: narrow shapes and limits before fetch to minimize API calls
        # ══════════════════════════════════════════════════════════════════════
        if [[ -n "$_filter" ]]; then
            local -a _filtered_shapes=()
            for _sh in "${_GPU_SHAPES[@]}"; do
                local _lm="${_SHAPE_LIMIT_MAP[$_sh]:-}"
                local _match_str="${_sh} ${_lm}"
                local _el_str="${_SHAPE_EXTRA_LIMITS[$_sh]:-}"
                [[ -n "$_el_str" ]] && _match_str+=" ${_el_str}"
                if [[ "${_match_str,,}" == *"${_filter,,}"* ]]; then
                    _filtered_shapes+=("$_sh")
                fi
            done
            _GPU_SHAPES=("${_filtered_shapes[@]}")
            _CAP_SHAPES=("${_filtered_shapes[@]}")
        fi

        # Collect all unique compute AD limits for resource-availability
        # Start with shape-mapped limits
        declare -A _RA_COMPUTE_AD=()
        for _sh in "${_GPU_SHAPES[@]}"; do
            local _lm="${_SHAPE_LIMIT_MAP[$_sh]:-}"
            [[ -n "$_lm" ]] && _RA_COMPUTE_AD["$_lm"]=1
            # Include secondary limits (core/memory) for RA fetch
            local _extras="${_SHAPE_EXTRA_LIMITS[$_sh]:-}"
            for _el in $_extras; do
                [[ -n "$_el" ]] && _RA_COMPUTE_AD["$_el"]=1
            done
        done

        # ══════════════════════════════════════════════════════════════════════
        # Phase 3: Parallel fetch — capacity reports + resource-availability
        # ══════════════════════════════════════════════════════════════════════
        local _gtmp; _gtmp=$(mktemp -d "${TEMP_DIR}/gpu_lim.XXXXXX")
        _step_init

        # Pre-fetch compute limits catalog (synchronous) so we discover ALL limit names
        # Skip when filtered — only fetch for the full report
        if [[ -z "$_filter" ]]; then
            if ! is_cache_fresh "$COMPUTE_LIMITS_CACHE" 2>/dev/null || [[ ! -s "$COMPUTE_LIMITS_CACHE" ]]; then
                _step_active "limits catalog"
                local _j; _j=$(oci limits value list --service-name compute --compartment-id "$tenancy_id" --region "$region" --scope-type AD --all --output json 2>/dev/null)
                [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" >/dev/null 2>&1 && echo "$_j" | _cache_write "$COMPUTE_LIMITS_CACHE"
                _step_complete "limits catalog"
            fi
        fi

        # Fetch compute hosts in background (for Dedicated Pool section)
        # Skip in filter mode — Dedicated Pool is not shown there
        local _ct_fetch_pid=""
        if [[ -z "$_filter" ]]; then
            fetch_compute_hosts &
            _ct_fetch_pid=$!
        fi

        local -a _ra_compute_list=()
        for _k in "${!_RA_COMPUTE_AD[@]}"; do _ra_compute_list+=("$_k"); done
        IFS=$'\n' _ra_compute_list=($(sort <<< "${_ra_compute_list[*]}")); unset IFS

        # Count total fetch work
        local _cap_fetches=$_ad_count
        local _ra_ad_fetches=$(( ${#_ra_compute_list[@]} * _ad_count ))
        
        local _fetch_total=$(( _cap_fetches + _ra_ad_fetches ))
        # Set timer start for the parallel fetch phase
        if [[ -n "${EPOCHREALTIME:-}" ]]; then
            _STEP_ACTIVE_T0="$EPOCHREALTIME"
        else
            _STEP_ACTIVE_T0=$(date +%s.%N 2>/dev/null || date +%s)
        fi
        _step_progress_start "compute capacity (${_fetch_total} queries)" "$_gtmp" "*.done" "$_fetch_total"
        
        local -a _fetch_pids=()
        local _max_concurrent=5
        
        # Robust throttle: count actual running background jobs
        _rpt_throttle() {
            while [[ $(jobs -rp | wc -l) -ge $_max_concurrent ]]; do
                sleep 0.15
            done
        }
        
        # Wrapper: resource-availability get with retry on 429
        _rpt_ra_fetch() {
            local _svc="$1" _lname="$2" _cid="$3" _out="$4" _err="$5"
            shift 5
            # remaining args: optional --availability-domain <ad>
            local _attempt
            for _attempt in 1 2 3; do
                oci limits resource-availability get \
                    --service-name "$_svc" \
                    --limit-name "$_lname" \
                    --compartment-id "$_cid" \
                    --region "$region" \
                    "$@" \
                    --output json > "$_out" 2>"$_err"
                # Success check: valid JSON with .data
                if [[ -s "$_out" ]] && grep -q '"data"' "$_out" 2>/dev/null; then
                    return 0
                fi
                # Rate limited? Retry with backoff
                if grep -q "TooManyRequests\|429" "$_err" 2>/dev/null; then
                    sleep $(( _attempt * 2 ))
                else
                    return 1  # Non-retryable error
                fi
            done
            return 1
        }
        
        # ── 3a: Capacity reports per AD (per-shape to avoid batch rejection) ──
        local _adi=0
        for _ad in "${_ad_list[@]}"; do
            local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
            if is_cache_fresh "$_cap_cache" 20 2>/dev/null && [[ -s "$_cap_cache" ]]; then
                touch "$_gtmp/cap_${_adi}.done"
            else
                mkdir -p "$_gtmp/ad_${_adi}"
                local _si=0
                for _sh in "${_CAP_SHAPES[@]}"; do
                    local _sh_json
                    if [[ "$_sh" == *".Flex" ]]; then
                        _sh_json=$(jq -nc --arg s "$_sh" --argjson o "$CAPACITY_FLEX_OCPUS" --argjson m "$CAPACITY_FLEX_MEMORY" \
                            '[{"instanceShape":$s,"instanceShapeConfig":{"ocpus":$o,"memoryInGBs":$m}}]')
                    else
                        _sh_json=$(jq -nc --arg s "$_sh" '[{"instanceShape":$s}]')
                    fi
                    _rpt_throttle
                    (oci compute compute-capacity-report create \
                        --compartment-id "$tenancy_id" \
                        --availability-domain "$_ad" \
                        --region "$region" \
                        --shape-availabilities "$_sh_json" \
                        --output json > "$_gtmp/ad_${_adi}/s_${_si}.json" 2>/dev/null
                     touch "$_gtmp/ad_${_adi}/s_${_si}.done") &
                    _fetch_pids+=($!)
                    ((_si++))
                done
                (
                    while [[ $(find "$_gtmp/ad_${_adi}/" -name 's_*.done' 2>/dev/null | wc -l) -lt $_si ]]; do
                        sleep 0.2
                    done
                    # Filter out empty/invalid files (failed shape calls produce empty files)
                    _valid_files=()
                    for _sf in "$_gtmp/ad_${_adi}"/s_*.json; do
                        [[ -s "$_sf" ]] && jq -e '.data' "$_sf" >/dev/null 2>&1 && _valid_files+=("$_sf")
                    done
                    if [[ ${#_valid_files[@]} -gt 0 ]]; then
                        jq -n --arg ad "$_ad" '{data: {"availability-domain": $ad, "shape-availabilities": [inputs | .data."shape-availabilities"[]?]}}' \
                            "${_valid_files[@]}" > "$_gtmp/cap_${_adi}.json" 2>/dev/null
                    else
                        echo '{"data":{"shape-availabilities":[]}}' > "$_gtmp/cap_${_adi}.json"
                    fi
                    touch "$_gtmp/cap_${_adi}.done"
                ) &
                _fetch_pids+=($!)
            fi
            ((_adi++))
        done
        
        # Wait for capacity reports before starting resource-availability
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        _fetch_pids=()
        
        # ── 3b: Resource-availability for compute AD limits ──
        # Uses: oci limits resource-availability get --service-name compute --limit-name <limit> --compartment-id $TENANCY_ID --availability-domain <ad>
        for _lname in "${_ra_compute_list[@]}"; do
            _adi=0
            for _ad in "${_ad_list[@]}"; do
                local _ra_file="$_gtmp/ra_compute_${_lname}_${_ad_short[$_adi]}.json"
                local _ra_err="$_gtmp/ra_compute_${_lname}_${_ad_short[$_adi]}.err"
                _rpt_throttle
                (_rpt_ra_fetch "compute" "$_lname" "$tenancy_id" "$_ra_file" "$_ra_err" \
                    --availability-domain "$_ad"
                 touch "$_gtmp/ra_compute_${_lname}_${_ad_short[$_adi]}.done") &
                _fetch_pids+=($!)
                ((_adi++))
            done
        done
        
        # Wait for all fetches
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        
        # Write capacity reports to cache
        _adi=0
        for _ad in "${_ad_list[@]}"; do
            local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
            if [[ -f "$_gtmp/cap_${_adi}.json" ]]; then
                local _cj; _cj=$(cat "$_gtmp/cap_${_adi}.json")
                [[ -n "$_cj" ]] && jq -e '.data."shape-availabilities"[0]' <<< "$_cj" >/dev/null 2>&1 && echo "$_cj" > "$_cap_cache"
            fi
            ((_adi++))
        done
        
        _step_complete "capacity-report(${_ad_count} ADs)  limits(${#_ra_compute_list[@]} × ${_ad_count} ADs = ${_ra_ad_fetches})  │  ${_fetch_total} API calls"

        # Wait for compute-hosts background fetch and show as separate step
        if [[ -n "$_ct_fetch_pid" ]]; then
            _step_active "compute-hosts"
            wait "$_ct_fetch_pid" 2>/dev/null
            _ct_fetch_pid=""
            local _ct_hosts=0
            if [[ -s "$COMPUTE_HOST_CACHE" ]]; then _ct_hosts=$(grep -cv "^#" "$COMPUTE_HOST_CACHE" 2>/dev/null) || _ct_hosts=0; fi
            _step_complete "compute-hosts(${_ct_hosts} hosts)"
        fi

        _step_finish
        echo ""
        
        # ══════════════════════════════════════════════════════════════════════
        # Helpers: read resource-availability from temp files
        # ══════════════════════════════════════════════════════════════════════
        
        # Get resource-availability for a limit in a specific AD/region
        # Returns: "limit|used|avail"
        _rpt_ra() {
            local _svc="$1" _lname="$2" _ad_key="$3"  # ad_key = ad_short or "region"
            local _rf="$_gtmp/ra_${_svc}_${_lname}_${_ad_key}.json"
            local _ef="$_gtmp/ra_${_svc}_${_lname}_${_ad_key}.err"
            
            # Check if response file exists and has valid JSON
            if [[ -s "$_rf" ]]; then
                # Validate it has .data key
                if jq -e '.data' "$_rf" >/dev/null 2>&1; then
                    local _lv _uv _av
                    _lv=$(jq -r '.data["effective-quota-value"] // "-"' "$_rf" 2>/dev/null)
                    _uv=$(jq -r '.data.used // "-"' "$_rf" 2>/dev/null)
                    _av=$(jq -r '.data.available // "-"' "$_rf" 2>/dev/null)
                    echo "${_lv}|${_uv}|${_av}"
                    return
                fi
            fi
            
            # API call failed — classify error using shared helper
            if [[ -s "$_ef" ]]; then
                _oci_parse_error "$_ef"
                case "$_OCI_ERR_CLASS" in
                    RATE) echo "RATE|RATE|RATE" ;;
                    DENY) echo "DENY|DENY|DENY" ;;
                    *)    echo "ERR|ERR|ERR" ;;
                esac
            else
                echo "-|-|-"
            fi
        }
        
        # Format a number compactly (large = unlimited, ERR/RATE/DENY passthrough)
        _rpt_fnum() {
            local _v="$1"
            [[ "$_v" == "-" || "$_v" == "null" || -z "$_v" ]] && { echo "-"; return; }
            [[ "$_v" == "ERR" || "$_v" == "RATE" || "$_v" == "DENY" ]] && { echo "$_v"; return; }
            [[ ${#_v} -ge 13 ]] && { echo "unlim"; return; }
            echo "$_v"
        }
        
        # ── Fetch diagnostics ──
        local _ra_ok=0 _ra_err=0 _ra_rate=0
        for _rf in "$_gtmp"/ra_*.json; do
            [[ ! -f "$_rf" ]] && continue
            if [[ -s "$_rf" ]] && jq -e '.data' "$_rf" >/dev/null 2>&1; then
                ((_ra_ok++))
            else
                ((_ra_err++))
                local _ef="${_rf%.json}.err"
                [[ -s "$_ef" ]] && grep -q "TooManyRequests\|429" "$_ef" 2>/dev/null && ((_ra_rate++))
            fi
        done
        
        if [[ $_ra_err -gt 0 ]]; then
            echo -e "  ${YELLOW}⚠ API Results:${NC} ${GREEN}${_ra_ok} succeeded${NC}  ${RED}${_ra_err} failed${NC}$( [[ $_ra_rate -gt 0 ]] && echo -e "  ${YELLOW}(${_ra_rate} rate-limited — try 'r' to refresh)${NC}" )"
            echo ""
        fi
        
        # ══════════════════════════════════════════════════════════════════════
        # Consolidated Compute Capacity Table
        # Shapes with capacity + used/avail, then additional unmapped limits
        # ══════════════════════════════════════════════════════════════════════
        if [[ -n "$_filter" ]]; then
            echo -e "  ${BOLD}${WHITE}━━━ Compute Standard Capacity ━━━${NC}  ${YELLOW}filter: ${WHITE}${_filter}${NC}"
        else
            echo -e "  ${BOLD}${WHITE}━━━ Compute Standard Capacity ━━━${NC}"
        fi
        echo ""

        # Sort shapes by group for contiguous display: VM GPU → BM GPU → Flex → Other
        local -a _sorted_shapes=()
        local -a _sg_vmgpu=() _sg_bmgpu=() _sg_flex=() _sg_other=()
        for _sh in "${_GPU_SHAPES[@]}"; do
            case "$_sh" in
                VM.GPU*)       _sg_vmgpu+=("$_sh") ;;
                BM.GPU*)       _sg_bmgpu+=("$_sh") ;;
                VM.Standard*)  _sg_flex+=("$_sh") ;;
                *)             _sg_other+=("$_sh") ;;
            esac
        done
        _sorted_shapes=("${_sg_vmgpu[@]}" "${_sg_bmgpu[@]}" "${_sg_flex[@]}" "${_sg_other[@]}")

        # Build set of shared limits (limits mapped by >1 shape) — reset each iteration
        local -A _limit_shape_count=()
        for _sh in "${_sorted_shapes[@]}"; do
            local _lm="${_SHAPE_LIMIT_MAP[$_sh]:-}"
            [[ -n "$_lm" ]] && _limit_shape_count["$_lm"]=$(( ${_limit_shape_count["$_lm"]:-0} + 1 ))
        done

        # Dynamic header: per-AD columns
        # Col layout: 2+46 shape+limit | per-AD: 1+8(cap) +1+7(used) +1+7(avail) = 25 per AD
        local _col1=46
        printf "  ${BOLD}${CYAN}%-${_col1}s${NC}" "Shape / Limit"
        for _ads in "${_ad_short[@]}"; do
            printf " ${BOLD}${CYAN}%-24s${NC}" "$_ads"
        done
        echo ""
        printf "  ${BOLD}${CYAN}%-${_col1}s${NC}" ""
        for _ads in "${_ad_short[@]}"; do
            printf " ${BOLD}${GRAY}%8s %7s %7s${NC}" "Cap" "Used" "Limit"
        done
        echo ""
        printf "  ${GRAY}%-${_col1}s" "$(printf '─%.0s' $(seq 1 $_col1))"
        for _ads in "${_ad_short[@]}"; do
            printf " %-24s" "$(printf '─%.0s' {1..24})"
        done
        echo -e "${NC}"

        # Display shapes with group headers (using sorted order for contiguous groups)
        local _prev_group=""
        for _sh in "${_sorted_shapes[@]}"; do
            local _lmap="${_SHAPE_LIMIT_MAP[$_sh]:-}"

            # Filter: skip shapes/limits not matching search term (case-insensitive)
            if [[ -n "$_filter" ]]; then
                local _match_str="${_sh} ${_lmap}"
                [[ "${_match_str,,}" != *"${_filter,,}"* ]] && continue
            fi

            # Skip shapes with no limit mapping and no capacity data (all dashes)
            if [[ -z "$_lmap" ]]; then
                local _has_cap_data=false _sci=0
                for _sc_ad in "${_ad_list[@]}"; do
                    local _sc_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_sci]}.json"
                    _cap_shape_status "$_sh" "$_sc_cache"
                    [[ "$_CAP_STATUS" != "-" ]] && _has_cap_data=true && break
                    ((_sci++))
                done
                [[ "$_has_cap_data" == "false" ]] && continue
            fi

            # Determine group and print header on change
            local _group=""
            case "$_sh" in
                VM.GPU*)       _group="VM GPU" ;;
                BM.GPU*)       _group="BM GPU" ;;
                VM.Standard*)  _group="Flex Compute" ;;
                *)             _group="Other" ;;
            esac
            if [[ "$_group" != "$_prev_group" ]]; then
                [[ -n "$_prev_group" ]] && echo ""
                echo -e "  ${BOLD}${CYAN}${_group}${NC}"
                _prev_group="$_group"
            fi

            # Build single-line label: show limit name for all mapped shapes
            local _limit_suffix=""
            if [[ -n "$_lmap" ]]; then
                local _shared_tag=""
                [[ ${_limit_shape_count["$_lmap"]:-0} -gt 1 ]] && _shared_tag=", shared"
                _limit_suffix=" (${_lmap}${_shared_tag})"
            fi
            local _vis_label="${_sh}${_limit_suffix}"
            local _pad=$(( _col1 - ${#_vis_label} ))
            [[ $_pad -lt 1 ]] && _pad=1

            # Print shape + limit suffix, padded to column width
            printf "  ${WHITE}%s%s${NC}%*s" "$_sh" "$_limit_suffix" "$_pad" ""
            local -a _shape_cap_strs=()   # collect per-AD cap strings for sub-rows
            _adi=0
            for _ad in "${_ad_list[@]}"; do
                local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
                _cap_shape_status "$_sh" "$_cap_cache"
                local _status="$_CAP_STATUS" _count="$_CAP_COUNT"

                # Format capacity status: ✓=available, ✗=everything else
                local _cap_str="✗"
                if [[ "$_status" == "AVAILABLE" ]]; then
                    if [[ "$_count" == "-" || "$_count" == "null" || -z "$_count" ]]; then
                        _cap_str="✓"
                    else
                        _cap_str="✓(${_count})"
                    fi
                fi
                _shape_cap_strs+=("$_cap_str")

                # Get resource-availability for this shape's limit
                local _ra_data _uv _av
                if [[ -n "$_lmap" ]]; then
                    _ra_data=$(_rpt_ra "compute" "$_lmap" "${_ad_short[$_adi]}")
                    local _lv_raw
                    IFS='|' read -r _lv_raw _uv _av <<< "$_ra_data"
                else
                    _uv="-"; _av="-"
                fi
                _uv=$(_rpt_fnum "$_uv"); _av=$(_rpt_fnum "$_av")

                # All cap symbols are UTF-8 (✓✗ = 3 bytes, 1 display char) + ANSI color (11 bytes)
                # Base width 10 = 8 display + 2 UTF-8 overhead; +11 for color escapes = 21
                local _cap_display="${RED}${_cap_str}${NC}"
                [[ "$_cap_str" == ✓* ]] && _cap_display="${GREEN}${_cap_str}${NC}"
                local _cw_color=21

                if [[ "$_uv" == "ERR" || "$_uv" == "RATE" || "$_uv" == "DENY" ]]; then
                    printf " %${_cw_color}b ${RED}%7s %7s${NC}" "$_cap_display" "$_uv" "$_av"
                else
                    printf " %${_cw_color}b %7s %7s" "$_cap_display" "$_uv" "$_av"
                fi
                ((_adi++))
            done
            echo ""

            # Sub-rows for secondary limits (e.g., memory alongside core)
            local _extras="${_SHAPE_EXTRA_LIMITS[$_sh]:-}"
            for _el in $_extras; do
                [[ -z "$_el" ]] && continue
                # Derive short label from limit name (e.g., "standard-e5-memory-count" → "memory")
                local _el_label="$_el"
                [[ "$_el" == *-memory-* ]] && _el_label="memory"
                [[ "$_el" == *-core-* ]] && _el_label="cores"
                local _el_vis="  └ ${_el_label} (${_el})"
                local _el_pad=$(( _col1 - ${#_el_vis} ))
                [[ $_el_pad -lt 1 ]] && _el_pad=1
                printf "  ${GRAY}%s${NC}%*s" "$_el_vis" "$_el_pad" ""
                _adi=0
                for _ad in "${_ad_list[@]}"; do
                    local _ra_data; _ra_data=$(_rpt_ra "compute" "$_el" "${_ad_short[$_adi]}")
                    local _lv_raw
                    IFS='|' read -r _lv_raw _uv _av <<< "$_ra_data"
                    _uv=$(_rpt_fnum "$_uv"); _av=$(_rpt_fnum "$_av")
                    if [[ "$_uv" == "ERR" || "$_uv" == "RATE" || "$_uv" == "DENY" ]]; then
                        printf " ${RED}%8s %7s %7s${NC}" "" "$_uv" "$_av"
                    else
                        printf " %8s %7s %7s" "" "$_uv" "$_av"
                    fi
                    ((_adi++))
                done
                echo ""
            done
        done

        # ══════════════════════════════════════════════════════════════════════
        # Actions
        # ══════════════════════════════════════════════════════════════════════
        echo ""
        if [[ $_ra_err -gt 0 ]]; then
            echo -e "  ${GRAY}${#_ra_compute_list[@]} compute limits × ${_ad_count} ADs + ${_cap_fetches} capacity = ${_fetch_total} API calls${NC}"
            echo -e "  ${GREEN}✓ ${_ra_ok} succeeded${NC}  ${RED}✗ ${_ra_err} failed${NC}$( [[ $_ra_rate -gt 0 ]] && echo -e "  ${YELLOW}(${_ra_rate} rate-limited)${NC}" )  ${GRAY}— use 'r' to retry${NC}"
        else
            echo -e "  ${GRAY}${#_ra_compute_list[@]} compute limits × ${_ad_count} ADs + ${_cap_fetches} capacity = ${GREEN}${_fetch_total} API calls OK${NC}"
        fi
        echo ""
        echo -e "  ${GRAY}Cap:   Physical hardware available right now — ✓(n)=n hosts, ✓=available (count not reported), ✗=no capacity${NC}"
        echo -e "  ${GRAY}       Flex shapes: capacity probed at ${WHITE}${CAPACITY_FLEX_OCPUS} OCPU / ${CAPACITY_FLEX_MEMORY} GB${GRAY} (change with ${WHITE}f${GRAY})${NC}"
        echo -e "  ${GRAY}Used:  Consumed from your tenancy service limit${NC}"
        echo -e "  ${GRAY}Limit: Remaining tenancy service limit — to provision, need both Cap=✓ AND Limit>0${NC}"

        # ── Dedicated Pool (from Compute Hosts) ──
        [[ -n "$_ct_fetch_pid" ]] && wait "$_ct_fetch_pid" 2>/dev/null
        _render_dedicated_pool_ext "banner"

        # Filter mode: show results and return (no interactive menu)
        if [[ -n "$_filter" ]]; then
            echo ""
            rm -rf "$_gtmp"
            _ui_pause "return"
            return
        fi

        echo ""
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}s${NC}${WHITE})${NC}      Configure shapes (${#_GPU_SHAPES[@]}/${#_CAPACITY_ALL_SHAPES[@]} enabled)"
        echo -e "  ${YELLOW}f${NC}${WHITE})${NC}      Flex probe config (${CAPACITY_FLEX_OCPUS} OCPU / ${CAPACITY_FLEX_MEMORY} GB)"
        echo -e "  ${CYAN}/${NC}${WHITE})${NC}      Filter by shape or limit name"
        echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh (clear all caches)"
        echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
        echo ""
        _ui_prompt "Compute Capacity" "s, f, /, env [c|r], r, b"
        
        local _sel
        read -r _sel
        [[ "${_sel:-}" == :* ]] && _nav_try_jump "$_sel" && return
        
        rm -rf "$_gtmp"
        
        case "$_sel" in
            s|S)
                _cap_shape_picker
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                continue
                ;;
            f|F)
                echo ""
                echo -e "  ${BOLD}${WHITE}Flex Shape Capacity Probe Config${NC}"
                echo -e "  ${GRAY}These values are used when querying capacity for Flex shapes.${NC}"
                echo -e "  ${GRAY}Current: ${WHITE}${CAPACITY_FLEX_OCPUS} OCPU / ${CAPACITY_FLEX_MEMORY} GB${NC}"
                echo ""
                local _new_ocpus _new_mem
                read -rp "  OCPUs [${CAPACITY_FLEX_OCPUS}]: " _new_ocpus
                read -rp "  Memory GB [${CAPACITY_FLEX_MEMORY}]: " _new_mem
                [[ "$_new_ocpus" =~ ^[0-9]+$ && "$_new_ocpus" -gt 0 ]] && CAPACITY_FLEX_OCPUS="$_new_ocpus"
                [[ "$_new_mem" =~ ^[0-9]+$ && "$_new_mem" -gt 0 ]] && CAPACITY_FLEX_MEMORY="$_new_mem"
                _cap_save_flex_conf
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                echo -e "  ${GREEN}✓ Saved: ${CAPACITY_FLEX_OCPUS} OCPU / ${CAPACITY_FLEX_MEMORY} GB — capacity caches cleared${NC}"
                sleep 0.5
                continue
                ;;
            /*)
                local _fterm="${_sel#/}"; _fterm="${_fterm# }"
                if [[ -z "$_fterm" ]]; then
                    echo -n -e "  ${CYAN}Filter: ${NC}"
                    read -r _fterm
                fi
                if [[ -n "$_fterm" ]]; then
                    rm -rf "$_gtmp"
                    _limits_gpu_report "$tenancy_id" "$compartment_id" "$region" "$_fterm"
                fi
                continue
                ;;
            r|R)
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                rm -f "$COMPUTE_LIMITS_CACHE" "$COMPUTE_LIMITS_REGION_CACHE"
                rm -f "$AD_LIST_CACHE" "$COMPUTE_SHAPES_CACHE"
                rm -f "$COMPUTE_HOST_CACHE"
                _CAPACITY_ALL_SHAPES=()
                continue
                ;;
            env*|ENV*)
                _env_dispatch "$_sel"
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                rm -f "$COMPUTE_LIMITS_CACHE" "$COMPUTE_LIMITS_REGION_CACHE"
                rm -f "$AD_LIST_CACHE" "$COMPUTE_SHAPES_CACHE"
                rm -f "$COMPUTE_HOST_CACHE"
                _CAPACITY_ALL_SHAPES=()
                continue
                ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) continue ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Compute Capacity Report — Real-time shape availability across ADs
# NOTE: Removed from menu — superseded by _limits_gpu_report() which includes
#       capacity + limits in a single consolidated view. Kept for reference.
#--------------------------------------------------------------------------------
_capacity_report() {
    local tenancy_id="$1" region="$2"
    
    while true; do
        tenancy_id="${TENANCY_ID:-$tenancy_id}"
        region="${FOCUS_REGION:-${REGION:-$region}}"
        echo ""
        # Find newest capacity cache file for display (may not exist on first run)
        local _cap_display_file
        _cap_display_file=$(ls -t "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json 2>/dev/null | head -1)
        _ui_menu_header "COMPUTE CAPACITY REPORT" \
            --breadcrumb "Operations" "Service Limits" "Capacity Report" \
            --cmd "oci compute compute-capacity-report create --compartment-id \$TENANCY_ID --availability-domain <AD> --shape-availabilities '[...]'" \
            --env \
            --cache \
            "${AD_LIST_CACHE}|ADs" \
            "${COMPUTE_SHAPES_CACHE}|Shapes" \
            "${_cap_display_file:-${CAPACITY_REPORT_CACHE_PREFIX}_none.json}|Capacity"
        
        # ── Discover ADs ──
        if ! _discover_ads "$tenancy_id"; then
            echo -e "  ${RED}Could not discover availability domains${NC}"
            _ui_pause "return"; return
        fi
        local -a _ad_list=("${_AD_LIST[@]}") _ad_short=("${_AD_SHORT[@]}")
        local _ad_count=${#_ad_list[@]}
        
        # ── Shapes to check (loads from config, defaults to GPU) ──
        _cap_load_shapes
        local -a _CAP_SHAPES=("${_REPORT_SHAPES[@]}")
        
        if [[ ${#_CAP_SHAPES[@]} -eq 0 ]]; then
            echo -e "  ${RED}No shapes discovered — check tenancy permissions for oci compute shape list${NC}"
            _ui_pause "return"; continue
        fi
        
        # ── Parallel fetch per shape per AD (20s cache) ──
        # Sends individual API calls per shape to avoid one bad shape killing the batch
        local _ctmp; _ctmp=$(mktemp -d "${TEMP_DIR}/cap_rpt.XXXXXX")
        local _total_calls=$(( ${#_CAP_SHAPES[@]} * _ad_count ))
        _step_init
        _step_progress_start "capacity report (${_ad_count} ADs)" "$_ctmp" "*.done" "$_ad_count"
        
        local -a _fetch_pids=()
        local _adi=0
        for _ad in "${_ad_list[@]}"; do
            local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
            if is_cache_fresh "$_cap_cache" 20 2>/dev/null && [[ -s "$_cap_cache" ]]; then
                touch "$_ctmp/cap_${_adi}.done"
            else
                mkdir -p "$_ctmp/ad_${_adi}"
                local _si=0
                for _sh in "${_CAP_SHAPES[@]}"; do
                    local _sh_json
                    if [[ "$_sh" == *".Flex" ]]; then
                        _sh_json=$(jq -nc --arg s "$_sh" --argjson o "$CAPACITY_FLEX_OCPUS" --argjson m "$CAPACITY_FLEX_MEMORY" \
                            '[{"instanceShape":$s,"instanceShapeConfig":{"ocpus":$o,"memoryInGBs":$m}}]')
                    else
                        _sh_json=$(jq -nc --arg s "$_sh" '[{"instanceShape":$s}]')
                    fi
                    (oci compute compute-capacity-report create \
                        --compartment-id "$tenancy_id" \
                        --availability-domain "$_ad" \
                        --shape-availabilities "$_sh_json" \
                        --region "$region" \
                        --output json > "$_ctmp/ad_${_adi}/s_${_si}.json" 2>/dev/null
                     touch "$_ctmp/ad_${_adi}/s_${_si}.done") &
                    _fetch_pids+=($!)
                    ((_si++))
                done
                # Merge subshell: waits for all shape calls for this AD, merges results
                (
                    # Wait for all shape calls to complete (use .done sentinels, not .json)
                    while [[ $(find "$_ctmp/ad_${_adi}/" -name 's_*.done' 2>/dev/null | wc -l) -lt $_si ]]; do
                        sleep 0.2
                    done
                    # Merge per-shape results into single per-AD cache format
                    # Filter out empty/invalid files (failed shape calls produce empty files)
                    _valid_files=()
                    for _sf in "$_ctmp/ad_${_adi}"/s_*.json; do
                        [[ -s "$_sf" ]] && jq -e '.data' "$_sf" >/dev/null 2>&1 && _valid_files+=("$_sf")
                    done
                    if [[ ${#_valid_files[@]} -gt 0 ]]; then
                        jq -n --arg ad "$_ad" '{data: {"availability-domain": $ad, "shape-availabilities": [inputs | .data."shape-availabilities"[]?]}}' \
                            "${_valid_files[@]}" > "$_ctmp/cap_${_adi}.json" 2>/dev/null
                    else
                        echo '{"data":{"shape-availabilities":[]}}' > "$_ctmp/cap_${_adi}.json"
                    fi
                    touch "$_ctmp/cap_${_adi}.done"
                ) &
                _fetch_pids+=($!)
            fi
            ((_adi++))
        done
        
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        
        # Write to cache + diagnostics
        local _cap_ok=0 _cap_fail=0
        _adi=0
        for _ad in "${_ad_list[@]}"; do
            local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
            if [[ -f "$_ctmp/cap_${_adi}.json" ]]; then
                local _cj; _cj=$(cat "$_ctmp/cap_${_adi}.json")
                if [[ -n "$_cj" ]] && jq -e '.data."shape-availabilities"[0]' <<< "$_cj" >/dev/null 2>&1; then
                    echo "$_cj" > "$_cap_cache"
                    ((_cap_ok++))
                else
                    ((_cap_fail++))
                    echo -e "  ${RED}✗ ${_ad_short[$_adi]}: No valid shape results returned${NC}" >&2
                fi
            elif [[ -s "$_cap_cache" ]]; then
                ((_cap_ok++))  # Already cached
            else
                ((_cap_fail++))
            fi
            ((_adi++))
        done
        
        _step_complete "${_ad_count} ADs ($(((_cap_ok))) OK${_cap_fail:+, ${_cap_fail} failed})"
        _step_finish
        echo ""
        
        if [[ $_cap_fail -gt 0 ]]; then
            echo -e "  ${YELLOW}⚠ ${_cap_fail}/${_ad_count} AD capacity queries failed — shapes may show '-'${NC}"
            echo ""
        fi
        
        rm -rf "$_ctmp"
        
        # ── Display ──
        # Group shapes by category
        local -a _grp_vm_gpu=() _grp_bm_gpu=() _grp_vm_std=() _grp_bm_std=() _grp_vm_opt=() _grp_bm_hpc=() _grp_other=()
        for _sh in "${_CAP_SHAPES[@]}"; do
            case "$_sh" in
                VM.GPU*)       _grp_vm_gpu+=("$_sh") ;;
                BM.GPU*)       _grp_bm_gpu+=("$_sh") ;;
                VM.Standard*)  _grp_vm_std+=("$_sh") ;;
                BM.Standard*)  _grp_bm_std+=("$_sh") ;;
                VM.Optimized*) _grp_vm_opt+=("$_sh") ;;
                BM.HPC*)       _grp_bm_hpc+=("$_sh") ;;
                *)             _grp_other+=("$_sh") ;;
            esac
        done
        
        # Column layout per AD: status(14) + count(6) = 20
        # Header
        printf "  ${BOLD}${CYAN}%-28s${NC}" "Shape"
        for _ads in "${_ad_short[@]}"; do
            printf "  ${BOLD}${CYAN}%-22s${NC}" "$_ads"
        done
        echo ""
        printf "  ${GRAY}%-28s" "$(printf '─%.0s' {1..28})"
        for _ads in "${_ad_short[@]}"; do
            printf "  %-22s" "$(printf '─%.0s' {1..22})"
        done
        echo -e "${NC}"
        
        # Render helper
        _cap_render_group() {
            local _grp_label="$1" _grp_color="$2"
            shift 2
            local -a _shapes=("$@")
            [[ ${#_shapes[@]} -eq 0 ]] && return
            
            echo -e "  ${BOLD}${_grp_color}${_grp_label}${NC}"
            
            for _sh in "${_shapes[@]}"; do
                printf "  ${_grp_color}%-28s${NC}" "$_sh"
                _adi=0
                for _ad in "${_ad_list[@]}"; do
                    local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
                    _cap_shape_status "$_sh" "$_cap_cache"
                    printf "  "
                    _cap_render_status "$_CAP_STATUS" "$_CAP_COUNT"
                    ((_adi++))
                done
                echo ""
            done
            echo ""
        }
        
        _cap_render_group "VM GPU" "$YELLOW" "${_grp_vm_gpu[@]}"
        _cap_render_group "BM GPU" "$GREEN" "${_grp_bm_gpu[@]}"
        _cap_render_group "VM Standard" "$WHITE" "${_grp_vm_std[@]}"
        _cap_render_group "BM Standard" "$MAGENTA" "${_grp_bm_std[@]}"
        _cap_render_group "VM Optimized" "$CYAN" "${_grp_vm_opt[@]}"
        _cap_render_group "BM HPC" "$WHITE" "${_grp_bm_hpc[@]}"
        _cap_render_group "Other" "$GRAY" "${_grp_other[@]}"
        
        # Summary
        local _avail_ct=0 _nohost_ct=0 _nosup_ct=0 _nodata_ct=0
        for _sh in "${_CAP_SHAPES[@]}"; do
            _adi=0
            for _ad in "${_ad_list[@]}"; do
                local _cap_cache="${CAPACITY_REPORT_CACHE_PREFIX}_${_ad_short[$_adi]}.json"
                _cap_shape_status "$_sh" "$_cap_cache"
                case "$_CAP_STATUS" in
                    AVAILABLE) ((_avail_ct++)) ;;
                    OUT_OF_HOST_CAPACITY) ((_nohost_ct++)) ;;
                    HARDWARE_NOT_SUPPORTED) ((_nosup_ct++)) ;;
                    *) ((_nodata_ct++)) ;;
                esac
                ((_adi++))
            done
        done
        echo -e "  ${GRAY}${#_CAP_SHAPES[@]} shapes × ${_ad_count} ADs │ ${GREEN}${_avail_ct} available${NC} ${RED}${_nohost_ct} no capacity${NC} ${GRAY}${_nosup_ct} not supported${NC}$( [[ $_nodata_ct -gt 0 ]] && echo -e " ${YELLOW}${_nodata_ct} no data${NC}" )"
        echo ""
        
        # ── Actions ──
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}s${NC}${WHITE})${NC}      Configure shapes (${#_CAP_SHAPES[@]}/${#_CAPACITY_ALL_SHAPES[@]} enabled)"
        echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh (clear all caches)"
        echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
        echo ""
        _ui_prompt "Capacity Report" "s, env [c|r], r, b"
        
        local _sel
        read -r _sel
        [[ "${_sel:-}" == :* ]] && _nav_try_jump "$_sel" && return
        case "$_sel" in
            s|S)
                _cap_shape_picker
                continue
                ;;
            r|R)
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                rm -f "$AD_LIST_CACHE" "$COMPUTE_SHAPES_CACHE"
                _CAPACITY_ALL_SHAPES=()
                continue
                ;;
            env*|ENV*)
                _env_dispatch "$_sel"
                rm -f "${CAPACITY_REPORT_CACHE_PREFIX}"_*.json
                rm -f "$AD_LIST_CACHE" "$COMPUTE_SHAPES_CACHE"
                _CAPACITY_ALL_SHAPES=()
                continue
                ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) continue ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Main Service Limits Menu
#--------------------------------------------------------------------------------
manage_service_limits() {
    local tenancy_id="${TENANCY_ID:-}"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    if [[ -z "$tenancy_id" ]]; then
        echo -e "${RED}TENANCY_ID not set — required for limits API${NC}"
        _ui_pause "return"
        return
    fi
    
    while true; do
        # Re-read from globals in case env was switched
        tenancy_id="${TENANCY_ID:-$tenancy_id}"
        compartment_id="${FOCUS_COMPARTMENT_ID:-${COMPARTMENT_ID:-$compartment_id}}"
        region="${FOCUS_REGION:-${REGION:-$region}}"
        local choice
        echo ""
        _ui_menu_header "SERVICE LIMITS & QUOTAS" \
            --color "$RED" \
            --breadcrumb "Operations" "Service Limits" \
            --cmd "oci limits service list --compartment-id \$TENANCY_ID | oci limits value list --service-name <svc> --compartment-id \$TENANCY_ID --all | oci limits resource-availability get | oci limits quota list --compartment-id \$TENANCY_ID" \
            --env
        
        _ui_actions
        echo -e "  ${YELLOW}1${NC}) ${WHITE}Quick View${NC}                    - All key services: compute, networking, storage, security, etc."
        echo -e "  ${YELLOW}2${NC}) ${WHITE}Browse by Service${NC}             - List all OCI services and explore limits"
        echo -e "  ${YELLOW}3${NC}) ${WHITE}Quotas${NC}                        - View tenancy quotas and governance rules"
        echo -e "  ${YELLOW}4${NC}) ${WHITE}Compute Standard Capacity${NC}     - Capacity, GPU limits, and related service limits"
        echo -e "  ${CYAN}/${NC})  ${WHITE}Search limits${NC}                 - Search limit names across all services"
        echo ""
        _ui_prompt "Service Limits" "1-4, /, env [c|r|oke|vcn], b"
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return
        
        case "$choice" in
            1) _limits_quick_view "$tenancy_id" "$compartment_id" "$region" ;;
            2) _limits_browse_services "$tenancy_id" "$compartment_id" "$region" ;;
            3) _limits_quotas_view "$tenancy_id" ;;
            4) _limits_gpu_report "$tenancy_id" "$compartment_id" "$region" ;;
            /*) _limits_search_global "$tenancy_id" "$compartment_id" "${choice#/}" ;;
            env*|ENV*) _env_dispatch "$choice" ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) echo -e "${RED}Invalid selection. Enter 1-4 or b.${NC}" ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Service Limits Quick View - Multi-service parallel fetch + categorized display
# Services: compute (4-col), compute-management, container-engine, container-registry,
#   vcn, load-balancer, fast-connect, block-storage, object-storage, filesystem,
#   lustrefilestorage, kms, secrets, identity, oci-bastion, logging-analytics, psacp, regions
#--------------------------------------------------------------------------------
#--------------------------------------------------------------------------------
# Service Limits Quick View - Multi-service parallel fetch + categorized display
# Services: compute (4-col), compute-management, container-engine, container-registry,
#   vcn, load-balancer, fast-connect, block-storage, object-storage, filesystem,
#   lustrefilestorage, kms, secrets, identity, oci-bastion, logging-analytics, psacp, regions
#--------------------------------------------------------------------------------
_limits_quick_view() {
    local tenancy_id="$1" compartment_id="$2" region="$3"
    local _show_zero_limits=false
    
    # Non-compute services: "svc_name|group|display_name"
    local -a _QV_SERVICES=(
        "compute-management|Compute|Compute Management"
        "container-engine|Containers|Container Engine (OKE)"
        "container-registry|Containers|Container Registry"
        "vcn|Networking|Virtual Cloud Network"
        "load-balancer|Networking|Load Balancer"
        "fast-connect|Networking|FastConnect"
        "block-storage|Storage|Block Volume"
        "object-storage|Storage|Object Storage"
        "filesystem|Storage|File Storage"
        "lustrefilestorage|Storage|Lustre File Storage"
        "kms|Security|Key Management"
        "secrets|Security|Secrets"
        "identity|Security|Identity"
        "oci-bastion|Security|Bastion"
        "logging-analytics|Platform|Logging Analytics"
        "psacp|Platform|Process Automation"
        "regions|Platform|Regions"
    )
    local -a _QV_GROUPS=("Compute" "Containers" "Networking" "Storage" "Security" "Platform")
    
    # Section visibility toggles — per service, all enabled by default
    declare -A _QV_SECTION=()
    _QV_SECTION["compute"]="on"
    for _def in "${_QV_SERVICES[@]}"; do _QV_SECTION["${_def%%|*}"]="on"; done
    
    # Value formatter: cap huge values as "unlimited", no comma formatting for compactness
    _qv_fmt_val() {
        local _v="$1" _tag="${2:-}"
        if [[ "$_v" == "0" ]]; then
            echo "[0]"
        elif [[ ${#_v} -ge 13 ]]; then
            # 1 trillion+ is effectively unlimited in OCI
            [[ -n "$_tag" ]] && echo "[unlimited] ($_tag)" || echo "[unlimited]"
        else
            [[ -n "$_tag" ]] && echo "[${_v}] ($_tag)" || echo "[${_v}]"
        fi
    }
    
    # Name truncation: cap at N chars, append .. if truncated
    _qv_trunc() {
        local _name="$1" _max="${2:-38}"
        if [[ ${#_name} -gt $_max ]]; then
            echo "${_name:0:$((_max-2))}.."
        else
            echo "$_name"
        fi
    }
    
    while true; do
        # Re-read from globals in case env was switched
        tenancy_id="${TENANCY_ID:-$tenancy_id}"
        compartment_id="${FOCUS_COMPARTMENT_ID:-${COMPARTMENT_ID:-$compartment_id}}"
        region="${FOCUS_REGION:-${REGION:-$region}}"
        echo ""
        _ui_menu_header "SERVICE LIMITS QUICK VIEW" \
            --breadcrumb "Operations" "Service Limits" "Quick View" \
            --cmd "oci limits value list --service-name <svc> --compartment-id \$TENANCY_ID --scope-type AD|REGION --all" \
            --env
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 1: Parallel fetch ALL services (cache-first)
        # ══════════════════════════════════════════════════════════════════════
        local _ltmp
        _ltmp=$(mktemp -d "${TEMP_DIR}/lim_qv.XXXXXX")
        local _fetch_total=0 _fetch_precomplete=0
        
        # Compute (uses existing cache constants)
        ((_fetch_total+=2))
        if is_cache_fresh "$COMPUTE_LIMITS_CACHE" 2>/dev/null && [[ -s "$COMPUTE_LIMITS_CACHE" ]]; then
            touch "$_ltmp/compute_ad.done"; ((_fetch_precomplete++))
        fi
        if is_cache_fresh "$COMPUTE_LIMITS_REGION_CACHE" 2>/dev/null && [[ -s "$COMPUTE_LIMITS_REGION_CACHE" ]]; then
            touch "$_ltmp/compute_rg.done"; ((_fetch_precomplete++))
        fi
        
        # Other services (dynamic cache paths)
        for _def in "${_QV_SERVICES[@]}"; do
            local _svc="${_def%%|*}"
            ((_fetch_total+=2))
            if is_cache_fresh "${CACHE_DIR}/limits_${_svc}_ad.json" 2>/dev/null && [[ -s "${CACHE_DIR}/limits_${_svc}_ad.json" ]]; then
                touch "$_ltmp/${_svc}_ad.done"; ((_fetch_precomplete++))
            fi
            if is_cache_fresh "${CACHE_DIR}/limits_${_svc}_region.json" 2>/dev/null && [[ -s "${CACHE_DIR}/limits_${_svc}_region.json" ]]; then
                touch "$_ltmp/${_svc}_region.done"; ((_fetch_precomplete++))
            fi
        done
        
        _step_init
        local _to_fetch=$(( (_fetch_total - _fetch_precomplete) / 2 ))
        if [[ $_fetch_precomplete -eq $_fetch_total ]]; then
            _step_active "service limits"
        else
            _step_progress_start "service limits (${_to_fetch} svc to fetch)" "$_ltmp" "*.done" "$_fetch_total"
        fi
        
        # Parallel fetch uncached (max 15 concurrent subshells)
        # Track PIDs explicitly — bare 'wait' would block on animation subshell
        local -a _fetch_pids=()
        local _running=0
        # Compute
        if [[ ! -f "$_ltmp/compute_ad.done" ]]; then
            (oci limits value list --service-name compute --compartment-id "$tenancy_id" \
                --region "$region" --scope-type AD --all --output json > "$_ltmp/compute_ad.json" 2>/dev/null
             touch "$_ltmp/compute_ad.done") &
            _fetch_pids+=($!); ((_running++))
        fi
        if [[ ! -f "$_ltmp/compute_rg.done" ]]; then
            (oci limits value list --service-name compute --compartment-id "$tenancy_id" \
                --region "$region" --scope-type REGION --all --output json > "$_ltmp/compute_rg.json" 2>/dev/null
             touch "$_ltmp/compute_rg.done") &
            _fetch_pids+=($!); ((_running++))
        fi
        # Other services
        for _def in "${_QV_SERVICES[@]}"; do
            local _svc="${_def%%|*}"
            if [[ ! -f "$_ltmp/${_svc}_ad.done" ]]; then
                (oci limits value list --service-name "$_svc" --compartment-id "$tenancy_id" \
                    --region "$region" --scope-type AD --all --output json > "$_ltmp/${_svc}_ad.json" 2>/dev/null
                 touch "$_ltmp/${_svc}_ad.done") &
                _fetch_pids+=($!); ((_running++))
                [[ $_running -ge 15 ]] && { wait -n 2>/dev/null || wait; ((_running--)); }
            fi
            if [[ ! -f "$_ltmp/${_svc}_region.done" ]]; then
                (oci limits value list --service-name "$_svc" --compartment-id "$tenancy_id" \
                    --region "$region" --scope-type REGION --all --output json > "$_ltmp/${_svc}_region.json" 2>/dev/null
                 touch "$_ltmp/${_svc}_region.done") &
                _fetch_pids+=($!); ((_running++))
                [[ $_running -ge 15 ]] && { wait -n 2>/dev/null || wait; ((_running--)); }
            fi
        done
        # Wait only on fetch PIDs (not the animation subshell)
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        
        # Load compute into vars and cache
        local limits_json="" region_limits_json=""
        if is_cache_fresh "$COMPUTE_LIMITS_CACHE" 2>/dev/null && [[ -s "$COMPUTE_LIMITS_CACHE" ]]; then
            limits_json=$(cat "$COMPUTE_LIMITS_CACHE")
        elif [[ -f "$_ltmp/compute_ad.json" ]]; then
            limits_json=$(cat "$_ltmp/compute_ad.json")
            if [[ -n "$limits_json" ]] && jq -e '.data' <<< "$limits_json" >/dev/null 2>&1; then
                echo "$limits_json" | _cache_write "$COMPUTE_LIMITS_CACHE"
            else limits_json='{"data":[]}'; fi
        else limits_json='{"data":[]}'; fi
        
        if is_cache_fresh "$COMPUTE_LIMITS_REGION_CACHE" 2>/dev/null && [[ -s "$COMPUTE_LIMITS_REGION_CACHE" ]]; then
            region_limits_json=$(cat "$COMPUTE_LIMITS_REGION_CACHE")
        elif [[ -f "$_ltmp/compute_rg.json" ]]; then
            region_limits_json=$(cat "$_ltmp/compute_rg.json")
            if [[ -n "$region_limits_json" ]] && jq -e '.data' <<< "$region_limits_json" >/dev/null 2>&1; then
                echo "$region_limits_json" | _cache_write "$COMPUTE_LIMITS_REGION_CACHE"
            else region_limits_json='{"data":[]}'; fi
        else region_limits_json='{"data":[]}'; fi
        
        # Write other services to cache — only cache valid non-error responses
        for _def in "${_QV_SERVICES[@]}"; do
            local _svc="${_def%%|*}"
            for _scope_tag in ad region; do
                local _cf="${CACHE_DIR}/limits_${_svc}_${_scope_tag}.json"
                [[ -f "$_ltmp/${_svc}_${_scope_tag}.json" ]] || continue
                is_cache_fresh "$_cf" 2>/dev/null && [[ -s "$_cf" ]] && continue
                local _j; _j=$(cat "$_ltmp/${_svc}_${_scope_tag}.json" 2>/dev/null)
                if [[ -n "$_j" ]] && jq -e '.data' <<< "$_j" >/dev/null 2>&1; then
                    echo "$_j" > "$_cf"
                fi
                # Skip caching errors/empty — next entry will re-fetch
            done
        done
        rm -rf "$_ltmp"
        
        _step_complete "$(( _fetch_total / 2 )) services"
        _step_finish
        echo ""
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 2: Compute 4-column display (existing logic)
        # ══════════════════════════════════════════════════════════════════════
        
        # LIMIT_IDX_MAP format: "svc|scope|name" for multi-service drill-down
        declare -A LIMIT_IDX_MAP=()
        local lidx=0
        local -a resv_names=()
        
        # Helper: max value across ADs for a limit in a JSON blob
        _qv_max_value() {
            local _ln="$1" _json="$2" _max=0
            while read -r _v; do
                [[ -z "$_v" || "$_v" == "null" ]] && continue
                [[ "$_v" -gt "$_max" ]] 2>/dev/null && _max="$_v"
            done < <(jq -r --arg n "$_ln" '[.data[] | select(.name == $n)] | .[].value // 0' <<< "$_json" 2>/dev/null)
            echo "$_max"
        }
        
        # Helper: test if a limit name is reserved/reservable
        _qv_is_resv() {
            [[ "$1" == *-reserved-count || "$1" == *-reserved || "$1" == *-reservable || "$1" == *-count-reservable ]]
        }
        
        # Categorize compute limits
        local -a _c_vm=() _c_bh=() _c_vg=() _c_bg=()
        
        while read -r _ln; do
            [[ -z "$_ln" || "$_ln" == "null" || ${#_ln} -lt 2 ]] && continue
            if _qv_is_resv "$_ln"; then resv_names+=("compute|$_ln"); continue; fi
            case $(_shape_category "$_ln") in
                vm)      _c_vm+=("$_ln") ;;
                bm_hpc)  _c_bh+=("$_ln") ;;
                vm_gpu)  _c_vg+=("$_ln") ;;
                bm_gpu)  _c_bg+=("$_ln") ;;
            esac
        done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$limits_json" 2>/dev/null)
        
        # Dedup region limits vs AD
        declare -A _AD_NAME_SET=()
        for _ln in "${_c_vm[@]}" "${_c_bh[@]}" "${_c_vg[@]}" "${_c_bg[@]}"; do _AD_NAME_SET["$_ln"]=1; done
        for _ln in "${resv_names[@]}"; do _AD_NAME_SET["${_ln#compute|}"]=1; done
        local -a _c_region=()
        while read -r _ln; do
            [[ -z "$_ln" || "$_ln" == "null" || ${#_ln} -lt 2 ]] && continue
            [[ -n "${_AD_NAME_SET[$_ln]+x}" ]] && continue
            if _qv_is_resv "$_ln"; then resv_names+=("compute|$_ln"); continue; fi
            _c_region+=("$_ln")
        done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$region_limits_json" 2>/dev/null)
        
        # Build numbered entries (only if compute section enabled)
        local -a _4c_vm=() _4c_bh=() _4c_vg=() _4c_bg=() _4c_rg=()
        if [[ "${_QV_SECTION[compute]}" == "on" ]]; then
            for _ln in "${_c_vm[@]}"; do
                local _mv; _mv=$(_qv_max_value "$_ln" "$limits_json")
                [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                ((lidx++)); LIMIT_IDX_MAP[$lidx]="compute|AD|$_ln"
                _4c_vm+=("${lidx}|${_ln}|${_mv}")
            done
            for _ln in "${_c_bh[@]}"; do
                local _mv; _mv=$(_qv_max_value "$_ln" "$limits_json")
                [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                ((lidx++)); LIMIT_IDX_MAP[$lidx]="compute|AD|$_ln"
                _4c_bh+=("${lidx}|${_ln}|${_mv}")
            done
            for _ln in "${_c_vg[@]}"; do
                local _mv; _mv=$(_qv_max_value "$_ln" "$limits_json")
                [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                ((lidx++)); LIMIT_IDX_MAP[$lidx]="compute|AD|$_ln"
                _4c_vg+=("${lidx}|${_ln}|${_mv}")
            done
            for _ln in "${_c_bg[@]}"; do
                local _mv; _mv=$(_qv_max_value "$_ln" "$limits_json")
                [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                ((lidx++)); LIMIT_IDX_MAP[$lidx]="compute|AD|$_ln"
                _4c_bg+=("${lidx}|${_ln}|${_mv}")
            done
            for _ln in "${_c_region[@]}"; do
                local _mv; _mv=$(jq -r --arg n "$_ln" '[.data[] | select(.name == $n)] | .[0].value // 0' <<< "$region_limits_json" 2>/dev/null)
                [[ -z "$_mv" || "$_mv" == "null" ]] && _mv=0
                [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                ((lidx++)); LIMIT_IDX_MAP[$lidx]="compute|REGION|$_ln"
                _4c_rg+=("${lidx}|${_ln}|${_mv}")
            done
        fi
        
        echo -e "  ${BOLD}${WHITE}── Compute ──${NC}"
        if [[ "${_QV_SECTION[compute]}" == "on" ]]; then
            echo ""
            _ui_4col_render valued _4c_vm _4c_bh _4c_vg _4c_bg
            
            # Region-scoped compute limits
            if [[ ${#_4c_rg[@]} -gt 0 ]]; then
                echo ""
                echo -e "    ${GRAY}Region-Scoped (${#_4c_rg[@]})${NC}"
                printf "    ${GRAY}%3s  %-42s %18s${NC}\n" "#" "LIMIT NAME" "LIMIT"
                for _entry in "${_4c_rg[@]}"; do
                    local _idx="${_entry%%|*}" _rest="${_entry#*|}"
                    local _name="${_rest%%|*}" _val="${_rest##*|}"
                    _name=$(_qv_trunc "$_name" 42)
                    local _vtxt; _vtxt=$(_qv_fmt_val "$_val" "r")
                    if [[ "$_val" == "0" ]]; then
                        printf "    ${GRAY}%3s) %-42s %18s${NC}\n" "$_idx" "$_name" "[0]"
                    else
                        printf "    ${YELLOW}%3s${WHITE})${NC} ${WHITE}%-42s${NC} ${GRAY}%18s${NC}\n" "$_idx" "$_name" "$_vtxt"
                    fi
                done
            fi
        else
            echo -e "    ${GRAY}(disabled — toggle with 's')${NC}"
        fi
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 3: Other service groups
        # ══════════════════════════════════════════════════════════════════════
        for _grp in "${_QV_GROUPS[@]}"; do
            local _grp_printed=false
            
            for _def in "${_QV_SERVICES[@]}"; do
                local _svc="${_def%%|*}" _g _dname
                IFS='|' read -r _ _g _dname <<< "$_def"
                [[ "$_g" != "$_grp" ]] && continue
                
                # Per-service toggle check
                if [[ "${_QV_SECTION[$_svc]}" != "on" ]]; then
                    # Still show group header if first service
                    if [[ "$_grp_printed" == "false" ]]; then
                        echo ""
                        echo -e "  ${BOLD}${WHITE}── ${_grp} ──${NC}"
                        _grp_printed=true
                    fi
                    echo -e "    ${GRAY}${_dname} (disabled)${NC}"
                    continue
                fi
                
                # Read cache files
                local _ad_json="" _rg_json=""
                local _ac="${CACHE_DIR}/limits_${_svc}_ad.json"
                local _rc="${CACHE_DIR}/limits_${_svc}_region.json"
                [[ -s "$_ac" ]] && _ad_json=$(cat "$_ac")
                [[ -s "$_rc" ]] && _rg_json=$(cat "$_rc")
                [[ -z "$_ad_json" ]] && _ad_json='{"data":[]}'
                [[ -z "$_rg_json" ]] && _rg_json='{"data":[]}'
                
                # Extract AD limit names
                local -a _s_ad_names=()
                while read -r _ln; do
                    [[ -z "$_ln" || "$_ln" == "null" || ${#_ln} -lt 2 ]] && continue
                    if _qv_is_resv "$_ln"; then resv_names+=("${_svc}|${_ln}"); continue; fi
                    _s_ad_names+=("$_ln")
                done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$_ad_json" 2>/dev/null)
                
                # Region-only names (dedup)
                declare -A _s_ad_set=()
                for _ln in "${_s_ad_names[@]}"; do _s_ad_set["$_ln"]=1; done
                local -a _s_rg_names=()
                while read -r _ln; do
                    [[ -z "$_ln" || "$_ln" == "null" || ${#_ln} -lt 2 ]] && continue
                    [[ -n "${_s_ad_set[$_ln]+x}" ]] && continue
                    if _qv_is_resv "$_ln"; then resv_names+=("${_svc}|${_ln}"); continue; fi
                    _s_rg_names+=("$_ln")
                done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$_rg_json" 2>/dev/null)
                
                # Count displayable limits
                local _svc_ct=0
                
                for _ln in "${_s_ad_names[@]}"; do
                    local _mv; _mv=$(_qv_max_value "$_ln" "$_ad_json")
                    [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                    ((_svc_ct++))
                done
                for _ln in "${_s_rg_names[@]}"; do
                    local _mv; _mv=$(jq -r --arg n "$_ln" '[.data[] | select(.name == $n)] | .[0].value // 0' <<< "$_rg_json" 2>/dev/null)
                    [[ -z "$_mv" || "$_mv" == "null" ]] && _mv=0
                    [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                    ((_svc_ct++))
                done
                
                [[ $_svc_ct -eq 0 ]] && continue
                
                # Print group header on first service with data
                if [[ "$_grp_printed" == "false" ]]; then
                    echo ""
                    echo -e "  ${BOLD}${WHITE}── ${_grp} ──${NC}"
                    _grp_printed=true
                fi
                
                echo -e "    ${BOLD}${CYAN}${_dname}${NC} ${GRAY}(${_svc} · ${_svc_ct})${NC}"
                printf "    ${GRAY}%5s  %-38s %18s %5s  %-38s %18s${NC}\n" \
                    "#" "LIMIT NAME" "LIMIT" "#" "LIMIT NAME" "LIMIT"

                # Build entries: idx|name|value[|R]
                local -a _s_entries=()
                for _ln in "${_s_ad_names[@]}"; do
                    local _mv; _mv=$(_qv_max_value "$_ln" "$_ad_json")
                    [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                    ((lidx++)); LIMIT_IDX_MAP[$lidx]="${_svc}|AD|${_ln}"
                    _s_entries+=("${lidx}|${_ln}|${_mv}")
                done
                for _ln in "${_s_rg_names[@]}"; do
                    local _mv; _mv=$(jq -r --arg n "$_ln" '[.data[] | select(.name == $n)] | .[0].value // 0' <<< "$_rg_json" 2>/dev/null)
                    [[ -z "$_mv" || "$_mv" == "null" ]] && _mv=0
                    [[ "$_mv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                    ((lidx++)); LIMIT_IDX_MAP[$lidx]="${_svc}|REGION|${_ln}"
                    _s_entries+=("${lidx}|${_ln}|${_mv}|R")
                done
                
                # 2-across rendering: fixed-width columns
                # Each half: 4-indent + 5-idx + 2-sep + 38-name + 18-value = 67
                local _ect=${#_s_entries[@]}
                local _ei=0
                while [[ $_ei -lt $_ect ]]; do
                    local _e1="${_s_entries[$_ei]}" _e2="${_s_entries[$((_ei+1))]:-}"
                    
                    # Parse entry: idx|name|value[|R]
                    local _i1="${_e1%%|*}" _r1="${_e1#*|}" _n1="${_r1%%|*}"
                    _n1=$(_qv_trunc "$_n1" 38)
                    local _r1b="${_r1#*|}"; local _v1="${_r1b%%|*}" _t1="${_r1b#*|}"
                    [[ "$_t1" == "$_v1" ]] && _t1=""    # no trailing tag
                    local _vt1; _vt1=$(_qv_fmt_val "$_v1" "${_t1:+r}")
                    
                    if [[ "$_v1" == "0" ]]; then
                        printf "    ${GRAY}%5s) %-38s %18s${NC}" "$_i1" "$_n1" "[0]"
                    else
                        printf "    ${YELLOW}%5s${WHITE})${NC} ${WHITE}%-38s${NC} ${GRAY}%18s${NC}" "$_i1" "$_n1" "$_vt1"
                    fi
                    
                    if [[ -n "$_e2" ]]; then
                        local _i2="${_e2%%|*}" _r2="${_e2#*|}" _n2="${_r2%%|*}"
                        _n2=$(_qv_trunc "$_n2" 38)
                        local _r2b="${_r2#*|}"; local _v2="${_r2b%%|*}" _t2="${_r2b#*|}"
                        [[ "$_t2" == "$_v2" ]] && _t2=""
                        local _vt2; _vt2=$(_qv_fmt_val "$_v2" "${_t2:+r}")
                        
                        if [[ "$_v2" == "0" ]]; then
                            printf " ${GRAY}%5s) %-38s %18s${NC}" "$_i2" "$_n2" "[0]"
                        else
                            printf " ${YELLOW}%5s${WHITE})${NC} ${WHITE}%-38s${NC} ${GRAY}%18s${NC}" "$_i2" "$_n2" "$_vt2"
                        fi
                    fi
                    echo ""
                    ((_ei+=2))
                done
            done
        done
        
        # ══════════════════════════════════════════════════════════════════════
        # Phase 4: Actions
        # ══════════════════════════════════════════════════════════════════════
        echo ""
        local _resv_ct=${#resv_names[@]}
        # Count disabled services
        local _disabled_ct=0
        [[ "${_QV_SECTION[compute]}" != "on" ]] && ((_disabled_ct++))
        for _def in "${_QV_SERVICES[@]}"; do
            [[ "${_QV_SECTION[${_def%%|*}]}" != "on" ]] && ((_disabled_ct++))
        done
        
        local _status_extra=""
        [[ $_disabled_ct -gt 0 ]] && _status_extra=" │ ${_disabled_ct} services hidden (s to toggle)"
        echo -e "  ${GRAY}Showing ${lidx} limits across $(( ${#_QV_SERVICES[@]} + 1 )) services │ ${_resv_ct} reserved/reservable hidden${_status_extra}${NC}"
        echo ""
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}#${NC}${WHITE})${NC}      Select limit → check availability (used/available per AD)"
        echo -e "  ${CYAN}/${NC}${WHITE})${NC}      Search limits by name"
        echo -e "  ${GREEN}s${NC}${WHITE})${NC}      Toggle sections (show/hide service groups)"
        echo -e "  ${GREEN}c${NC}${WHITE})${NC}      Capacity reservation limits (reserved/reservable)"
        if [[ "$_show_zero_limits" == "false" ]]; then
            echo -e "  ${GREEN}z${NC}${WHITE})${NC}      Show all limits (including zero)"
        else
            echo -e "  ${GREEN}z${NC}${WHITE})${NC}      Hide zero-value limits"
        fi
        echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh (clear cache)"
        echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
        echo ""
        _ui_prompt "Service Limits" "#, /, s, c, z, env [c|r], r, b"
        
        local selection
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        case "$selection" in
            [0-9]|[0-9][0-9]|[0-9][0-9][0-9]|[0-9][0-9][0-9][0-9])
                local sel_entry="${LIMIT_IDX_MAP[$selection]:-}"
                if [[ -n "$sel_entry" ]]; then
                    # Parse "svc|scope|name"
                    local _svc="${sel_entry%%|*}"
                    local _rest="${sel_entry#*|}"
                    local _scope="${_rest%%|*}"
                    local _lname="${_rest#*|}"
                    _limits_availability_detail "$_svc" "$_lname" "$tenancy_id" "$compartment_id" "$_scope"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            c|C)
                # Capacity reservation limits (reserved/reservable) across all services
                echo ""
                _ui_subheader "Capacity Reservation Limits (reserved / reservable)" 0
                echo ""
                if [[ ${#resv_names[@]} -eq 0 ]]; then
                    echo -e "  ${GRAY}No reserved/reservable limits found${NC}"
                else
                    declare -A _RESV_IDX_MAP=()
                    local _ridx=0
                    local _prev_svc=""
                    for _rentry in $(printf '%s\n' "${resv_names[@]}" | sort); do
                        local _rsvc="${_rentry%%|*}" _rln="${_rentry#*|}"
                        
                        # Get value from appropriate cache
                        local _rmv=0
                        if [[ "$_rsvc" == "compute" ]]; then
                            _rmv=$(_qv_max_value "$_rln" "$limits_json")
                        else
                            local _rac="${CACHE_DIR}/limits_${_rsvc}_ad.json"
                            [[ -s "$_rac" ]] && _rmv=$(_qv_max_value "$_rln" "$(cat "$_rac")")
                        fi
                        [[ "$_rmv" == "0" && "$_show_zero_limits" == "false" ]] && continue
                        ((_ridx++)); _RESV_IDX_MAP[$_ridx]="${_rsvc}|AD|${_rln}"
                        
                        # Service header on change
                        if [[ "$_rsvc" != "$_prev_svc" ]]; then
                            [[ -n "$_prev_svc" ]] && echo ""
                            echo -e "    ${BOLD}${CYAN}${_rsvc}${NC}"
                            _prev_svc="$_rsvc"
                        fi
                        
                        local _fmv; printf -v _fmv "%'d" "$_rmv" 2>/dev/null || _fmv="$_rmv"
                        local _rln_d; _rln_d=$(_qv_trunc "$_rln" 48)
                        if [[ "$_rmv" == "0" ]]; then
                            printf "    ${GRAY}%3s) %-48s [0]${NC}\n" "$_ridx" "$_rln_d"
                        else
                            printf "    ${YELLOW}%3s${WHITE})${NC} ${WHITE}%-48s${NC} ${GRAY}[%s]${NC}\n" "$_ridx" "$_rln_d" "$_fmv"
                        fi
                    done
                    echo ""
                    echo -e "  ${GRAY}${_ridx} capacity reservation limits${NC}"
                    echo ""
                    echo -e "  ${YELLOW}#${NC}${WHITE})${NC}      Select → check availability    ${CYAN}Enter${NC}${WHITE})${NC} Return"
                    echo ""
                    echo -n -e "  ${CYAN}Select: ${NC}"
                    local _rsel
                    read -r _rsel
                    if [[ "$_rsel" =~ ^[0-9]+$ ]] && [[ -n "${_RESV_IDX_MAP[$_rsel]:-}" ]]; then
                        local _re="${_RESV_IDX_MAP[$_rsel]}"
                        local _rs="${_re%%|*}" _rr="${_re#*|}"
                        local _rsc="${_rr%%|*}" _rn="${_rr#*|}"
                        _limits_availability_detail "$_rs" "$_rn" "$tenancy_id" "$compartment_id" "$_rsc"
                    fi
                fi
                ;;
            z|Z)
                [[ "$_show_zero_limits" == "false" ]] && _show_zero_limits=true || _show_zero_limits=false
                ;;
            s|S)
                # Toggle individual services on/off
                echo ""
                echo -e "  ${BOLD}${WHITE}Toggle Service Sections${NC}"
                echo ""
                
                # Build ordered list: compute first, then by group
                local -a _all_svc_keys=("compute")
                local -a _all_svc_names=("Compute (shapes)")
                local -a _all_svc_grps=("Compute")
                for _def in "${_QV_SERVICES[@]}"; do
                    local _sk="${_def%%|*}" _sg _sd
                    IFS='|' read -r _ _sg _sd <<< "$_def"
                    _all_svc_keys+=("$_sk")
                    _all_svc_names+=("$_sd")
                    _all_svc_grps+=("$_sg")
                done
                
                # Display numbered list grouped by category
                local _tidx=0 _prev_grp=""
                for _si in "${!_all_svc_keys[@]}"; do
                    local _sk="${_all_svc_keys[$_si]}" _sn="${_all_svc_names[$_si]}" _sg="${_all_svc_grps[$_si]}"
                    # Group header on change
                    if [[ "$_sg" != "$_prev_grp" ]]; then
                        [[ -n "$_prev_grp" ]] && echo ""
                        echo -e "    ${BOLD}${WHITE}${_sg}${NC}"
                        _prev_grp="$_sg"
                    fi
                    ((_tidx++))
                    local _state="${_QV_SECTION[$_sk]}"
                    if [[ "$_state" == "on" ]]; then
                        printf "    ${YELLOW}%2s${WHITE})${NC} ${GREEN}%-4s${NC} ${WHITE}%s${NC}\n" "$_tidx" " ON" "$_sn"
                    else
                        printf "    ${YELLOW}%2s${WHITE})${NC} ${RED}%-4s${NC} ${GRAY}%s${NC}\n" "$_tidx" "OFF" "$_sn"
                    fi
                done
                
                local _total_svc=$_tidx
                echo ""
                echo -e "  ${WHITE}Enable:${NC}  ${CYAN}e ${GRAY}1${NC} │ ${CYAN}e ${GRAY}1,3,5${NC} │ ${CYAN}e ${GRAY}1-5${NC} │ ${CYAN}e ${GRAY}all${NC}"
                echo -e "  ${WHITE}Disable:${NC} ${CYAN}d ${GRAY}1${NC} │ ${CYAN}d ${GRAY}1,3,5${NC} │ ${CYAN}d ${GRAY}1-5${NC} │ ${CYAN}d ${GRAY}all${NC}"
                echo -e "  ${WHITE}Toggle:${NC}  ${CYAN}1${NC} │ ${CYAN}1,3,5${NC} │ ${CYAN}1-5${NC}          ${GRAY}Enter) Return${NC}"
                echo ""
                echo -n -e "  ${CYAN}Select: ${NC}"
                local _tsel
                read -r _tsel
                [[ -z "$_tsel" ]] && continue
                
                # Parse action prefix: e/d or toggle
                local _taction="toggle" _tnums="$_tsel"
                case "$_tsel" in
                    e\ *|E\ *) _taction="on";  _tnums="${_tsel#* }" ;;
                    d\ *|D\ *) _taction="off"; _tnums="${_tsel#* }" ;;
                esac
                
                # Parse number spec using shared helper
                if ! _parse_targets "" "$_tnums" "$_total_svc"; then
                    continue
                fi
                
                # Apply action to selected indices
                for _ti in "${_SEL_INDICES[@]}"; do
                    local _tsk="${_all_svc_keys[$((_ti-1))]}"
                    [[ -z "$_tsk" ]] && continue
                    case "$_taction" in
                        on)     _QV_SECTION["$_tsk"]="on" ;;
                        off)    _QV_SECTION["$_tsk"]="off" ;;
                        toggle) [[ "${_QV_SECTION[$_tsk]}" == "on" ]] && _QV_SECTION["$_tsk"]="off" || _QV_SECTION["$_tsk"]="on" ;;
                    esac
                done
                ;;
            /*)
                _limits_search_in_map LIMIT_IDX_MAP "all" "$tenancy_id" "$compartment_id" "${selection#/}" "multi"
                ;;
            r|R)
                rm -f "$COMPUTE_LIMITS_CACHE" "$COMPUTE_LIMITS_REGION_CACHE"
                rm -f "${CACHE_DIR}"/limits_*_ad.json "${CACHE_DIR}"/limits_*_region.json
                continue
                ;;
            env*|ENV*)
                _env_dispatch "$selection"
                rm -f "$COMPUTE_LIMITS_CACHE" "$COMPUTE_LIMITS_REGION_CACHE"
                rm -f "${CACHE_DIR}"/limits_*_ad.json "${CACHE_DIR}"/limits_*_region.json
                continue
                ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) echo -e "${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Browse by Service - Fixed 2-column alignment
#--------------------------------------------------------------------------------
_limits_browse_services() {
    local tenancy_id="$1" compartment_id="$2" region="$3"
    
    while true; do
        echo ""
        _ui_menu_header "BROWSE SERVICE LIMITS" \
            --breadcrumb "Operations" "Service Limits" "By Service" \
            --cmd "oci limits service list --compartment-id \$TENANCY_ID --all" \
            --env \
            --cache \
            "${LIMITS_SERVICE_CACHE}|Services"
        
        # Fetch services (cache-first)
        local services_json _svc_cached=""
        _step_init
        _step_active "services"
        if is_cache_fresh "$LIMITS_SERVICE_CACHE" 2>/dev/null && [[ -s "$LIMITS_SERVICE_CACHE" ]]; then
            services_json=$(cat "$LIMITS_SERVICE_CACHE")
            _svc_cached=" cached"
        else
            services_json=$(oci limits service list \
                --compartment-id "$tenancy_id" \
                --region "$region" \
                --all --output json 2>/dev/null)
            [[ -z "$services_json" ]] && services_json='{"data":[]}'
            if jq -e '.data' <<< "$services_json" >/dev/null 2>&1; then
                echo "$services_json" | _cache_write "$LIMITS_SERVICE_CACHE"
            fi
        fi

        local svc_count=0
        svc_count=$(jq '.data | length' <<< "$services_json" 2>/dev/null) || svc_count=0
        _step_complete "services(${svc_count}${_svc_cached})"
        _step_finish
        echo ""
        
        if [[ $svc_count -eq 0 ]]; then
            echo -e "  ${GRAY}No services found${NC}"
            _ui_pause "return"
            return
        fi
        
        # Build service arrays (no ANSI in arrays — apply color in printf)
        declare -A SVC_MAP=()
        local sidx=0
        local -a svc_names=() svc_descs=()
        while IFS='|' read -r svc_name svc_desc; do
            [[ -z "$svc_name" ]] && continue
            ((sidx++))
            SVC_MAP[$sidx]="$svc_name"
            svc_names+=("$svc_name")
            svc_descs+=("${svc_desc:0:35}")
        done < <(jq -r '.data | sort_by(.name)[] | "\(.name)|\(.description // "")"' <<< "$services_json" 2>/dev/null)
        
        # 2-column display with fixed-width alignment
        local total=${#svc_names[@]}
        local half=$(( (total + 1) / 2 ))
        
        printf "  ${BOLD}${CYAN}%-4s %-28s %-36s  %-4s %-28s %-36s${NC}\n" \
            "#" "Service" "Description" "#" "Service" "Description"
        echo -e "  ${GRAY}$(printf '─%.0s' {1..140})${NC}"
        
        for (( i=0; i<half; i++ )); do
            local li=$(( i + 1 ))
            local ri=$(( i + half + 1 ))
            
            printf "  ${YELLOW}%-4s${NC} ${WHITE}%-28s${NC} ${GRAY}%-36s${NC}" \
                "${li})" "${svc_names[$i]:0:27}" "${svc_descs[$i]:0:35}"
            
            if [[ $ri -le $total ]]; then
                printf "  ${YELLOW}%-4s${NC} ${WHITE}%-28s${NC} ${GRAY}%-36s${NC}" \
                    "${ri})" "${svc_names[$((ri-1))]:0:27}" "${svc_descs[$((ri-1))]:0:35}"
            fi
            printf "\n"
        done
        
        echo ""
        echo -e "  ${GRAY}Tip: Common services: compute, vcn, block-storage, load-balancer, object-storage${NC}"
        echo ""
        echo -n -e "  ${CYAN}Enter #, service name, /search, or b [back]: ${NC}"
        
        local svc_choice
        read -r svc_choice
        
        [[ -z "$svc_choice" || "$svc_choice" == "b" || "$svc_choice" == "B" ]] && return
        [[ "$svc_choice" == "show" || "$svc_choice" == "SHOW" ]] && continue
        
        # / search → global cross-service limit search
        if [[ "$svc_choice" == /* ]]; then
            _limits_search_global "$tenancy_id" "$compartment_id" "${svc_choice#/}"
            continue
        fi
        
        local selected_service=""
        if [[ "$svc_choice" =~ ^[0-9]+$ ]]; then
            selected_service="${SVC_MAP[$svc_choice]:-}"
        else
            for _si in "${!SVC_MAP[@]}"; do
                [[ "${SVC_MAP[$_si]}" == "$svc_choice" ]] && { selected_service="$svc_choice"; break; }
            done
        fi
        
        if [[ -n "$selected_service" ]]; then
            _limits_service_detail "$selected_service" "$tenancy_id" "$compartment_id" "$region"
        else
            echo -e "${RED}Invalid selection${NC}"
            sleep 1
        fi
    done
}

#--------------------------------------------------------------------------------
# Service Detail - Parallel fetch, zero-safe availability
#--------------------------------------------------------------------------------
_limits_service_detail() {
    local service_name="$1" tenancy_id="$2" compartment_id="$3" region="${4:-${FOCUS_REGION:-$REGION}}"
    local show_zero=false
    
    while true; do
        echo ""
        _ui_menu_header "LIMITS: ${service_name^^}" \
            --breadcrumb "Operations" "Service Limits" "$service_name" \
            --cmd "oci limits value list --service-name ${service_name} --compartment-id \$TENANCY_ID --scope-type AD --all | oci limits value list --service-name ${service_name} --compartment-id \$TENANCY_ID --scope-type REGION --all" \
            --env
        
        _step_init
        
        # Parallel fetch AD + region with progress bar
        local _ltmp
        _ltmp=$(mktemp -d "${TEMP_DIR}/lim_svc.XXXXXX")
        _step_progress_start "${service_name} limits" "$_ltmp" "*.done" 2
        local -a _fetch_pids=()
        (oci limits value list --service-name "$service_name" --compartment-id "$tenancy_id" \
            --region "$region" --scope-type "AD" --all --output json > "$_ltmp/ad.json" 2>/dev/null
         touch "$_ltmp/ad.done") &
        _fetch_pids+=($!)
        (oci limits value list --service-name "$service_name" --compartment-id "$tenancy_id" \
            --region "$region" --scope-type "REGION" --all --output json > "$_ltmp/region.json" 2>/dev/null
         touch "$_ltmp/region.done") &
        _fetch_pids+=($!)
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        
        local ad_limits_json region_limits_json
        ad_limits_json=$(cat "$_ltmp/ad.json" 2>/dev/null)
        region_limits_json=$(cat "$_ltmp/region.json" 2>/dev/null)
        rm -rf "$_ltmp"
        _step_complete "${service_name} limits(AD + Region)"
        _step_finish
        
        # Normalize empty/invalid to safe JSON
        if [[ -z "$ad_limits_json" ]] || ! jq -e '.data' <<< "$ad_limits_json" >/dev/null 2>&1; then
            ad_limits_json='{"data":[]}'
        fi
        if [[ -z "$region_limits_json" ]] || ! jq -e '.data' <<< "$region_limits_json" >/dev/null 2>&1; then
            region_limits_json='{"data":[]}'
        fi
        
        # Get ADs
        local -a ad_list=()
        while read -r _ad; do
            [[ -n "$_ad" && "$_ad" != "null" ]] && ad_list+=("$_ad")
        done < <(jq -r '[.data[].["availability-domain"] // empty] | unique | sort[]' <<< "$ad_limits_json" 2>/dev/null)
        local ad_count=${#ad_list[@]}
        
        local -a ad_limit_names=()
        while read -r _ln; do
            [[ -n "$_ln" ]] && ad_limit_names+=("$_ln")
        done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$ad_limits_json" 2>/dev/null)
        
        local -a region_limit_names=()
        # Build AD name set for deduplication (AD scope takes priority)
        declare -A _AD_NAMES_SVC=()
        for _ln in "${ad_limit_names[@]}"; do _AD_NAMES_SVC["$_ln"]=1; done
        while read -r _ln; do
            [[ -n "$_ln" ]] || continue
            [[ -n "${_AD_NAMES_SVC[$_ln]+x}" ]] && continue
            region_limit_names+=("$_ln")
        done < <(jq -r '[.data[].name] | unique | sort[]' <<< "$region_limits_json" 2>/dev/null)
        
        echo ""
        
        local -a ad_short=()
        for _ad in "${ad_list[@]}"; do
            ad_short+=("$(echo "$_ad" | sed 's/.*://')")
        done
        
        declare -A LIMIT_IDX_MAP=()
        local lidx=0
        
        # ── Region-scoped limits ──
        if [[ ${#region_limit_names[@]} -gt 0 ]]; then
            echo -e "  ${BOLD}${MAGENTA}Region-Scoped Limits${NC}"
            printf "  ${BOLD}${CYAN}%-4s %-50s %15s${NC}\n" "#" "Limit Name" "Value"
            echo -e "  ${GRAY}$(printf '─%.0s' {1..72})${NC}"
            
            for _ln in "${region_limit_names[@]}"; do
                local _val
                _val=$(jq -r --arg name "$_ln" \
                    '[.data[] | select(.name == $name)] | .[0].value // 0' \
                    <<< "$region_limits_json" 2>/dev/null)
                [[ -z "$_val" || "$_val" == "null" ]] && _val=0
                
                [[ "$_val" == "0" && "$show_zero" == "false" ]] && continue
                
                ((lidx++))
                LIMIT_IDX_MAP[$lidx]="REGION|$_ln"
                
                local _fval
                _fval=$(printf "%'d" "$_val" 2>/dev/null || echo "$_val")
                
                if [[ "$_val" == "0" ]]; then
                    printf "  ${GRAY}%-4s %-50s %15s${NC}\n" "$lidx" "$_ln" "0"
                else
                    printf "  ${YELLOW}%-4s${NC} ${WHITE}%-50s${NC} ${GREEN}%15s${NC}\n" "$lidx" "$_ln" "$_fval"
                fi
            done
            echo ""
        fi
        
        # ── AD-scoped limits ──
        if [[ ${#ad_limit_names[@]} -gt 0 ]]; then
            echo -e "  ${BOLD}${CYAN}AD-Scoped Limits${NC}"
            
            printf "  ${BOLD}${CYAN}%-4s %-42s" "#" "Limit Name"
            for _ads in "${ad_short[@]}"; do
                printf " %15s" "$_ads"
            done
            printf "${NC}\n"
            
            local _sep="  $(printf '─%.0s' {1..46})"
            for (( _si=0; _si<ad_count; _si++ )); do _sep+="$(printf '─%.0s' {1..16})"; done
            echo -e "${GRAY}${_sep}${NC}"
            
            for _ln in "${ad_limit_names[@]}"; do
                local _all_zero=true
                local -a _ad_vals=()
                for _ad in "${ad_list[@]}"; do
                    local _val
                    _val=$(jq -r --arg name "$_ln" --arg ad "$_ad" \
                        '[.data[] | select(.name == $name and .["availability-domain"] == $ad)] | .[0].value // 0' \
                        <<< "$ad_limits_json" 2>/dev/null)
                    [[ -z "$_val" || "$_val" == "null" ]] && _val=0
                    [[ "$_val" != "0" ]] && _all_zero=false
                    _ad_vals+=("$_val")
                done
                
                [[ "$_all_zero" == "true" && "$show_zero" == "false" ]] && continue
                
                ((lidx++))
                LIMIT_IDX_MAP[$lidx]="AD|$_ln"
                
                local _name_color="$WHITE"
                echo "$_ln" | grep -qi 'gpu' && _name_color="$GREEN"
                echo "$_ln" | grep -qi 'hpc' && _name_color="$CYAN"
                
                if [[ "$_all_zero" == "true" ]]; then
                    printf "  ${GRAY}%-4s %-42s" "$lidx" "$_ln"
                    for _v in "${_ad_vals[@]}"; do printf " %15s" "0"; done
                    printf "${NC}\n"
                else
                    printf "  ${YELLOW}%-4s${NC} ${_name_color}%-42s${NC}" "$lidx" "$_ln"
                    for _v in "${_ad_vals[@]}"; do
                        local _fv
                        _fv=$(printf "%'d" "$_v" 2>/dev/null || echo "$_v")
                        if [[ "$_v" == "0" ]]; then
                            printf " ${GRAY}%15s${NC}" "0"
                        else
                            printf " ${WHITE}%15s${NC}" "$_fv"
                        fi
                    done
                    printf "\n"
                fi
            done
        fi
        
        local _total_shown=$lidx
        local _total_limits=$(( ${#ad_limit_names[@]} + ${#region_limit_names[@]} ))
        
        echo ""
        if [[ "$show_zero" == "false" ]]; then
            echo -e "  ${GRAY}Showing ${_total_shown} of ${_total_limits} limits (non-zero only)${NC}"
        else
            echo -e "  ${GRAY}Showing all ${_total_limits} limits${NC}"
        fi
        
        echo ""
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}#${NC})       Select limit → check availability (used/available)"
        echo -e "  ${CYAN}/${NC})       Search limits by name"
        if [[ "$show_zero" == "false" ]]; then
            echo -e "  ${GREEN}z${NC})       Show all limits (including zero)"
        else
            echo -e "  ${GREEN}z${NC})       Hide zero-value limits"
        fi
        echo -e "  ${MAGENTA}r${NC})       Refresh"
        echo -e "  ${CYAN}b${NC})       Back to service list"
        echo ""
        _ui_prompt "$service_name limits" "#, /, z, r, b"
        
        local action
        read -r action
        [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return
        
        case "$action" in
            [0-9]|[0-9][0-9]|[0-9][0-9][0-9])
                local sel_entry="${LIMIT_IDX_MAP[$action]:-}"
                if [[ -n "$sel_entry" ]]; then
                    local _scope="${sel_entry%%|*}"
                    local _lname="${sel_entry#*|}"
                    _limits_availability_detail "$service_name" "$_lname" "$tenancy_id" "$compartment_id" "$_scope"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            /*)
                _limits_search_in_map LIMIT_IDX_MAP "$service_name" "$tenancy_id" "$compartment_id" "${action#/}"
                ;;
            z|Z)
                [[ "$show_zero" == "false" ]] && show_zero=true || show_zero=false
                ;;
            r|R) continue ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) echo -e "${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Availability Detail - Parallel per-AD fetch, zero-safe
# Usage: _limits_availability_detail <service> <limit> <tenancy> <compartment> <scope>
#   scope = "AD" or "REGION"
#--------------------------------------------------------------------------------
_limits_availability_detail() {
    local service_name="$1" limit_name="$2" tenancy_id="$3" compartment_id="$4"
    local scope="${5:-AD}"
    local region="${FOCUS_REGION:-$REGION}"
    local _avail_detail_json=""
    
    # For AD-scoped limits, discover ADs from cached compute limits or API
    local -a ad_list=()
    if [[ "$scope" == "AD" ]]; then
        if _discover_ads "$tenancy_id"; then
            ad_list=("${_AD_LIST[@]}")
        fi
    fi
    
    # Build command string based on scope
    local _cmd_str=""
    if [[ ${#ad_list[@]} -gt 0 ]]; then
        _cmd_str="oci limits resource-availability get --service-name ${service_name} --limit-name ${limit_name} --compartment-id \$TENANCY_ID --availability-domain <ad> (×${#ad_list[@]} ADs)"
    else
        _cmd_str="oci limits resource-availability get --service-name ${service_name} --limit-name ${limit_name} --compartment-id \$TENANCY_ID"
    fi
    
    echo ""
    _ui_menu_header "RESOURCE AVAILABILITY: ${limit_name}" \
        --breadcrumb "Operations" "Service Limits" "${service_name}" "${limit_name}" \
        --cmd "$_cmd_str" \
        --env
    
    echo -e "  ${CYAN}Service:${NC} ${WHITE}${service_name}${NC}    ${CYAN}Limit:${NC} ${WHITE}${limit_name}${NC}"
    echo ""
    
    if [[ ${#ad_list[@]} -gt 0 ]]; then
        # Parallel fetch availability per AD with progress bar
        local _atmp
        _atmp=$(mktemp -d "${TEMP_DIR}/lim_avail.XXXXXX")
        local _ad_total=${#ad_list[@]}
        
        _step_init
        _step_progress_start "availability" "$_atmp" "*.done" "$_ad_total"
        
        local -a _fetch_pids=()
        for _ad in "${ad_list[@]}"; do
            local _ad_safe
            _ad_safe=$(echo "$_ad" | tr ':' '_')
            (oci limits resource-availability get \
                --service-name "$service_name" \
                --limit-name "$limit_name" \
                --compartment-id "$tenancy_id" \
                --region "$region" \
                --availability-domain "$_ad" \
                --output json > "$_atmp/${_ad_safe}.json" 2>"$_atmp/${_ad_safe}.err"
             touch "$_atmp/${_ad_safe}.done") &
            _fetch_pids+=($!)
        done
        for _pid in "${_fetch_pids[@]}"; do wait "$_pid" 2>/dev/null; done
        _step_complete "availability(${_ad_total} ADs)"
        _step_finish
        echo ""
        
        # Display per-AD results (show errors inline per-AD)
        printf "  ${BOLD}${CYAN}%-25s %15s %15s %15s %15s${NC}\n" \
            "Availability Domain" "Limit" "Used" "Available" "Quota"
        echo -e "  ${GRAY}$(printf '─%.0s' {1..88})${NC}"
        
        local _ad_failures=0
        local _first_err=""
        for _ad in "${ad_list[@]}"; do
            local _ad_short _ad_safe
            _ad_short=$(echo "$_ad" | sed 's/.*://')
            _ad_safe=$(echo "$_ad" | tr ':' '_')
            
            local avail_json
            avail_json=$(cat "$_atmp/${_ad_safe}.json" 2>/dev/null)
            
            if [[ -n "$avail_json" ]] && jq -e '.data' <<< "$avail_json" >/dev/null 2>&1; then
                local _used=0 _avail=0 _quota="—" _limit_val=0
                _used=$(jq -r '.data.used // 0' <<< "$avail_json")
                _avail=$(jq -r '.data.available // 0' <<< "$avail_json")
                _quota=$(jq -r '.data["effective-quota-value"] // "—"' <<< "$avail_json")
                [[ -z "$_used" || "$_used" == "null" ]] && _used=0
                [[ -z "$_avail" || "$_avail" == "null" ]] && _avail=0
                [[ "$_quota" == "null" ]] && _quota="—"
                _limit_val=$(( _used + _avail ))
                
                # Color availability
                local _avail_color="$GREEN"
                if [[ "$_avail" =~ ^[0-9]+$ ]]; then
                    [[ $_avail -eq 0 && $_limit_val -eq 0 ]] && _avail_color="$GRAY"
                    [[ $_avail -eq 0 && $_limit_val -gt 0 ]] && _avail_color="$RED"
                    [[ $_avail -gt 0 && $_limit_val -gt 0 && $(( _avail * 100 / _limit_val )) -lt 20 ]] && _avail_color="$YELLOW"
                fi
                
                local _fused _favail _flimit _fquota
                _fused=$(printf "%'d" "$_used" 2>/dev/null || echo "$_used")
                _favail=$(printf "%'d" "$_avail" 2>/dev/null || echo "$_avail")
                _flimit=$(printf "%'d" "$_limit_val" 2>/dev/null || echo "$_limit_val")
                _fquota="$_quota"
                [[ "$_quota" =~ ^[0-9]+$ ]] && _fquota=$(printf "%'d" "$_quota" 2>/dev/null || echo "$_quota")
                
                printf "  ${WHITE}%-25s${NC} %15s ${YELLOW}%15s${NC} ${_avail_color}%15s${NC} ${GRAY}%15s${NC}\n" \
                    "$_ad_short" "$_flimit" "$_fused" "$_favail" "$_fquota"
            else
                # API call failed for this AD
                ((_ad_failures++))
                local _ad_err
                _ad_err=$(cat "$_atmp/${_ad_safe}.err" 2>/dev/null)
                [[ -z "$_first_err" && -n "$_ad_err" ]] && _first_err="$_ad_err"
                printf "  ${WHITE}%-25s${NC} ${RED}%15s %15s %15s %15s${NC}\n" \
                    "$_ad_short" "—" "—" "ERROR" "—"
            fi
        done
        
        # If all ADs failed, show error details
        if [[ $_ad_failures -eq $_ad_total ]]; then
            echo ""
            echo -e "  ${YELLOW}⚠ resource-availability API failed for all ${_ad_total} ADs${NC}"
            if [[ -n "$_first_err" ]]; then
                local _err_msg
                _err_msg=$(echo "$_first_err" | grep -o '"message": *"[^"]*"' | head -1 | sed 's/"message": *"//' | sed 's/"$//')
                [[ -n "$_err_msg" ]] && echo -e "  ${RED}Error: ${_err_msg}${NC}"
            fi
            echo ""
            echo -e "  ${CYAN}Tip:${NC} Try manually: ${WHITE}oci limits resource-availability get --service-name ${service_name}${NC}"
            echo -e "       ${WHITE}--limit-name ${limit_name} --compartment-id \$TENANCY_ID --availability-domain <AD>${NC}"
        fi
        # Merge per-AD JSON files for j viewer
        _avail_detail_json=$(jq -s '{ data: [ .[] | .data // . ] }' "$_atmp"/*.json 2>/dev/null || echo "")
        rm -rf "$_atmp"
    else
        # Region-scoped limit
        local avail_json _avail_err=""
        avail_json=$(oci limits resource-availability get \
            --service-name "$service_name" \
            --limit-name "$limit_name" \
            --compartment-id "$tenancy_id" \
            --region "$region" \
            --output json 2>"${TMPDIR:-/tmp}/_avail_err.$$")
        _avail_err=$(cat "${TMPDIR:-/tmp}/_avail_err.$$" 2>/dev/null)
        rm -f "${TMPDIR:-/tmp}/_avail_err.$$"
        
        if [[ -n "$avail_json" ]] && jq -e '.data' <<< "$avail_json" >/dev/null 2>&1; then
            printf "  ${BOLD}${CYAN}%-25s %15s %15s %15s %15s${NC}\n" \
                "Scope" "Limit" "Used" "Available" "Quota"
            echo -e "  ${GRAY}$(printf '─%.0s' {1..88})${NC}"
            
            local _used=0 _avail=0 _quota="—" _limit_val=0
            _used=$(jq -r '.data.used // 0' <<< "$avail_json")
            _avail=$(jq -r '.data.available // 0' <<< "$avail_json")
            _quota=$(jq -r '.data["effective-quota-value"] // "—"' <<< "$avail_json")
            [[ -z "$_used" || "$_used" == "null" ]] && _used=0
            [[ -z "$_avail" || "$_avail" == "null" ]] && _avail=0
            [[ "$_quota" == "null" ]] && _quota="—"
            _limit_val=$(( _used + _avail ))
            
            local _avail_color="$GREEN"
            if [[ "$_avail" =~ ^[0-9]+$ ]]; then
                [[ $_avail -eq 0 && $_limit_val -eq 0 ]] && _avail_color="$GRAY"
                [[ $_avail -eq 0 && $_limit_val -gt 0 ]] && _avail_color="$RED"
                [[ $_avail -gt 0 && $_limit_val -gt 0 && $(( _avail * 100 / _limit_val )) -lt 20 ]] && _avail_color="$YELLOW"
            fi
            
            local _fused _favail _flimit _fquota
            _fused=$(printf "%'d" "$_used" 2>/dev/null || echo "$_used")
            _favail=$(printf "%'d" "$_avail" 2>/dev/null || echo "$_avail")
            _flimit=$(printf "%'d" "$_limit_val" 2>/dev/null || echo "$_limit_val")
            _fquota="$_quota"
            [[ "$_quota" =~ ^[0-9]+$ ]] && _fquota=$(printf "%'d" "$_quota" 2>/dev/null || echo "$_quota")
            
            printf "  ${WHITE}%-25s${NC} %15s ${YELLOW}%15s${NC} ${_avail_color}%15s${NC} ${GRAY}%15s${NC}\n" \
                "Region" "$_flimit" "$_fused" "$_favail" "$_fquota"
            _avail_detail_json="$avail_json"
        else
            # API call failed — detect reason
            echo -e "  ${YELLOW}⚠ resource-availability API not supported for this limit${NC}"
            echo ""
            if echo "$_avail_err" | grep -q 'InvalidParameter'; then
                echo -e "  ${GRAY}OCI returns InvalidParameter for '${limit_name}' — this limit type does not${NC}"
                echo -e "  ${GRAY}support the resource-availability get API. The configured service limit value${NC}"
                echo -e "  ${GRAY}is shown above in the compute limits view (max across ADs).${NC}"
            else
                echo -e "  ${GRAY}The resource-availability API returned an error for this limit.${NC}"
                if [[ -n "$_avail_err" ]]; then
                    local _err_msg
                    _err_msg=$(echo "$_avail_err" | grep -o '"message": *"[^"]*"' | head -1 | sed 's/"message": *"//' | sed 's/"$//')
                    [[ -n "$_err_msg" ]] && echo -e "  ${RED}Error: ${_err_msg}${NC}"
                fi
            fi
            echo ""
            echo -e "  ${CYAN}Tip:${NC} Use ${WHITE}oci limits value list --service-name compute --scope-type AD --all${NC}"
            echo -e "  ${GRAY}to see the configured limit value for this shape.${NC}"
        fi
    fi
    
    if [[ -n "$_avail_detail_json" ]]; then
        echo ""
        echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
        echo ""
        _ui_prompt "Resource Availability" "j, Enter"
        local _la_choice
        read -r _la_choice
        [[ "${_la_choice:-}" == :* ]] && _nav_try_jump "$_la_choice" && return
        case "$_la_choice" in
            j|J|json|JSON) _ui_json_viewer "Resource Availability: ${limit_name}" "$_avail_detail_json" ".data" ;;
            j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Resource Availability: ${limit_name}" "$_avail_detail_json" ".data" "${_la_choice#* }" ;;
        esac
    else
        echo ""
        _ui_pause
    fi
}

#--------------------------------------------------------------------------------
# Quotas View
#--------------------------------------------------------------------------------
_limits_quotas_view() {
    local tenancy_id="$1"
    local region="${FOCUS_REGION:-$REGION}"
    
    while true; do
        echo ""
        _ui_menu_header "TENANCY QUOTAS" \
            --breadcrumb "Operations" "Service Limits" "Quotas" \
            --cmd "oci limits quota list --compartment-id \$TENANCY_ID --all" \
            --cache \
            "${LIMITS_QUOTA_CACHE}|Quotas"
        
        local quotas_json _qt_cached=""
        _step_init
        _step_active "quotas"
        if is_cache_fresh "$LIMITS_QUOTA_CACHE" 2>/dev/null && [[ -s "$LIMITS_QUOTA_CACHE" ]]; then
            quotas_json=$(cat "$LIMITS_QUOTA_CACHE")
            _qt_cached=" cached"
        else
            quotas_json=$(oci limits quota list \
                --compartment-id "$tenancy_id" \
                --region "$region" \
                --all --output json 2>/dev/null)
            [[ -z "$quotas_json" ]] && quotas_json='{"data":[]}'
            if jq -e '.data' <<< "$quotas_json" >/dev/null 2>&1; then
                echo "$quotas_json" | _cache_write "$LIMITS_QUOTA_CACHE"
            fi
        fi
        
        local quota_count=0
        quota_count=$(jq '.data | length' <<< "$quotas_json" 2>/dev/null) || quota_count=0
        _step_complete "quotas(${quota_count}${_qt_cached})"
        _step_finish
        echo ""
        
        if [[ $quota_count -eq 0 ]]; then
            echo -e "  ${GRAY}No quotas defined in tenancy${NC}"
        else
            printf "  ${BOLD}${CYAN}%-4s %-40s %-12s %-10s %-50s${NC}\n" \
                "#" "Quota Name" "State" "Locks" "Description"
            echo -e "  ${GRAY}$(printf '─%.0s' {1..120})${NC}"
            
            local qidx=0
            declare -A QUOTA_MAP=()
            declare -A QUOTA_NAME_MAP=()
            while IFS='|' read -r q_name q_id q_state q_desc q_locks q_created; do
                [[ -z "$q_id" ]] && continue
                ((qidx++))
                QUOTA_MAP[$qidx]="$q_id"
                QUOTA_NAME_MAP[$qidx]="$q_name"
                
                local _qsc="$GREEN"
                [[ "$q_state" != "ACTIVE" ]] && _qsc="$YELLOW"
                
                local _lock_display="—"
                local _lock_color="$GRAY"
                if [[ -n "$q_locks" && "$q_locks" != "0" && "$q_locks" != "null" ]]; then
                    _lock_display="locked(${q_locks})"
                    _lock_color="$RED"
                fi
                
                printf "  ${YELLOW}%-4s${NC} ${WHITE}%-40s${NC} ${_qsc}%-12s${NC} ${_lock_color}%-10s${NC} ${GRAY}%-50s${NC}\n" \
                    "$qidx" "${q_name:0:38}" "$q_state" "$_lock_display" "${q_desc:0:48}"
            done < <(jq -r '.data[] |
                "\(.name)|\(.id)|\(.["lifecycle-state"])|\(.description // "")|\(.locks | length)|\(.["time-created"])"' \
                <<< "$quotas_json" 2>/dev/null | sort)
        fi
        
        echo ""
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}#${NC})       Select quota to view statements"
        echo -e "  ${CYAN}/${NC})       Search quotas by name"
        echo -e "  ${MAGENTA}r${NC})       Refresh"
        echo -e "  ${CYAN}b${NC})       Back"
        echo ""
        _ui_prompt "Quotas" "#, /, r, b"
        
        local selection
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        case "$selection" in
            [0-9]|[0-9][0-9])
                local sel_quota="${QUOTA_MAP[$selection]:-}"
                if [[ -n "$sel_quota" ]]; then
                    _limits_quota_detail "$sel_quota" "$tenancy_id"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            /*)
                # Search quota names — use inline term if provided
                local _qterm="${selection#/}"
                if [[ -z "$_qterm" ]]; then
                    echo ""
                    echo -n -e "  ${CYAN}Search quotas: ${NC}"
                    read -r _qterm
                fi
                if [[ -n "$_qterm" ]]; then
                    local -a _qmatches=()
                    local _qi
                    for _qi in $(echo "${!QUOTA_NAME_MAP[@]}" | tr ' ' '\n' | sort -n); do
                        [[ "${QUOTA_NAME_MAP[$_qi],,}" == *"${_qterm,,}"* ]] && _qmatches+=("$_qi")
                    done
                    if [[ ${#_qmatches[@]} -eq 0 ]]; then
                        echo -e "  ${YELLOW}No quotas matching '${_qterm}'${NC}"
                        sleep 1
                    elif [[ ${#_qmatches[@]} -eq 1 ]]; then
                        local _qk="${_qmatches[0]}"
                        echo -e "  ${GREEN}→ ${QUOTA_NAME_MAP[$_qk]}${NC}"
                        sleep 0.3
                        _limits_quota_detail "${QUOTA_MAP[$_qk]}" "$tenancy_id"
                    else
                        echo ""
                        echo -e "  ${WHITE}${#_qmatches[@]} matches for '${_qterm}':${NC}"
                        echo ""
                        declare -A _QS_MAP=()
                        local _qsi=0
                        for _qi in "${_qmatches[@]}"; do
                            ((_qsi++))
                            _QS_MAP[$_qsi]="$_qi"
                            printf "  ${YELLOW}%-4s${NC} ${WHITE}%s${NC}\n" "$_qsi" "${QUOTA_NAME_MAP[$_qi]}"
                        done
                        echo ""
                        echo -n -e "  ${CYAN}Select # (Enter to cancel): ${NC}"
                        local _qssel
                        read -r _qssel
                        if [[ "$_qssel" =~ ^[0-9]+$ ]] && [[ -n "${_QS_MAP[$_qssel]:-}" ]]; then
                            local _qk="${_QS_MAP[$_qssel]}"
                            _limits_quota_detail "${QUOTA_MAP[$_qk]}" "$tenancy_id"
                        fi
                    fi
                fi
                ;;
            r|R) rm -f "$LIMITS_QUOTA_CACHE"; continue ;;
            b|B|"") return ;;
            show|SHOW) continue ;;
            *) echo -e "${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Quota Detail - Statements with 225-char wrapping
#--------------------------------------------------------------------------------
_limits_quota_detail() {
    local quota_id="$1" tenancy_id="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Quota Detail" 0

    local quota_json
    quota_json=$(oci limits quota get \
        --quota-id "$quota_id" \
        --region "$region" \
        --output json 2>/dev/null)
    
    if [[ -z "$quota_json" ]] || ! jq -e '.data' <<< "$quota_json" >/dev/null 2>&1; then
        echo -e "  ${RED}Failed to fetch quota details${NC}"
        _ui_policy_hint "read quotas in compartment"
        _ui_pause
        return
    fi
    
    local q_name q_desc q_state q_created
    q_name=$(jq -r '.data.name // "N/A"' <<< "$quota_json")
    q_desc=$(jq -r '.data.description // ""' <<< "$quota_json")
    q_state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$quota_json")
    q_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$quota_json")
    
    echo -e "  ${CYAN}Name:${NC}          ${WHITE}${q_name}${NC}"
    echo -e "  ${CYAN}Description:${NC}   ${GRAY}${q_desc}${NC}"
    echo -e "  ${CYAN}State:${NC}         ${GREEN}${q_state}${NC}"
    echo -e "  ${CYAN}Created:${NC}       ${GRAY}${q_created}${NC}"
    echo -e "  ${CYAN}OCID:${NC}          ${YELLOW}${quota_id}${NC}"
    
    # Show locks
    local lock_count
    lock_count=$(jq '.data.locks | length' <<< "$quota_json" 2>/dev/null) || lock_count=0
    if [[ $lock_count -gt 0 ]]; then
        echo ""
        echo -e "  ${RED}Locked ($lock_count):${NC}"
        jq -r '.data.locks[] | "    \(.type): \(.message // "No message")"' <<< "$quota_json" 2>/dev/null | \
            while read -r _lmsg; do echo -e "  ${GRAY}${_lmsg}${NC}"; done
    fi
    
    # Show statements with wrapping at 225 chars
    # Continuation lines align to column 6 (under the statement text after "  NN) ")
    echo ""
    echo -e "  ${BOLD}${CYAN}Quota Statements:${NC}"
    echo -e "  ${GRAY}$(printf '─%.0s' {1..230})${NC}"
    
    local stmt_count
    stmt_count=$(jq '.data.statements | length' <<< "$quota_json" 2>/dev/null) || stmt_count=0
    
    local _wrap_width=225
    # 6 chars = "  NN) " — continuation lines pad to same column
    local _indent="      "
    
    if [[ $stmt_count -gt 0 ]]; then
        local sidx=0
        while IFS= read -r stmt; do
            ((sidx++))
            
            if [[ ${#stmt} -le $_wrap_width ]]; then
                printf "  ${YELLOW}%2d)${NC} ${WHITE}%s${NC}\n" "$sidx" "$stmt"
            else
                # First line
                printf "  ${YELLOW}%2d)${NC} ${WHITE}%s${NC}\n" "$sidx" "${stmt:0:$_wrap_width}"
                local _remaining="${stmt:$_wrap_width}"
                # Continuation lines
                while [[ ${#_remaining} -gt 0 ]]; do
                    printf "${_indent}${WHITE}%s${NC}\n" "${_remaining:0:$_wrap_width}"
                    _remaining="${_remaining:$_wrap_width}"
                done
            fi
        done < <(jq -r '.data.statements[]' <<< "$quota_json" 2>/dev/null)
    else
        echo -e "  ${GRAY}No statements defined${NC}"
    fi
    
    # Show freeform tags
    local _fftags
    _fftags=$(jq -r '.data["freeform-tags"] // {} | to_entries[] | "    \(.key) = \(.value)"' <<< "$quota_json" 2>/dev/null)
    if [[ -n "$_fftags" ]]; then
        echo ""
        echo -e "  ${CYAN}Freeform Tags:${NC}"
        echo -e "${GRAY}${_fftags}${NC}"
    fi

    echo ""
    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Quota Detail" "j, Enter"
    local _qd_choice
    read -r _qd_choice
    [[ "${_qd_choice:-}" == :* ]] && _nav_try_jump "$_qd_choice" && return
    case "$_qd_choice" in
        j|J|json|JSON) _ui_json_viewer "Quota: ${q_name}" "$quota_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Quota: ${q_name}" "$quota_json" ".data" "${_qd_choice#* }" ;;
    esac
}

#================================================================================
# FILE STORAGE SERVICE (FSS) MANAGEMENT
#================================================================================

#--------------------------------------------------------------------------------
# Fetch and cache FSS data (file systems, mount targets, exports)
# Usage: fetch_fss_data <compartment_id> [force_refresh]
# Populates: FSS_FS_CACHE, FSS_MT_CACHE, FSS_EXPORT_CACHE, FSS_MT_IP_CACHE
#--------------------------------------------------------------------------------
fetch_fss_data() {
    local compartment_id="$1"
    local force="${2:-false}"
    local region="${FOCUS_REGION:-$REGION}"

    # Check if all caches are fresh (invalidate if any resource is in transitional state)
    if [[ "$force" != "true" ]] && \
       is_cache_fresh "$FSS_FS_CACHE" && \
       is_cache_fresh "$FSS_MT_CACHE" && \
       is_cache_fresh "$FSS_EXPORT_CACHE" && \
       is_cache_fresh "$FSS_MT_IP_CACHE"; then
        # Check for transitional states across all FSS caches
        if _cache_invalidate_if_transitional "$FSS_FS_CACHE" "" '.data[]."lifecycle-state"' || \
           _cache_invalidate_if_transitional "$FSS_MT_CACHE" "" '.data[]."lifecycle-state"'; then
            : # fall through to re-fetch
        else
            return 0
        fi
    fi
    
    # Get availability domains
    local ads
    ads=$(fss_get_availability_domains "$compartment_id")
    if [[ -z "$ads" ]]; then
        echo -e "${RED}Unable to get availability domains${NC}" >&2
        return 1
    fi
    
    _step_init
    _step_active "file systems, mount targets, exports"
    
    #--- WAVE 1: FS per AD + MT per AD + exports — all in parallel ---
    local _ftmp="${TEMP_DIR}/fss_$$"
    mkdir -p "$_ftmp"
    local _pids=()
    local _ad_idx=0
    
    while IFS= read -r ad; do
        [[ -z "$ad" ]] && continue
        ((_ad_idx++))
        (oci fs file-system list --compartment-id "$compartment_id" --availability-domain "$ad" --region "$region" --all --output json > "$_ftmp/fs_${_ad_idx}.json" 2>/dev/null) &
        _pids+=($!)
        (oci fs mount-target list --compartment-id "$compartment_id" --availability-domain "$ad" --region "$region" --all --output json > "$_ftmp/mt_${_ad_idx}.json" 2>/dev/null) &
        _pids+=($!)
    done <<< "$ads"
    (oci fs export list --compartment-id "$compartment_id" --region "$region" --all --output json > "$_ftmp/exports.json" 2>/dev/null) &
    _pids+=($!)
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    
    # Merge file systems from all ADs
    local all_fs_json="[]"
    for f in "$_ftmp"/fs_*.json; do
        [[ -s "$f" ]] || continue
        local _fd; _fd=$(jq '.data // []' "$f" 2>/dev/null) || continue
        all_fs_json=$(echo "$all_fs_json" "$_fd" | jq -s 'add' 2>/dev/null)
    done
    echo "{\"data\":$(jq '.' <<< "$all_fs_json")}" > "$FSS_FS_CACHE"
    local _fs_ct; _fs_ct=$(jq 'length' <<< "$all_fs_json" 2>/dev/null); _fs_ct="${_fs_ct:-0}"
    _step_complete "file systems(${_fs_ct})"
    
    # Merge mount targets from all ADs
    local all_mt_json="[]"
    for f in "$_ftmp"/mt_*.json; do
        [[ -s "$f" ]] || continue
        local _md; _md=$(jq '.data // []' "$f" 2>/dev/null) || continue
        all_mt_json=$(echo "$all_mt_json" "$_md" | jq -s 'add' 2>/dev/null)
    done
    echo "{\"data\":$(jq '.' <<< "$all_mt_json")}" > "$FSS_MT_CACHE"
    local _mt_ct; _mt_ct=$(jq 'length' <<< "$all_mt_json" 2>/dev/null); _mt_ct="${_mt_ct:-0}"
    _step_complete "mount targets(${_mt_ct})"
    
    # Read exports
    local all_export_json='{"data":[]}'
    [[ -s "$_ftmp/exports.json" ]] && all_export_json=$(cat "$_ftmp/exports.json")
    if ! jq -e '.data' <<< "$all_export_json" > /dev/null 2>&1; then
        all_export_json='{"data":[]}'
    fi
    echo "$all_export_json" > "$FSS_EXPORT_CACHE"
    local _exp_ct; _exp_ct=$(jq '.data | length' <<< "$all_export_json" 2>/dev/null); _exp_ct="${_exp_ct:-0}"
    _step_complete "exports(${_exp_ct})"
    
    #--- WAVE 2: Resolve mount target private IPs — all in parallel ---
    _step_active "mount target IPs"
    > "$FSS_MT_IP_CACHE"
    _pids=()
    local _ip_idx=0
    while IFS='|' read -r mt_id ip_ids; do
        [[ -z "$mt_id" ]] && continue
        local first_ip_id
        first_ip_id=$(jq -r '.[0] // empty' <<< "$ip_ids" 2>/dev/null)
        if [[ -n "$first_ip_id" ]]; then
            ((_ip_idx++))
            (
                local _ip
                _ip=$(oci network private-ip get --private-ip-id "$first_ip_id" --region "$region" --query 'data."ip-address"' --raw-output 2>/dev/null)
                [[ -n "$_ip" ]] && echo "${mt_id}|${_ip}" > "$_ftmp/ip_${_ip_idx}.txt"
            ) &
            _pids+=($!)
        fi
    done < <(jq -r '.[] | "\(.id)|\(.["private-ip-ids"])"' <<< "$all_mt_json" 2>/dev/null)
    [[ ${#_pids[@]} -gt 0 ]] && wait "${_pids[@]}"
    
    # Merge IP results into cache
    local _ip_ct=0
    for f in "$_ftmp"/ip_*.txt; do
        [[ -s "$f" ]] || continue
        cat "$f" >> "$FSS_MT_IP_CACHE"
        ((_ip_ct++))
    done
    _step_complete "mount target IPs(${_ip_ct})"
    
    # Cleanup temp
    rm -rf "$_ftmp"
    _step_finish
}

#--------------------------------------------------------------------------------
# Get availability domains for compartment
#--------------------------------------------------------------------------------
fss_get_availability_domains() {
    local compartment_id="$1"
    
    local ad_json
    local ad_json
    ad_json=$(_get_ads_json "$compartment_id")
    
    if [[ -z "$ad_json" ]]; then
        echo -e "${RED}Error getting availability domains${NC}" >&2
        return 1
    fi
    
    jq -r '.data[].name' <<< "$ad_json" 2>/dev/null
}

#--------------------------------------------------------------------------------
# FSS - Guided Setup (File System → Mount Target → Export)
# Creates all three FSS components in sequence with a step-by-step wizard
#--------------------------------------------------------------------------------
fss_guided_setup() {
    local compartment_id="$1"
    local ad="$2"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/fss_actions_$(date +%Y%m%d).log"
    
    echo ""
    _ui_menu_header "FSS GUIDED SETUP WIZARD"
    echo ""
    echo -e "${WHITE}This wizard will guide you through creating:${NC}"
    echo -e "  ${YELLOW}Step 1/3${NC} - File System"
    echo -e "  ${YELLOW}Step 2/3${NC} - Mount Target"
    echo -e "  ${YELLOW}Step 3/3${NC} - Export (links File System to Mount Target)"
    echo ""
    echo -e "${GRAY}You can cancel at any step. Previously created resources will remain.${NC}"
    echo ""
    echo -n -e "${CYAN}Press Enter to begin (or 'q' to cancel): ${NC}"
    local start_confirm
    read -r start_confirm
    [[ "$start_confirm" == "q" || "$start_confirm" == "Q" ]] && return
    
    # ==================== STEP 1: Select Availability Domain ====================
    echo ""
    _ui_subheader "Select Availability Domain" 0
    echo ""
    
    local selected_ad="$ad"
    if [[ -z "$selected_ad" ]]; then
        echo -e "${CYAN}Available Availability Domains:${NC}"
        local ads_json
        ads_json=$(_get_ads_json "$compartment_id")
        
        local idx=0
        declare -A GUIDED_AD_MAP
        while read -r ad_name; do
            [[ -z "$ad_name" ]] && continue
            ((idx++))
            GUIDED_AD_MAP[$idx]="$ad_name"
            echo -e "  ${YELLOW}$idx${NC}) $ad_name"
        done < <(jq -r '.data[].name' <<< "$ads_json" 2>/dev/null)
        
        if [[ $idx -eq 0 ]]; then
            echo -e "${RED}No availability domains found${NC}"
            return
        fi
        
        echo ""
        echo -n -e "${CYAN}Select AD # (or 'q' to cancel): ${NC}"
        local ad_selection
        read -r ad_selection
        [[ "$ad_selection" == "q" || "$ad_selection" == "Q" ]] && return
        
        selected_ad="${GUIDED_AD_MAP[$ad_selection]}"
        if [[ -z "$selected_ad" ]]; then
            echo -e "${RED}Invalid selection${NC}"
            return
        fi
    fi
    
    local ad_short="${selected_ad##*:}"
    echo -e "  ${GREEN}✓${NC} Using AD: ${WHITE}${ad_short}${NC}"
    
    # ==================== STEP 1: Create File System ====================
    echo ""
    print_separator 80 "${BOLD}${YELLOW}"
    echo -e "${BOLD}${YELLOW}  Step 1/3 │ Create File System                                                   ${NC}"
    print_separator 80 "${BOLD}${YELLOW}"
    echo ""
    
    echo -n -e "${CYAN}Enter display name for file system: ${NC}"
    local fs_name
    read -r fs_name
    
    if [[ -z "$fs_name" ]]; then
        echo -e "${RED}Display name is required. Wizard cancelled.${NC}"
        return
    fi
    
    echo ""
    local fs_create_cmd="oci fs file-system create --compartment-id \"$compartment_id\" --availability-domain \"$selected_ad\" --display-name \"$fs_name\" --region \"$region\""
    echo -e "${GRAY}Command to execute:${NC}"
    echo -e "${WHITE}$fs_create_cmd${NC}"
    echo ""
    
    echo -n -e "${YELLOW}Create file system '${fs_name}'? (y/N): ${NC}"
    local confirm
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Wizard cancelled at Step 1${NC}"
        return
    fi
    
    echo ""
    if ! _fss_do_create_file_system "$compartment_id" "$selected_ad" "$fs_name"; then
        echo ""
        echo -e "${RED}Wizard stopped at Step 1. No resources were created.${NC}"
        _ui_pause
        return
    fi
    local new_fs_id="$FSS_CREATED_ID"
    
    # ==================== STEP 2: Create Mount Target ====================
    echo ""
    print_separator 80 "${BOLD}${YELLOW}"
    echo -e "${BOLD}${YELLOW}  Step 2/3 │ Create Mount Target                                                  ${NC}"
    print_separator 80 "${BOLD}${YELLOW}"
    echo ""
    
    # Option: use existing mount target or create new
    echo -e "${CYAN}Would you like to create a new mount target or use an existing one?${NC}"
    echo -e "  ${YELLOW}1${NC}) Create new mount target"
    echo -e "  ${YELLOW}2${NC}) Use existing mount target"
    echo -e "  ${CYAN}q${NC}) Cancel (file system already created)"
    echo ""
    echo -n -e "${CYAN}Select [1/2/q]: ${NC}"
    local mt_choice
    read -r mt_choice
    
    local new_mt_id=""
    local export_set_id=""
    
    if [[ "$mt_choice" == "2" ]]; then
        # Use existing mount target
        echo ""
        echo -e "${CYAN}Select an existing mount target:${NC}"
        FSS_SELECTED_MT=""
        fss_list_mount_targets "$compartment_id" "$selected_ad" "select"
        
        if [[ -z "$FSS_SELECTED_MT" ]]; then
            echo -e "${YELLOW}No mount target selected. Wizard stopped at Step 2.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            _ui_pause
            return
        fi
        
        new_mt_id="$FSS_SELECTED_MT"
        
        # Get export set ID from existing mount target
        local mt_json
        mt_json=$(oci fs mount-target get --mount-target-id "$new_mt_id" --region "$region" --output json 2>/dev/null)
        export_set_id=$(jq -r '.data["export-set-id"]' <<< "$mt_json")
        local mt_display_name
        mt_display_name=$(jq -r '.data["display-name"]' <<< "$mt_json")
        echo -e "${GREEN}✓ Using existing mount target: ${WHITE}$mt_display_name${NC}"
        
    elif [[ "$mt_choice" == "1" ]]; then
        # Create new mount target - select subnet
        echo ""
        echo -e "${CYAN}Available Subnets:${NC}"
        local subnets_json
        # Try cache first
        local _subnets_json_cached=""
        if is_cache_fresh "$OKE_SUBNET_LIST_CACHE" 2>/dev/null && [[ -s "$OKE_SUBNET_LIST_CACHE" ]]; then
            subnets_json=$(cat "$OKE_SUBNET_LIST_CACHE" 2>/dev/null)
            if [[ -n "$subnets_json" ]] && jq -e '.data[0]' <<< "$subnets_json" >/dev/null 2>&1; then
                _subnets_json_cached=" cached"
            else
                subnets_json=""
            fi
        fi
        if [[ -z "${_subnets_json_cached}" ]]; then
        subnets_json=$(oci network subnet list --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
        fi
        [[ -n "${_subnets_json_cached}" ]] && echo -e "  ${GREEN}(from cache)${NC}"
        
        local idx=0
        declare -A GUIDED_SUBNET_MAP
        while IFS='|' read -r subnet_name subnet_id cidr; do
            [[ -z "$subnet_name" ]] && continue
            ((idx++))
            GUIDED_SUBNET_MAP[$idx]="$subnet_id"
            echo -e "  ${YELLOW}$idx${NC}) $subnet_name (${cidr})"
        done < <(jq -r '.data[] | "\(.["display-name"])|\(.id)|\(.["cidr-block"])"' <<< "$subnets_json" 2>/dev/null)
        
        if [[ $idx -eq 0 ]]; then
            echo -e "${RED}No subnets found. Wizard stopped at Step 2.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            _ui_pause
            return
        fi
        
        echo ""
        echo -n -e "${CYAN}Select subnet #: ${NC}"
        local subnet_selection
        read -r subnet_selection
        local subnet_id="${GUIDED_SUBNET_MAP[$subnet_selection]}"
        
        if [[ -z "$subnet_id" ]]; then
            echo -e "${RED}Invalid selection. Wizard stopped at Step 2.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            _ui_pause
            return
        fi
        
        # Suggest mount target name based on file system name
        local suggested_mt_name="${fs_name}-mt"
        echo ""
        echo -n -e "${CYAN}Enter display name for mount target [${suggested_mt_name}]: ${NC}"
        local mt_name
        read -r mt_name
        [[ -z "$mt_name" ]] && mt_name="$suggested_mt_name"
        
        echo ""
        local mt_create_cmd="oci fs mount-target create --compartment-id \"$compartment_id\" --availability-domain \"$selected_ad\" --subnet-id \"$subnet_id\" --display-name \"$mt_name\" --region \"$region\""
        echo -e "${GRAY}Command to execute:${NC}"
        echo -e "${WHITE}$mt_create_cmd${NC}"
        echo ""
        
        echo -n -e "${YELLOW}Create mount target '${mt_name}'? (y/N): ${NC}"
        read -r confirm
        
        if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
            echo -e "${YELLOW}Wizard stopped at Step 2.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            _ui_pause
            return
        fi
        
        echo ""
        if ! _fss_do_create_mount_target "$compartment_id" "$selected_ad" "$subnet_id" "$mt_name"; then
            echo ""
            echo -e "${RED}Wizard stopped at Step 2.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            _ui_pause
            return
        fi
        new_mt_id="$FSS_CREATED_ID"
        export_set_id="$FSS_CREATED_EXPORT_SET_ID"
    else
        echo -e "${YELLOW}Wizard stopped at Step 2.${NC}"
        echo -e "${WHITE}Created resources:${NC}"
        echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
        _ui_pause
        return
    fi
    
    # Get export set ID if not already set
    if [[ -z "$export_set_id" || "$export_set_id" == "null" ]]; then
        _step_init
        _step_active "export set from mount target"
        local mt_detail
        mt_detail=$(oci fs mount-target get --mount-target-id "$new_mt_id" --region "$region" --output json 2>/dev/null)
        export_set_id=$(jq -r '.data["export-set-id"]' <<< "$mt_detail")
        _step_complete "export set from mount target"
        _step_finish
        
        if [[ -z "$export_set_id" || "$export_set_id" == "null" ]]; then
            echo -e "${RED}Could not retrieve export set ID from mount target${NC}"
            echo -e "${RED}Wizard stopped at Step 3. Mount target may still be initializing.${NC}"
            echo -e "${WHITE}Created resources:${NC}"
            echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
            echo -e "  ${GREEN}✓${NC} Mount Target: ${YELLOW}[$new_mt_id]${NC}"
            echo -e "${GRAY}Tip: Wait for the mount target to become ACTIVE, then use 'ce' to create the export manually.${NC}"
            _ui_pause
            return
        fi
    fi
    
    # ==================== STEP 3: Create Export ====================
    echo ""
    print_separator 80 "${BOLD}${YELLOW}"
    echo -e "${BOLD}${YELLOW}  Step 3/3 │ Create Export                                                        ${NC}"
    print_separator 80 "${BOLD}${YELLOW}"
    echo ""
    
    # Suggest export path based on file system name
    local suggested_path="/${fs_name}"
    echo -e "${CYAN}The export path is the NFS mount path clients will use.${NC}"
    echo ""
    echo -n -e "${CYAN}Enter export path [${suggested_path}]: ${NC}"
    local export_path
    read -r export_path
    [[ -z "$export_path" ]] && export_path="$suggested_path"
    
    # Ensure path starts with /
    [[ "${export_path:0:1}" != "/" ]] && export_path="/$export_path"
    
    echo ""
    local export_create_cmd="oci fs export create --file-system-id \"$new_fs_id\" --export-set-id \"$export_set_id\" --path \"$export_path\" --region \"$region\""
    echo -e "${GRAY}Command to execute:${NC}"
    echo -e "${WHITE}$export_create_cmd${NC}"
    echo ""
    
    echo -n -e "${YELLOW}Create export '${export_path}'? (y/N): ${NC}"
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Wizard stopped at Step 3.${NC}"
        echo -e "${WHITE}Created resources:${NC}"
        echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
        echo -e "  ${GREEN}✓${NC} Mount Target: ${YELLOW}[$new_mt_id]${NC}"
        echo -e "${GRAY}Tip: Use 'ce' to create the export later.${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    if ! _fss_do_create_export "$new_fs_id" "$export_set_id" "$export_path"; then
        echo ""
        echo -e "${RED}Wizard stopped at Step 3.${NC}"
        echo -e "${WHITE}Created resources:${NC}"
        echo -e "  ${GREEN}✓${NC} File System: ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
        echo -e "  ${GREEN}✓${NC} Mount Target: ${YELLOW}[$new_mt_id]${NC}"
        _ui_pause
        return
    fi
    local new_export_id="$FSS_CREATED_ID"
    
    # ==================== SUMMARY ====================
    # Resolve mount target display name
    local _mt_display="${mt_name:-${mt_display_name:-}}"
    [[ -z "$_mt_display" ]] && _mt_display="(unknown)"

    echo ""
    _ui_menu_header "GUIDED SETUP COMPLETE ✓" --color "$GREEN"
    echo ""
    echo -e "${WHITE}Resources Created:${NC}"
    echo -e "  ${GREEN}✓${NC} File System:  ${WHITE}$fs_name${NC} ${YELLOW}[$new_fs_id]${NC}"
    echo -e "  ${GREEN}✓${NC} Mount Target: ${WHITE}$_mt_display${NC} ${YELLOW}[$new_mt_id]${NC}"
    echo -e "  ${GREEN}✓${NC} Export:       ${WHITE}$export_path${NC} ${YELLOW}[$new_export_id]${NC}"
    echo ""
    
    # Resolve mount target IP
    local mt_detail_json
    mt_detail_json=$(oci fs mount-target get --mount-target-id "$new_mt_id" --region "$region" --output json 2>/dev/null)
    local mt_ip_id
    mt_ip_id=$(jq -r '.data["private-ip-ids"][0] // empty' <<< "$mt_detail_json" 2>/dev/null)
    local mt_ip="(resolving...)"
    if [[ -n "$mt_ip_id" ]]; then
        mt_ip=$(oci network private-ip get --private-ip-id "$mt_ip_id" --region "$region" --query 'data."ip-address"' --raw-output 2>/dev/null) || mt_ip="(pending)"
    fi
    
    _ui_subheader "Mount Command" 0
    echo -e "  ${CYAN}sudo mount -t nfs -o defaults ${mt_ip}:${export_path} /mnt/${fs_name}${NC}"
    echo ""
    echo -e "${GRAY}Note: Ensure NSGs/Security Lists allow NFS traffic (TCP 111, 2048-2050; UDP 111, 2048).${NC}"
    echo ""
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] GUIDED SETUP COMPLETE: FS=$new_fs_id MT=$new_mt_id Export=$new_export_id" >> "$log_file"
    
    _ui_pause
}

#--------------------------------------------------------------------------------
# FSS - Recursive Delete File System
# Finds and deletes associated exports, optionally the mount target, then the FS
#--------------------------------------------------------------------------------
fss_recursive_delete_file_system() {
    local compartment_id="$1"
    local fs_id="$2"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/fss_actions_$(date +%Y%m%d).log"
    
    echo ""
    _ui_menu_header "RECURSIVE DELETE FILE SYSTEM"
    echo ""
    
    # Get file system details
    _step_init
    _step_active "file system details"
    local fs_json
    fs_json=$(oci fs file-system get --file-system-id "$fs_id" --region "$region" --output json 2>/dev/null)
    _step_complete "file system details"
    _step_finish
    local fs_name
    fs_name=$(jq -r '.data["display-name"]' <<< "$fs_json" 2>/dev/null)
    local fs_state
    fs_state=$(jq -r '.data["lifecycle-state"]' <<< "$fs_json" 2>/dev/null)
    local fs_metered
    fs_metered=$(jq -r '.data["metered-bytes"]' <<< "$fs_json" 2>/dev/null)
    local fs_metered_gb="0"
    [[ -n "$fs_metered" && "$fs_metered" != "null" ]] && fs_metered_gb=$(echo "scale=2; $fs_metered / 1073741824" | bc 2>/dev/null || echo "0")
    
    echo -e "  ${CYAN}File System:${NC} ${WHITE}$fs_name${NC} (${fs_state}) - ${fs_metered_gb} GB"
    echo -e "  ${GRAY}$fs_id${NC}"
    echo ""
    
    # Find all exports linked to this file system
    echo -e "${CYAN}Searching for exports linked to this file system...${NC}"
    local exports_json
    exports_json=$(oci fs export list --compartment-id "$compartment_id" --file-system-id "$fs_id" --region "$region" --all --output json 2>/dev/null)
    
    local export_count
    export_count=$(jq '.data | length' <<< "$exports_json" 2>/dev/null) || export_count=0
    
    # Track export details and mount targets involved
    declare -a EXPORT_IDS
    declare -a EXPORT_PATHS
    declare -a EXPORT_SET_IDS
    declare -A INVOLVED_MT_IDS  # export_set_id -> mt_id
    local export_idx=0
    
    if [[ "$export_count" -gt 0 ]]; then
        while IFS='|' read -r exp_id exp_path exp_set_id exp_state; do
            [[ -z "$exp_id" ]] && continue
            [[ "$exp_state" == "DELETED" || "$exp_state" == "DELETING" ]] && continue
            
            EXPORT_IDS+=("$exp_id")
            EXPORT_PATHS+=("$exp_path")
            EXPORT_SET_IDS+=("$exp_set_id")
            ((export_idx++))
        done < <(jq -r '.data[] | "\(.id)|\(.path)|\(.["export-set-id"])|\(.["lifecycle-state"])"' <<< "$exports_json" 2>/dev/null)
    fi
    
    # Resolve mount targets for each export set
    declare -A MT_NAMES
    declare -A MT_EXPORT_COUNTS  # mt_id -> total export count (not just this FS)
    
    for exp_set_id in $(printf '%s\n' "${EXPORT_SET_IDS[@]}" | sort -u); do
        [[ -z "$exp_set_id" ]] && continue
        
        # Find mount target with this export set
        local mt_list_json
        mt_list_json=$(cat "$FSS_MT_CACHE" 2>/dev/null)
        
        local mt_id mt_name
        mt_id=$(jq -r --arg esid "$exp_set_id" '.data[] | select(.["export-set-id"] == $esid) | .id' <<< "$mt_list_json" 2>/dev/null)
        mt_name=$(jq -r --arg esid "$exp_set_id" '.data[] | select(.["export-set-id"] == $esid) | .["display-name"]' <<< "$mt_list_json" 2>/dev/null)
        
        if [[ -n "$mt_id" ]]; then
            INVOLVED_MT_IDS[$exp_set_id]="$mt_id"
            MT_NAMES[$mt_id]="$mt_name"
            
            # Count total exports on this mount target (not just from this FS)
            local total_exports
            total_exports=$(oci fs export list --compartment-id "$compartment_id" --export-set-id "$exp_set_id" --region "$region" --all --query 'data[?"lifecycle-state"!=`DELETED`] | length(@)' --raw-output 2>/dev/null) || total_exports=0
            MT_EXPORT_COUNTS[$mt_id]="$total_exports"
        fi
    done
    
    # Count exports from THIS file system per mount target
    declare -A FS_EXPORTS_PER_MT  # mt_id -> count of exports from this FS
    for i in "${!EXPORT_SET_IDS[@]}"; do
        local mt_id="${INVOLVED_MT_IDS[${EXPORT_SET_IDS[$i]}]}"
        if [[ -n "$mt_id" ]]; then
            FS_EXPORTS_PER_MT[$mt_id]=$(( ${FS_EXPORTS_PER_MT[$mt_id]:-0} + 1 ))
        fi
    done
    
    # ==================== Display What Will Be Deleted ====================
    echo ""
    echo -e "${BOLD}${RED}The following resources will be deleted:${NC}"
    echo ""
    
    # Show exports
    if [[ $export_idx -gt 0 ]]; then
        echo -e "  ${RED}Exports (${export_idx}):${NC}"
        for i in "${!EXPORT_IDS[@]}"; do
            echo -e "    ${RED}✗${NC} Export: ${WHITE}${EXPORT_PATHS[$i]}${NC}"
            echo -e "      ${GRAY}${EXPORT_IDS[$i]}${NC}"
        done
        echo ""
    else
        echo -e "  ${GRAY}No active exports linked to this file system${NC}"
        echo ""
    fi
    
    # Determine which mount targets can be deleted (all their exports are from this FS)
    declare -A MT_CAN_DELETE  # mt_id -> true/false
    local mt_delete_count=0
    
    for mt_id in $(printf '%s\n' "${!INVOLVED_MT_IDS[@]}" | while read -r k; do echo "${INVOLVED_MT_IDS[$k]}"; done | sort -u); do
        [[ -z "$mt_id" ]] && continue
        
        local total="${MT_EXPORT_COUNTS[$mt_id]:-0}"
        local from_this_fs="${FS_EXPORTS_PER_MT[$mt_id]:-0}"
        local mt_name="${MT_NAMES[$mt_id]}"
        
        if [[ "$total" -le "$from_this_fs" ]]; then
            # Mount target will have no exports after deletion - safe to delete
            MT_CAN_DELETE[$mt_id]="true"
            ((mt_delete_count++))
            echo -e "  ${RED}Mount Target:${NC}"
            echo -e "    ${RED}✗${NC} ${WHITE}${mt_name}${NC} ${GRAY}(will have 0 exports after delete)${NC}"
            echo -e "      ${GRAY}${mt_id}${NC}"
        else
            MT_CAN_DELETE[$mt_id]="false"
            local remaining=$((total - from_this_fs))
            echo -e "  ${YELLOW}Mount Target (kept):${NC}"
            echo -e "    ${YELLOW}~${NC} ${WHITE}${mt_name}${NC} ${GRAY}(has ${remaining} other export(s) - will NOT be deleted)${NC}"
            echo -e "      ${GRAY}${mt_id}${NC}"
        fi
    done
    echo ""
    
    # Show file system
    echo -e "  ${RED}File System:${NC}"
    echo -e "    ${RED}✗${NC} ${WHITE}${fs_name}${NC} (${fs_metered_gb} GB)"
    echo -e "      ${GRAY}${fs_id}${NC}"
    echo ""
    
    # Summary count
    local total_deletes=$((export_idx + mt_delete_count + 1))
    echo -e "${BOLD}${RED}Total resources to delete: ${total_deletes}${NC} (${export_idx} export(s), ${mt_delete_count} mount target(s), 1 file system)"
    echo ""
    
    # ==================== Command Preview ====================
    echo -e "${BOLD}${WHITE}Commands to Execute:${NC}"
    echo ""
    
    # Show export delete commands
    if [[ $export_idx -gt 0 ]]; then
        for i in "${!EXPORT_IDS[@]}"; do
            echo -e "  ${WHITE}\$ oci fs export delete --export-id \"${EXPORT_IDS[$i]}\" --region \"${region}\" --force${NC}"
        done
    fi
    
    # Show mount target delete commands
    for mt_id in $(printf '%s\n' "${!MT_CAN_DELETE[@]}"); do
        [[ "${MT_CAN_DELETE[$mt_id]}" != "true" ]] && continue
        echo -e "  ${WHITE}\$ oci fs mount-target delete --mount-target-id \"${mt_id}\" --region \"${region}\" --force${NC}"
    done
    
    # Show file system delete command
    echo -e "  ${WHITE}\$ oci fs file-system delete --file-system-id \"${fs_id}\" --region \"${region}\" --force${NC}"
    echo ""
    
    # ==================== Confirmation ====================
    echo -e "${RED}This action is ${BOLD}PERMANENT${NC}${RED} and cannot be undone.${NC}"
    echo ""
    if ! _ui_confirm "DELETE ALL" "confirm recursive deletion"; then
        echo -e "${YELLOW}Deletion cancelled${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    echo ""
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] RECURSIVE DELETE STARTED for file system: $fs_name ($fs_id)" >> "$log_file"
    
    # ==================== Phase 1: Delete Exports ====================
    if [[ $export_idx -gt 0 ]]; then
        _ui_subheader "Phase 1/3: Deleting Exports" 0
        for i in "${!EXPORT_IDS[@]}"; do
            local exp_id="${EXPORT_IDS[$i]}"
            local exp_path="${EXPORT_PATHS[$i]}"
            local delete_cmd="oci fs export delete --export-id \"$exp_id\" --region \"$region\" --force"

            echo -e "  ${CYAN}Deleting export: ${WHITE}$exp_path${NC}"
            echo -e "  ${GRAY}$delete_cmd${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTING: $delete_cmd" >> "$log_file"
            
            local result
            log_action "DELETE" "$delete_cmd"
            result=$(oci fs export delete --export-id "$exp_id" --region "$region" --force 2>&1)
            
            if [[ $? -eq 0 ]]; then
                echo -e "  ${GREEN}✓ Export deleted${NC}"
                log_action_result "SUCCESS" "DELETE operation"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted export $exp_id" >> "$log_file"
            else
                echo -e "  ${RED}✗ Failed to delete export: $result${NC}"
                log_action_result "FAILED" "DELETE operation"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete export $exp_id - $result" >> "$log_file"
            fi
        done
        echo ""
        
        # Brief wait for export deletions to propagate
        echo -e "${GRAY}Waiting 5s for export deletions to propagate...${NC}"
        sleep 5
    fi
    
    # ==================== Phase 2: Delete Mount Targets ====================
    if [[ $mt_delete_count -gt 0 ]]; then
        _ui_subheader "Phase 2/3: Deleting Mount Targets" 0
        for mt_id in $(printf '%s\n' "${!MT_CAN_DELETE[@]}"); do
            [[ "${MT_CAN_DELETE[$mt_id]}" != "true" ]] && continue
            
            local mt_name="${MT_NAMES[$mt_id]}"
            local delete_cmd="oci fs mount-target delete --mount-target-id \"$mt_id\" --region \"$region\" --force"
            
            echo -e "  ${CYAN}Deleting mount target: ${WHITE}$mt_name${NC}"
            echo -e "  ${GRAY}$delete_cmd${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTING: $delete_cmd" >> "$log_file"
            
            local result
            log_action "DELETE" "$delete_cmd"
            result=$(oci fs mount-target delete --mount-target-id "$mt_id" --region "$region" --force 2>&1)
            
            if [[ $? -eq 0 ]]; then
                echo -e "  ${GREEN}✓ Mount target deleted${NC}"
                log_action_result "SUCCESS" "DELETE operation"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted mount target $mt_id" >> "$log_file"
            else
                echo -e "  ${RED}✗ Failed to delete mount target: $result${NC}"
                log_action_result "FAILED" "DELETE operation"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete mount target $mt_id - $result" >> "$log_file"
            fi
        done
        echo ""
    else
        _ui_subheader "Phase 2/3: No Mount Targets to Delete (shared)" 0
        echo ""
    fi
    
    # ==================== Phase 3: Delete File System ====================
    _ui_subheader "Phase 3/3: Deleting File System" 0
    local delete_cmd="oci fs file-system delete --file-system-id \"$fs_id\" --region \"$region\" --force"
    echo -e "  ${CYAN}Deleting file system: ${WHITE}$fs_name${NC}"
    echo -e "  ${GRAY}$delete_cmd${NC}"
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTING: $delete_cmd" >> "$log_file"
    
    local result
    log_action "DELETE" "$delete_cmd"
    result=$(oci fs file-system delete --file-system-id "$fs_id" --region "$region" --force 2>&1)
    
    if [[ $? -eq 0 ]]; then
        echo -e "  ${GREEN}✓ File system deletion initiated${NC}"
        log_action_result "SUCCESS" "DELETE operation"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted file system $fs_id" >> "$log_file"
    else
        echo -e "  ${RED}✗ Failed to delete file system: $result${NC}"
        log_action_result "FAILED" "DELETE operation"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete file system $fs_id - $result" >> "$log_file"
    fi
    
    echo ""
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] RECURSIVE DELETE COMPLETED for: $fs_name ($fs_id)" >> "$log_file"
    echo -e "${GREEN}Recursive delete complete.${NC}"
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Manage File Storage - Main menu
#--------------------------------------------------------------------------------
manage_file_storage() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local ad="${AVAILABILITY_DOMAIN:-}"
    local region="${FOCUS_REGION:-$REGION}"
    local force_refresh=""
    
    while true; do
        echo ""
        _ui_menu_header "FILE STORAGE SERVICE (FSS)" \
            --color "$BLUE" \
            --breadcrumb "Storage" "File Storage" \
            --cmd "oci fs file-system list | oci fs file-system get | oci fs mount-target list | oci fs mount-target get | oci fs export list --compartment-id \$COMPARTMENT_ID | oci network private-ip get" \
            --env
        [[ -n "$ad" ]] && echo -e "  ${CYAN}AD:${NC}          ${WHITE}${ad}${NC}"
        
        # Show overview with data
        fss_show_overview "$compartment_id" "$force_refresh"
        force_refresh=""
        
        _ui_actions "Selection Options"
        echo -e "  ${YELLOW}f#${NC}        - View file system details (e.g., ${YELLOW}f1${NC})"
        echo -e "  ${YELLOW}m#${NC}        - View mount target details (e.g., ${YELLOW}m1${NC})"
        echo -e "  ${YELLOW}e#${NC}        - View export details (e.g., ${YELLOW}e1${NC})"
        echo ""
        echo -e "  ${GREEN}setup${NC}     - Guided setup wizard (FS → Mount Target → Export)"
        echo -e "  ${GREEN}cf${NC}        - Create file system"
        echo -e "  ${GREEN}cm${NC}        - Create mount target"
        echo -e "  ${GREEN}ce${NC}        - Create export"
        echo -e "  ${GREEN}cs${NC}        - Create snapshot"
        echo ""
        echo -e "  ${RED}df#${NC}       - Delete file system + exports + mount target (e.g., ${RED}df1${NC})"
        echo -e "  ${RED}dm#${NC}       - Delete mount target (e.g., ${RED}dm1${NC})"
        echo -e "  ${RED}de#${NC}       - Delete export (e.g., ${RED}de1${NC})"
        echo ""
        echo -e "  ${MAGENTA}r${NC}         - Reload FSS data"
        echo -e "  ${CYAN}b${NC}         - Back to main menu"
        echo ""
        _ui_prompt "File Storage" "#, r, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        [[ -z "$selection" || "$selection" == "b" || "$selection" == "B" ]] && return 0

        # Show menu again
        [[ "$selection" == "show" || "$selection" == "SHOW" ]] && continue
        
        # Refresh
        if [[ "$selection" == "r" || "$selection" == "R" || "$selection" == "refresh" ]]; then
            rm -f "$FSS_FS_CACHE" "$FSS_MT_CACHE" "$FSS_EXPORT_CACHE" "$FSS_MT_IP_CACHE"
            force_refresh="true"
            continue
        fi
        
        # Create commands
        if [[ "$selection" == "setup" || "$selection" == "SETUP" ]]; then
            fss_guided_setup "$compartment_id" "$ad"
            rm -f "$FSS_FS_CACHE" "$FSS_MT_CACHE" "$FSS_EXPORT_CACHE" "$FSS_MT_IP_CACHE"
            force_refresh="true"
            continue
        fi
        if [[ "$selection" == "cf" ]]; then
            fss_create_file_system "$compartment_id" "$ad"
            rm -f "$FSS_FS_CACHE"
            force_refresh="true"
            continue
        fi
        if [[ "$selection" == "cm" ]]; then
            fss_create_mount_target "$compartment_id" "$ad"
            rm -f "$FSS_MT_CACHE" "$FSS_MT_IP_CACHE"
            force_refresh="true"
            continue
        fi
        if [[ "$selection" == "ce" ]]; then
            fss_create_export "$compartment_id" "$ad"
            rm -f "$FSS_EXPORT_CACHE"
            force_refresh="true"
            continue
        fi
        if [[ "$selection" == "cs" ]]; then
            fss_create_snapshot "$compartment_id" "$ad"
            continue
        fi
        
        # View file system: f#
        if [[ "$selection" =~ ^f([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_FS_MAP[$sel_idx]}" ]]; then
                fss_show_file_system_detail "${FSS_FS_MAP[$sel_idx]}"
            else
                echo -e "${RED}Invalid file system number: f${sel_idx}${NC}"
            fi
            continue
        fi
        
        # View mount target: m#
        if [[ "$selection" =~ ^m([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_MT_MAP[$sel_idx]}" ]]; then
                fss_show_mount_target_detail "${FSS_MT_MAP[$sel_idx]}"
            else
                echo -e "${RED}Invalid mount target number: m${sel_idx}${NC}"
            fi
            continue
        fi
        
        # View export: e#
        if [[ "$selection" =~ ^e([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_EXPORT_MAP[$sel_idx]}" ]]; then
                fss_show_export_detail "${FSS_EXPORT_MAP[$sel_idx]}"
            else
                echo -e "${RED}Invalid export number: e${sel_idx}${NC}"
            fi
            continue
        fi
        
        # Delete file system: df# (recursive - exports + mount target + FS)
        if [[ "$selection" =~ ^df([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_FS_MAP[$sel_idx]}" ]]; then
                fss_recursive_delete_file_system "$compartment_id" "${FSS_FS_MAP[$sel_idx]}"
                rm -f "$FSS_FS_CACHE" "$FSS_MT_CACHE" "$FSS_EXPORT_CACHE" "$FSS_MT_IP_CACHE"
                force_refresh="true"
            else
                echo -e "${RED}Invalid file system number: df${sel_idx}${NC}"
            fi
            continue
        fi
        
        # Delete mount target: dm#
        if [[ "$selection" =~ ^dm([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_MT_MAP[$sel_idx]}" ]]; then
                FSS_SELECTED_MT="${FSS_MT_MAP[$sel_idx]}"
                fss_delete_mount_target_direct "$compartment_id"
                rm -f "$FSS_MT_CACHE" "$FSS_MT_IP_CACHE"
                force_refresh="true"
            else
                echo -e "${RED}Invalid mount target number: dm${sel_idx}${NC}"
            fi
            continue
        fi
        
        # Delete export: de#
        if [[ "$selection" =~ ^de([0-9]+)$ ]]; then
            local sel_idx="${BASH_REMATCH[1]}"
            if [[ -n "${FSS_EXPORT_MAP[$sel_idx]}" ]]; then
                FSS_SELECTED_EXPORT="${FSS_EXPORT_MAP[$sel_idx]}"
                fss_delete_export_direct "$compartment_id"
                rm -f "$FSS_EXPORT_CACHE"
                force_refresh="true"
            else
                echo -e "${RED}Invalid export number: de${sel_idx}${NC}"
            fi
            continue
        fi
        
        echo -e "${RED}Invalid selection${NC}"
    done
}
#--------------------------------------------------------------------------------
# FSS - Show Overview (Hierarchical: Mount Targets → Exports → File Systems)
#--------------------------------------------------------------------------------
fss_show_overview() {
    local compartment_id="$1"
    local force_refresh="${2:-false}"
    
    # Fetch and cache FSS data
    fetch_fss_data "$compartment_id" "$force_refresh"
    
    # Clear global maps
    declare -gA FSS_FS_MAP
    declare -gA FSS_MT_MAP
    declare -gA FSS_EXPORT_MAP
    declare -gA FSS_FS_NAMES
    FSS_FS_MAP=()
    FSS_MT_MAP=()
    FSS_EXPORT_MAP=()
    FSS_FS_NAMES=()
    
    local fs_idx=0
    local mt_idx=0
    local export_idx=0
    
    #---------------------------------------------------------------------------
    # Load data from caches
    #---------------------------------------------------------------------------
    local all_fs_json="[]"
    if [[ -f "$FSS_FS_CACHE" ]]; then
        all_fs_json=$(jq '.data // []' "$FSS_FS_CACHE" 2>/dev/null) || all_fs_json="[]"
    fi
    
    local all_mt_json="[]"
    if [[ -f "$FSS_MT_CACHE" ]]; then
        all_mt_json=$(jq '.data // []' "$FSS_MT_CACHE" 2>/dev/null) || all_mt_json="[]"
    fi
    
    local all_export_json='{"data":[]}'
    if [[ -f "$FSS_EXPORT_CACHE" ]]; then
        all_export_json=$(cat "$FSS_EXPORT_CACHE" 2>/dev/null) || all_export_json='{"data":[]}'
    fi
    
    # Load private IPs from cache (populated during fetch_fss_data)
    declare -A MT_IPS
    if [[ -f "$FSS_MT_IP_CACHE" ]]; then
        while IFS='|' read -r mt_id ip_addr; do
            [[ -z "$mt_id" ]] && continue
            MT_IPS[$mt_id]="$ip_addr"
        done < "$FSS_MT_IP_CACHE"
    fi
    
    # Build file system lookup
    declare -A FS_INFO  # fs_id -> "name|state|metered_bytes|ad"
    while IFS='|' read -r fs_id fs_name fs_state fs_bytes fs_ad; do
        [[ -z "$fs_id" ]] && continue
        FS_INFO[$fs_id]="$fs_name|$fs_state|$fs_bytes|$fs_ad"
    done < <(jq -r '.[] | "\(.id)|\(.["display-name"])|\(.["lifecycle-state"])|\(.["metered-bytes"])|\(.["availability-domain"])"' <<< "$all_fs_json" 2>/dev/null)
    
    # Build export lookup by export-set-id
    declare -A EXPORTS_BY_SET  # export_set_id -> "export_id|path|fs_id;export_id|path|fs_id;..."
    while IFS='|' read -r export_id export_path export_set_id fs_id export_state; do
        [[ -z "$export_id" ]] && continue
        if [[ -n "${EXPORTS_BY_SET[$export_set_id]}" ]]; then
            EXPORTS_BY_SET[$export_set_id]="${EXPORTS_BY_SET[$export_set_id]};$export_id|$export_path|$fs_id|$export_state"
        else
            EXPORTS_BY_SET[$export_set_id]="$export_id|$export_path|$fs_id|$export_state"
        fi
    done < <(jq -r '.data[] | "\(.id)|\(.path)|\(.["export-set-id"])|\(.["file-system-id"])|\(.["lifecycle-state"])"' <<< "$all_export_json" 2>/dev/null)
    
    # Track which file systems have exports
    declare -A FS_HAS_EXPORT
    
    #---------------------------------------------------------------------------
    # Display Mount Targets with Exports and File Systems
    #---------------------------------------------------------------------------
    local mt_count
    mt_count=$(jq 'length' <<< "$all_mt_json" 2>/dev/null) || mt_count=0
    
    if [[ "$mt_count" -gt 0 ]]; then
        _ui_subheader "Mount Targets with Exports" 0
        echo ""
        
        while IFS='|' read -r mt_id mt_name mt_state mt_ad export_set_id; do
            [[ -z "$mt_id" ]] && continue
            ((mt_idx++))
            
            FSS_MT_MAP[$mt_idx]="$mt_id"
            
            local mt_state_color
            mt_state_color=$(color_resource_state "$mt_state")
            
            local ad_short="${mt_ad##*:}"
            local mt_ip="${MT_IPS[$mt_id]:-N/A}"
            
            echo -e "${BOLD}${CYAN}┌──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
            echo -e "${BOLD}${CYAN}│${NC} ${YELLOW}[m${mt_idx}]${NC} ${BOLD}${WHITE}${mt_name}${NC}  ${mt_state_color}${mt_state}${NC}"
            echo -e "${BOLD}${CYAN}│${NC}     ${CYAN}IP:${NC} ${WHITE}${mt_ip}${NC}  ${CYAN}AD:${NC} ${WHITE}${ad_short}${NC}"
            echo -e "${BOLD}${CYAN}│${NC}     ${GRAY}${mt_id}${NC}"
            
            # Get exports for this mount target
            local exports="${EXPORTS_BY_SET[$export_set_id]}"
            
            if [[ -n "$exports" ]]; then
                echo -e "${BOLD}${CYAN}│${NC}"
                echo -e "${BOLD}${CYAN}│${NC}     ${BOLD}${WHITE}Exports:${NC}"
                
                # Parse exports (semicolon separated)
                IFS=';' read -ra EXPORT_ARRAY <<< "$exports"
                local exp_count=${#EXPORT_ARRAY[@]}
                local exp_i=0
                
                for export_entry in "${EXPORT_ARRAY[@]}"; do
                    ((exp_i++))
                    ((export_idx++))
                    
                    IFS='|' read -r exp_id exp_path exp_fs_id exp_state <<< "$export_entry"
                    FSS_EXPORT_MAP[$export_idx]="$exp_id"
                    
                    # Mark file system as having export
                    FS_HAS_EXPORT[$exp_fs_id]=1
                    
                    # Get file system info
                    local fs_info="${FS_INFO[$exp_fs_id]}"
                    local fs_name fs_state fs_bytes fs_ad
                    IFS='|' read -r fs_name fs_state fs_bytes fs_ad <<< "$fs_info"
                    
                    # Find fs_idx for this file system
                    local this_fs_idx=""
                    for i in "${!FSS_FS_MAP[@]}"; do
                        if [[ "${FSS_FS_MAP[$i]}" == "$exp_fs_id" ]]; then
                            this_fs_idx=$i
                            break
                        fi
                    done
                    if [[ -z "$this_fs_idx" ]]; then
                        ((fs_idx++))
                        FSS_FS_MAP[$fs_idx]="$exp_fs_id"
                        FSS_FS_NAMES[$fs_idx]="$fs_name"
                        this_fs_idx=$fs_idx
                    fi
                    
                    local exp_state_color
                    exp_state_color=$(color_resource_state "$exp_state")
                    
                    local fs_state_color
                    fs_state_color=$(color_resource_state "$fs_state")
                    
                    # Convert bytes to human readable
                    local fs_size="0 B"
                    if [[ -n "$fs_bytes" && "$fs_bytes" != "null" && "$fs_bytes" -gt 0 ]] 2>/dev/null; then
                        if [[ "$fs_bytes" -ge 1073741824 ]]; then
                            fs_size="$(echo "scale=1; $fs_bytes / 1073741824" | bc) GB"
                        elif [[ "$fs_bytes" -ge 1048576 ]]; then
                            fs_size="$(echo "scale=1; $fs_bytes / 1048576" | bc) MB"
                        elif [[ "$fs_bytes" -ge 1024 ]]; then
                            fs_size="$(echo "scale=1; $fs_bytes / 1024" | bc) KB"
                        else
                            fs_size="${fs_bytes} B"
                        fi
                    fi
                    
                    # Tree characters
                    local tree_char="├──"
                    local tree_cont="│  "
                    if [[ $exp_i -eq $exp_count ]]; then
                        tree_char="└──"
                        tree_cont="   "
                    fi
                    
                    echo -e "${BOLD}${CYAN}│${NC}     ${tree_char} ${YELLOW}[e${export_idx}]${NC} ${WHITE}${exp_path}${NC}  ${exp_state_color}${exp_state}${NC}"
                    echo -e "${BOLD}${CYAN}│${NC}     ${tree_cont}    └── ${YELLOW}[f${this_fs_idx}]${NC} ${WHITE}${fs_name:-N/A}${NC}  ${fs_state_color}${fs_state:-N/A}${NC}  ${CYAN}Size:${NC} ${WHITE}${fs_size}${NC}"
                    
                done
            else
                echo -e "${BOLD}${CYAN}│${NC}     ${GRAY}(No exports configured)${NC}"
            fi
            
            echo -e "${BOLD}${CYAN}└──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
            echo ""
            
        done < <(jq -r '.[] | "\(.id)|\(.["display-name"])|\(.["lifecycle-state"])|\(.["availability-domain"])|\(.["export-set-id"])"' <<< "$all_mt_json" 2>/dev/null)
    fi
    
    #---------------------------------------------------------------------------
    # Display Standalone File Systems (no exports)
    #---------------------------------------------------------------------------
    local standalone_fs=""
    while IFS='|' read -r fs_id fs_name fs_state fs_bytes fs_ad; do
        [[ -z "$fs_id" ]] && continue
        if [[ -z "${FS_HAS_EXPORT[$fs_id]}" ]]; then
            standalone_fs="${standalone_fs}${fs_id}|${fs_name}|${fs_state}|${fs_bytes}|${fs_ad}\n"
        fi
    done < <(jq -r '.[] | "\(.id)|\(.["display-name"])|\(.["lifecycle-state"])|\(.["metered-bytes"])|\(.["availability-domain"])"' <<< "$all_fs_json" 2>/dev/null)
    
    if [[ -n "$standalone_fs" ]]; then
        _ui_subheader "Standalone File Systems (no exports)" 0
        echo ""
        
        echo -e "${BOLD}${CYAN}┌──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        
        while IFS='|' read -r fs_id fs_name fs_state fs_bytes fs_ad; do
            [[ -z "$fs_id" ]] && continue
            ((fs_idx++))
            
            FSS_FS_MAP[$fs_idx]="$fs_id"
            FSS_FS_NAMES[$fs_idx]="$fs_name"
            
            local fs_state_color
            fs_state_color=$(color_resource_state "$fs_state")
            
            local ad_short="${fs_ad##*:}"
            
            # Convert bytes to human readable
            local fs_size="0 B"
            if [[ -n "$fs_bytes" && "$fs_bytes" != "null" && "$fs_bytes" -gt 0 ]] 2>/dev/null; then
                if [[ "$fs_bytes" -ge 1073741824 ]]; then
                    fs_size="$(echo "scale=1; $fs_bytes / 1073741824" | bc) GB"
                elif [[ "$fs_bytes" -ge 1048576 ]]; then
                    fs_size="$(echo "scale=1; $fs_bytes / 1048576" | bc) MB"
                elif [[ "$fs_bytes" -ge 1024 ]]; then
                    fs_size="$(echo "scale=1; $fs_bytes / 1024" | bc) KB"
                else
                    fs_size="${fs_bytes} B"
                fi
            fi
            
            echo -e "${BOLD}${CYAN}│${NC} ${YELLOW}[f${fs_idx}]${NC} ${WHITE}${fs_name}${NC}  ${fs_state_color}${fs_state}${NC}  ${CYAN}Size:${NC} ${WHITE}${fs_size}${NC}  ${CYAN}AD:${NC} ${WHITE}${ad_short}${NC}"
            echo -e "${BOLD}${CYAN}│${NC}      ${GRAY}${fs_id}${NC}"
            
        done < <(echo -e "$standalone_fs")
        
        echo -e "${BOLD}${CYAN}└──────────────────────────────────────────────────────────────────────────────────────────────────────────────${NC}"
        echo ""
    fi
    
    # Store counts
    FSS_FS_COUNT=$fs_idx
    FSS_MT_COUNT=$mt_idx
    FSS_EXPORT_COUNT=$export_idx
    
    #---------------------------------------------------------------------------
    # Summary
    #---------------------------------------------------------------------------
    _ui_summary
    echo -e "  Mount Targets: ${GREEN}$mt_idx${NC}"
    echo -e "  Exports:       ${GREEN}$export_idx${NC}"
    echo -e "  File Systems:  ${GREEN}$fs_idx${NC}"
    echo ""
    
    # NFS mount example
    if [[ $mt_idx -gt 0 && $export_idx -gt 0 ]]; then
        local sample_ip="${MT_IPS[${FSS_MT_MAP[1]}]:-<mount-target-ip>}"
        _ui_subheader "NFS Mount Example" 0
        echo -e "  ${GRAY}sudo mount -t nfs -o nfsvers=3 ${sample_ip}:/<export-path> /mnt/fss${NC}"
        echo ""
    fi
}

#--------------------------------------------------------------------------------
# FSS - Show File System Detail
#--------------------------------------------------------------------------------
fss_show_file_system_detail() {
    local fs_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "File System Details" 0
    _ui_oci_cmd "oci fs file-system get --file-system-id \$FS_OCID --region $region"

    _step_init
    _step_active "file system details"
    local fs_json
    fs_json=$(oci fs file-system get --file-system-id "$fs_id" --region "$region" --output json 2>&1)
    
    if [[ $? -ne 0 ]]; then
        _step_complete "file system details(failed)"
        _step_finish
        echo -e "${RED}Error getting file system: ${NC}"
        echo "$fs_json"
        return
    fi
    _step_complete "file system details"
    _step_finish
    
    local name state ad metered_bytes time_created
    name=$(jq -r '.data["display-name"] // "N/A"' <<< "$fs_json")
    state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$fs_json")
    ad=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$fs_json")
    metered_bytes=$(jq -r '.data["metered-bytes"] // 0' <<< "$fs_json")
    time_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$fs_json")
    
    local metered_gb="0"
    [[ -n "$metered_bytes" && "$metered_bytes" != "null" ]] && metered_gb=$(echo "scale=2; $metered_bytes / 1073741824" | bc 2>/dev/null || echo "0")
    
    echo -e "  ${CYAN}Name:${NC}              ${WHITE}$name${NC}"
    echo -e "  ${CYAN}State:${NC}             ${WHITE}$state${NC}"
    echo -e "  ${CYAN}Availability Domain:${NC} ${WHITE}$ad${NC}"
    echo -e "  ${CYAN}Metered Size:${NC}      ${WHITE}${metered_gb} GB${NC}"
    echo -e "  ${CYAN}Created:${NC}           ${WHITE}$time_created${NC}"
    echo -e "  ${CYAN}OCID:${NC}              ${YELLOW}$fs_id${NC}"
    echo ""
    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "File System" "j, Enter"
    local _fs_choice
    read -r _fs_choice
    [[ "${_fs_choice:-}" == :* ]] && _nav_try_jump "$_fs_choice" && return
    case "$_fs_choice" in
        j|J|json|JSON) _ui_json_viewer "File System: $name" "$fs_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "File System: $name" "$fs_json" ".data" "${_fs_choice#* }" ;;
    esac
}

#--------------------------------------------------------------------------------
# FSS - Show Mount Target Detail
#--------------------------------------------------------------------------------
fss_show_mount_target_detail() {
    local mt_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Mount Target Details" 0
    _ui_oci_cmd "oci fs mount-target get --mount-target-id \$MT_OCID --region $region"

    _step_init
    _step_active "mount target details"
    local mt_json
    mt_json=$(oci fs mount-target get --mount-target-id "$mt_id" --region "$region" --output json 2>&1)
    
    if [[ $? -ne 0 ]]; then
        _step_complete "mount target details(failed)"
        _step_finish
        echo -e "${RED}Error getting mount target: ${NC}"
        echo "$mt_json"
        return
    fi
    _step_complete "mount target details"
    
    # Get private IP
    local private_ip="N/A"
    local private_ip_ids
    private_ip_ids=$(jq -r '.data["private-ip-ids"][]' <<< "$mt_json" 2>/dev/null)
    if [[ -n "$private_ip_ids" ]]; then
        _step_active "private IP"
        local first_ip_id
        first_ip_id=$(echo "$private_ip_ids" | head -1)
        private_ip=$(oci network private-ip get --private-ip-id "$first_ip_id" --region "$region" --query 'data."ip-address"' --raw-output 2>/dev/null) || private_ip="N/A"
        _step_complete "private IP(${private_ip})"
    fi
    _step_finish
    
    local name state ad subnet_id export_set_id time_created
    name=$(jq -r '.data["display-name"] // "N/A"' <<< "$mt_json")
    state=$(jq -r '.data["lifecycle-state"] // "N/A"' <<< "$mt_json")
    ad=$(jq -r '.data["availability-domain"] // "N/A"' <<< "$mt_json")
    subnet_id=$(jq -r '.data["subnet-id"] // "N/A"' <<< "$mt_json")
    export_set_id=$(jq -r '.data["export-set-id"] // "N/A"' <<< "$mt_json")
    time_created=$(jq -r '.data["time-created"] // "N/A"' <<< "$mt_json")
    
    echo -e "  ${CYAN}Name:${NC}              ${WHITE}$name${NC}"
    echo -e "  ${CYAN}State:${NC}             ${WHITE}$state${NC}"
    echo -e "  ${CYAN}Availability Domain:${NC} ${WHITE}$ad${NC}"
    echo -e "  ${CYAN}Private IP:${NC}        ${WHITE}$private_ip${NC}"
    echo -e "  ${CYAN}Subnet OCID:${NC}       ${YELLOW}$subnet_id${NC}"
    echo -e "  ${CYAN}Export Set OCID:${NC}   ${YELLOW}$export_set_id${NC}"
    echo -e "  ${CYAN}Created:${NC}           ${WHITE}$time_created${NC}"
    echo -e "  ${CYAN}OCID:${NC}              ${YELLOW}$mt_id${NC}"
    echo ""
    
    # Show mount command
    if [[ "$private_ip" != "N/A" ]]; then
        _ui_subheader "Mount Command" 0
        echo -e "  ${GREEN}sudo mount -t nfs -o nfsvers=3 ${private_ip}:/<export_path> /mnt/<mount_point>${NC}"
        echo ""
    fi
    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Mount Target" "j, Enter"
    local _mt_choice
    read -r _mt_choice
    [[ "${_mt_choice:-}" == :* ]] && _nav_try_jump "$_mt_choice" && return
    case "$_mt_choice" in
        j|J|json|JSON) _ui_json_viewer "Mount Target: $name" "$mt_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Mount Target: $name" "$mt_json" ".data" "${_mt_choice#* }" ;;
    esac
}

#--------------------------------------------------------------------------------
