    echo -e "  ${CYAN}Created:${NC}           ${WHITE}$time_created${NC}"
    echo -e "  ${CYAN}OCID:${NC}              ${YELLOW}$export_id${NC}"
    echo ""
    
    # Show export options
    _ui_subheader "Export Options" 0
    jq -r '.data["export-options"][]? | "  Source: \(.source // "N/A"), Access: \(.access // "N/A"), Identity: \(.["identity-squash"] // "N/A")"' <<< "$export_json" 2>/dev/null
    echo ""
    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Export" "j, Enter"
    local _ex_choice
    read -r _ex_choice
    [[ "${_ex_choice:-}" == :* ]] && _nav_try_jump "$_ex_choice" && return
    case "$_ex_choice" in
        j|J|json|JSON) _ui_json_viewer "Export: $path" "$export_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Export: $path" "$export_json" ".data" "${_ex_choice#* }" ;;
    esac
}

#--------------------------------------------------------------------------------
# FSS - Delete Resource (mount target or export)
# Args: $1=resource_type ("mount-target"|"export")  $2=resource_ocid  $3=display_label
#--------------------------------------------------------------------------------

_fss_delete_resource() {
    local resource_type="$1"
    local resource_ocid="$2"
    local display_label="$3"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${MAINTENANCE_LOG_FILE}"

    echo ""
    _ui_subheader "Delete ${display_label}" 0
    echo ""

    local id_flag="--${resource_type}-id"
    local delete_cmd="oci fs ${resource_type} delete ${id_flag} \"${resource_ocid}\" --region \"${region}\" --force"

    echo -e "${BOLD}${WHITE}Command to Execute:${NC}"
    echo ""
    echo -e "  ${WHITE}\$ oci fs ${resource_type} delete ${id_flag} \"${resource_ocid}\" --region \"${region}\" --force${NC}"
    echo ""

    if ! _ui_confirm "DELETE" "confirm deletion"; then
        echo -e "${YELLOW}Deletion cancelled${NC}"
        return
    fi

    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTING: $delete_cmd" >> "$log_file"
    echo -e "${GRAY}$delete_cmd${NC}"

    local result
    log_action "DELETE" "$delete_cmd"
    result=$(oci fs "$resource_type" delete "$id_flag" "$resource_ocid" --region "$region" --force 2>&1)
    
    if [[ $? -eq 0 ]]; then
        echo -e "${GREEN}${display_label} deletion initiated${NC}"
        log_action_result "SUCCESS" "DELETE operation"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted $resource_ocid" >> "$log_file"
    else
        echo -e "${RED}Failed to delete ${display_label,,}: $result${NC}"
        log_action_result "FAILED" "DELETE operation"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete $resource_ocid - $result" >> "$log_file"
    fi
}

fss_delete_mount_target_direct() { _fss_delete_resource "mount-target" "$FSS_SELECTED_MT" "Mount Target"; }
fss_delete_export_direct() { _fss_delete_resource "export" "$FSS_SELECTED_EXPORT" "Export"; }


#--------------------------------------------------------------------------------
# FSS - List File Systems
#--------------------------------------------------------------------------------
fss_list_file_systems() {
    local compartment_id="$1"
    local ad="$2"
    local action="${3:-none}"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "File Systems" 0
    echo ""

    local fs_json
    local all_fs_json="[]"

    if [[ -n "$ad" ]]; then
        # Single AD specified
        local list_cmd="oci fs file-system list --compartment-id \"$compartment_id\" --availability-domain \"$ad\" --region \"$region\" --all --output json"
        echo -e "${GRAY}$list_cmd${NC}"
        echo ""

        fs_json=$(oci fs file-system list \
            --compartment-id "$compartment_id" \
            --availability-domain "$ad" \
            --region "$region" \
            --all \
            --output json 2>&1)
        
        if [[ $? -ne 0 ]]; then
            echo -e "${RED}Error listing file systems:${NC}"
            echo "$fs_json" | while IFS= read -r line; do echo -e "${RED}  $line${NC}"; done
            return 1
        fi
        
        all_fs_json=$(jq '.data // []' <<< "$fs_json" 2>/dev/null)
    else
        # No AD specified - iterate through all ADs
        echo -e "${CYAN}Getting availability domains...${NC}"
        local ads
        ads=$(fss_get_availability_domains "$compartment_id")
        
        if [[ -z "$ads" ]]; then
            echo -e "${RED}Unable to get availability domains${NC}"
            return 1
        fi
        
        while IFS= read -r ad_name; do
            [[ -z "$ad_name" ]] && continue
            
            local list_cmd="oci fs file-system list --compartment-id \"$compartment_id\" --availability-domain \"$ad_name\" --region \"$region\" --all --output json"
            echo -e "${GRAY}$list_cmd${NC}"

            fs_json=$(oci fs file-system list \
                --compartment-id "$compartment_id" \
                --availability-domain "$ad_name" \
                --region "$region" \
                --all \
                --output json 2>&1)
            
            if [[ $? -ne 0 ]]; then
                echo -e "${RED}Error listing file systems in $ad_name:${NC}"
                echo "$fs_json" | head -3 | while IFS= read -r line; do echo -e "${RED}  $line${NC}"; done
                continue
            fi
            
            local fs_data
            fs_data=$(jq '.data // []' <<< "$fs_json" 2>/dev/null)
            all_fs_json=$(echo "$all_fs_json" "$fs_data" | jq -s 'add' 2>/dev/null)
            
        done <<< "$ads"
        echo ""
    fi
    
    local fs_count
    fs_count=$(jq 'length' <<< "$all_fs_json" 2>/dev/null) || fs_count=0
    
    if [[ "$fs_count" -eq 0 ]]; then
        echo -e "${YELLOW}No file systems found${NC}"
        return 1
    fi
    
    echo -e "${GREEN}Found $fs_count file system(s)${NC}"
    echo ""
    
    _ui_table_header "%-3s %-35s %-12s %-15s %-20s %s" "#" "Display Name" "State" "Metered (GB)" "Availability Domain" "File System OCID"
    
    local idx=0
    declare -gA FSS_FS_MAP
    FSS_FS_MAP=()
    
    while IFS='|' read -r display_name state metered_bytes ad_name fs_id; do
        [[ -z "$display_name" ]] && continue
        ((idx++))
        
        FSS_FS_MAP[$idx]="$fs_id"
        
        local state_color
        state_color=$(color_resource_state "$state")
        
        local name_trunc="${display_name:0:33}"
        [[ ${#display_name} -gt 33 ]] && name_trunc="${name_trunc}.."
        
        # Convert bytes to GB
        local metered_gb="0"
        [[ -n "$metered_bytes" && "$metered_bytes" != "null" ]] && metered_gb=$(echo "scale=2; $metered_bytes / 1073741824" | bc 2>/dev/null || echo "0")
        
        # Extract AD name (last part)
        local ad_short="${ad_name##*:}"
        
        printf "${YELLOW}%-3s${NC} %-35s ${state_color}%-12s${NC} %-15s %-20s ${GRAY}%s${NC}\n" \
            "$idx" "$name_trunc" "$state" "${metered_gb}" "$ad_short" "$fs_id"
            
    done < <(jq -r '.[] | "\(.["display-name"])|\(.["lifecycle-state"])|\(.["metered-bytes"])|\(.["availability-domain"])|\(.id)"' <<< "$all_fs_json" 2>/dev/null)
    
    FSS_FS_COUNT=$idx
    echo ""
    
    case "$action" in
        none)
            _ui_pause
            ;;
        select)
            echo -n -e "${CYAN}Enter file system # (or Enter to cancel): ${NC}"
            read -r fs_selection
            if [[ -n "$fs_selection" && -n "${FSS_FS_MAP[$fs_selection]}" ]]; then
                FSS_SELECTED_FS="${FSS_FS_MAP[$fs_selection]}"
            fi
            ;;
    esac
    
    return 0
}

#--------------------------------------------------------------------------------
# FSS - Core create helpers (no interactive prompts)
# Used by both standalone cf/cm/ce commands and the guided setup wizard
#--------------------------------------------------------------------------------

# Core: create file system
# Args: $1=compartment_id $2=ad $3=display_name
# Sets: FSS_CREATED_ID on success
# Returns: 0 on success, 1 on failure
_fss_do_create_file_system() {
    local _comp="$1" _ad="$2" _name="$3"
    local _region="${FOCUS_REGION:-$REGION}"
    local _log="${LOGS_DIR}/fss_actions_$(date +%Y%m%d).log"
    local _cmd="oci fs file-system create --compartment-id \"$_comp\" --availability-domain \"$_ad\" --display-name \"$_name\" --region \"$_region\""

    echo -e "${CYAN}Creating file system...${NC}"
    log_action "CREATE" "$_cmd"
    local _result
    _result=$(oci fs file-system create \
        --compartment-id "$_comp" --availability-domain "$_ad" \
        --display-name "$_name" --region "$_region" --output json 2>&1)

    FSS_CREATED_ID=""
    if jq -e '.data.id' <<< "$_result" > /dev/null 2>&1; then
        FSS_CREATED_ID=$(jq -r '.data.id' <<< "$_result")
        echo -e "${GREEN}✓ File system created: ${WHITE}$_name${NC}"
        log_action_result "SUCCESS" "CREATE operation"
        echo -e "  ${CYAN}OCID:${NC} ${GRAY}$FSS_CREATED_ID${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Created FS $FSS_CREATED_ID" >> "$_log"
        return 0
    else
        echo -e "${RED}✗ Failed to create file system${NC}"
        log_action_result "FAILED" "CREATE operation"
        echo "$_result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $_result" >> "$_log"
        return 1
    fi
}

# Core: create mount target
# Args: $1=compartment_id $2=ad $3=subnet_id $4=display_name
# Sets: FSS_CREATED_ID, FSS_CREATED_EXPORT_SET_ID on success
# Returns: 0 on success, 1 on failure
_fss_do_create_mount_target() {
    local _comp="$1" _ad="$2" _subnet="$3" _name="$4"
    local _region="${FOCUS_REGION:-$REGION}"
    local _log="${LOGS_DIR}/fss_actions_$(date +%Y%m%d).log"
    local _cmd="oci fs mount-target create --compartment-id \"$_comp\" --availability-domain \"$_ad\" --subnet-id \"$_subnet\" --display-name \"$_name\" --region \"$_region\""

    echo -e "${CYAN}Creating mount target...${NC}"
    log_action "CREATE" "$_cmd"
    local _result
    _result=$(oci fs mount-target create \
        --compartment-id "$_comp" --availability-domain "$_ad" \
        --subnet-id "$_subnet" --display-name "$_name" \
        --region "$_region" --output json 2>&1)

    FSS_CREATED_ID=""
    FSS_CREATED_EXPORT_SET_ID=""
    if jq -e '.data.id' <<< "$_result" > /dev/null 2>&1; then
        FSS_CREATED_ID=$(jq -r '.data.id' <<< "$_result")
        FSS_CREATED_EXPORT_SET_ID=$(jq -r '.data["export-set-id"]' <<< "$_result")
        echo -e "${GREEN}✓ Mount target created: ${WHITE}$_name${NC}"
        log_action_result "SUCCESS" "CREATE operation"
        echo -e "  ${CYAN}OCID:${NC} ${GRAY}$FSS_CREATED_ID${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Created MT $FSS_CREATED_ID" >> "$_log"
        return 0
    else
        echo -e "${RED}✗ Failed to create mount target${NC}"
        log_action_result "FAILED" "CREATE operation"
        echo "$_result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $_result" >> "$_log"
        return 1
    fi
}

# Core: create export
# Args: $1=file_system_id $2=export_set_id $3=path
# Sets: FSS_CREATED_ID on success
# Returns: 0 on success, 1 on failure
_fss_do_create_export() {
    local _fs_id="$1" _es_id="$2" _path="$3"
    local _region="${FOCUS_REGION:-$REGION}"
    local _log="${LOGS_DIR}/fss_actions_$(date +%Y%m%d).log"
    local _cmd="oci fs export create --file-system-id \"$_fs_id\" --export-set-id \"$_es_id\" --path \"$_path\" --region \"$_region\""

    echo -e "${CYAN}Creating export...${NC}"
    log_action "CREATE" "$_cmd"
    local _result
    _result=$(oci fs export create \
        --file-system-id "$_fs_id" --export-set-id "$_es_id" \
        --path "$_path" --region "$_region" --output json 2>&1)

    FSS_CREATED_ID=""
    if jq -e '.data.id' <<< "$_result" > /dev/null 2>&1; then
        FSS_CREATED_ID=$(jq -r '.data.id' <<< "$_result")
        echo -e "${GREEN}✓ Export created: ${WHITE}$_path${NC}"
        log_action_result "SUCCESS" "CREATE operation"
        echo -e "  ${CYAN}OCID:${NC} ${GRAY}$FSS_CREATED_ID${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Created Export $FSS_CREATED_ID" >> "$_log"
        return 0
    else
        echo -e "${RED}✗ Failed to create export${NC}"
        log_action_result "FAILED" "CREATE operation"
        echo "$_result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $_result" >> "$_log"
        return 1
    fi
}

#--------------------------------------------------------------------------------
# FSS - Create File System
#--------------------------------------------------------------------------------
fss_create_file_system() {
    local compartment_id="$1"
    local ad="$2"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Create File System" 0
    echo ""
    
    # Get AD if not set
    if [[ -z "$ad" ]]; then
        echo -e "${CYAN}Available Availability Domains:${NC}"
        local ads_json
        ads_json=$(_get_ads_json "$compartment_id")
        
        local idx=0
        declare -A AD_MAP
        while read -r ad_name; do
            [[ -z "$ad_name" ]] && continue
            ((idx++))
            AD_MAP[$idx]="$ad_name"
            echo -e "  ${YELLOW}$idx${NC}) $ad_name"
        done < <(jq -r '.data[].name' <<< "$ads_json" 2>/dev/null)
        
        echo ""
        echo -n -e "${CYAN}Select AD #: ${NC}"
        read -r ad_selection
        ad="${AD_MAP[$ad_selection]}"
        
        if [[ -z "$ad" ]]; then
            echo -e "${RED}Invalid selection${NC}"
            return
        fi
    fi
    
    echo -n -e "${CYAN}Enter display name for file system: ${NC}"
    read -r fs_name
    
    if [[ -z "$fs_name" ]]; then
        echo -e "${RED}Display name is required${NC}"
        return
    fi
    
    echo ""
    local create_cmd="oci fs file-system create --compartment-id \"$compartment_id\" --availability-domain \"$ad\" --display-name \"$fs_name\" --region \"$region\""
    echo -e "${GRAY}Command to execute:${NC}"
    echo -e "${WHITE}$create_cmd${NC}"
    echo ""

    echo -n -e "${YELLOW}Proceed with creation? (y/N): ${NC}"
    read -r confirm

    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Cancelled${NC}"
        return
    fi

    echo ""
    _fss_do_create_file_system "$compartment_id" "$ad" "$fs_name" || true

    echo ""
    _ui_pause
}

