_ct_resolve_instance_names() {
    local source="$1"
    declare -gA CT_INST_NAMES=()
    
    # Collect unique non-N/A instance OCIDs
    local _ocids=""
    if [[ "$source" == "-" ]]; then
        _ocids=$(cat | cut -d'|' -f1 | grep '^ocid1\.instance\.' | sort -u)
    else
        _ocids=$(grep -v "^#" "$source" | cut -d'|' -f1 | grep '^ocid1\.instance\.' | sort -u)
    fi
    
    [[ -z "$_ocids" ]] && return 0
    
    local _count
    _count=$(echo "$_ocids" | wc -l)
    
    _step_active "instance names(${_count})"
    
    # ── Phase 1: Resolve from INSTANCE_LIST_CACHE (populated by c1) ──
    local _remaining_ocids="" _cache_hits=0
    if [[ -f "$INSTANCE_LIST_CACHE" ]] && is_cache_fresh "$INSTANCE_LIST_CACHE"; then
        # Build lookup from cache: OCID → display-name
        local _cache_lookup
        _cache_lookup=$(jq -r '.data[] | "\(.id)|\(.["display-name"])"' "$INSTANCE_LIST_CACHE" 2>/dev/null)
        
        if [[ -n "$_cache_lookup" ]]; then
            declare -A _cl_map=()
            while IFS='|' read -r _cl_id _cl_name; do
                [[ -n "$_cl_id" && -n "$_cl_name" ]] && _cl_map["$_cl_id"]="$_cl_name"
            done <<< "$_cache_lookup"
            
            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                if [[ -n "${_cl_map[$_oid]+x}" ]]; then
                    CT_INST_NAMES["$_oid"]="${_cl_map[$_oid]}"
                    ((_cache_hits++))
                else
                    _remaining_ocids+="${_oid}"$'\n'
                fi
            done <<< "$_ocids"
        else
            _remaining_ocids="$_ocids"
        fi
    else
        _remaining_ocids="$_ocids"
    fi
    
    # Remove trailing newline
    _remaining_ocids=$(echo "$_remaining_ocids" | sed '/^$/d')
    
    # ── Phase 2: If cache miss, populate INSTANCE_LIST_CACHE with bulk list (same as c1) ──
    local _api_resolved=0
    if [[ -n "$_remaining_ocids" ]]; then
        local _rem_count
        _rem_count=$(echo "$_remaining_ocids" | wc -l)
        
        local _region="${FOCUS_REGION:-$REGION}"
        local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
        
        # Single bulk call: oci compute instance list (same command as c1)
        local _bulk_json
        _bulk_json=$(_oci_call "instance list (name resolve)" \
            oci compute instance list \
            --compartment-id "$_compartment" \
            --region "$_region" \
            --all \
            --output json)
        
        if [[ -n "$_bulk_json" ]] && jq -e '.data' <<< "$_bulk_json" > /dev/null 2>&1; then
            # Save to INSTANCE_LIST_CACHE so c1 and future calls benefit
            echo "$_bulk_json" | _cache_write "$INSTANCE_LIST_CACHE"
            
            # Build lookup from the fresh data
            declare -A _bulk_map=()
            while IFS='|' read -r _bl_id _bl_name; do
                [[ -n "$_bl_id" && -n "$_bl_name" ]] && _bulk_map["$_bl_id"]="$_bl_name"
            done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$_bulk_json" 2>/dev/null)
            
            # Resolve remaining OCIDs from bulk data
            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                if [[ -n "${_bulk_map[$_oid]+x}" ]]; then
                    CT_INST_NAMES["$_oid"]="${_bulk_map[$_oid]}"
                    ((_api_resolved++))
                fi
            done <<< "$_remaining_ocids"
        fi
    fi
    
    local _total_resolved=$(( _cache_hits + _api_resolved ))
    if [[ $_cache_hits -gt 0 && $_api_resolved -eq 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count} cached)"
    elif [[ $_cache_hits -gt 0 && $_api_resolved -gt 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count}, ${_cache_hits} cached, ${_api_resolved} listed)"
    elif [[ $_api_resolved -gt 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count} via instance list)"
    else
        _step_complete "instance names(${_total_resolved}/${_count})"
    fi
}

#--------------------------------------------------------------------------------
# Capacity Topology - Search hosts across all fields
# Searches: instance OCID, state, details, shape, topology, HPC, net, local block
# Displays matching rows with search term highlighted
#--------------------------------------------------------------------------------
_ct_view_instance() {
    local prefill="$1"
    local instance_ocid=""
    
    if [[ -n "$prefill" && "$prefill" == ocid1.instance.* ]]; then
        instance_ocid="$prefill"
    else
        echo ""
        _ui_prompt "Instance Details" "OCID, Enter=back"
        local input
        read -r input
        [[ -z "$input" ]] && return
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        if [[ "$input" == ocid1.instance.* ]]; then
            instance_ocid="$input"
        else
            echo -e "${RED}Invalid OCID. Must start with ocid1.instance.${NC}"
            sleep 1
            return
        fi
    fi
    
    # Loop to handle refresh requests (return code 2 = refresh)
    while true; do
        display_instance_details "$instance_ocid"
        local ret=$?
        [[ -n "${_NAV_JUMP:-}" ]] && break
        [[ $ret -ne 2 ]] && break
    done
}

_ct_search_hosts() {
    local search_context="${1:-all}"  # "all", "state:VALUE", "details:VALUE"
    local _inline_term="${2:-}"
    
    while true; do
        echo ""
        local search_term="$_inline_term"
        if [[ -z "$search_term" ]]; then
            _ui_prompt "Search" "term, Enter=back"
            read -r search_term
            [[ "${search_term:-}" == :* ]] && _nav_try_jump "$search_term" && return
        fi
        _inline_term=""  # Clear after first use
        
        [[ -z "$search_term" ]] && return
        
        # If user pasted an instance OCID, show instance details instead of searching
        if [[ "$search_term" == ocid1.instance.* ]]; then
            _ct_view_instance "$search_term"
            continue
        fi
        
        # Escape regex special characters for safe grep/sed usage
        local search_escaped
        search_escaped=$(printf '%s' "$search_term" | sed 's/[.[\*^$()+?{|\\]/\\&/g')
        
        # Build the data set based on context
        local data_lines
        case "$search_context" in
            state:*)
                local filter_val="${search_context#state:}"
                data_lines=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | grep "|${filter_val}|")
                ;;
            details:*)
                local filter_val="${search_context#details:}"
                data_lines=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' -v d="$filter_val" '$3 == d')
                ;;
            *)
                data_lines=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE")
                ;;
        esac
        
        # Filter to matching lines (case-insensitive across all fields)
        local matched_lines
        matched_lines=$(echo "$data_lines" | grep -i "$search_escaped" 2>/dev/null)
        
        local match_count
        match_count=$(echo "$matched_lines" | grep -c . 2>/dev/null)
        [[ -z "$matched_lines" ]] && match_count=0
        
        echo ""
        _ui_subheader "Search Results: '${YELLOW}${search_term}${WHITE}' ($match_count matches)" 0
        echo ""
        
        if [[ "$match_count" -eq 0 ]]; then
            echo -e "  ${GRAY}No matches found for '${search_term}'${NC}"
            continue
        fi
        
        # Write matches to temp file for process substitution
        local _match_file="${TEMP_DIR}/ct_search_$$.txt"
        echo "$matched_lines" > "$_match_file"
        
        _col_build_fmt "CTOP"
        printf "${BOLD}${_CTOP_HDR_FMT}${NC}\n" "${_CTOP_HDR_ARGS[@]}"
        print_separator $_CTOP_SEP_WIDTH

        local _ct_idx=0
        declare -gA CT_HOST_MAP=()
        CT_HOST_MAP=()

        while IFS='|' read -r inst_id state details topo_id inst_shape hpc_island net_block local_block time_created time_updated bm_host_id; do
            [[ -z "$inst_id" ]] && continue
            ((_ct_idx++))

            [[ "$details" == "N/A" ]] && details="-"
            local shape_display="${inst_shape:-N/A}"
            [[ "$shape_display" == "N/A" ]] && shape_display="-"

            local hpc_display="-" net_display="-" local_display="-"
            [[ "$hpc_island" != "N/A" && -n "$hpc_island" ]] && hpc_display="..${hpc_island: -8}"
            [[ "$net_block" != "N/A" && -n "$net_block" ]] && net_display="..${net_block: -8}"
            [[ "$local_block" != "N/A" && -n "$local_block" ]] && local_display="..${local_block: -8}"

            [[ "$inst_id" == ocid1.instance.* ]] && CT_HOST_MAP[$_ct_idx]="$inst_id"

            local state_color="$GREEN"
            case "$state" in
                ACTIVE|HEALTHY) state_color="$GREEN" ;;
                DEGRADED|IMPAIRED) state_color="$YELLOW" ;;
                INACTIVE|FAILED|UNAVAILABLE) state_color="$RED" ;;
            esac

            local inst_display="-"
            [[ "$inst_id" == ocid1.instance.* ]] && inst_display="..${inst_id: -8}"

            local bm_display="-"
            [[ "${bm_host_id:-}" != "N/A" && -n "${bm_host_id:-}" ]] && bm_display="$bm_host_id"

            _col_print_row "CTOP" "$_ct_idx" "-" "$state" "$details" "$shape_display" \
                "$hpc_display" "$net_display" "$local_display" "$inst_display" "$bm_display" "$state_color"
        done < "$_match_file"
        rm -f "$_match_file" 2>/dev/null
        
        echo ""
        echo -e "  ${YELLOW}#${NC}) Instance details    ${GRAY}Search again or Enter to go back${NC}"
        _ui_prompt "Search" "#, term, Enter"
        local sel
        read -r sel
        
        [[ -z "$sel" ]] && return
        [[ "${sel:-}" == :* ]] && _nav_try_jump "$sel" && return
        
        if [[ "$sel" == ocid1.instance.* ]]; then
            _ct_view_instance "$sel"
            [[ -n "${_NAV_JUMP:-}" ]] && return
            continue
        elif [[ "$sel" =~ ^[0-9]+$ && -n "${CT_HOST_MAP[$sel]:-}" ]]; then
            _ct_view_instance "${CT_HOST_MAP[$sel]}"
            [[ -n "${_NAV_JUMP:-}" ]] && return
            continue
        fi
        
        # Treat as new search term
        search_term="$sel"
    done
}

manage_capacity_topology() {
    local tenancy_id="${TENANCY_ID:-}"
    
    while true; do
        echo ""
        _ui_menu_header "CAPACITY TOPOLOGY" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Capacity Topology" \
            --cmd "oci compute capacity-topology list --compartment-id \$TENANCY_ID --all | oci compute capacity-topology bare-metal-host list" \
            --env \
            --cache \
            "${CAPACITY_TOPOLOGY_CACHE}|Capacity Hosts"

        if [[ -z "$tenancy_id" ]]; then
            echo -e "${RED}TENANCY_ID not set. Cannot query capacity topology.${NC}"
            echo ""
            _ui_pause "return"
            return
        fi

        # ── Discovery ──
        _step_init
        if is_cache_fresh "$CAPACITY_TOPOLOGY_CACHE"; then
            _step_complete "capacity topology($(_clc "$CAPACITY_TOPOLOGY_CACHE") cached)"
        else
            _step_active "capacity topology"
            fetch_capacity_topology
            _step_complete "capacity topology($(_clc "$CAPACITY_TOPOLOGY_CACHE"))"
        fi
        _step_finish
        _display_api_refresh_status "Capacity topology data"
        
        if [[ ! -f "$CAPACITY_TOPOLOGY_CACHE" ]]; then
            echo -e "${RED}Failed to fetch capacity topology data${NC}"
            echo -e "  ${GRAY}If you expect topologies, verify IAM policy:${NC}"
            _ui_policy_hint "read capacity-topologies in compartment"
            echo ""
            _ui_pause "return"
            return
        fi

        # Count total hosts (excluding comment lines)
        local total_hosts
        total_hosts=$(grep -cv "^#" "$CAPACITY_TOPOLOGY_CACHE" 2>/dev/null)

        if [[ "${total_hosts:-0}" -eq 0 ]]; then
            local _ct_region="${FOCUS_REGION:-$REGION}"
            echo -e "${YELLOW}No capacity topologies found in ${WHITE}${_ct_region}${NC}"
            echo -e "  ${GRAY}Capacity topologies are region-specific. Use ${WHITE}env r${GRAY} to switch regions.${NC}"
            echo ""
            _ui_pause "return"
            return
        fi
        
        #-----------------------------------------------------------------------
        # RDMA Topology Overview (compact tree with shape/status counts)
        #-----------------------------------------------------------------------
        echo ""
        _ui_subheader "RDMA Topology Overview" 0
        echo ""
        
        # Aligned tree line helper
        # Args: prefix, label_color, label_text, label_pad_width, count, value_color, value
        # Visible column widths: CT=2, HPC=6, NB=10, LB=14, Shape=18
        # Target alignment column = 45; label_pad = 45 - prefix_visible
        _ro_line() {
            local prefix="$1" lcolor="$2" label="$3" lwidth="$4" count="$5" vcolor="$6" value="$7"
            echo -n -e "${prefix}${lcolor}"
            printf "%-${lwidth}s" "$label"
            echo -n -e "${NC} ${BOLD}[${WHITE}"
            printf "%3s hosts" "$count"
            echo -e "${NC}${BOLD}]${NC} ${vcolor}${value}${NC}"
        }
        
        # Capacity Topology OCID(s) at top (prefix visible=2, pad=43)
        local ro_topo_ocids
        ro_topo_ocids=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | cut -d'|' -f4 | sort -u)
        
        while IFS= read -r ro_tid; do
            [[ -z "$ro_tid" ]] && continue
            local ro_tid_cnt
            ro_tid_cnt=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' -v t="$ro_tid" '$4 == t' | wc -l)
            _ro_line "  " "${BOLD}${WHITE}" "Capacity Topology:" 43 "$ro_tid_cnt" "${YELLOW}" "$ro_tid"
        done <<< "$ro_topo_ocids"

        # Get unique HPC Islands, N/A sorted last
        local rdma_hpc_islands
        rdma_hpc_islands=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | cut -d'|' -f6 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
        
        local rdma_hpc_idx=0
        local rdma_hpc_total
        rdma_hpc_total=$(echo "$rdma_hpc_islands" | grep -c . 2>/dev/null)
        
        while IFS= read -r r_hpc_id; do
            [[ -z "$r_hpc_id" ]] && continue
            ((rdma_hpc_idx++))
            
            local r_hpc_conn="├"
            local r_hpc_pipe="│"
            [[ "$rdma_hpc_idx" -eq "$rdma_hpc_total" ]] && { r_hpc_conn="└"; r_hpc_pipe=" "; }
            
            local r_hpc_display="$r_hpc_id"
            [[ "$r_hpc_id" == "N/A" ]] && r_hpc_display="(non-RDMA)"
            
            local r_hpc_hosts
            r_hpc_hosts=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' -v h="$r_hpc_id" '$6 == h')
            local r_hpc_cnt
            r_hpc_cnt=$(echo "$r_hpc_hosts" | grep -c . 2>/dev/null)
            
            # HPC Island (prefix visible=6, pad=39)
            _ro_line "  ${r_hpc_conn}── " "${BOLD}${CYAN}" "HPC Island:" 39 "$r_hpc_cnt" "${YELLOW}" "$r_hpc_display"
            
            # Network Blocks within this HPC Island
            local r_net_blocks
            r_net_blocks=$(echo "$r_hpc_hosts" | cut -d'|' -f7 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
            local r_nb_idx=0
            local r_nb_total
            r_nb_total=$(echo "$r_net_blocks" | grep -c . 2>/dev/null)
            
            while IFS= read -r r_nb_id; do
                [[ -z "$r_nb_id" ]] && continue
                ((r_nb_idx++))
                
                local r_nb_conn="├"
                local r_nb_pipe="│"
                [[ "$r_nb_idx" -eq "$r_nb_total" ]] && { r_nb_conn="└"; r_nb_pipe=" "; }
                
                local r_nb_display="$r_nb_id"
                [[ "$r_nb_id" == "N/A" ]] && r_nb_display="(none)"
                
                local r_nb_hosts
                r_nb_hosts=$(echo "$r_hpc_hosts" | awk -F'|' -v n="$r_nb_id" '$7 == n')
                local r_nb_cnt
                r_nb_cnt=$(echo "$r_nb_hosts" | grep -c . 2>/dev/null)
                
                # Network Block (prefix visible=10, pad=35)
                _ro_line "  ${r_hpc_pipe}   ${r_nb_conn}── " "${BOLD}${MAGENTA}" "Network Block:" 35 "$r_nb_cnt" "${YELLOW}" "$r_nb_display"
                
                # Local Blocks within this Network Block
                local r_local_blocks
                r_local_blocks=$(echo "$r_nb_hosts" | cut -d'|' -f8 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
                local r_lb_idx=0
                local r_lb_total
                r_lb_total=$(echo "$r_local_blocks" | grep -c . 2>/dev/null)
                
                while IFS= read -r r_lb_id; do
                    [[ -z "$r_lb_id" ]] && continue
                    ((r_lb_idx++))
                    
                    local r_lb_conn="├"
                    local r_lb_pipe="│"
                    [[ "$r_lb_idx" -eq "$r_lb_total" ]] && { r_lb_conn="└"; r_lb_pipe=" "; }
                    
                    local r_lb_display="$r_lb_id"
                    [[ "$r_lb_id" == "N/A" ]] && r_lb_display="(none)"
                    
                    local r_lb_hosts
                    r_lb_hosts=$(echo "$r_nb_hosts" | awk -F'|' -v l="$r_lb_id" '$8 == l')
                    local r_lb_cnt
                    r_lb_cnt=$(echo "$r_lb_hosts" | grep -c . 2>/dev/null)
                    
                    # Local Block (prefix visible=14, pad=31)
                    _ro_line "  ${r_hpc_pipe}   ${r_nb_pipe}   ${r_lb_conn}── " "${BOLD}${BLUE}" "Local Block:" 31 "$r_lb_cnt" "${YELLOW}" "$r_lb_display"
                    
                    # List individual hosts under each Local Block
                    local r_host_idx=0
                    local r_host_total="$r_lb_cnt"

                    while IFS='|' read -r r_inst_id r_h_state r_h_details r_h_topo r_h_shape _r_hpc _r_nb _r_lb r_h_tcreated r_h_tupdated r_h_host_ocid; do
                        [[ -z "$r_inst_id" ]] && continue
                        ((r_host_idx++))

                        local r_host_conn="├"
                        [[ "$r_host_idx" -eq "$r_host_total" ]] && r_host_conn="└"

                        local r_state_color="$GREEN"
                        case "$r_h_state" in
                            ACTIVE|HEALTHY) r_state_color="$GREEN" ;;
                            DEGRADED|IMPAIRED) r_state_color="$YELLOW" ;;
                            INACTIVE|FAILED|UNAVAILABLE) r_state_color="$RED" ;;
                            *) r_state_color="$WHITE" ;;
                        esac

                        local r_h_shape_display="${r_h_shape:-N/A}"
                        [[ "$r_h_shape_display" == "N/A" ]] && r_h_shape_display="-"

                        local r_h_details_display="${r_h_details}"
                        [[ "$r_h_details" == "N/A" ]] && r_h_details_display="-"

                        # Instance present indicator
                        local _r_inst_flag=""
                        if [[ -n "$r_inst_id" && "$r_inst_id" != "N/A" ]]; then
                            _r_inst_flag=" ${GREEN}✓ instance${NC}"
                        fi

                        # Bare-metal host OCID
                        local _r_host_display="${r_h_host_ocid:-}"
                        [[ "$_r_host_display" == "N/A" ]] && _r_host_display=""

                        # Align [STATE] to start at Local Block OCID column
                        # Host prefix is 18 visible chars; Local Block OCID starts at col 58
                        # So shape field needs: 58 - 18 = 40 chars
                        local _r_shape_p
                        printf -v _r_shape_p '%-40s' "$r_h_shape_display"

                        # Details badge in brackets (skip if empty)
                        local _r_details_badge=""
                        [[ -n "$r_h_details_display" && "$r_h_details_display" != "-" ]] && _r_details_badge=" [${r_state_color}${r_h_details_display}${NC}]"

                        echo -e "  ${r_hpc_pipe}   ${r_nb_pipe}   ${r_lb_pipe}   ${r_host_conn}── ${CYAN}${_r_shape_p}${NC}[${r_state_color}${r_h_state}${NC}]${_r_details_badge} ${YELLOW}${_r_host_display}${NC}${_r_inst_flag}"
                    done < <(echo "$r_lb_hosts" | sort -t'|' -k5,5 -k2,2)
                    
                done <<< "$r_local_blocks"
                
            done <<< "$r_net_blocks"
            
        done <<< "$rdma_hpc_islands"
        
        echo ""
        
        #-----------------------------------------------------------------------
        #-----------------------------------------------------------------------
        # Lifecycle Summary (consolidated State + Details)
        #-----------------------------------------------------------------------
        _ui_subheader "Lifecycle Summary" 0
        printf "  ${BOLD}%-15s %-30s %8s %8s${NC}\n" "STATE" "DETAILS" "COUNT" "PERCENT"
        echo -e "  ──────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────────"
        
        # Get unique state+details combinations with counts, sorted by count descending
        while IFS='|' read -r lc_state lc_details lc_count; do
            [[ -z "$lc_state" ]] && continue
            local lc_pct
            lc_pct=$(echo "scale=1; $lc_count * 100 / $total_hosts" | bc)
            
            local lc_state_color="$WHITE"
            case "$lc_state" in
                ACTIVE|HEALTHY) lc_state_color="$GREEN" ;;
                DEGRADED|IMPAIRED) lc_state_color="$YELLOW" ;;
                INACTIVE|FAILED|UNAVAILABLE) lc_state_color="$RED" ;;
                *) lc_state_color="$GRAY" ;;
            esac
            
            local lc_det_color="$WHITE"
            case "$lc_details" in
                "(none)") lc_det_color="$GRAY" ;;
                *FAILED*|*ERROR*|*UNAVAILABLE*) lc_det_color="$RED" ;;
                *DEGRADED*|*WARNING*|*IMPAIRED*) lc_det_color="$YELLOW" ;;
                *HEALTHY*|*AVAILABLE*|*ACTIVE*) lc_det_color="$GREEN" ;;
            esac
            
            local lc_det_display="${lc_details:0:28}"
            [[ ${#lc_details} -gt 28 ]] && lc_det_display="${lc_det_display}.."
            
            printf "  ${lc_state_color}%-15s${NC} ${lc_det_color}%-30s${NC} %8s %7s%%\n" "$lc_state" "$lc_det_display" "$lc_count" "$lc_pct"
        done < <(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' '{
            state = $2
            details = ($3 == "" || $3 == "N/A") ? "(none)" : $3
            key = state "|" details
            count[key]++
        } END {
            for (k in count) printf "%s|%s\n", k, count[k]
        }' | sort -t'|' -k3 -rn)
        
        echo ""

        # ── Legend ──
        echo -e "  ${GRAY}┌────────────────────────────────────────────────────────────────────────────────────────┐${NC}"
        echo -e "  ${GRAY}│${NC} ${BOLD}${WHITE}Lifecycle Legend:${NC} ${GRAY}State/Details describe ${WHITE}bare-metal host hardware health${GRAY}, not occupancy${GRAY}│${NC}"
        echo -e "  ${GRAY}│${NC}  ${GREEN}ACTIVE/AVAILABLE${NC}  ${GRAY}= Host hardware healthy and functioning (instance may be running)   ${GRAY}│${NC}"
        echo -e "  ${GRAY}│${NC}  ${YELLOW}ACTIVE/DEGRADED${NC}   ${GRAY}= Host has hardware issues requiring attention                      ${GRAY}│${NC}"
        echo -e "  ${GRAY}│${NC}  ${RED}INACTIVE/MAINT${NC}    ${GRAY}= Host undergoing infrastructure maintenance                        ${GRAY}│${NC}"
        echo -e "  ${GRAY}│${NC}  ${GRAY}A host with an Instance OCID + AVAILABLE = instance running on healthy hardware       ${GRAY}│${NC}"
        echo -e "  ${GRAY}└────────────────────────────────────────────────────────────────────────────────────────┘${NC}"
        echo ""

        # ── Dedicated Pool ──
        _render_dedicated_pool "subheader"
        echo ""

        # ── Summary ──
        _ui_summary
        echo -e "  ${WHITE}Total Hosts:${NC} ${GREEN}$total_hosts${NC}"
        echo ""
        
        # Actions Menu
        #-----------------------------------------------------------------------
        _ui_actions
        echo -e "  ${YELLOW}1${NC}) View hosts by lifecycle state"
        echo -e "  ${YELLOW}2${NC}) View hosts by lifecycle details"
        echo -e "  ${YELLOW}3${NC}) View all hosts (detailed)"
        echo -e "  ${YELLOW}4${NC}) View RDMA topology tree (HPC Island → Network Block → Local Block)"
        echo -e "  ${CYAN}/${NC}) Search hosts"
        echo -e "  ${YELLOW}i${NC}) Instance details (paste OCID)"
        echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
        echo -e "  ${GREEN}col${NC}) Configure table columns"
        echo -e "  ${MAGENTA}r${NC}) Refresh data"
        echo -e "  ${CYAN}Enter${NC}) Return to menu"
        echo ""
        _ui_prompt "Capacity Topology" "1-4, /, i, j, col, r, Enter, show"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            1)
                capacity_topology_view_by_state
                ;;
            2)
                capacity_topology_view_by_details
                ;;
            3)
                capacity_topology_view_all_hosts
                ;;
            4)
                capacity_topology_view_rdma_tree
                ;;
            col|COL|columns|COLUMNS)
                _col_picker "CTOP" "Capacity Topology"
                ;;
            /*)
                _ct_search_hosts "all" "${choice#/}"
                ;;
            i|I)
                _ct_view_instance
                ;;
            ocid1.instance.*)
                _ct_view_instance "$choice"
                ;;
            j|J|json|JSON)
                _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data"
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data" "${choice#* }"
                ;;
            r|R)
                # Force refresh by removing cache
                rm -f "$CAPACITY_TOPOLOGY_CACHE" "$CAPACITY_TOPOLOGY_JSON_CACHE"
                echo -e "${YELLOW}Cache cleared, refreshing...${NC}"
                sleep 1
                ;;
            show|SHOW)
                continue
                ;;
            *)
                return
                ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

#--------------------------------------------------------------------------------
# Capacity Topology - View hosts filtered by lifecycle state
#--------------------------------------------------------------------------------
capacity_topology_view_by_state() {
    echo ""
    echo -e "${CYAN}Select lifecycle state to filter:${NC}"
    
    # Get unique states
    local states
    states=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | cut -d'|' -f2 | sort -u)

    local idx=0
    local -A state_map=()
    while IFS= read -r state; do
        [[ -z "$state" ]] && continue
        ((idx++))
        state_map[$idx]="$state"
        local count
        count=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | cut -d'|' -f2 | grep -c "^${state}$")
        echo -e "  ${GREEN}$idx${NC}) $state ($count hosts)"
    done <<< "$states"
    
    echo ""
    echo -n -e "${CYAN}Select #: ${NC}"
    read -r sel
    
    local selected_state="${state_map[$sel]}"
    [[ -z "$selected_state" ]] && return
    
    echo ""
    _ui_subheader "Hosts with Lifecycle State: $selected_state" 0
    
    # Resolve instance names with discovery pattern
    local _filtered_file="${TEMP_DIR}/ct_state_filtered_$$.txt"
    grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | grep "|${selected_state}|" > "$_filtered_file"
    
    local _host_ct
    _host_ct=$(wc -l < "$_filtered_file")
    
    _step_init
    _step_complete "hosts(${_host_ct})"
    _ct_resolve_instance_names "$_filtered_file"
    _step_finish
    
    echo ""
    _col_build_fmt "CTOP"
    printf "${BOLD}${_CTOP_HDR_FMT}${NC}\n" "${_CTOP_HDR_ARGS[@]}"
    print_separator $_CTOP_SEP_WIDTH

    local _ct_idx=0
    declare -gA CT_HOST_MAP=()
    CT_HOST_MAP=()

    while IFS='|' read -r inst_id state details topo_id inst_shape hpc_island net_block local_block time_created time_updated bm_host_id; do
        [[ -z "$inst_id" ]] && continue
        ((_ct_idx++))

        local state_color="$GREEN"
        case "$state" in
            ACTIVE|HEALTHY) state_color="$GREEN" ;;
            DEGRADED|IMPAIRED) state_color="$YELLOW" ;;
            INACTIVE|FAILED|UNAVAILABLE) state_color="$RED" ;;
        esac

        [[ "$details" == "N/A" ]] && details="-"
        local shape_display="${inst_shape:-N/A}"
        [[ "$shape_display" == "N/A" ]] && shape_display="-"

        local inst_name="-"
        if [[ "$inst_id" == ocid1.instance.* ]]; then
            CT_HOST_MAP[$_ct_idx]="$inst_id"
            [[ -n "${CT_INST_NAMES[$inst_id]+x}" ]] && inst_name="${CT_INST_NAMES[$inst_id]}"
        elif [[ "$inst_id" == "N/A" ]]; then
            inst_name=""
            inst_id="-"
        fi

        local hpc_display="-" net_display="-" local_display="-"
        [[ "$hpc_island" != "N/A" && -n "$hpc_island" ]] && hpc_display="..${hpc_island: -8}"
        [[ "$net_block" != "N/A" && -n "$net_block" ]] && net_display="..${net_block: -8}"
        [[ "$local_block" != "N/A" && -n "$local_block" ]] && local_display="..${local_block: -8}"

        local bm_display="-"
        [[ "$bm_host_id" != "N/A" && -n "$bm_host_id" ]] && bm_display="$bm_host_id"

        local inst_display="-"
        [[ "$inst_id" == ocid1.instance.* ]] && inst_display="..${inst_id: -8}"

        _col_print_row "CTOP" "$_ct_idx" "$inst_name" "$state" "$details" "$shape_display" \
            "$hpc_display" "$net_display" "$local_display" "$inst_display" "$bm_display" "$state_color"
    done < "$_filtered_file"
    rm -f "$_filtered_file" 2>/dev/null

    # Hidden columns notice
    if [[ $_CTOP_COL_COUNT -lt ${#_CTOP_COL_KEYS[@]} ]]; then
        local _hid=() _htotal=${#_CTOP_COL_KEYS[@]}
        declare -A _hen=(); for _ek in "${_CTOP_ENABLED_COLS[@]}"; do _hen["$_ek"]=1; done
        for _i in "${!_CTOP_COL_KEYS[@]}"; do
            [[ -z "${_hen[${_CTOP_COL_KEYS[$_i]}]:-}" ]] && _hid+=("${_CTOP_COL_LABELS[$_i]}")
        done
        local _hlist=""
        for _h in "${_hid[@]}"; do _hlist+="${_hlist:+, }$_h"; done
        echo -e "  ${GRAY}Hidden ($((_htotal - _CTOP_COL_COUNT))/${_htotal}): ${_hlist}  │  type ${YELLOW}col${GRAY} to configure${NC}"
    fi

    echo ""
    echo -e "  ${GRAY}Note: STATE/DETAILS = bare-metal host hardware health, not occupancy.${NC}"
    echo -e "  ${GRAY}AVAILABLE = hardware healthy (instance may still be running on it). DEGRADED = hardware issues.${NC}"
    echo ""
    while true; do
        echo -e "  ${YELLOW}#${NC}) Instance details    ${CYAN}/${NC}) Search    ${YELLOW}j${NC}) JSON    ${GREEN}col${NC}) Columns    ${CYAN}Enter${NC}) Return"
        _ui_prompt "State View" "#, /, j, col, Enter"
        local view_choice
        read -r view_choice

        [[ -z "$view_choice" ]] && return
        [[ "${view_choice:-}" == :* ]] && _nav_try_jump "$view_choice" && return

        case "$view_choice" in
            col|COL|columns|COLUMNS) _col_picker "CTOP" "Capacity Topology"; return ;;
            /*) _ct_search_hosts "state:${selected_state}" "${view_choice#/}"; [[ -n "${_NAV_JUMP:-}" ]] && return; return ;;
            show|SHOW) continue ;;
            j|J|json|JSON) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data"; continue ;;
            j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data" "${view_choice#* }"; continue ;;
            ocid1.instance.*) _ct_view_instance "$view_choice"; [[ -n "${_NAV_JUMP:-}" ]] && return; continue ;;
            *)
                if [[ "$view_choice" =~ ^[0-9]+$ && -n "${CT_HOST_MAP[$view_choice]:-}" ]]; then
                    _ct_view_instance "${CT_HOST_MAP[$view_choice]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                echo -e "  ${RED}Invalid selection${NC}"
                ;;
        esac
    done
}
capacity_topology_view_by_details() {
    echo ""
    echo -e "${CYAN}Select lifecycle details to filter:${NC}"
    
    # Get unique details
    local details_list
    details_list=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | cut -d'|' -f3 | sort -u)
    
    local idx=0
    declare -A details_map
    while IFS= read -r details; do
        [[ -z "$details" ]] && continue
        ((idx++))
        details_map[$idx]="$details"
        local count
        count=$(grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' -v d="$details" '$3 == d' | wc -l)
        local display="${details:0:50}"
        [[ "$details" == "N/A" ]] && display="(none)"
        echo -e "  ${GREEN}$idx${NC}) $display ($count hosts)"
    done <<< "$details_list"
    
    echo ""
    echo -n -e "${CYAN}Select #: ${NC}"
    read -r sel
    
    local selected_details="${details_map[$sel]}"
    [[ -z "$selected_details" ]] && return
    
    local display_title="$selected_details"
    [[ "$selected_details" == "N/A" ]] && display_title="(none)"
    
    echo ""
    _ui_subheader "Hosts with Lifecycle Details: $display_title" 0
    
    # Resolve instance names with discovery pattern
    local _filtered_file="${TEMP_DIR}/ct_details_filtered_$$.txt"
    grep -v "^#" "$CAPACITY_TOPOLOGY_CACHE" | awk -F'|' -v d="$selected_details" '$3 == d' > "$_filtered_file"
    
    local _host_ct
    _host_ct=$(wc -l < "$_filtered_file")
    
    _step_init
    _step_complete "hosts(${_host_ct})"
    _ct_resolve_instance_names "$_filtered_file"
    _step_finish
    
    echo ""
    _col_build_fmt "CTOP"
    printf "${BOLD}${_CTOP_HDR_FMT}${NC}\n" "${_CTOP_HDR_ARGS[@]}"
    print_separator $_CTOP_SEP_WIDTH

    local _ct_idx=0
    declare -gA CT_HOST_MAP=()
    CT_HOST_MAP=()

    while IFS='|' read -r inst_id state details topo_id inst_shape hpc_island net_block local_block time_created time_updated bm_host_id; do
        [[ -z "$inst_id" ]] && continue
        ((_ct_idx++))

        local state_color="$GREEN"
        case "$state" in
            ACTIVE|HEALTHY) state_color="$GREEN" ;;
            DEGRADED|IMPAIRED) state_color="$YELLOW" ;;
            INACTIVE|FAILED|UNAVAILABLE) state_color="$RED" ;;
        esac

        [[ "$details" == "N/A" ]] && details="-"
        local shape_display="${inst_shape:-N/A}"
        [[ "$shape_display" == "N/A" ]] && shape_display="-"

        local inst_name="-"
        if [[ "$inst_id" == ocid1.instance.* ]]; then
            CT_HOST_MAP[$_ct_idx]="$inst_id"
            [[ -n "${CT_INST_NAMES[$inst_id]+x}" ]] && inst_name="${CT_INST_NAMES[$inst_id]}"
        elif [[ "$inst_id" == "N/A" ]]; then
            inst_name=""
            inst_id="-"
        fi

        local hpc_display="-" net_display="-" local_display="-"
        [[ "$hpc_island" != "N/A" && -n "$hpc_island" ]] && hpc_display="..${hpc_island: -8}"
        [[ "$net_block" != "N/A" && -n "$net_block" ]] && net_display="..${net_block: -8}"
        [[ "$local_block" != "N/A" && -n "$local_block" ]] && local_display="..${local_block: -8}"

        local bm_display="-"
        [[ "$bm_host_id" != "N/A" && -n "$bm_host_id" ]] && bm_display="$bm_host_id"

        local inst_display="-"
        [[ "$inst_id" == ocid1.instance.* ]] && inst_display="..${inst_id: -8}"

        _col_print_row "CTOP" "$_ct_idx" "$inst_name" "$state" "$details" "$shape_display" \
            "$hpc_display" "$net_display" "$local_display" "$inst_display" "$bm_display" "$state_color"
    done < "$_filtered_file"
    rm -f "$_filtered_file" 2>/dev/null

    # Hidden columns notice
    if [[ $_CTOP_COL_COUNT -lt ${#_CTOP_COL_KEYS[@]} ]]; then
        local _hid=() _htotal=${#_CTOP_COL_KEYS[@]}
        declare -A _hen=(); for _ek in "${_CTOP_ENABLED_COLS[@]}"; do _hen["$_ek"]=1; done
        for _i in "${!_CTOP_COL_KEYS[@]}"; do
            [[ -z "${_hen[${_CTOP_COL_KEYS[$_i]}]:-}" ]] && _hid+=("${_CTOP_COL_LABELS[$_i]}")
        done
        local _hlist=""
        for _h in "${_hid[@]}"; do _hlist+="${_hlist:+, }$_h"; done
        echo -e "  ${GRAY}Hidden ($((_htotal - _CTOP_COL_COUNT))/${_htotal}): ${_hlist}  │  type ${YELLOW}col${GRAY} to configure${NC}"
    fi

    echo ""
    echo -e "  ${GRAY}Note: STATE/DETAILS = bare-metal host hardware health, not occupancy.${NC}"
    echo -e "  ${GRAY}AVAILABLE = hardware healthy (instance may still be running on it). DEGRADED = hardware issues.${NC}"
    echo ""
    while true; do
        echo -e "  ${YELLOW}#${NC}) Instance details    ${CYAN}/${NC}) Search    ${YELLOW}j${NC}) JSON    ${GREEN}col${NC}) Columns    ${CYAN}Enter${NC}) Return"
        _ui_prompt "Details View" "#, /, j, col, Enter"
        local view_choice
        read -r view_choice

        [[ -z "$view_choice" ]] && return
        [[ "${view_choice:-}" == :* ]] && _nav_try_jump "$view_choice" && return

        case "$view_choice" in
            col|COL|columns|COLUMNS) _col_picker "CTOP" "Capacity Topology"; return ;;
            /*) _ct_search_hosts "details:${selected_details}" "${view_choice#/}"; [[ -n "${_NAV_JUMP:-}" ]] && return; return ;;
            show|SHOW) continue ;;
            j|J|json|JSON) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data"; continue ;;
            j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data" "${view_choice#* }"; continue ;;
            ocid1.instance.*) _ct_view_instance "$view_choice"; [[ -n "${_NAV_JUMP:-}" ]] && return; continue ;;
            *)
                if [[ "$view_choice" =~ ^[0-9]+$ && -n "${CT_HOST_MAP[$view_choice]:-}" ]]; then
                    _ct_view_instance "${CT_HOST_MAP[$view_choice]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                echo -e "  ${RED}Invalid selection${NC}"
                ;;
        esac
    done
}

