#--------------------------------------------------------------------------------
# Capacity Topology - View RDMA topology tree
# Shows hierarchy: HPC Island → Network Block → Local Block → Hosts
#--------------------------------------------------------------------------------
capacity_topology_view_rdma_tree() {
    echo ""
    _ui_subheader "RDMA Topology Tree" 0
    echo -e "  ${GRAY}Hierarchy: HPC Island → Network Block → Local Block → Hosts${NC}"
    echo ""
    
    local cache="$CAPACITY_TOPOLOGY_CACHE"
    
    # Aligned tree line helper (same as overview but no 2-space leading indent)
    # Visible column widths: CT=2, HPC=4, NB=8, LB=12
    # Target alignment column = 43; label_pad = 43 - prefix_visible
    _rt_line() {
        local prefix="$1" lcolor="$2" label="$3" lwidth="$4" count="$5" vcolor="$6" value="$7"
        echo -n -e "${prefix}${lcolor}"
        printf "%-${lwidth}s" "$label"
        echo -n -e "${NC} ${BOLD}[${WHITE}"
        printf "%3s hosts" "$count"
        echo -e "${NC}${BOLD}]${NC} ${vcolor}${value}${NC}"
    }
    
    # Capacity Topology OCID(s) at top (prefix visible=2, pad=41)
    local rt_topo_ocids
    rt_topo_ocids=$(grep -v "^#" "$cache" | cut -d'|' -f4 | sort -u)
    
    while IFS= read -r rt_tid; do
        [[ -z "$rt_tid" ]] && continue
        local rt_tid_cnt
        rt_tid_cnt=$(grep -v "^#" "$cache" | awk -F'|' -v t="$rt_tid" '$4 == t' | wc -l)
        _rt_line "  " "${BOLD}${WHITE}" "Capacity Topology:" 41 "$rt_tid_cnt" "${YELLOW}" "$rt_tid"
    done <<< "$rt_topo_ocids"

    # Get unique HPC Islands (field 6), sort N/A last
    local hpc_islands
    hpc_islands=$(grep -v "^#" "$cache" | cut -d'|' -f6 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
    
    local hpc_idx=0
    local hpc_total
    hpc_total=$(echo "$hpc_islands" | grep -c . 2>/dev/null)
    
    while IFS= read -r hpc_id; do
        [[ -z "$hpc_id" ]] && continue
        ((hpc_idx++))
        
        local hpc_connector="├"
        local hpc_pipe="│"
        [[ "$hpc_idx" -eq "$hpc_total" ]] && { hpc_connector="└"; hpc_pipe=" "; }
        
        # Count hosts in this HPC Island
        local hpc_hosts
        hpc_hosts=$(grep -v "^#" "$cache" | awk -F'|' -v h="$hpc_id" '$6 == h')
        local hpc_host_count
        hpc_host_count=$(echo "$hpc_hosts" | grep -c . 2>/dev/null)
        
        # Display HPC Island
        local hpc_display="$hpc_id"
        [[ "$hpc_id" == "N/A" ]] && hpc_display="(non-RDMA)"
        
        # HPC Island (prefix visible=6, pad=37)
        _rt_line "  ${hpc_connector}── " "${BOLD}${CYAN}" "HPC Island:" 37 "$hpc_host_count" "${YELLOW}" "$hpc_display"
        
        # Get unique Network Blocks within this HPC Island
        local net_blocks
        net_blocks=$(echo "$hpc_hosts" | cut -d'|' -f7 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
        
        local nb_idx=0
        local nb_total
        nb_total=$(echo "$net_blocks" | grep -c . 2>/dev/null)
        
        while IFS= read -r nb_id; do
            [[ -z "$nb_id" ]] && continue
            ((nb_idx++))
            
            local nb_connector="├"
            local nb_pipe="│"
            [[ "$nb_idx" -eq "$nb_total" ]] && { nb_connector="└"; nb_pipe=" "; }
            
            # Count hosts in this Network Block
            local nb_hosts
            nb_hosts=$(echo "$hpc_hosts" | awk -F'|' -v n="$nb_id" '$7 == n')
            local nb_host_count
            nb_host_count=$(echo "$nb_hosts" | grep -c . 2>/dev/null)
            
            local nb_display="$nb_id"
            [[ "$nb_id" == "N/A" ]] && nb_display="(none)"
            
            # Network Block (prefix visible=10, pad=33)
            _rt_line "  ${hpc_pipe}   ${nb_connector}── " "${BOLD}${MAGENTA}" "Network Block:" 33 "$nb_host_count" "${YELLOW}" "$nb_display"
            
            # Get unique Local Blocks within this Network Block
            local local_blocks
            local_blocks=$(echo "$nb_hosts" | cut -d'|' -f8 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
            
            local lb_idx=0
            local lb_total
            lb_total=$(echo "$local_blocks" | grep -c . 2>/dev/null)
            
            while IFS= read -r lb_id; do
                [[ -z "$lb_id" ]] && continue
                ((lb_idx++))
                
                local lb_connector="├"
                local lb_pipe="│"
                [[ "$lb_idx" -eq "$lb_total" ]] && { lb_connector="└"; lb_pipe=" "; }
                
                # Get hosts in this Local Block
                local lb_hosts
                lb_hosts=$(echo "$nb_hosts" | awk -F'|' -v l="$lb_id" '$8 == l')
                local lb_host_count
                lb_host_count=$(echo "$lb_hosts" | grep -c . 2>/dev/null)
                
                local lb_display="$lb_id"
                [[ "$lb_id" == "N/A" ]] && lb_display="(none)"
                
                # Local Block (prefix visible=14, pad=29)
                _rt_line "  ${hpc_pipe}   ${nb_pipe}   ${lb_connector}── " "${BOLD}${BLUE}" "Local Block:" 29 "$lb_host_count" "${YELLOW}" "$lb_display"
                
                # List individual hosts
                local host_idx=0
                local host_total="$lb_host_count"
                
                while IFS='|' read -r inst_id h_state h_details h_topo h_shape _hpc _nb _lb h_tcreated h_tupdated h_host_ocid; do
                    [[ -z "$inst_id" ]] && continue
                    ((host_idx++))

                    local host_connector="├"
                    [[ "$host_idx" -eq "$host_total" ]] && host_connector="└"

                    local state_color="$GREEN"
                    case "$h_state" in
                        ACTIVE|HEALTHY) state_color="$GREEN" ;;
                        DEGRADED|IMPAIRED) state_color="$YELLOW" ;;
                        INACTIVE|FAILED|UNAVAILABLE) state_color="$RED" ;;
                        *) state_color="$WHITE" ;;
                    esac

                    local h_details_display="${h_details}"
                    [[ "$h_details" == "N/A" ]] && h_details_display="-"

                    local h_shape_display="${h_shape:-N/A}"
                    [[ "$h_shape_display" == "N/A" ]] && h_shape_display="-"

                    # Instance present indicator
                    local _h_inst_flag=""
                    if [[ -n "$inst_id" && "$inst_id" != "N/A" ]]; then
                        _h_inst_flag=" ${GREEN}✓ instance${NC}"
                    fi

                    # Align [STATE] to start at Local Block OCID column
                    # Host prefix is 18 visible chars; Local Block OCID starts at col 56
                    # So shape field needs: 56 - 18 = 38 chars
                    local _h_shape_p
                    printf -v _h_shape_p '%-38s' "$h_shape_display"

                    # Host OCID (bare-metal host)
                    local _h_host_display="${h_host_ocid:-}"
                    [[ "$_h_host_display" == "N/A" ]] && _h_host_display=""

                    # Details badge in brackets (skip if empty)
                    local _h_details_badge=""
                    [[ -n "$h_details_display" && "$h_details_display" != "-" ]] && _h_details_badge=" [${state_color}${h_details_display}${NC}]"

                    echo -e "  ${hpc_pipe}   ${nb_pipe}   ${lb_pipe}   ${host_connector}── ${CYAN}${_h_shape_p}${NC}[${state_color}${h_state}${NC}]${_h_details_badge} ${YELLOW}${_h_host_display}${NC}${_h_inst_flag}"
                done < <(echo "$lb_hosts" | sort -t'|' -k2,2)

                echo -e "  ${hpc_pipe}   ${nb_pipe}   ${lb_pipe}"
            done <<< "$local_blocks"
            
        done <<< "$net_blocks"
        
        echo -e "  ${hpc_pipe}"
    done <<< "$hpc_islands"
    
    echo ""
    echo -e "  ${CYAN}/${NC}) Search hosts    ${YELLOW}i${NC}) Instance details    ${YELLOW}j${NC}) JSON    ${CYAN}Enter${NC}) Return"
    _ui_prompt "RDMA Tree" "/, i, j, Enter, show"
    local view_choice
    read -r view_choice
    [[ "${view_choice:-}" == :* ]] && _nav_try_jump "$view_choice" && return
    case "$view_choice" in
        /*) _ct_search_hosts "all" "${view_choice#/}" ;;
        i|I) _ct_view_instance ;;
        ocid1.instance.*) _ct_view_instance "$view_choice" ;;
        j|J|json|JSON) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Capacity Topology JSON" "-f" "$CAPACITY_TOPOLOGY_JSON_CACHE" ".data" "${view_choice#* }" ;;
        show|SHOW)
            return
            ;;
    esac
}

#--------------------------------------------------------------------------------
# Compute Host helpers
#   _ch_resolve_instance_names  — resolve instance OCIDs to display names
#   _ch_view_instance           — drill into instance details
#   _ch_search_hosts            — context-aware search with CHOST column display
#--------------------------------------------------------------------------------

_ch_resolve_instance_names() {
    local source="$1"
    declare -gA CH_INST_NAMES=()

    # Collect unique non-N/A instance OCIDs (field $8 in CHOST cache)
    local _ocids=""
    if [[ "$source" == "-" ]]; then
        _ocids=$(cat | cut -d'|' -f8 | grep '^ocid1\.instance\.' | sort -u)
    else
        _ocids=$(grep -v "^#" "$source" | cut -d'|' -f8 | grep '^ocid1\.instance\.' | sort -u)
    fi

    [[ -z "$_ocids" ]] && return 0

    local _count
    _count=$(echo "$_ocids" | wc -l)

    _step_active "instance names(${_count})"

    # Phase 1: Resolve from INSTANCE_LIST_CACHE
    local _remaining_ocids="" _cache_hits=0
    if [[ -f "$INSTANCE_LIST_CACHE" ]] && is_cache_fresh "$INSTANCE_LIST_CACHE"; then
        local _cache_lookup
        _cache_lookup=$(jq -r '.data[] | "\(.id)|\(.["display-name"])"' "$INSTANCE_LIST_CACHE" 2>/dev/null)

        if [[ -n "$_cache_lookup" ]]; then
            declare -A _cl_map=()
            while IFS='|' read -r _cl_id _cl_name; do
                [[ -n "$_cl_id" && -n "$_cl_name" ]] && _cl_map["$_cl_id"]="$_cl_name"
            done <<< "$_cache_lookup"

            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                if [[ -n "${_cl_map[$_oid]+x}" ]]; then
                    CH_INST_NAMES["$_oid"]="${_cl_map[$_oid]}"
                    ((_cache_hits++))
                else
                    _remaining_ocids+="${_oid}"$'\n'
                fi
            done <<< "$_ocids"
        else
            _remaining_ocids="$_ocids"
        fi
    else
        _remaining_ocids="$_ocids"
    fi

    _remaining_ocids=$(echo "$_remaining_ocids" | sed '/^$/d')

    # Phase 2: Bulk list from API if cache miss
    local _api_resolved=0
    if [[ -n "$_remaining_ocids" ]]; then
        local _region="${FOCUS_REGION:-$REGION}"
        local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"

        local _bulk_json
        _bulk_json=$(_oci_call "instance list (name resolve)" \
            oci compute instance list \
            --compartment-id "$_compartment" \
            --region "$_region" \
            --all \
            --output json)

        if [[ -n "$_bulk_json" ]] && jq -e '.data' <<< "$_bulk_json" > /dev/null 2>&1; then
            echo "$_bulk_json" | _cache_write "$INSTANCE_LIST_CACHE"

            declare -A _bulk_map=()
            while IFS='|' read -r _bl_id _bl_name; do
                [[ -n "$_bl_id" && -n "$_bl_name" ]] && _bulk_map["$_bl_id"]="$_bl_name"
            done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$_bulk_json" 2>/dev/null)

            while IFS= read -r _oid; do
                [[ -z "$_oid" ]] && continue
                if [[ -n "${_bulk_map[$_oid]+x}" ]]; then
                    CH_INST_NAMES["$_oid"]="${_bulk_map[$_oid]}"
                    ((_api_resolved++))
                fi
            done <<< "$_remaining_ocids"
        fi
    fi

    local _total_resolved=$(( _cache_hits + _api_resolved ))
    if [[ $_cache_hits -gt 0 && $_api_resolved -eq 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count} cached)"
    elif [[ $_cache_hits -gt 0 && $_api_resolved -gt 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count}, ${_cache_hits} cached, ${_api_resolved} listed)"
    elif [[ $_api_resolved -gt 0 ]]; then
        _step_complete "instance names(${_total_resolved}/${_count} via instance list)"
    else
        _step_complete "instance names(${_total_resolved}/${_count})"
    fi
}

#--------------------------------------------------------------------------------
# Compute Host — Display full host detail view
#   Args: $1=compute host OCID
#   Returns: 0=back, 2=refresh (caller should re-call)
#--------------------------------------------------------------------------------
display_compute_host_details() {
    local host_ocid="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "COMPUTE HOST DETAILS" \
        --breadcrumb "Compute" "Compute Hosts" "Host Detail" \
        --cmd "oci compute compute-host get --compute-host-id \$HOST_OCID" \
        --env

    # ========== FETCH ==========
    _step_init
    _step_active "host"

    local host_json
    host_json=$(oci compute compute-host get --compute-host-id "$host_ocid" --region "$region" --output json 2>/dev/null)

    if [[ -z "$host_json" ]] || ! jq -e '.data' <<< "$host_json" > /dev/null 2>&1; then
        _step_complete "host(failed)"
        _step_finish
        echo -e "${RED}Failed to fetch compute host details for: ${host_ocid}${NC}"
        return 1
    fi
    _step_complete "host"
    _step_finish

    # ========== PARSE ALL FIELDS ==========
    local ch_display_name ch_state ch_health ch_shape ch_platform ch_has_impacted
    local ch_ad ch_fd ch_compartment_id
    local ch_hpc_island ch_network_block ch_local_block ch_gpu_fabric
    local ch_instance_id ch_host_group_id ch_capacity_reservation_id
    local ch_time_created ch_time_updated

    IFS=$'\t' read -r ch_display_name ch_state ch_health ch_shape ch_platform ch_has_impacted \
        ch_ad ch_fd ch_compartment_id \
        ch_hpc_island ch_network_block ch_local_block ch_gpu_fabric \
        ch_instance_id ch_host_group_id ch_capacity_reservation_id \
        ch_time_created ch_time_updated < <(jq -r '.data | [
        .["display-name"] // "N/A",
        .["lifecycle-state"] // "N/A",
        .health // "N/A",
        .shape // "N/A",
        (.platform // .["platform-type"] // "N/A"),
        (if .["impacted-component-details"] != null then "true" elif .["has-impacted-components"] == true then "true" else "false" end),
        .["availability-domain"] // "N/A",
        .["fault-domain"] // "N/A",
        .["compartment-id"] // "N/A",
        .["hpc-island-id"] // "N/A",
        .["network-block-id"] // "N/A",
        .["local-block-id"] // "N/A",
        .["gpu-memory-fabric-id"] // "N/A",
        .["instance-id"] // "N/A",
        .["compute-host-group-id"] // "N/A",
        .["capacity-reservation-id"] // "N/A",
        .["time-created"] // "N/A",
        .["time-updated"] // "N/A"
    ] | @tsv' <<< "$host_json")

    # ========== DISPLAY — Basic Info ==========
    echo ""
    _ui_subheader "Basic Info" 0

    # State coloring
    local state_color="$GREEN"
    case "$ch_state" in
        OCCUPIED) state_color="$GREEN" ;;
        AVAILABLE) state_color="$CYAN" ;;
        INACTIVE) state_color="$YELLOW" ;;
        *) state_color="$RED" ;;
    esac

    # Health coloring
    local health_color="$GREEN"
    case "$ch_health" in
        HEALTHY) health_color="$GREEN" ;;
        DEGRADED|IMPAIRED) health_color="$YELLOW" ;;
        UNHEALTHY|FAILED) health_color="$RED" ;;
    esac

    printf "  ${WHITE}%-20s${NC}${GREEN}%s${NC}\n" "Display Name:" "$ch_display_name"
    printf "  ${WHITE}%-20s${NC}${state_color}%s${NC}\n" "State:" "$ch_state"
    printf "  ${WHITE}%-20s${NC}${health_color}%s${NC}\n" "Health:" "$ch_health"
    printf "  ${WHITE}%-20s${NC}%s\n" "Shape:" "$ch_shape"
    printf "  ${WHITE}%-20s${NC}%s\n" "Platform:" "$ch_platform"
    if [[ "$ch_has_impacted" == "true" ]]; then
        printf "  ${WHITE}%-20s${NC}${RED}YES${NC}\n" "Has Impacted:"
    else
        printf "  ${WHITE}%-20s${NC}${GREEN}No${NC}\n" "Has Impacted:"
    fi
    printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "OCID:" "$host_ocid"

    # ========== DISPLAY — Impacted Components ==========
    if [[ "$ch_has_impacted" == "true" ]]; then
        local _imp_v1
        _imp_v1=$(jq -r '.data["impacted-component-details"]["impactedComponents"]["v1"] // empty' <<< "$host_json" 2>/dev/null)
        if [[ -n "$_imp_v1" ]]; then
            echo ""
            _ui_subheader "Impacted Components" 0

            local _imp_maint _imp_state _imp_cust_impact
            _imp_maint=$(jq -r '.maintenanceType // "N/A"' <<< "$_imp_v1")
            _imp_state=$(jq -r '.state // "N/A"' <<< "$_imp_v1")
            _imp_cust_impact=$(jq -r '.isCustomerImpacting // false' <<< "$_imp_v1")

            local _imp_cust_str="${GREEN}No${NC}"
            [[ "$_imp_cust_impact" == "true" ]] && _imp_cust_str="${RED}Yes${NC}"

            printf "  ${WHITE}%-22s${NC}${YELLOW}%s${NC}\n" "Maint. Type:" "$_imp_maint"
            printf "  ${WHITE}%-22s${NC}%s\n" "State:" "$_imp_state"
            printf "  ${WHITE}%-22s${NC}${_imp_cust_str}\n" "Customer Impacting:"

            local _imp_comp_count
            _imp_comp_count=$(jq -r '[.components // [] | .[]] | length' <<< "$_imp_v1")
            if [[ "${_imp_comp_count:-0}" -gt 0 ]]; then
                echo ""
                local _imp_idx=0
                while IFS=$'\t' read -r _ic_type _ic_action _ic_fault _ic_sev _ic_imp _ic_serial _ic_slot; do
                    ((_imp_idx++))
                    printf "  ${BOLD}${WHITE}Component %d/%d:${NC}\n" "$_imp_idx" "$_imp_comp_count"
                    printf "    ${WHITE}%-20s${NC}%s\n" "Type:" "$_ic_type"
                    printf "    ${WHITE}%-20s${NC}%s\n" "Action:" "$_ic_action"
                    printf "    ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Fault ID:" "$_ic_fault"
                    printf "    ${WHITE}%-20s${NC}%s\n" "Severity:" "$_ic_sev"
                    local _ic_imp_str="${GREEN}No${NC}"
                    [[ "$_ic_imp" == "true" ]] && _ic_imp_str="${RED}Yes${NC}"
                    printf "    ${WHITE}%-20s${NC}${_ic_imp_str}\n" "Impacting:"
                    if [[ -n "$_ic_serial" && "$_ic_serial" != "null" && "$_ic_serial" != "" ]]; then
                        printf "    ${WHITE}%-20s${NC}%s\n" "Serial Number:" "$_ic_serial"
                    fi
                    if [[ -n "$_ic_slot" && "$_ic_slot" != "null" && "$_ic_slot" != "" ]]; then
                        printf "    ${WHITE}%-20s${NC}%s\n" "Slot:" "$_ic_slot"
                    fi
                done < <(jq -r '.components[]? | [
                    .componentType // "N/A",
                    .action // "N/A",
                    .faultId // "N/A",
                    .severity // "N/A",
                    (.impacting // false | tostring),
                    (.locationData.serialNumber // ""),
                    (.locationData.slot // "")
                ] | @tsv' <<< "$_imp_v1")
            fi
        fi
    fi

    # ========== DISPLAY — Recycle Details ==========
    local _recycle_level
    _recycle_level=$(jq -r '.data["recycle-details"]["recycle-level"] // empty' <<< "$host_json" 2>/dev/null)
    if [[ -n "$_recycle_level" ]]; then
        echo ""
        _ui_subheader "Recycle Details" 0
        printf "  ${WHITE}%-22s${NC}${YELLOW}%s${NC}\n" "Recycle Level:" "$_recycle_level"
        local _recycle_hg
        _recycle_hg=$(jq -r '.data["recycle-details"]["compute-host-group-id"] // empty' <<< "$host_json" 2>/dev/null)
        if [[ -n "$_recycle_hg" && "$_recycle_hg" != "null" ]]; then
            printf "  ${WHITE}%-22s${NC}%s\n" "Host Group:" "$_recycle_hg"
        fi
    fi

    # ========== DISPLAY — Location ==========
    echo ""
    _ui_subheader "Location" 0

    # AD → short form
    local ad_short="$ch_ad"
    [[ "$ch_ad" == *:* ]] && ad_short="${ch_ad##*:}"

    # FD → short form
    local fd_short="$ch_fd"
    [[ "$ch_fd" == *FAULT-DOMAIN-* ]] && fd_short="FD-${ch_fd##*FAULT-DOMAIN-}"

    printf "  ${WHITE}%-20s${NC}%s\n" "Availability Domain:" "$ad_short"
    printf "  ${WHITE}%-20s${NC}%s\n" "Fault Domain:" "$fd_short"
    if [[ "$ch_compartment_id" != "N/A" ]]; then
        printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Compartment:" "$ch_compartment_id"
    fi

    # ========== DISPLAY — Topology ==========
    if [[ "$ch_hpc_island" != "N/A" || "$ch_network_block" != "N/A" || "$ch_local_block" != "N/A" ]]; then
        echo ""
        _ui_subheader "RDMA Topology" 0

        if [[ "$ch_hpc_island" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "HPC Island:" "$ch_hpc_island"
        fi
        if [[ "$ch_network_block" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Network Block:" "$ch_network_block"
        fi
        if [[ "$ch_local_block" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Local Block:" "$ch_local_block"
        fi
    fi

    # ========== DISPLAY — GPU ==========
    if [[ "$ch_gpu_fabric" != "N/A" ]]; then
        echo ""
        _ui_subheader "GPU" 0
        printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC} ${GRAY}[fabric-${ch_gpu_fabric: -5}]${NC}\n" "GPU Memory Fabric:" "$ch_gpu_fabric"
    fi

    # ========== DISPLAY — Associations ==========
    if [[ "$ch_instance_id" != "N/A" || "$ch_host_group_id" != "N/A" || "$ch_capacity_reservation_id" != "N/A" ]]; then
        echo ""
        _ui_subheader "Associations" 0

        if [[ "$ch_instance_id" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}  ${GRAY}(type ${CYAN}i${GRAY} to drill in)${NC}\n" "Instance:" "$ch_instance_id"
        fi
        if [[ "$ch_host_group_id" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Host Group:" "$ch_host_group_id"
        fi
        if [[ "$ch_capacity_reservation_id" != "N/A" ]]; then
            printf "  ${WHITE}%-20s${NC}${YELLOW}%s${NC}\n" "Capacity Reserv.:" "$ch_capacity_reservation_id"
        fi
    fi

    # ========== DISPLAY — Timestamps ==========
    echo ""
    _ui_subheader "Timestamps" 0
    printf "  ${WHITE}%-20s${NC}%s\n" "Created:" "$ch_time_created"
    if [[ "$ch_time_updated" != "N/A" && "$ch_time_updated" != "$ch_time_created" ]]; then
        printf "  ${WHITE}%-20s${NC}%s\n" "Updated:" "$ch_time_updated"
    fi

    # ========== ACTIONS ==========
    echo ""
    _ui_actions
    if [[ "$ch_instance_id" != "N/A" ]]; then
        echo -e "  ${YELLOW}i${NC}) Instance details"
    fi
    echo -e "  ${CYAN}j${NC}) View raw JSON  |  ${CYAN}j <key>${NC}) Search JSON"
    echo -e "  ${MAGENTA}r${NC}) Refresh host details"
    echo -e "  ${CYAN}Enter${NC}) Return"
    echo ""

    local _hint="j, r, Enter"
    [[ "$ch_instance_id" != "N/A" ]] && _hint="i, j, r, Enter"
    _ui_prompt "Compute Host - ${ch_display_name}" "$_hint"

    local action
    read -r action
    [[ "${action:-}" == :* ]] && _nav_try_jump "$action" && return

    case "$action" in
        i|I)
            if [[ "$ch_instance_id" != "N/A" ]]; then
                _ch_view_instance "$ch_instance_id"
                [[ -n "${_NAV_JUMP:-}" ]] && return
            else
                echo -e "  ${YELLOW}No instance associated with this host${NC}"
            fi
            ;;
        ocid1.instance.*)
            _ch_view_instance "$action"
            [[ -n "${_NAV_JUMP:-}" ]] && return
            ;;
        j|J|json|JSON)
            _ui_json_viewer "Compute Host JSON" "$host_json" ".data"
            ;;
        j\ *|J\ *|json\ *|JSON\ *)
            _ui_json_viewer "Compute Host JSON" "$host_json" ".data" "${action#* }"
            ;;
        r|R|refresh|REFRESH)
            echo ""
            echo -e "${YELLOW}Refreshing host details...${NC}"
            return 2
            ;;
        show|SHOW) return 2 ;;
        *) return 0 ;;
    esac

    return 2
}

#--------------------------------------------------------------------------------
# Compute Host — Host detail view wrapper (validates OCID, loops on refresh)
#   Args: $1=optional prefill OCID (or empty for prompt)
#--------------------------------------------------------------------------------
_ch_view_host() {
    local prefill="${1:-}"
    local host_ocid=""

    if [[ -n "$prefill" && "$prefill" == ocid1.compute* ]]; then
        host_ocid="$prefill"
    else
        echo ""
        _ui_prompt "Host Details" "OCID, Enter=back"
        local input
        read -r input
        [[ -z "$input" ]] && return
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        if [[ "$input" == ocid1.compute* ]]; then
            host_ocid="$input"
        else
            echo -e "${RED}Invalid OCID. Must start with ocid1.compute${NC}"
            sleep 1
            return
        fi
    fi

    while true; do
        display_compute_host_details "$host_ocid"
        local ret=$?
        [[ -n "${_NAV_JUMP:-}" ]] && break
        [[ $ret -ne 2 ]] && break
    done
}

_ch_view_instance() {
    local prefill="$1"
    local instance_ocid=""

    if [[ -n "$prefill" && "$prefill" == ocid1.instance.* ]]; then
        instance_ocid="$prefill"
    else
        echo ""
        _ui_prompt "Instance Details" "OCID, Enter=back"
        local input
        read -r input
        [[ -z "$input" ]] && return
        [[ "${input:-}" == :* ]] && _nav_try_jump "$input" && return
        if [[ "$input" == ocid1.instance.* ]]; then
            instance_ocid="$input"
        else
            echo -e "${RED}Invalid OCID. Must start with ocid1.instance.${NC}"
            sleep 1
            return
        fi
    fi

    while true; do
        display_instance_details "$instance_ocid"
        local ret=$?
        [[ -n "${_NAV_JUMP:-}" ]] && break
        [[ $ret -ne 2 ]] && break
    done
}

_ch_search_hosts() {
    local search_context="${1:-all}"  # "all", "state:VALUE", "health:VALUE", "shape:VALUE"
    local _inline_term="${2:-}"

    while true; do
        echo ""
        local search_term="$_inline_term"
        if [[ -z "$search_term" ]]; then
            _ui_prompt "Search" "term, Enter=back"
            read -r search_term
            [[ "${search_term:-}" == :* ]] && _nav_try_jump "$search_term" && return
        fi
        _inline_term=""

        [[ -z "$search_term" ]] && return

        if [[ "$search_term" == ocid1.instance.* ]]; then
            _ch_view_instance "$search_term"
            continue
        fi

        local search_escaped
        search_escaped=$(printf '%s' "$search_term" | sed 's/[.[\*^$()+?{|\\]/\\&/g')

        # Build data set based on context
        local data_lines
        case "$search_context" in
            state:*)
                local filter_val="${search_context#state:}"
                data_lines=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="$filter_val" '$2 == v')
                ;;
            health:*)
                local filter_val="${search_context#health:}"
                data_lines=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="$filter_val" '$3 == v')
                ;;
            shape:*)
                local filter_val="${search_context#shape:}"
                data_lines=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="$filter_val" '$4 == v')
                ;;
            impacted)
                data_lines=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '$16 == "true"')
                ;;
            *)
                data_lines=$(grep -v "^#" "$COMPUTE_HOST_CACHE")
                ;;
        esac

        local matched_lines
        matched_lines=$(echo "$data_lines" | grep -i "$search_escaped" 2>/dev/null)

        local match_count
        match_count=$(echo "$matched_lines" | grep -c . 2>/dev/null)
        [[ -z "$matched_lines" ]] && match_count=0

        echo ""
        _ui_subheader "Search Results: '${YELLOW}${search_term}${WHITE}' ($match_count matches)" 0
        echo ""

        if [[ "$match_count" -eq 0 ]]; then
            echo -e "  ${GRAY}No matches found for '${search_term}'${NC}"
            continue
        fi

        local _match_file="${TEMP_DIR}/ch_search_$$.txt"
        echo "$matched_lines" > "$_match_file"

        _col_build_fmt "CHOST"
        printf "${BOLD}${_CHOST_HDR_FMT}${NC}\n" "${_CHOST_HDR_ARGS[@]}"
        print_separator $_CHOST_SEP_WIDTH

        local _ch_idx=0
        declare -gA CH_HOST_MAP=()
        CH_HOST_MAP=()
        declare -gA CH_OCID_MAP=()
        CH_OCID_MAP=()
        _CH_ROW_COUNT=0

        while IFS='|' read -r display_name state health shape platform ad fd inst_id host_ocid _hpc _netblk _locblk _hostgrp _capres _gpufab has_impacted _rest; do
            [[ -z "$display_name" ]] && continue
            ((_ch_idx++))
            _ch_print_host_row "$_ch_idx" "$display_name" "$state" "$health" "$shape" \
                "$platform" "$ad" "$fd" "$inst_id" "$host_ocid" "$has_impacted" "$_gpufab"
        done < "$_match_file"
        rm -f "$_match_file" 2>/dev/null

        echo ""
        echo -e "  ${YELLOW}i#${NC}) Instance details    ${YELLOW}h#${NC}) Host details    ${CYAN}/${NC}${YELLOW}term${NC}) Search again    ${CYAN}Enter${NC}) Return"
        _ui_prompt "Search" "i#, h#, /term, Enter"
        local sel
        read -r sel

        [[ -z "$sel" ]] && return
        [[ "${sel:-}" == :* ]] && _nav_try_jump "$sel" && return

        case "$sel" in
            ocid1.instance.*)
                _ch_view_instance "$sel"
                [[ -n "${_NAV_JUMP:-}" ]] && return
                continue
                ;;
            ocid1.computecapacityhost.*|ocid1.computehost.*)
                _ch_view_host "$sel"
                [[ -n "${_NAV_JUMP:-}" ]] && return
                continue
                ;;
            h[0-9]*)
                local _hsel="${sel#h}"
                if [[ -n "${CH_OCID_MAP[$_hsel]:-}" ]]; then
                    _ch_view_host "${CH_OCID_MAP[$_hsel]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$_hsel" -ge 1 && "$_hsel" -le "$_ch_idx" ]] 2>/dev/null; then
                    echo -e "  ${RED}No host OCID for index #${_hsel}${NC}"
                else
                    echo -e "  ${RED}Invalid host index: ${sel}${NC}"
                fi
                ;;
            i[0-9]*)
                local _isel="${sel#i}"
                if [[ -n "${CH_HOST_MAP[$_isel]:-}" ]]; then
                    _ch_view_instance "${CH_HOST_MAP[$_isel]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$_isel" -ge 1 && "$_isel" -le "$_ch_idx" ]] 2>/dev/null; then
                    echo -e "  ${YELLOW}No instance running on host #${_isel}${NC}"
                else
                    echo -e "  ${RED}Invalid host index: ${sel}${NC}"
                fi
                ;;
            [0-9]*)
                if [[ -n "${CH_HOST_MAP[$sel]:-}" ]]; then
                    _ch_view_instance "${CH_HOST_MAP[$sel]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$sel" -ge 1 && "$sel" -le "$_ch_idx" ]] 2>/dev/null; then
                    echo -e "  ${YELLOW}No instance running on host #${sel}${NC}"
                fi
                ;;
        esac

        # Treat as new search term
        search_term="$sel"
    done
}

#--------------------------------------------------------------------------------
# Compute Host — Fetch K8s node data for instance→K8s mapping
#   Populates global _CH_K8S_MAP and _CH_PODS_MAP associative arrays
#   _CH_K8S_MAP[instance_ocid] = "nodeName|readyStatus|newNodeTaint|unschedulable|maintenanceTaint"
#   _CH_PODS_MAP[nodeName] = pod_count
#--------------------------------------------------------------------------------
_ch_fetch_k8s_data() {
    _CH_K8S_MAP=()
    _CH_PODS_MAP=()

    # Check if kubectl is available
    command -v kubectl &>/dev/null || return 0

    _step_active "k8s nodes"
    local _k8s_tmp="${TEMP_DIR}/ch_k8s_nodes_$$" _pods_tmp="${TEMP_DIR}/ch_k8s_pods_$$"

    (kubectl get nodes -o json > "$_k8s_tmp" 2>/dev/null) &
    local _k8s_pid=$!
    (kubectl get pods --all-namespaces --field-selector=status.phase=Running \
        -o custom-columns=NODE:.spec.nodeName --no-headers > "$_pods_tmp" 2>/dev/null) &
    local _pods_pid=$!
    wait "$_k8s_pid" 2>/dev/null
    wait "$_pods_pid" 2>/dev/null

    local _k8s_json
    _k8s_json=$(cat "$_k8s_tmp" 2>/dev/null)
    rm -f "$_k8s_tmp"

    if [[ -z "$_k8s_json" || "$_k8s_json" == "null" ]]; then
        rm -f "$_pods_tmp"
        _step_complete "k8s nodes(n/a)"
        return 0
    fi

    # Build K8s lookup: providerID|nodeName|readyStatus|newNodeTaint|unschedulable|maintenanceTaint
    local _k8s_lookup
    _k8s_lookup=$(jq -r '
        .items[] |
        (.spec.taints // [] | map(select(.key == "newNode")) | if length > 0 then .[0].effect else "N/A" end) as $newNodeTaint |
        (.spec.taints // [] | map(select(.key == "Maintenance")) | if length > 0 then .[0].effect else "N/A" end) as $maintenanceTaint |
        (.spec.unschedulable // false) as $unschedulable |
        "\(.spec.providerID)|\(.metadata.name)|\(.status.conditions[] | select(.type=="Ready") | .status)|\($newNodeTaint)|\($unschedulable)|\($maintenanceTaint)"
    ' <<< "$_k8s_json" 2>/dev/null)

    # Map by instance OCID (strip oci:// prefix from providerID)
    while IFS='|' read -r _kpid _krest; do
        [[ -z "$_kpid" ]] && continue
        local _kocid="${_kpid##*/}"
        [[ -n "$_kocid" ]] && _CH_K8S_MAP["$_kocid"]="${_krest}"
    done <<< "$_k8s_lookup"

    # Pods per node
    local _pods_per_node
    _pods_per_node=$(sort "$_pods_tmp" 2>/dev/null | uniq -c | awk '{print $2"|"$1}')
    rm -f "$_pods_tmp"

    while IFS='|' read -r _pn _pc; do
        [[ -n "$_pn" ]] && _CH_PODS_MAP["$_pn"]="$_pc"
    done <<< "$_pods_per_node"

    local _nc=${#_CH_K8S_MAP[@]}
    _step_complete "k8s nodes(${_nc})"
}

#--------------------------------------------------------------------------------
# Compute Host — Row display helper (shared by all view functions)
# Reads CHOST cache line fields, resolves display values, prints _col_print_row
#   Args: idx, pipe-delimited line (already parsed into positional vars)
#   Globals: CH_INST_NAMES (optional), CH_HOST_MAP (written), CH_OCID_MAP (written), _CH_ROW_COUNT (written)
#   Globals: _CH_K8S_MAP, _CH_PODS_MAP (read for K8s columns)
#--------------------------------------------------------------------------------
_ch_print_host_row() {
    local _idx="$1" display_name="$2" state="$3" health="$4" shape="$5" \
          platform="$6" ad="$7" fd="$8" inst_id="$9" host_ocid="${10}" has_impacted="${11:-false}" gpufab="${12:-}"
    _CH_ROW_COUNT="$_idx"

    # Append GPU memory fabric tag to shape if present
    if [[ -n "$gpufab" && "$gpufab" != "N/A" ]]; then
        shape="${shape} [fabric-${gpufab: -5}]"
    fi

    local state_color="$GREEN"
    case "$state" in
        OCCUPIED) state_color="$GREEN" ;;
        AVAILABLE) state_color="$CYAN" ;;
        INACTIVE) state_color="$YELLOW" ;;
        *) state_color="$RED" ;;
    esac

    local health_color="$GREEN"
    case "$health" in
        HEALTHY) health_color="$GREEN" ;;
        DEGRADED|IMPAIRED) health_color="$YELLOW" ;;
        UNHEALTHY|FAILED) health_color="$RED" ;;
    esac

    # Impacted indicator
    local impacted_display="-" impacted_color="$GRAY"
    if [[ "$has_impacted" == "true" ]]; then
        impacted_display="YES"
        impacted_color="$RED"
    fi

    [[ "$display_name" == "N/A" ]] && display_name="-"

    # Use resolved instance name if available
    if [[ "$inst_id" == ocid1.instance.* && -n "${CH_INST_NAMES[$inst_id]+x}" ]]; then
        display_name="${CH_INST_NAMES[$inst_id]}"
    fi

    # AD → AD1/AD2/AD3 (extract trailing digit from e.g. "jLaG:AP-SYDNEY-1-AD-1")
    local ad_short="-"
    if [[ "$ad" == *-AD-* ]]; then
        ad_short="AD${ad##*-AD-}"
    elif [[ "$ad" != "N/A" && -n "$ad" ]]; then
        ad_short="$ad"
    fi

    # FD → FD-1/FD-2/FD-3 (extract trailing digit from e.g. "FAULT-DOMAIN-3")
    local fd_short="-"
    if [[ "$fd" == *FAULT-DOMAIN-* ]]; then
        fd_short="FD-${fd##*FAULT-DOMAIN-}"
    elif [[ "$fd" != "N/A" && -n "$fd" ]]; then
        fd_short="$fd"
    fi

    # ── K8s resolution (from global _CH_K8S_MAP / _CH_PODS_MAP) ──
    local k8s_status="-" k8s_color="$GRAY"
    local cordon_status="-" cordon_color="$GRAY"
    local taint_status="-" taint_color="$GRAY"
    local pod_count="-" pod_color="$GRAY"

    if [[ "$inst_id" == ocid1.instance.* && -n "${_CH_K8S_MAP[$inst_id]+x}" ]]; then
        local _k8s_match="${_CH_K8S_MAP[$inst_id]}"
        local _k8s_node _k8s_ready _k8s_nn_taint _k8s_unsched _k8s_maint_taint
        IFS='|' read -r _k8s_node _k8s_ready _k8s_nn_taint _k8s_unsched _k8s_maint_taint <<< "$_k8s_match"

        if [[ "$_k8s_ready" == "True" ]]; then
            k8s_status="Ready"; k8s_color="$GREEN"
        else
            k8s_status="NotRdy"; k8s_color="$RED"
        fi

        if [[ "$_k8s_unsched" == "true" ]]; then
            cordon_status="Yes"; cordon_color="$YELLOW"
        fi

        local _has_n="false" _has_m="false"
        [[ "$_k8s_nn_taint" != "N/A" && -n "$_k8s_nn_taint" ]] && _has_n="true"
        [[ "$_k8s_maint_taint" != "N/A" && -n "$_k8s_maint_taint" ]] && _has_m="true"
        if [[ "$_has_n" == "true" && "$_has_m" == "true" ]]; then
            taint_status="n,m"; taint_color="$CYAN"
        elif [[ "$_has_n" == "true" ]]; then
            taint_status="newNode"; taint_color="$CYAN"
        elif [[ "$_has_m" == "true" ]]; then
            taint_status="maint"; taint_color="$MAGENTA"
        fi

        local _node_pods="${_CH_PODS_MAP[$_k8s_node]:-}"
        if [[ -n "$_node_pods" ]]; then
            pod_count="$_node_pods"; pod_color="$CYAN"
        else
            pod_count="0"; pod_color="$GRAY"
        fi
    fi

    # Host OCID → h# index mapping (unconditional, always available)
    CH_OCID_MAP[$_idx]="$host_ocid"

    # Instance OCID display + i# index mapping
    local inst_display="-"
    if [[ "$inst_id" == ocid1.instance.* ]]; then
        CH_HOST_MAP[$_idx]="$inst_id"
        inst_display="$inst_id"
    fi

    local host_display="-"
    if [[ "$host_ocid" != "N/A" && -n "$host_ocid" ]]; then
        if [[ "$has_impacted" == "true" ]]; then
            # Build compact impacted tag from lookup cache
            # Lookup format: host_ocid|maintenanceType|recycleLevel|comp1_type:action:faultId:severity;...
            local _row_imp_tag="Impacted"
            if [[ -s "${_CH_IMPACT_LOOKUP:-}" ]]; then
                local _row_imp_line
                _row_imp_line=$(grep "^${host_ocid}|" "$_CH_IMPACT_LOOKUP" 2>/dev/null | head -1)
                if [[ -n "$_row_imp_line" ]]; then
                    local _row_imp_mt _row_imp_rl _row_imp_comps _row_imp_detail=""
                    _row_imp_mt=$(echo "$_row_imp_line" | cut -d'|' -f2)
                    _row_imp_rl=$(echo "$_row_imp_line" | cut -d'|' -f3)
                    _row_imp_comps=$(echo "$_row_imp_line" | cut -d'|' -f4)
                    IFS=';' read -ra _row_imp_arr <<< "$_row_imp_comps"
                    for _ric in "${_row_imp_arr[@]}"; do
                        [[ -z "$_ric" ]] && continue
                        local _ric_type _ric_act _ric_fid _ric_sev
                        IFS=':' read -r _ric_type _ric_act _ric_fid _ric_sev <<< "$_ric"
                        [[ -n "$_row_imp_detail" ]] && _row_imp_detail+=", "
                        _row_imp_detail+="${_ric_type}/${_ric_act} ${_ric_fid}"
                    done
                    if [[ -n "$_row_imp_detail" ]]; then
                        _row_imp_tag="Impacted: ${_row_imp_detail}"
                        [[ -n "$_row_imp_rl" && "$_row_imp_rl" != "N/A" ]] && _row_imp_tag+=" | ${_row_imp_rl}"
                    fi
                fi
            fi
            host_display="${host_ocid} [${_row_imp_tag}]"
        else
            host_display="$host_ocid"
        fi
    fi

    _col_print_row "CHOST" "i${_idx}" "$display_name" "$state" "$health" "$impacted_display" "$shape" \
        "$platform" "$k8s_status" "$cordon_status" "$taint_status" "$pod_count" "$ad_short" "$fd_short" "$host_display" "$inst_display" \
        "$state_color" "$health_color" "$impacted_color" "$k8s_color" "$cordon_color" "$taint_color" "$pod_color"
}

#--------------------------------------------------------------------------------
# Compute Host — Hidden columns notice (DRY helper)
#--------------------------------------------------------------------------------
_ch_hidden_cols_notice() {
    if [[ $_CHOST_COL_COUNT -lt ${#_CHOST_COL_KEYS[@]} ]]; then
        local _hid=() _htotal=${#_CHOST_COL_KEYS[@]}
        declare -A _hen=(); for _ek in "${_CHOST_ENABLED_COLS[@]}"; do _hen["$_ek"]=1; done
        for _i in "${!_CHOST_COL_KEYS[@]}"; do
            [[ -z "${_hen[${_CHOST_COL_KEYS[$_i]}]:-}" ]] && _hid+=("${_CHOST_COL_LABELS[$_i]}")
        done
        local _hlist=""
        for _h in "${_hid[@]}"; do _hlist+="${_hlist:+, }$_h"; done
        echo -e "  ${GRAY}Hidden ($((_htotal - _CHOST_COL_COUNT))/${_htotal}): ${_hlist}  │  type ${YELLOW}col${GRAY} to configure${NC}"
    fi
}

#--------------------------------------------------------------------------------
# Compute Host — Fetch impacted host details via individual GET calls
#   Reads: $COMPUTE_HOST_CACHE (pipe-delimited), field 16=has_impacted, field 9=host OCID
#   Writes: Per-host JSON files in $COMPUTE_HOST_DETAIL_DIR/<suffix>.json
#   Uses parallel background subshells with progress bar.
#--------------------------------------------------------------------------------
_ch_fetch_impacted_details() {
    local region="${FOCUS_REGION:-$REGION}"

    # Get impacted host OCIDs
    local _imp_ocids=()
    while IFS= read -r _ocid; do
        [[ -n "$_ocid" ]] && _imp_ocids+=("$_ocid")
    done < <(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '$16 == "true" {print $9}')

    local _imp_total=${#_imp_ocids[@]}
    [[ "$_imp_total" -eq 0 ]] && return 0

    # Skip if detail cache is already populated and fresh
    [[ -z "$COMPUTE_HOST_DETAIL_DIR" || "$COMPUTE_HOST_DETAIL_DIR" != */compute_host_detail ]] && return 1
    mkdir -p "$COMPUTE_HOST_DETAIL_DIR"
    local _existing
    _existing=$(find "$COMPUTE_HOST_DETAIL_DIR" -maxdepth 1 -type f -name "*.json" 2>/dev/null | wc -l)
    if [[ "$_existing" -ge "$_imp_total" ]]; then
        # Check freshness of first file against COMPUTE_HOST_CACHE
        local _cache_mtime _detail_mtime
        _cache_mtime=$(stat -c %Y "$COMPUTE_HOST_CACHE" 2>/dev/null || echo 0)
        _detail_mtime=$(stat -c %Y "$COMPUTE_HOST_DETAIL_DIR"/*.json 2>/dev/null | head -1 || echo 0)
        if [[ "$_detail_mtime" -ge "$_cache_mtime" ]]; then
            return 0  # Detail cache is fresh
        fi
    fi

    # Parallel fetch with progress bar
    _step_active "impacted details(${_imp_total})"
    local _ch_pids=()
    for _ocid in "${_imp_ocids[@]}"; do
        local _suffix="${_ocid##*.}"
        (
            oci compute compute-host get \
                --compute-host-id "$_ocid" \
                --region "$region" \
                --output json > "$COMPUTE_HOST_DETAIL_DIR/${_suffix}.json" 2>/dev/null
        ) &
        _ch_pids+=($!)
    done

    _wait_pids "ch-detail" "${_ch_pids[@]}" || true
    _step_complete "impacted details(${_imp_total})"
}

#--------------------------------------------------------------------------------
# Compute Host — Impacted host summary below table (DRY helper)
#   Args: $1=search_context ("all", "state:VALUE", "health:VALUE", "shape:VALUE", "impacted")
#   Reads: $COMPUTE_HOST_CACHE (pipe-delimited), $COMPUTE_HOST_DETAIL_DIR (per-host get JSONs)
#   Prints: Compact impacted component + recycle details for hosts matching the filter.
#           Skips silently if no impacted hosts found.
#--------------------------------------------------------------------------------
_ch_print_impacted_summary() {
    local search_ctx="${1:-all}"

    # Get impacted host OCIDs matching the filter context
    local _imp_hosts_file="${TEMP_DIR}/ch_imp_summary_$$.txt"
    case "$search_ctx" in
        state:*)  grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="${search_ctx#state:}" '$2 == v && $16 == "true"' | cut -d'|' -f9 > "$_imp_hosts_file" ;;
        health:*) grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="${search_ctx#health:}" '$3 == v && $16 == "true"' | cut -d'|' -f9 > "$_imp_hosts_file" ;;
        shape:*)  grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="${search_ctx#shape:}" '$4 == v && $16 == "true"' | cut -d'|' -f9 > "$_imp_hosts_file" ;;
        impacted) grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '$16 == "true"' | cut -d'|' -f9 > "$_imp_hosts_file" ;;
        *)        grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '$16 == "true"' | cut -d'|' -f9 > "$_imp_hosts_file" ;;
    esac

    local _imp_ct
    _imp_ct=$(wc -l < "$_imp_hosts_file" 2>/dev/null)
    if [[ "${_imp_ct:-0}" -eq 0 ]]; then
        rm -f "$_imp_hosts_file" 2>/dev/null
        return
    fi

    echo ""
    echo -e "  ${BOLD}${RED}─── Impacted Host Details (${_imp_ct}) ───${NC}"

    while IFS= read -r _is_ocid; do
        [[ -z "$_is_ocid" ]] && continue

        # Extract shape from cache for display
        local _is_shape
        _is_shape=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v id="$_is_ocid" '$9 == id {print $4; exit}')

        # Try per-host detail cache first (compute-host get response)
        local _is_suffix="${_is_ocid##*.}"
        local _is_detail_file="$COMPUTE_HOST_DETAIL_DIR/${_is_suffix}.json"
        local _is_v1="" _is_recycle=""

        if [[ -s "$_is_detail_file" ]]; then
            _is_v1=$(jq -r '.data["impacted-component-details"]["impactedComponents"]["v1"] // empty' "$_is_detail_file" 2>/dev/null)
            _is_recycle=$(jq -r '.data["recycle-details"]["recycle-level"] // empty' "$_is_detail_file" 2>/dev/null)
        fi

        # Fallback to list JSON cache
        if [[ -z "$_is_v1" && -s "$COMPUTE_HOST_JSON_CACHE" ]]; then
            _is_v1=$(jq -r --arg hid "$_is_ocid" '
                [(.data.items // .data // [])[] | select(.id == $hid)] | .[0] |
                .["impacted-component-details"]["impactedComponents"]["v1"] // empty
            ' "$COMPUTE_HOST_JSON_CACHE" 2>/dev/null)
        fi

        if [[ -z "$_is_v1" ]]; then
            echo -e "  ${YELLOW}${_is_shape:-N/A}${NC} (${GRAY}...${_is_ocid: -12}${NC})"
            echo -e "    ${RED}Impacted${NC} — details unavailable"
            continue
        fi

        local _is_maint _is_state _is_cust
        _is_maint=$(jq -r '.maintenanceType // "N/A"' <<< "$_is_v1")
        _is_state=$(jq -r '.state // "N/A"' <<< "$_is_v1")
        _is_cust=$(jq -r '.isCustomerImpacting // false' <<< "$_is_v1")

        local _is_cust_str="${GREEN}No${NC}"
        [[ "$_is_cust" == "true" ]] && _is_cust_str="${RED}Yes${NC}"

        echo -e "  ${YELLOW}${_is_shape:-N/A}${NC} (${GRAY}...${_is_ocid: -12}${NC})"
        echo -e "    Maint: ${BOLD}${WHITE}${_is_maint}${NC} | State: ${BOLD}${WHITE}${_is_state}${NC} | Customer Impacting: ${_is_cust_str}"

        # Print recycle details if present
        if [[ -n "$_is_recycle" && "$_is_recycle" != "null" ]]; then
            echo -e "    Recycle: ${BOLD}${WHITE}${_is_recycle}${NC}"
        fi

        # Print each component on one line
        while IFS=$'\t' read -r _isc_type _isc_action _isc_fault _isc_sev; do
            echo -e "    Component: ${CYAN}${_isc_type}${NC} / ${WHITE}${_isc_action}${NC} — Fault: ${YELLOW}${_isc_fault}${NC} (${_isc_sev})"
        done < <(jq -r '.components[]? | [
            .componentType // "N/A",
            .action // "N/A",
            .faultId // "N/A",
            .severity // "N/A"
        ] | @tsv' <<< "$_is_v1")

    done < "$_imp_hosts_file"
    rm -f "$_imp_hosts_file" 2>/dev/null
}

#--------------------------------------------------------------------------------
# Compute Host — Post-table action loop (DRY helper)
#   Args: $1=view_label, $2=search_context
#--------------------------------------------------------------------------------
_ch_post_table_actions() {
    local view_label="$1" search_ctx="${2:-all}"

    # Build jq filter for JSON viewer based on search context
    local _jq_filter=".data"
    case "$search_ctx" in
        state:*)  _jq_filter="[.data[] | select(.\"lifecycle-state\" == \"${search_ctx#state:}\")]" ;;
        health:*) _jq_filter="[.data[] | select(.health == \"${search_ctx#health:}\")]" ;;
        shape:*)  _jq_filter="[.data[] | select(.shape == \"${search_ctx#shape:}\")]" ;;
        impacted) _jq_filter="[.data[] | select(.\"has-impacted-components\" == true)]" ;;
    esac

    echo ""
    while true; do
        echo -e "  ${YELLOW}i#${NC}) Instance details    ${YELLOW}h#${NC}) Host details    ${CYAN}/${NC}${YELLOW}term${NC}) Search    ${YELLOW}j${NC}) JSON    ${GREEN}col${NC}) Columns    ${CYAN}Enter${NC}) Return"
        _ui_prompt "$view_label" "i#, h#, /term, j, col, Enter"
        local view_choice
        read -r view_choice

        [[ -z "$view_choice" ]] && return
        [[ "${view_choice:-}" == :* ]] && _nav_try_jump "$view_choice" && return

        case "$view_choice" in
            col|COL|columns|COLUMNS) _col_picker "CHOST" "Compute Hosts"; return ;;
            /*) _ch_search_hosts "$search_ctx" "${view_choice#/}"; [[ -n "${_NAV_JUMP:-}" ]] && return; return ;;
            show|SHOW) continue ;;
            j|J|json|JSON)
                _ui_json_viewer "${view_label} JSON" "-f" "$COMPUTE_HOST_JSON_CACHE" "$_jq_filter"
                continue
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "${view_label} JSON" "-f" "$COMPUTE_HOST_JSON_CACHE" "$_jq_filter" "${view_choice#* }"
                continue
                ;;
            ocid1.instance.*) _ch_view_instance "$view_choice"; [[ -n "${_NAV_JUMP:-}" ]] && return; continue ;;
            ocid1.computecapacityhost.*|ocid1.computehost.*) _ch_view_host "$view_choice"; [[ -n "${_NAV_JUMP:-}" ]] && return; continue ;;
            h[0-9]*)
                local _hsel="${view_choice#h}"
                if [[ -n "${CH_OCID_MAP[$_hsel]:-}" ]]; then
                    _ch_view_host "${CH_OCID_MAP[$_hsel]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$_hsel" -ge 1 && "$_hsel" -le "${_CH_ROW_COUNT:-0}" ]] 2>/dev/null; then
                    echo -e "  ${RED}No host OCID for index #${_hsel}${NC}"
                else
                    echo -e "  ${RED}Invalid host index: ${view_choice}${NC}"
                fi
                ;;
            i[0-9]*)
                local _isel="${view_choice#i}"
                if [[ -n "${CH_HOST_MAP[$_isel]:-}" ]]; then
                    _ch_view_instance "${CH_HOST_MAP[$_isel]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$_isel" -ge 1 && "$_isel" -le "${_CH_ROW_COUNT:-0}" ]] 2>/dev/null; then
                    echo -e "  ${YELLOW}No instance running on host #${_isel}${NC}"
                else
                    echo -e "  ${RED}Invalid host index: ${view_choice}${NC}"
                fi
                ;;
            [0-9]*)
                if [[ -n "${CH_HOST_MAP[$view_choice]:-}" ]]; then
                    _ch_view_instance "${CH_HOST_MAP[$view_choice]}"
                    [[ -n "${_NAV_JUMP:-}" ]] && return
                    continue
                fi
                if [[ "$view_choice" -ge 1 && "$view_choice" -le "${_CH_ROW_COUNT:-0}" ]] 2>/dev/null; then
                    echo -e "  ${YELLOW}No instance running on host #${view_choice}${NC}"
                else
                    echo -e "  ${RED}Invalid selection: ${view_choice}${NC}"
                fi
                ;;
            *) echo -e "  ${RED}Invalid selection${NC}" ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Compute Hosts — manage_compute_hosts()
#--------------------------------------------------------------------------------
manage_compute_hosts() {
    local tenancy_id="${TENANCY_ID:-}"

    # Seed default column config (name + instance disabled) on first use
    if [[ ! -f "$CHOST_COLUMNS_CONF" ]]; then
        mkdir -p "$(dirname "$CHOST_COLUMNS_CONF")"
        printf "# Column config (auto-generated, format: key[:width])\n" > "$CHOST_COLUMNS_CONF"
        for _dk in "${_CHOST_COL_DEFAULT_ENABLED[@]}"; do
            echo "$_dk" >> "$CHOST_COLUMNS_CONF"
        done
    else
        # Migrate: add new columns if missing from existing config
        if ! grep -q "^impacted" "$CHOST_COLUMNS_CONF" 2>/dev/null; then
            sed -i '/^health$/a impacted' "$CHOST_COLUMNS_CONF" 2>/dev/null
        fi
        if ! grep -q "^instance" "$CHOST_COLUMNS_CONF" 2>/dev/null; then
            echo "instance" >> "$CHOST_COLUMNS_CONF"
        fi
        # v3.25.74: add K8s columns, remove platform from defaults
        if ! grep -q "^k8s" "$CHOST_COLUMNS_CONF" 2>/dev/null; then
            sed -i '/^shape$/a k8s\ncordon\ntaint\npods' "$CHOST_COLUMNS_CONF" 2>/dev/null
            # Remove platform from enabled list (user can re-enable via col)
            sed -i '/^platform$/d' "$CHOST_COLUMNS_CONF" 2>/dev/null
        fi
    fi

    while true; do
        echo ""
        _ui_menu_header "COMPUTE HOSTS" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Compute Hosts" \
            --cmd "oci compute compute-host list --compartment-id \$TENANCY_ID --region \$REGION --all" \
            --env \
            --cache \
            "${COMPUTE_HOST_CACHE}|Compute Hosts"

        if [[ -z "$tenancy_id" ]]; then
            echo -e "${RED}TENANCY_ID not set. Cannot query compute hosts.${NC}"
            echo ""
            _ui_pause "return"
            return
        fi

        # ── Discovery ──
        _step_init
        if is_cache_fresh "$COMPUTE_HOST_CACHE"; then
            _step_complete "compute hosts($(_clc "$COMPUTE_HOST_CACHE") cached)"
        else
            _step_active "compute hosts"
            fetch_compute_hosts
            _step_complete "compute hosts($(_clc "$COMPUTE_HOST_CACHE"))"
        fi
        _step_finish
        _display_api_refresh_status "Compute host API data"

        if [[ ! -f "$COMPUTE_HOST_CACHE" ]]; then
            echo -e "${RED}Failed to fetch compute host data${NC}"
            echo -e "  ${GRAY}If you expect hosts, verify IAM policy:${NC}"
            _ui_policy_hint "read compute-hosts in compartment"
            echo ""
            _ui_pause "return"
            return
        fi

        local total_hosts
        total_hosts=$(grep -cv "^#" "$COMPUTE_HOST_CACHE" 2>/dev/null)

        if [[ "${total_hosts:-0}" -eq 0 ]]; then
            local _ch_region="${FOCUS_REGION:-$REGION}"
            echo -e "${YELLOW}No dedicated compute hosts found in ${WHITE}${_ch_region}${NC}"
            echo -e "  ${GRAY}Compute hosts are region-specific. Use ${WHITE}env r${GRAY} to switch regions.${NC}"
            echo ""
            echo -e "  ${MAGENTA}r${NC}) Refresh data    ${CYAN}Enter${NC}) Return to menu"
            _ui_prompt "Compute Hosts" "r, Enter"
            local _empty_choice
            read -r _empty_choice
            case "$_empty_choice" in
                r|R) rm -f "$COMPUTE_HOST_CACHE"; [[ -n "$COMPUTE_HOST_DETAIL_DIR" && "$COMPUTE_HOST_DETAIL_DIR" == */compute_host_detail ]] && rm -rf "$COMPUTE_HOST_DETAIL_DIR" 2>/dev/null; echo -e "${YELLOW}Cache cleared, refreshing...${NC}"; sleep 1; continue ;;
                *) return ;;
            esac
        fi

        #-----------------------------------------------------------------------
        # Fetch impacted host details (individual GET calls) + build lookup
        # Format: host_ocid|maintenanceType|recycleLevel|comp1_type:comp1_action:comp1_faultId:comp1_severity;...
        #-----------------------------------------------------------------------
        _step_init
        _ch_fetch_impacted_details
        _ch_fetch_k8s_data
        _step_finish

        _CH_IMPACT_LOOKUP="${TEMP_DIR}/ch_impact_lookup_$$.txt"
        : > "$_CH_IMPACT_LOOKUP"

        # Build lookup from per-host detail cache (compute-host get responses)
        if [[ -d "$COMPUTE_HOST_DETAIL_DIR" ]]; then
            for _detail_file in "$COMPUTE_HOST_DETAIL_DIR"/*.json; do
                [[ -s "$_detail_file" ]] || continue
                jq -r '.data |
                    select(.["impacted-component-details"] != null) |
                    .id as $hid |
                    (.["recycle-details"]["recycle-level"] // "N/A") as $rl |
                    (.["impacted-component-details"]["impactedComponents"]["v1"] // {}) |
                    (.maintenanceType // "N/A") as $mt |
                    ([(.components // [])[] |
                        "\(.componentType // "?"):\(.action // "?"):\(.faultId // "?"):\(.severity // "?")"]
                    | join(";")) as $comps |
                    "\($hid)|\($mt)|\($rl)|\($comps)"
                ' "$_detail_file" >> "$_CH_IMPACT_LOOKUP" 2>/dev/null || true
            done
        fi

        # Fallback: if no detail files, try list JSON cache (may have data in some API versions)
        if [[ ! -s "$_CH_IMPACT_LOOKUP" && -s "$COMPUTE_HOST_JSON_CACHE" ]]; then
            jq -r '(.data.items // .data // [])[] |
                select(.["has-impacted-components"] == true) |
                .id as $hid |
                (.["recycle-details"]["recycle-level"] // "N/A") as $rl |
                (.["impacted-component-details"]["impactedComponents"]["v1"] // {}) |
                (.maintenanceType // "N/A") as $mt |
                ([(.components // [])[] |
                    "\(.componentType // "?"):\(.action // "?"):\(.faultId // "?"):\(.severity // "?")"]
                | join(";")) as $comps |
                "\($hid)|\($mt)|\($rl)|\($comps)"
            ' "$COMPUTE_HOST_JSON_CACHE" > "$_CH_IMPACT_LOOKUP" 2>/dev/null || true
        fi

        #-----------------------------------------------------------------------
        # RDMA Topology Overview (HPC Island → Network Block → Local Block)
        #-----------------------------------------------------------------------
        echo ""
        _ui_subheader "RDMA Topology Overview" 0
        echo ""

        # Aligned tree line helper
        # Args: prefix, label_color, label_text, label_pad_width, count_string, value_color, value
        # Count string is padded to 34 chars so OCIDs align across all tree levels
        # and match bare-metal host OCID column (col 84)
        _ch_ro_line() {
            local prefix="$1" lcolor="$2" label="$3" lwidth="$4" count_str="$5" vcolor="$6" value="$7"
            local _cnt_section="[${count_str}]"
            local _cnt_p
            printf -v _cnt_p '%-35s' "$_cnt_section"
            echo -n -e "${prefix}${lcolor}"
            printf "%-${lwidth}s" "$label"
            echo -e "${NC} ${BOLD}${WHITE}${_cnt_p}${NC} ${GRAY}[${vcolor}${value}${GRAY}]${NC}"
        }

        # Get unique HPC Islands (field 10), N/A sorted last
        local ch_hpc_islands
        ch_hpc_islands=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f10 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')

        local ch_hpc_idx=0
        local ch_hpc_total
        ch_hpc_total=$(echo "$ch_hpc_islands" | grep -c . 2>/dev/null)

        while IFS= read -r ch_hpc_id; do
            [[ -z "$ch_hpc_id" ]] && continue
            ((ch_hpc_idx++))

            local ch_hpc_conn="├" ch_hpc_pipe="│"
            [[ "$ch_hpc_idx" -eq "$ch_hpc_total" ]] && { ch_hpc_conn="└"; ch_hpc_pipe=" "; }

            local ch_hpc_display="$ch_hpc_id"
            [[ "$ch_hpc_id" == "N/A" ]] && ch_hpc_display="(non-RDMA)"

            local ch_hpc_hosts
            ch_hpc_hosts=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v h="$ch_hpc_id" '$10 == h')
            local ch_hpc_cnt ch_hpc_nb_cnt ch_hpc_lb_cnt
            ch_hpc_cnt=$(echo "$ch_hpc_hosts" | grep -c . 2>/dev/null)
            ch_hpc_nb_cnt=$(echo "$ch_hpc_hosts" | cut -d'|' -f11 | sort -u | grep -c . 2>/dev/null)
            ch_hpc_lb_cnt=$(echo "$ch_hpc_hosts" | cut -d'|' -f12 | sort -u | grep -c . 2>/dev/null)

            # HPC Island (prefix visible=4, pad=41)
            _ch_ro_line "  ${ch_hpc_conn}── " "${BOLD}${CYAN}" "HPC Island:" 41 "${ch_hpc_nb_cnt} nb, ${ch_hpc_lb_cnt} lb, ${ch_hpc_cnt} hosts" "${YELLOW}" "$ch_hpc_display"

            # Network Blocks within this HPC Island (field 11)
            local ch_net_blocks
            ch_net_blocks=$(echo "$ch_hpc_hosts" | cut -d'|' -f11 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
            local ch_nb_idx=0
            local ch_nb_total
            ch_nb_total=$(echo "$ch_net_blocks" | grep -c . 2>/dev/null)

            while IFS= read -r ch_nb_id; do
                [[ -z "$ch_nb_id" ]] && continue
                ((ch_nb_idx++))

                local ch_nb_conn="├" ch_nb_pipe="│"
                [[ "$ch_nb_idx" -eq "$ch_nb_total" ]] && { ch_nb_conn="└"; ch_nb_pipe=" "; }

                local ch_nb_display="$ch_nb_id"
                [[ "$ch_nb_id" == "N/A" ]] && ch_nb_display="(none)"

                local ch_nb_hosts
                ch_nb_hosts=$(echo "$ch_hpc_hosts" | awk -F'|' -v n="$ch_nb_id" '$11 == n')
                local ch_nb_cnt ch_nb_lb_cnt
                ch_nb_cnt=$(echo "$ch_nb_hosts" | grep -c . 2>/dev/null)
                ch_nb_lb_cnt=$(echo "$ch_nb_hosts" | cut -d'|' -f12 | sort -u | grep -c . 2>/dev/null)

                # Network Block (prefix visible=8, pad=37)
                _ch_ro_line "  ${ch_hpc_pipe}   ${ch_nb_conn}── " "${BOLD}${MAGENTA}" "Network Block:" 37 "${ch_nb_lb_cnt} lb, ${ch_nb_cnt} hosts" "${YELLOW}" "$ch_nb_display"

                # Local Blocks within this Network Block (field 12)
                local ch_local_blocks
                ch_local_blocks=$(echo "$ch_nb_hosts" | cut -d'|' -f12 | sort -u | awk '/^N\/A$/{last=$0;next}{print} END{if(last)print last}')
                local ch_lb_idx=0
                local ch_lb_total
                ch_lb_total=$(echo "$ch_local_blocks" | grep -c . 2>/dev/null)

                while IFS= read -r ch_lb_id; do
                    [[ -z "$ch_lb_id" ]] && continue
                    ((ch_lb_idx++))

                    local ch_lb_conn="├" ch_lb_pipe="│"
                    [[ "$ch_lb_idx" -eq "$ch_lb_total" ]] && { ch_lb_conn="└"; ch_lb_pipe=" "; }

                    local ch_lb_display="$ch_lb_id"
                    [[ "$ch_lb_id" == "N/A" ]] && ch_lb_display="(none)"

                    local ch_lb_hosts
                    ch_lb_hosts=$(echo "$ch_nb_hosts" | awk -F'|' -v l="$ch_lb_id" '$12 == l')
                    local ch_lb_cnt
                    ch_lb_cnt=$(echo "$ch_lb_hosts" | grep -c . 2>/dev/null)

                    # Local Block (prefix visible=12, pad=33)
                    _ch_ro_line "  ${ch_hpc_pipe}   ${ch_nb_pipe}   ${ch_lb_conn}── " "${BOLD}${BLUE}" "Local Block:" 33 "${ch_lb_cnt} hosts" "${YELLOW}" "$ch_lb_display"

                    # Individual hosts under this Local Block
                    # Align [STATE] [HEALTH] to start at Local Block OCID column
                    # Host prefix is 20 visible chars; Local Block OCID starts at col 62
                    # So shape field needs: 62 - 20 = 42 chars
                    local ch_host_idx=0
                    local ch_host_total="$ch_lb_cnt"

                    while IFS='|' read -r _hn _hs _hh _hshape _hplat _had _hfd _hinst _hocid _hhpc _hnb _hlb _hhostgrp _hcapres _hgpufab _himpacted _rest; do
                        [[ -z "$_hn" ]] && continue
                        ((ch_host_idx++))

                        local _hconn="├"
                        [[ "$ch_host_idx" -eq "$ch_host_total" ]] && _hconn="└"

                        local _hsc="$GREEN"
                        case "$_hs" in
                            OCCUPIED) _hsc="$GREEN" ;;
                            AVAILABLE) _hsc="$CYAN" ;;
                            INACTIVE) _hsc="$YELLOW" ;;
                            *) _hsc="$RED" ;;
                        esac

                        local _hhc="$GREEN"
                        case "$_hh" in
                            HEALTHY) _hhc="$GREEN" ;;
                            DEGRADED|IMPAIRED) _hhc="$YELLOW" ;;
                            UNHEALTHY|FAILED) _hhc="$RED" ;;
                        esac

                        local _hshape_d="${_hshape:-N/A}"
                        [[ "$_hshape_d" == "N/A" ]] && _hshape_d="-"
                        # Build shape + optional colored fabric tag with manual padding
                        # Target visible width = 42 to align [STATE] under Local Block OCID
                        local _hfab_tag="" _hfab_vis=0
                        if [[ -n "$_hgpufab" && "$_hgpufab" != "N/A" ]]; then
                            _hfab_tag=" ${WHITE}[${MAGENTA}fabric-${_hgpufab: -5}${WHITE}]${NC}"
                            _hfab_vis=15  # " [fabric-xxxxx]" visible chars
                        fi
                        local _hvis_len=$(( ${#_hshape_d} + _hfab_vis ))
                        local _hshape_pad=""
                        (( _hvis_len < 42 )) && printf -v _hshape_pad '%*s' $(( 42 - _hvis_len )) ""
                        local _hshape_p="${_hshape_d}${_hfab_tag}${_hshape_pad}"

                        local _hocid_d=""
                        if [[ -n "$_hocid" && "$_hocid" != "N/A" ]]; then
                            _hocid_d=" ${GRAY}[${YELLOW}${_hocid}${GRAY}]${NC}"
                        fi

                        local _hinst_flag=""
                        if [[ -n "$_hinst" && "$_hinst" != "N/A" ]]; then
                            _hinst_flag=" ${GREEN}✓ instance${NC}"
                        fi

                        local _himpact_flag=""
                        if [[ "$_himpacted" == "true" ]]; then
                            # Lookup format: host_ocid|maintenanceType|recycleLevel|comps
                            local _imp_line=""
                            if [[ -s "$_CH_IMPACT_LOOKUP" ]]; then
                                _imp_line=$(grep "^${_hocid}|" "$_CH_IMPACT_LOOKUP" 2>/dev/null | head -1)
                            fi
                            if [[ -n "$_imp_line" ]]; then
                                local _imp_mt _imp_rl _imp_comps
                                _imp_mt=$(echo "$_imp_line" | cut -d'|' -f2)
                                _imp_rl=$(echo "$_imp_line" | cut -d'|' -f3)
                                _imp_comps=$(echo "$_imp_line" | cut -d'|' -f4)
                                # Build compact component summary: NIC/DOWNTIME HPCRDMA-0002-03
                                local _imp_detail=""
                                IFS=';' read -ra _imp_arr <<< "$_imp_comps"
                                for _ic in "${_imp_arr[@]}"; do
                                    [[ -z "$_ic" ]] && continue
                                    local _ic_type _ic_act _ic_fid _ic_sev
                                    IFS=':' read -r _ic_type _ic_act _ic_fid _ic_sev <<< "$_ic"
                                    [[ -n "$_imp_detail" ]] && _imp_detail+=", "
                                    _imp_detail+="${_ic_type}/${_ic_act} ${_ic_fid}"
                                done
                                local _imp_suffix="maint:${_imp_mt}"
                                [[ -n "$_imp_rl" && "$_imp_rl" != "N/A" ]] && _imp_suffix+=" | ${_imp_rl}"
                                _himpact_flag=" ${LIGHT_RED}[Impacted: ${_imp_detail} ${_imp_suffix}]${NC}"
                            else
                                _himpact_flag=" ${LIGHT_RED}[Impacted]${NC}"
                            fi
                        fi

                        # Fixed-width state/health for column alignment
                        local _hs_p _hh_p
                        printf -v _hs_p '%-9s' "$_hs"
                        printf -v _hh_p '%-9s' "$_hh"
                        echo -e "  ${ch_hpc_pipe}   ${ch_nb_pipe}   ${ch_lb_pipe}   ${_hconn}── ${CYAN}${_hshape_p}${NC}[${_hsc}${_hs_p}${NC}] [${_hhc}${_hh_p}${NC}]${_hocid_d}${_hinst_flag}${_himpact_flag}"
                    done < <(echo "$ch_lb_hosts" | sort -t'|' -k4,4 -k2,2)

                done <<< "$ch_local_blocks"

            done <<< "$ch_net_blocks"

        done <<< "$ch_hpc_islands"

        echo ""

        #-----------------------------------------------------------------------
        # Summary (State / Health / Shape counts + Impacted)
        #-----------------------------------------------------------------------
        _ui_subheader "Summary" 0

        # Summary by State
        echo -n -e "  ${BOLD}${WHITE}By State:${NC}   "
        while read -r cnt st; do
            local _sc="$WHITE"
            case "$st" in
                OCCUPIED) _sc="$GREEN" ;;
                AVAILABLE) _sc="$CYAN" ;;
                INACTIVE) _sc="$YELLOW" ;;
                *) _sc="$RED" ;;
            esac
            echo -n -e "${_sc}${st}${NC}(${cnt})  "
        done < <(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f2 | sort | uniq -c | sort -rn)
        echo ""

        # Summary by Health
        echo -n -e "  ${BOLD}${WHITE}By Health:${NC}  "
        while read -r cnt ht; do
            local _hc="$WHITE"
            case "$ht" in
                HEALTHY) _hc="$GREEN" ;;
                DEGRADED|IMPAIRED) _hc="$YELLOW" ;;
                UNHEALTHY|FAILED) _hc="$RED" ;;
            esac
            echo -n -e "${_hc}${ht}${NC}(${cnt})  "
        done < <(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f3 | sort | uniq -c | sort -rn)
        echo ""

        # Summary by Shape
        echo -n -e "  ${BOLD}${WHITE}By Shape:${NC}   "
        while read -r cnt sh; do
            echo -n -e "${CYAN}${sh}${NC}(${cnt})  "
        done < <(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f4 | sort | uniq -c | sort -rn)
        echo ""

        # Has Impacted hosts
        local impacted_count
        impacted_count=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' '$16 == "true"' | wc -l)
        if [[ "$impacted_count" -gt 0 ]]; then
            echo -e "  ${BOLD}${RED}Impacted:${NC}   ${RED}${impacted_count} host(s) with impacted components${NC}"
        fi

        echo -e "  ${WHITE}Total Hosts:${NC} ${GREEN}$total_hosts${NC}"
        echo ""

        # ── Actions Menu ──
        _ui_actions
        echo -e "  ${YELLOW}1${NC}) View hosts by lifecycle state"
        echo -e "  ${YELLOW}2${NC}) View hosts by health"
        echo -e "  ${YELLOW}3${NC}) View all hosts (detailed)"
        echo -e "  ${YELLOW}4${NC}) View by shape"
        if [[ "$impacted_count" -gt 0 ]]; then
            echo -e "  ${RED}5${NC}) ${WHITE}View impacted hosts${NC}        - ${RED}${impacted_count} host(s) with impacted components${NC}"
        fi
        echo -e "  ${CYAN}/${NC}${YELLOW}term${NC}) Search hosts"
        echo -e "  ${YELLOW}i${NC}) Instance details (paste OCID)"
        echo -e "  ${YELLOW}h${NC}) Host details (paste OCID)"
        echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)"
        echo -e "  ${GREEN}col${NC}) Configure table columns"
        echo -e "  ${MAGENTA}r${NC}) Refresh data"
        echo -e "  ${CYAN}Enter${NC}) Return to menu"
        echo ""
        _ui_prompt "Compute Hosts" "1-5, /term, i, h, j, col, r, Enter, show"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            1) compute_host_view_by_state ;;
            2) compute_host_view_by_health ;;
            3) compute_host_view_all ;;
            4) compute_host_view_by_shape ;;
            5) compute_host_view_impacted ;;
            col|COL|columns|COLUMNS) _col_picker "CHOST" "Compute Hosts" ;;
            /*) _ch_search_hosts "all" "${choice#/}" ;;
            i|I) _ch_view_instance ;;
            h|H) _ch_view_host ;;
            ocid1.instance.*) _ch_view_instance "$choice" ;;
            ocid1.computecapacityhost.*|ocid1.computehost.*) _ch_view_host "$choice" ;;
            j|J|json|JSON)
                _ui_json_viewer "Compute Hosts JSON" "-f" "$COMPUTE_HOST_JSON_CACHE" ".data"
                ;;
            j\ *|J\ *|json\ *|JSON\ *)
                _ui_json_viewer "Compute Hosts JSON" "-f" "$COMPUTE_HOST_JSON_CACHE" ".data" "${choice#* }"
                ;;
            r|R)
                rm -f "$COMPUTE_HOST_CACHE" "$COMPUTE_HOST_JSON_CACHE"
                [[ -n "$COMPUTE_HOST_DETAIL_DIR" && "$COMPUTE_HOST_DETAIL_DIR" == */compute_host_detail ]] && rm -rf "$COMPUTE_HOST_DETAIL_DIR" 2>/dev/null
                echo -e "${YELLOW}Cache cleared, refreshing...${NC}"
                sleep 1
                ;;
            show|SHOW) continue ;;
            *) return ;;
        esac
        [[ -n "${_NAV_JUMP:-}" ]] && return
    done
}

#--------------------------------------------------------------------------------
# Compute Hosts — View hosts filtered by lifecycle state
#--------------------------------------------------------------------------------
compute_host_view_by_state() {
    echo ""
    echo -e "${CYAN}Select lifecycle state to filter:${NC}"

    local states
    states=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f2 | sort -u)

    local idx=0
    local -A state_map=()
    while IFS= read -r state; do
        [[ -z "$state" ]] && continue
        ((idx++))
        state_map[$idx]="$state"
        local count
        count=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f2 | grep -c "^${state}$")
        echo -e "  ${GREEN}$idx${NC}) $state ($count hosts)"
    done <<< "$states"

    echo ""
    echo -n -e "${CYAN}Select #: ${NC}"
    read -r sel

    local selected_state="${state_map[$sel]:-}"
    [[ -z "$selected_state" ]] && return

    echo ""
    _ui_subheader "Hosts with State: $selected_state" 0

    local _filtered_file="${TEMP_DIR}/ch_state_filtered_$$.txt"
    grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="$selected_state" '$2 == v' > "$_filtered_file"

    local _host_ct
    _host_ct=$(wc -l < "$_filtered_file")

    _step_init
    _step_complete "hosts(${_host_ct})"
    _ch_resolve_instance_names "$_filtered_file"
    _step_finish

    echo ""
    _col_build_fmt "CHOST"
    printf "${BOLD}${_CHOST_HDR_FMT}${NC}\n" "${_CHOST_HDR_ARGS[@]}"
    print_separator $_CHOST_SEP_WIDTH

    local _ch_idx=0
    declare -gA CH_HOST_MAP=()
    CH_HOST_MAP=()
    declare -gA CH_OCID_MAP=()
    CH_OCID_MAP=()

    while IFS='|' read -r display_name state health shape platform ad fd inst_id host_ocid _hpc _netblk _locblk _hostgrp _capres _gpufab has_impacted _rest; do
        [[ -z "$display_name" ]] && continue
        ((_ch_idx++))
        _ch_print_host_row "$_ch_idx" "$display_name" "$state" "$health" "$shape" \
            "$platform" "$ad" "$fd" "$inst_id" "$host_ocid" "$has_impacted" "$_gpufab"
    done < "$_filtered_file"
    rm -f "$_filtered_file" 2>/dev/null

    _ch_hidden_cols_notice
    _ch_post_table_actions "State View" "state:${selected_state}"
}

