    echo ""
    _col_build_fmt "CHOST"
    printf "${BOLD}${_CHOST_HDR_FMT}${NC}\n" "${_CHOST_HDR_ARGS[@]}"
    print_separator $_CHOST_SEP_WIDTH

    local _ch_idx=0
    declare -gA CH_HOST_MAP=()
    CH_HOST_MAP=()
    declare -gA CH_OCID_MAP=()
    CH_OCID_MAP=()

    while IFS='|' read -r display_name state health shape platform ad fd inst_id host_ocid _hpc _netblk _locblk _hostgrp _capres _gpufab has_impacted _rest; do
        [[ -z "$display_name" ]] && continue
        ((_ch_idx++))
        _ch_print_host_row "$_ch_idx" "$display_name" "$state" "$health" "$shape" \
            "$platform" "$ad" "$fd" "$inst_id" "$host_ocid" "$has_impacted" "$_gpufab"
    done < "$_sorted_file"
    rm -f "$_sorted_file" 2>/dev/null

    _ch_hidden_cols_notice
    _ch_post_table_actions "All Hosts View" "all"
}

#--------------------------------------------------------------------------------
# Compute Hosts — View hosts filtered by shape
#--------------------------------------------------------------------------------
compute_host_view_by_shape() {
    echo ""
    echo -e "${CYAN}Select shape to filter:${NC}"

    local shapes
    shapes=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f4 | sort -u)

    local idx=0
    declare -A shape_map
    while IFS= read -r shape; do
        [[ -z "$shape" ]] && continue
        ((idx++))
        shape_map[$idx]="$shape"
        local count
        count=$(grep -v "^#" "$COMPUTE_HOST_CACHE" | cut -d'|' -f4 | grep -c "^${shape}$")
        echo -e "  ${GREEN}$idx${NC}) $shape ($count hosts)"
    done <<< "$shapes"

    echo ""
    echo -n -e "${CYAN}Select #: ${NC}"
    read -r sel

    local selected_shape="${shape_map[$sel]:-}"
    [[ -z "$selected_shape" ]] && return

    echo ""
    _ui_subheader "Hosts with Shape: $selected_shape" 0

    local _filtered_file="${TEMP_DIR}/ch_shape_filtered_$$.txt"
    grep -v "^#" "$COMPUTE_HOST_CACHE" | awk -F'|' -v v="$selected_shape" '$4 == v' > "$_filtered_file"

    local _host_ct
    _host_ct=$(wc -l < "$_filtered_file")

    _step_init
    _step_complete "hosts(${_host_ct})"
    _ch_resolve_instance_names "$_filtered_file"
    _step_finish

    echo ""
    _col_build_fmt "CHOST"
    printf "${BOLD}${_CHOST_HDR_FMT}${NC}\n" "${_CHOST_HDR_ARGS[@]}"
    print_separator $_CHOST_SEP_WIDTH

    local _ch_idx=0
    declare -gA CH_HOST_MAP=()
    CH_HOST_MAP=()
    declare -gA CH_OCID_MAP=()
    CH_OCID_MAP=()

    while IFS='|' read -r display_name state health shape platform ad fd inst_id host_ocid _hpc _netblk _locblk _hostgrp _capres _gpufab has_impacted _rest; do
        [[ -z "$display_name" ]] && continue
        ((_ch_idx++))
        _ch_print_host_row "$_ch_idx" "$display_name" "$state" "$health" "$shape" \
            "$platform" "$ad" "$fd" "$inst_id" "$host_ocid" "$has_impacted" "$_gpufab"
    done < "$_filtered_file"
    rm -f "$_filtered_file" 2>/dev/null

    _ch_hidden_cols_notice
    _ch_post_table_actions "Shape View" "shape:${selected_shape}"
}

#--------------------------------------------------------------------------------
