#--------------------------------------------------------------------------------
# Manage GPU Instance Tagging - Main menu
#--------------------------------------------------------------------------------

manage_gpu_instance_tagging() {
    local tenancy_ocid="${TENANCY_ID:-$TENANCY_OCID}"
    local home_region=""
    
    while true; do
        echo ""
        _ui_menu_header "GPU INSTANCE TAGGING" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "GPU Tagging" \
            --cmd "oci iam region-subscription list --tenancy-id \"\$TENANCY_ID\" --query \"data[?\\\"is-home-region\\\"==\\\`true\\\`].\\\"region-name\\\" | [0]\" | oci iam tag-namespace list --compartment-id \$TENANCY_ID | oci iam tag list --tag-namespace-id \$TAG_NS_ID" \
            --env
        
        # ── Discovery ──
        _step_init
        
        if [[ -z "$home_region" ]]; then
            _step_active "home region"
            home_region=$(get_home_region)
            if [[ -z "$home_region" ]]; then
                _step_complete "home region(failed)"
                _step_finish
                echo -e "${RED}Error: Could not determine home region.${NC}"
                echo -e "${YELLOW}Please ensure TENANCY_ID or TENANCY_OCID is set in variables.sh${NC}"
                echo ""
                _ui_pause "return"
                return 1
            fi
            _step_complete "home region"
        else
            _step_complete "home region(cached)"
        fi
        
        _step_active "GPU tagging"
        validate_gpu_tagging_namespace "$tenancy_ocid" "$home_region" "compact"
        _step_complete "GPU tagging"
        _step_finish

        _ui_subheader "Configuration" 0
        echo -e "  ${CYAN}Tenancy:${NC}     ${YELLOW}${tenancy_ocid}${NC}"
        echo -e "  ${CYAN}Home Region:${NC} ${WHITE}${home_region}${NC}"
        echo -e "  ${CYAN}Namespace:${NC}   ${WHITE}${GPU_TAG_NAMESPACE}${NC}"
        echo -e "  ${CYAN}Tag Name:${NC}    ${WHITE}${GPU_TAG_NAME}${NC}"
        echo -e "  ${CYAN}Tag Values:${NC}  ${WHITE}${GPU_TAG_VALUES}${NC}"
        echo ""
        
        # Show validation result (green one-liner if ok, full detail if issues)
        _display_gpu_tag_validation
        echo ""
        
        _ui_actions
        echo ""
        
        echo -e "  ${CYAN}v${NC}) ${WHITE}Validate namespace and tag${NC}    - Check if namespace exists with proper tag configuration"
        echo -e "  ${GREEN}c${NC}) ${WHITE}Create namespace and tag${NC}      - Create ${GPU_TAG_NAMESPACE} namespace with ${GPU_TAG_NAME} tag"
        echo -e "  ${RED}d${NC}) ${WHITE}Delete namespace${NC}              - Retire and cascade-delete the namespace"
        echo ""
        echo -e "  ${CYAN}b${NC}) Back to main menu"
        echo ""
        _ui_prompt "GPU Tagging" "v, c, d, b, show"
        
        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return
        
        case "$choice" in
            v|V|1)
                validate_gpu_tagging_namespace "$tenancy_ocid" "$home_region" "full"
                echo ""
                _ui_pause
                ;;
            c|C|2)
                create_gpu_tagging_namespace "$tenancy_ocid" "$home_region"
                ;;
            d|D|3)
                delete_gpu_tagging_namespace "$tenancy_ocid" "$home_region"
                ;;
            b|B|back|BACK|"")
                return
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# K8s Node Storage Verification
# Collects comprehensive disk configuration from K8s nodes via kubectl debug.
# Displays: lsblk tree, device summary, blkid, mdstat, NVMe inventory,
#           NVMe SMART health, NVMe controller ID, and OCI volume metadata.
# Uses: kubectl debug node/<name> with busybox image (chroot /host)
#--------------------------------------------------------------------------------
readonly KUBECTL_DEBUG_IMAGE="${KUBECTL_DEBUG_IMAGE:-busybox}"
readonly KUBECTL_DEBUG_TIMEOUT="${KUBECTL_DEBUG_TIMEOUT:-4}"
readonly KUBECTL_DEBUG_GPU_TIMEOUT="${KUBECTL_DEBUG_GPU_TIMEOUT:-15}" # nvidia-smi can be slow

# -- Clean up stale node-debugger pods -----------------------------------------
# kubectl debug node/<name> creates ephemeral pods that are NOT auto-deleted.
# Stale pods from prior runs cause scheduling contention and degraded output
# when iterating multiple nodes. Call before each debug session.
# Args: $1 (optional) = node name — clean only pods targeting that node
#       (no args)      = clean ALL node-debugger pods
_kubectl_debug_cleanup() {
    local _node="${1:-}" _pods=""
    if [[ -n "$_node" ]]; then
        _pods=$(kubectl get pods --no-headers 2>/dev/null \
            | awk -v prefix="node-debugger-${_node}-" 'index($1, prefix) == 1 {print $1}')
    else
        _pods=$(kubectl get pods --no-headers 2>/dev/null \
            | awk '/^node-debugger-/ {print $1}')
    fi
    if [[ -n "$_pods" ]]; then
        echo "$_pods" | xargs kubectl delete pod --grace-period=0 --force &>/dev/null || true
    fi
    return 0
}

# -- Node comparison rendering helpers -----------------------------------------
# Shared by _netverify_compare, _gpuhealth_compare, _storage_compare, _xid_compare.
# Follow the _cc_val() pattern from compare_oke_clusters().
# Usage:
#   _comp_header  <lw> <cw> <name1> [name2 ...]
#   _comp_row     <lw> <cw> <label> <val1> [val2 ...]
#   _comp_sep     <lw> <cw> <node_count>

_comp_header() {
    local _lw=$1 _cw=$2; shift 2
    printf "  ${BOLD}%-${_lw}s${NC}" ""
    while [[ $# -gt 0 ]]; do
        printf " ${BOLD}%-${_cw}s${NC}" "${1:0:$_cw}"
        shift
    done
    echo ""
}

_comp_row() {
    local _lw=$1 _cw=$2 _label="$3"; shift 3
    local -a _vals=("$@")
    # Determine if all values match
    local _all_same=true
    for ((_ci=1; _ci<${#_vals[@]}; _ci++)); do
        [[ "${_vals[0]}" != "${_vals[$_ci]}" ]] && { _all_same=false; break; }
    done
    printf "  ${CYAN}%-${_lw}s${NC}" "$_label"
    for _v in "${_vals[@]}"; do
        if [[ "$_all_same" == true ]]; then
            printf " ${WHITE}%-${_cw}s${NC}" "${_v:0:$_cw}"
        else
            printf " ${YELLOW}%-${_cw}s${NC}" "${_v:0:$_cw}"
        fi
    done
    echo ""
}

_comp_sep() {
    local _lw=$1 _cw=$2 _nc=$3
    print_separator $((_lw + _cw * _nc + _nc))
}

# RunCommand preset templates — selectable from Bulk RunCommand menu
declare -gA RC_PRESETS=(
    [gpu-health]='nvidia-smi --query-gpu=index,gpu_bus_id,name,temperature.gpu,power.draw,power.limit,memory.used,memory.total,ecc.errors.uncorrected.volatile.total,ecc.errors.uncorrected.aggregate.total,retired_pages.pending,utilization.gpu --format=csv,noheader 2>/dev/null; echo "---TOPO---"; nvidia-smi topo -m 2>/dev/null; echo "---NVLINK---"; nvidia-smi nvlink -s 2>/dev/null'
    [gpu-ecc]='nvidia-smi --query-gpu=index,gpu_bus_id,ecc.errors.corrected.volatile.total,ecc.errors.corrected.aggregate.total,ecc.errors.uncorrected.volatile.total,ecc.errors.uncorrected.aggregate.total,retired_pages.sbe,retired_pages.dbe,retired_pages.pending --format=csv 2>/dev/null'
    [dmesg-xid]='dmesg -T 2>/dev/null | grep -i "NVRM\|Xid\|nvidia" | tail -50 || dmesg 2>/dev/null | grep -i "NVRM\|Xid\|nvidia" | tail -50'
    [dmesg-errors]='dmesg -T 2>/dev/null | grep -iE "error|fail|warn|oom|panic|hung" | tail -80 || echo "(dmesg unavailable)"'
    [rdma-status]='rdma link 2>/dev/null; echo "---IB---"; for d in /sys/class/infiniband/*/ports/*; do echo "$(basename $(dirname $(dirname $d))):$(basename $d) $(cat $d/state 2>/dev/null) $(cat $d/phys_state 2>/dev/null) $(cat $d/rate 2>/dev/null)"; done 2>/dev/null; echo "---COUNTERS---"; for d in /sys/class/infiniband/*/ports/*/counters; do dev=$(echo $d|sed "s|/sys/class/infiniband/||;s|/ports/|:|;s|/counters||"); echo "$dev rcv_err=$(cat $d/port_rcv_errors 2>/dev/null) link_dn=$(cat $d/link_downed 2>/dev/null)"; done 2>/dev/null'
    [system-info]='hostname; uptime; uname -r; cat /etc/os-release 2>/dev/null | head -3; free -h; df -h / /var 2>/dev/null; nproc'
)

# XID severity/description map — https://docs.nvidia.com/deploy/xid-errors/
declare -gA XID_DESCRIPTIONS=(
    [13]="Graphics Engine Exception|WARN|Often transient, may indicate driver issue"
    [31]="GPU memory page fault|WARN|Application-level memory error"
    [38]="Driver firmware error|CRIT|Driver/firmware communication failure"
    [43]="GPU stopped processing|CRIT|GPU hang detected"
    [45]="Preemptive cleanup|WARN|Usually benign — GPU reset for recovery"
    [48]="Double-bit ECC error|CRIT|Uncorrectable memory error — hardware issue"
    [61]="Internal micro-controller error|CRIT|Firmware-level error"
    [62]="Internal micro-controller breakpoint|CRIT|Firmware crash"
    [63]="ECC page retirement|WARN|Row remapping — monitor for accumulation"
    [64]="ECC page retirement — DBE|CRIT|Double-bit retirement — hardware degradation"
    [68]="NVDEC error|WARN|Video decode engine error"
    [74]="NVLink error|CRIT|NVLink communication failure — fabric issue"
    [79]="GPU fallen off bus|CRIT|GPU no longer reachable — PCIe/hardware failure"
    [92]="High single-bit ECC rate|WARN|Memory degradation indicator"
    [94]="Contained ECC error|WARN|ECC error contained successfully"
    [95]="Uncontained ECC error|CRIT|ECC error could not be contained"
    [119]="GSP RPC timeout|CRIT|GPU System Processor communication failure"
    [120]="GSP error|CRIT|GPU System Processor error"
)

#--------------------------------------------------------------------------------
# _k8s_parallel_collect — Run a collect function across nodes in parallel
# Spawns background kubectl debug pods for all nodes simultaneously, waits for
# completion, then stores raw output in temp files for sequential display.
#
# Args: $1 = collect function name (e.g., "_gpuhealth_collect")
#       $2..N = "index|node_name" pairs (e.g., "1|oke-node-abc" "2|oke-node-def")
# Sets: _PCOLLECT_DIR  = temp directory containing <index>.raw files
#       _PCOLLECT_CT   = number of nodes collected
# Caller must rm -rf "$_PCOLLECT_DIR" when done.
#--------------------------------------------------------------------------------
_k8s_parallel_collect() {
    local _fn="$1"; shift
    local -a _pairs=("$@")
    local _started=${#_pairs[@]}

    _PCOLLECT_DIR="${TEMP_DIR}/pcollect_$$_${RANDOM}"
    _PCOLLECT_CT="$_started"
    mkdir -p "$_PCOLLECT_DIR"

    # Launch all collect jobs in parallel
    local -a _pids=()
    for _pair in "${_pairs[@]}"; do
        local _idx="${_pair%%|*}"
        local _nname="${_pair#*|}"
        ( "$_fn" "$_nname" > "$_PCOLLECT_DIR/${_idx}.raw" 2>/dev/null ) &
        _pids+=($!)
    done

    # Wait with progress counter
    echo -e "  ${CYAN}Collecting from ${_started} nodes in parallel...${NC}"
    local _done=0
    for _pid in "${_pids[@]}"; do
        wait "$_pid" 2>/dev/null
        ((_done++))
        printf "\r  ${CYAN}Collected %d/%d nodes${NC}    " "$_done" "$_started"
    done
    echo ""
}

# -- Collect comprehensive disk info from a node via kubectl debug -------------
# Runs all disk commands in a single debug pod to minimize overhead.
# Returns: delimited text output with section markers for parsing.
# Args: $1 = node_name
_storage_collect_disk_info() {
    local _node="$1"
    local _rc=0

    # Clean up stale debug pods for this node before starting
    _kubectl_debug_cleanup "$_node"

    timeout --foreground --kill-after=2 "${KUBECTL_DEBUG_TIMEOUT}" kubectl debug "node/${_node}" \
        -i \
        --image="${KUBECTL_DEBUG_IMAGE}" \
        --profile=sysadmin \
        -q \
        -- chroot /host bash -c '
echo "===LSBLK_TREE==="
lsblk -o NAME,FSTYPE,SIZE,TYPE,MOUNTPOINTS --exclude 7 2>/dev/null || echo "(unavailable)"
echo ""
echo "===LSBLK_DEVICES==="
lsblk -d -o NAME,ROTA,DISC-GRAN,MODEL,SERIAL,REV,SIZE --exclude 7 2>/dev/null || echo "(unavailable)"
echo ""
echo "===BLKID==="
blkid 2>/dev/null || echo "(unavailable)"
echo ""
echo "===MDSTAT==="
cat /proc/mdstat 2>/dev/null || echo "(unavailable)"
echo ""
echo "===NVME_LIST==="
nvme list 2>/dev/null || echo "(nvme-cli not installed)"
echo ""
echo "===NVME_SMART==="
for dev in $(nvme list 2>/dev/null | awk "/^\/dev/{print \$1}"); do
    echo "--- ${dev} ---"
    nvme smart-log "${dev}" 2>/dev/null || echo "(unavailable)"
    echo ""
done
[[ -z "$(nvme list 2>/dev/null | awk "/^\/dev/{print \$1}")" ]] && echo "(no nvme devices)"
echo ""
echo "===NVME_IDCTRL==="
for dev in $(nvme list 2>/dev/null | awk "/^\/dev/{print \$1}" | sed "s/n[0-9]*$//" | sort -u); do
    echo "--- ${dev} ---"
    nvme id-ctrl "${dev}" 2>/dev/null | head -20 || echo "(unavailable)"
    echo ""
done
[[ -z "$(nvme list 2>/dev/null | awk "/^\/dev/{print \$1}")" ]] && echo "(no nvme devices)"
echo ""
echo "===END==="
' < <(sleep "${KUBECTL_DEBUG_GPU_TIMEOUT:-15}") 2>/dev/null || _rc=$?

    if [[ ${_rc} -eq 124 ]]; then
        echo "===LSBLK_TREE===
(timed out after ${KUBECTL_DEBUG_TIMEOUT}s)
===END==="
    elif [[ ${_rc} -ne 0 ]]; then
        echo "===LSBLK_TREE===
(unavailable — kubectl debug exit ${_rc})
===END==="
    fi
}

# -- Extract a section from disk info output -----------------------------------
# Args: $1 = full output, $2 = SECTION_NAME (e.g., LSBLK_TREE)
_storage_extract_section() {
    local _output="$1" _section="$2"
    echo "${_output}" | sed -n "/^===${_section}===/,/^===[A-Z]/{ /^===/d; p; }" | sed '$ { /^$/d; }'
}

# -- Display all storage sections for a node -----------------------------------
# Args: $1 = node_name, $2 = shape, $3 = full_output from _storage_collect_disk_info
_storage_display_node() {
    local _node="$1" _shape="$2" _output="$3"
    local _section _line

    # Check for failure — return 1 so caller prints [WARN]
    _section=$(_storage_extract_section "$_output" "LSBLK_TREE")
    if [[ "$_section" == *"timed out"* ]]; then
        return 1
    elif [[ "$_section" == "(unavailable"* ]]; then
        return 2
    fi
    local _layout_section="$_section"

    # ── Device Summary (lsblk -d) ──
    _section=$(_storage_extract_section "$_output" "LSBLK_DEVICES")
    if [[ -n "$_section" && "$_section" != "(unavailable)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            printf "      ${CYAN}%-18s${NC} %s\n" "Device Summary:" "$_line"
        done <<< "$_section"
    fi

    # ── Block IDs (blkid) ──
    _section=$(_storage_extract_section "$_output" "BLKID")
    if [[ -n "$_section" && "$_section" != "(unavailable)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            printf "      ${CYAN}%-18s${NC} %s\n" "Block ID:" "$_line"
        done <<< "$_section"
    fi

    # ── Device Layout (lsblk tree) ──
    while IFS= read -r _line; do
        [[ -z "$_line" ]] && continue
        printf "      ${CYAN}%-18s${NC} %s\n" "Device Layout:" "$_line"
    done <<< "$_layout_section"

    # ── Software RAID (mdstat) ──
    _section=$(_storage_extract_section "$_output" "MDSTAT")
    if [[ -n "$_section" && "$_section" != "(unavailable)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            printf "      ${CYAN}%-18s${NC} %s\n" "Software RAID:" "$_line"
        done <<< "$_section"
    fi

    # ── NVMe Devices ──
    _section=$(_storage_extract_section "$_output" "NVME_LIST")
    if [[ -n "$_section" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            printf "      ${CYAN}%-18s${NC} %s\n" "NVMe Device:" "$_line"
        done <<< "$_section"
    fi

    # ── NVMe SMART Logs ──
    _section=$(_storage_extract_section "$_output" "NVME_SMART")
    if [[ -n "$_section" && "$_section" != "(no nvme devices)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            local _color="$NC"
            if [[ "$_line" == *"critical_warning"* && "$_line" != *": 0" && "$_line" != *": 0x00" ]]; then
                _color="$RED"
            elif [[ "$_line" == *"percentage_used"* ]]; then
                local _pct
                _pct=$(echo "$_line" | grep -oP '\d+' | tail -1)
                [[ -n "$_pct" && "$_pct" -ge 80 ]] && _color="$YELLOW"
            fi
            printf "      ${CYAN}%-18s${NC} ${_color}%s${NC}\n" "NVMe SMART:" "$_line"
        done <<< "$_section"
    fi

    # ── NVMe Controller ID ──
    _section=$(_storage_extract_section "$_output" "NVME_IDCTRL")
    if [[ -n "$_section" && "$_section" != "(no nvme devices)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            printf "      ${CYAN}%-18s${NC} %s\n" "NVMe Controller:" "$_line"
        done <<< "$_section"
    fi
}

# -- Display OCI volume metadata for an instance --------------------------------
# Args: $1 = node_name, $2 = instance_ocid, $3 = compartment_id, $4 = AD
_storage_display_oci_volumes() {
    local _node="$1" _ocid="$2" _comp="$3" _ad="$4"
    
    echo -e "    ${BOLD}${CYAN}OCI Volume Metadata${NC}"
    echo ""
    
    # ── Boot Volume ──
    echo -e "    ${WHITE}Boot Volumes:${NC}"
    local _bv_attach
    _bv_attach=$(oci compute boot-volume-attachment list \
        --compartment-id "$_comp" \
        --instance-id "$_ocid" \
        --availability-domain "$_ad" \
        --output json 2>/dev/null)
    
    if [[ -z "$_bv_attach" ]] || ! jq -e '.data[0]' <<< "$_bv_attach" >/dev/null 2>&1; then
        echo -e "      ${GRAY}(none found)${NC}"
    else
        while IFS='|' read -r _bvid _bv_state _bv_enc; do
            [[ -z "$_bvid" ]] && continue
            local _bv_detail
            _bv_detail=$(oci bv boot-volume get --boot-volume-id "$_bvid" --output json 2>/dev/null)
            local _bv_name _bv_size _bv_vpus _bv_lc _bv_tier
            _bv_name=$(jq -r '.data."display-name" // "N/A"' <<< "$_bv_detail" 2>/dev/null)
            _bv_size=$(jq -r '.data."size-in-gbs" // 0' <<< "$_bv_detail" 2>/dev/null)
            _bv_vpus=$(jq -r '.data."vpus-per-gb" // 0' <<< "$_bv_detail" 2>/dev/null)
            _bv_lc=$(jq -r '.data."lifecycle-state" // "N/A"' <<< "$_bv_detail" 2>/dev/null)
            case "${_bv_vpus}" in
                0) _bv_tier="Lower Cost" ;; 10) _bv_tier="Balanced" ;;
                20) _bv_tier="Higher Perf" ;; 30) _bv_tier="Ultra High" ;;
                *) _bv_tier="${_bv_vpus} VPUs" ;;
            esac
            printf "      %-35s ${GREEN}%s GB${NC}  ${CYAN}%s VPUs${NC} (%s)  State: %s  Encrypt: %s\n" \
                "$_bv_name" "$_bv_size" "$_bv_vpus" "$_bv_tier" "$_bv_lc" "${_bv_enc:-N/A}"
        done < <(jq -r '.data[] | "\(."boot-volume-id")|\(."lifecycle-state")|\(."encryption-in-transit-type" // "N/A")"' <<< "$_bv_attach" 2>/dev/null)
    fi
    echo ""
    
    # ── Block Volumes ──
    echo -e "    ${WHITE}Block Volumes:${NC}"
    local _blk_attach
    _blk_attach=$(oci compute volume-attachment list \
        --compartment-id "$_comp" \
        --instance-id "$_ocid" \
        --output json 2>/dev/null)
    
    if [[ -z "$_blk_attach" ]] || ! jq -e '.data[0]' <<< "$_blk_attach" >/dev/null 2>&1; then
        echo -e "      ${GRAY}(none attached)${NC}"
    else
        printf "      ${BOLD}%-30s %-10s %-6s %-18s %-14s %-10s${NC}\n" \
            "Name" "Size" "VPUs" "Perf Tier" "Attach Type" "Device"
        printf "      ${GRAY}"
        printf '%.0s─' {1..88}
        printf "${NC}\n"
        
        while IFS='|' read -r _vid _vtype _vdev _vlc; do
            [[ -z "$_vid" ]] && continue
            [[ "$_vlc" == "DETACHED" || "$_vlc" == "DETACHING" ]] && continue
            local _vol_detail
            _vol_detail=$(oci bv volume get --volume-id "$_vid" --output json 2>/dev/null)
            local _v_name _v_size _v_vpus _v_tier
            _v_name=$(jq -r '.data."display-name" // "N/A"' <<< "$_vol_detail" 2>/dev/null)
            _v_size=$(jq -r '.data."size-in-gbs" // 0' <<< "$_vol_detail" 2>/dev/null)
            _v_vpus=$(jq -r '.data."vpus-per-gb" // 0' <<< "$_vol_detail" 2>/dev/null)
            case "${_v_vpus}" in
                0) _v_tier="Lower Cost" ;; 10) _v_tier="Balanced" ;;
                20) _v_tier="Higher Perf" ;; 30) _v_tier="Ultra High" ;;
                *) _v_tier="${_v_vpus} VPUs" ;;
            esac
            printf "      %-30s ${GREEN}%-10s${NC} ${CYAN}%-6s${NC} %-18s %-14s %-10s\n" \
                "${_v_name:0:30}" "${_v_size} GB" "$_v_vpus" "$_v_tier" "${_vtype:-N/A}" "${_vdev:-N/A}"
        done < <(jq -r '.data[] | "\(."volume-id")|\(."attachment-type" // "N/A")|\(.device // "N/A")|\(."lifecycle-state")"' <<< "$_blk_attach" 2>/dev/null)
    fi
    echo ""
}

# -- Compare storage config across nodes ---------------------------------------
_storage_compare() {
    local -n _cs_names=$1 _cs_shapes=$2 _cs_raw=$3
    local _nc=${#_cs_names[@]}

    echo ""
    _ui_subheader "Node Storage Comparison" 0
    echo ""

    local _lw=22 _cw=$(( (140 - 22) / _nc ))
    [[ $_cw -gt 35 ]] && _cw=35

    _comp_header $_lw $_cw "${_cs_names[@]}"
    printf "  ${GRAY}%-${_lw}s${NC}" ""
    for _s in "${_cs_shapes[@]}"; do printf " ${GRAY}%-${_cw}s${NC}" "${_s:0:$_cw}"; done
    echo ""
    _comp_sep $_lw $_cw $_nc

    local -a _v_blk_ct=() _v_nvme_ct=() _v_root_fs=() _v_root_sz=() _v_nvme_health=() _v_total_disk=()

    for ((_si=0; _si<_nc; _si++)); do
        local _raw="${_cs_raw[$_si]}"
        local _lsblk_dev _lsblk_tree _nvme_list _nvme_smart

        _lsblk_dev=$(_storage_extract_section "$_raw" "LSBLK_DEVICES")
        _lsblk_tree=$(_storage_extract_section "$_raw" "LSBLK_TREE")
        _nvme_list=$(_storage_extract_section "$_raw" "NVME_LIST")
        _nvme_smart=$(_storage_extract_section "$_raw" "NVME_SMART")

        # Block device count
        local _bct=0
        if [[ -n "$_lsblk_dev" && "$_lsblk_dev" != *"unavailable"* ]]; then
            _bct=$(echo "$_lsblk_dev" | grep -cE "^(sd|vd|nvme|dm-)" 2>/dev/null || true)
        fi
        _v_blk_ct+=("$_bct")

        # NVMe device count
        local _nct=0
        if [[ -n "$_nvme_list" && "$_nvme_list" != *"no nvme"* && "$_nvme_list" != *"unavailable"* ]]; then
            _nct=$(echo "$_nvme_list" | grep -c "^/dev/nvme" 2>/dev/null || true)
        fi
        _v_nvme_ct+=("$_nct")

        # Root FS type and size
        local _rfs="N/A" _rsz="N/A"
        if [[ -n "$_lsblk_tree" && "$_lsblk_tree" != *"unavailable"* && "$_lsblk_tree" != *"timed out"* ]]; then
            local _root_line
            _root_line=$(echo "$_lsblk_tree" | grep -E '\s/\s*$' | head -1)
            if [[ -n "$_root_line" ]]; then
                _rfs=$(echo "$_root_line" | awk '{print $2}')
                _rsz=$(echo "$_root_line" | awk '{print $3}')
            fi
        fi
        _v_root_fs+=("$_rfs")
        _v_root_sz+=("$_rsz")

        # NVMe SMART health
        local _nh="N/A"
        if [[ -n "$_nvme_smart" && "$_nvme_smart" != *"no nvme"* && "$_nvme_smart" != *"unavailable"* ]]; then
            local _cw_val
            _cw_val=$(echo "$_nvme_smart" | grep -i "critical_warning" | head -1 | awk -F: '{print $2}' | xargs)
            if [[ -n "$_cw_val" ]]; then
                [[ "$_cw_val" == "0" || "$_cw_val" == "0x00" ]] && _nh="Healthy" || _nh="WARN(${_cw_val})"
            fi
        fi
        _v_nvme_health+=("$_nh")

        # Total disk (sum sizes from LSBLK_DEVICES)
        local _total="N/A"
        if [[ -n "$_lsblk_dev" && "$_lsblk_dev" != *"unavailable"* ]]; then
            _total=$(echo "$_lsblk_dev" | awk '/^(sd|vd|nvme)/{print $4}' | paste -sd+ | bc 2>/dev/null || echo "N/A")
            [[ -n "$_total" && "$_total" != "N/A" ]] && _total="${_total}G"
        fi
        _v_total_disk+=("$_total")
    done

    _comp_row $_lw $_cw "Block Devices"  "${_v_blk_ct[@]}"
    _comp_row $_lw $_cw "NVMe Devices"   "${_v_nvme_ct[@]}"
    _comp_row $_lw $_cw "Root FS Type"   "${_v_root_fs[@]}"
    _comp_row $_lw $_cw "Root Size"      "${_v_root_sz[@]}"
    _comp_row $_lw $_cw "NVMe Health"    "${_v_nvme_health[@]}"
    _comp_row $_lw $_cw "Total Disk"     "${_v_total_disk[@]}"
    echo ""
}

# -- Main storage verification function ----------------------------------------
k8s_node_storage() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"
    
    # Check kubectl availability
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"
        return 1
    fi
    
    while true; do
        _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
        _region="${FOCUS_REGION:-$REGION}"
        echo ""
        _ui_menu_header "NODE STORAGE CONFIGURATION" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "Storage Verification" \
            --cmd "kubectl get nodes | kubectl debug node/<name> -- chroot /host lsblk | nvme list | nvme smart-log | blkid" \
            --env
        
        # ── Discover K8s nodes ──
        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"
            _step_finish
            echo -e "  ${RED}No K8s nodes found — check kubectl context${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct
        _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"
        _step_finish
        echo ""
        
        # ── Build node table ──
        # Columns: i#  Node Name  Shape  Status  Instance OCID
        declare -A _ST_MAP=()    # i# -> node_name|shape|status|ocid|ad|compartment
        local _st_idx=0
        local _st_tmpfile="${TEMP_DIR}/storage_nodes_$$"
        rm -f "$_st_tmpfile"
        
        printf "  ${BOLD}%-5s %-45s %-28s %-8s %-55s${NC}\n" \
            "ID" "Node Name" "Shape" "Status" "Instance OCID"
        print_separator 145
        
        while IFS='|' read -r _nname _shape _ready _ocid; do
            [[ -z "$_nname" ]] && continue
            ((_st_idx++))
            local _iid="i${_st_idx}"
            
            # Status color
            local _st_color="$GREEN" _st_label="Ready"
            if [[ "$_ready" != "True" ]]; then
                _st_color="$RED"; _st_label="NotRdy"
            fi
            
            # Get AD + compartment from instance (for OCI volume queries)
            local _ad="" _comp="$_compartment"
            if [[ -n "$_ocid" && "$_ocid" != "null" ]]; then
                # Try instance list cache for AD
                if [[ -s "$INSTANCE_LIST_CACHE" ]]; then
                    _ad=$(jq -r --arg id "$_ocid" '.data[] | select(.id == $id) | ."availability-domain" // ""' "$INSTANCE_LIST_CACHE" 2>/dev/null)
                    local _ic
                    _ic=$(jq -r --arg id "$_ocid" '.data[] | select(.id == $id) | ."compartment-id" // ""' "$INSTANCE_LIST_CACHE" 2>/dev/null)
                    [[ -n "$_ic" ]] && _comp="$_ic"
                fi
            fi
            
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s ${_st_color}%-8s${NC} ${GRAY}%-55s${NC}\n" \
                "$_iid" "${_nname:0:45}" "${_shape:0:28}" "$_st_label" "${_ocid:0:55}"
            
            echo "${_iid}|${_nname}|${_shape}|${_st_label}|${_ocid}|${_ad}|${_comp}" >> "$_st_tmpfile"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // .metadata.labels["beta.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)
        
        # Read map from temp file
        if [[ -f "$_st_tmpfile" ]]; then
            while IFS='|' read -r _iid _nname _shape _status _ocid _ad _comp; do
                _ST_MAP[$_iid]="${_nname}|${_shape}|${_status}|${_ocid}|${_ad}|${_comp}"
            done < "$_st_tmpfile"
            rm -f "$_st_tmpfile"
        fi
        
        local _total=${#_ST_MAP[@]}
        echo ""
        echo -e "  ${GRAY}${_total} K8s nodes │ debug image: ${KUBECTL_DEBUG_IMAGE} │ timeout: ${KUBECTL_DEBUG_TIMEOUT}s${NC}"
        echo ""
        
        # ── Actions ──
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}i#${NC}${WHITE})${NC}      View storage for node (e.g., ${YELLOW}i1${NC}, ${YELLOW}i1-i3${NC}, ${YELLOW}i1,i3,i5${NC}, ${YELLOW}all${NC})"
        echo -e "  ${GREEN}comp${NC}${WHITE})${NC}    Compare nodes side-by-side (e.g., ${GREEN}comp i1,i3${NC}  ${GREEN}comp all${NC})"
        echo -e "  ${GREEN}oci${NC}${WHITE})${NC}     Include OCI volume metadata (boot/block) on next selection"
        echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh node list"
        echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
        echo ""
        _ui_prompt "Node Storage" "i#, i#-i#, all, comp i#,i#, oci, r, b"

        local _sel
        read -r _sel
        [[ "${_sel:-}" == :* ]] && _nav_try_jump "$_sel" && return

        case "$_sel" in
            b|B|"") return ;;
            r|R) continue ;;
            show|SHOW) continue ;;
            comp*)
                local _comp_sel="${_sel#comp}"
                _comp_sel="${_comp_sel# }"
                if [[ -z "$_comp_sel" ]]; then
                    echo -e "  ${RED}Usage: comp i1,i2 or comp i1-i3 or comp all${NC}"; sleep 1; continue
                fi
                if ! _parse_targets "i" "$_comp_sel" "$_total"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                if [[ ${#_SEL_INDICES[@]} -lt 2 ]]; then
                    echo -e "  ${RED}Compare requires at least 2 nodes${NC}"; sleep 1; continue
                fi
                local -a _comp_names=() _comp_shapes=() _comp_raw=()
                local _interrupted=false
                trap '_interrupted=true' INT
                for _cidx in "${_SEL_INDICES[@]}"; do
                    [[ "$_interrupted" == true ]] && break
                    local _ciid="i${_cidx}"
                    local _cdata="${_ST_MAP[$_ciid]:-}"
                    [[ -z "$_cdata" ]] && continue
                    local _cn _cs _cst _cocid _cad _ccomp
                    IFS='|' read -r _cn _cs _cst _cocid _cad _ccomp <<< "$_cdata"
                    echo -e "  Collecting from ${GREEN}${_cn}${NC}  (${_cs})..."
                    local _craw
                    _craw=$(_storage_collect_disk_info "$_cn")
                    _comp_names+=("$_cn")
                    _comp_shapes+=("$_cs")
                    _comp_raw+=("$_craw")
                done
                trap - INT
                if [[ "$_interrupted" == true ]]; then
                    echo -e "\n${YELLOW}[INFO]${NC} Interrupted"
                elif [[ ${#_comp_names[@]} -ge 2 ]]; then
                    _storage_compare _comp_names _comp_shapes _comp_raw
                fi
                echo ""
                _ui_pause "return to node list"
                continue
                ;;
            oci|OCI)
                # Toggle OCI volume mode and prompt for node selection
                echo ""
                echo -e "  ${GREEN}OCI volume metadata enabled for this query${NC}"
                echo -ne "  ${CYAN}Select nodes (i#, i#-i#, all): ${NC}"
                local _oci_sel
                read -r _oci_sel
                [[ -z "$_oci_sel" ]] && continue
                
                # Parse targets
                if ! _parse_targets "i" "$_oci_sel" "$_total"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                [[ ${#_SEL_INDICES[@]} -eq 0 ]] && continue
                
                local _interrupted=false
                trap '_interrupted=true' INT
                for _tidx in "${_SEL_INDICES[@]}"; do
                    [[ "$_interrupted" == true ]] && break
                    local _tiid="i${_tidx}"
                    local _tdata="${_ST_MAP[$_tiid]:-}"
                    [[ -z "$_tdata" ]] && continue
                    IFS='|' read -r _tn _ts _tst _tocid _tad _tcomp <<< "$_tdata"
                    
                    echo -e "Collecting disk info for ${GREEN}${_tn}${NC}  (${_ts})..."
                    local _disk_output _drc=0
                    _disk_output=$(_storage_collect_disk_info "$_tn")
                    _storage_display_node "$_tn" "$_ts" "$_disk_output" || _drc=$?
                    if [[ $_drc -eq 1 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug timed out for ${GREEN}${_tn}${NC} (>${KUBECTL_DEBUG_TIMEOUT}s)"
                    elif [[ $_drc -eq 2 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug failed for ${GREEN}${_tn}${NC}"
                    fi
                    
                    # OCI volumes (only if disk succeeded)
                    if [[ $_drc -eq 0 && -n "$_tocid" && "$_tocid" != "null" ]]; then
                        if [[ -z "$_tad" ]]; then
                            _tad=$(oci compute instance get --instance-id "$_tocid" --query 'data."availability-domain"' --raw-output 2>/dev/null)
                        fi
                        if [[ -n "$_tad" ]]; then
                            _storage_display_oci_volumes "$_tn" "$_tocid" "$_tcomp" "$_tad"
                        fi
                    fi
                done
                trap - INT
                [[ "$_interrupted" == true ]] && echo -e "\n${YELLOW}[INFO]${NC} Interrupted"
                echo ""
                _ui_pause "return to node list"
                continue
                ;;
            *)
                # Parse i# selection
                if ! _parse_targets "i" "$_sel" "$_total"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                [[ ${#_SEL_INDICES[@]} -eq 0 ]] && continue

                if [[ ${#_SEL_INDICES[@]} -gt 1 ]]; then
                    # Multiple nodes: parallel collection
                    local -a _st_pairs=()
                    for _tidx in "${_SEL_INDICES[@]}"; do
                        local _tdata="${_ST_MAP[i${_tidx}]:-}"
                        [[ -z "$_tdata" ]] && continue
                        _st_pairs+=("${_tidx}|${_tdata%%|*}")
                    done
                    _k8s_parallel_collect "_storage_collect_disk_info" "${_st_pairs[@]}"

                    for _tidx in "${_SEL_INDICES[@]}"; do
                        local _tdata="${_ST_MAP[i${_tidx}]:-}"
                        [[ -z "$_tdata" ]] && continue
                        local _tn _ts _tst _tocid _tad _tcomp
                        IFS='|' read -r _tn _ts _tst _tocid _tad _tcomp <<< "$_tdata"
                        echo ""
                        _ui_subheader "Node Storage — ${_tn}  (${_ts})" 0
                        local _disk_output=""
                        [[ -f "$_PCOLLECT_DIR/${_tidx}.raw" ]] && _disk_output=$(cat "$_PCOLLECT_DIR/${_tidx}.raw")
                        if [[ -z "$_disk_output" ]]; then
                            echo -e "  ${YELLOW}[WARN]${NC} kubectl debug returned no data for ${GREEN}${_tn}${NC}"
                        else
                            local _drc=0
                            _storage_display_node "$_tn" "$_ts" "$_disk_output" || _drc=$?
                            if [[ $_drc -eq 1 ]]; then
                                echo -e "  ${YELLOW}[WARN]${NC} kubectl debug timed out for ${GREEN}${_tn}${NC} (>${KUBECTL_DEBUG_TIMEOUT}s)"
                            elif [[ $_drc -eq 2 ]]; then
                                echo -e "  ${YELLOW}[WARN]${NC} kubectl debug failed for ${GREEN}${_tn}${NC}"
                            fi
                        fi
                    done
                    rm -rf "$_PCOLLECT_DIR" 2>/dev/null
                else
                    # Single node: direct collection
                    local _tidx="${_SEL_INDICES[0]}"
                    local _tdata="${_ST_MAP[i${_tidx}]:-}"
                    [[ -z "$_tdata" ]] && continue
                    local _tn _ts _tst _tocid _tad _tcomp
                    IFS='|' read -r _tn _ts _tst _tocid _tad _tcomp <<< "$_tdata"
                    echo -e "Collecting disk info for ${GREEN}${_tn}${NC}  (${_ts})..."
                    local _disk_output _drc=0
                    _disk_output=$(_storage_collect_disk_info "$_tn")
                    _storage_display_node "$_tn" "$_ts" "$_disk_output" || _drc=$?
                    if [[ $_drc -eq 1 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug timed out for ${GREEN}${_tn}${NC} (>${KUBECTL_DEBUG_TIMEOUT}s)"
                    elif [[ $_drc -eq 2 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug failed for ${GREEN}${_tn}${NC}"
                    fi
                fi
                echo ""
                _ui_pause "return to node list"
                continue
                ;;
        esac
    done
}


#--------------------------------------------------------------------------------
# K8s Node Network Verification
# Collects host-level network configuration from K8s nodes via kubectl debug.
# Displays: lshw network hardware inventory and ip address summary.
# Uses: kubectl debug node/<n> with busybox image (chroot /host)
#--------------------------------------------------------------------------------

# -- Collect network info from a node via kubectl debug ------------------------
# Runs lshw + ip in a single debug pod.
# Returns: delimited text output with section markers for parsing.
# Args: $1 = node_name
_netverify_collect() {
    local _node="$1"
    local _rc=0

    # Clean up stale debug pods for this node before starting
    _kubectl_debug_cleanup "$_node"

    timeout --foreground --kill-after=2 "${KUBECTL_DEBUG_TIMEOUT}" kubectl debug "node/${_node}" \
        -i \
        --image="${KUBECTL_DEBUG_IMAGE}" \
        --profile=sysadmin \
        -q \
        -- chroot /host bash -c '
echo "===LSHW_NETWORK==="
lshw -class network -short 2>/dev/null || echo "(lshw not installed or no permission)"
echo ""
echo "===IP_ADDR==="
ip -br addr show 2>/dev/null || echo "(ip command unavailable)"
echo ""
echo "===RDMA_LINK==="
rdma link 2>/dev/null || echo "(rdma not available)"
echo ""
echo "===END==="
' < <(sleep "${KUBECTL_DEBUG_GPU_TIMEOUT:-15}") 2>/dev/null || _rc=$?

    if [[ ${_rc} -eq 124 ]]; then
        echo "===LSHW_NETWORK===
(timed out after ${KUBECTL_DEBUG_TIMEOUT}s)
===END==="
    elif [[ ${_rc} -ne 0 ]]; then
        echo "===LSHW_NETWORK===
(unavailable — kubectl debug exit ${_rc})
===END==="
    fi
}

# -- Display network sections for a node --------------------------------------
# Args: $1 = node_name, $2 = shape, $3 = full_output from _netverify_collect
_netverify_display_node() {
    local _node="$1" _shape="$2" _output="$3"
    local _section _line

    # Check for failure — return 1 so caller prints [WARN]
    _section=$(_storage_extract_section "$_output" "LSHW_NETWORK")
    if [[ "$_section" == *"timed out"* ]]; then
        return 1
    elif [[ "$_section" == "(unavailable"* ]]; then
        return 2
    fi

    # ── Network Hardware (lshw) ──
    if [[ -n "$_section" && "$_section" != "(lshw not installed or no permission)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            local _color="$NC"
            if [[ "$_line" == *"mlx"* || "$_line" == *"Mellanox"* || "$_line" == *"ConnectX"* || "$_line" == *"InfiniBand"* ]]; then
                _color="$GREEN"
            elif [[ "$_line" == *"Virtual"* || "$_line" == *"virtio"* || "$_line" == *"vnic"* ]]; then
                _color="$YELLOW"
            fi
            printf "      ${CYAN}%-18s${NC} ${_color}%s${NC}\n" "Network HW:" "$_line"
        done <<< "$_section"
    else
        printf "      ${CYAN}%-18s${NC} ${GRAY}%s${NC}\n" "Network HW:" "(lshw not installed or no permission)"
    fi

    # ── IP Address Summary ──
    _section=$(_storage_extract_section "$_output" "IP_ADDR")
    if [[ -n "$_section" && "$_section" != "(ip command unavailable)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            local _color="$NC"
            if [[ "$_line" == *" UP "* ]]; then
                _color="$GREEN"
            elif [[ "$_line" == *" DOWN "* ]]; then
                _color="$RED"
            elif [[ "$_line" == *"UNKNOWN"* ]]; then
                _color="$YELLOW"
            fi
            printf "      ${CYAN}%-18s${NC} ${_color}%s${NC}\n" "IP Address:" "$_line"
        done <<< "$_section"
    else
        printf "      ${CYAN}%-18s${NC} ${GRAY}%s${NC}\n" "IP Address:" "(ip command unavailable)"
    fi

    # ── RDMA Links ──
    _section=$(_storage_extract_section "$_output" "RDMA_LINK")
    if [[ -n "$_section" && "$_section" != "(rdma not available)" ]]; then
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            local _color="$NC"
            if [[ "$_line" == *"state ACTIVE"* ]]; then
                _color="$GREEN"
            elif [[ "$_line" == *"state DOWN"* || "$_line" == *"state INACTIVE"* ]]; then
                _color="$RED"
            fi
            printf "      ${CYAN}%-18s${NC} ${_color}%s${NC}\n" "RDMA Link:" "$_line"
        done <<< "$_section"
    else
        printf "      ${CYAN}%-18s${NC} ${GRAY}%s${NC}\n" "RDMA Link:" "(rdma not available)"
    fi
}

# -- Compare network config across nodes --------------------------------------
# Args: node_count, then parallel arrays via nameref: names[], shapes[], raw_outputs[]
_netverify_compare() {
    local -n _cn_names=$1 _cn_shapes=$2 _cn_raw=$3
    local _nc=${#_cn_names[@]}

    echo ""
    _ui_subheader "Node Network Comparison" 0
    echo ""

    local _lw=22 _cw=$(( (140 - 22) / _nc ))
    [[ $_cw -gt 35 ]] && _cw=35

    _comp_header $_lw $_cw "${_cn_names[@]}"
    # Shape sub-header
    printf "  ${GRAY}%-${_lw}s${NC}" ""
    for _s in "${_cn_shapes[@]}"; do printf " ${GRAY}%-${_cw}s${NC}" "${_s:0:$_cw}"; done
    echo ""
    _comp_sep $_lw $_cw $_nc

    # Extract metrics per node
    local -a _v_nic_ct=() _v_primary=() _v_up=() _v_down=() _v_rdma=() _v_rdma_ct=() _v_ifaces=()
    for ((_ni=0; _ni<_nc; _ni++)); do
        local _raw="${_cn_raw[$_ni]}"
        local _lshw _ip _rdma
        _lshw=$(_storage_extract_section "$_raw" "LSHW_NETWORK")
        _ip=$(_storage_extract_section "$_raw" "IP_ADDR")
        _rdma=$(_storage_extract_section "$_raw" "RDMA_LINK")

        # NIC count
        local _nics=0
        [[ -n "$_lshw" && "$_lshw" != *"not installed"* && "$_lshw" != *"timed out"* ]] && \
            _nics=$(echo "$_lshw" | grep -c "network" 2>/dev/null || true)
        _v_nic_ct+=("$_nics")

        # Primary IP (first UP non-lo)
        local _pip="N/A"
        if [[ -n "$_ip" && "$_ip" != *"unavailable"* ]]; then
            _pip=$(echo "$_ip" | grep " UP " | head -1 | awk '{print $1"="$3}')
            [[ -z "$_pip" ]] && _pip="N/A"
        fi
        _v_primary+=("$_pip")

        # Interface list
        local _iflist="N/A"
        if [[ -n "$_ip" && "$_ip" != *"unavailable"* ]]; then
            _iflist=$(echo "$_ip" | awk '$1 != "lo" {printf "%s ", $1}' | xargs)
            [[ -z "$_iflist" ]] && _iflist="N/A"
        fi
        _v_ifaces+=("$_iflist")

        # UP / DOWN counts
        local _u=0 _d=0
        if [[ -n "$_ip" && "$_ip" != *"unavailable"* ]]; then
            _u=$(echo "$_ip" | grep -c " UP " 2>/dev/null || true)
            _d=$(echo "$_ip" | grep -c " DOWN " 2>/dev/null || true)
        fi
        _v_up+=("$_u")
        _v_down+=("$_d")

        # RDMA
        if [[ -z "$_rdma" || "$_rdma" == *"not available"* ]]; then
            _v_rdma+=("No")
            _v_rdma_ct+=("0")
        else
            _v_rdma+=("Yes")
            local _act
            _act=$(echo "$_rdma" | grep -c "ACTIVE" 2>/dev/null || true)
            _v_rdma_ct+=("${_act} active")
        fi
    done

    _comp_row $_lw $_cw "NIC Count" "${_v_nic_ct[@]}"
    _comp_row $_lw $_cw "Primary IP" "${_v_primary[@]}"
    _comp_row $_lw $_cw "Interfaces" "${_v_ifaces[@]}"
    _comp_row $_lw $_cw "NICs UP" "${_v_up[@]}"
    _comp_row $_lw $_cw "NICs DOWN" "${_v_down[@]}"
    _comp_row $_lw $_cw "RDMA Available" "${_v_rdma[@]}"
    _comp_row $_lw $_cw "RDMA Links" "${_v_rdma_ct[@]}"
    echo ""
}

# -- Main network verification function ----------------------------------------
k8s_node_network() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"
    
    # Check kubectl availability
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"
        return 1
    fi
    
    while true; do
        _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
        _region="${FOCUS_REGION:-$REGION}"
        echo ""
        _ui_menu_header "NODE NETWORK CONFIGURATION" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "Network Verification" \
            --cmd "kubectl get nodes | kubectl debug node/<n> -- chroot /host lshw -class network -short | ip -br addr show | rdma link" \
            --env
        
        # ── Discover K8s nodes ──
        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"
            _step_finish
            echo -e "  ${RED}No K8s nodes found — check kubectl context${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct
        _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"
        _step_finish
        echo ""
        
        # ── Build node table ──
        declare -A _NV_MAP=()    # i# -> node_name|shape|status|ocid
        local _nv_idx=0
        local _nv_tmpfile="${TEMP_DIR}/netverify_nodes_$$"
        rm -f "$_nv_tmpfile"
        
        printf "  ${BOLD}%-5s %-45s %-28s %-8s %-55s${NC}\n" \
            "ID" "Node Name" "Shape" "Status" "Instance OCID"
        print_separator 145
        
        while IFS='|' read -r _nname _shape _ready _ocid; do
            [[ -z "$_nname" ]] && continue
            ((_nv_idx++))
            local _iid="i${_nv_idx}"
            
            local _st_color="$GREEN" _st_label="Ready"
            if [[ "$_ready" != "True" ]]; then
                _st_color="$RED"; _st_label="NotRdy"
            fi
            
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s ${_st_color}%-8s${NC} ${GRAY}%-55s${NC}\n" \
                "$_iid" "${_nname:0:45}" "${_shape:0:28}" "$_st_label" "${_ocid:0:55}"
            
            echo "${_iid}|${_nname}|${_shape}|${_st_label}|${_ocid}" >> "$_nv_tmpfile"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // .metadata.labels["beta.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)
        
        # Read map from temp file
        if [[ -f "$_nv_tmpfile" ]]; then
            while IFS='|' read -r _iid _nname _shape _status _ocid; do
                _NV_MAP[$_iid]="${_nname}|${_shape}|${_status}|${_ocid}"
            done < "$_nv_tmpfile"
            rm -f "$_nv_tmpfile"
        fi
        
        local _total=${#_NV_MAP[@]}
        echo ""
        echo -e "  ${GRAY}${_total} K8s nodes │ debug image: ${KUBECTL_DEBUG_IMAGE} │ timeout: ${KUBECTL_DEBUG_TIMEOUT}s${NC}"
        echo ""
        
        # ── Actions ──
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}i#${NC}${WHITE})${NC}      View network config for node (e.g., ${YELLOW}i1${NC}, ${YELLOW}i1-i3${NC}, ${YELLOW}i1,i3,i5${NC}, ${YELLOW}all${NC})"
        echo -e "  ${GREEN}comp${NC}${WHITE})${NC}    Compare nodes side-by-side (e.g., ${GREEN}comp i1,i3${NC}  ${GREEN}comp all${NC})"
        echo -e "  ${MAGENTA}r${NC}${WHITE})${NC}      Refresh node list"
        echo -e "  ${CYAN}b${NC}${WHITE})${NC}      Back"
        echo ""
        _ui_prompt "Node Network" "i#, i#-i#, all, comp i#,i#, r, b"

        local _sel
        read -r _sel
        [[ "${_sel:-}" == :* ]] && _nav_try_jump "$_sel" && return

        case "$_sel" in
            b|B|"") return ;;
            r|R) continue ;;
            show|SHOW) continue ;;
            comp*)
                local _comp_sel="${_sel#comp}"
                _comp_sel="${_comp_sel# }"
                if [[ -z "$_comp_sel" ]]; then
                    echo -e "  ${RED}Usage: comp i1,i2 or comp i1-i3 or comp all${NC}"; sleep 1; continue
                fi
                if ! _parse_targets "i" "$_comp_sel" "$_total"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                if [[ ${#_SEL_INDICES[@]} -lt 2 ]]; then
                    echo -e "  ${RED}Compare requires at least 2 nodes${NC}"; sleep 1; continue
                fi
                local -a _comp_names=() _comp_shapes=() _comp_raw=()
                local _interrupted=false
                trap '_interrupted=true' INT
                for _cidx in "${_SEL_INDICES[@]}"; do
                    [[ "$_interrupted" == true ]] && break
                    local _ciid="i${_cidx}"
                    local _cdata="${_NV_MAP[$_ciid]:-}"
                    [[ -z "$_cdata" ]] && continue
                    local _cn _cs _cst _cocid
                    IFS='|' read -r _cn _cs _cst _cocid <<< "$_cdata"
                    echo -e "  Collecting from ${GREEN}${_cn}${NC}  (${_cs})..."
                    local _craw
                    _craw=$(_netverify_collect "$_cn")
                    _comp_names+=("$_cn")
                    _comp_shapes+=("$_cs")
                    _comp_raw+=("$_craw")
                done
                trap - INT
                if [[ "$_interrupted" == true ]]; then
                    echo -e "\n${YELLOW}[INFO]${NC} Interrupted"
                elif [[ ${#_comp_names[@]} -ge 2 ]]; then
                    _netverify_compare _comp_names _comp_shapes _comp_raw
                fi
                echo ""
                _ui_pause "return to node list"
                continue
                ;;
            *)
                # Parse i# selection
                if ! _parse_targets "i" "$_sel" "$_total"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                [[ ${#_SEL_INDICES[@]} -eq 0 ]] && continue

                if [[ ${#_SEL_INDICES[@]} -gt 1 ]]; then
                    # Multiple nodes: parallel collection
                    local -a _nv_pairs=()
                    for _tidx in "${_SEL_INDICES[@]}"; do
                        local _tdata="${_NV_MAP[i${_tidx}]:-}"
                        [[ -z "$_tdata" ]] && continue
                        _nv_pairs+=("${_tidx}|${_tdata%%|*}")
                    done
                    _k8s_parallel_collect "_netverify_collect" "${_nv_pairs[@]}"

                    for _tidx in "${_SEL_INDICES[@]}"; do
                        local _tdata="${_NV_MAP[i${_tidx}]:-}"
                        [[ -z "$_tdata" ]] && continue
                        local _tn _ts _tst _tocid
                        IFS='|' read -r _tn _ts _tst _tocid <<< "$_tdata"
                        echo ""
                        _ui_subheader "Node Network — ${_tn}  (${_ts})" 0
                        local _net_output=""
                        [[ -f "$_PCOLLECT_DIR/${_tidx}.raw" ]] && _net_output=$(cat "$_PCOLLECT_DIR/${_tidx}.raw")
                        if [[ -z "$_net_output" ]]; then
                            echo -e "  ${YELLOW}[WARN]${NC} kubectl debug returned no data for ${GREEN}${_tn}${NC}"
                        else
                            local _nrc=0
                            _netverify_display_node "$_tn" "$_ts" "$_net_output" || _nrc=$?
                            if [[ $_nrc -eq 1 ]]; then
                                echo -e "  ${YELLOW}[WARN]${NC} kubectl debug timed out for ${GREEN}${_tn}${NC} (>${KUBECTL_DEBUG_TIMEOUT}s)"
                            elif [[ $_nrc -eq 2 ]]; then
                                echo -e "  ${YELLOW}[WARN]${NC} kubectl debug failed for ${GREEN}${_tn}${NC}"
                            fi
                        fi
                    done
                    rm -rf "$_PCOLLECT_DIR" 2>/dev/null
                else
                    # Single node: direct collection
                    local _tidx="${_SEL_INDICES[0]}"
                    local _tdata="${_NV_MAP[i${_tidx}]:-}"
                    [[ -z "$_tdata" ]] && continue
                    local _tn _ts _tst _tocid
                    IFS='|' read -r _tn _ts _tst _tocid <<< "$_tdata"
                    echo -e "Collecting network info for ${GREEN}${_tn}${NC}  (${_ts})..."
                    local _net_output _nrc=0
                    _net_output=$(_netverify_collect "$_tn")
                    _netverify_display_node "$_tn" "$_ts" "$_net_output" || _nrc=$?
                    if [[ $_nrc -eq 1 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug timed out for ${GREEN}${_tn}${NC} (>${KUBECTL_DEBUG_TIMEOUT}s)"
                    elif [[ $_nrc -eq 2 ]]; then
                        echo -e "${YELLOW}[WARN]${NC} kubectl debug failed for ${GREEN}${_tn}${NC}"
                    fi
                fi
                echo ""
                _ui_pause "return to node list"
                continue
                ;;
        esac
    done
}

# GPU HEALTH — nvidia-smi via kubectl debug (k,3,4)
#===============================================================================
# Collects: per-GPU temp, power, ECC, memory, utilization, NVLink, topology
# Uses: kubectl debug with chroot/host (same pattern as storage/network verify)
#--------------------------------------------------------------------------------

# -- Collect GPU info from a node via kubectl debug ----------------------------
# Args: $1 = node_name
_gpuhealth_collect() {
    local _node="$1"
    local _rc=0

    # Clean up stale debug pods for this node before starting
    _kubectl_debug_cleanup "$_node"

    timeout --foreground --kill-after=3 "${KUBECTL_DEBUG_GPU_TIMEOUT}" kubectl debug "node/${_node}" \
        -i \
        --image="${KUBECTL_DEBUG_IMAGE}" \
        --profile=sysadmin \
        -q \
        -- chroot /host bash -c '
echo "===GPU_CSV==="
nvidia-smi --query-gpu=index,gpu_bus_id,name,temperature.gpu,power.draw,power.limit,memory.used,memory.total,ecc.errors.uncorrected.volatile.total,ecc.errors.uncorrected.aggregate.total,retired_pages.pending,utilization.gpu,clocks.current.sm,clocks.max.sm --format=csv,noheader,nounits 2>/dev/null || echo "(nvidia-smi unavailable)"
echo ""
echo "===GPU_DRIVER==="
nvidia-smi --query-gpu=driver_version,vbios_version,gpu_bus_id --format=csv,noheader 2>/dev/null | head -1 || echo "N/A, N/A, N/A"
echo ""
echo "===GPU_TOPO==="
nvidia-smi topo -m 2>/dev/null || echo "(topology unavailable)"
echo ""
echo "===NVLINK_STATUS==="
nvidia-smi nvlink -s 2>/dev/null || echo "(nvlink status unavailable)"
echo ""
echo "===NVLINK_ERRORS==="
nvidia-smi nvlink -e 2>/dev/null || echo "(nvlink errors unavailable)"
echo ""
echo "===ECC_DETAIL==="
nvidia-smi --query-gpu=index,ecc.errors.corrected.volatile.total,ecc.errors.corrected.aggregate.total,ecc.errors.uncorrected.volatile.total,ecc.errors.uncorrected.aggregate.total,retired_pages.sbe,retired_pages.dbe,retired_pages.pending --format=csv,noheader,nounits 2>/dev/null || echo "(ecc detail unavailable)"
echo ""
echo "===END==="
' < <(sleep "${KUBECTL_DEBUG_GPU_TIMEOUT:-15}") 2>/dev/null || _rc=$?

    if [[ ${_rc} -eq 124 ]]; then
        echo "===GPU_CSV===
(timed out after ${KUBECTL_DEBUG_GPU_TIMEOUT}s)
===END==="
    elif [[ ${_rc} -ne 0 ]]; then
        echo "===GPU_CSV===
(kubectl debug failed — exit ${_rc})
===END==="
    fi
}

# -- Display GPU health for one node ------------------------------------------
# Args: $1=node_name $2=shape $3=full_output
_gpuhealth_display_node() {
    local _node="$1" _shape="$2" _output="$3"

    echo ""
    _ui_subheader "GPU Health — ${_node}" 0
    echo -e "  ${CYAN}Shape:${NC} ${WHITE}${_shape}${NC}"

    # Driver info
    local _drv_section
    _drv_section=$(awk '/^===GPU_DRIVER===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_drv_section" && "$_drv_section" != *"N/A"* && "$_drv_section" != *"Failed"* && "$_drv_section" != *"failed"* ]]; then
        local _drv_ver _vbios
        _drv_ver=$(echo "$_drv_section" | head -1 | cut -d',' -f1 | xargs)
        _vbios=$(echo "$_drv_section" | head -1 | cut -d',' -f2 | xargs)
        echo -e "  ${CYAN}Driver:${NC} ${WHITE}${_drv_ver}${NC}  ${CYAN}VBIOS:${NC} ${WHITE}${_vbios}${NC}"
    fi
    echo ""

    # Per-GPU table
    local _gpu_csv
    _gpu_csv=$(awk '/^===GPU_CSV===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")

    if [[ -z "$_gpu_csv" || "$_gpu_csv" == *"unavailable"* || "$_gpu_csv" == *"timed out"* || "$_gpu_csv" == *"failed"* || "$_gpu_csv" == *"Failed"* || "$_gpu_csv" == *"NVML"* ]]; then
        echo -e "  ${RED}${_gpu_csv:-nvidia-smi not available}${NC}"
        echo -e "  ${GRAY}Check that the NVIDIA driver is loaded on this node (nvidia-smi, dmesg | grep nvidia)${NC}"
        return
    fi

    printf "  ${BOLD}%-4s %-14s %-22s %7s %15s %9s %9s %8s %6s %6s %10s${NC}\n" \
        "GPU" "Bus ID" "Product" "Temp" "Power" "Mem Use" "Mem Tot" "ECC-Unc" "Retire" "Util%" "Clk MHz"
    print_separator 125

    local _any_warn=0
    while IFS=',' read -r _idx _bus _name _temp _pwr _plim _mused _mtot _ecc_uv _ecc_ua _ret _util _clk _clkmax; do
        [[ -z "$_idx" || "$_idx" == *"unavailable"* ]] && continue
        # Trim whitespace
        _idx=$(echo "$_idx" | xargs); _bus=$(echo "$_bus" | xargs); _name=$(echo "$_name" | xargs)
        _temp=$(echo "$_temp" | xargs); _pwr=$(echo "$_pwr" | xargs); _plim=$(echo "$_plim" | xargs)
        _mused=$(echo "$_mused" | xargs); _mtot=$(echo "$_mtot" | xargs)
        _ecc_uv=$(echo "$_ecc_uv" | xargs); _ecc_ua=$(echo "$_ecc_ua" | xargs)
        _ret=$(echo "$_ret" | xargs); _util=$(echo "$_util" | xargs)
        _clk=$(echo "$_clk" | xargs); _clkmax=$(echo "$_clkmax" | xargs)

        # Color: temperature
        local _tc="$GREEN"
        if [[ "$_temp" =~ ^[0-9]+$ ]]; then
            (( _temp >= GPU_TEMP_CRIT )) && { _tc="$RED"; _any_warn=1; }
            (( _temp >= GPU_TEMP_WARN && _temp < GPU_TEMP_CRIT )) && { _tc="$YELLOW"; }
        fi

        # Color: ECC uncorrected
        local _ec="$GREEN"
        local _ecc_total=0
        [[ "$_ecc_uv" =~ ^[0-9]+$ ]] && (( _ecc_total += _ecc_uv ))
        [[ "$_ecc_ua" =~ ^[0-9]+$ ]] && (( _ecc_total += _ecc_ua ))
        (( _ecc_total >= GPU_ECC_UNCORR_CRIT )) && { _ec="$RED"; _any_warn=1; }

        # Color: retired pages
        local _rc_c="$GREEN"
        [[ "$_ret" =~ ^[0-9]+$ && "$_ret" -ge "$GPU_RETIRED_PAGES_WARN" ]] && { _rc_c="$YELLOW"; _any_warn=1; }

        # Power with limit
        local _pwr_disp="${_pwr}W"
        [[ -n "$_plim" && "$_plim" != "N/A" ]] && _pwr_disp="${_pwr}/${_plim}W"

        # Clock with max
        local _clk_disp="${_clk}"
        [[ -n "$_clkmax" && "$_clkmax" != "N/A" ]] && _clk_disp="${_clk}/${_clkmax}"

        printf "  ${YELLOW}%-4s${NC} %-14s %-22s ${_tc}%7s${NC} %15s ${WHITE}%9s${NC} %9s ${_ec}%8s${NC} ${_rc_c}%6s${NC} %6s %10s\n" \
            "$_idx" "$_bus" "${_name:0:22}" "${_temp}°C" "$_pwr_disp" "${_mused}M" "${_mtot}M" "$_ecc_total" "$_ret" "${_util}%" "$_clk_disp"
    done <<< "$_gpu_csv"

    # ECC detail
    local _ecc_section
    _ecc_section=$(awk '/^===ECC_DETAIL===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_ecc_section" && "$_ecc_section" != *"unavailable"* ]]; then
        echo ""
        echo -e "  ${CYAN}ECC Detail:${NC}"
        printf "    ${BOLD}%-4s %12s %12s %12s %12s %10s %10s %8s${NC}\n" \
            "GPU" "Corr-Vol" "Corr-Agg" "Uncorr-Vol" "Uncorr-Agg" "Ret-SBE" "Ret-DBE" "Pending"
        while IFS=',' read -r _idx _cv _ca _uv _ua _rsbe _rdbe _rp; do
            [[ -z "$_idx" || "$_idx" == *"unavailable"* ]] && continue
            _idx=$(echo "$_idx" | xargs)
            local _uvc="$GREEN" _uac="$GREEN"
            _uv=$(echo "$_uv" | xargs); _ua=$(echo "$_ua" | xargs)
            [[ "$_uv" =~ ^[0-9]+$ && "$_uv" -gt 0 ]] && _uvc="$RED"
            [[ "$_ua" =~ ^[0-9]+$ && "$_ua" -gt 0 ]] && _uac="$RED"
            printf "    %-4s %12s %12s ${_uvc}%12s${NC} ${_uac}%12s${NC} %10s %10s %8s\n" \
                "$_idx" "$(echo "$_cv"|xargs)" "$(echo "$_ca"|xargs)" "$_uv" "$_ua" \
                "$(echo "$_rsbe"|xargs)" "$(echo "$_rdbe"|xargs)" "$(echo "$_rp"|xargs)"
        done <<< "$_ecc_section"
    fi

    # NVLink status
    local _nvl_section
    _nvl_section=$(awk '/^===NVLINK_STATUS===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_nvl_section" && "$_nvl_section" != *"unavailable"* ]]; then
        local _nvl_lines
        _nvl_lines=$(echo "$_nvl_section" | grep -cE "Link [0-9]" 2>/dev/null || true)
        local _nvl_inactive
        _nvl_inactive=$(echo "$_nvl_section" | grep -ci "inactive" 2>/dev/null || true)
        echo ""
        if [[ "$_nvl_inactive" -gt 0 ]]; then
            echo -e "  ${RED}NVLink:${NC} ${_nvl_lines} links, ${RED}${_nvl_inactive} INACTIVE${NC}"
            _any_warn=1
        else
            echo -e "  ${CYAN}NVLink:${NC} ${GREEN}${_nvl_lines} links active${NC}"
        fi
    fi

    # NVLink errors
    local _nvle_section
    _nvle_section=$(awk '/^===NVLINK_ERRORS===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_nvle_section" && "$_nvle_section" != *"unavailable"* ]]; then
        local _replay_total=0
        while read -r _line; do
            local _val
            _val=$(echo "$_line" | grep -oP 'Replay Errors\s*:\s*\K[0-9]+' 2>/dev/null)
            [[ "$_val" =~ ^[0-9]+$ ]] && (( _replay_total += _val ))
        done <<< "$_nvle_section"
        if [[ "$_replay_total" -gt "$GPU_NVLINK_ERROR_WARN" ]]; then
            echo -e "  ${RED}NVLink Replay Errors:${NC} ${RED}${_replay_total}${NC} ${GRAY}(threshold: ${GPU_NVLINK_ERROR_WARN})${NC}"
            _any_warn=1
        elif [[ "$_replay_total" -gt 0 ]]; then
            echo -e "  ${CYAN}NVLink Replay Errors:${NC} ${YELLOW}${_replay_total}${NC}"
        fi
    fi

    # GPU topology
    local _topo_section
    _topo_section=$(awk '/^===GPU_TOPO===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_topo_section" && "$_topo_section" != *"unavailable"* ]]; then
        echo ""
        echo -e "  ${CYAN}GPU Topology (nvidia-smi topo -m):${NC}"
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            echo -e "    ${GRAY}${_line}${NC}"
        done <<< "$_topo_section"
    fi

    # Summary verdict
    echo ""
    if [[ "$_any_warn" -gt 0 ]]; then
        echo -e "  ${RED}⚠ ISSUES DETECTED${NC} — review highlighted values above"
    else
        echo -e "  ${GREEN}✓ GPU HEALTHY${NC} — all metrics within thresholds"
    fi
}

# -- Compare GPU health across nodes ------------------------------------------
_gpuhealth_compare() {
    local -n _cg_names=$1 _cg_shapes=$2 _cg_raw=$3
    local _nc=${#_cg_names[@]}

    echo ""
    _ui_subheader "GPU Health Comparison" 0
    echo ""

    local _lw=22 _cw=$(( (140 - 22) / _nc ))
    [[ $_cw -gt 35 ]] && _cw=35

    _comp_header $_lw $_cw "${_cg_names[@]}"
    printf "  ${GRAY}%-${_lw}s${NC}" ""
    for _s in "${_cg_shapes[@]}"; do printf " ${GRAY}%-${_cw}s${NC}" "${_s:0:$_cw}"; done
    echo ""
    _comp_sep $_lw $_cw $_nc

    local -a _v_gpu_ct=() _v_model=() _v_driver=() _v_max_temp=() _v_power=()
    local -a _v_ecc=() _v_retired=() _v_util=() _v_clock=() _v_nvlink=()

    for ((_gi=0; _gi<_nc; _gi++)); do
        local _raw="${_cg_raw[$_gi]}"
        local _csv _drv_section _nvl_section

        _csv=$(awk '/^===GPU_CSV===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")
        _drv_section=$(awk '/^===GPU_DRIVER===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")
        _nvl_section=$(awk '/^===NVLINK_STATUS===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")

        if [[ -z "$_csv" || "$_csv" == *"unavailable"* || "$_csv" == *"timed out"* || "$_csv" == *"failed"* ]]; then
            _v_gpu_ct+=("N/A"); _v_model+=("N/A"); _v_driver+=("N/A"); _v_max_temp+=("N/A")
            _v_power+=("N/A"); _v_ecc+=("N/A"); _v_retired+=("N/A"); _v_util+=("N/A")
            _v_clock+=("N/A"); _v_nvlink+=("N/A")
            continue
        fi

        # GPU count
        local _gct=0 _model="N/A" _mt=0 _tpwr=0 _tplim=0 _tecc=0 _tret=0 _mutil=0 _mclk="" _mclkmax=""
        while IFS=',' read -r _idx _bus _name _temp _pwr _plim _mused _mtot _euv _eua _ret _util _clk _clkmax; do
            [[ -z "$_idx" || "$_idx" == *"unavailable"* ]] && continue
            ((_gct++))
            [[ $_gct -eq 1 ]] && _model=$(echo "$_name" | xargs)
            _temp=$(echo "$_temp" | xargs); _pwr=$(echo "$_pwr" | xargs); _plim=$(echo "$_plim" | xargs)
            _euv=$(echo "$_euv" | xargs); _eua=$(echo "$_eua" | xargs); _ret=$(echo "$_ret" | xargs)
            _util=$(echo "$_util" | xargs); _clk=$(echo "$_clk" | xargs); _clkmax=$(echo "$_clkmax" | xargs)
            [[ "$_temp" =~ ^[0-9]+$ && "$_temp" -gt "$_mt" ]] && _mt=$_temp
            [[ "$_pwr" =~ ^[0-9.]+$ ]] && _tpwr=$(awk "BEGIN{print $_tpwr + $_pwr}")
            [[ "$_plim" =~ ^[0-9.]+$ ]] && _tplim=$(awk "BEGIN{print $_tplim + $_plim}")
            [[ "$_euv" =~ ^[0-9]+$ ]] && ((_tecc+=_euv))
            [[ "$_eua" =~ ^[0-9]+$ ]] && ((_tecc+=_eua))
            [[ "$_ret" =~ ^[0-9]+$ ]] && ((_tret+=_ret))
            [[ "$_util" =~ ^[0-9]+$ && "$_util" -gt "$_mutil" ]] && _mutil=$_util
            [[ -z "$_mclk" ]] && { _mclk="$_clk"; _mclkmax="$_clkmax"; }
        done <<< "$_csv"

        _v_gpu_ct+=("$_gct")
        _v_model+=("${_model:0:30}")

        # Driver
        local _dv="N/A"
        [[ -n "$_drv_section" && "$_drv_section" != *"N/A"* ]] && \
            _dv=$(echo "$_drv_section" | head -1 | cut -d',' -f1 | xargs)
        _v_driver+=("$_dv")

        _v_max_temp+=("${_mt}°C")
        _v_power+=("${_tpwr}/${_tplim}W")
        _v_ecc+=("$_tecc")
        _v_retired+=("$_tret")
        _v_util+=("${_mutil}%")
        local _clk_disp="${_mclk:-N/A}"
        [[ -n "$_mclkmax" && "$_mclkmax" != "N/A" ]] && _clk_disp="${_mclk}/${_mclkmax}"
        _v_clock+=("${_clk_disp}MHz")

        # NVLink
        local _nvl="N/A"
        if [[ -n "$_nvl_section" && "$_nvl_section" != *"unavailable"* ]]; then
            if echo "$_nvl_section" | grep -qi "error\|inactive"; then
                _nvl="Errors"
            else
                _nvl="OK"
            fi
        fi
        _v_nvlink+=("$_nvl")
    done

    _comp_row $_lw $_cw "GPU Count"     "${_v_gpu_ct[@]}"
    _comp_row $_lw $_cw "GPU Model"     "${_v_model[@]}"
    _comp_row $_lw $_cw "Driver"        "${_v_driver[@]}"
    _comp_row $_lw $_cw "Max Temp"      "${_v_max_temp[@]}"
    _comp_row $_lw $_cw "Power (cur/lim)" "${_v_power[@]}"
    _comp_row $_lw $_cw "ECC Uncorrected" "${_v_ecc[@]}"
    _comp_row $_lw $_cw "Retired Pages" "${_v_retired[@]}"
    _comp_row $_lw $_cw "Max Util%"     "${_v_util[@]}"
    _comp_row $_lw $_cw "Clock MHz"     "${_v_clock[@]}"
    _comp_row $_lw $_cw "NVLink"        "${_v_nvlink[@]}"
    echo ""
}

# -- Main GPU health verification function ------------------------------------
k8s_node_gpu_health() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"

    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"; return 1
    fi

    while true; do
        _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
        _region="${FOCUS_REGION:-$REGION}"
        echo ""
        _ui_menu_header "NODE GPU HEALTH (nvidia-smi)" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "GPU Health" \
            --cmd "kubectl get nodes | kubectl debug node/<n> -- chroot /host nvidia-smi --query-gpu=... | nvidia-smi topo -m | nvidia-smi nvlink -s/-e" \
            --env

        echo -e "  ${GRAY}Thresholds: temp≥${GPU_TEMP_WARN}°C warn, ≥${GPU_TEMP_CRIT}°C crit | ECC uncorr≥${GPU_ECC_UNCORR_CRIT} crit | retired≥${GPU_RETIRED_PAGES_WARN} warn | NVLink replay≥${GPU_NVLINK_ERROR_WARN} warn${NC}"
        echo -e "  ${GRAY}Configure in variables.sh: GPU_TEMP_WARN, GPU_TEMP_CRIT, GPU_ECC_UNCORR_CRIT, GPU_RETIRED_PAGES_WARN, GPU_NVLINK_ERROR_WARN${NC}"

        # Discover K8s nodes
        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"; _step_finish
            echo -e "  ${RED}No K8s nodes found${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct
        _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"
        _step_finish
        echo ""

        # Build node table — filter to GPU nodes only
        declare -A _GH_MAP=()
        local _gh_idx=0

        printf "  ${BOLD}%-5s %-45s %-28s %5s %-8s${NC}\n" \
            "ID" "Node Name" "Shape" "GPUs" "Status"
        print_separator 100

        while IFS='|' read -r _nname _shape _ready _gpu_ct _ocid; do
            [[ -z "$_nname" ]] && continue
            [[ "$_gpu_ct" == "0" || -z "$_gpu_ct" ]] && continue  # Skip non-GPU nodes
            ((_gh_idx++))
            local _iid="i${_gh_idx}"

            local _st_color="$GREEN" _st_label="Ready"
            [[ "$_ready" != "True" ]] && { _st_color="$RED"; _st_label="NotRdy"; }

            printf "  ${YELLOW}%-5s${NC} %-45s %-28s %5s ${_st_color}%-8s${NC}\n" \
                "$_iid" "${_nname:0:45}" "${_shape:0:28}" "$_gpu_ct" "$_st_label"

            _GH_MAP[$_iid]="${_nname}|${_shape}|${_gpu_ct}|${_ocid}"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // .metadata.labels["beta.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.status.capacity["nvidia.com/gpu"] // "0") as $gpus |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($gpus)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)

        if [[ $_gh_idx -eq 0 ]]; then
            echo -e "  ${YELLOW}No GPU nodes detected in this cluster${NC}"
            _ui_pause "return"; return
        fi

        echo ""
        echo -e "  ${YELLOW}i#${NC} Select node  ${YELLOW}all${NC} All GPU nodes  ${GREEN}comp${NC} Compare (e.g., ${GREEN}comp i1,i2${NC}  ${GREEN}comp all${NC})"
        echo -e "  ${MAGENTA}r${NC} Refresh  ${CYAN}b${NC} Back"
        echo ""
        _ui_prompt "GPU Health" "i#, all, comp i#,i#, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            comp*)
                local _comp_sel="${_choice#comp}"
                _comp_sel="${_comp_sel# }"
                if [[ -z "$_comp_sel" ]]; then
                    echo -e "  ${RED}Usage: comp i1,i2 or comp i1-i3 or comp all${NC}"; sleep 1; continue
                fi
                if ! _parse_targets "i" "$_comp_sel" "$_gh_idx"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                if [[ ${#_SEL_INDICES[@]} -lt 2 ]]; then
                    echo -e "  ${RED}Compare requires at least 2 nodes${NC}"; sleep 1; continue
                fi
                local -a _comp_names=() _comp_shapes=() _comp_raw=()
                local _interrupted=false
                trap '_interrupted=true' INT
                for _cidx in "${_SEL_INDICES[@]}"; do
                    [[ "$_interrupted" == true ]] && break
                    local _entry="${_GH_MAP[i${_cidx}]:-}"
                    [[ -z "$_entry" ]] && continue
                    local _cn="${_entry%%|*}"; local _rest="${_entry#*|}"
                    local _cs="${_rest%%|*}"
                    echo -e "  Collecting from ${GREEN}${_cn}${NC}  (${_cs})..."
                    local _craw
                    _craw=$(_gpuhealth_collect "$_cn" 2>/dev/null)
                    _comp_names+=("$_cn")
                    _comp_shapes+=("$_cs")
                    _comp_raw+=("$_craw")
                done
                trap - INT
                if [[ "$_interrupted" == true ]]; then
                    echo -e "\n${YELLOW}[INFO]${NC} Interrupted"
                elif [[ ${#_comp_names[@]} -ge 2 ]]; then
                    _gpuhealth_compare _comp_names _comp_shapes _comp_raw
                fi
                echo ""
                _ui_pause
                ;;
            all|ALL)
                echo ""
                local _gh_total=$_gh_idx
                local _gh_summary_file="${TEMP_DIR}/gpu_health_summary_$$"
                rm -f "$_gh_summary_file"

                # Phase 1: Parallel collection
                local -a _gh_pairs=()
                for (( _gi=1; _gi<=_gh_total; _gi++ )); do
                    local _entry="${_GH_MAP[i${_gi}]}"
                    [[ -z "$_entry" ]] && continue
                    _gh_pairs+=("${_gi}|${_entry%%|*}")
                done
                _k8s_parallel_collect "_gpuhealth_collect" "${_gh_pairs[@]}"

                # Phase 2: Display results sequentially + build summary
                for (( _gi=1; _gi<=_gh_total; _gi++ )); do
                    local _entry="${_GH_MAP[i${_gi}]}"
                    [[ -z "$_entry" ]] && continue
                    local _nname="${_entry%%|*}"; local _rest="${_entry#*|}"
                    local _shape="${_rest%%|*}"; _rest="${_rest#*|}"; local _gpus="${_rest%%|*}"

                    local _raw=""
                    [[ -f "$_PCOLLECT_DIR/${_gi}.raw" ]] && _raw=$(cat "$_PCOLLECT_DIR/${_gi}.raw")
                    _gpuhealth_display_node "$_nname" "$_shape" "$_raw"

                    # Collect summary line
                    local _csv_section
                    _csv_section=$(awk '/^===GPU_CSV===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")
                    local _max_temp=0 _total_ecc=0 _total_ret=0 _verdict="HEALTHY"
                    while IFS=',' read -r _ _ _ _t _ _ _ _ _euv _eua _rp _ _ _; do
                        _t=$(echo "$_t"|xargs); _euv=$(echo "$_euv"|xargs); _eua=$(echo "$_eua"|xargs); _rp=$(echo "$_rp"|xargs)
                        [[ "$_t" =~ ^[0-9]+$ && "$_t" -gt "$_max_temp" ]] && _max_temp=$_t
                        [[ "$_euv" =~ ^[0-9]+$ ]] && ((_total_ecc+=_euv))
                        [[ "$_eua" =~ ^[0-9]+$ ]] && ((_total_ecc+=_eua))
                        [[ "$_rp" =~ ^[0-9]+$ ]] && ((_total_ret+=_rp))
                    done <<< "$_csv_section"
                    (( _total_ecc >= GPU_ECC_UNCORR_CRIT )) && _verdict="DEGRADED"
                    (( _max_temp >= GPU_TEMP_CRIT )) && _verdict="OVERTEMP"
                    (( _total_ret >= GPU_RETIRED_PAGES_WARN )) && [[ "$_verdict" == "HEALTHY" ]] && _verdict="WARN"
                    echo "${_nname}|${_gpus}|${_max_temp}|${_total_ecc}|${_total_ret}|${_verdict}" >> "$_gh_summary_file"
                done
                rm -rf "$_PCOLLECT_DIR" 2>/dev/null

                # Print fleet summary
                if [[ -s "$_gh_summary_file" ]]; then
                    echo ""
                    _ui_subheader "Fleet GPU Health Summary" 0
                    echo ""
                    printf "  ${BOLD}%-3s %-45s %5s %8s %10s %8s %-10s${NC}\n" \
                        "#" "Node" "GPUs" "Temp(mx)" "ECC-Uncorr" "Retired" "Status"
                    print_separator 100
                    local _si=0
                    while IFS='|' read -r _sn _sg _st _se _sr _sv; do
                        ((_si++))
                        local _vc="$GREEN"
                        [[ "$_sv" == "DEGRADED" || "$_sv" == "OVERTEMP" ]] && _vc="$RED"
                        [[ "$_sv" == "WARN" ]] && _vc="$YELLOW"
                        local _tc="$GREEN"
                        [[ "$_st" =~ ^[0-9]+$ ]] && { (( _st >= GPU_TEMP_CRIT )) && _tc="$RED"; (( _st >= GPU_TEMP_WARN && _st < GPU_TEMP_CRIT )) && _tc="$YELLOW"; }
                        local _ecc_c="$GREEN"; [[ "$_se" -gt 0 ]] && _ecc_c="$RED"
                        printf "  ${YELLOW}%-3s${NC} %-45s %5s ${_tc}%7s°C${NC} ${_ecc_c}%10s${NC} %8s ${_vc}%-10s${NC}\n" \
                            "$_si" "${_sn:0:45}" "$_sg" "$_st" "$_se" "$_sr" "$_sv"
                    done < "$_gh_summary_file"
                    rm -f "$_gh_summary_file"
                fi
                echo ""
                _ui_pause
                ;;
            i[0-9]*)
                local _sel="${_choice}"
                local _entry="${_GH_MAP[$_sel]:-}"
                if [[ -z "$_entry" ]]; then
                    echo -e "  ${RED}Invalid selection: ${_sel}${NC}"; sleep 1; continue
                fi
                local _nname="${_entry%%|*}"; local _rest="${_entry#*|}"
                local _shape="${_rest%%|*}"

                echo ""
                echo -e "  ${YELLOW}Collecting GPU data from ${WHITE}${_nname}${NC}${YELLOW}...${NC}"
                local _raw
                _raw=$(_gpuhealth_collect "$_nname" 2>/dev/null)
                _gpuhealth_display_node "$_nname" "$_shape" "$_raw"
                echo ""
                _ui_pause
                ;;
            show|SHOW) continue ;;
            *) echo -e "  ${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#===============================================================================
# DMESG XID ERROR SCANNER (k,3,5)
#===============================================================================
# Scans kernel logs for GPU XID errors via kubectl debug
# XID reference: https://docs.nvidia.com/deploy/xid-errors/index.html
# XID_DESCRIPTIONS map declared in constants section near KUBECTL_DEBUG constants
#--------------------------------------------------------------------------------

# -- Collect dmesg from a node via kubectl debug --------------------------------
_xid_collect() {
    local _node="$1"
    local _rc=0

    # Clean up stale debug pods for this node before starting
    _kubectl_debug_cleanup "$_node"

    timeout --foreground --kill-after=3 "${KUBECTL_DEBUG_GPU_TIMEOUT}" kubectl debug "node/${_node}" \
        -i \
        --image="${KUBECTL_DEBUG_IMAGE}" \
        --profile=sysadmin \
        -q \
        -- chroot /host bash -c '
echo "===DMESG_XID==="
dmesg -T 2>/dev/null | grep -iE "NVRM.*Xid|nvidia.*Xid" | tail -100 || dmesg 2>/dev/null | grep -iE "NVRM.*Xid|nvidia.*Xid" | tail -100 || echo "(dmesg unavailable)"
echo ""
echo "===DMESG_GPU_ERRORS==="
dmesg -T 2>/dev/null | grep -iE "NVRM.*error|nvidia.*error|nvidia.*fail|gpu.*fallen|NVLink" | grep -v "Xid" | tail -30 || echo "(none)"
echo ""
echo "===END==="
' < <(sleep "${KUBECTL_DEBUG_GPU_TIMEOUT:-15}") 2>/dev/null || _rc=$?

    if [[ ${_rc} -eq 124 ]]; then
        echo "===DMESG_XID===
(timed out after ${KUBECTL_DEBUG_GPU_TIMEOUT}s)
===END==="
    elif [[ ${_rc} -ne 0 ]]; then
        echo "===DMESG_XID===
(kubectl debug failed — exit ${_rc})
===END==="
    fi
}

# -- Display XID scan results for a node ----------------------------------------
_xid_display_node() {
    local _node="$1" _output="$2"

    echo ""
    _ui_subheader "XID Error Scan — ${_node}" 0

    # Check if kubectl debug actually ran (marker present in output)
    if [[ "$_output" != *"===DMESG_XID==="* ]]; then
        echo -e "  ${RED}kubectl debug failed — no output received${NC}"
        return
    fi

    local _xid_section
    _xid_section=$(awk '/^===DMESG_XID===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")

    if [[ "$_xid_section" == *"unavailable"* || "$_xid_section" == *"timed out"* ]]; then
        echo -e "  ${RED}${_xid_section}${NC}"
        return
    fi

    # Empty section means dmesg ran but found no XID errors — handled below by _total_xid == 0

    # Parse XID errors — extract code + count
    declare -A _xid_counts=()
    declare -A _xid_last=()
    local _total_xid=0

    while IFS= read -r _line; do
        [[ -z "$_line" ]] && continue
        local _xid_code
        _xid_code=$(echo "$_line" | grep -oP 'Xid[^:]*:\s*\K[0-9]+' 2>/dev/null || echo "")
        [[ -z "$_xid_code" ]] && continue
        ((_total_xid++))
        _xid_counts[$_xid_code]=$(( ${_xid_counts[$_xid_code]:-0} + 1 ))
        _xid_last[$_xid_code]="$_line"
    done <<< "$_xid_section"

    if [[ $_total_xid -eq 0 ]]; then
        echo -e "  ${GREEN}✓ No XID errors found in kernel log${NC}"
    else
        echo -e "  ${YELLOW}Found ${_total_xid} XID error(s)${NC}"
        echo ""
        printf "  ${BOLD}%-6s %6s %-8s %-60s${NC}\n" "XID" "Count" "Severity" "Description"
        print_separator 90

        for _code in $(echo "${!_xid_counts[@]}" | tr ' ' '\n' | sort -n); do
            local _ct="${_xid_counts[$_code]}"
            local _info="${XID_DESCRIPTIONS[$_code]:-Unknown XID|WARN|No description available}"
            local _desc="${_info%%|*}"; local _rest="${_info#*|}"
            local _sev="${_rest%%|*}"; local _note="${_rest#*|}"

            local _sc="$YELLOW"
            [[ "$_sev" == "CRIT" ]] && _sc="$RED"

            printf "  ${YELLOW}%-6s${NC} %6s ${_sc}%-8s${NC} ${WHITE}%-40s${NC} ${GRAY}%s${NC}\n" \
                "$_code" "$_ct" "$_sev" "$_desc" "$_note"
        done

        # Show recent raw entries
        echo ""
        echo -e "  ${CYAN}Recent XID entries (last 10):${NC}"
        echo "$_xid_section" | tail -10 | while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            echo -e "    ${GRAY}${_line:0:140}${NC}"
        done
    fi

    # GPU errors (non-XID)
    local _err_section
    _err_section=$(awk '/^===DMESG_GPU_ERRORS===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_err_section" && "$_err_section" != *"(none)"* && "$_err_section" != *"unavailable"* ]]; then
        local _err_ct
        _err_ct=$(echo "$_err_section" | grep -c . 2>/dev/null || true)
        if [[ "$_err_ct" -gt 0 ]]; then
            echo ""
            echo -e "  ${CYAN}Other GPU kernel errors (${_err_ct}):${NC}"
            echo "$_err_section" | tail -5 | while IFS= read -r _line; do
                echo -e "    ${GRAY}${_line:0:140}${NC}"
            done
        fi
    fi
}

# -- Compare XID errors across nodes ------------------------------------------
_xid_compare() {
    local -n _cx_names=$1 _cx_shapes=$2 _cx_raw=$3
    local _nc=${#_cx_names[@]}

    echo ""
    _ui_subheader "XID Error Comparison" 0
    echo ""

    local _lw=22 _cw=$(( (140 - 22) / _nc ))
    [[ $_cw -gt 35 ]] && _cw=35

    _comp_header $_lw $_cw "${_cx_names[@]}"
    printf "  ${GRAY}%-${_lw}s${NC}" ""
    for _s in "${_cx_shapes[@]}"; do printf " ${GRAY}%-${_cw}s${NC}" "${_s:0:$_cw}"; done
    echo ""
    _comp_sep $_lw $_cw $_nc

    local -a _v_total=() _v_unique=() _v_crit=() _v_recent=() _v_status=()

    for ((_xi=0; _xi<_nc; _xi++)); do
        local _raw="${_cx_raw[$_xi]}"
        local _xid_section
        _xid_section=$(awk '/^===DMESG_XID===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")

        if [[ -z "$_xid_section" || "$_xid_section" == *"unavailable"* || "$_xid_section" == *"timed out"* ]]; then
            _v_total+=("N/A"); _v_unique+=("N/A"); _v_crit+=("N/A")
            _v_recent+=("N/A"); _v_status+=("N/A")
            continue
        fi

        # Count total XIDs
        local _tot=0 _crit_ct=0
        local -A _seen_xids=()
        local _last_ts=""

        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            local _xcode
            _xcode=$(echo "$_line" | grep -oP 'Xid[^:]*:\s*\K[0-9]+' | head -1)
            [[ -z "$_xcode" ]] && continue
            ((_tot++))
            _seen_xids[$_xcode]=1
            # Check if critical (from XID_DESCRIPTIONS)
            local _desc="${XID_DESCRIPTIONS[$_xcode]:-}"
            [[ "$_desc" == *"|CRIT|"* ]] && ((_crit_ct++))
            # Last timestamp
            local _ts
            _ts=$(echo "$_line" | grep -oP '^\[?\s*\K[A-Z][a-z]{2}\s+\d+\s+\d+:\d+:\d+' | head -1)
            [[ -n "$_ts" ]] && _last_ts="$_ts"
        done <<< "$_xid_section"

        _v_total+=("$_tot")
        _v_unique+=("${#_seen_xids[@]}")
        _v_crit+=("$_crit_ct")
        _v_recent+=("${_last_ts:-none}")

        local _st="CLEAN"
        [[ $_crit_ct -gt 0 ]] && _st="CRITICAL"
        [[ $_tot -gt 0 && $_crit_ct -eq 0 ]] && _st="HAS_XIDS"
        _v_status+=("$_st")
    done

    _comp_row $_lw $_cw "Total XIDs"     "${_v_total[@]}"
    _comp_row $_lw $_cw "Unique Types"   "${_v_unique[@]}"
    _comp_row $_lw $_cw "Critical XIDs"  "${_v_crit[@]}"
    _comp_row $_lw $_cw "Most Recent"    "${_v_recent[@]}"
    _comp_row $_lw $_cw "Status"         "${_v_status[@]}"
    echo ""
}

# -- Main dmesg XID scanner --------------------------------------------------
k8s_node_dmesg_xid() {
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"; return 1
    fi

    while true; do
        echo ""
        _ui_menu_header "DMESG XID ERROR SCANNER" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "XID Scanner" \
            --cmd "kubectl get nodes | kubectl debug node/<n> -- chroot /host dmesg -T | grep Xid" \
            --env

        echo -e "  ${GRAY}Scans kernel logs for NVIDIA XID errors — early indicators of GPU hardware problems${NC}"
        echo -e "  ${GRAY}Critical XIDs: 48 (DBE), 63/64 (page retirement), 74 (NVLink), 79 (GPU off bus)${NC}"

        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"; _step_finish
            echo -e "  ${RED}No K8s nodes found${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct; _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"; _step_finish
        echo ""

        declare -A _XD_MAP=()
        local _xd_idx=0

        printf "  ${BOLD}%-5s %-45s %-28s %5s %-8s${NC}\n" "ID" "Node Name" "Shape" "GPUs" "Status"
        print_separator 100

        while IFS='|' read -r _nname _shape _ready _gpu_ct _ocid; do
            [[ -z "$_nname" ]] && continue
            [[ "$_gpu_ct" == "0" || -z "$_gpu_ct" ]] && continue
            ((_xd_idx++))
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s %5s ${GREEN}%-8s${NC}\n" \
                "i${_xd_idx}" "${_nname:0:45}" "${_shape:0:28}" "$_gpu_ct" \
                "$( [[ "$_ready" == "True" ]] && echo "Ready" || echo "NotRdy" )"
            _XD_MAP[i${_xd_idx}]="${_nname}|${_shape}"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.status.capacity["nvidia.com/gpu"] // "0") as $gpus |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($gpus)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)

        if [[ $_xd_idx -eq 0 ]]; then
            echo -e "  ${YELLOW}No GPU nodes detected${NC}"
            _ui_pause "return"; return
        fi

        echo ""
        echo -e "  ${YELLOW}i#${NC} Select node  ${YELLOW}all${NC} Scan all GPU nodes  ${GREEN}comp${NC} Compare (e.g., ${GREEN}comp i1,i2${NC}  ${GREEN}comp all${NC})"
        echo -e "  ${MAGENTA}r${NC} Refresh  ${CYAN}b${NC} Back"
        echo ""
        _ui_prompt "XID Scanner" "i#, all, comp i#,i#, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            comp*)
                local _comp_sel="${_choice#comp}"
                _comp_sel="${_comp_sel# }"
                if [[ -z "$_comp_sel" ]]; then
                    echo -e "  ${RED}Usage: comp i1,i2 or comp i1-i3 or comp all${NC}"; sleep 1; continue
                fi
                if ! _parse_targets "i" "$_comp_sel" "$_xd_idx"; then
                    echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue
                fi
                if [[ ${#_SEL_INDICES[@]} -lt 2 ]]; then
                    echo -e "  ${RED}Compare requires at least 2 nodes${NC}"; sleep 1; continue
                fi
                local -a _comp_names=() _comp_shapes=() _comp_raw=()
                local _interrupted=false
                trap '_interrupted=true' INT
                for _cidx in "${_SEL_INDICES[@]}"; do
                    [[ "$_interrupted" == true ]] && break
                    local _entry="${_XD_MAP[i${_cidx}]:-}"
                    [[ -z "$_entry" ]] && continue
                    local _cn="${_entry%%|*}"; local _cs="${_entry#*|}"
                    echo -e "  Collecting from ${GREEN}${_cn}${NC}..."
                    local _craw
                    _craw=$(_xid_collect "$_cn" 2>/dev/null)
                    _comp_names+=("$_cn")
                    _comp_shapes+=("$_cs")
                    _comp_raw+=("$_craw")
                done
                trap - INT
                if [[ "$_interrupted" == true ]]; then
                    echo -e "\n${YELLOW}[INFO]${NC} Interrupted"
                elif [[ ${#_comp_names[@]} -ge 2 ]]; then
                    _xid_compare _comp_names _comp_shapes _comp_raw
                fi
                echo ""
                _ui_pause
                ;;
            all|ALL)
                echo ""
                local _xd_total=$_xd_idx
                local _xd_summary="${TEMP_DIR}/xid_summary_$$"
                rm -f "$_xd_summary"

                # Phase 1: Parallel collection
                local -a _xd_pairs=()
                for (( _xi=1; _xi<=_xd_total; _xi++ )); do
                    local _entry="${_XD_MAP[i${_xi}]}"
                    [[ -z "$_entry" ]] && continue
                    _xd_pairs+=("${_xi}|${_entry%%|*}")
                done
                _k8s_parallel_collect "_xid_collect" "${_xd_pairs[@]}"

                # Phase 2: Display + summary
                for (( _xi=1; _xi<=_xd_total; _xi++ )); do
                    local _entry="${_XD_MAP[i${_xi}]}"
                    [[ -z "$_entry" ]] && continue
                    local _nname="${_entry%%|*}"

                    local _raw=""
                    [[ -f "$_PCOLLECT_DIR/${_xi}.raw" ]] && _raw=$(cat "$_PCOLLECT_DIR/${_xi}.raw")
                    _xid_display_node "$_nname" "$_raw"

                    # Summary line
                    local _xid_ct=0
                    local _xid_section; _xid_section=$(awk '/^===DMESG_XID===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_raw")
                    while IFS= read -r _line; do
                        echo "$_line" | grep -qP 'Xid[^:]*:\s*[0-9]+' && ((_xid_ct++))
                    done <<< "$_xid_section"
                    local _sv="CLEAN"
                    [[ $_xid_ct -gt 0 ]] && _sv="HAS_XIDS"
                    echo "${_nname}|${_xid_ct}|${_sv}" >> "$_xd_summary"
                done
                rm -rf "$_PCOLLECT_DIR" 2>/dev/null

                if [[ -s "$_xd_summary" ]]; then
                    echo ""
                    _ui_subheader "XID Scan Summary" 0
                    echo ""
                    printf "  ${BOLD}%-3s %-45s %10s %-10s${NC}\n" "#" "Node" "XID Count" "Status"
                    print_separator 75
                    local _si=0
                    while IFS='|' read -r _sn _sc _ss; do
                        ((_si++))
                        local _vc="$GREEN"; [[ "$_ss" == "HAS_XIDS" ]] && _vc="$RED"
                        printf "  ${YELLOW}%-3s${NC} %-45s %10s ${_vc}%-10s${NC}\n" "$_si" "${_sn:0:45}" "$_sc" "$_ss"
                    done < "$_xd_summary"
                    rm -f "$_xd_summary"
                fi
                echo ""
                _ui_pause
                ;;
            i[0-9]*)
                local _entry="${_XD_MAP[$_choice]:-}"
                if [[ -z "$_entry" ]]; then echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue; fi
                local _nname="${_entry%%|*}"
                echo -e "  ${YELLOW}Scanning ${WHITE}${_nname}${NC}${YELLOW}...${NC}"
                local _raw; _raw=$(_xid_collect "$_nname" 2>/dev/null)
                _xid_display_node "$_nname" "$_raw"
                echo ""; _ui_pause
                ;;
            *) echo -e "  ${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#===============================================================================
# RDMA / NCCL CONNECTIVITY DIAGNOSTICS (k,3,6)
#===============================================================================
# Checks InfiniBand/RoCE state, GID tables, port counters via kubectl debug
#--------------------------------------------------------------------------------

_rdma_collect() {
    local _node="$1"
    local _rc=0

    # Clean up stale debug pods for this node before starting
    _kubectl_debug_cleanup "$_node"

    timeout --foreground --kill-after=3 "${KUBECTL_DEBUG_GPU_TIMEOUT}" kubectl debug "node/${_node}" \
        -i \
        --image="${KUBECTL_DEBUG_IMAGE}" \
        --profile=sysadmin \
        -q \
        -- chroot /host bash -c '
echo "===RDMA_DEVICES==="
rdma link 2>/dev/null || echo "(rdma tool not available)"
echo ""
echo "===IB_STATE==="
for d in /sys/class/infiniband/*; do
    [[ -d "$d" ]] || continue
    dev=$(basename "$d")
    for p in $d/ports/*; do
        [[ -d "$p" ]] || continue
        port=$(basename "$p")
        state=$(cat "$p/state" 2>/dev/null || echo "unknown")
        phys=$(cat "$p/phys_state" 2>/dev/null || echo "unknown")
        rate=$(cat "$p/rate" 2>/dev/null || echo "unknown")
        echo "${dev}|port${port}|${state}|${phys}|${rate}"
    done
done
[[ ! -d /sys/class/infiniband ]] && echo "(no infiniband devices)"
echo ""
echo "===IB_COUNTERS==="
for d in /sys/class/infiniband/*/ports/*/counters; do
    [[ -d "$d" ]] || continue
    dev=$(echo "$d" | sed "s|/sys/class/infiniband/||;s|/ports/|:|;s|/counters||")
    rcv_err=$(cat "$d/port_rcv_errors" 2>/dev/null || echo "0")
    xmit_disc=$(cat "$d/port_xmit_discards" 2>/dev/null || echo "0")
    rcv_pkts=$(cat "$d/port_rcv_packets" 2>/dev/null || echo "0")
    xmit_pkts=$(cat "$d/port_xmit_packets" 2>/dev/null || echo "0")
    rcv_data=$(cat "$d/port_rcv_data" 2>/dev/null || echo "0")
    xmit_data=$(cat "$d/port_xmit_data" 2>/dev/null || echo "0")
    link_downed=$(cat "$d/link_downed" 2>/dev/null || echo "0")
    link_err_rec=$(cat "$d/link_error_recovery" 2>/dev/null || echo "0")
    echo "${dev}|${rcv_err}|${xmit_disc}|${rcv_pkts}|${xmit_pkts}|${rcv_data}|${xmit_data}|${link_downed}|${link_err_rec}"
done
[[ ! -d /sys/class/infiniband ]] && echo "(no counters)"
echo ""
echo "===GID_TABLE==="
for d in /sys/class/infiniband/*; do
    [[ -d "$d" ]] || continue
    dev=$(basename "$d")
    for gf in $d/ports/*/gids/*; do
        [[ -f "$gf" ]] || continue
        gid=$(cat "$gf" 2>/dev/null)
        [[ "$gid" == "0000:0000:0000:0000:0000:0000:0000:0000" ]] && continue
        [[ -z "$gid" ]] && continue
        idx=$(basename "$gf")
        port=$(basename "$(dirname "$(dirname "$gf")")")
        echo "${dev}|port${port}|gid${idx}|${gid}"
    done
done 2>/dev/null
[[ ! -d /sys/class/infiniband ]] && echo "(no GID table)"
echo ""
echo "===NCCL_ENV==="
# Check for any NCCL environment variables that might be set system-wide
grep -r "NCCL" /etc/environment /etc/profile.d/*.sh 2>/dev/null | head -10 || echo "(no system-level NCCL config)"
echo ""
echo "===END==="
' < <(sleep "${KUBECTL_DEBUG_GPU_TIMEOUT:-15}") 2>/dev/null || _rc=$?

    if [[ ${_rc} -eq 124 ]]; then
        echo "===RDMA_DEVICES===(timed out)
===END==="
    elif [[ ${_rc} -ne 0 ]]; then
        echo "===RDMA_DEVICES===(error rc=${_rc})
===END==="
    fi
}

_rdma_display_node() {
    local _node="$1" _output="$2"

    echo ""
    _ui_subheader "RDMA/InfiniBand Diagnostics — ${_node}" 0

    # RDMA devices
    local _rdma_section
    _rdma_section=$(awk '/^===RDMA_DEVICES===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    echo ""
    echo -e "  ${CYAN}RDMA Devices:${NC}"
    if [[ -z "$_rdma_section" || "$_rdma_section" == *"not available"* ]]; then
        echo -e "  ${RED}rdma tool not available on this node${NC}"
    else
        while IFS= read -r _line; do
            [[ -z "$_line" ]] && continue
            echo -e "    ${WHITE}${_line}${NC}"
        done <<< "$_rdma_section"
    fi

    # IB port states
    local _ib_section
    _ib_section=$(awk '/^===IB_STATE===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_ib_section" && "$_ib_section" != *"no infiniband"* ]]; then
        echo ""
        echo -e "  ${CYAN}InfiniBand Port States:${NC}"
        printf "    ${BOLD}%-20s %-8s %-20s %-20s %-20s${NC}\n" "Device" "Port" "State" "Physical" "Rate"
        local _ib_up=0 _ib_down=0
        while IFS='|' read -r _dev _port _state _phys _rate; do
            [[ -z "$_dev" ]] && continue
            local _sc="$GREEN"
            if echo "$_state" | grep -qi "ACTIVE"; then
                ((_ib_up++))
            else
                _sc="$RED"; ((_ib_down++))
            fi
            printf "    %-20s %-8s ${_sc}%-20s${NC} %-20s %-20s\n" "$_dev" "$_port" "$_state" "$_phys" "$_rate"
        done <<< "$_ib_section"
        echo ""
        echo -e "    ${GREEN}UP: ${_ib_up}${NC}  ${RED}DOWN: ${_ib_down}${NC}"
    fi

    # Port counters
    local _cnt_section
    _cnt_section=$(awk '/^===IB_COUNTERS===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_cnt_section" && "$_cnt_section" != *"no counters"* ]]; then
        echo ""
        echo -e "  ${CYAN}Port Counters:${NC}"
        printf "    ${BOLD}%-25s %12s %12s %14s %14s %8s %8s${NC}\n" \
            "Device:Port" "RcvErr" "XmitDisc" "RcvPkts" "XmitPkts" "LinkDn" "LinkRecov"
        while IFS='|' read -r _dev _rcve _xmitd _rcvp _xmitp _rcvd _xmitd2 _linkd _linke; do
            [[ -z "$_dev" ]] && continue
            local _ec="$GREEN"
            [[ "$_rcve" -gt 0 || "$_linkd" -gt 0 ]] && _ec="$RED"
            printf "    %-25s ${_ec}%12s${NC} %12s %14s %14s ${_ec}%8s${NC} %8s\n" \
                "$_dev" "$_rcve" "$_xmitd" "$_rcvp" "$_xmitp" "$_linkd" "$_linke"
        done <<< "$_cnt_section"
    fi

    # GID table summary
    local _gid_section
    _gid_section=$(awk '/^===GID_TABLE===/{f=1;next}/^===[A-Z]/{f=0}f' <<< "$_output")
    if [[ -n "$_gid_section" && "$_gid_section" != *"no GID"* ]]; then
        local _gid_ct
        _gid_ct=$(echo "$_gid_section" | grep -c . 2>/dev/null || true)
        echo ""
        echo -e "  ${CYAN}GID Table:${NC} ${WHITE}${_gid_ct} entries${NC}"
        # Show first few
        echo "$_gid_section" | head -8 | while IFS='|' read -r _dev _port _gidx _gid; do
            echo -e "    ${GRAY}${_dev} ${_port} ${_gidx}: ${_gid}${NC}"
        done
        [[ "$_gid_ct" -gt 8 ]] && echo -e "    ${GRAY}... and $((_gid_ct - 8)) more${NC}"
    fi
}

k8s_node_rdma_diagnostics() {
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"; _ui_pause "return"; return 1
    fi

    while true; do
        echo ""
        _ui_menu_header "RDMA / NCCL CONNECTIVITY DIAGNOSTICS" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "RDMA Diagnostics" \
            --cmd "kubectl get nodes | kubectl debug node/<n> -- chroot /host rdma link | /sys/class/infiniband/*/ports/*/state" \
            --env

        echo -e "  ${GRAY}Verifies InfiniBand/RoCE interfaces, port states, GID tables, and error counters${NC}"
        echo -e "  ${GRAY}Essential for distributed training — all RDMA ports must be ACTIVE for NCCL allreduce${NC}"

        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"; _step_finish
            echo -e "  ${RED}No K8s nodes found${NC}"; _ui_pause "return"; return
        fi
        local _node_ct; _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"; _step_finish
        echo ""

        declare -A _RD_MAP=()
        local _rd_idx=0

        printf "  ${BOLD}%-5s %-45s %-28s %5s${NC}\n" "ID" "Node Name" "Shape" "GPUs"
        print_separator 90

        while IFS='|' read -r _nname _shape _gpu_ct; do
            [[ -z "$_nname" ]] && continue
            [[ "$_gpu_ct" == "0" || -z "$_gpu_ct" ]] && continue
            ((_rd_idx++))
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s %5s\n" "i${_rd_idx}" "${_nname:0:45}" "${_shape:0:28}" "$_gpu_ct"
            _RD_MAP[i${_rd_idx}]="${_nname}|${_shape}"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.capacity["nvidia.com/gpu"] // "0") as $gpus |
            "\(.metadata.name)|\($shape)|\($gpus)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)

        if [[ $_rd_idx -eq 0 ]]; then
            echo -e "  ${YELLOW}No GPU nodes detected${NC}"; _ui_pause "return"; return
        fi

        echo ""
        echo -e "  ${YELLOW}i#${NC} Select node  ${YELLOW}all${NC} Scan all  ${MAGENTA}r${NC} Refresh  ${CYAN}b${NC} Back"
        echo ""
        _ui_prompt "RDMA Diagnostics" "i#, all, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            all|ALL)
                echo ""
                # Phase 1: Parallel collection
                local -a _rd_pairs=()
                for (( _ri=1; _ri<=_rd_idx; _ri++ )); do
                    local _entry="${_RD_MAP[i${_ri}]:-}"
                    [[ -z "$_entry" ]] && continue
                    _rd_pairs+=("${_ri}|${_entry%%|*}")
                done
                _k8s_parallel_collect "_rdma_collect" "${_rd_pairs[@]}"

                # Phase 2: Display results
                for (( _ri=1; _ri<=_rd_idx; _ri++ )); do
                    local _entry="${_RD_MAP[i${_ri}]:-}"
                    [[ -z "$_entry" ]] && continue
                    local _nname="${_entry%%|*}"
                    local _raw=""
                    [[ -f "$_PCOLLECT_DIR/${_ri}.raw" ]] && _raw=$(cat "$_PCOLLECT_DIR/${_ri}.raw")
                    _rdma_display_node "$_nname" "$_raw"
                done
                rm -rf "$_PCOLLECT_DIR" 2>/dev/null
                echo ""; _ui_pause
                ;;
            i[0-9]*)
                local _entry="${_RD_MAP[$_choice]:-}"
                if [[ -z "$_entry" ]]; then echo -e "  ${RED}Invalid selection${NC}"; sleep 1; continue; fi
                local _nname="${_entry%%|*}"
                echo -e "  ${YELLOW}Checking ${WHITE}${_nname}${NC}..."
                local _raw; _raw=$(_rdma_collect "$_nname" 2>/dev/null)
                _rdma_display_node "$_nname" "$_raw"
                echo ""; _ui_pause
                ;;
            *) echo -e "  ${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#===============================================================================
# TRAINING JOB ↔ PHYSICAL HOST CORRELATION (k,4)
#===============================================================================
# Maps running training pods → K8s nodes → OCI instances → GPU clusters → fabrics
#--------------------------------------------------------------------------------
training_job_correlation() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"

    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"; _ui_pause "return"; return 1
    fi

    while true; do
        echo ""
        _ui_menu_header "TRAINING JOB ↔ PHYSICAL HOST CORRELATION" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "Job Correlation" \
            --cmd "kubectl get pods --all-namespaces -o json | kubectl get nodes -o json | oci compute-gpu-memory-cluster list" \
            --env

        echo -e "  ${GRAY}Maps running pods → K8s nodes → OCI instances → GPU clusters → fabrics${NC}"
        echo -e "  ${GRAY}Helps identify which physical hosts are involved in distributed training${NC}"

        _step_init
        _step_active "pods, nodes(2 parallel)"
        local _pod_tmp="${TEMP_DIR}/job_corr_$$"
        mkdir -p "$_pod_tmp"

        (kubectl get pods --all-namespaces -o json > "$_pod_tmp/pods.json" 2>/dev/null) &
        local _p1=$!
        (kubectl get nodes -o json > "$_pod_tmp/nodes.json" 2>/dev/null) &
        local _p2=$!
        wait "$_p1" "$_p2" 2>/dev/null

        local _pods_json="" _nodes_json=""
        [[ -s "$_pod_tmp/pods.json" ]] && _pods_json=$(cat "$_pod_tmp/pods.json")
        [[ -s "$_pod_tmp/nodes.json" ]] && _nodes_json=$(cat "$_pod_tmp/nodes.json")
        rm -rf "${_pod_tmp:?}"

        if [[ -z "$_pods_json" ]] || ! jq -e '.items[0]' <<< "$_pods_json" >/dev/null 2>&1; then
            _step_complete "failed"; _step_finish
            echo -e "  ${RED}Cannot fetch pods${NC}"; _ui_pause "return"; return
        fi
        local _pod_ct; _pod_ct=$(jq '.items | length' <<< "$_pods_json" 2>/dev/null)
        local _node_ct; _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "pods(${_pod_ct}), nodes(${_node_ct})"
        _step_finish

        # Build node → instance OCID map
        declare -A _NODE_OCID=() _NODE_SHAPE=()
        while IFS='|' read -r _nname _ocid _shape; do
            [[ -n "$_nname" ]] && { _NODE_OCID[$_nname]="$_ocid"; _NODE_SHAPE[$_nname]="$_shape"; }
        done < <(jq -r '.items[] |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            (.metadata.labels["node.kubernetes.io/instance-type"] // "N/A") as $shape |
            "\(.metadata.name)|\($ocid)|\($shape)"
        ' <<< "$_nodes_json" 2>/dev/null)

        # Build instance → GPU cluster map from cache
        declare -A _INST_CLUSTER=() _INST_FABRIC=()
        if [[ -s "$INSTANCE_CLUSTER_MAP_CACHE" ]]; then
            while IFS='|' read -r _iid _cid _cname _fab; do
                [[ -n "$_iid" ]] && { _INST_CLUSTER[$_iid]="$_cname"; _INST_FABRIC[$_iid]="$_fab"; }
            done < <(grep -v '^#' "$INSTANCE_CLUSTER_MAP_CACHE" 2>/dev/null)
        fi

        # Filter GPU-using pods (request nvidia.com/gpu > 0) AND training-like pods
        echo ""
        _ui_subheader "GPU Pods (requesting nvidia.com/gpu)" 0
        echo ""
        printf "  ${BOLD}%-4s %-25s %-40s %-10s %-35s %-15s %-12s${NC}\n" \
            "#" "Namespace" "Pod Name" "Phase" "Node" "GPU Cluster" "Fabric"
        print_separator 155

        local _gp_idx=0
        declare -A _GP_MAP=()

        while IFS='|' read -r _ns _pname _phase _nodename _gpu_req; do
            [[ -z "$_pname" ]] && continue
            ((_gp_idx++))
            local _ocid="${_NODE_OCID[$_nodename]:-}"
            local _cluster="${_INST_CLUSTER[$_ocid]:-${GRAY}-${NC}}"
            local _fabric="${_INST_FABRIC[$_ocid]:-${GRAY}-${NC}}"

            local _pc="$GREEN"
            [[ "$_phase" != "Running" ]] && _pc="$YELLOW"
            [[ "$_phase" == "Failed" || "$_phase" == "Error" ]] && _pc="$RED"

            printf "  ${YELLOW}%-4s${NC} %-25s %-40s ${_pc}%-10s${NC} %-35s %-15s %-12s\n" \
                "$_gp_idx" "${_ns:0:25}" "${_pname:0:40}" "$_phase" "${_nodename:0:35}" \
                "${_cluster:0:15}" "${_fabric:0:12}"
            _GP_MAP[$_gp_idx]="${_ns}|${_pname}|${_nodename}|${_ocid}"
        done < <(jq -r '
            [.items[] |
            select(
                (.spec.containers[]?.resources.requests["nvidia.com/gpu"] // "0" | tonumber) > 0 or
                (.spec.containers[]?.resources.limits["nvidia.com/gpu"] // "0" | tonumber) > 0
            )] | sort_by(.spec.nodeName // "") |
            .[] |
            "\(.metadata.namespace)|\(.metadata.name)|\(.status.phase // "Unknown")|\(.spec.nodeName // "N/A")|\(.spec.containers[0].resources.requests["nvidia.com/gpu"] // "0")"
        ' <<< "$_pods_json" 2>/dev/null)

        if [[ $_gp_idx -eq 0 ]]; then
            echo -e "  ${GRAY}No pods requesting nvidia.com/gpu found${NC}"
        fi

        # Show node → cluster grouping summary
        echo ""
        _ui_subheader "Node → Instance → GPU Cluster Mapping" 0
        echo ""
        printf "  ${BOLD}%-35s %-55s %-18s %-12s %5s${NC}\n" \
            "K8s Node" "Instance OCID" "GPU Cluster" "Fabric" "Pods"
        print_separator 135

        # Count pods per node
        declare -A _NODE_POD_CT=()
        for _gi in $(seq 1 $_gp_idx); do
            local _e="${_GP_MAP[$_gi]:-}"
            local _nn; _nn=$(echo "$_e" | cut -d'|' -f3)
            _NODE_POD_CT[$_nn]=$(( ${_NODE_POD_CT[$_nn]:-0} + 1 ))
        done

        for _nn in $(echo "${!_NODE_POD_CT[@]}" | tr ' ' '\n' | sort); do
            local _ocid="${_NODE_OCID[$_nn]:-N/A}"
            local _cluster="${_INST_CLUSTER[$_ocid]:-${GRAY}-${NC}}"
            local _fabric="${_INST_FABRIC[$_ocid]:-${GRAY}-${NC}}"
            local _pct="${_NODE_POD_CT[$_nn]:-0}"

            printf "  %-35s ${GRAY}%-55s${NC} %-18s %-12s %5s\n" \
                "${_nn:0:35}" "${_ocid:0:55}" "${_cluster:0:18}" "${_fabric:0:12}" "$_pct"
        done

        # Check for cross-fabric placement warnings
        local _fabrics_seen=()
        for _nn in "${!_NODE_POD_CT[@]}"; do
            local _ocid="${_NODE_OCID[$_nn]:-}"
            local _fab="${_INST_FABRIC[$_ocid]:-}"
            [[ -n "$_fab" && "$_fab" != "-" ]] && _fabrics_seen+=("$_fab")
        done
        local _unique_fabrics
        if [[ ${#_fabrics_seen[@]} -gt 0 ]]; then
            _unique_fabrics=$(printf '%s\n' "${_fabrics_seen[@]}" | sort -u | wc -l)
        else
            _unique_fabrics=0
        fi
        if [[ "${_unique_fabrics:-0}" -gt 1 ]]; then
            echo ""
            echo -e "  ${RED}⚠ WARNING: GPU pods span ${_unique_fabrics} different fabrics — may impact NCCL performance${NC}"
            printf '%s\n' "${_fabrics_seen[@]}" | sort -u | while read -r _f; do
                echo -e "    ${YELLOW}• Fabric: ${_f}${NC}"
            done
        fi

        echo ""
        _ui_prompt "Job Correlation" "r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return
        case "$_choice" in
            r|R) continue ;;
            *) return ;;
        esac
    done
}

#===============================================================================
# BULK RUNCOMMAND EXECUTION
#===============================================================================
# Execute the same command across multiple instances simultaneously
# Integrates with RC_PRESETS and existing RunCommand infrastructure
#--------------------------------------------------------------------------------
bulk_runcommand() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"
    local _log_file="${LOGS_DIR}/bulk_runcommand_actions.log"

    echo ""
    _ui_menu_header "BULK RUNCOMMAND EXECUTION" \
        --color "$YELLOW" \
        --breadcrumb "Compute" "Instances" "Bulk RunCommand" \
        --cmd "oci instance-agent command create --compartment-id \$COMPARTMENT_ID --content file://... --target file://..." \
        --env

    echo -e "  ${GRAY}Execute the same command across multiple instances simultaneously${NC}"

    # Discover instances
    _step_init
    _step_active "instances"
    local _inst_json
    if is_cache_fresh "$INSTANCE_LIST_CACHE"; then
        _inst_json=$(cat "$INSTANCE_LIST_CACHE")
        _step_complete "instances(cached)"
    else
        _inst_json=$(oci compute instance list --compartment-id "$_compartment" --region "$_region" --all --output json 2>/dev/null)
        [[ -n "$_inst_json" ]] && echo "$_inst_json" | _cache_write "$INSTANCE_LIST_CACHE"
        _step_complete "instances"
    fi
    _step_finish

    if [[ -z "$_inst_json" ]] || ! jq -e '.data[0]' <<< "$_inst_json" >/dev/null 2>&1; then
        echo -e "  ${RED}No instances found${NC}"; _ui_pause "return"; return
    fi

    # Build instance table (RUNNING only)
    echo ""
    declare -A _BRC_MAP=()
    local _brc_idx=0

    printf "  ${BOLD}%-5s %-40s %-28s %-12s${NC}\n" "ID" "Instance Name" "Shape" "State"
    print_separator 90

    while IFS='|' read -r _iid _name _shape _state; do
        [[ -z "$_iid" || "$_state" != "RUNNING" ]] && continue
        ((_brc_idx++))
        printf "  ${YELLOW}%-5s${NC} %-40s %-28s ${GREEN}%-12s${NC}\n" \
            "i${_brc_idx}" "${_name:0:40}" "${_shape:0:28}" "$_state"
        _BRC_MAP[i${_brc_idx}]="${_iid}|${_name}"
    done < <(jq -r '.data[] | select(.["lifecycle-state"] == "RUNNING") |
        "\(.id)|\(.["display-name"] // "N/A")|\(.shape // "N/A")|\(.["lifecycle-state"])"
    ' <<< "$_inst_json" 2>/dev/null | sort -t'|' -k2,2)

    if [[ $_brc_idx -eq 0 ]]; then
        echo -e "  ${YELLOW}No running instances found${NC}"; _ui_pause "return"; return
    fi

    # Multi-select instances
    echo ""
    echo -e "  ${WHITE}Select instances (multi-select):${NC} e.g. ${YELLOW}i1,i3,i5${NC} or ${YELLOW}i1-i4${NC} or ${YELLOW}all${NC}"
    echo -n -e "  ${CYAN}Select: ${NC}"
    local _sel; read -r _sel
    [[ -z "$_sel" ]] && return

    # Parse targets using _parse_targets pattern
    local -a _target_ids=()
    if [[ "${_sel,,}" == "all" ]]; then
        for (( _i=1; _i<=_brc_idx; _i++ )); do _target_ids+=("i${_i}"); done
    else
        # Parse comma-separated and ranges
        IFS=',' read -ra _parts <<< "$_sel"
        for _part in "${_parts[@]}"; do
            _part=$(echo "$_part" | xargs)
            if [[ "$_part" =~ ^i?([0-9]+)-i?([0-9]+)$ ]]; then
                for (( _r=${BASH_REMATCH[1]}; _r<=${BASH_REMATCH[2]}; _r++ )); do
                    _target_ids+=("i${_r}")
                done
            elif [[ "$_part" =~ ^i?([0-9]+)$ ]]; then
                _target_ids+=("i${BASH_REMATCH[1]}")
            fi
        done
    fi

    # Validate
    local -a _valid_targets=()
    for _tid in "${_target_ids[@]}"; do
        [[ -n "${_BRC_MAP[$_tid]:-}" ]] && _valid_targets+=("$_tid")
    done

    if [[ ${#_valid_targets[@]} -eq 0 ]]; then
        echo -e "  ${RED}No valid instances selected${NC}"; _ui_pause "return"; return
    fi

    echo -e "  ${GREEN}✓ ${#_valid_targets[@]} instance(s) selected${NC}"

    # Select command source
    echo ""
    _ui_subheader "Command Source" 0
    echo ""
    echo -e "  ${YELLOW}1${NC}) Select preset"
    echo -e "  ${YELLOW}2${NC}) Type/paste inline script"
    echo ""

    # Show presets
    echo -e "  ${WHITE}Available Presets:${NC}"
    local _pi=0
    declare -A _PRESET_MAP=()
    for _pname in $(echo "${!RC_PRESETS[@]}" | tr ' ' '\n' | sort); do
        ((_pi++))
        _PRESET_MAP[$_pi]="$_pname"
        local _preview="${RC_PRESETS[$_pname]:0:80}"
        printf "    ${CYAN}p%-2s${NC} ${WHITE}%-15s${NC} ${GRAY}%s...${NC}\n" "$_pi" "$_pname" "$_preview"
    done

    echo ""
    echo -n -e "  ${CYAN}Select (1-2, or p# for preset): ${NC}"
    local _src; read -r _src

    local _script_content=""
    local _label=""

    case "$_src" in
        p[0-9]*)
            local _pn="${_src#p}"
            local _pname="${_PRESET_MAP[$_pn]:-}"
            if [[ -z "$_pname" ]]; then
                echo -e "  ${RED}Invalid preset${NC}"; _ui_pause; return
            fi
            _script_content="${RC_PRESETS[$_pname]}"
            _label="bulk-${_pname}"
            echo -e "  ${GREEN}✓ Using preset: ${_pname}${NC}"
            ;;
        1)
            echo ""
            echo -e "  ${WHITE}Available Presets:${NC}"
            for _pn in $(seq 1 $_pi); do
                printf "    ${CYAN}%-3s${NC} ${WHITE}%s${NC}\n" "$_pn" "${_PRESET_MAP[$_pn]}"
            done
            echo ""
            echo -n -e "  ${CYAN}Select preset #: ${NC}"
            local _pc; read -r _pc
            local _pname="${_PRESET_MAP[$_pc]:-}"
            if [[ -z "$_pname" ]]; then echo -e "  ${RED}Invalid${NC}"; return; fi
            _script_content="${RC_PRESETS[$_pname]}"
            _label="bulk-${_pname}"
            echo -e "  ${GREEN}✓ Using preset: ${_pname}${NC}"
            ;;
        2)
            echo -e "  ${WHITE}Enter script (finish with 'EOF'):${NC}"
            local _lines=""
            while IFS= read -r _line; do
                [[ "$_line" == "EOF" || "$_line" == "eof" ]] && break
                _lines+="${_line}"$'\n'
            done
            _script_content="$_lines"
            _label="bulk-custom"
            ;;
        *) echo -e "  ${YELLOW}Cancelled${NC}"; return ;;
    esac

    [[ -z "$_script_content" ]] && { echo -e "  ${RED}No script content${NC}"; return; }

    # Timeout
    echo -n -e "  ${CYAN}Timeout seconds (default=600): ${NC}"
    local _timeout; read -r _timeout; [[ -z "$_timeout" ]] && _timeout=600

    # Preview + confirm
    echo ""
    echo -e "  ${WHITE}Script preview:${NC}"
    head -3 <<< "$_script_content" | while IFS= read -r _line; do
        echo -e "    ${GRAY}${_line}${NC}"
    done
    echo ""
    echo -e "  ${WHITE}Targets: ${YELLOW}${#_valid_targets[@]} instances${NC}"
    for _tid in "${_valid_targets[@]}"; do
        local _e="${_BRC_MAP[$_tid]}"; echo -e "    ${GRAY}• ${_e#*|}${NC}"
    done

    echo ""
    echo -e "  ${GRAY}\$ oci instance-agent command create --compartment-id ${_compartment} --timeout-in-seconds ${_timeout} --display-name ${_label} --content ... --target ...${NC}"
    echo ""
    if ! _ui_confirm "EXECUTE on ${#_valid_targets[@]} instances"; then
        echo -e "  ${YELLOW}Cancelled${NC}"; return
    fi

    # Execute
    echo ""
    local _brc_tmp="${TEMP_DIR}/bulk_rc_$$"
    mkdir -p "$_brc_tmp"

    # Build content file (shared)
    jq -n --arg text "$_script_content" '{"source":{"sourceType":"TEXT","text":$text}}' > "$_brc_tmp/content.json"

    local _success=0 _fail=0
    for _tid in "${_valid_targets[@]}"; do
        local _e="${_BRC_MAP[$_tid]}"
        local _iid="${_e%%|*}"; local _iname="${_e#*|}"

        jq -n --arg iid "$_iid" '{"instanceId":$iid}' > "$_brc_tmp/target_${_tid}.json"

        local _cmd_display="oci instance-agent command create --compartment-id ${_compartment} --timeout-in-seconds ${_timeout} --display-name \"${_label}-${_iname}\" --content file://${_brc_tmp}/content.json --target file://${_brc_tmp}/target_${_tid}.json --output json"
        echo -e "  ${YELLOW}→ ${_iname}${NC}..."
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${_cmd_display}" >> "$_log_file"
        log_action "BULK_RUN_COMMAND" "$_cmd_display" --quiet

        local _result _rc_err_file="$_brc_tmp/err_${_tid}.txt"
        _result=$(oci instance-agent command create \
            --compartment-id "$_compartment" \
            --timeout-in-seconds "$_timeout" \
            --display-name "${_label}-${_iname}" \
            --content "file://${_brc_tmp}/content.json" \
            --target "file://${_brc_tmp}/target_${_tid}.json" \
            --output json 2>"$_rc_err_file")
        local _rc_exit=$?
        if [[ $_rc_exit -eq 0 && -n "$_result" ]] && jq -e '.data.id' <<< "$_result" >/dev/null 2>&1; then
            local _cid; _cid=$(jq -r '.data.id // "?"' <<< "$_result" 2>/dev/null)
            echo -e "    ${GREEN}✓ Submitted${NC} ${GRAY}(${_cid})${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: ${_cid} → ${_iname}" >> "$_log_file"
            log_action_result "SUCCESS" "Bulk run command ${_cid} → ${_iname}"
            ((_success++))
        else
            # Extract error from stderr or stdout JSON
            local _err_msg=""
            if [[ -s "$_rc_err_file" ]]; then
                _err_msg=$(head -5 "$_rc_err_file" | tr '\n' ' ')
            fi
            if [[ -z "$_err_msg" && -n "$_result" ]]; then
                _err_msg=$(jq -r '.message // .code // empty' <<< "$_result" 2>/dev/null)
            fi
            [[ -z "$_err_msg" && $_rc_exit -ne 0 ]] && _err_msg="exit code $_rc_exit"
            echo -e "    ${RED}✗ Failed${NC}"
            [[ -n "$_err_msg" ]] && echo -e "      ${GRAY}${_err_msg:0:200}${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${_iname} — ${_err_msg:-unknown}" >> "$_log_file"
            log_action_result "FAILED" "Bulk run command failed for ${_iname}: ${_err_msg:-unknown}"
            ((_fail++))
        fi
    done

    rm -rf "${_brc_tmp:?}"
    echo ""
    echo -e "  ${WHITE}Results:${NC} ${GREEN}${_success} succeeded${NC}, ${RED}${_fail} failed${NC}"
    echo -e "  ${GRAY}Log: ${_log_file}${NC}"
    _ui_pause
}

#===============================================================================
# MULTI-CLUSTER FLEET SUMMARY (o,6)
#===============================================================================
# Aggregates GPU cluster info across all known regions/compartments
#--------------------------------------------------------------------------------
multi_cluster_fleet_summary() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "MULTI-CLUSTER GPU FLEET SUMMARY" \
        --color "$RED" \
        --breadcrumb "Operations" "Fleet Summary" \
        --cmd "oci ce cluster list | oci compute-gpu-memory-cluster list --compartment-id \$COMPARTMENT_ID [per region]" \
        --env

    echo -e "  ${GRAY}Aggregates OKE clusters and GPU clusters across subscribed regions${NC}"

    # Get subscribed regions
    _step_init
    _step_active "regions"
    local _regions_json
    _regions_json=$(oci iam region-subscription list --tenancy-id "${TENANCY_ID:-$_compartment}" --output json 2>/dev/null)
    local _region_list=()
    if [[ -n "$_regions_json" ]]; then
        while read -r _r; do
            [[ -n "$_r" ]] && _region_list+=("$_r")
        done < <(jq -r '.data[].\"region-name\"' <<< "$_regions_json" 2>/dev/null)
    fi
    [[ ${#_region_list[@]} -eq 0 ]] && _region_list=("$_region")
    _step_complete "regions(${#_region_list[@]})"
    _step_finish

    # Fetch OKE clusters + GPU clusters across all regions in parallel
    local _fleet_tmp="${TEMP_DIR}/fleet_summary_$$"
    mkdir -p "$_fleet_tmp"

    _step_init
    _step_active "fleet data(${#_region_list[@]} regions parallel)"

    local _fleet_pids=()
    for _r in "${_region_list[@]}"; do
        (
            oci ce cluster list --compartment-id "$_compartment" --region "$_r" --all --output json > "$_fleet_tmp/oke_${_r}.json" 2>/dev/null
            oci compute-gpu-memory-cluster list --compartment-id "$_compartment" --region "$_r" --all --output json > "$_fleet_tmp/gpu_${_r}.json" 2>/dev/null
            oci compute instance list --compartment-id "$_compartment" --region "$_r" --all --output json > "$_fleet_tmp/inst_${_r}.json" 2>/dev/null
        ) &
        _fleet_pids+=($!)
    done
    wait "${_fleet_pids[@]}" 2>/dev/null
    _step_complete "fleet data"
    _step_finish

    # OKE Clusters
    echo ""
    _ui_subheader "OKE Clusters Across Regions" 0
    echo ""
    printf "  ${BOLD}%-3s %-18s %-35s %-12s %-12s %-8s${NC}\n" \
        "#" "Region" "Cluster Name" "State" "K8s Version" "NPs"
    print_separator 100

    local _oke_idx=0
    for _r in "${_region_list[@]}"; do
        [[ ! -s "$_fleet_tmp/oke_${_r}.json" ]] && continue
        while IFS='|' read -r _cname _cstate _cver _np_ct; do
            [[ -z "$_cname" ]] && continue
            ((_oke_idx++))
            local _sc="$GREEN"; [[ "$_cstate" != "ACTIVE" ]] && _sc="$YELLOW"
            printf "  ${YELLOW}%-3s${NC} %-18s %-35s ${_sc}%-12s${NC} %-12s %-8s\n" \
                "$_oke_idx" "$_r" "${_cname:0:35}" "$_cstate" "$_cver" "$_np_ct"
        done < <(jq -r '(.data // [])[] |
            "\(.name // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.["kubernetes-version"] // "N/A")|\((.["node-pools"] // []) | length)"
        ' "$_fleet_tmp/oke_${_r}.json" 2>/dev/null)
    done
    [[ $_oke_idx -eq 0 ]] && echo -e "  ${GRAY}No OKE clusters found${NC}"

    # GPU Clusters
    echo ""
    _ui_subheader "GPU Memory Clusters Across Regions" 0
    echo ""
    printf "  ${BOLD}%-3s %-18s %-35s %-12s %6s %-12s${NC}\n" \
        "#" "Region" "Cluster Name" "State" "Size" "Fabric"
    print_separator 100

    local _gpu_idx=0 _total_gpus=0
    for _r in "${_region_list[@]}"; do
        [[ ! -s "$_fleet_tmp/gpu_${_r}.json" ]] && continue
        while IFS='|' read -r _cname _cstate _csize _fab; do
            [[ -z "$_cname" ]] && continue
            ((_gpu_idx++))
            local _sc="$GREEN"; [[ "$_cstate" != "ACTIVE" ]] && _sc="$YELLOW"
            [[ "$_cstate" == "CREATING" || "$_cstate" == "SCALING" ]] && _sc="$CYAN"
            printf "  ${YELLOW}%-3s${NC} %-18s %-35s ${_sc}%-12s${NC} %6s %-12s\n" \
                "$_gpu_idx" "$_r" "${_cname:0:35}" "$_cstate" "$_csize" "${_fab:0:12}"
            [[ "$_csize" =~ ^[0-9]+$ ]] && ((_total_gpus+=_csize))
        done < <(jq -r '(.data // .items // [])[] |
            (.["gpu-memory-fabric-id"] // "" | .[-5:] | ascii_downcase) as $fab |
            "\(.["display-name"] // "N/A")|\(.["lifecycle-state"] // "N/A")|\(.["compute-instance-count"] // .size // "?")|\($fab)"
        ' "$_fleet_tmp/gpu_${_r}.json" 2>/dev/null)
    done
    [[ $_gpu_idx -eq 0 ]] && echo -e "  ${GRAY}No GPU memory clusters found${NC}"

    # Instance summary per region
    echo ""
    _ui_subheader "Instance Summary Per Region" 0
    echo ""
    printf "  ${BOLD}%-18s %8s %8s %8s %10s${NC}\n" "Region" "Running" "Stopped" "Other" "GPU Total"
    print_separator 60

    for _r in "${_region_list[@]}"; do
        [[ ! -s "$_fleet_tmp/inst_${_r}.json" ]] && continue
        local _running _stopped _other _gpu_instances
        _running=$(jq '[.data[] | select(.["lifecycle-state"]=="RUNNING")] | length' "$_fleet_tmp/inst_${_r}.json" 2>/dev/null || echo "0")
        _stopped=$(jq '[.data[] | select(.["lifecycle-state"]=="STOPPED")] | length' "$_fleet_tmp/inst_${_r}.json" 2>/dev/null || echo "0")
        _other=$(jq '[.data[] | select(.["lifecycle-state"] | IN("RUNNING","STOPPED","TERMINATED") | not)] | length' "$_fleet_tmp/inst_${_r}.json" 2>/dev/null || echo "0")
        _gpu_instances=$(jq '[.data[] | select(.["lifecycle-state"]=="RUNNING" and (.shape | test("GPU|BM\\.GPU|VM\\.GPU"; "i")))] | length' "$_fleet_tmp/inst_${_r}.json" 2>/dev/null || echo "0")
        [[ "$_running" == "0" && "$_stopped" == "0" && "$_other" == "0" ]] && continue
        printf "  %-18s ${GREEN}%8s${NC} ${YELLOW}%8s${NC} %8s ${CYAN}%10s${NC}\n" "$_r" "$_running" "$_stopped" "$_other" "$_gpu_instances"
    done

    # Grand totals
    echo ""
    echo -e "  ${WHITE}Fleet Totals:${NC} ${CYAN}${_gpu_idx} GPU clusters${NC}, ${WHITE}${_total_gpus} total instances in GPU clusters${NC}, ${GREEN}${_oke_idx} OKE clusters${NC} across ${WHITE}${#_region_list[@]} regions${NC}"

    rm -rf "${_fleet_tmp:?}"
    echo ""
    _ui_pause
}

#===============================================================================
# EVENT TIMELINE VIEW (o,7)
#===============================================================================
# Chronological view of operations from log files + work requests
#--------------------------------------------------------------------------------
event_timeline_view() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "EVENT TIMELINE" \
        --color "$RED" \
        --breadcrumb "Operations" "Event Timeline" \
        --cmd "Log files: \$LOGS_DIR/*.log" \
        --env

    echo -e "  ${GRAY}Chronological view of all recorded operations from script action logs${NC}"

    # Collect all log entries from LOGS_DIR
    local _timeline_file="${TEMP_DIR}/timeline_$$"
    rm -f "$_timeline_file"

    _step_init
    _step_active "log files"
    local _log_count=0

    if [[ -d "$LOGS_DIR" ]]; then
        for _lf in "$LOGS_DIR"/*.log; do
            [[ ! -f "$_lf" ]] && continue
            local _source
            _source=$(basename "$_lf" .log)
            while IFS= read -r _line; do
                # Parse [YYYY-MM-DD HH:MM:SS] PREFIX: message
                if [[ "$_line" =~ ^\[([0-9]{4}-[0-9]{2}-[0-9]{2}\ [0-9]{2}:[0-9]{2}:[0-9]{2})\]\ (.+) ]]; then
                    local _ts="${BASH_REMATCH[1]}"
                    local _msg="${BASH_REMATCH[2]}"
                    echo "${_ts}|${_source}|${_msg}" >> "$_timeline_file"
                    ((_log_count++))
                fi
            done < "$_lf"
        done
    fi
    _step_complete "log files(${_log_count} entries)"
    _step_finish

    if [[ ! -s "$_timeline_file" || $_log_count -eq 0 ]]; then
        echo ""
        echo -e "  ${GRAY}No action log entries found in ${LOGS_DIR}/${NC}"
        echo -e "  ${GRAY}Logs are created when you perform create/update/delete/execute operations${NC}"
        echo ""
        _ui_pause "return"
        return
    fi

    # Sort by timestamp (newest first) and display
    echo ""
    local _page_size=40
    local _total_lines=$_log_count
    local _page=0

    while true; do
        local _skip=$(( _page * _page_size ))
        local _showing_from=$(( _skip + 1 ))
        local _showing_to=$(( _skip + _page_size ))
        [[ $_showing_to -gt $_total_lines ]] && _showing_to=$_total_lines

        echo ""
        echo -e "  ${WHITE}Timeline (${_showing_from}-${_showing_to} of ${_total_lines}, newest first):${NC}"
        echo ""
        printf "  ${BOLD}%-20s %-25s %-8s %s${NC}\n" "Timestamp" "Source" "Action" "Details"
        print_separator 140

        sort -r "$_timeline_file" | tail -n +$((_skip+1)) | head -n $_page_size | while IFS='|' read -r _ts _src _msg; do
            [[ -z "$_ts" ]] && continue
            # Color by action type
            local _ac="$WHITE"
            [[ "$_msg" == SUCCESS* ]] && _ac="$GREEN"
            [[ "$_msg" == FAILED* || "$_msg" == ERROR* ]] && _ac="$RED"
            [[ "$_msg" == EXECUTE* ]] && _ac="$YELLOW"

            local _action="${_msg%%:*}"
            local _detail="${_msg#*: }"
            [[ "$_action" == "$_detail" ]] && _detail=""

            printf "  ${GRAY}%-20s${NC} ${CYAN}%-25s${NC} ${_ac}%-8s${NC} ${WHITE}%.80s${NC}\n" \
                "$_ts" "${_src:0:25}" "${_action:0:8}" "${_detail:0:80}"
        done

        echo ""
        local _has_more="false"
        [[ $_showing_to -lt $_total_lines ]] && _has_more="true"

        if [[ "$_has_more" == "true" ]]; then
            echo -e "  ${YELLOW}n${NC}) Next page  ${YELLOW}p${NC}) Prev page  ${MAGENTA}/${NC}) Filter  ${CYAN}b${NC}) Back"
        else
            echo -e "  ${YELLOW}p${NC}) Prev page  ${MAGENTA}/${NC}) Filter  ${CYAN}b${NC}) Back"
        fi
        echo ""
        _ui_prompt "Timeline" "n, p, /, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && { rm -f "$_timeline_file"; _nav_try_jump "$_choice" && return; }

        case "$_choice" in
            n|N) [[ "$_has_more" == "true" ]] && ((_page++)) ;;
            p|P) [[ $_page -gt 0 ]] && ((_page--)) ;;
            /|search)
                echo -n -e "  ${CYAN}Filter text: ${NC}"
                local _filter; read -r _filter
                if [[ -n "$_filter" ]]; then
                    local _filtered="${_timeline_file}.filtered"
                    grep -i "$_filter" "$_timeline_file" > "$_filtered" 2>/dev/null
                    local _fct; _fct=$(wc -l < "$_filtered")
                    echo -e "  ${GREEN}Found ${_fct} matching entries${NC}"
                    if [[ $_fct -gt 0 ]]; then
                        sort -r "$_filtered" | head -n $_page_size | while IFS='|' read -r _ts _src _msg; do
                            local _ac="$WHITE"
                            [[ "$_msg" == SUCCESS* ]] && _ac="$GREEN"
                            [[ "$_msg" == FAILED* ]] && _ac="$RED"
                            printf "  ${GRAY}%-20s${NC} ${CYAN}%-25s${NC} ${_ac}%.100s${NC}\n" "$_ts" "${_src:0:25}" "${_msg:0:100}"
                        done
                    fi
                    rm -f "$_filtered"
                    _ui_pause
                fi
                ;;
            b|B|back|"") rm -f "$_timeline_file"; return ;;
            *) ;;
        esac
    done
}

#===============================================================================
# AUDIT LOGS
#===============================================================================
# View OCI audit events — API calls, resource changes, access activity
# Follows Work Requests pattern: wrapper → time picker → list → detail
#--------------------------------------------------------------------------------

# Global map for audit event drill-down (index → full event JSON key)
declare -gA AUDIT_MAP

#--------------------------------------------------------------------------------
# Wrapper: manage time range + filter state, loops calling list display
#--------------------------------------------------------------------------------
manage_audit_logs() {
    local _audit_time_range=""
    local _audit_filter=""
    local _audit_filter_file="${TEMP_DIR}/.audit_next_filter_$$"
    local _audit_time_file="${TEMP_DIR}/.audit_next_time_$$"

    # First entry: prompt for time range
    _audit_select_time_range "_audit_time_range"
    [[ -z "$_audit_time_range" ]] && return 0

    while true; do
        echo "$_audit_filter" > "$_audit_filter_file"
        echo "$_audit_time_range" > "$_audit_time_file"

        audit_list_interactive "$_audit_time_range" "$_audit_filter" "$_audit_filter_file" "$_audit_time_file"
        local _rc=$?

        if [[ $_rc -eq 2 ]]; then
            # Re-query: pick up updated filter/time from temp files
            _audit_filter=$(cat "$_audit_filter_file" 2>/dev/null)
            _audit_time_range=$(cat "$_audit_time_file" 2>/dev/null)
            continue
        else
            rm -f "$_audit_filter_file" "$_audit_time_file"
            return 0
        fi
    done
}

#--------------------------------------------------------------------------------
# Interactive time range picker
# Args: $1 = variable name to set with range code
#--------------------------------------------------------------------------------
_audit_select_time_range() {
    local _varname="$1"
    echo ""
    echo -e "  ${BOLD}${CYAN}Select Audit Event Time Range${NC}"
    echo ""
    echo -e "  ${YELLOW}1${NC}) Last 1 hour ${GREEN}(recommended)${NC}"
    echo -e "  ${YELLOW}2${NC}) Last 4 hours"
    echo -e "  ${YELLOW}3${NC}) Last 24 hours ${YELLOW}(may return many events)${NC}"
    echo -e "  ${YELLOW}4${NC}) Last 7 days ${RED}(large result set)${NC}"
    echo -e "  ${YELLOW}5${NC}) Custom range (RFC 3339 start/end)"
    echo ""
    echo -n -e "  ${BOLD}${CYAN}[Audit Time Range] Selection (1-5, b): ${NC}"
    local _choice
    read -r _choice

    case "$_choice" in
        1|"") printf -v "$_varname" '%s' "1h" ;;
        2) printf -v "$_varname" '%s' "4h" ;;
        3) printf -v "$_varname" '%s' "24h" ;;
        4) printf -v "$_varname" '%s' "7d" ;;
        5)
            echo ""
            echo -e "  ${CYAN}Enter start time (RFC 3339, e.g. 2026-02-22T00:00:00Z):${NC}"
            echo -n "  Start: "
            local _start; read -r _start
            echo -e "  ${CYAN}Enter end time (RFC 3339, e.g. 2026-02-22T12:00:00Z):${NC}"
            echo -n "  End: "
            local _end; read -r _end
            if [[ -z "$_start" || -z "$_end" ]]; then
                echo -e "  ${RED}Both start and end times required. Defaulting to 1 hour.${NC}"
                printf -v "$_varname" '%s' "1h"
            else
                printf -v "$_varname" '%s' "custom:${_start}|${_end}"
            fi
            ;;
        b|B) printf -v "$_varname" '%s' "" ;;
        *) echo -e "  ${YELLOW}Invalid selection. Defaulting to 1 hour.${NC}"
           printf -v "$_varname" '%s' "1h" ;;
    esac
}

#--------------------------------------------------------------------------------
# Resolve time range code to RFC 3339 start/end times
# Args: $1 = range code (1h|4h|24h|7d|custom:START|END)
# Output: two lines — start_time then end_time
#--------------------------------------------------------------------------------
_audit_resolve_times() {
    local _range="$1"
    local _end_epoch _start_epoch _end_time _start_time

    _end_epoch=$(date +%s)
    _end_time=$(date -u -d "@${_end_epoch}" '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null)

    case "$_range" in
        1h)  _start_epoch=$((_end_epoch - 3600)) ;;
        4h)  _start_epoch=$((_end_epoch - 14400)) ;;
        24h) _start_epoch=$((_end_epoch - 86400)) ;;
        7d)  _start_epoch=$((_end_epoch - 604800)) ;;
        custom:*)
            local _custom_part="${_range#custom:}"
            _start_time="${_custom_part%%|*}"
            _end_time="${_custom_part#*|}"
            echo "$_start_time"
            echo "$_end_time"
            return 0
            ;;
        *) _start_epoch=$((_end_epoch - 3600)) ;;
    esac

    _start_time=$(date -u -d "@${_start_epoch}" '+%Y-%m-%dT%H:%M:%SZ' 2>/dev/null)
    echo "$_start_time"
    echo "$_end_time"
}

#--------------------------------------------------------------------------------
# Human-readable label for time range code
#--------------------------------------------------------------------------------
_audit_time_label() {
    case "$1" in
        1h)  echo "Last 1 hour" ;;
        4h)  echo "Last 4 hours" ;;
        24h) echo "Last 24 hours" ;;
        7d)  echo "Last 7 days" ;;
        custom:*) echo "Custom range" ;;
        *)   echo "Last 1 hour" ;;
    esac
}

#--------------------------------------------------------------------------------
# Main audit events list display with interactive actions
# Args: $1=time_range  $2=filter  $3=filter_file  $4=time_file
# Returns: 0=back  2=re-query (filter/time changed)
#--------------------------------------------------------------------------------
audit_list_interactive() {
    local _time_range="$1"
    local _filter="${2:-}"
    local _filter_file="${3:-}"
    local _time_file="${4:-}"
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"

    # Resolve time range to start/end
    local _times _start_time _end_time
    _times=$(_audit_resolve_times "$_time_range")
    _start_time=$(head -1 <<< "$_times")
    _end_time=$(tail -1 <<< "$_times")

    echo ""
    _ui_menu_header "AUDIT LOGS" \
        --color "$RED" \
        --breadcrumb "Operations" "Audit Logs" \
        --cmd "oci audit event list --compartment-id \$COMPARTMENT_ID --start-time $_start_time --end-time $_end_time" \
        --env \
        --cache "${AUDIT_EVENTS_CACHE}|events"

    local _time_label
    _time_label=$(_audit_time_label "$_time_range")
    echo -e "  ${CYAN}Time Range:${NC} ${WHITE}${_time_label}${NC}  ${GRAY}(${_start_time} → ${_end_time})${NC}"
    [[ -n "$_filter" ]] && echo -e "  ${CYAN}Filter:${NC} ${WHITE}${_filter}${NC}"
    echo ""

    # Check cache freshness — invalidate if time range changed
    local _cache_valid=0
    if [[ -f "$AUDIT_EVENTS_CACHE" && -s "$AUDIT_EVENTS_CACHE" ]]; then
        local _cached_range
        _cached_range=$(jq -r '.meta.time_range // empty' "$AUDIT_EVENTS_CACHE" 2>/dev/null)
        local _ttl
        _ttl=$(_cache_ttl "$AUDIT_EVENTS_CACHE")
        local _age
        _age=$(( $(date +%s) - $(stat -c %Y "$AUDIT_EVENTS_CACHE" 2>/dev/null || echo 0) ))
        if [[ "$_cached_range" == "$_time_range" && $_age -lt $_ttl ]]; then
            _cache_valid=1
        fi
    fi

    _step_init
    _step_active "audit events"

    local _audit_json=""
    if [[ $_cache_valid -eq 1 ]]; then
        _audit_json=$(jq '.data' "$AUDIT_EVENTS_CACHE" 2>/dev/null)
    else
        # Note: omit --all to avoid slow multi-page pagination; first page (~100 events)
        # is sufficient for interactive display. Users can narrow with time range or filter.
        _audit_json=$(oci audit event list \
            --compartment-id "$_compartment" \
            --region "$region" \
            --start-time "$_start_time" \
            --end-time "$_end_time" \
            --output json 2>/dev/null)

        # Cache with metadata wrapper for time range tracking
        if [[ -n "$_audit_json" && "$_audit_json" != "null" ]]; then
            local _data_part="$_audit_json"
            # Extract .data if present
            if jq -e '.data' <<< "$_audit_json" >/dev/null 2>&1; then
                _data_part=$(jq '.data' <<< "$_audit_json")
            fi
            jq -n --arg tr "$_time_range" --argjson data "$_data_part" \
                '{meta: {time_range: $tr, cached_at: (now | todate)}, data: $data}' \
                > "$AUDIT_EVENTS_CACHE" 2>/dev/null
            _audit_json="$_data_part"
        fi
    fi

    local _event_count=0
    if [[ -n "$_audit_json" && "$_audit_json" != "null" ]]; then
        _event_count=$(jq 'if type == "array" then length else 0 end' <<< "$_audit_json" 2>/dev/null)
    fi
    _event_count="${_event_count:-0}"
    _step_complete "audit events(${_event_count})"
    _step_finish

    if [[ -z "$_audit_json" || "$_audit_json" == "null" || "$_event_count" -eq 0 ]]; then
        echo -e "  ${YELLOW}No audit events found for the selected time range.${NC}"
        echo ""
        if [[ -n "$_filter" ]]; then
            echo -e "  ${GRAY}Press Enter to clear filter, or 'b' to go back...${NC}"
            local _empty_choice; read -r _empty_choice
            if [[ "$_empty_choice" == "b" || "$_empty_choice" == "B" ]]; then
                return 0
            fi
            [[ -n "$_filter_file" ]] && echo "" > "$_filter_file"
            return 2
        fi
        _ui_pause "return"
        return 0
    fi

    # Apply filter if set (key:value syntax — source:xxx, principal:xxx, status:xxx, name:xxx)
    local _display_json="$_audit_json"
    if [[ -n "$_filter" ]]; then
        local _fkey="${_filter%%:*}"
        local _fval="${_filter#*:}"
        _fkey=$(echo "$_fkey" | tr '[:upper:]' '[:lower:]')
        case "$_fkey" in
            source)
                _display_json=$(jq --arg v "$_fval" '[.[] | select(.source // "" | ascii_downcase | contains($v | ascii_downcase))]' <<< "$_audit_json" 2>/dev/null) ;;
            principal)
                _display_json=$(jq --arg v "$_fval" '[.[] | select((.data.identity."principal-name" // .data.identity."principal-id" // "") | ascii_downcase | contains($v | ascii_downcase))]' <<< "$_audit_json" 2>/dev/null) ;;
            status)
                _display_json=$(jq --arg v "$_fval" '[.[] | select((.data.response.status // "" | tostring) | contains($v))]' <<< "$_audit_json" 2>/dev/null) ;;
            name|event)
                _display_json=$(jq --arg v "$_fval" '[.[] | select((.data."event-name" // "") | ascii_downcase | contains($v | ascii_downcase))]' <<< "$_audit_json" 2>/dev/null) ;;
            *)
                echo -e "  ${YELLOW}Unknown filter key '${_fkey}'. Supported: source, principal, status, name${NC}"
                _display_json="$_audit_json"
                ;;
        esac
        local _filtered_count
        _filtered_count=$(jq 'length' <<< "$_display_json" 2>/dev/null)
        echo -e "  ${CYAN}Showing ${WHITE}${_filtered_count}${CYAN} of ${_event_count} events${NC}"
        echo ""
    fi

    # Table display with pagination
    local _page_size=50
    local _total
    _total=$(jq 'length' <<< "$_display_json" 2>/dev/null)
    _total="${_total:-0}"
    local _page=0
    local _max_pages=$(( (_total + _page_size - 1) / _page_size ))
    [[ $_max_pages -eq 0 ]] && _max_pages=1

    while true; do
        local _offset=$(( _page * _page_size ))
        local _end_idx=$(( _offset + _page_size ))
        [[ $_end_idx -gt $_total ]] && _end_idx=$_total

        # Build column format and print header
        _col_build_fmt "AUD"
        printf "${BOLD}${_AUD_HDR_FMT}${NC}\n" "${_AUD_HDR_ARGS[@]}"
        print_separator $_AUD_SEP_WIDTH

        # Clear and populate audit map
        AUDIT_MAP=()
        local _idx=0

        while IFS='|' read -r _evt_time _evt_name _res_name _principal _status _source _evt_type _req_action; do
            [[ -z "$_evt_time" ]] && continue
            ((_idx++))
            local _global_idx=$(( _offset + _idx ))
            AUDIT_MAP[$_global_idx]="$_evt_type"

            # Format time: strip date portion for readability
            local _time_short="${_evt_time:0:19}"
            _time_short="${_time_short/T/ }"

            # Color status code: 2xx=green, 4xx=yellow, 5xx=red
            local _status_color="$GRAY"
            if [[ "$_status" =~ ^2 ]]; then _status_color="$GREEN"
            elif [[ "$_status" =~ ^4 ]]; then _status_color="$YELLOW"
            elif [[ "$_status" =~ ^5 ]]; then _status_color="$RED"
            fi

            _col_print_row "AUD" "a${_global_idx}" "$_time_short" "$_evt_name" "$_res_name" "$_principal" "$_status" "$_source" "$_evt_type" "$_req_action" "$_status_color"

        done < <(jq -r --argjson off "$_offset" --argjson lim "$_page_size" \
            'sort_by(.["event-time"]) | reverse | .[$off:$off+$lim] | .[] |
            "\(.["event-time"] // "N/A")|\(.data["event-name"] // "N/A")|\(.data["resource-name"] // "N/A")|\(.data.identity["principal-name"] // .data.identity["principal-id"] // "N/A")|\(.data.response.status // "N/A")|\(.source // "N/A")|\(.["event-type"] // "N/A")|\(.data.request.action // "N/A")"' \
            <<< "$_display_json" 2>/dev/null)

        # Hidden columns hint
        local -a _aud_hidden=()
        declare -A _aud_en_chk=()
        for _ek in "${_AUD_ENABLED_COLS[@]}"; do _aud_en_chk["$_ek"]=1; done
        for _ak in "${_AUD_COL_KEYS[@]}"; do
            [[ -z "${_aud_en_chk[$_ak]:-}" ]] && _aud_hidden+=("$_ak")
        done
        echo ""
        if [[ ${#_aud_hidden[@]} -gt 0 ]]; then
            echo -e "${GRAY}Hidden columns: ${_aud_hidden[*]} — use 'col' to toggle${NC}"
        fi
        if [[ $_max_pages -gt 1 ]]; then
            echo -e "  ${GRAY}Page $((_page + 1)) of ${_max_pages} (${_total} events)${NC}"
        fi

        # Interactive action loop
        while true; do
            _ui_actions "Audit Actions"
            echo -e "  ${YELLOW}a#${NC}        - View event detail (e.g., ${YELLOW}a1${NC})"
            echo -e "  ${YELLOW}/ <term>${NC}  - Search events for term (searches event name, source, principal, resource)"
            echo -e "  ${YELLOW}filter${NC}    - Filter events (${GRAY}source:xxx | principal:xxx | status:xxx | name:xxx${NC})"
            echo -e "  ${YELLOW}col${NC}       - Toggle column visibility"
            echo -e "  ${YELLOW}time${NC}      - Change time range"
            [[ $_max_pages -gt 1 ]] && echo -e "  ${YELLOW}n${NC}/${YELLOW}p${NC}       - Next/Previous page"
            echo -e "  ${YELLOW}r${NC}         - Reload (clear cache)"
            echo -e "  ${YELLOW}b${NC}         - Back to Operations"
            echo ""
            _ui_prompt "Audit Logs" "a#, / <term>, filter, col, time, r, b"
            local _choice; read -r _choice

            case "$_choice" in
                a[0-9]*)
                    local _sel="${_choice#a}"
                    if [[ -n "${AUDIT_MAP[$_sel]:-}" ]]; then
                        audit_show_event_detail "$_display_json" "$_sel"
                    else
                        echo -e "  ${RED}Invalid event index. Use a1-a${_total}.${NC}"
                    fi
                    ;;
                /*)
                    local _search_term="${_choice#/}"
                    _search_term="${_search_term# }"  # trim leading space
                    if [[ -z "$_search_term" ]]; then
                        echo -e "  ${YELLOW}Usage: / <search term>${NC}"
                    else
                        echo ""
                        echo -e "  ${CYAN}Search results for:${NC} ${WHITE}${_search_term}${NC}"
                        echo ""
                        local _search_results
                        _search_results=$(jq --arg term "$_search_term" '[.[] | select(
                            ((.data["event-name"] // "") | ascii_downcase | contains($term | ascii_downcase)) or
                            ((.source // "") | ascii_downcase | contains($term | ascii_downcase)) or
                            ((.data.identity["principal-name"] // "") | ascii_downcase | contains($term | ascii_downcase)) or
                            ((.data["resource-name"] // "") | ascii_downcase | contains($term | ascii_downcase)) or
                            ((.["event-type"] // "") | ascii_downcase | contains($term | ascii_downcase)) or
                            ((.data.request.action // "") | ascii_downcase | contains($term | ascii_downcase))
                        )]' <<< "$_display_json" 2>/dev/null)
                        local _search_count
                        _search_count=$(jq 'length' <<< "$_search_results" 2>/dev/null)
                        _search_count="${_search_count:-0}"
                        if [[ "$_search_count" -eq 0 ]]; then
                            echo -e "  ${YELLOW}No events matched '${_search_term}'.${NC}"
                        else
                            echo -e "  ${GREEN}Found ${_search_count} matching event(s):${NC}"
                            echo ""
                            _col_build_fmt "AUD"
                            printf "${BOLD}${_AUD_HDR_FMT}${NC}\n" "${_AUD_HDR_ARGS[@]}"
                            print_separator $_AUD_SEP_WIDTH
                            local _si=0
                            while IFS='|' read -r _s_time _s_name _s_res _s_principal _s_status _s_source _s_etype _s_action; do
                                [[ -z "$_s_time" ]] && continue
                                ((_si++))
                                local _s_time_short="${_s_time:0:19}"
                                _s_time_short="${_s_time_short/T/ }"
                                local _s_status_color="$GRAY"
                                if [[ "$_s_status" =~ ^2 ]]; then _s_status_color="$GREEN"
                                elif [[ "$_s_status" =~ ^4 ]]; then _s_status_color="$YELLOW"
                                elif [[ "$_s_status" =~ ^5 ]]; then _s_status_color="$RED"
                                fi
                                _col_print_row "AUD" "$_si" "$_s_time_short" "$_s_name" "$_s_res" "$_s_principal" "$_s_status" "$_s_source" "$_s_etype" "$_s_action" "$_s_status_color"
                            done < <(jq -r '.[] | "\(.["event-time"] // "N/A")|\(.data["event-name"] // "N/A")|\(.data["resource-name"] // "N/A")|\(.data.identity["principal-name"] // .data.identity["principal-id"] // "N/A")|\(.data.response.status // "N/A")|\(.source // "N/A")|\(.["event-type"] // "N/A")|\(.data.request.action // "N/A")"' <<< "$_search_results" 2>/dev/null | head -50)
                            [[ "$_search_count" -gt 50 ]] && echo -e "  ${GRAY}... showing first 50 of ${_search_count} matches${NC}"
                            echo ""
                            # Interactive selection from search results
                            while true; do
                                echo -e "  ${YELLOW}s#${NC} - View event detail (e.g., ${YELLOW}s1${NC})  │  ${WHITE}Enter${NC} - Back"
                                _ui_prompt "Search Results" "s#, Enter"
                                local _s_choice; read -r _s_choice
                                case "$_s_choice" in
                                    s[0-9]*)
                                        local _s_sel="${_s_choice#s}"
                                        if [[ "$_s_sel" -ge 1 && "$_s_sel" -le "$_search_count" ]] 2>/dev/null; then
                                            audit_show_event_detail "$_search_results" "$_s_sel"
                                        else
                                            echo -e "  ${RED}Invalid index. Use s1-s${_search_count}.${NC}"
                                        fi
                                        ;;
                                    [0-9]*)
                                        if [[ "$_s_choice" -ge 1 && "$_s_choice" -le "$_search_count" ]] 2>/dev/null; then
                                            audit_show_event_detail "$_search_results" "$_s_choice"
                                        else
                                            echo -e "  ${RED}Invalid index. Use 1-${_search_count}.${NC}"
                                        fi
                                        ;;
                                    "") break ;;
                                    *) echo -e "  ${RED}Invalid selection. Use s# or Enter to go back.${NC}" ;;
                                esac
                            done
                        fi
                    fi
                    ;;
                filter|FILTER)
                    echo ""
                    echo -e "  ${CYAN}Enter filter (key:value). Supported keys:${NC}"
                    echo -e "    ${WHITE}source${NC}:computeApi    ${WHITE}principal${NC}:username"
                    echo -e "    ${WHITE}status${NC}:200           ${WHITE}name${NC}:LaunchInstance"
                    echo -e "  ${GRAY}Leave empty to clear filter.${NC}"
                    echo -n "  Filter: "
                    local _new_filter; read -r _new_filter
                    [[ -n "$_filter_file" ]] && echo "$_new_filter" > "$_filter_file"
                    return 2
                    ;;
                time|TIME)
                    local _new_time=""
                    _audit_select_time_range "_new_time"
                    if [[ -n "$_new_time" ]]; then
                        [[ -n "$_time_file" ]] && echo "$_new_time" > "$_time_file"
                        # Clear cache so new time range triggers fresh fetch
                        rm -f "$AUDIT_EVENTS_CACHE" 2>/dev/null
                        return 2
                    fi
                    ;;
                n|N|next)
                    if [[ $((_page + 1)) -lt $_max_pages ]]; then
                        ((_page++))
                        break  # break inner loop to redraw table
                    else
                        echo -e "  ${YELLOW}Already on last page.${NC}"
                    fi
                    ;;
                p|P|prev)
                    if [[ $_page -gt 0 ]]; then
                        ((_page--))
                        break
                    else
                        echo -e "  ${YELLOW}Already on first page.${NC}"
                    fi
                    ;;
                r|R)
                    rm -f "$AUDIT_EVENTS_CACHE" 2>/dev/null
                    echo -e "  ${GREEN}Cache cleared. Reloading...${NC}"
                    return 2
                    ;;
                col|COL|columns|COLUMNS)
                    _col_picker "AUD" "Audit Log Columns"
                    break  # redraw table with new columns
                    ;;
                show|SHOW) break ;;
                b|B|"") return 0 ;;
                :*) _nav_try_jump "$_choice" && return 0 ;;
                *) echo -e "  ${RED}Invalid selection. Use a#, filter, col, time, n, p, r, or b.${NC}" ;;
            esac
        done
    done
}

#--------------------------------------------------------------------------------
# Display full detail for a single audit event
# Args: $1=json_array  $2=event_index (1-based within sorted array)
#--------------------------------------------------------------------------------
audit_show_event_detail() {
    local _json="$1"
    local _idx="$2"
    local _zero_idx=$((_idx - 1))

    local _event
    _event=$(jq --argjson i "$_zero_idx" 'sort_by(.["event-time"]) | reverse | .[$i]' <<< "$_json" 2>/dev/null)

    if [[ -z "$_event" || "$_event" == "null" ]]; then
        echo -e "  ${RED}Event not found at index ${_idx}.${NC}"
        _ui_pause "return"
        return
    fi

    echo ""
    _ui_menu_header "AUDIT EVENT DETAIL" \
        --breadcrumb "Operations" "Audit Logs" "Event a${_idx}" \
        --cmd "oci audit event list → event detail"

    # Extract fields
    local _evt_type _evt_time _source _evt_name
    _evt_type=$(jq -r '.["event-type"] // "N/A"' <<< "$_event")
    _evt_time=$(jq -r '.["event-time"] // "N/A"' <<< "$_event")
    _source=$(jq -r '.source // "N/A"' <<< "$_event")
    _evt_name=$(jq -r '.data["event-name"] // "N/A"' <<< "$_event")

    local _compartment_id _compartment_name _res_name _res_id
    _compartment_id=$(jq -r '.["compartment-id"] // "N/A"' <<< "$_event")
    _compartment_name=$(jq -r '.data["compartment-name"] // "N/A"' <<< "$_event")
    _res_name=$(jq -r '.data["resource-name"] // "N/A"' <<< "$_event")
    _res_id=$(jq -r '.data["resource-id"] // "N/A"' <<< "$_event")

    local _principal_name _principal_id _ip_address
    _principal_name=$(jq -r '.data.identity["principal-name"] // "N/A"' <<< "$_event")
    _principal_id=$(jq -r '.data.identity["principal-id"] // "N/A"' <<< "$_event")
    _ip_address=$(jq -r '.data.identity["ip-address"] // "N/A"' <<< "$_event")

    local _action _status _message
    _action=$(jq -r '.data.request.action // "N/A"' <<< "$_event")
    _status=$(jq -r '.data.response.status // "N/A"' <<< "$_event")
    _message=$(jq -r '.data.response.message // "N/A"' <<< "$_event")

    # Color status
    local _status_color="$GRAY"
    if [[ "$_status" =~ ^2 ]]; then _status_color="$GREEN"
    elif [[ "$_status" =~ ^4 ]]; then _status_color="$YELLOW"
    elif [[ "$_status" =~ ^5 ]]; then _status_color="$RED"
    fi

    # Display sections
    echo -e "  ${BOLD}${WHITE}Event${NC}"
    echo -e "    Event Type:   ${CYAN}${_evt_type}${NC}"
    echo -e "    Time:         ${WHITE}${_evt_time}${NC}"
    echo -e "    Source:       ${WHITE}${_source}${NC}"
    echo -e "    Event Name:   ${WHITE}${_evt_name}${NC}"
    echo ""

    echo -e "  ${BOLD}${WHITE}Resource${NC}"
    echo -e "    Compartment:  ${WHITE}${_compartment_name}${NC} ${GRAY}(${_compartment_id})${NC}"
    echo -e "    Name:         ${CYAN}${_res_name}${NC}"
    echo -e "    ID:           ${GRAY}${_res_id}${NC}"
    echo ""

    echo -e "  ${BOLD}${WHITE}Identity${NC}"
    echo -e "    Principal:    ${WHITE}${_principal_name}${NC}"
    echo -e "    Principal ID: ${GRAY}${_principal_id}${NC}"
    echo -e "    IP Address:   ${WHITE}${_ip_address}${NC}"
    echo ""

    echo -e "  ${BOLD}${WHITE}Request / Response${NC}"
    echo -e "    Action:       ${WHITE}${_action}${NC}"
    echo -e "    Status:       ${_status_color}${_status}${NC}"
    echo -e "    Message:      ${WHITE}${_message}${NC}"
    echo ""

    # Interactive: json dump or back
    while true; do
        _ui_actions "Detail Actions"
        echo -e "  ${YELLOW}j${NC}     - View JSON ${GRAY}| j <key> Search JSON${NC}"
        echo -e "  ${YELLOW}b${NC}     - Back to event list"
        echo ""
        _ui_prompt "Event Detail" "j, j <key>, b"
        local _dchoice; read -r _dchoice

        case "$_dchoice" in
            json|JSON|j|J)
                _ui_json_viewer "Event JSON" "$_event" "."
                _ui_pause
                ;;
            json\ *|JSON\ *|j\ *|J\ *)
                _ui_json_viewer "Event JSON" "$_event" "." "${_dchoice#* }"
                ;;
            b|B|"") return ;;
            :*) _nav_try_jump "$_dchoice" && return ;;
            *) echo -e "  ${RED}Invalid selection.${NC}" ;;
        esac
    done
}

#===============================================================================
# FLEET REPORT EXPORT
#===============================================================================
# Export current fleet state to markdown file
#--------------------------------------------------------------------------------
export_fleet_report() {
    local _compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local _region="${FOCUS_REGION:-$REGION}"
    local _ts; _ts=$(date '+%Y%m%d_%H%M%S')
    local _report="${LOGS_DIR}/fleet_report_${_ts}.md"

    echo ""
    echo -e "  ${YELLOW}Generating fleet report...${NC}"

    _step_init
    _step_active "fleet data"

    {
        echo "# GPU Fleet Report"
        echo "Generated: $(date '+%Y-%m-%d %H:%M:%S')"
        echo "Compartment: ${_compartment}"
        echo "Region: ${_region}"
        echo ""

        # OKE Cluster
        if [[ -s "$OKE_ENV_CACHE" ]]; then
            local _cname; _cname=$(grep 'CLUSTER_NAME=' "$OKE_ENV_CACHE" | cut -d= -f2-)
            local _cstate; _cstate=$(grep 'CLUSTER_STATE=' "$OKE_ENV_CACHE" | cut -d= -f2-)
            local _cver; _cver=$(grep 'CLUSTER_VERSION=' "$OKE_ENV_CACHE" | cut -d= -f2-)
            echo "## OKE Cluster"
            echo "| Field | Value |"
            echo "|-------|-------|"
            echo "| Name | ${_cname} |"
            echo "| State | ${_cstate} |"
            echo "| Version | ${_cver} |"
            echo ""
        fi

        # GPU Clusters
        if [[ -s "$CLUSTER_CACHE" ]]; then
            echo "## GPU Memory Clusters"
            echo "| Name | State | Fabric | Size |"
            echo "|------|-------|--------|------|"
            while IFS='|' read -r _cid _cname _cstate _fab _ic _cc _sz; do
                [[ "$_cid" == \#* || -z "$_cid" ]] && continue
                echo "| ${_cname} | ${_cstate} | ${_fab} | ${_sz} |"
            done < "$CLUSTER_CACHE"
            echo ""
        fi

        # Instances
        if [[ -s "$INSTANCE_LIST_CACHE" ]]; then
            echo "## Compute Instances"
            local _run _stop _total
            _run=$(jq '[.data[] | select(.["lifecycle-state"]=="RUNNING")] | length' "$INSTANCE_LIST_CACHE" 2>/dev/null || echo "0")
            _stop=$(jq '[.data[] | select(.["lifecycle-state"]=="STOPPED")] | length' "$INSTANCE_LIST_CACHE" 2>/dev/null || echo "0")
            _total=$(jq '.data | length' "$INSTANCE_LIST_CACHE" 2>/dev/null || echo "0")
            echo "- Total: ${_total}"
            echo "- Running: ${_run}"
            echo "- Stopped: ${_stop}"
            echo ""

            echo "| Name | Shape | State | AD |"
            echo "|------|-------|-------|----|"
            jq -r '.data[] | select(.["lifecycle-state"] != "TERMINATED") |
                "| \(.["display-name"] // "N/A") | \(.shape // "N/A") | \(.["lifecycle-state"] // "N/A") | \(.["availability-domain"] // "N/A" | split(":") | last) |"
            ' "$INSTANCE_LIST_CACHE" 2>/dev/null
            echo ""
        fi

        # Maintenance events
        if [[ -s "$MAINT_EVENTS_CACHE" ]]; then
            local _me_ct; _me_ct=$(jq '.data | length' "$MAINT_EVENTS_CACHE" 2>/dev/null || echo "0")
            echo "## Maintenance Events"
            echo "Active events: ${_me_ct}"
            echo ""
        fi

    } > "$_report"

    _step_complete "report"
    _step_finish

    echo -e "  ${GREEN}✓ Fleet report saved:${NC} ${WHITE}${_report}${NC}"
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# K8s NVIDIA Bug Report — Generate nvidia-bug-report.sh on GPU nodes
# Runs via kubectl debug with chroot /host. The report .log.gz stays on the node.
#--------------------------------------------------------------------------------
k8s_nvidia_bug_report() {
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"; return 1
    fi

    while true; do
        echo ""
        _ui_menu_header "NVIDIA BUG REPORT" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "NVIDIA Bug Report" \
            --cmd "kubectl debug node/<n> -- chroot /host nvidia-bug-report.sh --output-file nvidia-bug-report-\$(hostname)-\$(date +%Y%m%d%H%M%S)" \
            --env

        echo -e "  ${GRAY}Generates a comprehensive NVIDIA diagnostic bundle on the selected GPU node${NC}"
        echo -e "  ${GRAY}Output: /tmp/nvidia-bug-report-<hostname>-<timestamp>.log.gz on the node${NC}"

        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"; _step_finish
            echo -e "  ${RED}No K8s nodes found${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct; _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"; _step_finish
        echo ""

        declare -A _NBR_MAP=()
        local _nbr_idx=0

        printf "  ${BOLD}%-5s %-45s %-28s %5s %-8s${NC}\n" "ID" "Node Name" "Shape" "GPUs" "Status"
        print_separator 100

        while IFS='|' read -r _nname _shape _ready _gpu_ct _ocid; do
            [[ -z "$_nname" ]] && continue
            [[ "$_gpu_ct" == "0" || -z "$_gpu_ct" ]] && continue
            ((_nbr_idx++))
            local _st_color="$GREEN" _st_label="Ready"
            [[ "$_ready" != "True" ]] && { _st_color="$RED"; _st_label="NotRdy"; }
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s %5s ${_st_color}%-8s${NC}\n" \
                "i${_nbr_idx}" "${_nname:0:45}" "${_shape:0:28}" "$_gpu_ct" "$_st_label"
            _NBR_MAP[i${_nbr_idx}]="${_nname}|${_shape}"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // .metadata.labels["beta.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.status.capacity["nvidia.com/gpu"] // "0") as $gpus |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($gpus)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)

        if [[ $_nbr_idx -eq 0 ]]; then
            echo -e "  ${YELLOW}No GPU nodes detected in this cluster${NC}"
            _ui_pause "return"; return
        fi

        echo ""
        echo -e "  ${YELLOW}i#${NC} Select node to generate bug report"
        echo -e "  ${MAGENTA}r${NC} Refresh  ${CYAN}b${NC} Back"
        echo ""
        _ui_prompt "NVIDIA Bug Report" "i#, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            i[0-9]*)
                local _entry="${_NBR_MAP[$_choice]:-}"
                if [[ -z "$_entry" ]]; then
                    echo -e "  ${RED}Invalid selection: $_choice${NC}"; sleep 1; continue
                fi
                local _nname="${_entry%%|*}"
                local _nshape="${_entry#*|}"

                echo ""
                _ui_subheader "NVIDIA Bug Report — ${_nname}" 0
                echo -e "  ${GRAY}Shape: ${_nshape}${NC}"
                echo ""

                _kubectl_debug_cleanup "$_nname"

                echo ""

                local _nbr_cmd="nvidia-bug-report.sh --output-file /tmp/nvidia-bug-report-\$(hostname)-\$(date +%Y%m%d%H%M%S)"
                log_action "NVIDIA_BUG_REPORT" "kubectl debug node/${_nname} -- chroot /host ${_nbr_cmd}"

                local _nbr_t0; _nbr_t0=$(date +%s)
                _show_spinner "Generating NVIDIA bug report on ${_nname}..." &
                local _nbr_sp=$!
                local _nbr_output _nbr_rc=0
                _nbr_output=$(timeout --foreground --kill-after=5 120 kubectl debug "node/${_nname}" \
                    -i \
                    --image="${KUBECTL_DEBUG_IMAGE}" \
                    --profile=sysadmin \
                    -q \
                    -- chroot /host bash -c '
nvidia-bug-report.sh --output-file /tmp/nvidia-bug-report-$(hostname)-$(date +%Y%m%d%H%M%S) 2>&1
echo ""
echo "===FILES==="
ls -lh /tmp/nvidia-bug-report-*.log.gz 2>/dev/null | tail -5 || echo "(no report files found)"
echo "===END==="
' < <(sleep 120) 2>/dev/null) || _nbr_rc=$?
                local _nbr_elapsed=$(( $(date +%s) - _nbr_t0 ))
                _kill_spinner "$_nbr_sp" "Completed in ${_nbr_elapsed}s"

                if [[ $_nbr_rc -eq 124 ]]; then
                    echo -e "  ${RED}Timed out after 120s${NC}"
                elif [[ $_nbr_rc -ne 0 ]]; then
                    echo -e "  ${YELLOW}kubectl debug exited with code ${_nbr_rc}${NC}"
                fi

                # Display output
                if [[ -n "$_nbr_output" ]]; then
                    local _in_files=false
                    while IFS= read -r _line; do
                        if [[ "$_line" == "===FILES===" ]]; then
                            _in_files=true
                            echo ""
                            echo -e "  ${BOLD}Report Files on Node:${NC}"
                            continue
                        fi
                        [[ "$_line" == "===END===" ]] && break
                        if [[ "$_in_files" == true ]]; then
                            printf '  %b%s%b\n' "${GREEN}" "$_line" "${NC}"
                        else
                            printf '  %b%s%b\n' "${GRAY}" "$_line" "${NC}"
                        fi
                    done <<< "$_nbr_output"
                fi

                echo ""
                echo -e "  ${GRAY}Elapsed: ${WHITE}${_nbr_elapsed}s${NC}"
                echo -e "  ${CYAN}To retrieve the report:${NC}"
                echo -e "  ${WHITE}  ssh <node-ip> 'cat /tmp/nvidia-bug-report-*.log.gz' > nvidia-bug-report.log.gz${NC}"
                echo ""
                if [[ $_nbr_rc -eq 0 ]]; then
                    log_action_result "SUCCESS" "NVIDIA bug report on ${_nname} (${_nbr_elapsed}s)"
                elif [[ $_nbr_rc -eq 124 ]]; then
                    log_action_result "FAILED" "NVIDIA bug report timed out on ${_nname} (120s)"
                else
                    log_action_result "FAILED" "NVIDIA bug report failed on ${_nname} (rc=${_nbr_rc})"
                fi

                _kubectl_debug_cleanup "$_nname"
                _ui_pause
                ;;
            *)
                echo -e "  ${RED}Invalid selection${NC}"; sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# K8s SOS Report — Generate diagnostic bundle on K8s nodes
# Auto-detects Oracle Linux vs Ubuntu and runs the appropriate sos command.
# Oracle Linux: sudo sos report --batch  (output: /var/tmp/sosreport-*.tar.xz)
# Ubuntu:       sudo sos report --batch  (output: /tmp/sosreport-*.tar.xz)
# Ref: https://docs.oracle.com/en-us/iaas/oracle-linux/oci/diagnostics-sos.htm
#--------------------------------------------------------------------------------
k8s_sos_report() {
    if ! command -v kubectl &>/dev/null; then
        echo -e "  ${RED}kubectl not available${NC}"
        _ui_pause "return"; return 1
    fi

    while true; do
        echo ""
        _ui_menu_header "SOS REPORT" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "SOS Report" \
            --cmd "kubectl debug node/<n> -- chroot /host sos report --batch" \
            --env

        echo -e "  ${GRAY}Generates a comprehensive diagnostic bundle on the selected node${NC}"
        echo -e "  ${GRAY}Auto-detects OS: Oracle Linux (/var/tmp/) or Ubuntu (/tmp/)${NC}"
        echo -e "  ${GRAY}Collects: system config, logs, hardware info, network, storage, kernel${NC}"

        _step_init
        _step_active "K8s nodes"
        local _nodes_json
        _nodes_json=$(kubectl get nodes -o json 2>/dev/null)
        if [[ -z "$_nodes_json" ]] || ! jq -e '.items[0]' <<< "$_nodes_json" >/dev/null 2>&1; then
            _step_complete "0 nodes"; _step_finish
            echo -e "  ${RED}No K8s nodes found${NC}"
            _ui_pause "return"; return
        fi
        local _node_ct; _node_ct=$(jq '.items | length' <<< "$_nodes_json" 2>/dev/null)
        _step_complete "${_node_ct} nodes"; _step_finish
        echo ""

        declare -A _SOS_MAP=()
        local _sos_idx=0

        printf "  ${BOLD}%-5s %-45s %-28s %-12s %-8s${NC}\n" "ID" "Node Name" "Shape" "OS Image" "Status"
        print_separator 110

        while IFS='|' read -r _nname _shape _ready _os_image _ocid; do
            [[ -z "$_nname" ]] && continue
            ((_sos_idx++))
            local _st_color="$GREEN" _st_label="Ready"
            [[ "$_ready" != "True" ]] && { _st_color="$RED"; _st_label="NotRdy"; }
            local _os_short="${_os_image:0:12}"
            printf "  ${YELLOW}%-5s${NC} %-45s %-28s %-12s ${_st_color}%-8s${NC}\n" \
                "i${_sos_idx}" "${_nname:0:45}" "${_shape:0:28}" "$_os_short" "$_st_label"
            _SOS_MAP[i${_sos_idx}]="${_nname}|${_shape}|${_os_image}"
        done < <(jq -r '
            .items[] |
            (.metadata.labels["node.kubernetes.io/instance-type"] // .metadata.labels["beta.kubernetes.io/instance-type"] // "N/A") as $shape |
            (.status.conditions[] | select(.type=="Ready") | .status) as $ready |
            (.status.nodeInfo.osImage // "N/A") as $os |
            (.spec.providerID // "" | gsub("^oci://"; "")) as $ocid |
            "\(.metadata.name)|\($shape)|\($ready)|\($os)|\($ocid)"
        ' <<< "$_nodes_json" 2>/dev/null | sort -t'|' -k1,1)

        if [[ $_sos_idx -eq 0 ]]; then
            echo -e "  ${YELLOW}No nodes found${NC}"
            _ui_pause "return"; return
        fi

        echo ""
        echo -e "  ${YELLOW}i#${NC} Select node to generate SOS report"
        echo -e "  ${MAGENTA}r${NC} Refresh  ${CYAN}b${NC} Back"
        echo ""
        _ui_prompt "SOS Report" "i#, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            i[0-9]*)
                local _entry="${_SOS_MAP[$_choice]:-}"
                if [[ -z "$_entry" ]]; then
                    echo -e "  ${RED}Invalid selection: $_choice${NC}"; sleep 1; continue
                fi
                local _nname="${_entry%%|*}"; local _rest="${_entry#*|}"
                local _nshape="${_rest%%|*}"
                local _nos="${_rest#*|}"

                echo ""
                _ui_subheader "SOS Report — ${_nname}" 0
                echo -e "  ${GRAY}Shape: ${_nshape}  |  OS: ${_nos}${NC}"
                echo ""

                _kubectl_debug_cleanup "$_nname"

                echo ""

                log_action "SOS_REPORT" "kubectl debug node/${_nname} -- chroot /host sos report --batch"

                local _sos_t0; _sos_t0=$(date +%s)
                _show_spinner "Generating SOS report on ${_nname}..." &
                local _sos_sp=$!
                local _sos_output _sos_rc=0
                _sos_output=$(timeout --foreground --kill-after=5 300 kubectl debug "node/${_nname}" \
                    -i \
                    --image="${KUBECTL_DEBUG_IMAGE}" \
                    --profile=sysadmin \
                    -q \
                    -- chroot /host bash -c '
# Detect OS and ensure sos is available
if [ -f /etc/oracle-release ] || grep -qi "oracle" /etc/os-release 2>/dev/null; then
    _os_type="oracle"
    _sos_dir="/var/tmp"
    command -v sos >/dev/null 2>&1 || { echo "ERROR: sos not installed. Install with: dnf install sos"; exit 1; }
elif grep -qi "ubuntu" /etc/os-release 2>/dev/null; then
    _os_type="ubuntu"
    _sos_dir="/tmp"
    command -v sos >/dev/null 2>&1 || command -v sosreport >/dev/null 2>&1 || { echo "ERROR: sosreport not installed. Install with: apt install sosreport"; exit 1; }
else
    _os_type="other"
    _sos_dir="/var/tmp"
    command -v sos >/dev/null 2>&1 || command -v sosreport >/dev/null 2>&1 || { echo "ERROR: sos not installed"; exit 1; }
fi

echo "OS detected: ${_os_type}"
echo "Running: sos report --batch --tmp-dir ${_sos_dir}"
echo ""

sos report --batch --tmp-dir "${_sos_dir}" 2>&1 || sosreport --batch --tmp-dir "${_sos_dir}" 2>&1

echo ""
echo "===REPORTS==="
ls -lht ${_sos_dir}/sosreport-*.tar.xz 2>/dev/null | head -3 || \
ls -lht ${_sos_dir}/sosreport-*.tar.gz 2>/dev/null | head -3 || \
echo "(no report files found)"
echo "===END==="
' < <(sleep 300) 2>/dev/null) || _sos_rc=$?

                local _sos_elapsed=$(( $(date +%s) - _sos_t0 ))
                _kill_spinner "$_sos_sp" "Completed in ${_sos_elapsed}s"

                if [[ $_sos_rc -eq 124 ]]; then
                    echo -e "  ${RED}Timed out after 300s${NC}"
                elif [[ $_sos_rc -ne 0 ]]; then
                    echo -e "  ${YELLOW}kubectl debug exited with code ${_sos_rc}${NC}"
                fi

                # Display output
                if [[ -n "$_sos_output" ]]; then
                    local _in_reports=false
                    while IFS= read -r _line; do
                        if [[ "$_line" == "===REPORTS===" ]]; then
                            _in_reports=true
                            echo ""
                            echo -e "  ${BOLD}Report Files on Node:${NC}"
                            continue
                        fi
                        [[ "$_line" == "===END===" ]] && break
                        if [[ "$_in_reports" == true ]]; then
                            printf '  %b%s%b\n' "${GREEN}" "$_line" "${NC}"
                        else
                            # Show key progress lines
                            case "$_line" in
                                *"Running"*|*"OS detected"*|*"ERROR"*|*"finished"*|*"generated"*|*"/sosreport-"*)
                                    printf '  %b%s%b\n' "${WHITE}" "$_line" "${NC}" ;;
                                *"plugin"*|*"Loaded"*)
                                    ;; # Skip verbose plugin loading
                                *)
                                    printf '  %b%s%b\n' "${GRAY}" "$_line" "${NC}" ;;
                            esac
                        fi
                    done <<< "$_sos_output"
                fi

                echo ""
                echo -e "  ${GRAY}Elapsed: ${WHITE}${_sos_elapsed}s${NC}"
                echo -e "  ${CYAN}To retrieve the report:${NC}"
                echo -e "  ${WHITE}  ssh <node-ip> 'cat /var/tmp/sosreport-*.tar.xz' > sosreport.tar.xz${NC}"
                echo -e "  ${GRAY}  (or /tmp/ on Ubuntu)${NC}"
                echo ""
                if [[ $_sos_rc -eq 0 ]]; then
                    log_action_result "SUCCESS" "SOS report on ${_nname} (${_sos_elapsed}s)"
                elif [[ $_sos_rc -eq 124 ]]; then
                    log_action_result "FAILED" "SOS report timed out on ${_nname} (300s)"
                else
                    log_action_result "FAILED" "SOS report failed on ${_nname} (rc=${_sos_rc})"
                fi

                _kubectl_debug_cleanup "$_nname"
                _ui_pause
                ;;
            *)
                echo -e "  ${RED}Invalid selection${NC}"; sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# GPU Tolerations - View/add/remove newNode + Maintenance tolerations on
# gpu-operator daemonsets AND nvidia-gpu-device-plugin in kube-system so
# pods are not evicted when these taints are applied to nodes.
#--------------------------------------------------------------------------------
k8s_gpu_operator_tolerations() {
    local log_file="${LOGS_DIR}/gpu_tolerations_$(date '+%Y%m%d').log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null

    while true; do
        echo ""
        _ui_menu_header "GPU TOLERATIONS" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "GPU Tolerations" \
            --cmd "kubectl get ds -n gpu-operator -o json | kubectl get ds <ds> -n kube-system -o json | kubectl patch ds <ds> -n <ns> --type=json" \
            --env

        # --- Prerequisites ---
        if ! command -v kubectl &>/dev/null; then
            echo -e "  ${RED}kubectl not available${NC}"
            _ui_pause "return"; return
        fi

        # --- Discovery: gpu-operator ns + nvidia-gpu-device-plugin in kube-system ---
        _step_init
        local _has_gpuop=0 _has_devplugin=0 _has_dra=0
        local _ds_json_gpuop="" _ds_json_devplugin="" _ds_json_dra=""

        # gpu-operator namespace daemonsets
        _step_active "gpu-operator daemonsets"
        if kubectl get namespace gpu-operator &>/dev/null 2>&1; then
            _ds_json_gpuop=$(kubectl get daemonsets -n gpu-operator -o json 2>/dev/null)
            if [[ -n "$_ds_json_gpuop" ]] && jq -e '.items[0]' <<< "$_ds_json_gpuop" >/dev/null 2>&1; then
                local _ct_gpuop
                _ct_gpuop=$(jq '.items | length' <<< "$_ds_json_gpuop" 2>/dev/null)
                _has_gpuop=1
                _step_complete "${_ct_gpuop} gpu-operator"
            else
                _step_complete "0 gpu-operator"
            fi
        else
            _step_complete "no gpu-operator ns"
        fi

        # nvidia-gpu-device-plugin in kube-system
        _step_active "kube-system device-plugin"
        _ds_json_devplugin=$(kubectl get daemonset nvidia-gpu-device-plugin -n kube-system -o json 2>/dev/null)
        if [[ -n "$_ds_json_devplugin" ]] && jq -e '.metadata.name' <<< "$_ds_json_devplugin" >/dev/null 2>&1; then
            _has_devplugin=1
            _step_complete "1 device-plugin"
        else
            _step_complete "no device-plugin"
            _ds_json_devplugin=""
        fi

        # nvidia-dra-driver-gpu-kubelet-plugin in nvidia-dra-driver-gpu namespace
        _step_active "dra-driver-gpu kubelet-plugin"
        _ds_json_dra=$(kubectl get daemonset nvidia-dra-driver-gpu-kubelet-plugin -n nvidia-dra-driver-gpu -o json 2>/dev/null)
        if [[ -n "$_ds_json_dra" ]] && jq -e '.metadata.name' <<< "$_ds_json_dra" >/dev/null 2>&1; then
            _has_dra=1
            _step_complete "1 dra-kubelet-plugin"
        else
            _step_complete "no dra-kubelet-plugin"
            _ds_json_dra=""
        fi
        _step_finish

        if [[ $_has_gpuop -eq 0 && $_has_devplugin -eq 0 && $_has_dra -eq 0 ]]; then
            echo ""
            echo -e "  ${RED}No GPU daemonsets found${NC}"
            echo -e "  ${GRAY}Checked: gpu-operator ns, nvidia-gpu-device-plugin in kube-system, nvidia-dra-driver-gpu ns${NC}"
            local _kctx; _kctx=$(kubectl config current-context 2>/dev/null) || _kctx="(none)"
            echo -e "  ${GRAY}kubeconfig context: ${WHITE}${_kctx}${NC}"
            _ui_pause "return"; return
        fi
        echo ""

        # --- Parse daemonset data ---
        # DS_DATA format: name|namespace|ready|desired|has_newNode|has_Maintenance
        declare -A DS_INDEX_MAP=()
        declare -A DS_DATA=()
        declare -A DS_TOLS=()
        local _ds_idx=0

        printf "  ${BOLD}%-5s %-48s %-22s %6s %8s  %-12s %-12s${NC}\n" \
            "ID" "DaemonSet Name" "Namespace" "Ready" "Desired" "newNode" "Maintenance"
        print_separator 120

        # Helper to add a row to the table
        _gpu_tol_add_row() {
            local _rname="$1" _rns="$2" _rready="$3" _rdesired="$4" _rhnew="$5" _rhmaint="$6" _rtols="$7"
            ((_ds_idx++))
            local _did="d${_ds_idx}"
            DS_INDEX_MAP[$_did]="$_rname"
            DS_DATA[$_did]="${_rname}|${_rns}|${_rready}|${_rdesired}|${_rhnew}|${_rhmaint}"
            DS_TOLS[$_did]="$_rtols"

            local _new_icon _maint_icon
            [[ "$_rhnew" == "true" ]]   && _new_icon="${GREEN}✓${NC}" || _new_icon="${RED}✗${NC}"
            [[ "$_rhmaint" == "true" ]] && _maint_icon="${GREEN}✓${NC}" || _maint_icon="${RED}✗${NC}"

            # %b for colored icon + %-11s "" for padding (ANSI codes break %-Nb width)
            printf "  ${YELLOW}%-5s${NC} %-48s %-22s %6s %8s  %b%-11s %b\n" \
                "$_did" "${_rname:0:48}" "$_rns" "$_rready" "$_rdesired" \
                "$_new_icon" "" "$_maint_icon"
        }

        # Process gpu-operator daemonsets
        if [[ $_has_gpuop -eq 1 ]]; then
            while IFS='|' read -r _ds_name _ds_ready _ds_desired _has_new _has_maint; do
                [[ -z "$_ds_name" ]] && continue
                # Fetch toleration text separately (avoids newline-in-pipe bug)
                local _tol_text
                _tol_text=$(jq -r --arg name "$_ds_name" '
                    .items[] | select(.metadata.name == $name) |
                    (.spec.template.spec.tolerations // [])[] |
                    "     \(.key // "<unset>")=\(.value // "*") op=\(.operator // "Equal") effect=\(.effect // "<all>")"
                ' <<< "$_ds_json_gpuop" 2>/dev/null)
                _gpu_tol_add_row "$_ds_name" "gpu-operator" "$_ds_ready" "$_ds_desired" "$_has_new" "$_has_maint" "$_tol_text"
            done < <(jq -r '
                .items[] |
                (.metadata.name) as $name |
                (.status.numberReady // 0) as $ready |
                (.status.desiredNumberScheduled // 0) as $desired |
                ((.spec.template.spec.tolerations // []) | any(
                    .key == "newNode" and .value == "true" and .effect == "NoSchedule"
                )) as $has_new |
                ((.spec.template.spec.tolerations // []) | any(
                    .key == "Maintenance" and .value == "true" and .effect == "NoSchedule"
                )) as $has_maint |
                "\($name)|\($ready)|\($desired)|\($has_new)|\($has_maint)"
            ' <<< "$_ds_json_gpuop" 2>/dev/null | sort -t'|' -k1,1)
        fi

        # Process nvidia-gpu-device-plugin from kube-system (single object, not .items[])
        if [[ $_has_devplugin -eq 1 ]]; then
            local _dp_name _dp_ready _dp_desired _dp_hnew _dp_hmaint _dp_tols
            _dp_name=$(jq -r '.metadata.name' <<< "$_ds_json_devplugin" 2>/dev/null)
            _dp_ready=$(jq -r '.status.numberReady // 0' <<< "$_ds_json_devplugin" 2>/dev/null)
            _dp_desired=$(jq -r '.status.desiredNumberScheduled // 0' <<< "$_ds_json_devplugin" 2>/dev/null)
            _dp_hnew=$(jq -r '(.spec.template.spec.tolerations // []) | any(
                .key == "newNode" and .value == "true" and .effect == "NoSchedule"
            )' <<< "$_ds_json_devplugin" 2>/dev/null)
            _dp_hmaint=$(jq -r '(.spec.template.spec.tolerations // []) | any(
                .key == "Maintenance" and .value == "true" and .effect == "NoSchedule"
            )' <<< "$_ds_json_devplugin" 2>/dev/null)
            _dp_tols=$(jq -r '
                [(.spec.template.spec.tolerations // [])[] |
                    "     \(.key // "<unset>")=\(.value // "*") op=\(.operator // "Equal") effect=\(.effect // "<all>")"
                ] | join("\n")
            ' <<< "$_ds_json_devplugin" 2>/dev/null)
            _gpu_tol_add_row "$_dp_name" "kube-system" "$_dp_ready" "$_dp_desired" "$_dp_hnew" "$_dp_hmaint" "$_dp_tols"
        fi

        # Process nvidia-dra-driver-gpu-kubelet-plugin (single object, like device-plugin)
        if [[ $_has_dra -eq 1 ]]; then
            local _dra_name _dra_ready _dra_desired _dra_hnew _dra_hmaint _dra_tols
            _dra_name=$(jq -r '.metadata.name' <<< "$_ds_json_dra" 2>/dev/null)
            _dra_ready=$(jq -r '.status.numberReady // 0' <<< "$_ds_json_dra" 2>/dev/null)
            _dra_desired=$(jq -r '.status.desiredNumberScheduled // 0' <<< "$_ds_json_dra" 2>/dev/null)
            _dra_hnew=$(jq -r '(.spec.template.spec.tolerations // []) | any(
                .key == "newNode" and .value == "true" and .effect == "NoSchedule"
            )' <<< "$_ds_json_dra" 2>/dev/null)
            _dra_hmaint=$(jq -r '(.spec.template.spec.tolerations // []) | any(
                .key == "Maintenance" and .value == "true" and .effect == "NoSchedule"
            )' <<< "$_ds_json_dra" 2>/dev/null)
            _dra_tols=$(jq -r '
                (.spec.template.spec.tolerations // [])[] |
                "     \(.key // "<unset>")=\(.value // "*") op=\(.operator // "Equal") effect=\(.effect // "<all>")"
            ' <<< "$_ds_json_dra" 2>/dev/null)
            _gpu_tol_add_row "$_dra_name" "nvidia-dra-driver-gpu" "$_dra_ready" "$_dra_desired" "$_dra_hnew" "$_dra_hmaint" "$_dra_tols"
        fi

        unset -f _gpu_tol_add_row

        echo ""

        # --- Detailed Tolerations (color-coded: green=managed, gray=other) ---
        _ui_subheader "Current Tolerations per DaemonSet" 0
        echo ""
        local _d_key
        for _d_key in $(echo "${!DS_INDEX_MAP[@]}" | tr ' ' '\n' | sort -t'd' -k1.2 -n); do
            local _d_name="${DS_INDEX_MAP[$_d_key]}"
            local _d_ns
            _d_ns=$(echo "${DS_DATA[$_d_key]}" | cut -d'|' -f2)
            echo -e "  ${CYAN}${_d_key}${NC} ${WHITE}${_d_name}${NC} ${GRAY}(${_d_ns})${NC}"
            if [[ -z "${DS_TOLS[$_d_key]:-}" ]]; then
                echo -e "     ${GRAY}(none)${NC}"
            else
                while IFS= read -r _tol_line; do
                    [[ -z "$_tol_line" ]] && continue
                    if [[ "$_tol_line" == *"newNode="* || "$_tol_line" == *"Maintenance="* ]]; then
                        echo -e "${GREEN}${_tol_line}${NC}"
                    else
                        echo -e "${GRAY}${_tol_line}${NC}"
                    fi
                done <<< "${DS_TOLS[$_d_key]}"
            fi
        done

        echo ""

        # --- Summary ---
        local _all_new=0 _all_maint=0 _total_ds=$_ds_idx
        for _d_key in "${!DS_DATA[@]}"; do
            local _hn _hm
            _hn=$(echo "${DS_DATA[$_d_key]}" | cut -d'|' -f5)
            _hm=$(echo "${DS_DATA[$_d_key]}" | cut -d'|' -f6)
            [[ "$_hn" == "true" ]] && ((_all_new++))
            [[ "$_hm" == "true" ]] && ((_all_maint++))
        done
        echo -e "  ${BOLD}Summary:${NC} ${_total_ds} daemonset(s) | newNode: ${_all_new}/${_total_ds} | Maintenance: ${_all_maint}/${_total_ds}"

        echo ""
        _ui_actions
        echo ""
        echo -e "  ${YELLOW}d#${NC}             Show live tolerations for a daemonset (e.g. ${YELLOW}d1${NC})"
        echo -e "  ${GREEN}add d#|all${NC}     Add newNode + Maintenance tolerations"
        echo -e "  ${RED}remove d#|all${NC}  Remove newNode + Maintenance tolerations"
        echo -e "  ${MAGENTA}r${NC}) Refresh  ${CYAN}b${NC}) Back"
        echo ""
        _ui_prompt "GPU Tolerations" "d#, add d#|all, remove d#|all, r, b"
        local _choice; read -r _choice
        [[ "${_choice:-}" == :* ]] && _nav_try_jump "$_choice" && return

        case "$_choice" in
            r|R) continue ;;
            b|B|back|"") return ;;
            add\ *|ADD\ *)
                local _targets="${_choice#* }"
                _k8s_gpu_toleration_add "$_targets" "$log_file"
                ;;
            remove\ *|REMOVE\ *)
                local _targets="${_choice#* }"
                _k8s_gpu_toleration_remove "$_targets" "$log_file"
                ;;
            d[0-9]*)
                # Show live tolerations for a single daemonset
                local _dsel="${_choice}"
                if [[ -z "${DS_INDEX_MAP[$_dsel]:-}" ]]; then
                    echo -e "  ${RED}Invalid ID: ${_dsel}${NC}"; sleep 1; continue
                fi
                local _dsel_name="${DS_INDEX_MAP[$_dsel]}"
                local _dsel_ns
                _dsel_ns=$(echo "${DS_DATA[$_dsel]}" | cut -d'|' -f2)
                echo ""
                _ui_subheader "Live Tolerations: ${_dsel_name} (${_dsel_ns})" 0
                echo ""
                echo -e "  ${GRAY}$ kubectl get daemonset ${_dsel_name} -n ${_dsel_ns} -o json | jq ...${NC}"
                echo ""
                local _live_json
                _live_json=$(kubectl get daemonset "${_dsel_name}" -n "${_dsel_ns}" -o json 2>/dev/null)
                local _live_tols
                _live_tols=$(jq -r '
                    (.spec.template.spec.tolerations // []) | to_entries[] |
                    "\(.value.key // "*")|\(.value.effect // "All")|\(.value.operator // "Equal")|\(.value.value // "n/a")"
                ' <<< "$_live_json" 2>/dev/null)
                if [[ -z "$_live_tols" ]]; then
                    echo -e "  ${GRAY}(no tolerations set)${NC}"
                else
                    echo -e "  ${WHITE}${BOLD}=== ${_dsel_name} ===${NC}"
                    while IFS='|' read -r _tk _te _to _tv; do
                        [[ -z "$_tk" ]] && continue
                        # Highlight managed tolerations (newNode/Maintenance) vs others
                        local _key_color="$GRAY"
                        if [[ "$_tk" == "newNode" || "$_tk" == "Maintenance" ]]; then
                            _key_color="$GREEN"
                        fi
                        printf "    ${_key_color}[%-20s]${NC}  effect=${YELLOW}%-12s${NC}  operator=${CYAN}%-8s${NC}  value=${WHITE}%s${NC}\n" \
                            "$_tk" "$_te" "$_to" "$_tv"
                    done <<< "$_live_tols"
                fi
                echo ""
                _ui_pause
                ;;
            *)
                echo -e "  ${RED}Invalid selection. Use: d#, add d#|all, remove d#|all, r, b${NC}"
                sleep 1
                ;;
        esac

        # Clean up associative arrays for next loop iteration
        unset DS_INDEX_MAP DS_DATA DS_TOLS
    done
}

#--------------------------------------------------------------------------------
# Add newNode + Maintenance tolerations to GPU daemonsets
# Uses DS_DATA (name|namespace|ready|desired|has_new|has_maint) from caller
# Args: $1 = targets (d#, d#-d#, all)
#       $2 = log file path
#--------------------------------------------------------------------------------
_k8s_gpu_toleration_add() {
    local targets="$1" log_file="$2"

    if ! _parse_targets "d" "$targets" "DS_INDEX_MAP"; then
        echo -e "  ${RED}No valid targets. Use: add d1, add d1,d3, add d1-d5, add all${NC}"
        sleep 2; return 1
    fi

    echo ""
    _ui_subheader "Add Tolerations: newNode + Maintenance" 0
    echo ""

    # Preview table — show which daemonsets will be patched
    declare -a _ADD_TARGETS=()
    printf "  ${BOLD}%-5s %-48s %-22s %-12s %-12s %-8s${NC}\n" \
        "ID" "DaemonSet" "Namespace" "newNode" "Maintenance" "Action"
    print_separator 114

    for _si in "${_SEL_INDICES[@]}"; do
        local _key="d${_si}"
        local _data="${DS_DATA[$_key]}"
        local _name _ns _hn _hm
        _name=$(echo "$_data" | cut -d'|' -f1)
        _ns=$(echo "$_data" | cut -d'|' -f2)
        _hn=$(echo "$_data" | cut -d'|' -f5)
        _hm=$(echo "$_data" | cut -d'|' -f6)

        if [[ "$_hn" == "true" && "$_hm" == "true" ]]; then
            printf "  ${YELLOW}%-5s${NC} %-48s %-22s ${GREEN}%b${NC}%-11s ${GREEN}%b${NC}%-11s ${GRAY}%-8s${NC}\n" \
                "$_key" "${_name:0:48}" "$_ns" "✓" "" "✓" "" "Skip"
        else
            local _add_new_icon _add_new_color _add_maint_icon _add_maint_color
            [[ "$_hn" == "true" ]] && { _add_new_icon="✓"; _add_new_color="${GREEN}"; } || { _add_new_icon="✗"; _add_new_color="${RED}"; }
            [[ "$_hm" == "true" ]] && { _add_maint_icon="✓"; _add_maint_color="${GREEN}"; } || { _add_maint_icon="✗"; _add_maint_color="${RED}"; }
            printf "  ${YELLOW}%-5s${NC} %-48s %-22s ${_add_new_color}%b${NC}%-11s ${_add_maint_color}%b${NC}%-11s ${GREEN}%-8s${NC}\n" \
                "$_key" "${_name:0:48}" "$_ns" "$_add_new_icon" "" "$_add_maint_icon" "" "Patch"
            _ADD_TARGETS+=("${_key}|${_name}|${_ns}|${_hn}|${_hm}")
        fi
    done

    if [[ ${#_ADD_TARGETS[@]} -eq 0 ]]; then
        echo ""
        echo -e "  ${GREEN}All selected daemonsets already have both tolerations${NC}"
        _ui_pause; return 0
    fi

    # Show current tolerations + what will be added (green) per daemonset
    declare -A _ADD_PATCHES=()
    echo ""
    _ui_subheader "Current Tolerations" 0
    for _t in "${_ADD_TARGETS[@]}"; do
        local _tname _tns _thn _thm
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)
        _thn=$(echo "$_t" | cut -d'|' -f4)
        _thm=$(echo "$_t" | cut -d'|' -f5)

        local _cur_json
        _cur_json=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null)
        echo -e "  ${WHITE}${BOLD}${_tname}${NC} ${GRAY}(${_tns})${NC}"
        echo ""

        # Show existing tolerations in gray
        local _all_tol_ct
        _all_tol_ct=$(jq '(.spec.template.spec.tolerations // []) | length' <<< "$_cur_json" 2>/dev/null)
        _all_tol_ct=${_all_tol_ct:-0}
        for ((_ti=0; _ti<_all_tol_ct; _ti++)); do
            local _ti_json
            _ti_json=$(jq --argjson i "$_ti" '.spec.template.spec.tolerations[$i]' <<< "$_cur_json" 2>/dev/null)
            echo -e "    ${GRAY}index ${_ti}${NC}"
            echo "$_ti_json" | while IFS= read -r _jline; do
                echo -e "      ${GRAY}${_jline}${NC}"
            done
        done

        # Show tolerations being added in green
        if [[ "$_thn" != "true" ]]; then
            echo -e "    ${GREEN}index ${_all_tol_ct} ← ADD${NC}"
            echo -e "      ${GREEN}{${NC}"
            echo -e "      ${GREEN}  \"key\": \"newNode\",${NC}"
            echo -e "      ${GREEN}  \"operator\": \"Equal\",${NC}"
            echo -e "      ${GREEN}  \"value\": \"true\",${NC}"
            echo -e "      ${GREEN}  \"effect\": \"NoSchedule\"${NC}"
            echo -e "      ${GREEN}}${NC}"
            ((_all_tol_ct++))
        fi
        if [[ "$_thm" != "true" ]]; then
            echo -e "    ${GREEN}index ${_all_tol_ct} ← ADD${NC}"
            echo -e "      ${GREEN}{${NC}"
            echo -e "      ${GREEN}  \"key\": \"Maintenance\",${NC}"
            echo -e "      ${GREEN}  \"operator\": \"Equal\",${NC}"
            echo -e "      ${GREEN}  \"value\": \"true\",${NC}"
            echo -e "      ${GREEN}  \"effect\": \"NoSchedule\"${NC}"
            echo -e "      ${GREEN}}${NC}"
        fi

        # Build patch command and store for command display
        local _prev_ops=()
        [[ "$_thn" != "true" ]] && _prev_ops+=('{"op":"add","path":"/spec/template/spec/tolerations/-","value":{"key":"newNode","operator":"Equal","value":"true","effect":"NoSchedule"}}')
        [[ "$_thm" != "true" ]] && _prev_ops+=('{"op":"add","path":"/spec/template/spec/tolerations/-","value":{"key":"Maintenance","operator":"Equal","value":"true","effect":"NoSchedule"}}')
        _ADD_PATCHES["${_tname}|${_tns}"]=$(IFS=','; echo "[${_prev_ops[*]}]")
        echo ""
    done

    # Show commands to execute
    echo ""
    _ui_subheader "Commands to Execute" 0
    for _t in "${_ADD_TARGETS[@]}"; do
        local _tname _tns
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)
        local _patch="${_ADD_PATCHES["${_tname}|${_tns}"]}"
        echo -e "  ${GRAY}kubectl patch daemonset ${_tname} -n ${_tns} --type=json -p '${_patch}'${NC}"
        echo ""
    done
    unset _ADD_PATCHES

    echo -n -e "  ${CYAN}Add tolerations to ${#_ADD_TARGETS[@]} daemonset(s)? [y/N]: ${NC}"
    local _confirm; read -r _confirm
    if [[ ! "$_confirm" =~ ^[Yy] ]]; then
        echo -e "  ${YELLOW}Cancelled${NC}"
        _ui_pause; return 1
    fi

    echo ""
    local _ok=0 _fail=0
    for _t in "${_ADD_TARGETS[@]}"; do
        local _tid _tname _tns _thn _thm
        _tid=$(echo "$_t" | cut -d'|' -f1)
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)
        _thn=$(echo "$_t" | cut -d'|' -f4)
        _thm=$(echo "$_t" | cut -d'|' -f5)

        # Build patch JSON — only add missing tolerations
        local _patch_ops=()
        if [[ "$_thn" != "true" ]]; then
            _patch_ops+=('{"op":"add","path":"/spec/template/spec/tolerations/-","value":{"key":"newNode","operator":"Equal","value":"true","effect":"NoSchedule"}}')
        fi
        if [[ "$_thm" != "true" ]]; then
            _patch_ops+=('{"op":"add","path":"/spec/template/spec/tolerations/-","value":{"key":"Maintenance","operator":"Equal","value":"true","effect":"NoSchedule"}}')
        fi

        local _patch_json
        _patch_json=$(IFS=','; echo "[${_patch_ops[*]}]")

        # Check if tolerations array exists; if null, initialize it first
        local _fresh_check
        _fresh_check=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null)
        local _has_tol
        _has_tol=$(jq -r '
            if (.spec.template.spec.tolerations // null) == null then "null" else "exists" end
        ' <<< "$_fresh_check" 2>/dev/null)

        if [[ "$_has_tol" == "null" ]]; then
            local _init_cmd="kubectl patch daemonset ${_tname} -n ${_tns} --type=json -p '[{\"op\":\"add\",\"path\":\"/spec/template/spec/tolerations\",\"value\":[]}]'"
            echo -e "  ${GRAY}$ ${_init_cmd}${NC}"
            _log_to "$log_file" "EXECUTE" "$_init_cmd"
            log_action "INIT_TOLERATIONS" "$_init_cmd" --quiet
            local _init_result
            _init_result=$(kubectl patch daemonset "${_tname}" -n "${_tns}" --type=json \
                -p '[{"op":"add","path":"/spec/template/spec/tolerations","value":[]}]' 2>&1)
            if [[ $? -ne 0 ]]; then
                echo -e "  ${RED}✗ Failed to initialize tolerations array for ${_tname} (${_tns}): ${_init_result}${NC}"
                _log_to "$log_file" "FAILED" "Init tolerations ${_tname} -n ${_tns}: ${_init_result}"
                log_action_result "FAILED" "Init tolerations ${_tname} (${_tns})"
                ((_fail++))
                continue
            fi
        fi

        local _cmd="kubectl patch daemonset ${_tname} -n ${_tns} --type=json -p '${_patch_json}'"
        echo -e "  ${GRAY}$ ${_cmd}${NC}"
        _log_to "$log_file" "EXECUTE" "$_cmd"
        log_action "ADD_TOLERATION" "$_cmd" --quiet

        local _result
        _result=$(kubectl patch daemonset "${_tname}" -n "${_tns}" --type=json -p "${_patch_json}" 2>&1)
        local _rc=$?

        if [[ $_rc -eq 0 ]]; then
            echo -e "  ${GREEN}✓ Patched ${_tname} (${_tns})${NC}"
            _log_to "$log_file" "SUCCESS" "Add tolerations ${_tname} -n ${_tns}"
            log_action_result "SUCCESS" "Add tolerations ${_tname} (${_tns})"
            # Show updated tolerations after patch
            local _post_tols
            _post_tols=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null | jq '.spec.template.spec.tolerations' 2>/dev/null)
            if [[ -n "$_post_tols" && "$_post_tols" != "null" ]]; then
                echo -e "  ${GRAY}Updated tolerations:${NC}"
                echo "$_post_tols" | while IFS= read -r _jline; do
                    echo -e "    ${CYAN}${_jline}${NC}"
                done
            fi
            ((_ok++))
        else
            echo -e "  ${RED}✗ Failed ${_tname} (${_tns}): ${_result}${NC}"
            _log_to "$log_file" "FAILED" "Add tolerations ${_tname} -n ${_tns}: ${_result}"
            log_action_result "FAILED" "Add tolerations ${_tname} (${_tns})"
            ((_fail++))
        fi
    done

    echo ""
    echo -e "  ${BOLD}Result:${NC} ${GREEN}${_ok} succeeded${NC}, ${RED}${_fail} failed${NC}"
    _log_to "$log_file" "SUMMARY" "Add tolerations: ${_ok} succeeded, ${_fail} failed"
    _ui_pause
}

#--------------------------------------------------------------------------------
# Remove newNode + Maintenance tolerations from GPU daemonsets
# Uses DS_DATA (name|namespace|ready|desired|has_new|has_maint) from caller
# Args: $1 = targets (d#, d#-d#, all)
#       $2 = log file path
#--------------------------------------------------------------------------------
_k8s_gpu_toleration_remove() {
    local targets="$1" log_file="$2"

    if ! _parse_targets "d" "$targets" "DS_INDEX_MAP"; then
        echo -e "  ${RED}No valid targets. Use: remove d1, remove d1,d3, remove d1-d5, remove all${NC}"
        sleep 2; return 1
    fi

    echo ""
    _ui_subheader "Remove Tolerations: newNode + Maintenance" 0
    echo ""

    # Preview table
    declare -a _RM_TARGETS=()
    printf "  ${BOLD}%-5s %-48s %-22s %-12s %-12s %-8s${NC}\n" \
        "ID" "DaemonSet" "Namespace" "newNode" "Maintenance" "Action"
    print_separator 114

    for _si in "${_SEL_INDICES[@]}"; do
        local _key="d${_si}"
        local _data="${DS_DATA[$_key]}"
        local _name _ns _hn _hm
        _name=$(echo "$_data" | cut -d'|' -f1)
        _ns=$(echo "$_data" | cut -d'|' -f2)
        _hn=$(echo "$_data" | cut -d'|' -f5)
        _hm=$(echo "$_data" | cut -d'|' -f6)

        if [[ "$_hn" != "true" && "$_hm" != "true" ]]; then
            printf "  ${YELLOW}%-5s${NC} %-48s %-22s ${GRAY}%b${NC}%-11s ${GRAY}%b${NC}%-11s ${GRAY}%-8s${NC}\n" \
                "$_key" "${_name:0:48}" "$_ns" "✗" "" "✗" "" "Skip"
        else
            local _rm_new_icon _rm_new_color _rm_maint_icon _rm_maint_color
            [[ "$_hn" == "true" ]] && { _rm_new_icon="✓"; _rm_new_color="${GREEN}"; } || { _rm_new_icon="✗"; _rm_new_color="${RED}"; }
            [[ "$_hm" == "true" ]] && { _rm_maint_icon="✓"; _rm_maint_color="${GREEN}"; } || { _rm_maint_icon="✗"; _rm_maint_color="${RED}"; }
            printf "  ${YELLOW}%-5s${NC} %-48s %-22s ${_rm_new_color}%b${NC}%-11s ${_rm_maint_color}%b${NC}%-11s ${RED}%-8s${NC}\n" \
                "$_key" "${_name:0:48}" "$_ns" "$_rm_new_icon" "" "$_rm_maint_icon" "" "Remove"
            _RM_TARGETS+=("${_key}|${_name}|${_ns}")
        fi
    done

    if [[ ${#_RM_TARGETS[@]} -eq 0 ]]; then
        echo ""
        echo -e "  ${GREEN}None of the selected daemonsets have managed tolerations to remove${NC}"
        _ui_pause; return 0
    fi

    # Show current tolerations per daemonset (highlight ones being removed)
    # Store resolved indices per target for the command display below
    declare -A _RM_PATCHES=()
    echo ""
    _ui_subheader "Current Tolerations" 0
    for _t in "${_RM_TARGETS[@]}"; do
        local _tname _tns
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)
        local _prev_json
        _prev_json=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null)
        local _prev_indices
        _prev_indices=$(jq -r '
            [(.spec.template.spec.tolerations // []) | to_entries[] |
              select((.value.key == "newNode" or .value.key == "Maintenance") and
                     .value.value == "true" and .value.effect == "NoSchedule") | .key
            ] | sort | reverse | .[]
        ' <<< "$_prev_json" 2>/dev/null)

        echo -e "  ${WHITE}${BOLD}${_tname}${NC} ${GRAY}(${_tns})${NC}"
        echo ""

        if [[ -n "$_prev_indices" ]]; then
            # Build set of removal indices for lookup
            local -A _rm_idx_set=()
            while IFS= read -r _pidx; do
                [[ -z "$_pidx" ]] && continue
                _rm_idx_set[$_pidx]=1
            done <<< "$_prev_indices"
            # List every toleration — full JSON object per index
            local _all_tol_ct
            _all_tol_ct=$(jq '(.spec.template.spec.tolerations // []) | length' <<< "$_prev_json" 2>/dev/null)
            for ((_ti=0; _ti<_all_tol_ct; _ti++)); do
                local _ti_json _ti_color _ti_label
                _ti_json=$(jq --argjson i "$_ti" '.spec.template.spec.tolerations[$i]' <<< "$_prev_json" 2>/dev/null)
                if [[ -n "${_rm_idx_set[$_ti]:-}" ]]; then
                    _ti_color="$RED"
                    _ti_label=" ← REMOVE"
                else
                    _ti_color="$GRAY"
                    _ti_label=""
                fi
                echo -e "    ${_ti_color}index ${_ti}${NC}${RED}${_ti_label}${NC}"
                echo "$_ti_json" | while IFS= read -r _jline; do
                    echo -e "      ${_ti_color}${_jline}${NC}"
                done
            done
            unset _rm_idx_set
            # Build patch JSON and store for command display
            local _prev_ops=()
            while IFS= read -r _pidx; do
                [[ -z "$_pidx" ]] && continue
                _prev_ops+=("{\"op\":\"remove\",\"path\":\"/spec/template/spec/tolerations/${_pidx}\"}")
            done <<< "$_prev_indices"
            _RM_PATCHES["${_tname}|${_tns}"]=$(IFS=','; echo "[${_prev_ops[*]}]")
        else
            echo -e "    ${GRAY}(no matching tolerations to remove)${NC}"
        fi
        echo ""
    done

    # Show commands to execute
    echo ""
    _ui_subheader "Commands to Execute" 0
    for _t in "${_RM_TARGETS[@]}"; do
        local _tname _tns
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)
        local _patch="${_RM_PATCHES["${_tname}|${_tns}"]:-[]}"
        echo -e "  ${GRAY}kubectl patch daemonset ${_tname} -n ${_tns} --type=json -p '${_patch}'${NC}"
        echo ""
    done
    unset _RM_PATCHES

    echo -n -e "  ${CYAN}Remove tolerations from ${#_RM_TARGETS[@]} daemonset(s)? [y/N]: ${NC}"
    local _confirm; read -r _confirm
    if [[ ! "$_confirm" =~ ^[Yy] ]]; then
        echo -e "  ${YELLOW}Cancelled${NC}"
        _ui_pause; return 1
    fi

    echo ""
    local _ok=0 _fail=0
    for _t in "${_RM_TARGETS[@]}"; do
        local _tid _tname _tns
        _tid=$(echo "$_t" | cut -d'|' -f1)
        _tname=$(echo "$_t" | cut -d'|' -f2)
        _tns=$(echo "$_t" | cut -d'|' -f3)

        # Re-fetch fresh JSON for this daemonset to get current toleration indices
        local _fresh_json
        _fresh_json=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null)
        if [[ -z "$_fresh_json" ]]; then
            echo -e "  ${RED}✗ Cannot fetch ${_tname} (${_tns})${NC}"
            _log_to "$log_file" "FAILED" "Fetch daemonset ${_tname} -n ${_tns} for removal"
            ((_fail++))
            continue
        fi

        # Find indices of newNode/Maintenance tolerations, sorted in reverse
        local _indices
        _indices=$(jq -r '
            [(.spec.template.spec.tolerations // []) | to_entries[] |
              select((.value.key == "newNode" or .value.key == "Maintenance") and
                     .value.value == "true" and .value.effect == "NoSchedule") | .key
            ] | sort | reverse | .[]
        ' <<< "$_fresh_json" 2>/dev/null)

        if [[ -z "$_indices" ]]; then
            echo -e "  ${GRAY}✓ ${_tname} (${_tns}) — no matching tolerations found (already clean)${NC}"
            _log_to "$log_file" "SKIP" "No tolerations to remove on ${_tname} -n ${_tns}"
            continue
        fi

        # Build patch JSON with descending indices to prevent index shift
        local _patch_ops=()
        while IFS= read -r _idx; do
            [[ -z "$_idx" ]] && continue
            _patch_ops+=("{\"op\":\"remove\",\"path\":\"/spec/template/spec/tolerations/${_idx}\"}")
        done <<< "$_indices"

        local _patch_json
        _patch_json=$(IFS=','; echo "[${_patch_ops[*]}]")

        local _cmd="kubectl patch daemonset ${_tname} -n ${_tns} --type=json -p '${_patch_json}'"
        echo -e "  ${GRAY}$ ${_cmd}${NC}"
        _log_to "$log_file" "EXECUTE" "$_cmd"
        log_action "REMOVE_TOLERATION" "$_cmd" --quiet

        local _result
        _result=$(kubectl patch daemonset "${_tname}" -n "${_tns}" --type=json -p "${_patch_json}" 2>&1)
        local _rc=$?

        if [[ $_rc -eq 0 ]]; then
            echo -e "  ${GREEN}✓ Removed tolerations from ${_tname} (${_tns})${NC}"
            _log_to "$log_file" "SUCCESS" "Remove tolerations ${_tname} -n ${_tns}"
            log_action_result "SUCCESS" "Remove tolerations ${_tname} (${_tns})"
            # Show remaining tolerations after removal
            local _post_tols
            _post_tols=$(kubectl get daemonset "${_tname}" -n "${_tns}" -o json 2>/dev/null | jq '.spec.template.spec.tolerations' 2>/dev/null)
            if [[ -n "$_post_tols" && "$_post_tols" != "null" ]]; then
                echo -e "  ${GRAY}Remaining tolerations:${NC}"
                echo "$_post_tols" | while IFS= read -r _jline; do
                    echo -e "    ${CYAN}${_jline}${NC}"
                done
            else
                echo -e "  ${GRAY}Remaining tolerations: (none)${NC}"
            fi
            ((_ok++))
        else
            echo -e "  ${RED}✗ Failed ${_tname} (${_tns}): ${_result}${NC}"
            _log_to "$log_file" "FAILED" "Remove tolerations ${_tname} -n ${_tns}: ${_result}"
            log_action_result "FAILED" "Remove tolerations ${_tname} (${_tns})"
            ((_fail++))
        fi
    done

    echo ""
    echo -e "  ${BOLD}Result:${NC} ${GREEN}${_ok} succeeded${NC}, ${RED}${_fail} failed${NC}"
    _log_to "$log_file" "SUMMARY" "Remove tolerations: ${_ok} succeeded, ${_fail} failed"
    _ui_pause
}

#--------------------------------------------------------------------------------
# K8s Storage Provisioning Validation — BV, FSS, Lustre
# Validates IAM policies, storage classes, CSI drivers, PVCs, mount targets,
# Lustre file systems, and NSG network rules for storage provisioning readiness.
# Reuses cached NSG/subnet data from --manage n when available.
#--------------------------------------------------------------------------------
k8s_storage_provisioning_check() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local tenancy_id="${TENANCY_ID:-$(get_oke_env_value "TENANCY_OCID")}"
    [[ -z "$tenancy_id" || "$tenancy_id" == "N/A" ]] && tenancy_id="$COMPARTMENT_ID"

    local _stv_show_all=0

    while true; do
        echo ""
        _ui_menu_header "K8S STORAGE PROVISIONING VALIDATION" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "Storage Validation" \
            --cmd "kubectl get sc | kubectl get pvc -A | kubectl get csidrivers | oci iam policy list | oci network nsg rules list | oci fs mount-target list | oci lfs lustre-file-system-collection list-lustre-file-systems" \
            --env \
            --cache \
            "${POLICIES_ALL_CACHE}|Policies" \
            "${COMPARTMENTS_CACHE}|Compartments" \
            "${FSS_MT_CACHE}|FSS MTs" \
            "${LUSTRE_FS_CACHE}|Lustre" \
            "${NETWORK_RESOURCES_CACHE}|NSGs|NSG"

        # Prerequisites
        if ! command -v kubectl &>/dev/null; then
            echo -e "  ${RED}kubectl not available${NC}"
            _ui_pause "return"; return
        fi
        if ! command -v jq &>/dev/null; then
            echo -e "  ${RED}jq not available${NC}"
            _ui_pause "return"; return
        fi

        #---------------------------------------------------------------
        # DISCOVERY PHASE — parallel fetches where possible
        # Caches checked: COMPARTMENTS_CACHE (--manage i1),
        #   POLICIES_ALL_CACHE (--manage i3), FSS_MT_CACHE (--manage s1),
        #   LUSTRE_FS_CACHE (--manage s2), NSG_RULES_DETAIL_DIR (--manage n1)
        #---------------------------------------------------------------
        _step_init
        local _stv_ptmp="${TEMP_DIR}/stv_$$"
        mkdir -p "$_stv_ptmp"

        # --- Policies (reuse cache from --manage i3 / i1) ---
        # Use _STEP_OUTER=1 so _policy_fetch_all merges its compartment+policy
        # steps into this parent bar instead of creating a nested discovery bar
        local _pol_needs_fetch=0
        if [[ ! -f "$POLICIES_ALL_CACHE" ]] || [[ ! -f "$COMPARTMENTS_CACHE" ]] || \
           ! is_cache_fresh "$POLICIES_ALL_CACHE"; then
            _pol_needs_fetch=1
        fi
        if [[ $_pol_needs_fetch -eq 1 ]]; then
            _STEP_OUTER=1 _policy_fetch_all "$tenancy_id"
        else
            _policy_fetch_all "$tenancy_id"   # returns immediately (cache fresh)
        fi
        local _pol_count=0
        [[ -f "$POLICIES_ALL_CACHE" ]] && _pol_count=$(jq '.data | length' "$POLICIES_ALL_CACHE" 2>/dev/null || echo "0")
        # If cache was already fresh, _policy_fetch_all added no steps — add our own
        [[ $_pol_needs_fetch -eq 0 ]] && _step_complete "policies(${_pol_count}, cached)"
        # --- K8s resources + node pools in parallel ---
        _step_active "k8s resources"
        kubectl get storageclasses -o json > "$_stv_ptmp/sc.json" 2>/dev/null &
        local _p1=$!
        kubectl get pvc -A -o json > "$_stv_ptmp/pvc.json" 2>/dev/null &
        local _p2=$!
        kubectl get csidrivers -o json > "$_stv_ptmp/csi.json" 2>/dev/null &
        local _p3=$!
        kubectl version -o json > "$_stv_ptmp/ver.json" 2>/dev/null &
        local _p4=$!

        # Node pool fetch (parallel) — authoritative source for worker/pod subnets
        local _p5=""
        local _stv_cluster_id; _stv_cluster_id=$(get_oke_env_value "OKE_CLUSTER_ID")
        if [[ -s "$OKE_NODEPOOL_CACHE" ]] && is_cache_fresh "$OKE_NODEPOOL_CACHE"; then
            cp "$OKE_NODEPOOL_CACHE" "$_stv_ptmp/np.json" 2>/dev/null
        elif [[ -n "$_stv_cluster_id" && "$_stv_cluster_id" != "N/A" ]]; then
            (oci ce node-pool list --compartment-id "$compartment_id" --cluster-id "$_stv_cluster_id" \
                --region "$region" --all --output json > "$_stv_ptmp/np.json" 2>/dev/null && \
             cp "$_stv_ptmp/np.json" "$OKE_NODEPOOL_CACHE" 2>/dev/null) &
            _p5=$!
        fi

        wait $_p1 $_p2 $_p3 $_p4 ${_p5:+$_p5} 2>/dev/null

        local _sc_ct=0 _pvc_ct=0 _csi_ct=0 _np_ct=0
        [[ -s "$_stv_ptmp/sc.json" ]] && _sc_ct=$(jq '.items | length' "$_stv_ptmp/sc.json" 2>/dev/null || echo 0)
        [[ -s "$_stv_ptmp/pvc.json" ]] && _pvc_ct=$(jq '.items | length' "$_stv_ptmp/pvc.json" 2>/dev/null || echo 0)
        [[ -s "$_stv_ptmp/csi.json" ]] && _csi_ct=$(jq '.items | length' "$_stv_ptmp/csi.json" 2>/dev/null || echo 0)
        [[ -s "$_stv_ptmp/np.json" ]] && _np_ct=$(jq '(.data // []) | length' "$_stv_ptmp/np.json" 2>/dev/null || echo 0)
        _step_complete "sc(${_sc_ct}) pvc(${_pvc_ct}) csi(${_csi_ct}) np(${_np_ct})"

        # --- NSG / Subnet resolution ---
        _step_active "network"
        local _w_sub_ocid="" _w_sub_name="" _w_sub_cidr="" _w_nsg_ocid="" _w_nsg_name=""
        local _p_sub_ocid="" _p_sub_name="" _p_sub_cidr="" _p_nsg_ocid="" _p_nsg_name=""
        local _fss_sub_ocid="" _fss_sub_name="" _fss_sub_cidr="" _fss_nsg_ocid="" _fss_nsg_name=""
        local _lus_sub_ocid="" _lus_sub_name="" _lus_sub_cidr="" _lus_nsg_ocid="" _lus_nsg_name=""

        # OKE cluster JSON — endpoint, LB, VCN, compartment
        local _oke_cluster_comp="" _oke_vcn_ocid="" _oke_vcn_name=""
        local _oke_ep_sub="" _oke_lb_sub="" _oke_cluster_name=""
        local _oke_ep_sub_name="" _oke_ep_sub_cidr="" _oke_lb_sub_name="" _oke_lb_sub_cidr=""
        _oke_vcn_name=$(get_oke_env_value "VCN_NAME")
        _oke_cluster_name=$(get_oke_env_value "CLUSTER_NAME")
        if [[ -s "$OKE_CLUSTER_JSON_CACHE" ]]; then
            IFS=$'\t' read -r _oke_cluster_comp _oke_vcn_ocid _oke_ep_sub _oke_lb_sub < <(
                jq -r '.data | [
                    (.["compartment-id"] // "N/A"),
                    (.["vcn-id"] // "N/A"),
                    (.["endpoint-config"]["subnet-id"] // "N/A"),
                    (.options["service-lb-subnet-ids"][0] // "N/A")
                ] | @tsv' "$OKE_CLUSTER_JSON_CACHE" 2>/dev/null
            )
        fi

        # Fallback: OKE_ENV_CACHE (name-matched — used only if node pool unavailable)
        _w_sub_ocid=$(get_oke_env_value "WORKER_SUBNET_OCID")
        _w_sub_name=$(get_oke_env_value "WORKER_SUBNET_NAME")
        _w_nsg_ocid=$(get_oke_env_value "WORKER_NSG_OCID")
        _w_nsg_name=$(get_oke_env_value "WORKER_NSG_NAME")
        _p_sub_ocid=$(get_oke_env_value "POD_SUBNET_OCID")
        _p_sub_name=$(get_oke_env_value "POD_SUBNET_NAME")
        _p_nsg_ocid=$(get_oke_env_value "POD_NSG_OCID")
        _p_nsg_name=$(get_oke_env_value "POD_NSG_NAME")

        # Override with authoritative node pool data (placement-configs, not name-matching)
        local _np_source="name-match"
        if [[ -s "$_stv_ptmp/np.json" && $_np_ct -gt 0 ]]; then
            local _np_w _np_wn _np_p _np_pn
            _np_w=$(jq -r '.data[0]["node-config-details"]["placement-configs"][0]["subnet-id"] // empty' "$_stv_ptmp/np.json" 2>/dev/null)
            _np_wn=$(jq -r '.data[0]["node-config-details"]["nsg-ids"][0] // empty' "$_stv_ptmp/np.json" 2>/dev/null)
            _np_p=$(jq -r '.data[0]["node-config-details"]["node-pool-pod-network-option-details"]["pod-subnet-ids"][0] // empty' "$_stv_ptmp/np.json" 2>/dev/null)
            _np_pn=$(jq -r '.data[0]["node-config-details"]["node-pool-pod-network-option-details"]["pod-nsg-ids"][0] // empty' "$_stv_ptmp/np.json" 2>/dev/null)
            [[ -n "$_np_w" ]] && _w_sub_ocid="$_np_w" && _np_source="node-pool"
            [[ -n "$_np_wn" ]] && _w_nsg_ocid="$_np_wn"
            [[ -n "$_np_p" ]] && _p_sub_ocid="$_np_p"
            [[ -n "$_np_pn" ]] && _p_nsg_ocid="$_np_pn"
        fi

        # Resolve names, CIDRs, and FSS/Lustre subnets from NETWORK_RESOURCES_CACHE
        if [[ -f "$NETWORK_RESOURCES_CACHE" ]]; then
            # Worker subnet name + CIDR
            if [[ -n "$_w_sub_ocid" && "$_w_sub_ocid" != "N/A" ]]; then
                IFS='|' read -r _w_sub_name _w_sub_cidr < <(awk -F'|' -v ocid="$_w_sub_ocid" '$1=="SUBNET" && $6==ocid {print $2"|"$3; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            fi
            # Worker NSG name
            [[ -n "$_w_nsg_ocid" && "$_w_nsg_ocid" != "N/A" ]] && \
                _w_nsg_name=$(awk -F'|' -v ocid="$_w_nsg_ocid" '$1=="NSG" && $5==ocid {print $2; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            # Pod subnet name + CIDR
            if [[ -n "$_p_sub_ocid" && "$_p_sub_ocid" != "N/A" ]]; then
                IFS='|' read -r _p_sub_name _p_sub_cidr < <(awk -F'|' -v ocid="$_p_sub_ocid" '$1=="SUBNET" && $6==ocid {print $2"|"$3; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            fi
            # Pod NSG name
            [[ -n "$_p_nsg_ocid" && "$_p_nsg_ocid" != "N/A" ]] && \
                _p_nsg_name=$(awk -F'|' -v ocid="$_p_nsg_ocid" '$1=="NSG" && $5==ocid {print $2; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            # Endpoint subnet name + CIDR
            if [[ -n "$_oke_ep_sub" && "$_oke_ep_sub" != "N/A" ]]; then
                IFS='|' read -r _oke_ep_sub_name _oke_ep_sub_cidr < <(awk -F'|' -v ocid="$_oke_ep_sub" '$1=="SUBNET" && $6==ocid {print $2"|"$3; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            fi
            # Service LB subnet name + CIDR
            if [[ -n "$_oke_lb_sub" && "$_oke_lb_sub" != "N/A" ]]; then
                IFS='|' read -r _oke_lb_sub_name _oke_lb_sub_cidr < <(awk -F'|' -v ocid="$_oke_lb_sub" '$1=="SUBNET" && $6==ocid {print $2"|"$3; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            fi
            # FSS subnet — match shortname "fss"
            while IFS='|' read -r _t _n _c _a _s _o _rest; do
                [[ "$_t" != "SUBNET" ]] && continue
                local _sn; _sn=$(get_shortname_match "$_n")
                if [[ "$_sn" == "fss" ]]; then
                    _fss_sub_ocid="$_o"; _fss_sub_name="$_n"; _fss_sub_cidr="$_c"
                    break
                fi
            done < "$NETWORK_RESOURCES_CACHE"
            # Lustre subnet — match shortname "lustre"
            while IFS='|' read -r _t _n _c _a _s _o _rest; do
                [[ "$_t" != "SUBNET" ]] && continue
                local _sn; _sn=$(get_shortname_match "$_n")
                if [[ "$_sn" == "lustre" ]]; then
                    _lus_sub_ocid="$_o"; _lus_sub_name="$_n"; _lus_sub_cidr="$_c"
                    break
                fi
            done < "$NETWORK_RESOURCES_CACHE"
            # FSS NSG — match shortname "fss"
            while IFS='|' read -r _t _n _ _s _o _rest; do
                [[ "$_t" != "NSG" ]] && continue
                local _sn; _sn=$(get_shortname_match "$_n")
                if [[ "$_sn" == "fss" ]]; then
                    _fss_nsg_ocid="$_o"; _fss_nsg_name="$_n"
                    break
                fi
            done < "$NETWORK_RESOURCES_CACHE"
            # Lustre NSG — match shortname "lustre"
            while IFS='|' read -r _t _n _ _s _o _rest; do
                [[ "$_t" != "NSG" ]] && continue
                local _sn; _sn=$(get_shortname_match "$_n")
                if [[ "$_sn" == "lustre" ]]; then
                    _lus_nsg_ocid="$_o"; _lus_nsg_name="$_n"
                    break
                fi
            done < "$NETWORK_RESOURCES_CACHE"
        fi

        # Fetch NSG rules for relevant NSGs (reuse cache from --manage n)
        local _nsg_ids_to_fetch=""
        [[ -n "$_w_nsg_ocid" && "$_w_nsg_ocid" != "N/A" ]] && _nsg_ids_to_fetch+="${_w_nsg_ocid}"$'\n'
        [[ -n "$_p_nsg_ocid" && "$_p_nsg_ocid" != "N/A" ]] && _nsg_ids_to_fetch+="${_p_nsg_ocid}"$'\n'
        [[ -n "$_fss_nsg_ocid" ]] && _nsg_ids_to_fetch+="${_fss_nsg_ocid}"$'\n'
        [[ -n "$_lus_nsg_ocid" ]] && _nsg_ids_to_fetch+="${_lus_nsg_ocid}"$'\n'
        [[ -n "$_nsg_ids_to_fetch" ]] && fetch_nsg_rules_detail_parallel "$_nsg_ids_to_fetch"
        local _nsg_ct=0
        [[ -d "$NSG_RULES_DETAIL_DIR" ]] && _nsg_ct=$(find "$NSG_RULES_DETAIL_DIR" -name "*.json" -type f 2>/dev/null | wc -l)
        _step_complete "nsgs(${_nsg_ct})"

        # --- FSS mount targets ---
        _step_active "mount targets"
        local _mt_json=""
        if [[ -f "$FSS_MT_CACHE" ]] && is_cache_fresh "$FSS_MT_CACHE" 2>/dev/null; then
            _mt_json=$(cat "$FSS_MT_CACHE" 2>/dev/null)
        else
            # Fetch across all ADs
            local _ads
            _ads=$(oci iam availability-domain list --compartment-id "$compartment_id" --region "$region" --query 'data[].name' --raw-output 2>/dev/null | jq -r '.[]' 2>/dev/null)
            if [[ -n "$_ads" ]]; then
                local _all_mt="[]" _mt_pids=()
                mkdir -p "$_stv_ptmp/mt"
                local _mi=0
                while IFS= read -r _ad; do
                    [[ -z "$_ad" ]] && continue
                    ((_mi++))
                    (oci fs mount-target list --compartment-id "$compartment_id" --availability-domain "$_ad" --region "$region" --all --output json > "$_stv_ptmp/mt/mt_${_mi}.json" 2>/dev/null) &
                    _mt_pids+=($!)
                done <<< "$_ads"
                [[ ${#_mt_pids[@]} -gt 0 ]] && wait "${_mt_pids[@]}" 2>/dev/null
                for _f in "$_stv_ptmp"/mt/mt_*.json; do
                    [[ -s "$_f" ]] || continue
                    local _md; _md=$(jq '.data // []' "$_f" 2>/dev/null) || continue
                    _all_mt=$(echo "$_all_mt" "$_md" | jq -s 'add' 2>/dev/null)
                done
                _mt_json="{\"data\":$_all_mt}"
            fi
        fi
        local _mt_ct=0
        [[ -n "$_mt_json" ]] && _mt_ct=$(jq '.data | length' <<< "$_mt_json" 2>/dev/null || echo 0)
        _step_complete "mount targets(${_mt_ct})"

        # --- FSS: Override subnet from actual mount target (authoritative) ---
        local _fss_mt_sub_ocid="" _fss_same_vcn=-1
        if [[ -n "$_mt_json" && "$_mt_ct" -gt 0 ]]; then
            _fss_mt_sub_ocid=$(jq -r '[.data[] | select(."lifecycle-state" == "ACTIVE")] | .[0]."subnet-id" // empty' <<< "$_mt_json" 2>/dev/null)
            if [[ -n "$_fss_mt_sub_ocid" ]]; then
                _fss_sub_ocid="$_fss_mt_sub_ocid"
                # Resolve from NETWORK_RESOURCES_CACHE (same VCN = found in cache)
                if [[ -f "$NETWORK_RESOURCES_CACHE" ]]; then
                    local _mt_sub_line
                    _mt_sub_line=$(awk -F'|' -v ocid="$_fss_mt_sub_ocid" '$1=="SUBNET" && $6==ocid {print $0; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
                    if [[ -n "$_mt_sub_line" ]]; then
                        _fss_same_vcn=1
                        IFS='|' read -r _ _fss_sub_name _fss_sub_cidr _ _ _ _ _ _ _ <<< "$_mt_sub_line"
                    else
                        _fss_same_vcn=0
                        # Subnet not in OKE VCN cache — different VCN or different compartment
                        # Try direct API resolve for name/CIDR
                        local _mt_sub_json
                        _mt_sub_json=$(oci network subnet get --subnet-id "$_fss_mt_sub_ocid" --region "$region" --output json 2>/dev/null)
                        if [[ -n "$_mt_sub_json" ]]; then
                            _fss_sub_name=$(jq -r '.data."display-name" // "N/A"' <<< "$_mt_sub_json" 2>/dev/null)
                            _fss_sub_cidr=$(jq -r '.data."cidr-block" // "N/A"' <<< "$_mt_sub_json" 2>/dev/null)
                        fi
                    fi
                fi
                # Re-fetch NSG rules if the FSS NSG wasn't already fetched
                if [[ -n "$_fss_nsg_ocid" ]]; then
                    local _fss_nsg_short="${_fss_nsg_ocid##*.}"
                    if [[ ! -f "${NSG_RULES_DETAIL_DIR}/${_fss_nsg_short}.json" ]]; then
                        fetch_nsg_rules_detail_parallel "$_fss_nsg_ocid"
                    fi
                fi
            fi
        fi

        # --- Lustre file systems (reuse cache from --manage s2) ---
        _step_active "lustre"
        local _lfs_json=""
        if [[ -f "$LUSTRE_FS_CACHE" ]] && is_cache_fresh "$LUSTRE_FS_CACHE"; then
            _lfs_json=$(cat "$LUSTRE_FS_CACHE" 2>/dev/null)
        else
            _lfs_json=$(oci lfs lustre-file-system-collection list-lustre-file-systems \
                --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
            [[ -n "$_lfs_json" && "$_lfs_json" != "null" ]] && echo "$_lfs_json" | _cache_write "$LUSTRE_FS_CACHE"
        fi
        local _lfs_ct=0
        [[ -n "$_lfs_json" && "$_lfs_json" != "null" ]] && _lfs_ct=$(jq '.data.items | length' <<< "$_lfs_json" 2>/dev/null || echo 0)
        _step_complete "lustre(${_lfs_ct})"

        _step_finish
        echo ""

        #---------------------------------------------------------------
        # HELPER: Check a policy statement for verb+resource+where
        # Matches principals: any-user, any-group, group <n>, dynamic-group <n>
        # Matches scope: in tenancy | in compartment <name|id>
        # Args: $1=verb+resource (e.g. "manage volumes")
        #       $2=where clause  (e.g. "request.principal.type = 'cluster'")
        # Sets: _pol_found (0/1), _pol_name, _pol_comp, _pol_principal
        #---------------------------------------------------------------
        _stv_check_policy() {
            local verb_resource="$1" where_clause="$2"
            _pol_found=0 _pol_name="" _pol_comp="" _pol_principal="" _pol_match_type=""
            [[ ! -f "$POLICIES_ALL_CACHE" ]] && return

            local _match
            _match=$(python3 - "$verb_resource" "$where_clause" "$POLICIES_ALL_CACHE" << 'PYEOF'
import json, re, sys

verb_resource = sys.argv[1]   # e.g. "manage volumes"
where_clause  = sys.argv[2]   # e.g. "request.principal.type = 'cluster'"
cache_file    = sys.argv[3]

with open(cache_file) as f:
    data = json.load(f)

# Principal: allow any-user|any-group|group <name>|dynamic-group <name> to
principal_pat = r'allow\s+(?P<principal>any-user|any-group|(?:dynamic-)?group\s+\S+)\s+to\s+'

# Verb + resource with flexible whitespace
vr_pat = r'\s+'.join(re.escape(w) for w in verb_resource.strip().split())

# Scope: in tenancy | in compartment <name|id ocid>
scope_pat = r'\s+in\s+(?P<scope>tenancy|compartment\s+(?:id\s+)?\S+)'

# Where clause — flexible spacing, single/double quotes
where_pat = r'\s*'.join(re.escape(w) for w in where_clause.strip().split())
where_pat = where_pat.replace(r"\'", r"['\"]")

# Pattern WITH where clause (specific grant)
full_pat = principal_pat + vr_pat + scope_pat + r'.*?' + where_pat
# Pattern WITHOUT where clause (broad grant — no where at all)
broad_pat = principal_pat + vr_pat + scope_pat + r'\s*$'

# Try specific (with where) first, then broad (no where)
for match_type, pat in [("specific", full_pat), ("broad", broad_pat)]:
    for pol in data.get('data', []):
        for s in pol.get('statements', []):
            m = re.search(pat, s, re.IGNORECASE)
            if m:
                principal = m.group('principal')
                scope = m.group('scope')
                comp_id = pol.get('compartment-id', '')
                pol_name = pol.get('name', 'Unknown')
                print(f"{match_type}|{pol_name}|{comp_id}|{principal}|{scope}")
                sys.exit(0)
PYEOF
)
            if [[ -n "$_match" ]]; then
                _pol_found=1
                _pol_match_type="${_match%%|*}"
                local _rest="${_match#*|}"
                _pol_name="${_rest%%|*}"
                _rest="${_rest#*|}"
                local _comp_id="${_rest%%|*}"
                _rest="${_rest#*|}"
                _pol_principal="${_rest%%|*}"
                if [[ "$_comp_id" == "$tenancy_id" ]]; then
                    _pol_comp="tenancy"
                else
                    _pol_comp="compartment"
                fi
            fi
        }

        # Pad colored text to exact visual width (handles ANSI codes)
        _tpad() {
            local _w=$1; shift; local _text="$*"
            local _plain; _plain=$(printf '%b' "$_text" | sed 's/\x1b\[[0-9;]*m//g')
            local _vlen=${#_plain} _pad=$((_w - ${#_plain}))
            (( _pad < 0 )) && _pad=0
            printf '%b%*s' "$_text" "$_pad" ""
        }

        # Single-line policy result
        _stv_print_policy() {
            local vr="$1"
            if [[ $_pol_found -eq 1 ]]; then
                local _how="specific"; [[ "$_pol_match_type" == "broad" ]] && _how="broad"
                printf "    ${GREEN}✓${NC}  %-34s ${GRAY}%s, %s (%s)${NC}\n" "$vr" "$_pol_comp" "$_pol_principal" "$_how"
            else
                printf "    ${RED}✗${NC}  %-34s ${RED}NOT FOUND${NC}\n" "$vr"
            fi
        }

        # Policy search footer — shows what was searched
        _stv_policy_footer() {
            echo -e "    ${GRAY}Searched ${_pol_count} policies: specific (where clause) + broad (no where clause)${NC}"
        }

        #---------------------------------------------------------------
        # HELPER: Check NSG rule for specific port/protocol
        # Args: $1=nsg_ocid $2=direction(INGRESS|EGRESS) $3=protocol(6=TCP|17=UDP)
        #       $4=dest_port_min $5=dest_port_max $6=source_or_dest_cidr
        #       $7=src_port_min(optional) $8=src_port_max(optional)
        # Returns: 0=found, 1=not found
        #---------------------------------------------------------------
        _stv_check_nsg_rule() {
            local nsg_ocid="$1" direction="$2" protocol="$3"
            local dport_min="$4" dport_max="$5" cidr="$6"
            local sport_min="${7:-}" sport_max="${8:-}"
            [[ -z "$nsg_ocid" ]] && return 1

            local _rules_json
            _rules_json=$(get_cached_nsg_rules "$nsg_ocid" 2>/dev/null)
            [[ -z "$_rules_json" ]] && return 1

            local _found
            _found=$(jq -r --arg dir "$direction" --arg proto "$protocol" \
                --arg dpmin "$dport_min" --arg dpmax "$dport_max" \
                --arg cidr "$cidr" --arg spmin "$sport_min" --arg spmax "$sport_max" '
                .rules[] |
                select(.direction == $dir) |
                select(.protocol == $proto or .protocol == "all") |
                select(
                    (.source // .destination // "") as $target |
                    ($target == $cidr) or ($target == "0.0.0.0/0")
                ) |
                if $proto == "6" then
                    select(
                        (.protocol == "all") or
                        (."tcp-options" == null) or
                        ((."tcp-options"."destination-port-range".min // 0 | tonumber) <= ($dpmin | tonumber) and
                         (."tcp-options"."destination-port-range".max // 0 | tonumber) >= ($dpmax | tonumber))
                    ) |
                    if ($spmin != "" and $spmax != "") then
                        select(
                            (.protocol == "all") or
                            (."tcp-options" == null) or
                            (."tcp-options"."source-port-range" == null) or
                            ((."tcp-options"."source-port-range".min // 0 | tonumber) <= ($spmin | tonumber) and
                             (."tcp-options"."source-port-range".max // 0 | tonumber) >= ($spmax | tonumber))
                        )
                    else . end
                elif $proto == "17" then
                    select(
                        (.protocol == "all") or
                        (."udp-options" == null) or
                        ((."udp-options"."destination-port-range".min // 0 | tonumber) <= ($dpmin | tonumber) and
                         (."udp-options"."destination-port-range".max // 0 | tonumber) >= ($dpmax | tonumber))
                    )
                else . end |
                "FOUND"
            ' <<< "$_rules_json" 2>/dev/null | head -n1)

            [[ "$_found" == "FOUND" ]]
        }

        #---------------------------------------------------------------
        # HELPER: Print NSG rule check row
        # Args: $1=description $2=direction $3=protocol_name $4=ports $5=found(0/1)
        #---------------------------------------------------------------
        _stv_print_rule_row() {
            local desc="$1" direction="$2" proto="$3" ports="$4" found="$5"
            local status_icon status_text
            if [[ "$found" -eq 1 ]]; then
                status_icon="${GREEN}✓${NC}"
                status_text="${GREEN}✓${NC}"
            else
                status_icon="${RED}✗${NC}"
                status_text="${RED}✗ MISSING${NC}"
            fi
            printf "  %-52b %-10s %-10s %-18s %b\n" "$desc" "$direction" "$proto" "$ports" "$status_text"
        }

        #---------------------------------------------------------------
        # HELPER: Print lines with truncation (header + max 5 data rows)
        # Args: $1=lines_content $2=item_count $3=max_show $4=show_all_flag
        #---------------------------------------------------------------
        _stv_print_lines() {
            local _lines="$1" _ct=$2 _max=$3 _show=$4
            local _ln=0 _dn=0
            while IFS= read -r _line; do
                [[ -z "$_line" ]] && continue
                ((_ln++))
                if [[ $_ln -eq 1 ]]; then
                    echo "$_line"
                    continue
                fi
                ((_dn++))
                if [[ $_show -eq 1 ]] || [[ $_dn -le $_max ]]; then
                    echo "$_line"
                fi
            done <<< "$_lines"
            if [[ $_show -eq 0 && $_ct -gt $_max ]]; then
                local _rem=$((_ct - _max))
                echo -e "    ${GRAY}... and ${_rem} more (press ${CYAN}a${GRAY} to show all)${NC}"
            fi
        }

        #===============================================================
        # PHASE 2: COMPUTE ALL RESULTS (no printing)
        #===============================================================

        # --- BV: Policy checks ---
        local _bv_pol_ok=0 _bv_pol_total=2
        _stv_check_policy "manage volumes" "request.principal.type = 'cluster'"
        local _bv_p1_found=$_pol_found _bv_p1_comp="$_pol_comp" _bv_p1_principal="$_pol_principal" _bv_p1_match="$_pol_match_type"
        [[ $_pol_found -eq 1 ]] && ((_bv_pol_ok++))

        _stv_check_policy "manage volume-attachments" "request.principal.type = 'cluster'"
        local _bv_p2_found=$_pol_found _bv_p2_comp="$_pol_comp" _bv_p2_principal="$_pol_principal" _bv_p2_match="$_pol_match_type"
        [[ $_pol_found -eq 1 ]] && ((_bv_pol_ok++))

        # --- BV: Storage classes ---
        local _bv_sc_ok=0 _bv_sc_name="" _bv_sc_reclaim="" _bv_sc_bind="" _bv_sc_expand="" _bv_sc_default=""
        if [[ -s "$_stv_ptmp/sc.json" ]]; then
            while IFS='|' read -r sc_name sc_prov sc_reclaim sc_bind sc_expand sc_default; do
                [[ -z "$sc_name" || "$sc_prov" != "blockvolume.csi.oraclecloud.com" ]] && continue
                _bv_sc_ok=1; _bv_sc_name="$sc_name"; _bv_sc_reclaim="$sc_reclaim"
                _bv_sc_bind="$sc_bind"; _bv_sc_expand="$sc_expand"; _bv_sc_default="$sc_default"
                break
            done < <(jq -r '.items[] | "\(.metadata.name)|\(.provisioner)|\(.reclaimPolicy // "N/A")|\(.volumeBindingMode // "N/A")|\(.allowVolumeExpansion // false)|\(.metadata.annotations["storageclass.kubernetes.io/is-default-class"] // "false")"' "$_stv_ptmp/sc.json" 2>/dev/null)
        fi

        # --- BV: PVCs ---
        local _bv_pvc_ct=0 _bv_pvc_lines=""
        if [[ -s "$_stv_ptmp/pvc.json" ]]; then
            while IFS='|' read -r pvc_name pvc_ns pvc_status pvc_vol pvc_sc pvc_cap; do
                [[ -z "$pvc_name" ]] && continue
                if [[ $_bv_pvc_ct -eq 0 ]]; then
                    _bv_pvc_lines+="$(printf "    ${GRAY}%-30s %-14s %-9s %-14s %s${NC}" "Name" "Namespace" "Status" "StorageClass" "Size")"$'\n'
                fi
                _bv_pvc_lines+="$(printf "    %-30s %-14s %-9s %-14s %s" "${pvc_name:0:28}" "${pvc_ns:0:12}" "$pvc_status" "${pvc_sc:0:12}" "$pvc_cap")"$'\n'
                ((_bv_pvc_ct++))
            done < <(jq -r '.items[] | select(.spec.storageClassName != null) |
                select(.spec.storageClassName | test("bv|block"; "i")) |
                "\(.metadata.name)|\(.metadata.namespace)|\(.status.phase)|\(.spec.volumeName // "N/A")|\(.spec.storageClassName)|\(.status.capacity.storage // .spec.resources.requests.storage // "N/A")"' "$_stv_ptmp/pvc.json" 2>/dev/null)
        fi

        # --- BV: Compartment / VCN alignment ---
        local _bv_w_sub_comp="" _bv_comp_ok=-1
        if [[ -f "$NETWORK_RESOURCES_CACHE" && -n "$_w_sub_ocid" && "$_w_sub_ocid" != "N/A" ]]; then
            _bv_w_sub_comp=$(awk -F'|' -v ocid="$_w_sub_ocid" '$1=="SUBNET" && $6==ocid {print $10; exit}' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
        fi
        if [[ -n "$_oke_cluster_comp" && "$_oke_cluster_comp" != "N/A" && -n "$_bv_w_sub_comp" ]]; then
            [[ "$_oke_cluster_comp" == "$_bv_w_sub_comp" ]] && _bv_comp_ok=1 || _bv_comp_ok=0
        fi

        # --- FSS: Policy checks ---
        local _fss_pol_ok=0 _fss_pol_total=2
        _stv_check_policy "manage file-family" "request.principal.type = 'cluster'"
        local _fss_p1_found=$_pol_found _fss_p1_comp="$_pol_comp" _fss_p1_principal="$_pol_principal" _fss_p1_match="$_pol_match_type"
        [[ $_pol_found -eq 1 ]] && ((_fss_pol_ok++))

        _stv_check_policy "use virtual-network-family" "request.principal.type = 'cluster'"
        local _fss_p2_found=$_pol_found _fss_p2_comp="$_pol_comp" _fss_p2_principal="$_pol_principal" _fss_p2_match="$_pol_match_type"
        [[ $_pol_found -eq 1 ]] && ((_fss_pol_ok++))

        # --- FSS: CSI driver ---
        local _fss_csi_ok=0
        if [[ -s "$_stv_ptmp/csi.json" ]]; then
            local _fss_csi_found
            _fss_csi_found=$(jq -r '.items[] | select(.metadata.name == "fss.csi.oraclecloud.com") | .metadata.name' "$_stv_ptmp/csi.json" 2>/dev/null)
            [[ -n "$_fss_csi_found" ]] && _fss_csi_ok=1
        fi

        # --- FSS: Storage classes ---
        local _fss_sc_ok=0 _fss_sc_name="" _fss_sc_reclaim="" _fss_sc_bind=""
        if [[ -s "$_stv_ptmp/sc.json" ]]; then
            while IFS='|' read -r sc_name sc_prov sc_reclaim sc_bind sc_mt; do
                [[ -z "$sc_name" || "$sc_prov" != "fss.csi.oraclecloud.com" ]] && continue
                _fss_sc_ok=1; _fss_sc_name="$sc_name"; _fss_sc_reclaim="$sc_reclaim"; _fss_sc_bind="$sc_bind"
                break
            done < <(jq -r '.items[] | "\(.metadata.name)|\(.provisioner)|\(.reclaimPolicy // "N/A")|\(.volumeBindingMode // "N/A")|\(.parameters.mountTargetOcid // .parameters.mountTargetId // "")"' "$_stv_ptmp/sc.json" 2>/dev/null)
        fi

        # --- FSS: Mount targets ---
        local _mt_display_ct=0 _mt_lines=""
        if [[ -n "$_mt_json" && "$_mt_ct" -gt 0 ]]; then
            _mt_lines+="$(printf "    ${GRAY}%-30s %-20s %-16s %-10s %s${NC}" "Name" "AD" "IP" "State" "Exports")"$'\n'
            while IFS='|' read -r mt_name mt_ad mt_state mt_id mt_subnet_id mt_export_set_id; do
                [[ -z "$mt_name" ]] && continue
                ((_mt_display_ct++))
                local _ad_short="${mt_ad##*:}"; _ad_short="${_ad_short:-$mt_ad}"
                local _mt_ip="N/A"
                [[ -f "$FSS_MT_IP_CACHE" ]] && _mt_ip=$(grep "^${mt_id}|" "$FSS_MT_IP_CACHE" 2>/dev/null | cut -d'|' -f2 | head -n1)
                [[ -z "$_mt_ip" ]] && _mt_ip="N/A"
                local _exp_ct=0
                [[ -f "$FSS_EXPORT_CACHE" ]] && _exp_ct=$(jq --arg esid "$mt_export_set_id" '[.data[] | select(.["export-set-id"] == $esid)] | length' "$FSS_EXPORT_CACHE" 2>/dev/null || echo 0)
                _mt_lines+="$(printf "    %-30s %-20s %-16s %-10s %s" "${mt_name:0:28}" "${_ad_short:0:18}" "$_mt_ip" "$mt_state" "${_exp_ct} exports")"$'\n'
            done < <(jq -r '.data[] | "\(."display-name")|\(."availability-domain")|\(."lifecycle-state")|\(.id)|\(."subnet-id")|\(."export-set-id" // "")"' <<< "$_mt_json" 2>/dev/null)
        fi

        # --- FSS: Network checks ---
        local _fss_net_ok=0 _fss_net_total=0 _fss_net_skip=0 _fss_rule_lines=""
        if [[ -z "$_fss_sub_cidr" || -z "$_fss_nsg_ocid" ]]; then
            _fss_net_skip=1
        else
            if [[ -n "$_w_nsg_ocid" && "$_w_nsg_ocid" != "N/A" && -n "$_fss_sub_cidr" ]]; then
                local _r1=0; _stv_check_nsg_rule "$_w_nsg_ocid" "EGRESS" "6" "111" "111" "$_fss_sub_cidr" && _r1=1
                local _r1b=0; _stv_check_nsg_rule "$_w_nsg_ocid" "EGRESS" "6" "2048" "2050" "$_fss_sub_cidr" && _r1b=1
                local _r1_ok=0; [[ $_r1 -eq 1 && $_r1b -eq 1 ]] && _r1_ok=1
                ((_fss_net_total++)); [[ $_r1_ok -eq 1 ]] && ((_fss_net_ok++))
                local _r2=0; _stv_check_nsg_rule "$_w_nsg_ocid" "EGRESS" "17" "111" "111" "$_fss_sub_cidr" && _r2=1
                local _r2b=0; _stv_check_nsg_rule "$_w_nsg_ocid" "EGRESS" "17" "2048" "2048" "$_fss_sub_cidr" && _r2b=1
                local _r2_ok=0; [[ $_r2 -eq 1 && $_r2b -eq 1 ]] && _r2_ok=1
                ((_fss_net_total++)); [[ $_r2_ok -eq 1 ]] && ((_fss_net_ok++))
            fi
            if [[ -n "$_fss_nsg_ocid" && -n "$_w_sub_cidr" ]]; then
                local _r3=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "6" "111" "111" "$_w_sub_cidr" && _r3=1
                local _r3b=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "6" "2048" "2050" "$_w_sub_cidr" && _r3b=1
                local _r3_ok=0; [[ $_r3 -eq 1 && $_r3b -eq 1 ]] && _r3_ok=1
                ((_fss_net_total++)); [[ $_r3_ok -eq 1 ]] && ((_fss_net_ok++))
                local _r4=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "17" "111" "111" "$_w_sub_cidr" && _r4=1
                local _r4b=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "17" "2048" "2048" "$_w_sub_cidr" && _r4b=1
                local _r4_ok=0; [[ $_r4 -eq 1 && $_r4b -eq 1 ]] && _r4_ok=1
                ((_fss_net_total++)); [[ $_r4_ok -eq 1 ]] && ((_fss_net_ok++))
            fi
            if [[ -n "$_p_nsg_ocid" && "$_p_nsg_ocid" != "N/A" && -n "$_p_sub_cidr" ]]; then
                local _r5=0; _stv_check_nsg_rule "$_p_nsg_ocid" "EGRESS" "6" "111" "111" "$_fss_sub_cidr" && _r5=1
                local _r5b=0; _stv_check_nsg_rule "$_p_nsg_ocid" "EGRESS" "6" "2048" "2050" "$_fss_sub_cidr" && _r5b=1
                local _r5_ok=0; [[ $_r5 -eq 1 && $_r5b -eq 1 ]] && _r5_ok=1
                ((_fss_net_total++)); [[ $_r5_ok -eq 1 ]] && ((_fss_net_ok++))
                local _r6=0; _stv_check_nsg_rule "$_p_nsg_ocid" "EGRESS" "17" "111" "111" "$_fss_sub_cidr" && _r6=1
                local _r6b=0; _stv_check_nsg_rule "$_p_nsg_ocid" "EGRESS" "17" "2048" "2048" "$_fss_sub_cidr" && _r6b=1
                local _r6_ok=0; [[ $_r6 -eq 1 && $_r6b -eq 1 ]] && _r6_ok=1
                ((_fss_net_total++)); [[ $_r6_ok -eq 1 ]] && ((_fss_net_ok++))
                if [[ -n "$_fss_nsg_ocid" ]]; then
                    local _r7=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "6" "111" "111" "$_p_sub_cidr" && _r7=1
                    local _r7b=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "6" "2048" "2050" "$_p_sub_cidr" && _r7b=1
                    local _r7_ok=0; [[ $_r7 -eq 1 && $_r7b -eq 1 ]] && _r7_ok=1
                    ((_fss_net_total++)); [[ $_r7_ok -eq 1 ]] && ((_fss_net_ok++))
                    local _r8=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "17" "111" "111" "$_p_sub_cidr" && _r8=1
                    local _r8b=0; _stv_check_nsg_rule "$_fss_nsg_ocid" "INGRESS" "17" "2048" "2048" "$_p_sub_cidr" && _r8b=1
                    local _r8_ok=0; [[ $_r8 -eq 1 && $_r8b -eq 1 ]] && _r8_ok=1
                    ((_fss_net_total++)); [[ $_r8_ok -eq 1 ]] && ((_fss_net_ok++))
                fi
            fi
        fi

        # --- FSS: Build network detail lines for display ---
        local _fss_net_lines=""
        if [[ $_fss_net_skip -eq 0 ]]; then
            _fss_net_lines+="$(printf "    Subnet: ${GREEN}✓${NC} %s (%s)" "${_fss_sub_name}" "${_fss_sub_cidr}")"$'\n'
            _fss_net_lines+="$(printf "    NSG:    ${GREEN}✓${NC} %s" "${_fss_nsg_name}")"$'\n'
            if [[ -n "$_w_nsg_ocid" && "$_w_nsg_ocid" != "N/A" && -n "$_fss_sub_cidr" ]]; then
                local _t1="${GREEN}✓${NC}" _t1b="${GREEN}✓${NC}" _t2="${GREEN}✓${NC}" _t2b="${GREEN}✓${NC}"
                [[ ${_r1:-0} -eq 0 ]] && _t1="${RED}✗${NC}"; [[ ${_r1b:-0} -eq 0 ]] && _t1b="${RED}✗${NC}"
                [[ ${_r2:-0} -eq 0 ]] && _t2="${RED}✗${NC}"; [[ ${_r2b:-0} -eq 0 ]] && _t2b="${RED}✗${NC}"
                _fss_net_lines+="$(printf "    Worker → FSS:  %b TCP 111  %b TCP 2048-2050  %b UDP 111  %b UDP 2048" "$_t1" "$_t1b" "$_t2" "$_t2b")"$'\n'
            fi
            if [[ -n "$_fss_nsg_ocid" && -n "$_w_sub_cidr" ]]; then
                local _t3="${GREEN}✓${NC}" _t3b="${GREEN}✓${NC}" _t4="${GREEN}✓${NC}" _t4b="${GREEN}✓${NC}"
                [[ ${_r3:-0} -eq 0 ]] && _t3="${RED}✗${NC}"; [[ ${_r3b:-0} -eq 0 ]] && _t3b="${RED}✗${NC}"
                [[ ${_r4:-0} -eq 0 ]] && _t4="${RED}✗${NC}"; [[ ${_r4b:-0} -eq 0 ]] && _t4b="${RED}✗${NC}"
                _fss_net_lines+="$(printf "    FSS → Worker:  %b TCP 111  %b TCP 2048-2050  %b UDP 111  %b UDP 2048" "$_t3" "$_t3b" "$_t4" "$_t4b")"$'\n'
            fi
            if [[ -n "$_p_nsg_ocid" && "$_p_nsg_ocid" != "N/A" && -n "$_p_sub_cidr" ]]; then
                local _t5="${GREEN}✓${NC}" _t5b="${GREEN}✓${NC}" _t6="${GREEN}✓${NC}" _t6b="${GREEN}✓${NC}"
                [[ ${_r5:-0} -eq 0 ]] && _t5="${RED}✗${NC}"; [[ ${_r5b:-0} -eq 0 ]] && _t5b="${RED}✗${NC}"
                [[ ${_r6:-0} -eq 0 ]] && _t6="${RED}✗${NC}"; [[ ${_r6b:-0} -eq 0 ]] && _t6b="${RED}✗${NC}"
                _fss_net_lines+="$(printf "    Pod → FSS:     %b TCP 111  %b TCP 2048-2050  %b UDP 111  %b UDP 2048" "$_t5" "$_t5b" "$_t6" "$_t6b")"$'\n'
                if [[ -n "$_fss_nsg_ocid" ]]; then
                    local _t7="${GREEN}✓${NC}" _t7b="${GREEN}✓${NC}" _t8="${GREEN}✓${NC}" _t8b="${GREEN}✓${NC}"
                    [[ ${_r7:-0} -eq 0 ]] && _t7="${RED}✗${NC}"; [[ ${_r7b:-0} -eq 0 ]] && _t7b="${RED}✗${NC}"
                    [[ ${_r8:-0} -eq 0 ]] && _t8="${RED}✗${NC}"; [[ ${_r8b:-0} -eq 0 ]] && _t8b="${RED}✗${NC}"
                    _fss_net_lines+="$(printf "    FSS → Pod:     %b TCP 111  %b TCP 2048-2050  %b UDP 111  %b UDP 2048" "$_t7" "$_t7b" "$_t8" "$_t8b")"$'\n'
                fi
            fi
        fi

        # --- FSS: PVCs ---
        local _fss_pvc_ct=0 _fss_pvc_lines=""
        if [[ -s "$_stv_ptmp/pvc.json" ]]; then
            while IFS='|' read -r pvc_name pvc_ns pvc_status pvc_vol pvc_sc pvc_cap; do
                [[ -z "$pvc_name" ]] && continue
                if [[ $_fss_pvc_ct -eq 0 ]]; then
                    _fss_pvc_lines+="$(printf "    ${GRAY}%-30s %-14s %-9s %-14s %s${NC}" "Name" "Namespace" "Status" "StorageClass" "Size")"$'\n'
                fi
                _fss_pvc_lines+="$(printf "    %-30s %-14s %-9s %-14s %s" "${pvc_name:0:28}" "${pvc_ns:0:12}" "$pvc_status" "${pvc_sc:0:12}" "$pvc_cap")"$'\n'
                ((_fss_pvc_ct++))
            done < <(jq -r '.items[] | select(.spec.storageClassName != null) |
                select(.spec.storageClassName | test("fss"; "i")) |
                "\(.metadata.name)|\(.metadata.namespace)|\(.status.phase)|\(.spec.volumeName // "N/A")|\(.spec.storageClassName)|\(.status.capacity.storage // .spec.resources.requests.storage // "N/A")"' "$_stv_ptmp/pvc.json" 2>/dev/null)
        fi

        # --- Lustre: K8s version ---
        local _lus_k8s_ok=0 _k8s_ver="N/A"
        if [[ -s "$_stv_ptmp/ver.json" ]]; then
            _k8s_ver=$(jq -r '.serverVersion.gitVersion // "N/A"' "$_stv_ptmp/ver.json" 2>/dev/null)
            local _k8s_minor
            _k8s_minor=$(jq -r '.serverVersion.minor // "0"' "$_stv_ptmp/ver.json" 2>/dev/null)
            _k8s_minor="${_k8s_minor//[^0-9]/}"
            [[ -n "$_k8s_minor" && "$_k8s_minor" -ge 29 ]] && _lus_k8s_ok=1
        fi

        # --- Lustre: CSI driver ---
        local _lus_csi_ok=0
        if [[ -s "$_stv_ptmp/csi.json" ]]; then
            local _lus_csi_found
            _lus_csi_found=$(jq -r '.items[] | select(.metadata.name == "lustre.csi.oraclecloud.com") | .metadata.name' "$_stv_ptmp/csi.json" 2>/dev/null)
            [[ -n "$_lus_csi_found" ]] && _lus_csi_ok=1
        fi

        # --- Lustre: File systems (lines stored for display) ---
        local _lfs_lines=""
        if [[ "$_lfs_ct" -gt 0 ]]; then
            _lfs_lines+="$(printf "    ${GRAY}%-30s %-20s %-10s %-16s %s${NC}" "Name" "AD" "Capacity" "MGS Address" "State")"$'\n'
            while IFS='|' read -r lfs_name lfs_ad lfs_cap lfs_mgs lfs_state lfs_fsname; do
                [[ -z "$lfs_name" ]] && continue
                local _ad_short="${lfs_ad##*:}"
                local _cap_display="N/A"
                if [[ "$lfs_cap" =~ ^[0-9]+$ && "$lfs_cap" -gt 0 ]]; then
                    _cap_display=$(echo "scale=0; $lfs_cap / 1000" | bc 2>/dev/null)
                    _cap_display="${_cap_display} TiB"
                fi
                local _mgs_display="${lfs_mgs}"
                [[ "$lfs_mgs" == "null" || -z "$lfs_mgs" ]] && _mgs_display="N/A"
                _lfs_lines+="$(printf "    %-30s %-20s %-10s %-16s %s" "${lfs_name:0:28}" "${_ad_short:0:18}" "$_cap_display" "$_mgs_display" "$lfs_state")"
                [[ "$_mgs_display" != "N/A" && "$lfs_fsname" != "null" && -n "$lfs_fsname" ]] && \
                    _lfs_lines+="  (${_mgs_display}@tcp:/${lfs_fsname})"
                _lfs_lines+=$'\n'
            done < <(jq -r '.data.items[] | "\(."display-name")|\(."availability-domain")|\(."capacity-in-gbs" // 0)|\(."mgs-address" // "N/A")|\(."lifecycle-state")|\(."file-system-name" // "")"' <<< "$_lfs_json" 2>/dev/null)
        fi

        # --- Lustre: Network checks ---
        local _lus_net_ok=0 _lus_net_total=0 _lus_net_skip=0
        if [[ -z "$_lus_sub_cidr" || -z "$_lus_nsg_ocid" ]]; then
            _lus_net_skip=1
        else
            if [[ -n "$_w_nsg_ocid" && "$_w_nsg_ocid" != "N/A" && -n "$_lus_sub_cidr" ]]; then
                local _lr1=0; _stv_check_nsg_rule "$_w_nsg_ocid" "EGRESS" "6" "988" "988" "$_lus_sub_cidr" "512" "1023" && _lr1=1
                ((_lus_net_total++)); [[ $_lr1 -eq 1 ]] && ((_lus_net_ok++))
            fi
            if [[ -n "$_lus_nsg_ocid" && -n "$_w_sub_cidr" ]]; then
                local _lr2=0; _stv_check_nsg_rule "$_lus_nsg_ocid" "INGRESS" "6" "988" "988" "$_w_sub_cidr" "512" "1023" && _lr2=1
                ((_lus_net_total++)); [[ $_lr2 -eq 1 ]] && ((_lus_net_ok++))
            fi
            if [[ -n "$_p_nsg_ocid" && "$_p_nsg_ocid" != "N/A" && -n "$_p_sub_cidr" ]]; then
                local _lr3=0; _stv_check_nsg_rule "$_p_nsg_ocid" "EGRESS" "6" "988" "988" "$_lus_sub_cidr" "512" "1023" && _lr3=1
                ((_lus_net_total++)); [[ $_lr3 -eq 1 ]] && ((_lus_net_ok++))
                if [[ -n "$_lus_nsg_ocid" ]]; then
                    local _lr4=0; _stv_check_nsg_rule "$_lus_nsg_ocid" "INGRESS" "6" "988" "988" "$_p_sub_cidr" "512" "1023" && _lr4=1
                    ((_lus_net_total++)); [[ $_lr4 -eq 1 ]] && ((_lus_net_ok++))
                fi
            fi
        fi

        # --- Lustre: PVCs ---
        local _lus_pvc_ct=0 _lus_pvc_lines=""
        if [[ -s "$_stv_ptmp/pvc.json" ]]; then
            while IFS='|' read -r pvc_name pvc_ns pvc_status pvc_vol pvc_sc pvc_cap; do
                [[ -z "$pvc_name" ]] && continue
                if [[ $_lus_pvc_ct -eq 0 ]]; then
                    _lus_pvc_lines+="$(printf "    ${GRAY}%-30s %-14s %-9s %-14s %s${NC}" "Name" "Namespace" "Status" "StorageClass" "Size")"$'\n'
                fi
                _lus_pvc_lines+="$(printf "    %-30s %-14s %-9s %-14s %s" "${pvc_name:0:28}" "${pvc_ns:0:12}" "$pvc_status" "${pvc_sc:0:12}" "$pvc_cap")"$'\n'
                ((_lus_pvc_ct++))
            done < <(jq -r '.items[] | select(.spec.storageClassName != null) |
                select(.spec.storageClassName | test("lustre"; "i")) |
                "\(.metadata.name)|\(.metadata.namespace)|\(.status.phase)|\(.spec.volumeName // "N/A")|\(.spec.storageClassName)|\(.status.capacity.storage // .spec.resources.requests.storage // "N/A")"' "$_stv_ptmp/pvc.json" 2>/dev/null)
        fi

        # --- Determine per-service status ---
        local _bv_status="READY"
        [[ $_bv_pol_ok -lt $_bv_pol_total || $_bv_sc_ok -eq 0 ]] && _bv_status="NOT READY"

        local _fss_status="READY" _fss_issues=0
        [[ $_fss_pol_ok -lt $_fss_pol_total ]] && _fss_issues=1
        [[ $_fss_csi_ok -eq 0 ]] && _fss_issues=1
        [[ $_mt_display_ct -eq 0 ]] && _fss_issues=1
        [[ $_fss_same_vcn -eq 0 ]] && _fss_issues=1
        [[ $_fss_net_total -gt 0 && $_fss_net_ok -lt $_fss_net_total ]] && _fss_issues=1
        if [[ $_fss_issues -eq 1 ]]; then
            if [[ $_fss_pol_ok -eq 0 && $_fss_csi_ok -eq 0 ]]; then _fss_status="NOT READY"
            elif [[ $_fss_same_vcn -eq 0 ]]; then _fss_status="NOT READY"
            else _fss_status="PARTIAL"; fi
        fi

        local _lus_status="READY" _lus_issues=0
        [[ $_lus_k8s_ok -eq 0 ]] && _lus_issues=1
        [[ $_lus_csi_ok -eq 0 ]] && _lus_issues=1
        [[ $_lus_net_total -gt 0 && $_lus_net_ok -lt $_lus_net_total ]] && _lus_issues=1
        if [[ $_lus_issues -eq 1 ]]; then
            if [[ $_lus_csi_ok -eq 0 && $_lus_k8s_ok -eq 0 ]]; then _lus_status="NOT READY"
            else _lus_status="PARTIAL"; fi
        fi

        #===============================================================
        # PHASE 3: SUMMARY TABLE (at top)
        #===============================================================
        local _total_pvcs=$((_bv_pvc_ct + _fss_pvc_ct + _lus_pvc_ct))

        # Status icons for table
        local _bv_oi="${GREEN}✓ READY${NC}"; [[ "$_bv_status" == "NOT READY" ]] && _bv_oi="${RED}✗ NOT READY${NC}"
        local _fss_oi="${GREEN}✓ READY${NC}"
        [[ "$_fss_status" == "PARTIAL" ]] && _fss_oi="${YELLOW}⚠ PARTIAL${NC}"
        [[ "$_fss_status" == "NOT READY" ]] && _fss_oi="${RED}✗ NOT READY${NC}"
        local _lus_oi="${GREEN}✓ READY${NC}"
        [[ "$_lus_status" == "PARTIAL" ]] && _lus_oi="${YELLOW}⚠ PARTIAL${NC}"
        [[ "$_lus_status" == "NOT READY" ]] && _lus_oi="${RED}✗ NOT READY${NC}"

        # Policy icons
        local _bv_pi="${GREEN}✓${NC}"; [[ $_bv_pol_ok -lt $_bv_pol_total ]] && _bv_pi="${RED}✗${NC}"
        local _fss_pi="${GREEN}✓${NC}"; [[ $_fss_pol_ok -lt $_fss_pol_total ]] && _fss_pi="${RED}✗${NC}"

        # CSI/Storage display
        local _bv_ci="${GREEN}✓${NC} oci-bv"; [[ $_bv_sc_ok -eq 0 ]] && _bv_ci="${RED}✗${NC} oci-bv"
        local _fss_ci="${GREEN}✓${NC} fss.csi"; [[ $_fss_csi_ok -eq 0 ]] && _fss_ci="${RED}✗${NC} fss.csi"
        local _lus_ci="${GREEN}✓${NC} lustre.csi"; [[ $_lus_csi_ok -eq 0 ]] && _lus_ci="${RED}✗${NC} lustre.csi"

        # Network display
        local _bv_ni="N/A"
        [[ $_bv_comp_ok -eq 1 ]] && _bv_ni="${GREEN}✓${NC} same comp"
        [[ $_bv_comp_ok -eq 0 ]] && _bv_ni="${YELLOW}⚠${NC} diff comp"
        local _fss_ni="N/A"
        if [[ $_fss_same_vcn -eq 0 ]]; then
            _fss_ni="${RED}✗${NC} diff VCN"
        elif [[ $_fss_net_total -gt 0 && $_fss_net_ok -lt $_fss_net_total ]]; then
            _fss_ni="${YELLOW}⚠${NC} ${_fss_net_ok}/${_fss_net_total}"
        elif [[ $_fss_net_total -gt 0 && $_fss_net_ok -eq $_fss_net_total ]]; then
            _fss_ni="${GREEN}✓${NC} ${_fss_net_ok}/${_fss_net_total}"
        elif [[ $_fss_same_vcn -eq 1 ]]; then
            _fss_ni="${GREEN}✓${NC} same VCN"
        fi
        local _lus_ni="N/A"
        [[ $_lus_net_total -gt 0 && $_lus_net_ok -lt $_lus_net_total ]] && _lus_ni="${YELLOW}⚠${NC} ${_lus_net_ok}/${_lus_net_total}"
        [[ $_lus_net_total -gt 0 && $_lus_net_ok -eq $_lus_net_total ]] && _lus_ni="${GREEN}✓${NC} ${_lus_net_ok}/${_lus_net_total}"

        printf "  ${BOLD}┌──────────────────┬──────────┬───────────────┬──────────────┬──────┬─────────────┐${NC}\n"
        printf "  ${BOLD}│ %-16s │ %-8s │ %-13s │ %-12s │ %-4s │ %-11s │${NC}\n" "Service" "Policies" "CSI / Storage" "Network" "PVCs" "Status"
        printf "  ${BOLD}├──────────────────┼──────────┼───────────────┼──────────────┼──────┼─────────────┤${NC}\n"
        printf "  │ %s │ %s │ %s │ %s │ %s │ %s │\n" \
            "$(_tpad 16 "Block Volume")" "$(_tpad 8 "${_bv_pi} ${_bv_pol_ok}/${_bv_pol_total}")" "$(_tpad 13 "$_bv_ci")" "$(_tpad 12 "$_bv_ni")" "$(_tpad 4 "$_bv_pvc_ct")" "$(_tpad 11 "$_bv_oi")"
        printf "  │ %s │ %s │ %s │ %s │ %s │ %s │\n" \
            "$(_tpad 16 "File Storage")" "$(_tpad 8 "${_fss_pi} ${_fss_pol_ok}/${_fss_pol_total}")" "$(_tpad 13 "$_fss_ci")" "$(_tpad 12 "$_fss_ni")" "$(_tpad 4 "$_fss_pvc_ct")" "$(_tpad 11 "$_fss_oi")"
        printf "  │ %s │ %s │ %s │ %s │ %s │ %s │\n" \
            "$(_tpad 16 "Lustre")" "$(_tpad 8 "N/A")" "$(_tpad 13 "$_lus_ci")" "$(_tpad 12 "$_lus_ni")" "$(_tpad 4 "$_lus_pvc_ct")" "$(_tpad 11 "$_lus_oi")"
        printf "  ${BOLD}└──────────────────┴──────────┴───────────────┴──────────────┴──────┴─────────────┘${NC}\n"
        echo -e "  ${GRAY}PVCs: ${_total_pvcs} total (${_bv_pvc_ct} BV, ${_fss_pvc_ct} FSS, ${_lus_pvc_ct} Lustre)${NC}"
        echo ""

        # --- Policy search criteria ---
        echo -e "  ${BOLD}Policy Search${NC} ${GRAY}(${_pol_count} policies across all compartments)${NC}"
        echo ""
        echo -e "    ${GRAY}Principals${NC}   any-user  ${GRAY}│${NC}  any-group  ${GRAY}│${NC}  group ${GRAY}<name>${NC}  ${GRAY}│${NC}  dynamic-group ${GRAY}<name>${NC}"
        echo -e "    ${GRAY}Scopes${NC}       in tenancy  ${GRAY}│${NC}  in compartment ${GRAY}<name|id>${NC}"
        echo -e "    ${GRAY}Where${NC}        ${GREEN}1st${NC} specific ${GRAY}(where request.principal.type = 'cluster')${NC}  ${GRAY}→${NC}  ${CYAN}2nd${NC} broad ${GRAY}(no where clause)${NC}"
        echo ""

        #===============================================================
        # PHASE 4: COMPACT PER-SERVICE DETAILS
        #===============================================================

        # ◆ BLOCK VOLUME (BV) ─────────────────────────────────────────
        echo -e "  ${BOLD}◆ BLOCK VOLUME (BV)${NC}"
        echo ""

        # Policies
        echo -e "  Policies (${_bv_pol_ok}/${_bv_pol_total}):"
        _pol_found=$_bv_p1_found; _pol_comp="$_bv_p1_comp"; _pol_principal="$_bv_p1_principal"; _pol_match_type="$_bv_p1_match"
        _stv_print_policy "manage volumes"
        _pol_found=$_bv_p2_found; _pol_comp="$_bv_p2_comp"; _pol_principal="$_bv_p2_principal"; _pol_match_type="$_bv_p2_match"
        _stv_print_policy "manage volume-attachments"

        # Storage
        if [[ $_bv_sc_ok -eq 1 ]]; then
            local _def_tag=""; [[ "$_bv_sc_default" == "true" ]] && _def_tag="default, "
            echo -e "  Storage: ${GREEN}✓${NC} ${_bv_sc_name} (${_def_tag}Reclaim: ${_bv_sc_reclaim}, Bind: ${_bv_sc_bind}, Expand: ${_bv_sc_expand})"
        else
            echo -e "  Storage: ${RED}✗${NC} No BV storage class (blockvolume.csi.oraclecloud.com)"
        fi

        # Network / OKE subnet topology
        local _comp_ic="${GREEN}✓${NC}"; [[ $_bv_comp_ok -eq 0 ]] && _comp_ic="${YELLOW}⚠${NC}"
        if [[ -n "$_oke_cluster_comp" && "$_oke_cluster_comp" != "N/A" ]]; then
            if [[ $_bv_comp_ok -eq 1 ]]; then
                echo -e "  Network: ${GREEN}✓${NC} OKE & subnets in same compartment ${GRAY}(source: ${_np_source})${NC}"
            elif [[ $_bv_comp_ok -eq 0 ]]; then
                echo -e "  Network: ${YELLOW}⚠${NC} OKE cluster & worker subnet in different compartments"
            else
                echo -e "  Network: ${GRAY}compartment check unavailable${NC}"
            fi
            echo -e "    ${GRAY}VCN: ${_oke_vcn_name:-N/A}${NC}"
            printf "    ${GRAY}%-12s${NC} %-28s ${GRAY}%s${NC}\n" "Worker:" "${_w_sub_name:-N/A} (${_w_sub_cidr:-N/A})" "${_w_nsg_name:+NSG: $_w_nsg_name}"
            [[ -n "$_p_sub_name" && "$_p_sub_name" != "N/A" ]] && \
                printf "    ${GRAY}%-12s${NC} %-28s ${GRAY}%s${NC}\n" "Pod:" "${_p_sub_name} (${_p_sub_cidr:-N/A})" "${_p_nsg_name:+NSG: $_p_nsg_name}"
            [[ -n "$_oke_ep_sub_name" ]] && \
                printf "    ${GRAY}%-12s${NC} %s\n" "Endpoint:" "${_oke_ep_sub_name} (${_oke_ep_sub_cidr:-N/A})"
            [[ -n "$_oke_lb_sub_name" ]] && \
                printf "    ${GRAY}%-12s${NC} %s\n" "SVC LB:" "${_oke_lb_sub_name} (${_oke_lb_sub_cidr:-N/A})"
        else
            echo -e "  Network: ${GRAY}N/A (OKE cluster not cached — run main menu first)${NC}"
        fi

        # PVCs
        if [[ $_bv_pvc_ct -gt 0 ]]; then
            echo -e "  PVCs (${_bv_pvc_ct}):"
            _stv_print_lines "$_bv_pvc_lines" "$_bv_pvc_ct" 5 "$_stv_show_all"
        else
            echo -e "  PVCs (0): ${GRAY}(none)${NC}"
        fi
        echo ""

        # ◆ FILE STORAGE SERVICE (FSS) ─────────────────────────────────
        echo -e "  ${BOLD}◆ FILE STORAGE SERVICE (FSS)${NC}"
        echo ""

        # Policies
        echo -e "  Policies (${_fss_pol_ok}/${_fss_pol_total}):"
        _pol_found=$_fss_p1_found; _pol_comp="$_fss_p1_comp"; _pol_principal="$_fss_p1_principal"; _pol_match_type="$_fss_p1_match"
        _stv_print_policy "manage file-family"
        _pol_found=$_fss_p2_found; _pol_comp="$_fss_p2_comp"; _pol_principal="$_fss_p2_principal"; _pol_match_type="$_fss_p2_match"
        _stv_print_policy "use virtual-network-family"

        # CSI
        if [[ $_fss_csi_ok -eq 1 ]]; then
            echo -e "  CSI: ${GREEN}✓${NC} fss.csi.oraclecloud.com"
        else
            echo -e "  CSI: ${RED}✗${NC} fss.csi.oraclecloud.com — NOT FOUND"
        fi

        # Storage
        if [[ $_fss_sc_ok -eq 1 ]]; then
            echo -e "  Storage: ${GREEN}✓${NC} ${_fss_sc_name} (Reclaim: ${_fss_sc_reclaim}, Bind: ${_fss_sc_bind})"
        else
            echo -e "  Storage: ${RED}✗${NC} No FSS storage class (fss.csi.oraclecloud.com)"
        fi

        # Mount Targets
        if [[ $_mt_display_ct -gt 0 ]]; then
            echo -e "  Mount Targets (${_mt_display_ct}):"
            _stv_print_lines "$_mt_lines" "$_mt_display_ct" 5 "$_stv_show_all"
        else
            echo -e "  Mount Targets: ${RED}✗${NC} None in compartment"
        fi

        # Network
        if [[ $_mt_display_ct -gt 0 && -n "$_fss_sub_name" ]]; then
            # Show mount target subnet topology
            local _vcn_ic="${GREEN}✓${NC}"; local _vcn_lbl="same VCN as OKE"
            [[ $_fss_same_vcn -eq 0 ]] && _vcn_ic="${RED}✗${NC}" && _vcn_lbl="DIFFERENT VCN — cross-VCN routing required"
            [[ $_fss_same_vcn -lt 0 ]] && _vcn_ic="${GRAY}?${NC}" && _vcn_lbl="VCN check unavailable"
            local _src_lbl="mount-target"; [[ -z "$_fss_mt_sub_ocid" ]] && _src_lbl="name-match"

            if [[ $_fss_net_skip -eq 1 ]]; then
                echo -e "  Network:"
            else
                local _fss_net_ic="${GREEN}✓${NC}"; [[ $_fss_net_ok -lt $_fss_net_total ]] && _fss_net_ic="${RED}✗${NC}"
                echo -e "  Network (${_fss_net_ic} ${_fss_net_ok}/${_fss_net_total}):"
            fi
            printf "    ${GRAY}%-12s${NC} %b %s\n" "VCN:" "$_vcn_ic" "$_vcn_lbl"
            printf "    ${GRAY}%-12s${NC} %-28s ${GRAY}(source: %s)${NC}\n" "FSS Subnet:" "${_fss_sub_name} (${_fss_sub_cidr})" "$_src_lbl"
            if [[ -n "$_fss_nsg_name" ]]; then
                printf "    ${GRAY}%-12s${NC} %s\n" "FSS NSG:" "${_fss_nsg_name}"
            else
                printf "    ${GRAY}%-12s${NC} ${YELLOW}⚠${NC} not found ${GRAY}(NSG name must contain 'fss')${NC}\n" "FSS NSG:"
            fi
            printf "    ${GRAY}%-12s${NC} %-28s ${GRAY}%s${NC}\n" "Worker:" "${_w_sub_name:-N/A} (${_w_sub_cidr:-N/A})" "${_w_nsg_name:+NSG: $_w_nsg_name}"
            # Port rules
            if [[ -n "$_fss_net_lines" ]]; then
                echo -n "$_fss_net_lines" | while IFS= read -r _rl; do
                    # Skip subnet/NSG lines from _fss_net_lines (we already show them above)
                    [[ "$_rl" == *"Subnet:"* || "$_rl" == *"NSG:"* ]] && continue
                    echo "$_rl"
                done
            elif [[ $_fss_net_skip -eq 1 && -z "$_fss_nsg_ocid" ]]; then
                echo -e "    ${YELLOW}⚠${NC} NSG rule check skipped — no FSS NSG detected"
            fi
        elif [[ $_mt_display_ct -eq 0 ]]; then
            echo -e "  Network: ${GRAY}N/A (no mount targets — cannot determine FSS subnet)${NC}"
        else
            echo -e "  Network: ${YELLOW}⚠${NC} Mount target subnet could not be resolved"
        fi

        # PVCs
        if [[ $_fss_pvc_ct -gt 0 ]]; then
            echo -e "  PVCs (${_fss_pvc_ct}):"
            _stv_print_lines "$_fss_pvc_lines" "$_fss_pvc_ct" 5 "$_stv_show_all"
        else
            echo -e "  PVCs (0): ${GRAY}(none)${NC}"
        fi
        echo ""

        # ◆ LUSTRE ─────────────────────────────────────────────────────
        echo -e "  ${BOLD}◆ LUSTRE${NC}"
        echo ""

        # K8s + CSI on one line
        local _k8s_ic="${GREEN}✓${NC}"; [[ $_lus_k8s_ok -eq 0 ]] && _k8s_ic="${RED}✗${NC}"
        local _lcsi_ic="${GREEN}✓${NC}"; [[ $_lus_csi_ok -eq 0 ]] && _lcsi_ic="${RED}✗${NC}"
        echo -e "  K8s: ${_k8s_ic} ${_k8s_ver} (>= 1.29)    CSI: ${_lcsi_ic} lustre.csi.oraclecloud.com"

        # File Systems
        if [[ "$_lfs_ct" -gt 0 ]]; then
            echo -e "  File Systems (${_lfs_ct}):"
            _stv_print_lines "$_lfs_lines" "$_lfs_ct" 5 "$_stv_show_all"
        else
            echo -e "  File Systems: ${GRAY}(none)${NC}"
        fi

        # Network
        if [[ $_lus_net_skip -eq 1 ]]; then
            echo -e "  Network (Worker → Lustre): ${YELLOW}⚠${NC} No Lustre subnet detected — skipped"
        elif [[ $_lus_net_total -gt 0 ]]; then
            local _lus_net_ic="${GREEN}✓${NC}"; [[ $_lus_net_ok -lt $_lus_net_total ]] && _lus_net_ic="${YELLOW}⚠${NC}"
            echo -e "  Network (Worker → Lustre): ${_lus_net_ic} ${_lus_net_ok}/${_lus_net_total} rules OK"
        fi

        # PVCs
        if [[ $_lus_pvc_ct -gt 0 ]]; then
            echo -e "  PVCs (${_lus_pvc_ct}):"
            _stv_print_lines "$_lus_pvc_lines" "$_lus_pvc_ct" 5 "$_stv_show_all"
        else
            echo -e "  PVCs (0): ${GRAY}(none)${NC}"
        fi
        echo ""

        # Cleanup temp
        rm -rf "${_stv_ptmp:?}"

        # --- Actions ---
        _ui_actions
        echo ""
        local _has_long=0
        { [[ $_bv_pvc_ct -gt 5 ]] || [[ $_mt_display_ct -gt 5 ]] || [[ $_fss_pvc_ct -gt 5 ]] || [[ "${_lfs_ct:-0}" -gt 5 ]] || [[ $_lus_pvc_ct -gt 5 ]]; } && _has_long=1
        if [[ $_has_long -eq 1 ]]; then
            if [[ $_stv_show_all -eq 0 ]]; then
                echo -e "  ${CYAN}a${NC}) Show all items"
            else
                echo -e "  ${CYAN}a${NC}) Collapse to 5 items"
            fi
        fi
        echo -e "  ${CYAN}r${NC}) Refresh"
        echo -e "  ${CYAN}b${NC}) Back"
        echo ""
        local _prompt_opts="r, b"
        [[ $_has_long -eq 1 ]] && _prompt_opts="a, r, b"
        _ui_prompt "Storage Validation" "$_prompt_opts"

        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return

        case "$choice" in
            a|A) _stv_show_all=$(( 1 - _stv_show_all )); continue ;;
            r|R) _stv_show_all=0; continue ;;
            b|B|back|BACK|"") return ;;
            *) echo -e "${RED}Invalid selection${NC}"; sleep 1 ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Authorized SSH Keys - Distribute SSH public keys to K8s worker nodes
# Uses ConfigMap + DaemonSet pattern (kube-system namespace)
# Ref: github.com/oracle-quickstart/oci-hpc-oke (adding-ssh-keys-to-worker-nodes)
#--------------------------------------------------------------------------------
k8s_authorized_ssh_keys() {
    local _ask_log="${LOGS_DIR}/ssh_keys_$(date '+%Y%m%d').log"
    mkdir -p "$(dirname "$_ask_log")" 2>/dev/null
    local _ns="kube-system"
    local _cm_name="authorized-ssh-keys"
    local _ds_name="authorized-ssh-keys"

    # Persistent config directory for YAML manifests
    local _cfg_dir="${SCRIPT_DIR}/kubernetes-configs/ssh-authorized-keys"
    mkdir -p "$_cfg_dir" 2>/dev/null
    local _cm_yaml="${_cfg_dir}/configmap.yaml"
    local _ds_yaml="${_cfg_dir}/daemonset.yaml"

    # Write the DaemonSet manifest if it doesn't exist yet
    if [[ ! -f "$_ds_yaml" ]]; then
        cat > "$_ds_yaml" << 'DSEOF'
apiVersion: apps/v1
kind: DaemonSet
metadata:
  name: authorized-ssh-keys
  namespace: kube-system
spec:
  selector:
    matchLabels:
      app: authorized-ssh-keys
  updateStrategy:
    type: RollingUpdate
    rollingUpdate:
      maxSurge: 0
      maxUnavailable: "100%"
  template:
    metadata:
      labels:
        app: authorized-ssh-keys
    spec:
      dnsPolicy: ClusterFirst
      hostNetwork: true
      priorityClassName: system-node-critical
      restartPolicy: Always
      terminationGracePeriodSeconds: 0
      tolerations: [{ operator: Exists }]
      volumes:
        - { name: root, hostPath: { path: / }}
        - { name: authorized-ssh-keys, configMap: { name: authorized-ssh-keys }}
      containers:
        - command:
            - /usr/bin/bash
            - -c
            - |
              set -e -o pipefail; exit=0; trap 'exit=1; echo "Exit signal" >&2' SIGINT SIGTERM
              homepath=/host/home/ubuntu; if [[ ! -e /host/home/ubuntu ]]; then homepath=/host/home/opc; fi
              current=$(cat "$homepath"/.ssh/authorized_keys | sort -u)
              current_hash=$(echo "$current" | md5sum | awk '{print $1}')
              latest=$(awk 1 /authorized/*.pub | sort -u)
              latest_hash=$(echo "$latest" | md5sum | awk '{print $1}')
              keys=$(echo "$latest" | wc -l)
              if [[ $current_hash != $latest_hash ]] && [ "$keys" -gt 0 ]; then
                echo "$latest" > "$homepath"/.ssh/authorized_keys.tmp
                echo "$(date) Updating $keys keys ($current_hash -> $latest_hash)" >&2
                echo "$latest" | tee "$homepath"/.ssh/authorized_keys
              fi
              while :; do [[ "$exit" -gt 0 ]] && break; sleep 1; done
          image: oraclelinux:9
          name: authorized-ssh-keys
          resources:
            requests:
              cpu: 0m
              ephemeral-storage: 10Mi
              memory: 64Mi
            limits:
              cpu: 100m
              ephemeral-storage: 10Mi
              memory: 64Mi
          securityContext:
            privileged: true
          volumeMounts:
            - { name: root, mountPath: /host }
            - { name: authorized-ssh-keys, mountPath: /authorized }
DSEOF
    fi

    while true; do
        echo ""
        _ui_menu_header "AUTHORIZED SSH KEYS" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" "SSH Keys" \
            --cmd "kubectl get cm ${_cm_name} -n ${_ns} | kubectl get ds ${_ds_name} -n ${_ns} | kubectl rollout restart" \
            --env
        echo -e "  ${GRAY}Configs: ${_cfg_dir}/${NC}"

        # --- Discovery ---
        _step_init
        local _cm_exists=0 _ds_exists=0 _ds_ready="" _ds_desired="" _key_count=0
        local _cm_json="" _ds_json=""

        _step_active "configmap"
        _cm_json=$(kubectl get configmap "$_cm_name" -n "$_ns" -o json 2>/dev/null)
        if [[ -n "$_cm_json" ]] && jq -e '.metadata.name' <<< "$_cm_json" >/dev/null 2>&1; then
            _cm_exists=1
            _key_count=$(jq '[.data // {} | keys[] | select(endswith(".pub"))] | length' <<< "$_cm_json" 2>/dev/null)
            _step_complete "cm(${_key_count} keys)"
        else
            _step_complete "no configmap"
            _cm_json=""
        fi

        _step_active "daemonset"
        _ds_json=$(kubectl get daemonset "$_ds_name" -n "$_ns" -o json 2>/dev/null)
        if [[ -n "$_ds_json" ]] && jq -e '.metadata.name' <<< "$_ds_json" >/dev/null 2>&1; then
            _ds_exists=1
            _ds_ready=$(jq -r '.status.numberReady // 0' <<< "$_ds_json")
            _ds_desired=$(jq -r '.status.desiredNumberScheduled // 0' <<< "$_ds_json")
            _step_complete "ds(${_ds_ready}/${_ds_desired} ready)"
        else
            _step_complete "no daemonset"
            _ds_json=""
        fi
        _step_finish
        echo ""

        # --- Current keys summary ---
        if [[ $_cm_exists -eq 1 && $_key_count -gt 0 ]]; then
            echo -e "  ${WHITE}Current SSH Keys (${_key_count}):${NC}"
            local _ki=0
            while IFS= read -r _kname; do
                ((_ki++))
                local _kval; _kval=$(jq -r --arg k "$_kname" '.data[$k] // ""' <<< "$_cm_json" 2>/dev/null)
                local _ktype="${_kval%% *}"
                local _kcomment="${_kval##* }"
                [[ "$_kcomment" == "$_kval" ]] && _kcomment=""
                printf "    ${YELLOW}%d${NC}) ${GREEN}%-20s${NC} ${WHITE}%-10s${NC} ${GRAY}%s${NC}\n" "$_ki" "$_kname" "$_ktype" "$_kcomment"
            done < <(jq -r '.data // {} | keys[] | select(endswith(".pub"))' <<< "$_cm_json" 2>/dev/null)
            echo ""
        elif [[ $_cm_exists -eq 1 ]]; then
            echo -e "  ${YELLOW}ConfigMap exists but has no .pub keys${NC}"
            echo ""
        fi

        # --- DaemonSet status ---
        if [[ $_ds_exists -eq 1 ]]; then
            echo -e "  ${WHITE}DaemonSet:${NC} ${GREEN}${_ds_ready}/${_ds_desired}${NC} pods ready"
        else
            echo -e "  ${GRAY}DaemonSet not deployed${NC}"
        fi
        echo ""

        # --- Actions ---
        _ui_actions
        echo ""
        if [[ $_cm_exists -eq 0 && $_ds_exists -eq 0 ]]; then
            echo -e "  ${YELLOW}1${NC}) ${GREEN}Create${NC}    - Create ConfigMap + DaemonSet to distribute SSH keys"
        else
            echo -e "  ${YELLOW}1${NC}) ${GREEN}Add Key${NC}   - Add an SSH public key to the ConfigMap"
            echo -e "  ${YELLOW}2${NC}) ${GREEN}Remove Key${NC} - Remove an SSH public key from the ConfigMap"
            echo -e "  ${YELLOW}3${NC}) ${GREEN}Edit${NC}       - Edit the ConfigMap directly (kubectl edit)"
            echo -e "  ${YELLOW}4${NC}) ${GREEN}Restart${NC}    - Restart DaemonSet to apply key changes"
            echo -e "  ${YELLOW}5${NC}) ${GREEN}Pods${NC}       - Show DaemonSet pod status"
            echo -e "  ${YELLOW}6${NC}) ${GREEN}Logs${NC}       - Show DaemonSet pod logs"
            if [[ $_ds_exists -eq 0 && $_cm_exists -eq 1 ]]; then
                echo -e "  ${YELLOW}7${NC}) ${GREEN}Deploy DS${NC} - Deploy the DaemonSet (ConfigMap exists but no DaemonSet)"
            fi
            echo -e "  ${RED}d${NC}) ${WHITE}Delete${NC}     - Remove ConfigMap + DaemonSet entirely"
        fi
        echo ""
        echo -e "  ${CYAN}r${NC}) Refresh"
        echo -e "  ${CYAN}b${NC}) Back"
        echo ""
        local _prompt_range="1, b"
        [[ $_cm_exists -eq 1 || $_ds_exists -eq 1 ]] && _prompt_range="1-6, d, r, b"
        _ui_prompt "SSH Keys" "$_prompt_range"

        local _ask_input
        read -r _ask_input
        [[ "${_ask_input:-}" == :* ]] && _nav_try_jump "$_ask_input" && return

        case "$_ask_input" in
            1)
                if [[ $_cm_exists -eq 0 && $_ds_exists -eq 0 ]]; then
                    # --- INITIAL CREATE: ConfigMap + DaemonSet ---
                    echo ""
                    echo -e "  ${WHITE}This will create:${NC}"
                    echo -e "    ${CYAN}1.${NC} ConfigMap '${_cm_name}' in ${_ns} with your SSH public key(s)"
                    echo -e "    ${CYAN}2.${NC} DaemonSet '${_ds_name}' that distributes keys to all worker nodes"
                    echo ""

                    # Collect keys
                    local -a _new_keys=() _new_names=()
                    local _adding=1
                    while [[ $_adding -eq 1 ]]; do
                        echo -e "  ${WHITE}SSH public key #$(( ${#_new_keys[@]} + 1 )):${NC}"
                        echo -e "    ${YELLOW}f${NC}) Select from ~/.ssh/"
                        echo -e "    ${YELLOW}p${NC}) Paste key"
                        echo ""
                        _ui_prompt "Option" "f, p"
                        local _opt; read -r _opt

                        local _key_content="" _key_fname=""
                        if [[ "$_opt" =~ ^[fF]$ ]]; then
                            # List .pub files
                            local -a _pubs=()
                            while IFS= read -r _pf; do
                                _pubs+=("$_pf")
                            done < <(find ~/.ssh -maxdepth 1 -name '*.pub' -type f 2>/dev/null | sort)
                            if [[ ${#_pubs[@]} -eq 0 ]]; then
                                echo -e "  ${YELLOW}No .pub files found in ~/.ssh/${NC}"
                                continue
                            fi
                            local _pi=0
                            for _pf in "${_pubs[@]}"; do
                                ((_pi++))
                                local _pfp; _pfp=$(ssh-keygen -lf "$_pf" 2>/dev/null | awk '{print $2}') || _pfp=""
                                echo -e "    ${YELLOW}${_pi}${NC}) ${_pf##*/}  ${GRAY}${_pfp}${NC}"
                            done
                            echo ""
                            _ui_prompt "Key #" "1-${#_pubs[@]}"
                            local _sel; read -r _sel
                            if [[ "$_sel" =~ ^[0-9]+$ ]] && [[ -n "${_pubs[$((_sel-1))]:-}" ]]; then
                                _key_content=$(cat "${_pubs[$((_sel-1))]}" 2>/dev/null)
                                _key_fname="${_pubs[$((_sel-1))]##*/}"
                            else
                                echo -e "  ${YELLOW}Invalid selection${NC}"
                                continue
                            fi
                        elif [[ "$_opt" =~ ^[pP]$ ]]; then
                            echo -e "  ${WHITE}Paste your SSH public key:${NC}"
                            local _pasted; read -r _pasted
                            if [[ -n "$_pasted" ]]; then
                                _key_content="$_pasted"
                                _ui_prompt "Key filename" "e.g. user1.pub"
                                local _fn; read -r _fn
                                _key_fname="${_fn:-key$(( ${#_new_keys[@]} + 1 )).pub}"
                                [[ "$_key_fname" != *.pub ]] && _key_fname="${_key_fname}.pub"
                            fi
                        else
                            echo -e "  ${YELLOW}Skipped${NC}"
                            continue
                        fi

                        if [[ -n "$_key_content" ]]; then
                            _new_keys+=("$_key_content")
                            _new_names+=("$_key_fname")
                            echo -e "  ${GREEN}✓ Added:${NC} ${_key_fname}"
                        fi

                        echo ""
                        _ui_prompt "Add another key?" "y/n"
                        local _more; read -r _more
                        [[ ! "$_more" =~ ^[yY] ]] && _adding=0
                    done

                    if [[ ${#_new_keys[@]} -eq 0 ]]; then
                        echo -e "  ${YELLOW}No keys provided — cancelled${NC}"
                        _ui_pause; continue
                    fi

                    # Build ConfigMap YAML (persisted to config dir)
                    {
                        echo "apiVersion: v1"
                        echo "kind: ConfigMap"
                        echo "metadata:"
                        echo "  name: ${_cm_name}"
                        echo "  namespace: ${_ns}"
                        echo "data:"
                        for (( _ki=0; _ki<${#_new_keys[@]}; _ki++ )); do
                            local _escaped_key="${_new_keys[$_ki]//\'/\'\'}"
                            echo "  ${_new_names[$_ki]}: '${_escaped_key}'"
                        done
                    } > "$_cm_yaml"

                    # Apply (DaemonSet YAML already exists at $_ds_yaml)
                    echo ""
                    local _cm_cmd="kubectl apply -f ${_cm_yaml}"
                    local _ds_cmd="kubectl apply -f ${_ds_yaml}"
                    echo -e "  ${GRAY}\$ ${_cm_cmd}${NC}"
                    echo -e "  ${GRAY}\$ ${_ds_cmd}${NC}"
                    echo ""
                    log_action "SSH_KEYS_CREATE" "${_cm_cmd} && ${_ds_cmd}" --quiet

                    _ui_prompt "Apply ConfigMap + DaemonSet?" "y/n"
                    local _confirm; read -r _confirm
                    if [[ ! "$_confirm" =~ ^[yY] ]]; then
                        echo -e "  ${YELLOW}Cancelled${NC}"
                        rm -f "$_cm_yaml"
                        _ui_pause; continue
                    fi

                    _step_init; _step_active "applying configmap"
                    local _cm_rc=0
                    kubectl apply -f "$_cm_yaml" 2>&1 || _cm_rc=$?
                    if [[ $_cm_rc -eq 0 ]]; then
                        _step_complete "configmap applied"
                    else
                        _step_complete "configmap failed"; _step_finish
                        echo -e "  ${RED}✗ Failed to apply ConfigMap${NC}"
                        log_action_result "FAILED" "SSH keys ConfigMap create"
                        _ui_pause; continue
                    fi

                    _step_active "applying daemonset"
                    local _ds_rc=0
                    kubectl apply -f "$_ds_yaml" 2>&1 || _ds_rc=$?
                    if [[ $_ds_rc -eq 0 ]]; then
                        _step_complete "daemonset applied"
                    else
                        _step_complete "daemonset failed"
                    fi
                    _step_finish

                    if [[ $_ds_rc -eq 0 ]]; then
                        echo -e "  ${GREEN}✓ ConfigMap + DaemonSet created successfully${NC}"
                        log_action_result "SUCCESS" "SSH keys: ${#_new_keys[@]} keys, DaemonSet deployed"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] CREATE: ${#_new_keys[@]} keys deployed via ConfigMap + DaemonSet" >> "$_ask_log"
                    else
                        echo -e "  ${RED}✗ DaemonSet deployment failed${NC}"
                        log_action_result "FAILED" "SSH keys DaemonSet deploy"
                    fi
                    echo -e "  ${GRAY}Configs saved: ${_cfg_dir}/${NC}"
                    echo ""
                    _ui_pause
                else
                    # --- ADD KEY to existing ConfigMap ---
                    echo ""
                    echo -e "  ${WHITE}Add SSH public key to ConfigMap:${NC}"
                    echo -e "    ${YELLOW}f${NC}) Select from ~/.ssh/"
                    echo -e "    ${YELLOW}p${NC}) Paste key"
                    echo ""
                    _ui_prompt "Option" "f, p"
                    local _opt; read -r _opt

                    local _key_content="" _key_fname=""
                    if [[ "$_opt" =~ ^[fF]$ ]]; then
                        local -a _pubs=()
                        while IFS= read -r _pf; do
                            _pubs+=("$_pf")
                        done < <(find ~/.ssh -maxdepth 1 -name '*.pub' -type f 2>/dev/null | sort)
                        if [[ ${#_pubs[@]} -eq 0 ]]; then
                            echo -e "  ${YELLOW}No .pub files found in ~/.ssh/${NC}"
                            _ui_pause; continue
                        fi
                        local _pi=0
                        for _pf in "${_pubs[@]}"; do
                            ((_pi++))
                            local _pfp; _pfp=$(ssh-keygen -lf "$_pf" 2>/dev/null | awk '{print $2}') || _pfp=""
                            echo -e "    ${YELLOW}${_pi}${NC}) ${_pf##*/}  ${GRAY}${_pfp}${NC}"
                        done
                        echo ""
                        _ui_prompt "Key #" "1-${#_pubs[@]}"
                        local _sel; read -r _sel
                        if [[ "$_sel" =~ ^[0-9]+$ ]] && [[ -n "${_pubs[$((_sel-1))]:-}" ]]; then
                            _key_content=$(cat "${_pubs[$((_sel-1))]}" 2>/dev/null)
                            _key_fname="${_pubs[$((_sel-1))]##*/}"
                        else
                            echo -e "  ${YELLOW}Invalid selection${NC}"; _ui_pause; continue
                        fi
                    elif [[ "$_opt" =~ ^[pP]$ ]]; then
                        echo -e "  ${WHITE}Paste your SSH public key:${NC}"
                        local _pasted; read -r _pasted
                        if [[ -n "$_pasted" ]]; then
                            _key_content="$_pasted"
                            _ui_prompt "Key filename" "e.g. user2.pub"
                            local _fn; read -r _fn
                            _key_fname="${_fn:-key.pub}"
                            [[ "$_key_fname" != *.pub ]] && _key_fname="${_key_fname}.pub"
                        fi
                    else
                        echo -e "  ${YELLOW}Cancelled${NC}"; _ui_pause; continue
                    fi

                    if [[ -z "$_key_content" ]]; then
                        echo -e "  ${YELLOW}No key provided${NC}"; _ui_pause; continue
                    fi

                    local _patch_json
                    _patch_json=$(jq -n --arg fname "$_key_fname" --arg content "$_key_content" '{data: {($fname): $content}}')
                    local _patch_cmd="kubectl patch configmap ${_cm_name} -n ${_ns} --type merge -p '${_patch_json}'"
                    echo -e "  ${GRAY}\$ ${_patch_cmd}${NC}"
                    log_action "SSH_KEY_ADD" "$_patch_cmd" --quiet

                    _step_init; _step_active "patching configmap"
                    local _p_rc=0
                    kubectl patch configmap "$_cm_name" -n "$_ns" --type merge \
                        -p "$_patch_json" 2>&1 || _p_rc=$?

                    if [[ $_p_rc -eq 0 ]]; then
                        _step_complete "key added"; _step_finish
                        echo -e "  ${GREEN}✓ Key '${_key_fname}' added to ConfigMap${NC}"
                        echo -e "  ${GRAY}Run ${WHITE}Restart${GRAY} (option 4) to distribute to nodes${NC}"
                        log_action_result "SUCCESS" "Added key ${_key_fname}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] ADD_KEY: ${_key_fname}" >> "$_ask_log"
                    else
                        _step_complete "patch failed"; _step_finish
                        echo -e "  ${RED}✗ Failed to add key${NC}"
                        log_action_result "FAILED" "Add key ${_key_fname}"
                    fi
                    echo ""
                    _ui_pause
                fi
                ;;

            2)
                [[ $_cm_exists -eq 0 ]] && { echo -e "  ${RED}No ConfigMap found${NC}"; _ui_pause; continue; }
                # --- REMOVE KEY ---
                echo ""
                if [[ $_key_count -eq 0 ]]; then
                    echo -e "  ${YELLOW}No keys in ConfigMap${NC}"; _ui_pause; continue
                fi
                echo -e "  ${WHITE}Select key to remove:${NC}"
                local -a _rm_keys=()
                local _ri=0
                while IFS= read -r _kname; do
                    ((_ri++))
                    _rm_keys+=("$_kname")
                    printf "    ${YELLOW}%d${NC}) ${GREEN}%s${NC}\n" "$_ri" "$_kname"
                done < <(jq -r '.data // {} | keys[] | select(endswith(".pub"))' <<< "$_cm_json" 2>/dev/null)
                echo ""
                _ui_prompt "Key # to remove" "1-${#_rm_keys[@]}"
                local _rm_sel; read -r _rm_sel
                if [[ ! "$_rm_sel" =~ ^[0-9]+$ ]] || [[ -z "${_rm_keys[$((_rm_sel-1))]:-}" ]]; then
                    echo -e "  ${YELLOW}Invalid selection${NC}"; _ui_pause; continue
                fi
                local _rm_name="${_rm_keys[$((_rm_sel-1))]}"

                local _rm_cmd="kubectl patch configmap ${_cm_name} -n ${_ns} --type json -p '[{\"op\":\"remove\",\"path\":\"/data/${_rm_name}\"}]'"
                echo -e "  ${GRAY}\$ ${_rm_cmd}${NC}"
                _ui_prompt "Remove key '${_rm_name}'?" "y/n"
                local _rm_confirm; read -r _rm_confirm
                if [[ ! "$_rm_confirm" =~ ^[yY] ]]; then
                    echo -e "  ${YELLOW}Cancelled${NC}"; _ui_pause; continue
                fi

                log_action "SSH_KEY_REMOVE" "$_rm_cmd" --quiet
                _step_init; _step_active "removing key"
                local _rm_rc=0
                kubectl patch configmap "$_cm_name" -n "$_ns" --type json \
                    -p "[{\"op\":\"remove\",\"path\":\"/data/${_rm_name}\"}]" 2>&1 || _rm_rc=$?
                if [[ $_rm_rc -eq 0 ]]; then
                    _step_complete "removed"; _step_finish
                    echo -e "  ${GREEN}✓ Key '${_rm_name}' removed${NC}"
                    echo -e "  ${GRAY}Run ${WHITE}Restart${GRAY} (option 4) to apply to nodes${NC}"
                    log_action_result "SUCCESS" "Removed key ${_rm_name}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] REMOVE_KEY: ${_rm_name}" >> "$_ask_log"
                else
                    _step_complete "failed"; _step_finish
                    echo -e "  ${RED}✗ Failed to remove key${NC}"
                    log_action_result "FAILED" "Remove key ${_rm_name}"
                fi
                echo ""
                _ui_pause
                ;;

            3)
                [[ $_cm_exists -eq 0 ]] && { echo -e "  ${RED}No ConfigMap found${NC}"; _ui_pause; continue; }
                # --- EDIT ConfigMap ---
                echo ""
                local _edit_cmd="kubectl edit configmap ${_cm_name} -n ${_ns}"
                echo -e "  ${GRAY}\$ ${_edit_cmd}${NC}"
                log_action "SSH_KEY_EDIT" "$_edit_cmd" --quiet
                kubectl edit configmap "$_cm_name" -n "$_ns"
                echo ""
                echo -e "  ${GRAY}Run ${WHITE}Restart${GRAY} (option 4) to distribute updated keys${NC}"
                log_action_result "SUCCESS" "Edited SSH keys ConfigMap"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] EDIT: ${_edit_cmd}" >> "$_ask_log"
                _ui_pause
                ;;

            4)
                [[ $_ds_exists -eq 0 ]] && { echo -e "  ${RED}No DaemonSet found${NC}"; _ui_pause; continue; }
                # --- RESTART DaemonSet ---
                echo ""
                local _restart_cmd="kubectl rollout restart daemonset/${_ds_name} -n ${_ns}"
                echo -e "  ${GRAY}\$ ${_restart_cmd}${NC}"
                log_action "SSH_KEY_RESTART" "$_restart_cmd" --quiet

                _step_init; _step_active "restarting daemonset"
                local _rs_rc=0
                kubectl rollout restart "daemonset/${_ds_name}" -n "$_ns" 2>&1 || _rs_rc=$?
                if [[ $_rs_rc -eq 0 ]]; then
                    _step_complete "restarted"; _step_finish
                    echo -e "  ${GREEN}✓ DaemonSet restart initiated${NC}"

                    # Watch rollout status briefly
                    _step_init; _step_active "waiting for rollout"
                    kubectl rollout status "daemonset/${_ds_name}" -n "$_ns" --timeout=60s 2>&1 || true
                    _step_complete "rollout complete"; _step_finish

                    log_action_result "SUCCESS" "Restarted SSH keys DaemonSet"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] RESTART: ${_restart_cmd}" >> "$_ask_log"
                else
                    _step_complete "failed"; _step_finish
                    echo -e "  ${RED}✗ Failed to restart DaemonSet${NC}"
                    log_action_result "FAILED" "Restart SSH keys DaemonSet"
                fi
                echo ""
                _ui_pause
                ;;

            5)
                # --- PODS ---
                echo ""
                local _pods_cmd="kubectl get pods -n ${_ns} -l app=${_ds_name} -o wide"
                echo -e "  ${GRAY}\$ ${_pods_cmd}${NC}"
                echo ""
                kubectl get pods -n "$_ns" -l "app=${_ds_name}" -o wide 2>&1
                echo ""
                _ui_pause
                ;;

            6)
                # --- LOGS ---
                echo ""
                local _logs_cmd="kubectl logs -n ${_ns} -l app=${_ds_name} --tail=50"
                echo -e "  ${GRAY}\$ ${_logs_cmd}${NC}"
                echo ""
                kubectl logs -n "$_ns" -l "app=${_ds_name}" --tail=50 --prefix 2>&1
                echo ""
                _ui_pause
                ;;

            7)
                if [[ $_ds_exists -eq 0 && $_cm_exists -eq 1 ]]; then
                    # --- DEPLOY DS only (ConfigMap exists, DaemonSet missing) ---
                    echo ""
                    local _ds_cmd="kubectl apply -f ${_ds_yaml}"
                    echo -e "  ${GRAY}\$ ${_ds_cmd}${NC}"
                    log_action "SSH_KEY_DEPLOY_DS" "$_ds_cmd" --quiet

                    _ui_prompt "Deploy DaemonSet?" "y/n"
                    local _dc; read -r _dc
                    if [[ ! "$_dc" =~ ^[yY] ]]; then
                        echo -e "  ${YELLOW}Cancelled${NC}"; _ui_pause; continue
                    fi

                    _step_init; _step_active "deploying daemonset"
                    local _drc=0
                    kubectl apply -f "$_ds_yaml" 2>&1 || _drc=$?
                    if [[ $_drc -eq 0 ]]; then
                        _step_complete "deployed"; _step_finish
                        echo -e "  ${GREEN}✓ DaemonSet deployed${NC}"
                        log_action_result "SUCCESS" "Deployed SSH keys DaemonSet"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] DEPLOY_DS" >> "$_ask_log"
                    else
                        _step_complete "failed"; _step_finish
                        echo -e "  ${RED}✗ Failed to deploy DaemonSet${NC}"
                        log_action_result "FAILED" "Deploy SSH keys DaemonSet"
                    fi
                    echo ""
                    _ui_pause
                else
                    echo -e "${RED}Invalid selection${NC}"; sleep 1
                fi
                ;;

            d|D)
                [[ $_cm_exists -eq 0 && $_ds_exists -eq 0 ]] && { echo -e "  ${RED}Nothing to delete${NC}"; _ui_pause; continue; }
                # --- DELETE all ---
                echo ""
                echo -e "  ${RED}This will delete:${NC}"
                [[ $_ds_exists -eq 1 ]] && echo -e "    ${WHITE}DaemonSet:${NC} ${_ds_name} (stops key distribution)"
                [[ $_cm_exists -eq 1 ]] && echo -e "    ${WHITE}ConfigMap:${NC} ${_cm_name} (${_key_count} keys)"
                echo -e "  ${GRAY}Worker node authorized_keys will NOT be reverted${NC}"
                echo ""
                _ui_prompt "Are you sure?" "y/n"
                local _del_confirm; read -r _del_confirm
                if [[ ! "$_del_confirm" =~ ^[yY] ]]; then
                    echo -e "  ${YELLOW}Cancelled${NC}"; _ui_pause; continue
                fi

                _step_init
                if [[ $_ds_exists -eq 1 ]]; then
                    _step_active "deleting daemonset"
                    kubectl delete daemonset "$_ds_name" -n "$_ns" --ignore-not-found 2>&1 || true
                    _step_complete "daemonset deleted"
                fi
                if [[ $_cm_exists -eq 1 ]]; then
                    _step_active "deleting configmap"
                    kubectl delete configmap "$_cm_name" -n "$_ns" --ignore-not-found 2>&1 || true
                    _step_complete "configmap deleted"
                fi
                _step_finish
                echo -e "  ${GREEN}✓ SSH key resources removed${NC}"
                log_action_result "SUCCESS" "Deleted SSH keys ConfigMap + DaemonSet"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] DELETE: ConfigMap + DaemonSet removed" >> "$_ask_log"
                echo ""
                _ui_pause
                ;;

            r|R|refresh|REFRESH)
                continue
                ;;
            b|B|back|BACK|"")
                return
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Kubernetes Management - Node operations and troubleshooting
#--------------------------------------------------------------------------------
manage_kubernetes() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    while true; do
        echo ""
        _ui_menu_header "KUBERNETES MANAGEMENT" \
            --color "$GREEN" \
            --breadcrumb "Kubernetes" "K8s Management" \
            --cmd "kubectl get nodes | kubectl drain | kubectl delete node | kubectl debug node/<n> -- chroot /host lsblk | lshw | ip addr | oci compute instance list --compartment-id \$COMPARTMENT_ID" \
            --env
        
        _ui_actions
        echo ""
        echo -e "  ${RED}1${NC}) ${WHITE}Kubelet Deregister${NC}           - Drain, delete K8s node, and show recovery steps for kubelet issues"
        echo -e "  ${YELLOW}2${NC}) ${GREEN}Node Storage Verification${NC}   - Disk layout, NVMe health, SMART logs, OCI volumes via kubectl debug"
        echo -e "  ${YELLOW}3${NC}) ${GREEN}Node Network Verification${NC}   - Host NIC hardware and IP address config via kubectl debug"
        echo -e "  ${YELLOW}4${NC}) ${GREEN}Node GPU Health${NC}             - nvidia-smi temps, ECC, NVLink, topology via kubectl debug"
        echo -e "  ${YELLOW}5${NC}) ${GREEN}Dmesg XID Error Scanner${NC}     - Scan kernel logs for NVIDIA XID errors per GPU node"
        echo -e "  ${YELLOW}6${NC}) ${GREEN}RDMA / NCCL Diagnostics${NC}     - InfiniBand port states, GID tables, error counters"
        echo -e "  ${YELLOW}7${NC}) ${GREEN}NVIDIA Bug Report${NC}           - Generate nvidia-bug-report.sh on a GPU node"
        echo -e "  ${YELLOW}8${NC}) ${GREEN}SOS Report${NC}                  - Generate sos diagnostic bundle (Oracle Linux / Ubuntu)"
        echo -e "  ${YELLOW}9${NC}) ${GREEN}GPU Tolerations${NC}             - View/add/remove tolerations on gpu-operator & device-plugin daemonsets"
        echo -e "  ${YELLOW}10${NC}) ${GREEN}Storage Provisioning Check${NC} - Validate BV, FSS, Lustre prerequisites for K8s"
        echo -e "  ${YELLOW}11${NC}) ${GREEN}Authorized SSH Keys${NC}        - Distribute SSH public keys to worker nodes via DaemonSet"
        echo ""
        echo -e "  ${CYAN}b${NC}) Back"
        echo ""
        _ui_prompt "K8s Management" "1-11, b, show"
        
        local choice
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return
        
        case "$choice" in
            1)
                k8s_kubelet_deregister
                ;;
            2)
                k8s_node_storage
                ;;
            3)
                k8s_node_network
                ;;
            4)
                k8s_node_gpu_health
                ;;
            5)
                k8s_node_dmesg_xid
                ;;
            6)
                k8s_node_rdma_diagnostics
                ;;
            7)
                k8s_nvidia_bug_report
                ;;
            8)
                k8s_sos_report
                ;;
            9)
                k8s_gpu_operator_tolerations
                ;;
            10)
                k8s_storage_provisioning_check
                ;;
            11)
                k8s_authorized_ssh_keys
                ;;
            b|B|back|BACK|"")
                return
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Kubelet Deregister - Drain and delete a K8s node, show recovery steps
#--------------------------------------------------------------------------------
k8s_kubelet_deregister() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/k8s_deregister_$(date '+%Y%m%d_%H%M%S').log"
    
    echo ""
    _ui_menu_header "KUBELET DEREGISTER (DRAIN + DELETE NODE)" --color "$RED"
    echo ""
    
    # Check kubectl availability
    if ! command -v kubectl &>/dev/null; then
        echo -e "${RED}kubectl not available - cannot perform node operations${NC}"
        echo ""
        _ui_pause "return"
        return 1
    fi
    
    # Fetch instances from cache or OCI (TTL from CACHE_TTL_MAP)
    _step_init
    _step_active "instances and K8s node mappings"
    local instances_json _kd_cached=""
    if is_cache_fresh "$INSTANCE_LIST_CACHE"; then
        instances_json=$(cat "$INSTANCE_LIST_CACHE")
        _kd_cached=" cached"
    else
        local _kd_err_file _kd_rc=0
        _kd_err_file=$(mktemp "${TEMP_DIR}/kd_err.XXXXXX") 2>/dev/null
        instances_json=$(oci compute instance list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all \
            --output json 2>"$_kd_err_file") || _kd_rc=$?
        # OCI CLI returns empty stdout when compartment has 0 instances
        if [[ -z "$instances_json" && $_kd_rc -eq 0 ]]; then
            instances_json='{"data":[]}'
        fi
        if [[ -n "$instances_json" ]] && jq -e '.data' <<< "$instances_json" > /dev/null 2>&1; then
            echo "$instances_json" | _cache_write "$INSTANCE_LIST_CACHE"
        fi
    fi
    _step_complete "instances and K8s node mappings${_kd_cached}"
    _step_finish

    if [[ -z "$instances_json" ]] || ! jq -e '.data' <<< "$instances_json" > /dev/null 2>&1; then
        echo -e "${RED}Failed to fetch instances${NC}"
        _ui_policy_hint "read instances in compartment"
        echo -e "  ${WHITE}Command:${NC} ${GRAY}oci compute instance list --compartment-id \"${compartment_id}\" --region \"${region}\" --all --output json${NC}"
        local _err_msg=""
        if [[ -f "${_kd_err_file:-}" && -s "$_kd_err_file" ]]; then
            _err_msg=$(grep -oP '(?<=message: ).*' "$_kd_err_file" | head -1)
            [[ -z "$_err_msg" ]] && _err_msg=$(tail -3 "$_kd_err_file")
        fi
        if [[ -z "$_err_msg" && -n "$instances_json" ]]; then
            _err_msg=$(jq -r '.message // .code // empty' <<< "$instances_json" 2>/dev/null)
            [[ -z "$_err_msg" ]] && _err_msg=$(echo "$instances_json" | head -5)
        fi
        [[ -n "$_err_msg" ]] && echo -e "  ${WHITE}Error:${NC}   ${GRAY}${_err_msg}${NC}"
        rm -f "${_kd_err_file:-}"
        _ui_pause "return"
        return 1
    fi
    rm -f "${_kd_err_file:-}"
    
    # Fetch K8s node info
    local k8s_nodes_json
    k8s_nodes_json=$(kubectl get nodes -o json 2>/dev/null)
    
    local k8s_lookup
    k8s_lookup=$(jq -r '
        .items[] |
        (.spec.taints // [] | map(select(.key == "newNode")) | if length > 0 then .[0].effect else "N/A" end) as $newNodeTaint |
        (.spec.unschedulable // false) as $unschedulable |
        "\(.spec.providerID)|\(.metadata.name)|\(.status.conditions[] | select(.type=="Ready") | .status)|\($newNodeTaint)|\($unschedulable)"
    ' <<< "$k8s_nodes_json" 2>/dev/null)
    
    # Build instance list with K8s node names
    declare -A DEREG_MAP=()      # i# -> ocid|name|k8s_node_name
    local dereg_idx=0
    
    echo ""
    _ui_subheader "Instances with K8s Node Names" 0
    echo ""
    printf "${BOLD}%-5s %-50s %-10s %-8s %-45s %s${NC}\n" \
        "ID" "Display Name" "State" "K8s" "Kubectl Node Name" "Instance OCID"
    print_separator 210
    
    jq -r ' 
        .data[] |
        select(.["lifecycle-state"] != "TERMINATED") |
        "\(.["time-created"] // "N/A")|\(.["display-name"])|\(.["lifecycle-state"])|\(.id)"
    ' <<< "$instances_json" 2>/dev/null | sort -t'|' -k1,1 | while IFS='|' read -r time_created name state ocid; do
        ((dereg_idx++))
        local iid="i${dereg_idx}"
        
        # Color state
        local state_color
        state_color=$(color_oci_state "$state")
        
        # Check K8s membership
        local k8s_status="No"
        local k8s_color="$YELLOW"
        local k8s_node_name="-"
        
        local k8s_match
        k8s_match=$(echo "$k8s_lookup" | grep -F "$ocid" 2>/dev/null)

        if [[ -n "$k8s_match" ]]; then
            k8s_node_name=$(echo "$k8s_match" | cut -d'|' -f2)
            local k8s_ready
            k8s_ready=$(echo "$k8s_match" | cut -d'|' -f3)
            
            if [[ "$k8s_ready" == "True" ]]; then
                k8s_status="Ready"
                k8s_color="$GREEN"
            else
                k8s_status="NotRdy"
                k8s_color="$RED"
            fi
        fi
        
        printf "${YELLOW}%-5s${NC} %-50s ${state_color}%-10s${NC} ${k8s_color}%-8s${NC} ${WHITE}%-45s${NC} ${GRAY}%s${NC}\n" \
            "$iid" "${name:0:50}" "$state" "$k8s_status" "${k8s_node_name:0:45}" "$ocid"
        
        # Write to temp file for map (subshell)
        echo "${iid}|${ocid}|${name}|${k8s_node_name}" >> "${TEMP_DIR}/dereg_map_$$"
    done
    
    # Read map from temp file
    if [[ -f "${TEMP_DIR}/dereg_map_$$" ]]; then
        while IFS='|' read -r iid ocid name k8s_node; do
            DEREG_MAP[$iid]="${ocid}|${name}|${k8s_node}"
        done < "${TEMP_DIR}/dereg_map_$$"
        rm -f "${TEMP_DIR}/dereg_map_$$"
    fi
    
    local total=${#DEREG_MAP[@]}
    echo ""
    echo -e "${GRAY}Total: ${total} instances (excluding TERMINATED)${NC}"
    echo ""
    
    # Selection loop
    while true; do
        _ui_actions
        echo -e "  ${YELLOW}i#${NC}  - Select instance to deregister (e.g., 'i1', 'i5')"
        echo -e "  ${CYAN}b${NC}   - Back"
        echo ""
        echo -n -e "${CYAN}Select instance [i#/b]: ${NC}"
        local selection
        read -r selection
        
        [[ -z "$selection" || "$selection" == "b" || "$selection" == "B" ]] && return 0
        
        # Validate selection
        local selected_data="${DEREG_MAP[$selection]:-}"
        if [[ -z "$selected_data" ]]; then
            echo -e "${RED}Invalid selection: ${selection}${NC}"
            sleep 1
            continue
        fi
        
        local sel_ocid sel_name sel_k8s_node
        IFS='|' read -r sel_ocid sel_name sel_k8s_node <<< "$selected_data"
        
        if [[ "$sel_k8s_node" == "-" || -z "$sel_k8s_node" ]]; then
            echo -e "${RED}Instance '${sel_name}' is not registered as a K8s node${NC}"
            sleep 1
            continue
        fi
        
        echo ""
        _ui_subheader "Kubelet Deregister" 0
        echo ""
        echo -e "  ${CYAN}Instance:${NC}  ${WHITE}${sel_name}${NC}"
        echo -e "  ${CYAN}OCID:${NC}      ${YELLOW}${sel_ocid}${NC}"
        echo -e "  ${CYAN}K8s Node:${NC}  ${WHITE}${sel_k8s_node}${NC}"
        echo ""
        
        echo -e "${BOLD}${YELLOW}This will execute:${NC}"
        echo -e "  ${GRAY}1. kubectl drain ${sel_k8s_node} --ignore-daemonsets --delete-emptydir-data${NC}"
        echo -e "  ${GRAY}2. kubectl delete node ${sel_k8s_node}${NC}"
        echo ""
        echo -e "${RED}WARNING: This will evict all pods and remove the node from the cluster.${NC}"
        echo ""
        echo -n -e "${BOLD}${YELLOW}Proceed? [y/N]: ${NC}"
        local confirm
        read -r confirm
        
        if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
            echo -e "${GRAY}Cancelled${NC}"
            continue
        fi
        
        # Ensure log directory exists
        mkdir -p "$(dirname "$log_file")" 2>/dev/null || true
        
        # Step 1: Drain
        echo ""
        local drain_cmd="kubectl drain ${sel_k8s_node} --ignore-daemonsets --delete-emptydir-data"
        _ui_subheader "Step 1: Draining Node" 0
        echo -e "${GRAY}\$ ${drain_cmd}${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${drain_cmd}" >> "$log_file"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] Instance: ${sel_name} (${sel_ocid})" >> "$log_file"
        
        log_action "DRAIN" "$drain_cmd"
        if kubectl drain "$sel_k8s_node" --ignore-daemonsets --delete-emptydir-data 2>&1 | tee -a "$log_file"; then
            echo ""
            echo -e "${GREEN}✓ Node drained successfully${NC}"
            log_action_result "SUCCESS" "DRAIN operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] RESULT: Drain succeeded" >> "$log_file"
        else
            echo ""
            echo -e "${YELLOW}⚠ Drain encountered errors (see above). Continuing with delete...${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] RESULT: Drain had errors" >> "$log_file"
        fi
        
        # Step 2: Delete node
        echo ""
        local delete_cmd="kubectl delete node ${sel_k8s_node}"
        _ui_subheader "Step 2: Deleting Node from Cluster" 0
        echo -e "${GRAY}\$ ${delete_cmd}${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: ${delete_cmd}" >> "$log_file"
        
        log_action "DELETE" "$delete_cmd"
        if kubectl delete node "$sel_k8s_node" 2>&1 | tee -a "$log_file"; then
            echo ""
            echo -e "${GREEN}✓ Node deleted from cluster${NC}"
            log_action_result "SUCCESS" "DELETE operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] RESULT: Delete succeeded" >> "$log_file"
        else
            echo ""
            echo -e "${RED}✗ Failed to delete node${NC}"
            log_action_result "FAILED" "DELETE operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] RESULT: Delete failed" >> "$log_file"
        fi
        
        # Step 3: Show manual recovery steps
        _ui_menu_header "ON THE PROBLEMATIC NODE, RUN THE FOLLOWING"
        echo ""
        echo -e "  ${WHITE}# SSH to the node${NC}"
        echo -e "  ${GRAY}ssh opc@<node-ip>${NC}"
        echo ""
        echo -e "  ${WHITE}# Step 1: Stop kubelet and CRI-O${NC}"
        echo -e "  ${YELLOW}sudo systemctl stop kubelet crio${NC}"
        echo ""
        echo -e "  ${WHITE}# Step 2: Remove kubelet PKI certificates${NC}"
        echo -e "  ${YELLOW}sudo rm /var/lib/kubelet/pki/*${NC}"
        echo ""
        echo -e "  ${WHITE}# Step 3: Re-bootstrap the node${NC}"
        echo -e "  ${YELLOW}sudo oke bootstrap${NC}"
        echo ""
        echo -e "${GRAY}The node will re-register with the cluster and rejoin as a fresh worker node.${NC}"
        echo -e "${GRAY}Log file: ${log_file}${NC}"
        echo ""
        _ui_pause
    done
}

#--------------------------------------------------------------------------------
# Manage NVIDIA GPU Stack Health - Check GPU Operator & DRA per node
#--------------------------------------------------------------------------------
manage_nvidia_gpu_stack_health() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_menu_header "NVIDIA GPU STACK HEALTH CHECK" \
        --color "$GREEN" \
        --breadcrumb "Kubernetes" "GPU Stack Health" \
        --cmd "kubectl get nodes -o json | kubectl get node \$NODE -o json | kubectl get ns | kubectl get pods -n gpu-operator -o json | kubectl get pods -n nvidia-dra-driver-gpu -o json" \
        --env
    
    # Check if kubectl is available
    if ! command -v kubectl &>/dev/null; then
        echo -e "${RED}kubectl not available - cannot check GPU stack health${NC}"
        echo ""
        _ui_pause "return"
        return 1
    fi
    
    # Test cluster connectivity
    if ! kubectl cluster-info &>/dev/null; then
        echo -e "${RED}Cannot connect to Kubernetes cluster${NC}"
        echo ""
        _ui_pause "return"
        return 1
    fi
    
    _step_init
    _step_active "nodes"

    # Get all nodes with provider IDs for OCI instance matching
    local nodes_json
    nodes_json=$(kubectl get nodes -o json 2>/dev/null)

    if [[ -z "$nodes_json" ]]; then
        _step_finish
        echo -e "${RED}Failed to get nodes${NC}"
        echo ""
        _ui_pause "return"
        return 1
    fi

    local _k8s_node_ct
    _k8s_node_ct=$(jq '.items | length' <<< "$nodes_json" 2>/dev/null || echo "0")
    _step_complete "nodes(${_k8s_node_ct})"

    # Fetch OCI instances to detect GPU shapes (source of truth for GPU detection)
    _step_active "OCI instances"
    local instances_json=""
    if is_cache_fresh "$INSTANCE_LIST_CACHE" && [[ -s "$INSTANCE_LIST_CACHE" ]]; then
        instances_json=$(cat "$INSTANCE_LIST_CACHE")
        local _inst_ct
        _inst_ct=$(jq '(.data // []) | length' <<< "$instances_json" 2>/dev/null || echo "0")
        _step_complete "OCI instances(${_inst_ct}, cached)"
    else
        instances_json=$(oci compute instance list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all --output json 2>/dev/null)
        if [[ -n "$instances_json" ]]; then
            echo "$instances_json" | _cache_write "$INSTANCE_LIST_CACHE"
            local _inst_ct
            _inst_ct=$(jq '(.data // []) | length' <<< "$instances_json" 2>/dev/null || echo "0")
            _step_complete "OCI instances(${_inst_ct})"
        else
            _step_complete "OCI instances(0)"
        fi
    fi

    # Build OCID→shape map from OCI instances
    declare -A _INST_SHAPE_MAP=()
    declare -A _INST_NAME_MAP=()
    if [[ -n "$instances_json" ]]; then
        while IFS=$'\t' read -r _iocid _ishape _iname; do
            [[ -z "$_iocid" ]] && continue
            _INST_SHAPE_MAP["$_iocid"]="$_ishape"
            _INST_NAME_MAP["$_iocid"]="$_iname"
        done < <(jq -r '(.data // [])[] | [.id, .shape, (.["display-name"] // "N/A")] | @tsv' <<< "$instances_json" 2>/dev/null)
    fi

    # Build node list: extract providerID→OCID, match OCI shape, detect GPU nodes
    # OKE providerID format: oci://<instance-ocid>
    local node_data
    node_data=$(jq -r '
        .items[] |
        {
            name: .metadata.name,
            gpu_count: (.status.capacity["nvidia.com/gpu"] // "0"),
            gpu_product: (.metadata.labels["nvidia.com/gpu.product"] // "-"),
            ready: (.status.conditions[] | select(.type=="Ready") | .status),
            unschedulable: (.spec.unschedulable // false),
            taints: ((.spec.taints // []) | map(.key + "=" + (.value // "") + ":" + .effect) | join(",")),
            provider_id: (.spec.providerID // "")
        } | "\(.name)|\(.gpu_count)|\(.gpu_product)|\(.ready)|\(.unschedulable)|\(.taints)|\(.provider_id)"
    ' <<< "$nodes_json" 2>/dev/null)

    # Enrich node data with OCI shape — determine GPU from shape (not device plugin)
    local enriched_node_data=""
    local _has_gpu_nodes=false
    while IFS='|' read -r _n_name _n_gpu _n_product _n_ready _n_unsched _n_taints _n_provid; do
        [[ -z "$_n_name" ]] && continue
        # Extract instance OCID from providerID (oci://<ocid>)
        local _n_ocid="${_n_provid#oci://}"
        local _n_shape="${_INST_SHAPE_MAP[$_n_ocid]:-}"
        local _n_inst_name="${_INST_NAME_MAP[$_n_ocid]:-}"

        # Determine if GPU node from OCI shape (contains .GPU. or .GPU2. .GPU3. .GPU4. etc.)
        local _is_gpu="false"
        if [[ "$_n_shape" == *".GPU"* || "$_n_shape" == *".gpu"* ]]; then
            _is_gpu="true"
            _has_gpu_nodes=true
        fi

        # Append shape and is_gpu flag to node data
        [[ -n "$enriched_node_data" ]] && enriched_node_data+=$'\n'
        enriched_node_data+="${_n_name}|${_n_gpu}|${_n_product}|${_n_ready}|${_n_unsched}|${_n_taints}|${_n_shape}|${_is_gpu}"
    done <<< "$node_data"

    if [[ "$_has_gpu_nodes" == "false" ]]; then
        _step_finish
        echo -e "${YELLOW}No GPU nodes detected in this cluster (no instances with GPU shapes found)${NC}"
        echo ""
        _ui_pause "return"
        return 0
    fi

    _step_complete "GPU shapes detected"
    _step_finish
    echo ""

    # Show validation commands used
    _ui_subheader "Validation Commands" 0
    echo ""
    echo -e "${GRAY}OCI instance shapes (GPU detection source of truth):${NC}"
    echo -e "  ${CYAN}oci compute instance list --compartment-id \$COMPARTMENT_ID --region ${region} --lifecycle-state RUNNING --all | jq '.data[] | {shape, \"display-name\"}'${NC}"
    echo ""
    echo -e "${GRAY}Node & GPU info:${NC}"
    echo -e "  ${CYAN}kubectl get nodes -o json | jq '.items[] | {name, providerID: .spec.providerID, gpu: .status.capacity[\"nvidia.com/gpu\"], taints: .spec.taints}'${NC}"
    echo ""
    echo -e "${GRAY}GPU Operator pods per node:${NC}"
    echo -e "  ${CYAN}kubectl get pods -n gpu-operator -o json | jq '.items[] | {node: .spec.nodeName, name: .metadata.name, phase: .status.phase}'${NC}"
    echo ""
    echo -e "${GRAY}DRA Driver pods per node:${NC}"
    echo -e "  ${CYAN}kubectl get pods -n nvidia-dra-driver-gpu -o json | jq '.items[] | {node: .spec.nodeName, name: .metadata.name, phase: .status.phase}'${NC}"
    echo ""
    echo -e "${GRAY}DRA Controller (deployment - runs on any node):${NC}"
    echo -e "  ${CYAN}kubectl get pods -n nvidia-dra-driver-gpu -l app=nvidia-dra-controller -o wide${NC}"
    echo ""
    
    # Get all pods from gpu-operator namespace with ready status
    # Format: nodeName|podName|phase|readyContainers/totalContainers
    local gpu_op_pods
    gpu_op_pods=$(kubectl get pods -n gpu-operator -o json 2>/dev/null | jq -r '
        .items[] | 
        ((.status.containerStatuses // []) | map(select(.ready == true)) | length) as $ready |
        ((.status.containerStatuses // []) | length) as $total |
        "\(.spec.nodeName // "N/A")|\(.metadata.name)|\(.status.phase)|\($ready)/\($total)"
    ' 2>/dev/null)
    
    # Get all pods from nvidia-dra-driver-gpu namespace with ready status
    # Format: nodeName|podName|phase|readyContainers/totalContainers
    local dra_pods
    dra_pods=$(kubectl get pods -n nvidia-dra-driver-gpu -o json 2>/dev/null | jq -r '
        .items[] | 
        ((.status.containerStatuses // []) | map(select(.ready == true)) | length) as $ready |
        ((.status.containerStatuses // []) | length) as $total |
        "\(.spec.nodeName // "N/A")|\(.metadata.name)|\(.status.phase)|\($ready)/\($total)"
    ' 2>/dev/null)
    
    # Check if namespaces exist
    local gpu_op_ns_exists=false
    local dra_ns_exists=false
    kubectl get ns gpu-operator &>/dev/null && gpu_op_ns_exists=true
    kubectl get ns nvidia-dra-driver-gpu &>/dev/null && dra_ns_exists=true
    
    # Check DRA kubelet plugin status globally
    # Pattern matches: nvidia-dra-driver-gpu-kubelet-plugin-* or *-k8s-dra-driver-kubelet-plugin-*
    local dra_kubelet_plugin_count=0
    local dra_kubelet_plugin_ready=0
    local dra_kubelet_plugin_status="${GRAY}-"
    if [[ "$dra_ns_exists" == "true" ]]; then
        # Count kubelet-plugin pods and their ready status (flexible pattern)
        while IFS='|' read -r node_name pod_name phase ready_status; do
            if [[ "$pod_name" == *"kubelet-plugin"* ]]; then
                ((dra_kubelet_plugin_count++))
                if [[ "$phase" == "Running" ]]; then
                    # Check if all containers are ready (e.g., "2/2" means ready)
                    local ready_num total_num
                    ready_num=$(echo "$ready_status" | cut -d'/' -f1)
                    total_num=$(echo "$ready_status" | cut -d'/' -f2)
                    if [[ "$ready_num" == "$total_num" && "$total_num" != "0" ]]; then
                        ((dra_kubelet_plugin_ready++))
                    fi
                fi
            fi
        done <<< "$dra_pods"
        
        if [[ $dra_kubelet_plugin_count -gt 0 ]]; then
            if [[ $dra_kubelet_plugin_ready -eq $dra_kubelet_plugin_count ]]; then
                dra_kubelet_plugin_status="${GREEN}✓ ${dra_kubelet_plugin_ready}/${dra_kubelet_plugin_count} Ready"
            else
                dra_kubelet_plugin_status="${YELLOW}◐ ${dra_kubelet_plugin_ready}/${dra_kubelet_plugin_count} Ready"
            fi
        else
            dra_kubelet_plugin_status="${RED}✗ No kubelet-plugin pods found"
        fi
    fi
    
    # Summary section
    _ui_subheader "Namespace Status" 0
    echo ""
    if [[ "$gpu_op_ns_exists" == "true" ]]; then
        local gpu_op_pod_count
        gpu_op_pod_count=$(kubectl get pods -n gpu-operator --no-headers 2>/dev/null | wc -l | tr -d ' ')
        echo -e "  ${CYAN}gpu-operator:${NC}          ${GREEN}EXISTS${NC} (${gpu_op_pod_count} pods)"
        
        # Check if using host drivers (no nvidia-driver pods)
        local driver_pod_count
        driver_pod_count=$(kubectl get pods -n gpu-operator --no-headers 2>/dev/null | grep -c "nvidia-driver" 2>/dev/null || true)
        driver_pod_count=${driver_pod_count:-0}
        driver_pod_count=$(echo "$driver_pod_count" | tr -d '[:space:]')
        if [[ -z "$driver_pod_count" || "$driver_pod_count" == "0" ]]; then
            echo -e "  ${CYAN}Driver Mode:${NC}           ${GRAY}HOST${NC} (driver.enabled: false - using pre-installed drivers)"
        else
            echo -e "  ${CYAN}Driver Mode:${NC}           ${GREEN}OPERATOR${NC} (${driver_pod_count} nvidia-driver pods)"
        fi
    else
        echo -e "  ${CYAN}gpu-operator:${NC}          ${RED}NOT FOUND${NC}"
    fi
    
    if [[ "$dra_ns_exists" == "true" ]]; then
        local dra_pod_count
        dra_pod_count=$(kubectl get pods -n nvidia-dra-driver-gpu --no-headers 2>/dev/null | wc -l | tr -d ' ')
        echo -e "  ${CYAN}nvidia-dra-driver-gpu:${NC} ${GREEN}EXISTS${NC} (${dra_pod_count} pods)"
        echo -e "  ${CYAN}DRA Kubelet Plugin:${NC}    ${dra_kubelet_plugin_status}${NC}"
    else
        echo -e "  ${CYAN}nvidia-dra-driver-gpu:${NC} ${RED}NOT FOUND${NC}"
    fi
    echo ""
    
    # Build header for component matrix
    _ui_subheader "Per-Node Component Status (GPU Nodes Only)" 0
    echo ""
    echo -e "${GRAY}Components: driver=NVIDIA Driver (or 'host' if using pre-installed drivers) | toolkit=Container Toolkit | plugin=Device Plugin${NC}"
    echo -e "${GRAY}            gfd=GPU Feature Discovery | dcgm=DCGM Exporter | validator=Operator Validator | mig-mgr=MIG Manager${NC}"
    echo -e "${GRAY}            dra-drv=DRA Kubelet Plugin (*kubelet-plugin* pods in nvidia-dra-driver-gpu namespace)${NC}"
    echo ""
    
    # Print header
    printf "${BOLD}%-3s %-28s %-22s %-5s %-6s %-20s %-7s %-7s %-7s %-5s %-5s %-9s %-8s %-8s %-80s${NC}\n" \
        "#" "Node Name" "OCI Shape" "GPUs" "Ready" "GPU Product" "driver" "toolkit" "plugin" "gfd" "dcgm" "validator" "mig-mgr" "dra-drv" "Taints"
    print_separator 265

    # Process each node - only GPU nodes (detected via OCI shape)
    local node_idx=0
    declare -A NODE_INDEX_MAP
    local total_nodes=0
    local gpu_nodes=0
    local healthy_nodes=0

    while IFS='|' read -r node_name gpu_count gpu_product ready unschedulable taints oci_shape is_gpu; do
        [[ -z "$node_name" ]] && continue
        ((total_nodes++))

        # Skip non-GPU nodes (based on OCI shape, not device plugin)
        [[ "$is_gpu" != "true" ]] && continue

        ((gpu_nodes++))
        ((node_idx++))
        NODE_INDEX_MAP[$node_idx]="$node_name"
        
        # Truncate fields
        local node_trunc="${node_name:0:28}"
        local shape_trunc="${oci_shape:0:22}"
        local product_trunc="${gpu_product:0:20}"
        
        # Process taints for display
        local taints_display="-"
        local taints_color="$GRAY"
        if [[ -n "$taints" && "$taints" != "null" ]]; then
            # Shorten common taint patterns
            taints_display=$(echo "$taints" | sed 's/nvidia.com\/gpu=:NoSchedule/gpu:NoSched/g' \
                | sed 's/node.kubernetes.io\/unschedulable:NoSchedule/unschedulable/g' \
                | sed 's/oci.oraclecloud.com\/oke-new-node:NoSchedule/newNode/g' \
                | sed 's/:NoSchedule/:NoSch/g' \
                | sed 's/:NoExecute/:NoEx/g' \
                | sed 's/:PreferNoSchedule/:PrefNo/g')
            taints_display="${taints_display:0:80}"
            taints_color="$YELLOW"
        fi
        
        # Ready status color
        local ready_color="$GREEN"
        [[ "$ready" != "True" ]] && ready_color="$RED"
        
        # GPU count color
        local gpu_color="$CYAN"
        
        # Helper function to get component status from pod list
        # Returns: "color|value" (e.g., "GREEN|1/1" or "RED|-")
        _get_pod_status() {
            local pods="$1"
            local node="$2"
            local pattern="$3"
            local optional="$4"  # "optional" if component is optional
            
            local pod_line
            pod_line=$(echo "$pods" | grep "^${node}|.*${pattern}" | head -1)
            
            if [[ -n "$pod_line" ]]; then
                local phase ready_status ready_num total_num
                phase=$(echo "$pod_line" | cut -d'|' -f3)
                ready_status=$(echo "$pod_line" | cut -d'|' -f4)
                ready_num=$(echo "$ready_status" | cut -d'/' -f1)
                total_num=$(echo "$ready_status" | cut -d'/' -f2)
                
                if [[ "$phase" == "Succeeded" ]]; then
                    echo "GREEN|done"
                elif [[ "$phase" == "Running" && "$ready_num" == "$total_num" && "$total_num" != "0" ]]; then
                    echo "GREEN|run"
                elif [[ "$phase" == "Running" ]]; then
                    echo "YELLOW|${ready_status}"
                else
                    echo "YELLOW|${phase:0:4}"
                fi
            else
                if [[ "$optional" == "optional" ]]; then
                    echo "GRAY|-"
                else
                    echo "RED|-"
                fi
            fi
        }
        
        # Check each GPU Operator component - store color and value separately
        local driver_color="GRAY" driver_val="-"
        local toolkit_color="GRAY" toolkit_val="-"
        local plugin_color="GRAY" plugin_val="-"
        local gfd_color="GRAY" gfd_val="-"
        local dcgm_color="GRAY" dcgm_val="-"
        local validator_color="GRAY" validator_val="-"
        local mig_color="GRAY" mig_val="-"
        
        if [[ "$gpu_op_ns_exists" == "true" ]]; then
            # Check driver - handle host driver mode
            local driver_pod
            driver_pod=$(echo "$gpu_op_pods" | grep "^${node_name}|.*nvidia-driver" | head -1)
            if [[ -n "$driver_pod" ]]; then
                local d_phase d_ready d_rnum d_tnum
                d_phase=$(echo "$driver_pod" | cut -d'|' -f3)
                d_ready=$(echo "$driver_pod" | cut -d'|' -f4)
                d_rnum=$(echo "$d_ready" | cut -d'/' -f1)
                d_tnum=$(echo "$d_ready" | cut -d'/' -f2)
                if [[ "$d_phase" == "Running" && "$d_rnum" == "$d_tnum" && "$d_tnum" != "0" ]]; then
                    driver_color="GREEN"; driver_val="$d_ready"
                elif [[ "$d_phase" == "Running" ]]; then
                    driver_color="YELLOW"; driver_val="$d_ready"
                else
                    driver_color="YELLOW"; driver_val="${d_phase:0:4}"
                fi
            else
                # Check if any driver pods exist cluster-wide
                if echo "$gpu_op_pods" | grep -q "nvidia-driver"; then
                    driver_color="RED"; driver_val="-"
                else
                    driver_color="GRAY"; driver_val="host"
                fi
            fi
            
            # Check other components using helper
            local result
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "container-toolkit")
            toolkit_color="${result%%|*}"; toolkit_val="${result#*|}"
            
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "device-plugin")
            plugin_color="${result%%|*}"; plugin_val="${result#*|}"
            
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "feature-discovery")
            gfd_color="${result%%|*}"; gfd_val="${result#*|}"
            
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "dcgm")
            dcgm_color="${result%%|*}"; dcgm_val="${result#*|}"
            
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "validator")
            validator_color="${result%%|*}"; validator_val="${result#*|}"
            
            result=$(_get_pod_status "$gpu_op_pods" "$node_name" "mig-manager" "optional")
            mig_color="${result%%|*}"; mig_val="${result#*|}"
        fi
        
        # Check DRA kubelet-plugin (per-node daemonset)
        local dra_color="GRAY" dra_val="-"
        
        if [[ "$dra_ns_exists" == "true" ]]; then
            local node_dra_pod
            node_dra_pod=$(echo "$dra_pods" | grep "^${node_name}|.*kubelet-plugin" | head -1)
            
            if [[ -n "$node_dra_pod" ]]; then
                local dra_phase dra_ready_status dra_ready_num dra_total_num
                dra_phase=$(echo "$node_dra_pod" | cut -d'|' -f3)
                dra_ready_status=$(echo "$node_dra_pod" | cut -d'|' -f4)
                dra_ready_num=$(echo "$dra_ready_status" | cut -d'/' -f1)
                dra_total_num=$(echo "$dra_ready_status" | cut -d'/' -f2)
                
                if [[ "$dra_phase" == "Running" && "$dra_ready_num" == "$dra_total_num" && "$dra_total_num" != "0" ]]; then
                    dra_color="GREEN"; dra_val="$dra_ready_status"
                elif [[ "$dra_phase" == "Running" ]]; then
                    dra_color="YELLOW"; dra_val="$dra_ready_status"
                else
                    dra_color="YELLOW"; dra_val="${dra_phase:0:4}"
                fi
            else
                dra_color="RED"; dra_val="-"
            fi
        fi
        
        # Check if node is healthy (all required components running for GPU node)
        local node_healthy=true
        if [[ "$gpu_op_ns_exists" == "true" ]]; then
            # Driver: either has green status or using host drivers is acceptable
            [[ "$driver_color" != "GREEN" && "$driver_val" != "host" ]] && node_healthy=false
            [[ "$toolkit_color" != "GREEN" ]] && node_healthy=false
            [[ "$plugin_color" != "GREEN" ]] && node_healthy=false
        fi
        [[ "$node_healthy" == "true" ]] && ((healthy_nodes++))
        
        # Convert color names to actual codes
        local dc tc pc gc dcc vc mc drac
        case "$driver_color" in GREEN) dc="$GREEN";; YELLOW) dc="$YELLOW";; RED) dc="$RED";; *) dc="$GRAY";; esac
        case "$toolkit_color" in GREEN) tc="$GREEN";; YELLOW) tc="$YELLOW";; RED) tc="$RED";; *) tc="$GRAY";; esac
        case "$plugin_color" in GREEN) pc="$GREEN";; YELLOW) pc="$YELLOW";; RED) pc="$RED";; *) pc="$GRAY";; esac
        case "$gfd_color" in GREEN) gc="$GREEN";; YELLOW) gc="$YELLOW";; RED) gc="$RED";; *) gc="$GRAY";; esac
        case "$dcgm_color" in GREEN) dcc="$GREEN";; YELLOW) dcc="$YELLOW";; RED) dcc="$RED";; *) dcc="$GRAY";; esac
        case "$validator_color" in GREEN) vc="$GREEN";; YELLOW) vc="$YELLOW";; RED) vc="$RED";; *) vc="$GRAY";; esac
        case "$mig_color" in GREEN) mc="$GREEN";; YELLOW) mc="$YELLOW";; RED) mc="$RED";; *) mc="$GRAY";; esac
        case "$dra_color" in GREEN) drac="$GREEN";; YELLOW) drac="$YELLOW";; RED) drac="$RED";; *) drac="$GRAY";; esac
        
        # Print row with proper alignment
        printf "${YELLOW}%-3s${NC} %-28s ${WHITE}%-22s${NC} ${gpu_color}%-5s${NC} ${ready_color}%-6s${NC} %-20s ${dc}%-7s${NC} ${tc}%-7s${NC} ${pc}%-7s${NC} ${gc}%-5s${NC} ${dcc}%-5s${NC} ${vc}%-9s${NC} ${mc}%-8s${NC} ${drac}%-8s${NC} ${taints_color}%-80s${NC}\n" \
            "$node_idx" "$node_trunc" "$shape_trunc" "$gpu_count" "$ready" "$product_trunc" "$driver_val" "$toolkit_val" "$plugin_val" "$gfd_val" "$dcgm_val" "$validator_val" "$mig_val" "$dra_val" "$taints_display"

    done <<< "$enriched_node_data"
    
    if [[ $gpu_nodes -eq 0 ]]; then
        echo -e "  ${YELLOW}No GPU nodes found in the cluster${NC}"
    fi

    echo ""
    print_separator 265
    
    # Summary
    echo ""
    _ui_summary
    echo ""
    echo -e "  ${WHITE}Total Nodes:${NC}   $total_nodes"
    echo -e "  ${WHITE}GPU Nodes:${NC}     $gpu_nodes"
    if [[ $gpu_nodes -gt 0 ]]; then
        if [[ $healthy_nodes -eq $gpu_nodes ]]; then
            echo -e "  ${WHITE}Healthy:${NC}       ${GREEN}$healthy_nodes / $gpu_nodes${NC} ${GREEN}✓ All GPU nodes healthy${NC}"
        else
            echo -e "  ${WHITE}Healthy:${NC}       ${YELLOW}$healthy_nodes / $gpu_nodes${NC} ${RED}⚠ Some nodes have issues${NC}"
        fi
    fi
    echo ""
    
    # Legend
    _ui_legend
    echo -e "  ${GREEN}run${NC}, ${GREEN}done${NC} = Healthy    ${YELLOW}0/1${NC}, ${YELLOW}1/2${NC} = Not all containers Ready    ${RED}-${NC} = Missing    ${GRAY}-${NC} = N/A or Optional"
    echo ""
    _ui_subheader "Status Values" 0
    echo -e "  ${GREEN}run${NC}  = Pod Running with all containers Ready"
    echo -e "  ${GREEN}done${NC} = Pod Succeeded (completed successfully, e.g., validator)"
    echo -e "  ${YELLOW}N/N${NC}  = Pod Running but not all containers Ready (e.g., 0/1, 1/2)"
    echo -e "  ${YELLOW}Pend${NC} = Pod in Pending state"
    echo -e "  ${GRAY}host${NC} = Using pre-installed host drivers (driver.enabled: false)"
    echo -e "  ${RED}-${NC}    = Required component missing"
    echo -e "  ${GRAY}-${NC}    = Optional component not deployed (e.g., mig-mgr)"
    echo ""
    _ui_subheader "Common Taints" 0
    echo -e "  ${YELLOW}newNode${NC} = oci.oraclecloud.com/oke-new-node:NoSchedule (node initializing)"
    echo -e "  ${YELLOW}gpu:NoSch${NC} = nvidia.com/gpu:NoSchedule (GPU dedicated)"
    echo -e "  ${YELLOW}unschedulable${NC} = node.kubernetes.io/unschedulable:NoSchedule (cordoned)"
    echo ""
    
    # Interactive menu
    while true; do
        _ui_actions
        echo -e "  Enter ${YELLOW}#${NC} (e.g., 1) to view detailed pod status for a node"
        echo -e "  Enter ${CYAN}pods${NC} to list all GPU-related pods"
        echo -e "  Enter ${CYAN}dra${NC} to list DRA kubelet-plugin pods with READY status"
        echo -e "  Enter ${CYAN}events${NC} to show recent events from GPU namespaces"
        echo -e "  Enter ${MAGENTA}r${NC} to refresh the status"
        echo -e "  Enter ${CYAN}b${NC} to go back"
        echo ""
        _ui_prompt "GPU Stack Health" "n#, r, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        case "$selection" in
            [0-9]*)
                local selected_node="${NODE_INDEX_MAP[$selection]:-}"
                if [[ -z "$selected_node" ]]; then
                    echo -e "${RED}Invalid node number: $selection${NC}"
                    continue
                fi
                
                echo ""
                _ui_detail_banner "Pod Details for Node" "${selected_node}" "${BOLD}${CYAN}"
                echo ""
                
                # Show node taints
                _ui_subheader "Node Taints" 0
                kubectl get node "$selected_node" -o json 2>/dev/null | jq -r '
                    .spec.taints // [] | if length == 0 then "  (none)" else .[] | "  \(.key)=\(.value // ""):\(.effect)" end
                ' 2>/dev/null || echo -e "${GRAY}  Unable to fetch taints${NC}"
                echo ""
                
                _ui_subheader "GPU Operator Pods (gpu-operator namespace)" 0
                kubectl get pods -n gpu-operator -o wide --field-selector spec.nodeName="$selected_node" 2>/dev/null || echo -e "${GRAY}  No pods found${NC}"
                echo ""
                
                _ui_subheader "DRA Pods (nvidia-dra-driver-gpu namespace)" 0
                kubectl get pods -n nvidia-dra-driver-gpu -o wide --field-selector spec.nodeName="$selected_node" 2>/dev/null || echo -e "${GRAY}  No pods found${NC}"
                echo ""
                
                # Show node labels related to NVIDIA
                _ui_subheader "NVIDIA Node Labels" 0
                kubectl get node "$selected_node" -o json 2>/dev/null | jq -r '
                    .metadata.labels | to_entries[] | 
                    select(.key | startswith("nvidia.com") or startswith("feature.node.kubernetes.io/pci-10de")) |
                    "  \(.key) = \(.value)"
                ' 2>/dev/null || echo -e "${GRAY}  No NVIDIA labels found${NC}"
                echo ""
                ;;
            pods|PODS)
                echo ""
                _ui_subheader "All GPU Operator Pods" 0
                kubectl get pods -n gpu-operator -o wide 2>/dev/null || echo -e "${GRAY}Namespace not found${NC}"
                echo ""
                _ui_subheader "All DRA Pods" 0
                kubectl get pods -n nvidia-dra-driver-gpu -o wide 2>/dev/null || echo -e "${GRAY}Namespace not found${NC}"
                echo ""
                ;;
            dra|DRA)
                echo ""
                _ui_subheader "DRA Kubelet Plugin Pods (*kubelet-plugin*)" 0
                echo ""
                # Show kubelet-plugin pods with their ready status
                kubectl get pods -n nvidia-dra-driver-gpu -o wide 2>/dev/null | grep -E "NAME|kubelet-plugin" || echo -e "${GRAY}No kubelet-plugin pods found${NC}"
                echo ""
                # Also show summary
                local total_plugin_pods ready_plugin_pods
                total_plugin_pods=$(kubectl get pods -n nvidia-dra-driver-gpu --no-headers 2>/dev/null | grep -c "kubelet-plugin" 2>/dev/null || true)
                total_plugin_pods=${total_plugin_pods:-0}
                total_plugin_pods=$(echo "$total_plugin_pods" | tr -d '[:space:]')
                [[ -z "$total_plugin_pods" ]] && total_plugin_pods=0
                ready_plugin_pods=$(kubectl get pods -n nvidia-dra-driver-gpu --no-headers 2>/dev/null | grep "kubelet-plugin" | awk '$2 ~ /^[0-9]+\/[0-9]+$/ {split($2,a,"/"); if(a[1]==a[2] && $3=="Running") count++} END {print count+0}')
                echo -e "${WHITE}Summary: ${CYAN}${ready_plugin_pods}${NC}/${CYAN}${total_plugin_pods}${NC} kubelet-plugin pods fully ready${NC}"
                echo ""
                ;;
            events|EVENTS)
                echo ""
                _ui_subheader "Recent Events (gpu-operator)" 0
                kubectl get events -n gpu-operator --sort-by='.lastTimestamp' 2>/dev/null | tail -20 || echo -e "${GRAY}No events${NC}"
                echo ""
                _ui_subheader "Recent Events (nvidia-dra-driver-gpu)" 0
                kubectl get events -n nvidia-dra-driver-gpu --sort-by='.lastTimestamp' 2>/dev/null | tail -20 || echo -e "${GRAY}No events${NC}"
                echo ""
                ;;
            r|R|refresh|REFRESH)
                manage_nvidia_gpu_stack_health
                return
                ;;
            b|B|back|BACK|"")
                return
                ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Unknown command${NC}"
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Create GPU Tagging Namespace and Tag
#--------------------------------------------------------------------------------
create_gpu_tagging_namespace() {
    local tenancy_ocid="$1"
    local home_region="$2"
    
    echo ""
    _ui_menu_header "CREATE TAG NAMESPACE AND TAG"
    echo ""
    
    # Use global DEBUG_MODE
    local debug_flag=""
    if [[ "$DEBUG_MODE" == "true" ]]; then
        debug_flag="--debug"
    fi
    
    # Step 1: Check if namespace already exists
    echo -e "${YELLOW}Step 1: Checking if namespace already exists...${NC}"
    echo ""
    
    local check_cmd="oci iam tag-namespace list --compartment-id \"$tenancy_ocid\" --all --query \"data[?name=='${GPU_TAG_NAMESPACE}']\" --output json"
    echo -e "${GRAY}$check_cmd${NC}"
    echo ""
    
    local existing_ns
    existing_ns=$(oci iam tag-namespace list \
        --compartment-id "$tenancy_ocid" \
        --all \
        --query "data[?name=='${GPU_TAG_NAMESPACE}']" \
        --output json 2>/dev/null)
    
    local namespace_ocid
    namespace_ocid=$(jq -r '.[0].id // empty' <<< "$existing_ns" 2>/dev/null)
    
    if [[ -n "$namespace_ocid" ]]; then
        local ns_state
        ns_state=$(jq -r '.[0]["lifecycle-state"] // "UNKNOWN"' <<< "$existing_ns" 2>/dev/null)
        
        echo -e "${YELLOW}⚠ Namespace '${GPU_TAG_NAMESPACE}' already exists${NC}"
        echo -e "  ${CYAN}OCID:${NC}  ${YELLOW}${namespace_ocid}${NC}"
        echo -e "  ${CYAN}State:${NC} ${WHITE}${ns_state}${NC}"
        echo ""
        
        if [[ "$ns_state" == "ACTIVE" ]]; then
            echo -e "${WHITE}Checking if tag '${GPU_TAG_NAME}' exists...${NC}"
            echo ""
            
            local existing_tag
            existing_tag=$(oci iam tag list \
                --tag-namespace-id "$namespace_ocid" \
                --all \
                --query "data[?name=='${GPU_TAG_NAME}']" \
                --output json 2>/dev/null)
            
            local tag_ocid
            tag_ocid=$(jq -r '.[0].id // empty' <<< "$existing_tag" 2>/dev/null)
            
            if [[ -n "$tag_ocid" ]]; then
                echo -e "${GREEN}✓ Tag '${GPU_TAG_NAME}' already exists${NC}"
                echo -e "  ${CYAN}OCID:${NC} ${YELLOW}${tag_ocid}${NC}"
                echo ""
                echo -e "${WHITE}No action needed - namespace and tag are already configured.${NC}"
            else
                echo -e "${YELLOW}Tag '${GPU_TAG_NAME}' does not exist. Creating...${NC}"
                echo ""
                _create_gpu_tag "$namespace_ocid" "$home_region" "$debug_flag"
            fi
        else
            echo -e "${RED}Namespace is in state '${ns_state}' - cannot create tag${NC}"
        fi
        
        echo ""
        _ui_pause
        return
    fi
    
    echo -e "${GREEN}✓ Namespace does not exist. Proceeding with creation...${NC}"
    echo ""
    
    # Step 2: Create namespace
    echo -e "${YELLOW}Step 2: Creating tag namespace '${GPU_TAG_NAMESPACE}'...${NC}"
    echo ""
    
    local create_ns_cmd="oci iam tag-namespace create \\
    --compartment-id \"$tenancy_ocid\" \\
    --name \"${GPU_TAG_NAMESPACE}\" \\
    --description \"${GPU_TAG_NAMESPACE_DESCRIPTION}\" \\
    --region \"$home_region\""
    
    echo -e "${BOLD}${YELLOW}Command to execute:${NC}"
    echo -e "${GRAY}$create_ns_cmd${NC}"
    echo ""
    
    echo -n -e "${CYAN}Execute this command? [y/N]: ${NC}"
    local confirm
    read -r confirm
    
    if [[ ! "$confirm" =~ ^[Yy] ]]; then
        echo -e "${YELLOW}Operation cancelled${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    echo ""
    log_action "CREATE_TAG_NAMESPACE" "$create_ns_cmd"
    
    local ns_result
    ns_result=$(oci iam tag-namespace create \
        --compartment-id "$tenancy_ocid" \
        --name "${GPU_TAG_NAMESPACE}" \
        --description "${GPU_TAG_NAMESPACE_DESCRIPTION}" \
        --region "$home_region" \
        --output json $debug_flag 2>&1)
    local ns_exit=$?
    
    if [[ $ns_exit -eq 0 ]]; then
        namespace_ocid=$(jq -r '.data.id // empty' <<< "$ns_result" 2>/dev/null)
        echo -e "${GREEN}✓ Namespace created successfully${NC}"
        echo -e "  ${CYAN}OCID:${NC} ${YELLOW}${namespace_ocid}${NC}"
        log_action_result "SUCCESS" "Namespace ${GPU_TAG_NAMESPACE} created: ${namespace_ocid}"
        echo ""
        
        # Wait for namespace to be active
        echo -e "${YELLOW}Waiting for namespace to become active...${NC}"
        sleep 5
        
        # Step 3: Create tag
        echo ""
        echo -e "${YELLOW}Step 3: Creating tag '${GPU_TAG_NAME}' in namespace...${NC}"
        echo ""
        
        _create_gpu_tag "$namespace_ocid" "$home_region" "$debug_flag"
    else
        echo -e "${RED}✗ Failed to create namespace${NC}"
        echo -e "${GRAY}Error: $ns_result${NC}"
        log_action_result "FAILED" "Namespace creation failed"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Helper: Create GPU tag in namespace
#--------------------------------------------------------------------------------
_create_gpu_tag() {
    local namespace_ocid="$1"
    local home_region="$2"
    local debug_flag="$3"
    
    # Build validator JSON for enum values
    local values_json
    values_json=$(echo "${GPU_TAG_VALUES}" | tr ',' '\n' | jq -R . | jq -s '.')
    local validator_json="{\"validator-type\": \"ENUM\", \"values\": ${values_json}}"
    
    local create_tag_cmd="oci iam tag create \\
    --tag-namespace-id \"$namespace_ocid\" \\
    --name \"${GPU_TAG_NAME}\" \\
    --description \"${GPU_TAG_NAME_DESCRIPTION}\" \\
    --validator '${validator_json}' \\
    --region \"$home_region\""
    
    echo -e "${BOLD}${YELLOW}Command to execute:${NC}"
    echo -e "${GRAY}$create_tag_cmd${NC}"
    echo ""
    
    echo -n -e "${CYAN}Execute this command? [y/N]: ${NC}"
    local confirm
    read -r confirm
    
    if [[ ! "$confirm" =~ ^[Yy] ]]; then
        echo -e "${YELLOW}Tag creation cancelled${NC}"
        return
    fi
    
    echo ""
    log_action "CREATE_TAG" "$create_tag_cmd"
    
    local tag_result
    tag_result=$(oci iam tag create \
        --tag-namespace-id "$namespace_ocid" \
        --name "${GPU_TAG_NAME}" \
        --description "${GPU_TAG_NAME_DESCRIPTION}" \
        --validator "$validator_json" \
        --region "$home_region" \
        --output json $debug_flag 2>&1)
    local tag_exit=$?
    
    if [[ $tag_exit -eq 0 ]]; then
        local tag_ocid
        tag_ocid=$(jq -r '.data.id // empty' <<< "$tag_result" 2>/dev/null)
        echo -e "${GREEN}✓ Tag created successfully${NC}"
        echo -e "  ${CYAN}OCID:${NC} ${YELLOW}${tag_ocid}${NC}"
        log_action_result "SUCCESS" "Tag ${GPU_TAG_NAME} created: ${tag_ocid}"
    else
        echo -e "${RED}✗ Failed to create tag${NC}"
        echo -e "${GRAY}Error: $tag_result${NC}"
        log_action_result "FAILED" "Tag creation failed"
    fi
}

#--------------------------------------------------------------------------------
# Validate GPU Tagging Namespace and Tag
#--------------------------------------------------------------------------------
validate_gpu_tagging_namespace() {
    local tenancy_ocid="$1"
    local home_region="$2"
    local mode="${3:-full}"   # "full" (manual v) or "compact" (auto on entry)
    
    # When called manually, show its own discovery bar
    if [[ "$mode" == "full" ]]; then
        _step_init
        _step_active "GPU tagging"
    fi
    
    _GPU_TAG_ALL_VALID=true
    local namespace_ocid=""
    local tag_data=""
    _GPU_TAG_NS_CHECK="missing"
    _GPU_TAG_TAG_CHECK="missing"
    _GPU_TAG_VAL_CHECK="missing"
    _GPU_TAG_NS_STATE=""
    _GPU_TAG_TAG_STATE=""
    _GPU_TAG_VALIDATOR_TYPE=""
    _GPU_TAG_VALIDATOR_VALUES=""
    _GPU_TAG_MISSING_VALUES=()
    
    # Fetch namespace
    local existing_ns
    existing_ns=$(oci iam tag-namespace list \
        --compartment-id "$tenancy_ocid" \
        --all \
        --query "data[?name=='${GPU_TAG_NAMESPACE}']" \
        --output json 2>/dev/null)
    
    namespace_ocid=$(jq -r '.[0].id // empty' <<< "$existing_ns" 2>/dev/null)
    
    if [[ -n "$namespace_ocid" ]]; then
        _GPU_TAG_NS_STATE=$(jq -r '.[0]["lifecycle-state"] // "UNKNOWN"' <<< "$existing_ns" 2>/dev/null)
        [[ "$_GPU_TAG_NS_STATE" == "ACTIVE" ]] && _GPU_TAG_NS_CHECK="ok" || { _GPU_TAG_NS_CHECK="warn"; _GPU_TAG_ALL_VALID=false; }
        
        # Fetch tag
        local tag_info
        tag_info=$(oci iam tag get \
            --tag-namespace-id "$namespace_ocid" \
            --tag-name "${GPU_TAG_NAME}" \
            --output json 2>/dev/null)
        
        tag_data=$(jq '.data' <<< "$tag_info" 2>/dev/null)
        
        if [[ -n "$tag_data" && "$tag_data" != "null" ]]; then
            _GPU_TAG_TAG_STATE=$(jq -r '.["lifecycle-state"] // "UNKNOWN"' <<< "$tag_data")
            _GPU_TAG_VALIDATOR_TYPE=$(jq -r '.validator["validator-type"] // "NONE"' <<< "$tag_data")
            _GPU_TAG_VALIDATOR_VALUES=$(jq -r '.validator.values // [] | join(", ")' <<< "$tag_data")
            
            [[ "$_GPU_TAG_TAG_STATE" == "ACTIVE" ]] && _GPU_TAG_TAG_CHECK="ok" || { _GPU_TAG_TAG_CHECK="warn"; _GPU_TAG_ALL_VALID=false; }
            
            # Check validator values
            if [[ "$_GPU_TAG_VALIDATOR_TYPE" == "ENUM" ]]; then
                _GPU_TAG_VAL_CHECK="ok"
                local expected_values
                IFS=',' read -ra expected_values <<< "${GPU_TAG_VALUES}"
                for val in "${expected_values[@]}"; do
                    val=$(echo "$val" | xargs)
                    local value_exists
                    value_exists=$(jq -r --arg v "$val" '.validator.values // [] | map(select(. == $v)) | length' <<< "$tag_data")
                    if [[ "$value_exists" -eq 0 ]]; then
                        _GPU_TAG_MISSING_VALUES+=("$val")
                        _GPU_TAG_VAL_CHECK="fail"
                        _GPU_TAG_ALL_VALID=false
                    fi
                done
            else
                _GPU_TAG_VAL_CHECK="fail"
                _GPU_TAG_ALL_VALID=false
            fi
        else
            _GPU_TAG_ALL_VALID=false
        fi
    else
        _GPU_TAG_ALL_VALID=false
    fi
    
    if [[ "$mode" == "full" ]]; then
        _step_complete "GPU tagging"
        _step_finish
    fi
    
    # In compact mode, caller handles display after _step_finish
    [[ "$mode" == "compact" ]] && return 0
    
    # ── Full display (manual v option) ── always show full detail
    _display_gpu_tag_validation "full"
}

# Display GPU tag validation results (uses _GPU_TAG_* globals set by validate_gpu_tagging_namespace)
# Args: $1 = "full" to always show detail, omit for compact (green one-liner if ok)
_display_gpu_tag_validation() {
    local display_mode="${1:-compact}"
    
    if [[ "$display_mode" != "full" && "$_GPU_TAG_ALL_VALID" == "true" ]]; then
        # Compact: all checks passed — single green line
        echo -e "  ${GREEN}✓ GPU namespace configured correctly${NC} — ${GPU_TAG_NAMESPACE}.${GPU_TAG_NAME} ENUM [${_GPU_TAG_VALIDATOR_VALUES}]"
        return 0
    fi
    
    _ui_subheader "Validation" 0
    echo ""
    
    # Namespace row
    if [[ "$_GPU_TAG_NS_CHECK" == "ok" ]]; then
        echo -e "  ${GREEN}✓${NC} ${WHITE}Namespace${NC}   ${GREEN}${GPU_TAG_NAMESPACE}${NC}  (${_GPU_TAG_NS_STATE})"
    elif [[ "$_GPU_TAG_NS_CHECK" == "warn" ]]; then
        echo -e "  ${YELLOW}⚠${NC} ${WHITE}Namespace${NC}   ${YELLOW}${GPU_TAG_NAMESPACE}${NC}  (${_GPU_TAG_NS_STATE} - expected ACTIVE)"
    else
        echo -e "  ${RED}✗${NC} ${WHITE}Namespace${NC}   ${RED}${GPU_TAG_NAMESPACE} not found${NC}"
    fi
    
    # Tag row
    if [[ "$_GPU_TAG_TAG_CHECK" == "ok" ]]; then
        echo -e "  ${GREEN}✓${NC} ${WHITE}Tag${NC}         ${GREEN}${GPU_TAG_NAME}${NC}  (${_GPU_TAG_TAG_STATE})"
    elif [[ "$_GPU_TAG_TAG_CHECK" == "warn" ]]; then
        echo -e "  ${YELLOW}⚠${NC} ${WHITE}Tag${NC}         ${YELLOW}${GPU_TAG_NAME}${NC}  (${_GPU_TAG_TAG_STATE} - expected ACTIVE)"
    elif [[ "$_GPU_TAG_NS_CHECK" == "missing" ]]; then
        echo -e "  ${GRAY}–${NC} ${WHITE}Tag${NC}         ${GRAY}skipped (no namespace)${NC}"
    else
        echo -e "  ${RED}✗${NC} ${WHITE}Tag${NC}         ${RED}${GPU_TAG_NAME} not found in namespace${NC}"
    fi
    
    # Validator row
    if [[ "$_GPU_TAG_VAL_CHECK" == "ok" ]]; then
        echo -e "  ${GREEN}✓${NC} ${WHITE}Validator${NC}   ENUM [${GREEN}${_GPU_TAG_VALIDATOR_VALUES}${NC}]"
    elif [[ "$_GPU_TAG_VAL_CHECK" == "fail" && "$_GPU_TAG_VALIDATOR_TYPE" != "ENUM" ]]; then
        echo -e "  ${RED}✗${NC} ${WHITE}Validator${NC}   ${RED}${_GPU_TAG_VALIDATOR_TYPE}${NC} (expected ENUM)"
    elif [[ "$_GPU_TAG_VAL_CHECK" == "fail" ]]; then
        echo -e "  ${RED}✗${NC} ${WHITE}Validator${NC}   ENUM [${YELLOW}${_GPU_TAG_VALIDATOR_VALUES:-empty}${NC}] — missing: ${RED}${_GPU_TAG_MISSING_VALUES[*]}${NC}"
    elif [[ "$_GPU_TAG_TAG_CHECK" == "missing" || "$_GPU_TAG_NS_CHECK" == "missing" ]]; then
        echo -e "  ${GRAY}–${NC} ${WHITE}Validator${NC}   ${GRAY}skipped${NC}"
    fi
    
    echo ""
    if [[ "$_GPU_TAG_ALL_VALID" == "true" ]]; then
        echo -e "  ${GREEN}✓ All checks passed${NC} — namespace and tag are properly configured."
    else
        echo -e "  ${RED}✗ Checks failed${NC} — use ${GREEN}c${NC} to create the missing namespace/tag."
    fi
}

#--------------------------------------------------------------------------------
# Delete GPU Tagging Namespace
#--------------------------------------------------------------------------------
delete_gpu_tagging_namespace() {
    local tenancy_ocid="$1"
    local home_region="$2"
    
    echo ""
    _ui_menu_header "DELETE TAG NAMESPACE"
    echo ""
    
    # Use global DEBUG_MODE
    local debug_flag=""
    if [[ "$DEBUG_MODE" == "true" ]]; then
        debug_flag="--debug"
    fi
    
    # Step 1: Find namespace
    echo -e "${YELLOW}Step 1: Finding namespace '${GPU_TAG_NAMESPACE}'...${NC}"
    echo ""
    
    local check_cmd="oci iam tag-namespace list --compartment-id \"$tenancy_ocid\" --all --query \"data[?name=='${GPU_TAG_NAMESPACE}']\" --output json"
    echo -e "${GRAY}$check_cmd${NC}"
    echo ""
    
    local existing_ns
    existing_ns=$(oci iam tag-namespace list \
        --compartment-id "$tenancy_ocid" \
        --all \
        --query "data[?name=='${GPU_TAG_NAMESPACE}']" \
        --output json 2>/dev/null)
    
    local namespace_ocid ns_state
    namespace_ocid=$(jq -r '.[0].id // empty' <<< "$existing_ns" 2>/dev/null)
    
    if [[ -z "$namespace_ocid" ]]; then
        echo -e "${YELLOW}Namespace '${GPU_TAG_NAMESPACE}' does not exist. Nothing to delete.${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    ns_state=$(jq -r '.[0]["lifecycle-state"] // "UNKNOWN"' <<< "$existing_ns" 2>/dev/null)
    
    echo -e "${WHITE}Found namespace:${NC}"
    echo -e "  ${CYAN}Name:${NC}  ${WHITE}${GPU_TAG_NAMESPACE}${NC}"
    echo -e "  ${CYAN}OCID:${NC}  ${YELLOW}${namespace_ocid}${NC}"
    echo -e "  ${CYAN}State:${NC} ${WHITE}${ns_state}${NC}"
    echo ""
    
    if [[ "$ns_state" == "DELETED" ]]; then
        echo -e "${YELLOW}Namespace is already in DELETED state${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    # Warning
    echo -e "${RED}╔════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║                      ⚠️  WARNING  ⚠️                             ║${NC}"
    echo -e "${RED}╚════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${RED}This will:${NC}"
    echo -e "${WHITE}  1. Retire the namespace (mark as inactive)${NC}"
    echo -e "${WHITE}  2. Cascade-delete the namespace and ALL tags within it${NC}"
    echo ""
    echo -e "${RED}This action cannot be undone!${NC}"
    echo ""
    
    _ui_subheader "Commands to Execute" 0
    echo -e "  ${GRAY}\$ oci iam tag-namespace retire --tag-namespace-id \"${namespace_ocid}\" --region \"${home_region}\"${NC}"
    echo -e "  ${GRAY}\$ oci iam tag-namespace cascade-delete --tag-namespace-id \"${namespace_ocid}\" --region \"${home_region}\"${NC}"
    echo ""
    
    if ! _ui_confirm "DELETE" "confirm"; then
        echo -e "${YELLOW}Operation cancelled${NC}"
        echo ""
        _ui_pause
        return
    fi
    
    echo ""
    
    # Step 2: Retire namespace (required before delete)
    if [[ "$ns_state" == "ACTIVE" ]]; then
        echo -e "${YELLOW}Step 2: Retiring namespace...${NC}"
        echo ""
        
        local retire_cmd="oci iam tag-namespace retire \\
    --tag-namespace-id \"$namespace_ocid\" \\
    --region \"$home_region\""
        
        echo -e "${GRAY}$retire_cmd${NC}"
        echo ""
        
        log_action "RETIRE_TAG_NAMESPACE" "$retire_cmd"
        
        local retire_result
        retire_result=$(oci iam tag-namespace retire \
            --tag-namespace-id "$namespace_ocid" \
            --region "$home_region" \
            $debug_flag 2>&1)
        local retire_exit=$?
        
        if [[ $retire_exit -eq 0 ]]; then
            echo -e "${GREEN}✓ Namespace retired successfully${NC}"
            log_action_result "SUCCESS" "Namespace retired"
        else
            echo -e "${RED}✗ Failed to retire namespace${NC}"
            echo -e "${GRAY}Error: $retire_result${NC}"
            log_action_result "FAILED" "Namespace retire failed"
            echo ""
            _ui_pause
            return
        fi
        
        echo ""
        echo -e "${YELLOW}Waiting for retire to complete...${NC}"
        sleep 3
    else
        echo -e "${YELLOW}Step 2: Namespace already retired (state: ${ns_state}), skipping retire...${NC}"
    fi
    
    echo ""
    
    # Step 3: Cascade delete
    echo -e "${YELLOW}Step 3: Cascade-deleting namespace and all tags...${NC}"
    echo ""
    
    local delete_cmd="oci iam tag-namespace cascade-delete \\
    --tag-namespace-id \"$namespace_ocid\" \\
    --region \"$home_region\""
    
    echo -e "${GRAY}$delete_cmd${NC}"
    echo ""
    
    log_action "CASCADE_DELETE_TAG_NAMESPACE" "$delete_cmd"
    
    local delete_result
    delete_result=$(oci iam tag-namespace cascade-delete \
        --tag-namespace-id "$namespace_ocid" \
        --region "$home_region" \
        $debug_flag 2>&1)
    local delete_exit=$?
    
    if [[ $delete_exit -eq 0 ]]; then
        echo -e "${GREEN}✓ Namespace cascade-delete initiated successfully${NC}"
        echo -e "${YELLOW}Note: The delete operation runs asynchronously. It may take a few minutes to complete.${NC}"
        log_action_result "SUCCESS" "Namespace cascade-delete initiated"
    else
        echo -e "${RED}✗ Failed to delete namespace${NC}"
        echo -e "${GRAY}Error: $delete_result${NC}"
        log_action_result "FAILED" "Namespace cascade-delete failed"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Create Instance Configuration interactively
#--------------------------------------------------------------------------------
create_instance_configuration_interactive() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local ad="${FOCUS_AD:-$AD}"
    # IC needs a single AD — use first if multi-AD selected
    [[ "$ad" == *","* ]] && ad="${ad%%,*}"
    local worker_subnet="${WORKER_SUBNET_ID:-}"
    local worker_nsg="${WORKER_SUBNET_NSG_ID:-}"
    local pod_subnet="${POD_SUBNET_ID:-}"
    local pod_nsg="${POD_SUBNET_NSG_ID:-}"
    local image_id="${IMAGE_ID:-}"
    
    echo ""
    _ui_menu_header "CREATE INSTANCE CONFIGURATION"
    echo ""
    
    # ========== PURPOSE SELECTION ==========
    _ui_subheader "Instance Configuration Purpose" 0
    echo ""
    echo -e "  ${GREEN}1${NC}) ${WHITE}OKE Cluster${NC}        ${GRAY}(worker nodes for Oracle Kubernetes Engine)${NC}"
    echo -e "  ${GREEN}2${NC}) ${WHITE}Normal Instances${NC}   ${GRAY}(standalone compute instances)${NC}"
    echo -e "  ${GREEN}3${NC}) ${WHITE}Cluster Network${NC}    ${GRAY}(RDMA cluster network instances)${NC}"
    echo ""
    echo -n -e "${CYAN}Select purpose [1]: ${NC}"
    local purpose_choice
    read -r purpose_choice
    
    local ic_purpose="oke"
    case "$purpose_choice" in
        2) ic_purpose="normal" ;;
        3) ic_purpose="cluster_network" ;;
        *) ic_purpose="oke" ;;
    esac
    echo -e "${GREEN}✓ Purpose: ${WHITE}${ic_purpose}${NC}"
    echo ""
    
    # ========== OKE CLUSTER SELECTION + CNI DETECTION ==========
    local network_type="flannel"
    local max_pods="60"
    local oke_cluster_name="" oke_version="unknown"
    
    if [[ "$ic_purpose" == "oke" ]]; then
        #------------------------------------------------------------
        # Helper: resolve CNI from cluster-pod-network-options array
        # Args: $1 = JSON file path
        #       $2 = cluster name (for display)
        #       $3 = label suffix
        #       $4 = optional jq array index (for list responses)
        # Sets: network_type (native or flannel)
        #------------------------------------------------------------
        _resolve_cni() {
            local _file="$1" _cname="$2" _label="${3:-}" _idx="${4:-}"
            local _cni_list _has_native=false _has_flannel=false
            
            if [[ ! -f "$_file" || ! -s "$_file" ]]; then
                network_type="flannel"
                echo -e "${YELLOW}⚠ No cluster data available for ${_cname}. Defaulting to flannel.${NC}"
                return
            fi
            
            if [[ -n "$_idx" ]]; then
                _cni_list=$(jq -r --argjson i "$_idx" '.data[$i]["cluster-pod-network-options"][]? | .["cni-type"] // empty' "$_file" 2>/dev/null)
            else
                _cni_list=$(jq -r '.data["cluster-pod-network-options"][]? | .["cni-type"] // empty' "$_file" 2>/dev/null)
            fi
            
            while read -r _ct; do
                [[ "$_ct" == "OCI_VCN_IP_NATIVE" ]] && _has_native=true
                [[ "$_ct" == "FLANNEL_OVERLAY" ]] && _has_flannel=true
            done <<< "$_cni_list"
            
            if [[ "$_has_native" == "true" && "$_has_flannel" == "true" ]]; then
                echo -e "  ${WHITE}Cluster ${CYAN}${_cname}${WHITE}${_label} supports both CNI types:${NC}"
                echo -e "  ${GREEN}1${NC}) ${WHITE}VCN-Native CNI${NC}  ${GRAY}(OCI_VCN_IP_NATIVE — pods get VCN IPs directly)${NC}"
                echo -e "  ${GREEN}2${NC}) ${WHITE}Flannel CNI${NC}     ${GRAY}(FLANNEL_OVERLAY — overlay networking)${NC}"
                echo ""
                echo -n -e "${CYAN}Select CNI type [1]: ${NC}"
                local _cni_pick
                read -r _cni_pick
                if [[ "$_cni_pick" == "2" ]]; then
                    network_type="flannel"
                    echo -e "${GREEN}✓ Selected: ${WHITE}Flannel CNI${NC}"
                else
                    network_type="native"
                    echo -e "${GREEN}✓ Selected: ${WHITE}VCN-Native CNI${NC}"
                fi
            elif [[ "$_has_native" == "true" ]]; then
                network_type="native"
                echo -e "${GREEN}✓ CNI: ${WHITE}VCN-Native${NC} ${GRAY}(from cluster${_label} ${_cname})${NC}"
            elif [[ "$_has_flannel" == "true" ]]; then
                network_type="flannel"
                echo -e "${GREEN}✓ CNI: ${WHITE}Flannel${NC} ${GRAY}(from cluster${_label} ${_cname})${NC}"
            else
                network_type="flannel"
                echo -e "${YELLOW}⚠ Could not determine CNI from cluster ${_cname}. Defaulting to flannel.${NC}"
            fi
        }
        
        # Discover OKE clusters — write list to temp file
        _step_init
        _step_active "OKE clusters"
        local _oke_list_tmpf="${TEMP_DIR}/oke_cluster_list_$$.json"
        oci ce cluster list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --lifecycle-state ACTIVE \
            --all --output json 2>/dev/null > "$_oke_list_tmpf"
        local _oke_cc
        _oke_cc=$(jq '.data | length' "$_oke_list_tmpf" 2>/dev/null || echo "0")
        _step_complete "OKE clusters(${_oke_cc})"
        _step_finish
        
        local _oke_sel_idx="0"  # jq array index of selected cluster
        
        if [[ "$_oke_cc" -eq 0 ]]; then
            echo -e "${YELLOW}No active OKE clusters found. Using defaults.${NC}"
            oke_cluster_name="unknown"
        elif [[ "$_oke_cc" -eq 1 ]]; then
            _oke_sel_idx="0"
            oke_cluster_name=$(jq -r '.data[0].name' "$_oke_list_tmpf")
            oke_version=$(jq -r '.data[0]["kubernetes-version"] // "unknown"' "$_oke_list_tmpf" | sed 's/^v//' | cut -d'.' -f1,2)
            echo -e "${GREEN}✓ Detected cluster: ${WHITE}${oke_cluster_name}${NC} ${GRAY}(v${oke_version})${NC}"
            _resolve_cni "$_oke_list_tmpf" "$oke_cluster_name" "" "$_oke_sel_idx"
            
            echo ""
            echo -e "  ${WHITE}Cluster:${NC}  ${CYAN}${oke_cluster_name}${NC} ${GRAY}(v${oke_version})${NC}"
            echo -e "  ${WHITE}CNI:${NC}      ${CYAN}${network_type}${NC}"
            echo ""
            echo -n -e "${CYAN}Use this cluster configuration? [Y/n]: ${NC}"
            local _oke_confirm
            read -r _oke_confirm
            if [[ "$_oke_confirm" =~ ^[Nn] ]]; then
                echo ""
                echo -e "${WHITE}Select CNI type manually:${NC}"
                echo -e "  ${GREEN}1${NC}) ${WHITE}VCN-Native CNI${NC}  ${GRAY}(OCI_VCN_IP_NATIVE — pods get VCN IPs directly)${NC}"
                echo -e "  ${GREEN}2${NC}) ${WHITE}Flannel CNI${NC}     ${GRAY}(FLANNEL_OVERLAY — overlay networking)${NC}"
                echo ""
                echo -n -e "${CYAN}Select CNI type [1]: ${NC}"
                local _manual_cni
                read -r _manual_cni
                if [[ "$_manual_cni" == "2" ]]; then
                    network_type="flannel"
                    echo -e "${GREEN}✓ Manual: ${WHITE}Flannel CNI${NC}"
                else
                    network_type="native"
                    echo -e "${GREEN}✓ Manual: ${WHITE}VCN-Native CNI${NC}"
                fi
            else
                echo -e "${GREEN}✓ Using: ${WHITE}${oke_cluster_name}${NC} (${network_type})${NC}"
            fi
        else
            # Multiple clusters — let user pick
            echo ""
            echo -e "${WHITE}Select OKE Cluster:${NC}"
            local _oke_idx=0
            declare -A _OKE_MAP=()
            while IFS='|' read -r _oname _ojidx _ostate _over; do
                ((_oke_idx++))
                _OKE_MAP[$_oke_idx]="$_ojidx|$_oname|$_over"
                local _ver_short
                _ver_short=$(echo "$_over" | sed 's/^v//' | cut -d'.' -f1,2)
                printf "  ${YELLOW}%2d${NC}) ${WHITE}%-40s${NC} ${GREEN}%-8s${NC} ${GRAY}v%s${NC}\n" \
                    "$_oke_idx" "$_oname" "$_ostate" "$_ver_short"
            done < <(jq -r '.data | to_entries[] | "\(.value.name)|\(.key)|\(.value["lifecycle-state"])|\(.value["kubernetes-version"] // "unknown")"' "$_oke_list_tmpf" 2>/dev/null)
            echo ""
            echo -n -e "${CYAN}Select cluster [1]: ${NC}"
            local _oke_pick
            read -r _oke_pick
            [[ -z "$_oke_pick" ]] && _oke_pick=1
            
            if [[ -n "${_OKE_MAP[$_oke_pick]:-}" ]]; then
                local _oke_jidx _oke_name _oke_ver
                IFS='|' read -r _oke_jidx _oke_name _oke_ver <<< "${_OKE_MAP[$_oke_pick]}"
                _oke_sel_idx="$_oke_jidx"
                oke_cluster_name="$_oke_name"
                oke_version=$(echo "$_oke_ver" | sed 's/^v//' | cut -d'.' -f1,2)
                echo -e "${GREEN}✓ Cluster: ${WHITE}${oke_cluster_name}${NC} ${GRAY}(v${oke_version})${NC}"
                _resolve_cni "$_oke_list_tmpf" "$oke_cluster_name" "" "$_oke_sel_idx"
            else
                echo -e "${YELLOW}Invalid selection. Using first cluster.${NC}"
                oke_cluster_name=$(jq -r '.data[0].name' "$_oke_list_tmpf")
                oke_version=$(jq -r '.data[0]["kubernetes-version"] // "unknown"' "$_oke_list_tmpf" | sed 's/^v//' | cut -d'.' -f1,2)
                _resolve_cni "$_oke_list_tmpf" "$oke_cluster_name" "" "0"
            fi
            
            # Confirm selected cluster + CNI
            echo ""
            echo -e "  ${WHITE}Cluster:${NC}  ${CYAN}${oke_cluster_name}${NC} ${GRAY}(v${oke_version})${NC}"
            echo -e "  ${WHITE}CNI:${NC}      ${CYAN}${network_type}${NC}"
            echo ""
            echo -n -e "${CYAN}Use this cluster configuration? [Y/n]: ${NC}"
            local _oke_confirm2
            read -r _oke_confirm2
            if [[ "$_oke_confirm2" =~ ^[Nn] ]]; then
                echo ""
                echo -e "${WHITE}Select CNI type manually:${NC}"
                echo -e "  ${GREEN}1${NC}) ${WHITE}VCN-Native CNI${NC}  ${GRAY}(OCI_VCN_IP_NATIVE — pods get VCN IPs directly)${NC}"
                echo -e "  ${GREEN}2${NC}) ${WHITE}Flannel CNI${NC}     ${GRAY}(FLANNEL_OVERLAY — overlay networking)${NC}"
                echo ""
                echo -n -e "${CYAN}Select CNI type [1]: ${NC}"
                local _manual_cni2
                read -r _manual_cni2
                if [[ "$_manual_cni2" == "2" ]]; then
                    network_type="flannel"
                    echo -e "${GREEN}✓ Manual: ${WHITE}Flannel CNI${NC}"
                else
                    network_type="native"
                    echo -e "${GREEN}✓ Manual: ${WHITE}VCN-Native CNI${NC}"
                fi
            else
                echo -e "${GREEN}✓ Using: ${WHITE}${oke_cluster_name}${NC} (${network_type})${NC}"
            fi
        fi
        # Extract VCN OCID from selected cluster — used to auto-select VCN for subnet/NSG
        local _oke_vcn_ocid=""
        _oke_vcn_ocid=$(jq -r --argjson i "$_oke_sel_idx" '.data[$i]["vcn-id"] // empty' "$_oke_list_tmpf" 2>/dev/null)
        if [[ -n "$_oke_vcn_ocid" ]]; then
            echo -e "${GREEN}✓ VCN (from OKE cluster): ${WHITE}$(jq -r --argjson i "$_oke_sel_idx" '.data[$i].name // "unknown"' "$_oke_list_tmpf" 2>/dev/null)${NC}"
        fi

        # Extract cluster OCID — needed to fetch node pool spec for auto-selecting subnet/NSG
        local _oke_cluster_ocid=""
        _oke_cluster_ocid=$(jq -r --argjson i "$_oke_sel_idx" '.data[$i].id // empty' "$_oke_list_tmpf" 2>/dev/null)

        rm -f "$_oke_list_tmpf"

        # ---- Auto-select worker/pod subnet + NSG from OKE node pool spec ----
        if [[ -n "$_oke_cluster_ocid" ]]; then
            echo ""
            _step_init
            _step_active "node pools (from OKE cluster)"
            local _np_json=""
            _np_json=$(_safe_exec "oci ce node-pool list --compartment-id ${compartment_id} --cluster-id ${_oke_cluster_ocid} --region ${region} --all --output json")
            _step_complete "node pools"
            _step_finish

            local _np_count=0
            _np_count=$(jq '.data | length' <<< "$_np_json" 2>/dev/null || echo 0)

            if [[ "$_np_count" -gt 0 ]]; then
                local _np_ref_idx=0  # jq array index of reference node pool

                if [[ "$_np_count" -eq 1 ]]; then
                    local _np_ref_name
                    _np_ref_name=$(jq -r '.data[0].name // "unknown"' <<< "$_np_json" 2>/dev/null)
                    echo -e "${GREEN}✓ Reference node pool (auto): ${WHITE}${_np_ref_name}${NC}"
                else
                    # Multiple node pools — let user pick reference
                    # Pre-scan for a "system" node pool to use as the smart default
                    local _np_system_sel=""
                    echo -e "${WHITE}Select reference node pool for subnet/NSG configuration:${NC}"
                    local _npi=0
                    declare -A _NP_SEL_MAP=()
                    while IFS='|' read -r _npn _nps _npsz _npsh; do
                        [[ -z "$_npn" ]] && continue
                        ((_npi++))
                        _NP_SEL_MAP[$_npi]=$((_npi - 1))  # map selection → jq index
                        local _np_sc="$GREEN"
                        [[ "$_nps" != "ACTIVE" ]] && _np_sc="$YELLOW"
                        local _np_tag=""
                        # Flag "system" node pool as recommended default
                        if [[ -z "$_np_system_sel" ]] && echo "$_npn" | grep -qi "system"; then
                            _np_system_sel="$_npi"
                            _np_tag=" ${CYAN}<- recommended${NC}"
                        fi
                        printf "  ${YELLOW}%2d${NC}) %-30s ${_np_sc}%-10s${NC} %-5s ${GRAY}%s${NC}%b\n" \
                            "$_npi" "${_npn:0:30}" "$_nps" "$_npsz" "${_npsh:0:25}" "$_np_tag"
                    done < <(jq -r '.data[] | "\(.name)|\(.["lifecycle-state"])|\(.["node-config-details"].size // "?")|\(.["node-shape"] // "?")"' <<< "$_np_json" 2>/dev/null)
                    echo ""
                    # Default to "system" node pool if found, otherwise first
                    local _np_default="${_np_system_sel:-1}"
                    echo -n -e "${CYAN}Select node pool [${_np_default}]: ${NC}"
                    local _np_pick
                    read -r _np_pick
                    [[ -z "$_np_pick" ]] && _np_pick="$_np_default"
                    _np_ref_idx="${_NP_SEL_MAP[$_np_pick]:-0}"
                    local _np_ref_name
                    _np_ref_name=$(jq -r --argjson i "$_np_ref_idx" '.data[$i].name // "unknown"' <<< "$_np_json" 2>/dev/null)
                    echo -e "${GREEN}✓ Reference node pool: ${WHITE}${_np_ref_name}${NC} ${GRAY}(${_np_count} total)${NC}"
                fi

                # Worker subnet — from placement-configs[0].subnet-id
                local _np_worker_subnet=""
                _np_worker_subnet=$(jq -r --argjson i "$_np_ref_idx" '.data[$i]["node-config-details"]["placement-configs"][0]["subnet-id"] // empty' <<< "$_np_json" 2>/dev/null)
                [[ -n "$_np_worker_subnet" && -z "$worker_subnet" ]] && worker_subnet="$_np_worker_subnet"

                # Worker NSGs — from nsg-ids[0]
                local _np_worker_nsg=""
                _np_worker_nsg=$(jq -r --argjson i "$_np_ref_idx" '.data[$i]["node-config-details"]["nsg-ids"][0] // empty' <<< "$_np_json" 2>/dev/null)
                [[ -n "$_np_worker_nsg" && -z "$worker_nsg" ]] && worker_nsg="$_np_worker_nsg"

                # Pod subnet — from node-pool-pod-network-option-details.pod-subnet-ids[0]
                local _np_pod_subnet=""
                _np_pod_subnet=$(jq -r --argjson i "$_np_ref_idx" '.data[$i]["node-config-details"]["node-pool-pod-network-option-details"]["pod-subnet-ids"][0] // empty' <<< "$_np_json" 2>/dev/null)
                [[ -n "$_np_pod_subnet" && -z "$pod_subnet" ]] && pod_subnet="$_np_pod_subnet"

                # Pod NSG — from node-pool-pod-network-option-details.pod-nsg-ids[0]
                local _np_pod_nsg=""
                _np_pod_nsg=$(jq -r --argjson i "$_np_ref_idx" '.data[$i]["node-config-details"]["node-pool-pod-network-option-details"]["pod-nsg-ids"][0] // empty' <<< "$_np_json" 2>/dev/null)
                [[ -n "$_np_pod_nsg" && -z "$pod_nsg" ]] && pod_nsg="$_np_pod_nsg"

                # Max pods per node — from node-pool-pod-network-option-details.max-pods-per-node
                local _np_max_pods=""
                _np_max_pods=$(jq -r --argjson i "$_np_ref_idx" '.data[$i]["node-config-details"]["node-pool-pod-network-option-details"]["max-pods-per-node"] // empty' <<< "$_np_json" 2>/dev/null)
                [[ -n "$_np_max_pods" && "$_np_max_pods" != "null" ]] && max_pods="$_np_max_pods"

                # Resolve display names in parallel
                local _nptmp_names
                _nptmp_names=$(mktemp -d "${TEMP_DIR}/np_names.XXXXXXXXXX")
                local -a _par_pids14=()
                if [[ -n "$worker_subnet" ]]; then
                    (resolve_subnet_name_cached "$worker_subnet" > "$_nptmp_names/ws" 2>/dev/null) &
                    _par_pids14+=($!)
                fi
                if [[ -n "$worker_nsg" ]]; then
                    (resolve_nsg_name_cached "$worker_nsg" > "$_nptmp_names/wn" 2>/dev/null) &
                    _par_pids14+=($!)
                fi
                if [[ -n "$pod_subnet" ]]; then
                    (resolve_subnet_name_cached "$pod_subnet" > "$_nptmp_names/ps" 2>/dev/null) &
                    _par_pids14+=($!)
                fi
                if [[ -n "$pod_nsg" ]]; then
                    (resolve_nsg_name_cached "$pod_nsg" > "$_nptmp_names/pn" 2>/dev/null) &
                    _par_pids14+=($!)
                fi
                [[ ${#_par_pids14[@]} -gt 0 ]] && wait "${_par_pids14[@]}" 2>/dev/null

                local _ws_name="" _wn_name="" _ps_name="" _pn_name=""
                [[ -s "$_nptmp_names/ws" ]] && _ws_name=$(<"$_nptmp_names/ws")
                [[ -s "$_nptmp_names/wn" ]] && _wn_name=$(<"$_nptmp_names/wn")
                [[ -s "$_nptmp_names/ps" ]] && _ps_name=$(<"$_nptmp_names/ps")
                [[ -s "$_nptmp_names/pn" ]] && _pn_name=$(<"$_nptmp_names/pn")
                rm -rf "$_nptmp_names" 2>/dev/null

                # Display with resolved names
                if [[ -n "$worker_subnet" ]]; then
                    echo -e "${GREEN}✓ Worker Subnet (from node pool): ${WHITE}${_ws_name:-unknown}${NC}  ${GRAY}[${worker_subnet}]${NC}"
                fi
                if [[ -n "$worker_nsg" ]]; then
                    echo -e "${GREEN}✓ Worker NSG (from node pool): ${WHITE}${_wn_name:-unknown}${NC}  ${GRAY}[${worker_nsg}]${NC}"
                fi
                if [[ -n "$pod_subnet" ]]; then
                    echo -e "${GREEN}✓ Pod Subnet (from node pool): ${WHITE}${_ps_name:-unknown}${NC}  ${GRAY}[${pod_subnet}]${NC}"
                fi
                if [[ -n "$pod_nsg" ]]; then
                    echo -e "${GREEN}✓ Pod NSG (from node pool): ${WHITE}${_pn_name:-unknown}${NC}  ${GRAY}[${pod_nsg}]${NC}"
                fi
                if [[ -n "$max_pods" ]]; then
                    echo -e "${GREEN}✓ Max Pods/Node (from node pool): ${WHITE}${max_pods}${NC}"
                fi
            else
                echo -e "${YELLOW}⚠ No node pools found for cluster — subnet/NSG will be selected manually${NC}"
            fi
        fi

        [[ -z "$oke_version" || "$oke_version" == "null" ]] && oke_version="unknown"
        [[ -z "$oke_cluster_name" || "$oke_cluster_name" == "null" ]] && oke_cluster_name="unknown"
        echo ""
    fi
    
    # ========== INTERACTIVE RESOURCE DISCOVERY ==========
    # Discover AD if not set
    if [[ -z "$ad" ]]; then
        # Try OKE_ENV_CACHE first
        if [[ -s "$OKE_ENV_CACHE" ]]; then
            local _cached_ad
            _cached_ad=$(grep '^AD=' "$OKE_ENV_CACHE" 2>/dev/null | head -1 | cut -d= -f2-)
            if [[ -n "$_cached_ad" && "$_cached_ad" != "N/A" ]]; then
                ad="$_cached_ad"
                echo -e "${GREEN}✓ AD (from cache): ${WHITE}${ad}${NC}"
            fi
        fi
    fi
    if [[ -z "$ad" ]]; then
        _step_init
        _step_active "availability domains"
        local _ad_json
        _ad_json=$(oci iam availability-domain list --compartment-id "$compartment_id" --region "$region" --output json 2>/dev/null)
        _step_complete "availability domains"
        _step_finish
        
        local _ad_count
        _ad_count=$(jq '.data | length' <<< "$_ad_json" 2>/dev/null || echo 0)
        
        if [[ "$_ad_count" -eq 1 ]]; then
            ad=$(jq -r '.data[0].name' <<< "$_ad_json")
            echo -e "${GREEN}✓ AD (auto-selected): ${WHITE}${ad}${NC}"
        elif [[ "$_ad_count" -gt 1 ]]; then
            echo -e "${WHITE}Available Availability Domains:${NC}"
            local _ad_idx=0
            declare -A _AD_MAP=()
            while IFS= read -r _ad_name; do
                [[ -z "$_ad_name" ]] && continue
                ((_ad_idx++))
                _AD_MAP[$_ad_idx]="$_ad_name"
                echo -e "  ${YELLOW}${_ad_idx}${NC}) ${WHITE}${_ad_name}${NC}"
            done < <(jq -r '.data[].name' <<< "$_ad_json" 2>/dev/null)
            echo ""
            echo -n -e "${CYAN}Select AD [1]: ${NC}"
            local _ad_pick
            read -r _ad_pick
            [[ -z "$_ad_pick" ]] && _ad_pick=1
            ad="${_AD_MAP[$_ad_pick]:-${_AD_MAP[1]}}"
            echo -e "${GREEN}✓ AD: ${WHITE}${ad}${NC}"
        else
            echo -e "${RED}No availability domains found.${NC}"
            _ui_pause "return"
            return 1
        fi
        echo ""
    fi
    
    # Discover subnets and NSGs if not already set
    local _need_subnet=false _need_nsg=false
    [[ -z "$worker_subnet" ]] && _need_subnet=true
    [[ -z "$worker_nsg" ]] && _need_nsg=true
    
    # Declare outside if-block so data persists for summary name resolution
    local _sub_json="" _nsg_json=""
    local _pod_sub_json="" _pod_nsg_json=""
    
    if [[ "$_need_subnet" == "true" || "$_need_nsg" == "true" ]]; then
        # Determine VCN to search in
        local _vcn_ocid=""
        # For OKE purpose, use VCN from selected cluster first, then fall back to cache
        if [[ "$ic_purpose" == "oke" ]]; then
            if [[ -n "${_oke_vcn_ocid:-}" ]]; then
                _vcn_ocid="$_oke_vcn_ocid"
            else
                _vcn_ocid=$(get_oke_env_value "VCN_OCID" 2>/dev/null)
            fi
        fi
        
        if [[ -z "$_vcn_ocid" || "$_vcn_ocid" == "N/A" ]]; then
            _step_init
            _step_active "VCNs"
            fetch_vcn_list
            local _vcn_count
            _vcn_count=$(get_vcn_count)
            _step_complete "VCNs(${_vcn_count})"
            _step_finish
            
            if [[ "${_vcn_count:-0}" -eq 1 ]]; then
                while IFS='|' read -r _vid _vname _; do
                    [[ "$_vid" =~ ^#.*$ ]] && continue
                    [[ -z "$_vid" ]] && continue
                    _vcn_ocid="$_vid"
                    echo -e "${GREEN}✓ VCN (auto-selected): ${WHITE}${_vname}${NC}"
                    break
                done < "$VCN_LIST_CACHE"
            elif [[ "${_vcn_count:-0}" -gt 1 ]]; then
                echo -e "${WHITE}Available VCNs:${NC}"
                local _vcn_idx=0
                declare -A _VCN_MAP=()
                while IFS='|' read -r _vid _vname _vcidr _; do
                    [[ "$_vid" =~ ^#.*$ ]] && continue
                    [[ -z "$_vid" ]] && continue
                    ((_vcn_idx++))
                    _VCN_MAP[$_vcn_idx]="$_vid"
                    printf "  ${YELLOW}%2d${NC}) %-35s ${GRAY}[%s]${NC}\n" "$_vcn_idx" "$_vname" "$_vcidr"
                done < "$VCN_LIST_CACHE"
                echo ""
                echo -n -e "${CYAN}Select VCN [1]: ${NC}"
                local _vcn_pick
                read -r _vcn_pick
                [[ -z "$_vcn_pick" ]] && _vcn_pick=1
                _vcn_ocid="${_VCN_MAP[$_vcn_pick]:-${_VCN_MAP[1]}}"
            else
                echo -e "${RED}No VCNs found in compartment.${NC}"
                _ui_pause "return"
                return 1
            fi
            echo ""
        fi
        
        # Fetch subnets and NSGs for this VCN (use cache if fresh)
        local _sub_cached="" _nsg_cached=""
        
        # Try OKE_SUBNET_LIST_CACHE for subnets (JSON format)
        if is_cache_fresh "$OKE_SUBNET_LIST_CACHE" 2>/dev/null; then
            _sub_json=$(cat "$OKE_SUBNET_LIST_CACHE" 2>/dev/null)
            if [[ -n "$_sub_json" ]] && jq -e '.data[0]' <<< "$_sub_json" >/dev/null 2>&1; then
                _sub_cached=" cached"
            else
                _sub_json=""
            fi
        fi
        
        # Try NETWORK_RESOURCES_CACHE for NSGs (text format → convert to JSON)
        if [[ -z "$_nsg_json" ]] && is_cache_fresh "$NETWORK_RESOURCES_CACHE" 2>/dev/null; then
            local _nsg_lines
            _nsg_lines=$(grep '^NSG|' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            if [[ -n "$_nsg_lines" ]]; then
                # Convert text format to JSON: NSG|NAME||STATE|OCID|COMPARTMENT_ID
                _nsg_json=$(echo "$_nsg_lines" | awk -F'|' '{printf "{\"id\":\"%s\",\"display-name\":\"%s\",\"lifecycle-state\":\"%s\"}\n", $5, $2, $4}' | jq -s '{data: .}' 2>/dev/null)
                if [[ -n "$_nsg_json" ]] && jq -e '.data[0]' <<< "$_nsg_json" >/dev/null 2>&1; then
                    _nsg_cached=" cached"
                else
                    _nsg_json=""
                fi
            fi
        fi
        
        # Fetch live if cache miss
        if [[ -z "$_sub_json" || -z "$_nsg_json" ]]; then
            _step_init
            local _net_comp="${NETWORK_COMPARTMENT_ID:-$compartment_id}"
            
            if [[ -z "$_sub_json" && -z "$_nsg_json" ]]; then
                # Both stale — fetch in parallel via temp files
                local _ic_sub_tmp _ic_nsg_tmp
                _ic_sub_tmp=$(create_temp_file); _ic_nsg_tmp=$(create_temp_file)
                
                _step_active "subnets+NSGs(2 parallel)"
                (
                    local _s; _s=$(oci network subnet list --vcn-id "$_vcn_ocid" --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
                    if [[ "$_net_comp" != "$compartment_id" ]]; then
                        local _s2; _s2=$(oci network subnet list --vcn-id "$_vcn_ocid" --compartment-id "$_net_comp" --region "$region" --all --output json 2>/dev/null)
                        if [[ -n "$_s2" ]] && jq -e '.data[0]' <<< "$_s2" >/dev/null 2>&1; then
                            _s=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_s $_s2" 2>/dev/null)
                        fi
                    fi
                    echo "$_s" > "$_ic_sub_tmp"
                ) &
                local _sp=$!
                (
                    local _n; _n=$(oci network nsg list --compartment-id "$compartment_id" --vcn-id "$_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                    if [[ "$_net_comp" != "$compartment_id" ]]; then
                        local _n2; _n2=$(oci network nsg list --compartment-id "$_net_comp" --vcn-id "$_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                        if [[ -n "$_n2" ]] && jq -e '.data[0]' <<< "$_n2" >/dev/null 2>&1; then
                            _n=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_n $_n2" 2>/dev/null)
                        fi
                    fi
                    echo "$_n" > "$_ic_nsg_tmp"
                ) &
                local _np=$!
                wait $_sp $_np 2>/dev/null
                _sub_json=$(<"$_ic_sub_tmp"); _nsg_json=$(<"$_ic_nsg_tmp")
                rm -f "$_ic_sub_tmp" "$_ic_nsg_tmp"
                _step_complete "subnets"
                _step_complete "NSGs"
            else
                # Only one stale — fetch sequentially
                if [[ -z "$_sub_json" ]]; then
                    _step_active "subnets"
                    _sub_json=$(oci network subnet list --vcn-id "$_vcn_ocid" --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
                    if [[ "$_net_comp" != "$compartment_id" ]]; then
                        local _sub_json2
                        _sub_json2=$(oci network subnet list --vcn-id "$_vcn_ocid" --compartment-id "$_net_comp" --region "$region" --all --output json 2>/dev/null)
                        if [[ -n "$_sub_json2" ]] && jq -e '.data[0]' <<< "$_sub_json2" >/dev/null 2>&1; then
                            _sub_json=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_sub_json $_sub_json2" 2>/dev/null)
                        fi
                    fi
                    _step_complete "subnets"
                fi
                if [[ -z "$_nsg_json" ]]; then
                    _step_active "NSGs"
                    _nsg_json=$(oci network nsg list --compartment-id "$compartment_id" --vcn-id "$_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                    if [[ "$_net_comp" != "$compartment_id" ]]; then
                        local _nsg_json2
                        _nsg_json2=$(oci network nsg list --compartment-id "$_net_comp" --vcn-id "$_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                        if [[ -n "$_nsg_json2" ]] && jq -e '.data[0]' <<< "$_nsg_json2" >/dev/null 2>&1; then
                            _nsg_json=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_nsg_json $_nsg_json2" 2>/dev/null)
                        fi
                    fi
                    _step_complete "NSGs"
                fi
            fi
            _step_finish
        else
            echo -e "${GREEN}✓ subnets(${_sub_cached}) & NSGs(${_nsg_cached}) from cache${NC}"
        fi
        
        # Select worker subnet
        if [[ "$_need_subnet" == "true" ]]; then
            echo ""
            local _sub_count
            _sub_count=$(jq '.data | length' <<< "$_sub_json" 2>/dev/null || echo 0)
            
            if [[ "$_sub_count" -eq 0 ]]; then
                echo -e "${RED}No subnets found in VCN.${NC}"
                _ui_pause "return"
                return 1
            fi
            
            local _sub_label="Worker Subnet"
            [[ "$ic_purpose" == "normal" ]] && _sub_label="Instance Subnet"
            [[ "$ic_purpose" == "cluster_network" ]] && _sub_label="RDMA Subnet"
            
            # Find likely default by name pattern
            local _sub_default_idx=""
            local _sub_idx=0
            declare -A _SUB_MAP=()
            
            echo -e "${WHITE}Select ${_sub_label}:${NC}"
            while IFS='|' read -r _sid _sname _scidr _saccess; do
                [[ -z "$_sid" ]] && continue
                ((_sub_idx++))
                _SUB_MAP[$_sub_idx]="$_sid"
                local _access_color="$RED"
                [[ "$_saccess" == "Public" ]] && _access_color="$LIGHT_GREEN"
                local _tag=""
                if [[ "$ic_purpose" == "oke" ]] && echo "$_sname" | grep -qi "worker"; then
                    _tag=" ${CYAN}← likely worker${NC}"
                    [[ -z "$_sub_default_idx" ]] && _sub_default_idx=$_sub_idx
                elif [[ "$ic_purpose" == "cluster_network" ]] && echo "$_sname" | grep -qi "rdma\|cluster"; then
                    _tag=" ${CYAN}← likely RDMA${NC}"
                    [[ -z "$_sub_default_idx" ]] && _sub_default_idx=$_sub_idx
                fi
                printf "  ${YELLOW}%2d${NC}) %-35s ${GRAY}[%-15s]${NC} [${_access_color}%-7s${NC}]%b\n" \
                    "$_sub_idx" "$_sname" "$_scidr" "$_saccess" "$_tag"
            done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])|\(.["cidr-block"])|\(if .["prohibit-public-ip-on-vnic"] then "Private" else "Public" end)"' <<< "$_sub_json" 2>/dev/null)
            echo ""
            
            local _sub_default_hint=""
            [[ -n "$_sub_default_idx" ]] && _sub_default_hint="${_sub_default_idx}"
            echo -n -e "${CYAN}Select ${_sub_label} # [${_sub_default_hint:-}]: ${NC}"
            local _sub_pick
            read -r _sub_pick
            [[ -z "$_sub_pick" && -n "$_sub_default_idx" ]] && _sub_pick="$_sub_default_idx"
            
            if [[ -n "${_SUB_MAP[$_sub_pick]:-}" ]]; then
                worker_subnet="${_SUB_MAP[$_sub_pick]}"
                echo -e "${GREEN}✓ ${_sub_label} selected${NC}"
            else
                echo -e "${RED}Invalid selection.${NC}"
                _ui_pause "return"
                return 1
            fi
            echo ""
        fi
        
        # Select worker NSG
        if [[ "$_need_nsg" == "true" ]]; then
            local _nsg_count
            _nsg_count=$(jq '.data | length' <<< "$_nsg_json" 2>/dev/null || echo 0)
            
            local _nsg_label="Worker NSG"
            [[ "$ic_purpose" == "normal" ]] && _nsg_label="Instance NSG"
            [[ "$ic_purpose" == "cluster_network" ]] && _nsg_label="RDMA NSG"
            
            if [[ "$_nsg_count" -eq 0 ]]; then
                echo -e "${YELLOW}No NSGs found. Proceeding without NSG.${NC}"
                worker_nsg=""
            else
                # Find likely default by name pattern
                local _nsg_default_idx=""
                local _nsg_idx=0
                declare -A _NSG_MAP=()
                
                echo -e "${WHITE}Select ${_nsg_label}:${NC}"
                echo -e "  ${YELLOW} 0${NC}) ${GRAY}(none - skip NSG)${NC}"
                while IFS='|' read -r _nid _nname; do
                    [[ -z "$_nid" ]] && continue
                    ((_nsg_idx++))
                    _NSG_MAP[$_nsg_idx]="$_nid"
                    local _tag=""
                    if [[ "$ic_purpose" == "oke" ]] && echo "$_nname" | grep -qi "worker"; then
                        _tag=" ${CYAN}← likely worker${NC}"
                        [[ -z "$_nsg_default_idx" ]] && _nsg_default_idx=$_nsg_idx
                    elif [[ "$ic_purpose" == "cluster_network" ]] && echo "$_nname" | grep -qi "rdma\|cluster"; then
                        _tag=" ${CYAN}← likely RDMA${NC}"
                        [[ -z "$_nsg_default_idx" ]] && _nsg_default_idx=$_nsg_idx
                    fi
                    printf "  ${YELLOW}%2d${NC}) %-40s%b\n" "$_nsg_idx" "$_nname" "$_tag"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$_nsg_json" 2>/dev/null)
                echo ""
                
                local _nsg_default_hint="0=none"
                [[ -n "$_nsg_default_idx" ]] && _nsg_default_hint="${_nsg_default_idx}"
                echo -n -e "${CYAN}Select ${_nsg_label} # [${_nsg_default_hint}]: ${NC}"
                local _nsg_pick
                read -r _nsg_pick
                [[ -z "$_nsg_pick" && -n "$_nsg_default_idx" ]] && _nsg_pick="$_nsg_default_idx"
                [[ -z "$_nsg_pick" ]] && _nsg_pick="0"
                
                if [[ "$_nsg_pick" == "0" ]]; then
                    worker_nsg=""
                    echo -e "${GREEN}✓ No NSG selected${NC}"
                elif [[ -n "${_NSG_MAP[$_nsg_pick]:-}" ]]; then
                    worker_nsg="${_NSG_MAP[$_nsg_pick]}"
                    echo -e "${GREEN}✓ ${_nsg_label} selected${NC}"
                else
                    echo -e "${RED}Invalid selection.${NC}"
                    _ui_pause "return"
                    return 1
                fi
            fi
            echo ""
        fi
    fi
    
    # For non-OKE purposes, set network type (OKE already has it from cluster detection)
    if [[ "$ic_purpose" != "oke" ]]; then
        network_type="standard"
    fi
    
    # Validate pod subnet/NSG when native is selected — discover interactively if missing
    if [[ "$network_type" == "native" ]]; then
        local _need_pod_subnet=false _need_pod_nsg=false
        [[ -z "$pod_subnet" ]] && _need_pod_subnet=true
        [[ -z "$pod_nsg" ]] && _need_pod_nsg=true
        
        if [[ "$_need_pod_subnet" == "true" || "$_need_pod_nsg" == "true" ]]; then
            echo ""
            echo -e "${WHITE}Native pod networking requires pod subnet and NSG selection.${NC}"
            
            # Resolve VCN — use OKE cluster VCN first, then cache
            local _pod_vcn_ocid=""
            if [[ -n "${_oke_vcn_ocid:-}" ]]; then
                _pod_vcn_ocid="$_oke_vcn_ocid"
            else
                _pod_vcn_ocid=$(get_oke_env_value "VCN_OCID" 2>/dev/null)
            fi
            
            if [[ -z "$_pod_vcn_ocid" || "$_pod_vcn_ocid" == "N/A" ]]; then
                _step_init
                _step_active "VCNs"
                fetch_vcn_list
                local _pod_vcn_count
                _pod_vcn_count=$(get_vcn_count)
                _step_complete "VCNs(${_pod_vcn_count})"
                _step_finish
                
                if [[ "${_pod_vcn_count:-0}" -eq 1 ]]; then
                    while IFS='|' read -r _pvid _; do
                        [[ "$_pvid" =~ ^#.*$ ]] && continue
                        [[ -z "$_pvid" ]] && continue
                        _pod_vcn_ocid="$_pvid"
                        break
                    done < "$VCN_LIST_CACHE"
                elif [[ "${_pod_vcn_count:-0}" -gt 1 ]]; then
                    echo -e "${WHITE}Select VCN for pod networking:${NC}"
                    local _pv_idx=0
                    declare -A _POD_VCN_MAP=()
                    while IFS='|' read -r _pvid _pvname _pvcidr _; do
                        [[ "$_pvid" =~ ^#.*$ ]] && continue
                        [[ -z "$_pvid" ]] && continue
                        ((_pv_idx++))
                        _POD_VCN_MAP[$_pv_idx]="$_pvid"
                        printf "  ${YELLOW}%2d${NC}) %-35s ${GRAY}[%s]${NC}\n" "$_pv_idx" "$_pvname" "$_pvcidr"
                    done < "$VCN_LIST_CACHE"
                    echo ""
                    echo -n -e "${CYAN}Select VCN [1]: ${NC}"
                    local _pv_pick
                    read -r _pv_pick
                    [[ -z "$_pv_pick" ]] && _pv_pick=1
                    _pod_vcn_ocid="${_POD_VCN_MAP[$_pv_pick]:-${_POD_VCN_MAP[1]}}"
                else
                    echo -e "${RED}No VCNs found.${NC}"
                    _ui_pause "return"
                    return 1
                fi
            fi
            
            # Fetch subnets and NSGs (reuse worker data if same VCN, else use cache/live)
            local _pod_net_comp="${NETWORK_COMPARTMENT_ID:-$compartment_id}"
            local _pod_sub_cached="" _pod_nsg_cached=""
            
            # If same VCN as worker, reuse the already-fetched data
            if [[ "$_pod_vcn_ocid" == "${_vcn_ocid:-}" && -n "$_sub_json" ]]; then
                _pod_sub_json="$_sub_json"
                _pod_nsg_json="$_nsg_json"
                _pod_sub_cached=" reused"
                _pod_nsg_cached=" reused"
                echo -e "${GREEN}✓ Reusing subnet & NSG data from worker VCN${NC}"
            else
                # Try caches
                if is_cache_fresh "$OKE_SUBNET_LIST_CACHE" 2>/dev/null; then
                    _pod_sub_json=$(cat "$OKE_SUBNET_LIST_CACHE" 2>/dev/null)
                    [[ -n "$_pod_sub_json" ]] && jq -e '.data[0]' <<< "$_pod_sub_json" >/dev/null 2>&1 && _pod_sub_cached=" cached"
                    [[ -z "$_pod_sub_cached" ]] && _pod_sub_json=""
                fi
                if is_cache_fresh "$NETWORK_RESOURCES_CACHE" 2>/dev/null; then
                    local _pnsg_lines
                    _pnsg_lines=$(grep '^NSG|' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
                    if [[ -n "$_pnsg_lines" ]]; then
                        _pod_nsg_json=$(echo "$_pnsg_lines" | awk -F'|' '{printf "{\"id\":\"%s\",\"display-name\":\"%s\",\"lifecycle-state\":\"%s\"}\n", $5, $2, $4}' | jq -s '{data: .}' 2>/dev/null)
                        [[ -n "$_pod_nsg_json" ]] && jq -e '.data[0]' <<< "$_pod_nsg_json" >/dev/null 2>&1 && _pod_nsg_cached=" cached"
                        [[ -z "$_pod_nsg_cached" ]] && _pod_nsg_json=""
                    fi
                fi
                
                # Fetch live if needed
                if [[ -z "$_pod_sub_json" || -z "$_pod_nsg_json" ]]; then
                    _step_init
                    if [[ -z "$_pod_sub_json" && -z "$_pod_nsg_json" ]]; then
                        # Both stale — fetch in parallel via temp files
                        local _ps_tmp _pn_tmp
                        _ps_tmp=$(create_temp_file); _pn_tmp=$(create_temp_file)
                        
                        _step_active "pod subnets+NSGs(2 parallel)"
                        (
                            local _s; _s=$(oci network subnet list --vcn-id "$_pod_vcn_ocid" --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
                            if [[ "$_pod_net_comp" != "$compartment_id" ]]; then
                                local _s2; _s2=$(oci network subnet list --vcn-id "$_pod_vcn_ocid" --compartment-id "$_pod_net_comp" --region "$region" --all --output json 2>/dev/null)
                                if [[ -n "$_s2" ]] && jq -e '.data[0]' <<< "$_s2" >/dev/null 2>&1; then
                                    _s=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_s $_s2" 2>/dev/null)
                                fi
                            fi
                            echo "$_s" > "$_ps_tmp"
                        ) &
                        local _psp=$!
                        (
                            local _n; _n=$(oci network nsg list --compartment-id "$compartment_id" --vcn-id "$_pod_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                            if [[ "$_pod_net_comp" != "$compartment_id" ]]; then
                                local _n2; _n2=$(oci network nsg list --compartment-id "$_pod_net_comp" --vcn-id "$_pod_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                                if [[ -n "$_n2" ]] && jq -e '.data[0]' <<< "$_n2" >/dev/null 2>&1; then
                                    _n=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_n $_n2" 2>/dev/null)
                                fi
                            fi
                            echo "$_n" > "$_pn_tmp"
                        ) &
                        local _pnp=$!
                        wait $_psp $_pnp 2>/dev/null
                        _pod_sub_json=$(<"$_ps_tmp"); _pod_nsg_json=$(<"$_pn_tmp")
                        rm -f "$_ps_tmp" "$_pn_tmp"
                        _step_complete "pod subnets"
                        _step_complete "pod NSGs"
                    else
                        if [[ -z "$_pod_sub_json" ]]; then
                            _step_active "pod subnets"
                            _pod_sub_json=$(oci network subnet list --vcn-id "$_pod_vcn_ocid" --compartment-id "$compartment_id" --region "$region" --all --output json 2>/dev/null)
                            if [[ "$_pod_net_comp" != "$compartment_id" ]]; then
                                local _pod_sub_json2
                                _pod_sub_json2=$(oci network subnet list --vcn-id "$_pod_vcn_ocid" --compartment-id "$_pod_net_comp" --region "$region" --all --output json 2>/dev/null)
                                if [[ -n "$_pod_sub_json2" ]] && jq -e '.data[0]' <<< "$_pod_sub_json2" >/dev/null 2>&1; then
                                    _pod_sub_json=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_pod_sub_json $_pod_sub_json2" 2>/dev/null)
                                fi
                            fi
                            _step_complete "pod subnets"
                        fi
                        if [[ -z "$_pod_nsg_json" ]]; then
                            _step_active "pod NSGs"
                            _pod_nsg_json=$(oci network nsg list --compartment-id "$compartment_id" --vcn-id "$_pod_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                            if [[ "$_pod_net_comp" != "$compartment_id" ]]; then
                                local _pod_nsg_json2
                                _pod_nsg_json2=$(oci network nsg list --compartment-id "$_pod_net_comp" --vcn-id "$_pod_vcn_ocid" --region "$region" --all --output json 2>/dev/null)
                                if [[ -n "$_pod_nsg_json2" ]] && jq -e '.data[0]' <<< "$_pod_nsg_json2" >/dev/null 2>&1; then
                                    _pod_nsg_json=$(jq -s '{ data: (.[0].data + .[1].data) | unique_by(.id) }' <<< "$_pod_nsg_json $_pod_nsg_json2" 2>/dev/null)
                                fi
                            fi
                            _step_complete "pod NSGs"
                        fi
                    fi
                    _step_finish
                else
                    echo -e "${GREEN}✓ pod subnets(${_pod_sub_cached}) & NSGs(${_pod_nsg_cached}) from cache${NC}"
                fi
            fi
            
            # Select pod subnet
            if [[ "$_need_pod_subnet" == "true" ]]; then
                echo ""
                echo -e "${WHITE}Select Pod Subnet:${NC}"
                local _ps_idx=0 _ps_default_idx=""
                declare -A _POD_SUB_MAP=()
                while IFS='|' read -r _psid _psname _pscidr _psaccess; do
                    [[ -z "$_psid" ]] && continue
                    ((_ps_idx++))
                    _POD_SUB_MAP[$_ps_idx]="$_psid"
                    local _access_color="$RED"
                    [[ "$_psaccess" == "Public" ]] && _access_color="$LIGHT_GREEN"
                    local _tag=""
                    if echo "$_psname" | grep -qi "pod"; then
                        _tag=" ${CYAN}← likely pod subnet${NC}"
                        [[ -z "$_ps_default_idx" ]] && _ps_default_idx=$_ps_idx
                    fi
                    printf "  ${YELLOW}%2d${NC}) %-35s ${GRAY}[%-15s]${NC} [${_access_color}%-7s${NC}]%b\n" \
                        "$_ps_idx" "$_psname" "$_pscidr" "$_psaccess" "$_tag"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])|\(.["cidr-block"])|\(if .["prohibit-public-ip-on-vnic"] then "Private" else "Public" end)"' <<< "$_pod_sub_json" 2>/dev/null)
                echo ""
                
                local _ps_default_hint=""
                [[ -n "$_ps_default_idx" ]] && _ps_default_hint="${_ps_default_idx}"
                echo -n -e "${CYAN}Select Pod Subnet # [${_ps_default_hint:-}]: ${NC}"
                local _ps_pick
                read -r _ps_pick
                [[ -z "$_ps_pick" && -n "$_ps_default_idx" ]] && _ps_pick="$_ps_default_idx"
                
                if [[ -n "${_POD_SUB_MAP[$_ps_pick]:-}" ]]; then
                    pod_subnet="${_POD_SUB_MAP[$_ps_pick]}"
                    echo -e "${GREEN}✓ Pod Subnet selected${NC}"
                else
                    echo -e "${RED}Invalid selection.${NC}"
                    _ui_pause "return"
                    return 1
                fi
            fi
            
            # Select pod NSG
            if [[ "$_need_pod_nsg" == "true" ]]; then
                echo ""
                echo -e "${WHITE}Select Pod NSG:${NC}"
                local _pn_idx=0 _pn_default_idx=""
                declare -A _POD_NSG_MAP=()
                echo -e "  ${YELLOW} 0${NC}) ${GRAY}(none - skip NSG)${NC}"
                while IFS='|' read -r _pnid _pnname; do
                    [[ -z "$_pnid" ]] && continue
                    ((_pn_idx++))
                    _POD_NSG_MAP[$_pn_idx]="$_pnid"
                    local _tag=""
                    if echo "$_pnname" | grep -qi "pod"; then
                        _tag=" ${CYAN}← likely pod NSG${NC}"
                        [[ -z "$_pn_default_idx" ]] && _pn_default_idx=$_pn_idx
                    fi
                    printf "  ${YELLOW}%2d${NC}) %-40s%b\n" "$_pn_idx" "$_pnname" "$_tag"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$_pod_nsg_json" 2>/dev/null)
                echo ""
                
                local _pn_default_hint="0=none"
                [[ -n "$_pn_default_idx" ]] && _pn_default_hint="${_pn_default_idx}"
                echo -n -e "${CYAN}Select Pod NSG # [${_pn_default_hint}]: ${NC}"
                local _pn_pick
                read -r _pn_pick
                [[ -z "$_pn_pick" && -n "$_pn_default_idx" ]] && _pn_pick="$_pn_default_idx"
                [[ -z "$_pn_pick" ]] && _pn_pick="0"
                
                if [[ "$_pn_pick" == "0" ]]; then
                    pod_nsg=""
                    echo -e "${GREEN}✓ No pod NSG selected${NC}"
                elif [[ -n "${_POD_NSG_MAP[$_pn_pick]:-}" ]]; then
                    pod_nsg="${_POD_NSG_MAP[$_pn_pick]}"
                    echo -e "${GREEN}✓ Pod NSG selected${NC}"
                else
                    echo -e "${RED}Invalid selection.${NC}"
                    _ui_pause "return"
                    return 1
                fi
            fi
        fi
    fi
    
    # ========== STEP 1: Cloud-init file selection ==========
    _ui_subheader "Step 1: Cloud-Init Configuration" 0
    echo ""
    
    local cloud_init_file="cloud-init.yml"
    local cwd
    cwd=$(pwd)
    
    # Check for cloud-init files in current directory (using associative array to avoid duplicates)
    declare -A found_files_map
    local found_files=()
    
    # First pass: collect all matching files, using basename as key to prevent duplicates
    for f in "$cwd"/*.yml "$cwd"/*.yaml "$cwd"/cloud-init*; do
        [[ -f "$f" ]] || continue
        local bname
        bname=$(basename "$f")
        # Only add if not already in map
        if [[ -z "${found_files_map[$bname]:-}" ]]; then
            found_files_map[$bname]="$f"
            found_files+=("$f")
        fi
    done
    
    if [[ ${#found_files[@]} -gt 0 ]]; then
        echo -e "${WHITE}Found cloud-init files in current directory ($cwd):${NC}"
        local idx=0
        for f in "${found_files[@]}"; do
            ((idx++))
            local fname
            fname=$(basename "$f")
            echo -e "  ${YELLOW}${idx}${NC}) $fname"
        done
        echo ""
    fi
    
    echo -n -e "${CYAN}Enter cloud-init file path [${cloud_init_file}]: ${NC}"
    local input_file
    read -r input_file
    
    # Handle numeric selection
    if [[ "$input_file" =~ ^[0-9]+$ ]] && [[ $input_file -ge 1 ]] && [[ $input_file -le ${#found_files[@]} ]]; then
        cloud_init_file="${found_files[$((input_file-1))]}"
    elif [[ -n "$input_file" ]]; then
        cloud_init_file="$input_file"
    fi
    
    # Validate file exists
    if [[ ! -f "$cloud_init_file" ]]; then
        echo -e "${RED}Error: Cloud-init file not found: ${cloud_init_file}${NC}"
        _ui_pause "return"
        return 1
    fi
    
    echo ""
    echo -e "${GREEN}✓ Cloud-init: ${WHITE}${cloud_init_file}${NC}"
    
    # ========== STEP 2: Image Selection (before shape) ==========
    echo ""
    _ui_subheader "Step 2: Image Selection" 0
    echo ""
    
    _step_init
    _step_active "images"
    
    # Fetch custom images from cache if fresh, else live
    local custom_only_json="" _img_custom_cached=""
    if is_cache_fresh "$CUSTOM_IMAGE_CACHE" 2>/dev/null && [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
        custom_only_json=$(cat "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
        if [[ -n "$custom_only_json" ]] && jq -e '.data[0]' <<< "$custom_only_json" >/dev/null 2>&1; then
            _img_custom_cached=" cached"
        else
            custom_only_json=""
        fi
    fi
    
    # If no cache, fetch from live (custom images only — compartment-scoped)
    if [[ -z "$custom_only_json" ]] || ! jq -e '.data' <<< "$custom_only_json" >/dev/null 2>&1; then
        local _live_images_json
        _live_images_json=$(oci compute image list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --lifecycle-state "AVAILABLE" \
            --sort-by "TIMECREATED" \
            --sort-order "DESC" \
            --all \
            --output json 2>/dev/null)
        if [[ -n "$_live_images_json" ]] && jq -e '.data' <<< "$_live_images_json" >/dev/null 2>&1; then
            custom_only_json=$(jq --arg cid "$compartment_id" \
                '{ data: [.data[] | select(.["compartment-id"] == $cid)] }' <<< "$_live_images_json" 2>/dev/null)
        fi
        [[ -z "$custom_only_json" ]] && custom_only_json='{"data":[]}'
    fi
    _step_complete "images(custom${_img_custom_cached})"
    _step_finish
    
    local custom_count=0
    [[ -n "$custom_only_json" ]] && custom_count=$(jq -r '.data | length' <<< "$custom_only_json" 2>/dev/null) || custom_count=0
    [[ ! "$custom_count" =~ ^[0-9]+$ ]] && custom_count=0
    
    # Resolve default IMAGE_ID name if set
    local default_image_name=""
    if [[ -n "$image_id" ]]; then
        default_image_name=$(resolve_image_name_cached "$image_id")
        [[ "$default_image_name" == "N/A" ]] && default_image_name=""
    fi
    
    # Image selection loop — default: custom only, 'a' expands to platform
    local _show_platform=false
    local images_json='{"data":[]}' images_count=0
    
    while true; do
        echo ""
        echo -e "${WHITE}Available Images in Compartment (${CYAN}${region}${WHITE}):${NC}"
        echo ""
        
        declare -a IMAGE_LIST=()
        declare -A IMAGE_NAME_MAP=()
        local img_idx=0
        
        printf "  ${GRAY}%-4s %-105s %-20s${NC}\n" "#" "Image Name" "OS Version"
        echo -e "  ${GRAY}$(printf '─%.0s' {1..135})${NC}"
        
        # Custom images (always shown)
        if [[ $custom_count -gt 0 ]]; then
            echo -e "  ${MAGENTA}${BOLD}Custom Images (${custom_count})${NC}"
            while IFS='|' read -r img_ocid img_name img_os img_os_ver; do
                [[ -z "$img_ocid" ]] && continue
                ((img_idx++))
                IMAGE_LIST+=("$img_ocid")
                IMAGE_NAME_MAP["$img_ocid"]="$img_name"
                printf "  ${YELLOW}%-4s${NC} ${MAGENTA}%-105s${NC} ${CYAN}%-20s${NC}\n" "${img_idx})" "$img_name" "$img_os_ver"
            done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "N/A")|\(.["operating-system"] // "N/A")|\(.["operating-system-version"] // "N/A")"' <<< "$custom_only_json" 2>/dev/null)
            echo ""
        elif [[ "$_show_platform" == "false" ]]; then
            echo -e "  ${GRAY}No custom images found${NC}"
            echo ""
        fi
        
        # Platform images (only shown when expanded)
        if [[ "$_show_platform" == "true" ]]; then
            if [[ $images_count -gt 0 ]]; then
                echo -e "  ${WHITE}${BOLD}Platform Images (${images_count})${NC}"
                while IFS='|' read -r img_ocid img_name img_os img_os_ver; do
                    [[ -z "$img_ocid" ]] && continue
                    ((img_idx++))
                    IMAGE_LIST+=("$img_ocid")
                    IMAGE_NAME_MAP["$img_ocid"]="$img_name"
                    printf "  ${YELLOW}%-4s${NC} ${WHITE}%-105s${NC} ${CYAN}%-20s${NC}\n" "${img_idx})" "$img_name" "$img_os_ver"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "N/A")|\(.["operating-system"] // "N/A")|\(.["operating-system-version"] // "N/A")"' <<< "$images_json" 2>/dev/null)
            else
                echo -e "  ${GRAY}No platform images found${NC}"
            fi
            echo ""
        fi
        
        echo ""
        if [[ "$_show_platform" == "false" ]]; then
            echo -e "  ${GREEN}a${NC}) ${WHITE}Show Platform Images${NC} ${GRAY}(Oracle-provided OS images)${NC}"
        fi
        echo -e "  ${GREEN}p${NC}) ${WHITE}Paste image OCID${NC} ${GRAY}(if desired image not listed)${NC}"
        if [[ -n "$image_id" ]]; then
            echo -e "  ${GREEN}0${NC}) ${WHITE}Use pre-set IMAGE_ID${NC}: ${CYAN}${default_image_name:-Unknown}${NC} ${GRAY}(${YELLOW}...${image_id: -25}${GRAY})${NC}"
        fi
        echo ""
        echo -n -e "${CYAN}Select image [1]: ${NC}"
        local img_choice
        read -r img_choice
        
        [[ -z "$img_choice" ]] && img_choice="1"
        
        # Show Platform Images on demand
        if [[ "$img_choice" == "a" || "$img_choice" == "A" ]]; then
            if [[ "$_show_platform" == "false" ]]; then
                echo -e "  ${WHITE}Fetching platform images...${NC}"
                local _platform_json
                _platform_json=$(oci compute image list \
                    --compartment-id "$compartment_id" \
                    --region "$region" \
                    --lifecycle-state "AVAILABLE" \
                    --sort-by "TIMECREATED" \
                    --sort-order "DESC" \
                    --all \
                    --output json 2>/dev/null)
                if [[ -n "$_platform_json" ]] && jq -e '.data' <<< "$_platform_json" >/dev/null 2>&1; then
                    images_json=$(jq --arg cid "$compartment_id" \
                        '{ data: [.data[] | select(.["compartment-id"] != $cid)] }' <<< "$_platform_json" 2>/dev/null)
                    images_count=$(jq -r '.data | length' <<< "$images_json" 2>/dev/null) || images_count=0
                    [[ ! "$images_count" =~ ^[0-9]+$ ]] && images_count=0
                fi
                _show_platform=true
            fi
            continue  # Re-render with platform images visible
        fi
        
        if [[ "$img_choice" == "p" || "$img_choice" == "P" ]]; then
            echo -n -e "${CYAN}Paste image OCID: ${NC}"
            local _pasted_ocid
            read -r _pasted_ocid
            if [[ "$_pasted_ocid" == ocid1.image.* ]]; then
                image_id="$_pasted_ocid"
                local _pasted_name
                _pasted_name=$(oci compute image get --image-id "$image_id" --region "$region" --query 'data."display-name"' --raw-output 2>/dev/null || echo "")
                echo -e "${GREEN}✓ Image: ${CYAN}${_pasted_name:-$image_id}${NC}"
                break
            else
                echo -e "${RED}Invalid OCID format.${NC}"
                _ui_pause "return"
                return 1
            fi
        elif [[ "$img_choice" == "0" ]] && [[ -n "$image_id" ]]; then
            echo -e "${GREEN}✓ Using pre-set image: ${CYAN}${default_image_name:-...${image_id: -30}}${NC}"
            break
        elif [[ "$img_choice" =~ ^[0-9]+$ ]] && [[ $img_choice -ge 1 ]] && [[ $img_choice -le ${#IMAGE_LIST[@]} ]]; then
            image_id="${IMAGE_LIST[$((img_choice-1))]}"
            local selected_img_name="${IMAGE_NAME_MAP[$image_id]:-}"
            [[ -z "$selected_img_name" ]] && selected_img_name=$(resolve_image_name_cached "$image_id")
            echo -e "${GREEN}✓ Selected image: ${CYAN}${selected_img_name}${NC}"
            break
        else
            echo -e "${RED}Invalid selection.${NC}"
            sleep 1
            continue
        fi
    done
    echo ""
    
    # ========== STEP 3: Shape Selection + Enablement Check ==========
    echo ""
    _ui_subheader "Step 3: Instance Shape" 0
    echo ""
    
    # Discover shapes: available in region + compatible with image (parallel)
    _step_init
    local _sh_tmp _co_tmp
    _sh_tmp=$(create_temp_file); _co_tmp=$(create_temp_file)
    
    _step_active "shapes+compat(2 parallel)"
    ( oci compute shape list \
        --compartment-id "$compartment_id" \
        --availability-domain "$ad" \
        --region "$region" \
        --image-id "$image_id" \
        --all --output json > "$_sh_tmp" 2>/dev/null ) &
    local _shp=$!
    ( oci compute image-shape-compatibility-entry list \
        --image-id "$image_id" \
        --region "$region" \
        --output json > "$_co_tmp" 2>/dev/null ) &
    local _cop=$!
    wait $_shp $_cop 2>/dev/null
    
    local _shapes_json _compat_json
    _shapes_json=$(<"$_sh_tmp"); _compat_json=$(<"$_co_tmp")
    rm -f "$_sh_tmp" "$_co_tmp"
    _step_complete "available shapes"
    _step_complete "image shape compatibility"
    _step_finish
    
    # Build compatibility set
    declare -A _IMG_COMPAT_SET=()
    if [[ -n "$_compat_json" ]] && jq -e '.data' <<< "$_compat_json" >/dev/null 2>&1; then
        while read -r _cs; do
            [[ -n "$_cs" ]] && _IMG_COMPAT_SET["$_cs"]=1
        done < <(jq -r '.data[].shape' <<< "$_compat_json" 2>/dev/null | sort)
    fi
    
    # Build shape lists by category using centralized function
    local -a _s4_vm=() _s4_vm_old=() _s4_bm=() _s4_bm_old=() _s4_bm_gpu=() _s4_vm_gpu=()
    local _s4_idx=0
    
    if [[ -n "$_shapes_json" ]] && jq -e '.data[0]' <<< "$_shapes_json" >/dev/null 2>&1; then
        _shapes_categorize "$_shapes_json" "_IMG_COMPAT_SET" \
            _s4_vm _s4_vm_old _s4_bm _s4_bm_old _s4_bm_gpu _s4_vm_gpu \
            _s4_idx
    fi
    
    # Shape display+selection loop
    local shape_name="${SHAPE_NAME:-BM.GPU.H100.8}"
    
    echo -e "  ${GRAY}${_s4_idx} shapes available in ${WHITE}${ad}${GRAY} for this image${NC}"
    
    _SC_SELECTED=""
    _shapes_render_compat select \
        _s4_vm _s4_vm_old _s4_bm _s4_bm_old _s4_bm_gpu _s4_vm_gpu \
        "$_s4_idx" "$shape_name"
    
    if [[ -n "$_SC_SELECTED" ]]; then
        shape_name="$_SC_SELECTED"
    fi
    echo -e "${GREEN}✓ Shape: ${WHITE}${shape_name}${NC}"
    
    # ── Shape enablement check ──
    # Check if shape was in the shapes_json we already fetched
    local _shape_found=false
    if [[ -n "$_shapes_json" ]] && jq -e '.data' <<< "$_shapes_json" >/dev/null 2>&1; then
        local _match
        _match=$(jq -r --arg s "$shape_name" '.data[] | select(.shape == $s) | .shape' <<< "$_shapes_json" 2>/dev/null | head -1)
        [[ "$_match" == "$shape_name" ]] && _shape_found=true
    fi
    
    if [[ "$_shape_found" == "false" ]]; then
        echo ""
        echo -e "${RED}⚠ Shape ${WHITE}${shape_name}${RED} is not currently enabled/available${NC}"
        echo -e "${GRAY}  in AD ${WHITE}${ad}${GRAY} with the selected image.${NC}"
        echo ""
        echo -e "${WHITE}This may mean:${NC}"
        echo -e "  ${GRAY}•${NC} The shape needs to be enabled for your tenancy (contact Oracle support)"
        echo -e "  ${GRAY}•${NC} The shape is not available in this AD"
        echo -e "  ${GRAY}•${NC} The image is not compatible with this shape"
        echo ""
        echo -e "  ${GREEN}1${NC}) ${WHITE}Continue anyway${NC}     ${GRAY}(shape may become available or is not yet listed)${NC}"
        echo -e "  ${GREEN}2${NC}) ${WHITE}List available shapes${NC} ${GRAY}(see what's enabled for this image)${NC}"
        echo -e "  ${YELLOW}4${NC}) ${WHITE}Add shape to image${NC}   ${GRAY}(add ${shape_name} to image compatibility list)${NC}"
        echo -e "  ${RED}3${NC}) ${WHITE}Cancel${NC}"
        echo ""
        echo -n -e "${CYAN}Select [1]: ${NC}"
        local _shape_act
        read -r _shape_act
        
        case "${_shape_act:-1}" in
            2)
                echo ""
                echo -e "${WHITE}Available shapes for selected image in ${CYAN}${ad}${WHITE}:${NC}"
                echo ""
                
                # Build numbered selection list
                local _shape_idx=0
                declare -A _SHAPE_SEL_MAP=()
                
                # GPU shapes first
                local _has_gpu=false
                while IFS='|' read -r _sname _socpu _smem; do
                    [[ -z "$_sname" ]] && continue
                    [[ "$_sname" != *GPU* ]] && continue
                    if [[ "$_has_gpu" == "false" ]]; then
                        echo -e "  ${WHITE}GPU Shapes:${NC}"
                        _has_gpu=true
                    fi
                    ((_shape_idx++))
                    _SHAPE_SEL_MAP[$_shape_idx]="$_sname"
                    printf "  ${YELLOW}%-4s${NC} ${YELLOW}%-40s${NC} %10s %12s\n" "${_shape_idx})" "$_sname" "$_socpu" "$_smem"
                done < <(jq -r '.data[] | "\(.shape)|\(.ocpus // "N/A")|\(.["memory-in-gbs"] // "N/A")"' <<< "$_shapes_json" 2>/dev/null | sort)
                
                # BM shapes (non-GPU)
                local _has_bm=false
                while IFS='|' read -r _sname _socpu _smem; do
                    [[ -z "$_sname" ]] && continue
                    [[ "$_sname" == *GPU* ]] && continue
                    [[ "$_sname" != BM.* ]] && continue
                    if [[ "$_has_bm" == "false" ]]; then
                        echo -e "  ${WHITE}BM Shapes:${NC}"
                        _has_bm=true
                    fi
                    ((_shape_idx++))
                    _SHAPE_SEL_MAP[$_shape_idx]="$_sname"
                    printf "  ${GREEN}%-4s${NC} ${WHITE}%-40s${NC} %10s %12s\n" "${_shape_idx})" "$_sname" "$_socpu" "$_smem"
                done < <(jq -r '.data[] | "\(.shape)|\(.ocpus // "N/A")|\(.["memory-in-gbs"] // "N/A")"' <<< "$_shapes_json" 2>/dev/null | sort)
                
                # VM shapes
                local _has_vm=false
                while IFS='|' read -r _sname _socpu _smem; do
                    [[ -z "$_sname" ]] && continue
                    [[ "$_sname" == *GPU* ]] && continue
                    [[ "$_sname" != VM.* ]] && continue
                    if [[ "$_has_vm" == "false" ]]; then
                        echo -e "  ${WHITE}VM Shapes:${NC}"
                        _has_vm=true
                    fi
                    ((_shape_idx++))
                    _SHAPE_SEL_MAP[$_shape_idx]="$_sname"
                    printf "  ${CYAN}%-4s${NC} ${WHITE}%-40s${NC} %10s %12s\n" "${_shape_idx})" "$_sname" "$_socpu" "$_smem"
                done < <(jq -r '.data[] | "\(.shape)|\(.ocpus // "N/A")|\(.["memory-in-gbs"] // "N/A")"' <<< "$_shapes_json" 2>/dev/null | sort)
                
                echo ""
                echo -e "  ${GRAY}0${NC}) Keep original: ${WHITE}${shape_name}${NC}"
                echo ""
                echo -n -e "${CYAN}Select shape [0=keep ${shape_name}]: ${NC}"
                local _shape_sel
                read -r _shape_sel
                
                if [[ -n "$_shape_sel" && "$_shape_sel" != "0" && -n "${_SHAPE_SEL_MAP[$_shape_sel]}" ]]; then
                    shape_name="${_SHAPE_SEL_MAP[$_shape_sel]}"
                    _shape_found=true
                    echo -e "${GREEN}✓ Shape: ${WHITE}${shape_name}${NC}"
                else
                    echo -e "${YELLOW}⚠ Continuing with: ${WHITE}${shape_name}${NC}"
                fi
                ;;
            3)
                echo -e "${YELLOW}Cancelled.${NC}"
                _ui_pause "return"
                return 0
                ;;
            4)
                echo ""
                local _compat_log="${LOGS_DIR}/custom_images_actions.log"
                mkdir -p "$(dirname "$_compat_log")" 2>/dev/null
                
                local _add_cmd="oci compute image-shape-compatibility-entry add --image-id \"$image_id\" --shape-name \"$shape_name\" --region \"$region\""
                echo -e "  ${WHITE}$ ${_add_cmd}${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $_add_cmd" >> "$_compat_log"
                
                local _add_result
                _add_result=$(oci compute image-shape-compatibility-entry add \
                    --image-id "$image_id" \
                    --shape-name "$shape_name" \
                    --region "$region" \
                    --output json 2>&1)

                if echo "$_add_result" | jq -e '.data' >/dev/null 2>&1 || [[ -z "$_add_result" ]]; then
                    echo -e "  ${GREEN}✓ Added shape compatibility: ${WHITE}${shape_name}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Added shape compat ${shape_name} to image ${image_id}" >> "$_compat_log"
                    
                    # Re-verify shape availability after adding
                    echo ""
                    _step_init
                    _step_active "re-checking shape availability"
                    _shapes_json=$(oci compute shape list \
                        --compartment-id "$compartment_id" \
                        --availability-domain "$ad" \
                        --image-id "$image_id" \
                        --region "$region" \
                        --all --output json 2>/dev/null)
                    _step_complete "re-checking shape availability"
                    _step_finish
                    
                    local _rematch
                    _rematch=$(jq -r --arg s "$shape_name" '.data[] | select(.shape == $s) | .shape' <<< "$_shapes_json" 2>/dev/null | head -1)
                    if [[ "$_rematch" == "$shape_name" ]]; then
                        _shape_found=true
                        echo -e "${GREEN}✓ Shape ${WHITE}${shape_name}${GREEN} is now available${NC}"
                    else
                        echo -e "${YELLOW}⚠ Shape added to compatibility but still not showing as available.${NC}"
                        echo -e "${GRAY}  This may take a moment to propagate, or the shape may not be enabled in this AD.${NC}"
                    fi
                else
                    echo -e "  ${RED}✗ Failed to add shape compatibility${NC}"
                    echo -e "  ${GRAY}${_add_result}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: ${shape_name} — ${_add_result}" >> "$_compat_log"
                fi
                ;;
            *) ;; # Continue anyway
        esac
        if [[ "$_shape_found" == "false" ]]; then
            echo -e "${YELLOW}⚠ Continuing with unverified shape: ${WHITE}${shape_name}${NC}"
        fi
    else
        echo -e "${GREEN}✓ Shape ${WHITE}${shape_name}${GREEN} is available in ${WHITE}${ad}${NC}"
    fi
    
    # Flex shape config - detect and prompt for OCPUs and Memory
    local flex_ocpus=""
    local flex_memory_gb=""
    local is_flex_shape=false
    
    if [[ "$shape_name" == *".Flex"* || "$shape_name" == *".Flex" ]]; then
        is_flex_shape=true
        echo ""
        _ui_subheader "Step 4a: Flex Shape Configuration" 0
        echo ""
        echo -e "${WHITE}Flex shapes require OCPU and Memory configuration.${NC}"
        echo ""
        
        # OCPUs
        echo -n -e "${CYAN}Number of OCPUs [2]: ${NC}"
        local ocpu_input
        read -r ocpu_input
        flex_ocpus="${ocpu_input:-2}"
        if ! [[ "$flex_ocpus" =~ ^[0-9]+$ ]] || [[ "$flex_ocpus" -lt 1 ]]; then
            echo -e "${YELLOW}Invalid value, using default: 2${NC}"
            flex_ocpus="2"
        fi
        echo -e "${GREEN}✓ OCPUs: ${WHITE}${flex_ocpus}${NC}"
        
        # Memory - default is 16x OCPUs for E5.Flex (max ratio)
        local default_memory=$((flex_ocpus * 16))
        echo -e "${GRAY}  Memory range: 1 GB to ${flex_ocpus} x 64 GB (max $((flex_ocpus * 64)) GB)${NC}"
        echo -n -e "${CYAN}Memory in GB [${default_memory}]: ${NC}"
        local mem_input
        read -r mem_input
        flex_memory_gb="${mem_input:-$default_memory}"
        if ! [[ "$flex_memory_gb" =~ ^[0-9]+$ ]] || [[ "$flex_memory_gb" -lt 1 ]]; then
            echo -e "${YELLOW}Invalid value, using default: ${default_memory}${NC}"
            flex_memory_gb="$default_memory"
        fi
        echo -e "${GREEN}✓ Memory: ${WHITE}${flex_memory_gb} GB${NC}"
    fi
    echo ""
    
    # ========== STEP 4b: GPU RDMA Cluster Configuration ==========
    local is_gpu_rdma_cluster="false"
    local _is_gpu_shape="false"
    [[ "$shape_name" == *GPU* || "$shape_name" == *HPC* ]] && _is_gpu_shape="true"
    
    if [[ "$_is_gpu_shape" == "true" || "$ic_purpose" == "cluster_network" ]]; then
        echo ""
        _ui_subheader "Step 4b: GPU RDMA Cluster" 0
        echo ""
        echo -e "${WHITE}Is this for a GPU RDMA cluster?${NC}"
        echo -e "${GRAY}  Always enabled: Custom Logs Monitoring, Compute Instance Run Command,${NC}"
        echo -e "${GRAY}                  Compute Instance Monitoring${NC}"
        echo -e "${GRAY}  GPU RDMA adds:  Compute RDMA GPU Monitoring,${NC}"
        echo -e "${GRAY}                  Compute HPC RDMA Auto-Configuration,${NC}"
        echo -e "${GRAY}                  Compute HPC RDMA Authentication${NC}"
        echo ""
        echo -n -e "${CYAN}GPU RDMA cluster? [Y/n]: ${NC}"
        local _gpu_rdma_input
        read -r _gpu_rdma_input
        if [[ ! "$_gpu_rdma_input" =~ ^[Nn] ]]; then
            is_gpu_rdma_cluster="true"
        fi
        echo -e "${GREEN}✓ GPU RDMA cluster: ${WHITE}${is_gpu_rdma_cluster}${NC}"
    fi
    echo ""
    
    # ========== STEP 4: Boot Volume Configuration ==========
    echo ""
    _ui_subheader "Step 4: Boot Volume Configuration" 0
    echo ""
    
    local boot_volume_size="512"
    echo -n -e "${CYAN}Boot volume size in GB [${boot_volume_size}]: ${NC}"
    local bv_size_input
    read -r bv_size_input
    [[ -n "$bv_size_input" ]] && boot_volume_size="$bv_size_input"
    echo -e "${GREEN}✓ Boot volume size: ${WHITE}${boot_volume_size} GB${NC}"
    
    local boot_volume_vpus="20"
    echo ""
    echo -e "${WHITE}VPUs per GB (performance):${NC}"
    echo -e "  ${GRAY}10 = Balanced, 20 = Higher Performance, 30+ = Ultra High Performance${NC}"
    echo -n -e "${CYAN}Boot volume VPUs per GB [${boot_volume_vpus}]: ${NC}"
    local bv_vpus_input
    read -r bv_vpus_input
    [[ -n "$bv_vpus_input" ]] && boot_volume_vpus="$bv_vpus_input"
    echo -e "${GREEN}✓ Boot volume VPUs/GB: ${WHITE}${boot_volume_vpus}${NC}"
    
    # ========== STEP 5a: PV Encryption in Transit ==========
    echo ""
    _ui_subheader "Step 5a: PV Encryption in Transit" 0
    echo ""
    local pv_encryption_enabled="false"
    echo -n -e "${CYAN}Enable PV encryption in transit? [y/N]: ${NC}"
    local _pve_input
    read -r _pve_input
    if [[ "$_pve_input" =~ ^[Yy] ]]; then
        pv_encryption_enabled="true"
    fi
    echo -e "${GREEN}✓ PV encryption in transit: ${WHITE}${pv_encryption_enabled}${NC}"
    
    # ========== STEP 5b: KMS Key Management ==========
    echo ""
    _ui_subheader "Step 5b: Encryption Key Management" 0
    echo ""
    local kms_key_id=""
    echo -e "  ${GREEN}1${NC}) ${WHITE}Oracle-managed keys${NC}  ${GRAY}(default, no additional setup)${NC}"
    echo -e "  ${GREEN}2${NC}) ${WHITE}Customer-managed KMS${NC} ${GRAY}(use a key from OCI Vault)${NC}"
    echo ""
    echo -n -e "${CYAN}Select encryption [1]: ${NC}"
    local _kms_choice
    read -r _kms_choice
    
    if [[ "$_kms_choice" == "2" ]]; then
        echo ""
        _step_init
        _step_active "vaults and keys"
        
        # Search for vaults in compartment
        local _vaults_json
        _vaults_json=$(oci kms management vault list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all --output json 2>/dev/null)
        _step_complete "vaults and keys"
        _step_finish
        
        local _vault_count=0
        [[ -n "$_vaults_json" ]] && _vault_count=$(jq '[.data[] | select(.["lifecycle-state"] == "ACTIVE")] | length' <<< "$_vaults_json" 2>/dev/null || echo 0)
        
        if [[ "$_vault_count" -gt 0 ]]; then
            echo ""
            echo -e "${WHITE}Available Vaults:${NC}"
            local _v_idx=0
            declare -A _VAULT_MAP=()
            declare -A _VAULT_EP_MAP=()
            while IFS='|' read -r _v_id _v_name _v_ep; do
                [[ -z "$_v_id" ]] && continue
                ((_v_idx++))
                _VAULT_MAP[$_v_idx]="$_v_id"
                _VAULT_EP_MAP[$_v_idx]="$_v_ep"
                echo -e "  ${YELLOW}${_v_idx}${NC}) ${WHITE}${_v_name}${NC}"
            done < <(jq -r '.data[] | select(.["lifecycle-state"] == "ACTIVE") | "\(.id)|\(.["display-name"])|\(.["management-endpoint"])"' <<< "$_vaults_json" 2>/dev/null)
            
            echo ""
            echo -n -e "${CYAN}Select vault [1]: ${NC}"
            local _vault_pick
            read -r _vault_pick
            [[ -z "$_vault_pick" ]] && _vault_pick=1
            
            local _selected_vault_id="${_VAULT_MAP[$_vault_pick]:-${_VAULT_MAP[1]}}"
            local _selected_vault_ep="${_VAULT_EP_MAP[$_vault_pick]:-${_VAULT_EP_MAP[1]}}"
            
            if [[ -n "$_selected_vault_ep" ]]; then
                # List keys in the selected vault
                echo ""
                _step_init
                _step_active "keys in vault"
                local _keys_json
                _keys_json=$(oci kms management key list \
                    --compartment-id "$compartment_id" \
                    --endpoint "$_selected_vault_ep" \
                    --region "$region" \
                    --all --output json 2>/dev/null)
                _step_complete "keys in vault"
                _step_finish
                
                local _key_count=0
                [[ -n "$_keys_json" ]] && _key_count=$(jq '[.data[] | select(.["lifecycle-state"] == "ENABLED")] | length' <<< "$_keys_json" 2>/dev/null || echo 0)
                
                if [[ "$_key_count" -gt 0 ]]; then
                    echo ""
                    echo -e "${WHITE}Available Keys:${NC}"
                    local _k_idx=0
                    declare -A _KEY_MAP=()
                    while IFS='|' read -r _k_id _k_name _k_algo; do
                        [[ -z "$_k_id" ]] && continue
                        ((_k_idx++))
                        _KEY_MAP[$_k_idx]="$_k_id"
                        echo -e "  ${YELLOW}${_k_idx}${NC}) ${WHITE}${_k_name}${NC}  ${GRAY}(${_k_algo})${NC}"
                    done < <(jq -r '.data[] | select(.["lifecycle-state"] == "ENABLED") | "\(.id)|\(.["display-name"])|\(.algorithm)"' <<< "$_keys_json" 2>/dev/null)
                    
                    echo ""
                    echo -n -e "${CYAN}Select key [1]: ${NC}"
                    local _key_pick
                    read -r _key_pick
                    [[ -z "$_key_pick" ]] && _key_pick=1
                    kms_key_id="${_KEY_MAP[$_key_pick]:-${_KEY_MAP[1]}}"
                    echo -e "${GREEN}✓ KMS key: ${WHITE}${kms_key_id}${NC}"
                else
                    echo -e "${YELLOW}⚠ No enabled keys found in vault. Using Oracle-managed keys.${NC}"
                fi
            fi
        else
            echo -e "${YELLOW}⚠ No active vaults found in compartment. Using Oracle-managed keys.${NC}"
        fi
    else
        echo -e "${GREEN}✓ Encryption: ${WHITE}Oracle-managed keys${NC}"
    fi
    
    # ========== STEP 5c: Public IP Assignment (GPU clusters) ==========
    local assign_public_ip="false"
    if [[ "$is_gpu_rdma_cluster" == "true" ]]; then
        echo ""
        _ui_subheader "Step 5c: Public IP Assignment" 0
        echo ""
        echo -n -e "${CYAN}Assign public IP to instance? [y/N]: ${NC}"
        local _pubip_input
        read -r _pubip_input
        if [[ "$_pubip_input" =~ ^[Yy] ]]; then
            assign_public_ip="true"
        fi
        echo -e "${GREEN}✓ Public IP: ${WHITE}${assign_public_ip}${NC}"
    fi
    
    # ========== STEP 5d: Secondary VNIC ==========
    local add_secondary_vnic="false"
    local sec_vnic_subnet="" sec_vnic_nsg="" sec_vnic_name="" sec_vnic_public_ip="false"
    echo ""
    _ui_subheader "Step 5d: Secondary VNIC" 0
    echo ""
    echo -n -e "${CYAN}Add a secondary VNIC? [y/N]: ${NC}"
    local _sec_vnic_input
    read -r _sec_vnic_input
    
    if [[ "$_sec_vnic_input" =~ ^[Yy] ]]; then
        add_secondary_vnic="true"
        
        # Display name
        echo ""
        echo -n -e "${CYAN}Secondary VNIC display name [secondary-vnic]: ${NC}"
        local _sv_name_input
        read -r _sv_name_input
        sec_vnic_name="${_sv_name_input:-secondary-vnic}"
        
        # Subnet selection - reuse VCN discovery
        local _sv_vcn_ocid=""
        _sv_vcn_ocid=$(get_oke_env_value "VCN_OCID" 2>/dev/null)
        [[ -z "$_sv_vcn_ocid" || "$_sv_vcn_ocid" == "N/A" ]] && _sv_vcn_ocid="${FOCUS_VCN_OCID:-}"
        
        if [[ -n "$_sv_vcn_ocid" ]]; then
            echo ""
            _step_init
            _step_active "subnets for secondary VNIC"
            local _sv_sub_json
            _sv_sub_json=$(oci network subnet list \
                --compartment-id "$compartment_id" \
                --vcn-id "$_sv_vcn_ocid" \
                --region "$region" \
                --all --output json 2>/dev/null)
            _step_complete "subnets for secondary VNIC"
            _step_finish
            
            local _sv_sub_count
            _sv_sub_count=$(jq '.data | length' <<< "$_sv_sub_json" 2>/dev/null || echo 0)
            
            if [[ "$_sv_sub_count" -gt 0 ]]; then
                echo ""
                echo -e "${WHITE}Select subnet for secondary VNIC:${NC}"
                local _sv_s_idx=0
                declare -A _SV_SUB_MAP=()
                while IFS='|' read -r _sv_sid _sv_sname _sv_scidr; do
                    [[ -z "$_sv_sid" ]] && continue
                    ((_sv_s_idx++))
                    _SV_SUB_MAP[$_sv_s_idx]="$_sv_sid"
                    echo -e "  ${YELLOW}${_sv_s_idx}${NC}) ${WHITE}${_sv_sname}${NC} (${GRAY}${_sv_scidr}${NC})"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])|\(.["cidr-block"])"' <<< "$_sv_sub_json" 2>/dev/null)
                
                echo ""
                echo -n -e "${CYAN}Select subnet #: ${NC}"
                local _sv_sub_pick
                read -r _sv_sub_pick
                if [[ -n "${_SV_SUB_MAP[$_sv_sub_pick]}" ]]; then
                    sec_vnic_subnet="${_SV_SUB_MAP[$_sv_sub_pick]}"
                fi
            fi
            
            # NSG selection for secondary VNIC
            echo ""
            _step_init
            _step_active "NSGs for secondary VNIC"
            local _sv_nsg_json
            _sv_nsg_json=$(oci network nsg list \
                --compartment-id "$compartment_id" \
                --vcn-id "$_sv_vcn_ocid" \
                --all --output json 2>/dev/null)
            _step_complete "NSGs for secondary VNIC"
            _step_finish
            
            local _sv_nsg_count
            _sv_nsg_count=$(jq '.data | length' <<< "$_sv_nsg_json" 2>/dev/null || echo 0)
            
            if [[ "$_sv_nsg_count" -gt 0 ]]; then
                echo ""
                echo -e "${WHITE}Select NSG for secondary VNIC:${NC}"
                local _sv_n_idx=0
                declare -A _SV_NSG_MAP=()
                while IFS='|' read -r _sv_nid _sv_nname; do
                    [[ -z "$_sv_nid" ]] && continue
                    ((_sv_n_idx++))
                    _SV_NSG_MAP[$_sv_n_idx]="$_sv_nid"
                    echo -e "  ${YELLOW}${_sv_n_idx}${NC}) ${WHITE}${_sv_nname}${NC}"
                done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$_sv_nsg_json" 2>/dev/null)
                echo -e "  ${GRAY}0${NC}) No NSG"
                
                echo ""
                echo -n -e "${CYAN}Select NSG # [0=none]: ${NC}"
                local _sv_nsg_pick
                read -r _sv_nsg_pick
                if [[ -n "$_sv_nsg_pick" && "$_sv_nsg_pick" != "0" && -n "${_SV_NSG_MAP[$_sv_nsg_pick]}" ]]; then
                    sec_vnic_nsg="${_SV_NSG_MAP[$_sv_nsg_pick]}"
                fi
            fi
        else
            # Manual entry if no VCN known
            echo ""
            echo -n -e "${CYAN}Secondary VNIC subnet OCID: ${NC}"
            read -r sec_vnic_subnet
            echo -n -e "${CYAN}Secondary VNIC NSG OCID (Enter to skip): ${NC}"
            read -r sec_vnic_nsg
        fi
        
        # Public IP for secondary VNIC
        echo ""
        echo -n -e "${CYAN}Assign public IP to secondary VNIC? [y/N]: ${NC}"
        local _sv_pubip
        read -r _sv_pubip
        [[ "$_sv_pubip" =~ ^[Yy] ]] && sec_vnic_public_ip="true"
        
        echo -e "${GREEN}✓ Secondary VNIC: ${WHITE}${sec_vnic_name}${NC}"
        if [[ -n "$sec_vnic_subnet" ]]; then
            echo -e "  ${WHITE}Subnet:${NC} ${GRAY}...${sec_vnic_subnet: -20}${NC}"
        fi
        if [[ -n "$sec_vnic_nsg" ]]; then
            echo -e "  ${WHITE}NSG:${NC}    ${GRAY}...${sec_vnic_nsg: -20}${NC}"
        fi
        echo -e "  ${WHITE}Public IP:${NC} ${GRAY}${sec_vnic_public_ip}${NC}"
    else
        echo -e "${GREEN}✓ Secondary VNIC: ${WHITE}none${NC}"
    fi
    
    # ========== STEP 5: Max Pods Configuration (OKE only) ==========
    if [[ "$ic_purpose" == "oke" ]]; then
        echo ""
        _ui_subheader "Step 5: OKE Max Pods" 0
        echo ""
        echo -n -e "${CYAN}Max pods per node [${max_pods}]: ${NC}"
        local max_pods_input
        read -r max_pods_input
        [[ -n "$max_pods_input" ]] && max_pods="$max_pods_input"
        echo -e "${GREEN}✓ Max pods: ${WHITE}${max_pods}${NC}"
    else
        max_pods=""
    fi
    
    # ========== STEP 6: Generate Display Name ==========
    echo ""
    _ui_subheader "Step 6: Display Name" 0
    echo ""
    
    # Count existing instance configs with similar naming pattern to auto-increment
    # Format: ic-<shape>-<cluster-name>-<oke-version>-<cni-type>-# (OKE)
    #         ic-<shape>-inst-#  (normal)
    #         ic-<shape>-cn-#    (cluster_network)
    local base_name=""
    if [[ "$ic_purpose" == "oke" ]]; then
        base_name="ic-${shape_name}-${oke_cluster_name}-${oke_version}-${network_type}"
    elif [[ "$ic_purpose" == "normal" ]]; then
        base_name="ic-${shape_name}-inst"
    else
        base_name="ic-${shape_name}-cn"
    fi
    local next_num=1
    
    # Find the highest existing number for this base pattern
    if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
        local highest=0
        while IFS='|' read -r _ ic_existing_name _; do
            # Match pattern: ic-<shape>-oke-<version>-<networking>-<N>
            if [[ "$ic_existing_name" =~ ^${base_name}-([0-9]+)$ ]]; then
                local found_num="${BASH_REMATCH[1]}"
                (( found_num > highest )) && highest=$found_num
            fi
        done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
        next_num=$((highest + 1))
    fi
    
    # Also check via live OCI API only if cache might be stale
    if ! is_cache_fresh "$INSTANCE_CONFIG_CACHE" 2>/dev/null; then
        local live_ics
        live_ics=$(oci compute-management instance-configuration list \
            --compartment-id "$compartment_id" \
            --all --output json 2>/dev/null)
        
        if [[ -n "$live_ics" ]] && jq -e '.data[0]' <<< "$live_ics" >/dev/null; then
            while read -r ic_existing_name; do
                [[ -z "$ic_existing_name" ]] && continue
                if [[ "$ic_existing_name" =~ ^${base_name}-([0-9]+)$ ]]; then
                    local found_num="${BASH_REMATCH[1]}"
                    (( found_num >= next_num )) && next_num=$((found_num + 1))
                fi
            done < <(jq -r '.data[]."display-name" // empty' <<< "$live_ics" 2>/dev/null)
        fi
    fi
    
    local display_name="${base_name}-${next_num}"
    
    echo -e "${WHITE}Auto-generated display name: ${CYAN}${display_name}${NC}"
    echo -n -e "${CYAN}Accept or enter custom name [${display_name}]: ${NC}"
    local name_input
    read -r name_input
    [[ -n "$name_input" ]] && display_name="$name_input"
    echo -e "${GREEN}✓ Display name: ${WHITE}${display_name}${NC}"
    
    # ========== STEP 7: Compare with Existing Configs ==========
    echo ""
    _ui_subheader "Existing Instance Configurations" 0
    echo ""
    
    # Refresh instance configs
    fetch_instance_configurations > /dev/null 2>&1
    
    if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
        local ic_count=0
        _ui_table_header "%-4s %-60s %s" "#" "Name" "OCID"
        while IFS='|' read -r ic_ocid ic_name _; do
            [[ "$ic_ocid" =~ ^#.*$ ]] && continue
            [[ -z "$ic_ocid" ]] && continue
            ((ic_count++))
            printf "${YELLOW}%-4s${NC} ${WHITE}%-60s${NC} ${GRAY}...%s${NC}\n" \
                "$ic_count" "${ic_name:0:60}" "${ic_ocid: -20}"
        done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
        
        if [[ $ic_count -eq 0 ]]; then
            echo -e "  ${GRAY}(No existing instance configurations found)${NC}"
        fi
    else
        echo -e "  ${GRAY}(No existing instance configurations found)${NC}"
    fi
    echo ""
    
    echo -n -e "${CYAN}Compare with existing config (# or enter to skip): ${NC}"
    local compare_choice
    read -r compare_choice
    
    if [[ -n "$compare_choice" && "$compare_choice" =~ ^[0-9]+$ ]]; then
        local compare_idx=0
        local compare_ocid=""
        while IFS='|' read -r ic_ocid ic_name _; do
            [[ "$ic_ocid" =~ ^#.*$ ]] && continue
            [[ -z "$ic_ocid" ]] && continue
            ((compare_idx++))
            if [[ $compare_idx -eq $compare_choice ]]; then
                compare_ocid="$ic_ocid"
                break
            fi
        done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
        
        if [[ -n "$compare_ocid" ]]; then
            echo ""
            _ui_subheader "Comparing with: ${ic_name}" 0
            echo ""
            _step_init
            _step_active "full configuration details"
            
            # Get FULL instance configuration JSON for existing config
            _step_complete "full configuration details"
            _step_finish
            local existing_json
            existing_json=$(oci compute-management instance-configuration get \
                --instance-configuration-id "$compare_ocid" \
                --output json 2>/dev/null)
            
            if [[ -z "$existing_json" ]]; then
                echo -e "${RED}Failed to fetch configuration details${NC}"
                _ui_policy_hint "read instance-configurations in compartment"
                _ui_pause
            else
                # Extract launch-details for comparison
                local existing_launch
                existing_launch=$(jq '.data["instance-details"]["launch-details"]' <<< "$existing_json")
                
                echo ""
                _ui_menu_header "CONFIGURATION COMPARISON"
                echo ""
                echo -e "${BOLD}Comparing:${NC}"
                echo -e "  ${GREEN}A (new):${NC} ${display_name}"
                echo -e "  ${BLUE}B (existing):${NC} ${ic_name}"
                
                local has_diff=false
                
                # Shape
                local ex_shape
                ex_shape=$(jq -r '.shape // "N/A"' <<< "$existing_launch")
                _ui_compare_field "Shape" "$shape_name" "New" "$ex_shape" "Existing" || has_diff=true
                
                # Shape Config (for flex shapes)
                if [[ "$is_flex_shape" == "true" ]]; then
                    local ex_ocpus ex_memory
                    ex_ocpus=$(jq -r '.["shape-config"].ocpus // "N/A"' <<< "$existing_launch")
                    ex_memory=$(jq -r '.["shape-config"]["memory-in-gbs"] // "N/A"' <<< "$existing_launch")
                    _ui_compare_field "Shape Config (OCPUs)" "$flex_ocpus" "New" "$ex_ocpus" "Existing" || has_diff=true
                    _ui_compare_field "Shape Config (Memory GB)" "$flex_memory_gb" "New" "$ex_memory" "Existing" || has_diff=true
                fi
                
                # Availability Domain
                local ex_ad
                ex_ad=$(jq -r '.["availability-domain"] // "N/A"' <<< "$existing_launch")
                _ui_compare_field "Availability Domain" "$ad" "New" "$ex_ad" "Existing" || has_diff=true
                
                # Boot Volume Size
                local ex_bvsize
                ex_bvsize=$(jq -r '.["source-details"]["boot-volume-size-in-gbs"] // "N/A"' <<< "$existing_launch")
                _ui_compare_field "Boot Volume Size (GB)" "$boot_volume_size" "New" "$ex_bvsize" "Existing" || has_diff=true
                
                # Boot Volume VPUs
                local ex_bvvpus
                ex_bvvpus=$(jq -r '.["source-details"]["boot-volume-vpus-per-gb"] // "N/A"' <<< "$existing_launch")
                _ui_compare_field "Boot Volume VPUs/GB" "$boot_volume_vpus" "New" "$ex_bvvpus" "Existing" || has_diff=true
                
                # Image
                local ex_img_id ex_img_name
                ex_img_id=$(jq -r '.["source-details"]["image-id"] // "N/A"' <<< "$existing_launch")
                ex_img_name="(fetching...)"
                [[ -n "$ex_img_id" && "$ex_img_id" != "N/A" ]] && ex_img_name=$(resolve_image_name_cached "$ex_img_id")
                local new_img_name
                new_img_name=$(resolve_image_name_cached "$image_id")
                echo ""
                _ui_subheader "Image" 0
                if [[ "$image_id" == "$ex_img_id" ]]; then
                    echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}$new_img_name${NC} (${YELLOW}$image_id${NC})"
                else
                    echo -e "  ${RED}✗ Different:${NC}"
                    echo -e "    ${GREEN}New:${NC} ${WHITE}$new_img_name${NC}"
                    echo -e "      ${YELLOW}$image_id${NC}"
                    echo -e "    ${BLUE}Existing:${NC} ${WHITE}$ex_img_name${NC}"
                    echo -e "      ${YELLOW}$ex_img_id${NC}"
                    has_diff=true
                fi
                
                # Subnet
                local ex_subnet
                ex_subnet=$(jq -r '.["create-vnic-details"]["subnet-id"] // "N/A"' <<< "$existing_launch")
                local new_sub_name ex_sub_name
                new_sub_name=$(resolve_subnet_name_cached "$worker_subnet")
                ex_sub_name=$(resolve_subnet_name_cached "$ex_subnet")
                echo ""
                _ui_subheader "Worker Subnet" 0
                if [[ "$worker_subnet" == "$ex_subnet" ]]; then
                    echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}${new_sub_name}${NC} ${GRAY}(${worker_subnet})${NC}"
                else
                    echo -e "  ${RED}✗ Different:${NC}"
                    echo -e "    ${GREEN}New:${NC} ${WHITE}${new_sub_name}${NC} ${GRAY}(${worker_subnet})${NC}"
                    echo -e "    ${BLUE}Existing:${NC} ${WHITE}${ex_sub_name}${NC} ${GRAY}(${ex_subnet})${NC}"
                    has_diff=true
                fi
                
                # NSG
                local ex_nsgs new_nsgs_sorted ex_nsgs_sorted
                ex_nsgs_sorted=$(jq -r '.["create-vnic-details"]["nsg-ids"] // [] | .[]' <<< "$existing_launch" 2>/dev/null | sort )
                new_nsgs_sorted="$worker_nsg"
                local new_nsg_name ex_nsg_name
                new_nsg_name=$(resolve_nsg_name_cached "$worker_nsg")
                echo ""
                _ui_subheader "Worker NSG" 0
                if [[ "$new_nsgs_sorted" == "$ex_nsgs_sorted" ]]; then
                    echo -e "  ${GREEN}✓ Same:${NC} ${WHITE}${new_nsg_name}${NC} ${GRAY}(${worker_nsg})${NC}"
                else
                    echo -e "  ${RED}✗ Different:${NC}"
                    echo -e "    ${GREEN}New:${NC} ${WHITE}${new_nsg_name}${NC} ${GRAY}(${worker_nsg})${NC}"
                    echo -e "    ${BLUE}Existing:${NC}"
                    if [[ -n "$ex_nsgs_sorted" ]]; then
                        while read -r nsg; do
                            ex_nsg_name=$(resolve_nsg_name_cached "$nsg")
                            echo -e "      ${WHITE}${ex_nsg_name}${NC} ${GRAY}(${nsg})${NC}"
                        done <<< "$ex_nsgs_sorted"
                    else
                        echo -e "      (none)"
                    fi
                    has_diff=true
                fi
                
                # Metadata (excluding user_data)
                echo ""
                _ui_subheader "Metadata Fields" 0
                local ex_meta_keys
                ex_meta_keys=$(jq -r '.metadata // {} | keys[]' <<< "$existing_launch" 2>/dev/null | grep -v '^user_data$' | sort )
                local new_max_pods_val="$max_pods"
                local ex_max_pods
                ex_max_pods=$(jq -r '.metadata["oke-max-pods"] // "(not set)"' <<< "$existing_launch")
                if [[ "$new_max_pods_val" == "$ex_max_pods" ]]; then
                    echo -e "  ${GREEN}✓${NC} ${WHITE}oke-max-pods:${NC} $new_max_pods_val"
                else
                    echo -e "  ${RED}✗${NC} ${WHITE}oke-max-pods:${NC}"
                    echo -e "      ${GREEN}New:${NC} $new_max_pods_val"
                    echo -e "      ${BLUE}Existing:${NC} $ex_max_pods"
                    has_diff=true
                fi
                
                # Native pod networking metadata comparison
                local ex_native_flag
                ex_native_flag=$(jq -r '.metadata["oke-native-pod-networking"] // "(not set)"' <<< "$existing_launch")
                local new_native_flag="(not set)"
                [[ "$network_type" == "native" ]] && new_native_flag="true"
                
                if [[ "$new_native_flag" != "$ex_native_flag" ]]; then
                    echo -e "  ${RED}✗${NC} ${WHITE}oke-native-pod-networking:${NC}"
                    echo -e "      ${GREEN}New:${NC} $new_native_flag"
                    echo -e "      ${BLUE}Existing:${NC} $ex_native_flag"
                    has_diff=true
                else
                    echo -e "  ${GREEN}✓${NC} ${WHITE}oke-native-pod-networking:${NC} $new_native_flag"
                fi
                
                local ex_pod_subnets ex_pod_nsgids
                ex_pod_subnets=$(jq -r '.metadata["pod-subnets"] // "(not set)"' <<< "$existing_launch")
                ex_pod_nsgids=$(jq -r '.metadata["pod-nsgids"] // "(not set)"' <<< "$existing_launch")
                local new_pod_subnets="(not set)" new_pod_nsgids="(not set)"
                if [[ "$network_type" == "native" ]]; then
                    new_pod_subnets="$pod_subnet"
                    new_pod_nsgids="$pod_nsg"
                fi
                
                if [[ "$new_pod_subnets" != "$ex_pod_subnets" ]]; then
                    echo -e "  ${RED}✗${NC} ${WHITE}pod-subnets:${NC}"
                    local _new_psn _ex_psn
                    _new_psn=$(resolve_subnet_name_cached "$new_pod_subnets" 2>/dev/null)
                    _ex_psn=$(resolve_subnet_name_cached "$ex_pod_subnets" 2>/dev/null)
                    echo -e "      ${GREEN}New:${NC} ${WHITE}${_new_psn}${NC} ${GRAY}(${new_pod_subnets})${NC}"
                    echo -e "      ${BLUE}Existing:${NC} ${WHITE}${_ex_psn}${NC} ${GRAY}(${ex_pod_subnets})${NC}"
                    has_diff=true
                elif [[ "$new_pod_subnets" != "(not set)" ]]; then
                    local _psn_display
                    _psn_display=$(resolve_subnet_name_cached "$new_pod_subnets")
                    echo -e "  ${GREEN}✓${NC} ${WHITE}pod-subnets:${NC} ${WHITE}${_psn_display}${NC} ${GRAY}(${new_pod_subnets})${NC}"
                fi
                
                if [[ "$new_pod_nsgids" != "$ex_pod_nsgids" ]]; then
                    echo -e "  ${RED}✗${NC} ${WHITE}pod-nsgids:${NC}"
                    local _new_pnn _ex_pnn
                    _new_pnn=$(resolve_nsg_name_cached "$new_pod_nsgids" 2>/dev/null)
                    _ex_pnn=$(resolve_nsg_name_cached "$ex_pod_nsgids" 2>/dev/null)
                    echo -e "      ${GREEN}New:${NC} ${WHITE}${_new_pnn}${NC} ${GRAY}(${new_pod_nsgids})${NC}"
                    echo -e "      ${BLUE}Existing:${NC} ${WHITE}${_ex_pnn}${NC} ${GRAY}(${ex_pod_nsgids})${NC}"
                    has_diff=true
                elif [[ "$new_pod_nsgids" != "(not set)" ]]; then
                    local _pnn_display
                    _pnn_display=$(resolve_nsg_name_cached "$new_pod_nsgids")
                    echo -e "  ${GREEN}✓${NC} ${WHITE}pod-nsgids:${NC} ${WHITE}${_pnn_display}${NC} ${GRAY}(${new_pod_nsgids})${NC}"
                fi
                
                # Cloud-init diff
                echo ""
                _ui_menu_header "CLOUD-INIT USER-DATA COMPARISON"
                echo ""
                _ui_legend
                echo -e "  ${RED}- Lines only in:${NC} ${GREEN}New config${NC}"
                echo -e "  ${GREEN}+ Lines only in:${NC} ${BLUE}${ic_name}${NC}"
                echo ""
                
                local ex_ud
                ex_ud=$(jq -r '.metadata.user_data // empty' <<< "$existing_launch")
                
                local tmp_new tmp_existing
                tmp_new=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
                tmp_existing=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
                
                # New cloud-init is the file itself
                cp "$cloud_init_file" "$tmp_new" 2>/dev/null || echo "# No cloud-init" > "$tmp_new"
                
                if [[ -n "$ex_ud" ]]; then
                    decode_user_data_to_file "$ex_ud" "$tmp_existing" || echo "# Failed to decode user_data" > "$tmp_existing"
                else
                    echo "# No user_data" > "$tmp_existing"
                fi
                
                if diff -q "$tmp_new" "$tmp_existing" > /dev/null 2>&1; then
                    echo -e "${GREEN}✓ Cloud-init user-data is identical${NC}"
                else
                    echo -e "${RED}✗ Cloud-init user-data is DIFFERENT${NC}"
                    echo ""
                    _ui_subheader "Differences Found" 0
                    echo ""
                    
                    local diff_output
                    diff_output=$(diff -u "$tmp_new" "$tmp_existing" 2>/dev/null | tail -n +4)
                    
                    while IFS= read -r line; do
                        if [[ "$line" =~ ^@@ ]]; then
                            echo ""
                            printf '%b%s%b\n' "${YELLOW}" "$line" "${NC}"
                        elif [[ "$line" =~ ^- ]]; then
                            printf '%b%s%b\n' "${RED}" "$line" "${NC}"
                        elif [[ "$line" =~ ^\+ ]]; then
                            printf '%b%s%b\n' "${GREEN}" "$line" "${NC}"
                        elif [[ "$line" =~ ^[[:space:]] ]]; then
                            printf '%b%s%b\n' "${GRAY}" "$line" "${NC}"
                        fi
                    done <<< "$diff_output"
                    
                    has_diff=true
                fi
                
                rm -f "$tmp_new" "$tmp_existing"
                
                # Summary
                echo ""
                _ui_content_border
                if [[ "$has_diff" == "true" ]]; then
                    echo -e "${RED}✗ Configurations have differences${NC}"
                else
                    echo -e "${GREEN}✓ Configurations are identical${NC}"
                fi
                _ui_content_border
                
                echo ""
                _ui_pause
            fi
        fi
    fi
    
    # ========== STEP 9: Build and Show Command ==========
    echo ""
    _ui_subheader "Configuration Summary" 0
    echo ""
    echo -e "  ${WHITE}Display Name:${NC}       ${CYAN}${display_name}${NC}"
    if [[ "$is_flex_shape" == "true" ]]; then
        echo -e "  ${WHITE}Shape:${NC}              ${WHITE}${shape_name}${NC} (${CYAN}${flex_ocpus} OCPUs${NC}, ${CYAN}${flex_memory_gb} GB Memory${NC})"
    else
        echo -e "  ${WHITE}Shape:${NC}              ${WHITE}${shape_name}${NC}"
    fi
    echo -e "  ${WHITE}Network Type:${NC}       ${WHITE}${network_type}${NC}"
    echo -e "  ${WHITE}Boot Volume:${NC}        ${WHITE}${boot_volume_size} GB @ ${boot_volume_vpus} VPUs/GB${NC}"
    echo -e "  ${WHITE}PV Encryption:${NC}      ${WHITE}${pv_encryption_enabled}${NC}"
    if [[ -n "$kms_key_id" ]]; then
        echo -e "  ${WHITE}KMS Key:${NC}            ${YELLOW}...${kms_key_id: -20}${NC}"
    else
        echo -e "  ${WHITE}Encryption:${NC}         ${WHITE}Oracle-managed keys${NC}"
    fi
    if [[ "$is_gpu_rdma_cluster" == "true" ]]; then
        echo -e "  ${WHITE}GPU RDMA Cluster:${NC}   ${GREEN}yes${NC}"
    fi
    echo -e "  ${WHITE}Public IP:${NC}          ${WHITE}${assign_public_ip}${NC}"
    echo -e "  ${WHITE}Max Pods:${NC}           ${WHITE}${max_pods}${NC}"
    echo -e "  ${WHITE}Cloud-Init:${NC}         ${WHITE}${cloud_init_file}${NC}"
    echo -e "  ${WHITE}Region:${NC}             ${WHITE}${region}${NC}"
    echo -e "  ${WHITE}AD:${NC}                 ${WHITE}${ad}${NC}"
    echo ""
    
    # Show compartment with name
    local compartment_name_display
    compartment_name_display=$(resolve_compartment_name "$compartment_id")
    echo -e "  ${WHITE}Compartment:${NC}        ${WHITE}${compartment_name_display}${NC} (${YELLOW}${compartment_id}${NC})"
    
    # Show subnet with name (from already-fetched data)
    local subnet_name_display
    subnet_name_display=$(jq -r --arg sid "$worker_subnet" '.data[] | select(.id == $sid) | .["display-name"] // empty' <<< "$_sub_json" 2>/dev/null | head -1)
    [[ -z "$subnet_name_display" ]] && subnet_name_display=$(resolve_subnet_name_cached "$worker_subnet")
    echo -e "  ${WHITE}Worker Subnet:${NC}      ${WHITE}${subnet_name_display}${NC} (${YELLOW}${worker_subnet}${NC})"
    
    # Show NSG with name (if selected)
    if [[ -n "$worker_nsg" ]]; then
        local nsg_name_display
        nsg_name_display=$(jq -r --arg nid "$worker_nsg" '.data[] | select(.id == $nid) | .["display-name"] // empty' <<< "$_nsg_json" 2>/dev/null | head -1)
        [[ -z "$nsg_name_display" ]] && nsg_name_display=$(resolve_nsg_name_cached "$worker_nsg")
        echo -e "  ${WHITE}Worker NSG:${NC}         ${WHITE}${nsg_name_display}${NC} (${YELLOW}${worker_nsg}${NC})"
    else
        echo -e "  ${WHITE}Worker NSG:${NC}         ${GRAY}(none)${NC}"
    fi
    
    # Show pod subnet/NSG when native (from already-fetched data)
    if [[ "$network_type" == "native" ]]; then
        local pod_subnet_name_display pod_nsg_name_display
        pod_subnet_name_display=$(jq -r --arg sid "$pod_subnet" '.data[] | select(.id == $sid) | .["display-name"] // empty' <<< "${_pod_sub_json:-$_sub_json}" 2>/dev/null | head -1)
        [[ -z "$pod_subnet_name_display" ]] && pod_subnet_name_display="Unknown"
        pod_nsg_name_display=$(jq -r --arg nid "$pod_nsg" '.data[] | select(.id == $nid) | .["display-name"] // empty' <<< "${_pod_nsg_json:-$_nsg_json}" 2>/dev/null | head -1)
        [[ -z "$pod_nsg_name_display" ]] && pod_nsg_name_display="Unknown"
        echo -e "  ${WHITE}Pod Subnet:${NC}         ${WHITE}${pod_subnet_name_display}${NC} (${YELLOW}${pod_subnet}${NC})"
        echo -e "  ${WHITE}Pod NSG:${NC}            ${WHITE}${pod_nsg_name_display}${NC} (${YELLOW}${pod_nsg}${NC})"
    fi
    
    # Show image with name (from already-fetched data)
    local img_name_display="${IMAGE_NAME_MAP[$image_id]:-}"
    if [[ -z "$img_name_display" ]]; then
        # Try all_images_json
        img_name_display=$(jq -r --arg id "$image_id" '.data[] | select(.id == $id) | .["display-name"] // empty' <<< "$images_json" 2>/dev/null | head -1)
    fi
    [[ -z "$img_name_display" ]] && img_name_display=$(resolve_image_name_cached "$image_id")
    echo -e "  ${WHITE}Image:${NC}              ${WHITE}${img_name_display}${NC} (${YELLOW}${image_id}${NC})"
    
    # Show secondary VNIC (from already-fetched data)
    if [[ "$add_secondary_vnic" == "true" ]]; then
        echo ""
        echo -e "  ${WHITE}Secondary VNIC:${NC}     ${WHITE}${sec_vnic_name}${NC}"
        if [[ -n "$sec_vnic_subnet" ]]; then
            local sv_sub_name
            sv_sub_name=$(jq -r --arg sid "$sec_vnic_subnet" '.data[] | select(.id == $sid) | .["display-name"] // empty' <<< "${_sv_sub_json:-$_sub_json}" 2>/dev/null | head -1)
            [[ -z "$sv_sub_name" ]] && sv_sub_name=$(resolve_subnet_name_cached "$sec_vnic_subnet")
            echo -e "  ${WHITE}  Subnet:${NC}           ${WHITE}${sv_sub_name}${NC} (${YELLOW}${sec_vnic_subnet}${NC})"
        fi
        if [[ -n "$sec_vnic_nsg" ]]; then
            local sv_nsg_name
            sv_nsg_name=$(jq -r --arg nid "$sec_vnic_nsg" '.data[] | select(.id == $nid) | .["display-name"] // empty' <<< "${_sv_nsg_json:-$_nsg_json}" 2>/dev/null | head -1)
            [[ -z "$sv_nsg_name" ]] && sv_nsg_name=$(resolve_nsg_name_cached "$sec_vnic_nsg")
            echo -e "  ${WHITE}  NSG:${NC}              ${WHITE}${sv_nsg_name}${NC} (${YELLOW}${sec_vnic_nsg}${NC})"
        fi
    fi
    echo ""
    
    # Encode cloud-init
    local base64_cloud_init
    base64_cloud_init=$(base64 -w 0 "$cloud_init_file")
    
    # Build the JSON payload
    local shape_config_json=""
    if [[ "$is_flex_shape" == "true" ]]; then
        shape_config_json=$(cat <<SCEOF
    "shapeConfig": {
      "ocpus": ${flex_ocpus},
      "memoryInGBs": ${flex_memory_gb}
    },
SCEOF
)
    fi
    
    # Build metadata block based on network type and purpose
    local metadata_json=""
    if [[ "$ic_purpose" == "oke" && "$network_type" == "native" ]]; then
        metadata_json=$(cat <<MDEOF
    "metadata": {
      "user_data": "${base64_cloud_init}",
      "oke-native-pod-networking": "true",
      "oke-max-pods": "${max_pods}",
      "pod-subnets": "${pod_subnet}",
      "pod-nsgids": "${pod_nsg}"
    },
MDEOF
)
    elif [[ "$ic_purpose" == "oke" ]]; then
        metadata_json=$(cat <<MDEOF
    "metadata": {
      "user_data": "${base64_cloud_init}",
      "oke-max-pods": "${max_pods}"
    },
MDEOF
)
    else
        metadata_json=$(cat <<MDEOF
    "metadata": {
      "user_data": "${base64_cloud_init}"
    },
MDEOF
)
    fi
    
    # Build nsgIds array (empty array if no NSG selected)
    local nsg_ids_json="[]"
    [[ -n "$worker_nsg" ]] && nsg_ids_json="[\"${worker_nsg}\"]"
    
    # Build agent plugins based on GPU RDMA cluster flag
    # Build agent plugins: monitoring always enabled, RDMA plugins conditional
    local gpu_rdma_state="DISABLED"
    if [[ "$is_gpu_rdma_cluster" == "true" ]]; then
        gpu_rdma_state="ENABLED"
    fi
    
    # Build sourceDetails with optional KMS key
    local source_details_json
    if [[ -n "$kms_key_id" ]]; then
        source_details_json=$(cat <<SDEOF
    "sourceDetails": {
      "bootVolumeSizeInGBs": "${boot_volume_size}",
      "bootVolumeVpusPerGB": "${boot_volume_vpus}",
      "sourceType": "image",
      "imageId": "${image_id}",
      "kmsKeyId": "${kms_key_id}"
    },
SDEOF
)
    else
        source_details_json=$(cat <<SDEOF
    "sourceDetails": {
      "bootVolumeSizeInGBs": "${boot_volume_size}",
      "bootVolumeVpusPerGB": "${boot_volume_vpus}",
      "sourceType": "image",
      "imageId": "${image_id}"
    },
SDEOF
)
    fi
    
    # Build secondary VNICs block
    local secondary_vnics_json=""
    if [[ "$add_secondary_vnic" == "true" && -n "$sec_vnic_subnet" ]]; then
        local sec_nsg_ids_json="[]"
        [[ -n "$sec_vnic_nsg" ]] && sec_nsg_ids_json="[\"${sec_vnic_nsg}\"]"
        secondary_vnics_json=$(cat <<SVEOF
  "secondaryVnics": [
    {
      "createVnicDetails": {
        "assignPublicIp": ${sec_vnic_public_ip},
        "assignPrivateDnsRecord": true,
        "displayName": "${sec_vnic_name}",
        "subnetId": "${sec_vnic_subnet}",
        "nsgIds": ${sec_nsg_ids_json}
      }
    }
  ],
SVEOF
)
    fi
    
    local instance_details_json
    instance_details_json=$(cat <<EOF
{
  "instanceType": "compute",
${secondary_vnics_json}
  "launchDetails": {
    "availabilityDomain": "${ad}",
    "compartmentId": "${compartment_id}",
    "createVnicDetails": {
      "assignIpv6Ip": false,
      "assignPublicIp": ${assign_public_ip},
      "assignPrivateDnsRecord": true,
      "subnetId": "${worker_subnet}",
      "nsgIds": ${nsg_ids_json}
    },
${metadata_json}
    "shape": "${shape_name}",
${shape_config_json}
${source_details_json}
    "agentConfig": {
      "isMonitoringDisabled": false,
      "isManagementDisabled": false,
      "pluginsConfig": [
        { "name": "WebLogic Management Service", "desiredState": "DISABLED" },
        { "name": "Vulnerability Scanning", "desiredState": "DISABLED" },
        { "name": "Oracle Java Management Service", "desiredState": "DISABLED" },
        { "name": "Oracle Autonomous Linux", "desiredState": "DISABLED" },
        { "name": "OS Management Service Agent", "desiredState": "DISABLED" },
        { "name": "OS Management Hub Agent", "desiredState": "DISABLED" },
        { "name": "Management Agent", "desiredState": "DISABLED" },
        { "name": "Custom Logs Monitoring", "desiredState": "ENABLED" },
        { "name": "Compute Instance Run Command", "desiredState": "ENABLED" },
        { "name": "Compute Instance Monitoring", "desiredState": "ENABLED" },
        { "name": "Compute RDMA GPU Monitoring", "desiredState": "${gpu_rdma_state}" },
        { "name": "Compute HPC RDMA Auto-Configuration", "desiredState": "${gpu_rdma_state}" },
        { "name": "Compute HPC RDMA Authentication", "desiredState": "${gpu_rdma_state}" },
        { "name": "Block Volume Management", "desiredState": "DISABLED" },
        { "name": "Bastion", "desiredState": "DISABLED" }
      ]
    },
    "isPvEncryptionInTransitEnabled": ${pv_encryption_enabled},
    "instanceOptions": {
      "areLegacyImdsEndpointsDisabled": false
    },
    "availabilityConfig": {
      "recoveryAction": "RESTORE_INSTANCE"
    }
  }
}
EOF
)
    
    # Clean up JSON - remove empty lines from non-flex shapes and ensure valid JSON
    instance_details_json=$(jq '.' <<< "$instance_details_json" 2>/dev/null || echo "$instance_details_json")
    
    _ui_subheader "Configuration Summary" 0
    echo ""
    if [[ "$is_flex_shape" == "true" ]]; then
        echo -e "  ${CYAN}Shape:${NC}       ${WHITE}${shape_name}${NC} (${CYAN}${flex_ocpus} OCPUs${NC}, ${CYAN}${flex_memory_gb} GB Memory${NC})"
    else
        echo -e "  ${CYAN}Shape:${NC}       ${WHITE}${shape_name}${NC}"
    fi
    echo -e "  ${CYAN}Boot Vol:${NC}    ${WHITE}${boot_volume_size} GB @ ${boot_volume_vpus} VPUs/GB${NC}"
    echo -e "  ${CYAN}PV Encrypt:${NC}  ${WHITE}${pv_encryption_enabled}${NC}"
    if [[ -n "$kms_key_id" ]]; then
        echo -e "  ${CYAN}KMS Key:${NC}     ${YELLOW}...${kms_key_id: -20}${NC}"
    fi
    if [[ "$is_gpu_rdma_cluster" == "true" ]]; then
        echo -e "  ${CYAN}GPU RDMA:${NC}    ${GREEN}yes${NC}"
    fi
    echo -e "  ${CYAN}Public IP:${NC}   ${WHITE}${assign_public_ip}${NC}"
    echo -e "  ${CYAN}Max Pods:${NC}    ${WHITE}${max_pods}${NC}"
    echo -e "  ${CYAN}Network:${NC}     ${WHITE}${network_type}${NC}"
    echo ""
    
    # Show image with name and OCID on same line
    local img_summary_name
    img_summary_name=$(resolve_image_name_cached "$image_id")
    echo -e "  ${CYAN}Image:${NC}       ${WHITE}${img_summary_name}${NC} (${YELLOW}${image_id}${NC})"
    
    # Show worker subnet with name and OCID on same line
    local subnet_summary_name
    subnet_summary_name=$(resolve_subnet_name_cached "$worker_subnet")
    echo -e "  ${CYAN}Worker Sub:${NC}  ${WHITE}${subnet_summary_name}${NC} (${YELLOW}${worker_subnet}${NC})"
    
    # Show worker NSG with name and OCID on same line
    local nsg_summary_name
    nsg_summary_name=$(resolve_nsg_name_cached "$worker_nsg")
    echo -e "  ${CYAN}Worker NSG:${NC}  ${WHITE}${nsg_summary_name}${NC} (${YELLOW}${worker_nsg}${NC})"
    
    # Show pod subnet/NSG when native
    if [[ "$network_type" == "native" ]]; then
        local pod_sub_summary pod_nsg_summary
        pod_sub_summary=$(resolve_subnet_name_cached "$pod_subnet")
        pod_nsg_summary=$(resolve_nsg_name_cached "$pod_nsg")
        echo -e "  ${CYAN}Pod Sub:${NC}     ${WHITE}${pod_sub_summary}${NC} (${YELLOW}${pod_subnet}${NC})"
        echo -e "  ${CYAN}Pod NSG:${NC}     ${WHITE}${pod_nsg_summary}${NC} (${YELLOW}${pod_nsg}${NC})"
    fi
    
    # Show secondary VNIC
    if [[ "$add_secondary_vnic" == "true" ]]; then
        echo -e "  ${CYAN}2nd VNIC:${NC}    ${WHITE}${sec_vnic_name}${NC} (${YELLOW}...${sec_vnic_subnet: -20}${NC})"
    fi
    echo ""
    
    _ui_subheader "Command to Execute" 0
    echo ""
    printf "%s\n" "oci --region \"${region}\" \\"
    printf "%s\n" "  compute-management instance-configuration create \\"
    printf "%s\n" "  --compartment-id \"${compartment_id}\" \\"
    printf "%s\n" "  --display-name \"${display_name}\" \\"
    printf "%s\n" "  --instance-details '...'"
    echo ""
    
    _ui_subheader "Instance Details JSON Payload" 0
    echo ""
    jq '.' <<< "$instance_details_json" 2>/dev/null || echo "$instance_details_json"
    echo ""
    
    # Ensure logs directory exists
    mkdir -p "${LOGS_DIR}" 2>/dev/null
    local log_file="${LOGS_DIR}/instance_config_create_$(date +%Y%m%d_%H%M%S).log"
    
    _ui_subheader "CONFIRM CREATION" 0
    echo ""
    echo -e "${YELLOW}This will create a new Instance Configuration.${NC}"
    echo -e "${WHITE}Log file: ${CYAN}${log_file}${NC}"
    echo ""
    if ! _ui_confirm "CREATE" "confirm" "$CYAN"; then
        echo -e "${YELLOW}Cancelled.${NC}"
        _ui_pause "return"
        return 0
    fi
    
    # Execute the command
    echo ""
    echo -e "${YELLOW}Creating Instance Configuration...${NC}"
    
    # Log the command with full details
    {
        echo "=========================================="
        echo "Instance Configuration Creation"
        echo "Timestamp: $(date)"
        echo "=========================================="
        echo ""
        echo "Display Name: ${display_name}"
        echo "Shape: ${shape_name}"
        if [[ "$is_flex_shape" == "true" ]]; then
            echo "Shape Config: ${flex_ocpus} OCPUs, ${flex_memory_gb} GB Memory"
        fi
        echo "Image ID: ${image_id}"
        echo "Network Type: ${network_type}"
        if [[ "$network_type" == "native" ]]; then
            echo "Pod Subnet ID: ${pod_subnet}"
            echo "Pod NSG ID: ${pod_nsg}"
        fi
        echo "Boot Volume: ${boot_volume_size} GB @ ${boot_volume_vpus} VPUs/GB"
        echo "PV Encryption in Transit: ${pv_encryption_enabled}"
        echo "GPU RDMA Cluster: ${is_gpu_rdma_cluster}"
        echo "Public IP: ${assign_public_ip}"
        [[ -n "$kms_key_id" ]] && echo "KMS Key ID: ${kms_key_id}"
        echo "Max Pods: ${max_pods}"
        echo "Cloud-Init File: ${cloud_init_file}"
        if [[ "$add_secondary_vnic" == "true" ]]; then
            echo "Secondary VNIC: ${sec_vnic_name}"
            echo "Secondary VNIC Subnet: ${sec_vnic_subnet}"
            [[ -n "$sec_vnic_nsg" ]] && echo "Secondary VNIC NSG: ${sec_vnic_nsg}"
        fi
        echo ""
        echo "Command:"
        echo "oci --region \"${region}\" \\"
        echo "  compute-management instance-configuration create \\"
        echo "  --compartment-id \"${compartment_id}\" \\"
        echo "  --display-name \"${display_name}\" \\"
        echo "  --instance-details '<see JSON payload below>'"
        echo ""
        echo "=========================================="
        echo "Instance Details JSON Payload:"
        echo "=========================================="
        jq '.' <<< "$instance_details_json" 2>/dev/null || echo "$instance_details_json"
        echo ""
        echo "=========================================="
        echo "Execution Output:"
        echo "=========================================="
    } > "$log_file"
    
    local result
    result=$(oci --region "${region}" \
        compute-management instance-configuration create \
        --compartment-id "${compartment_id}" \
        --display-name "${display_name}" \
        --instance-details "${instance_details_json}" 2>&1)
    local exit_code=$?
    
    # Log the result
    echo "$result" >> "$log_file"
    
    if [[ $exit_code -eq 0 ]]; then
        local new_ocid
        new_ocid=$(jq -r '.data.id // empty' <<< "$result" 2>/dev/null)
        
        echo ""
        echo -e "${GREEN}╔════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${GREEN}║                    INSTANCE CONFIGURATION CREATED                          ║${NC}"
        echo -e "${GREEN}╚════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${WHITE}Name:${NC} ${CYAN}${display_name}${NC}"
        echo -e "${WHITE}OCID:${NC} ${YELLOW}${new_ocid}${NC}"
        echo -e "${WHITE}Log:${NC}  ${WHITE}${log_file}${NC}"
        echo ""
        
        # Invalidate cache
        rm -f "$INSTANCE_CONFIG_CACHE"
        
        echo -e "${GREEN}✓ Instance Configuration created successfully!${NC}"
    else
        echo ""
        echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════╗${NC}"
        echo -e "${RED}║                    FAILED TO CREATE INSTANCE CONFIGURATION                 ║${NC}"
        echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════╝${NC}"
        echo ""
        echo -e "${RED}Error:${NC}"
        echo "$result"
        echo ""
        echo -e "${WHITE}Log file: ${CYAN}${log_file}${NC}"
    fi
    
    echo ""
    _ui_pause
    
    # Refresh the menu to show new instance config
    display_gpu_management_menu > /dev/null 2>&1
}

#--------------------------------------------------------------------------------
# Delete Instance Configuration interactively
#--------------------------------------------------------------------------------
delete_instance_configuration_interactive() {
    local delete_args="$1"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/instance_config_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_menu_header "DELETE INSTANCE CONFIGURATION" \
        --breadcrumb "Compute" "Instance Configs" "Delete" \
        --cmd "oci compute-management instance-configuration delete --instance-configuration-id \$IC_OCID --force" \
        --env
    
    # ── Discovery ── (always fresh after deletion)
    _step_init
    _QUIET_SPINNERS=1
    rm -f "$INSTANCE_CONFIG_CACHE"
    
    local _del_pids=() _del_stale=0
    ( fetch_instance_configurations ) &
    _del_pids+=($!); ((_del_stale++))
    
    if ! is_cache_fresh "$CLUSTER_CACHE" || [[ ! -s "$CLUSTER_CACHE" ]]; then
        ( fetch_gpu_clusters ) &
        _del_pids+=($!); ((_del_stale++))
    fi
    
    _step_active "IC + GPU clusters(${_del_stale} parallel)"
    wait "${_del_pids[@]}" 2>/dev/null
    _step_complete "instance configs($(_clc "$INSTANCE_CONFIG_CACHE"))"
    _step_complete "GPU clusters($(_clc "$CLUSTER_CACHE"))"
    _QUIET_SPINNERS=0
    _step_finish
    
    # Rebuild IC_INDEX_MAP with c# keys from cache
    IC_INDEX_MAP=()
    local _ic_idx=0
    if [[ -f "$INSTANCE_CONFIG_CACHE" ]]; then
        while IFS='|' read -r _ic_ocid _ic_name _; do
            [[ "$_ic_ocid" =~ ^#.*$ ]] && continue
            [[ -z "$_ic_ocid" ]] && continue
            ((_ic_idx++))
            IC_INDEX_MAP["c${_ic_idx}"]="$_ic_ocid"
        done < <(grep -v '^#' "$INSTANCE_CONFIG_CACHE" 2>/dev/null)
    fi
    echo ""
    
    # Check if any instance configurations exist
    if [[ ${#IC_INDEX_MAP[@]} -eq 0 ]]; then
        echo -e "${YELLOW}No Instance Configurations available to delete${NC}"
        echo ""
        _ui_pause
        return 0
    fi
    
    # Display Instance Configurations
    echo -e "${WHITE}Available Instance Configurations:${NC}"
    echo ""
    printf "${BOLD}%-6s %-60s %-20s %s${NC}\n" \
        "ID" "Instance Configuration Name" "Created" "OCID"
    print_separator 160
    
    # Sort and display instance configs, build display map
    local ic_output_temp
    ic_output_temp=$(mktemp "${TEMP_DIR}/tmp.XXXXXXXXXX")
    
    local _did
    for _did in "${!IC_INDEX_MAP[@]}"; do
        # Only process c# keys (skip i# aliases to avoid duplicates)
        [[ "$_did" =~ ^c[0-9]+$ ]] || continue
        local ic_ocid="${IC_INDEX_MAP[$_did]}"
        [[ -z "$ic_ocid" ]] && continue
        
        local ic_name ic_time_created
        ic_name=$(lookup_cache "$INSTANCE_CONFIG_CACHE" "$ic_ocid" 2)
        ic_time_created=$(lookup_cache "$INSTANCE_CONFIG_CACHE" "$ic_ocid" 3)
        
        local time_display="N/A"
        if [[ -n "$ic_time_created" && "$ic_time_created" != "N/A" ]]; then
            time_display="${ic_time_created:0:16}"
            time_display="${time_display/T/ }"
        fi
        
        local _did_num="${_did#c}"
        echo "${_did_num}|${_did}|${ic_name}|${time_display}|${ic_ocid}" >> "$ic_output_temp"
    done
    
    sort -t'|' -k1 -n "$ic_output_temp" | while IFS='|' read -r _ _did ic_name time_display ic_ocid; do
        printf "${YELLOW}%-6s${NC} ${GREEN}%-60s${NC} ${GRAY}%-20s${NC} ${CYAN}%s${NC}\n" \
            "$_did" "$ic_name" "$time_display" "$ic_ocid"
    done
    
    rm -f "$ic_output_temp"
    echo ""
    
    # If no args provided, prompt interactively
    if [[ -z "$delete_args" ]]; then
        echo -e "${WHITE}Usage: Enter one of the following:${NC}"
        echo -e "  ${YELLOW}#${NC}           - Delete a single config (e.g., ${YELLOW}1${NC} or ${YELLOW}c1${NC})"
        echo -e "  ${YELLOW}#,#,#${NC}       - Delete multiple configs (e.g., ${YELLOW}1,3,5${NC} or ${YELLOW}c1,c3,c5${NC})"
        echo -e "  ${YELLOW}#-#${NC}         - Delete a range of configs (e.g., ${YELLOW}1-3${NC} or ${YELLOW}c1-c3${NC})"
        echo -e "  ${RED}all${NC}         - Delete ALL instance configurations"
        echo -e "  ${CYAN}cancel${NC}      - Cancel"
        echo ""
        echo -n -e "${CYAN}Select Instance Configuration(s) to delete: ${NC}"
        read -r delete_args
    fi
    
    # Check for cancel
    if [[ -z "$delete_args" || "$delete_args" == "cancel" ]]; then
        echo -e "${YELLOW}Delete cancelled${NC}"
        return 0
    fi
    
    # Build list of ICs to delete using shared parser
    declare -a DELETE_IDS=()
    declare -a DELETE_OCIDS=()
    declare -a DELETE_NAMES=()
    
    if ! _parse_targets "c" "$delete_args" "IC_INDEX_MAP"; then
        echo -e "${RED}No valid instance configurations selected for deletion${NC}"
        _ui_pause
        return 1
    fi
    
    for _k in "${_SEL_KEYS[@]}"; do
        local ic_ocid="${IC_INDEX_MAP[$_k]}"
        [[ -z "$ic_ocid" ]] && continue
        DELETE_IDS+=("$_k")
        DELETE_OCIDS+=("$ic_ocid")
        
        local ic_name
        ic_name=$(get_instance_config_name "$ic_ocid")
        DELETE_NAMES+=("$ic_name")
    done
    
    # Validate we have something to delete
    if [[ ${#DELETE_OCIDS[@]} -eq 0 ]]; then
        echo -e "${RED}No valid instance configurations selected for deletion${NC}"
        _ui_pause
        return 1
    fi
    
    # Show what will be deleted
    echo ""
    echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║              ⚠️  WARNING: DELETE INSTANCE CONFIGURATION(S)  ⚠️                  ║${NC}"
    echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}The following ${RED}${#DELETE_OCIDS[@]}${WHITE} instance configuration(s) will be deleted:${NC}"
    echo ""
    
    local clusters_warning=""
    for i in "${!DELETE_OCIDS[@]}"; do
        local ic_ocid="${DELETE_OCIDS[$i]}"
        local ic_name="${DELETE_NAMES[$i]}"
        local iid="${DELETE_IDS[$i]}"
        
        printf "  ${YELLOW}%-5s${NC} ${WHITE}%-60s${NC} ${GRAY}%s${NC}\n" "$iid" "$ic_name" "$ic_ocid"
        
        # Check if this IC is in use by any GPU memory clusters
        if [[ -f "$CLUSTER_CACHE" ]]; then
            while IFS='|' read -r cluster_ocid cluster_name cluster_state _ cluster_ic_id _; do
                [[ "$cluster_ocid" =~ ^#.*$ ]] && continue
                [[ -z "$cluster_ocid" ]] && continue
                [[ "$cluster_state" == "DELETED" ]] && continue
                
                if [[ "$cluster_ic_id" == "$ic_ocid" ]]; then
                    clusters_warning+="        ↳ ${RED}IN USE by cluster: ${YELLOW}${cluster_name}${NC} ${GRAY}(${cluster_state})${NC}\n"
                fi
            done < "$CLUSTER_CACHE"
        fi
        
        if [[ -n "$clusters_warning" ]]; then
            echo -e "$clusters_warning"
            clusters_warning=""
        fi
    done
    
    echo ""
    echo -e "${RED}This action cannot be undone!${NC}"
    echo ""
    
    # Show exact commands that will be executed
    echo -e "${BOLD}Commands to Execute:${NC}"
    for i in "${!DELETE_OCIDS[@]}"; do
        echo -e "  ${WHITE}$ oci compute-management instance-configuration delete --instance-configuration-id \"${DELETE_OCIDS[$i]}\" --region \"${region}\" --force${NC}"
    done
    echo ""
    
    # Confirmation
    if [[ ${#DELETE_OCIDS[@]} -gt 1 ]]; then
        if ! _ui_confirm "DELETE ${#DELETE_OCIDS[@]}" "confirm deletion of ${#DELETE_OCIDS[@]} configs"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    else
        if ! _ui_confirm "DELETE" "confirm deletion"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    fi
    
    # Execute deletions
    echo ""
    local success_count=0
    local fail_count=0
    
    for i in "${!DELETE_OCIDS[@]}"; do
        local ic_ocid="${DELETE_OCIDS[$i]}"
        local ic_name="${DELETE_NAMES[$i]}"
        local iid="${DELETE_IDS[$i]}"
        
        local cmd="oci compute-management instance-configuration delete --instance-configuration-id ${ic_ocid} --region ${region} --force"
        
        _ui_subheader "Command to Execute" 0
        echo -e "${GRAY}$ ${cmd}${NC}"
        
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"
        
        local result
        result=$(_safe_exec "$cmd")
        local exit_code=$?
        
        if [[ $exit_code -eq 0 ]]; then
            echo -e "${GREEN}✓ Deleted: ${WHITE}${ic_name}${NC} ${GRAY}(${iid})${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted IC '${ic_name}' (${ic_ocid})" >> "$log_file"
            ((success_count++))
        else
            echo -e "${RED}✗ Failed: ${WHITE}${ic_name}${NC} ${GRAY}(${iid})${NC}"
            echo -e "  ${RED}${result}${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete IC '${ic_name}' (${ic_ocid}): ${result}" >> "$log_file"
            ((fail_count++))
        fi
        echo ""
    done
    
    # Summary
    _ui_subheader "Delete Summary" 0
    echo -e "  ${GREEN}Succeeded:${NC} ${success_count}"
    [[ $fail_count -gt 0 ]] && echo -e "  ${RED}Failed:${NC}    ${fail_count}"
    echo -e "  ${GRAY}Log file:  ${log_file}${NC}"
    echo ""
    
    # Invalidate cache
    rm -f "$INSTANCE_CONFIG_CACHE"
    
    _ui_pause
}

#===============================================================================
# OBJECT STORAGE MANAGEMENT
#===============================================================================

manage_object_storage() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    # Get namespace
    local namespace
    namespace=$(oci os ns get --output json 2>/dev/null | jq -r '.data // empty')
    
    if [[ -z "$namespace" ]]; then
        echo -e "${RED}Failed to get Object Storage namespace${NC}"
        _ui_pause
        return
    fi
    
    while true; do
        echo ""
        _ui_menu_header "OBJECT STORAGE MANAGEMENT" \
            --color "$BLUE" \
            --breadcrumb "Storage" "Object Storage" \
            --cmd "oci os ns get | oci os bucket list --compartment-id \$COMPARTMENT_ID --namespace-name \$NAMESPACE | oci os private-endpoint list --compartment-id \$COMPARTMENT_ID" \
            --env "Namespace" "$namespace"
        
        # Fetch and display data
        _step_init
        _step_complete "namespace(${namespace})"
        
        _step_active "buckets, private endpoints"
        local _os_tmp="${TEMP_DIR}/os_$$"
        mkdir -p "$_os_tmp"
        
        (oci os bucket list --compartment-id "$compartment_id" --namespace-name "$namespace" --region "$region" --output json > "$_os_tmp/buckets.json" 2>/dev/null) &
        local _pid_b=$!
        (oci os private-endpoint list --compartment-id "$compartment_id" --region "$region" --output json > "$_os_tmp/pe.json" 2>/dev/null) &
        local _pid_p=$!
        wait "$_pid_b" "$_pid_p" 2>/dev/null
        
        local buckets_json=""
        [[ -s "$_os_tmp/buckets.json" ]] && buckets_json=$(cat "$_os_tmp/buckets.json")
        local bucket_count=0
        if [[ -n "$buckets_json" && "$buckets_json" != "null" ]]; then
            bucket_count=$(jq '.data | length // 0' <<< "$buckets_json" 2>/dev/null)
        fi
        
        local pe_json=""
        [[ -s "$_os_tmp/pe.json" ]] && pe_json=$(cat "$_os_tmp/pe.json")
        local pe_count=0
        if [[ -n "$pe_json" ]] && jq -e '.data' <<< "$pe_json" > /dev/null 2>&1; then
            pe_count=$(jq '.data | length' <<< "$pe_json" 2>/dev/null)
        fi
        [[ -z "$pe_count" || "$pe_count" == "null" ]] && pe_count=0
        
        rm -rf "$_os_tmp" 2>/dev/null
        _step_complete "buckets(${bucket_count}), endpoints(${pe_count})"
        _step_finish
        
        echo ""
        _ui_subheader "Object Storage Summary" 0
        echo ""
        echo -e "  ${CYAN}Buckets:${NC}           ${WHITE}${bucket_count}${NC}"
        echo -e "  ${CYAN}Private Endpoints:${NC} ${WHITE}${pe_count}${NC}"
        echo ""
        
        # Declare maps outside if blocks for proper scope
        local idx=0
        local pe_idx=0
        declare -A BUCKET_MAP
        declare -A PE_MAP
        BUCKET_MAP=()
        PE_MAP=()
        
        # Display buckets summary table
        if [[ "$bucket_count" -gt 0 ]]; then
            _ui_subheader "Buckets" 0
            printf "  ${BOLD}%-4s %-40s %-15s %-12s %-15s${NC}\n" "b#" "Bucket Name" "Storage Tier" "Versioning" "Auto-Tiering"
            print_separator 100
            
            while IFS='|' read -r bucket_name storage_tier versioning auto_tiering; do
                [[ -z "$bucket_name" ]] && continue
                ((idx++))
                
                BUCKET_MAP[$idx]="$bucket_name"
                
                local tier_display="${storage_tier:-Standard}"
                local version_display="${versioning:-Disabled}"
                local auto_tier_display="${auto_tiering:-Disabled}"
                
                # Color code versioning
                local version_color="$GRAY"
                [[ "$versioning" == "Enabled" ]] && version_color="$GREEN"
                
                printf "  ${YELLOW}%-4s${NC} %-40s %-15s ${version_color}%-12s${NC} %-15s\n" \
                    "b${idx}" "${bucket_name:0:38}" "$tier_display" "$version_display" "$auto_tier_display"
                    
            done < <(jq -r '.data[] | "\(.name)|\(.["storage-tier"] // "Standard")|\(.versioning // "Disabled")|\(.["auto-tiering"] // "Disabled")"' <<< "$buckets_json" 2>/dev/null)
            echo ""
        fi
        
        # Display private endpoints summary
        if [[ "$pe_count" -gt 0 ]]; then
            _ui_subheader "Private Endpoints" 0
            printf "  ${BOLD}%-4s %-30s %-12s %-15s %s${NC}\n" "p#" "Name" "State" "Namespace" "Prefix"
            print_separator 120
            
            # PE_MAP stores: name|namespace for later lookup
            while IFS='|' read -r pe_name pe_state pe_namespace prefix; do
                [[ -z "$pe_name" ]] && continue
                ((pe_idx++))
                
                # Store name|namespace for lookup
                PE_MAP[$pe_idx]="${pe_name}|${pe_namespace}"
                
                local state_color
                state_color=$(color_resource_state "$pe_state")
                
                local prefix_display="${prefix:-N/A}"
                local ns_display="${pe_namespace:-N/A}"
                
                printf "  ${YELLOW}%-4s${NC} %-30s ${state_color}%-12s${NC} %-15s %s\n" \
                    "p${pe_idx}" "${pe_name:0:28}" "$pe_state" "${ns_display:0:13}" "$prefix_display"
                    
            done < <(jq -r '.data[] | "\(.name)|\(.["lifecycle-state"])|\(.namespace)|\(.prefix // "N/A")"' <<< "$pe_json" 2>/dev/null)
            echo ""
        fi
        
        _ui_actions
        echo ""
        _ui_action_group "Buckets"
        echo -e "  ${YELLOW}b#${NC}) ${WHITE}View Bucket Details${NC}    - Enter 'b' + number (e.g., b1)"
        echo ""
        _ui_action_group "Private Endpoints"
        echo -e "  ${YELLOW}p#${NC}) ${WHITE}View PE Details${NC}        - Enter 'p' + number (e.g., p1)"
        echo -e "  ${GREEN}pc${NC}) ${WHITE}Create Private Endpoint${NC}"
        echo -e "  ${RED}pd${NC}) ${WHITE}Delete Private Endpoint${NC}  - (e.g., ${RED}pd p1${NC}, ${RED}pd p1-p3${NC}, ${RED}pd all${NC})"
        echo ""
        _ui_action_group "Operations"
        echo -e "  ${CYAN}w${NC})  ${WHITE}Work Requests${NC}          - View work request status and logs"
        echo ""
        echo -e "  ${MAGENTA}r${NC})  Refresh"
        echo -e "  ${CYAN}b${NC})  Back to main menu"
        echo ""
        _ui_prompt "Object Storage" "b#, p#, r, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        case "$selection" in
            b[0-9]|b[0-9][0-9])
                local bucket_num="${selection:1}"
                if [[ -n "${BUCKET_MAP[$bucket_num]}" ]]; then
                    os_view_bucket_details "$namespace" "${BUCKET_MAP[$bucket_num]}"
                else
                    echo -e "${RED}Invalid bucket number${NC}"
                    sleep 1
                fi
                ;;
            p[0-9]|p[0-9][0-9])
                local pe_num="${selection:1}"
                if [[ -n "${PE_MAP[$pe_num]}" ]]; then
                    os_view_private_endpoint_details "${PE_MAP[$pe_num]}"
                else
                    echo -e "${RED}Invalid private endpoint number${NC}"
                    sleep 1
                fi
                ;;
            pc|PC)
                os_create_private_endpoint "$compartment_id" "$namespace"
                ;;
            pd|PD|pd\ *|PD\ *)
                local _pd_raw="${selection#[pP][dD]}"
                _pd_raw="${_pd_raw# }"
                os_delete_private_endpoints "$compartment_id" "$pe_idx" "$_pd_raw"
                ;;
            w|W)
                os_manage_work_requests "$compartment_id"
                ;;
            r|R) continue ;;
            b|B|back|BACK|"") return ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Object Storage - Manage Work Requests
#--------------------------------------------------------------------------------
os_manage_work_requests() {
    local compartment_id="$1"
    
    while true; do
        echo ""
        _ui_subheader "Object Storage Work Requests" 0
        echo ""
        
        _step_init
        _step_active "work requests"
        
        # Fetch work requests using oci os work-request list
        local wr_json
        wr_json=$(oci os work-request list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --output json 2>/dev/null)
        
        local wr_count=0
        if [[ -n "$wr_json" ]] && jq -e '.data' <<< "$wr_json" > /dev/null 2>&1; then
            wr_count=$(jq '.data | length' <<< "$wr_json" 2>/dev/null)
        fi
        [[ -z "$wr_count" || "$wr_count" == "null" ]] && wr_count=0
        _step_complete "work requests(${wr_count})"
        _step_finish
        
        echo ""
        _ui_subheader "Work Requests (${wr_count})" 0
        
        if [[ "$wr_count" -eq 0 ]]; then
            echo -e "  ${GRAY}No work requests found${NC}"
            echo ""
            echo -e "${GRAY}Note: Work requests may have completed or expired${NC}"
            echo ""
            _ui_pause "return"
            return
        fi
        
        printf "  ${BOLD}%-3s %-12s %-25s %-20s %-8s %-20s${NC}\n" "#" "Status" "Operation" "Resource" "%" "Time"
        print_separator 100
        
        declare -A WR_MAP
        WR_MAP=()
        local idx=0
        
        while IFS='|' read -r wr_id wr_status wr_operation wr_resource wr_percent wr_time wr_finished; do
            [[ -z "$wr_id" ]] && continue
            ((idx++))
            
            WR_MAP[$idx]="$wr_id"
            
            # Format status with color
            local status_color="$WHITE"
            status_color=$(color_resource_state "$wr_status")
            
            # Format operation type - clean up the name
            local op_display="${wr_operation//_/ }"
            op_display="${op_display:0:23}"
            
            # Format resource - extract PE name if present
            local resource_display="N/A"
            if [[ -n "$wr_resource" && "$wr_resource" != "null" ]]; then
                # Check if it's an OCID
                if [[ "$wr_resource" =~ ^ocid1\. ]]; then
                    resource_display="...${wr_resource: -15}"
                else
                    resource_display="${wr_resource:0:18}"
                fi
            fi
            
            # Format time
            local time_display="${wr_time:0:19}"
            [[ -n "$wr_finished" && "$wr_finished" != "null" ]] && time_display="${wr_finished:0:19}"
            
            # Format percentage
            local percent_display="${wr_percent:-0}%"
            
            printf "  ${YELLOW}%-3s${NC} ${status_color}%-12s${NC} %-25s %-20s %-8s %-20s\n" \
                "$idx" "$wr_status" "$op_display" "$resource_display" "$percent_display" "$time_display"
                
        done < <(jq -r '.data[] | "\(.id)|\(.status)|\(.["operation-type"])|\(.resources[0].identifier // "N/A")|\(.["percent-complete"])|\(.["time-accepted"])|\(.["time-finished"])"' <<< "$wr_json" 2>/dev/null)
        
        echo ""
        _ui_actions
        echo -e "  ${YELLOW}1-${idx}${NC}) View work request details and logs"
        echo -e "  ${MAGENTA}r${NC})   Refresh"
        echo -e "  ${CYAN}b${NC})   Back"
        echo ""
        _ui_prompt "Object Storage > WR" "w#, b, show"
        read -r selection
        [[ "${selection:-}" == :* ]] && _nav_try_jump "$selection" && return
        
        case "$selection" in
            [0-9]|[0-9][0-9])
                if [[ -n "${WR_MAP[$selection]}" ]]; then
                    os_view_work_request_details "${WR_MAP[$selection]}"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            r|R) continue ;;
            b|B|back|BACK|"") return ;;
            show|SHOW)
                continue
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Object Storage - View Work Request Details
#--------------------------------------------------------------------------------
os_view_work_request_details() {
    local wr_id="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Work Request Details" 0
    echo ""
    
    # Get work request details using oci os work-request get
    _step_init
    _step_active "work request details"
    local wr_json
    wr_json=$(oci os work-request get \
        --work-request-id "$wr_id" \
        --region "$region" \
        --output json 2>/dev/null)
    _step_complete "work request details"
    _step_finish
    
    if [[ -z "$wr_json" ]] || ! jq -e '.data' <<< "$wr_json" > /dev/null 2>&1; then
        echo -e "${RED}Failed to fetch work request details${NC}"
        _ui_policy_hint "read work-requests in compartment"
        _ui_pause
        return
    fi
    
    # Extract details
    local wr_status wr_operation wr_percent wr_accepted wr_finished
    wr_status=$(jq -r '.data.status // "N/A"' <<< "$wr_json")
    wr_operation=$(jq -r '.data["operation-type"] // "N/A"' <<< "$wr_json")
    wr_percent=$(jq -r '.data["percent-complete"] // 0' <<< "$wr_json")
    wr_accepted=$(jq -r '.data["time-accepted"] // "N/A"' <<< "$wr_json")
    wr_finished=$(jq -r '.data["time-finished"] // "N/A"' <<< "$wr_json")
    
    # Status color
    local status_color="$WHITE"
    status_color=$(color_resource_state "$wr_status")
    
    echo ""
    _ui_subheader "Basic Info" 0
    echo -e "  ${CYAN}Work Request ID:${NC} ${YELLOW}$wr_id${NC}"
    echo -e "  ${CYAN}Operation:${NC}       ${WHITE}$wr_operation${NC}"
    echo -e "  ${CYAN}Status:${NC}          ${status_color}$wr_status${NC}"
    echo -e "  ${CYAN}Progress:${NC}        ${WHITE}${wr_percent}%${NC}"
    echo ""
    _ui_subheader "Timestamps" 0
    echo -e "  ${CYAN}Accepted:${NC}  ${WHITE}${wr_accepted:0:19}${NC}"
    echo -e "  ${CYAN}Finished:${NC}  ${WHITE}${wr_finished:0:19}${NC}"
    
    # Show resources
    local resources
    resources=$(jq -r '.data.resources // []' <<< "$wr_json")
    local resource_count
    resource_count=$(jq 'length' <<< "$resources" 2>/dev/null)
    
    if [[ "$resource_count" -gt 0 ]]; then
        echo ""
        _ui_subheader "Resources" 0
        jq -r '.[] | "  \(.["entity-type"] // "Unknown"): \(.identifier // "N/A")"' <<< "$resources" 2>/dev/null
    fi
    
    # Check for errors if status is FAILED
    if [[ "$wr_status" == "FAILED" || "$wr_status" == "CANCELED" ]]; then
        echo ""
        _ui_subheader "Errors" 0
        
        local errors_json
        errors_json=$(oci os work-request-error list \
            --work-request-id "$wr_id" \
            --region "$region" \
            --output json 2>/dev/null)
        
        if [[ -n "$errors_json" ]] && jq -e '.data[0]' <<< "$errors_json" > /dev/null 2>&1; then
            jq -r '.data[] | "  [\(.code // "ERROR")] \(.message // "No message")"' <<< "$errors_json" 2>/dev/null | while read -r line; do
                echo -e "  ${RED}$line${NC}"
            done
        else
            echo -e "  ${GRAY}No error details available${NC}"
        fi
    fi
    
    # Fetch and display logs
    echo ""
    _ui_subheader "Work Request Logs" 0
    
    local logs_json
    logs_json=$(oci os work-request-log-entry list \
        --work-request-id "$wr_id" \
        --region "$region" \
        --output json 2>/dev/null)
    
    if [[ -n "$logs_json" ]] && jq -e '.data[0]' <<< "$logs_json" > /dev/null 2>&1; then
        local log_count
        log_count=$(jq '.data | length' <<< "$logs_json" 2>/dev/null)
        echo -e "  ${GRAY}(${log_count} log entries)${NC}"
        echo ""
        
        jq -r '.data[] | "\(.timestamp // "N/A")|\(.message // "No message")"' <<< "$logs_json" 2>/dev/null | while IFS='|' read -r log_time log_msg; do
            local time_display="${log_time:0:19}"
            echo -e "  ${GRAY}[$time_display]${NC} $log_msg"
        done
    else
        echo -e "  ${GRAY}No log entries available${NC}"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Object Storage - View Bucket Details
#--------------------------------------------------------------------------------
os_view_bucket_details() {
    local namespace="$1"
    local bucket_name="$2"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Bucket Details: $bucket_name" 0
    _ui_oci_cmd "oci os bucket get --namespace-name \$NAMESPACE --bucket-name \$BUCKET_NAME"
    
    _step_init
    _step_active "bucket details"
    
    local bucket_json
    bucket_json=$(oci os bucket get --namespace-name "$namespace" --bucket-name "$bucket_name" --region "$region" --output json 2>/dev/null)
    
    if [[ -z "$bucket_json" || "$bucket_json" == "null" ]]; then
        _step_complete "bucket details(failed)"
        _step_finish
        echo -e "${RED}Failed to get bucket details${NC}"
        _ui_pause
        return
    fi
    _step_complete "bucket details"
    _step_finish
    
    # Extract fields in single jq call
    local compartment_id created_by etag storage_tier versioning auto_tiering
    local public_access object_events_enabled replication_enabled kms_key_id
    local approximate_count approximate_size
    
    IFS=$'\t' read -r compartment_id created_by etag storage_tier versioning auto_tiering \
        public_access object_events_enabled replication_enabled kms_key_id \
        approximate_count approximate_size time_created < <(jq -r '.data | [
            .["compartment-id"] // "N/A",
            .["created-by"] // "N/A",
            .etag // "N/A",
            .["storage-tier"] // "Standard",
            .versioning // "Disabled",
            .["auto-tiering"] // "Disabled",
            .["public-access-type"] // "NoPublicAccess",
            .["object-events-enabled"] // false,
            .["replication-enabled"] // false,
            .["kms-key-id"] // "N/A",
            .["approximate-count"] // "N/A",
            .["approximate-size"] // "N/A",
            .["time-created"] // "N/A"
        ] | @tsv' <<< "$bucket_json")
    
    # Format size
    local size_display="N/A"
    if [[ "$approximate_size" =~ ^[0-9]+$ ]] && [[ "$approximate_size" -gt 0 ]]; then
        if [[ "$approximate_size" -gt 1099511627776 ]]; then
            size_display=$(echo "scale=2; $approximate_size / 1099511627776" | bc)" TB"
        elif [[ "$approximate_size" -gt 1073741824 ]]; then
            size_display=$(echo "scale=2; $approximate_size / 1073741824" | bc)" GB"
        elif [[ "$approximate_size" -gt 1048576 ]]; then
            size_display=$(echo "scale=2; $approximate_size / 1048576" | bc)" MB"
        else
            size_display="${approximate_size} bytes"
        fi
    fi
    
    _ui_subheader "Basic Information" 0
    echo -e "  ${CYAN}Bucket Name:${NC}      ${WHITE}$bucket_name${NC}"
    echo -e "  ${CYAN}Namespace:${NC}        ${WHITE}$namespace${NC}"
    echo -e "  ${CYAN}Storage Tier:${NC}     ${WHITE}$storage_tier${NC}"
    echo -e "  ${CYAN}Time Created:${NC}     ${WHITE}${time_created/T/ }${NC}"
    echo -e "  ${CYAN}Compartment:${NC}      ${WHITE}$(resolve_compartment_name "$compartment_id")${NC} ${GRAY}($compartment_id)${NC}"
    echo ""
    
    _ui_subheader "Storage Statistics" 0
    echo -e "  ${CYAN}Object Count:${NC}     ${WHITE}$approximate_count${NC}"
    echo -e "  ${CYAN}Total Size:${NC}       ${WHITE}$size_display${NC}"
    echo ""
    
    _ui_subheader "Configuration" 0
    local version_color="$GRAY"
    [[ "$versioning" == "Enabled" ]] && version_color="$GREEN"
    echo -e "  ${CYAN}Versioning:${NC}       ${version_color}$versioning${NC}"
    
    local auto_tier_color="$GRAY"
    [[ "$auto_tiering" == "InfrequentAccess" ]] && auto_tier_color="$GREEN"
    echo -e "  ${CYAN}Auto-Tiering:${NC}     ${auto_tier_color}$auto_tiering${NC}"
    
    local public_color="$GREEN"
    [[ "$public_access" != "NoPublicAccess" ]] && public_color="$YELLOW"
    echo -e "  ${CYAN}Public Access:${NC}    ${public_color}$public_access${NC}"
    
    local events_color="$GRAY"
    [[ "$object_events_enabled" == "true" ]] && events_color="$GREEN"
    echo -e "  ${CYAN}Object Events:${NC}    ${events_color}$object_events_enabled${NC}"
    
    local repl_color="$GRAY"
    [[ "$replication_enabled" == "true" ]] && repl_color="$GREEN"
    echo -e "  ${CYAN}Replication:${NC}      ${repl_color}$replication_enabled${NC}"
    echo ""
    
    _ui_subheader "Encryption" 0
    if [[ "$kms_key_id" != "N/A" && "$kms_key_id" != "null" && -n "$kms_key_id" ]]; then
        echo -e "  ${CYAN}Encryption:${NC}       ${WHITE}Customer-managed KMS${NC}"
        echo -e "  ${CYAN}KMS Key:${NC}          ${YELLOW}$kms_key_id${NC}"
    else
        echo -e "  ${CYAN}Encryption:${NC}       ${WHITE}Oracle-managed${NC}"
    fi
    echo ""
    
    _ui_subheader "Access URLs" 0
    echo -e "  ${CYAN}Object Storage:${NC}  ${WHITE}https://objectstorage.${FOCUS_REGION:-$REGION}.oraclecloud.com/n/${namespace}/b/${bucket_name}/o/${NC}"
    echo -e "  ${CYAN}Swift:${NC}           ${WHITE}https://swiftobjectstorage.${FOCUS_REGION:-$REGION}.oraclecloud.com/v1/${namespace}/${bucket_name}${NC}"
    echo ""

    echo -e "  ${YELLOW}j${NC}) View raw JSON (j <keyword> to search)  ${CYAN}Enter${NC}) Return"
    echo ""
    _ui_prompt "Bucket" "j, Enter"
    local _bk_choice
    read -r _bk_choice
    [[ "${_bk_choice:-}" == :* ]] && _nav_try_jump "$_bk_choice" && return
    case "$_bk_choice" in
        j|J|json|JSON) _ui_json_viewer "Bucket: $bucket_name" "$bucket_json" ".data" ;;
        j\ *|J\ *|json\ *|JSON\ *) _ui_json_viewer "Bucket: $bucket_name" "$bucket_json" ".data" "${_bk_choice#* }" ;;
    esac
}

#--------------------------------------------------------------------------------
# Object Storage - View Private Endpoint Details
#--------------------------------------------------------------------------------
os_view_private_endpoint_details() {
    local pe_info="$1"
    local region="${FOCUS_REGION:-$REGION}"

    echo ""
    _ui_subheader "Private Endpoint Details" 0
    _ui_oci_cmd "oci os private-endpoint get --pe-name \$PE_NAME --namespace-name \$NAMESPACE | oci network subnet get --subnet-id \$SUBNET_ID | oci network nsg get-nsg-rules"
    
    # Parse name|namespace from pe_info
    local pe_name pe_namespace
    IFS='|' read -r pe_name pe_namespace <<< "$pe_info"
    
    # Validate
    if [[ -z "$pe_name" || -z "$pe_namespace" ]]; then
        echo -e "${RED}Invalid private endpoint reference${NC}"
        _ui_pause
        return
    fi
    
    _step_init
    _step_active "private endpoint"
    
    local pe_json
    pe_json=$(oci os private-endpoint get --pe-name "$pe_name" --namespace-name "$pe_namespace" --region "$region" --output json 2>&1)
    _step_complete "private endpoint(${pe_name})"
    
    # Check for API error
    if ! jq -e '.data' <<< "$pe_json" > /dev/null 2>&1; then
        _step_finish
        echo -e "${RED}Failed to get private endpoint details${NC}"
        echo -e "${GRAY}Error: ${pe_json:0:200}${NC}"
        _ui_pause
        return
    fi
    
    # Extract fields
    local name state compartment_id namespace prefix subnet_id
    local private_ip time_created pe_id
    
    name=$(jq -r '.data.name // "N/A"' <<< "$pe_json")
    IFS=$'\t' read -r state compartment_id namespace prefix subnet_id \
        private_ip time_created pe_id < <(jq -r '.data | [
            .["lifecycle-state"] // "N/A",
            .["compartment-id"] // "N/A",
            .namespace // "N/A",
            .prefix // "N/A",
            .["subnet-id"] // "N/A",
            .["private-endpoint-ip"] // "N/A",
            .["time-created"] // "N/A",
            .id // "N/A"
        ] | @tsv' <<< "$pe_json")
    
    # Prefetch subnet + NSG rules in parallel
    local subnet_name="" subnet_cidr=""
    local nsg_ids_json
    nsg_ids_json=$(jq -c '.data["nsg-ids"] // []' <<< "$pe_json")
    local nsg_count
    nsg_count=$(jq 'length' <<< "$nsg_ids_json" 2>/dev/null || echo "0")
    
    local _pe_pids=() _pe_stale=0
    local _pe_tmp="${TEMP_DIR}/pe_detail_$$"
    mkdir -p "$_pe_tmp"
    
    # Launch subnet get in background
    if [[ -n "$subnet_id" && "$subnet_id" != "N/A" && "$subnet_id" != "null" ]]; then
        (oci network subnet get --subnet-id "$subnet_id" --output json > "$_pe_tmp/subnet.json" 2>/dev/null) &
        _pe_pids+=($!); ((_pe_stale++))
    fi
    
    # Launch NSG rules fetch in background
    if [[ "$nsg_count" -gt 0 ]]; then
        (
            local nsg_ids_list=""
            while read -r nsg_id; do
                [[ -n "$nsg_id" ]] && nsg_ids_list+="$nsg_id"$'\n'
            done < <(jq -r '.[]' <<< "$nsg_ids_json" 2>/dev/null)
            fetch_nsg_rules_detail_parallel "$nsg_ids_list"
        ) &
        _pe_pids+=($!); ((_pe_stale++))
    fi
    
    if [[ ${#_pe_pids[@]} -gt 0 ]]; then
        _step_active "subnet+NSGs(${_pe_stale} parallel)"
        wait "${_pe_pids[@]}" 2>/dev/null
    fi
    
    # Read subnet results
    if [[ -s "$_pe_tmp/subnet.json" ]]; then
        subnet_name=$(jq -r '.data["display-name"] // "N/A"' "$_pe_tmp/subnet.json" 2>/dev/null)
        subnet_cidr=$(jq -r '.data["cidr-block"] // "N/A"' "$_pe_tmp/subnet.json" 2>/dev/null)
        _step_complete "subnet(${subnet_name})"
    fi
    [[ "$nsg_count" -gt 0 ]] && _step_complete "NSG rules(${nsg_count})"
    rm -rf "${_pe_tmp:?}"
    _step_finish
    
    local state_color
    state_color=$(color_resource_state "$state")
    
    echo ""
    _ui_subheader "Basic Information" 0
    echo -e "  ${CYAN}Name:${NC}            ${WHITE}$name${NC}"
    echo -e "  ${CYAN}State:${NC}           ${state_color}$state${NC}"
    echo -e "  ${CYAN}Namespace:${NC}       ${WHITE}$namespace${NC}"
    echo -e "  ${CYAN}Prefix:${NC}          ${WHITE}$prefix${NC}"
    echo -e "  ${CYAN}Time Created:${NC}    ${WHITE}${time_created/T/ }${NC}"
    echo -e "  ${CYAN}PE OCID:${NC}         ${YELLOW}$pe_id${NC}"
    echo -e "  ${CYAN}Compartment:${NC}     ${WHITE}$(resolve_compartment_name "$compartment_id")${NC} ${GRAY}($compartment_id)${NC}"
    echo ""
    
    _ui_subheader "Network Configuration" 0
    echo -e "  ${CYAN}Private IP:${NC}      ${WHITE}$private_ip${NC}"
    
    # Display subnet details
    if [[ -n "$subnet_name" ]]; then
        echo -e "  ${CYAN}Subnet:${NC}          ${WHITE}$subnet_name${NC} (${subnet_cidr})"
        echo -e "  ${CYAN}Subnet OCID:${NC}     ${YELLOW}$subnet_id${NC}"
    else
        echo -e "  ${CYAN}Subnet OCID:${NC}     ${GRAY}N/A${NC}"
    fi
    echo ""
    
    # Display NSGs
    PE_NSG_MAP=()
    local nsg_idx=0
    
    if [[ "$nsg_count" -gt 0 ]]; then
        _ui_subheader "Network Security Groups" 0
        printf "  ${BOLD}%-3s %-35s %s${NC}\n" "#" "NSG Name" "OCID"
        
        while read -r nsg_id; do
            [[ -z "$nsg_id" ]] && continue
            ((nsg_idx++))
            PE_NSG_MAP[$nsg_idx]="$nsg_id"
            
            # Get NSG name from cache
            local nsg_name="Unknown"
            local cached_data
            cached_data=$(get_cached_nsg_rules "$nsg_id")
            if [[ -n "$cached_data" ]]; then
                nsg_name=$(jq -r '.nsg_name // "Unknown"' <<< "$cached_data" 2>/dev/null)
            fi
            
            printf "  ${YELLOW}%-3s${NC} ${WHITE}%-35s${NC} ${GRAY}%s${NC}\n" "$nsg_idx" "${nsg_name:0:33}" "$nsg_id"
        done < <(jq -r '.[]' <<< "$nsg_ids_json" 2>/dev/null)
        echo ""
    else
        _ui_subheader "Network Security Groups" 0
        echo -e "  ${GRAY}None configured${NC}"
        echo ""
    fi
    
    # Access targets
    local access_targets
    access_targets=$(jq -r '.data["access-targets"] // []' <<< "$pe_json")
    local target_count
    target_count=$(jq 'length' <<< "$access_targets" 2>/dev/null || echo "0")
    
    if [[ "$target_count" -gt 0 ]]; then
        _ui_subheader "Access Targets" 0
        while IFS='|' read -r target_namespace target_compartment target_bucket; do
            [[ -z "$target_namespace" ]] && continue
            echo -e "  ${CYAN}Namespace:${NC}   ${WHITE}$target_namespace${NC}"
            if [[ "$target_compartment" == "*" ]]; then
                echo -e "  ${CYAN}Compartment:${NC} ${WHITE}All compartments${NC}"
            else
                echo -e "  ${CYAN}Compartment:${NC} ${WHITE}$(resolve_compartment_name "$target_compartment")${NC} ${GRAY}($target_compartment)${NC}"
            fi
            if [[ "$target_bucket" == "*" ]]; then
                echo -e "  ${CYAN}Bucket:${NC}      ${WHITE}All buckets${NC}"
            elif [[ "$target_bucket" != "null" && -n "$target_bucket" ]]; then
                echo -e "  ${CYAN}Bucket:${NC}      ${WHITE}$target_bucket${NC}"
            fi
            echo ""
        done < <(jq -r '.[] | "\(.namespace)|\(.["compartment-id"])|\(.bucket // "null")"' <<< "$access_targets" 2>/dev/null)
    fi
    
    # FQDNs - correct structure: .data.fqdns["prefix-fqdns"]
    _ui_subheader "FQDNs" 0
    local obj_fqdn swift_fqdn s3_fqdn
    obj_fqdn=$(jq -r '.data.fqdns["prefix-fqdns"]["object-storage-api-fqdn"] // "N/A"' <<< "$pe_json")
    swift_fqdn=$(jq -r '.data.fqdns["prefix-fqdns"]["swift-api-fqdn"] // "N/A"' <<< "$pe_json")
    s3_fqdn=$(jq -r '.data.fqdns["prefix-fqdns"]["s3-compatibility-api-fqdn"] // "N/A"' <<< "$pe_json")
    
    # Store FQDNs in map for dig selection (use global for child function access)
    PE_FQDN_MAP=()
    local fqdn_idx=0
    
    if [[ "$obj_fqdn" != "N/A" && -n "$obj_fqdn" ]]; then
        ((fqdn_idx++))
        PE_FQDN_MAP[$fqdn_idx]="$obj_fqdn|Object Storage API"
    fi
    if [[ "$swift_fqdn" != "N/A" && -n "$swift_fqdn" ]]; then
        ((fqdn_idx++))
        PE_FQDN_MAP[$fqdn_idx]="$swift_fqdn|Swift API"
    fi
    if [[ "$s3_fqdn" != "N/A" && -n "$s3_fqdn" ]]; then
        ((fqdn_idx++))
        PE_FQDN_MAP[$fqdn_idx]="$s3_fqdn|S3 Compatibility API"
    fi
    
    printf "  ${BOLD}%-3s %-25s %s${NC}\n" "#" "API Type" "FQDN"
    local fidx=0
    if [[ "$obj_fqdn" != "N/A" && -n "$obj_fqdn" ]]; then
        ((fidx++))
        printf "  ${YELLOW}%-3s${NC} %-25s ${WHITE}%s${NC}\n" "$fidx" "Object Storage API" "$obj_fqdn"
    fi
    if [[ "$swift_fqdn" != "N/A" && -n "$swift_fqdn" ]]; then
        ((fidx++))
        printf "  ${YELLOW}%-3s${NC} %-25s ${WHITE}%s${NC}\n" "$fidx" "Swift API" "$swift_fqdn"
    fi
    if [[ "$s3_fqdn" != "N/A" && -n "$s3_fqdn" ]]; then
        ((fidx++))
        printf "  ${YELLOW}%-3s${NC} %-25s ${WHITE}%s${NC}\n" "$fidx" "S3 Compatibility API" "$s3_fqdn"
    fi
    echo ""
    
    # Additional FQDN entries
    local additional_fqdns
    additional_fqdns=$(jq -r '.data.fqdns["additional-prefixes-fqdns"] // {}' <<< "$pe_json")
    local add_fqdn_count
    add_fqdn_count=$(jq 'keys | length' <<< "$additional_fqdns" 2>/dev/null || echo "0")
    
    if [[ "$add_fqdn_count" -gt 0 ]]; then
        _ui_subheader "Additional Prefix FQDNs" 0
        while IFS='|' read -r add_key add_val; do
            [[ -z "$add_key" ]] && continue
            ((fqdn_idx++))
            PE_FQDN_MAP[$fqdn_idx]="$add_val|Additional: $add_key"
            printf "  ${YELLOW}%-3s${NC} %-25s ${WHITE}%s${NC}\n" "$fqdn_idx" "Additional: $add_key" "$add_val"
        done < <(jq -r 'to_entries[] | "\(.key)|\(.value)"' <<< "$additional_fqdns" 2>/dev/null)
        echo ""
    fi
    
    # Interactive actions
    _ui_actions
    echo ""
    _ui_action_group "DNS Lookup (dig)"
    if [[ "$fqdn_idx" -gt 0 ]]; then
        echo -e "  ${YELLOW}d1-d${fqdn_idx}${NC}) Dig individual FQDN (e.g., d1)"
        echo -e "  ${CYAN}da${NC})   Dig ALL FQDNs"
    fi
    echo ""
    if [[ "$nsg_idx" -gt 0 ]]; then
        _ui_action_group "NSG Rules"
        echo -e "  ${YELLOW}n1-n${nsg_idx}${NC}) View individual NSG rules (e.g., n1)"
        echo -e "  ${CYAN}na${NC})   Show ALL NSG rules"
        echo -e "  ${CYAN}p${NC})    Check for required ports (80/443 ingress)"
        echo ""
    fi
    echo -e "  ${YELLOW}j${NC})    View raw JSON (j <keyword> to search)"
    echo -e "  ${WHITE}Enter${NC}) Return"
    echo ""
    echo -n -e "${BOLD}${CYAN}Select option (or Enter to return): ${NC}"
    read -r selection
    
    # Handle port check command
    if [[ "$selection" == "p" || "$selection" == "P" || "$selection" == "port" || "$selection" == "ports" ]]; then
        pe_check_required_ports "$nsg_idx" "$private_ip" "$subnet_id"
        echo ""
        _ui_pause
    # Handle dig commands
    elif [[ "$selection" =~ ^d[0-9]+$ ]]; then
        local dig_num="${selection:1}"
        if [[ -n "${PE_FQDN_MAP[$dig_num]}" ]]; then
            local fqdn_entry="${PE_FQDN_MAP[$dig_num]}"
            local fqdn_val="${fqdn_entry%%|*}"
            local fqdn_label="${fqdn_entry##*|}"
            echo ""
            pe_dig_fqdn "$fqdn_val" "$fqdn_label"
        else
            echo -e "${RED}Invalid FQDN number${NC}"
        fi
        echo ""
        _ui_pause
    elif [[ "$selection" == "da" || "$selection" == "DA" ]]; then
        echo ""
        _ui_subheader "DNS Lookup for All FQDNs" 0
        for ((i=1; i<=fqdn_idx; i++)); do
            local fqdn_entry="${PE_FQDN_MAP[$i]}"
            [[ -z "$fqdn_entry" ]] && continue
            local fqdn_val="${fqdn_entry%%|*}"
            local fqdn_label="${fqdn_entry##*|}"
            echo ""
            print_separator 80 "${BOLD}${MAGENTA}"
            pe_dig_fqdn "$fqdn_val" "$fqdn_label"
        done
        echo ""
        _ui_pause
    # Handle NSG commands
    elif [[ "$selection" =~ ^n[0-9]+$ ]]; then
        local nsg_num="${selection:1}"
        if [[ -n "${PE_NSG_MAP[$nsg_num]}" ]]; then
            os_view_nsg_rules "${PE_NSG_MAP[$nsg_num]}"
        else
            echo -e "${RED}Invalid NSG number${NC}"
            sleep 1
        fi
    elif [[ "$selection" == "na" || "$selection" == "NA" ]]; then
        # Show all NSGs using cached data
        echo ""
        _ui_subheader "All NSG Rules" 0
        for ((i=1; i<=nsg_idx; i++)); do
            local nsg_id="${PE_NSG_MAP[$i]}"
            [[ -z "$nsg_id" ]] && continue
            
            echo ""
            print_separator 80 "${BOLD}${MAGENTA}"
            
            # Get NSG details from cache
            local cached_data nsg_name rules_json
            cached_data=$(get_cached_nsg_rules "$nsg_id")
            
            if [[ -n "$cached_data" ]]; then
                nsg_name=$(jq -r '.nsg_name // "Unknown"' <<< "$cached_data")
                # Wrap rules in data format for display_nsg_rules_table
                rules_json=$(jq '{data: .rules}' <<< "$cached_data")
            else
                # Fallback to direct fetch if cache miss
                local nsg_detail_json
                nsg_detail_json=$(oci network nsg get --nsg-id "$nsg_id" --output json 2>/dev/null)
                nsg_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$nsg_detail_json")
                rules_json=$(oci network nsg rules list --nsg-id "$nsg_id" --all --output json 2>/dev/null)
            fi
            
            echo -e "${BOLD}${CYAN}NSG #${i}: ${WHITE}$nsg_name${NC}"
            echo -e "${CYAN}NSG OCID:${NC} ${YELLOW}$nsg_id${NC}"
            echo ""
            
            display_nsg_rules_table "$rules_json" "false"
        done
        echo ""
        _ui_pause
    elif [[ "$selection" == "j" || "$selection" == "J" || "$selection" == "json" || "$selection" == "JSON" ]]; then
        _ui_json_viewer "OS Private Endpoint: $name" "$pe_json" ".data"
    elif [[ "$selection" == j\ * || "$selection" == J\ * || "$selection" == json\ * || "$selection" == JSON\ * ]]; then
        _ui_json_viewer "OS Private Endpoint: $name" "$pe_json" ".data" "${selection#* }"
    elif [[ -z "$selection" ]]; then
        # Enter pressed, return
        return
    fi
}

#--------------------------------------------------------------------------------
# Private Endpoint - Dig FQDN and check for private IP
#--------------------------------------------------------------------------------
pe_dig_fqdn() {
    local fqdn="$1"
    local label="$2"
    
    echo -e "${BOLD}${CYAN}FQDN:${NC} ${WHITE}$label${NC}"
    echo -e "${CYAN}Host:${NC} ${WHITE}$fqdn${NC}"
    echo ""
    
    # Perform dig
    local dig_output
    dig_output=$(dig +short "$fqdn" 2>/dev/null)
    
    if [[ -z "$dig_output" ]]; then
        echo -e "${RED}No DNS response received${NC}"
        return
    fi
    
    _ui_subheader "DNS Resolution" 0
    
    # Check each IP in the response
    local has_private=false
    local has_public=false
    
    while read -r ip_line; do
        [[ -z "$ip_line" ]] && continue
        
        # Check if it's a private IP (10.x.x.x, 172.16-31.x.x, 192.168.x.x)
        if [[ "$ip_line" =~ ^10\. ]] || \
           [[ "$ip_line" =~ ^172\.(1[6-9]|2[0-9]|3[0-1])\. ]] || \
           [[ "$ip_line" =~ ^192\.168\. ]]; then
            echo -e "  ${GREEN}✓ $ip_line${NC} ${GRAY}(Private IP)${NC}"
            has_private=true
        elif [[ "$ip_line" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            echo -e "  ${RED}✗ $ip_line${NC} ${RED}(PUBLIC IP - NOT using Private Endpoint!)${NC}"
            has_public=true
        else
            # Could be a CNAME or other record
            echo -e "  ${YELLOW}→ $ip_line${NC} ${GRAY}(CNAME/Alias)${NC}"
        fi
    done <<< "$dig_output"
    
    echo ""
    
    # Summary
    if [[ "$has_public" == "true" ]]; then
        echo -e "${BOLD}${RED}⚠ WARNING: DNS is resolving to PUBLIC IP!${NC}"
        echo -e "${RED}  Traffic is NOT routing through the Private Endpoint.${NC}"
        echo -e "${RED}  Check VCN DNS resolver configuration.${NC}"
    elif [[ "$has_private" == "true" ]]; then
        echo -e "${BOLD}${GREEN}✓ DNS is correctly resolving to Private IP${NC}"
        echo -e "${GREEN}  Traffic will route through the Private Endpoint.${NC}"
    fi
}

#--------------------------------------------------------------------------------
# Private Endpoint - Check for required ports (80/443 ingress)
#--------------------------------------------------------------------------------
pe_check_required_ports() {
    local nsg_count="$1"
    local private_ip="$2"
    local subnet_id="$3"
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    
    # Declare function-level variables for tracking missing rules
    declare -A missing_nsg_ports
    declare -A missing_sl_ports
    
    echo ""
    _ui_subheader "Required Ports Check (80/443 Ingress)" 0
    echo ""
    
    # Build NSG name lookup map for the compartment (to resolve source NSG OCIDs to names)
    echo -e "${GRAY}Building NSG name lookup...${NC}"
    declare -gA PE_NSG_NAME_LOOKUP
    PE_NSG_NAME_LOOKUP=()
    
    local all_nsgs_json
    all_nsgs_json=$(oci network nsg list --compartment-id "$compartment_id" --region "${FOCUS_REGION:-$REGION}" --all --output json 2>/dev/null)
    
    if [[ -n "$all_nsgs_json" ]]; then
        while IFS='|' read -r lookup_id lookup_name; do
            [[ -n "$lookup_id" ]] && PE_NSG_NAME_LOOKUP["$lookup_id"]="$lookup_name"
        done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$all_nsgs_json" 2>/dev/null)
    fi
    
    # Collect all NSG IDs for parallel fetch
    local nsg_ids=""
    for ((i=1; i<=nsg_count; i++)); do
        local nsg_id="${PE_NSG_MAP[$i]}"
        [[ -n "$nsg_id" ]] && nsg_ids+="$nsg_id"$'\n'
    done
    
    # Fetch all NSG rules in parallel with caching
    if [[ "$nsg_count" -gt 0 ]]; then
        fetch_nsg_rules_detail_parallel "$nsg_ids"
    fi
    echo ""
    
    # Track overall findings - arrays for good/missing rules
    local missing_rules=()
    declare -A nsg_good_rules   # nsg_id -> pipe-delimited good rules
    declare -A nsg_has_80       # nsg_id -> true/false
    declare -A nsg_has_443      # nsg_id -> true/false
    declare -A NSG_NAMES        # nsg_id -> name
    
    # ═══════════════════════════════════════════════════════════════════════════
    # NSG SECTION
    # ═══════════════════════════════════════════════════════════════════════════
    _ui_subheader "Network Security Groups" 0
    echo ""
    
    if [[ "$nsg_count" -eq 0 ]]; then
        echo -e "${YELLOW}No NSGs configured on this Private Endpoint${NC}"
    else
        # Check each NSG using cached data
        for ((i=1; i<=nsg_count; i++)); do
            local nsg_id="${PE_NSG_MAP[$i]}"
            [[ -z "$nsg_id" ]] && continue
            
            # Get cached NSG rules
            local cached_data nsg_name rules_data
            cached_data=$(get_cached_nsg_rules "$nsg_id")
            
            if [[ -n "$cached_data" ]]; then
                nsg_name=$(jq -r '.nsg_name // "Unknown"' <<< "$cached_data")
                rules_data=$(jq -c '.rules // []' <<< "$cached_data")
            else
                # Fallback to direct fetch if cache miss
                local nsg_json
                nsg_json=$(oci network nsg get --nsg-id "$nsg_id" --output json 2>/dev/null)
                nsg_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$nsg_json")
                
                local rules_json
                rules_json=$(oci network nsg rules list --nsg-id "$nsg_id" --all --output json 2>/dev/null)
                rules_data=$(jq -c '.data // []' <<< "$rules_json")
            fi
            
            NSG_NAMES[$nsg_id]="$nsg_name"
            nsg_has_80[$nsg_id]="false"
            nsg_has_443[$nsg_id]="false"
            nsg_good_rules[$nsg_id]=""
            
            if [[ -z "$rules_data" ]] || [[ "$rules_data" == "[]" ]] || [[ "$rules_data" == "null" ]]; then
                missing_rules+=("$nsg_id|$nsg_name|80")
                missing_rules+=("$nsg_id|$nsg_name|443")
                continue
            fi
            
            # Check for port 80 and 443 ingress rules
            while IFS='|' read -r rule_source rule_protocol rule_ports rule_desc rule_port_type; do
                [[ -z "$rule_source" ]] && continue
                
                # Resolve source to name if it's an NSG OCID
                local resolved_source="$rule_source"
                if [[ "$rule_source" =~ ^ocid1\.networksecuritygroup\. ]]; then
                    local lookup_name="${PE_NSG_NAME_LOOKUP[$rule_source]}"
                    if [[ -n "$lookup_name" ]]; then
                        resolved_source="$lookup_name"
                    else
                        resolved_source="...${rule_source: -12}"
                    fi
                fi
                
                # Store the good rule
                local rule_entry="$resolved_source|$rule_protocol|$rule_ports|$rule_desc"
                if [[ -n "${nsg_good_rules[$nsg_id]}" ]]; then
                    nsg_good_rules[$nsg_id]="${nsg_good_rules[$nsg_id]}"$'\n'"$rule_entry"
                else
                    nsg_good_rules[$nsg_id]="$rule_entry"
                fi
                
                # Check which ports this rule covers
                if [[ "$rule_port_type" == "80" || "$rule_port_type" == "both" ]]; then
                    nsg_has_80[$nsg_id]="true"
                fi
                if [[ "$rule_port_type" == "443" || "$rule_port_type" == "both" ]]; then
                    nsg_has_443[$nsg_id]="true"
                fi
            done < <(jq -r ' 
                .[] | 
                select(.direction == "INGRESS") |
                select(.protocol == "6" or .protocol == "all") |
                # Check if covers port 80
                (if (.protocol == "all") or (.["tcp-options"] == null) or (.["tcp-options"]["destination-port-range"] == null) or
                   ((.["tcp-options"]["destination-port-range"]["min"] // 0) <= 80 and (.["tcp-options"]["destination-port-range"]["max"] // 0) >= 80)
                then true else false end) as $covers80 |
                # Check if covers port 443  
                (if (.protocol == "all") or (.["tcp-options"] == null) or (.["tcp-options"]["destination-port-range"] == null) or
                   ((.["tcp-options"]["destination-port-range"]["min"] // 0) <= 443 and (.["tcp-options"]["destination-port-range"]["max"] // 0) >= 443)
                then true else false end) as $covers443 |
                # Only output rules that cover at least one port
                select($covers80 or $covers443) |
                # Determine port type for tracking
                (if $covers80 and $covers443 then "both" elif $covers80 then "80" else "443" end) as $portType |
                "\(.source // "N/A")|\(if .protocol == "all" then "ALL" else "TCP" end)|\(if .protocol == "all" or .["tcp-options"] == null or .["tcp-options"]["destination-port-range"] == null then "ALL" else "\(.["tcp-options"]["destination-port-range"]["min"])-\(.["tcp-options"]["destination-port-range"]["max"])" end)|\(.description // "No description")|\($portType)"
            ' <<< "$rules_data" 2>/dev/null)
            
            # Track missing ports
            [[ "${nsg_has_80[$nsg_id]}" == "false" ]] && missing_rules+=("$nsg_id|$nsg_name|80")
            [[ "${nsg_has_443[$nsg_id]}" == "false" ]] && missing_rules+=("$nsg_id|$nsg_name|443")
        done
        
        # Display GOOD rules section
        local has_good_rules=false
        for nsg_id in "${!nsg_good_rules[@]}"; do
            [[ -n "${nsg_good_rules[$nsg_id]}" ]] && has_good_rules=true && break
        done
        
        if [[ "$has_good_rules" == "true" ]]; then
            echo -e "${BOLD}${GREEN}Good (ports 80/443 covered):${NC}"
            printf "  ${BOLD}%-25s %-25s %-8s %-10s %s${NC}\n" "NSG Name" "Source" "Protocol" "Ports" "Description"
            print_separator 100
            
            for nsg_id in "${!nsg_good_rules[@]}"; do
                local nsg_name="${NSG_NAMES[$nsg_id]}"
                [[ -z "${nsg_good_rules[$nsg_id]}" ]] && continue
                
                local first_line=true
                while IFS='|' read -r src proto ports desc; do
                    [[ -z "$src" ]] && continue
                    if [[ "$first_line" == "true" ]]; then
                        printf "  ${GREEN}%-25s${NC} ${CYAN}%-25s${NC} %-8s %-10s ${GRAY}%s${NC}\n" \
                            "${nsg_name:0:25}" "${src:0:25}" "$proto" "$ports" "${desc:0:40}"
                        first_line=false
                    else
                        printf "  ${GREEN}%-25s${NC} ${CYAN}%-25s${NC} %-8s %-10s ${GRAY}%s${NC}\n" \
                            "" "${src:0:25}" "$proto" "$ports" "${desc:0:40}"
                    fi
                done <<< "${nsg_good_rules[$nsg_id]}"
            done
            echo ""
        fi
        
        # Display MISSING rules section
        # Build unique missing NSG list with ports
        for missing in "${missing_rules[@]}"; do
            local m_nsg_id="${missing%%|*}"
            local temp="${missing#*|}"
            local m_nsg_name="${temp%%|*}"
            local m_port="${temp##*|}"
            
            if [[ -z "${missing_nsg_ports[$m_nsg_id]}" ]]; then
                missing_nsg_ports[$m_nsg_id]="$m_nsg_name|$m_port"
            else
                # Append port if not already there
                if [[ ! "${missing_nsg_ports[$m_nsg_id]}" =~ \|$m_port ]]; then
                    missing_nsg_ports[$m_nsg_id]="${missing_nsg_ports[$m_nsg_id]},$m_port"
                fi
            fi
        done
        
        if [[ ${#missing_nsg_ports[@]} -gt 0 ]]; then
            echo -e "${BOLD}${RED}Missing (need ingress rules):${NC}"
            printf "  ${BOLD}%-35s %-12s %-12s %s${NC}\n" "NSG Name" "Port 80" "Port 443" "OCID"
            print_separator 100
            
            for nsg_id in "${!missing_nsg_ports[@]}"; do
                local info="${missing_nsg_ports[$nsg_id]}"
                local nsg_name="${info%%|*}"
                local ports="${info#*|}"
                
                local p80_status="${GREEN}✓${NC}"
                local p443_status="${GREEN}✓${NC}"
                [[ "$ports" =~ 80 ]] && p80_status="${RED}✗ Missing${NC}"
                [[ "$ports" =~ 443 ]] && p443_status="${RED}✗ Missing${NC}"
                
                printf "  ${WHITE}%-35s${NC} %-20s %-20s ${GRAY}...%s${NC}\n" \
                    "${nsg_name:0:35}" "$(echo -e $p80_status)" "$(echo -e $p443_status)" "${nsg_id: -12}"
            done
            echo ""
        else
            echo -e "${GREEN}✓ All NSGs have port 80/443 ingress rules${NC}"
            echo ""
        fi
    fi
    
    # ═══════════════════════════════════════════════════════════════════════════
    # SECURITY LIST SECTION - Only check SLs on the PE's subnet
    # ═══════════════════════════════════════════════════════════════════════════
    _ui_subheader "Security Lists (Subnet: ${subnet_id:+...${subnet_id: -12}})" 0
    echo ""
    
    local sl_missing_rules=()
    declare -A sl_good_rules
    declare -A sl_has_80
    declare -A sl_has_443
    declare -A SL_NAMES
    local sl_count=0
    local sl_json=""
    
    if [[ -z "$subnet_id" || "$subnet_id" == "N/A" || "$subnet_id" == "null" ]]; then
        echo -e "${YELLOW}No subnet associated with Private Endpoint - cannot check Security Lists${NC}"
    else
        # Get the subnet's security list IDs
        local subnet_json
        subnet_json=$(oci network subnet get --subnet-id "$subnet_id" --region "${FOCUS_REGION:-$REGION}" --output json 2>/dev/null)
        
        if [[ -z "$subnet_json" ]]; then
            echo -e "${RED}Failed to get subnet details${NC}"
        else
            local sl_ids_json
            sl_ids_json=$(jq -r '.data["security-list-ids"] // []' <<< "$subnet_json")
            sl_count=$(jq 'length' <<< "$sl_ids_json" 2>/dev/null || echo "0")
            
            if [[ "$sl_count" -eq 0 ]]; then
                echo -e "${GRAY}No security lists assigned to subnet${NC}"
            else
                echo -e "${GRAY}Checking $sl_count security list(s) on PE subnet...${NC}"
                echo ""
                
                # Check each security list
                while read -r sl_id; do
                    [[ -z "$sl_id" || "$sl_id" == "null" ]] && continue
                    
                    # Get security list details
                    local sl_detail
                    sl_detail=$(oci network security-list get --security-list-id "$sl_id" --region "${FOCUS_REGION:-$REGION}" --output json 2>/dev/null)
                    
                    if [[ -z "$sl_detail" ]]; then
                        continue
                    fi
                    
                    local sl_name
                    sl_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$sl_detail")
                    SL_NAMES[$sl_id]="$sl_name"
                    sl_has_80[$sl_id]="false"
                    sl_has_443[$sl_id]="false"
                    sl_good_rules[$sl_id]=""
                    
                    # Store for wizard
                    sl_json="$sl_detail"
                    
                    # Get ingress rules
                    local ingress_rules
                    ingress_rules=$(jq -c '.data["ingress-security-rules"] // []' <<< "$sl_detail")
                    
                    if [[ -z "$ingress_rules" ]] || [[ "$ingress_rules" == "[]" ]]; then
                        sl_missing_rules+=("$sl_id|$sl_name|80")
                        sl_missing_rules+=("$sl_id|$sl_name|443")
                        continue
                    fi
                    
                    # Check rules
                    while IFS='|' read -r rule_source rule_protocol rule_ports rule_port_type; do
                        [[ -z "$rule_source" ]] && continue
                        
                        local rule_entry="$rule_source|$rule_protocol|$rule_ports"
                        if [[ -n "${sl_good_rules[$sl_id]}" ]]; then
                            sl_good_rules[$sl_id]="${sl_good_rules[$sl_id]}"$'\n'"$rule_entry"
                        else
                            sl_good_rules[$sl_id]="$rule_entry"
                        fi
                        
                        if [[ "$rule_port_type" == "80" || "$rule_port_type" == "both" ]]; then
                            sl_has_80[$sl_id]="true"
                        fi
                        if [[ "$rule_port_type" == "443" || "$rule_port_type" == "both" ]]; then
                            sl_has_443[$sl_id]="true"
                        fi
                    done < <(jq -r ' 
                        .[] |
                        select(.protocol == "6" or .protocol == "all") |
                        (if (.protocol == "all") or (.["tcp-options"] == null) or (.["tcp-options"]["destination-port-range"] == null) or
                           ((.["tcp-options"]["destination-port-range"]["min"] // 0) <= 80 and (.["tcp-options"]["destination-port-range"]["max"] // 0) >= 80)
                        then true else false end) as $covers80 |
                        (if (.protocol == "all") or (.["tcp-options"] == null) or (.["tcp-options"]["destination-port-range"] == null) or
                           ((.["tcp-options"]["destination-port-range"]["min"] // 0) <= 443 and (.["tcp-options"]["destination-port-range"]["max"] // 0) >= 443)
                        then true else false end) as $covers443 |
                        select($covers80 or $covers443) |
                        (if $covers80 and $covers443 then "both" elif $covers80 then "80" else "443" end) as $portType |
                        "\(.source // "N/A")|\(if .protocol == "all" then "ALL" else "TCP" end)|\(if .protocol == "all" or .["tcp-options"] == null or .["tcp-options"]["destination-port-range"] == null then "ALL" else "\(.["tcp-options"]["destination-port-range"]["min"])-\(.["tcp-options"]["destination-port-range"]["max"])" end)|\($portType)"
                    ' <<< "$ingress_rules" 2>/dev/null)
                    
                    [[ "${sl_has_80[$sl_id]}" == "false" ]] && sl_missing_rules+=("$sl_id|$sl_name|80")
                    [[ "${sl_has_443[$sl_id]}" == "false" ]] && sl_missing_rules+=("$sl_id|$sl_name|443")
                done < <(jq -r '.[]' <<< "$sl_ids_json" 2>/dev/null)
                
                # Display GOOD rules section
                local has_sl_good=false
                for sl_id in "${!sl_good_rules[@]}"; do
                    [[ -n "${sl_good_rules[$sl_id]}" ]] && has_sl_good=true && break
                done
                
                if [[ "$has_sl_good" == "true" ]]; then
                    echo -e "${BOLD}${GREEN}Good (ports 80/443 covered):${NC}"
                    printf "  ${BOLD}%-30s %-25s %-8s %-10s %s${NC}\n" "Security List Name" "Source CIDR" "Protocol" "Ports" "OCID"
                    print_separator 100
                    
                    for sl_id in "${!sl_good_rules[@]}"; do
                        local sl_name="${SL_NAMES[$sl_id]}"
                        [[ -z "${sl_good_rules[$sl_id]}" ]] && continue
                        
                        local first_line=true
                        while IFS='|' read -r src proto ports; do
                            [[ -z "$src" ]] && continue
                            if [[ "$first_line" == "true" ]]; then
                                printf "  ${GREEN}%-30s${NC} ${CYAN}%-25s${NC} %-8s %-10s ${GRAY}...%s${NC}\n" \
                                    "${sl_name:0:30}" "${src:0:25}" "$proto" "$ports" "${sl_id: -12}"
                                first_line=false
                            else
                                printf "  ${GREEN}%-30s${NC} ${CYAN}%-25s${NC} %-8s %-10s\n" \
                                    "" "${src:0:25}" "$proto" "$ports"
                            fi
                        done <<< "${sl_good_rules[$sl_id]}"
                    done
                    echo ""
                fi
                
                # Display MISSING rules section
                for missing in "${sl_missing_rules[@]}"; do
                    local m_sl_id="${missing%%|*}"
                    local temp="${missing#*|}"
                    local m_sl_name="${temp%%|*}"
                    local m_port="${temp##*|}"
                    
                    if [[ -z "${missing_sl_ports[$m_sl_id]}" ]]; then
                        missing_sl_ports[$m_sl_id]="$m_sl_name|$m_port"
                    else
                        if [[ ! "${missing_sl_ports[$m_sl_id]}" =~ \|$m_port ]]; then
                            missing_sl_ports[$m_sl_id]="${missing_sl_ports[$m_sl_id]},$m_port"
                        fi
                    fi
                done
                
                if [[ ${#missing_sl_ports[@]} -gt 0 ]]; then
                    echo -e "${BOLD}${RED}Missing (need ingress rules):${NC}"
                    printf "  ${BOLD}%-40s %-12s %-12s %s${NC}\n" "Security List Name" "Port 80" "Port 443" "OCID"
                    print_separator 100
                    
                    for sl_id in "${!missing_sl_ports[@]}"; do
                        local info="${missing_sl_ports[$sl_id]}"
                        local sl_name="${info%%|*}"
                        local ports="${info#*|}"
                        
                        local p80_status="${GREEN}✓${NC}"
                        local p443_status="${GREEN}✓${NC}"
                        [[ "$ports" =~ 80 ]] && p80_status="${RED}✗ Missing${NC}"
                        [[ "$ports" =~ 443 ]] && p443_status="${RED}✗ Missing${NC}"
                        
                        printf "  ${WHITE}%-40s${NC} %-20s %-20s ${GRAY}...%s${NC}\n" \
                            "${sl_name:0:40}" "$(echo -e $p80_status)" "$(echo -e $p443_status)" "${sl_id: -12}"
                    done
                    echo ""
                else
                    echo -e "${GREEN}✓ All Security Lists have port 80/443 ingress rules${NC}"
                    echo ""
                fi
            fi
        fi
    fi
    
    # ═══════════════════════════════════════════════════════════════════════════
    # SUMMARY AND ACTIONS
    # ═══════════════════════════════════════════════════════════════════════════
    _ui_summary
    echo ""
    
    local nsgs_missing=${#missing_nsg_ports[@]}
    local sls_missing=${#missing_sl_ports[@]}
    
    if [[ "$nsgs_missing" -eq 0 && "$sls_missing" -eq 0 ]]; then
        echo -e "${GREEN}✓ All NSGs and Security Lists have port 80/443 ingress rules configured${NC}"
    else
        [[ "$nsgs_missing" -gt 0 ]] && echo -e "${RED}✗ $nsgs_missing NSG(s) missing port 80/443 rules${NC}"
        [[ "$sls_missing" -gt 0 ]] && echo -e "${RED}✗ $sls_missing Security List(s) missing port 80/443 rules${NC}"
    fi
    
    echo ""
    
    # Prompt to add rules if any are missing
    if [[ ${#missing_rules[@]} -gt 0 || ${#sl_missing_rules[@]} -gt 0 ]]; then
        echo -e "${BOLD}${YELLOW}Would you like to add missing ingress rules?${NC}"
        echo ""
        
        local add_choice=""
        if [[ ${#missing_rules[@]} -gt 0 && ${#sl_missing_rules[@]} -gt 0 ]]; then
            echo -e "  ${YELLOW}1${NC}) Add rules to NSGs ($nsgs_missing NSG(s) missing rules)"
            echo -e "  ${YELLOW}2${NC}) Add rules to Security Lists ($sls_missing SL(s) missing rules)"
            echo -e "  ${YELLOW}3${NC}) Skip"
            echo ""
            echo -n -e "${CYAN}Select option [3]: ${NC}"
            read -r add_choice
            [[ -z "$add_choice" ]] && add_choice="3"
        elif [[ ${#missing_rules[@]} -gt 0 ]]; then
            echo -n -e "${CYAN}Add rules to NSGs? (y/N): ${NC}"
            local yn
            read -r yn
            [[ "$yn" == "y" || "$yn" == "Y" ]] && add_choice="1"
        elif [[ ${#sl_missing_rules[@]} -gt 0 ]]; then
            echo -n -e "${CYAN}Add rules to Security Lists? (y/N): ${NC}"
            local yn
            read -r yn
            [[ "$yn" == "y" || "$yn" == "Y" ]] && add_choice="2"
        fi
        
        local rules_added=false
        case "$add_choice" in
            1)
                pe_add_nsg_rules_wizard "$compartment_id" missing_rules all_nsgs_json
                rules_added=true
                ;;
            2)
                pe_add_sl_rules_wizard "$compartment_id" sl_missing_rules sl_json
                rules_added=true
                ;;
        esac
        
        # Refresh NSG cache if rules were added
        if [[ "$rules_added" == "true" ]]; then
            echo ""
            echo -e "${GRAY}Refreshing NSG rules cache...${NC}"
            rm -rf "${NSG_RULES_DETAIL_DIR:?}"
            mkdir -p "$NSG_RULES_DETAIL_DIR"
            echo -e "${GREEN}✓ NSG cache refreshed${NC}"
        fi
    fi
}

#--------------------------------------------------------------------------------
# PE - Add Security List Rules Wizard
#--------------------------------------------------------------------------------
pe_add_sl_rules_wizard() {
    local compartment_id="$1"
    local -n sl_missing_rules_ref=$2
    local -n sl_json_ref=$3
    
    echo ""
    _ui_subheader "Add Security List Rules Wizard" 0
    echo ""
    
    # Collect unique SLs that need rules
    declare -A sl_missing_info
    local sl_list_idx=0
    declare -A SL_SELECT_MAP
    
    for missing in "${sl_missing_rules_ref[@]}"; do
        local m_sl_id="${missing%%|*}"
        local temp="${missing#*|}"
        local m_sl_name="${temp%%|*}"
        
        if [[ -z "${sl_missing_info[$m_sl_id]}" ]]; then
            ((sl_list_idx++))
            sl_missing_info[$m_sl_id]="$m_sl_name"
            SL_SELECT_MAP[$sl_list_idx]="$m_sl_id"
        fi
    done
    
    # Step 1: Select which SL(s) to add rules to
    echo -e "${WHITE}Step 1: Select target Security List(s) to add rules${NC}"
    echo ""
    printf "  ${BOLD}%-3s %-50s${NC}\n" "#" "Security List Name (missing rules)"
    print_separator 60
    
    for ((idx=1; idx<=sl_list_idx; idx++)); do
        local slid="${SL_SELECT_MAP[$idx]}"
        local slname="${sl_missing_info[$slid]}"
        printf "  ${YELLOW}%-3s${NC} %-50s\n" "$idx" "${slname:0:48}"
    done
    
    echo ""
    echo -e "  ${GRAY}Enter: 'all' for all SLs, or specific numbers (e.g., 1,3 or 1-3)${NC}"
    echo -n -e "${CYAN}Select Security List(s) [all]: ${NC}"
    local sl_selection
    read -r sl_selection
    [[ -z "$sl_selection" ]] && sl_selection="all"
    
    # Parse selection
    declare -A selected_sls
    if [[ "$sl_selection" == "all" || "$sl_selection" == "ALL" ]]; then
        for ((idx=1; idx<=sl_list_idx; idx++)); do
            selected_sls["${SL_SELECT_MAP[$idx]}"]=1
        done
    elif [[ "$sl_selection" =~ ^[0-9]+-[0-9]+$ ]]; then
        local start_num="${sl_selection%-*}"
        local end_num="${sl_selection#*-}"
        for ((idx=start_num; idx<=end_num; idx++)); do
            [[ -n "${SL_SELECT_MAP[$idx]}" ]] && selected_sls["${SL_SELECT_MAP[$idx]}"]=1
        done
    else
        IFS=',' read -ra nums <<< "$sl_selection"
        for num in "${nums[@]}"; do
            num=$(echo "$num" | tr -d ' ')
            [[ -n "${SL_SELECT_MAP[$num]}" ]] && selected_sls["${SL_SELECT_MAP[$num]}"]=1
        done
    fi
    
    if [[ ${#selected_sls[@]} -eq 0 ]]; then
        echo -e "${RED}No Security Lists selected. Aborting.${NC}"
        return
    fi
    
    echo -e "  ${GREEN}Selected ${#selected_sls[@]} Security List(s)${NC}"
    echo ""
    
    # Step 2: Enter source CIDR
    echo -e "${WHITE}Step 2: Enter source CIDR${NC}"
    echo -e "${GRAY}  Examples: 10.0.0.0/8, 10.0.0.0/16, 0.0.0.0/0 (any)${NC}"
    echo -n -e "${CYAN}Source CIDR [10.0.0.0/8]: ${NC}"
    local source_cidr
    read -r source_cidr
    [[ -z "$source_cidr" ]] && source_cidr="10.0.0.0/8"
    
    # Step 3: Choose which ports to add
    echo ""
    echo -e "${WHITE}Step 3: Select ports to add${NC}"
    echo -e "  ${YELLOW}1${NC}) Port 443 only (HTTPS) ${GREEN}← recommended${NC}"
    echo -e "  ${YELLOW}2${NC}) Port 80 only (HTTP)"
    echo -e "  ${YELLOW}3${NC}) Both ports 80 and 443"
    echo -e "  ${YELLOW}4${NC}) ALL protocols (no port restriction)"
    echo ""
    echo -n -e "${CYAN}Select ports [1]: ${NC}"
    local port_choice
    read -r port_choice
    [[ -z "$port_choice" ]] && port_choice="1"
    
    local ports_to_add=()
    local protocol_choice="6"
    local ports_display=""
    
    case "$port_choice" in
        1) ports_to_add=("443"); ports_display="443 (HTTPS)" ;;
        2) ports_to_add=("80"); ports_display="80 (HTTP)" ;;
        3) ports_to_add=("80" "443"); ports_display="80 (HTTP), 443 (HTTPS)" ;;
        4) 
            ports_to_add=("ALL")
            protocol_choice="all"
            ports_display="ALL protocols"
            ;;
        *) ports_to_add=("443"); ports_display="443 (HTTPS)" ;;
    esac
    
    # Summary before execution
    echo ""
    _ui_subheader "Configuration Summary" 0
    echo ""
    echo -e "  ${CYAN}Source CIDR:${NC}      ${WHITE}$source_cidr${NC}"
    echo -e "  ${CYAN}Ports:${NC}            ${WHITE}$ports_display${NC}"
    echo -e "  ${CYAN}Target SLs:${NC}       ${WHITE}${#selected_sls[@]} Security List(s)${NC}"
    for sl_id in "${!selected_sls[@]}"; do
        echo -e "                    • ${GREEN}${sl_missing_info[$sl_id]}${NC}"
    done
    echo ""
    
    echo -n -e "${YELLOW}Proceed with adding rules? (Y/n): ${NC}"
    local proceed
    read -r proceed
    
    if [[ "$proceed" == "n" || "$proceed" == "N" ]]; then
        echo -e "${YELLOW}Aborted.${NC}"
        return
    fi
    
    echo ""
    
    # Process each selected Security List
    for sl_id in "${!selected_sls[@]}"; do
        local m_sl_name="${sl_missing_info[$sl_id]}"
        
        echo -e "${BOLD}${CYAN}Security List: $m_sl_name${NC}"
        echo -e "  ${GRAY}$sl_id${NC}"
        
        # Get existing ingress rules (fresh fetch per SL to handle multi-SL)
        local existing_rules _sl_fresh
        _sl_fresh=$(oci network security-list get --security-list-id "$sl_id" --output json 2>/dev/null)
        existing_rules=$(jq '.data["ingress-security-rules"] // []' <<< "$_sl_fresh")
        
        # Build new rules to add
        local new_rules="$existing_rules"
        
        for port in "${ports_to_add[@]}"; do
            local protocol_name="HTTP"
            [[ "$port" == "443" ]] && protocol_name="HTTPS"
            [[ "$port" == "ALL" ]] && protocol_name="ALL"
            
            local new_rule=""
            if [[ "$port" == "ALL" ]]; then
                new_rule=$(cat <<EOF
{
  "protocol": "all",
  "source": "$source_cidr",
  "source-type": "CIDR_BLOCK",
  "description": "Allow ALL access to Object Storage Private Endpoint",
  "is-stateless": false
}
EOF
)
            else
                new_rule=$(cat <<EOF
{
  "protocol": "6",
  "source": "$source_cidr",
  "source-type": "CIDR_BLOCK",
  "tcp-options": {
    "destination-port-range": {
      "min": $port,
      "max": $port
    }
  },
  "description": "Allow $protocol_name access to Object Storage Private Endpoint",
  "is-stateless": false
}
EOF
)
            fi
            
            new_rules=$(jq --argjson rule "$new_rule" '. + [$rule]' <<< "$new_rules")
            echo -e "  ${WHITE}Adding: Port $port ($protocol_name) ingress rule${NC}"
        done
        
        # Build command for display
        echo ""
        echo -e "${GRAY}Command:${NC}"
        echo "oci network security-list update \\"
        echo "  --security-list-id \"$sl_id\" \\"
        echo "  --ingress-security-rules '...'"
        echo ""
        
        # Confirm before executing
        echo -n -e "${YELLOW}Execute? (Y/n): ${NC}"
        local confirm_exec
        read -r confirm_exec
        
        if [[ "$confirm_exec" != "n" && "$confirm_exec" != "N" ]]; then
            # Log the action
            local log_file="${LOGS_DIR}/object_storage_actions_$(date +%Y%m%d).log"
            mkdir -p "$(dirname "$log_file")" 2>/dev/null
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] UPDATE SECURITY LIST: oci network security-list update --security-list-id \"$sl_id\" --ingress-security-rules '...' " >> "$log_file"
            
            # Execute the command
            local result
            log_action "UPDATE" "oci network security-list update"
            result=$(oci network security-list update \
                --security-list-id "$sl_id" \
                --ingress-security-rules "$new_rules" \
                --region "${FOCUS_REGION:-$REGION}" \
                --force \
                --output json 2>&1)
            
            if jq -e '.data' <<< "$result" > /dev/null 2>&1; then
                echo -e "${GREEN}✓ Rules added successfully to $m_sl_name${NC}"
                log_action_result "SUCCESS" "UPDATE operation"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Added rules to $m_sl_name" >> "$log_file"
            else
                echo -e "${RED}✗ Failed to add rules to $m_sl_name${NC}"
                log_action_result "FAILED" "UPDATE operation"
                echo "$result"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
            fi
        else
            echo -e "${YELLOW}Skipped adding rules to $m_sl_name${NC}"
        fi
        echo ""
    done
    
    echo -e "${WHITE}Rule addition complete.${NC}"
}

#--------------------------------------------------------------------------------
# PE - Add NSG Rules Wizard
#--------------------------------------------------------------------------------
pe_add_nsg_rules_wizard() {
    local compartment_id="$1"
    local -n missing_rules_ref=$2
    local -n all_nsgs_json_ref=$3
    
    echo ""
    _ui_subheader "Add NSG Rules Wizard" 0
    echo ""
    
    # Collect unique NSGs that need rules
    declare -A nsg_missing_info
    local nsg_list_idx=0
    declare -A NSG_SELECT_MAP
    
    for missing in "${missing_rules_ref[@]}"; do
        local m_nsg_id="${missing%%|*}"
        local temp="${missing#*|}"
        local m_nsg_name="${temp%%|*}"
        
        if [[ -z "${nsg_missing_info[$m_nsg_id]}" ]]; then
            ((nsg_list_idx++))
            nsg_missing_info[$m_nsg_id]="$m_nsg_name"
            NSG_SELECT_MAP[$nsg_list_idx]="$m_nsg_id"
        fi
    done
    
    # Step 0: Select which NSG(s) to add rules to
    echo -e "${WHITE}Step 1: Select target NSG(s) to add rules${NC}"
    echo ""
    printf "  ${BOLD}%-3s %-45s${NC}\n" "#" "NSG Name (missing rules)"
    print_separator 55
    
    for ((idx=1; idx<=nsg_list_idx; idx++)); do
        local nid="${NSG_SELECT_MAP[$idx]}"
        local nname="${nsg_missing_info[$nid]}"
        printf "  ${YELLOW}%-3s${NC} %-45s\n" "$idx" "${nname:0:43}"
    done
    
    echo ""
    echo -e "  ${GRAY}Enter: 'all' for all NSGs, or specific numbers (e.g., 1,3 or 1-3)${NC}"
    echo -n -e "${CYAN}Select NSG(s) [all]: ${NC}"
    local nsg_selection
    read -r nsg_selection
    [[ -z "$nsg_selection" ]] && nsg_selection="all"
    
    # Parse selection
    declare -A selected_nsgs
    if [[ "$nsg_selection" == "all" || "$nsg_selection" == "ALL" ]]; then
        for ((idx=1; idx<=nsg_list_idx; idx++)); do
            selected_nsgs["${NSG_SELECT_MAP[$idx]}"]=1
        done
    elif [[ "$nsg_selection" =~ ^[0-9]+-[0-9]+$ ]]; then
        # Range format: 1-3
        local start_num="${nsg_selection%-*}"
        local end_num="${nsg_selection#*-}"
        for ((idx=start_num; idx<=end_num; idx++)); do
            [[ -n "${NSG_SELECT_MAP[$idx]}" ]] && selected_nsgs["${NSG_SELECT_MAP[$idx]}"]=1
        done
    else
        # Comma-separated: 1,3,5
        IFS=',' read -ra nums <<< "$nsg_selection"
        for num in "${nums[@]}"; do
            num=$(echo "$num" | tr -d ' ')
            [[ -n "${NSG_SELECT_MAP[$num]}" ]] && selected_nsgs["${NSG_SELECT_MAP[$num]}"]=1
        done
    fi
    
    if [[ ${#selected_nsgs[@]} -eq 0 ]]; then
        echo -e "${RED}No NSGs selected. Aborting.${NC}"
        return
    fi
    
    echo -e "  ${GREEN}Selected ${#selected_nsgs[@]} NSG(s)${NC}"
    echo ""
    
    # Step 1: Choose source type (CIDR or NSG)
    echo -e "${WHITE}Step 2: Select source type${NC}"
    echo -e "  ${YELLOW}1${NC}) CIDR Block (e.g., 10.0.0.0/8)"
    echo -e "  ${YELLOW}2${NC}) Network Security Group (NSG)"
    echo ""
    echo -n -e "${CYAN}Select source type [1]: ${NC}"
    local source_type_choice
    read -r source_type_choice
    [[ -z "$source_type_choice" ]] && source_type_choice="1"
    
    local source_value=""
    local source_type=""
    local source_display=""
    
    if [[ "$source_type_choice" == "2" ]]; then
        # NSG source - list available NSGs
        source_type="NETWORK_SECURITY_GROUP"
        echo ""
        echo -e "${WHITE}Available NSGs in compartment:${NC}"
        
        local nsg_idx=0
        declare -A SOURCE_NSG_MAP
        SOURCE_NSG_MAP=()
        
        printf "  ${BOLD}%-3s %-45s${NC}\n" "#" "NSG Name"
        print_separator 55
        
        while IFS='|' read -r src_nsg_id src_nsg_name; do
            [[ -z "$src_nsg_id" ]] && continue
            ((nsg_idx++))
            SOURCE_NSG_MAP[$nsg_idx]="$src_nsg_id|$src_nsg_name"
            printf "  ${YELLOW}%-3s${NC} %-45s\n" "$nsg_idx" "${src_nsg_name:0:43}"
        done < <(jq -r '.data[] | "\(.id)|\(.["display-name"])"' <<< "$all_nsgs_json_ref" 2>/dev/null)
        
        echo ""
        echo -n -e "${CYAN}Select source NSG #: ${NC}"
        local nsg_choice
        read -r nsg_choice
        
        if [[ -n "${SOURCE_NSG_MAP[$nsg_choice]}" ]]; then
            source_value="${SOURCE_NSG_MAP[$nsg_choice]%%|*}"
            source_display="${SOURCE_NSG_MAP[$nsg_choice]#*|}"
            echo -e "  ${GREEN}Selected: $source_display${NC}"
        else
            echo -e "${RED}Invalid selection. Using default CIDR.${NC}"
            source_type="CIDR_BLOCK"
            source_value="10.0.0.0/8"
            source_display="10.0.0.0/8"
        fi
    else
        # CIDR source
        source_type="CIDR_BLOCK"
        echo ""
        echo -e "${WHITE}Enter source CIDR:${NC}"
        echo -e "${GRAY}  Examples: 10.0.0.0/8, 10.0.0.0/16, 0.0.0.0/0 (any)${NC}"
        echo -n -e "${CYAN}Source CIDR [10.0.0.0/8]: ${NC}"
        read -r source_value
        [[ -z "$source_value" ]] && source_value="10.0.0.0/8"
        source_display="$source_value"
    fi
    
    # Step 2: Choose which ports to add
    echo ""
    echo -e "${WHITE}Step 3: Select ports to add${NC}"
    echo -e "  ${YELLOW}1${NC}) Port 443 only (HTTPS) ${GREEN}← recommended${NC}"
    echo -e "  ${YELLOW}2${NC}) Port 80 only (HTTP)"
    echo -e "  ${YELLOW}3${NC}) Both ports 80 and 443"
    echo -e "  ${YELLOW}4${NC}) ALL protocols (no port restriction)"
    echo ""
    echo -n -e "${CYAN}Select ports [1]: ${NC}"
    local port_choice
    read -r port_choice
    [[ -z "$port_choice" ]] && port_choice="1"
    
    local ports_to_add=()
    local protocol_choice="6"  # TCP by default
    local ports_display=""
    
    case "$port_choice" in
        1) ports_to_add=("443"); ports_display="443 (HTTPS)" ;;
        2) ports_to_add=("80"); ports_display="80 (HTTP)" ;;
        3) ports_to_add=("80" "443"); ports_display="80 (HTTP), 443 (HTTPS)" ;;
        4) 
            ports_to_add=("ALL")
            protocol_choice="all"
            ports_display="ALL protocols"
            ;;
        *) ports_to_add=("443"); ports_display="443 (HTTPS)" ;;
    esac
    
    # Summary before execution
    echo ""
    _ui_subheader "Configuration Summary" 0
    echo ""
    echo -e "  ${CYAN}Source Type:${NC}  ${WHITE}$source_type${NC}"
    echo -e "  ${CYAN}Source:${NC}       ${WHITE}$source_display${NC}"
    echo -e "  ${CYAN}Ports:${NC}        ${WHITE}$ports_display${NC}"
    echo -e "  ${CYAN}Target NSGs:${NC}  ${WHITE}${#selected_nsgs[@]} NSG(s)${NC}"
    for nsg_id in "${!selected_nsgs[@]}"; do
        echo -e "                • ${GREEN}${nsg_missing_info[$nsg_id]}${NC}"
    done
    echo ""
    
    echo -n -e "${YELLOW}Proceed with adding rules? (Y/n): ${NC}"
    local proceed
    read -r proceed
    
    if [[ "$proceed" == "n" || "$proceed" == "N" ]]; then
        echo -e "${YELLOW}Aborted.${NC}"
        return
    fi
    
    echo ""
    
    # Process each selected NSG
    for nsg_id in "${!selected_nsgs[@]}"; do
        local m_nsg_name="${nsg_missing_info[$nsg_id]}"
        
        echo -e "${BOLD}${CYAN}NSG: $m_nsg_name${NC}"
        echo -e "  ${GRAY}$nsg_id${NC}"
        
        # Build security rules JSON
        local rules_json="["
        local first_rule=true
        
        for port in "${ports_to_add[@]}"; do
            [[ "$first_rule" == "false" ]] && rules_json+=","
            first_rule=false
            
            local protocol_name="HTTP"
            [[ "$port" == "443" ]] && protocol_name="HTTPS"
            [[ "$port" == "ALL" ]] && protocol_name="ALL"
            
            rules_json+="{"
            rules_json+="\"direction\": \"INGRESS\","
            rules_json+="\"protocol\": \"$protocol_choice\","
            rules_json+="\"source\": \"$source_value\","
            rules_json+="\"source-type\": \"$source_type\","
            
            if [[ "$port" != "ALL" ]]; then
                rules_json+="\"tcp-options\": {"
                rules_json+="\"destination-port-range\": {"
                rules_json+="\"min\": $port,"
                rules_json+="\"max\": $port"
                rules_json+="}"
                rules_json+="},"
            fi
            
            rules_json+="\"description\": \"Allow $protocol_name access to Object Storage Private Endpoint\","
            rules_json+="\"is-stateless\": false"
            rules_json+="}"
            
            echo -e "  ${WHITE}Adding: Port $port ($protocol_name) ingress rule${NC}"
        done
        rules_json+="]"
        
        # Build command for display and logging
        echo ""
        echo -e "${GRAY}Command:${NC}"
        echo "oci network nsg rules add \\"
        echo "  --nsg-id \"$nsg_id\" \\"
        echo "  --security-rules '$rules_json'"
        echo ""
        
        # Confirm before executing
        echo -n -e "${YELLOW}Execute? (Y/n): ${NC}"
        local confirm_exec
        read -r confirm_exec
        
        if [[ "$confirm_exec" != "n" && "$confirm_exec" != "N" ]]; then
            # Log the action
            local log_file="${LOGS_DIR}/object_storage_actions_$(date +%Y%m%d).log"
            mkdir -p "$(dirname "$log_file")" 2>/dev/null
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] ADD NSG RULES: oci network nsg rules add --nsg-id \"$nsg_id\" --security-rules '...' " >> "$log_file"
            
            # Execute the command
            local result
            result=$(oci network nsg rules add \
                --nsg-id "$nsg_id" \
                --security-rules "$rules_json" \
                --region "${FOCUS_REGION:-$REGION}" \
                --output json 2>&1)
            
            if jq -e '.data' <<< "$result" > /dev/null 2>&1; then
                echo -e "${GREEN}✓ Rules added successfully to $m_nsg_name${NC}"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Added rules to $m_nsg_name" >> "$log_file"
                
                # Invalidate cache for this NSG
                local cache_file="${NSG_CACHE_DIR}/${nsg_id}.json"
                rm -f "$cache_file" 2>/dev/null
            else
                echo -e "${RED}✗ Failed to add rules to $m_nsg_name${NC}"
                echo "$result"
                echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
            fi
        else
            echo -e "${YELLOW}Skipped adding rules to $m_nsg_name${NC}"
        fi
        echo ""
    done
    
    echo -e "${WHITE}Rule addition complete.${NC}"
}

#--------------------------------------------------------------------------------
# Object Storage - View NSG Rules
#--------------------------------------------------------------------------------
os_view_nsg_rules() {
    local nsg_id="$1"
    
    echo ""
    _ui_subheader "NSG Rules" 0
    echo ""
    
    # Try to get from cache first
    local cached_data nsg_name rules_json
    cached_data=$(get_cached_nsg_rules "$nsg_id")
    
    if [[ -n "$cached_data" ]]; then
        local nsg_name
        nsg_name=$(jq -r '.nsg_name // "Unknown"' <<< "$cached_data")
        # Wrap rules in data format for display_nsg_rules_table
        rules_json=$(jq '{data: .rules}' <<< "$cached_data")
    else
        # Fallback to direct fetch if not cached
        local nsg_json
        nsg_json=$(oci network nsg get --nsg-id "$nsg_id" --output json 2>/dev/null)
        nsg_name=$(jq -r '.data["display-name"] // "Unknown"' <<< "$nsg_json")
        rules_json=$(oci network nsg rules list --nsg-id "$nsg_id" --all --output json 2>/dev/null)
    fi
    
    echo -e "${CYAN}NSG Name:${NC} ${WHITE}$nsg_name${NC}"
    echo -e "${CYAN}NSG OCID:${NC} ${YELLOW}$nsg_id${NC}"
    echo ""
    
    # Use shared function (no cache lookup - fetch NSG names on demand)
    display_nsg_rules_table "$rules_json" "false"
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Object Storage - Create Private Endpoint
#--------------------------------------------------------------------------------
os_create_private_endpoint() {
    local compartment_id="$1"
    local namespace="$2"
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Create Private Endpoint" 0
    echo ""
    
    # Get endpoint name
    echo -n -e "${CYAN}Enter private endpoint name: ${NC}"
    read -r pe_name
    
    if [[ -z "$pe_name" ]]; then
        echo -e "${RED}Name is required${NC}"
        _ui_pause
        return
    fi
    
    # Get prefix
    echo ""
    echo -e "${GRAY}Prefix is a unique identifier for DNS resolution (e.g., 'myprefix')${NC}"
    echo -e "${GRAY}The FQDN will be: <prefix>.objectstorage.<region>.oci.customer-oci.com${NC}"
    echo -n -e "${CYAN}Enter prefix: ${NC}"
    read -r pe_prefix
    
    if [[ -z "$pe_prefix" ]]; then
        echo -e "${RED}Prefix is required${NC}"
        _ui_pause
        return
    fi
    
    # List subnets for selection
    echo ""
    _step_init
    _step_active "subnets"
    
    local subnets_json _pe_sub_cached=""
    # Try subnet cache first
    if is_cache_fresh "$OKE_SUBNET_LIST_CACHE" 2>/dev/null && [[ -s "$OKE_SUBNET_LIST_CACHE" ]]; then
        subnets_json=$(cat "$OKE_SUBNET_LIST_CACHE" 2>/dev/null)
        if [[ -n "$subnets_json" ]] && jq -e '.data[0]' <<< "$subnets_json" >/dev/null 2>&1; then
            _pe_sub_cached=" cached"
        else
            subnets_json=""
        fi
    fi
    [[ -z "$_pe_sub_cached" ]] && subnets_json=$(oci network subnet list --compartment-id "$compartment_id" --region "$region" --output json 2>/dev/null)
    _step_complete "subnets${_pe_sub_cached}"
    _step_finish
    
    if [[ -z "$subnets_json" || "$subnets_json" == "null" ]]; then
        echo -e "${RED}Failed to list subnets${NC}"
        _ui_policy_hint "read subnets in compartment"
        _ui_pause
        return
    fi
    
    local subnet_count
    subnet_count=$(jq '.data | length // 0' <<< "$subnets_json" 2>/dev/null)
    
    if [[ "$subnet_count" -eq 0 ]]; then
        echo -e "${RED}No subnets found in compartment${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    echo -e "${WHITE}Select a subnet:${NC}"
    printf "  ${BOLD}%-3s %-35s %-20s %-12s${NC}\n" "#" "Subnet Name" "CIDR" "Access"
    print_separator 80
    
    local subnet_idx=0
    declare -A SUBNET_MAP
    SUBNET_MAP=()
    
    while IFS='|' read -r subnet_name subnet_cidr subnet_access subnet_id; do
        [[ -z "$subnet_name" ]] && continue
        ((subnet_idx++))
        
        SUBNET_MAP[$subnet_idx]="$subnet_id"
        
        local access_display="Private"
        local access_color="$GREEN"
        if [[ "$subnet_access" == "true" ]]; then
            access_display="Public"
            access_color="$YELLOW"
        fi
        
        printf "  ${YELLOW}%-3s${NC} %-35s %-20s ${access_color}%-12s${NC}\n" \
            "$subnet_idx" "${subnet_name:0:33}" "$subnet_cidr" "$access_display"
            
    done < <(jq -r '.data[] | "\(.["display-name"])|\(.["cidr-block"])|\(.["prohibit-public-ip-on-vnic"] | not)|\(.id)"' <<< "$subnets_json" 2>/dev/null)
    
    echo ""
    echo -n -e "${CYAN}Select subnet #: ${NC}"
    read -r subnet_selection
    
    if [[ -z "${SUBNET_MAP[$subnet_selection]}" ]]; then
        echo -e "${RED}Invalid subnet selection${NC}"
        _ui_pause
        return
    fi
    
    local selected_subnet="${SUBNET_MAP[$subnet_selection]}"
    
    # Optional: NSG selection
    echo ""
    echo -e "${BOLD}${YELLOW}⚠ IMPORTANT:${NC} ${WHITE}NSGs cannot be added after Private Endpoint creation.${NC}"
    echo -e "${WHITE}  You must delete and recreate the PE to change NSGs.${NC}"
    echo ""
    echo -n -e "${CYAN}Add NSG(s)? (Y/n): ${NC}"
    read -r add_nsg
    
    local selected_nsg_ids=()
    if [[ "$add_nsg" != "n" && "$add_nsg" != "N" ]]; then
        local nsgs_json _pe_nsg_cached=""
        # Try NSG cache first
        if is_cache_fresh "$NETWORK_RESOURCES_CACHE" 2>/dev/null; then
            local _nsg_lines
            _nsg_lines=$(grep '^NSG|' "$NETWORK_RESOURCES_CACHE" 2>/dev/null)
            if [[ -n "$_nsg_lines" ]]; then
                nsgs_json=$(echo "$_nsg_lines" | awk -F'|' '{printf "{\"id\":\"%s\",\"display-name\":\"%s\",\"lifecycle-state\":\"%s\"}\n", $5, $2, $4}' | jq -s '{data: .}' 2>/dev/null)
                [[ -n "$nsgs_json" ]] && jq -e '.data[0]' <<< "$nsgs_json" >/dev/null 2>&1 && _pe_nsg_cached=" cached"
                [[ -z "$_pe_nsg_cached" ]] && nsgs_json=""
            fi
        fi
        [[ -z "$_pe_nsg_cached" ]] && nsgs_json=$(oci network nsg list --compartment-id "$compartment_id" --region "$region" --output json 2>/dev/null)
        
        if [[ -n "$nsgs_json" && "$nsgs_json" != "null" ]]; then
            local nsg_count
            nsg_count=$(jq '.data | length // 0' <<< "$nsgs_json" 2>/dev/null)
            
            if [[ "$nsg_count" -gt 0 ]]; then
                echo ""
                echo -e "${WHITE}Available NSGs:${NC}"
                printf "  ${BOLD}%-3s %-40s${NC}\n" "#" "NSG Name"
                print_separator 50
                
                local nsg_idx=0
                declare -A NSG_MAP
                declare -A NSG_NAME_MAP
                NSG_MAP=()
                NSG_NAME_MAP=()
                
                while IFS='|' read -r nsg_name nsg_id; do
                    [[ -z "$nsg_name" ]] && continue
                    ((nsg_idx++))
                    NSG_MAP[$nsg_idx]="$nsg_id"
                    NSG_NAME_MAP[$nsg_idx]="$nsg_name"
                    printf "  ${YELLOW}%-3s${NC} %-40s\n" "$nsg_idx" "${nsg_name:0:38}"
                done < <(jq -r '.data[] | "\(.["display-name"])|\(.id)"' <<< "$nsgs_json" 2>/dev/null)
                
                # NSG selection loop with validation for max 5
                local max_nsgs=5
                while true; do
                    selected_nsg_ids=()
                    
                    echo ""
                    echo -e "${GRAY}Selection formats: ${WHITE}1,3,5${GRAY} | ${WHITE}1-3${GRAY} | ${WHITE}all${GRAY} | Enter to skip${NC}"
                    echo -e "${GRAY}Note: Maximum ${max_nsgs} NSGs can be attached to a Private Endpoint${NC}"
                    echo -n -e "${CYAN}Select NSG(s): ${NC}"
                    read -r nsg_selection
                    
                    if [[ -z "$nsg_selection" ]]; then
                        # User skipped NSG selection
                        break
                    fi
                    
                    # Parse selection
                    if [[ "$nsg_selection" == "all" || "$nsg_selection" == "ALL" ]]; then
                        # Select all NSGs
                        for ((i=1; i<=nsg_idx; i++)); do
                            selected_nsg_ids+=("${NSG_MAP[$i]}")
                        done
                    elif [[ "$nsg_selection" =~ ^[0-9]+-[0-9]+$ ]]; then
                        # Range format: 1-3
                        local start_num="${nsg_selection%-*}"
                        local end_num="${nsg_selection#*-}"
                        for ((i=start_num; i<=end_num; i++)); do
                            if [[ -n "${NSG_MAP[$i]}" ]]; then
                                selected_nsg_ids+=("${NSG_MAP[$i]}")
                            fi
                        done
                    elif [[ "$nsg_selection" =~ ^[0-9,]+$ ]]; then
                        # Comma-separated: 1,3,5
                        IFS=',' read -ra nums <<< "$nsg_selection"
                        for num in "${nums[@]}"; do
                            num=$(echo "$num" | tr -d ' ')
                            if [[ -n "${NSG_MAP[$num]}" ]]; then
                                selected_nsg_ids+=("${NSG_MAP[$num]}")
                            fi
                        done
                    elif [[ "$nsg_selection" =~ ^[0-9]+$ ]]; then
                        # Single number
                        if [[ -n "${NSG_MAP[$nsg_selection]}" ]]; then
                            selected_nsg_ids+=("${NSG_MAP[$nsg_selection]}")
                        fi
                    fi
                    
                    # Validate max 5 NSGs
                    if [[ ${#selected_nsg_ids[@]} -gt $max_nsgs ]]; then
                        echo ""
                        echo -e "${RED}✗ Error: Selected ${#selected_nsg_ids[@]} NSGs, but maximum is ${max_nsgs}.${NC}"
                        echo -e "${YELLOW}  Please select ${max_nsgs} or fewer NSGs.${NC}"
                        continue
                    fi
                    
                    # Show selected NSGs and exit loop
                    if [[ ${#selected_nsg_ids[@]} -gt 0 ]]; then
                        echo ""
                        echo -e "${GREEN}Selected ${#selected_nsg_ids[@]} NSG(s):${NC}"
                        for nsg_id in "${selected_nsg_ids[@]}"; do
                            # Find name for this ID
                            for ((i=1; i<=nsg_idx; i++)); do
                                if [[ "${NSG_MAP[$i]}" == "$nsg_id" ]]; then
                                    echo -e "  ${WHITE}• ${NSG_NAME_MAP[$i]}${NC}"
                                    break
                                fi
                            done
                        done
                    fi
                    break
                done
            fi
        fi
    fi
    
    # Access Targets configuration
    echo ""
    _ui_subheader "Access Targets" 0
    echo -e "${GRAY}Configure which buckets can be accessed through this Private Endpoint${NC}"
    echo -e "${GRAY}Use '*' for wildcard access (all buckets/compartments)${NC}"
    echo ""
    
    # Prompt for bucket
    echo -n -e "${CYAN}Enter bucket name [*]: ${NC}"
    read -r access_bucket
    [[ -z "$access_bucket" ]] && access_bucket="*"
    
    # Prompt for compartment-id
    echo -n -e "${CYAN}Enter compartment-id [*]: ${NC}"
    read -r access_compartment
    [[ -z "$access_compartment" ]] && access_compartment="*"
    
    # Create access targets JSON file
    local access_targets_file="${TEMP_DIR}/pe_access_targets_$$.json"
    mkdir -p "$(dirname "$access_targets_file")" 2>/dev/null
    
    jq -n --arg b "$access_bucket" --arg c "$access_compartment" --arg n "$namespace" \
        '[{bucket: $b, "compartment-id": $c, namespace: $n}]' > "$access_targets_file"
    
    echo ""
    echo -e "${WHITE}Access Targets JSON:${NC}"
    cat "$access_targets_file"
    echo ""
    
    # Build NSG IDs JSON array
    local nsg_ids_json=""
    if [[ ${#selected_nsg_ids[@]} -gt 0 ]]; then
        nsg_ids_json=$(printf '%s\n' "${selected_nsg_ids[@]}" | jq -R . | jq -s .)
    fi
    
    # Build and display command
    local create_cmd="oci os private-endpoint create \\
    --compartment-id \"$compartment_id\" \\
    --name \"$pe_name\" \\
    --namespace-name \"$namespace\" \\
    --prefix \"$pe_prefix\" \\
    --subnet-id \"$selected_subnet\" \\
    --access-targets file://$access_targets_file \\
    --region \"$region\""
    
    if [[ -n "$nsg_ids_json" ]]; then
        create_cmd="$create_cmd \\
    --nsg-ids '$nsg_ids_json'"
    fi
    
    echo ""
    echo -e "${GRAY}Command to execute:${NC}"
    echo -e "${WHITE}$create_cmd${NC}"
    echo ""
    
    echo -n -e "${YELLOW}Proceed with creation? (y/N): ${NC}"
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Cancelled${NC}"
        rm -f "$access_targets_file" 2>/dev/null
        _ui_pause
        return
    fi
    
    # Log the action
    local log_file="${LOGS_DIR}/object_storage_actions_$(date +%Y%m%d).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] CREATE PRIVATE ENDPOINT: $create_cmd" >> "$log_file"
    
    local result
    if [[ -n "$nsg_ids_json" ]]; then
        log_action "CREATE" "$create_cmd"
        result=$(oci os private-endpoint create \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --name "$pe_name" \
            --namespace-name "$namespace" \
            --prefix "$pe_prefix" \
            --subnet-id "$selected_subnet" \
            --access-targets "file://$access_targets_file" \
            --nsg-ids "$nsg_ids_json" \
            --output json 2>&1)
    else
        log_action "CREATE" "$create_cmd"
        result=$(oci os private-endpoint create \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --name "$pe_name" \
            --namespace-name "$namespace" \
            --prefix "$pe_prefix" \
            --subnet-id "$selected_subnet" \
            --access-targets "file://$access_targets_file" \
            --output json 2>&1)
    fi
    
    # Clean up temp file
    rm -f "$access_targets_file" 2>/dev/null
    
    # Check for work request (async operation)
    local work_request_id
    work_request_id=$(jq -r '.["opc-work-request-id"] // empty' <<< "$result" 2>/dev/null)
    
    if [[ -n "$work_request_id" ]]; then
        echo -e "${GREEN}✓ Private endpoint creation initiated${NC}"
        log_action_result "SUCCESS" "CREATE operation"
        echo -e "  ${CYAN}Name:${NC}         ${WHITE}$pe_name${NC}"
        echo -e "  ${CYAN}Prefix:${NC}       ${WHITE}$pe_prefix${NC}"
        echo -e "  ${CYAN}Work Request:${NC} ${YELLOW}$work_request_id${NC}"
        echo -e "  ${GRAY}Endpoint will show CREATING state until complete${NC}"
        echo -e "  ${GRAY}Use 'w' from Object Storage menu to view work request status${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Creation initiated, work-request: $work_request_id" >> "$log_file"
    elif jq -e '.data.name' <<< "$result" > /dev/null 2>&1; then
        echo -e "${GREEN}✓ Private endpoint created${NC}"
        echo -e "  ${CYAN}Name:${NC}      ${WHITE}$pe_name${NC}"
        echo -e "  ${CYAN}Namespace:${NC} ${WHITE}$namespace${NC}"
        echo -e "  ${CYAN}Prefix:${NC}    ${WHITE}$pe_prefix${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Created $pe_name in namespace $namespace" >> "$log_file"
    else
        echo -e "${RED}Failed to create private endpoint${NC}"
        log_action_result "FAILED" "CREATE operation"
        echo "$result"
        echo -e "  ${GRAY}Use 'w' from Object Storage menu to view work request errors${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Object Storage - Delete Private Endpoints (multi-select)
# Uses PE_MAP from parent scope: PE_MAP[idx]="name|namespace"
# Args: $1=compartment_id  $2=pe_count  $3=targets (optional)
#--------------------------------------------------------------------------------
os_delete_private_endpoints() {
    local compartment_id="$1"
    local pe_count="${2:-0}"
    local targets="${3:-}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/object_storage_actions_$(date +%Y%m%d).log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_subheader "Delete Private Endpoints" 0
    echo ""
    
    if [[ "$pe_count" -eq 0 ]]; then
        echo -e "${YELLOW}No private endpoints available to delete${NC}"
        _ui_pause
        return
    fi
    
    # If no targets provided, show list and prompt
    if [[ -z "$targets" ]]; then
        echo -e "${WHITE}Available Private Endpoints:${NC}"
        printf "  ${BOLD}%-4s %-30s %-12s %-15s${NC}\n" "p#" "Name" "State" "Namespace"
        print_separator 80
        
        local _di
        for _di in $(seq 1 "$pe_count"); do
            [[ -z "${PE_MAP[$_di]:-}" ]] && continue
            local _pe_name="${PE_MAP[$_di]%%|*}"
            local _pe_ns="${PE_MAP[$_di]#*|}"
            printf "  ${YELLOW}%-4s${NC} %-30s ${WHITE}%-15s${NC}\n" "p${_di}" "${_pe_name:0:28}" "${_pe_ns:0:13}"
        done
        echo ""
        echo -n -e "${CYAN}Select targets (p1, p1-p3, p1,p2, all) [Enter to cancel]: ${NC}"
        read -r targets
        [[ -z "$targets" ]] && { echo -e "${YELLOW}Cancelled${NC}"; return; }
    fi
    
    # Parse targets using _parse_targets
    if ! _parse_targets "p" "$targets" "$pe_count"; then
        echo -e "${RED}Invalid selection${NC}"
        _ui_pause
        return
    fi
    
    if [[ ${#_SEL_INDICES[@]} -eq 0 ]]; then
        echo -e "${YELLOW}No valid targets selected${NC}"
        _ui_pause
        return
    fi
    
    # Build list of PEs to delete and show summary
    local _del_count=${#_SEL_INDICES[@]}
    declare -a _del_names=()
    declare -a _del_namespaces=()
    
    echo -e "${RED}WARNING: This will permanently delete ${_del_count} private endpoint(s):${NC}"
    echo ""
    
    for _idx in "${_SEL_INDICES[@]}"; do
        local _entry="${PE_MAP[$_idx]:-}"
        [[ -z "$_entry" ]] && continue
        local _name="${_entry%%|*}"
        local _ns="${_entry#*|}"
        _del_names+=("$_name")
        _del_namespaces+=("$_ns")
        echo -e "  ${RED}✗${NC} ${WHITE}${_name}${NC} ${GRAY}(namespace: ${_ns})${NC}"
    done
    
    # Command preview
    echo ""
    echo -e "${BOLD}${WHITE}Commands to Execute:${NC}"
    echo ""
    for _i in "${!_del_names[@]}"; do
        echo -e "  ${WHITE}\$ oci os private-endpoint delete --pe-name \"${_del_names[$_i]}\" --namespace-name \"${_del_namespaces[$_i]}\" --region \"${region}\" --force${NC}"
    done
    echo ""
    
    if ! _ui_confirm "DELETE" "confirm deletion of ${_del_count} endpoint(s)"; then
        echo -e "${YELLOW}Cancelled${NC}"
        _ui_pause
        return
    fi
    
    # Execute deletions
    local _success=0 _failed=0
    for _i in "${!_del_names[@]}"; do
        local _name="${_del_names[$_i]}"
        local _ns="${_del_namespaces[$_i]}"
        local delete_cmd="oci os private-endpoint delete --pe-name \"$_name\" --namespace-name \"$_ns\" --region \"$region\" --force"
        
        echo -e "  ${CYAN}Deleting: ${WHITE}${_name}${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTING: $delete_cmd" >> "$log_file"
        
        local result
        log_action "DELETE" "$delete_cmd"
        result=$(oci os private-endpoint delete --pe-name "$_name" --namespace-name "$_ns" --region "$region" --force 2>&1)
        
        if [[ $? -eq 0 ]]; then
            echo -e "  ${GREEN}✓ Deletion initiated${NC}"
            log_action_result "SUCCESS" "DELETE operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted $_name (namespace: $_ns)" >> "$log_file"
            ((_success++))
        else
            echo -e "  ${RED}✗ Failed: $result${NC}"
            log_action_result "FAILED" "DELETE operation"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete $_name - $result" >> "$log_file"
            ((_failed++))
        fi
    done
    
    echo ""
    echo -e "${GREEN}✓ ${_success} deleted${NC}"
    [[ $_failed -gt 0 ]] && echo -e "  ${RED}✗ ${_failed} failed${NC}"
    echo -e "  ${GRAY}Use 'w' from Object Storage menu to view work request status${NC}"
    echo ""
    _ui_pause
}

#===============================================================================
# CUSTOM IMAGES MANAGEMENT
#===============================================================================

manage_custom_images() {
    local compartment_id="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
    local region="${FOCUS_REGION:-$REGION}"
    
    while true; do
        echo ""
        _ui_menu_header "CUSTOM IMAGES MANAGEMENT" \
            --color "$YELLOW" \
            --breadcrumb "Compute" "Custom Images" \
            --cmd "oci compute image list --compartment-id \$COMPARTMENT_ID --sort-by TIMECREATED --all | oci compute image get | oci compute image-shape-compatibility-entry list | oci compute shape list" \
            --env \
            --cache \
            "${CUSTOM_IMAGE_CACHE}|Custom Images"
        
        # ── Discovery ──
        _step_init
        _step_active "custom images"
        
        local custom_images_json _ci_cached=""
        if is_cache_fresh "$CUSTOM_IMAGE_CACHE"; then
            # Invalidate if any image is IMPORTING/PROVISIONING/EXPORTING
            if _cache_invalidate_if_transitional "$CUSTOM_IMAGE_CACHE" "" '.data[]."lifecycle-state"'; then
                : # fall through to fetch
            else
                custom_images_json=$(cat "$CUSTOM_IMAGE_CACHE")
                _ci_cached=" cached"
            fi
        fi
        if [[ -z "$_ci_cached" ]]; then
            local images_json
            images_json=$(oci compute image list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --sort-by TIMECREATED \
                --sort-order DESC \
                --all \
                --output json 2>/dev/null)
            
            # Filter to only show custom images (images where compartment-id matches user's compartment)
            # Oracle platform images have a different compartment-id
            if [[ -n "$images_json" ]] && jq -e '.data' <<< "$images_json" > /dev/null 2>&1; then
                custom_images_json=$(jq --arg comp_id "$compartment_id" '{data: [.data[] | select(.["compartment-id"] == $comp_id)]}' <<< "$images_json")
            else
                custom_images_json='{"data":[]}'
            fi
            
            # Write cache (atomic)
            if [[ -n "$custom_images_json" ]]; then
                echo "$custom_images_json" > "${CUSTOM_IMAGE_CACHE}.tmp" && mv "${CUSTOM_IMAGE_CACHE}.tmp" "$CUSTOM_IMAGE_CACHE"
            fi
        fi
        
        local image_count=0
        if [[ -n "$custom_images_json" ]] && jq -e '.data' <<< "$custom_images_json" > /dev/null 2>&1; then
            image_count=$(jq '.data | length' <<< "$custom_images_json" 2>/dev/null)
        fi
        [[ -z "$image_count" || "$image_count" == "null" ]] && image_count=0
        _step_complete "custom images(${image_count}${_ci_cached})"
        _step_finish
        
        # Count by lifecycle state
        local count_available count_importing count_provisioning count_disabled count_other
        count_available=$(jq '[.data[] | select(.["lifecycle-state"] == "AVAILABLE")] | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
        count_importing=$(jq '[.data[] | select(.["lifecycle-state"] == "IMPORTING")] | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
        count_provisioning=$(jq '[.data[] | select(.["lifecycle-state"] == "PROVISIONING")] | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
        count_disabled=$(jq '[.data[] | select(.["lifecycle-state"] == "DISABLED")] | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
        count_other=$(( image_count - count_available - count_importing - count_provisioning - count_disabled ))
        [[ "$count_other" -lt 0 ]] && count_other=0
        
        echo ""
        
        # Build image map for selection
        declare -A IMAGE_MAP
        IMAGE_MAP=()
        declare -A IMAGE_NAME_MAP
        IMAGE_NAME_MAP=()
        local idx=0
        
        if [[ "$image_count" -gt 0 ]]; then
            _ui_subheader "Custom Images (${image_count})" 0
            echo ""
            
            printf "  ${BOLD}%-3s %-105s %-20s %-14s %-12s %-12s${NC}\n" "#" "Image Name" "OS" "Status" "Billable GB" "Created"
            print_separator 175
            
            while IFS='|' read -r img_id img_name img_os img_billable_gb img_created img_state; do
                [[ -z "$img_id" ]] && continue
                ((idx++))
                
                IMAGE_MAP[$idx]="$img_id"
                IMAGE_NAME_MAP[$idx]="$img_name"
                
                # Format billable size (already in GB from billable-size-in-gbs)
                local size_gb="N/A"
                if [[ -n "$img_billable_gb" && "$img_billable_gb" != "null" && "$img_billable_gb" != "0" ]]; then
                    size_gb="${img_billable_gb}"
                fi
                
                # Format date: YYYY-MM-DD → MM-DD-YYYY
                local created_display="${img_created:0:10}"
                if [[ "$created_display" =~ ^([0-9]{4})-([0-9]{2})-([0-9]{2})$ ]]; then
                    created_display="${BASH_REMATCH[2]}-${BASH_REMATCH[3]}-${BASH_REMATCH[1]}"
                fi
                
                # Color-code status
                local state_color; state_color=$(color_resource_state "$img_state")
                
                printf "  ${YELLOW}%-3s${NC} %-105s %-20s ${state_color}%-14s${NC} %-12s %-12s\n" \
                    "$idx" "$img_name" "$img_os" "$img_state" "$size_gb" "$created_display"
                    
            done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "Unnamed")|\(.["operating-system"] // "N/A")|\(.["billable-size-in-gbs"] // "null")|\(.["time-created"] // "N/A")|\(.["lifecycle-state"] // "UNKNOWN")"' <<< "$custom_images_json" 2>/dev/null)
            echo ""
            
            # Summary counts
            echo -e "  ${CYAN}Total Custom Images:${NC} ${WHITE}${image_count}${NC}"
            if [[ "$count_available" -gt 0 ]]; then
                echo -e "  ${GREEN}Available:${NC}           ${WHITE}${count_available}${NC}"
            fi
            if [[ "$count_importing" -gt 0 ]]; then
                echo -e "  ${YELLOW}Importing:${NC}           ${WHITE}${count_importing}${NC}"
            fi
            if [[ "$count_provisioning" -gt 0 ]]; then
                echo -e "  ${YELLOW}Provisioning:${NC}        ${WHITE}${count_provisioning}${NC}"
            fi
            if [[ "$count_disabled" -gt 0 ]]; then
                echo -e "  ${RED}Disabled:${NC}            ${WHITE}${count_disabled}${NC}"
            fi
            if [[ "$count_other" -gt 0 ]]; then
                echo -e "  ${GRAY}Other:${NC}               ${WHITE}${count_other}${NC}"
            fi
            echo -e "  ${GRAY}(Filtered to show only images created in this compartment)${NC}"
            echo ""
        else
            _ui_subheader "Custom Images (0)" 0
            echo -e "  ${GRAY}No custom images found in this compartment${NC}"
            echo ""
        fi
        
        # Menu options
        _ui_actions
        if [[ "$idx" -gt 0 ]]; then
            echo -e "  ${CYAN}#${NC})    View image details (enter number)"
        fi
        echo -e "  ${GREEN}i${NC})    Import image from URL"
        echo -e "  ${GREEN}c${NC})    Create image from instance"
        echo -e "  ${GREEN}e${NC})    Export image to Object Storage"
        echo -e "  ${CYAN}s #${NC})  Shape compatibility (view/add/remove, s # selects image directly)"
        echo -e "  ${RED}d #${NC})  Delete custom image (d 1, d 1,2, d 1-3, d all)"
        echo -e "  ${MAGENTA}r${NC})    Refresh list"
        echo -e "  ${CYAN}q${NC})    Back to main menu"
        echo ""
        _ui_prompt "Custom Images" "#, i, c, e, s #, d #, r, q, show"
        read -r choice
        [[ "${choice:-}" == :* ]] && _nav_try_jump "$choice" && return
        
        case "$choice" in
            [0-9]*)
                if [[ -n "${IMAGE_MAP[$choice]}" ]]; then
                    custom_image_view_details "${IMAGE_MAP[$choice]}"
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
            i|I)
                custom_image_import "$compartment_id"
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            c|C)
                custom_image_create_from_instance "$compartment_id"
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            e|E)
                custom_image_export "$compartment_id"
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            s|S)
                custom_image_shape_compatibility "$compartment_id"
                ;;
            s\ [0-9]*|S\ [0-9]*|s[0-9]*|S[0-9]*)
                local _sc_num="${choice//[^0-9]/}"
                if [[ -n "${IMAGE_MAP[$_sc_num]:-}" ]]; then
                    custom_image_shape_compatibility "$compartment_id" "${IMAGE_MAP[$_sc_num]}" "${IMAGE_NAME_MAP[$_sc_num]}"
                else
                    echo -e "${RED}Invalid image number: ${_sc_num}${NC}"
                    sleep 1
                fi
                ;;
            d|D|delete|DELETE)
                custom_image_delete "$compartment_id" "" "$idx"
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            d\ *|D\ *|delete\ *|DELETE\ *)
                local _del_args="${choice#* }"
                custom_image_delete "$compartment_id" "$_del_args" "$idx"
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            r|R)
                rm -f "$CUSTOM_IMAGE_CACHE"
                ;;
            q|Q|"")
                break
                ;;
            show|SHOW)
                continue
                ;;
            env*|ENV*)
                _env_dispatch "$choice"
                ;;
            *)
                echo -e "${RED}Invalid selection${NC}"
                sleep 1
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Custom Images - View Details
#--------------------------------------------------------------------------------
custom_image_view_details() {
    local image_id="$1"
    # Extract region from image OCID (images may be from a different region than focus)
    local region
    region=$(_ocid_region "$image_id" "${FOCUS_REGION:-$REGION}")

    echo ""
    _ui_subheader "Image Details" 0
    echo ""
    _step_init
    _step_active "image details"

    local img_json
    img_json=$(oci compute image get --image-id "$image_id" --region "$region" --output json 2>/dev/null)
    _step_complete "image details"
    _step_finish
    
    if [[ -z "$img_json" ]] || ! jq -e '.data' <<< "$img_json" > /dev/null 2>&1; then
        echo -e "${RED}Failed to fetch image details${NC}"
        _ui_policy_hint "read images in compartment"
        _ui_pause
        return
    fi
    
    # Extract fields
    local name os os_version billable_gb launch_mode create_type
    local time_created base_image_id compartment_id state
    
    IFS=$'\t' read -r name os os_version billable_gb launch_mode create_type \
        time_created base_image_id compartment_id state < <(jq -r '.data | [
            .["display-name"] // "N/A",
            .["operating-system"] // "N/A",
            .["operating-system-version"] // "N/A",
            .["billable-size-in-gbs"] // 0,
            .["launch-mode"] // "N/A",
            .["create-image-allowed"] // "N/A",
            .["time-created"] // "N/A",
            .["base-image-id"] // "N/A",
            .["compartment-id"] // "N/A",
            .["lifecycle-state"] // "N/A"
        ] | @tsv' <<< "$img_json")
    
    # Format billable size (already in GB)
    local size_gb="N/A"
    if [[ -n "$billable_gb" && "$billable_gb" != "0" && "$billable_gb" != "null" ]]; then
        size_gb="${billable_gb}"
    fi
    
    # Format date: YYYY-MM-DDTHH:MM:SS → MM-DD-YYYY HH:MM:SS
    local created_display="${time_created/T/ }"
    if [[ "$time_created" =~ ^([0-9]{4})-([0-9]{2})-([0-9]{2})T(.+)$ ]]; then
        created_display="${BASH_REMATCH[2]}-${BASH_REMATCH[3]}-${BASH_REMATCH[1]} ${BASH_REMATCH[4]}"
    fi
    
    echo ""
    _ui_subheader "Basic Information" 0
    echo -e "  ${CYAN}Name:${NC}           ${WHITE}$name${NC}"
    echo -e "  ${CYAN}State:${NC}          ${GREEN}$state${NC}"
    echo -e "  ${CYAN}OS:${NC}             ${WHITE}$os $os_version${NC}"
    echo -e "  ${CYAN}Billable Size:${NC}  ${WHITE}${size_gb} GB${NC}"
    echo -e "  ${CYAN}Launch Mode:${NC}    ${WHITE}$launch_mode${NC}"
    echo -e "  ${CYAN}Created:${NC}        ${WHITE}${created_display}${NC}"
    echo ""
    _ui_subheader "Identifiers" 0
    echo -e "  ${CYAN}Image OCID:${NC}     ${YELLOW}$image_id${NC}"
    echo -e "  ${CYAN}Compartment:${NC}    ${WHITE}$(resolve_compartment_name "$compartment_id")${NC} ${GRAY}($compartment_id)${NC}"
    if [[ "$base_image_id" != "N/A" && "$base_image_id" != "null" ]]; then
        echo -e "  ${CYAN}Base Image:${NC}     ${YELLOW}$base_image_id${NC}"
    fi
    echo ""
    
    # Show launch options
    local launch_options
    launch_options=$(jq -r '.data["launch-options"] // {}' <<< "$img_json")
    if [[ -n "$launch_options" && "$launch_options" != "{}" ]]; then
        _ui_subheader "Launch Options" 0
        local boot_vol_type firmware network_type
        boot_vol_type=$(jq -r '.["boot-volume-type"] // "N/A"' <<< "$launch_options")
        firmware=$(jq -r '.firmware // "N/A"' <<< "$launch_options")
        network_type=$(jq -r '.["network-type"] // "N/A"' <<< "$launch_options")
        echo -e "  ${CYAN}Boot Volume Type:${NC} ${WHITE}$boot_vol_type${NC}"
        echo -e "  ${CYAN}Firmware:${NC}         ${WHITE}$firmware${NC}"
        echo -e "  ${CYAN}Network Type:${NC}     ${WHITE}$network_type${NC}"
        echo ""
    fi
    
    # Show compatible shapes in 4-column categorized layout with modern/older split
    _ui_subheader "Compatible Shapes" 0
    
    # Fetch shape compatibility list
    local compat_json
    compat_json=$(oci compute image-shape-compatibility-entry list --image-id "$image_id" --region "$region" --output json 2>/dev/null)
    
    declare -A _COMPAT_SET=()
    
    if [[ -n "$compat_json" ]] && jq -e '.data' <<< "$compat_json" > /dev/null 2>&1; then
        local shape_count
        shape_count=$(jq '.data | length' <<< "$compat_json")
        
        while read -r _cs; do
            [[ -z "$_cs" ]] && continue
            _COMPAT_SET["$_cs"]=1
        done < <(jq -r '.data[].shape' <<< "$compat_json" 2>/dev/null)
        
        # Fetch all available shapes in region for categorized display
        local _ci_compartment="${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}"
        local _avail_shapes_json
        _avail_shapes_json=$(_get_shapes_json "$_ci_compartment")
        
        if [[ -n "$_avail_shapes_json" ]] && jq -e '.data[0]' <<< "$_avail_shapes_json" >/dev/null 2>&1; then
            local _avail_total
            _avail_total=$(jq '[.data[].shape] | unique | length' <<< "$_avail_shapes_json" 2>/dev/null)
            echo -e "  ${WHITE}${shape_count} compatible${NC} ${GRAY}of ${_avail_total} available shapes${NC}"
            echo ""
            
            local -a _sc_vm=() _sc_vm_old=() _sc_bm=() _sc_bm_old=() _sc_bm_gpu=() _sc_vm_gpu=()
            local _sc_dtotal=0
            
            _shapes_categorize "$_avail_shapes_json" "_COMPAT_SET" \
                _sc_vm _sc_vm_old _sc_bm _sc_bm_old _sc_bm_gpu _sc_vm_gpu \
                _sc_dtotal
            
            _shapes_render_compat display \
                _sc_vm _sc_vm_old _sc_bm _sc_bm_old _sc_bm_gpu _sc_vm_gpu \
                "$_sc_dtotal"
        else
            # Fallback: just show compat count if shape list unavailable
            echo -e "  ${WHITE}$shape_count compatible shape(s)${NC}"
        fi
    else
        echo -e "  ${GRAY}Unable to retrieve shape compatibility${NC}"
    fi
    echo ""
    
    _ui_pause
}

#--------------------------------------------------------------------------------
# Custom Images - Import from URL
#--------------------------------------------------------------------------------
custom_image_import() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/custom_images_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_subheader "Import Image from URL" 0
    echo ""
    echo -e "${GRAY}Provide a publicly accessible URL or a pre-authenticated request (PAR) URL${NC}"
    echo -e "${GRAY}pointing to a QCOW2, VMDK, or OCI image file.${NC}"
    echo ""
    
    # Get URL
    echo -n -e "${CYAN}Enter image URL: ${NC}"
    read -r image_url
    
    if [[ -z "$image_url" ]]; then
        echo -e "${YELLOW}Import cancelled - no URL provided${NC}"
        _ui_pause
        return
    fi
    
    # Validate URL format
    if [[ ! "$image_url" =~ ^https?:// ]]; then
        echo -e "${RED}Invalid URL - must start with http:// or https://${NC}"
        _ui_pause
        return
    fi
    
    # Extract display name from URL
    # For Object Storage URLs: .../o/ImageName or .../o/ImageName?params
    # For other URLs: use basename of the path
    echo ""
    local default_name=""
    local url_no_params="${image_url%%\?*}"   # strip query params
    if [[ "$url_no_params" =~ /o/(.+)$ ]]; then
        # Object Storage URL - extract everything after /o/
        default_name="${BASH_REMATCH[1]}"
    else
        default_name=$(basename "$url_no_params")
        default_name="${default_name%.*}"   # strip extension for non-ObjStorage URLs
    fi
    [[ -z "$default_name" || "$default_name" == "/" ]] && default_name="imported-image"
    
    echo -n -e "${CYAN}Enter display name [${default_name}]: ${NC}"
    read -r image_name
    [[ -z "$image_name" ]] && image_name="$default_name"
    
    # Auto-detect OS from image name
    # Pattern: <OS-Name>-<Version>-<rest>  e.g. Canonical-Ubuntu-22.04-aarch64-...
    # OS is everything before the first version pattern (digits.digits)
    # Replace hyphens with spaces in the OS portion
    local auto_os=""
    if [[ "$image_name" =~ ^([A-Za-z]([A-Za-z0-9]*-)*[A-Za-z0-9]*)-[0-9]+\.[0-9]+ ]]; then
        auto_os="${BASH_REMATCH[1]}"
        # Replace hyphens with spaces
        auto_os="${auto_os//-/ }"
    fi
    
    # Check if image with same display name already exists
    echo ""
    echo -e "${GRAY}Checking for existing image with same name...${NC}"
    local existing_images
    existing_images=$(oci compute image list \
        --compartment-id "$compartment_id" \
        --region "$region" \
        --display-name "$image_name" \
        --lifecycle-state AVAILABLE \
        --output json 2>/dev/null)
    
    local existing_count=0
    if [[ -n "$existing_images" ]] && jq -e '.data[0]' <<< "$existing_images" >/dev/null; then
        existing_count=$(jq '.data | length' <<< "$existing_images" 2>/dev/null)
    fi
    
    if [[ "$existing_count" -gt 0 ]]; then
        local existing_id existing_os
        existing_id=$(jq -r '.data[0].id' <<< "$existing_images" 2>/dev/null)
        existing_os=$(jq -r '.data[0]["operating-system"] // "N/A"' <<< "$existing_images" 2>/dev/null)
        echo -e "${YELLOW}⚠ An image named '${image_name}' already exists:${NC}"
        echo -e "  ${CYAN}OCID:${NC} ${YELLOW}$existing_id${NC}"
        echo -e "  ${CYAN}OS:${NC}   ${WHITE}$existing_os${NC}"
        echo ""
        echo -n -e "${YELLOW}Continue with import anyway? (y/N): ${NC}"
        read -r dup_confirm
        if [[ "$dup_confirm" != "y" && "$dup_confirm" != "Y" ]]; then
            echo -e "${YELLOW}Import cancelled${NC}"
            _ui_pause
            return
        fi
    else
        echo -e "  ${GREEN}✓${NC} No duplicate found"
    fi
    
    # Get operating system name (with auto-detected default)
    echo ""
    if [[ -n "$auto_os" ]]; then
        echo -e "${GRAY}Auto-detected OS from image name: ${WHITE}${auto_os}${NC}"
        echo -n -e "${CYAN}Enter operating system name [${auto_os}]: ${NC}"
    else
        echo -e "${GRAY}Examples: Canonical Ubuntu, Oracle Linux, CentOS, Windows, Custom${NC}"
        echo -n -e "${CYAN}Enter operating system name: ${NC}"
    fi
    read -r os_name
    [[ -z "$os_name" && -n "$auto_os" ]] && os_name="$auto_os"
    
    if [[ -z "$os_name" ]]; then
        echo -e "${RED}Operating system name is required${NC}"
        _ui_pause
        return
    fi
    
    # Determine source image type
    # OCI CLI only supports QCOW2 and VMDK for --source-image-type
    # For native OCI images, the flag is omitted entirely
    echo ""
    _ui_subheader "Source Image Type" 0
    echo -e "  ${YELLOW}1${NC}) QCOW2"
    echo -e "  ${YELLOW}2${NC}) VMDK"
    echo -e "  ${YELLOW}3${NC}) None - OCI native format (omit source type flag)"
    echo ""
    echo -n -e "${CYAN}Select source type [3]: ${NC}"
    read -r type_choice
    
    local source_type=""
    case "$type_choice" in
        1) source_type="QCOW2" ;;
        2) source_type="VMDK" ;;
        *) source_type="" ;;
    esac
    
    # Build the command
    local cmd="oci compute image import from-object-uri"
    cmd+=" --uri \"$image_url\""
    cmd+=" --compartment-id \"$compartment_id\""
    cmd+=" --region \"$region\""
    cmd+=" --operating-system \"$os_name\""
    cmd+=" --display-name \"$image_name\""
    [[ -n "$source_type" ]] && cmd+=" --source-image-type \"$source_type\""
    
    local source_type_display="${source_type:-None (OCI native)}"
    
    echo ""
    _ui_subheader "Confirm Import" 0
    echo ""
    echo -e "${CYAN}URL:${NC}              $image_url"
    echo -e "${CYAN}Display Name:${NC}     $image_name"
    echo -e "${CYAN}Operating System:${NC} $os_name"
    echo -e "${CYAN}Source Type:${NC}      $source_type_display"
    echo ""
    _ui_subheader "Command to Execute" 0
    echo -e "${GRAY}$cmd${NC}"
    echo ""
    echo -n -e "${YELLOW}Proceed with import? (y/N): ${NC}"
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Import cancelled${NC}"
        _ui_pause
        return
    fi
    
    # Execute import — use direct invocation (not _safe_exec) to preserve spaces in OS name/display name
    echo ""
    echo -e "${GRAY}Importing image (this may take several minutes)...${NC}"
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"
    echo -e "${WHITE}$ $cmd${NC}"

    local -a _import_args=(
        oci compute image import from-object-uri
        --uri "$image_url"
        --compartment-id "$compartment_id"
        --region "$region"
        --operating-system "$os_name"
        --display-name "$image_name"
    )
    [[ -n "$source_type" ]] && _import_args+=(--source-image-type "$source_type")

    local result
    result=$(OCI_CLI_INTERACTIVE=0 "${_import_args[@]}" 2>&1)
    
    if jq -e '.data.id' <<< "$result" > /dev/null 2>&1; then
        local new_image_id
        new_image_id=$(jq -r '.data.id' <<< "$result")
        echo -e "${GREEN}✓ Image import initiated successfully${NC}"
        echo -e "  ${CYAN}Image OCID:${NC} ${YELLOW}$new_image_id${NC}"
        echo -e "  ${GRAY}Image will be available once import completes${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Imported image $image_name (OS: $os_name) -> $new_image_id" >> "$log_file"
        
        # ── Auto-add GPU shape compatibility (vendor + architecture aware) ──
        echo ""
        
        # Detect GPU vendor and architecture from image name
        local _gpu_vendor="all" _img_arch="x86"
        local _img_name_upper
        _img_name_upper=$(echo "$image_name" | tr '[:lower:]' '[:upper:]')
        
        # Architecture detection
        if echo "$_img_name_upper" | grep -qE 'AARCH64|ARM64'; then
            _img_arch="arm"
        fi
        
        # Vendor detection
        if echo "$_img_name_upper" | grep -qE 'AMD|ROCM|MI300'; then
            _gpu_vendor="amd"
        elif echo "$_img_name_upper" | grep -qE 'CUDA|NVIDIA|NCCL'; then
            _gpu_vendor="nvidia"
        fi
        
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SHAPE_DETECT: vendor=${_gpu_vendor} arch=${_img_arch} (from name: $image_name)" >> "$log_file"
        
        # Build detection label
        local _detect_parts=()
        [[ "$_gpu_vendor" == "nvidia" ]] && _detect_parts+=("${GREEN}NVIDIA/CUDA${NC}")
        [[ "$_gpu_vendor" == "amd" ]]    && _detect_parts+=("${MAGENTA}AMD/ROCm${NC}")
        [[ "$_img_arch" == "arm" ]]      && _detect_parts+=("${BLUE}aarch64/ARM${NC}")
        [[ "$_img_arch" == "x86" ]]      && _detect_parts+=("${WHITE}x86_64${NC}")
        
        if [[ ${#_detect_parts[@]} -gt 0 && ("$_gpu_vendor" != "all" || "$_img_arch" != "x86") ]]; then
            local _detect_label
            _detect_label=$(IFS=', '; echo "${_detect_parts[*]}")
            echo -e "${WHITE}Adding shape compatibility (${_detect_label}${WHITE} detected from image name)${NC}..."
        else
            echo -e "${WHITE}Adding GPU shape compatibility ${GRAY}(all GPU/HPC x86 — no vendor/arch detected in name)${NC}..."
        fi
        
        # Fetch available shapes in region (all shapes, not just GPU)
        local _all_shapes_json
        _all_shapes_json=$(_get_shapes_json "$compartment_id")
        
        local -a _target_shape_names=()
        local _total_candidates=0 _arch_skipped=0 _vendor_skipped=0
        
        # Classify shape architecture using processor-description + name patterns
        # ARM: processor contains "Ampere", "Grace" OR shape has .A1. .A2. .A3.
        # x86: everything else (Intel, AMD EPYC, etc.)
        _is_arm_shape() {
            local _shape="$1" _proc="$2"
            local _proc_up _shape_up
            _proc_up=$(echo "$_proc" | tr '[:lower:]' '[:upper:]')
            _shape_up=$(echo "$_shape" | tr '[:lower:]' '[:upper:]')
            # Processor description: Ampere Altra/AmpereOne (ARM compute), Grace (GB200)
            if echo "$_proc_up" | grep -qE 'AMPERE|GRACE'; then
                return 0
            fi
            # Shape name patterns: .A1. .A2. .A3. are Ampere ARM, GB200 is Grace ARM
            if echo "$_shape_up" | grep -qE '\.A[1-3]\.|GB200'; then
                return 0
            fi
            return 1
        }
        
        if [[ -n "$_all_shapes_json" ]] && jq -e '.data[0]' <<< "$_all_shapes_json" >/dev/null 2>&1; then
            
            # Extract shape + processor-description pairs
            local -a _candidate_shapes=() _candidate_procs=()
            while IFS='|' read -r _cs _cp; do
                [[ -z "$_cs" ]] && continue
                _candidate_shapes+=("$_cs")
                _candidate_procs+=("$_cp")
            done < <(jq -r '[.data[] | {shape, proc: (."processor-description" // "")}] | unique_by(.shape) | sort_by(.shape)[] | "\(.shape)|\(.proc)"' <<< "$_all_shapes_json" 2>/dev/null)
            
            # Filter shapes by architecture, type, and vendor
            for _ci in "${!_candidate_shapes[@]}"; do
                local _cs="${_candidate_shapes[$_ci]}"
                local _cp="${_candidate_procs[$_ci]}"
                local _cs_upper
                _cs_upper=$(echo "$_cs" | tr '[:lower:]' '[:upper:]')
                
                local _is_gpu=false _is_hpc=false _is_arm=false
                echo "$_cs_upper" | grep -q 'GPU' && _is_gpu=true
                echo "$_cs_upper" | grep -q 'HPC' && _is_hpc=true
                _is_arm_shape "$_cs" "$_cp" && _is_arm=true
                
                # Skip non-GPU/HPC shapes (we only add accelerator shapes)
                if [[ "$_is_gpu" == "false" && "$_is_hpc" == "false" ]]; then
                    continue
                fi
                ((_total_candidates++))
                
                # Architecture filter
                if [[ "$_img_arch" == "arm" && "$_is_arm" == "false" ]]; then
                    ((_arch_skipped++))
                    continue
                fi
                if [[ "$_img_arch" == "x86" && "$_is_arm" == "true" ]]; then
                    ((_arch_skipped++))
                    continue
                fi
                
                # Vendor filter (only applies to GPU shapes, not HPC)
                if [[ "$_is_hpc" == "true" ]]; then
                    _target_shape_names+=("$_cs")  # HPC always included for matching arch
                    continue
                fi
                
                case "$_gpu_vendor" in
                    nvidia)
                        if ! echo "$_cs_upper" | grep -qE '\.MI[0-9]'; then
                            _target_shape_names+=("$_cs")
                        else
                            ((_vendor_skipped++))
                        fi
                        ;;
                    amd)
                        if echo "$_cs_upper" | grep -qE '\.MI[0-9]'; then
                            _target_shape_names+=("$_cs")
                        else
                            ((_vendor_skipped++))
                        fi
                        ;;
                    *)
                        _target_shape_names+=("$_cs")
                        ;;
                esac
            done
            
            # Show what was filtered
            local _skip_parts=()
            [[ $_arch_skipped -gt 0 ]]   && _skip_parts+=("${_arch_skipped} wrong-arch")
            [[ $_vendor_skipped -gt 0 ]] && _skip_parts+=("${_vendor_skipped} wrong-vendor")
            if [[ ${#_skip_parts[@]} -gt 0 ]]; then
                echo -e "  ${GRAY}($(IFS=', '; echo "${_skip_parts[*]}") shapes skipped from ${_total_candidates} GPU/HPC candidates)${NC}"
            fi
        fi
        
        if [[ ${#_target_shape_names[@]} -gt 0 ]]; then
            local _gs_ok=0 _gs_fail=0
            for _gs in "${_target_shape_names[@]}"; do
                local _gs_result
                _gs_result=$(oci compute image-shape-compatibility-entry add \
                    --image-id "$new_image_id" \
                    --shape-name "$_gs" \
                    --region "$region" \
                    --output json 2>&1)
                
                if echo "$_gs_result" | jq -e '.data' >/dev/null 2>&1 || [[ -z "$_gs_result" ]]; then
                    # Color-code: magenta=AMD, green=NVIDIA, cyan=HPC, blue=ARM
                    local _gs_color="$GREEN"
                    echo "$_gs" | grep -qiE '\.MI[0-9]' && _gs_color="$MAGENTA"
                    echo "$_gs" | grep -qi 'HPC' && _gs_color="$CYAN"
                    _is_arm_shape "$_gs" "" && _gs_color="$BLUE"
                    echo -e "  ${GREEN}✓${NC} ${_gs_color}${_gs}${NC}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SHAPE_COMPAT: Added ${_gs} to ${new_image_id}" >> "$log_file"
                    ((_gs_ok++))
                else
                    echo -e "  ${RED}✗${NC} ${_gs}"
                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SHAPE_COMPAT_FAIL: ${_gs} — ${_gs_result}" >> "$log_file"
                    ((_gs_fail++))
                fi
            done
            echo ""
            local _summary_label=""
            [[ "$_gpu_vendor" == "nvidia" ]] && _summary_label=" NVIDIA"
            [[ "$_gpu_vendor" == "amd" ]]    && _summary_label=" AMD"
            [[ "$_img_arch" == "arm" ]]      && _summary_label="${_summary_label} ARM"
            echo -e "  ${GREEN}${_gs_ok}${_summary_label} GPU/HPC shapes added${NC}${_gs_fail:+, ${RED}${_gs_fail} failed${NC}}"
        else
            if [[ "$_img_arch" == "arm" ]]; then
                echo -e "  ${YELLOW}No ARM-compatible GPU/HPC shapes found in region${NC}"
                echo -e "  ${GRAY}(ARM GPU shapes like GB200 Grace may not yet be available)${NC}"
            else
                echo -e "  ${GRAY}No matching GPU/HPC shapes found in region${NC}"
            fi
        fi
    else
        echo -e "${RED}Failed to import image${NC}"
        echo "$result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Custom Images - Create from Instance
#--------------------------------------------------------------------------------
custom_image_create_from_instance() {
    local compartment_id="$1"
    local log_file="${LOGS_DIR}/custom_images_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    local region="${FOCUS_REGION:-$REGION}"
    
    echo ""
    _ui_subheader "Create Image from Instance" 0
    echo ""
    
    # Prompt for compartment
    local comp_name
    comp_name=$(resolve_compartment_name "$compartment_id")
    echo -e "${CYAN}Compartment:${NC} ${WHITE}$comp_name${NC} ${GRAY}($compartment_id)${NC}"
    echo -n -e "${CYAN}Use this compartment? (Y/n): ${NC}"
    read -r comp_confirm
    if [[ "$comp_confirm" == "n" || "$comp_confirm" == "N" ]]; then
        local tenancy_id="${TENANCY_ID:-}"
        [[ -z "$tenancy_id" ]] && tenancy_id=$(get_tenancy_id_from_compartment "$compartment_id")
        
        if [[ -n "$tenancy_id" ]] && display_compartment_selector "$tenancy_id" "$compartment_id"; then
            local _default_idx="${COMP_IDX_REV[$compartment_id]:-}"
            local _default_hint=""
            [[ -n "$_default_idx" ]] && _default_hint="${_default_idx}"
            echo -n -e "${CYAN}Select compartment number [${_default_hint:-Enter to cancel}]: ${NC}"
            local comp_choice
            read -r comp_choice
            [[ -z "$comp_choice" && -n "$_default_hint" ]] && comp_choice="$_default_hint"
            
            if [[ -n "$comp_choice" && -n "${COMP_IDX[$comp_choice]:-}" ]]; then
                compartment_id="${COMP_IDX[$comp_choice]}"
                local _sel_data="${COMP_MAP[$compartment_id]}"
                local _sel_name="${_sel_data%%|*}"
                echo -e "${GREEN}✓ Compartment: ${_sel_name}${NC}"
            else
                echo -e "${RED}No compartment selected - cancelled${NC}"
                _ui_pause
                return
            fi
        else
            echo -n -e "${CYAN}Enter compartment OCID: ${NC}"
            read -r compartment_id
            if [[ -z "$compartment_id" ]]; then
                echo -e "${RED}No compartment provided - cancelled${NC}"
                _ui_pause
                return
            fi
        fi
    fi
    echo ""
    
    # List all instances (cache-first from INSTANCE_LIST_CACHE)
    _step_init
    _step_active "instances"
    local instances_json _inst_cached=""
    if is_cache_fresh "$INSTANCE_LIST_CACHE" 2>/dev/null && [[ -s "$INSTANCE_LIST_CACHE" ]]; then
        instances_json=$(cat "$INSTANCE_LIST_CACHE" 2>/dev/null)
        if [[ -n "$instances_json" ]] && jq -e '.data[0]' <<< "$instances_json" >/dev/null 2>&1; then
            _inst_cached=" cached"
        else
            instances_json=""
        fi
    fi
    if [[ -z "$_inst_cached" ]]; then
        instances_json=$(oci compute instance list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --all \
            --output json 2>/dev/null)
    fi
    _step_complete "instances${_inst_cached}"
    _step_finish
    
    if [[ -z "$instances_json" ]] || ! jq -e '.data[0]' <<< "$instances_json" > /dev/null 2>&1; then
        echo -e "${RED}No instances found in this compartment${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    _ui_subheader "Select Instance" 0
    printf "  ${BOLD}%-4s %-45s %-15s %-22s %-16s %-10s${NC}\n" \
        "#" "Display Name" "State" "Shape" "Launch Mode" "AD"
    print_separator 120
    
    declare -A CI_INSTANCE_MAP=()
    declare -A CI_INSTANCE_NAME_MAP=()
    declare -A CI_INSTANCE_LAUNCH_MODE=()
    local idx=0

    while IFS='|' read -r inst_id inst_name inst_state inst_shape inst_ad inst_launch_mode; do
        [[ -z "$inst_id" ]] && continue
        # Skip terminated instances
        [[ "$inst_state" == "TERMINATED" ]] && continue
        ((idx++))

        CI_INSTANCE_MAP[$idx]="$inst_id"
        CI_INSTANCE_NAME_MAP[$idx]="$inst_name"
        CI_INSTANCE_LAUNCH_MODE[$idx]="${inst_launch_mode:-NATIVE}"
        
        # Color state
        local state_color
        state_color=$(color_oci_state "$inst_state")

        local ad_short="${inst_ad##*:}"
        
        printf "  ${YELLOW}%-4s${NC} %-45s ${state_color}%-15s${NC} %-22s %-16s %-10s\n" \
            "$idx" "$inst_name" "$inst_state" "${inst_shape:0:22}" "${inst_launch_mode:-N/A}" "$ad_short"
            
    done < <(jq -r ' 
        .data[] |
        "\(.id)|\(.["display-name"] // "Unnamed")|\(.["lifecycle-state"])|\(.shape // "N/A")|\(.["availability-domain"] // "N/A")|\(.["launch-mode"] // "NATIVE")"
    ' <<< "$instances_json" 2>/dev/null | sort -t'|' -k2,2)
    
    if [[ $idx -eq 0 ]]; then
        echo -e "  ${GRAY}No instances found (excluding TERMINATED)${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    echo -n -e "${CYAN}Select instance #: ${NC}"
    read -r inst_choice

    local selected_instance=""
    [[ -n "$inst_choice" ]] && selected_instance="${CI_INSTANCE_MAP[$inst_choice]:-}"
    if [[ -z "$selected_instance" ]]; then
        echo -e "${RED}Invalid instance selection${NC}"
        _ui_pause
        return
    fi
    
    # Get instance details for defaults (from the locally-fetched data, not INSTANCE_LIST_CACHE)
    local instance_name inst_launch_mode
    instance_name="${CI_INSTANCE_NAME_MAP[$inst_choice]:-custom-image}"
    inst_launch_mode="${CI_INSTANCE_LAUNCH_MODE[$inst_choice]}"
    
    # Get image name
    echo ""
    local default_name="${instance_name}-image-$(date +%Y%m%d)"
    echo -n -e "${CYAN}Enter image display name [${default_name}]: ${NC}"
    read -r image_name
    [[ -z "$image_name" ]] && image_name="$default_name"
    
    # Strip leading hyphens (OCI CLI misinterprets as flags, triggers interactive mode)
    image_name="${image_name#-}"
    image_name="${image_name#-}"

    # Build the command string for display/logging
    local cmd="oci compute image create"
    cmd+=" --compartment-id \"$compartment_id\""
    cmd+=" --instance-id \"$selected_instance\""
    cmd+=" --display-name \"$image_name\""
    cmd+=" --region \"$region\""
    if [[ -n "$inst_launch_mode" && "$inst_launch_mode" != "null" && "$inst_launch_mode" != "N/A" ]]; then
        cmd+=" --launch-mode \"$inst_launch_mode\""
    fi
    
    echo ""
    _ui_subheader "Confirm Image Creation" 0
    echo ""
    echo -e "${CYAN}Instance:${NC}    $instance_name"
    echo -e "${CYAN}Instance ID:${NC} ${YELLOW}$selected_instance${NC}"
    echo -e "${CYAN}Image Name:${NC}  $image_name"
    echo -e "${CYAN}Launch Mode:${NC} $inst_launch_mode"
    echo ""
    _ui_subheader "Command to Execute" 0
    echo -e "${GRAY}$cmd${NC}"
    echo ""
    echo -e "${YELLOW}NOTE: The instance will remain running during image creation${NC}"
    echo ""
    echo -n -e "${YELLOW}Proceed with image creation? (y/N): ${NC}"
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Image creation cancelled${NC}"
        _ui_pause
        return
    fi
    
    # Execute creation
    echo ""
    echo -e "${GRAY}Creating image (this may take several minutes)...${NC}"
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"
    echo -e "${WHITE}$ $cmd${NC}"

    # Use direct invocation (not _safe_exec) to preserve spaces in display name
    local -a _create_args=(
        oci compute image create
        --compartment-id "$compartment_id"
        --instance-id "$selected_instance"
        --display-name "$image_name"
        --region "$region"
    )
    if [[ -n "$inst_launch_mode" && "$inst_launch_mode" != "null" && "$inst_launch_mode" != "N/A" ]]; then
        _create_args+=(--launch-mode "$inst_launch_mode")
    fi

    local result
    result=$(OCI_CLI_INTERACTIVE=0 "${_create_args[@]}" 2>&1)

    if jq -e '.data.id' <<< "$result" > /dev/null 2>&1; then
        local new_image_id
        new_image_id=$(jq -r '.data.id' <<< "$result")
        echo -e "${GREEN}✓ Image creation initiated successfully${NC}"
        echo -e "  ${CYAN}Image OCID:${NC} ${YELLOW}$new_image_id${NC}"
        echo -e "  ${CYAN}Launch Mode:${NC} ${WHITE}$inst_launch_mode${NC}"
        echo -e "  ${GRAY}Image will be available once creation completes${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Created image $image_name (launch-mode: $inst_launch_mode) from $instance_name -> $new_image_id" >> "$log_file"
    else
        echo -e "${RED}Failed to create image${NC}"
        echo "$result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Custom Images - Export to Object Storage
#--------------------------------------------------------------------------------
custom_image_export() {
    local compartment_id="$1"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/custom_images_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_subheader "Export Image to Object Storage" 0
    echo ""
    
    # Get namespace
    local namespace
    namespace=$(oci os ns get --output json 2>/dev/null | jq -r '.data // empty')
    
    if [[ -z "$namespace" ]]; then
        echo -e "${RED}Failed to get Object Storage namespace${NC}"
        _ui_pause
        return
    fi
    
    # List custom images (cache-first)
    _step_init
    _step_active "custom images"
    local images_json _ci_exp_cached=""
    if is_cache_fresh "$CUSTOM_IMAGE_CACHE" 2>/dev/null && [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
        images_json=$(cat "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
        if [[ -n "$images_json" ]] && jq -e '.data[0]' <<< "$images_json" >/dev/null 2>&1; then
            _ci_exp_cached=" cached"
        else
            images_json=""
        fi
    fi
    if [[ -z "$_ci_exp_cached" ]]; then
        images_json=$(oci compute image list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --lifecycle-state AVAILABLE \
            --sort-by TIMECREATED \
            --sort-order DESC \
            --all \
            --output json 2>/dev/null)
    fi
    _step_complete "custom images${_ci_exp_cached}"
    _step_finish

    # Filter to only show custom images
    local custom_images_json
    if [[ -n "$_ci_exp_cached" ]]; then
        custom_images_json="$images_json"
    elif [[ -n "$images_json" ]] && jq -e '.data' <<< "$images_json" > /dev/null 2>&1; then
        custom_images_json=$(jq --arg comp_id "$compartment_id" '{data: [.data[] | select(.["compartment-id"] == $comp_id)]}' <<< "$images_json")
    else
        custom_images_json='{"data":[]}'
    fi
    
    local img_count=0
    img_count=$(jq '.data | length' <<< "$custom_images_json" 2>/dev/null || echo "0")
    
    if [[ "$img_count" -eq 0 ]]; then
        echo -e "${RED}No custom images found in this compartment${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    _ui_subheader "Select Image to Export" 0
    printf "  ${BOLD}%-4s %-105s %-18s %-10s %-12s${NC}\n" "#" "Image Name" "OS" "Size (GB)" "Created"
    print_separator 160
    
    declare -A EXPORT_IMAGE_MAP=()
    local idx=0
    
    while IFS='|' read -r img_id img_name img_os img_billable_gb img_created; do
        [[ -z "$img_id" ]] && continue
        ((idx++))
        EXPORT_IMAGE_MAP[$idx]="$img_id|$img_name"
        
        local size_gb="N/A"
        if [[ -n "$img_billable_gb" && "$img_billable_gb" != "null" && "$img_billable_gb" != "0" ]]; then
            size_gb="${img_billable_gb}"
        fi
        # Format date: YYYY-MM-DD → MM-DD-YYYY
        local created_display="${img_created:0:10}"
        if [[ "$created_display" =~ ^([0-9]{4})-([0-9]{2})-([0-9]{2})$ ]]; then
            created_display="${BASH_REMATCH[2]}-${BASH_REMATCH[3]}-${BASH_REMATCH[1]}"
        fi
        
        printf "  ${YELLOW}%-4s${NC} %-105s %-18s %-10s %-12s\n" \
            "$idx" "$img_name" "$img_os" "$size_gb" "$created_display"
    done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "Unnamed")|\(.["operating-system"] // "N/A")|\(.["billable-size-in-gbs"] // "null")|\(.["time-created"] // "N/A")"' <<< "$custom_images_json" 2>/dev/null)
    
    echo ""
    echo -n -e "${CYAN}Select image #: ${NC}"
    read -r img_choice
    
    local selected_entry="${EXPORT_IMAGE_MAP[$img_choice]}"
    if [[ -z "$selected_entry" ]]; then
        echo -e "${RED}Invalid image selection${NC}"
        _ui_pause
        return
    fi
    
    local selected_image selected_image_name
    IFS='|' read -r selected_image selected_image_name <<< "$selected_entry"
    
    # List buckets
    echo ""
    _step_init
    _step_active "buckets"
    local buckets_json
    buckets_json=$(oci os bucket list --compartment-id "$compartment_id" --namespace-name "$namespace" --region "$region" --output json 2>/dev/null)
    _step_complete "buckets"
    _step_finish
    
    if [[ -z "$buckets_json" ]] || ! jq -e '.data[0]' <<< "$buckets_json" > /dev/null 2>&1; then
        echo -e "${RED}No buckets found${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    _ui_subheader "Select Destination Bucket" 0
    declare -A BUCKET_MAP
    idx=0
    
    while read -r bucket_name; do
        [[ -z "$bucket_name" ]] && continue
        ((idx++))
        BUCKET_MAP[$idx]="$bucket_name"
        echo -e "  ${YELLOW}${idx}${NC}) $bucket_name"
    done < <(jq -r '.data[].name' <<< "$buckets_json" 2>/dev/null)
    
    echo ""
    echo -n -e "${CYAN}Select bucket #: ${NC}"
    read -r bucket_choice
    
    local selected_bucket="${BUCKET_MAP[$bucket_choice]}"
    if [[ -z "$selected_bucket" ]]; then
        echo -e "${RED}Invalid bucket selection${NC}"
        _ui_pause
        return
    fi
    
    # Get object name
    echo ""
    local default_name="${selected_image_name// /-}-$(date +%Y%m%d).oci"
    echo -n -e "${CYAN}Enter object name [${default_name}]: ${NC}"
    read -r object_name
    [[ -z "$object_name" ]] && object_name="$default_name"
    
    # Select export format
    echo ""
    _ui_subheader "Export Format" 0
    echo -e "  ${YELLOW}1${NC}) OCI (Oracle Cloud Image format)"
    echo -e "  ${YELLOW}2${NC}) QCOW2"
    echo -e "  ${YELLOW}3${NC}) VMDK"
    echo ""
    echo -n -e "${CYAN}Select format [1]: ${NC}"
    read -r format_choice
    
    local export_format="OCI"
    case "$format_choice" in
        2) export_format="QCOW2"; [[ ! "$object_name" =~ \.qcow2$ ]] && object_name="${object_name%.oci}.qcow2" ;;
        3) export_format="VMDK"; [[ ! "$object_name" =~ \.vmdk$ ]] && object_name="${object_name%.oci}.vmdk" ;;
        *) export_format="OCI" ;;
    esac
    
    # Build the command string for display/logging
    local cmd="oci compute image export to-object"
    cmd+=" --image-id \"$selected_image\""
    cmd+=" --namespace \"$namespace\""
    cmd+=" --bucket-name \"$selected_bucket\""
    cmd+=" --name \"$object_name\""
    cmd+=" --export-format \"$export_format\""
    cmd+=" --region \"$region\""
    
    echo ""
    _ui_subheader "Confirm Export" 0
    echo ""
    echo -e "${CYAN}Image:${NC}       $selected_image_name"
    echo -e "${CYAN}Bucket:${NC}      $selected_bucket"
    echo -e "${CYAN}Object Name:${NC} $object_name"
    echo -e "${CYAN}Format:${NC}      $export_format"
    echo ""
    _ui_subheader "Command to Execute" 0
    echo -e "${GRAY}$cmd${NC}"
    echo ""
    echo -n -e "${YELLOW}Proceed with export? (y/N): ${NC}"
    read -r confirm
    
    if [[ "$confirm" != "y" && "$confirm" != "Y" ]]; then
        echo -e "${YELLOW}Export cancelled${NC}"
        _ui_pause
        return
    fi
    
    # Execute export — use direct invocation (not _safe_exec) to preserve spaces in names
    echo ""
    echo -e "${GRAY}Exporting image (this may take several minutes)...${NC}"
    echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"

    local -a _export_args=(
        oci compute image export to-object
        --image-id "$selected_image"
        --namespace "$namespace"
        --bucket-name "$selected_bucket"
        --name "$object_name"
        --export-format "$export_format"
        --region "$region"
    )

    local result
    result=$(OCI_CLI_INTERACTIVE=0 "${_export_args[@]}" 2>&1)

    if jq -e '.data' <<< "$result" > /dev/null 2>&1; then
        echo -e "${GREEN}✓ Image export initiated successfully${NC}"
        echo -e "  ${CYAN}Destination:${NC} ${WHITE}$selected_bucket/$object_name${NC}"
        echo -e "  ${GRAY}Export will complete in background${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Exported $selected_image_name to $selected_bucket/$object_name" >> "$log_file"
    else
        echo -e "${RED}Failed to export image${NC}"
        echo "$result"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $result" >> "$log_file"
    fi
    
    echo ""
    _ui_pause
}

#--------------------------------------------------------------------------------
# Custom Images - Shape Compatibility (View / Add / Remove)
# Shows all shapes with ✓/✗ marks, numbered missing shapes for multi-select add,
# and multi-select remove. Loops until user exits.
#--------------------------------------------------------------------------------
custom_image_shape_compatibility() {
    local compartment_id="$1"
    local preselected_image_id="${2:-}"
    local preselected_image_name="${3:-}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/custom_images_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_subheader "Image Shape Compatibility" 0
    echo ""

    local selected_image="" selected_image_name=""

    if [[ -n "$preselected_image_id" ]]; then
        # Skip image list discovery — image passed directly (e.g. from 's 2')
        selected_image="$preselected_image_id"
        selected_image_name="$preselected_image_name"
    else
        # List custom images (cache-first) — discovery only when user must pick
        _step_init
        _step_active "custom images"
        local images_json _ci_sc_cached=""
        if is_cache_fresh "$CUSTOM_IMAGE_CACHE" 2>/dev/null && [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
            images_json=$(cat "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
            if [[ -n "$images_json" ]] && jq -e '.data[0]' <<< "$images_json" >/dev/null 2>&1; then
                _ci_sc_cached=" cached"
            else
                images_json=""
            fi
        fi
        if [[ -z "$_ci_sc_cached" ]]; then
            images_json=$(oci compute image list \
                --compartment-id "$compartment_id" \
                --region "$region" \
                --lifecycle-state AVAILABLE \
                --sort-by TIMECREATED \
                --sort-order DESC \
                --all \
                --output json 2>/dev/null)
        fi
        _step_complete "custom images${_ci_sc_cached}"
        _step_finish

        local custom_images_json
        if [[ -n "$_ci_sc_cached" ]]; then
            custom_images_json="$images_json"
        elif [[ -n "$images_json" ]] && jq -e '.data' <<< "$images_json" > /dev/null 2>&1; then
            custom_images_json=$(jq --arg comp_id "$compartment_id" '{data: [.data[] | select(.["compartment-id"] == $comp_id)]}' <<< "$images_json")
        else
            custom_images_json='{"data":[]}'
        fi

        local img_count=0
        img_count=$(jq '.data | length' <<< "$custom_images_json" 2>/dev/null || echo "0")

        if [[ "$img_count" -eq 0 ]]; then
            echo -e "${RED}No custom images found in this compartment${NC}"
            _ui_pause
            return
        fi

        echo ""
        _ui_subheader "Select Image" 0
        printf "  ${BOLD}%-4s %-105s %-18s %-12s${NC}\n" "#" "Image Name" "OS" "Created"
        print_separator 145

        declare -A SC_IMAGE_MAP=()
        declare -A SC_IMAGE_NAME_MAP=()
        local idx=0

        while IFS='|' read -r img_id img_name img_os img_created; do
            [[ -z "$img_id" ]] && continue
            ((idx++))
            SC_IMAGE_MAP[$idx]="$img_id"
            SC_IMAGE_NAME_MAP[$idx]="$img_name"
            local created_display="${img_created:0:10}"
            if [[ "$created_display" =~ ^([0-9]{4})-([0-9]{2})-([0-9]{2})$ ]]; then
                created_display="${BASH_REMATCH[2]}-${BASH_REMATCH[3]}-${BASH_REMATCH[1]}"
            fi
            printf "  ${YELLOW}%-4s${NC} %-105s %-18s %-12s\n" \
                "$idx" "$img_name" "$img_os" "$created_display"
        done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "Unnamed")|\(.["operating-system"] // "N/A")|\(.["time-created"] // "N/A")"' <<< "$custom_images_json" 2>/dev/null)

        echo ""
        echo -n -e "${CYAN}Select image #: ${NC}"
        local img_choice
        read -r img_choice

        selected_image="${SC_IMAGE_MAP[$img_choice]}"
        if [[ -z "$selected_image" ]]; then
            echo -e "${RED}Invalid image selection${NC}"
            _ui_pause
            return
        fi
        selected_image_name="${SC_IMAGE_NAME_MAP[$img_choice]}"
    fi
    
    # ── Main loop: show compat + missing, handle add/remove ──
    while true; do
        echo ""
        _ui_subheader "Shape Compatibility" 0
        echo -e "  ${CYAN}Image:${NC} ${WHITE}$selected_image_name${NC}"
        echo -e "  ${CYAN}OCID:${NC}  ${YELLOW}$selected_image${NC}"
        echo ""
        
        # Derive region from image OCID (may differ from focus region)
        local _img_region
        _img_region=$(_ocid_region "$selected_image" "$region")

        # Fetch compat list + available shapes (parallel)
        _step_init
        local _ci_co_tmp _ci_sh_tmp
        _ci_co_tmp=$(create_temp_file); _ci_sh_tmp=$(create_temp_file)

        _step_active "compat+shapes(2 parallel)"
        ( oci compute image-shape-compatibility-entry list --image-id "$selected_image" --region "$_img_region" --output json > "$_ci_co_tmp" 2>/dev/null ) &
        local _cip1=$!
        ( _get_shapes_json "${FOCUS_COMPARTMENT_ID:-$COMPARTMENT_ID}" > "$_ci_sh_tmp" ) &
        local _cip2=$!
        wait $_cip1 $_cip2 2>/dev/null

        local compat_json _avail_json
        compat_json=$(<"$_ci_co_tmp"); _avail_json=$(<"$_ci_sh_tmp")
        rm -f "$_ci_co_tmp" "$_ci_sh_tmp"
        _step_complete "shape compatibility"
        _step_complete "available shapes in region ${_img_region}"
        _step_finish
        
        # Build compat set
        declare -A _SC_COMPAT_SET=()
        local compat_count=0
        if [[ -n "$compat_json" ]] && jq -e '.data' <<< "$compat_json" > /dev/null 2>&1; then
            compat_count=$(jq '.data | length' <<< "$compat_json")
            while read -r _cs; do
                [[ -z "$_cs" ]] && continue
                _SC_COMPAT_SET["$_cs"]=1
            done < <(jq -r '.data[].shape' <<< "$compat_json" 2>/dev/null)
        fi
        
        # Full categorized display with ✓/✗
        local _midx=0
        declare -A _MISS_MAP=()
        
        if [[ -n "$_avail_json" ]] && jq -e '.data[0]' <<< "$_avail_json" >/dev/null 2>&1; then
            local _avail_total
            _avail_total=$(jq '[.data[].shape] | unique | length' <<< "$_avail_json" 2>/dev/null)
            local _miss_total=$((_avail_total - compat_count))
            [[ $_miss_total -lt 0 ]] && _miss_total=0
            
            echo -e "  ${WHITE}${compat_count} compatible${NC} ${GRAY}of ${_avail_total} available shapes${NC}${_miss_total:+ (${RED}${_miss_total} missing${NC})}"
            echo ""
            
            local -a _sc_vm=() _sc_vm_old=() _sc_bm=() _sc_bm_old=() _sc_bm_gpu=() _sc_vm_gpu=()
            local _sc_dtotal=0
            
            _shapes_categorize "$_avail_json" "_SC_COMPAT_SET" \
                _sc_vm _sc_vm_old _sc_bm _sc_bm_old _sc_bm_gpu _sc_vm_gpu \
                _sc_dtotal
            
            _shapes_render_compat display \
                _sc_vm _sc_vm_old _sc_bm _sc_bm_old _sc_bm_gpu _sc_vm_gpu \
                "$_sc_dtotal"
            
            # Build missing shapes for numbered selection
            local -a _miss_vm=() _miss_bh=() _miss_vg=() _miss_bg=()
            local -a _raw_vm=() _raw_bh=() _raw_vg=() _raw_bg=()
            
            while read -r _as; do
                [[ -z "$_as" ]] && continue
                [[ -n "${_SC_COMPAT_SET[$_as]+x}" ]] && continue
                case $(_shape_category "$_as") in
                    vm)      _raw_vm+=("$_as") ;;
                    bm_hpc)  _raw_bh+=("$_as") ;;
                    vm_gpu)  _raw_vg+=("$_as") ;;
                    bm_gpu)  _raw_bg+=("$_as") ;;
                esac
            done < <(jq -r '[.data[].shape] | unique | sort[]' <<< "$_avail_json" 2>/dev/null)
            
            local _s
            for _s in "${_raw_vm[@]}"; do ((_midx++)); _MISS_MAP[$_midx]="$_s"; _miss_vm+=("${_midx}|${_s}"); done
            for _s in "${_raw_bh[@]}"; do ((_midx++)); _MISS_MAP[$_midx]="$_s"; _miss_bh+=("${_midx}|${_s}"); done
            for _s in "${_raw_vg[@]}"; do ((_midx++)); _MISS_MAP[$_midx]="$_s"; _miss_vg+=("${_midx}|${_s}"); done
            for _s in "${_raw_bg[@]}"; do ((_midx++)); _MISS_MAP[$_midx]="$_s"; _miss_bg+=("${_midx}|${_s}"); done
            
            echo ""
            if [[ $_midx -gt 0 ]]; then
                _ui_subheader "Missing Shapes (${_midx} not yet compatible)" 0
                echo ""
                _ui_4col_render numbered _miss_vm _miss_bh _miss_vg _miss_bg
            else
                echo -e "  ${GREEN}✓ All available shapes are already compatible${NC}"
            fi
        else
            echo -e "  ${WHITE}${compat_count} compatible shape(s)${NC}"
            echo -e "  ${GRAY}Could not fetch available shapes to show missing${NC}"
        fi
        
        # ── Actions ──
        echo ""
        _ui_actions
        if [[ $_midx -gt 0 ]]; then
            echo -e "  ${CYAN}#${NC})    Add missing shape(s) (${YELLOW}1${NC}, ${YELLOW}1,3,5${NC}, ${YELLOW}1-5${NC}, ${YELLOW}all${NC})"
            echo -e "  ${GRAY}c${NC})    Custom (add shape by name)"
        fi
        if [[ $compat_count -gt 0 ]]; then
            echo -e "  ${RED}rm${NC})   Remove shape compatibility"
        fi
        echo -e "  ${MAGENTA}r${NC})    Refresh"
        echo -e "  ${CYAN}b${NC})    Back"
        echo ""
        _ui_prompt "Shape Compat - ${selected_image_name}" "#, c, rm, r, b"
        local _sc_action
        read -r _sc_action
        [[ "${_sc_action:-}" == :* ]] && _nav_try_jump "$_sc_action" && return
        
        case "$_sc_action" in
            b|B|"")
                return
                ;;
            r|R)
                continue
                ;;
            c|C)
                # Custom shape add by name
                echo ""
                echo -e "  ${GRAY}Enter the exact shape name (e.g., BM.GPU.H100.8, VM.GPU.A10.1)${NC}"
                echo -n -e "  ${CYAN}Custom shape name: ${NC}"
                local _cust_shape
                read -r _cust_shape
                if [[ -n "$_cust_shape" ]]; then
                    if [[ -n "${_SC_COMPAT_SET[$_cust_shape]+x}" ]]; then
                        echo -e "  ${YELLOW}Shape '${_cust_shape}' is already compatible${NC}"
                        _ui_pause
                        continue
                    fi
                    echo ""
                    local _add_cmd="oci compute image-shape-compatibility-entry add --image-id \"$selected_image\" --shape-name \"$_cust_shape\" --region \"$region\""
                    echo -e "  ${WHITE}$ $_add_cmd${NC}"
                    echo ""
                    echo -n -e "  ${YELLOW}Confirm? (y/N): ${NC}"
                    local _confirm
                    read -r _confirm
                    if [[ "$_confirm" == "y" || "$_confirm" == "Y" ]]; then
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $_add_cmd" >> "$log_file"
                        local _result
                        _result=$(oci compute image-shape-compatibility-entry add --image-id "$selected_image" --shape-name "$_cust_shape" --region "$region" --output json 2>&1)
                        if echo "$_result" | jq -e '.data' >/dev/null 2>&1 || [[ -z "$_result" ]]; then
                            echo -e "  ${GREEN}✓ Added: $_cust_shape${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Added shape compat $_cust_shape to $selected_image_name" >> "$log_file"
                        else
                            echo -e "  ${RED}✗ Failed: $_cust_shape${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $_cust_shape — $_result" >> "$log_file"
                        fi
                    else
                        echo -e "  ${YELLOW}Cancelled${NC}"
                    fi
                fi
                ;;
            rm|RM)
                # Remove shape compatibility — multi-select
                if [[ $compat_count -eq 0 ]]; then
                    echo -e "  ${GRAY}No shapes to remove${NC}"
                    _ui_pause
                    continue
                fi
                echo ""
                _ui_subheader "Remove Shape Compatibility" 0
                echo ""
                
                # Build numbered compat list by category
                declare -A _RM_MAP=()
                local -a _rm_vm=() _rm_bh=() _rm_vg=() _rm_bg=()
                local -a _rmr_vm=() _rmr_bh=() _rmr_vg=() _rmr_bg=()
                
                while read -r _rs; do
                    [[ -z "$_rs" ]] && continue
                    case $(_shape_category "$_rs") in
                        vm)      _rmr_vm+=("$_rs") ;;
                        bm_hpc)  _rmr_bh+=("$_rs") ;;
                        vm_gpu)  _rmr_vg+=("$_rs") ;;
                        bm_gpu)  _rmr_bg+=("$_rs") ;;
                    esac
                done < <(jq -r '.data[].shape' <<< "$compat_json" 2>/dev/null | sort)
                
                local _rmidx=0
                for _s in "${_rmr_vm[@]}"; do ((_rmidx++)); _RM_MAP[$_rmidx]="$_s"; _rm_vm+=("${_rmidx}|${_s}"); done
                for _s in "${_rmr_bh[@]}"; do ((_rmidx++)); _RM_MAP[$_rmidx]="$_s"; _rm_bh+=("${_rmidx}|${_s}"); done
                for _s in "${_rmr_vg[@]}"; do ((_rmidx++)); _RM_MAP[$_rmidx]="$_s"; _rm_vg+=("${_rmidx}|${_s}"); done
                for _s in "${_rmr_bg[@]}"; do ((_rmidx++)); _RM_MAP[$_rmidx]="$_s"; _rm_bg+=("${_rmidx}|${_s}"); done
                
                _ui_4col_render numbered _rm_vm _rm_bh _rm_vg _rm_bg
                
                echo ""
                echo -e "  ${GRAY}Enter shape #(s): single (1), comma (1,5), range (1-5), or 'all'${NC}"
                echo -n -e "  ${RED}Remove shape(s): ${NC}"
                local _rm_input
                read -r _rm_input
                
                if [[ -z "$_rm_input" ]]; then
                    continue
                fi
                
                local -a _shapes_to_rm=()
                if _parse_targets "" "$_rm_input" "$_rmidx"; then
                    for _si in "${_SEL_INDICES[@]}"; do
                        [[ -n "${_RM_MAP[$_si]}" ]] && _shapes_to_rm+=("${_RM_MAP[$_si]}")
                    done
                fi
                
                if [[ ${#_shapes_to_rm[@]} -eq 0 ]]; then
                    echo -e "  ${RED}No valid shapes selected${NC}"
                    _ui_pause
                    continue
                fi
                
                echo ""
                echo -e "  ${BOLD}${WHITE}Removing ${#_shapes_to_rm[@]} shape(s):${NC}"
                for _sr in "${_shapes_to_rm[@]}"; do
                    echo -e "    ${WHITE}• $_sr${NC}"
                done
                echo ""
                echo -e "  ${BOLD}Commands to Execute:${NC}"
                for _sr in "${_shapes_to_rm[@]}"; do
                    echo -e "  ${WHITE}$ oci compute image-shape-compatibility-entry remove --image-id \"$selected_image\" --shape-name \"$_sr\" --region \"$region\" --force${NC}"
                done
                echo ""
                echo -n -e "  ${RED}Confirm removal? (y/N): ${NC}"
                local _rm_confirm
                read -r _rm_confirm
                
                if [[ "$_rm_confirm" == "y" || "$_rm_confirm" == "Y" ]]; then
                    local _rm_ok=0 _rm_fail=0
                    for _sr in "${_shapes_to_rm[@]}"; do
                        local _rm_cmd="oci compute image-shape-compatibility-entry remove --image-id \"$selected_image\" --shape-name \"$_sr\" --region \"$region\" --force"
                        echo -e "  ${WHITE}$ $_rm_cmd${NC}"
                        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $_rm_cmd" >> "$log_file"
                        oci compute image-shape-compatibility-entry remove --image-id "$selected_image" --shape-name "$_sr" --region "$region" --force 2>/dev/null
                        if [[ $? -eq 0 ]]; then
                            echo -e "  ${GREEN}✓ Removed: $_sr${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Removed shape compat $_sr from $selected_image_name" >> "$log_file"
                            ((_rm_ok++))
                        else
                            echo -e "  ${RED}✗ Failed: $_sr${NC}"
                            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Remove $_sr" >> "$log_file"
                            ((_rm_fail++))
                        fi
                    done
                    echo ""
                    echo -e "  ${GREEN}${_rm_ok} removed${NC}${_rm_fail:+, ${RED}${_rm_fail} failed${NC}}"
                else
                    echo -e "  ${YELLOW}Cancelled${NC}"
                fi
                ;;
            show|SHOW)
                continue
                ;;
            *)
                # Try as shape number(s) to add missing shapes
                if [[ $_midx -gt 0 ]] && _parse_targets "" "$_sc_action" "$_midx"; then
                    local -a _shapes_to_add=()
                    for _si in "${_SEL_INDICES[@]}"; do
                        [[ -n "${_MISS_MAP[$_si]}" ]] && _shapes_to_add+=("${_MISS_MAP[$_si]}")
                    done
                    
                    if [[ ${#_shapes_to_add[@]} -gt 0 ]]; then
                        echo ""
                        echo -e "  ${BOLD}${WHITE}Adding ${#_shapes_to_add[@]} shape(s):${NC}"
                        for _sa in "${_shapes_to_add[@]}"; do
                            echo -e "    ${WHITE}• $_sa${NC}"
                        done
                        echo ""
                        echo -e "  ${BOLD}Commands to Execute:${NC}"
                        for _sa in "${_shapes_to_add[@]}"; do
                            echo -e "  ${WHITE}$ oci compute image-shape-compatibility-entry add --image-id \"$selected_image\" --shape-name \"$_sa\" --region \"$region\"${NC}"
                        done
                        echo ""
                        echo -n -e "  ${YELLOW}Confirm? (y/N): ${NC}"
                        local _add_confirm
                        read -r _add_confirm
                        
                        if [[ "$_add_confirm" == "y" || "$_add_confirm" == "Y" ]]; then
                            local _add_ok=0 _add_fail=0
                            for _sa in "${_shapes_to_add[@]}"; do
                                local _add_cmd="oci compute image-shape-compatibility-entry add --image-id \"$selected_image\" --shape-name \"$_sa\" --region \"$region\""
                                echo -e "  ${WHITE}$ $_add_cmd${NC}"
                                echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $_add_cmd" >> "$log_file"
                                local _add_result
                                _add_result=$(oci compute image-shape-compatibility-entry add --image-id "$selected_image" --shape-name "$_sa" --region "$region" --output json 2>&1)
                                if echo "$_add_result" | jq -e '.data' >/dev/null 2>&1 || [[ -z "$_add_result" ]]; then
                                    echo -e "  ${GREEN}✓ Added: $_sa${NC}"
                                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Added shape compat $_sa to $selected_image_name" >> "$log_file"
                                    ((_add_ok++))
                                else
                                    echo -e "  ${RED}✗ Failed: $_sa${NC}"
                                    echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: $_sa — $_add_result" >> "$log_file"
                                    ((_add_fail++))
                                fi
                            done
                            echo ""
                            echo -e "  ${GREEN}${_add_ok} added${NC}${_add_fail:+, ${RED}${_add_fail} failed${NC}}"
                        else
                            echo -e "  ${YELLOW}Cancelled${NC}"
                        fi
                    else
                        echo -e "  ${RED}No valid shapes selected${NC}"
                    fi
                else
                    echo -e "${RED}Invalid selection${NC}"
                    sleep 1
                fi
                ;;
        esac
    done
}

#--------------------------------------------------------------------------------
# Custom Images - Delete
#--------------------------------------------------------------------------------
custom_image_delete() {
    local compartment_id="$1"
    local delete_args="${2:-}"
    local parent_idx="${3:-0}"
    local region="${FOCUS_REGION:-$REGION}"
    local log_file="${LOGS_DIR}/custom_images_actions.log"
    mkdir -p "$(dirname "$log_file")" 2>/dev/null
    
    echo ""
    _ui_subheader "Delete Custom Image" 0
    echo ""
    
    # List images (all states - user may want to delete IMPORTING/DISABLED images too)
    _step_init
    _step_active "custom images"
    local images_json _ci_del_cached=""
    if is_cache_fresh "$CUSTOM_IMAGE_CACHE" 2>/dev/null && [[ -s "$CUSTOM_IMAGE_CACHE" ]]; then
        images_json=$(cat "$CUSTOM_IMAGE_CACHE" 2>/dev/null)
        if [[ -n "$images_json" ]] && jq -e '.data[0]' <<< "$images_json" >/dev/null 2>&1; then
            _ci_del_cached=" cached"
        else
            images_json=""
        fi
    fi
    if [[ -z "$_ci_del_cached" ]]; then
        images_json=$(oci compute image list \
            --compartment-id "$compartment_id" \
            --region "$region" \
            --sort-by TIMECREATED \
            --sort-order DESC \
            --all \
            --output json 2>/dev/null)
    fi
    _step_complete "custom images${_ci_del_cached}"
    _step_finish
    
    # Filter to only show custom images (images where compartment-id matches user's compartment)
    local custom_images_json
    if [[ -n "$_ci_del_cached" ]]; then
        custom_images_json="$images_json"
    elif [[ -n "$images_json" ]] && jq -e '.data' <<< "$images_json" > /dev/null 2>&1; then
        custom_images_json=$(jq --arg comp_id "$compartment_id" '{data: [.data[] | select(.["compartment-id"] == $comp_id)]}' <<< "$images_json")
    else
        custom_images_json='{"data":[]}'
    fi
    
    if [[ -z "$custom_images_json" ]] || ! jq -e '.data[0]' <<< "$custom_images_json" > /dev/null 2>&1; then
        echo -e "${RED}No custom images found${NC}"
        _ui_pause
        return
    fi
    
    echo ""
    _ui_subheader "Custom Images" 0
    printf "  ${BOLD}%-4s %-105s %-20s %-14s${NC}\n" "#" "Image Name" "OS" "Status"
    print_separator 150
    
    declare -A _DEL_IMG_MAP=()
    declare -A _DEL_NAME_MAP=()
    local idx=0
    
    while IFS='|' read -r img_id img_name img_os img_state; do
        [[ -z "$img_id" ]] && continue
        ((idx++))
        _DEL_IMG_MAP[$idx]="$img_id"
        _DEL_NAME_MAP[$idx]="$img_name"
        
        # Color-code status
        local state_color; state_color=$(color_resource_state "$img_state")
        
        printf "  ${YELLOW}%-4s${NC} %-105s %-20s ${state_color}%-14s${NC}\n" "$idx)" "$img_name" "$img_os" "$img_state"
    done < <(jq -r '.data[] | "\(.id)|\(.["display-name"] // "Unnamed")|\(.["operating-system"] // "N/A")|\(.["lifecycle-state"] // "UNKNOWN")"' <<< "$custom_images_json" 2>/dev/null)
    
    echo ""
    
    # If no args provided, prompt interactively
    if [[ -z "$delete_args" ]]; then
        echo -e "${WHITE}Usage: Enter one of the following:${NC}"
        echo -e "  ${YELLOW}#${NC}            - Delete a single image (e.g., ${YELLOW}1${NC})"
        echo -e "  ${YELLOW}#,#,#${NC}        - Delete multiple images (e.g., ${YELLOW}1,3,5${NC})"
        echo -e "  ${YELLOW}#-#${NC}          - Delete a range of images (e.g., ${YELLOW}1-3${NC})"
        echo -e "  ${RED}all${NC}          - Delete ALL custom images"
        echo -e "  ${CYAN}cancel${NC}       - Cancel"
        echo ""
        echo -n -e "${CYAN}Select image(s) to delete: ${NC}"
        read -r delete_args
    fi
    
    # Check for cancel
    if [[ -z "$delete_args" || "$delete_args" == "cancel" ]]; then
        echo -e "${YELLOW}Delete cancelled${NC}"
        return 0
    fi
    
    # Parse selection using _parse_targets with empty prefix (bare numbers)
    if ! _parse_targets "" "$delete_args" "$idx"; then
        echo -e "${RED}No valid images selected for deletion${NC}"
        _ui_pause
        return 1
    fi
    
    # Build delete lists
    declare -a DEL_OCIDS=() DEL_NAMES=() DEL_IDS=()
    for _k in "${_SEL_KEYS[@]}"; do
        local _ocid="${_DEL_IMG_MAP[$_k]:-}"
        [[ -z "$_ocid" ]] && continue
        DEL_IDS+=("$_k")
        DEL_OCIDS+=("$_ocid")
        DEL_NAMES+=("${_DEL_NAME_MAP[$_k]}")
    done
    
    if [[ ${#DEL_OCIDS[@]} -eq 0 ]]; then
        echo -e "${RED}No valid images selected for deletion${NC}"
        _ui_pause
        return 1
    fi
    
    # Show what will be deleted
    echo ""
    echo -e "${RED}╔════════════════════════════════════════════════════════════════════════════════╗${NC}"
    echo -e "${RED}║                    ⚠️  WARNING: DELETE CUSTOM IMAGE(S)  ⚠️                       ║${NC}"
    echo -e "${RED}╚════════════════════════════════════════════════════════════════════════════════╝${NC}"
    echo ""
    echo -e "${WHITE}The following ${RED}${#DEL_OCIDS[@]}${WHITE} image(s) will be deleted:${NC}"
    echo ""
    
    for i in "${!DEL_OCIDS[@]}"; do
        printf "  ${YELLOW}%-4s${NC} ${WHITE}%-80s${NC} ${GRAY}%s${NC}\n" \
            "${DEL_IDS[$i]})" "${DEL_NAMES[$i]}" "${DEL_OCIDS[$i]}"
    done
    
    echo ""
    echo -e "${RED}This action cannot be undone!${NC}"
    echo ""
    
    # Show exact commands that will be executed
    echo -e "${BOLD}Commands to Execute:${NC}"
    for i in "${!DEL_OCIDS[@]}"; do
        echo -e "  ${WHITE}$ oci compute image delete --image-id \"${DEL_OCIDS[$i]}\" --region \"${region}\" --force${NC}"
    done
    echo ""
    
    # Confirmation
    if [[ ${#DEL_OCIDS[@]} -gt 1 ]]; then
        if ! _ui_confirm "DELETE ${#DEL_OCIDS[@]}" "confirm deletion of ${#DEL_OCIDS[@]} images"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    else
        if ! _ui_confirm "DELETE" "confirm deletion"; then
            echo -e "${YELLOW}Delete cancelled${NC}"
            _ui_pause
            return 0
        fi
    fi
    
    # Execute deletions
    echo ""
    local success_count=0 fail_count=0
    
    for i in "${!DEL_OCIDS[@]}"; do
        local img_ocid="${DEL_OCIDS[$i]}"
        local img_name="${DEL_NAMES[$i]}"
        local img_idx="${DEL_IDS[$i]}"
        
        local cmd="oci compute image delete --image-id ${img_ocid} --region ${region} --force"
        
        echo -e "${WHITE}$ ${cmd}${NC}"
        echo "[$(date '+%Y-%m-%d %H:%M:%S')] EXECUTE: $cmd" >> "$log_file"
        
        local result
        result=$(_safe_exec "$cmd")
        local exit_code=$?
        
        if [[ $exit_code -eq 0 || -z "$result" || "$result" == "{}" ]]; then
            echo -e "${GREEN}✓ Deleted: ${WHITE}${img_name}${NC} ${GRAY}(${img_idx})${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] SUCCESS: Deleted image '${img_name}' (${img_ocid})" >> "$log_file"
            ((success_count++))
        else
            echo -e "${RED}✗ Failed: ${WHITE}${img_name}${NC} ${GRAY}(${img_idx})${NC}"
            echo -e "  ${RED}${result}${NC}"
            echo "[$(date '+%Y-%m-%d %H:%M:%S')] FAILED: Delete image '${img_name}' (${img_ocid}): ${result}" >> "$log_file"
            ((fail_count++))
        fi
        echo ""
    done
    
    # Summary
    _ui_subheader "Delete Summary" 0
    echo -e "  ${GREEN}Succeeded:${NC} ${success_count}"
    [[ $fail_count -gt 0 ]] && echo -e "  ${RED}Failed:${NC}    ${fail_count}"
    echo -e "  ${GRAY}Log file:  ${log_file}${NC}"
    echo ""
    
    _ui_pause
}

