#===============================================================================
# MAIN
#===============================================================================

#===============================================================================
# INITIAL SETUP FUNCTIONS
#===============================================================================

# IMDS v2 endpoint
readonly IMDS_BASE="http://169.254.169.254/opc/v2"
readonly IMDS_HEADER="Authorization: Bearer Oracle"

#--------------------------------------------------------------------------------
# Check if running on OCI instance with IMDS available
#--------------------------------------------------------------------------------
is_oci_instance() {
    curl -sS -H "$IMDS_HEADER" "${IMDS_BASE}/instance/" -o /dev/null 2>/dev/null
}

#--------------------------------------------------------------------------------
# Wait for IMDS to be available
#--------------------------------------------------------------------------------
wait_for_imds() {
    local timeout=60
    local elapsed=0
    
    while true; do
        if curl -sS -H "$IMDS_HEADER" "${IMDS_BASE}/instance/" -o /dev/null 2>/dev/null; then
            return 0
        fi
        sleep 2
        elapsed=$((elapsed + 2))
        if [[ $elapsed -ge $timeout ]]; then
            return 1
        fi
    done
}

#--------------------------------------------------------------------------------
# Fetch instance metadata from IMDS
#--------------------------------------------------------------------------------
fetch_imds_metadata() {
    local instance_json
    instance_json=$(curl -sH "$IMDS_HEADER" --max-redirs 0 "${IMDS_BASE}/instance/" 2>/dev/null)
    
    if [[ -z "$instance_json" ]]; then
        return 1
    fi
    
    # Extract values
    SETUP_TENANCY_ID=$(jq -r '.tenantId // empty' <<< "$instance_json")
    SETUP_COMPARTMENT_ID=$(jq -r '.compartmentId // empty' <<< "$instance_json")
    SETUP_REGION=$(jq -r '.canonicalRegionName // empty' <<< "$instance_json")
    SETUP_AD=$(jq -r '.availabilityDomain // empty' <<< "$instance_json")
    
    if [[ -z "$SETUP_TENANCY_ID" || -z "$SETUP_COMPARTMENT_ID" || -z "$SETUP_REGION" ]]; then
        return 1
    fi
    
    return 0
}

#--------------------------------------------------------------------------------
# Check OCI CLI with instance principal auth
#--------------------------------------------------------------------------------
check_oci_instance_principal() {
    if ! command -v oci &>/dev/null; then
        return 1
    fi
    
    if ! oci iam region list --auth instance_principal &>/dev/null; then
        return 1
    fi
    
    return 0
}

#--------------------------------------------------------------------------------
# Select from list helper for initial setup
#--------------------------------------------------------------------------------
setup_select_from_list() {
    local prompt="$1"
    local -n items_ref=$2
    local -n result_ref=$3
    local allow_skip="${4:-false}"
    
    if [[ ${#items_ref[@]} -eq 0 ]]; then
        echo -e "${YELLOW}No items available${NC}"
        result_ref=""
        return 1
    fi
    
    declare -A local_map
    local idx=1
    for item in "${items_ref[@]}"; do
        local name=$(echo "$item" | cut -d'|' -f1)
        local id=$(echo "$item" | cut -d'|' -f2)
        local extra=$(echo "$item" | cut -d'|' -f3-)
        
        if [[ -n "$extra" ]]; then
            printf "${YELLOW}%3d${NC}) ${CYAN}%-50s${NC} ${GRAY}%s${NC}\n" "$idx" "$name" "$extra"
        else
            printf "${YELLOW}%3d${NC}) ${CYAN}%-50s${NC}\n" "$idx" "$name"
        fi
        
        local_map[$idx]="$id"
        ((idx++))
    done
    
    if [[ "$allow_skip" == "true" ]]; then
        echo -e "${GRAY}  0) Skip / Enter manually later${NC}"
    fi
    
    echo ""
    while true; do
        echo -n -e "${WHITE}$prompt ${NC}"
        read -r selection
        
        if [[ "$allow_skip" == "true" && "$selection" == "0" ]]; then
            result_ref=""
            return 0
        fi
        
        if [[ "$selection" =~ ^[0-9]+$ ]] && [[ -n "${local_map[$selection]:-}" ]]; then
            result_ref="${local_map[$selection]}"
            return 0
        fi
        
        echo -e "${RED}Invalid selection. Please try again.${NC}"
    done
}

#--------------------------------------------------------------------------------
# Run initial setup to create variables.sh
#--------------------------------------------------------------------------------
run_initial_setup() {
    _ui_menu_header "INITIAL SETUP - CREATING VARIABLES.SH" --color "$BLUE"
    
    # ── Discovery: Cloud Shell or IMDS + OCI CLI ──
    _step_init
    local setup_tenancy_name=""
    local setup_compartment_name=""

    # ── Check for OCI Cloud Shell ──
    if [[ -n "${OCI_CS_TERMINAL_OCID:-}" ]]; then
        _step_active "Cloud Shell"
        SETUP_TENANCY_ID="${OCI_TENANCY:-}"
        SETUP_COMPARTMENT_ID="${OCI_TENANCY:-}"   # root compartment = tenancy OCID
        SETUP_REGION="${OCI_REGION:-}"
        SETUP_AD=""

        if [[ -z "$SETUP_TENANCY_ID" || -z "$SETUP_REGION" ]]; then
            _step_complete "Cloud Shell(missing env vars)"
            _step_finish
            echo -e "${RED}ERROR: OCI Cloud Shell detected but OCI_TENANCY/OCI_REGION not set${NC}"
            return 1
        fi
        _step_complete "Cloud Shell"

        # Resolve names using default Cloud Shell auth (no --auth flag needed)
        _step_active "names"
        setup_tenancy_name=$(oci iam tenancy get --tenancy-id "$SETUP_TENANCY_ID" \
            --query 'data.name' --raw-output 2>/dev/null)
        [[ "$setup_tenancy_name" == "null" ]] && setup_tenancy_name=""
        _step_complete "names"
        _step_finish

        # Display detected environment
        echo ""
        echo -e "${WHITE}OCI Cloud Shell detected:${NC}"
        if [[ -n "$setup_tenancy_name" ]]; then
            echo -e "  Tenancy:     ${CYAN}${setup_tenancy_name}${NC} ${GRAY}[${SETUP_TENANCY_ID}]${NC}"
        else
            echo -e "  Tenancy:     ${CYAN}${SETUP_TENANCY_ID}${NC}"
        fi
        echo -e "  Compartment: ${CYAN}${SETUP_COMPARTMENT_ID}${NC} ${GRAY}(root)${NC}"
        echo -e "  Region:      ${CYAN}$SETUP_REGION${NC}"
    else
        # ── IMDS-based discovery (OCI compute instance) ──
        # Check if on OCI instance
        _step_active "IMDS"
        if ! is_oci_instance; then
            _step_complete "IMDS(unavailable)"
            _step_finish
            echo -e "${RED}ERROR: Not running on an OCI instance or IMDS not available${NC}"
            echo -e "${YELLOW}Please create variables.sh manually with:${NC}"
            echo -e "  REGION=\"your-region\""
            echo -e "  TENANCY_ID=\"ocid1.tenancy...\""
            echo -e "  COMPARTMENT_ID=\"ocid1.compartment...\""
            return 1
        fi

        if ! wait_for_imds; then
            _step_complete "IMDS(timeout)"
            _step_finish
            echo -e "${RED}ERROR: Timeout waiting for IMDS${NC}"
            return 1
        fi
        _step_complete "IMDS"

        _step_active "metadata"
        if ! fetch_imds_metadata; then
            _step_complete "metadata(failed)"
            _step_finish
            echo -e "${RED}ERROR: Failed to fetch instance metadata${NC}"
            return 1
        fi
        _step_complete "metadata"

        _step_active "OCI CLI"
        if ! check_oci_instance_principal; then
            _step_complete "OCI CLI(failed)"
            _step_finish
            echo -e "${RED}ERROR: OCI CLI or instance principal auth not available${NC}"
            return 1
        fi
        _step_complete "OCI CLI"

        _step_active "names"

        # Resolve tenancy name
        setup_tenancy_name=$(oci iam tenancy get --tenancy-id "$SETUP_TENANCY_ID" \
            --auth instance_principal --query 'data.name' --raw-output 2>/dev/null)
        [[ "$setup_tenancy_name" == "null" ]] && setup_tenancy_name=""

        # Resolve compartment name
        setup_compartment_name=$(oci iam compartment get --compartment-id "$SETUP_COMPARTMENT_ID" \
            --auth instance_principal --query 'data.name' --raw-output 2>/dev/null)
        [[ "$setup_compartment_name" == "null" ]] && setup_compartment_name=""
        _step_complete "names"
        _step_finish

        echo ""
        echo -e "${WHITE}Base environment detected:${NC}"
        if [[ -n "$setup_tenancy_name" ]]; then
            echo -e "  Tenancy:     ${CYAN}${setup_tenancy_name}${NC} ${GRAY}[${SETUP_TENANCY_ID}]${NC}"
        else
            echo -e "  Tenancy:     ${CYAN}${SETUP_TENANCY_ID}${NC}"
        fi
        if [[ -n "$setup_compartment_name" ]]; then
            echo -e "  Compartment: ${CYAN}${setup_compartment_name}${NC} ${GRAY}[${SETUP_COMPARTMENT_ID}]${NC}"
        else
            echo -e "  Compartment: ${CYAN}${SETUP_COMPARTMENT_ID}${NC}"
        fi
        echo -e "  Region: ${CYAN}$SETUP_REGION${NC}"
        echo -e "  AD:     ${CYAN}${SETUP_AD##*:}${NC}"
    fi
    
    # Auth flag: instance_principal for IMDS, empty for Cloud Shell (uses default delegation token)
    local _setup_auth=""
    [[ -z "${OCI_CS_TERMINAL_OCID:-}" ]] && _setup_auth="--auth instance_principal"

    # ── Select Region ──
    echo ""
    _ui_subheader "Region Selection" 0
    _step_init
    _step_active "regions"
    local regions_json
    regions_json=$(oci iam region-subscription list \
        --tenancy-id "$SETUP_TENANCY_ID" \
        ${_setup_auth} \
        --all --output json 2>/dev/null)
    local _rc
    _rc=$(jq '.data | length' <<< "$regions_json" 2>/dev/null || echo "0")
    _step_complete "regions(${_rc})"
    _step_finish
    
    if [[ -n "$regions_json" ]] && jq -e '.data[0]' <<< "$regions_json" >/dev/null 2>&1; then
        local ridx=0
        declare -A _SETUP_REGION_MAP=()
        while IFS='|' read -r rname rstatus rhome; do
            ((ridx++))
            _SETUP_REGION_MAP[$ridx]="$rname"
            local _rc="$GREEN" _home="" _current=""
            [[ "$rstatus" != "READY" ]] && _rc="$YELLOW"
            [[ "$rhome" == "true" ]] && _home=" ${CYAN}(home)${NC}"
            [[ "$rname" == "$SETUP_REGION" ]] && _current=" ${YELLOW}← detected${NC}"
            printf "  ${YELLOW}%2d${NC}) ${_rc}%-20s${NC}${_home}${_current}\n" "$ridx" "$rname"
        done < <(jq -r '.data[] | "\(.["region-name"])|\(.status)|\(.["is-home-region"])"' <<< "$regions_json" 2>/dev/null | sort)
        
        echo ""
        echo -n -e "${CYAN}Select region [Enter to keep ${WHITE}${SETUP_REGION}${CYAN}]: ${NC}"
        local r_choice
        read -r r_choice
        if [[ -n "$r_choice" && -n "${_SETUP_REGION_MAP[$r_choice]:-}" ]]; then
            SETUP_REGION="${_SETUP_REGION_MAP[$r_choice]}"
            echo -e "${GREEN}✓ Region: $SETUP_REGION${NC}"
        else
            echo -e "${GREEN}✓ Region: $SETUP_REGION (kept)${NC}"
        fi
    fi
    
    # ── Select AD ──
    echo ""
    _ui_subheader "Availability Domain" 0
    _step_init
    _step_active "availability domains"
    local ads_json
    ads_json=$(oci iam availability-domain list \
        --compartment-id "$SETUP_COMPARTMENT_ID" \
        ${_setup_auth} \
        --all --output json 2>/dev/null)
    local _adc
    _adc=$(jq '.data | length' <<< "$ads_json" 2>/dev/null || echo "0")
    _step_complete "availability domains(${_adc})"
    _step_finish
    
    if [[ -n "$ads_json" ]] && jq -e '.data[0]' <<< "$ads_json" >/dev/null 2>&1; then
        local aidx=0
        declare -A _SETUP_AD_MAP=()
        while IFS= read -r adname; do
            ((aidx++))
            _SETUP_AD_MAP[$aidx]="$adname"
            local _current=""
            [[ "$adname" == "$SETUP_AD" ]] && _current=" ${YELLOW}← detected${NC}"
            printf "  ${YELLOW}%2d${NC}) ${WHITE}%-40s${NC}${_current}\n" "$aidx" "$adname"
        done < <(jq -r '.data[].name' <<< "$ads_json" 2>/dev/null | sort)

        # Auto-select when only one AD exists
        if [[ "$aidx" -eq 1 ]]; then
            SETUP_AD="${_SETUP_AD_MAP[1]}"
            echo -e "${GREEN}Auto-selected (only AD): ${WHITE}${SETUP_AD##*:}${NC}"
        else
            echo ""
            echo -e "  ${GRAY}Select one AD, multiple (e.g., 1,2,3), or all${NC}"
            if [[ -z "$SETUP_AD" ]]; then
                echo -e "  ${GRAY}(No default AD — Cloud Shell does not provide one)${NC}"
                echo -n -e "${CYAN}Select AD [Enter for first listed]: ${NC}"
            else
                echo -n -e "${CYAN}Select AD [Enter to keep ${WHITE}${SETUP_AD##*:}${CYAN}]: ${NC}"
            fi
            local ad_choice
            read -r ad_choice
            if [[ -z "$ad_choice" ]]; then
                if [[ -z "$SETUP_AD" && -n "${_SETUP_AD_MAP[1]:-}" ]]; then
                    SETUP_AD="${_SETUP_AD_MAP[1]}"
                    echo -e "${GREEN}✓ AD: ${SETUP_AD##*:} (first)${NC}"
                else
                    echo -e "${GREEN}✓ AD: ${SETUP_AD##*:} (kept)${NC}"
                fi
            elif [[ "$ad_choice" == "all" || "$ad_choice" == "ALL" ]]; then
                local all_ads=""
                for ((i=1; i<=aidx; i++)); do
                    [[ -n "$all_ads" ]] && all_ads+=","
                    all_ads+="${_SETUP_AD_MAP[$i]}"
                done
                SETUP_AD="$all_ads"
                echo -e "${GREEN}✓ AD: all (${aidx} domains)${NC}"
            elif [[ "$ad_choice" == *","* ]]; then
                local multi_ads=""
                local sel
                while IFS= read -r sel; do
                    sel="${sel// /}"
                    if [[ -n "$sel" && -n "${_SETUP_AD_MAP[$sel]:-}" ]]; then
                        [[ -n "$multi_ads" ]] && multi_ads+=","
                        multi_ads+="${_SETUP_AD_MAP[$sel]}"
                    fi
                done < <(tr ',' '\n' <<< "$ad_choice")
                if [[ -n "$multi_ads" ]]; then
                    SETUP_AD="$multi_ads"
                    local _ad_ct
                    _ad_ct=$(tr ',' '\n' <<< "$multi_ads" | wc -l)
                    echo -e "${GREEN}✓ AD: ${_ad_ct} domain(s)${NC}"
                else
                    echo -e "${GREEN}✓ AD: ${SETUP_AD##*:} (kept)${NC}"
                fi
            elif [[ -n "${_SETUP_AD_MAP[$ad_choice]:-}" ]]; then
                SETUP_AD="${_SETUP_AD_MAP[$ad_choice]}"
                echo -e "${GREEN}✓ AD: ${SETUP_AD##*:}${NC}"
            else
                echo -e "${GREEN}✓ AD: ${SETUP_AD##*:} (kept)${NC}"
            fi
        fi
    fi
    
    # Initialize variables
    local oke_cluster_id="" oke_cluster_name=""
    
    # ── Select OKE Cluster ──
    echo ""
    _ui_subheader "OKE Clusters" 0
    _step_init
    _step_active "OKE clusters"
    
    local clusters_json
    clusters_json=$(oci ce cluster list \
        --compartment-id "$SETUP_COMPARTMENT_ID" \
        ${_setup_auth} \
        --lifecycle-state ACTIVE \
        --all \
        --output json 2>/dev/null)
    local _okec
    _okec=$(jq '.data | length' <<< "$clusters_json" 2>/dev/null || echo "0")
    _step_complete "OKE clusters(${_okec})"
    _step_finish
    
    local -a clusters=()
    while IFS= read -r line; do
        [[ -n "$line" ]] && clusters+=("$line")
    done < <(jq -r '.data[] | "\(.name)|\(.id)|\(.["kubernetes-version"])"' <<< "$clusters_json" 2>/dev/null)
    
    if [[ ${#clusters[@]} -eq 1 ]]; then
        oke_cluster_name=$(echo "${clusters[0]}" | cut -d'|' -f1)
        oke_cluster_id=$(echo "${clusters[0]}" | cut -d'|' -f2)
        local k8s_version=$(echo "${clusters[0]}" | cut -d'|' -f3)
        
        echo -e "${GREEN}Auto-selected (only cluster):${NC}"
        echo -e "  ${CYAN}Name:${NC}    ${WHITE}$oke_cluster_name${NC}"
        echo -e "  ${CYAN}Version:${NC} ${WHITE}$k8s_version${NC}"
    elif [[ ${#clusters[@]} -gt 1 ]]; then
        setup_select_from_list "Select OKE Cluster:" clusters oke_cluster_id true
        [[ -n "$oke_cluster_id" ]] && oke_cluster_name=$(jq -r --arg id "$oke_cluster_id" '.data[] | select(.id == $id) | .name' <<< "$clusters_json")
    fi
    
    if [[ -n "$oke_cluster_id" ]]; then
        echo -e "${GREEN}✓ OKE Cluster: ${WHITE}$oke_cluster_name${NC}"
    fi
    
    # ── Display summary ──
    _ui_menu_header "CONFIGURATION SUMMARY" --color "$BLUE"
    _ui_subheader "Base Environment" 0
    if [[ -n "$setup_tenancy_name" ]]; then
        echo -e "  ${CYAN}Tenancy:${NC}        ${setup_tenancy_name} ${GRAY}[${SETUP_TENANCY_ID}]${NC}"
    else
        echo -e "  ${CYAN}Tenancy:${NC}        $SETUP_TENANCY_ID"
    fi
    echo -e "  ${CYAN}Region:${NC}         $SETUP_REGION"
    if [[ "$SETUP_AD" == *","* ]]; then
        local _summary_ad_ct=$(echo "$SETUP_AD" | tr ',' '\n' | wc -l)
        echo -e "  ${CYAN}AD:${NC}             all (${_summary_ad_ct} domains)"
    else
        echo -e "  ${CYAN}AD:${NC}             ${SETUP_AD##*:}"
    fi
    if [[ -n "$setup_compartment_name" ]]; then
        echo -e "  ${CYAN}Compartment:${NC}    ${setup_compartment_name} ${GRAY}[${SETUP_COMPARTMENT_ID}]${NC}"
    else
        echo -e "  ${CYAN}Compartment:${NC}    $SETUP_COMPARTMENT_ID"
    fi
    echo ""
    _ui_subheader "Selected Resources" 0
    [[ -n "$oke_cluster_id" ]] && echo -e "  ${GREEN}✓${NC} OKE Cluster: $oke_cluster_name" || echo -e "  ${YELLOW}○${NC} OKE Cluster: (not set)"
    
    # Save configuration
    echo ""
    echo -n -e "${CYAN}Save configuration to variables.sh? (Y/n): ${NC}"
    read -r save_choice
    
    if [[ ! "$save_choice" =~ ^[Yy]$ && -n "$save_choice" ]]; then
        echo -e "${YELLOW}Configuration not saved${NC}"
        return 1
    fi
    
    local output_file="${SCRIPT_DIR}/variables.sh"
    cat > "$output_file" <<EOF
#!/bin/bash
#===============================================================================
# OCI Environment Configuration
# Auto-generated on $(date -u +"%Y-%m-%d %H:%M:%S UTC")
#===============================================================================

REGION="$SETUP_REGION"
TENANCY_ID="$SETUP_TENANCY_ID"
COMPARTMENT_ID="$SETUP_COMPARTMENT_ID"
AD="$SETUP_AD"

# OKE Cluster
OKE_CLUSTER_ID="$oke_cluster_id"
CLUSTER_NAME="$oke_cluster_name"

# Instance filter for listing: "gpu", "non-gpu", or "all"
INSTANCE_FILTER="all"
EOF

    chmod 600 "$output_file"
    echo -e "${GREEN}Configuration saved to: ${WHITE}$output_file${NC}"
    echo ""
    
    return 0
}

#--------------------------------------------------------------------------------
# Check if variables.sh has required values populated
#--------------------------------------------------------------------------------
check_variables_populated() {
    # Check minimum required variables (from variables.sh)
    if [[ -z "${REGION:-}" || -z "${TENANCY_ID:-}" || -z "${COMPARTMENT_ID:-}" ]]; then
        return 1
    fi
    return 0
}

# Validate config values after sourcing variables.sh and initializing focus
# Warns on malformed OCIDs and missing optional variables (non-fatal)
_validate_config() {
    local errors=0 warnings=0

    # ── Required variables (fatal) ──
    if [[ -z "${COMPARTMENT_ID:-}" ]]; then
        log_error "COMPARTMENT_ID not set in variables.sh"
        ((errors++))
    elif [[ ! "$COMPARTMENT_ID" == ocid1.compartment.* && ! "$COMPARTMENT_ID" == ocid1.tenancy.* ]]; then
        log_error "COMPARTMENT_ID doesn't look like a valid OCID: ${COMPARTMENT_ID:0:40}..."
        ((errors++))
    fi

    if [[ -z "${REGION:-}" ]]; then
        log_error "REGION not set in variables.sh"
        ((errors++))
    elif [[ ! "$REGION" =~ ^[a-z]{2}-[a-z]+-[0-9]+$ ]]; then
        log_warn "REGION format looks unusual: $REGION (expected: us-ashburn-1)"
        ((warnings++))
    fi

    if [[ -z "${TENANCY_ID:-}" ]]; then
        log_error "TENANCY_ID not set in variables.sh"
        ((errors++))
    elif [[ ! "$TENANCY_ID" == ocid1.tenancy.* ]]; then
        log_error "TENANCY_ID doesn't look like a valid OCID: ${TENANCY_ID:0:40}..."
        ((errors++))
    fi

    # ── Optional variables (warning only) ──
    if [[ -n "${OKE_CLUSTER_ID:-}" && ! "$OKE_CLUSTER_ID" == ocid1.cluster.* ]]; then
        log_warn "OKE_CLUSTER_ID doesn't look like a valid cluster OCID: ${OKE_CLUSTER_ID:0:40}..."
        ((warnings++))
    fi

    if [[ -n "${NETWORK_COMPARTMENT_ID:-}" && ! "$NETWORK_COMPARTMENT_ID" == ocid1.compartment.* && ! "$NETWORK_COMPARTMENT_ID" == ocid1.tenancy.* ]]; then
        log_warn "NETWORK_COMPARTMENT_ID doesn't look like a valid OCID: ${NETWORK_COMPARTMENT_ID:0:40}..."
        ((warnings++))
    fi

    if [[ -n "${VCN_OCID:-}" && ! "$VCN_OCID" == ocid1.vcn.* ]]; then
        log_warn "VCN_OCID doesn't look like a valid VCN OCID: ${VCN_OCID:0:40}..."
        ((warnings++))
    fi

    # ── Result ──
    if [[ $errors -gt 0 ]]; then
        log_error "$errors config error(s) found. Run --setup to fix."
        return 1
    fi
    if [[ $warnings -gt 0 ]]; then
        log_warn "$warnings config warning(s). Values may be incorrect in variables.sh."
    fi
    return 0
}

#===============================================================================
# MAIN FUNCTION
#===============================================================================

main() {
    # Check dependencies first
    check_dependencies || exit 1
    
    # Source variables file
    local variables_found=false
    # Pre-validate variables.sh contains only safe content (variable assignments, comments, blanks)
    _validate_variables_file() {
        local _vf="$1"
        [[ ! -f "$_vf" ]] && return 1
        # Reject if file contains anything other than: comments, blank lines, var=value assignments, export statements
        if grep -qvE '^\s*(#|$|[A-Za-z_][A-Za-z0-9_]*=|export\s+[A-Za-z_])' "$_vf" 2>/dev/null; then
            echo -e "${RED}ERROR: $_vf contains non-assignment lines — refusing to source for security${NC}" >&2
            return 1
        fi
        return 0
    }
    if [[ -f "$SCRIPT_DIR/variables.sh" ]] && _validate_variables_file "$SCRIPT_DIR/variables.sh"; then
        # shellcheck source=/dev/null
        source "$SCRIPT_DIR/variables.sh"
        variables_found=true
    elif [[ -f "./variables.sh" ]] && _validate_variables_file "./variables.sh"; then
        # shellcheck source=/dev/null
        source "./variables.sh"
        variables_found=true
    fi
    
    # Check if variables.sh exists and has required values
    if [[ "$variables_found" == "false" ]]; then
        echo -e "${YELLOW}variables.sh not found.${NC}"
        echo ""
        echo -n -e "${CYAN}Would you like to run initial setup? (Y/n): ${NC}"
        read -r setup_choice
        
        if [[ "$setup_choice" =~ ^[Yy]$ || -z "$setup_choice" ]]; then
            if run_initial_setup; then
                # Re-source the newly created file
                source "./variables.sh"
            else
                echo -e "${RED}Setup failed or cancelled. Exiting.${NC}"
                exit 1
            fi
        else
            echo -e "${YELLOW}Please create variables.sh with COMPARTMENT_ID, REGION, and TENANCY_ID.${NC}"
            exit 1
        fi
    elif ! check_variables_populated; then
        echo -e "${YELLOW}variables.sh exists but required values (COMPARTMENT_ID, REGION, TENANCY_ID) are not set.${NC}"
        echo ""
        echo -n -e "${CYAN}Would you like to run setup to populate values? (Y/n): ${NC}"
        read -r setup_choice
        
        if [[ "$setup_choice" =~ ^[Yy]$ || -z "$setup_choice" ]]; then
            if run_initial_setup; then
                # Re-source the file
                source "./variables.sh"
            else
                echo -e "${RED}Setup failed or cancelled.${NC}"
                exit 1
            fi
        fi
    fi
    
    # Create cache and temp directories - restrict to owner only (contains OCI resource data)
    ( umask 077 && mkdir -p "$CACHE_DIR" "$TEMP_DIR" )
    
    # Parse global options
    local custom_compartment=""
    local custom_region=""
    local args=("$@")
    local new_args=()
    local i=0
    
    while [[ $i -lt ${#args[@]} ]]; do
        case "${args[$i]}" in
            --compartment-id)
                if [[ $((i + 1)) -lt ${#args[@]} ]]; then
                    custom_compartment="${args[$((i + 1))]}"
                    i=$((i + 2))
                else
                    log_error "--compartment-id requires a value"
                    exit 1
                fi
                ;;
            --region)
                if [[ $((i + 1)) -lt ${#args[@]} ]]; then
                    custom_region="${args[$((i + 1))]}"
                    i=$((i + 2))
                else
                    log_error "--region requires a value"
                    exit 1
                fi
                ;;
            --debug)
                DEBUG_MODE=true
                i=$((i + 1))
                ;;
            *)
                new_args+=("${args[$i]}")
                i=$((i + 1))
                ;;
        esac
    done
    
    # Initialize environment focus system
    _focus_init "$custom_compartment" "$custom_region"
    
    # Validate config values (OCID formats, region format)
    _validate_config || exit 1
    
    # Detect tool versions and OCI auth method (once at startup)
    _detect_tool_versions

    # Restore positional parameters
    set -- "${new_args[@]}"

    # Route to appropriate function based on arguments
    case "${1:-}" in
        "")
            interactive_management_main_menu
            ;;
        --setup)
            run_initial_setup
            ;;
        --list-cliques)
            list_all_cliques
            ;;
        --cliques-summary)
            list_cliques_summary
            ;;
        --manage)
            shift
            interactive_management_main_menu "$1"
            ;;
        --search)
            shift
            oci_resource_search "${1:-}" "true"
            ;;
        --maintenance)
            list_maintenance_instances "$FOCUS_COMPARTMENT_ID" "$FOCUS_REGION"
            ;;
        --maintenance-events)
            list_maintenance_events "$FOCUS_COMPARTMENT_ID" "$FOCUS_REGION"
            ;;
        --announcements)
            list_all_announcements "$FOCUS_COMPARTMENT_ID" "$FOCUS_REGION"
            ;;
        --refresh)
            refresh_all_caches
            ;;
        --help|-h)
            show_help
            ;;
        c|c[0-9]|k|k[0-9]|n|n[0-9]|s|s[0-9]|i|i[0-9]|o|o[0-9]|r|env|env\ *)
            # Menu shortcut passed as CLI argument — route to interactive menu
            interactive_management_main_menu "$1"
            ;;
        *)
            # Assume it's an instance OCID or instance config OCID or GPU cluster OCID
            local instance_id="$1"
            local show_labels="false"
            local show_clique="false"
            local count_clique="false"
            local show_console_history="false"
            local show_instance_details="false"
            local show_user_data="false"
            local show_config_user_data="false"
            local show_list_cluster="false"
            local do_terminate="false"
            
            shift
            while [[ $# -gt 0 ]]; do
                case "$1" in
                    --labels)
                        show_labels="true"
                        shift
                        ;;
                    --clique)
                        show_clique="true"
                        shift
                        ;;
                    --count-clique)
                        count_clique="true"
                        show_clique="true"
                        shift
                        ;;
                    --all)
                        show_labels="true"
                        show_clique="true"
                        count_clique="true"
                        shift
                        ;;
                    --console-history)
                        show_console_history="true"
                        shift
                        ;;
                    --details)
                        show_instance_details="true"
                        shift
                        ;;
                    --get-user-data)
                        show_user_data="true"
                        shift
                        ;;
                    --get-user-data-config)
                        show_config_user_data="true"
                        shift
                        ;;
                    --list-cluster)
                        show_list_cluster="true"
                        shift
                        ;;
                    --terminate)
                        do_terminate="true"
                        shift
                        ;;
                    *)
                        log_error "Unknown option: $1"
                        exit 1
                        ;;
                esac
            done
            
            if [[ "$do_terminate" == "true" ]]; then
                terminate_instance_interactive "$instance_id"
            elif [[ "$show_list_cluster" == "true" ]]; then
                list_instances_by_gpu_cluster "$instance_id" "$FOCUS_COMPARTMENT_ID" "$FOCUS_REGION"
            elif [[ "$show_config_user_data" == "true" ]]; then
                get_instance_config_user_data "$instance_id"
            elif [[ "$show_user_data" == "true" ]]; then
                get_instance_user_data "$instance_id"
            elif [[ "$show_console_history" == "true" ]]; then
                get_console_history "$instance_id"
            elif [[ "$show_instance_details" == "true" ]]; then
                # Loop to handle refresh requests
                while true; do
                    display_instance_details "$instance_id"
                    local ret=$?
                    [[ $ret -ne 2 ]] && break  # Exit loop unless refresh requested
                done
            else
                get_node_info "$instance_id" "$show_labels" "$show_clique" "$count_clique"
            fi
            ;;
    esac
}

# Run main function
main "$@"